### Escrita padronizada de produtos tabulares -------------------------------
### Em todos os CSVs gravados pelo script, valores ausentes são exportados de
### forma explícita como NA. Antes da gravação, strings vazias, "NA" textual e
### marcadores "---" são convertidos para NA real, evitando que ausências sejam
### interpretadas como valores preenchidos em auditorias e relatórios.
MONITORA_VALORES_AUSENTES_EXPORTACAO <- c("", "NA", "---")

monitora_sanitizar_ausencias_produto <- function(x) {
  if (!inherits(x, c("data.frame", "data.table"))) return(x)
  out <- data.table::as.data.table(data.table::copy(x))
  if (!length(names(out))) return(out)

  for (cc in names(out)) {
    v <- out[[cc]]
    if (is.character(v) || is.factor(v)) {
      v <- as.character(v)
      z <- trimws(v)
 ### produtos corrigidos usam ausência física como literal NA.
 ### Além de vazio/NA/"NA", qualquer token composto só por traços
 ### ASCII/Unicode ("-", "--", "---", "—", etc.) é ausência.
      ausente <- is.na(v) | !nzchar(z) | tolower(z) == "na" |
        grepl("^[[:space:]]*[-–—−]+[[:space:]]*$", z, perl = TRUE)
      if (any(ausente, na.rm = TRUE)) v[ausente] <- NA_character_
      data.table::set(out, j = cc, value = v)
    }
  }
  out
}

monitora_sanitizar_posix_produto <- function(x) {
  if (!inherits(x, c("data.frame", "data.table"))) return(x)
  out <- data.table::as.data.table(data.table::copy(x))
  for (cc in names(out)) {
    v <- out[[cc]]
    if (!inherits(v, "POSIXt")) next
 ### `fwrite ` formata POSIXt internamente. Um atributo POSIXct legado com
 ### payload textual/NaN só falhava nessa etapa tardia. Normalize a coluna
 ### para ISO-8601 antes da exportação; valores irrecuperáveis tornam-se NA.
    epoch <- if (inherits(v, "POSIXlt")) {
      suppressWarnings(as.numeric(as.POSIXct(v)))
    } else {
      suppressWarnings(as.numeric(unclass(v)))
    }
    ok <- is.finite(epoch)
    texto <- rep(NA_character_, length(v))
    if (any(ok)) {
      tz <- attr(v, "tzone", exact = TRUE)
      if (is.null(tz) || !length(tz) || is.na(tz[1L])) tz <- ""
      seguro <- structure(epoch[ok], class = c("POSIXct", "POSIXt"), tzone = as.character(tz)[1L])
      texto[ok] <- suppressWarnings(format(seguro, "%Y-%m-%d %H:%M:%S %z", tz = as.character(tz)[1L]))
    }
    data.table::set(out, j = cc, value = texto)
  }
  out
}

monitora_fwrite <- function(x, file = "", ...) {
  args <- list(...)
  args$na <- "NA"
 ### contrato de serialização portátil. `fwrite ` não deve depender
 ### da localidade do processo nem usar CRLF diferente por sistema operacional.
 ### O BOM permanece opt-in aqui: logs/arquivos incrementais não podem receber
 ### BOM interno; os produtos canônicos destinados à abertura humana o ativam
 ### nos respectivos escritores.
  if (is.null(args$encoding)) args$encoding <- "UTF-8"
  if (is.null(args$eol)) args$eol <- "\n"
  if (is.null(args$bom)) args$bom <- FALSE
 ### POSIXt precisa ser normalizado antes da sanitização geral: esta última
 ### usa `as.character ` para fatores/caracteres e, em colunas POSIXct com
 ### payload legado inválido, acionava as.POSIXlt.POSIXct e dois warnings.
  x <- monitora_sanitizar_posix_produto(x)
  x <- monitora_sanitizar_ausencias_produto(x)
 ### Segurança operacional: garantir que o diretório de destino exista antes
 ### da escrita. Isso evita falhas tardias em auditorias finais quando o
 ### diretório log/output foi removido, não foi incluído no working directory
 ### atual, ou quando o caminho é relativo e ainda não existe.
  if (!missing(file) && !is.null(file) && length(file) == 1L && nzchar(as.character(file))) {
    dir_destino <- dirname(as.character(file))
    if (!is.na(dir_destino) && nzchar(dir_destino) && dir_destino != ".") {
      dir.create(dir_destino, showWarnings = FALSE, recursive = TRUE)
    }
  }
 ### Segurança operacional: data.table::fwrite em data.table/data.frame
 ### vazio sem colunas gera warning e cria arquivo de 0 byte. Em relatórios
 ### auditáveis isso é indesejável, porque parece falha de escrita. Quando
 ### algum chamador ainda devolver objeto sem esquema, criamos um cabeçalho
 ### mínimo explícito. Relatórios críticos devem preferir esquemas próprios.
  if ((data.table::is.data.table(x) || is.data.frame(x)) && identical(ncol(x), 0L)) {
    x <- data.table::data.table(sem_registros = character())
  }
  do.call(utils::getFromNamespace("fwrite", "data.table"), c(list(x = x, file = file), args))
}

monitora_fwrite_atomico <- function(x, file, ...) {
  file <- as.character(file)[1L]
  dir.create(dirname(file), recursive = TRUE, showWarnings = FALSE)
  tmp <- paste0(file, ".tmp_", Sys.getpid(), "_", format(Sys.time(), "%Y%m%d%H%M%S"))
  on.exit(if (file.exists(tmp)) unlink(tmp), add = TRUE)
  monitora_fwrite(x, tmp, ...)
  if (!file.exists(tmp) || is.na(file.info(tmp)$size) || file.info(tmp)$size <= 0L) {
    stop("Falha ao criar candidato temporário para escrita atômica: ", file, call. = FALSE)
  }
  ok <- file.rename(tmp, file)
  if (!isTRUE(ok)) {
 ### Filesystems que não substituem destino por rename recebem fallback
 ### copy+hash; o arquivo anterior só é tocado depois do candidato completo.
    ok <- file.copy(tmp, file, overwrite = TRUE, copy.date = TRUE)
    if (isTRUE(ok)) {
      h_tmp <- unname(tools::md5sum(tmp)); h_dst <- unname(tools::md5sum(file))
      ok <- !is.na(h_tmp) && !is.na(h_dst) && identical(h_tmp, h_dst)
    }
  }
  if (!isTRUE(ok)) stop("Falha na troca atômica do produto: ", file, call. = FALSE)
  invisible(file)
}
