### Acesso seguro a objetos globais dentro de funções
###
### Motivo: funções como a auditoria final eram executadas depois de `setwd(output/)`.
### Quando usavam `exists(..., inherits = FALSE)` dentro do ambiente local da função,
### não enxergavam variáveis globais como MONITORA_OUTPUT_DIR e caíam em fallbacks
### baseados em `getwd `, produzindo caminhos inválidos como output/output.
monitora_global_existe <- function(nome) {
  is.character(nome) && length(nome) == 1L &&
    exists(nome, envir = .GlobalEnv, inherits = FALSE)
}

monitora_global_get <- function(nome, default = NULL) {
  if (monitora_global_existe(nome)) get(nome, envir = .GlobalEnv, inherits = FALSE) else default
}

monitora_global_is_true <- function(nome) {
  isTRUE(monitora_global_get(nome, FALSE))
}

monitora_dir_global_obrigatorio <- function(nome, criar = TRUE) {
  x <- monitora_global_get(nome, NULL)
  if (is.null(x) || length(x) != 1L || is.na(x) || !nzchar(as.character(x))) {
    stop(nome, " não está definido no ambiente global; não é seguro prosseguir.", call. = FALSE)
  }
  x <- normalizePath(as.character(x), winslash = "/", mustWork = FALSE)
  if (grepl("/(output|log|input|extracted)/(output|log|input|extracted)$", x)) {
    stop(nome, " inválido com diretório operacional aninhado: ", x, call. = FALSE)
  }
  if (isTRUE(criar)) dir.create(x, showWarnings = FALSE, recursive = TRUE)
  x
}


### Privacidade em metadados e auditorias -----------------------------------
### Produtos locais como registros_importados.csv, registros_corrig.csv e
### registros_validados.csv podem conter dados reais da execução. Esses produtos
### não devem ser publicados sem triagem. As auditorias auxiliares, porém, não
### precisam gravar exemplos brutos de nomes, UCs, coordenadas, URLs, UUIDs ou
### outros identificadores. As funções abaixo reduzem a exposição acidental em
### objetos materializados de auditoria, preservando contagens, status e motivos.

monitora_privacidade_caminho_relativo <- function(path, base_dir = MONITORA_BASE_DIR) {
  if (is.null(path) || !length(path)) return(character())
  path <- as.character(path)
  out <- rep(NA_character_, length(path))
  base_norm <- tryCatch(normalizePath(base_dir, winslash = "/", mustWork = FALSE), error = function(e) as.character(base_dir))
  for (i in seq_along(path)) {
    p <- path[i]
    if (is.na(p) || !nzchar(trimws(p))) { out[i] <- NA_character_; next }
    pn <- tryCatch(normalizePath(p, winslash = "/", mustWork = FALSE), error = function(e) p)
    if (nzchar(base_norm) && startsWith(pn, paste0(base_norm, "/"))) {
      out[i] <- substring(pn, nchar(base_norm) + 2L)
    } else if (basename(pn) %in% c("input", "output", "log", "extracted")) {
      out[i] <- basename(pn)
    } else {
      out[i] <- basename(pn)
    }
  }
  out
}

monitora_privacidade_caminho_entrada <- function(path) {
 ## Evita materializar caminhos locais, nomes de usuário ou pastas de execução nos relatórios.
 ## estrutura local completa. Quando possível, mantém caminho relativo à pasta
 ## do projeto; caso contrário, preserva apenas o nome do arquivo.
  monitora_privacidade_caminho_relativo(path, MONITORA_BASE_DIR)
}

monitora_privacidade_padrao_sensivel <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  grepl("[0-9]{3}\\.?[0-9]{3}\\.?[0-9]{3}[- ]?[0-9]{2}", x, perl = TRUE) |
    grepl("[A-Z0-9._%+-]+@[A-Z0-9.-]+\\.[A-Z]{2,}", x, ignore.case = TRUE, perl = TRUE) |
    grepl("https?://|www\\.", x, ignore.case = TRUE, perl = TRUE) |
    grepl("[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}", x, ignore.case = TRUE, perl = TRUE) |
    grepl("^[[:alpha:]]:", x, perl = TRUE) |
    startsWith(x, "/") | startsWith(x, "\\")
}

monitora_privacidade_coluna_sensivel <- function(nome) {
  nm <- tolower(as.character(nome))
  grepl("cpf|usuario|usu[aá]rio|validador|coletor|nome|uc$|unidade.*conserv|foto|url|link|media|m[ií]dia|uuid|coorden|latitude|longitude|geopoint|observ|obs|coment|descri|caminho|path", nm, perl = TRUE)
}

monitora_privacidade_mascarar_campo <- function(x, marcador = "[omitido_privacidade]") {
  x <- as.character(x)
  tem <- !is.na(x) & nzchar(trimws(x))
  x[tem] <- marcador
  x
}

monitora_privacidade_sanitizar_auditoria <- function(dt, mascarar_exemplos = TRUE) {
  if (!inherits(dt, c("data.frame", "data.table"))) return(dt)
  out <- data.table::as.data.table(data.table::copy(dt))
  if (!ncol(out)) return(out)

 ## Em auditorias de mapeamento/validação, exemplos brutos são informativos,
 ## mas podem materializar dados pessoais ou institucionais. Preservamos as
 ## métricas e substituímos exemplos por marcador genérico.
  cols_exemplo <- intersect(c("exemplos", "exemplos_coleta", "exemplos_invalidos", "detalhe", "valor_residual", "tokens_invalidos", "urls", "url", "foto", "uuid"), names(out))
  if (isTRUE(mascarar_exemplos) && length(cols_exemplo)) {
    for (cc in cols_exemplo) {
      v <- as.character(out[[cc]])
      tem <- !is.na(v) & nzchar(trimws(v))
      if (any(tem, na.rm = TRUE)) {
        marcador <- if (grepl("coleta", cc, ignore.case = TRUE)) "[identificadores_omitidos]" else "[exemplos_omitidos_privacidade]"
        v[tem] <- marcador
        data.table::set(out, j = cc, value = v)
      }
    }
  }

 ## Para qualquer coluna de auditoria com nome potencialmente sensível,
 ## mascara valores não vazios; mantém nomes de atributos e status técnicos.
  for (cc in names(out)) {
    if (cc %in% c("atributo", "regra", "tipo", "status", "status_mapeamento", "formato_esperado", "motivo_bloqueio", "orientacao", "produto", "schema")) next
    v <- out[[cc]]
    if (!(is.character(v) || is.factor(v))) next
    vv <- as.character(v)
    sens_col <- monitora_privacidade_coluna_sensivel(cc)
    sens_val <- monitora_privacidade_padrao_sensivel(vv)
    idx <- (!is.na(vv) & nzchar(trimws(vv))) & (sens_col | sens_val)
    if (any(idx, na.rm = TRUE)) {
      vv[idx] <- if (grepl("caminho|path|auditoria", cc, ignore.case = TRUE)) "[caminho_relativo_omitido]" else "[omitido_privacidade]"
      data.table::set(out, j = cc, value = vv)
    }
  }
  out
}

monitora_io_arquivo_script_ativo <- function() {
  candidatos <- character(0)
  if (requireNamespace("rstudioapi", quietly = TRUE)) {
    candidatos <- c(candidatos, tryCatch(rstudioapi::getActiveDocumentContext()$path, error = function(e) NA_character_))
  }
  cmd_file <- grep("^--file=", commandArgs(FALSE), value = TRUE)
  if (length(cmd_file)) candidatos <- c(candidatos, sub("^--file=", "", cmd_file[1L]))
  frames <- sys.frames()
  if (length(frames)) candidatos <- c(candidatos, unlist(lapply(frames, function(fr) tryCatch(fr$ofile, error = function(e) NA_character_)), use.names = FALSE))
  candidatos <- unique(as.character(candidatos))
  candidatos <- candidatos[!is.na(candidatos) & nzchar(candidatos) & file.exists(candidatos) & !dir.exists(candidatos)]
  if (length(candidatos)) normalizePath(candidatos[1L], winslash = "/", mustWork = TRUE) else NA_character_
}

monitora_io_hash_inventario_input <- function(input_dir) {
  arqs <- if (dir.exists(input_dir)) list.files(input_dir, recursive = TRUE, full.names = TRUE, all.files = TRUE, no.. = TRUE) else character(0)
  arqs <- sort(arqs[file.exists(arqs) & !dir.exists(arqs)])
  if (!length(arqs)) return(list(n = 0L, hash = NA_character_))
  input_norm <- normalizePath(input_dir, winslash = "/", mustWork = TRUE)
  arqs_norm <- normalizePath(arqs, winslash = "/", mustWork = TRUE)
  rel <- substring(arqs_norm, nchar(input_norm) + 2L)
  info <- file.info(arqs)
  assinatura_meta <- paste(input_norm, paste(rel, as.numeric(info$size), as.numeric(info$mtime), sep = "|", collapse = "\n"), sep = "\n")
  cache <- get0("MONITORA_IO_CACHE_INVENTARIO_INPUT", ifnotfound = NULL, envir = .GlobalEnv, inherits = FALSE)
  if (is.list(cache) && identical(cache$assinatura_meta, assinatura_meta) && is.list(cache$resultado)) return(cache$resultado)
  hashes <- vapply(arqs, monitora_doc_sha256, character(1L))
  texto <- paste(rel, as.numeric(info$size), hashes, sep = "|", collapse = "\n")
  hash_inv <- if (requireNamespace("digest", quietly = TRUE)) digest::digest(texto, algo = "sha256") else paste0("inventario_sem_digest:", nchar(texto), ":", sum(utf8ToInt(enc2utf8(texto)), na.rm = TRUE))
  resultado <- list(n = length(arqs), hash = hash_inv)
  assign("MONITORA_IO_CACHE_INVENTARIO_INPUT", list(assinatura_meta = assinatura_meta, resultado = resultado), envir = .GlobalEnv)
  resultado
}

monitora_io_manifesto_execucao <- function(fase = "inicio") {
  script_ativo <- monitora_io_arquivo_script_ativo()
  inv_input <- monitora_io_hash_inventario_input(MONITORA_INPUT_DIR)
  data.table::data.table(
    fase = as.character(fase),
    exec_id = as.character(monitora_global_get("MONITORA_EXEC_ID", NA_character_)),
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S"),
    script_build_id = as.character(get0("MONITORA_SCRIPT_BUILD_ID", ifnotfound = NA_character_, inherits = TRUE)),
    script_arquivo = if (!is.na(script_ativo)) basename(script_ativo) else NA_character_,
    script_sha256 = if (!is.na(script_ativo)) monitora_doc_sha256(script_ativo) else NA_character_,
    input_n_arquivos = as.integer(inv_input$n),
    input_inventario_sha256 = as.character(inv_input$hash),
    getwd = normalizePath(getwd(), winslash = "/", mustWork = FALSE),
    base_dir = MONITORA_BASE_DIR,
    input_dir = MONITORA_INPUT_DIR,
    output_dir = MONITORA_OUTPUT_DIR,
    log_dir = MONITORA_LOG_DIR
  )
}

monitora_gravar_manifesto_execucao <- function(fase = "inicio") {
  man <- monitora_io_manifesto_execucao(fase)
  monitora_fwrite(man, file.path(MONITORA_OUTPUT_DIR, "manifesto_execucao_ultima_execucao.csv"))
  monitora_fwrite(man, file.path(MONITORA_LOG_DIR, paste0("manifesto_execucao_", fase, "_", format(Sys.time(), "%Y%m%d_%H%M%S"), ".csv")))
  invisible(man)
}

### O identificador precisa existir antes do primeiro manifesto; antes desta
