if (!exists("MONITORA_EXEC_ID", inherits = TRUE) || !nzchar(as.character(get("MONITORA_EXEC_ID", inherits = TRUE))[1L])) {
  MONITORA_EXEC_ID <- format(Sys.time(), "%Y%m%d_%H%M%S")
