### Diagnóstico opcional e reversível de warnings POSIX -------------------
### Colunas POSIXt são normalizadas em monitora_fwrite antes da exportação.
### O modo imediato permanece disponível apenas para investigação deliberada.
MONITORA_WARN_OPTION_ORIGINAL <- getOption("warn", 0)
MONITORA_DIAGNOSTICO_POSIX_IMEDIATO <-
  toupper(trimws(Sys.getenv("MONITORA_DIAGNOSTICAR_WARNINGS_POSIX", "N"))) == "S"
if (isTRUE(MONITORA_DIAGNOSTICO_POSIX_IMEDIATO)) {
  options(warn = 1)
  message(
    "[monitora] Diagnóstico POSIX ativo no modo ", MONITORA_MODO_EXECUCAO,
    ": warnings serão impressos na etapa causal e a opção warn será restaurada ao encerrar."
  )
}

monitora_diagnostico_posix_restaurar <- function() {
  if (exists("MONITORA_WARN_OPTION_ORIGINAL", inherits = TRUE)) {
    options(warn = get("MONITORA_WARN_OPTION_ORIGINAL", inherits = TRUE))
  }
  invisible(TRUE)
}

### delimita a chamada real sem suprimir o warning. A comprovou que
### registros_corrig não possui coluna POSIXt nesse checkpoint; portanto, a
### investigação agora separa organização física e exportação operacional e
### registra a pilha curta da chamada que efetivamente emitir o aviso.
monitora_posix_diagnosticar_etapa <- function(etapa, expr) {
  expr_sub <- substitute(expr)
  env <- parent.frame()
  withCallingHandlers(
    eval(expr_sub, envir = env),
    warning = function(w) {
      msg <- conditionMessage(w)
      chamadas <- sys.calls()
      chamadas_txt <- vapply(chamadas, function(z) paste(deparse(z, width.cutoff = 160L), collapse = " "), character(1L))
      origem_warning <- paste(deparse(conditionCall(w), width.cutoff = 160L), collapse = " ")
      if (!grepl("POSIX", paste(c(msg, origem_warning, chamadas_txt), collapse = " "), ignore.case = TRUE)) return(invisible(NULL))
      chamadas_txt <- tail(chamadas_txt, 12L)
      detalhe <- paste0("etapa=", etapa, " | warning=", msg, " | origem=", origem_warning, " | chamadas=", paste(chamadas_txt, collapse = " -> "))
      if (isTRUE(get0("MONITORA_DIAGNOSTICO_POSIX_IMEDIATO", ifnotfound = FALSE, inherits = TRUE))) message("[monitora][diagnostico_posix] ", detalhe)
      if (exists("monitora_log_registrar_evento", mode = "function")) {
        monitora_log_registrar_evento("diagnostico_warning_posix", "AVISO", NA_character_, detalhe, "R20: localizar consumidor causal; warning preservado")
      }
      invisible(NULL)
    }
  )
}

