monitora_correcao_campo_multiselect_auditoria <- function(atributo, chaves = NULL) {
 ### Campos exportados como listas/multiple choice podem voltar em ordem
 ### diferente após recálculos do XLSForm. Para estes campos a persistência deve
 ### ser validada por conjunto de tokens, não por igualdade literal da string.
  atributo <- as.character(atributo)
  z <- monitora_correcao_normalizar_nome_coluna(atributo)
  z[is.na(z)] <- ""
  tipo_col <- character(0)
  if (!is.null(chaves) && "tipo_forma_vida" %in% names(chaves)) {
    tipo_col <- monitora_correcao_normalizar_nome_coluna(chaves$tipo_forma_vida)
  }
  listas_explicitas <- c(
    "tipo_forma_vida", "amostragem_registro_tipo_forma_vida", "encostam",
    "forma_vida_nativa", "forma_vida_exotica", "forma_vida_seca_morta",
    "amostragem_registro_forma_vida_nativa",
    "amostragem_registro_forma_vida_exotica",
    "amostragem_registro_forma_vida_seca_morta"
  )
  eh_tipo <- nzchar(z) & z %in% unique(c(monitora_correcao_normalizar_nome_coluna(listas_explicitas), tipo_col))
 ### Os cabeçalhos físicos do download SISMONITORA usam também o rótulo
 ### humano no plural ("Formas de vida de plantas... nativas"). Depois da
 ### normalização esse rótulo vira `formas_de_vida_*` e não casava com o
 ### detector histórico `forma_vida`. O conteúdo continuava correto, mas uma
 ### reordenação contratual dos mesmos tokens era falsamente classificada como
 ### perda de persistência. Ambos os nomes representam a mesma lista XLSForm.
  eh_lista_forma <- grepl("(^|_)formas?_de_vida(_|$)", z) &
    grepl("nativ|exotic|exotica|exotico|seca_morta|seca|morta", z) &
    !grepl("habito|habito|especie|popular|foto|imagem|uuid|data|coleta|outra_especie", z)
  eh_tipo | eh_lista_forma
}

monitora_correcao_canonizar_multiselect <- function(x) {
  vapply(as.character(x), function(xx) {
    toks <- monitora_correcao_tokenizar(xx)
    toks <- monitora_correcao_normalizar_nome_coluna(toks)
    toks <- unique(toks[!is.na(toks) & nzchar(toks)])
    if (!length(toks)) return("")
    paste(sort(toks), collapse = " ")
  }, character(1))
}

monitora_correcao_valores_equivalentes <- function(valor_final, valor_esperado, atributo, chaves = NULL) {
 ### Comparação vetorizada usada nas travas de persistência. Campos escalares
 ### continuam com comparação literal normalizada. Campos multiselect usam
 ### comparação semântica por tokens. Em replay de operações semânticas antigas,
 ### uma operação do tipo append_token deve ser considerada persistida quando o
 ### token esperado está contido no valor final, mesmo que o valor final contenha
 ### outros tokens adicionados por outra operação compatível.
  valor_final <- as.character(valor_final)
  valor_esperado <- as.character(valor_esperado)
  n <- max(length(valor_final), length(valor_esperado), length(atributo), 1L)
  valor_final <- rep(valor_final, length.out = n)
  valor_esperado <- rep(valor_esperado, length.out = n)
  atributo <- rep(as.character(atributo), length.out = n)
  multi <- monitora_correcao_campo_multiselect_auditoria(atributo, chaves)
  out <- monitora_correcao_na_para_vazio(valor_final) == monitora_correcao_na_para_vazio(valor_esperado)
  if (any(multi, na.rm = TRUE)) {
    canon_final <- monitora_correcao_canonizar_multiselect(valor_final[multi])
    canon_esp <- monitora_correcao_canonizar_multiselect(valor_esperado[multi])
    out_multi <- mapply(function(ff, ee) {
      ff <- trimws(as.character(ff)); ee <- trimws(as.character(ee))
      if (!nzchar(ee)) return(!nzchar(ff))
      toks_esp <- unique(strsplit(ee, "\\s+")[[1]])
      toks_fin <- unique(strsplit(ff, "\\s+")[[1]])
      toks_esp <- toks_esp[nzchar(toks_esp)]
      toks_fin <- toks_fin[nzchar(toks_fin)]
      if (!length(toks_esp)) return(!length(toks_fin))
      all(toks_esp %in% toks_fin)
    }, canon_final, canon_esp, USE.NAMES = FALSE)
    out[multi] <- out_multi
  }
  out[is.na(out)] <- FALSE
  out
}

monitora_correcao_primeira_coluna_normalizada <- function(dt, candidatos = character(0)) {
  colmap <- if (exists("monitora_publicacao_ae_colnames_norm_dt", mode = "function")) {
    monitora_publicacao_ae_colnames_norm_dt(dt)
  } else {
    nms <- names(dt)
    if (exists("monitora_correcao_colunas_protegidas_existentes", mode = "function")) {
      nms <- setdiff(nms, monitora_correcao_colunas_protegidas_existentes(dt))
    }
    data.table::data.table(col = nms, norm = monitora_correcao_normalizar_nome_coluna(nms))
  }
  if (length(candidatos) == 0L || !nrow(colmap)) return(NA_character_)
  cand_norm <- monitora_correcao_normalizar_nome_coluna(candidatos)
  cand_norm <- cand_norm[!is.na(cand_norm) & nzchar(cand_norm)]
  if (!length(cand_norm)) return(NA_character_)
  for (cc in cand_norm) {
    hit <- colmap[data.table::J(cc), on = "norm", nomatch = 0L]
    if (nrow(hit)) return(hit$col[1L])
  }
  NA_character_
}

monitora_correcao_resolver_atributo_auditoria <- function(dt, atributo) {
 ### Resolve o nome de coluna registrado na auditoria contra o objeto final.
 ### Necessário porque campos XLSForm com HTML/aspas podem ser preservados em
 ### memória e voltar do CSV com aspas normalizadas. A comparação deve usar o
 ### nome real do objeto final, sem depender de igualdade literal frágil.
  nms <- names(dt)
  atributo <- as.character(atributo)[1L]
  if (is.na(atributo) || !nzchar(trimws(atributo)) || !length(nms)) return(NA_character_)
  if (atributo %in% nms) return(atributo)
  attr_norm <- monitora_correcao_normalizar_nome_coluna(atributo)
  nms_norm <- monitora_correcao_normalizar_nome_coluna(nms)
  hit <- which(!is.na(nms_norm) & nzchar(nms_norm) & nms_norm == attr_norm)
  if (length(hit) == 1L) return(nms[hit[1L]])
  if (length(hit) > 1L) {
 ### Preferir colunas não protegidas quando houver aliases técnicos duplicados.
    prot <- tryCatch(monitora_correcao_coluna_protegida(nms[hit]), error = function(e) rep(FALSE, length(hit)))
    hit2 <- hit[!prot]
    if (length(hit2)) return(nms[hit2[1L]])
    return(nms[hit[1L]])
  }
 ### Fallback mais permissivo: remove HTML e normaliza novamente. Mantém ordem
 ### original das colunas para comportamento determinístico.
  limpa_html <- function(x) {
    x <- gsub("<[^>]+>", " ", as.character(x), perl = TRUE)
    monitora_correcao_normalizar_nome_coluna(x)
  }
  attr_html <- limpa_html(atributo)
  nms_html <- limpa_html(nms)
  hit <- which(!is.na(nms_html) & nzchar(nms_html) & nms_html == attr_html)
  if (length(hit)) return(nms[hit[1L]])
  NA_character_
}


### ----------------------
### O painel funcional da não deve ser reconstruído para compensar
### efeitos colaterais do fluxo de montagem/normalização de registros_corrig.
### Esta camada atua antes do painel, no contrato estrutural do objeto entregue
### a ele: resolve chaves operacionais com critérios explícitos e audita o
### schema. Normalizações semânticas pesadas continuam no pós-painel/produtos.

monitora_publicacao_p_norm_chave <- function(x) {
  x <- enc2utf8(as.character(x))
  x[is.na(x)] <- ""
  x <- gsub("<[^>]+>", " ", x, perl = TRUE)
  x <- gsub("&quot;", " ", x, fixed = TRUE)
  x <- gsub("\"", " ", x, fixed = TRUE)
  x2 <- suppressWarnings(iconv(x, from = "", to = "ASCII//TRANSLIT"))
  x[!is.na(x2)] <- x2[!is.na(x2)]
  x <- tolower(x)
  x <- gsub("[^a-z0-9]+", "_", x, perl = TRUE)
  x <- gsub("_+", "_", x, perl = TRUE)
  gsub("^_|_$", "", x, perl = TRUE)
}

monitora_publicacao_p_coluna_texto_nao_vazia <- function(dt, col, max_n = 5000L) {
  if (is.null(dt) || !(col %in% names(dt)) || !nrow(dt)) return(character())
  v <- as.character(dt[[col]])
  v <- trimws(v)
  v <- v[!is.na(v) & nzchar(v)]
  if (length(v) > max_n) v <- v[seq_len(max_n)]
  v
}

monitora_publicacao_p_coluna_perfil_numerico <- function(dt, col, min_prop_num = 0.80, min_prop_range = 0.80, min_distintos = 2L, intervalo = c(-Inf, Inf)) {
  v <- monitora_publicacao_p_coluna_texto_nao_vazia(dt, col)
  if (!length(v)) return(FALSE)
  num <- suppressWarnings(as.numeric(gsub(",", ".", v, fixed = TRUE)))
  ok <- !is.na(num)
  if (mean(ok) < min_prop_num) return(FALSE)
  num <- num[ok]
  if (!length(num)) return(FALSE)
  prop_range <- mean(num >= intervalo[1L] & num <= intervalo[2L])
  length(unique(num)) >= min_distintos && prop_range >= min_prop_range
}

monitora_publicacao_p_coluna_perfil_ponto_amostral <- function(dt, col) {
  v <- monitora_publicacao_p_coluna_texto_nao_vazia(dt, col)
  if (!length(v)) return(FALSE)
  num <- suppressWarnings(as.numeric(gsub(",", ".", v, fixed = TRUE)))
  ok <- !is.na(num)
  if (mean(ok) < 0.80) return(FALSE)
  num <- num[ok]
  if (!length(num)) return(FALSE)
  prop_int <- mean(abs(num - round(num)) < 1e-9)
  prop_range <- mean(num >= 1 & num <= 101)
  length(unique(num)) >= 2L && prop_int >= 0.80 && prop_range >= 0.80
}

monitora_publicacao_p_coluna_perfil_ponto_metro <- function(dt, col) {
  v <- monitora_publicacao_p_coluna_texto_nao_vazia(dt, col)
  if (!length(v)) return(FALSE)
  num <- suppressWarnings(as.numeric(gsub(",", ".", v, fixed = TRUE)))
  ok <- !is.na(num)
  if (mean(ok) < 0.80) return(FALSE)
  num <- num[ok]
  if (!length(num)) return(FALSE)
  prop_range <- mean(num >= 0 & num <= 50)
  length(unique(num)) >= 2L && prop_range >= 0.80
}

monitora_publicacao_p_resolver_coluna_por_alias_e_perfil <- function(dt, aliases, incluir_regex = character(), excluir_regex = character(), perfil_fun = NULL, permitir_sem_perfil_se_vazio = TRUE) {
  nms <- names(dt)
  if (!length(nms)) return(NA_character_)
  norm <- monitora_publicacao_p_norm_chave(nms)
  aliases_norm <- monitora_publicacao_p_norm_chave(aliases)

  idx <- which(norm %in% aliases_norm)
  if (!length(idx) && length(incluir_regex)) {
    idx <- unique(unlist(lapply(incluir_regex, function(rx) grep(rx, norm, perl = TRUE))))
  }
  if (length(idx) && length(excluir_regex)) {
    excl <- Reduce(`|`, lapply(excluir_regex, function(rx) grepl(rx, norm[idx], perl = TRUE)))
    idx <- idx[!excl]
  }
  if (!length(idx)) return(NA_character_)

  if (!is.null(perfil_fun) && nrow(dt)) {
    bons <- idx[vapply(nms[idx], function(cc) isTRUE(perfil_fun(dt, cc)), logical(1))]
    if (length(bons)) return(nms[bons[1L]])
    return(NA_character_)
  }

  if (!nrow(dt) && isTRUE(permitir_sem_perfil_se_vazio)) return(nms[idx[1L]])
  nms[idx[1L]]
}

monitora_publicacao_p_resolver_coluna_ponto_amostral <- function(dt) {
  monitora_publicacao_p_resolver_coluna_por_alias_e_perfil(
    dt,
    aliases = c(
