monitora_correcao_colunas_chave <- function(dt) {
  list(
    coleta = monitora_correcao_primeira_coluna(dt, c("coleta", "id_coleta", "COLETA"), c("^coleta$", "id.*coleta")),
    coleta_uuid = monitora_correcao_primeira_coluna(dt, c("coleta_uuid", "uuid_coleta"), c("coleta.*uuid", "uuid.*coleta")),
    uuid_registro = monitora_correcao_primeira_coluna(dt, c("MONITORA_UUID_REGISTRO_CANONICO", "amostragem/registro/uuid", "uuid (amostragem/registro)", "uuid_registro", "UUID_REGISTRO"), c("registro.*uuid", "uuid.*registro")),
    ponto_amostral = monitora_publicacao_p_resolver_coluna_ponto_amostral(dt),
    ponto_metro = monitora_publicacao_p_resolver_coluna_ponto_metro(dt),
    tipo_forma_vida = monitora_correcao_primeira_coluna(dt, c("amostragem/registro/tipo_forma_vida", "tipo_forma_vida"), c("tipo.*forma.*vida", "encostam.*vareta")),
    uc = monitora_correcao_primeira_coluna(dt, c("UC", "uc", "Unidade de Conservação"), c("unidade.*conserv")),
    ea = monitora_correcao_primeira_coluna(dt, c("EA", "ea", "Estrato amostral", "estrato_amostral", "Area elegivel", "Área elegível"), c("^EA$", "estrato.*amostral", "[aá]rea.*eleg[ií]vel")),
    ano = monitora_correcao_primeira_coluna(dt, c("ANO", "ano"), c("^ano$")),
    data_hora = monitora_correcao_primeira_coluna(dt, c("Data (data_hora)", "data_hora/data", "amostragem/registro/data", "data"), c("^data \\(data_hora\\)$", "data_hora/data", "amostragem.*/data$", "^data$")),
    ciclo = monitora_correcao_primeira_coluna(dt, c("CICLO", "ciclo"), c("^ciclo$")),
    ua = monitora_correcao_primeira_coluna(dt, c("UA", "ua"), c("unidade.*amostral")),
    campanha = monitora_correcao_primeira_coluna(dt, c("CAMPANHA", "campanha"), c("campanha"))
  )
}

### Mapa canônico de colunas por papel operacional
### -------------------------------------------------------------------------
### Dados históricos misturam nomes canônicos do XLSForm e labels longos usados
### como cabeçalhos em CSVs pós-tratados. A resolução por simples grepl pode
### confundir listas principais de forma de vida com campos dependentes de hábito
### ou campos de espécie. As funções abaixo classificam explicitamente cada
### coluna antes de permitir uso no painel/correções.
monitora_correcao_tokens_forma_vida_catalogo <- function() {
  unique(c(
    "graminoide", "erva_nao_graminoide", "ervas_de_passarinho", "bromelioide", "erva_bromelioide",
    "cactacea", "orquidea", "samambaia", "arbusto_abaixo", "arbusto_acima",
    "arvore_abaixo", "arvore_acima", "bambu", "liana", "lianas", "palmeira",
    "canela_de_ema", "vela_de_ema", "outros", "outra", "desconhecida"
  ))
}

monitora_correcao_tokens_habito_catalogo <- function() {
  c("terrestre", "epifita", "epífita", "rupicola", "rupícola")
}

monitora_correcao_sinonimos_forma <- function(forma) {
  f <- monitora_correcao_normalizar_nome_coluna(forma)
  out <- switch(
    f,
    bromelioide = c("bromelioide", "bromelioides", "erva_bromelioide", "bromelia", "bromelias"),
    erva_bromelioide = c("erva_bromelioide", "bromelioide", "bromelioides", "bromelia", "bromelias"),
    cactacea = c("cactacea", "cactaceas", "cacto", "cactos"),
    orquidea = c("orquidea", "orquideas"),
    samambaia = c("samambaia", "samambaias"),
    graminoide = c("graminoide", "graminoides", "erva_graminoide"),
    erva_nao_graminoide = c("erva_nao_graminoide", "ervas_nao_graminoides", "nao_graminoide"),
    arbusto_abaixo = c("arbusto_abaixo", "arbustos_abaixo", "arbusto_inferior", "arbustos_inferior"),
    arbusto_acima = c("arbusto_acima", "arbustos_acima", "arbusto_superior", "arbustos_superior"),
    arvore_abaixo = c("arvore_abaixo", "arvores_abaixo", "arvore_menor"),
    arvore_acima = c("arvore_acima", "arvores_acima", "arvore_maior"),
    lianas = c("liana", "lianas"),
    f
  )
  unique(monitora_correcao_normalizar_nome_coluna(out))
}

monitora_correcao_categoria_coluna_canonica <- function(col) {
  z <- monitora_correcao_normalizar_nome_coluna(col)
  out <- rep(NA_character_, length(z))
  out[grepl("nativ", z)] <- "nativa"
  out[grepl("exotic|exotica|exotico", z)] <- "exotica"
  out[grepl("seca_morta|seca_e_morta|secas_ou_mortas|morta", z)] <- "seca_morta"
  out[z %in% c("amostragem_registro_forma_vida_outros", "forma_vida_outros")] <- "outra_forma_vida"
  out
}


monitora_correcao_papel_coluna_canonico <- function(cols) {
  cols <- as.character(cols)
  z <- monitora_correcao_normalizar_nome_coluna(cols)
  out <- rep("outro", length(cols))
  out[monitora_correcao_coluna_protegida(cols)] <- "protegida"

  eh_tipo <- grepl("(^|_)tipo_forma_vida($|_)", z) | grepl("encostam.*vareta", z)
  out[eh_tipo & out != "protegida"] <- "campo_superior_tipo_forma_vida"

  eh_foto <- grepl("foto|imagem|image", z)
  out[eh_foto & out == "outro"] <- "imagem_foto"

 ### Campos de espécie/nome popular: incluem campos fechados e campos abertos
 ### "outra sp". Estes campos nunca podem receber tokens de forma de vida.
  eh_especie <- grepl("(^|_)especies(_|$)|(^|_)especie(_|$)|nome_popular|outra_sp|_sp($|_)", z) |
    grepl("especies_de|outra_especie|outra_especie_de|especie_ou_nome_popular", z)
  out[eh_especie & out == "outro"] <- "especie_nome_popular"

 ### Listas principais de formas de vida: só aceitamos os campos-pai, nunca
 ### campos de espécie, foto, atributos condicionais ou campos "outra espécie".
  eh_lista_nativa <- z %in% c("amostragem_registro_forma_vida_nativa", "forma_vida_nativa") |
    (grepl("formas_de_vida_de_plantas", z) & grepl("nativ", z) & !grepl("especie|popular|foto|imagem|desconhecida|outra_especie", z))
  eh_lista_exotica <- z %in% c("amostragem_registro_forma_vida_exotica", "forma_vida_exotica") |
    (grepl("formas_de_vida_de_plantas", z) & grepl("exotic|exotica|exotico", z) & !grepl("especie|popular|foto|imagem|desconhecida|outra_especie", z))
  eh_lista_seca <- z %in% c("amostragem_registro_forma_vida_seca_morta", "forma_vida_seca_morta") |
    (grepl("formas_de_vida_de_plantas", z) & grepl("seca|morta", z) & !grepl("especie|popular|foto|imagem|desconhecida|outra_especie", z))
  eh_lista_outros <- z %in% c("amostragem_registro_forma_vida_outros", "forma_vida_outros")
  out[(eh_lista_nativa | eh_lista_exotica | eh_lista_seca | eh_lista_outros) & out == "outro"] <- "lista_principal_forma_vida"

  formas_cond <- c("bromelioide", "erva_bromelioide", "cactacea", "orquidea", "samambaia")
  forma_pat <- paste(formas_cond, collapse = "|")
  eh_dependente_nome <- grepl(paste0("(^|_)forma_vida_(nativa|exotica|seca_morta)_", "(", forma_pat, ")$"), z)
  eh_dependente_label <- (grepl("observad|selecione", z) & grepl(forma_pat, z))
  out[(eh_dependente_nome | eh_dependente_label) & out == "outro"] <- "atributo_dependente_habito"

  out
}

monitora_correcao_token_associado_coluna <- function(cols) {
  cols <- as.character(cols)
  z <- monitora_correcao_normalizar_nome_coluna(cols)
  tokens <- monitora_correcao_tokens_forma_vida_catalogo()
  out <- rep(NA_character_, length(cols))
  for (tok in tokens) {
    sins <- monitora_correcao_sinonimos_forma(tok)
    hit <- rep(FALSE, length(z))
    for (ss in sins) hit <- hit | grepl(paste0("(^|_)", ss, "($|_)"), z)
    out[is.na(out) & hit] <- tok
  }
 ### rótulos históricos nem sempre preservam o `name` XLSForm no nome
 ### físico da coluna. Estes padrões são inequívocos e distinguem os pares de
 ### altura/diâmetro sem recorrer a substring aproximada ou posição da coluna.
  out[is.na(out) & grepl("arvore", z) & grepl("(menor_que_5|abaixo_de_5|abaixo.*5cm|menor.*5cm)", z)] <- "arvore_abaixo"
  out[is.na(out) & grepl("arvore", z) & grepl("(igual_ou_maior_que_5|acima_de_5|acima.*5cm|maior.*5cm)", z)] <- "arvore_acima"
  out[is.na(out) & grepl("arbusto", z) & grepl("(inferior_a_50|abaixo.*50|abaixo.*0_5|inferior.*0_5)", z)] <- "arbusto_abaixo"
  out[is.na(out) & grepl("arbusto", z) & grepl("(igual_ou_superior_a_50|acima.*50|acima.*0_5|superior.*0_5)", z)] <- "arbusto_acima"
  out[is.na(out) & grepl("bambu|taquara", z)] <- "bambu"
  out[is.na(out) & grepl("liana|cipo|trepadeira", z)] <- "lianas"
  out[is.na(out) & grepl("palmeira", z)] <- "palmeira"
  out[is.na(out) & grepl("erva_de_passarinho|hemiparasita", z)] <- "ervas_de_passarinho"
  out
}

if (!exists(".MONITORA_MAPA_COLUNAS_CANONICAS_CACHE", inherits = FALSE)) {
  .MONITORA_MAPA_COLUNAS_CANONICAS_CACHE <- new.env(parent = emptyenv())
}

monitora_correcao_mapa_colunas_cache_key <- function(dt, contexto = "estrutura") {
  nms <- names(dt)
  bruto <- paste0(length(nms), "::", paste(nms, collapse = "\r"))
  if (requireNamespace("digest", quietly = TRUE)) {
    h <- digest::digest(bruto, algo = "xxhash64")
  } else {
    rr <- as.integer(charToRaw(bruto))
    h <- sprintf("%08x", sum(rr * seq_along(rr)) %% .Machine$integer.max)
  }
  paste0("mapa_", contexto, "_", h)
}

monitora_correcao_mapa_colunas_estrutura <- function(dt) {
  dt <- data.table::as.data.table(dt)
  nms <- names(dt)
  mapa <- data.table::data.table(
    coluna_registros_corrig = nms,
    coluna_norm = monitora_correcao_normalizar_nome_coluna(nms),
    papel_coluna = monitora_correcao_papel_coluna_canonico(nms),
    categoria = monitora_correcao_categoria_coluna_canonica(nms),
    token_associado = monitora_correcao_token_associado_coluna(nms),
    n_preenchidos = NA_integer_
  )
  mapa[, painel_editavel_seguro := papel_coluna %in% c("lista_principal_forma_vida", "atributo_dependente_habito", "especie_nome_popular", "campo_superior_tipo_forma_vida", "outro") & !monitora_correcao_coluna_protegida(coluna_registros_corrig)]
  mapa[, observacao := data.table::fifelse(papel_coluna == "protegida", "coluna estrutural protegida",
                        data.table::fifelse(papel_coluna == "lista_principal_forma_vida", "lista principal de tokens de forma de vida",
                        data.table::fifelse(papel_coluna == "atributo_dependente_habito", "campo dependente/hábito de forma condicional",
                        data.table::fifelse(papel_coluna == "especie_nome_popular", "campo de espécie/nome popular; não receber tokens de forma de vida", ""))))]
  mapa[]
}

monitora_correcao_mapa_colunas_canonicas <- function(dt, meta_xls = NULL, contexto = "mapa_colunas", gravar = FALSE, incluir_preenchidos = isTRUE(gravar), usar_cache = TRUE) {
  dt <- data.table::as.data.table(dt)
  if (isTRUE(usar_cache)) {
    key <- monitora_correcao_mapa_colunas_cache_key(dt, "estrutura")
    mapa_cache <- tryCatch(get(key, envir = .MONITORA_MAPA_COLUNAS_CANONICAS_CACHE, inherits = FALSE), error = function(e) NULL)
    if (is.null(mapa_cache)) {
      mapa_cache <- monitora_correcao_mapa_colunas_estrutura(dt)
      try(assign(key, mapa_cache, envir = .MONITORA_MAPA_COLUNAS_CANONICAS_CACHE), silent = TRUE)
    }
    mapa <- data.table::copy(mapa_cache)
  } else {
    mapa <- monitora_correcao_mapa_colunas_estrutura(dt)
  }
  if (isTRUE(incluir_preenchidos)) {
    vals_n <- vapply(dt, function(x) sum(!is.na(x) & nzchar(trimws(as.character(x)))), integer(1))
    mapa[, n_preenchidos := as.integer(vals_n[coluna_registros_corrig])]
  }
  if (isTRUE(gravar)) {
    base_dir <- if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) get("MONITORA_CORRECOES_DIR", inherits = TRUE) else file.path("output", "correcoes_campos")
    dir.create(base_dir, recursive = TRUE, showWarnings = FALSE)
    arq <- file.path(base_dir, paste0("auditoria_mapa_colunas_canonicas_", contexto, ".csv"))
    try(monitora_fwrite(mapa, arq, na = ""), silent = TRUE)
    try(monitora_fwrite(mapa, file.path(base_dir, "auditoria_mapa_colunas_canonicas_ultima_execucao.csv"), na = ""), silent = TRUE)
  }
  mapa[]
}

monitora_correcao_mapa_linha <- function(dt, col, mapa = NULL) {
  if (is.null(mapa)) mapa <- monitora_correcao_mapa_colunas_canonicas(dt)
  mapa[coluna_registros_corrig == col]
}

### Registro operacional derivado do contrato único ---------------------------------
###
### As categorias que podem participar de movimentos não são mantidas em uma
### tabela paralela. Elas são projetadas, uma única vez por processo, dos campos
### select_multiple do XLSForm 21FEV25 cuja relevance depende de
### tipo_forma_vida. Assim, forma_vida_outros/forma_vida_outros e o token pai
### outra_forma_vida entram no mesmo motor das demais categorias sem duplicar a
### autoridade contratual. O cache evita reconstrução em cada invalidação Shiny.
if (!exists(".MONITORA_CONTRATO_MOVIMENTO_CACHE", inherits = FALSE)) {
  .MONITORA_CONTRATO_MOVIMENTO_CACHE <- new.env(parent = emptyenv())
}

monitora_contrato_categorias_movimento <- function(forcar = FALSE) {
  if (isTRUE(forcar)) {
    chaves_cache <- ls(envir = .MONITORA_CONTRATO_MOVIMENTO_CACHE, all.names = TRUE)
    if (length(chaves_cache)) rm(list = chaves_cache, envir = .MONITORA_CONTRATO_MOVIMENTO_CACHE)
  }
  if (!isTRUE(forcar) && exists("categorias", envir = .MONITORA_CONTRATO_MOVIMENTO_CACHE, inherits = FALSE)) {
    return(data.table::copy(get("categorias", envir = .MONITORA_CONTRATO_MOVIMENTO_CACHE, inherits = FALSE)))
  }
  if (!exists("monitora_contrato_unico_indices_cache", mode = "function")) {
    stop("Contrato único ainda não está disponível para resolver categorias de movimento.", call. = FALSE)
  }
  cu <- monitora_contrato_unico_indices_cache()
  attrs <- data.table::copy(data.table::as.data.table(cu$indices$por_atributo_canonico))
  obrig <- c("caminho_registro", "name_curto", "label_2025_sem_html", "tipo_base", "list_name", "relevant")
  faltam <- setdiff(obrig, names(attrs))
  if (length(faltam)) stop("Contrato único incompleto para movimentos: ", paste(faltam, collapse = ", "), call. = FALSE)
  cand <- attrs[
    tipo_base == "select_multiple" &
      grepl("tipo_forma_vida", relevant, fixed = TRUE) &
      grepl("^forma_vida_", list_name)
  ]
  cand[, categoria := sub(
    ".*selected\\(\\$\\{tipo_forma_vida\\},\\s*['\"]([^'\"]+)['\"].*",
    "\\1", as.character(relevant), perl = TRUE
  )]
  cand <- cand[categoria %in% c("nativa", "exotica", "seca_morta", "outra_forma_vida")]
  choices_21 <- data.table::copy(data.table::as.data.table(cu$indices$por_choice_name))
  if ("arquivo_xlsform" %in% names(choices_21)) {
    choices_21 <- choices_21[grepl("21FEV25", as.character(arquivo_xlsform), ignore.case = TRUE)]
  } else {
    choices_21 <- choices_21[0]
  }
  cand[, admite_desconhecida := vapply(list_name, function(lista) {
    toks <- as.character(choices_21[list_name == lista, name])
    any(monitora_correcao_normalizar_nome_coluna(toks) %in% c("desconhecida", "desconhecido"))
  }, logical(1))]
  cand[, admite_habito := vapply(name_curto, function(parent_name) {
    rels <- as.character(attrs$relevant)
    any(attrs$tipo_base == "select_one" & grepl(paste0("${", parent_name, "}"), rels, fixed = TRUE), na.rm = TRUE)
  }, logical(1))]
  cand <- unique(cand[, .(
    token_pai = as.character(categoria),
    caminho_registro = as.character(caminho_registro),
    name_curto = as.character(name_curto),
    list_name = as.character(list_name),
    label = as.character(label_2025_sem_html),
    admite_desconhecida = as.logical(admite_desconhecida),
    admite_habito = as.logical(admite_habito)
  ), by = .(categoria)], by = "categoria")
  esperadas <- c("nativa", "exotica", "seca_morta", "outra_forma_vida")
  if (!setequal(cand$categoria, esperadas) || anyDuplicated(cand$categoria)) {
    stop("Contrato único não resolveu exatamente as quatro categorias de movimento esperadas do XLSForm 21FEV25.", call. = FALSE)
  }
  cand[, .ordem_categoria := match(categoria, esperadas)]
  data.table::setorder(cand, .ordem_categoria)
  cand[, .ordem_categoria := NULL]
  assign("categorias", cand[], envir = .MONITORA_CONTRATO_MOVIMENTO_CACHE)
  data.table::copy(cand[])
}

monitora_contrato_tokens_categoria_movimento <- function(categoria) {
  categoria_alvo <- tolower(trimws(as.character(categoria)[1L]))
  chave_cache <- paste0("tokens_", categoria_alvo)
  if (exists(chave_cache, envir = .MONITORA_CONTRATO_MOVIMENTO_CACHE, inherits = FALSE)) {
    return(get(chave_cache, envir = .MONITORA_CONTRATO_MOVIMENTO_CACHE, inherits = FALSE))
  }
  info <- monitora_contrato_categorias_movimento()[categoria == categoria_alvo]
  if (nrow(info) != 1L) return(character(0))
  cu <- monitora_contrato_unico_indices_cache()
  choices <- data.table::as.data.table(cu$indices$por_choice_name)
  if (!nrow(choices) || !all(c("list_name", "name") %in% names(choices))) return(character(0))
  if (!("arquivo_xlsform" %in% names(choices))) return(character(0))
  choices <- choices[grepl("21FEV25", as.character(arquivo_xlsform), ignore.case = TRUE)]
  out <- unique(as.character(choices[list_name == info$list_name[1L] & !is.na(name) & nzchar(as.character(name)), name]))
  assign(chave_cache, out, envir = .MONITORA_CONTRATO_MOVIMENTO_CACHE)
  out
}

### Projeta no dicionário de edição os metadados das listas principais sem
### reconstruir list_name por convenção textual. Em particular,
### outra_forma_vida é armazenada no XLSForm 21FEV25 como forma_vida_outros;
### portanto paste0("forma_vida_", categoria) criava um contrato paralelo e
### bloqueava operações válidas no backend.
monitora_contrato_aplicar_metadados_categorias_movimento <- function(d) {
  d <- data.table::as.data.table(d)
 ### O dicionário também é reconstruído sem meta_xls explícito durante a
 ### pré-validação transacional. Nessa fase as colunas de metadados podem ainda
 ### não existir; criá-las aqui preserva a projeção contratual e evita que a
 ### expressão data.table seguinte procure um símbolo xlsform_name ausente.
  obrig_base <- c("papel_coluna", "categoria_coluna")
  if (!all(obrig_base %in% names(d)) || !nrow(d)) return(d)
  if (!("xlsform_name" %in% names(d))) d[, xlsform_name := NA_character_]
  if (!("xlsform_list_name" %in% names(d))) d[, xlsform_list_name := NA_character_]
  info <- monitora_contrato_categorias_movimento()
  idx_info <- match(as.character(d$categoria_coluna), as.character(info$categoria))
  idx <- which(
    as.character(d$papel_coluna) == "lista_principal_forma_vida" &
      !is.na(idx_info)
  )
  if (length(idx)) {
    data.table::set(d, i = idx, j = "xlsform_name", value = as.character(info$name_curto[idx_info[idx]]))
    data.table::set(d, i = idx, j = "xlsform_list_name", value = as.character(info$list_name[idx_info[idx]]))
  }
  d[]
}

monitora_correcao_coluna_forma_vida <- function(dt, categoria) {
  cat_val <- tolower(as.character(categoria)[1L])
  info <- tryCatch(monitora_contrato_categorias_movimento()[categoria == cat_val], error = function(e) data.table::data.table())
  if (nrow(info) != 1L) return(NA_character_)
  if (is.null(dt) || !length(names(dt))) return(NA_character_)
  mapa <- monitora_correcao_mapa_colunas_canonicas(dt)
  cand <- mapa[papel_coluna == "lista_principal_forma_vida" & categoria == cat_val]
  if (!nrow(cand)) return(NA_character_)
  cand[, score := 0L]
  caminho_norm <- monitora_correcao_normalizar_nome_coluna(info$caminho_registro[1L])
  name_norm <- monitora_correcao_normalizar_nome_coluna(info$name_curto[1L])
  cand[coluna_norm == caminho_norm, score := score + 600L]
  cand[coluna_norm == name_norm, score := score + 550L]
  cand[grepl("formas_de_vida_de_plantas", coluna_norm), score := score + 450L]
  cand[grepl("amostragem_registro", coluna_norm), score := score + 50L]
  data.table::setorder(cand, -score, coluna_registros_corrig)
  cand$coluna_registros_corrig[1L]
}

monitora_correcao_colunas_forma_vida_principais <- function(dt) {
  cats <- tryCatch(monitora_contrato_categorias_movimento()$categoria, error = function(e) character(0))
  unique(na.omit(unlist(lapply(cats, function(cat) monitora_correcao_colunas_forma_vida_categoria(dt, cat)), use.names = FALSE)))
}

monitora_correcao_colunas_forma_vida_categoria <- function(dt, categoria) {
  cat_val <- tolower(as.character(categoria)[1L])
  info <- tryCatch(monitora_contrato_categorias_movimento()[categoria == cat_val], error = function(e) data.table::data.table())
  if (nrow(info) != 1L || is.null(dt) || !length(names(dt))) return(character(0))
  mapa <- monitora_correcao_mapa_colunas_canonicas(dt)
  cand <- mapa[papel_coluna == "lista_principal_forma_vida" & categoria == cat_val]
  if (!nrow(cand)) return(character(0))
  cand[, score := 0L]
  caminho_norm <- monitora_correcao_normalizar_nome_coluna(info$caminho_registro[1L])
  name_norm <- monitora_correcao_normalizar_nome_coluna(info$name_curto[1L])
  cand[coluna_norm == caminho_norm, score := score + 600L]
  cand[coluna_norm == name_norm, score := score + 550L]
  cand[grepl("formas_de_vida_de_plantas", coluna_norm), score := score + 450L]
  cand[grepl("amostragem_registro", coluna_norm), score := score + 50L]
  data.table::setorder(cand, -score, coluna_registros_corrig)
  unique(cand$coluna_registros_corrig)
}

monitora_correcao_coluna_principal_segura <- function(dt, col, categoria = NA_character_) {
  if (is.na(col) || !nzchar(col) || !(col %in% names(dt))) return(FALSE)
  mapa <- monitora_correcao_mapa_colunas_canonicas(dt)
  r <- mapa[coluna_registros_corrig == col]
  if (!nrow(r)) return(FALSE)
  isTRUE(r$papel_coluna[1L] == "lista_principal_forma_vida" && (is.na(categoria) || !nzchar(categoria) || r$categoria[1L] == categoria))
}

monitora_correcao_resolver_coluna_especie_exotica <- function(dt, forma, meta_xls = NULL) {
  if (is.null(dt) || !length(names(dt))) return(NA_character_)
  forma_norm <- monitora_correcao_normalizar_nome_coluna(forma)
  mapa <- monitora_correcao_mapa_colunas_canonicas(dt)
  cand <- mapa[papel_coluna == "especie_nome_popular" & (categoria == "exotica" | grepl("exotic|exotica|exotico", coluna_norm))]
  if (!nrow(cand)) return(NA_character_)
  sins <- monitora_correcao_sinonimos_forma(forma_norm)
  cand[, score := 0L]
  for (ss in sins) cand[grepl(paste0("(^|_)", ss, "($|_)"), coluna_norm), score := score + 200L]
  cand[grepl("(^|_)especies_exotica(_|$)|especies_de", coluna_norm), score := score + 80L]
  cand[grepl("outra_sp|outra_especie", coluna_norm), score := score + 40L]
  cand <- cand[score > 0L]
  if (!nrow(cand)) return(NA_character_)
  data.table::setorder(cand, -score, coluna_registros_corrig)
  cand$coluna_registros_corrig[1L]
}

monitora_correcao_colunas_especie_exotica_por_forma <- function(dt, forma, mapa = NULL) {
  if (is.null(mapa)) mapa <- monitora_correcao_mapa_colunas_canonicas(dt)
  forma_norm <- monitora_correcao_normalizar_nome_coluna(forma)
  sins <- monitora_correcao_sinonimos_forma(forma_norm)
  cand <- mapa[papel_coluna == "especie_nome_popular" & (categoria == "exotica" | grepl("exotic|exotica|exotico", coluna_norm))]
  if (!nrow(cand)) return(character(0))
  hit <- rep(FALSE, nrow(cand))
  for (ss in sins) hit <- hit | grepl(paste0("(^|_)", ss, "($|_)"), cand$coluna_norm)
  cols <- cand[hit, coluna_registros_corrig]
  unique(cols[!is.na(cols) & nzchar(cols) & cols %in% names(dt)])
}

monitora_correcao_colunas_dependentes_por_token <- function(dt, categoria, token, meta_xls = NULL) {
  if (is.null(dt) || !length(names(dt))) return(character(0))
  cat_val <- as.character(categoria)[1L]
  token <- as.character(token)[1L]
  mapa <- monitora_correcao_mapa_colunas_canonicas(dt)
  sins <- monitora_correcao_sinonimos_forma(token)
  hit <- rep(FALSE, nrow(mapa))
  for (ss in sins) hit <- hit | grepl(paste0("(^|_)", ss, "($|_)"), mapa$coluna_norm)
  if ("token_associado" %in% names(mapa)) {
    token_mapa <- monitora_correcao_normalizar_nome_coluna(mapa$token_associado)
    token_alvo <- unique(monitora_correcao_normalizar_nome_coluna(c(token, sins)))
    hit <- hit | (!is.na(token_mapa) & token_mapa %in% token_alvo)
  }
  roles <- c("atributo_dependente_habito", "especie_nome_popular")
  cols <- mapa[hit & papel_coluna %in% roles & (is.na(cat_val) | !nzchar(cat_val) | categoria == cat_val | is.na(categoria)), coluna_registros_corrig]
  unique(cols[!is.na(cols) & nzchar(cols) & cols %in% names(dt) & !monitora_correcao_coluna_protegida(cols)])
}


### Segurança de integridade para correções assistidas
### Estas colunas são estruturais/rastreamento e nunca devem ser alteradas
### por painel, correção manual, recálculo XLSForm ou ações automáticas.
if (!exists("MONITORA_CORRECAO_COLUNAS_PROTEGIDAS", inherits = FALSE)) {
  MONITORA_CORRECAO_COLUNAS_PROTEGIDAS <- unique(c(
    ".id", "id", "ID", "uuid", "UUID", "uuid_registro", "UUID_REGISTRO",
    "coleta_uuid", "COLETA_UUID", "COLETA", "PROTOCOLO", "arquivo_origem",
    "linha_indice", "linha_origem", "linha_origem_registros_corrig",
    "ordem_linha_original", "arquivo_fonte", "source_file",
    "MONITORA_HABITOS_CANONICOS_PRESERVADOS",
    "ANO", "DATA_MONITORA_PARSEADA", "num_placa_formatado",
    "DATA DO REGISTRO", "DATA DO RECEBIMENTO", "ULTIMA EDICAO", "data_do_registro", "data_do_recebimento", "ultima_edicao"
  ))
}

monitora_correcao_coluna_protegida <- function(cols) {
  cols <- as.character(cols)
  prot <- as.character(MONITORA_CORRECAO_COLUNAS_PROTEGIDAS)
  prot_norm <- tolower(monitora_correcao_normalizar_nome_coluna(prot))
  cols_norm <- tolower(monitora_correcao_normalizar_nome_coluna(cols))
  (!is.na(cols) & nzchar(cols) & (cols %in% prot | tolower(cols) %in% tolower(prot) | cols_norm %in% prot_norm))
}

monitora_correcao_colunas_protegidas_existentes <- function(dt) {
  nms <- names(dt)
  nms[monitora_correcao_coluna_protegida(nms)]
}

monitora_correcao_filtrar_colunas_seguras <- function(cols, dt = NULL) {
  cols <- unique(as.character(cols))
  cols <- cols[!is.na(cols) & nzchar(cols)]
  if (!is.null(dt)) cols <- cols[cols %in% names(dt)]
  cols[!monitora_correcao_coluna_protegida(cols)]
}

monitora_correcao_snapshot_colunas_protegidas <- function(dt) {
  dt <- data.table::as.data.table(dt)
  cols <- monitora_correcao_colunas_protegidas_existentes(dt)
  if (!length(cols)) return(data.table::data.table(.linha_monitora = integer()))
  out <- data.table::copy(dt[, cols, with = FALSE])
  out[, .linha_monitora := seq_len(.N)]
  data.table::setcolorder(out, c(".linha_monitora", cols))
  out[]
}

monitora_correcao_diferenca_derivado_data_autorizada <- function(col, idx, depois) {
 ### ANO e DATA_MONITORA_PARSEADA são colunas protegidas contra edição direta,
 ### mas podem mudar por recálculo autorizado após correção de Data (data_hora).
 ### Esta função libera apenas diferenças em que o valor final esteja exatamente
 ### coerente com a data atual do registro; qualquer divergência continua bloqueada.
  col <- as.character(col)[1L]
  if (is.na(col) || !nzchar(col) || !length(idx) || is.null(depois) || !(col %in% names(depois))) {
    return(rep(FALSE, length(idx)))
  }
  col_norm <- tolower(monitora_correcao_normalizar_nome_coluna(col))
  if (!(col_norm %in% c("ano", "data_monitora_parseada"))) return(rep(FALSE, length(idx)))

  chaves <- tryCatch(monitora_correcao_colunas_chave(depois), error = function(e) list(data_hora = NA_character_))
  data_col <- if (!is.null(chaves$data_hora) && !is.na(chaves$data_hora) && nzchar(chaves$data_hora) && chaves$data_hora %in% names(depois)) chaves$data_hora else NA_character_
  if (is.na(data_col) || !nzchar(data_col)) return(rep(FALSE, length(idx)))

  data_calc <- tryCatch(monitora_data_parsear(depois[[data_col]]), error = function(e) rep(as.IDate(NA), nrow(depois)))
  idx <- as.integer(idx)
  idx <- idx[!is.na(idx) & idx >= 1L & idx <= nrow(depois)]
  if (!length(idx)) return(logical(0))

  atual <- as.character(depois[[col]][idx])
  atual[is.na(atual)] <- ""

  if (identical(col_norm, "ano")) {
    esperado <- as.character(lubridate::year(data_calc[idx]))
  } else {
    esperado <- as.character(data_calc[idx])
  }
  esperado[is.na(esperado)] <- ""
  ok <- atual == esperado
  ok[is.na(ok)] <- FALSE
  ok
}

monitora_correcao_auditar_colunas_protegidas <- function(snapshot_antes, dt_depois, contexto = "pos_correcoes", abortar = TRUE) {
  antes <- data.table::as.data.table(snapshot_antes)
  depois <- data.table::as.data.table(dt_depois)
  cols <- intersect(setdiff(names(antes), ".linha_monitora"), names(depois))
 ### Para auditoria queremos justamente as colunas protegidas presentes no snapshot.
  if (!length(cols) || nrow(antes) != nrow(depois)) return(data.table::data.table())

  out <- vector("list", length(cols))
  out_ok <- vector("list", length(cols))
  for (ii in seq_along(cols)) {
    cc <- cols[ii]
    a <- as.character(antes[[cc]])
    b <- as.character(depois[[cc]])
    a[is.na(a)] <- ""
    b[is.na(b)] <- ""
    idx <- which(a != b)
    if (length(idx)) {
      autorizada <- monitora_correcao_diferenca_derivado_data_autorizada(cc, idx, depois)
      if (length(autorizada) != length(idx)) autorizada <- rep(FALSE, length(idx))
      autorizada[is.na(autorizada)] <- FALSE

      idx_ok <- idx[autorizada]
      if (length(idx_ok)) {
        out_ok[[ii]] <- data.table::data.table(
          contexto = contexto,
          coluna_protegida = cc,
          linha_indice = idx_ok,
          valor_antes = as.character(antes[[cc]][idx_ok]),
          valor_depois = as.character(depois[[cc]][idx_ok]),
          autorizacao = "recalculo_derivado_de_Data_data_hora"
        )
      }

      idx_erro <- idx[!autorizada]
      if (length(idx_erro)) {
        out[[ii]] <- data.table::data.table(
          contexto = contexto,
          coluna_protegida = cc,
          linha_indice = idx_erro,
          valor_antes = as.character(antes[[cc]][idx_erro]),
          valor_depois = as.character(depois[[cc]][idx_erro])
        )
      }
    }
  }
  out <- out[!vapply(out, is.null, logical(1))]
  out_ok <- out_ok[!vapply(out_ok, is.null, logical(1))]
  res <- if (length(out)) data.table::rbindlist(out, fill = TRUE, use.names = TRUE) else data.table::data.table(
    contexto = character(), coluna_protegida = character(), linha_indice = integer(), valor_antes = character(), valor_depois = character()
  )
  res_ok <- if (length(out_ok)) data.table::rbindlist(out_ok, fill = TRUE, use.names = TRUE) else data.table::data.table(
    contexto = character(), coluna_protegida = character(), linha_indice = integer(), valor_antes = character(), valor_depois = character(), autorizacao = character()
  )

  base_dir <- if (exists("MONITORA_CORRECOES_DIR", inherits = FALSE)) MONITORA_CORRECOES_DIR else "output/correcoes_campos"
  arq <- file.path(base_dir, paste0("auditoria_colunas_protegidas_", contexto, ".csv"))
  arq_ok <- file.path(base_dir, paste0("auditoria_colunas_protegidas_recalculo_autorizado_", contexto, ".csv"))
  dir.create(dirname(arq), showWarnings = FALSE, recursive = TRUE)
  monitora_fwrite(res, arq, na = "")
  if (nrow(res_ok)) monitora_fwrite(res_ok, arq_ok, na = "")

  if (nrow(res_ok) && exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento(
      "colunas_protegidas",
      "INFO",
      arq_ok,
      paste0(nrow(res_ok), " alteração(ões) autorizada(s) em derivado(s) protegido(s) de Data (data_hora)"),
      "recalculo controlado de DATA_MONITORA_PARSEADA/ANO"
    )
  }

  if (nrow(res)) {
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("colunas_protegidas", "ERRO", arq, paste0(nrow(res), " alteração(ões) indevida(s) em coluna(s) protegida(s)"), "execução bloqueada para preservar integridade")
    }
    if (isTRUE(abortar)) {
      stop(paste0("Integridade violada: ", nrow(res), " alteração(ões) em coluna(s) protegida(s). Ver ", arq), call. = FALSE)
    }
  } else if (exists("monitora_log_registrar_evento", mode = "function")) {
    detalhe <- if (nrow(res_ok)) "Nenhuma alteração indevida; recálculos autorizados registrados em auditoria própria" else "Nenhuma alteração em colunas protegidas após correções"
    monitora_log_registrar_evento("colunas_protegidas", "INFO", arq, detalhe, "OK")
  }
  res[]
}


### Valida se uma coluna pode receber hábito/atributo dependente de forma de vida
### condicional. Ela nunca pode ser a própria lista principal de formas de vida
### (nativa/exótica/seca_morta) nem coluna estrutural. Essa trava evita corrupção
### semântica como gravar "terrestre" dentro da lista de formas nativas.
monitora_correcao_coluna_eh_lista_principal_forma_vida <- function(dt, col) {
  if (is.na(col) || !nzchar(col) || is.null(dt) || !(col %in% names(dt))) return(FALSE)
  papel <- monitora_correcao_papel_coluna_canonico(col)
  papel %in% c("lista_principal_forma_vida", "campo_superior_tipo_forma_vida")
}

monitora_correcao_coluna_habito_segura <- function(dt, col, categoria = NA_character_, forma = NA_character_) {
  if (is.na(col) || !nzchar(col) || is.null(dt) || !(col %in% names(dt))) return(FALSE)
  if (monitora_correcao_coluna_protegida(col)) return(FALSE)
  papel <- monitora_correcao_papel_coluna_canonico(col)
  norm <- monitora_correcao_normalizar_nome_coluna(col)
  forma_norm <- monitora_correcao_normalizar_nome_coluna(forma)
  sinonimos <- monitora_correcao_sinonimos_forma(forma_norm)
  sinonimos <- sinonimos[!is.na(sinonimos) & nzchar(sinonimos)]
  if (length(sinonimos) && !any(vapply(sinonimos, function(ff) grepl(paste0("(^|_)", ff, "($|_)"), norm), logical(1)))) return(FALSE)
  if (identical(papel, "atributo_dependente_habito")) return(TRUE)
 ### Rótulos físicos do template podem não conter a categoria no texto
 ### (nativa sem sufixo; exótica/seca-morta com.1/.2). Eles são seguros
 ### quando — e somente quando — o resolvedor de publicação do caminho
 ### categoria×forma aponta exatamente para essa coluna. Não se usa conteúdo
 ### observado nem heurística de preenchimento.
  regra <- tryCatch(monitora_correcao_regra_habito_contrato_atual(categoria, forma), error = function(e) data.table::data.table())
  if (nrow(regra) == 1L && exists("monitora_validados_resolver_coluna", mode = "function")) {
    fisica <- tryCatch(monitora_validados_resolver_coluna(names(dt), regra$atributo_canonico[1L]), error = function(e) NA_character_)
    if (!is.na(fisica) && identical(as.character(fisica), as.character(col)) &&
        !grepl("especie|esp[eé]cie|nome_popular|foto|imagem", norm, ignore.case = TRUE)) return(TRUE)
  }
  FALSE
}

monitora_correcao_auditar_formas_vida_semantica <- function(dt, contexto = "pos_correcoes", abortar = TRUE) {
  dt <- data.table::as.data.table(dt)
  cols <- unique(c(
    tryCatch(monitora_correcao_coluna_forma_vida(dt, "nativa"), error = function(e) NA_character_),
    tryCatch(monitora_correcao_coluna_forma_vida(dt, "exotica"), error = function(e) NA_character_),
    tryCatch(monitora_correcao_coluna_forma_vida(dt, "seca_morta"), error = function(e) NA_character_)
  ))
  cols <- cols[!is.na(cols) & nzchar(cols) & cols %in% names(dt)]
  if (!length(cols)) {
    res <- data.table::data.table(contexto = character(), coluna = character(), linha_indice = integer(), token_invalido = character(), valor = character())
  } else {
    tokens_habito <- c("terrestre", "epifita", "epífita", "rupicola", "rupícola")
    out <- vector("list", length(cols))
    for (ii in seq_along(cols)) {
      cc <- cols[ii]
      vals <- as.character(dt[[cc]])
      norm_vals <- monitora_correcao_limpar_texto(vals)
      achados <- vector("list", length(tokens_habito))
      for (jj in seq_along(tokens_habito)) {
        tok <- monitora_correcao_limpar_texto(tokens_habito[jj])
        idx <- which(monitora_correcao_token_presente_vec(norm_vals, tok))
        if (length(idx)) {
          achados[[jj]] <- data.table::data.table(
            contexto = contexto,
            coluna = cc,
            linha_indice = idx,
            token_invalido = tok,
            valor = vals[idx]
          )
        }
      }
      achados <- achados[!vapply(achados, is.null, logical(1))]
      if (length(achados)) out[[ii]] <- data.table::rbindlist(achados, fill = TRUE, use.names = TRUE)
    }
    out <- out[!vapply(out, is.null, logical(1))]
    res <- if (length(out)) data.table::rbindlist(out, fill = TRUE, use.names = TRUE) else data.table::data.table(
      contexto = character(), coluna = character(), linha_indice = integer(), token_invalido = character(), valor = character()
    )
  }
  arq <- file.path(if (exists("MONITORA_CORRECOES_DIR", inherits = FALSE)) MONITORA_CORRECOES_DIR else "output/correcoes_campos",
                   paste0("auditoria_semantica_formas_vida_", contexto, ".csv"))
  monitora_fwrite(res, arq, na = "")
  if (nrow(res)) {
    msg <- paste0(nrow(res), " ocorrência(s) de token de hábito em coluna principal de forma de vida. Ver ", arq)
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("auditoria_semantica_formas_vida", "ERRO", arq, msg, "execução bloqueada para preservar integridade semântica")
    }
    if (isTRUE(abortar)) stop(msg, call. = FALSE)
  } else if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento("auditoria_semantica_formas_vida", "INFO", arq, "Nenhum token de hábito em colunas principais de forma de vida", "OK")
  }
  res[]
}



monitora_correcao_auditar_papeis_colunas_semantica <- function(dt, contexto = "pos_correcoes", abortar = FALSE, linhas = NULL) {
  dt <- data.table::as.data.table(dt)
  mapa <- monitora_correcao_mapa_colunas_canonicas(dt)
  forma_tokens <- setdiff(monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokens_forma_vida_catalogo()), c("outra", "outros", "desconhecida", "desconhecido"))
  habitos <- monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokens_habito_catalogo())
  linhas_idx <- if (is.null(linhas)) seq_len(nrow(dt)) else unique(as.integer(linhas))
  linhas_idx <- linhas_idx[!is.na(linhas_idx) & linhas_idx >= 1L & linhas_idx <= nrow(dt)]
  achados <- list()
  cols_ver <- mapa[papel_coluna %in% c("especie_nome_popular", "atributo_dependente_habito", "lista_principal_forma_vida"), coluna_registros_corrig]
  for (cc in cols_ver) {
    vals <- as.character(dt[[cc]][linhas_idx])
    vals_norm <- monitora_correcao_limpar_texto(vals)
    papel <- mapa[coluna_registros_corrig == cc, papel_coluna][1L]
    if (papel %in% c("especie_nome_popular", "atributo_dependente_habito")) {
      hit <- rep(FALSE, length(vals_norm))
      for (tok in forma_tokens) hit <- hit | monitora_correcao_token_presente_vec(vals_norm, tok)
      if (any(hit, na.rm = TRUE)) {
        achados[[length(achados)+1L]] <- data.table::data.table(
          contexto = contexto,
          tipo_achado = ifelse(papel == "especie_nome_popular", "valor_forma_vida_em_coluna_especie", "valor_forma_vida_em_coluna_dependente"),
          coluna = cc,
          papel_coluna = papel,
          linha_indice = linhas_idx[hit],
          valor = vals[hit]
        )
      }
    } else if (papel == "lista_principal_forma_vida") {
      hit <- rep(FALSE, length(vals_norm))
      for (tok in habitos) hit <- hit | monitora_correcao_token_presente_vec(vals_norm, tok)
      if (any(hit, na.rm = TRUE)) {
        achados[[length(achados)+1L]] <- data.table::data.table(
          contexto = contexto,
          tipo_achado = "valor_habito_em_lista_principal",
          coluna = cc,
          papel_coluna = papel,
          linha_indice = linhas_idx[hit],
          valor = vals[hit]
        )
      }
    }
  }
  res <- if (length(achados)) data.table::rbindlist(achados, fill = TRUE, use.names = TRUE) else data.table::data.table(contexto=character(), tipo_achado=character(), coluna=character(), papel_coluna=character(), linha_indice=integer(), valor=character())
  arq <- file.path(if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) get("MONITORA_CORRECOES_DIR", inherits = TRUE) else file.path("output", "correcoes_campos"), paste0("auditoria_semantica_papeis_colunas_", contexto, ".csv"))
  dir.create(dirname(arq), recursive = TRUE, showWarnings = FALSE)
  try(monitora_fwrite(res, arq, na = ""), silent = TRUE)
  if (nrow(res) && isTRUE(abortar)) stop(paste0("Integridade semântica por papel violada: ", nrow(res), " achado(s). Ver ", arq), call. = FALSE)
  res[]
}


monitora_correcao_coluna_dependente_segura <- function(dt, nome, dicionario = NULL, contexto = "dependente") {
  col <- monitora_correcao_resolver_coluna(dt, nome, dicionario, permitir_heuristica = FALSE)
  if (is.na(col) || !(col %in% names(dt))) return(NA_character_)
  if (monitora_correcao_coluna_protegida(col)) return(NA_character_)
  col
}


monitora_correcao_norm_xlsform_id <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  x <- basename(x)
  x <- sub("\\.(xlsx|xls|csv)$", "", x, ignore.case = TRUE)
  x <- tolower(monitora_correcao_normalizar_nome_coluna(x))
 ### Remove sufixos técnicos comuns gerados pelo XLSForm/ODK/KoBo, mantendo o
 ### identificador lógico do formulário. Ex.: *_nSrC9X3 -> *.
  x <- sub("_n[a-z0-9]{4,}$", "", x, ignore.case = TRUE)
  x
}

monitora_correcao_xlsform_registro <- function(dt, linha = NULL, meta_xls = NULL) {
 ### Identifica a versão XLSForm mais provável para uma linha específica.
 ### A decisão é por registro, porque registros_corrig pode conter registros de
 ### várias versões históricas no mesmo objeto e, portanto, várias colunas
 ### paralelas para o mesmo conceito.
  if (is.null(meta_xls) || is.null(meta_xls$arquivos) || !nrow(meta_xls$arquivos) ||
      is.null(dt) || is.null(linha) || length(linha) != 1L || is.na(linha) || linha < 1L || linha > nrow(dt)) {
    return(NA_character_)
  }
  arqs <- data.table::as.data.table(meta_xls$arquivos)
  for (cc in c("arquivo_xlsform", "form_id", "version")) if (!(cc %in% names(arqs))) arqs[, (cc) := NA_character_]
  arqs[, arquivo_norm := monitora_correcao_norm_xlsform_id(arquivo_xlsform)]
  arqs[, form_id_norm := monitora_correcao_norm_xlsform_id(form_id)]
  arqs[, version_norm := monitora_correcao_norm_xlsform_id(version)]

  cols_origem <- intersect(c(".id", "PROTOCOLO", "protocolo", "controle_versao", "n_form_ref", "form_id", "form_version", "version"), names(dt))
  vals <- unique(unlist(lapply(cols_origem, function(cc) as.character(dt[[cc]][linha])), use.names = FALSE))
  vals <- vals[!is.na(vals) & nzchar(vals)]
  if (!length(vals)) return(NA_character_)
  vals_norm <- monitora_correcao_norm_xlsform_id(vals)
  vals_norm <- vals_norm[nzchar(vals_norm)]
  texto_norm <- paste(vals_norm, collapse = " ")

  arqs[, score := 0L]
 ### O formulário de agosto/2022 foi publicado com identificadores lógicos
 ### diferentes no XLSForm e no CSV exportado. O contrato embutido usa
 ### `comp_camp_sav_plantas_herb_lenh_nat_exot_ago22`/`..._ago2022`, enquanto
 ### os registros reais usam `PLANTASHERBACEASELENHOSAS_CAMPSAV_11AGO22`.
 ### Esta equivalência pertence ao resolvedor de versão (não à sanitização dos
 ### dados) e evita atribuir regras required do formulário atual a linhas 2022.
  alias_2022 <- "plantasherbaceaselenhosas_campsav_11ago22"
  if (alias_2022 %in% vals_norm) {
    arqs[
      arquivo_norm == "plantas_herb_e_lenhosas_campsav_ago2022" |
        form_id_norm == "comp_camp_sav_plantas_herb_lenh_nat_exot_ago22",
      score := score + 250L
    ]
  }
 ### Controle de versão é a melhor evidência quando existe.
  if ("controle_versao" %in% names(dt)) {
    v <- monitora_correcao_norm_xlsform_id(as.character(dt[["controle_versao"]][linha]))
    arqs[nzchar(version_norm) & version_norm == v, score := score + 200L]
  }
 ### Protocolo/.id identificam o formulário lógico; nomes de arquivo podem incluir
 ### extensão ou sufixo técnico, por isso comparamos versões normalizadas.
  arqs[nzchar(form_id_norm) & form_id_norm %in% vals_norm, score := score + 150L]
  arqs[nzchar(arquivo_norm) & arquivo_norm %in% vals_norm, score := score + 150L]
  arqs[, hit_form_id_texto := nzchar(form_id_norm) & vapply(form_id_norm, function(pat) grepl(pat, texto_norm, fixed = TRUE), logical(1))]
  arqs[, hit_arquivo_texto := nzchar(arquivo_norm) & vapply(arquivo_norm, function(pat) grepl(pat, texto_norm, fixed = TRUE), logical(1))]
  arqs[hit_form_id_texto == TRUE, score := score + 100L]
  arqs[hit_arquivo_texto == TRUE, score := score + 100L]
 ### Se o arquivo histórico tem sufixo técnico, o prefixo sem sufixo também conta.
  arqs[, arquivo_prefixo := sub("_n[a-z0-9]{4,}$", "", arquivo_norm, ignore.case = TRUE)]
  arqs[, hit_prefixo_texto := nzchar(arquivo_prefixo) & vapply(arquivo_prefixo, function(pat) grepl(pat, texto_norm, fixed = TRUE), logical(1))]
  arqs[hit_prefixo_texto == TRUE, score := score + 80L]

  data.table::setorder(arqs, -score, arquivo_xlsform)
  if (nrow(arqs) && is.finite(arqs$score[1L]) && arqs$score[1L] > 0L) return(as.character(arqs$arquivo_xlsform[1L]))
  NA_character_
}

monitora_correcao_score_coluna_categoria <- function(cols, categoria) {
  categoria <- tolower(as.character(categoria[1L]))
  n <- monitora_correcao_normalizar_nome_coluna(cols)
  out <- integer(length(cols))
  if (!length(cols)) return(out)
  if (categoria == "nativa") {
    out <- out + ifelse(grepl("nativ", n), 120L, 0L)
    out <- out + ifelse(!grepl("_1$|_2$|exot|seca|morta", n), 45L, 0L)
  } else if (categoria == "exotica") {
    out <- out + ifelse(grepl("exot", n), 120L, 0L)
    out <- out + ifelse(grepl("_1$", n), 55L, 0L)
  } else if (categoria == "seca_morta") {
    out <- out + ifelse(grepl("seca|morta", n), 120L, 0L)
    out <- out + ifelse(grepl("_2$", n), 55L, 0L)
  }
  out
}

monitora_correcao_candidatos_coluna_xlsform <- function(dt, campo, arquivo_xlsform = NA_character_, categoria = NA_character_, dicionario = NULL, excluir_especie = FALSE) {
 ### Retorna candidatos de coluna de registros_corrig para um campo XLSForm,
 ### priorizando a versão histórica do registro. Não escolhe destino por label
 ### global sem considerar a versão/categoria.
  if (is.null(dt) || is.null(campo) || !length(campo)) return(data.table::data.table())
  colmap_publicacao_ae <- if (exists("monitora_publicacao_ae_colnames_norm_dt", mode = "function")) {
    monitora_publicacao_ae_colnames_norm_dt(dt)
  } else {
    nms0 <- monitora_correcao_filtrar_colunas_seguras(names(dt), dt)
    data.table::data.table(col = nms0, norm = monitora_correcao_normalizar_nome_coluna(nms0))
  }
  nms <- colmap_publicacao_ae$col
  if (!length(nms)) return(data.table::data.table())
  nms_norm <- colmap_publicacao_ae$norm

  d <- if (!is.null(dicionario) && nrow(dicionario)) data.table::as.data.table(dicionario) else data.table::data.table()
  if (!nrow(d)) return(data.table::data.table())
  for (cc in c("arquivo_xlsform", "name", "caminho_registro", "type", "tipo_base", "list_name", "label", "relevant", "required")) {
    if (!(cc %in% names(d))) d[, (cc) := NA_character_]
  }
  campo <- as.character(campo[1L])
  dd <- d[name == campo | caminho_registro == campo | label == campo]
  if (!is.na(arquivo_xlsform) && nzchar(arquivo_xlsform)) {
    arq_alvo <- as.character(arquivo_xlsform[1L])
    dd_ver <- dd[arquivo_xlsform == arq_alvo]
    if (nrow(dd_ver)) dd <- dd_ver
  }
  if (!nrow(dd)) return(data.table::data.table())

  vals <- unique(unlist(dd[, .(name, caminho_registro, label)], use.names = FALSE))
  vals <- vals[!is.na(vals) & nzchar(vals)]
  vals_norm <- monitora_correcao_normalizar_nome_coluna(vals)
  forma_tokens <- unique(monitora_correcao_normalizar_nome_coluna(c(dd$name, dd$list_name, dd$label, dd$dependent_name)))
  forma_tokens <- forma_tokens[!is.na(forma_tokens) & nzchar(forma_tokens)]

  candidatos <- data.table::data.table(col = nms, norm = nms_norm, score = 0L)
 ### Caminho ou name exatos são fortes, quando o CSV preserva nomes canônicos.
  for (vv in vals) {
    vv_norm <- monitora_correcao_normalizar_nome_coluna(vv)
    candidatos[col == vv, score := pmax(score, 500L)]
    candidatos[tolower(col) == tolower(vv), score := pmax(score, 480L)]
    candidatos[norm == vv_norm, score := pmax(score, 430L)]
  }
 ### Labels históricos podem variar; exigir presença dos termos essenciais.
  label_norm <- monitora_correcao_normalizar_nome_coluna(dd$label)
  label_norm <- label_norm[!is.na(label_norm) & nzchar(label_norm)]
  for (ll in label_norm) {
    termos <- unlist(strsplit(ll, "_+"), use.names = FALSE)
    termos <- termos[nchar(termos) >= 5L]
    termos <- termos[!termos %in% c("span", "style", "color", "red", "observada", "observado", "amostragem", "registro")]
    if (length(termos)) {
      hit <- Reduce(`&`, lapply(termos[seq_len(min(3L, length(termos)))], function(tt) grepl(tt, candidatos$norm, fixed = TRUE)))
      candidatos[hit, score := pmax(score, 180L)]
    }
  }
  candidatos[, score := score + monitora_correcao_score_coluna_categoria(col, categoria)]
  if (isTRUE(excluir_especie)) {
    candidatos[grepl("especie|especies|nome_popular|outra_sp|_sp($|_)", norm), score := -999999L]
  }
  candidatos <- candidatos[score > 0L]
  if (!nrow(candidatos)) return(candidatos)
  data.table::setorder(candidatos, -score, col)
  candidatos[]
}

monitora_correcao_resolver_coluna_xlsform_registro <- function(dt, campo, linha = NULL, meta_xls = NULL, categoria = NA_character_, excluir_especie = FALSE) {
  arquivo <- monitora_correcao_xlsform_registro(dt, linha, meta_xls)
  dicionario <- if (!is.null(meta_xls) && !is.null(meta_xls$campos)) meta_xls$campos else NULL
  cand <- monitora_correcao_candidatos_coluna_xlsform(dt, campo, arquivo, categoria, dicionario, excluir_especie = excluir_especie)
  if (nrow(cand)) return(cand$col[1L])
 ### Fallback seguro: usa o resolvedor genérico, mas só quando não houver versão
 ### identificável. Com versão identificável e sem candidato, retornar NA evita
 ### preencher coluna de outra versão histórica.
  if (is.na(arquivo) || !nzchar(arquivo)) {
    col <- monitora_correcao_resolver_coluna(dt, campo, dicionario, permitir_heuristica = FALSE)
    if (!is.na(col) && !monitora_correcao_coluna_protegida(col)) return(col)
  }
  NA_character_
}

monitora_correcao_normalizar_forma_habito <- function(forma) {
  out <- monitora_correcao_normalizar_nome_coluna(as.character(forma))
  out[out %in% c("erva_bromelioide", "bromelioides")] <- "bromelioide"
  mapa <- c(cactaceas = "cactacea", orquideas = "orquidea", samambaias = "samambaia")
  idx <- match(out, names(mapa), nomatch = 0L)
  out[idx > 0L] <- unname(mapa[idx[idx > 0L]])
  out
}

### Índice executável do contrato atual de hábitos. A lista nasce dos campos
### select_one+required do XLSForm 21FEV25 embutido, não das ocorrências do
### dataset. Assim o mesmo código funciona com qualquer combinação de anos e
### falha de modo fechado se o contrato atual deixar de ser unívoco.
monitora_correcao_regras_habito_contrato_atual <- function(meta_xls = NULL) {
  usar_cache <- is.null(meta_xls)
  cache <- get0("MONITORA_REGRAS_HABITO_CONTRATO_ATUAL_CACHE", ifnotfound = NULL, envir = .GlobalEnv, inherits = FALSE)
  if (isTRUE(usar_cache) && data.table::is.data.table(cache) && nrow(cache)) return(cache[])
  meta <- monitora_correcao_xlsform_meta_atual(meta_xls)
  campos <- if (!is.null(meta$campos)) data.table::copy(data.table::as.data.table(meta$campos)) else data.table::data.table()
  if (!nrow(campos)) stop("Contrato XLSForm atual sem campos para resolver hábitos obrigatórios.", call. = FALSE)
  for (cc in c("arquivo_xlsform", "name", "caminho_registro", "type", "tipo_base", "list_name", "relevant", "required")) {
    if (!(cc %in% names(campos))) campos[, (cc) := NA_character_]
  }
  atual <- grepl("21FEV25", as.character(campos$arquivo_xlsform), ignore.case = TRUE)
  requerido <- tolower(trimws(as.character(campos$required))) %in% c("yes", "true", "1", "sim")
  select_one <- grepl("select_one", paste(campos$type, campos$tipo_base), ignore.case = TRUE)
  padrao <- "^forma_vida_(nativa|exotica|seca_morta)_(bromelioide|cactacea|orquidea|samambaia)$"
  regras <- campos[atual & requerido & select_one & grepl(padrao, as.character(name), perl = TRUE)]
  regras[, `:=`(
    categoria = sub(padrao, "\\1", as.character(name), perl = TRUE),
    forma = sub(padrao, "\\2", as.character(name), perl = TRUE),
    atributo_canonico = data.table::fifelse(
      !is.na(caminho_registro) & nzchar(as.character(caminho_registro)),
      as.character(caminho_registro), paste0("amostragem/registro/", as.character(name))
    )
  )]
  regras <- unique(regras[, .(categoria, forma, name, atributo_canonico, list_name, relevant, required, arquivo_xlsform)])
  duplicadas <- regras[, .N, by = .(categoria, forma)][N != 1L]
  if (nrow(duplicadas) || nrow(regras) != 12L) {
    stop("Contrato XLSForm 21FEV25 não resolveu univocamente os 12 atributos categoria×forma de hábito obrigatório.", call. = FALSE)
  }
  data.table::setorder(regras, categoria, forma)
  if (isTRUE(usar_cache)) assign("MONITORA_REGRAS_HABITO_CONTRATO_ATUAL_CACHE", regras[], envir = .GlobalEnv)
  regras[]
}

monitora_correcao_regra_habito_contrato_atual <- function(categoria, forma, meta_xls = NULL) {
  categoria_alvo <- tolower(trimws(as.character(categoria)[1L]))
  forma_alvo <- monitora_correcao_normalizar_forma_habito(forma)
  regras <- monitora_correcao_regras_habito_contrato_atual(meta_xls)
  regra <- regras[as.character(regras$categoria) == categoria_alvo & as.character(regras$forma) == forma_alvo]
  if (nrow(regra) != 1L) return(data.table::data.table())
  regra[]
}

monitora_correcao_regra_habito_por_coluna_fisica <- function(dt, col, meta_xls = NULL) {
  col <- as.character(col)[1L]
  if (is.null(dt) || is.na(col) || !nzchar(col) || !(col %in% names(dt)) ||
      !exists("monitora_validados_resolver_coluna", mode = "function")) {
    return(data.table::data.table())
  }
  regras <- monitora_correcao_regras_habito_contrato_atual(meta_xls)
  regras[, coluna_fisica := vapply(atributo_canonico, function(atributo) {
    tryCatch(monitora_validados_resolver_coluna(names(dt), atributo), error = function(e) NA_character_)
  }, character(1L))]
  regra <- regras[!is.na(coluna_fisica) & coluna_fisica == col]
  if (nrow(regra) != 1L) return(data.table::data.table())
  regra[]
}

monitora_correcao_resolver_coluna_habito <- function(dt, categoria, forma, dicionario = NULL, linha = NULL, meta_xls = NULL) {
 ### `registros_corrig` possui um único atributo físico vigente por
 ### categoria×forma. O caminho do contrato 2025 é resolvido pela mesma ordem
 ### usada para projetar `registros_validados`: caminho, rótulo físico atual e
 ### só então alias curto. Preenchimento observado nunca decide canonicidade.
  categoria <- tolower(as.character(categoria[1L]))
  forma <- tolower(as.character(forma[1L]))
  if (!nzchar(categoria) || !nzchar(forma) || is.null(dt) || !length(names(dt))) return(NA_character_)

  forma_canonica <- monitora_correcao_normalizar_forma_habito(forma)
  regra_atual <- tryCatch(monitora_correcao_regra_habito_contrato_atual(categoria, forma_canonica, meta_xls), error = function(e) data.table::data.table())
  if (nrow(regra_atual) == 1L && exists("monitora_validados_resolver_coluna", mode = "function")) {
    col_atual <- tryCatch(monitora_validados_resolver_coluna(names(dt), regra_atual$atributo_canonico[1L]), error = function(e) NA_character_)
    if (monitora_correcao_coluna_habito_segura(dt, col_atual, categoria, forma_canonica)) return(col_atual)
  }

  nome_canonico <- paste0("forma_vida_", categoria, "_", forma_canonica)
  nms <- names(dt)
  nms_base <- sub("^.*/", "", nms)
  cand_canon <- nms[nms == paste0("amostragem/registro/", nome_canonico) | nms == nome_canonico | nms_base == nome_canonico]
  if (length(cand_canon)) {
    prioridade <- match(cand_canon, c(paste0("amostragem/registro/", nome_canonico), nome_canonico), nomatch = 3L)
    cand_canon <- cand_canon[order(prioridade, nchar(cand_canon), cand_canon)]
    for (col in cand_canon) {
      if (monitora_correcao_coluna_habito_segura(dt, col, categoria, forma_canonica)) return(col)
    }
  }

  meta_local <- meta_xls
  if (is.null(meta_local) && !is.null(dicionario)) {
    meta_local <- list(campos = data.table::as.data.table(dicionario), arquivos = data.table::data.table())
  }
  campos <- if (!is.null(meta_local) && !is.null(meta_local$campos)) data.table::as.data.table(meta_local$campos) else data.table::data.table()
  if (nrow(campos)) {
    arquivo <- monitora_correcao_xlsform_registro(dt, linha, meta_local)
    parent <- paste0("forma_vida_", categoria)
    alvo_nome <- paste0("forma_vida_", categoria, "_", forma)
    dd <- campos[name == alvo_nome]
    if (!nrow(dd)) dd <- campos[name == alvo_nome | (list_name == alvo_nome)]
    if (!is.na(arquivo) && nzchar(arquivo)) {
      dd_ver <- dd[arquivo_xlsform == arquivo]
      if (nrow(dd_ver)) dd <- dd_ver
    }
 ### Preferir o select_one de hábito/tipo observado; excluir campos de espécie.
    if (nrow(dd)) {
      dd[, eh_especie := grepl("especie|esp[eé]cie|nome popular|_sp($|_)|outra espécie", paste(name, label, type, list_name), ignore.case = TRUE)]
      dd[, eh_select := grepl("select_one", type, ignore.case = TRUE)]
      data.table::setorder(dd, -eh_select, eh_especie, name)
      for (campo in dd[eh_especie == FALSE, name]) {
        col <- monitora_correcao_resolver_coluna_xlsform_registro(dt, campo, linha, meta_local, categoria = categoria, excluir_especie = TRUE)
        if (monitora_correcao_coluna_habito_segura(dt, col, categoria, forma)) return(col)
      }
    }
  }

 ### Fallback histórico, ainda seguro e sem colunas protegidas. Só é usado quando
 ### a versão não pôde ser resolvida ou o dicionário não trouxe campo explícito.
  nms <- monitora_correcao_filtrar_colunas_seguras(names(dt), dt)
  if (!length(nms)) return(NA_character_)
  nms_norm <- monitora_correcao_normalizar_nome_coluna(nms)
  forma_norm <- monitora_correcao_normalizar_nome_coluna(forma)
  forma_sinonimos <- switch(
    forma_norm,
    orquidea = c("orquidea", "orquideas"),
    bromelioide = c("bromelioide", "bromelioides", "erva_bromelioide"),
    erva_bromelioide = c("erva_bromelioide", "bromelioide", "bromelioides"),
    cactacea = c("cactacea", "cactaceas"),
    samambaia = c("samambaia", "samambaias"),
    forma_norm
  )
  forma_sinonimos <- unique(monitora_correcao_normalizar_nome_coluna(forma_sinonimos))
  forma_hit <- Reduce(`|`, lapply(forma_sinonimos, function(ff) grepl(ff, nms_norm, fixed = TRUE)))
  eh_especie <- grepl("especie|especies|nome_popular|outra_sp|_sp($|_)", nms_norm)
  eh_habito_label <- grepl("observad|selecione|habito|forma_vida", nms_norm)
  candidatos_idx <- which(forma_hit & eh_habito_label & !eh_especie)
  if (!length(candidatos_idx)) return(NA_character_)
  cand <- data.table::data.table(col = nms[candidatos_idx], norm = nms_norm[candidatos_idx])
  cand[, score := monitora_correcao_score_coluna_categoria(col, categoria)]
  cand[grepl("^a_.*observada|^a_.*observado", norm), score := score + 20L]
  cand[grepl("^selecione", norm), score := score + 5L]
  data.table::setorder(cand, -score, col)
  if (nrow(cand) && cand$score[1L] > 0L) {
    col_final <- cand$col[1L]
    if (monitora_correcao_coluna_habito_segura(dt, col_final, categoria, forma)) return(col_final)
  }
  NA_character_
}

### Reconhece se uma operação simples/SANHAB representa um hábito do contrato
### e devolve sua regra categoria×forma. A UI e a fila continuam exibindo os
### mesmos atributos; somente o backend traduz a intenção para o campo físico
### canônico antes de prevalidar e escrever.
monitora_correcao_regra_habito_operacao <- function(linha_corr, meta_xls = NULL) {
  op <- data.table::as.data.table(linha_corr)
  if (!nrow(op)) return(data.table::data.table())
  pegar <- function(cols) {
    for (cc in cols) if (cc %in% names(op)) {
      v <- trimws(as.character(op[[cc]][1L])); if (!is.na(v) && nzchar(v) && toupper(v) != "NA") return(v)
    }
    NA_character_
  }
  regras <- monitora_correcao_regras_habito_contrato_atual(meta_xls)
  categoria_ctx <- tolower(pegar(c("categoria_destino", "lista_destino", "categoria_superior")))
  forma_ctx <- monitora_correcao_normalizar_forma_habito(pegar(c("forma_valida_escolhida", "token_pai", "forma_de_vida_detectada")))
  if (!is.na(categoria_ctx) && nzchar(categoria_ctx) && !is.na(forma_ctx) && nzchar(forma_ctx)) {
    hit_ctx <- regras[categoria == categoria_ctx & forma == forma_ctx]
    if (nrow(hit_ctx) == 1L) return(hit_ctx[])
  }
  atributo <- pegar(c("atributo_canonico", "atributo_coluna_registros_corrig", "campo_dependente_preenchido", "atributo"))
  if (is.na(atributo) || !nzchar(atributo)) return(data.table::data.table())
  attr_lower <- tolower(atributo)
  hit <- regras[tolower(name) == attr_lower | tolower(atributo_canonico) == attr_lower | tolower(sub("^.*/", "", atributo_canonico)) == attr_lower]
  if (nrow(hit) == 1L) return(hit[])
  if (exists("monitora_validados_colunas_versãos", mode = "function")) {
    hits_alias <- vapply(regras$atributo_canonico, function(path) {
      cand <- tryCatch(monitora_validados_colunas_versãos(path), error = function(e) character())
      any(tolower(cand) == attr_lower)
    }, logical(1L))
    hit <- regras[hits_alias]
    if (nrow(hit) == 1L) return(hit[])
  }
  data.table::data.table()
}

monitora_correcao_resolver_coluna_operacao <- function(dt, linha_corr, dicionario = NULL, meta_xls = NULL) {
  regra <- tryCatch(monitora_correcao_regra_habito_operacao(linha_corr, meta_xls), error = function(e) data.table::data.table())
  if (nrow(regra) == 1L) {
    col <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, regra$categoria[1L], regra$forma[1L], dicionario, meta_xls = meta_xls), error = function(e) NA_character_)
    if (!is.na(col) && col %in% names(dt)) return(col)
  }
  op <- data.table::as.data.table(linha_corr)
  req <- if (nrow(op) && "atributo_coluna_registros_corrig" %in% names(op)) as.character(op$atributo_coluna_registros_corrig[1L]) else NA_character_
  monitora_correcao_resolver_coluna(dt, req, dicionario, permitir_heuristica = FALSE)
}

### Fonte única dos tokens de forma de vida que exigem hábito obrigatório
### (terrestre/epifita/rupicola). Usada tanto pelos bloqueios de movimento em
### lote (MVLOTE/TRIOUT) quanto pelo diagnóstico de ocorrências pré/pós-painel
### (monitora_correcao_mask_habito_obrigatorio_ausente , ), para não
### divergir em duas listas hard-coded do mesmo contrato.
monitora_correcao_tokens_formas_exigem_habito <- function() {
  formas <- tryCatch(unique(monitora_correcao_regras_habito_contrato_atual()$forma), error = function(e) c("bromelioide", "cactacea", "orquidea", "samambaia"))
  unique(c(formas, if ("bromelioide" %in% formas) "erva_bromelioide" else character()))
}

monitora_correcao_classificar_dependencia <- function(parent_col, token, dep_col) {
  txt <- tolower(paste(parent_col, token, dep_col, collapse = " "))
  parent_norm <- monitora_correcao_normalizar_nome_coluna(parent_col)
  dep_norm <- monitora_correcao_normalizar_nome_coluna(dep_col)
  token_norm <- monitora_correcao_limpar_texto(token)

 ### Regras globais de presença de espécie no XLSForm histórico são úteis para
 ### documentação, mas produzem muito ruído quando validadas linha a linha.
  if (grepl("(^|_)amostragem(_|$).*especie", parent_norm) && token_norm %in% c("sim", "yes", "1")) {
    return("informativa_especie_global")
  }
  if (grepl("especie|esp[eé]cie|(^|_)sp($|_)", txt)) return("informativa_especie")
  if (grepl("foto|imagem|image|observa", txt)) return("informativa")
  if (grepl("forma_vida|tipo_forma|encostam", txt)) return("critica_forma_vida")
  "revisao_condicional"
}


monitora_correcao_resolver_dependencias <- function(dt, deps, dicionario = NULL, incluir_bloqueadas = FALSE) {
 ### Resolve dependências condicionais uma única vez, deduplicando por colunas já
 ### resolvidas. Isso evita pendências duplicadas quando XLSForms históricos usam
 ### nomes/labels diferentes para a mesma coluna real de registros_corrig.
  if (is.null(deps) || !nrow(deps)) return(data.table::data.table())
  dt <- data.table::as.data.table(dt)
  deps <- data.table::as.data.table(deps)
  if (!all(c("parent_name", "token", "dependent_name") %in% names(deps))) return(data.table::data.table())
  if (!("fonte" %in% names(deps))) deps[, fonte := NA_character_]
  if (!("required" %in% names(deps))) deps[, required := NA_character_]
  deps <- deps[
    !is.na(parent_name) & nzchar(parent_name) &
      !is.na(token) & nzchar(token) &
      !is.na(dependent_name) & nzchar(dependent_name)
  ]
  if (!nrow(deps)) return(data.table::data.table())
  deps <- unique(deps[, .(parent_name, token, dependent_name, fonte, required)])

  out <- vector("list", nrow(deps))
  for (ii in seq_len(nrow(deps))) {
    parent_raw <- as.character(deps$parent_name[ii])
    dep_raw <- as.character(deps$dependent_name[ii])
    tok <- as.character(deps$token[ii])
    fonte <- as.character(deps$fonte[ii])
    required <- tolower(trimws(as.character(deps$required[ii])))
    required_ativo <- !is.na(required) && required %in% c("yes", "true", "1", "sim", "s")
    status <- "ok"
    msg <- "regra resolvida"
    parent_col <- NA_character_
    dep_col <- NA_character_

    if (monitora_correcao_coluna_protegida(parent_raw) || monitora_correcao_coluna_protegida(dep_raw)) {
      status <- "bloqueada_regra_xlsform_insegura"
      msg <- "regra aponta diretamente para coluna estrutural/protegida"
    } else {
      parent_col <- NA_character_
      if (exists("monitora_validados_resolver_coluna", mode = "function")) {
        parent_col <- tryCatch(
          monitora_validados_resolver_coluna(names(dt), paste0("amostragem/registro/", parent_raw)),
          error = function(e) NA_character_
        )
      }
      if (is.na(parent_col) || !(parent_col %in% names(dt))) {
        parent_col <- monitora_correcao_resolver_coluna(dt, parent_raw, dicionario, permitir_heuristica = FALSE)
      }
 ### Dependências chegam pelo `name` canônico do XLSForm. Em registros_corrig
 ### também podem existir aliases curtos vazios; aceitá-los como a coluna
 ### física gerava milhares de falsos "required ausente". Para hábitos,
 ### usa-se o mesmo resolvedor categoria×forma do diagnóstico/SANHAB. Para
 ### os demais campos de registro, prioriza-se o caminho canônico usado na
 ### projeção de registros_validados antes do fallback genérico.
      dep_norm_pre <- monitora_correcao_normalizar_nome_coluna(dep_raw)
      hit_hab_pre <- regexec("^forma_vida_(nativa|exotica|seca_morta)_(bromelioide|erva_bromelioide|cactacea|orquidea|samambaia)$", dep_norm_pre, perl = TRUE)
      partes_hab_pre <- regmatches(dep_norm_pre, hit_hab_pre)[[1L]]
      if (length(partes_hab_pre) == 3L) {
        dep_col <- tryCatch(
          monitora_correcao_resolver_coluna_habito(dt, partes_hab_pre[2L], partes_hab_pre[3L], dicionario = dicionario),
          error = function(e) NA_character_
        )
      } else if (identical(dep_norm_pre, "forma_serrapilheira") &&
                 exists("monitora_publicacao_c_resolver_coluna_materiais_botanicos", mode = "function")) {
        dep_col <- tryCatch(
          monitora_publicacao_c_resolver_coluna_materiais_botanicos(dt, criar = FALSE),
          error = function(e) NA_character_
        )
      } else {
        dep_col <- NA_character_
        if (exists("monitora_validados_resolver_coluna", mode = "function")) {
          dep_col <- tryCatch(
            monitora_validados_resolver_coluna(names(dt), paste0("amostragem/registro/", dep_raw)),
            error = function(e) NA_character_
          )
        }
        if (is.na(dep_col) || !(dep_col %in% names(dt))) {
          dep_col <- monitora_correcao_resolver_coluna(dt, dep_raw, dicionario, permitir_heuristica = FALSE)
        }
      }
      if (is.na(parent_col) || is.na(dep_col) || !(parent_col %in% names(dt)) || !(dep_col %in% names(dt))) {
        status <- "ignorada_coluna_nao_resolvida"
        msg <- "parent/dependent não resolvidos em registros_corrig"
      } else if (monitora_correcao_coluna_protegida(parent_col) || monitora_correcao_coluna_protegida(dep_col)) {
        status <- "bloqueada_regra_xlsform_insegura"
        msg <- "regra resolve para coluna estrutural/protegida"
      } else {
        papel_parent <- monitora_correcao_papel_coluna_canonico(parent_col)
        papel_dep <- monitora_correcao_papel_coluna_canonico(dep_col)
        parent_norm_x <- monitora_correcao_normalizar_nome_coluna(parent_raw)
        dep_norm_x <- monitora_correcao_normalizar_nome_coluna(dep_raw)
        parent_col_norm_x <- monitora_correcao_normalizar_nome_coluna(parent_col)
        parent_gate_especie <- parent_norm_x %in% c("especie", "especies")
        parent_gate_especie_ok <- grepl(
          "(^|_)amostragem_(especie|especies)$|havera_identificacao_de_especie|havera_identificacao_de_especies|havera_identificacao_de_especie_ou_outro_nivel_taxonomico",
          parent_col_norm_x
        )
        dep_raw_especie <- grepl("_sp($|_)|especie|nome_popular", dep_norm_x)
        dep_raw_habito <- grepl("^forma_vida_(nativa|exotica|seca_morta)_(bromelioide|erva_bromelioide|cactacea|orquidea|samambaia)$", dep_norm_x)
        categoria_dep_raw <- monitora_correcao_categoria_coluna_canonica(dep_raw)
        categoria_dep_col <- monitora_correcao_categoria_coluna_canonica(dep_col)
        token_dep_raw <- monitora_correcao_token_associado_coluna(dep_raw)
        token_dep_col <- monitora_correcao_token_associado_coluna(dep_col)
        if (isTRUE(parent_gate_especie) && !isTRUE(parent_gate_especie_ok)) {
          status <- "bloqueada_parent_especie_resolvido_para_folha"
          msg <- paste0("seletor global ", parent_raw, " resolveu indevidamente para campo folha: ", parent_col)
        } else if (isTRUE(dep_raw_especie) && !identical(papel_dep, "especie_nome_popular")) {
          status <- "bloqueada_dependent_especie_resolvido_para_outro_papel"
          msg <- paste0("dependent_name de espécie resolveu para papel incompatível: ", papel_dep, " [", dep_col, "]")
        } else if (isTRUE(dep_raw_habito) && !identical(papel_dep, "atributo_dependente_habito")) {
          status <- "bloqueada_dependent_habito_resolvido_para_outro_papel"
          msg <- paste0("dependent_name de hábito resolveu para papel incompatível: ", papel_dep, " [", dep_col, "]")
        } else if (!is.na(categoria_dep_raw) && nzchar(categoria_dep_raw) && !is.na(categoria_dep_col) && nzchar(categoria_dep_col) && categoria_dep_raw != categoria_dep_col) {
          status <- "bloqueada_dependent_categoria_divergente"
          msg <- paste0("categoria do dependent_name diverge da coluna resolvida: ", categoria_dep_raw, " != ", categoria_dep_col)
        } else if (!is.na(token_dep_raw) && nzchar(token_dep_raw) && !is.na(token_dep_col) && nzchar(token_dep_col) && token_dep_raw != token_dep_col) {
          status <- "bloqueada_dependent_token_divergente"
          msg <- paste0("token do dependent_name diverge da coluna resolvida: ", token_dep_raw, " != ", token_dep_col)
        } else if (grepl("^forma_vida_(nativa|exotica|seca_morta)$", parent_norm_x) && !identical(papel_parent, "lista_principal_forma_vida")) {
          status <- "bloqueada_parent_col_nao_lista_principal"
          msg <- paste0("parent_name de forma de vida resolveu para coluna com papel inválido: ", papel_parent)
        } else if (grepl("^forma_vida_(nativa|exotica|seca_morta)_", dep_norm_x) && papel_dep %in% c("protegida", "campo_superior_tipo_forma_vida", "lista_principal_forma_vida")) {
          status <- "bloqueada_dependent_col_papel_invalido"
          msg <- paste0("dependent_name de forma de vida resolveu para coluna com papel inválido: ", papel_dep)
        } else if (papel_dep == "outro" && dep_col %in% c("EA", "UA", "UC", "CICLO", "CAMPANHA", "ANO")) {
          status <- "bloqueada_dependent_col_contexto"
          msg <- "dependent_name resolveu para coluna de contexto/amostragem, não para atributo dependente"
        } else if (!isTRUE(required_ativo)) {
          status <- "ignorada_dependencia_nao_required"
          msg <- "campo relevante, porém não required; ausência não constitui pendência contratual"
        } else {
          sev_tmp <- monitora_correcao_classificar_dependencia(parent_raw, tok, dep_raw)
          validar_globais <- tolower(Sys.getenv("MONITORA_VALIDAR_CONDICIONAIS_GLOBAIS_ESPECIE", "false")) %in% c("true", "1", "yes", "sim", "s")
          if (identical(sev_tmp, "informativa_especie_global") && !isTRUE(validar_globais)) {
            status <- "ignorada_regra_global_informativa"
            msg <- "regra global de espécie mantida no dicionário, mas ignorada na validação linha-a-linha por alto ruído esperado"
          } else if (grepl("^informativa", sev_tmp)) {
            status <- "ignorada_regra_informativa_coberta_por_triagem"
            msg <- "regra informativa coberta pelos relatórios diagnósticos específicos; não tratada como required isolado fora da relevance composta"
          }
        }
      }
    }

    out[[ii]] <- data.table::data.table(
      parent_name = parent_raw,
      token = tok,
      token_norm = monitora_correcao_limpar_texto(tok),
      dependent_name = dep_raw,
      fonte = fonte,
      required = required,
      required_ativo = required_ativo,
      parent_col = parent_col,
      dependent_col = dep_col,
      status_regra = status,
      mensagem_regra = msg,
      severidade = monitora_correcao_classificar_dependencia(parent_raw, tok, dep_raw)
    )
  }
  res <- data.table::rbindlist(out, fill = TRUE, use.names = TRUE)
  if (!isTRUE(incluir_bloqueadas)) res <- res[status_regra == "ok"]
  if (nrow(res)) {
    data.table::setorderv(res, c("status_regra", "parent_col", "token_norm", "dependent_col", "parent_name", "dependent_name"), na.last = TRUE)
    res <- unique(res, by = c("status_regra", "parent_col", "token_norm", "dependent_col", "required_ativo"))
  }
  res[]
}

monitora_correcao_resolver_coluna_base_publicacao_ae <- function(dt, nome, dicionario = NULL, permitir_heuristica = TRUE) {
  if (is.null(nome) || is.na(nome) || !nzchar(nome)) return(NA_character_)
  nms <- setdiff(names(dt), monitora_correcao_colunas_protegidas_existentes(dt))
  if (nome %in% nms) return(nome)

 ### 1. comparação simples, sem diferenciar maiúsculas/minúsculas
  hit <- nms[tolower(nms) == tolower(nome)]
  if (length(hit) > 0) return(hit[1])

 ### 2. comparação normalizada: remove tags HTML, aspas escapadas, acentos e pontuação.
 ### Esta etapa corrige labels vindos do XLSForm/painel que chegam no CSV com
 ### variações de aspas em <span style="color:red">.
  hit_norm <- monitora_correcao_primeira_coluna_normalizada(dt, nome)
  if (!is.na(hit_norm) && nzchar(hit_norm)) return(hit_norm)

 ### 3. atalhos semânticos para os principais campos hierárquicos de forma de vida.
  nome_norm <- monitora_correcao_normalizar_nome_coluna(nome)
  if (grepl("formas_de_vida_de_plantas.*exot", nome_norm) || grepl("forma_vida_exotica$", nome_norm)) {
    col <- monitora_correcao_coluna_forma_vida(dt, "exotica")
    if (!is.na(col) && col %in% nms) return(col)
  }
  if (grepl("formas_de_vida_de_plantas.*nativ", nome_norm) || grepl("forma_vida_nativa$", nome_norm)) {
    col <- monitora_correcao_coluna_forma_vida(dt, "nativa")
    if (!is.na(col) && col %in% nms) return(col)
  }
  if (grepl("formas_de_vida_de_plantas.*seca.*morta", nome_norm) || grepl("forma_vida_seca_morta$", nome_norm)) {
    col <- monitora_correcao_coluna_forma_vida(dt, "seca_morta")
    if (!is.na(col) && col %in% nms) return(col)
  }
  if (grepl("encostam.*vareta", nome_norm) || grepl("tipo_forma_vida", nome_norm)) {
    col <- monitora_correcao_colunas_chave(dt)$tipo_forma_vida
    if (!is.na(col) && col %in% nms) return(col)
  }

 ### 4. resolução por dicionário XLSForm/atributos, também com normalização.
  if (!is.null(dicionario) && nrow(dicionario) > 0) {
    d <- data.table::as.data.table(dicionario)
    for (cc in c("name", "caminho_registro", "label", "atributo_coluna_registros_corrig", "xlsform_name", "xlsform_label")) {
      if (!(cc %in% names(d))) d[, (cc) := NA_character_]
    }
    cand <- unique(c(
      d[name == nome, name],
      d[name == nome, caminho_registro],
      d[name == nome, label],
      d[caminho_registro == nome, name],
      d[caminho_registro == nome, caminho_registro],
      d[caminho_registro == nome, label],
      d[label == nome, name],
      d[label == nome, caminho_registro],
      d[label == nome, label],
      d[atributo_coluna_registros_corrig == nome, atributo_coluna_registros_corrig],
      d[xlsform_name == nome, atributo_coluna_registros_corrig],
      d[xlsform_label == nome, atributo_coluna_registros_corrig]
    ))
    cand <- cand[!is.na(cand) & nzchar(cand)]
    cand <- monitora_correcao_filtrar_colunas_seguras(cand, NULL)
    for (cc in cand) {
      if (cc %in% nms) return(cc)
      hit <- nms[tolower(nms) == tolower(cc)]
      if (length(hit) > 0) return(hit[1])
      hit_norm <- monitora_correcao_primeira_coluna_normalizada(dt, cc)
      if (!is.na(hit_norm) && nzchar(hit_norm)) return(hit_norm)
    }

 ### Match normalizado entre o nome solicitado e qualquer coluna de mapeamento do dicionário.
    alvo_norm <- monitora_correcao_normalizar_nome_coluna(nome)
    vals <- unique(c(d$name, d$caminho_registro, d$label, d$atributo_coluna_registros_corrig, d$xlsform_name, d$xlsform_label))
    vals <- vals[!is.na(vals) & nzchar(vals)]
    vals_norm <- monitora_correcao_normalizar_nome_coluna(vals)
    vals_hit <- vals[vals_norm == alvo_norm]
    for (vv in vals_hit) {
      cand2 <- unique(c(
        d[name == vv, name], d[name == vv, caminho_registro], d[name == vv, label], d[name == vv, atributo_coluna_registros_corrig],
        d[caminho_registro == vv, name], d[caminho_registro == vv, caminho_registro], d[caminho_registro == vv, label], d[caminho_registro == vv, atributo_coluna_registros_corrig],
        d[label == vv, name], d[label == vv, caminho_registro], d[label == vv, label], d[label == vv, atributo_coluna_registros_corrig],
        d[atributo_coluna_registros_corrig == vv, atributo_coluna_registros_corrig]
      ))
      cand2 <- cand2[!is.na(cand2) & nzchar(cand2)]
      cand2 <- monitora_correcao_filtrar_colunas_seguras(cand2, NULL)
      for (cc in cand2) {
        if (cc %in% nms) return(cc)
        hit_norm <- monitora_correcao_primeira_coluna_normalizada(dt, cc)
        if (!is.na(hit_norm) && nzchar(hit_norm)) return(hit_norm)
      }
    }
  }

 ### 5. Heurística final apenas para diagnóstico/compatibilidade visual.
 ### Escritas semânticas chamam o resolvedor com permitir_heuristica=FALSE e
 ### falham de modo fechado quando não existe correspondência inequívoca.
  if (!isTRUE(permitir_heuristica)) return(NA_character_)
  nms_norm <- monitora_correcao_normalizar_nome_coluna(nms)
  alvo_norm <- monitora_correcao_normalizar_nome_coluna(nome)
  if (nzchar(alvo_norm)) {
    hit_alvo_em_coluna <- which(grepl(alvo_norm, nms_norm, fixed = TRUE))
    hit_coluna_em_alvo <- which(nzchar(nms_norm) & vapply(nms_norm, function(pat) grepl(pat, alvo_norm, fixed = TRUE), logical(1)))
    hit <- unique(c(hit_alvo_em_coluna, hit_coluna_em_alvo))
  } else {
    hit <- integer(0)
  }
  if (length(hit) > 0) return(nms[hit[1]])
  NA_character_
}


monitora_correcao_resolver_coluna <- function(dt, nome, dicionario = NULL, permitir_heuristica = TRUE) {
  if (is.null(nome) || is.na(nome) || !nzchar(nome)) return(NA_character_)
  env <- if (exists("monitora_publicacao_ae_cache_env", mode = "function")) monitora_publicacao_ae_cache_env("resolver_coluna") else .GlobalEnv
  dt_sig <- if (exists("monitora_publicacao_ae_dt_names_sig", mode = "function")) monitora_publicacao_ae_dt_names_sig(dt) else paste(length(names(dt)), sum(nchar(names(dt))), collapse = "_")
  dic_sig <- tryCatch({
    if (is.null(dicionario)) "dic_null" else paste0(nrow(data.table::as.data.table(dicionario)), ":", paste(intersect(c("name", "caminho_registro", "label", "atributo_coluna_registros_corrig", "xlsform_name", "xlsform_label"), names(data.table::as.data.table(dicionario))), collapse = "+"))
  }, error = function(e) "dic_err")
  key <- paste0(if (isTRUE(permitir_heuristica)) "heur::" else "strict::", dt_sig, "::", dic_sig, "::", if (exists("monitora_publicacao_ae_cache_key", mode = "function")) monitora_publicacao_ae_cache_key(nome, 240L) else gsub("[^A-Za-z0-9]+", "_", nome))
  if (exists(key, envir = env, inherits = FALSE)) return(get(key, envir = env, inherits = FALSE))
  ans <- monitora_correcao_resolver_coluna_base_publicacao_ae(dt, nome, dicionario, permitir_heuristica = permitir_heuristica)
  assign(key, ans, envir = env)
  ans
}

monitora_correcao_tipo_xlsform <- function(type) {
  type <- trimws(as.character(type))
  base <- sub("\\s+.*$", "", type)
  lista <- ifelse(grepl("\\s+", type), sub("^[^[:space:]]+\\s+", "", type), NA_character_)
  data.table::data.table(tipo_base = base, list_name = lista)
}

### Metadados XLSForm embutidos para o painel de correções
### Gerados a partir das versões históricas 2022, 2023, 2024 e 2025 anexadas ao projeto.
### Esta seção evita dependência de leitura externa de.xlsx/.zip durante a execução.
### Implementação sem linhas gigantes para evitar truncamento no console do R.
monitora_correcao_fread_tsv_embutido <- function(linhas) {
  data.table::fread(
    text = paste(linhas, collapse = "\n"),
    sep = "\t",
    quote = "",
    encoding = "UTF-8",
    na.strings = "",
    showProgress = FALSE
  )
}

