monitora_correcao_xlsforms_embutidos_cache_publicacao_ae <- function(forcar = FALSE) {
  env <- if (exists("monitora_publicacao_ae_cache_env", mode = "function")) monitora_publicacao_ae_cache_env("xlsforms_embutidos") else .GlobalEnv
  chave <- "meta_xlsforms_todas_versoes"
  if (!isTRUE(forcar) && exists(chave, envir = env, inherits = FALSE)) return(get(chave, envir = env, inherits = FALSE))
  meta <- monitora_correcao_xlsforms_embutidos()
  for (nm in c("campos", "opcoes", "dependencias", "arquivos")) {
    if (is.null(meta[[nm]])) meta[[nm]] <- data.table::data.table()
    meta[[nm]] <- data.table::as.data.table(meta[[nm]])
  }
  if (nrow(meta$campos)) {
    for (cc in c("arquivo_xlsform", "name", "caminho_registro", "label", "list_name", "tipo_base", "type")) if (!(cc %in% names(meta$campos))) meta$campos[, (cc) := NA_character_]
    meta$campos[, `:=`(
      arquivo_norm_publicacao_ae = monitora_correcao_norm_xlsform_id(arquivo_xlsform),
      name_norm_publicacao_ae = monitora_correcao_normalizar_nome_coluna(name),
      caminho_norm_publicacao_ae = monitora_correcao_normalizar_nome_coluna(caminho_registro),
      label_norm_publicacao_ae = monitora_correcao_normalizar_nome_coluna(label),
      arquivo_21fev25_publicacao_ae = grepl("21FEV25", arquivo_xlsform, ignore.case = TRUE)
    )]
    data.table::setindexv(meta$campos, c("arquivo_xlsform", "name"))
    data.table::setindexv(meta$campos, c("arquivo_xlsform", "caminho_registro"))
    data.table::setindexv(meta$campos, c("arquivo_21fev25_publicacao_ae", "name"))
    data.table::setindexv(meta$campos, c("arquivo_21fev25_publicacao_ae", "caminho_registro"))
  }
  if (nrow(meta$opcoes)) {
    for (cc in c("arquivo_xlsform", "list_name", "name", "label")) if (!(cc %in% names(meta$opcoes))) meta$opcoes[, (cc) := NA_character_]
    meta$opcoes[, `:=`(
      arquivo_norm_publicacao_ae = monitora_correcao_norm_xlsform_id(arquivo_xlsform),
      name_norm_publicacao_ae = monitora_correcao_normalizar_nome_coluna(name),
      label_norm_publicacao_ae = monitora_correcao_normalizar_nome_coluna(label),
      arquivo_21fev25_publicacao_ae = grepl("21FEV25", arquivo_xlsform, ignore.case = TRUE)
    )]
    data.table::setindexv(meta$opcoes, c("arquivo_xlsform", "list_name"))
    data.table::setindexv(meta$opcoes, c("arquivo_21fev25_publicacao_ae", "list_name"))
  }
  if (nrow(meta$dependencias)) {
    for (cc in c("arquivo_xlsform", "parent_name", "token", "dependent_name")) if (!(cc %in% names(meta$dependencias))) meta$dependencias[, (cc) := NA_character_]
    meta$dependencias[, `:=`(
      arquivo_norm_publicacao_ae = monitora_correcao_norm_xlsform_id(arquivo_xlsform),
      parent_norm_publicacao_ae = monitora_correcao_normalizar_nome_coluna(parent_name),
      token_norm_publicacao_ae = monitora_correcao_limpar_texto(token),
      dependent_norm_publicacao_ae = monitora_correcao_normalizar_nome_coluna(dependent_name)
    )]
    data.table::setindexv(meta$dependencias, c("arquivo_xlsform", "parent_name", "token", "dependent_name"))
  }
  if (nrow(meta$arquivos)) {
    for (cc in c("arquivo_xlsform", "form_id", "version")) if (!(cc %in% names(meta$arquivos))) meta$arquivos[, (cc) := NA_character_]
    meta$arquivos[, `:=`(
      arquivo_norm_publicacao_ae = monitora_correcao_norm_xlsform_id(arquivo_xlsform),
      form_id_norm_publicacao_ae = monitora_correcao_norm_xlsform_id(form_id),
      version_norm_publicacao_ae = monitora_correcao_norm_xlsform_id(version)
    )]
  }
  assign(chave, meta, envir = env)
  meta
}

monitora_correcao_ler_xlsforms <- function(...) {
 ### Todas as regras utilizadas pelo painel são carregadas da seção embutida acima,
 ### sem dependência de leitura externa de XLSForms durante a execução.
  monitora_correcao_xlsforms_embutidos_cache_publicacao_ae()
}

monitora_correcao_dependencias_padrao <- function() {
  formas_cond <- c("bromelioide", "cactacea", "orquidea", "samambaia")
  cats <- c("nativa", "exotica", "seca_morta")
  out <- data.table::CJ(categoria = cats, token = formas_cond)
  out[, parent_name := paste0("forma_vida_", categoria)]
  out[, dependent_name := paste0("forma_vida_", categoria, "_", token)]
  out[, dependent_type := "select_one habito_forma_vida"]
  out[, dependent_list_name := "habito_forma_vida"]
  out[, required := "yes"]
  out[, relevant := paste0("selected(${", parent_name, "}, '", token, "')")]
  out[, fonte := "regra_padrao_monitora"]
  out[]
}

monitora_correcao_unificar_dependencias <- function(dep_xlsform) {
  dep_padrao <- monitora_correcao_dependencias_padrao()
  if (is.null(dep_xlsform) || nrow(dep_xlsform) == 0) return(dep_padrao)
  dep_xlsform <- data.table::as.data.table(data.table::copy(dep_xlsform))
 ### Versões históricas permanecem disponíveis para auditoria/importação,
 ### mas somente o XLSForm operacional 21FEV25 governa os cálculos vigentes.
  if ("arquivo_xlsform" %in% names(dep_xlsform)) {
    origem <- as.character(dep_xlsform$arquivo_xlsform)
    atual <- grepl("21FEV25", origem, ignore.case = TRUE)
    sem_origem <- is.na(origem) | !nzchar(trimws(origem))
    dep_xlsform <- dep_xlsform[atual | sem_origem]
  }
  cols <- union(names(dep_xlsform), names(dep_padrao))
  for (cc in setdiff(cols, names(dep_xlsform))) dep_xlsform[, (cc) := NA_character_]
  for (cc in setdiff(cols, names(dep_padrao))) dep_padrao[, (cc) := NA_character_]
  unique(data.table::rbindlist(list(dep_xlsform[, ..cols], dep_padrao[, ..cols]), fill = TRUE, use.names = TRUE))
}

monitora_correcao_dicionario_atributos <- function(dt, meta_xls = NULL) {
  dt <- data.table::as.data.table(dt)
  chaves <- monitora_correcao_colunas_chave(dt)
  nms <- names(dt)
  campos <- if (!is.null(meta_xls) && !is.null(meta_xls$campos)) data.table::as.data.table(meta_xls$campos) else data.table::data.table()
  out <- data.table::data.table(
    atributo_coluna_registros_corrig = nms,
    n_preenchidos = vapply(dt, function(x) sum(!is.na(x) & nzchar(trimws(as.character(x)))), integer(1)),
    n_valores_unicos = vapply(dt, function(x) length(unique(na.omit(as.character(x)))), integer(1)),
    classe_r = vapply(dt, function(x) paste(class(x), collapse = "/"), character(1))
  )
  out[, escopo_sugerido := "ponto"]
  cols_coleta <- unique(na.omit(c(chaves$coleta, chaves$coleta_uuid, chaves$uc, chaves$ano, chaves$ua, chaves$campanha, "form_veg", "CICLO", "PROTOCOLO")))
  out[atributo_coluna_registros_corrig %in% cols_coleta, escopo_sugerido := "coleta_inteira"]
  out[grepl("form_veg|campanha|ciclo|^UC$|^EA$|^UA$|estrato|[aá]rea.*eleg[ií]vel|data_hora/data|data_hora/hora|num_placa|coordenada|protocolo", atributo_coluna_registros_corrig, ignore.case = TRUE), escopo_sugerido := "coleta_inteira"]
  out[grepl("ponto|registro|forma_vida|esp[eé]cie|ex[oó]tica|nativa|seca|morta", atributo_coluna_registros_corrig, ignore.case = TRUE), escopo_sugerido := "ponto"]
 ### Campos superiores/estruturais de coleta devem sobrescrever regras genéricas
 ### posteriores, inclusive nomes legados como "Data (data_hora)".
  out[grepl("form_veg|campanha|ciclo|^UC$|^EA$|^UA$|estrato|[aá]rea.*eleg[ií]vel|data_hora|data \\(data_hora\\)|hor[aá]rio \\(data_hora\\)|data_do_registro|^data$|^hora$|num_placa|coordenada|protocolo", atributo_coluna_registros_corrig, ignore.case = TRUE), escopo_sugerido := "coleta_inteira"]
 ### "Horário (data_hora)" contém a substring "data" (do próprio
 ### qualificador de grupo "(data_hora)"), então o antigo grepl("data",...)
 ### genérico classificava HORÁRIO como "data/texto" -- confirmado
 ### reproduzindo o bug (validação de contrato recomputava tipo_base_edicao
 ### como "date" para Horário, rejeitando um valor de hora válido como
 ### "data inválida"). Checar o padrão de hora ANCORADO no início da string
 ### primeiro resolve genericamente (não é uma exceção só para "Horário":
 ### qualquer atributo cujo nome comece com "hora"/"horário" passa a ser
 ### classificado corretamente antes do teste genérico de "data").
 ### "coordenada" também não tinha inferência de tipo dedicada
 ### (caía em "texto", pulando a validação de faixa lat/lon já existente em
 ### monitora_correcao_validar_formato_valor para tipo_base "geopoint").
 ### Padrão genérico por nome, mesmo estilo dos demais casos desta cadeia.
  out[, tipo_valor_inferido := fifelse(grepl("uuid", atributo_coluna_registros_corrig, ignore.case = TRUE), "uuid",
                                fifelse(grepl("^hor[aá]rio|^hora($|[^a-zA-Z])", atributo_coluna_registros_corrig, ignore.case = TRUE), "hora/texto",
                                fifelse(grepl("data", atributo_coluna_registros_corrig, ignore.case = TRUE), "data/texto",
                                fifelse(grepl("coordenada", atributo_coluna_registros_corrig, ignore.case = TRUE), "geopoint/texto",
                                fifelse(grepl("forma_vida|esp[eé]cies|tipo_forma", atributo_coluna_registros_corrig, ignore.case = TRUE), "select_multiple/texto",
                                fifelse(grepl("ponto_metro", atributo_coluna_registros_corrig, ignore.case = TRUE), "decimal", "texto"))))))]
  if (nrow(campos) > 0) {
    out[, xlsform_name := NA_character_]
    out[, xlsform_label := NA_character_]
    out[, xlsform_tipo := NA_character_]
    out[, xlsform_tipo_base := NA_character_]
    out[, xlsform_list_name := NA_character_]
    out[, xlsform_required := NA_character_]
    out[, xlsform_relevant := NA_character_]
 ### Precedência contratual do XLSForm (/): quando o mesmo
 ### name/caminho_registro/label existe em mais de um XLSForm embutido (ex.
 ### versões históricas 03MAI24/05MAI23/ago2022 reutilizando um "name" que a
 ### publicação vigente redefiniu), o candidato do XLSForm 21FEV25/publicação
 ### atual deve sempre vencer; XLSForms históricos só servem de fallback
 ### quando não há candidato vigente. Sem isso, o primeiro hit por ordem de
 ### rbind (arbitrária) podia rebaixar campos select_one/select_multiple do
 ### contrato vigente para "text" com rótulo histórico (ex.: samambaia nativa).
    campos_pri <- data.table::copy(campos)
    if (!("arquivo_21fev25_publicacao_ae" %in% names(campos_pri))) {
      campos_pri[, arquivo_21fev25_publicacao_ae := grepl("21FEV25", arquivo_xlsform, ignore.case = TRUE)]
    }
    campos_pri[, arquivo_21fev25_publicacao_ae := fifelse(is.na(arquivo_21fev25_publicacao_ae), FALSE, arquivo_21fev25_publicacao_ae)]
 ### (causa raiz de 13/14 "bloqueado_sem_dominio_xlsform"):
 ### colunas de registros_corrig que nunca ganharam um `name` curto
 ### canônico ficam com o rótulo histórico bruto + sufixo de escopo como
 ### nome de coluna (ex.: "**Espécies** de <span style=""color:red"">
 ### graminóides exóticas:</span> (amostragem/registro)"). Esse rótulo bruto
 ### tem aspas duplicadas (herdadas de um nível de escaping do atributo HTML
 ### `style="..."` ao virar cabeçalho de coluna) e o sufixo de escopo, então
 ### nunca bate contra `campos$label` (que preserva aspas simples e não tem
 ### o sufixo) nos dois testes acima -- xlsform_tipo/xlsform_list_name
 ### ficavam NA, n_opcoes_xlsform virava 0 e o atributo era bloqueado por
 ### "falta de domínio" mesmo quando o list_name do XLSForm existe e tem
 ### opções reais (confirmado: list_name "especies_exotica_graminoide" tem
 ### opções no XLSForm; só a resolução por nome falhava). Pré-computado uma
 ### única vez fora do loop por atributo (custo por linha de registros_corrig,
 ### não por candidato do XLSForm). O nível de duplicação de aspas observado
 ### varia por execução/estágio (2 ou 4 aspas seguidas conforme o dado já
 ### passou por 1 ou 2 ciclos de escaping upstream); nenhum rótulo XLSForm
 ### legítimo usa aspas consecutivas, então colapsar QUALQUER sequência de
 ### aspas para uma única aspa é seguro e cobre os dois casos sem depender
 ### de contar pares.
    normalizar_rotulo_alias_coluna <- function(x) {
      x <- as.character(x)
      x[is.na(x)] <- ""
      x <- sub(" \\(amostragem/registro\\)$", "", x, perl = TRUE)
      x <- gsub("\"+", "\"", x, perl = TRUE)
      trimws(x)
    }
    campos_pri[, label_norm_alias := normalizar_rotulo_alias_coluna(label)]
    for (ii in seq_len(nrow(out))) {
      cc <- out$atributo_coluna_registros_corrig[ii]
      hit <- campos_pri[name == cc | caminho_registro == cc | label == cc]
      if (nrow(hit) == 0) {
        hit <- campos_pri[grepl(paste0("(^|/)", gsub("([][{}()+*^$|\\\\?.])", "\\\\\\1", cc, perl = TRUE), "$"), caminho_registro, ignore.case = TRUE)]
      }
      if (nrow(hit) == 0) {
        cc_norm <- normalizar_rotulo_alias_coluna(cc)
        if (nzchar(cc_norm)) hit <- campos_pri[label_norm_alias == cc_norm]
      }
      if (nrow(hit) > 0) {
        hit[, match_caminho_exato := caminho_registro == cc]
        data.table::setorderv(hit, c("arquivo_21fev25_publicacao_ae", "match_caminho_exato"), order = c(-1L, -1L))
        tipo_hit <- monitora_correcao_tipo_xlsform(hit$type[1])
        data.table::set(out, i = ii, j = "xlsform_name", value = hit$name[1])
        data.table::set(out, i = ii, j = "xlsform_label", value = hit$label[1])
        data.table::set(out, i = ii, j = "xlsform_tipo", value = hit$type[1])
        data.table::set(out, i = ii, j = "xlsform_tipo_base", value = tipo_hit$tipo_base[1])
        data.table::set(out, i = ii, j = "xlsform_list_name", value = tipo_hit$list_name[1])
        if ("required" %in% names(hit)) data.table::set(out, i = ii, j = "xlsform_required", value = hit$required[1])
        if ("relevant" %in% names(hit)) data.table::set(out, i = ii, j = "xlsform_relevant", value = hit$relevant[1])
      }
    }
  }
  mapa_papel <- monitora_correcao_mapa_colunas_canonicas(dt)
  idx_papel <- match(out$atributo_coluna_registros_corrig, mapa_papel$coluna_registros_corrig)
  out[, papel_coluna := mapa_papel$papel_coluna[idx_papel]]
  out[, categoria_coluna := mapa_papel$categoria[idx_papel]]
  out[, token_associado_coluna := mapa_papel$token_associado[idx_papel]]
  out[, observacao_papel_coluna := mapa_papel$observacao[idx_papel]]
  out <- monitora_contrato_aplicar_metadados_categorias_movimento(out)
  out[papel_coluna == "campo_superior_tipo_forma_vida", xlsform_name := fifelse(is.na(xlsform_name) | !nzchar(xlsform_name), "tipo_forma_vida", xlsform_name)]
  out[papel_coluna == "campo_superior_tipo_forma_vida", xlsform_list_name := "tipo_forma_vida"]
  contrato <- tryCatch(monitora_correcao_contrato_edicao(dt, meta_xls, out), error = function(e) data.table::data.table())
  if (nrow(contrato)) {
    cols_contrato <- intersect(
      c(
        "atributo_coluna_registros_corrig", "tipo_base_edicao", "painel_editavel",
        "painel_motivo_bloqueio", "acoes_permitidas", "atende_template_sismonitora",
        "ordem_template_sismonitora", "atributos_template_sismonitora", "posicoes_template_sismonitora",
        "estrategias_template_sismonitora"
      ),
      names(contrato)
    )
    out <- merge(out, contrato[, ..cols_contrato], by = "atributo_coluna_registros_corrig", all.x = TRUE, sort = FALSE)
  } else if (exists("monitora_correcao_anotar_contrato_template_sismonitora", mode = "function")) {
    out <- monitora_correcao_anotar_contrato_template_sismonitora(out, dt)
  }

 ### Rótulos históricos de espécie são resolvidos exclusivamente pelo índice
 ### de aliases do contrato único. O token e a categoria são derivados do
 ### caminho canônico encontrado; não há tabela paralela de atributos.
  out[, caminho_candidato_especie := NA_character_]
  idx_alias_esp <- which(
    out$papel_coluna == "especie_nome_popular" &
      (is.na(out$token_associado_coluna) | !nzchar(out$token_associado_coluna))
  )
  if (length(idx_alias_esp)) {
    contrato_idx_alias <- tryCatch(monitora_contrato_unico_indices_cache(), error = function(e) NULL)
    aliases_esp <- if (!is.null(contrato_idx_alias) && !is.null(contrato_idx_alias$indices$por_alias_normalizado)) {
      data.table::copy(data.table::as.data.table(contrato_idx_alias$indices$por_alias_normalizado))
    } else {
      data.table::data.table()
    }
    if (nrow(aliases_esp)) {
      for (ii_alias in idx_alias_esp) {
        alias_norm <- monitora_contrato_unico_normalizar_texto_seguro(out$atributo_coluna_registros_corrig[ii_alias])
        hit_alias <- aliases_esp[
          alias_normalizado == alias_norm &
            grepl("(^|/)(forma_vida_(nativa|seca_morta)_|especies_exotica_|exotica_)", caminho_registro)
        ]
        if (!nrow(hit_alias)) next
        caminho_alias <- as.character(hit_alias$caminho_registro[1L])
        categoria_alias <- if (grepl("/forma_vida_nativa_", caminho_alias)) {
          "nativa"
        } else if (grepl("/(especies_exotica_|exotica_)", caminho_alias)) {
          "exotica"
        } else if (grepl("/forma_vida_seca_morta_", caminho_alias)) {
          "seca_morta"
        } else {
          NA_character_
        }
        token_alias <- sub("^.*/", "", caminho_alias)
        token_alias <- sub("^forma_vida_(nativa|seca_morta)_", "", token_alias)
        token_alias <- sub("^especies_exotica_", "", token_alias)
        token_alias <- sub("^exotica_", "", token_alias)
        token_alias <- sub("_outra_sp$", "", token_alias)
        token_alias <- sub("_sp$", "", token_alias)
        if (!is.na(categoria_alias) && nzchar(token_alias)) {
          data.table::set(out, i = ii_alias, j = "token_associado_coluna", value = token_alias)
          data.table::set(out, i = ii_alias, j = "categoria_coluna", value = categoria_alias)
          data.table::set(out, i = ii_alias, j = "caminho_candidato_especie", value = caminho_alias)
        }
      }
    }
  }
  out[
    papel_coluna == "especie_nome_popular" & (is.na(categoria_coluna) | !nzchar(categoria_coluna)),
    categoria_coluna := "nativa"
  ]
  if ("tipo_base_edicao" %in% names(out) &&
      any(out$papel_coluna == "especie_nome_popular" & !is.na(out$token_associado_coluna) & nzchar(out$token_associado_coluna), na.rm = TRUE)) {
    idx_esp <- which(out$papel_coluna == "especie_nome_popular" & !is.na(out$token_associado_coluna) & nzchar(out$token_associado_coluna))
    contrato_idx_esp <- tryCatch(monitora_contrato_unico_indices_cache(), error = function(e) NULL)
    at_esp <- if (!is.null(contrato_idx_esp) && !is.null(contrato_idx_esp$indices$por_caminho_registro)) {
      data.table::as.data.table(contrato_idx_esp$indices$por_caminho_registro)
    } else {
      data.table::data.table(caminho_registro = character(), tipo_base = character())
    }
    caminhos_validos <- if (nrow(at_esp)) unique(at_esp$caminho_registro) else character(0)
    tipo_por_caminho <- if (nrow(at_esp)) stats::setNames(at_esp$tipo_base, at_esp$caminho_registro) else character(0)
    for (ii_esp in idx_esp) {
      cat_esp <- out$categoria_coluna[ii_esp]
      tok_esp <- out$token_associado_coluna[ii_esp]
      tipo_alvo <- out$tipo_base_edicao[ii_esp]
      candidatos <- if (identical(cat_esp, "exotica")) {
        c(
          paste0("amostragem/registro/especies_exotica_", tok_esp),
          paste0("amostragem/registro/exotica_", tok_esp, "_outra_sp")
        )
      } else {
        c(
          paste0("amostragem/registro/forma_vida_", cat_esp, "_", tok_esp, "_sp"),
          paste0("amostragem/registro/forma_vida_", cat_esp, "_", tok_esp)
        )
      }
      candidatos <- candidatos[candidatos %in% caminhos_validos]
      if (!length(candidatos)) next
      if (!is.na(tipo_alvo) && nzchar(tipo_alvo)) {
        bate_tipo <- candidatos[tipo_por_caminho[candidatos] == tipo_alvo]
        if (length(bate_tipo)) candidatos <- bate_tipo
      }
      data.table::set(out, i = ii_esp, j = "caminho_candidato_especie", value = candidatos[1L])
    }
  }

  if (exists("monitora_perfil_painel_edicao_operacional_contrato_unico", mode = "function")) {
 ### Consulta o resolvedor pelo caminho candidato derivado do próprio
 ### contrato quando existir; nos demais casos usa o nome observado.
    chave_consulta_perfil <- fifelse(
      !is.na(out$caminho_candidato_especie) & nzchar(out$caminho_candidato_especie),
      out$caminho_candidato_especie,
      out$atributo_coluna_registros_corrig
    )
    perfil_oper <- tryCatch(
      monitora_perfil_painel_edicao_operacional_contrato_unico(chave_consulta_perfil),
      error = function(e) data.table::data.table()
    )
    if (nrow(perfil_oper)) {
      data.table::setnames(perfil_oper, "atributo_coluna_registros_corrig", "chave_consulta_perfil", skip_absent = TRUE)
      mapa_chave <- data.table::data.table(
        atributo_coluna_registros_corrig = out$atributo_coluna_registros_corrig,
        chave_consulta_perfil = chave_consulta_perfil
      )
      perfil_oper <- merge(mapa_chave, perfil_oper, by = "chave_consulta_perfil", all.x = TRUE, sort = FALSE)
      perfil_oper[, chave_consulta_perfil := NULL]
      cols_oper <- intersect(c(
        "atributo_coluna_registros_corrig", "atributo_canonico_2025", "caminho_registro",
        "name_curto", "tipo_base_contrato_unico", "cardinalidade_operacional_contrato_unico",
        "relevant_contrato_unico", "campo_pai_contrato_unico",
        "escopo_operacional_contrato_unico", "escopos_permitidos_contrato_unico",
        "motivo_escopo_contrato_unico"
      ), names(perfil_oper))
      cols_drop <- setdiff(cols_oper, "atributo_coluna_registros_corrig")
      cols_drop <- intersect(cols_drop, names(out))
      if (length(cols_drop)) out[, (cols_drop) := NULL]
      out <- merge(out, perfil_oper[, ..cols_oper], by = "atributo_coluna_registros_corrig", all.x = TRUE, sort = FALSE)
      out[escopo_operacional_contrato_unico %in% c("ponto"), escopo_sugerido := "ponto"]
      out[escopo_operacional_contrato_unico %in% c("coleta_inteira"), escopo_sugerido := "coleta_inteira"]

 ### reconciliação obrigatória pós-merge do
 ### perfil_painel_edicao. Nenhum atributo pode terminar com
 ### painel_editavel=TRUE quando o contrato único o classifica como
 ### "fora_do_perfil_painel_edicao" ou "protegido" -- isto mascarava,
 ### no painel, atributos que só falhavam na hora de ADICIONAR a
 ### correção (ex.: UA antes da resolução de alias acima). Esta é uma
 ### rede de segurança genérica (não uma lista por nome de atributo):
 ### qualquer atributo futuro nesta mesma contradição já nasce
 ### bloqueado e com motivo visível antes do preenchimento.
      if ("painel_editavel" %in% names(out)) {
        idx_contra <- which(
          !is.na(out$escopo_operacional_contrato_unico) &
            out$escopo_operacional_contrato_unico %in% c("fora_do_perfil_painel_edicao", "protegido") &
            out$painel_editavel %in% TRUE
        )
        if (length(idx_contra)) {
          data.table::set(out, i = idx_contra, j = "painel_editavel", value = FALSE)
          data.table::set(out, i = idx_contra, j = "acoes_permitidas", value = "")
          if (!("painel_motivo_bloqueio" %in% names(out))) out[, painel_motivo_bloqueio := NA_character_]
          data.table::set(
            out, i = idx_contra, j = "painel_motivo_bloqueio",
            value = paste0(
              "reconciliado pelo contrato unico: ", out$motivo_escopo_contrato_unico[idx_contra]
            )
          )
        }
      }
    }
  }
  if ("caminho_candidato_especie" %in% names(out)) out[, caminho_candidato_especie := NULL]
  out[]
}

### --------------------------------------------------------------------
### Identidade operacional imutável. `linha_indice` continua disponível para
### inspeção humana, mas não é mais a identidade de uma linha: exclusões e
### ordenações mudam a posição física. UUIDs candidatos são validados ANTES do
### coalesce, impedindo que um UUID pai/malformado sombreie o UUID válido de
### outra coluna da mesma exportação.
MONITORA_COL_ROW_ID <- "MONITORA_ROW_ID"
MONITORA_COL_UUID_REGISTRO_CANONICO <- "MONITORA_UUID_REGISTRO_CANONICO"

monitora_uuid_registro_valido <- function(x) {
  x <- trimws(as.character(x))
  !is.na(x) & grepl("^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[1-5][0-9a-fA-F]{3}-[89abAB][0-9a-fA-F]{3}-[0-9a-fA-F]{12}$", x)
}

monitora_identidade_assegurar <- function(dt, contexto = "operacional") {
  dt <- monitora_dt_referenciar(dt)
  n <- nrow(dt)
  if (!n) {
    if (!(MONITORA_COL_UUID_REGISTRO_CANONICO %in% names(dt))) data.table::set(dt, j = MONITORA_COL_UUID_REGISTRO_CANONICO, value = character(0))
    if (!(MONITORA_COL_ROW_ID %in% names(dt))) data.table::set(dt, j = MONITORA_COL_ROW_ID, value = character(0))
    return(dt[])
  }
  candidatos_uuid <- unique(intersect(c(
    MONITORA_COL_UUID_REGISTRO_CANONICO, "uuid (amostragem/registro)",
    "amostragem/registro/uuid", "uuid_registro", "UUID_REGISTRO", "UUID"
  ), names(dt)))
  uuid_canon <- rep(NA_character_, n)
  fonte_uuid <- if (".id" %in% names(dt)) as.character(dt[[".id"]]) else if ("arquivo_origem" %in% names(dt)) as.character(dt[["arquivo_origem"]]) else rep("__fonte_unica__", n)
  for (cc in candidatos_uuid) {
    cand <- trimws(as.character(dt[[cc]]))
    cand[!monitora_uuid_registro_valido(cand)] <- NA_character_
    if (identical(cc, "UUID") && "MONITORA_TIPO_ENTRADA" %in% names(dt)) cand[as.character(dt$MONITORA_TIPO_ENTRADA) == "bruto_lote_sismonitora"] <- NA_character_
    chave_fonte_uuid <- paste(fonte_uuid, cand, sep = "::")
    repetido_fonte <- !is.na(cand) & (duplicated(chave_fonte_uuid) | duplicated(chave_fonte_uuid, fromLast = TRUE))
    cand[repetido_fonte] <- NA_character_
    preencher <- is.na(uuid_canon) & !is.na(cand)
    uuid_canon[preencher] <- tolower(cand[preencher])
  }
  data.table::set(dt, j = MONITORA_COL_UUID_REGISTRO_CANONICO, value = uuid_canon)

  row_existente <- if (MONITORA_COL_ROW_ID %in% names(dt)) trimws(as.character(dt[[MONITORA_COL_ROW_ID]])) else rep(NA_character_, n)
  row_ok <- !is.na(row_existente) & nzchar(row_existente) & !duplicated(row_existente) & !duplicated(row_existente, fromLast = TRUE)
  if (all(row_ok)) return(dt[])

  primeira <- function(cands) {
    cc <- intersect(cands, names(dt))
    if (!length(cc)) return(rep("", n))
    out <- rep(NA_character_, n)
    for (nm in cc) {
      val <- trimws(as.character(dt[[nm]]))
      val[is.na(val)] <- ""
      hit <- (is.na(out) | !nzchar(out)) & nzchar(val)
      out[hit] <- val[hit]
    }
    out[is.na(out)] <- ""
    out
  }
  normalizar_id <- function(x) {
    x <- toupper(trimws(as.character(x)))
    x[is.na(x)] <- ""
    gsub("[|\r\n]+", "_", x)
  }
  partes <- list(
    primeira(c("UC", "uc")), primeira(c("CICLO", "ciclo")),
    primeira(c("CAMPANHA", "campanha")), primeira(c("EA", "ea")),
    primeira(c("UA", "ua")), primeira(c("COLETA", "coleta", "coleta_uuid")),
    primeira(c("ponto_amostral (amostragem/registro)", "Ponto amostral", "ponto_amostral")),
    primeira(c("ponto_metro (amostragem/registro)", "Ponto metro", "ponto_metro")),
    primeira(c(".id", "arquivo_origem", "MONITORA_FONTE", "arquivo_fonte"))
  )
  chave <- do.call(paste, c(lapply(partes, normalizar_id), sep = "|"))
  aux_id <- data.table::data.table(chave = chave, ordem = seq_len(n))
  aux_id[, ocorrencia := seq_len(.N), by = chave]
  fallback <- paste0("KEY::", chave, "::", aux_id$ocorrencia)
  novo <- ifelse(!is.na(uuid_canon), paste0("UUID::", uuid_canon), fallback)
  novo[row_ok] <- row_existente[row_ok]
  if (anyDuplicated(novo)) {
    aux_dup <- data.table::data.table(id = novo)
    aux_dup[, ocorrencia := seq_len(.N), by = id]
    novo <- paste0(novo, "::", aux_dup$ocorrencia)
  }
  data.table::set(dt, j = MONITORA_COL_ROW_ID, value = novo)
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento("identidade_linha_r22", "INFO", NA_character_, paste0(n, " linha(s) com identidade operacional assegurada em ", contexto, "; UUID canônico válido em ", sum(!is.na(uuid_canon)), " linha(s)"), "MONITORA_ROW_ID é imutável; linha_indice é apenas posição de exibição")
  }
  dt[]
}

