monitora_correcao_colapsar_contexto_valores <- function(x, max_valores = 12L) {
  x <- unique(trimws(as.character(x)))
  x <- x[!is.na(x) & nzchar(x)]
  if (!length(x)) return(NA_character_)
  if (length(x) == 1L) return(x[1L])
  x <- sort(x)
  if (length(x) <= max_valores) return(paste(x, collapse = "; "))
  paste0("multiplos(", length(x), "): ", paste(utils::head(x, max_valores), collapse = "; "), "; ...")
}

monitora_correcao_contexto_linhas <- function(dt, linhas, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  get_ctx <- function(col) {
    if (is.na(col) || !nzchar(col) || !(col %in% names(dt)) || !length(linhas)) return(NA_character_)
    monitora_correcao_colapsar_contexto_valores(dt[[col]][linhas])
  }
  data.table::data.table(
    UC = get_ctx(chaves$uc),
    EA = get_ctx(chaves$ea),
    UA = get_ctx(chaves$ua),
    CICLO = get_ctx(chaves$ciclo),
    CAMPANHA = get_ctx(chaves$campanha),
    ANO = get_ctx(chaves$ano),
    `Data (data_hora)` = get_ctx(chaves$data_hora),
    `Ponto amostral` = get_ctx(chaves$ponto_amostral),
    `Ponto metro` = get_ctx(chaves$ponto_metro)
  )
}

monitora_correcao_anexar_contexto_operacao <- function(op, dt, linhas, chaves = monitora_correcao_colunas_chave(dt)) {
  op <- data.table::as.data.table(op)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!("linha_indice" %in% names(op))) op[, linha_indice := NA_integer_]
  if (!("monitora_row_id" %in% names(op))) op[, monitora_row_id := NA_character_]
  if (nrow(op) == 1L && length(linhas) > 0L && MONITORA_COL_ROW_ID %in% names(dt)) {
    ids_linhas <- as.character(dt[[MONITORA_COL_ROW_ID]][linhas])
    ids_linhas <- unique(ids_linhas[!is.na(ids_linhas) & nzchar(ids_linhas)])
    if (length(ids_linhas) == 1L) data.table::set(op, j = "monitora_row_id", value = ids_linhas[1L])
    if (!("alvos_solicitados_monitora_row_id" %in% names(op))) op[, alvos_solicitados_monitora_row_id := NA_character_]
    atual_ids <- as.character(op$alvos_solicitados_monitora_row_id[1L])
    if (length(ids_linhas) && monitora_correcao_vazio(atual_ids)) {
      data.table::set(op, j = "alvos_solicitados_monitora_row_id", value = monitora_correcao_serializar_ids_estaveis(ids_linhas))
    }
    if (!is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) {
      if (!("uuid_registro" %in% names(op))) op[, uuid_registro := NA_character_]
      atual_uuid <- as.character(op$uuid_registro[1L])
      uuids_linhas <- unique(as.character(dt[[chaves$uuid_registro]][linhas]))
      uuids_linhas <- uuids_linhas[!is.na(uuids_linhas) & nzchar(uuids_linhas)]
      if (length(uuids_linhas) && monitora_correcao_vazio(atual_uuid)) {
        data.table::set(op, j = "uuid_registro", value = monitora_correcao_colapsar_lista_serializada(uuids_linhas))
      }
    }
  }
  dt_parece_global <- FALSE
  if (exists("registros_corrig", envir = .GlobalEnv, inherits = FALSE)) {
    rr_global <- get("registros_corrig", envir = .GlobalEnv, inherits = FALSE)
    dt_parece_global <- tryCatch(nrow(dt) == nrow(rr_global), error = function(e) FALSE)
  }
 ### Só gravar linha_indice quando as linhas são índices globais de registros_corrig.
 ### Chamadas com subconjuntos filtrados continuam usando coleta/ponto/uuid como fallback.
  if (isTRUE(dt_parece_global) && nrow(op) == 1L && length(linhas) == 1L) data.table::set(op, j = "linha_indice", value = as.integer(linhas[1L]))
  ctx <- monitora_correcao_contexto_linhas(dt, linhas, chaves)
  for (cc in names(ctx)) {
    if (!(cc %in% names(op))) op[, (cc) := NA_character_]
    data.table::set(op, j = cc, value = ctx[[cc]][1L])
  }
 ### manter também as chaves técnicas de ponto nas operações compostas.
 ### A aplicação das correções usa ponto_amostral/ponto_metro como chaves estáveis;
 ### se apenas os rótulos "Ponto amostral"/"Ponto metro" forem preenchidos, ações
 ### contratuais derivadas podem voltar para o escopo da COLETA inteira.
  preencher_chave_tecnica <- function(dest, src) {
    if (!(src %in% names(op))) return(invisible(FALSE))
    if (!(dest %in% names(op))) op[, (dest) := NA_character_]
    val_src <- as.character(op[[src]][1L])
    val_dst <- as.character(op[[dest]][1L])
    if (nrow(op) == 1L && monitora_correcao_vazio(val_dst) && !monitora_correcao_vazio(val_src)) {
      data.table::set(op, j = dest, value = val_src)
    }
    invisible(TRUE)
  }
  preencher_chave_tecnica("ponto_amostral", "Ponto amostral")
  preencher_chave_tecnica("ponto_metro", "Ponto metro")
  op[]
}

### sanitização de placeholders e conciliação semântica ----------------
### O plano solicitado pelo usuário é imutável; o plano efetivo é derivado
### por especificidade. Correções específicas prevalecem sobre operações em
### lote e sanitizações amplas, independentemente da ordem dos cliques.

monitora_correcao_sanitizar_placeholders_semanticos <- function(dt, linhas = NULL, colunas = NULL,
                                                                 contexto = "sanitizacao_placeholders_semanticos",
                                                                 gravar = TRUE) {
  dt <- monitora_dt_referenciar(dt)
  if (is.null(linhas)) linhas <- seq_len(nrow(dt))
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas)) return(list(dt = dt[], audit = data.table::data.table(), linhas = integer()))
  if (is.null(colunas)) {
    mapa <- tryCatch(monitora_correcao_mapa_colunas_canonicas(
      dt, contexto = paste0(contexto, "_mapa"), gravar = FALSE,
      incluir_preenchidos = FALSE, usar_cache = TRUE
    ), error = function(e) data.table::data.table())
    papeis <- c(
      "atributo_dependente_habito", "especie_nome_popular",
      "lista_principal_forma_vida", "descritor_outra_forma_vida",
      "campo_superior_tipo_forma_vida"
    )
    colunas <- if (nrow(mapa)) mapa[papel_coluna %in% papeis, unique(coluna_registros_corrig)] else character(0)
    colunas <- unique(c(colunas, names(dt)[grepl("outr.*forma.*vida|outra.*especie|especies.*outr", monitora_correcao_normalizar_nome_coluna(names(dt))) ]))
  }
  colunas <- unique(as.character(colunas))
  colunas <- colunas[!is.na(colunas) & nzchar(colunas) & colunas %in% names(dt)]
  audit <- data.table::data.table()
  linhas_mudadas <- integer(0)
  for (cc in colunas) {
    valores <- as.character(dt[[cc]][linhas])
    vazio_sem <- monitora_correcao_vazio_semantico_vec(valores)
    vazio_basico <- is.na(valores) | toupper(trimws(valores)) %in% c("", "NA", "NAN", "NULL", "<NA>", "---")
    idx_local <- which(vazio_sem & !vazio_basico)
    if (!length(idx_local)) next
    idx <- linhas[idx_local]
    antes <- valores[idx_local]
    data.table::set(dt, i = idx, j = cc, value = NA_character_)
    audit <- data.table::rbindlist(list(audit, data.table::data.table(
      contexto = contexto,
      status = "placeholder_serializado_sanitizado",
      linha_indice = idx,
      monitora_row_id = if (MONITORA_COL_ROW_ID %in% names(dt)) as.character(dt[[MONITORA_COL_ROW_ID]][idx]) else NA_character_,
      atributo = cc,
      valor_antes = antes,
      valor_depois = NA_character_,
      regra = "todos_os_componentes_serializados_sao_marcadores_de_ausencia"
    )), fill = TRUE, use.names = TRUE)
    linhas_mudadas <- unique(c(linhas_mudadas, idx))
  }
  if (isTRUE(gravar)) {
    out_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE)
    log_dir <- get0("MONITORA_LOG_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "log"), inherits = TRUE)
    exec_id <- get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)
    dir.create(out_dir, recursive = TRUE, showWarnings = FALSE)
    dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
    arq_ult <- file.path(out_dir, "auditoria_sanitizacao_placeholders_semanticos_ultima_execucao.csv")
    arq_log <- file.path(log_dir, paste0("auditoria_sanitizacao_placeholders_semanticos_", exec_id, ".csv"))
    monitora_fwrite(audit, arq_ult, na = "")
    monitora_fwrite(audit, arq_log, na = "")
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento(
        "sanitizacao_placeholders_semanticos", "INFO", arq_ult,
        paste0(nrow(audit), " célula(s) com placeholder serializado sanitizada(s) em ", contexto),
        "valores originais e atributos preservados na auditoria"
      )
    }
  }
  list(dt = dt[], audit = audit[], linhas = linhas_mudadas)
}

monitora_correcao_serializar_ids_estaveis <- function(x) {
  x <- unique(as.character(x))
  x <- x[!is.na(x) & nzchar(x)]
  if (!length(x)) return(NA_character_)
  x <- gsub("%", "%25", x, fixed = TRUE)
  x <- gsub("|", "%7C", x, fixed = TRUE)
  paste(x, collapse = "\n")
}

monitora_correcao_parse_ids_estaveis <- function(x) {
  x <- as.character(x)
  x <- x[!is.na(x) & nzchar(x)]
  if (!length(x)) return(character(0))
  out <- unlist(strsplit(x, "\n", fixed = TRUE), use.names = FALSE)
  out <- gsub("%7C", "|", out, fixed = TRUE)
  out <- gsub("%25", "%", out, fixed = TRUE)
  unique(out[!is.na(out) & nzchar(out)])
}

monitora_correcao_classe_abrangencia <- function(op) {
  op <- data.table::as.data.table(op)
  existente <- if ("classe_abrangencia_semantica" %in% names(op)) trimws(as.character(op$classe_abrangencia_semantica[1L])) else ""
  if (!is.na(existente) && nzchar(existente)) return(existente)
  tipo <- if ("tipo_correcao" %in% names(op)) tolower(trimws(as.character(op$tipo_correcao[1L]))) else ""
  acao <- if ("acao" %in% names(op)) tolower(trimws(as.character(op$acao[1L]))) else ""
  txt <- paste(tipo, acao)
  if (grepl("limpeza_outras_formas|sanitizar_orfaos_encostam|sanitizacao_habito_obrigatorio_ausente", txt)) return("sanitizacao_ampla")
  if (grepl("movimento_forma_vida_lote|lote_multicoletas_campo_superior", txt)) return("operacao_lote")
  "correcao_especifica"
}

monitora_correcao_prioridade_abrangencia <- function(classe) {
  data.table::fcase(
    classe == "correcao_especifica", 3L,
    classe == "operacao_lote", 2L,
    classe == "sanitizacao_ampla", 1L,
    default = 0L
  )
}

### identidade canônica e conservação dos movimentos ----------------
### `valor_original_esperado` é uma fotografia/pré-condição da célula e nunca
### participa da identidade do token nem da lista de remoção. A identidade de
### um movimento é: categoria de origem + token canônico de origem + categoria
### e forma de destino (+ hábito, quando aplicável).
monitora_correcao_tokens_origem_movimento <- function(op) {
  op <- data.table::as.data.table(op)
  if (!nrow(op)) return(character(0))
  get1 <- function(cc) if (cc %in% names(op)) as.character(op[[cc]][1L]) else NA_character_
  vals <- monitora_correcao_parse_lista_serializada(get1("token_removido"))
  if (!length(vals)) vals <- monitora_correcao_parse_lista_serializada(get1("token_pai"))
  vals <- unique(trimws(as.character(vals)))
  vals <- vals[!is.na(vals) & nzchar(vals)]
  if (!length(vals)) return(character(0))
  todas <- tolower(vals) %in% c("__todas__", "todas", "todos", "all", "*")
  if (any(todas)) return("*")
  vals <- tryCatch(
    monitora_correcao_forma_canonica_lote(vals),
    error = function(e) monitora_correcao_normalizar_nome_coluna(vals)
  )
  sort(unique(vals[!is.na(vals) & nzchar(vals)]))
}

monitora_correcao_eh_movimento_semantico <- function(op) {
  op <- data.table::as.data.table(op)
  if (!nrow(op)) return(FALSE)
  get1 <- function(cc) if (cc %in% names(op)) tolower(trimws(as.character(op[[cc]][1L]))) else ""
  get1("acao") %in% c("mover_forma_vida", "mover_forma_vida_lote", "movimento_forma_vida_atomico", "movimento_forma_vida_lote_atomico") ||
    get1("tipo_correcao") %in% c("movimento_forma_vida", "movimento_forma_vida_atomico", "movimento_forma_vida_condicional", "movimento_forma_vida_lote", "movimento_forma_vida_lote_atomico") ||
    get1("atributo_coluna_registros_corrig") %in% c("__mover_forma_vida__", "__movimento_forma_vida__", "__mover_forma_vida_lote__", "__movimento_forma_vida_lote__")
}

monitora_correcao_relacao_movimentos <- function(novo, existente) {
  if (!monitora_correcao_eh_movimento_semantico(novo) || !monitora_correcao_eh_movimento_semantico(existente)) return(NA_character_)
  novo <- data.table::as.data.table(novo); existente <- data.table::as.data.table(existente)
  get1 <- function(x, cc) if (cc %in% names(x)) tolower(trimws(as.character(x[[cc]][1L]))) else ""
  origem_n <- get1(novo, "categoria_origem"); origem_e <- get1(existente, "categoria_origem")
  if (!identical(origem_n, origem_e)) return("compativel_categorias_origem_distintas")
  tok_n <- monitora_correcao_tokens_origem_movimento(novo)
  tok_e <- monitora_correcao_tokens_origem_movimento(existente)
  if (!length(tok_n) || !length(tok_e)) return("conflito_movimento_sem_token_origem")
  sobrepoe <- "*" %in% c(tok_n, tok_e) || length(intersect(tok_n, tok_e)) > 0L
  if (!sobrepoe) return("compativel_tokens_origem_distintos")
  efeito <- function(x) {
    forma <- get1(x, "forma_valida_escolhida")
    if (!nzchar(forma)) forma <- get1(x, "valor_novo")
    forma <- tryCatch(monitora_correcao_forma_canonica_lote(forma)[1L], error = function(e) monitora_correcao_normalizar_nome_coluna(forma)[1L])
    paste(get1(x, "categoria_destino"), forma, get1(x, "habito_escolhido"), sep = "|")
  }
  if (identical(efeito(novo), efeito(existente))) return("duplicada_mesmo_movimento")
  "conflito_mesmo_token_origem_destinos_distintos"
}

monitora_correcao_tokens_canonicos_valor <- function(valor) {
  vals <- tryCatch(monitora_correcao_tokenizar(valor), error = function(e) character(0))
  vals <- tryCatch(monitora_correcao_forma_canonica_lote(vals), error = function(e) monitora_correcao_normalizar_nome_coluna(vals))
  sort(unique(vals[!is.na(vals) & nzchar(vals)]))
}

monitora_correcao_validar_conservacao_tokens <- function(antes, depois, remocoes_permitidas = character(0)) {
  antes <- as.character(antes); depois <- as.character(depois)
  if (length(antes) != length(depois)) return(list(ok = FALSE, linhas = seq_len(max(length(antes), length(depois))), detalhes = "cardinalidade_antes_depois_divergente"))
  permitidos <- tryCatch(monitora_correcao_forma_canonica_lote(remocoes_permitidas), error = function(e) monitora_correcao_normalizar_nome_coluna(remocoes_permitidas))
  permitidos <- unique(permitidos[!is.na(permitidos) & nzchar(permitidos)])
  perdas <- lapply(seq_along(antes), function(ii) {
    a <- monitora_correcao_tokens_canonicos_valor(antes[ii])
    d <- monitora_correcao_tokens_canonicos_valor(depois[ii])
    setdiff(setdiff(a, d), permitidos)
  })
  falhas <- which(lengths(perdas) > 0L)
  list(
    ok = !length(falhas),
    linhas = as.integer(falhas),
    detalhes = if (length(falhas)) paste(vapply(falhas, function(ii) paste0(ii, ":", paste(perdas[[ii]], collapse = "+")), character(1L)), collapse = ";") else ""
  )
}

monitora_correcao_dominios_operacao <- function(op, dt = NULL) {
  op <- data.table::as.data.table(op)
  get1 <- function(cc) if (cc %in% names(op)) as.character(op[[cc]][1L]) else NA_character_
  tipo <- tolower(trimws(get1("tipo_correcao")))
  acao <- tolower(trimws(get1("acao")))
  attr <- get1("atributo_coluna_registros_corrig")
  contexto <- paste(tipo, acao, attr, get1("tipo_triagem"), get1("tipo_ocorrencia_diagnostica"), get1("ocorrencia_diagnostica_contextual"), get1("escopo_diagnostico_mvlote"))
  contexto_norm <- monitora_correcao_normalizar_nome_coluna(contexto)
  toks_op <- unique(c(
    monitora_correcao_parse_lista_serializada(get1("token_removido")),
    monitora_correcao_parse_lista_serializada(get1("valor_original_esperado")),
    monitora_correcao_parse_lista_serializada(get1("valor_novo")),
    monitora_correcao_parse_lista_serializada(get1("token_pai"))
  ))
  toks_op_norm <- monitora_correcao_normalizar_nome_coluna(toks_op)
  if (grepl("limpar_outras_formas|outras_formas_vida|outra_forma_vida|forma_vida_outros", contexto_norm) || any(toks_op_norm %in% monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokens_residuo_historico_outras_formas()))) return("outras_formas_vida")
 ### Movimento deve ser reconhecido antes da regra de hábito: formas que
 ### exigem hábito possuem simultaneamente o domínio do token de origem e o
 ### domínio do hábito de destino. Classificá-las apenas como hábito fazia
 ### movimentos distintos colidirem e ocultava a mutação da lista principal.
  if (monitora_correcao_eh_movimento_semantico(op)) {
    cat <- tolower(trimws(get1("categoria_origem")))
    toks <- monitora_correcao_tokens_origem_movimento(op)
    if (!length(toks)) toks <- "forma_indefinida"
    dominios <- paste0("forma_vida:", cat, ":", toks)
    hab <- get1("habito_escolhido")
    destino <- tolower(trimws(get1("categoria_destino")))
    forma_destino <- get1("forma_valida_escolhida")
    if (monitora_correcao_vazio(forma_destino)) forma_destino <- get1("valor_novo")
    forma_destino <- tryCatch(monitora_correcao_forma_canonica_lote(forma_destino)[1L], error = function(e) monitora_correcao_normalizar_nome_coluna(forma_destino)[1L])
    if (!monitora_correcao_vazio(hab) && !monitora_correcao_vazio(destino) && !monitora_correcao_vazio(forma_destino)) {
      dominios <- c(dominios, paste0("habito:", destino, ":", forma_destino))
    }
    return(unique(dominios))
  }
  papel <- tryCatch(monitora_correcao_papel_coluna_canonico(attr)[1L], error = function(e) NA_character_)
  regra_habito_op <- tryCatch(monitora_correcao_regra_habito_operacao(op), error = function(e) data.table::data.table())
  if (nrow(regra_habito_op) == 1L || grepl("habito", contexto_norm) || isTRUE(papel == "atributo_dependente_habito")) {
 ### O domínio deve representar o mesmo atributo semântico mesmo quando
 ### uma operação específica usa o name/caminho canônico e SANHAB usa o
 ### rótulo físico materializado. Sem essa canonização, as duas intenções
 ### pareciam independentes e a sanitização ampla podia sobrescrever a
 ### decisão específica.
    cat_h <- if (nrow(regra_habito_op) == 1L) tolower(trimws(as.character(regra_habito_op$categoria[1L]))) else tolower(trimws(get1("categoria_destino")))
    if (monitora_correcao_vazio(cat_h)) cat_h <- tolower(trimws(get1("categoria_origem")))
    forma_h <- if (nrow(regra_habito_op) == 1L) monitora_correcao_normalizar_nome_coluna(as.character(regra_habito_op$forma[1L])) else monitora_correcao_normalizar_nome_coluna(get1("forma_valida_escolhida"))
    attr_norm_h <- monitora_correcao_normalizar_nome_coluna(attr)
    m_attr_h <- regexec("forma_vida_(nativa|exotica|seca_morta)_(bromelioide|cactacea|orquidea|samambaia)", attr_norm_h, perl = TRUE)
    p_attr_h <- regmatches(attr_norm_h, m_attr_h)[[1L]]
    if (length(p_attr_h) >= 3L) {
      if (monitora_correcao_vazio(cat_h)) cat_h <- p_attr_h[2L]
      if (monitora_correcao_vazio(forma_h)) forma_h <- p_attr_h[3L]
    }
    if (!is.null(dt) && inherits(dt, c("data.frame", "data.table")) && (monitora_correcao_vazio(cat_h) || monitora_correcao_vazio(forma_h))) {
      mapa_h <- tryCatch(monitora_correcao_mapa_colunas_canonicas(dt), error = function(e) data.table::data.table())
      if (nrow(mapa_h)) {
        z_h <- mapa_h[coluna_registros_corrig == attr]
        if (nrow(z_h)) {
          if (monitora_correcao_vazio(cat_h)) cat_h <- tolower(trimws(as.character(z_h$categoria[1L])))
          if (monitora_correcao_vazio(forma_h)) forma_h <- monitora_correcao_normalizar_nome_coluna(as.character(z_h$token_associado[1L]))
        }
      }
    }
    if (forma_h %in% c("erva_bromelioide", "bromelioides")) forma_h <- "bromelioide"
    if (!monitora_correcao_vazio(cat_h) && !monitora_correcao_vazio(forma_h)) return(paste0("habito:", cat_h, ":", forma_h))
    return(paste0("habito:atributo:", attr_norm_h))
  }
  if (grepl("sanitizar_orfaos_encostam|sem_forma_vida", contexto_norm)) {
    cat <- get1("categoria_origem")
    if (is.na(cat) || !nzchar(cat)) {
      cat <- sub(".*(nativa|exotica|seca_morta)_sem_forma_vida.*", "\\1", contexto_norm)
      if (identical(cat, contexto_norm)) cat <- "categoria_indefinida"
    }
    return(paste0("orfao_encostam:", cat))
  }
  if (isTRUE(papel == "campo_superior_tipo_forma_vida") || grepl("encostam|tipo_forma_vida", contexto_norm)) {
    cats <- intersect(toks_op_norm, c("nativa", "exotica", "seca_morta"))
    if (length(cats)) return(paste0("orfao_encostam:", cats))
  }
  if (isTRUE(papel == "lista_principal_forma_vida")) {
    cat <- tryCatch(monitora_correcao_categoria_coluna_canonica(attr)[1L], error = function(e) NA_character_)
    toks <- toks_op_norm[!is.na(toks_op_norm) & nzchar(toks_op_norm)]
    if (length(toks)) return(paste0("forma_vida:", cat, ":", toks))
  }
  if (!is.na(attr) && nzchar(attr)) return(paste0("atributo:", attr))
  "dominio_indefinido"
}

monitora_correcao_efeito_operacao <- function(op) {
  op <- data.table::as.data.table(op)
  get1 <- function(cc) if (cc %in% names(op)) as.character(op[[cc]][1L]) else ""
  paste(
    tolower(trimws(get1("acao"))),
    trimws(get1("valor_novo")), trimws(get1("token_removido")),
    trimws(get1("categoria_origem")), trimws(get1("categoria_destino")),
    trimws(get1("forma_valida_escolhida")), trimws(get1("habito_escolhido")),
    sep = "|"
  )
}

monitora_correcao_efeito_operacao_dominio <- function(op, dominio) {
  op <- data.table::as.data.table(op)
  get1 <- function(cc) if (cc %in% names(op)) trimws(as.character(op[[cc]][1L])) else ""
  dominio <- as.character(dominio)[1L]
  if (grepl("^habito:", dominio)) {
    val <- get1("habito_escolhido")
    if (monitora_correcao_vazio(val)) val <- get1("valor_novo")
    return(paste0("habito_final:", tolower(val)))
  }
  if (identical(dominio, "outras_formas_vida")) return("resolver_outras_formas_vida")
  if (grepl("^orfao_encostam:", dominio)) return("resolver_orfao_encostam")
  if (grepl("^forma_vida:", dominio)) {
    destino <- get1("categoria_destino")
    forma <- get1("forma_valida_escolhida")
    if (monitora_correcao_vazio(forma)) forma <- get1("valor_novo")
    return(paste0("forma_final:", destino, ":", forma, ":", tolower(get1("acao"))))
  }
  monitora_correcao_efeito_operacao(op)
}

monitora_correcao_linhas_alvo_operacao <- function(dt, op, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, indice_row_id = NULL) {
  dt <- data.table::as.data.table(dt)
  op <- data.table::as.data.table(op)
  if (!nrow(op) || !nrow(dt)) return(integer(0))
  n_esperado <- suppressWarnings(as.integer(c(
    if ("n_linhas_solicitadas" %in% names(op)) op$n_linhas_solicitadas[1L] else NA,
    if ("n_linhas_esperado" %in% names(op)) op$n_linhas_esperado[1L] else NA,
    if ("n_linhas_alvo" %in% names(op)) op$n_linhas_alvo[1L] else NA
  )))
  n_esperado <- n_esperado[is.finite(n_esperado) & n_esperado > 0L]
  n_esperado <- if (length(n_esperado)) n_esperado[1L] else NA_integer_
  idx_row_id <- integer(0)
  if (MONITORA_COL_ROW_ID %in% names(dt)) {
 ### Depois da conciliação, a lista efetiva é a autoridade: ela já retirou
 ### alvos protegidos por decisões específicas e não depende de posições
 ### físicas antigas. Só usar monitora_row_id legado quando não houver
 ### escopo efetivo materializado.
    ids_efetivos <- if ("alvos_efetivos_monitora_row_id" %in% names(op)) monitora_correcao_parse_ids_estaveis(as.character(op$alvos_efetivos_monitora_row_id)) else character(0)
    ids <- if (length(ids_efetivos)) ids_efetivos else if ("monitora_row_id" %in% names(op)) monitora_correcao_parse_ids_estaveis(as.character(op$monitora_row_id)) else character(0)
    ids <- ids[!is.na(ids) & nzchar(ids)]
    idx <- if (!is.null(indice_row_id)) unname(indice_row_id[ids]) else match(ids, as.character(dt[[MONITORA_COL_ROW_ID]]), nomatch = 0L)
    idx[is.na(idx)] <- 0L
    idx_row_id <- unique(as.integer(idx[idx > 0L]))
  }
  idx_uuid <- integer(0)
  if ("uuid_registro" %in% names(op) && !is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) {
    uu <- unique(monitora_correcao_parse_lista_serializada(op$uuid_registro))
    uu <- uu[!is.na(uu) & nzchar(uu)]
    idx_uuid <- unique(as.integer(which(as.character(dt[[chaves$uuid_registro]]) %chin% uu)))
  }
  vals_serial <- character(0)
  for (cc in intersect(c("linhas_alvo_serializadas_operacao", "linhas_alvo_serializadas", "linha_indice"), names(op))) {
    vals_serial <- c(vals_serial, as.character(op[[cc]]))
  }
  idx_serial <- suppressWarnings(as.integer(monitora_correcao_parse_serial_generico(vals_serial)))
  idx_serial <- unique(idx_serial[!is.na(idx_serial) & idx_serial >= 1L & idx_serial <= nrow(dt)])
 ### Em execução já afetados pelo defeito de agrupamento, monitora_row_id
 ### guardou só o primeiro alvo. Recupera a lista física completa somente se
 ### (a) sua cardinalidade coincide com a intenção congelada e (b) todos os
 ### IDs/UUIDs ainda disponíveis apontam para posições contidas nessa lista.
 ### Essa dupla verificação evita transformar linha_indice legado em fallback
 ### amplo e silencioso quando o dataset/reordenamento já não é compatível.
  idx_estaveis_disponiveis <- unique(c(idx_row_id, idx_uuid))
  serial_compativel <- is.finite(n_esperado) && length(idx_serial) == n_esperado &&
    length(idx_estaveis_disponiveis) > 0L && all(idx_estaveis_disponiveis %in% idx_serial)
  if (isTRUE(serial_compativel) && length(idx_estaveis_disponiveis) < n_esperado) return(idx_serial)
  if (length(idx_row_id) && (!is.finite(n_esperado) || length(idx_row_id) == n_esperado)) return(idx_row_id)
  if (length(idx_uuid) && is.finite(n_esperado) && length(idx_uuid) == n_esperado) return(idx_uuid)
  if (length(idx_row_id)) return(idx_row_id)
  if (length(idx_uuid)) return(idx_uuid)
  if (length(idx_serial) && !length(idx_estaveis_disponiveis)) return(idx_serial)
  tryCatch(monitora_correcao_localizar_linhas(dt, op, chaves, indice), error = function(e) integer(0))
}

monitora_correcao_aplicar_escopo_conciliado <- function(dt, linhas, op) {
  dt <- data.table::as.data.table(dt)
  op <- data.table::as.data.table(op)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas) || !nrow(op)) return(linhas)
  ids_ef <- if ("alvos_efetivos_monitora_row_id" %in% names(op)) monitora_correcao_parse_ids_estaveis(op$alvos_efetivos_monitora_row_id) else character(0)
  if (length(ids_ef) && MONITORA_COL_ROW_ID %in% names(dt)) {
    linhas <- linhas[as.character(dt[[MONITORA_COL_ROW_ID]][linhas]) %chin% ids_ef]
  } else if ("linhas_alvo_efetivas_serializadas" %in% names(op)) {
    idx_ef <- suppressWarnings(as.integer(monitora_correcao_parse_serial_generico(op$linhas_alvo_efetivas_serializadas)))
    idx_ef <- unique(idx_ef[!is.na(idx_ef) & idx_ef >= 1L & idx_ef <= nrow(dt)])
    if (length(idx_ef)) linhas <- intersect(linhas, idx_ef)
  }
  unique(as.integer(linhas))
}

monitora_correcao_reconciliar_plano_semantico <- function(dt, corr, contexto = "reconciliacao_semantica",
                                                           gravar = TRUE, abortar = FALSE) {
  dt <- data.table::as.data.table(dt)
  corr <- data.table::copy(data.table::as.data.table(corr))
  vazio <- list(corr = corr, auditoria = data.table::data.table(), conflitos = data.table::data.table(), n_excluidos = 0L, n_conflitos = 0L)
  if (!nrow(corr)) return(vazio)
  template <- monitora_correcao_template()
  for (cc in setdiff(names(template), names(corr))) data.table::set(corr, j = cc, value = template[[cc]][1L])
  if (!(MONITORA_COL_ROW_ID %in% names(dt))) dt <- monitora_identidade_assegurar(dt, contexto = paste0(contexto, "_identidade"))
  chaves <- monitora_correcao_colunas_chave(dt)
  indice <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  indice_row_id <- stats::setNames(seq_len(nrow(dt)), as.character(dt[[MONITORA_COL_ROW_ID]]))
  atomos <- list()
  conflitos_localizacao <- list()
  for (ii in seq_len(nrow(corr))) {
    classe <- monitora_correcao_classe_abrangencia(corr[ii])
    dominios <- unique(monitora_correcao_dominios_operacao(corr[ii], dt = dt))
    linhas <- monitora_correcao_linhas_alvo_operacao(dt, corr[ii], chaves, indice, indice_row_id = indice_row_id)
    linhas <- unique(as.integer(linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]))
    ids_op <- if ("id_correcao" %in% names(corr)) as.character(corr$id_correcao[ii]) else paste0("__linha_", ii)
    if (is.na(ids_op) || !nzchar(ids_op)) ids_op <- paste0("__linha_", ii)
    ids_resolvidos <- if (length(linhas)) as.character(dt[[MONITORA_COL_ROW_ID]][linhas]) else character(0)
    n_solicitado <- suppressWarnings(as.integer(corr$n_linhas_solicitadas[ii]))
    if (!is.finite(n_solicitado) || n_solicitado < 1L) n_solicitado <- suppressWarnings(as.integer(corr$n_linhas_esperado[ii]))
    if (!is.finite(n_solicitado) || n_solicitado < 1L) n_solicitado <- length(ids_resolvidos)
    ids_solicitados_congelados <- monitora_correcao_parse_ids_estaveis(c(
      corr$alvos_solicitados_monitora_row_id[ii], corr$monitora_row_id[ii]
    ))
 ### Só completar a identidade solicitada quando todos os alvos forem
 ### recuperados. Em falha parcial, preservar a lista original permite
 ### diagnosticar exatamente quais identidades deixaram de resolver.
    if (!length(ids_solicitados_congelados) ||
        (length(ids_resolvidos) == n_solicitado && length(ids_solicitados_congelados) != n_solicitado)) {
      data.table::set(corr, i = ii, j = "alvos_solicitados_monitora_row_id", value = monitora_correcao_serializar_ids_estaveis(ids_resolvidos))
    }
    data.table::set(corr, i = ii, j = "n_linhas_solicitadas", value = as.integer(n_solicitado))
    n_itens_req <- suppressWarnings(as.integer(corr$n_itens_solicitados[ii]))
    if (!is.finite(n_itens_req) || n_itens_req < 1L) n_itens_req <- max(1L, n_solicitado)
    data.table::set(corr, i = ii, j = "n_itens_solicitados", value = as.integer(n_itens_req))
    if (!length(linhas) || length(ids_resolvidos) != n_solicitado) {
      conflitos_localizacao[[length(conflitos_localizacao) + 1L]] <- data.table::data.table(
        monitora_row_id = if (length(ids_resolvidos)) monitora_correcao_serializar_ids_estaveis(ids_resolvidos) else NA_character_,
        linha_indice = NA_integer_, dominio_semantico = paste(dominios, collapse = " | "),
        ids_operacoes = ids_op, classes = classe,
        efeitos = paste0("cardinalidade_solicitada=", n_solicitado, "; cardinalidade_resolvida=", length(ids_resolvidos)),
        contexto = contexto, status = "conflito_cardinalidade_alvos_nao_resolvida",
        mensagem = "A operação foi bloqueada: nem todos os alvos declarados foram resolvidos por identidade estável"
      )
      next
    }
    atomos[[length(atomos) + 1L]] <- data.table::CJ(
      op_row = ii, dominio_semantico = dominios, linha_indice = linhas,
      sorted = FALSE, unique = TRUE
    )[, `:=`(
      id_correcao = ids_op,
      monitora_row_id = as.character(dt[[MONITORA_COL_ROW_ID]][linha_indice]),
      classe_abrangencia_semantica = classe,
      prioridade = monitora_correcao_prioridade_abrangencia(classe),
      efeito = vapply(dominio_semantico, function(dd) monitora_correcao_efeito_operacao_dominio(corr[ii], dd), character(1L))
    )]
  }
  atom <- if (length(atomos)) data.table::rbindlist(atomos, fill = TRUE, use.names = TRUE) else data.table::data.table()
  conflitos_loc <- if (length(conflitos_localizacao)) data.table::rbindlist(conflitos_localizacao, fill = TRUE, use.names = TRUE) else data.table::data.table()
  if (!nrow(atom)) {
    if (isTRUE(abortar) && nrow(conflitos_loc)) stop("Plano semântico bloqueado: nenhum alvo pôde ser resolvido com a cardinalidade solicitada.", call. = FALSE)
    return(list(corr = corr[0], auditoria = data.table::data.table(), conflitos = conflitos_loc[], n_excluidos = 0L, n_conflitos = nrow(conflitos_loc)))
  }

  especificas <- unique(atom[classe_abrangencia_semantica == "correcao_especifica", .(
    alvo = monitora_row_id, dominio_semantico, id_protetor = id_correcao
  )])
  especificas_wild <- especificas[grepl("^forma_vida:[^:]+:", dominio_semantico)]
  if (nrow(especificas_wild)) {
    especificas_wild[, dominio_semantico := sub("^(forma_vida:[^:]+:).*$", "\\1*", dominio_semantico)]
    especificas <- unique(data.table::rbindlist(list(especificas, especificas_wild), fill = TRUE, use.names = TRUE))
  }
  excl <- if (nrow(especificas)) merge(
    atom[classe_abrangencia_semantica != "correcao_especifica"],
    especificas,
    by.x = c("monitora_row_id", "dominio_semantico"),
    by.y = c("alvo", "dominio_semantico"),
    allow.cartesian = TRUE
  ) else data.table::data.table()
  if (nrow(excl)) excl <- excl[id_correcao != id_protetor]

 ### Conflitos que não têm solução pela precedência: duas decisões específicas
 ### divergentes, ou duas operações não específicas divergentes sobre o mesmo
 ### alvo/domínio. Sanitização/lote versus específica é resolvido por exclusão.
  conflitos <- atom[, {
    ids <- unique(id_correcao)
    classes <- unique(classe_abrangencia_semantica)
    efeitos <- unique(efeito)
    conflito <- length(ids) > 1L && length(efeitos) > 1L &&
      (all(classes == "correcao_especifica") || !any(classes == "correcao_especifica"))
    if (conflito) .(ids_operacoes = paste(ids, collapse = " | "), classes = paste(classes, collapse = " | "), efeitos = paste(efeitos, collapse = " | ")) else NULL
  }, by = .(monitora_row_id, linha_indice, dominio_semantico)]
  if (nrow(conflitos_loc)) conflitos <- data.table::rbindlist(list(conflitos, conflitos_loc), fill = TRUE, use.names = TRUE)

 ### TRIOUT não pode apagar/rebaixar um ancestral quando existe descendente
 ### ecológico significativo. Placeholders já foram sanitizados e não entram.
  tri_rows <- unique(atom[classe_abrangencia_semantica == "sanitizacao_ampla" & dominio_semantico == "outras_formas_vida", .(op_row, id_correcao, monitora_row_id, linha_indice)])
  if (nrow(tri_rows) && nrow(excl)) {
    excl_tri <- unique(excl[dominio_semantico == "outras_formas_vida", .(op_row, monitora_row_id)])
    if (nrow(excl_tri)) tri_rows <- tri_rows[!excl_tri, on = .(op_row, monitora_row_id)]
  }
  if (nrow(tri_rows)) {
    regras <- tryCatch(monitora_correcao_contrato_fechamento_hierarquico(dt), error = function(e) data.table::data.table())
    regras <- regras[status_regra == "ok" & token %in% monitora_correcao_tokens_residuo_historico_outras_formas() & campo_inferior %in% names(dt)]
    if (nrow(regras)) {
      conf_desc <- list()
      for (rr in seq_len(nrow(tri_rows))) {
        li <- tri_rows$linha_indice[rr]
        cols_sig <- regras[!monitora_correcao_vazio_vec(vapply(campo_inferior, function(cc) as.character(dt[[cc]][li]), character(1L))), unique(campo_inferior)]
        if (length(cols_sig)) conf_desc[[length(conf_desc) + 1L]] <- data.table::data.table(
          monitora_row_id = tri_rows$monitora_row_id[rr], linha_indice = li,
          dominio_semantico = "outras_formas_vida",
          ids_operacoes = tri_rows$id_correcao[rr], classes = "sanitizacao_ampla",
          efeitos = paste0("conflito_descendente_significativo:", paste(cols_sig, collapse = " | "))
        )
      }
      if (length(conf_desc)) conflitos <- unique(data.table::rbindlist(list(conflitos, data.table::rbindlist(conf_desc, fill = TRUE)), fill = TRUE, use.names = TRUE))
    }
  }

  auditoria <- data.table::data.table()
  manter <- rep(TRUE, nrow(corr))
  for (ii in seq_len(nrow(corr))) {
    classe <- monitora_correcao_classe_abrangencia(corr[ii])
    at_i <- atom[op_row == ii]
    ids_todos <- unique(at_i$monitora_row_id)
    ex_i <- if (nrow(excl)) excl[op_row == ii] else excl
    ids_ex <- unique(as.character(ex_i$monitora_row_id))
    ids_ef <- setdiff(ids_todos, ids_ex)
    linhas_ef <- unique(at_i[monitora_row_id %chin% ids_ef, linha_indice])
    prot <- unique(as.character(ex_i$id_protetor))
    prot <- prot[!is.na(prot) & nzchar(prot)]
    data.table::set(corr, i = ii, j = "classe_abrangencia_semantica", value = classe)
    data.table::set(corr, i = ii, j = "dominio_semantico", value = paste(unique(at_i$dominio_semantico), collapse = " | "))
    data.table::set(corr, i = ii, j = "alvos_efetivos_monitora_row_id", value = monitora_correcao_serializar_ids_estaveis(ids_ef))
    data.table::set(corr, i = ii, j = "alvos_excluidos_monitora_row_id", value = monitora_correcao_serializar_ids_estaveis(ids_ex))
    data.table::set(corr, i = ii, j = "n_linhas_efetivas", value = as.integer(length(ids_ef)))
    data.table::set(corr, i = ii, j = "n_linhas_excluidas", value = as.integer(length(ids_ex)))
    data.table::set(corr, i = ii, j = "n_itens_efetivos", value = as.integer(length(ids_ef)))
    data.table::set(corr, i = ii, j = "ids_operacoes_protetoras", value = if (length(prot)) paste(prot, collapse = " | ") else NA_character_)
    data.table::set(corr, i = ii, j = "linhas_alvo_efetivas_serializadas", value = monitora_correcao_colapsar_lista_serializada(as.character(linhas_ef)))
    n_itens_req_i <- suppressWarnings(as.integer(corr$n_itens_solicitados[ii]))
    houve_dedup <- is.finite(n_itens_req_i) && n_itens_req_i > length(ids_todos)
    status <- if (length(ids_ex) && length(ids_ef)) "aplicacao_parcial_exclui_especificas" else if (length(ids_ex) && !length(ids_ef)) "subsumida_por_decisoes_especificas" else if (houve_dedup) "alvos_duplicados_mesmo_dominio_deduplicados" else "sem_sobreposicao_especifica"
    data.table::set(corr, i = ii, j = "status_conciliacao_semantica", value = status)
    if (classe != "correcao_especifica") {
      data.table::set(corr, i = ii, j = "n_linhas_alvo", value = as.integer(length(ids_ef)))
      data.table::set(corr, i = ii, j = "n_linhas_esperado", value = as.integer(length(ids_ef)))
      if ("n_itens_auditaveis" %in% names(corr)) data.table::set(corr, i = ii, j = "n_itens_auditaveis", value = as.integer(length(ids_ef)))
    }
    if (length(ids_ex)) {
      auditoria <- data.table::rbindlist(list(auditoria, data.table::data.table(
        contexto = contexto, status = "alvo_amplo_excluido_por_decisao_especifica",
        id_operacao_ampla = as.character(corr$id_correcao[ii]),
        classe_operacao_ampla = classe,
        id_operacao_protetora = as.character(ex_i$id_protetor),
        monitora_row_id = as.character(ex_i$monitora_row_id),
        linha_indice = as.integer(ex_i$linha_indice),
        dominio_semantico = as.character(ex_i$dominio_semantico),
        mensagem = "Decisão específica preservada; alvo retirado do escopo efetivo da sanitização/operação em lote independentemente da ordem dos cliques"
      )), fill = TRUE, use.names = TRUE)
    }
    if (houve_dedup) {
      auditoria <- data.table::rbindlist(list(auditoria, data.table::data.table(
        contexto = contexto, status = "alvo_duplicado_mesmo_dominio_deduplicado",
        id_operacao_ampla = as.character(corr$id_correcao[ii]),
        classe_operacao_ampla = classe, id_operacao_protetora = NA_character_,
        monitora_row_id = NA_character_, linha_indice = NA_integer_,
        dominio_semantico = paste(unique(at_i$dominio_semantico), collapse = " | "),
        mensagem = paste0(n_itens_req_i - length(ids_todos), " item(ns) repetido(s) removido(s); intenção e contagem solicitada preservadas")
      )), fill = TRUE, use.names = TRUE)
    }
    if (length(ids_todos) != length(ids_ef) + length(ids_ex)) stop("Invariante de reconciliação violada: solicitados != efetivos + excluídos.", call. = FALSE)
    if (classe != "correcao_especifica" && !length(ids_ef)) manter[ii] <- FALSE
  }
  corr_ef <- corr[manter]
  if (nrow(conflitos)) {
    conflitos[, `:=`(contexto = contexto, status = "conflito_semantico_nao_resolvido", mensagem = "Duas intenções de mesma precedência ou duas operações amplas/lote definem efeitos incompatíveis; correção manual obrigatória antes do modal")]
  }
  if (isTRUE(gravar)) {
    out_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE)
    log_dir <- get0("MONITORA_LOG_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "log"), inherits = TRUE)
    exec_id <- get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)
    dir.create(out_dir, recursive = TRUE, showWarnings = FALSE); dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
    monitora_fwrite(auditoria, file.path(out_dir, "auditoria_conciliacao_semantica_operacoes_ultima_execucao.csv"), na = "")
    monitora_fwrite(conflitos, file.path(out_dir, "auditoria_conflitos_semanticos_fila_ultima_execucao.csv"), na = "")
    monitora_fwrite(auditoria, file.path(log_dir, paste0("auditoria_conciliacao_semantica_operacoes_", exec_id, ".csv")), na = "")
    assign("MONITORA_AUDITORIA_CONCILIACAO_SEMANTICA_ULTIMA", auditoria, envir = .GlobalEnv)
    assign("MONITORA_CONFLITOS_SEMANTICOS_ULTIMOS", conflitos, envir = .GlobalEnv)
  }
  if (isTRUE(abortar) && nrow(conflitos)) stop(
    "Plano semântico bloqueado: ", nrow(conflitos),
    " conflito(s) não resolvido(s). Ver auditoria_conflitos_semanticos_fila_ultima_execucao.csv.",
    call. = FALSE
  )
  list(corr = corr_ef[], auditoria = auditoria[], conflitos = conflitos[], n_excluidos = nrow(auditoria), n_conflitos = nrow(conflitos))
}

monitora_correcao_anexar_contexto_auditoria <- function(audit, dt, chaves = monitora_correcao_colunas_chave(dt)) {
  audit <- data.table::as.data.table(audit)
  if (!nrow(audit)) return(audit)
  dt <- data.table::as.data.table(dt)
  if (!("monitora_row_id" %in% names(audit))) audit[, monitora_row_id := NA_character_]
  if (MONITORA_COL_ROW_ID %in% names(dt) && "linha_indice" %in% names(audit)) {
    idx_id <- suppressWarnings(as.integer(audit$linha_indice))
    ok_id <- !is.na(idx_id) & idx_id >= 1L & idx_id <= nrow(dt)
    vals_id <- as.character(audit$monitora_row_id)
    preencher_id <- ok_id & (is.na(vals_id) | !nzchar(trimws(vals_id)))
    vals_id[preencher_id] <- as.character(dt[[MONITORA_COL_ROW_ID]][idx_id[preencher_id]])
    data.table::set(audit, j = "monitora_row_id", value = vals_id)
  }
  campos <- c(
    COLETA = chaves$coleta,
    coleta_uuid = chaves$coleta_uuid,
    uuid_registro = chaves$uuid_registro,
    UC = chaves$uc,
    EA = chaves$ea,
    UA = chaves$ua,
    CICLO = chaves$ciclo,
    CAMPANHA = chaves$campanha,
    ANO = chaves$ano,
    "Data (data_hora)" = chaves$data_hora,
    "Ponto amostral" = chaves$ponto_amostral,
    "Ponto metro" = chaves$ponto_metro
  )
  for (nm in names(campos)) {
    col <- campos[[nm]]
    if (!(nm %in% names(audit))) audit[, (nm) := NA_character_]
    if (is.na(col) || !nzchar(col) || !(col %in% names(dt)) || !("linha_indice" %in% names(audit))) next
    idx <- suppressWarnings(as.integer(audit$linha_indice))
    ok <- !is.na(idx) & idx >= 1L & idx <= nrow(dt)
    vals <- rep(NA_character_, nrow(audit))
    vals[ok] <- as.character(dt[[col]][idx[ok]])
    antigos <- as.character(audit[[nm]])
    preservar <- !is.na(antigos) & nzchar(trimws(antigos))
    vals[preservar] <- antigos[preservar]
    data.table::set(audit, j = nm, value = vals)
  }
  audit[]
}



monitora_correcao_gravar_resumo_operacoes_atomicas <- function(audit, persistencia = data.table::data.table(), contexto = "pos_correcoes") {
 ### Resumo de uma linha por operação semântica. A auditoria detalhada continua
 ### célula a célula, mas este produto facilita validar se cada id_correcao foi
 ### roteado como unidade atômica e se persistiu no objeto/CSV final.
  audit <- data.table::as.data.table(audit)
  persistencia <- data.table::as.data.table(persistencia)
  if (!nrow(audit)) return(data.table::data.table())
  for (cc in c("id_correcao", "status", "atributo", "linha_indice", "mensagem", "n_operacoes_atomicas", "n_itens_solicitados", "n_itens_efetivos", "n_linhas_solicitadas", "n_linhas_efetivas", "n_linhas_excluidas")) if (!(cc %in% names(audit))) data.table::set(audit, j = cc, value = NA_character_)
  for (cc in c("id_correcao", "status_persistencia")) if (!(cc %in% names(persistencia))) data.table::set(persistencia, j = cc, value = NA_character_)
  classificar_tipo <- function(id) {
    id <- as.character(id)
    out <- rep("operacao_generica", length(id))
    out[grepl("^MVLOTE_", id)] <- "movimento_forma_vida_lote_atomico"
    out[grepl("^MOVFV_", id)] <- "movimento_forma_vida_atomico"
    out[grepl("^TRIDESC_", id)] <- "triagem_desconhecida_atomica"
    out[grepl("^TRIOUT", id)] <- "limpeza_outras_formas_atomica"
    out[grepl("^SANHAB", id)] <- "sanitizacao_habito_obrigatorio_ausente"
    out[grepl("^SANEORF", id)] <- "sanitizacao_orfaos_encostam"
    out[grepl("^PENDFV", id)] <- "pendencia_sem_forma_vida_lote"
    out[grepl("^EXCCOL_", id)] <- "exclusao_coleta_atomica"
    out[grepl("^RECALC_SUPERIORES_XLSFORM$", id)] <- "recalculo_superiores_xlsform"
    out[grepl("^FECHAMENTO_HIERARQUICO_CONTRATO$", id)] <- "fechamento_hierarquico_contrato"
    out[grepl("^SYNC_ENCOSTAM_FINAL$", id)] <- "sincronizacao_final_encostam"
    out
  }
  max_inteiro_seguro <- function(x) {
    z <- suppressWarnings(as.integer(x))
    z <- z[is.finite(z)]
    if (length(z)) as.integer(max(z)) else NA_integer_
  }
  resumo <- audit[, .(
    tipo_operacao = classificar_tipo(id_correcao[1L]),
    n_operacoes_atomicas = max_inteiro_seguro(n_operacoes_atomicas),
    n_itens_solicitados = max_inteiro_seguro(n_itens_solicitados),
    n_itens_efetivos = max_inteiro_seguro(n_itens_efetivos),
    n_linhas_solicitadas = max_inteiro_seguro(n_linhas_solicitadas),
    n_linhas_efetivas = max_inteiro_seguro(n_linhas_efetivas),
    n_linhas_excluidas = max_inteiro_seguro(n_linhas_excluidas),
    n_linhas_auditoria = .N,
    n_linhas_afetadas = data.table::uniqueN(suppressWarnings(as.integer(linha_indice)), na.rm = TRUE),
    n_atributos_afetados = data.table::uniqueN(as.character(atributo)[!is.na(atributo) & nzchar(as.character(atributo))]),
    status_aplicacao = if (any(grepl("^(falha|bloqueada)", as.character(status)))) "falha_ou_bloqueio" else if (any(as.character(status) %in% c("aplicada", "aplicada_atomica", "excluida_coleta"))) "aplicada" else "sem_alteracao",
    mensagens = monitora_correcao_colapsar_contexto_valores(mensagem, max_valores = 5L)
  ), by = id_correcao]
  if (nrow(persistencia) > 0L) {
    pers <- persistencia[, .(
      n_checagens_persistencia = .N,
      n_falhas_persistencia = sum(grepl("^falha", as.character(status_persistencia)), na.rm = TRUE),
      status_persistencia_operacao = if (any(grepl("^falha", as.character(status_persistencia)))) "falha" else "ok"
    ), by = id_correcao]
    resumo <- merge(resumo, pers, by = "id_correcao", all.x = TRUE)
  } else {
    resumo[, `:=`(n_checagens_persistencia = NA_integer_, n_falhas_persistencia = NA_integer_, status_persistencia_operacao = NA_character_)]
  }
  if (exists("MONITORA_LOG_DIR", inherits = TRUE) && exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) {
    exec_id <- if (exists("MONITORA_EXEC_ID", inherits = TRUE)) MONITORA_EXEC_ID else format(Sys.time(), "%Y%m%d_%H%M%S")
    arq_log <- file.path(MONITORA_LOG_DIR, paste0("auditoria_operacoes_atomicas_resumo_", contexto, "_", exec_id, ".csv"))
    arq_ult <- file.path(MONITORA_CORRECOES_DIR, paste0("auditoria_operacoes_atomicas_resumo_", contexto, "_ultima_execucao.csv"))
    try(monitora_fwrite(resumo, arq_log, na = ""), silent = TRUE)
    try(monitora_fwrite(resumo, arq_ult, na = ""), silent = TRUE)
  }
  resumo[]
}

monitora_correcao_auditar_persistencia_operacoes <- function(dt, audit, chaves = monitora_correcao_colunas_chave(dt), coletas_excluidas = character(), contexto = "pos_correcoes", abortar = TRUE) {
 ### Confere se as operações registradas como aplicadas na auditoria realmente
 ### persistem no objeto final que será gravado/exportado. Esta trava evita o
 ### cenário perigoso em que a auditoria marca uma correção como aplicada, mas o
 ### registros_corrig.csv permanece com o valor antigo por uso de cópia temporária,
 ### linha_indice obsoleto ou reatribuição perdida.
  audit <- data.table::as.data.table(audit)
  dt <- monitora_dt_referenciar(dt)
  if (!nrow(audit)) return(data.table::data.table())
  for (cc in c("id_correcao", "status", "atributo", "linha_indice", "monitora_row_id", "valor_depois", "COLETA", "coleta_uuid", "uuid_registro", "UC", "EA", "UA", "CICLO", "CAMPANHA", "ANO", "Data (data_hora)", "Ponto amostral", "Ponto metro")) {
    if (!(cc %in% names(audit))) data.table::set(audit, j = cc, value = NA_character_)
  }
  coletas_excluidas <- unique(as.character(coletas_excluidas))
  coletas_excluidas <- coletas_excluidas[!is.na(coletas_excluidas) & nzchar(trimws(coletas_excluidas))]
  indice <- monitora_correcao_criar_indice_linhas(dt, chaves)
  norm0 <- function(x) monitora_correcao_na_para_vazio(x)
  localizar_aud <- function(ii) {
    data.table::data.table(
      linha_indice = audit$linha_indice[ii],
      monitora_row_id = audit$monitora_row_id[ii],
      uuid_registro = audit$uuid_registro[ii],
      coleta_uuid = audit$coleta_uuid[ii],
      coleta = audit$COLETA[ii],
      UC = audit$UC[ii],
      EA = audit$EA[ii],
      UA = audit$UA[ii],
      CICLO = audit$CICLO[ii],
      CAMPANHA = audit$CAMPANHA[ii],
      ANO = audit$ANO[ii],
      `Data (data_hora)` = audit[["Data (data_hora)"]][ii],
      ponto_amostral = audit[["Ponto amostral"]][ii],
      ponto_metro = audit[["Ponto metro"]][ii],
      escopo_aplicacao = "ponto"
    )
  }
  out <- vector("list", 0L)
  kk <- 0L

 ### Primeiro valida exclusões por COLETA em lote, uma vez por COLETA.
  if (length(coletas_excluidas) > 0L && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    for (co in coletas_excluidas) {
      n_rest <- sum(as.character(dt[[chaves$coleta]]) == co, na.rm = TRUE)
      kk <- kk + 1L
      out[[kk]] <- data.table::data.table(
        contexto = contexto,
        id_correcao = paste(unique(audit[COLETA == co & status == "excluida_coleta", id_correcao]), collapse = ";"),
        status_persistencia = ifelse(n_rest == 0L, "ok_exclusao_persistiu", "falha_exclusao_nao_persistiu"),
        mensagem = ifelse(n_rest == 0L, "COLETA excluída não possui vestígios no objeto final", paste0("COLETA excluída ainda possui ", n_rest, " linha(s) no objeto final")),
        atributo = chaves$coleta,
        COLETA = co,
        linha_indice_auditoria = NA_integer_,
        n_linhas_localizadas_final = as.integer(n_rest),
        valor_esperado = "<REGISTRO_REMOVIDO>",
        valor_final = ifelse(n_rest == 0L, NA_character_, co)
      )
    }
  }

 ### relocalização por chave estável pós-EXCCOL. A auditoria
 ### não pode mais (a) descartar silenciosamente correções cujo alvo foi
 ### removido por EXCCOL, nem (b) deixar de distinguir "linha_indice cru
 ### deslocado, mas relocalizado corretamente por chave estável" de uma falha
 ### real de persistência. `categoria_persistencia_chave_estavel` é uma coluna
 ### aditiva (não substitui `status_persistencia`, mantendo replay_semantico_v1
 ### e consumidores existentes intactos).
  chave_vazia <- function(x) monitora_correcao_vazio(x)
  status_aplicados <- c("aplicada", "aplicada_atomica")
  rows <- which(as.character(audit$status) %in% status_aplicados)
  if (length(rows) > 0L) {
    for (ii in rows) {
      attr <- as.character(audit$atributo[ii])
      co <- as.character(audit$COLETA[ii])
      if (!is.na(co) && nzchar(trimws(co)) && co %chin% coletas_excluidas) {
        kk <- kk + 1L
        out[[kk]] <- data.table::data.table(
          contexto = contexto, id_correcao = as.character(audit$id_correcao[ii]), status_persistencia = "ok_subsumida_por_exclusao_coleta",
          categoria_persistencia_chave_estavel = "subsumida_por_EXCCOL_mesma_sessao",
          mensagem = paste0("Decisão semântica preservada na trilha, mas seu registro-alvo pertencia à COLETA ", co, ", removida por EXCCOL nesta mesma sessão; exclusão estrutural dominante confirmada"),
          atributo = attr, atributo_resolvido = NA_character_, COLETA = co,
          linha_indice_auditoria = suppressWarnings(as.integer(audit$linha_indice[ii])), n_linhas_localizadas_final = 0L,
          linhas_localizadas_final_indice = NA_character_,
          valor_esperado = as.character(audit$valor_depois[ii]), valor_final = NA_character_
        )
        next
      }
      if (is.na(attr) || !nzchar(trimws(attr)) || startsWith(attr, "__")) next
      attr_dt <- monitora_correcao_resolver_atributo_auditoria(dt, attr)
      if (is.na(attr_dt) || !nzchar(trimws(attr_dt)) || !(attr_dt %in% names(dt))) {
        kk <- kk + 1L
        out[[kk]] <- data.table::data.table(
          contexto = contexto, id_correcao = as.character(audit$id_correcao[ii]), status_persistencia = "falha_atributo_ausente",
          categoria_persistencia_chave_estavel = "erro_valor_nao_persistiu",
          mensagem = paste0("Atributo auditado não existe no objeto final, mesmo após resolução por nome normalizado: ", attr), atributo = attr, atributo_resolvido = NA_character_, COLETA = co,
          linha_indice_auditoria = suppressWarnings(as.integer(audit$linha_indice[ii])), n_linhas_localizadas_final = 0L,
          linhas_localizadas_final_indice = NA_character_,
          valor_esperado = as.character(audit$valor_depois[ii]), valor_final = NA_character_
        )
        next
      }
      alvo <- localizar_aud(ii)
 ### quando o próprio atributo corrigido É uma das chaves de
 ### contexto usadas para relocalizar (UC/EA/UA/CICLO/CAMPANHA/ANO/
 ### Data (data_hora) -- ex.: correção de UA em escopo coleta_inteira),
 ### o contexto capturado na fila (valor ANTIGO) deixa de bater contra o
 ### objeto final assim que a correção é aplicada a TODAS as linhas da
 ### coleta, e monitora_correcao_localizar_linhas filtra as próprias
 ### linhas corrigidas para fora -- reproduzido: uma correção de UA
 ### coleta_inteira genuinamente persistida era classificada como
 ### "falha_linha_nao_localizada" só porque o contexto de UA ficou
 ### desatualizado. Correção: não usar o valor de contexto do PRÓPRIO
 ### atributo que está sendo auditado como filtro de relocalização
 ### (as demais chaves de contexto continuam restringindo normalmente).
      campo_contexto_por_chave <- list(
        uc = "UC", ea = "EA", ua = "UA", ciclo = "CICLO", campanha = "CAMPANHA",
        ano = "ANO", data_hora = "Data (data_hora)"
      )
      for (nm_chave in names(campo_contexto_por_chave)) {
        col_chave <- chaves[[nm_chave]]
        campo_ctx <- campo_contexto_por_chave[[nm_chave]]
        if (!is.na(col_chave) && identical(col_chave, attr_dt) && campo_ctx %in% names(alvo)) {
          data.table::set(alvo, j = campo_ctx, value = NA_character_)
        }
      }
      linhas <- monitora_correcao_localizar_linhas(dt, alvo, chaves, indice)
      linhas <- unique(as.integer(linhas))
      linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]

 ### Determina o método de relocalização efetivamente usado, apenas para
 ### diagnóstico/categoria (não influencia a busca em si, que já prioriza
 ### chave estável dentro de monitora_correcao_localizar_linhas ).
      uuid_val <- as.character(audit$uuid_registro[ii])
      row_id_val <- as.character(audit$monitora_row_id[ii])
      coleta_uuid_val <- as.character(audit$coleta_uuid[ii])
      li_raw <- suppressWarnings(as.integer(audit$linha_indice[ii]))
      metodo_localizacao <- if (!chave_vazia(row_id_val) && MONITORA_COL_ROW_ID %in% names(dt)) {
        "monitora_row_id"
      } else if (!chave_vazia(uuid_val) && !is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) {
        "uuid_registro"
      } else if (!chave_vazia(coleta_uuid_val) || (!is.na(co) && !chave_vazia(co))) {
        "chave_composta"
      } else {
        "linha_indice"
      }
      linha_deslocada <- FALSE
      if (!is.na(li_raw) && li_raw >= 1L && li_raw <= nrow(dt) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt) && !chave_vazia(co)) {
        coleta_no_indice_bruto <- as.character(dt[[chaves$coleta]][li_raw])
        linha_deslocada <- !identical(coleta_no_indice_bruto, co)
      }

      esperado <- as.character(audit$valor_depois[ii])
      if (!length(linhas)) {
        categoria_falha <- if (metodo_localizacao == "linha_indice" && chave_vazia(uuid_val) && chave_vazia(coleta_uuid_val) && chave_vazia(co)) {
          "erro_chave_ausente"
        } else {
          "erro_chave_ambigua"
        }
        kk <- kk + 1L
        out[[kk]] <- data.table::data.table(
          contexto = contexto, id_correcao = as.character(audit$id_correcao[ii]), status_persistencia = "falha_linha_nao_localizada",
          categoria_persistencia_chave_estavel = categoria_falha,
          mensagem = "Linha auditada como aplicada não foi localizada no objeto final por chaves estáveis/contexto", atributo = attr, COLETA = co,
          linha_indice_auditoria = suppressWarnings(as.integer(audit$linha_indice[ii])), n_linhas_localizadas_final = 0L,
          linhas_localizadas_final_indice = NA_character_,
          valor_esperado = esperado, valor_final = NA_character_
        )
        next
      }
      finais <- as.character(dt[[attr_dt]][linhas])
      ok <- monitora_correcao_valores_equivalentes(finais, esperado, attr_dt, chaves)
      modo_comparacao <- ifelse(
        isTRUE(monitora_correcao_campo_multiselect_auditoria(attr_dt, chaves)),
        "tokens_multiselect",
        "literal"
      )
      status <- ifelse(all(ok), "ok_aplicacao_persistiu", "falha_valor_nao_persistiu")
      categoria_ok <- if (metodo_localizacao == "monitora_row_id") {
        "relocalizado_por_monitora_row_id"
      } else if (metodo_localizacao == "uuid_registro") {
        "relocalizado_por_uuid"
      } else if (linha_deslocada) {
        "linha_indice_deslocado_relocalizado"
      } else if (metodo_localizacao == "chave_composta") {
        "relocalizado_por_chave_composta"
      } else {
        "persistiu"
      }
      categoria_persist <- ifelse(identical(status, "ok_aplicacao_persistiu"), categoria_ok, "erro_valor_nao_persistiu")
      kk <- kk + 1L
      out[[kk]] <- data.table::data.table(
        contexto = contexto,
        id_correcao = as.character(audit$id_correcao[ii]),
        status_persistencia = status,
        categoria_persistencia_chave_estavel = categoria_persist,
        mensagem = ifelse(identical(status, "ok_aplicacao_persistiu"), "Valor auditado persiste no objeto final", "Valor final diverge do valor_depois auditado"),
        modo_comparacao = modo_comparacao,
        atributo = attr,
        atributo_resolvido = attr_dt,
        COLETA = co,
        linha_indice_auditoria = suppressWarnings(as.integer(audit$linha_indice[ii])),
        n_linhas_localizadas_final = as.integer(length(linhas)),
        linhas_localizadas_final_indice = paste(linhas, collapse = ";"),
        valor_esperado = esperado,
        valor_final = paste(unique(finais), collapse = " | ")
      )
    }
  }
  res <- if (length(out)) data.table::rbindlist(out, fill = TRUE, use.names = TRUE) else data.table::data.table()
  if (nrow(res) > 0L) {
 ### A auditoria de persistência deve validar o estado final do produto, não
 ### valores intermediários de operações que foram corretamente sobrescritas por
 ### outra operação aplicada no mesmo alvo. Isto ocorre, por exemplo, quando a
 ### limpeza de "outra forma" harmoniza uma célula e, na sequência, um MVLOTE
 ### move a mesma forma para outra categoria. Se outra operação aplicada no
 ### mesmo alvo já confere com o valor final, a divergência intermediária é
 ### marcada como sobreposição compatível, sem bloquear a execução.
    for (cc in c("atributo_resolvido", "COLETA", "linha_indice_auditoria", "linhas_localizadas_final_indice", "status_persistencia", "categoria_persistencia_chave_estavel")) {
      if (!(cc %in% names(res))) data.table::set(res, j = cc, value = NA_character_)
    }
    chave_res <- paste(
      as.character(res$COLETA),
      as.character(res$linha_indice_auditoria),
      as.character(res$atributo_resolvido),
      sep = "\r"
    )
    chaves_ok <- unique(chave_res[as.character(res$status_persistencia) == "ok_aplicacao_persistiu"])
    idx_sobreposta <- which(as.character(res$status_persistencia) == "falha_valor_nao_persistiu" & chave_res %chin% chaves_ok)
    if (length(idx_sobreposta) > 0L) {
      data.table::set(res, i = idx_sobreposta, j = "status_persistencia", value = "ok_sobreposta_por_correcao_final_compativel")
      data.table::set(res, i = idx_sobreposta, j = "mensagem", value = "Valor intermediário auditado foi sobrescrito por outra correção aplicada no mesmo alvo; o estado final confere com auditoria posterior")
      data.table::set(res, i = idx_sobreposta, j = "categoria_persistencia_chave_estavel", value = "persistiu")
    }

 ### Recalculos automáticos de campos superiores derivados do XLSForm podem
 ### registrar estados intermediários quando há múltiplas harmonizações no mesmo
 ### conjunto de linhas. Para o campo superior de categorias de forma de vida
 ### (**Encostam** / tipo_forma_vida), a trava robusta é semântica: o valor
 ### final deve ser idêntico ao que a própria função oficial de recálculo do
 ### script produziria a partir das listas inferiores finais. A validação evita
 ### depender de igualdade literal com valor_depois intermediário e evita
 ### depender apenas de linha_indice histórico após EXCCOL.
    eh_coluna_tipo_superior <- function(x) {
      x <- as.character(x)
      z <- monitora_correcao_normalizar_nome_coluna(x)
      z[is.na(z)] <- ""
      grepl("encostam.*vareta", z) |
        grepl("(^|_)tipo_forma_vida($|_)", z) |
        grepl("tipo.*forma.*vida", z)
    }
    tipo_col_persist <- NA_character_
    cand_tipo <- c(
      if (!is.null(chaves$tipo_forma_vida)) chaves$tipo_forma_vida else NA_character_,
      unique(as.character(res$atributo_resolvido[eh_coluna_tipo_superior(res$atributo_resolvido)])),
      unique(as.character(res$atributo[eh_coluna_tipo_superior(res$atributo)]))
    )
    cand_tipo <- unique(cand_tipo[!is.na(cand_tipo) & nzchar(trimws(cand_tipo))])
    if (length(cand_tipo) > 0L) {
      for (cc_tipo in cand_tipo) {
        cc_res <- monitora_correcao_resolver_atributo_auditoria(dt, cc_tipo)
        if (!is.na(cc_res) && nzchar(cc_res) && cc_res %in% names(dt)) {
          tipo_col_persist <- cc_res
          break
        }
      }
    }
    if (!is.na(tipo_col_persist) && nzchar(tipo_col_persist) && tipo_col_persist %in% names(dt)) {
      idx_recalc <- which(
        as.character(res$status_persistencia) == "falha_valor_nao_persistiu" &
          as.character(res$id_correcao) %in% c("RECALC_SUPERIORES_XLSFORM", "FECHAMENTO_HIERARQUICO_CONTRATO") &
          (
            as.character(res$atributo_resolvido) == tipo_col_persist |
              eh_coluna_tipo_superior(res$atributo_resolvido) |
              eh_coluna_tipo_superior(res$atributo)
          )
      )
      if (length(idx_recalc) > 0L) {
        linhas_por_recalc <- lapply(idx_recalc, function(ii_recalc) {
          linhas_txt <- as.character(res$linhas_localizadas_final_indice[ii_recalc])
          linhas_recalc <- suppressWarnings(as.integer(unlist(strsplit(linhas_txt, ";", fixed = TRUE), use.names = FALSE)))
          linhas_recalc <- unique(linhas_recalc[!is.na(linhas_recalc) & linhas_recalc >= 1L & linhas_recalc <= nrow(dt)])
          if (!length(linhas_recalc)) {
            li_recalc <- suppressWarnings(as.integer(res$linha_indice_auditoria[ii_recalc]))
            if (!is.na(li_recalc) && li_recalc >= 1L && li_recalc <= nrow(dt)) linhas_recalc <- li_recalc
          }
          linhas_recalc
        })
        linhas_recalc_uniao <- unique(as.integer(unlist(linhas_por_recalc, use.names = FALSE)))
        dt_recalc <- data.table::copy(dt)
        antes_recalc_todos <- as.character(dt_recalc[[tipo_col_persist]][linhas_recalc_uniao])
        try(monitora_correcao_recalcular_tipo_forma_vida(dt_recalc, linhas_recalc_uniao), silent = TRUE)
        for (jj_recalc in seq_along(idx_recalc)) {
          ii_recalc <- idx_recalc[jj_recalc]
          linhas_recalc <- linhas_por_recalc[[jj_recalc]]
          if (!length(linhas_recalc)) next
          pos_uniao <- match(linhas_recalc, linhas_recalc_uniao)
          antes_recalc <- antes_recalc_todos[pos_uniao]
          esperado_recalc <- as.character(dt_recalc[[tipo_col_persist]][linhas_recalc])
          final_recalc <- as.character(dt[[tipo_col_persist]][linhas_recalc])
          ok_recalc <- monitora_correcao_valores_equivalentes(
            final_recalc,
            esperado_recalc,
            tipo_col_persist,
            chaves
          )
          if (all(ok_recalc)) {
            data.table::set(res, i = ii_recalc, j = "status_persistencia", value = "ok_recalculo_superior_estado_final_consistente")
            data.table::set(res, i = ii_recalc, j = "categoria_persistencia_chave_estavel", value = "persistiu")
            data.table::set(res, i = ii_recalc, j = "mensagem", value = "Valor auditado intermediário divergiu, mas o campo superior final é idêntico ao recálculo oficial a partir das listas inferiores finais")
            data.table::set(res, i = ii_recalc, j = "modo_comparacao", value = "recalculo_oficial_tipo_forma_vida")
            data.table::set(res, i = ii_recalc, j = "valor_esperado", value = paste(unique(esperado_recalc), collapse = " | "))
            data.table::set(res, i = ii_recalc, j = "valor_final", value = paste(unique(final_recalc), collapse = " | "))
          } else {
            data.table::set(res, i = ii_recalc, j = "mensagem", value = paste0(
              "Valor final diverge do valor_depois auditado e também do recálculo oficial de tipo_forma_vida; antes_recalculo=",
              paste(unique(antes_recalc), collapse = " | "),
              "; esperado_recalculo=",
              paste(unique(esperado_recalc), collapse = " | "),
              "; final=",
              paste(unique(final_recalc), collapse = " | ")
            ))
            data.table::set(res, i = ii_recalc, j = "modo_comparacao", value = "falha_recalculo_oficial_tipo_forma_vida")
            data.table::set(res, i = ii_recalc, j = "valor_esperado", value = paste(unique(esperado_recalc), collapse = " | "))
            data.table::set(res, i = ii_recalc, j = "valor_final", value = paste(unique(final_recalc), collapse = " | "))
          }
        }
      }
    }
  }




 ### --------------------------
 ### Auditoria de persistência com helpers nomeados e indexação segura.
 ### Corrige a colisão de nomes gerada por múltiplas funções locais chamadas
 ### ``, que fazia `linhas_estado` deixar de ser vetor inteiro e ser
 ### interpretado pelo data.table como i de join.

    monitora_persist_resolver_linhas_estado <- function(row_res, n_dt) {
      if (!is.data.frame(row_res) || !length(n_dt) || is.na(n_dt) || n_dt < 1L) return(integer(0))
      linhas_txt <- if ("linhas_localizadas_final_indice" %in% names(row_res)) {
        as.character(row_res$linhas_localizadas_final_indice[1L])
      } else NA_character_
      linhas <- suppressWarnings(as.integer(unlist(strsplit(linhas_txt, ";", fixed = TRUE), use.names = FALSE)))
      linhas <- unique(linhas[!is.na(linhas) & linhas >= 1L & linhas <= n_dt])
      if (!length(linhas) && "linha_indice_auditoria" %in% names(row_res)) {
        li <- suppressWarnings(as.integer(row_res$linha_indice_auditoria[1L]))
        if (!is.na(li) && li >= 1L && li <= n_dt) linhas <- li
      }
      as.integer(linhas)
    }

    monitora_persist_aplicar_normalizadores_estado <- function(dt_sub, linhas_sub, contexto_estado = "persistencia_estado_final_contratual") {
      old_publicacao_g_sim <- get0("MONITORA_PUBLICACAO_G_MODO_SIMULACAO_CONTRATO", ifnotfound = FALSE, inherits = TRUE)
      assign("MONITORA_PUBLICACAO_G_MODO_SIMULACAO_CONTRATO", TRUE, envir = .GlobalEnv)
      on.exit(assign("MONITORA_PUBLICACAO_G_MODO_SIMULACAO_CONTRATO", old_publicacao_g_sim, envir = .GlobalEnv), add = TRUE)
      dt_sub <- monitora_dt_referenciar(dt_sub)
      linhas_sub <- unique(as.integer(linhas_sub))
      linhas_sub <- linhas_sub[!is.na(linhas_sub) & linhas_sub >= 1L & linhas_sub <= nrow(dt_sub)]
      if (!length(linhas_sub)) return(invisible(dt_sub))

      meta_publicacao_f <- get0("MONITORA_META_XLSFORMS_CORRECOES", ifnotfound = NULL, inherits = TRUE)
      if (exists("monitora_correcao_preparar_schema_edicao_painel", mode = "function")) {
        try(monitora_correcao_preparar_schema_edicao_painel(dt_sub, meta_publicacao_f, contexto = paste0(contexto_estado, "_schema")), silent = TRUE)
      }
      if (exists("monitora_publicacao_c_sincronizar_materiais_botanicos", mode = "function")) {
        try(monitora_publicacao_c_sincronizar_materiais_botanicos(dt_sub, linhas_sub, contexto = paste0(contexto_estado, "_materiais_botanicos")), silent = TRUE)
      }
      if (exists("monitora_correcao_sincronizar_encostam_final", mode = "function")) {
        try(monitora_correcao_sincronizar_encostam_final(dt_sub, linhas_sub, contexto = paste0(contexto_estado, "_encostam_final")), silent = TRUE)
      } else if (exists("monitora_correcao_recalcular_tipo_forma_vida", mode = "function")) {
        try(monitora_correcao_recalcular_tipo_forma_vida(dt_sub, linhas_sub), silent = TRUE)
      }
      invisible(dt_sub)
    }

    monitora_persist_colunas_formas_estado <- function(dt_ref) {
      cats <- c("nativa", "exotica", "seca_morta")
      out_cols <- character()
      for (cat in cats) {
        cc <- tryCatch(monitora_correcao_coluna_forma_vida(dt_ref, cat), error = function(e) NA_character_)
        if (!is.na(cc) && nzchar(cc) && cc %in% names(dt_ref)) out_cols <- c(out_cols, cc)
      }
      unique(out_cols)
    }

    monitora_persist_colunas_contrato_estado <- function(dt_ref, atributo_resolvido = NA_character_, chaves_ref = monitora_correcao_colunas_chave(dt_ref)) {
      nms <- names(dt_ref)
      nms_norm <- tryCatch(
        vapply(nms, monitora_correcao_normalizar_nome_coluna, character(1)),
        error = function(e) tolower(trimws(nms))
      )
      padrao_contrato <- paste(
        c(
          "encostam", "tipo_forma_vida", "forma_vida_nativa", "forma_vida_exotica", "forma_vida_seca_morta",
          "forma_serrapilheira", "serrapilheira", "materiais_botanicos", "material_botanico", "fragmentos_botanicos",
          "material_inundado", "outra_forma_vida", "outras_formas", "samambaia", "orquidea", "cactacea", "bromelioide"
        ),
        collapse = "|"
      )
      cols_regex <- nms[grepl(padrao_contrato, nms_norm, perl = TRUE)]
      mat_col <- if (exists("monitora_publicacao_c_resolver_coluna_materiais_botanicos", mode = "function")) {
        tryCatch(monitora_publicacao_c_resolver_coluna_materiais_botanicos(dt_ref, criar = FALSE), error = function(e) NA_character_)
      } else NA_character_
      candidatos <- c(atributo_resolvido, chaves_ref$tipo_forma_vida, monitora_persist_colunas_formas_estado(dt_ref), mat_col, cols_regex)
      unique(candidatos[!is.na(candidatos) & nzchar(candidatos)])
    }

    monitora_persist_intersectar_colunas_estado <- function(cols, dt_a, dt_b) {
      cols <- unique(as.character(cols))
      cols <- cols[!is.na(cols) & nzchar(cols)]
      cols[cols %in% union(names(dt_a), names(dt_b))]
    }

    monitora_persist_extrair_coluna_estado <- function(dt_ref, col) {
      if (col %in% names(dt_ref)) as.character(dt_ref[[col]]) else rep(NA_character_, nrow(dt_ref))
    }

    monitora_persist_valores_equivalentes_estado <- function(final_vals, esperado_vals, col, chaves_ref) {
      ok <- tryCatch(
        monitora_correcao_valores_equivalentes(final_vals, esperado_vals, col, chaves_ref),
        error = function(e) monitora_correcao_na_para_vazio(final_vals) == monitora_correcao_na_para_vazio(esperado_vals)
      )
      isTRUE(all(ok, na.rm = FALSE))
    }

    monitora_persist_reclassificar_estado_contratual <- function(res, dt, chaves, contexto_estado = "persistencia_estado_final_contratual") {
      if (!nrow(res)) return(res)
      idx <- which(as.character(res$status_persistencia) == "falha_valor_nao_persistiu")
      if (!length(idx)) return(res)

      for (ii_estado in idx) {
        attr_estado <- as.character(res$atributo_resolvido[ii_estado])
        if (is.na(attr_estado) || !nzchar(attr_estado)) attr_estado <- as.character(res$atributo[ii_estado])
        attr_estado <- tryCatch(monitora_correcao_resolver_atributo_auditoria(dt, attr_estado), error = function(e) attr_estado)
        if (is.na(attr_estado) || !nzchar(attr_estado) || !(attr_estado %in% names(dt))) next

        linhas_estado <- monitora_persist_resolver_linhas_estado(res[ii_estado], nrow(dt))
        if (!is.integer(linhas_estado)) linhas_estado <- as.integer(linhas_estado)
        linhas_estado <- unique(linhas_estado[!is.na(linhas_estado) & linhas_estado >= 1L & linhas_estado <= nrow(dt)])
        if (!length(linhas_estado)) next

        dt_final <- data.table::copy(dt[linhas_estado])
        dt_esperado <- data.table::copy(dt[linhas_estado])
        esperado_raw <- as.character(res$valor_esperado[ii_estado])
        if (!length(esperado_raw) || all(is.na(esperado_raw))) esperado_raw <- NA_character_
        if (length(esperado_raw) != nrow(dt_esperado)) esperado_raw <- rep(esperado_raw[1L], nrow(dt_esperado))
        data.table::set(dt_esperado, i = seq_len(nrow(dt_esperado)), j = attr_estado, value = esperado_raw)

        linhas_sub <- seq_len(nrow(dt_esperado))
        monitora_persist_aplicar_normalizadores_estado(dt_esperado, linhas_sub, contexto_estado = paste0("persistencia_esperado_", contexto_estado))
        monitora_persist_aplicar_normalizadores_estado(dt_final, linhas_sub, contexto_estado = paste0("persistencia_final_", contexto_estado))

        chaves_sub <- monitora_correcao_colunas_chave(dt_final)
        cols_estado <- monitora_persist_intersectar_colunas_estado(
          monitora_persist_colunas_contrato_estado(dt_final, attr_estado, chaves_sub),
          dt_final,
          dt_esperado
        )
        if (!length(cols_estado)) cols_estado <- attr_estado

        falhas_cols <- character()
        for (cc_estado in cols_estado) {
          final_vals <- monitora_persist_extrair_coluna_estado(dt_final, cc_estado)
          esperado_vals <- monitora_persist_extrair_coluna_estado(dt_esperado, cc_estado)
          if (!monitora_persist_valores_equivalentes_estado(final_vals, esperado_vals, cc_estado, chaves_sub)) {
            falhas_cols <- c(falhas_cols, cc_estado)
          }
        }

        if (!length(falhas_cols)) {
          data.table::set(res, i = ii_estado, j = "status_persistencia", value = "ok_estado_final_contratual_consistente")
          data.table::set(res, i = ii_estado, j = "mensagem", value = "Valor auditado intermediário divergiu, mas o estado final real é equivalente ao estado final esperado após aplicação dos normalizadores contratuais")
          data.table::set(res, i = ii_estado, j = "modo_comparacao", value = "estado_final_contratual_normalizado")
          data.table::set(res, i = ii_estado, j = "valor_esperado", value = paste(
            vapply(cols_estado, function(cc) paste0(cc, "=", paste(unique(monitora_persist_extrair_coluna_estado(dt_esperado, cc)), collapse = " | ")), character(1)),
            collapse = "; "
          ))
          data.table::set(res, i = ii_estado, j = "valor_final", value = paste(
            vapply(cols_estado, function(cc) paste0(cc, "=", paste(unique(monitora_persist_extrair_coluna_estado(dt_final, cc)), collapse = " | ")), character(1)),
            collapse = "; "
          ))
        } else {
          data.table::set(res, i = ii_estado, j = "mensagem", value = paste0(
            "Valor final diverge do valor_depois auditado e também do estado final contratual normalizado; colunas divergentes=",
            paste(unique(falhas_cols), collapse = ";")
          ))
          data.table::set(res, i = ii_estado, j = "modo_comparacao", value = "falha_estado_final_contratual_normalizado")
        }
      }
      res
    }

    res <- monitora_persist_reclassificar_estado_contratual(res, dt, chaves, contexto_estado = contexto)

 ### Reclassificação contratual de persistência --------------------------
 ### TRIOUT_ATOM (limpeza de outras formas) pode ter checagens marcadas
 ### `falha_valor_nao_persistiu` (divergência no campo superior recalculado,
 ### ex. "Formas de vida de plantas nativas:"), mesmo com a PRÓPRIA operação
 ### já auditada como bem-sucedida (residuos_antes=6, residuos_depois=0,
 ### pendencias_manuais=0 -- ver a linha sentinela `atributo =
 ### "__limpar_outras_formas_vida__"` que
 ### monitora_correcao_aplicar_limpeza_outras_formas_atomica grava no
 ### próprio `audit`). O reclassificador global abaixo
 ### (monitora_persist_reclassificar_por_efeito_diagnostico_final) só
 ### confirma o efeito quando a triagem diagnóstica final do objeto INTEIRO
 ### não tem nenhuma ocorrência impeditiva -- critério correto para famílias
 ### que dependem de recálculo cruzado (PENDFV/MVLOTE/...), mas
 ### desnecessariamente amplo para TRIOUT: 12 linhas impeditivas
 ### remanescentes de OUTRAS categorias (nativa/seca-morta/exótica sem forma
 ### de vida, não relacionadas à limpeza de outras formas) bloqueavam a
 ### reclassificação de uma operação que, no seu próprio escopo, já havia
 ### zerado o resíduo. Esta camada roda ANTES do reclassificador global e
 ### resolve só pelo efeito da PRÓPRIA operação TRIOUT -- nunca por ausência
 ### global de pendências. Não altera nenhuma outra família
 ### (PENDFV/MVLOTE/TRIDESC/MOVFV/RECALC_SUPERIORES_XLSFORM/
 ### SYNC_ENCOSTAM_FINAL), não altera a auditoria de exclusão de COLETAS
 ### (`ok_exclusao_persistiu`, caminho totalmente separado) e não toca
 ### pipes/relevance/cardinalidade. Se a sentinela da própria operação não
 ### existir ou indicar resíduo/pendência manual real, a falha permanece --
 ### cai no reclassificador global (linha abaixo) como segunda tentativa e,
 ### se também não resolver, continua bloqueando normalmente.
    monitora_persist_reclassificar_triout_por_efeito_proprio <- function(res, audit, contexto_estado = "pos_aplicacao_objeto") {
      if (!nrow(res)) return(res)
      if (!("status_persistencia" %in% names(res))) return(res)
      idx_falha <- which(as.character(res$status_persistencia) %in% c(
        "falha_valor_nao_persistiu",
        "falha_linha_nao_localizada"
      ))
      if (!length(idx_falha)) return(res)

      ids <- as.character(res$id_correcao)
      ids[is.na(ids)] <- ""
      idx_triout <- idx_falha[grepl("^TRIOUT", ids[idx_falha])]
      if (!length(idx_triout)) return(res)

      audit <- tryCatch(data.table::as.data.table(audit), error = function(e) data.table::data.table())
      if (!nrow(audit) || !all(c("id_correcao", "atributo", "status") %in% names(audit))) return(res)
      sentinela <- audit[as.character(atributo) == "__limpar_outras_formas_vida__"]
      if (!nrow(sentinela)) return(res)

      ids_triout_falha <- unique(ids[idx_triout])
      for (id_alvo in ids_triout_falha) {
        linha_sentinela <- sentinela[as.character(id_correcao) == id_alvo]
        if (!nrow(linha_sentinela)) next
 ### Exige que TODAS as linhas sentinela da própria operação confirmem
 ### resíduo zerado e sem pendência manual -- nunca reclassifica por
 ### maioria/parcialidade.
        ok_proprio <- all(as.character(linha_sentinela$status) == "auditoria_ok")
        if (!isTRUE(ok_proprio)) next
        idx_desta_id <- idx_triout[ids[idx_triout] == id_alvo]
        msg_sentinela <- as.character(linha_sentinela$mensagem[1L])
        if (is.na(msg_sentinela) || !nzchar(msg_sentinela)) msg_sentinela <- "residuos_depois=0; pendencias_manuais=0."
        data.table::set(res, i = idx_desta_id, j = "status_persistencia", value = "ok_persistiu_por_efeito_especifico_outras_formas")
        data.table::set(res, i = idx_desta_id, j = "mensagem", value = paste0(
          "Limpeza de outras formas persistiu por efeito específico; pendências impeditivas globais remanescentes não relacionadas permanecem para checkpoint de registros_corrig. Auditoria própria da operação: ",
          msg_sentinela
        ))
        if (!("modo_comparacao" %in% names(res))) data.table::set(res, j = "modo_comparacao", value = NA_character_)
        data.table::set(res, i = idx_desta_id, j = "modo_comparacao", value = "efeito_especifico_operacao_triout")
      }
      res
    }

    res <- monitora_persist_reclassificar_triout_por_efeito_proprio(res, audit, contexto_estado = contexto)
 ### FIM ajuste ------------------------------------------------------

 ### auditoria de persistência por efeito diagnóstico final --------
 ### A partir da validação operacional, preview/modal e aplicação já convergem para o estado sem
 ### ocorrências impeditivas. A trava de persistência, porém, ainda comparava
 ### valores intermediários auditados com o objeto final depois de operações
 ### sobrepostas e normalizadores contratuais (TRIOUT -> PENDFV -> recálculos).
 ### Esta camada não substitui a auditoria célula-a-célula; ela apenas
 ### reclassifica divergências literais/posicionais de operações semânticas
 ### quando a própria triagem final de ocorrências impeditivas confirma que o
 ### efeito diagnóstico da sessão foi alcançado.
    monitora_persist_reclassificar_por_efeito_diagnostico_final <- function(res, dt, contexto_estado = "pos_aplicacao_objeto") {
      if (!nrow(res)) return(res)
      if (!("status_persistencia" %in% names(res))) return(res)
      idx_falha_compat <- which(as.character(res$status_persistencia) %in% c(
        "falha_valor_nao_persistiu",
        "falha_linha_nao_localizada"
      ))
      if (!length(idx_falha_compat)) return(res)

      ids <- as.character(res$id_correcao)
      ids[is.na(ids)] <- ""
 ### Só reclassificar famílias em que o critério correto é o desaparecimento
 ### da ocorrência diagnóstica, não igualdade literal do valor intermediário.
      idx_familias_semanticas <- idx_falha_compat[grepl(
        "^(TRIOUT|PENDFV|MVLOTE|TRIDESC|MOVFV|RECALC_SUPERIORES_XLSFORM|FECHAMENTO_HIERARQUICO_CONTRATO|SYNC_ENCOSTAM_FINAL)",
        ids[idx_falha_compat]
      )]
      if (!length(idx_familias_semanticas)) return(res)

      efeito <- tryCatch({
        if (!exists("monitora_diag_rel_gerar_ocorrencias", mode = "function")) {
          stop("função monitora_diag_rel_gerar_ocorrencias indisponível")
        }
        base_tmp <- file.path(
          tempdir(),
          paste0(
            "monitora_persistencia_efeito_diagnostico_",
            gsub("[^A-Za-z0-9_]+", "_", as.character(contexto_estado)),
            "_", format(Sys.time(), "%Y%m%d%H%M%S")
          )
        )
        dir.create(base_tmp, recursive = TRUE, showWarnings = FALSE)
        diag <- suppressWarnings(suppressMessages(monitora_diag_rel_gerar_ocorrencias(
          dt,
          fase = "pos_painel",
          base_dir = base_tmp,
          coletas_triagem_por_tipo = NULL,
          triagem_painel_unificada = NULL,
          validar_contagens = FALSE
        )))
        resumo <- data.table::as.data.table(diag$resumo)
        if (!nrow(resumo) || !("severidade" %in% names(resumo)) || !("n_linhas" %in% names(resumo))) {
          stop("resumo diagnóstico final sem colunas esperadas")
        }
        imp <- resumo[as.character(severidade) == "impeditiva"]
        n_linhas_imp <- sum(suppressWarnings(as.integer(imp$n_linhas)), na.rm = TRUE)
        n_coletas_imp <- if ("n_coletas" %in% names(imp)) sum(suppressWarnings(as.integer(imp$n_coletas)), na.rm = TRUE) else NA_integer_
        list(ok = isTRUE(n_linhas_imp == 0L), n_linhas_imp = n_linhas_imp, n_coletas_imp = n_coletas_imp, resumo = resumo, erro = NA_character_)
      }, error = function(e) {
        list(ok = FALSE, n_linhas_imp = NA_integer_, n_coletas_imp = NA_integer_, resumo = data.table::data.table(), erro = conditionMessage(e))
      })

      if (isTRUE(efeito$ok)) {
        data.table::set(res, i = idx_familias_semanticas, j = "status_persistencia", value = "ok_persistiu_por_efeito_diagnostico_final")
        data.table::set(res, i = idx_familias_semanticas, j = "mensagem", value = paste0(
          "Valor auditado intermediário divergiu ou a linha histórica não foi localizada, mas a triagem diagnóstica final não encontrou ocorrências impeditivas remanescentes; persistência confirmada por efeito diagnóstico final em ",
          contexto_estado,
          "."
        ))
        if (!("modo_comparacao" %in% names(res))) data.table::set(res, j = "modo_comparacao", value = NA_character_)
        data.table::set(res, i = idx_familias_semanticas, j = "modo_comparacao", value = "efeito_diagnostico_final")
      } else {
 ### Se ainda há pendência impeditiva final, manter falha. Apenas enriquecer
 ### a mensagem para diferenciar falha real de impossibilidade de reclassificar.
        msg_extra <- if (!is.na(efeito$erro) && nzchar(efeito$erro)) {
          paste0(" Auditoria por efeito diagnóstico final indisponível: ", efeito$erro)
        } else {
          paste0(" Triagem diagnóstica final ainda indica ", efeito$n_linhas_imp, " linha(s) impeditiva(s).")
        }
        for (ii_msg in idx_familias_semanticas) {
          msg_atual <- as.character(res$mensagem[ii_msg])
          if (is.na(msg_atual)) msg_atual <- ""
          data.table::set(res, i = ii_msg, j = "mensagem", value = paste0(msg_atual, msg_extra))
        }
      }
      res
    }

    res <- monitora_persist_reclassificar_por_efeito_diagnostico_final(res, dt, contexto_estado = contexto)
 ### FIM auditoria por efeito diagnóstico final ----------------------

  if (nrow(res) > 0L) {
    exec_id_pers <- if (exists("MONITORA_EXEC_ID", inherits = TRUE)) MONITORA_EXEC_ID else format(Sys.time(), "%Y%m%d_%H%M%S")
    arq_log <- file.path(MONITORA_LOG_DIR, paste0("auditoria_persistencia_correcoes_", contexto, "_", exec_id_pers, ".csv"))
    arq_ult <- file.path(MONITORA_CORRECOES_DIR, paste0("auditoria_persistencia_correcoes_", contexto, "_ultima_execucao.csv"))
    monitora_fwrite(res, arq_log, na = "")
    monitora_fwrite(res, arq_ult, na = "")
    monitora_correcao_gravar_resumo_operacoes_atomicas(audit, res, contexto = contexto)
    falhas <- res[grepl("^falha", status_persistencia)]
    if (nrow(falhas) > 0L) {
 ### falha de uma operação solicitada pelo usuário e divergência de
 ### uma derivação interna têm consequências distintas. A primeira impede
 ### substituir o checkpoint canônico; a segunda marca registros_corrig
 ### como pendente e bloqueia somente registros_validados/produtos finais.
 ### Isso cumpre o contrato anunciado pelo painel e impede que um defeito
 ### interno descarte uma sessão cujas operações do usuário persistiram.
      ids_derivacao_interna <- c(
        "RECALC_SUPERIORES_XLSFORM",
        "FECHAMENTO_HIERARQUICO_CONTRATO",
        "SYNC_ENCOSTAM_FINAL"
      )
      falhas_derivacao <- falhas[as.character(id_correcao) %in% ids_derivacao_interna]
      falhas_usuario <- falhas[!(as.character(id_correcao) %in% ids_derivacao_interna)]
      modo_replay_nao_abortivo <- isTRUE(get0("MONITORA_REPLAY_DIAGNOSTICO_NAO_ABORTAR", ifnotfound = FALSE, inherits = TRUE)) &&
        isTRUE(get0("MONITORA_REAPLICAR_CORRECOES_ANTERIORES", ifnotfound = FALSE, inherits = TRUE)) &&
        (isTRUE(get0("MONITORA_REPLAY_SEMANTICO_EM_EXECUCAO", ifnotfound = FALSE, inherits = TRUE)) ||
           isTRUE(get0("MONITORA_CORRECOES_REAPLICADAS_PRE_PAINEL", ifnotfound = FALSE, inherits = TRUE)) ||
           exists("MONITORA_CORRECOES_REAPLICADAS_ARQUIVO", inherits = TRUE) ||
           exists("MONITORA_ARQUIVO_CORRECOES_CAMPOS_REAPLICADO", inherits = TRUE))
      somente_derivacao <- nrow(falhas_usuario) == 0L && nrow(falhas_derivacao) > 0L
      nivel_persist <- if (isTRUE(modo_replay_nao_abortivo) || isTRUE(somente_derivacao)) "AVISO" else "ERRO"
      acao_persist <- if (isTRUE(somente_derivacao)) {
        "registros_corrig seguirá como checkpoint marcado; registros_validados e produtos finais serão bloqueados"
      } else if (isTRUE(modo_replay_nao_abortivo)) {
        "diagnóstico não bloqueante ativo; execução continuará até o painel para coletar estado pós-replay"
      } else {
        "execução bloqueada; revisar auditoria_persistencia_correcoes_*"
      }
      monitora_log_registrar_evento(
        "persistencia_correcoes", nivel_persist, arq_log,
        paste0(
          nrow(falhas), " divergência(s) em ", contexto,
          "; operações_usuario=", nrow(falhas_usuario),
          "; derivacoes_internas=", nrow(falhas_derivacao)
        ),
        acao_persist
      )
      if (isTRUE(somente_derivacao)) {
        assign("MONITORA_PERSISTENCIA_DERIVACOES_PENDENTES", TRUE, envir = .GlobalEnv)
        assign("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS", TRUE, envir = .GlobalEnv)
        manifesto_pendente <- data.table::data.table(
          exec_id = exec_id_pers,
          contexto = contexto,
          status = "checkpoint_com_pendencia_derivacao_interna",
          n_linhas = nrow(dt),
          n_colunas = ncol(dt),
          n_falhas_derivacao = nrow(falhas_derivacao),
          n_falhas_operacoes_usuario = 0L,
          arquivo_auditoria = arq_ult,
          observacao = "Operações do usuário persistiram; checkpoint registros_corrig permitido, registros_validados bloqueado."
        )
        arq_manifesto_pendente <- file.path(
          MONITORA_CORRECOES_DIR,
          paste0("manifesto_checkpoint_pendencias_derivacao_", exec_id_pers, ".csv")
        )
        try(monitora_fwrite(manifesto_pendente, arq_manifesto_pendente, na = ""), silent = TRUE)
      } else if (isTRUE(abortar) && !isTRUE(modo_replay_nao_abortivo)) {
 ### falha de validação nunca pode apagar o trabalho da sessão.
 ### O candidato é gravado em área explicitamente NÃO CANÔNICA; somente
 ### uma auditoria sem falhas autoriza a troca atômica de registros_corrig.
        dir_rec <- file.path(MONITORA_CORRECOES_DIR, "recuperacao_transacional")
        dir.create(dir_rec, recursive = TRUE, showWarnings = FALSE)
        arq_rec <- file.path(dir_rec, paste0("registros_corrig_candidato_NAO_VALIDADO_", exec_id_pers, ".csv"))
        arq_manifesto <- file.path(dir_rec, paste0("manifesto_recuperacao_", exec_id_pers, ".csv"))
        try(monitora_fwrite(dt, arq_rec, na = ""), silent = TRUE)
        manifesto_rec <- data.table::data.table(
          exec_id = exec_id_pers, contexto = contexto, status = "candidato_nao_validado",
          n_linhas = nrow(dt), n_colunas = ncol(dt), n_falhas_persistencia = nrow(falhas),
          n_falhas_operacoes_usuario = nrow(falhas_usuario),
          n_falhas_derivacao_interna = nrow(falhas_derivacao),
          arquivo_candidato = arq_rec, arquivo_auditoria = arq_ult,
          observacao = "Arquivo de recuperação; não substitui registros_corrig.csv até a auditoria concluir sem falhas."
        )
        try(monitora_fwrite(manifesto_rec, arq_manifesto, na = ""), silent = TRUE)
        assign("MONITORA_RECUPERACAO_TRANSACIONAL_ULTIMA", arq_rec, envir = .GlobalEnv)
        if (exists("monitora_cadeia_dados_relatorio_gerar", mode = "function")) {
          try(monitora_cadeia_dados_relatorio_gerar("falha_persistencia_operacao_usuario"), silent = TRUE)
        }
        stop(paste0(
          "Uma ou mais operações solicitadas pelo usuário não persistiram em registros_corrig (", contexto,
          "). O candidato foi preservado em ", arq_rec, "; ver ", basename(arq_ult), "."
        ), call. = FALSE)
      }
    } else {
      monitora_log_registrar_evento(
        "persistencia_correcoes", "INFO", arq_log,
        paste0(nrow(res), " checagem(ns) de persistência de correções confirmada(s) em ", contexto),
        "OK"
      )
    }
  }
  res[]
}

monitora_correcao_materializar_auditoria_persistencia_pos_export <- function(auditoria, contexto) {
 ### Materialização explícita e verificável da releitura pós-exportação.
 ### Não depende da posterior reorganização do layout de output: grava na
 ### área operacional, no log da execução e no destino canônico de auditoria.
  auditoria <- data.table::as.data.table(auditoria)
  contexto <- as.character(contexto)[1L]
  if (is.na(contexto) || !nzchar(contexto)) contexto <- "pos_export_registros_corrig"
  if (!nrow(auditoria) && !length(names(auditoria))) {
    auditoria <- data.table::data.table(
      contexto = contexto,
      status_persistencia = "nao_aplicavel_sem_operacoes",
      mensagem = "Nenhuma operação auditável estava disponível para releitura pós-exportação"
    )
  }
  exec_id <- get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)
  nome_ult <- paste0("auditoria_persistencia_correcoes_", contexto, "_ultima_execucao.csv")
  nome_exec <- paste0("auditoria_persistencia_correcoes_", contexto, "_", exec_id, ".csv")
  output_dir <- get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE)
  correcoes_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(output_dir, "02_painel_correcoes", "operacoes_sessao"), inherits = TRUE)
  log_dir <- get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE)
  canonico_dir <- file.path(output_dir, "03_auditorias", "persistencia")
  destinos <- unique(c(
    file.path(correcoes_dir, nome_ult),
    file.path(log_dir, nome_exec),
    file.path(canonico_dir, nome_ult)
  ))
  gravados <- character()
  erros <- character()
  for (arq in destinos) {
    ok <- tryCatch({
      dir.create(dirname(arq), recursive = TRUE, showWarnings = FALSE)
      monitora_fwrite(auditoria, arq, na = "")
      file.exists(arq) && isTRUE(file.info(arq)$size > 0)
    }, error = function(e) {
      erros <<- c(erros, paste0(arq, ": ", conditionMessage(e)))
      FALSE
    })
    if (isTRUE(ok)) gravados <- c(gravados, arq)
  }
  if (!length(gravados)) {
    stop("Não foi possível materializar a auditoria pós-exportação: ", paste(erros, collapse = " | "), call. = FALSE)
  }
  assign("MONITORA_AUDITORIA_PERSISTENCIA_POS_EXPORT_ULTIMA", data.table::copy(auditoria), envir = .GlobalEnv)
  assign("MONITORA_ARQUIVOS_AUDITORIA_PERSISTENCIA_POS_EXPORT_ULTIMA", gravados, envir = .GlobalEnv)
  invisible(gravados)
}

monitora_correcao_auditoria_operacoes_atual <- function() {
 ### A organização intermediária do output pode mover a cópia operacional antes
 ### da exportação final. A releitura não pode depender apenas do objeto em
 ### memória: recupera a mesma auditoria materializada, sem reconstruir operações.
  aud <- get0("MONITORA_AUDITORIA_CORRECOES_CAMPOS_ULTIMA", ifnotfound = NULL, inherits = TRUE)
  if (inherits(aud, c("data.frame", "data.table")) && nrow(data.table::as.data.table(aud))) {
    return(data.table::copy(data.table::as.data.table(aud)))
  }
  output_dir <- get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE)
  correcoes_dir <- get0(
    "MONITORA_CORRECOES_DIR",
    ifnotfound = file.path(output_dir, "02_painel_correcoes", "operacoes_sessao"),
    inherits = TRUE
  )
  log_dir <- get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE)
  candidatos <- c(
    file.path(correcoes_dir, "auditoria_correcoes_campos_ultima_execucao.csv"),
    file.path(output_dir, "02_painel_correcoes", "auditorias_operacionais", "auditoria_correcoes_campos_ultima_execucao.csv")
  )
  logs <- list.files(
    log_dir, pattern = "^auditoria_correcoes_campos_[0-9]{8}_[0-9]{6}[.]csv$",
    full.names = TRUE
  )
  if (length(logs)) candidatos <- c(candidatos, sort(logs, decreasing = TRUE))
  candidatos <- unique(candidatos[file.exists(candidatos)])
  for (arq in candidatos) {
    aud <- tryCatch(
      data.table::fread(arq, encoding = "UTF-8", na.strings = NULL, colClasses = "character", showProgress = FALSE),
      error = function(e) NULL
    )
    if (inherits(aud, c("data.frame", "data.table")) && nrow(data.table::as.data.table(aud))) {
      assign("MONITORA_AUDITORIA_CORRECOES_CAMPOS_ULTIMA", data.table::copy(data.table::as.data.table(aud)), envir = .GlobalEnv)
      return(data.table::copy(data.table::as.data.table(aud)))
    }
  }
  data.table::data.table()
}

monitora_correcao_auditar_releitura_pos_export <- function(caminho, contexto) {
 ### Motor único para os três pontos de exportação de registros_corrig.
 ### Sempre materializa um resultado: checagens por operação ou não aplicável.
  output_dir <- get0("MONITORA_OUTPUT_DIR", ifnotfound = dirname(caminho), inherits = TRUE)
  candidatos_produto <- unique(c(
    caminho,
    if (exists("monitora_produtos_path_canonico", mode = "function")) {
      tryCatch(monitora_produtos_path_canonico("registros_corrig.csv", output_dir), error = function(e) NA_character_)
    } else NA_character_,
    file.path(output_dir, "01_produtos_dados", "registros_corrig.csv")
  ))
  candidatos_produto <- candidatos_produto[!is.na(candidatos_produto) & nzchar(candidatos_produto)]
  existentes <- candidatos_produto[file.exists(candidatos_produto)]
  if (!length(existentes)) {
    stop("Produto registros_corrig ausente para releitura pós-exportação: ", paste(candidatos_produto, collapse = " | "), call. = FALSE)
  }
  caminho <- existentes[1L]
  obj_lido <- data.table::fread(
    caminho, encoding = "UTF-8", na.strings = c("", "NA"),
    colClasses = "character", showProgress = FALSE
  )
  aud <- monitora_correcao_auditoria_operacoes_atual()
  res <- if (nrow(aud) && exists("monitora_correcao_auditar_persistencia_operacoes", mode = "function")) {
    monitora_correcao_auditar_persistencia_operacoes(
      obj_lido,
      aud,
      chaves = monitora_correcao_colunas_chave(obj_lido),
      coletas_excluidas = if (exists("MONITORA_COLETAS_EXCLUIDAS_CORRECOES_ULTIMA", inherits = TRUE)) MONITORA_COLETAS_EXCLUIDAS_CORRECOES_ULTIMA else character(),
      contexto = contexto,
      abortar = FALSE
    )
  } else {
    data.table::data.table()
  }
  monitora_correcao_materializar_auditoria_persistencia_pos_export(res, contexto = contexto)
  monitora_correcao_marcar_checkpoint_por_auditoria_operacoes(res, contexto = contexto)
  invisible(data.table::as.data.table(res))
}

monitora_correcao_novo_id <- function(prefix = "CORR") {
  paste0(prefix, "_", format(Sys.time(), "%Y%m%d%H%M%S"), "_", sample.int(9999, 1))
}

monitora_correcao_assinatura_operacoes <- function(ops) {
  ops <- data.table::as.data.table(ops)
  if (!nrow(ops)) return(character(0))
  cols_sig <- c(
    "tipo_correcao", "escopo_aplicacao", "tipo_triagem", "escopo_diagnostico_mvlote",
    "categoria_base_diagnostica", "coleta", "coleta_uuid", "uuid_registro", "monitora_row_id",
    "linha_indice", "linhas_alvo_serializadas", "ponto_amostral", "ponto_metro",
    "atributo_coluna_registros_corrig", "acao", "token_pai", "token_removido",
    "categoria_origem", "categoria_destino", "valor_original_esperado", "valor_novo",
    "forma_valida_escolhida", "habito_escolhido"
  )
  for (cc in cols_sig) if (!(cc %in% names(ops))) data.table::set(ops, j = cc, value = NA_character_)
  do.call(paste, c(lapply(cols_sig, function(cc) {
    z <- as.character(ops[[cc]])
    z[is.na(z)] <- ""
    trimws(tolower(z))
  }), sep = "\r"))
}

monitora_correcao_serial_linhas_canonico <- function(x) {
  li <- suppressWarnings(as.integer(monitora_correcao_parse_serial_generico(x)))
  li <- sort(unique(li[!is.na(li) & li > 0L]))
  if (!length(li)) return("")
  paste(li, collapse = ";")
}

monitora_correcao_primeiro_campo_existente <- function(dt, campos, padrao = NA_character_) {
  dt <- data.table::as.data.table(dt)
  for (cc in campos) {
    if (cc %in% names(dt)) {
      z <- as.character(dt[[cc]])
      z <- z[!is.na(z) & nzchar(trimws(z))]
      if (length(z)) return(z[1L])
    }
  }
  padrao
}

monitora_correcao_assinaturas_mvlote <- function(ops) {
  ops <- data.table::as.data.table(ops)
  if (!nrow(ops)) return(data.table::data.table(escopo = character(), solucao = character(), completa = character()))
  cols <- c(
    "tipo_correcao", "tipo_triagem", "escopo_diagnostico_mvlote", "categoria_base_diagnostica",
    "categoria_origem", "categoria_destino", "token_pai", "token_removido",
    "valor_original_esperado", "valor_novo", "forma_valida_escolhida", "habito_escolhido",
    "linhas_alvo_serializadas", "linha_indice", "coleta"
  )
  for (cc in cols) if (!(cc %in% names(ops))) data.table::set(ops, j = cc, value = NA_character_)
  canon_txt <- function(z) {
    z <- as.character(z)
    z[is.na(z)] <- ""
    trimws(tolower(z))
  }
  canon_forma <- function(z) {
    zz <- tryCatch(monitora_correcao_forma_canonica_lote(monitora_correcao_parse_serial_generico(z)), error = function(e) monitora_correcao_parse_serial_generico(z))
    zz <- unique(trimws(tolower(as.character(zz))))
    zz <- zz[!is.na(zz) & nzchar(zz)]
    if (!length(zz)) return("")
    paste(sort(zz), collapse = ";")
  }
  linhas_sig <- vapply(seq_len(nrow(ops)), function(i) {
    zz <- monitora_correcao_serial_linhas_canonico(ops$linhas_alvo_serializadas[i])
    if (!nzchar(zz)) zz <- monitora_correcao_serial_linhas_canonico(ops$linha_indice[i])
    zz
  }, character(1))
  token_sig <- vapply(seq_len(nrow(ops)), function(i) {
 ### A fotografia da célula não integra a identidade da forma movida.
 ### Usá-la aqui fazia duas formas distintas da mesma linha parecerem o
 ### mesmo escopo e uma operação substituía/ocultava a outra na fila.
    tok <- canon_forma(ops$token_removido[i])
    if (!nzchar(tok)) tok <- canon_forma(ops$token_pai[i])
    tok
  }, character(1))
  forma_dest <- vapply(seq_len(nrow(ops)), function(i) {
    canon_forma(c(ops$forma_valida_escolhida[i], ops$valor_novo[i]))
  }, character(1))
  tipo <- canon_txt(ops$tipo_triagem)
  tipo[!nzchar(tipo)] <- canon_txt(ops$escopo_diagnostico_mvlote)[!nzchar(tipo)]
  tipo[!nzchar(tipo)] <- "movimento_forma_vida_lote"
  cat_base <- canon_txt(ops$categoria_base_diagnostica)
  cat_base[!nzchar(cat_base)] <- canon_txt(ops$categoria_origem)[!nzchar(cat_base)]
  escopo <- paste(tipo, cat_base, canon_txt(ops$categoria_origem), token_sig, linhas_sig, sep = "\r")
  solucao <- paste(canon_txt(ops$categoria_destino), forma_dest, canon_txt(ops$habito_escolhido), sep = "\r")
  data.table::data.table(escopo = escopo, solucao = solucao, completa = paste(escopo, solucao, sep = "\r"))
}

monitora_correcao_status_mvlote_fatal <- function(status) {
  status <- unique(tolower(trimws(as.character(status))))
  status <- status[!is.na(status) & nzchar(status)]
  if (!length(status)) return(FALSE)
  nao_fatais <- c(
    "bloqueada_operacao_repetida_sem_efeito",
    "bloqueada_sem_ocorrencias_migraveis",
    "ignorada_operacao_repetida_sem_efeito",
    "ignorada_sem_efeito_estado_ja_corrigido",
    "substituida_por_operacao_posterior",
    "duplicada_exata_bloqueada",
    "sem_ocorrencias_migraveis_estado_ja_corrigido"
  )
  status_f <- setdiff(status, nao_fatais)
  if (!length(status_f)) return(FALSE)
  any(grepl("^(falha_|erro_|bloqueada_coluna_protegida|bloqueada_operacao_nula|falha_habito|falha_coluna|falha_lote|falha_n_linhas|falha_sem_linhas)", status_f))
}

monitora_correcao_normalizar_mvlote_sessao <- function(corr, contexto = "backend") {
  corr <- data.table::as.data.table(corr)
  audit <- data.table::data.table()
  if (!nrow(corr) || !exists("monitora_correcao_eh_operacao_movimento_forma_vida_lote", mode = "function")) {
    attr(corr, "auditoria_normalizacao_mvlote") <- audit
    return(corr[])
  }
  idx <- which(monitora_correcao_eh_operacao_movimento_forma_vida_lote(corr))
  if (length(idx) < 2L) {
    attr(corr, "auditoria_normalizacao_mvlote") <- audit
    return(corr[])
  }
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  sig <- monitora_correcao_assinaturas_mvlote(corr[idx])
  tmp <- data.table::data.table(row_id = idx, ordem_norm = seq_along(idx), escopo = sig$escopo, solucao = sig$solucao, completa = sig$completa)
  tmp <- tmp[nzchar(escopo)]
  if (!nrow(tmp)) {
    attr(corr, "auditoria_normalizacao_mvlote") <- audit
    return(corr[])
  }
  tmp[, n_escopo := .N, by = escopo]
  repet <- tmp[n_escopo > 1L]
  if (!nrow(repet)) {
    attr(corr, "auditoria_normalizacao_mvlote") <- audit
    return(corr[])
  }
  keep <- repet[, .SD[which.max(ordem_norm)], by = escopo]$row_id
  drop <- setdiff(repet$row_id, keep)
  if (length(drop)) {
    audit <- data.table::rbindlist(lapply(drop, function(rr) {
      data.table::data.table(
        id_correcao = if ("id_correcao" %in% names(corr)) as.character(corr$id_correcao[rr]) else NA_character_,
        ordem_operacao = if ("ordem_operacao" %in% names(corr)) as.character(corr$ordem_operacao[rr]) else NA_character_,
        status = "substituida_por_operacao_posterior",
        mensagem = paste0("MVLOTE ", contexto, ": operação anterior substituída por operação posterior com o mesmo escopo diagnóstico de linhas."),
        atributo = "__mover_forma_vida_lote__",
        linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = contexto
      )
    }), fill = TRUE, use.names = TRUE)
    corr <- corr[-drop]
  }
  attr(corr, "auditoria_normalizacao_mvlote") <- audit
  corr[]
}

monitora_correcao_criar_indice_linhas <- function(dt, chaves = monitora_correcao_colunas_chave(dt)) {
 ### Índice leve para reduzir revarreduras repetidas de registros_corrig durante
 ### lotes de correção. Mantém compatibilidade: quando o índice não existe,
 ### monitora_correcao_localizar_linhas usa o caminho original por varredura.
  dt <- data.table::as.data.table(dt)
  indice <- new.env(parent = emptyenv())
  indice$n <- nrow(dt)
  indice$por_linha_indice <- seq_len(nrow(dt))
  criar_split <- function(col) {
    if (is.na(col) || !nzchar(col) || !(col %in% names(dt))) return(NULL)
    vals <- as.character(dt[[col]])
    ok <- !is.na(vals) & nzchar(trimws(vals))
    if (!any(ok)) return(NULL)
    split(which(ok), vals[ok], drop = TRUE)
  }
  indice$por_coleta_uuid <- criar_split(chaves$coleta_uuid)
  indice$por_coleta <- criar_split(chaves$coleta)
  indice$por_uuid_registro <- criar_split(chaves$uuid_registro)
  indice$por_ponto_amostral <- criar_split(chaves$ponto_amostral)
  indice$por_monitora_row_id <- criar_split(if (MONITORA_COL_ROW_ID %in% names(dt)) MONITORA_COL_ROW_ID else NA_character_)
  indice
}

monitora_correcao_indice_obter <- function(indice, nome, valor) {
  if (is.null(indice) || is.null(nome) || !nzchar(nome) || monitora_correcao_vazio(valor)) return(integer(0))
  if (!exists(nome, envir = indice, inherits = FALSE)) return(integer(0))
  tab <- get(nome, envir = indice, inherits = FALSE)
  if (is.null(tab)) return(integer(0))
  valor <- as.character(valor)[1L]
  if (is.na(valor) || !nzchar(trimws(valor))) return(integer(0))
  out <- tab[[valor]]
  if (is.null(out)) integer(0) else as.integer(out)
}

monitora_correcao_localizar_linhas <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL) {
 ### Localização segura de linhas para correções assistidas.
 ### A linha_indice é tratada apenas como fallback, pois exclusões, filtros e
 ### reordenações tornam índices numéricos frágeis entre o painel e a aplicação.
 ### A prioridade passa a ser: MONITORA_ROW_ID > UUID do registro > UUID/ID da COLETA > chaves de
 ### contexto do ponto > linha_indice validado por contexto.
  n_dt <- nrow(dt)
  if (n_dt == 0L) return(integer(0))
  idx <- rep(TRUE, n_dt)
  escopo <- tolower(trimws(as.character(corr$escopo_aplicacao[1])))
  if (is.na(escopo) || !nzchar(escopo)) escopo <- "ponto"

  get1 <- function(nm) {
    if (!(nm %in% names(corr))) return(NA_character_)
    as.character(corr[[nm]][1L])
  }
  vazio <- function(x) monitora_correcao_vazio(x)
  restringir <- function(linhas, col, valor) {
    linhas <- as.integer(linhas)
    linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= n_dt]
    if (!length(linhas) || is.na(col) || !nzchar(col) || !(col %in% names(dt)) || vazio(valor)) return(linhas)
    linhas[as.character(dt[[col]][linhas]) == as.character(valor)]
  }
  filtrar_contexto_ponto <- function(linhas) {
    linhas <- restringir(linhas, chaves$ponto_amostral, get1("ponto_amostral"))
    linhas <- restringir(linhas, chaves$ponto_metro, get1("ponto_metro"))
    linhas
  }
  filtrar_contexto_basico <- function(linhas) {
    linhas <- restringir(linhas, chaves$uc, get1("UC"))
    linhas <- restringir(linhas, chaves$ea, get1("EA"))
    linhas <- restringir(linhas, chaves$ua, get1("UA"))
    linhas <- restringir(linhas, chaves$ciclo, get1("CICLO"))
    linhas <- restringir(linhas, chaves$campanha, get1("CAMPANHA"))
    linhas <- restringir(linhas, chaves$ano, get1("ANO"))
    linhas <- restringir(linhas, chaves$data_hora, get1("Data (data_hora)"))
    if (escopo %in% c("ponto", "coleta_ponto", "uuid_registro")) linhas <- filtrar_contexto_ponto(linhas)
    linhas
  }

  row_id_val <- get1("monitora_row_id")
  if (!vazio(row_id_val) && MONITORA_COL_ROW_ID %in% names(dt)) {
    hit_row_id <- monitora_correcao_indice_obter(indice, "por_monitora_row_id", row_id_val)
    if (!length(hit_row_id)) hit_row_id <- which(as.character(dt[[MONITORA_COL_ROW_ID]]) == row_id_val)
    if (length(hit_row_id) == 1L) return(as.integer(hit_row_id))
  }

  uuid_val <- get1("uuid_registro")
  if (!vazio(uuid_val) && !is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) {
    hit_uuid <- monitora_correcao_indice_obter(indice, "por_uuid_registro", uuid_val)
    if (!length(hit_uuid)) hit_uuid <- which(as.character(dt[[chaves$uuid_registro]]) == uuid_val)
    hit_uuid <- filtrar_contexto_basico(hit_uuid)
    if (length(hit_uuid) > 0L) return(as.integer(hit_uuid))
  }

  linhas_base <- integer(0)
  coleta_uuid_val <- get1("coleta_uuid")
  coleta_val <- get1("coleta")
  if (!vazio(coleta_uuid_val) && !is.na(chaves$coleta_uuid) && chaves$coleta_uuid %in% names(dt)) {
    linhas_base <- monitora_correcao_indice_obter(indice, "por_coleta_uuid", coleta_uuid_val)
    if (!length(linhas_base)) linhas_base <- which(as.character(dt[[chaves$coleta_uuid]]) == coleta_uuid_val)
  } else if (!vazio(coleta_val) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    linhas_base <- monitora_correcao_indice_obter(indice, "por_coleta", coleta_val)
    if (!length(linhas_base)) linhas_base <- which(as.character(dt[[chaves$coleta]]) == coleta_val)
  }
  if (length(linhas_base) > 0L) {
    linhas_base <- filtrar_contexto_basico(linhas_base)
    if (length(linhas_base) > 0L) return(as.integer(linhas_base))
  }

  if (!vazio(coleta_uuid_val) && !is.na(chaves$coleta_uuid) && chaves$coleta_uuid %in% names(dt)) idx <- idx & as.character(dt[[chaves$coleta_uuid]]) == coleta_uuid_val
  if (!vazio(coleta_val) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) idx <- idx & as.character(dt[[chaves$coleta]]) == coleta_val
  idx_linhas <- which(idx)
  idx_linhas <- filtrar_contexto_basico(idx_linhas)
  if (length(idx_linhas) > 0L && (!vazio(coleta_uuid_val) || !vazio(coleta_val) || !vazio(get1("ponto_amostral")))) return(as.integer(idx_linhas))

 ### Fallback por linha_indice apenas se ainda não houver chave estável. Quando
 ### houver contexto suficiente, a linha é aceita somente se o contexto bater.
  if ("linha_indice" %in% names(corr)) {
    li <- suppressWarnings(as.integer(corr$linha_indice[1L]))
    if (!is.na(li) && li >= 1L && li <= n_dt) {
      li_ctx <- filtrar_contexto_basico(li)
      if (length(li_ctx) > 0L || all(vapply(c("UC", "EA", "UA", "CICLO", "CAMPANHA", "ANO", "Data (data_hora)", "ponto_amostral", "ponto_metro"), function(nm) vazio(get1(nm)), logical(1)))) return(li)
    }
  }

  integer(0)
}

monitora_correcao_aplicar_operacao <- function(valor_atual, acao, valor_novo, valor_original_esperado = NA_character_) {
  acao <- tolower(trimws(as.character(acao)))
  valor_novo <- if (is.na(valor_novo)) NA_character_ else as.character(valor_novo)
  valor_original_esperado <- if (is.na(valor_original_esperado)) NA_character_ else as.character(valor_original_esperado)
  if (acao %in% c("clear", "limpar")) return(rep(NA_character_, length(valor_atual)))
  if (acao %in% c("append_token", "adicionar_token")) return(vapply(valor_atual, monitora_correcao_append_token_valor, character(1), token = valor_novo))
  if (acao %in% c("remove_token", "remover_token")) {
    token_remover <- if (monitora_correcao_vazio(valor_novo)) valor_original_esperado else valor_novo
    return(vapply(valor_atual, monitora_correcao_remove_token_valor, character(1), token = token_remover))
  }
  if (acao %in% c("replace_token", "substituir_token")) return(vapply(valor_atual, monitora_correcao_replace_token_valor, character(1), token_antigo = valor_original_esperado, token_novo = valor_novo))
  rep(valor_novo, length(valor_atual))
}

### ------------------------------------------
### Contrato transacional por tipo de operação:
### - update/substituir_valor e clear/limpar continuam sendo operações de célula inteira;
### quando valor_original_esperado é informado, ele precisa coincidir com o valor completo atual.
### - append_token, remove_token e replace_token são operações tokenizadas; nelas,
### valor_original_esperado pode ser token/subconjunto de tokens presente no campo,
### sem exigir igualdade literal com a célula completa.
### - remove_token aceita o token a remover em valor_novo ou, se vazio, em valor_original_esperado.

monitora_publicacao_d_tokens_presentes_em_valor <- function(valor_atual, tokens_esperados) {
  alvo <- monitora_correcao_tokenizar(tokens_esperados)
  if (!length(alvo)) return(rep(TRUE, length(valor_atual)))
  vapply(
    valor_atual,
    function(v) all(alvo %in% monitora_correcao_tokenizar(v)),
    logical(1)
  )
}

monitora_publicacao_d_precondicao_valor_original <- function(valor_atual, acao, valor_novo, valor_original_esperado) {
  acao <- tolower(trimws(as.character(acao)[1L]))
  if (is.na(acao)) acao <- ""
  valor_novo <- if (length(valor_novo)) as.character(valor_novo[1L]) else NA_character_
  valor_original_esperado <- if (length(valor_original_esperado)) as.character(valor_original_esperado[1L]) else NA_character_
  if (monitora_correcao_vazio(valor_original_esperado) && !(acao %in% c("remove_token", "remover_token"))) {
    return(list(ok = TRUE, mensagem = "OK"))
  }

  valor_atual <- as.character(valor_atual)
  esperado_norm <- monitora_correcao_na_para_vazio(valor_original_esperado)
  atual_norm <- monitora_correcao_na_para_vazio(valor_atual)
  iguais <- atual_norm == esperado_norm

  if (acao %in% c("update", "substituir_valor", "clear", "limpar")) {
    if (all(iguais)) return(list(ok = TRUE, mensagem = "OK"))
    return(list(
      ok = FALSE,
      mensagem = paste0("valor_original_esperado não confere em ", sum(!iguais), " linha(s); operação de valor completo exige igualdade da célula inteira")
    ))
  }

  if (acao %in% c("replace_token", "substituir_token")) {
    tokens_alvo <- valor_original_esperado
    contem <- monitora_publicacao_d_tokens_presentes_em_valor(valor_atual, tokens_alvo)
    if (all(contem)) {
      if (all(iguais)) return(list(ok = TRUE, mensagem = "OK"))
      return(list(
        ok = TRUE,
        mensagem = paste0("OK; valor_original_esperado divergiu em ", sum(!iguais), " linha(s), mas o(s) token(s)-alvo de substituição estava(m) presente(s) em todas as linhas-alvo")
      ))
    }
    return(list(
      ok = FALSE,
      mensagem = paste0("valor_original_esperado não confere em ", sum(!iguais), " linha(s) e o(s) token(s)-alvo de substituição não estava(m) presente(s) em ", sum(!contem), " linha(s)")
    ))
  }

  if (acao %in% c("remove_token", "remover_token")) {
    tokens_alvo <- if (monitora_correcao_vazio(valor_novo)) valor_original_esperado else valor_novo
    contem <- monitora_publicacao_d_tokens_presentes_em_valor(valor_atual, tokens_alvo)
    if (all(contem)) {
      if (all(iguais)) return(list(ok = TRUE, mensagem = "OK"))
      return(list(
        ok = TRUE,
        mensagem = paste0("OK; valor_original_esperado divergiu em ", sum(!iguais), " linha(s), mas o(s) token(s)-alvo de remoção estava(m) presente(s) em todas as linhas-alvo")
      ))
    }
    return(list(
      ok = FALSE,
      mensagem = paste0("token(s)-alvo de remoção não estava(m) presente(s) em ", sum(!contem), " linha(s)")
    ))
  }

  if (acao %in% c("append_token", "adicionar_token")) {
    if (monitora_correcao_vazio(valor_original_esperado)) return(list(ok = TRUE, mensagem = "OK"))
    contem <- monitora_publicacao_d_tokens_presentes_em_valor(valor_atual, valor_original_esperado)
    if (all(iguais) || all(contem)) {
      if (all(iguais)) return(list(ok = TRUE, mensagem = "OK"))
      return(list(
        ok = TRUE,
        mensagem = paste0("OK; valor_original_esperado divergiu em ", sum(!iguais), " linha(s), mas estava contido como token/subconjunto em todas as linhas-alvo")
      ))
    }
    return(list(
      ok = FALSE,
      mensagem = paste0("valor_original_esperado não confere em ", sum(!iguais), " linha(s) e não está contido como token/subconjunto em ", sum(!contem), " linha(s)")
    ))
  }

  if (monitora_correcao_vazio(valor_original_esperado) || all(iguais)) {
    return(list(ok = TRUE, mensagem = "OK"))
  }
  list(ok = FALSE, mensagem = paste0("valor_original_esperado não confere em ", sum(!iguais), " linha(s)"))
}
