monitora_correcao_calcular_tipo_forma_vida_esperado <- function(dt, linhas = NULL, chaves = monitora_correcao_colunas_chave(dt)) {
 ###
 ### Calcula o valor esperado do campo superior de forma de vida a partir do
 ### estado FINAL do ponto, resolvendo automaticamente condicionantes do contrato.
 ### Regra central: solo_nu/solo exposto é mutuamente exclusivo com qualquer
 ### contato real com a vareta. Contato real inclui categorias derivadas das
 ### listas inferiores finais e quaisquer tokens superiores materiais/contratuais
 ### já presentes, como serrapilheira/material botânico ou outra forma válida.
  dt <- data.table::as.data.table(dt)
  if (is.null(linhas)) linhas <- seq_len(nrow(dt))
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas)) return(character(0))
  tipo_col <- chaves$tipo_forma_vida
  if (is.na(tipo_col) || !nzchar(tipo_col) || !(tipo_col %in% names(dt))) return(rep(NA_character_, length(linhas)))

  categorias_movimento <- tryCatch(monitora_contrato_categorias_movimento()$categoria, error = function(e) character(0))
  if (!length(categorias_movimento)) stop("Contrato único não forneceu categorias para recalcular tipo_forma_vida.", call. = FALSE)
  parent_cols <- stats::setNames(vapply(
    categorias_movimento,
    function(cat) tryCatch(monitora_correcao_coluna_forma_vida(dt, cat), error = function(e) NA_character_),
    character(1)
  ), categorias_movimento)
  parent_cols <- parent_cols[!is.na(parent_cols) & nzchar(parent_cols) & parent_cols %in% names(dt)]
  material_col <- if (exists("monitora_publicacao_c_resolver_coluna_materiais_botanicos", mode = "function")) {
    tryCatch(monitora_publicacao_c_resolver_coluna_materiais_botanicos(dt, criar = FALSE), error = function(e) NA_character_)
  } else NA_character_

  antes <- as.character(dt[[tipo_col]][linhas])
  solo_tokens <- c("solo_nu", "solo_exposto", "solo", "rocha", "rochas")
  ausentes_tokens <- c("", "na", "nan", "null", "---")
  categorias_controladas <- categorias_movimento
  preenchidas <- if (length(parent_cols)) lapply(parent_cols, function(cc) !monitora_correcao_vazio_vec(dt[[cc]][linhas])) else list()

 ### o estado derivado depende apenas de Encostam atual, presença de
 ### material e presença/vazio das quatro listas inferiores. Calcula uma vez
 ### por assinatura distinta, em vez de repetir tokenização em todas as linhas.
  tem_material <- rep(FALSE, length(linhas))
  if (!is.na(material_col) && nzchar(material_col) && material_col %in% names(dt)) {
    mat_vals <- as.character(dt[[material_col]][linhas])
    mat_unicos <- unique(mat_vals)
    mat_mapa <- vapply(mat_unicos, function(v) length(monitora_publicacao_c_tokens_materiais_em_valor(v)) > 0L, logical(1L))
    tem_material <- unname(mat_mapa[match(mat_vals, mat_unicos)])
    tem_material[is.na(tem_material)] <- FALSE
  }
  partes_assinatura <- c(list(monitora_correcao_na_para_vazio(antes), as.integer(tem_material)), lapply(preenchidas, as.integer))
  assinatura <- do.call(paste, c(partes_assinatura, sep = "\034"))
  assinatura_unica <- unique(assinatura)
  representantes <- match(assinatura_unica, assinatura)
  esperado_unico <- vapply(representantes, function(ii) {
    atual <- monitora_correcao_tokenizar(antes[ii])
    atual_norm <- monitora_correcao_limpar_texto(atual)
    remover_solo <- atual_norm %in% monitora_correcao_limpar_texto(solo_tokens)
    remover_categorias <- atual_norm %in% categorias_controladas
    remover_desconhecida_superior <- atual_norm %in% monitora_correcao_limpar_texto(tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) c("desconhecida", "desconhecido")))
    remover_ausentes <- atual_norm %in% ausentes_tokens | is.na(atual_norm) | !nzchar(atual_norm)
    outros_contatos <- atual[!(remover_solo | remover_categorias | remover_desconhecida_superior | remover_ausentes)]
    if (isTRUE(tem_material[ii])) outros_contatos <- unique(c(outros_contatos, monitora_publicacao_c_token_material_superior()))

    cats <- if (length(parent_cols)) names(parent_cols)[vapply(preenchidas, function(z) isTRUE(z[ii]), logical(1))] else character(0)
    contato_real <- unique(c(outros_contatos, cats))
    contato_real <- contato_real[!is.na(contato_real) & nzchar(trimws(contato_real))]

    if (length(contato_real)) {
      monitora_correcao_colapsar_tokens(contato_real)
    } else {
      "solo_nu"
    }
  }, character(1L), USE.NAMES = FALSE)
  unname(esperado_unico[match(assinatura, assinatura_unica)])
}

monitora_correcao_sincronizar_encostam_final <- function(dt,
                                                          linhas = NULL,
                                                          chaves = monitora_correcao_colunas_chave(dt),
                                                          contexto = "pos_correcoes",
                                                          sincronizar_materiais = TRUE) {
 ### Sincronização final obrigatória do campo superior Encostam/tipo_forma_vida.
 ###
 ### Justificativa operacional:
 ### - operações como TRIOUT, MVLOTE e recálculos intermediários podem tocar as
 ### listas inferiores em momentos diferentes;
 ### - Encostam é campo derivado e não deve depender do último valor intermediário
 ### auditado, mas sim do contrato final: categorias superiores coerentes com
 ### as listas inferiores finais;
 ### - a aplicação é feita em bloco via data.table::set , alterando apenas as
 ### linhas efetivamente divergentes.
  dt <- monitora_dt_referenciar(dt)
  if (is.null(linhas)) linhas <- seq_len(nrow(dt))
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  chaves <- monitora_correcao_colunas_chave(dt)
  if (isTRUE(sincronizar_materiais) && exists("monitora_publicacao_c_sincronizar_materiais_botanicos", mode = "function")) {
    try(monitora_publicacao_c_sincronizar_materiais_botanicos(dt, linhas, contexto = paste0(contexto, "_materiais_botanicos")), silent = TRUE)
  }
  tipo_col <- chaves$tipo_forma_vida
  audit <- data.table::data.table()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  if (!length(linhas) || is.na(tipo_col) || !nzchar(tipo_col) || !(tipo_col %in% names(dt))) {
    return(list(dt = dt, audit = audit, linhas = integer(), afetacoes = afetacoes))
  }
  antes <- as.character(dt[[tipo_col]][linhas])
  esperado <- monitora_correcao_calcular_tipo_forma_vida_esperado(dt, linhas, chaves)
  mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(esperado)
  linhas_mudou <- linhas[mudou]
  if (length(linhas_mudou) > 0L) {
    data.table::set(dt, i = linhas_mudou, j = tipo_col, value = esperado[mudou])
    audit <- data.table::data.table(
      id_correcao = "SYNC_ENCOSTAM_FINAL",
      ordem_operacao = NA_character_,
      status = "aplicada",
      mensagem = paste0(
        "Sincronização final obrigatória de Encostam/tipo_forma_vida a partir das listas inferiores finais; contexto=",
        contexto
      ),
      atributo = tipo_col,
      linha_indice = linhas_mudou,
      valor_antes = antes[mudou],
      valor_depois = esperado[mudou],
      arquivo_correcao = "sincronizacao_final_pos_correcoes"
    )
    afetacoes <- data.table::data.table(linha_indice = linhas_mudou, atributo = tipo_col)
  }
  list(dt = dt, audit = audit, linhas = linhas_mudou, afetacoes = afetacoes)
}

### sanitização de tokens superiores órfãos de Encostam
### -------------------------------------------------------------------------
### Caso remanescente após correções manuais: Encostam/tipo_forma_vida contém um
### token de categoria (nativa/exotica/seca_morta) mas a(s) coluna(s) inferior(es)
### dessa categoria estão vazias (órfão). Reaproveita apenas fonte já existente e
### comprovada: monitora_correcao_colunas_forma_vida_categoria para localizar as
### listas inferiores de cada categoria, monitora_relatorio_exoticas_tem_token
### para detectar o token superior (mesma função usada pelo próprio painel para
### os contadores de "nativa/exotica/seca_morta sem forma de vida"), e
### monitora_correcao_sincronizar_encostam_final -> monitora_correcao_calcular_
### tipo_forma_vida_esperado (inalteradas) para o recálculo em si — essa última
### já implementa a regra de solo_nu correta: qualquer token de categoria é
### descartado do Encostam a menos que a lista inferior correspondente esteja
### realmente preenchida, e qualquer outro contato real (material botânico,
### serrapilheira, forma_vida_outros atual, etc.) impede solo_nu; "outra forma de
### vida" legada não é tratada como categoria válida porque não é uma das 3
### categorias controladas nem um contato reconhecido por essa função. Nenhuma
### lista nova de tokens/categorias foi criada.
monitora_correcao_linhas_orfaos_encostam <- function(dt, chaves = monitora_correcao_colunas_chave(dt), linhas = NULL) {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (is.null(linhas)) linhas <- seq_len(n)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= n]
  tipo_col <- chaves$tipo_forma_vida
  if (!length(linhas) || is.na(tipo_col) || !nzchar(as.character(tipo_col)[1L]) || !(as.character(tipo_col)[1L] %in% names(dt))) {
    return(list(linhas = integer(0), categorias = data.table::data.table(linha_indice = integer(), categoria = character())))
  }
  tipo_col <- as.character(tipo_col)[1L]
  categorias <- c("nativa", "exotica", "seca_morta")
  toks_categoria <- list(
    nativa = c("nativa", "nativas", "nativo", "nativos"),
    exotica = c("exotica", "exoticas", "exotico", "exoticos"),
    seca_morta = c("seca_morta", "seca", "secas", "seco", "secos", "morta", "mortas", "morto", "mortos")
  )
  tipo_vals <- as.character(dt[[tipo_col]][linhas])
  vazio_vec <- function(v) { z <- tryCatch(monitora_correcao_vazio_vec(v), error = function(e) is.na(v) | !nzchar(trimws(as.character(v)))); z[is.na(z)] <- TRUE; z }
  achados <- list()
  for (cat in categorias) {
    tem_tok <- tryCatch(monitora_relatorio_exoticas_tem_token(tipo_vals, toks_categoria[[cat]]), error = function(e) rep(FALSE, length(linhas)))
    tem_tok[is.na(tem_tok)] <- FALSE
    cols_cat <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(dt, cat), error = function(e) character(0))
    cols_cat <- cols_cat[cols_cat %in% names(dt)]
    forma_preenchida <- rep(FALSE, length(linhas))
    for (cc in cols_cat) forma_preenchida <- forma_preenchida | !vazio_vec(dt[[cc]][linhas])
    orfao <- tem_tok & !forma_preenchida
    if (any(orfao)) achados[[cat]] <- data.table::data.table(linha_indice = linhas[orfao], categoria = cat)
  }
  achados_dt <- if (length(achados)) data.table::rbindlist(achados, use.names = TRUE) else data.table::data.table(linha_indice = integer(), categoria = character())
  list(linhas = sort(unique(achados_dt$linha_indice)), categorias = achados_dt[])
}

monitora_correcao_sanitizar_orfaos_encostam_atomica <- function(dt, linhas = NULL, chaves = monitora_correcao_colunas_chave(dt), id_correcao = "SANEAR_ORFAOS_ENCOSTAM", ordem_operacao = NA_character_, arquivo_correcao = NA_character_, contexto = "sanitizacao_orfaos_encostam") {
  dt <- monitora_dt_referenciar(dt)
  achado <- monitora_correcao_linhas_orfaos_encostam(dt, chaves = chaves, linhas = linhas)
  linhas_orfas <- achado$linhas
  if (!length(linhas_orfas)) {
    return(list(dt = dt[], audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character())))
  }
  tipo_col <- as.character(chaves$tipo_forma_vida)[1L]
  antes_tipo <- as.character(dt[[tipo_col]][linhas_orfas])
  sync <- monitora_correcao_sincronizar_encostam_final(dt, linhas = linhas_orfas, chaves = chaves, contexto = contexto)
  dt <- data.table::as.data.table(sync$dt)
  depois_tipo <- as.character(dt[[tipo_col]][linhas_orfas])
  cats_por_linha <- split(achado$categorias$categoria, achado$categorias$linha_indice)
  audit_rows <- vector("list", length(linhas_orfas))
  for (ii in seq_along(linhas_orfas)) {
    li <- linhas_orfas[ii]
    cats_orf <- unique(as.character(cats_por_linha[[as.character(li)]]))
    solo_nu_add <- identical(monitora_correcao_na_para_vazio(depois_tipo[ii]), "solo_nu") && !identical(monitora_correcao_na_para_vazio(antes_tipo[ii]), "solo_nu")
    audit_rows[[ii]] <- data.table::data.table(
      id_correcao = id_correcao, ordem_operacao = ordem_operacao,
      status = "sanitizada_atomica",
      mensagem = paste0(
        "Token(s) superior(es) orfao(s) removido(s) de Encostam (lista inferior vazia): ", paste(cats_orf, collapse = ";"),
        "; Encostam recalculado a partir das listas inferiores finais",
        if (isTRUE(solo_nu_add)) "; solo_nu adicionado (nenhuma categoria/material valido restante na vareta)" else ""
      ),
      atributo = tipo_col,
      linha_indice = li,
      valor_antes = antes_tipo[ii],
      valor_depois = depois_tipo[ii],
      arquivo_correcao = arquivo_correcao,
      token_removido_orfao = paste(cats_orf, collapse = ";"),
      solo_nu_adicionado = isTRUE(solo_nu_add)
    )
  }
  audit <- data.table::rbindlist(audit_rows, fill = TRUE, use.names = TRUE)
  list(dt = dt[], audit = audit[], linhas = linhas_orfas, afetacoes = data.table::data.table(linha_indice = linhas_orfas, atributo = tipo_col))
}

### sanitização pré-painel de Encostam = desconhecida
### -------------------------------------------------------------------------
### Caso estrito e auditável: quando o campo superior Encostam/tipo_forma_vida
### contém exclusivamente o token desconhecida/desconhecido e as listas
### inferiores nativa/exótica/seca_morta estão vazias, o registro não tem
### categoria-base observável. Por decisão metodológica, "nativa" é usada como
### categoria técnica hospedeira para preservar a pendência como
### nativa/desconhecida no painel, sem inferir forma de vida válida. A ocorrência
### continua impeditiva até substituição assistida ou exclusão da COLETA.
monitora_correcao_sanitizar_encostam_desconhecida_para_nativa <- function(dt,
                                                                          chaves = monitora_correcao_colunas_chave(dt),
                                                                          output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = tempdir(), inherits = TRUE),
                                                                          log_dir = get0("MONITORA_LOG_DIR", ifnotfound = tempdir(), inherits = TRUE),
                                                                          exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                                                          contexto = "pre_painel") {
  dt <- monitora_dt_referenciar(dt)
  audit <- data.table::data.table()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  rel <- data.table::data.table()
  n <- nrow(dt)
  if (!n) return(list(dt = dt[], audit = audit, relatorio = rel, linhas = integer(), afetacoes = afetacoes))
  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) chaves)
  tipo_col <- tryCatch(chaves$tipo_forma_vida, error = function(e) NA_character_)
  if (is.na(tipo_col) || !nzchar(as.character(tipo_col)[1L]) || !(as.character(tipo_col)[1L] %in% names(dt))) {
    return(list(dt = dt[], audit = audit, relatorio = rel, linhas = integer(), afetacoes = afetacoes))
  }
  tipo_col <- as.character(tipo_col)[1L]
  col_nat <- tryCatch(monitora_correcao_coluna_forma_vida(dt, "nativa"), error = function(e) NA_character_)
  if (is.na(col_nat) || !nzchar(as.character(col_nat)[1L]) || !(as.character(col_nat)[1L] %in% names(dt))) {
    return(list(dt = dt[], audit = audit, relatorio = rel, linhas = integer(), afetacoes = afetacoes))
  }
  col_nat <- as.character(col_nat)[1L]
  cols_inf <- unique(unlist(lapply(c("nativa", "exotica", "seca_morta"), function(cat) {
    cc <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(dt, cat), error = function(e) character(0))
    cc[cc %in% names(dt)]
  }), use.names = FALSE))
  if (!length(cols_inf)) return(list(dt = dt[], audit = audit, relatorio = rel, linhas = integer(), afetacoes = afetacoes))

  toks_desc <- tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) c("desconhecida", "desconhecido"))
  toks_desc_norm <- unique(monitora_correcao_limpar_texto(toks_desc))
  tipo_vals <- as.character(dt[[tipo_col]])
  tokens_por_linha <- lapply(tipo_vals, function(v) {
    z <- tryCatch(monitora_correcao_tokenizar(v), error = function(e) character(0))
    z <- monitora_correcao_limpar_texto(z)
    z[!is.na(z) & nzchar(z)]
  })
  encostam_exclusivamente_desc <- vapply(tokens_por_linha, function(z) length(z) > 0L && all(z %in% toks_desc_norm), logical(1))
  inferior_vazia <- rep(TRUE, n)
  for (cc in cols_inf) {
    vv <- tryCatch(monitora_correcao_vazio_vec(dt[[cc]]), error = function(e) is.na(dt[[cc]]) | !nzchar(trimws(as.character(dt[[cc]]))))
    vv[is.na(vv)] <- TRUE
    inferior_vazia <- inferior_vazia & vv
  }
  linhas <- which(encostam_exclusivamente_desc & inferior_vazia)
  linhas <- unique(as.integer(linhas[!is.na(linhas) & linhas >= 1L & linhas <= n]))
  if (!length(linhas)) return(list(dt = dt[], audit = audit, relatorio = rel, linhas = integer(), afetacoes = afetacoes))

  pegar <- function(col) {
    if (!is.na(col) && nzchar(as.character(col)[1L]) && as.character(col)[1L] %in% names(dt)) as.character(dt[[as.character(col)[1L]]][linhas]) else rep(NA_character_, length(linhas))
  }
  antes_tipo <- as.character(dt[[tipo_col]][linhas])
  antes_nat <- as.character(dt[[col_nat]][linhas])
  depois_nat <- vapply(antes_nat, monitora_correcao_append_token_valor, character(1), token = "desconhecida")
  data.table::set(dt, i = linhas, j = col_nat, value = depois_nat)
  sync <- tryCatch(monitora_correcao_sincronizar_encostam_final(dt, linhas = linhas, chaves = chaves, contexto = paste0(contexto, "_encostam_desconhecida_para_nativa")), error = function(e) list(dt = dt, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table()))
  dt <- data.table::as.data.table(sync$dt)
  depois_tipo <- as.character(dt[[tipo_col]][linhas])

  audit <- data.table::rbindlist(list(
    data.table::data.table(
      id_correcao = "SAN_DESC_SUP_PRE_PAINEL",
      ordem_operacao = NA_character_,
      status = "sanitizada_pre_painel",
      mensagem = paste0("Sanitização pré-painel auditável: Encostam exclusivamente desconhecida foi pré-tratado para Encostam=nativa e forma_vida_nativa=desconhecida; contexto=", contexto),
      atributo = col_nat,
      linha_indice = linhas,
      valor_antes = antes_nat,
      valor_depois = depois_nat,
      arquivo_correcao = "sanitizacao_encostam_desconhecida_para_nativa"
    ),
    if (!is.null(sync$audit) && data.table::is.data.table(sync$audit) && nrow(sync$audit)) sync$audit else data.table::data.table()
  ), fill = TRUE, use.names = TRUE)
  afetacoes <- data.table::rbindlist(list(
    data.table::data.table(linha_indice = linhas, atributo = col_nat),
    if (!is.null(sync$afetacoes) && data.table::is.data.table(sync$afetacoes) && nrow(sync$afetacoes)) sync$afetacoes else data.table::data.table()
  ), fill = TRUE, use.names = TRUE)
  ch <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) chaves)
  rel <- data.table::data.table(
    contexto = contexto,
    acao = "encostam_desconhecida_superior_only_para_nativa_desconhecida",
    justificativa_tecnica = "Categoria técnica hospedeira para caso sem categoria-base; permanece ocorrência de Forma de vida desconhecida até correção assistida ou exclusão da COLETA.",
    linha_indice = linhas,
    COLETA = pegar(ch$coleta),
    UC = pegar(ch$uc),
    CICLO = pegar(ch$ciclo),
    CAMPANHA = pegar(ch$campanha),
    EA = pegar(ch$ea),
    UA = pegar(ch$ua),
    ANO = pegar(ch$ano),
    ponto_amostral = pegar(ch$ponto_amostral),
    ponto_metro = pegar(ch$ponto_metro),
    Encostam_original = antes_tipo,
    Encostam_final = depois_tipo,
    forma_vida_nativa_original = antes_nat,
    forma_vida_nativa_final = depois_nat
  )
  arqs <- unique(c(
    file.path(output_dir, "correcoes_campos", "relatorios_pre_painel", "sanitizacao_encostam_desconhecida_para_nativa.csv"),
    file.path(output_dir, "02_painel_correcoes", "relatorios_pre_painel", "sanitizacao_encostam_desconhecida_para_nativa.csv"),
    file.path(log_dir, paste0("sanitizacao_encostam_desconhecida_para_nativa_", exec_id, ".csv"))
  ))
  for (aa in arqs) {
    try({ dir.create(dirname(aa), recursive = TRUE, showWarnings = FALSE); monitora_fwrite(rel, aa, na = "") }, silent = TRUE)
  }
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento(
      "painel_correcoes", "INFO", arqs[1L],
      paste0("Sanitização pré-painel Encostam=desconhecida superior-only aplicada em ", length(linhas), " linha(s); pendência preservada como nativa/desconhecida, com Encostam recalculado para nativa."),
      "relatório específico gerado; operação não infere forma válida nem resolve a pendência"
    )
  }
  list(dt = dt[], audit = audit[], relatorio = rel[], linhas = linhas, afetacoes = unique(afetacoes))
}

monitora_correcao_recalcular_tipo_forma_vida <- function(dt, linhas) {
 ### Recalcula tipo_forma_vida em bloco, evitando set linha-a-linha.
 ### Mantém tokens materiais já existentes e atualiza apenas as categorias
 ### derivadas das listas principais de forma de vida.
  dt <- monitora_dt_referenciar(dt)
  chaves <- monitora_correcao_colunas_chave(dt)
  if (exists("monitora_publicacao_c_sincronizar_materiais_botanicos", mode = "function")) {
    try(monitora_publicacao_c_sincronizar_materiais_botanicos(dt, linhas, contexto = "recalculo_tipo_forma_vida_materiais_botanicos"), silent = TRUE)
  }
  tipo_col <- chaves$tipo_forma_vida
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (is.na(tipo_col) || !(tipo_col %in% names(dt)) || length(linhas) == 0L) return(invisible(dt))
  antes <- as.character(dt[[tipo_col]][linhas])
  depois <- monitora_correcao_calcular_tipo_forma_vida_esperado(dt, linhas, chaves)
  mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
  if (any(mudou, na.rm = TRUE)) {
    data.table::set(dt, i = linhas[mudou], j = tipo_col, value = depois[mudou])
  }
  invisible(dt)
}



monitora_correcao_recalcular_superiores_vinculados_legado_r22 <- function(dt, linhas, deps = NULL, dicionario = NULL, afetacoes = NULL) {
 ### Recalcula e harmoniza campos superiores vinculados por regras do XLSForm.
 ### Regra conservadora:
 ### 1. se um campo inferior dependente estiver preenchido, o token correspondente é garantido no campo superior;
 ### 2. o campo superior de classe geral (**Encostam** na vareta / tipo_forma_vida) é sempre recalculado
 ### a partir das colunas pai de nativa, exótica e seca/morta;
 ### 3. remoções de tokens em campos intermediários continuam sendo feitas por operações explícitas
 ### (por exemplo, movimento exótica -> nativa), evitando apagar informação válida de forma automática.
  dt <- data.table::as.data.table(dt)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (length(linhas) == 0L) return(data.table::data.table())
  audit <- data.table::data.table()
  deps <- if (is.null(deps)) data.table::data.table() else data.table::as.data.table(deps)
  if (nrow(deps) > 0L) {
    regras <- monitora_correcao_resolver_dependencias(dt, deps, dicionario, incluir_bloqueadas = TRUE)
    if (nrow(regras) > 0L) {
      bloqueadas <- regras[status_regra == "bloqueada_regra_xlsform_insegura"]
      if (nrow(bloqueadas)) {
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = "RECALC_SUPERIORES_XLSFORM",
          ordem_operacao = NA_character_,
          status = "bloqueada_regra_xlsform_insegura",
          mensagem = bloqueadas$mensagem_regra,
          atributo = bloqueadas$parent_col,
          linha_indice = NA_integer_,
          valor_antes = NA_character_,
          valor_depois = NA_character_,
          arquivo_correcao = "recalculo_automatico_pos_correcoes",
          parent_name = bloqueadas$parent_name,
          dependent_name = bloqueadas$dependent_name,
          token = bloqueadas$token
        )), fill = TRUE, use.names = TRUE)
      }
      deps_validas <- regras[status_regra == "ok"]
      if (nrow(deps_validas) > 0L) {
        deps_validas <- unique(deps_validas, by = c("parent_col", "token_norm", "dependent_col"))
 ### ajuste validação operacional (etapa_validacao): o hábito (dependent_col classificado
 ### como "atributo_dependente_habito" -- ex.: forma_vida_nativa_
 ### bromelioide) só é exibido no XLSForm quando a lista principal de
 ### forma de vida (parent_col, "lista_principal_forma_vida") JÁ contém
 ### o token da forma; a dependência é forma -> hábito, nunca o
 ### contrário. Preencher o hábito (terrestre/epifita/rupicola) não é
 ### evidência de que a forma deveria existir no campo superior, e
 ### sintetizar esse token ali causou as 625 falhas de persistência de
 ### RECALC_SUPERIORES_XLSFORM na validação operacional ao processar PENDHAB. Excluir
 ### explicitamente esse par do recálculo automático de superiores.
        papel_parent_dv <- monitora_correcao_papel_coluna_canonico(deps_validas$parent_col)
        papel_dep_dv <- monitora_correcao_papel_coluna_canonico(deps_validas$dependent_col)
        deps_validas <- deps_validas[!(papel_dep_dv == "atributo_dependente_habito" & papel_parent_dv == "lista_principal_forma_vida")]
      }
      if (nrow(deps_validas) > 0L) {
 ### ajuste validação operacional (etapa_validacao): "modulo"/"Módulo (amostragem)" é um
 ### controle de navegação do XLSForm (basico/avancado), não um campo
 ### superior derivável a partir de filhos preenchidos. Causa raiz
 ### confirmada na validação operacional: a regra XLSForm-embutida liga parent="modulo"/
 ### token="avancado" ao campo de ESPÉCIE "forma_vida_nativa_bromelioide_sp"
 ### (relevance composta "selected(${modulo},'avancado') and
 ### selected(${forma_vida_nativa},'bromelioide')", dividida em duas
 ### linhas de dependência, uma por parent). Quando essa coluna "_sp" não
 ### existe/está vazia em registros_corrig, o resolvedor de coluna
 ### genérico (heurística de substring, monitora_correcao_resolver_coluna )
 ### pode colapsar o nome para a coluna de HÁBITO "forma_vida_nativa_
 ### bromelioide" (que PENDHAB acabou de preencher) em vez da coluna de
 ### espécie -- e o recálculo então tenta sintetizar Módulo=avancado a
 ### partir disso, exatamente as 27 falhas da validação operacional. Como "modulo" nunca
 ### deveria ser sintetizado a partir de um filho neste recálculo
 ### automático (é controle de navegação, não campo de dado derivável),
 ### excluir qualquer regra cujo parent normalize para "modulo".
        parent_norm_dv <- monitora_correcao_normalizar_nome_coluna(deps_validas$parent_col)
        deps_validas <- deps_validas[!grepl("^modulo($|_)", parent_norm_dv)]
      }
      if (nrow(deps_validas) > 0L) {
        for (rr in seq_len(nrow(deps_validas))) {
          parent_col <- deps_validas$parent_col[rr]
          dep_col <- deps_validas$dependent_col[rr]
          token <- deps_validas$token[rr]
          if (is.na(parent_col) || is.na(dep_col)) next
          if (!(parent_col %in% names(dt)) || !(dep_col %in% names(dt))) next
          if (monitora_correcao_coluna_protegida(parent_col) || monitora_correcao_coluna_protegida(dep_col)) next
          idx_base <- linhas
          if (nrow(afetacoes) > 0L) {
            idx_base <- afetacoes[atributo == dep_col, linha_indice]
            idx_base <- unique(idx_base[!is.na(idx_base) & idx_base %in% linhas])
          }
          if (length(idx_base) == 0L) next
          idx <- idx_base[!monitora_correcao_vazio_vec(dt[[dep_col]][idx_base])]
          if (length(idx) == 0L) next
          antes <- as.character(dt[[parent_col]][idx])
          depois <- vapply(antes, monitora_correcao_append_token_valor, character(1), token = token)
          mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
          if (any(mudou)) {
            data.table::set(dt, i = idx[mudou], j = parent_col, value = depois[mudou])
            audit <- data.table::rbindlist(list(audit, data.table::data.table(
              id_correcao = "RECALC_SUPERIORES_XLSFORM",
              ordem_operacao = NA_character_,
              status = "aplicada",
              mensagem = paste0("Campo superior atualizado a partir de campo inferior vinculado pelo XLSForm: ", dep_col),
              atributo = parent_col,
              linha_indice = idx[mudou],
              valor_antes = antes[mudou],
              valor_depois = depois[mudou],
              arquivo_correcao = "recalculo_automatico_pos_correcoes"
            )), fill = TRUE, use.names = TRUE)
          }
        }
      }
    }
  }

 ### 2. Recalcular classe geral de forma de vida, inclusive removendo 'exotica'
 ### quando a coluna de formas exóticas ficou vazia após movimento/correção.
  chaves <- monitora_correcao_colunas_chave(dt)
  tipo_col <- chaves$tipo_forma_vida
  if (!is.na(tipo_col) && tipo_col %in% names(dt)) {
    antes_tipo <- as.character(dt[[tipo_col]][linhas])
    monitora_correcao_recalcular_tipo_forma_vida(dt, linhas)
    depois_tipo <- as.character(dt[[tipo_col]][linhas])
    mudou <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_tipo)
    if (any(mudou)) {
      audit <- data.table::rbindlist(list(audit, data.table::data.table(
        id_correcao = "RECALC_SUPERIORES_XLSFORM",
        ordem_operacao = NA_character_,
        status = "aplicada",
        mensagem = "Campo superior tipo_forma_vida recalculado a partir das categorias de forma de vida",
        atributo = tipo_col,
        linha_indice = linhas[mudou],
        valor_antes = antes_tipo[mudou],
        valor_depois = depois_tipo[mudou],
        arquivo_correcao = "recalculo_automatico_pos_correcoes"
      )), fill = TRUE, use.names = TRUE)
    }
  }
  audit[]
}

### fechamento hierárquico ascendente por contrato explícito ------------
###
### Regras XLSForm `relevant` são direcionais e não podem ser invertidas de
### forma genérica. O motor abaixo deriva somente ancestrais inequívocos:
### campo canônico de hábito ou espécie preenchido
### -> token da forma na lista principal da mesma categoria
### -> token da categoria em Encostam/tipo_forma_vida.
###
### O resolvedor exige papel, categoria e token canônicos. Colunas ambíguas,
### campos textuais superiores, controles de navegação e aliases sem categoria
### são apenas reportados e nunca recebem mutação. A operação é monotônica e
### idempotente: acrescenta tokens ausentes e preserva os existentes; remoções
### continuam sob operações explícitas de limpeza/movimento.
if (!exists(".MONITORA_FECHAMENTO_HIERARQUICO_CACHE", inherits = FALSE)) {
  .MONITORA_FECHAMENTO_HIERARQUICO_CACHE <- new.env(parent = emptyenv())
}

monitora_correcao_contrato_fechamento_hierarquico <- function(dt) {
  dt <- data.table::as.data.table(dt)
  chave_cache <- monitora_correcao_mapa_colunas_cache_key(dt, "fechamento_hierarquico_r24")
  if (exists(chave_cache, envir = .MONITORA_FECHAMENTO_HIERARQUICO_CACHE, inherits = FALSE)) {
    return(data.table::copy(get(chave_cache, envir = .MONITORA_FECHAMENTO_HIERARQUICO_CACHE, inherits = FALSE)))
  }
  mapa <- monitora_correcao_mapa_colunas_canonicas(
    dt, contexto = "fechamento_hierarquico_r24", gravar = FALSE,
    incluir_preenchidos = FALSE, usar_cache = TRUE
  )
  if (!nrow(mapa)) return(data.table::data.table())

 ### Algumas colunas operacionais preservam o label histórico em vez do path
 ### canônico (por exemplo, a árvore D30 nativa). Recuperar categoria/token
 ### somente por aliases contratuais EXATOS e unívocos; labels compartilhados
 ### entre categorias permanecem sem inferência.
  aliases_contrato <- tryCatch(monitora_validados_aliases(), error = function(e) list())
  idx_sem_hierarquia <- which(
    mapa$papel_coluna %in% c("atributo_dependente_habito", "especie_nome_popular") &
      (is.na(mapa$categoria) | !nzchar(mapa$categoria) | is.na(mapa$token_associado) | !nzchar(mapa$token_associado))
  )
  if (length(idx_sem_hierarquia) && length(aliases_contrato)) {
    for (ii in idx_sem_hierarquia) {
      col_alvo <- mapa$coluna_registros_corrig[ii]
      chaves_hit <- names(aliases_contrato)[vapply(aliases_contrato, function(vals) col_alvo %in% as.character(vals), logical(1L))]
      if (!length(chaves_hit)) next
      cats_hit <- unique(monitora_correcao_categoria_coluna_canonica(chaves_hit))
      toks_hit <- unique(monitora_correcao_token_associado_coluna(chaves_hit))
      cats_hit <- cats_hit[!is.na(cats_hit) & nzchar(cats_hit)]
      toks_hit <- toks_hit[!is.na(toks_hit) & nzchar(toks_hit)]
      if (length(cats_hit) == 1L && length(toks_hit) == 1L) {
        data.table::set(mapa, i = ii, j = "categoria", value = cats_hit)
        data.table::set(mapa, i = ii, j = "token_associado", value = toks_hit)
      }
    }
  }

  regras <- mapa[papel_coluna %in% c("atributo_dependente_habito", "especie_nome_popular")]
  if (!nrow(regras)) return(data.table::data.table())

  regras[, campo_superior := vapply(categoria, function(cat) {
    if (is.na(cat) || !nzchar(cat) || !(cat %in% c("nativa", "exotica", "seca_morta"))) return(NA_character_)
    tryCatch(monitora_correcao_coluna_forma_vida(dt, cat), error = function(e) NA_character_)
  }, character(1L))]
  regras[, papel_superior := monitora_correcao_papel_coluna_canonico(campo_superior)]
  regras[, status_regra := data.table::fifelse(
    is.na(categoria) | !nzchar(categoria) | !(categoria %in% c("nativa", "exotica", "seca_morta")) |
      is.na(token_associado) | !nzchar(token_associado),
    "nao_derivavel_relacao_ambigua",
    data.table::fifelse(
      is.na(campo_superior) | !nzchar(campo_superior) | !(campo_superior %in% names(dt)),
      "bloqueada_superior_nao_resolvido",
      data.table::fifelse(
        papel_superior != "lista_principal_forma_vida" | campo_superior == coluna_registros_corrig,
        "bloqueada_papeis_incompativeis",
        "ok"
      )
    )
  )]
  regras_finais <- unique(regras[, .(
    campo_inferior = coluna_registros_corrig,
    papel_inferior = papel_coluna,
    categoria,
    token = token_associado,
    campo_superior,
    papel_superior,
    status_regra
  )], by = c("campo_inferior", "categoria", "token", "campo_superior"))
  assign(chave_cache, regras_finais, envir = .MONITORA_FECHAMENTO_HIERARQUICO_CACHE)
  data.table::copy(regras_finais)
}

monitora_correcao_recalcular_superiores_vinculados <- function(dt, linhas, deps = NULL, dicionario = NULL, afetacoes = NULL,
                                                               modo_encostam = c("recalcular", "acrescentar")) {
  dt <- monitora_dt_referenciar(dt)
  modo_encostam <- match.arg(modo_encostam)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas)) return(data.table::data.table())

  audit <- data.table::data.table()
  regras <- monitora_correcao_contrato_fechamento_hierarquico(dt)
  bloqueadas <- regras[status_regra != "ok"]
  if (nrow(bloqueadas)) {
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento(
        "fechamento_hierarquico_contrato", "INFO", NA_character_,
        paste0(nrow(bloqueadas), " relação(ões) inferiores sem derivação automática inequívoca; nenhuma mutação aplicada nessas relações"),
        "relações constarão no relatório dedicado do fechamento hierárquico"
      )
    }
  }

  regras <- regras[status_regra == "ok"]
  if (nrow(regras)) {
    habitos_validos <- monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokens_habito_catalogo())
    for (rr in seq_len(nrow(regras))) {
      inferior <- regras$campo_inferior[rr]
      superior <- regras$campo_superior[rr]
      papel <- regras$papel_inferior[rr]
      token <- regras$token[rr]
      if (!(inferior %in% names(dt)) || !(superior %in% names(dt))) next

      valores_inf <- as.character(dt[[inferior]][linhas])
      preenchido <- !monitora_correcao_vazio_vec(valores_inf)
      if (identical(papel, "atributo_dependente_habito")) {
        preenchido <- preenchido & monitora_correcao_normalizar_nome_coluna(valores_inf) %in% habitos_validos
      }
      idx <- linhas[preenchido %in% TRUE]
      if (!length(idx)) next

      antes <- as.character(dt[[superior]][idx])
      depois <- monitora_correcao_append_token_vetor_memo(antes, token)
      mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
      if (!any(mudou, na.rm = TRUE)) next
      idx_mudou <- idx[mudou]
      data.table::set(dt, i = idx_mudou, j = superior, value = depois[mudou])
      audit <- data.table::rbindlist(list(audit, data.table::data.table(
        id_correcao = "FECHAMENTO_HIERARQUICO_CONTRATO",
        ordem_operacao = NA_character_,
        status = "aplicada",
        mensagem = paste0(
          "Token superior inequívoco acrescentado por fechamento hierárquico: ",
          inferior, " -> ", superior, " [", token, "]"
        ),
        atributo = superior,
        linha_indice = idx_mudou,
        valor_antes = antes[mudou],
        valor_depois = depois[mudou],
        arquivo_correcao = "fechamento_hierarquico_contrato_r24",
        dependent_name = inferior,
        parent_name = superior,
        token = token
      )), fill = TRUE, use.names = TRUE)
    }
  }

 ### O segundo nível é uma derivação própria e tipada já existente: listas
 ### principais finais -> Encostam. Ele roda depois do fechamento inferior e
 ### pode tanto acrescentar quanto retirar categorias órfãs do campo superior.
  chaves <- monitora_correcao_colunas_chave(dt)
  tipo_col <- chaves$tipo_forma_vida
  if (!is.na(tipo_col) && tipo_col %in% names(dt)) {
    antes_tipo <- as.character(dt[[tipo_col]][linhas])
    if (identical(modo_encostam, "acrescentar")) {
      depois_append <- antes_tipo
      for (cat in c("nativa", "exotica", "seca_morta")) {
        col_lista <- tryCatch(monitora_correcao_coluna_forma_vida(dt, cat), error = function(e) NA_character_)
        if (is.na(col_lista) || !(col_lista %in% names(dt))) next
        tem_lista <- !monitora_correcao_vazio_vec(dt[[col_lista]][linhas])
        idx_local <- which(tem_lista %in% TRUE)
        if (length(idx_local)) {
          depois_append[idx_local] <- monitora_correcao_append_token_vetor_memo(depois_append[idx_local], cat)
        }
      }
      mudou_append <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_append)
      if (any(mudou_append, na.rm = TRUE)) data.table::set(dt, i = linhas[mudou_append], j = tipo_col, value = depois_append[mudou_append])
    } else {
      monitora_correcao_recalcular_tipo_forma_vida(dt, linhas)
    }
    depois_tipo <- as.character(dt[[tipo_col]][linhas])
    mudou_tipo <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_tipo)
    if (any(mudou_tipo, na.rm = TRUE)) {
      audit <- data.table::rbindlist(list(audit, data.table::data.table(
        id_correcao = "FECHAMENTO_HIERARQUICO_CONTRATO",
        ordem_operacao = NA_character_, status = "aplicada",
        mensagem = if (identical(modo_encostam, "acrescentar")) "Tokens superiores ausentes acrescentados em Encostam a partir das listas principais, sem remover tokens existentes" else "Encostam/tipo_forma_vida recalculado a partir das listas principais finais",
        atributo = tipo_col, linha_indice = linhas[mudou_tipo],
        valor_antes = antes_tipo[mudou_tipo], valor_depois = depois_tipo[mudou_tipo],
        arquivo_correcao = "fechamento_hierarquico_contrato_r24"
      )), fill = TRUE, use.names = TRUE)
    }
  }
  audit[]
}

### Wrapper de segurança em torno de
### monitora_correcao_recalcular_superiores_vinculados. A função evita que
### recálculos extensos bloqueiem o caminho interativo do painel:
### 1. limita explicitamente o escopo às linhas afetadas (nunca recomputa
### o dataset inteiro -- já era o contrato de `linhas`, aqui só reforçado
### por log/auditoria, sem mudar a assinatura da função original);
### 2. registra n_linhas e tempo decorrido (log objetivo para diagnosticar
### lentidão real vs. travamento);
### 3. aplica um limite de tempo (setTimeLimit, base R, sem depender de
### pacote novo); se estourar, a chamada é abortada com erro capturável
### em vez de travar indefinidamente;
### 4. em caso de timeout/erro, cai para o recálculo mínimo e sabidamente
### seguro de tipo_forma_vida (monitora_correcao_recalcular_tipo_forma_vida,
### já vetorizado e usado isoladamente em ~15 pontos do script) para que
### o Encostam ainda fique coerente, mesmo sem o enriquecimento de campos
### superiores vinculados ao XLSForm nesta chamada específica.
monitora_correcao_recalcular_superiores_vinculados_seguro <- function(dt, linhas, deps = NULL, dicionario = NULL, afetacoes = NULL,
                                                                       timeout_seg = 20, modo_encostam = c("recalcular", "acrescentar"),
                                                                       registrar_log = TRUE) {
  modo_encostam <- match.arg(modo_encostam)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  n_linhas <- length(linhas)
  if (n_linhas == 0L) return(data.table::data.table())
  t0 <- Sys.time()
  on.exit(try(setTimeLimit(cpu = Inf, elapsed = Inf, transient = FALSE), silent = TRUE), add = TRUE)
  resultado <- tryCatch({
    setTimeLimit(elapsed = timeout_seg, transient = TRUE)
    monitora_correcao_recalcular_superiores_vinculados(dt, linhas, deps, dicionario, afetacoes, modo_encostam = modo_encostam)
  }, error = function(e) {
    list(erro = TRUE, mensagem = conditionMessage(e))
  })
  dt_seg <- as.numeric(difftime(Sys.time(), t0, units = "secs"))
  if (isTRUE(registrar_log) && exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento(
      "recalculo_superiores_vinculados_seguro", "INFO", NA_character_,
      paste0("n_linhas=", n_linhas, "; tempo=", round(dt_seg, 2), "s; timeout_configurado=", timeout_seg, "s"),
      "wrapper de seguranca com timeout, etapa_validacao v2.6.3"
    )
  }
  if (is.list(resultado) && isTRUE(resultado$erro)) {
    if (isTRUE(registrar_log) && exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento(
        "recalculo_superiores_vinculados_seguro", "AVISO", NA_character_,
        paste0("Recalculo de campos superiores vinculados abortado (", resultado$mensagem, "); aplicando somente recalculo minimo de tipo_forma_vida em ", n_linhas, " linha(s)."),
        "fallback seguro para nao travar o painel"
      )
    }
    chaves_fb <- monitora_correcao_colunas_chave(dt)
    tipo_col_fb <- chaves_fb$tipo_forma_vida
    audit_fb <- data.table::data.table()
    if (!is.na(tipo_col_fb) && tipo_col_fb %in% names(dt)) {
      antes_fb <- as.character(dt[[tipo_col_fb]][linhas])
      monitora_correcao_recalcular_tipo_forma_vida(dt, linhas)
      depois_fb <- as.character(dt[[tipo_col_fb]][linhas])
      mudou_fb <- monitora_correcao_na_para_vazio(antes_fb) != monitora_correcao_na_para_vazio(depois_fb)
      if (any(mudou_fb)) {
        audit_fb <- data.table::data.table(
          id_correcao = "RECALC_SUPERIORES_FALLBACK_SEGURO",
          ordem_operacao = NA_character_,
          status = "aplicada_fallback_timeout",
          mensagem = "Campo superior tipo_forma_vida recalculado no modo fallback seguro (timeout/erro no recalculo completo de vinculados)",
          atributo = tipo_col_fb,
          linha_indice = linhas[mudou_fb],
          valor_antes = antes_fb[mudou_fb],
          valor_depois = depois_fb[mudou_fb],
          arquivo_correcao = "recalculo_automatico_pos_correcoes"
        )
      }
    }
    return(audit_fb)
  }
  resultado
}


monitora_correcao_reforcar_movimentos_forma_vida <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), dicionario = NULL) {
 ### Backstop semântico para movimentos entre categorias de forma de vida.
 ### A auditoria mostrou que, em alguns fluxos do painel, a operação remove_token
 ### podia não esvaziar a categoria de origem antes do recálculo do campo superior.
 ### Aqui a transação de movimento é interpretada semanticamente: token_pai deve sair
 ### da categoria_origem e entrar em categoria_destino nas linhas-alvo. Só depois o
 ### tipo_forma_vida é recalculado.
  dt <- data.table::as.data.table(dt)
  corr <- data.table::as.data.table(corr)
  if (nrow(corr) == 0L) {
    return(list(audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character())))
  }
  cols_need <- c("tipo_correcao", "id_correcao", "escopo_aplicacao", "coleta", "coleta_uuid", "uuid_registro", "ponto_amostral", "token_pai", "categoria_origem", "categoria_destino")
  for (cc in setdiff(cols_need, names(corr))) corr[, (cc) := NA_character_]
  mov <- corr[tolower(trimws(as.character(tipo_correcao))) %in% c("movimento_forma_vida_condicional", "movimento_forma_vida")]
  mov <- mov[!monitora_correcao_vazio(token_pai) & !monitora_correcao_vazio(categoria_origem) & !monitora_correcao_vazio(categoria_destino)]
  if (nrow(mov) == 0L) {
    return(list(audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character())))
  }
  mov <- unique(mov[, .(
    id_correcao,
    escopo_aplicacao,
    coleta,
    coleta_uuid,
    uuid_registro,
    ponto_amostral,
    token_pai,
    categoria_origem = tolower(trimws(as.character(categoria_origem))),
    categoria_destino = tolower(trimws(as.character(categoria_destino)))
  )])
  audit <- data.table::data.table()
  linhas_afetadas <- integer(0)
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())

  for (rr in seq_len(nrow(mov))) {
    linha_mov <- mov[rr]
    linhas <- monitora_correcao_localizar_linhas(dt, linha_mov, chaves)
    linhas <- unique(as.integer(linhas))
    linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
    if (length(linhas) == 0L) next
    token <- as.character(linha_mov$token_pai[1])
    col_origem <- monitora_correcao_coluna_forma_vida(dt, linha_mov$categoria_origem[1])
    col_destino <- monitora_correcao_coluna_forma_vida(dt, linha_mov$categoria_destino[1])

    if (!is.na(col_origem) && col_origem %in% names(dt)) {
      antes <- as.character(dt[[col_origem]][linhas])
      depois <- vapply(antes, monitora_correcao_remove_token_valor, character(1), token = token)
      mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
      if (any(mudou)) {
        data.table::set(dt, i = linhas[mudou], j = col_origem, value = depois[mudou])
        linhas_afetadas <- unique(c(linhas_afetadas, linhas[mudou]))
        afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou], atributo = col_origem)), fill = TRUE, use.names = TRUE)
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = linha_mov$id_correcao[1],
          ordem_operacao = NA_character_,
          status = "aplicada",
          mensagem = paste0("Backstop semântico do movimento: token removido da categoria de origem ", linha_mov$categoria_origem[1]),
          atributo = col_origem,
          linha_indice = linhas[mudou],
          valor_antes = antes[mudou],
          valor_depois = depois[mudou],
          arquivo_correcao = "reforco_semantico_movimento_forma_vida"
        )), fill = TRUE, use.names = TRUE)
      }
    }

    if (!is.na(col_destino) && col_destino %in% names(dt)) {
      antes <- as.character(dt[[col_destino]][linhas])
      depois <- vapply(antes, monitora_correcao_append_token_valor, character(1), token = token)
      mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
      if (any(mudou)) {
        data.table::set(dt, i = linhas[mudou], j = col_destino, value = depois[mudou])
        linhas_afetadas <- unique(c(linhas_afetadas, linhas[mudou]))
        afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou], atributo = col_destino)), fill = TRUE, use.names = TRUE)
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = linha_mov$id_correcao[1],
          ordem_operacao = NA_character_,
          status = "aplicada",
          mensagem = paste0("Backstop semântico do movimento: token garantido na categoria de destino ", linha_mov$categoria_destino[1]),
          atributo = col_destino,
          linha_indice = linhas[mudou],
          valor_antes = antes[mudou],
          valor_depois = depois[mudou],
          arquivo_correcao = "reforco_semantico_movimento_forma_vida"
        )), fill = TRUE, use.names = TRUE)
      }
    }
  }
  list(audit = audit[], linhas = linhas_afetadas, afetacoes = afetacoes[])
}


### Limpeza atômica de outras formas de vida
### -------------------------------------------------------------------------
### Rotina transacional vetorizada para sanitizar resíduos históricos de
### outra(s) forma(s) de vida. Contrato atual:
### - tokens históricos de "outra" são removidos das listas antigas;
### - descritores livres inequívocos são convertidos para tokens atuais do
### XLSForm 21FEV25 em forma_vida_outros;
### - descritores ambíguos, como briófita/briofita sem especificação, não são
### convertidos automaticamente; são limpos como resíduo legado sem gerar token atual;
### - campos históricos de descritor/foto correlatos são limpos sempre que a
### sanitização de outra forma de vida é aplicada;
### - após toda a remoção/conversão, **Encostam** é reconstruído a partir das
### listas inferiores finais; somente se nenhum contato válido restar recebe
### solo_nu, que é exclusivo e nunca pode coexistir com outra categoria.
monitora_correcao_tokens_outras_formas_vida <- function() {
  c("outra_forma_vida", "outras_formas_vida", "forma_vida_outros", "outra", "outro", "outras", "outros")
}

monitora_correcao_tokens_residuo_historico_outras_formas <- function() {
 ### Tokens que indicam resíduo histórico de "outra forma de vida" nas listas
 ### antigas. Não inclui forma_vida_outros: esse é o campo atual válido do
 ### XLSForm 21FEV25; valores como musgos/hepaticas/liquens/fungos nele são
 ### resultado esperado da sanitização e não devem manter a pendência ativa.
  c("outra_forma_vida", "outras_formas_vida", "outra", "outro", "outras", "outros")
}

monitora_correcao_tokens_tipo_validos_pos_limpeza_outras <- function() {
 ### Após remover "outra" das sublistas antigas, nativa/exotica/seca_morta só
 ### contam como categorias efetivas se os campos inferiores correspondentes
 ### permanecerem preenchidos. Aqui entram apenas categorias não inferíveis a
 ### partir dessas sublistas e que podem ser preservadas no campo superior.
  c("solo_nu", "serrapilheira", "fragmentos_botanicos", "material_inundado", "material_botanico")
}

monitora_correcao_contem_qualquer_token_vec <- function(x, tokens) {
  x <- as.character(x)
  if (!length(x)) return(logical(0))
  tokens <- unique(monitora_correcao_normalizar_nome_coluna(tokens))
  tokens <- tokens[!is.na(tokens) & nzchar(tokens)]
  if (!length(tokens)) return(rep(FALSE, length(x)))
  out <- rep(FALSE, length(x))
  for (tok in tokens) out <- out | monitora_correcao_token_presente_vec(x, tok)
  out
}

monitora_correcao_colapsar_lista_serializada <- function(x) {
  x <- unique(trimws(as.character(x)))
  x <- x[!is.na(x) & nzchar(x)]
  if (!length(x)) return(NA_character_)
  paste(x, collapse = "|")
}

monitora_correcao_parse_lista_serializada <- function(x) {
  x <- as.character(x)
  if (!length(x) || is.na(x[1L]) || !nzchar(trimws(x[1L]))) return(character(0))
  z <- unlist(strsplit(x[1L], "[|,;]+", perl = TRUE), use.names = FALSE)
  z <- trimws(z)
  unique(z[!is.na(z) & nzchar(z)])
}

monitora_correcao_normalizar_descritor_outra_forma <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  x <- tolower(x)
  x <- iconv(x, from = "", to = "ASCII//TRANSLIT")
  x[is.na(x)] <- ""
  x <- gsub("[^a-z0-9]+", " ", x, perl = TRUE)
  x <- gsub("\\s+", " ", x, perl = TRUE)
  trimws(x)
}

monitora_correcao_adicionar_tokens_valor <- function(valor, tokens) {
  tokens <- monitora_correcao_tokenizar(tokens)
  out <- valor
  if (!length(tokens)) return(out)
  for (tt in tokens) out <- monitora_correcao_append_token_valor(out, tt)
  out
}

monitora_correcao_classificar_descritor_outra_forma <- function(x) {
  x_chr <- as.character(x)
  vazio <- monitora_correcao_vazio_vec(x_chr)
  z <- monitora_correcao_normalizar_descritor_outra_forma(x_chr)
  token <- rep("", length(z))
  status <- rep("limpeza_descritor_legado_sem_conversao", length(z))
  status[vazio] <- "vazio"

  add_token <- function(cond, tok) {
    cond[is.na(cond)] <- FALSE
    if (!any(cond)) return(invisible(NULL))
    token[cond] <<- vapply(token[cond], monitora_correcao_adicionar_tokens_valor, character(1), tokens = tok)
    invisible(NULL)
  }

 ### Conversões inequívocas para tokens atuais do XLSForm 21FEV25.
 ### "m" é aceito apenas porque a regra se aplica exclusivamente a descritores
 ### históricos de outra forma de vida, onde o uso observado representa musgo.
  musgo <- z %in% c("m", "musgo", "musgos", "musg9", "mugo", "mugos") |
    grepl("(^| )musg[a-z0-9]*($| )", z, perl = TRUE) |
    grepl("(^| )mugo[s]?($| )", z, perl = TRUE) |
    grepl("(^| )lodo($| )", z, perl = TRUE)
  add_token(musgo, "musgos")

  hepatica <- grepl("(^| )hepatic[a-z]*($| )", z, perl = TRUE)
  add_token(hepatica, "hepaticas")

  antocero <- grepl("(^| )antocer[a-z]*($| )", z, perl = TRUE)
  add_token(antocero, "antoceros")

  liquen <- grepl("(^| )liquen[s]?($| )", z, perl = TRUE)
  add_token(liquen, "liquens")

  fungo <- grepl("(^| )(fungo[s]?|cogumelo[s]?)($| )", z, perl = TRUE)
  add_token(fungo, "fungos")

  convertido <- !vazio & nzchar(token)
  status[convertido] <- "convertido_para_token_atual_xlsform21"

  briofita <- !convertido & !vazio & (
    grepl("(^| )briofit[a-z]*($| )", z, perl = TRUE) |
      grepl("(^| )bryophyt[a-z]*($| )", z, perl = TRUE)
  )
  status[briofita] <- "limpeza_sem_conversao_briofita_termo_amplo"

  data.table::data.table(
    valor_original = x_chr,
    valor_normalizado = z,
    token_xlsform21 = data.table::fifelse(nzchar(token), token, NA_character_),
    status_sanitizacao = status
  )
}

monitora_correcao_colunas_limpeza_outras_formas <- function(dt, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  nms <- names(dt)
  nms_norm <- monitora_correcao_normalizar_nome_coluna(nms)
  mapa <- monitora_correcao_mapa_colunas_canonicas(dt, contexto = "limpeza_outras_formas", gravar = FALSE)

  listas <- mapa[papel_coluna == "lista_principal_forma_vida" & categoria %in% c("nativa", "exotica", "seca_morta"), coluna_registros_corrig]
  listas <- unique(listas[!is.na(listas) & nzchar(listas) & listas %in% nms])

  resolver_dt <- function(vals) {
    vals <- unique(as.character(vals))
    vals <- vals[!is.na(vals) & nzchar(vals)]
    out <- character(0)
    for (vv in vals) {
      hit <- nms[nms == vv]
      if (length(hit)) out <- c(out, hit[1L])
      vv_norm <- monitora_correcao_normalizar_nome_coluna(vv)
      hit2 <- which(nms_norm == vv_norm)
      if (length(hit2)) out <- c(out, nms[hit2[1L]])
      col_res <- tryCatch(monitora_correcao_resolver_coluna(dt, vv, dicionario, permitir_heuristica = FALSE), error = function(e) NA_character_)
      if (!is.na(col_res) && nzchar(col_res) && col_res %in% nms) out <- c(out, col_res)
    }
    unique(out[out %in% nms])
  }

  descritores <- character(0)
  fotos <- character(0)
  forma_outros <- resolver_dt(c(
    "amostragem/registro/forma_vida_outros",
    "forma_vida_outros",
    "Outras plantas terrestres, líquens e/ou fungos​: (amostragem/registro)",
    "Outras plantas terrestres, líquens e/ou fungos: (amostragem/registro)"
  ))

  if (!is.null(dicionario) && nrow(data.table::as.data.table(dicionario)) > 0L) {
    d <- data.table::as.data.table(dicionario)
    for (cc in c("name", "caminho_registro", "label", "type", "list_name", "relevant")) if (!(cc %in% names(d))) d[, (cc) := NA_character_]
    d[, texto_busca := paste(name, caminho_registro, label, type, list_name, relevant, sep = " ")]
    d[, texto_norm := monitora_correcao_normalizar_nome_coluna(texto_busca)]
    d[, eh_outra_forma_historica := (
      grepl("forma_vida_(nativa|exotica|seca_morta)_outra", texto_norm) |
        (grepl("outr.*forma.*vida", texto_norm) & grepl("nativ|exotic|exotica|exotico|seca|morta", texto_norm))
    )]
    d[, eh_foto_outra_forma := eh_outra_forma_historica & grepl("foto|imagem|image|upload|arquivo|anexo|midia|media", texto_norm)]
    d[, eh_descritor_outra_forma := eh_outra_forma_historica &
        !grepl("especie|especies|outra_sp|_sp($|_)|foto|imagem|image|upload|arquivo|anexo|midia|media|plantas_terrestres|liquen|liquens|fungo|fungos", texto_norm)]
    if (any(d$eh_descritor_outra_forma, na.rm = TRUE)) {
      cand_vals <- unique(unlist(d[eh_descritor_outra_forma == TRUE, .(name, caminho_registro, label)], use.names = FALSE))
      descritores <- c(descritores, resolver_dt(cand_vals))
    }
    if (any(d$eh_foto_outra_forma, na.rm = TRUE)) {
      cand_vals <- unique(unlist(d[eh_foto_outra_forma == TRUE, .(name, caminho_registro, label)], use.names = FALSE))
      fotos <- c(fotos, resolver_dt(cand_vals))
    }
  }

  fallback_desc <- nms[(
    (grepl("outr.*forma.*vida", nms_norm) | grepl("forma_vida.*outr", nms_norm)) &
      grepl("nativ|exotic|exotica|exotico|seca|morta", nms_norm) &
      !grepl("especie|especies|outra_sp|_sp($|_)|foto|imagem|image|upload|arquivo|anexo|midia|media|plantas_terrestres|liquen|liquens|fungo|fungos", nms_norm)
  )]
  fallback_foto <- nms[(
    (grepl("outr.*forma.*vida", nms_norm) | grepl("forma_vida.*outr", nms_norm)) &
      grepl("nativ|exotic|exotica|exotico|seca|morta", nms_norm) &
      grepl("foto|imagem|image|upload|arquivo|anexo|midia|media", nms_norm) &
      !grepl("especie|especies|outra_sp|_sp($|_)", nms_norm)
  )]
  descritores <- unique(c(descritores, fallback_desc))
  descritores <- descritores[descritores %in% nms]
  fotos <- unique(c(fotos, fallback_foto))
  fotos <- fotos[fotos %in% nms]
  forma_outros <- unique(forma_outros[forma_outros %in% nms])

  tipo_cols <- mapa[papel_coluna == "campo_superior_tipo_forma_vida", coluna_registros_corrig]
  tipo_cols <- unique(tipo_cols[!is.na(tipo_cols) & nzchar(tipo_cols) & tipo_cols %in% nms])
  chaves <- monitora_correcao_colunas_chave(dt)
  tipo_update <- if (!is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% nms) chaves$tipo_forma_vida else if (length(tipo_cols)) tipo_cols[1L] else NA_character_

  data.table::rbindlist(list(
    data.table::data.table(classe = "lista_principal_forma_vida", coluna = listas, categoria = mapa[match(listas, coluna_registros_corrig), categoria], usar_para_escrita_solo_nu = FALSE),
    data.table::data.table(classe = "descritor_outra_forma_vida", coluna = descritores, categoria = NA_character_, usar_para_escrita_solo_nu = FALSE),
    data.table::data.table(classe = "foto_outra_forma_vida", coluna = fotos, categoria = NA_character_, usar_para_escrita_solo_nu = FALSE),
    data.table::data.table(classe = "campo_atual_forma_vida_outros", coluna = forma_outros, categoria = NA_character_, usar_para_escrita_solo_nu = FALSE),
    data.table::data.table(classe = "campo_superior_tipo_forma_vida", coluna = tipo_cols, categoria = NA_character_, usar_para_escrita_solo_nu = tipo_cols == tipo_update)
  ), fill = TRUE, use.names = TRUE)[!is.na(coluna) & nzchar(coluna)]
}

monitora_correcao_contar_residuos_outras_formas <- function(dt, linhas, cols_info) {
  dt <- data.table::as.data.table(dt)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  tokens_outra <- monitora_correcao_tokens_residuo_historico_outras_formas()
  listas <- cols_info[classe == "lista_principal_forma_vida" & coluna %in% names(dt), coluna]
  descritores <- cols_info[classe == "descritor_outra_forma_vida" & coluna %in% names(dt), coluna]
  fotos <- cols_info[classe == "foto_outra_forma_vida" & coluna %in% names(dt), coluna]
  if (!length(linhas)) {
    return(data.table::data.table(linhas_alvo = 0L, linhas_com_token_outra = 0L, celulas_com_token_outra = 0L, linhas_com_descritor = 0L, celulas_com_descritor = 0L, linhas_com_foto_historica = 0L, celulas_com_foto_historica = 0L, linhas_com_residuo_total = 0L))
  }
  flag_token <- rep(FALSE, length(linhas)); n_token <- 0L
  for (cc in listas) {
    hit <- monitora_correcao_contem_qualquer_token_vec(dt[[cc]][linhas], tokens_outra)
    flag_token <- flag_token | hit
    n_token <- n_token + sum(hit, na.rm = TRUE)
  }
  flag_desc <- rep(FALSE, length(linhas)); n_desc <- 0L
  for (cc in descritores) {
    hit <- !monitora_correcao_vazio_vec(dt[[cc]][linhas])
    flag_desc <- flag_desc | hit
    n_desc <- n_desc + sum(hit, na.rm = TRUE)
  }
  flag_foto <- rep(FALSE, length(linhas)); n_foto <- 0L
  for (cc in fotos) {
    hit <- !monitora_correcao_vazio_vec(dt[[cc]][linhas])
    flag_foto <- flag_foto | hit
    n_foto <- n_foto + sum(hit, na.rm = TRUE)
  }
  data.table::data.table(
    linhas_alvo = length(linhas),
    linhas_com_token_outra = sum(flag_token, na.rm = TRUE),
    celulas_com_token_outra = n_token,
    linhas_com_descritor = sum(flag_desc, na.rm = TRUE),
    celulas_com_descritor = n_desc,
    linhas_com_foto_historica = sum(flag_foto, na.rm = TRUE),
    celulas_com_foto_historica = n_foto,
    linhas_com_residuo_total = sum(flag_token | flag_desc | flag_foto, na.rm = TRUE)
  )
}

monitora_correcao_localizar_linhas_limpeza_outras_formas <- function(dt, linha_corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL) {
  dt <- data.table::as.data.table(dt)
  linha_corr <- data.table::as.data.table(linha_corr)
  esc <- if ("escopo_aplicacao" %in% names(linha_corr)) tolower(trimws(as.character(linha_corr$escopo_aplicacao[1L]))) else ""
  if (is.na(esc)) esc <- ""

 ### TRIOUT é operação por ocorrência diagnóstica estável.
 ### Prioridade de resolução:
 ### 1) UUID(s) do registro;
 ### 2) chave composta de contexto (COLETA + ponto_amostral/ponto_metro, quando gravados);
 ### 3) COLETA como fallback legado;
 ### 4) linha_indice/linhas_alvo_serializadas apenas como último recurso validável.
 ### A posição da linha não pode ser a identidade primária, pois exclusões de
 ### COLETA deslocam o data.table antes de TRIOUT ser simulado/aplicado.
  parse_any <- function(cols) {
    vals <- character(0)
    for (cc in intersect(cols, names(linha_corr))) {
      vals <- c(vals, unlist(lapply(as.character(linha_corr[[cc]]), monitora_correcao_parse_serial_generico), use.names = FALSE))
    }
    vals <- unique(trimws(as.character(vals)))
    vals[!is.na(vals) & nzchar(vals)]
  }

  idx_uuid <- integer(0)
  if (!is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) {
    uu <- parse_any(c("uuid_registro", "uuid_registro_serializado", "uuids_registro"))
    if (length(uu)) idx_uuid <- which(trimws(as.character(dt[[chaves$uuid_registro]])) %chin% uu)
  }
  idx_uuid <- unique(as.integer(idx_uuid))
  idx_uuid <- idx_uuid[!is.na(idx_uuid) & idx_uuid >= 1L & idx_uuid <= nrow(dt)]
  if (length(idx_uuid)) return(idx_uuid)

  idx_ctx <- seq_len(nrow(dt))
  tem_ctx <- FALSE
  coletas <- parse_any(c("coleta", "COLETA", "coletas"))
  if (length(coletas) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    idx_ctx <- idx_ctx[as.character(dt[[chaves$coleta]][idx_ctx]) %chin% coletas]
    tem_ctx <- TRUE
  }
  uas <- parse_any(c("UA", "ua"))
  if (length(uas) && !is.na(chaves$ua) && chaves$ua %in% names(dt)) {
    idx_ctx <- idx_ctx[as.character(dt[[chaves$ua]][idx_ctx]) %chin% uas]
    tem_ctx <- TRUE
  }
  ciclos <- parse_any(c("CICLO", "ciclo"))
  if (length(ciclos) && !is.na(chaves$ciclo) && chaves$ciclo %in% names(dt)) {
    idx_ctx <- idx_ctx[as.character(dt[[chaves$ciclo]][idx_ctx]) %chin% ciclos]
    tem_ctx <- TRUE
  }
  campanhas <- parse_any(c("CAMPANHA", "campanha"))
  if (length(campanhas) && !is.na(chaves$campanha) && chaves$campanha %in% names(dt)) {
    idx_ctx <- idx_ctx[as.character(dt[[chaves$campanha]][idx_ctx]) %chin% campanhas]
    tem_ctx <- TRUE
  }
  anos <- parse_any(c("ANO", "ano"))
  if (length(anos) && !is.na(chaves$ano) && chaves$ano %in% names(dt)) {
    idx_ctx <- idx_ctx[as.character(dt[[chaves$ano]][idx_ctx]) %chin% anos]
    tem_ctx <- TRUE
  }
  pontos <- parse_any(c("ponto_amostral", "Ponto amostral", "ponto_amostral_serializado"))
  if (length(pontos) && !is.na(chaves$ponto_amostral) && chaves$ponto_amostral %in% names(dt)) {
    idx_ctx <- idx_ctx[as.character(dt[[chaves$ponto_amostral]][idx_ctx]) %chin% pontos]
    tem_ctx <- TRUE
  }
  metros <- parse_any(c("ponto_metro", "Ponto metro", "ponto_metro_serializado"))
  if (length(metros) && !is.na(chaves$ponto_metro) && chaves$ponto_metro %in% names(dt)) {
    idx_ctx <- idx_ctx[as.character(dt[[chaves$ponto_metro]][idx_ctx]) %chin% metros]
    tem_ctx <- TRUE
  }
  idx_ctx <- unique(as.integer(idx_ctx))
  idx_ctx <- idx_ctx[!is.na(idx_ctx) & idx_ctx >= 1L & idx_ctx <= nrow(dt)]
  if (isTRUE(tem_ctx) && length(idx_ctx)) return(idx_ctx)

  if (esc %in% c("lote_coletas", "coletas_filtradas", "multicoletas_atomico", "coleta_inteira")) {
    if (is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) return(integer(0))
    coletas <- parse_any(c("coleta", "COLETA", "coletas"))
    if (!length(coletas)) return(integer(0))
    idx <- which(as.character(dt[[chaves$coleta]]) %chin% coletas)
    pontos <- parse_any(c("ponto_amostral", "Ponto amostral"))
    if (length(pontos) && !is.na(chaves$ponto_amostral) && chaves$ponto_amostral %in% names(dt)) {
      idx <- idx[as.character(dt[[chaves$ponto_amostral]][idx]) %chin% pontos]
    }
    return(unique(as.integer(idx)))
  }

  parse_linhas_exp <- function() {
    vals <- character(0)
    for (cc in intersect(c("linhas_alvo_serializadas", "valor_original_esperado", "linha_indice"), names(linha_corr))) {
      vals <- c(vals, monitora_correcao_parse_serial_generico(linha_corr[[cc]][1L]))
    }
    idx <- suppressWarnings(as.integer(vals))
    unique(idx[!is.na(idx) & idx >= 1L & idx <= nrow(dt)])
  }
  idx_exp <- parse_linhas_exp()
  if (length(idx_exp)) return(idx_exp)

  unique(as.integer(monitora_correcao_localizar_linhas(dt, linha_corr, chaves, indice)))
}

monitora_correcao_aplicar_limpeza_outras_formas_atomica <- function(dt, linhas, id_correcao = NA_character_, arquivo_correcao = NA_character_, dicionario = NULL) {
 ### CRÍTICO: não usar as.data.table aqui.
 ### Em alguns fluxos, as.data.table pode operar sobre uma cópia/local; a auditoria
 ### fica correta, mas a alteração não persiste no objeto exportado. setDT /referência
 ### preserva a alteração no mesmo data.table usado pelo fluxo principal.
  dt <- monitora_dt_referenciar(dt)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  audit <- data.table::data.table()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  if (!length(linhas)) {
 ### limpeza de outras formas deve ser idempotente.
 ### Escopo vazio pode ocorrer quando as COLETAS-alvo foram quarentenadas,
 ### excluídas na mesma sessão ou quando o lote filtrado não contém resíduo
 ### remanescente. Isso é sucesso auditável; pendências reais serão capturadas
 ### pela auditoria impeditiva pós-aplicação, sem abortar a aplicação aqui.
    return(list(audit = data.table::data.table(id_correcao = id_correcao, ordem_operacao = NA_character_, status = "ok_sem_linhas_alvo", mensagem = "Nenhuma linha-alvo localizada para limpeza atômica de outras formas de vida; operação tratada como idempotente e não bloqueante. Se houver resíduo remanescente, a auditoria impeditiva pós-painel registrará a pendência.", atributo = "__limpar_outras_formas_vida__", linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao), linhas = integer(), afetacoes = afetacoes, falha = FALSE))
  }
  cols_info <- monitora_correcao_colunas_limpeza_outras_formas(dt, dicionario)
  listas <- cols_info[classe == "lista_principal_forma_vida" & coluna %in% names(dt), unique(coluna)]
  descritores <- cols_info[classe == "descritor_outra_forma_vida" & coluna %in% names(dt), unique(coluna)]
  fotos <- cols_info[classe == "foto_outra_forma_vida" & coluna %in% names(dt), unique(coluna)]
  forma_outros_col <- cols_info[classe == "campo_atual_forma_vida_outros" & coluna %in% names(dt), unique(coluna)]
  forma_outros_col <- if (length(forma_outros_col)) forma_outros_col[1L] else NA_character_
  if (is.na(forma_outros_col) || !nzchar(forma_outros_col)) {
    forma_outros_col <- "amostragem/registro/forma_vida_outros"
    if (!(forma_outros_col %in% names(dt))) data.table::set(dt, j = forma_outros_col, value = NA_character_)
    cols_info <- data.table::rbindlist(list(
      cols_info,
      data.table::data.table(classe = "campo_atual_forma_vida_outros", coluna = forma_outros_col, categoria = NA_character_, usar_para_escrita_solo_nu = FALSE)
    ), fill = TRUE, use.names = TRUE)
  }
  tipo_cols <- cols_info[classe == "campo_superior_tipo_forma_vida" & coluna %in% names(dt), unique(coluna)]
  tipo_update <- cols_info[classe == "campo_superior_tipo_forma_vida" & usar_para_escrita_solo_nu == TRUE & coluna %in% names(dt), coluna]
  tipo_update <- if (length(tipo_update)) tipo_update[1L] else NA_character_
  if (!length(listas) && !length(descritores) && !length(fotos)) {
    return(list(audit = data.table::data.table(id_correcao = id_correcao, ordem_operacao = NA_character_, status = "falha_sem_colunas", mensagem = "Nenhuma coluna de lista/descritor/foto histórica de outra forma de vida detectada", atributo = "__limpar_outras_formas_vida__", linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao), linhas = integer(), afetacoes = afetacoes, falha = TRUE))
  }
  tokens_outra <- monitora_correcao_tokens_residuo_historico_outras_formas()
  remover_serial <- paste(tokens_outra, collapse = " ")
  registrar <- function(col, idx, antes, depois, mensagem, status = "aplicada") {
    idx <- as.integer(idx)
    mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
    if (!any(mudou, na.rm = TRUE)) return(invisible(NULL))
    idx2 <- idx[mudou]
    audit <<- data.table::rbindlist(list(audit, data.table::data.table(
      id_correcao = id_correcao,
      ordem_operacao = NA_character_,
      status = status,
      mensagem = mensagem,
      atributo = col,
      linha_indice = idx2,
      valor_antes = antes[mudou],
      valor_depois = depois[mudou],
      arquivo_correcao = arquivo_correcao
    )), fill = TRUE, use.names = TRUE)
    afetacoes <<- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = idx2, atributo = col)), fill = TRUE, use.names = TRUE)
  }
  registrar_evento <- function(col, idx, antes, depois, mensagem, status = "aplicada") {
    idx <- as.integer(idx)
    if (!length(idx)) return(invisible(NULL))
    audit <<- data.table::rbindlist(list(audit, data.table::data.table(
      id_correcao = id_correcao,
      ordem_operacao = NA_character_,
      status = status,
      mensagem = mensagem,
      atributo = col,
      linha_indice = idx,
      valor_antes = antes,
      valor_depois = depois,
      arquivo_correcao = arquivo_correcao
    )), fill = TRUE, use.names = TRUE)
    invisible(NULL)
  }

  resumo_antes <- monitora_correcao_contar_residuos_outras_formas(dt, linhas, cols_info)

 ### 1) Converter descritores inequívocos para o campo atual forma_vida_outros;
 ### descritores sem equivalência inequívoca são limpos como resíduo legado,
 ### sem gerar outra_forma_vida atual e sem bloquear a sanitização.
  for (cc in descritores) {
    antes <- as.character(dt[[cc]][linhas])
    cls <- monitora_correcao_classificar_descritor_outra_forma(antes)
    conv <- cls$status_sanitizacao == "convertido_para_token_atual_xlsform21"
    legado <- !conv & !monitora_correcao_vazio_vec(antes)
    campo_outros_ok <- !is.na(forma_outros_col) && forma_outros_col %in% names(dt)

    if (any(conv, na.rm = TRUE)) {
      if (campo_outros_ok) {
        idx_conv <- linhas[conv]
        antes_outros <- as.character(dt[[forma_outros_col]][idx_conv])
        depois_outros <- mapply(monitora_correcao_adicionar_tokens_valor, antes_outros, cls$token_xlsform21[conv], USE.NAMES = FALSE)
        data.table::set(dt, i = idx_conv, j = forma_outros_col, value = depois_outros)
        registrar(forma_outros_col, idx_conv, antes_outros, depois_outros, paste0("Limpeza atômica: descritor histórico de outra forma de vida convertido para token atual do XLSForm 21FEV25 a partir de ", cc))
      } else {
        registrar_evento("amostragem/registro/forma_vida_outros", linhas[conv], antes[conv], cls$token_xlsform21[conv], "Descritor histórico teria conversão inequívoca, mas campo atual forma_vida_outros não foi localizado", "falha_sem_campo_atual_forma_vida_outros")
      }
    }

    if (any(legado, na.rm = TRUE)) {
      registrar_evento(cc, linhas[legado], antes[legado], as.character(cls$status_sanitizacao[legado]), "Descritor histórico de outra forma de vida sem equivalência inequívoca no XLSForm 21FEV25; limpo como resíduo legado sem gerar token atual", "limpeza_descritor_legado_sem_conversao")
    }

    limpar <- ((conv & campo_outros_ok) | legado) & !monitora_correcao_vazio_vec(antes)
    if (any(limpar, na.rm = TRUE)) {
      depois <- antes
      depois[limpar] <- NA_character_
      data.table::set(dt, i = linhas[limpar], j = cc, value = NA_character_)
      registrar(cc, linhas, antes, depois, "Limpeza atômica: descritor textual histórico de outra forma de vida limpo; conversões inequívocas foram migradas e demais descritores foram removidos sem conversão")
    }
  }

 ### 2) Remover tokens históricos das listas antigas.
  for (cc in listas) {
    antes <- as.character(dt[[cc]][linhas])
    depois <- vapply(antes, monitora_correcao_remove_token_valor, character(1), token = remover_serial)
    mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
    if (any(mudou, na.rm = TRUE)) {
      data.table::set(dt, i = linhas[mudou], j = cc, value = depois[mudou])
      registrar(cc, linhas, antes, depois, "Limpeza atômica: token(s) histórico(s) de outra(s) forma(s) de vida removido(s) da lista principal")
    }
  }

 ### 3) Limpar fotos/imagens históricas correlatas, pois esses campos não fazem
 ### parte do contrato atual do XLSForm 21FEV25.
  for (cc in fotos) {
    antes <- as.character(dt[[cc]][linhas])
    limpar <- !monitora_correcao_vazio_vec(antes)
    if (any(limpar, na.rm = TRUE)) {
      depois <- antes
      depois[limpar] <- NA_character_
      data.table::set(dt, i = linhas[limpar], j = cc, value = NA_character_)
      registrar(cc, linhas, antes, depois, "Limpeza atômica: foto/imagem histórica de outra forma de vida limpa por não integrar o XLSForm 21FEV25")
    }
  }

 ### 4) Reconstruir o campo superior a partir dos campos inferiores finais.
  if (!is.na(tipo_update) && tipo_update %in% names(dt)) {
    tipo_antes <- as.character(dt[[tipo_update]][linhas])
    n <- length(linhas)
    tipo_novo <- rep(NA_character_, n)
    append_vec <- function(cond, token) {
      cond[is.na(cond)] <- FALSE
      if (!any(cond)) return(invisible(NULL))
      tipo_novo[cond] <<- vapply(tipo_novo[cond], monitora_correcao_append_token_valor, character(1), token = token)
      invisible(NULL)
    }
    for (cat in c("nativa", "exotica", "seca_morta")) {
      cols_cat <- cols_info[classe == "lista_principal_forma_vida" & categoria == cat & coluna %in% names(dt), unique(coluna)]
      tem_cat <- rep(FALSE, n)
      for (cc in cols_cat) tem_cat <- tem_cat | !monitora_correcao_vazio_vec(dt[[cc]][linhas])
      append_vec(tem_cat, cat)
    }
    if (!is.na(forma_outros_col) && forma_outros_col %in% names(dt)) {
      append_vec(!monitora_correcao_vazio_vec(dt[[forma_outros_col]][linhas]), "outra_forma_vida")
    }
    for (tok in c("serrapilheira", "fragmentos_botanicos", "material_inundado", "material_botanico")) {
      append_vec(monitora_correcao_token_presente_vec(tipo_antes, tok), tok)
    }
 ### `solo_nu` é decidido somente depois que todas as categorias, o campo
 ### atual de outras formas e os materiais preserváveis foram reconciliados.
 ### Nunca o acrescentar incrementalmente: isso impediria provar sua
 ### exclusividade e já causou coexistências inválidas em versões anteriores.
    sem_contato <- monitora_correcao_vazio_vec(tipo_novo)
    tipo_novo[sem_contato] <- "solo_nu"
    data.table::set(dt, i = linhas, j = tipo_update, value = tipo_novo)
    registrar(tipo_update, linhas, tipo_antes, tipo_novo, "Limpeza atômica: campo superior de forma de vida recalculado após sanitização de outra forma de vida")

 ### Gate local redundante e impeditivo da transação TRIOUT. O gate global
 ### pós-painel repete a mesma invariante antes de registros_validados.
    tem_solo <- monitora_correcao_token_presente_vec(tipo_novo, "solo_nu")
    tem_outro <- vapply(tipo_novo, function(v) {
      toks <- monitora_correcao_tokenizar(v)
      toks_norm <- monitora_correcao_normalizar_nome_coluna(toks)
      any(!is.na(toks_norm) & nzchar(toks_norm) & toks_norm != "solo_nu")
    }, logical(1L))
    vazio_final <- monitora_correcao_vazio_vec(tipo_novo)
    invalida <- (tem_solo & tem_outro) | vazio_final
    if (any(invalida, na.rm = TRUE)) {
      registrar_evento(
        tipo_update,
        linhas[invalida],
        tipo_antes[invalida],
        tipo_novo[invalida],
        "Falha impeditiva: fechamento TRIOUT produziu Encostam vazio ou solo_nu coexistindo com outro contato",
        "falha_invariante_solo_nu_pos_triout"
      )
    }
  } else {
    registrar_evento("tipo_forma_vida", linhas, rep(NA_character_, length(linhas)), rep(NA_character_, length(linhas)), "Campo superior tipo_forma_vida/Encostam não localizado para recálculo pós-sanitização", "falha_sem_tipo_forma_vida")
  }

  resumo_depois <- monitora_correcao_contar_residuos_outras_formas(dt, linhas, cols_info)
  n_pend <- sum(audit$status %in% c("falha_sem_campo_atual_forma_vida_outros", "falha_sem_tipo_forma_vida"), na.rm = TRUE)
  audit <- data.table::rbindlist(list(audit, data.table::data.table(
    id_correcao = id_correcao,
    ordem_operacao = NA_character_,
    status = ifelse(resumo_depois$linhas_com_residuo_total[1L] == 0L && n_pend == 0L, "auditoria_ok", "falha_residuo_pos_limpeza"),
    mensagem = paste0("Limpeza atômica outras formas: linhas_alvo=", length(linhas), "; residuos_antes=", resumo_antes$linhas_com_residuo_total[1L], "; residuos_depois=", resumo_depois$linhas_com_residuo_total[1L], "; pendencias_manuais=", n_pend, "; regra_solo_nu_pos_recalculo=ativa"),
    atributo = "__limpar_outras_formas_vida__",
    linha_indice = NA_integer_,
    valor_antes = as.character(resumo_antes$linhas_com_residuo_total[1L]),
    valor_depois = as.character(resumo_depois$linhas_com_residuo_total[1L]),
    arquivo_correcao = arquivo_correcao
  )), fill = TRUE, use.names = TRUE)
  list(audit = audit[], linhas = unique(afetacoes$linha_indice), afetacoes = afetacoes[], falha = any(grepl("^falha", as.character(audit$status))))
}

monitora_correcao_eh_operacao_limpeza_outras_formas <- function(corr) {
  corr <- data.table::as.data.table(corr)
  acao <- if ("acao" %in% names(corr)) tolower(trimws(as.character(corr$acao))) else rep("", nrow(corr))
  tipo <- if ("tipo_correcao" %in% names(corr)) tolower(trimws(as.character(corr$tipo_correcao))) else rep("", nrow(corr))
  acao %in% c("limpar_outras_formas_vida", "limpeza_outras_formas_vida_atomica") |
    tipo %in% c("triagem_limpeza_outras_formas_vida_atomica", "limpeza_outras_formas_vida_atomica")
}


### contagem semântica global e aplicação vetorizada de operações
### -------------------------------------------------------------------------
### A fila do painel pode conter muitos itens auditáveis para uma única decisão
### do usuário. As funções abaixo mantêm a rastreabilidade por item, mas aplicam
### a alteração por grupo semântico, evitando o gargalo observado quando 424
### itens auditáveis foram tratados como 424 operações.
monitora_correcao_contar_operacoes_semanticas <- function(correcoes) {
  if (is.null(correcoes)) return(0L)
  cc <- data.table::as.data.table(correcoes)
  if (!nrow(cc)) return(0L)
  if (!("id_correcao" %in% names(cc))) return(nrow(cc))
  ids <- trimws(as.character(cc$id_correcao))
  ids[is.na(ids) | !nzchar(ids)] <- paste0("__linha_", which(is.na(ids) | !nzchar(ids)))
  as.integer(data.table::uniqueN(ids))
}

monitora_correcao_eh_operacao_pendencia_sem_forma <- function(corr) {
  corr <- data.table::as.data.table(corr)
  tipo <- if ("tipo_correcao" %in% names(corr)) tolower(trimws(as.character(corr$tipo_correcao))) else rep("", nrow(corr))
  id <- if ("id_correcao" %in% names(corr)) toupper(trimws(as.character(corr$id_correcao))) else rep("", nrow(corr))
  esc <- if ("escopo_contextual_painel" %in% names(corr)) tolower(trimws(as.character(corr$escopo_contextual_painel))) else rep("", nrow(corr))
  tipo %in% c("pendencia_sem_forma_vida_lote", "pendencia_sem_forma_vida") |
    grepl("^PENDFV", id) |
    esc %in% c("linhas_pendentes_ocorrencia_diagnostica", "linhas_pendentes_ocorrencia")
}

monitora_correcao_primeiro_valor <- function(x) {
  x <- as.character(x)
  x <- x[!is.na(x) & nzchar(trimws(x))]
  if (!length(x)) return(NA_character_)
  x[1L]
}

monitora_correcao_inferir_categoria_pendfv <- function(grupo, atributo = NA_character_) {
  g <- data.table::as.data.table(grupo)
  vals <- character(0)
  for (cc in intersect(c("categoria_destino", "categoria_origem", "tipo_triagem", "ocorrencia_diagnostica_contextual"), names(g))) vals <- c(vals, as.character(g[[cc]]))
  vals <- c(vals, as.character(atributo))
  txt <- tolower(paste(vals, collapse = " "))
  if (grepl("seca_morta|seca.*morta|morta", txt, perl = TRUE)) return("seca_morta")
  if (grepl("exotic|exotica|exotico", txt, perl = TRUE)) return("exotica")
  if (grepl("nativ", txt, perl = TRUE)) return("nativa")
  NA_character_
}

monitora_correcao_linhas_pendfv_grupo <- function(dt, grupo, col, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  grupo <- data.table::as.data.table(grupo)
  idx <- integer(0)
  if (!is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt) && "uuid_registro" %in% names(grupo)) {
    uu <- unique(trimws(as.character(grupo$uuid_registro)))
    uu <- uu[!is.na(uu) & nzchar(uu)]
    if (length(uu)) idx <- which(trimws(as.character(dt[[chaves$uuid_registro]])) %chin% uu)
  }
 ### motor único: PENDFV também é ocorrência diagnóstica por linha.
 ### Se o painel gravou linha_indice/linhas_alvo_serializadas, essas linhas são
 ### preferidas ao escopo amplo de COLETAS. COLETA é apenas fallback legado.
  if (!length(idx)) {
    li_vals <- character(0)
    for (cc_li in intersect(c("linhas_alvo_serializadas", "linha_indice"), names(grupo))) {
      li_vals <- c(li_vals, unlist(lapply(as.character(grupo[[cc_li]]), monitora_correcao_parse_serial_generico), use.names = FALSE))
    }
    li <- suppressWarnings(as.integer(li_vals))
    li <- unique(li[!is.na(li) & li >= 1L & li <= nrow(dt)])
    if (length(li)) idx <- li
  }
  if (!length(idx) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt) && "coleta" %in% names(grupo)) {
    coletas <- unique(unlist(lapply(as.character(grupo$coleta), monitora_correcao_parse_lista_serializada), use.names = FALSE))
    coletas <- coletas[!is.na(coletas) & nzchar(coletas)]
    if (length(coletas)) idx <- which(as.character(dt[[chaves$coleta]]) %chin% coletas)
    if (length(idx) && !is.na(chaves$ponto_amostral) && chaves$ponto_amostral %in% names(dt) && "ponto_amostral" %in% names(grupo)) {
      pontos <- unique(trimws(as.character(grupo$ponto_amostral)))
      pontos <- pontos[!is.na(pontos) & nzchar(pontos)]
      if (length(pontos)) idx <- idx[trimws(as.character(dt[[chaves$ponto_amostral]][idx])) %chin% pontos]
    }
  }
  idx <- unique(as.integer(idx))
  idx <- idx[!is.na(idx) & idx >= 1L & idx <= nrow(dt)]
  if (!length(idx) || is.na(col) || !(col %in% names(dt))) return(integer(0))
  categoria <- monitora_correcao_inferir_categoria_pendfv(grupo, col)
  vazio_destino <- monitora_correcao_vazio_vec(dt[[col]][idx])
  if (!is.na(categoria) && nzchar(categoria) && !is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% names(dt)) {
    tem_cat <- monitora_correcao_contem_qualquer_token_vec(dt[[chaves$tipo_forma_vida]][idx], categoria)
  } else {
    tem_cat <- rep(TRUE, length(idx))
  }
  idx[tem_cat & vazio_destino]
}

### ajuste validação operacional (etapa_validacao): PENDHAB (tipo_correcao == "pendencia_habito_lote")
### é criado pelo painel com uma linha auditável POR REGISTRO (ver
### monitora_painel_criar_ops_pendencia_habito ), cada uma já trazendo
### uuid_registro/linha_indice/COLETA/ponto exatos do registro que o usuário
### auditou. Rotear esse tipo pelo motor genérico de PENDFV
### (monitora_correcao_linhas_pendfv_grupo , pensado para replay entre
### execuções e que reconstrói o escopo por COLETA inteira) reexpande o grupo
### para toda COLETA com o campo de hábito ainda vazio -- foi assim que 27/4
### linhas auditadas na validação operacional viraram 193/283 linhas afetadas e o recálculo de
### campos superiores tentou aplicar RECALC_SUPERIORES_XLSFORM em linhas que
### nunca foram decisão do usuário. Para hábito, o escopo tem que ser
### exatamente as linhas auditáveis salvas, uma a uma, sem união por COLETA.
monitora_correcao_linhas_pendhab_grupo_exato <- function(dt, grupo, col, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  grupo <- data.table::as.data.table(grupo)
  if (!nrow(dt) || !nrow(grupo) || is.na(col) || !(col %in% names(dt))) return(integer(0))

  uuid_col <- if (!is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) chaves$uuid_registro else NA_character_
  coleta_col <- if (!is.na(chaves$coleta) && chaves$coleta %in% names(dt)) chaves$coleta else NA_character_
  ponto_col <- if (!is.na(chaves$ponto_amostral) && chaves$ponto_amostral %in% names(dt)) chaves$ponto_amostral else NA_character_
  metro_col <- if (!is.na(chaves$ponto_metro) && chaves$ponto_metro %in% names(dt)) chaves$ponto_metro else NA_character_

  dt_uuid <- if (!is.na(uuid_col)) trimws(as.character(dt[[uuid_col]])) else rep(NA_character_, nrow(dt))
  dt_coleta <- if (!is.na(coleta_col)) trimws(as.character(dt[[coleta_col]])) else rep(NA_character_, nrow(dt))
  dt_ponto <- if (!is.na(ponto_col)) trimws(as.character(dt[[ponto_col]])) else rep(NA_character_, nrow(dt))
  dt_metro <- if (!is.na(metro_col)) trimws(as.character(dt[[metro_col]])) else rep(NA_character_, nrow(dt))

  g_uuid <- if ("uuid_registro" %in% names(grupo)) trimws(as.character(grupo$uuid_registro)) else rep(NA_character_, nrow(grupo))
  g_li <- if ("linha_indice" %in% names(grupo)) suppressWarnings(as.integer(grupo$linha_indice)) else rep(NA_integer_, nrow(grupo))
  g_coleta <- if ("coleta" %in% names(grupo)) trimws(as.character(grupo$coleta)) else rep(NA_character_, nrow(grupo))
  g_ponto <- if ("ponto_amostral" %in% names(grupo)) trimws(as.character(grupo$ponto_amostral)) else rep(NA_character_, nrow(grupo))
  g_metro <- if ("ponto_metro" %in% names(grupo)) trimws(as.character(grupo$ponto_metro)) else rep(NA_character_, nrow(grupo))

  idx_out <- integer(0)
  for (rr in seq_len(nrow(grupo))) {
    linha <- integer(0)

 ### 1) chave preferencial: uuid_registro, se identificar exatamente 1 linha.
    if (!is.na(uuid_col) && !is.na(g_uuid[rr]) && nzchar(g_uuid[rr])) {
      cand <- which(dt_uuid == g_uuid[rr])
      if (length(cand) == 1L) linha <- cand
    }

 ### 2) fallback: linha_indice, só aceito se a COLETA da linha_indice ainda
 ### bater com a COLETA auditada (protege contra deslocamento de posição).
    if (!length(linha) && !is.na(g_li[rr]) && g_li[rr] >= 1L && g_li[rr] <= nrow(dt)) {
      coleta_ok <- is.na(coleta_col) || is.na(g_coleta[rr]) || !nzchar(g_coleta[rr]) || identical(dt_coleta[g_li[rr]], g_coleta[rr])
      if (coleta_ok) linha <- g_li[rr]
    }

 ### 3) fallback final: COLETA + ponto_amostral + ponto_metro, só quando a
 ### combinação identifica exatamente 1 linha (nunca a COLETA inteira).
    if (!length(linha) && !is.na(coleta_col) && !is.na(g_coleta[rr]) && nzchar(g_coleta[rr])) {
      cand <- which(dt_coleta == g_coleta[rr])
      if (!is.na(ponto_col) && !is.na(g_ponto[rr]) && nzchar(g_ponto[rr])) cand <- cand[dt_ponto[cand] == g_ponto[rr]]
      if (!is.na(metro_col) && !is.na(g_metro[rr]) && nzchar(g_metro[rr])) cand <- cand[dt_metro[cand] == g_metro[rr]]
      if (length(cand) == 1L) linha <- cand
    }

    if (length(linha) == 1L) idx_out <- c(idx_out, linha)
  }
  idx_out <- unique(as.integer(idx_out))
  idx_out[!is.na(idx_out) & idx_out >= 1L & idx_out <= nrow(dt)]
}

monitora_correcao_aplicar_pendencias_sem_forma_atomicas <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), arquivo_correcao = NA_character_, dicionario = NULL, silencioso = FALSE, registrar_perf = TRUE) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::copy(data.table::as.data.table(corr))
  if (!nrow(corr)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  idx <- which(monitora_correcao_eh_operacao_pendencia_sem_forma(corr))
  if (!length(idx)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  corr[, .grupo_pendfv_atom := data.table::fifelse(!is.na(id_correcao) & nzchar(as.character(id_correcao)), as.character(id_correcao), paste0("__linha_", seq_len(.N)))]
  grupos <- unique(corr[idx, .grupo_pendfv_atom])
  audit <- data.table::data.table()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  linhas_total <- integer(0)
  falha <- FALSE
  n_total <- length(grupos)
  for (gg in seq_along(grupos)) {
    gid <- grupos[gg]
    grupo <- corr[.grupo_pendfv_atom == gid]
    attr_raw <- monitora_correcao_primeiro_valor(if ("atributo_coluna_registros_corrig" %in% names(grupo)) grupo$atributo_coluna_registros_corrig else NA_character_)
    col <- tryCatch(monitora_correcao_resolver_coluna(dt, attr_raw, dicionario, permitir_heuristica = FALSE), error = function(e) NA_character_)
    acao <- monitora_correcao_acao_normalizar(monitora_correcao_primeiro_valor(if ("acao" %in% names(grupo)) grupo$acao else "append_token"))
    valor <- monitora_correcao_primeiro_valor(if ("valor_novo" %in% names(grupo)) grupo$valor_novo else NA_character_)
    id_cor <- monitora_correcao_primeiro_valor(grupo$id_correcao)
    if (!isTRUE(silencioso) && exists("monitora_correcao_console_msg", mode = "function")) monitora_correcao_console_msg("Aplicando operação semântica PENDFV ", gg, "/", n_total, ": atributo=", attr_raw, "; token=", valor, ".")
    tipo_grupo <- tolower(trimws(monitora_correcao_primeiro_valor(if ("tipo_correcao" %in% names(grupo)) grupo$tipo_correcao else NA_character_)))
    eh_habito_lote <- identical(tipo_grupo, "pendencia_habito_lote")
    linhas <- if (isTRUE(eh_habito_lote)) monitora_correcao_linhas_pendhab_grupo_exato(dt, grupo, col, chaves) else monitora_correcao_linhas_pendfv_grupo(dt, grupo, col, chaves)
    if (isTRUE(eh_habito_lote) && length(linhas) < nrow(grupo)) {
      audit <- data.table::rbindlist(list(audit, data.table::data.table(id_correcao = id_cor, ordem_operacao = NA_character_, status = "aviso_localizacao_parcial_habito", mensagem = paste0("Correção contextual de hábito em lote: ", length(linhas), " de ", nrow(grupo), " linha(s) auditável(is) localizada(s) exatamente no estado corrente (as demais podem já estar aplicadas ou fora do escopo atual)."), atributo = col, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao)), fill = TRUE, use.names = TRUE)
    }
    if (is.na(col) || !(col %in% names(dt))) {
      falha <- TRUE
      audit <- data.table::rbindlist(list(audit, data.table::data.table(id_correcao = id_cor, ordem_operacao = NA_character_, status = "falha_coluna_pendencia_sem_forma", mensagem = paste0("Coluna de forma de vida não localizada para operação contextual: ", attr_raw), atributo = attr_raw, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao)), fill = TRUE, use.names = TRUE)
      next
    }
    if (!length(linhas)) {
      audit <- data.table::rbindlist(list(audit, data.table::data.table(id_correcao = id_cor, ordem_operacao = NA_character_, status = "ok_sem_linhas_pendentes", mensagem = "Operação contextual sem efeito: nenhuma linha pendente sem forma permaneceu no estado corrente", atributo = col, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao)), fill = TRUE, use.names = TRUE)
      next
    }
    antes <- as.character(dt[[col]][linhas])
    novo <- monitora_correcao_aplicar_operacao(antes, acao, valor, NA_character_)
    mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(novo)
    if (any(mudou, na.rm = TRUE)) {
      data.table::set(dt, i = linhas[mudou], j = col, value = novo[mudou])
      linhas_mudou <- linhas[mudou]
      linhas_total <- unique(c(linhas_total, linhas_mudou))
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas_mudou, atributo = col)), fill = TRUE, use.names = TRUE)
      msg_aplicada <- if (isTRUE(eh_habito_lote)) paste0("Correção contextual de hábito em lote: ", length(linhas_mudou), " linha(s) alterada(s)") else paste0("Correção contextual vetorizada de pendência sem forma: ", length(linhas_mudou), " linha(s) alterada(s) em uma operação semântica")
      audit <- data.table::rbindlist(list(audit, data.table::data.table(id_correcao = id_cor, ordem_operacao = NA_character_, status = "aplicada", mensagem = msg_aplicada, atributo = col, linha_indice = linhas_mudou, valor_antes = antes[mudou], valor_depois = novo[mudou], arquivo_correcao = arquivo_correcao)), fill = TRUE, use.names = TRUE)
    } else {
      audit <- data.table::rbindlist(list(audit, data.table::data.table(id_correcao = id_cor, ordem_operacao = NA_character_, status = "ignorada_sem_alteracao", mensagem = "Operação contextual sem efeito: valores finais já correspondiam ao token solicitado", atributo = col, linha_indice = linhas, valor_antes = antes, valor_depois = novo, arquivo_correcao = arquivo_correcao)), fill = TRUE, use.names = TRUE)
    }
    if (isTRUE(registrar_perf) && exists("monitora_perf_registrar_checkpoint", mode = "function")) {
      try(monitora_perf_registrar_checkpoint(paste0("painel_correcoes_pendfv_", gg, "_de_", n_total), paste0("operação contextual PENDFV ", gg, "/", n_total, " aplicada"), dt), silent = TRUE)
    }
  }
  corr_out <- corr[!(.grupo_pendfv_atom %in% grupos)]
  corr_out[, .grupo_pendfv_atom := NULL]
  corr[, .grupo_pendfv_atom := NULL]
  list(dt = dt[], corr = corr_out[], audit = audit[], linhas = linhas_total, afetacoes = unique(afetacoes), falha = falha, n_grupos = length(grupos))
}

monitora_correcao_linhas_residuo_outras_formas <- function(dt, linhas, cols_info) {
  dt <- data.table::as.data.table(dt)
  linhas <- unique(as.integer(linhas)); linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas)) return(integer(0))
  tokens_outra <- monitora_correcao_tokens_residuo_historico_outras_formas()
  listas <- cols_info[classe == "lista_principal_forma_vida" & coluna %in% names(dt), coluna]
  descritores <- cols_info[classe == "descritor_outra_forma_vida" & coluna %in% names(dt), coluna]
  fotos <- cols_info[classe == "foto_outra_forma_vida" & coluna %in% names(dt), coluna]
  flag <- rep(FALSE, length(linhas))
  for (cc in listas) flag <- flag | monitora_correcao_contem_qualquer_token_vec(dt[[cc]][linhas], tokens_outra)
  for (cc in descritores) flag <- flag | !monitora_correcao_vazio_vec(dt[[cc]][linhas])
  for (cc in fotos) flag <- flag | !monitora_correcao_vazio_vec(dt[[cc]][linhas])
  linhas[flag]
}

monitora_correcao_linhas_escopo_operacao_outras_estado_corrente <- function(dt, grupo, chaves = monitora_correcao_colunas_chave(dt), indice = NULL) {
  dt <- data.table::as.data.table(dt)
  grupo <- data.table::as.data.table(grupo)

 ### TRIOUT atômico e vetorizado, com COLETA como filtro
 ### operacional estável. A operação de limpeza de outras formas não deve
 ### depender de linha_indice depois que outras operações podem deslocar o
 ### data.table, nem precisa expandir uma aplicação por item. O fluxo seguro é:
 ### 1) resolver o universo corrente por COLETA/chaves estáveis do próprio
 ### grupo TRIOUT;
 ### 2) dentro desse universo, o aplicador vetorizado atua somente nas linhas
 ### que ainda tenham resíduo real de outra forma;
 ### 3) linha_indice/linhas_alvo_serializadas permanecem apenas como fallback
 ### legado para arquivos antigos sem COLETA/contexto.
  parse_any <- function(cols) {
    vals <- character(0)
    for (cc in intersect(cols, names(grupo))) {
      vals <- c(vals, unlist(lapply(as.character(grupo[[cc]]), monitora_correcao_parse_serial_generico), use.names = FALSE))
    }
    vals <- unique(trimws(as.character(vals)))
    vals <- vals[!is.na(vals) & nzchar(vals) & !(toupper(vals) %in% c("NA", "NAN", "NULL"))]
    vals
  }

  idx_filtro <- seq_len(nrow(dt))
  tem_filtro_estavel <- FALSE

  coletas <- parse_any(c("coleta", "COLETA", "coletas"))
  if (length(coletas) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    idx_filtro <- idx_filtro[as.character(dt[[chaves$coleta]][idx_filtro]) %chin% coletas]
    tem_filtro_estavel <- TRUE
  }

 ### Ponto/metro só restringem quando a operação é inequivocamente de um único
 ### ponto. Em operações agrupadas, listas serializadas de pontos e metros não
 ### carregam pareamento seguro; usar interseção de vetores pode errar o alvo.
  pontos <- parse_any(c("ponto_amostral", "Ponto amostral", "ponto_amostral_serializado"))
  metros <- parse_any(c("ponto_metro", "Ponto metro", "ponto_metro_serializado"))
  if (length(coletas) <= 1L && length(pontos) == 1L && !is.na(chaves$ponto_amostral) && chaves$ponto_amostral %in% names(dt)) {
    idx_filtro <- idx_filtro[as.character(dt[[chaves$ponto_amostral]][idx_filtro]) %chin% pontos]
    tem_filtro_estavel <- TRUE
    if (length(metros) == 1L && !is.na(chaves$ponto_metro) && chaves$ponto_metro %in% names(dt)) {
      idx_filtro <- idx_filtro[as.character(dt[[chaves$ponto_metro]][idx_filtro]) %chin% metros]
    }
  }

 ### UUIDs continuam aceitos, mas apenas quando há UUID real. Não deixar o
 ### literal "NA" bloquear o fallback estável por COLETA.
  uuids <- parse_any(c("uuid_registro", "uuid_registro_serializado", "uuids_registro"))
  if (length(uuids) && !is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) {
    idx_uuid <- which(trimws(as.character(dt[[chaves$uuid_registro]])) %chin% uuids)
    idx_uuid <- as.integer(idx_uuid[!is.na(idx_uuid) & idx_uuid >= 1L & idx_uuid <= nrow(dt)])
    if (length(idx_uuid)) {
      if (isTRUE(tem_filtro_estavel)) idx_filtro <- intersect(idx_filtro, idx_uuid) else idx_filtro <- idx_uuid
      tem_filtro_estavel <- TRUE
    }
  }

  idx_filtro <- unique(as.integer(idx_filtro))
  idx_filtro <- idx_filtro[!is.na(idx_filtro) & idx_filtro >= 1L & idx_filtro <= nrow(dt)]
  if (isTRUE(tem_filtro_estavel) && length(idx_filtro)) return(idx_filtro)

 ### Fallback: aplicar resolução linha a linha antiga somente quando a operação
 ### não traz COLETA/contexto estável. Isso preserva compatibilidade com
 ### correcoes_campos legados, mas evita que posição antiga domine a run atual.
  idx <- unique(unlist(lapply(seq_len(nrow(grupo)), function(ii) monitora_correcao_localizar_linhas_limpeza_outras_formas(dt, grupo[ii], chaves, indice)), use.names = FALSE))
  idx <- as.integer(idx); idx <- idx[!is.na(idx) & idx >= 1L & idx <= nrow(dt)]
  if (length(idx)) return(unique(idx))

  integer(0)
}

monitora_correcao_aplicar_limpezas_outras_formas_estado_corrente <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL, silencioso = FALSE, registrar_perf = TRUE) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::copy(data.table::as.data.table(corr))
  if (!nrow(corr)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  idx <- which(monitora_correcao_eh_operacao_limpeza_outras_formas(corr))
  if (!length(idx)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  corr[, .grupo_triout_atom := data.table::fifelse(!is.na(id_correcao) & nzchar(as.character(id_correcao)), as.character(id_correcao), paste0("__linha_", seq_len(.N)))]
  grupos <- unique(corr[idx, .grupo_triout_atom])
  audit <- data.table::data.table()
  linhas_total <- integer(0)
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  falha <- FALSE
  cols_info <- monitora_correcao_colunas_limpeza_outras_formas(dt, dicionario)
  n_total <- length(grupos)
  for (gg in seq_along(grupos)) {
    gid <- grupos[gg]
    grupo <- corr[.grupo_triout_atom == gid]
    id_cor <- monitora_correcao_primeiro_valor(grupo$id_correcao)
    linhas_escopo <- monitora_correcao_linhas_escopo_operacao_outras_estado_corrente(dt, grupo, chaves, indice)
    linhas_escopo <- monitora_correcao_aplicar_escopo_conciliado(dt, linhas_escopo, grupo)
    linhas_residuo <- monitora_correcao_linhas_residuo_outras_formas(dt, linhas_escopo, cols_info)
    if (!isTRUE(silencioso) && exists("monitora_correcao_console_msg", mode = "function")) monitora_correcao_console_msg("Aplicando operação semântica TRIOUT ", gg, "/", n_total, ": escopo=", length(linhas_escopo), " linha(s); resíduos=", length(linhas_residuo), ".")
    if (!length(linhas_residuo)) {
      audit <- data.table::rbindlist(list(audit, data.table::data.table(id_correcao = id_cor, ordem_operacao = NA_character_, status = "ok_sem_residuo_no_estado_corrente", mensagem = paste0("Limpeza de outras formas sem ação: nenhum resíduo remanescente no estado corrente do escopo (", length(linhas_escopo), " linha(s))."), atributo = "__limpar_outras_formas_vida__", linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao)), fill = TRUE, use.names = TRUE)
      next
    }
    res <- monitora_correcao_aplicar_limpeza_outras_formas_atomica(dt, linhas_residuo, id_correcao = id_cor, arquivo_correcao = arquivo_correcao, dicionario = dicionario)
    if (nrow(res$audit)) audit <- data.table::rbindlist(list(audit, res$audit), fill = TRUE, use.names = TRUE)
    if (length(res$linhas)) linhas_total <- unique(c(linhas_total, res$linhas))
    if (nrow(res$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res$afetacoes), fill = TRUE, use.names = TRUE)
    linhas_residuo_pos <- monitora_correcao_linhas_residuo_outras_formas(dt, linhas_escopo, monitora_correcao_colunas_limpeza_outras_formas(dt, dicionario))
    if (length(linhas_residuo_pos)) {
      falha <- TRUE
      audit <- data.table::rbindlist(list(audit, data.table::data.table(id_correcao = id_cor, ordem_operacao = NA_character_, status = "falha_residuo_pos_limpeza_estado_corrente", mensagem = paste0("Limpeza de outras formas deixou ", length(linhas_residuo_pos), " linha(s) com resíduo no estado corrente."), atributo = "__limpar_outras_formas_vida__", linha_indice = linhas_residuo_pos, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao)), fill = TRUE, use.names = TRUE)
    }
    if (isTRUE(registrar_perf) && exists("monitora_perf_registrar_checkpoint", mode = "function")) {
      try(monitora_perf_registrar_checkpoint(paste0("painel_correcoes_triout_", gg, "_de_", n_total), paste0("operação TRIOUT ", gg, "/", n_total, " aplicada no estado corrente"), dt), silent = TRUE)
    }
  }
  corr_out <- corr[!(.grupo_triout_atom %in% grupos)]
  corr_out[, .grupo_triout_atom := NULL]
  corr[, .grupo_triout_atom := NULL]
  list(dt = dt[], corr = corr_out[], audit = audit[], linhas = linhas_total, afetacoes = unique(afetacoes), falha = falha, n_grupos = length(grupos))
}


monitora_correcao_auditar_persistencia_limpeza_outras_formas <- function(dt,
                                                                         arquivo_correcao = MONITORA_ARQUIVO_CORRECOES_CAMPOS,
                                                                         dicionario = NULL,
                                                                         contexto = "persistencia_limpeza_outras_formas",
                                                                         abortar = TRUE) {
  if (!file.exists(arquivo_correcao)) return(invisible(data.table::data.table()))
  dt <- monitora_dt_referenciar(dt)
  corr <- tryCatch(
    data.table::fread(arquivo_correcao, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character"),
    error = function(e) data.table::data.table()
  )
  if (nrow(corr) == 0L) return(invisible(data.table::data.table()))
  template <- monitora_correcao_template()
  for (cc in setdiff(names(template), names(corr))) corr[, (cc) := NA_character_]
  data.table::setDT(corr)
  idx_limpeza <- which(monitora_correcao_eh_operacao_limpeza_outras_formas(corr))
  if (!length(idx_limpeza)) return(invisible(data.table::data.table()))

  chaves <- monitora_correcao_colunas_chave(dt)
  indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
  corr_limpeza <- data.table::copy(corr[idx_limpeza])
  plano_efetivo <- get0("MONITORA_PLANO_CORRECOES_EFETIVO_ULTIMO", ifnotfound = NULL, inherits = TRUE)
  if (inherits(plano_efetivo, c("data.frame", "data.table")) && nrow(data.table::as.data.table(plano_efetivo))) {
    plano_efetivo <- data.table::as.data.table(plano_efetivo)
    idx_plano_limpeza <- which(monitora_correcao_eh_operacao_limpeza_outras_formas(plano_efetivo))
    ids_arquivo <- unique(as.character(corr_limpeza$id_correcao))
    cand_plano <- plano_efetivo[idx_plano_limpeza]
    if (length(ids_arquivo) && "id_correcao" %in% names(cand_plano)) cand_plano <- cand_plano[as.character(id_correcao) %in% ids_arquivo]
    if (nrow(cand_plano)) corr_limpeza <- data.table::copy(cand_plano)
  }
  corr_limpeza <- monitora_correcao_agrupar_operacoes_semanticas(corr_limpeza)
  if (!("id_correcao" %in% names(corr_limpeza))) corr_limpeza[, id_correcao := NA_character_]
  corr_limpeza[, .grupo_auditoria_triout := data.table::fifelse(
    !is.na(id_correcao) & nzchar(trimws(as.character(id_correcao))),
    as.character(id_correcao),
    paste0("__linha_", seq_len(.N))
  )]
  grupos_auditoria <- unique(corr_limpeza$.grupo_auditoria_triout)
  linhas <- unique(unlist(lapply(grupos_auditoria, function(gid) {
    grupo <- corr_limpeza[.grupo_auditoria_triout == gid]
    escopo_gid <- monitora_correcao_linhas_alvo_operacao(dt, grupo, chaves, indice_linhas)
    if (!length(escopo_gid)) escopo_gid <- monitora_correcao_linhas_escopo_operacao_outras_estado_corrente(dt, grupo, chaves, indice_linhas)
    monitora_correcao_aplicar_escopo_conciliado(dt, escopo_gid, grupo)
  }), use.names = FALSE))
  linhas <- as.integer(linhas)
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  ids_alvo_efetivos <- unique(monitora_correcao_parse_ids_estaveis(corr_limpeza$alvos_efetivos_monitora_row_id))
  ids_alvo_declarados <- if (length(ids_alvo_efetivos)) ids_alvo_efetivos else unique(monitora_correcao_parse_ids_estaveis(c(
    corr_limpeza$alvos_solicitados_monitora_row_id, corr_limpeza$monitora_row_id
  )))
  ids_alvo_presentes <- if (MONITORA_COL_ROW_ID %in% names(dt) && length(linhas)) unique(as.character(dt[[MONITORA_COL_ROW_ID]][linhas])) else character(0)
  ids_alvo_ausentes <- setdiff(ids_alvo_declarados, ids_alvo_presentes)
  auditoria_aplicacao <- get0("MONITORA_AUDITORIA_CORRECOES_CAMPOS_ULTIMA", ifnotfound = NULL, inherits = TRUE)
  ids_excluidos_auditados <- character(0)
  if (inherits(auditoria_aplicacao, c("data.frame", "data.table")) && nrow(data.table::as.data.table(auditoria_aplicacao))) {
    auditoria_aplicacao <- data.table::as.data.table(auditoria_aplicacao)
    if (all(c("status", "monitora_row_id") %in% names(auditoria_aplicacao))) {
      ids_excluidos_auditados <- unique(as.character(auditoria_aplicacao[status == "excluida_coleta", monitora_row_id]))
      ids_excluidos_auditados <- ids_excluidos_auditados[!is.na(ids_excluidos_auditados) & nzchar(ids_excluidos_auditados)]
    }
  }
  ids_ausentes_por_exclusao <- intersect(ids_alvo_ausentes, ids_excluidos_auditados)
  ids_ausentes_nao_justificados <- setdiff(ids_alvo_ausentes, ids_excluidos_auditados)
  n_alvos_declarados_contagem <- sum(vapply(grupos_auditoria, function(gid) {
    grupo <- corr_limpeza[.grupo_auditoria_triout == gid]
    vals <- suppressWarnings(as.integer(as.character(grupo$n_linhas_alvo)))
    vals <- vals[is.finite(vals) & vals >= 0L]
    if (length(vals)) max(vals) else NA_integer_
  }, integer(1L)), na.rm = TRUE)
  n_alvos_declarados <- if (length(ids_alvo_declarados)) length(ids_alvo_declarados) else n_alvos_declarados_contagem

  cols_info <- monitora_correcao_colunas_limpeza_outras_formas(dt, dicionario)
  resumo <- monitora_correcao_contar_residuos_outras_formas(dt, linhas, cols_info)
  resumo[, `:=`(
    contexto = contexto,
    n_operacoes_limpeza = length(idx_limpeza),
    n_linhas_escopo = length(linhas),
    n_linhas_universo_auditado = length(linhas),
    n_linhas_alvo_declarado = n_alvos_declarados,
    n_linhas_alvo_ausentes_estado_corrente = length(ids_alvo_ausentes),
    n_linhas_alvo_ausentes_por_exclusao_coleta = length(ids_ausentes_por_exclusao),
    n_linhas_alvo_ausentes_nao_justificadas = length(ids_ausentes_nao_justificados),
    cardinalidade_reconciliada = length(linhas) + length(ids_alvo_ausentes) == n_alvos_declarados,
    regra_abrangencia_auditoria = "identidade_estavel_presente_mais_alvos_auditados_como_excluidos_na_sessao",
    n_colunas_lista_principal = cols_info[classe == "lista_principal_forma_vida", uniqueN(coluna)],
    n_colunas_descritor_outra = cols_info[classe == "descritor_outra_forma_vida", uniqueN(coluna)],
    arquivo_correcao = arquivo_correcao
  )]

  arq_ult <- file.path(MONITORA_CORRECOES_DIR, paste0("auditoria_persistencia_limpeza_outras_formas_", contexto, "_ultima_execucao.csv"))
  arq_log <- file.path(MONITORA_LOG_DIR, paste0("auditoria_persistencia_limpeza_outras_formas_", contexto, "_", MONITORA_EXEC_ID, ".csv"))
  monitora_fwrite(resumo, arq_ult, na = "")
  monitora_fwrite(resumo, arq_log, na = "")

  msg <- paste0(
    "Persistência limpeza outras formas [", contexto, "]: universo_auditado=", length(linhas),
    "; alvos_declarados=", n_alvos_declarados,
    "; ausentes_por_exclusao_coleta=", length(ids_ausentes_por_exclusao),
    "; ausentes_nao_justificados=", length(ids_ausentes_nao_justificados),
    "; residuos=", resumo$linhas_com_residuo_total[1L],
    "; tokens=", resumo$celulas_com_token_outra[1L],
    "; descritores=", resumo$celulas_com_descritor[1L]
  )
  monitora_log_registrar_evento(
    "limpeza_outras_formas_persistencia",
    ifelse(resumo$linhas_com_residuo_total[1L] > 0L || length(ids_ausentes_nao_justificados) > 0L, "ERRO", "INFO"),
    arq_ult,
    msg,
    "auditoria obrigatória após aplicação atômica e antes da exportação final"
  )
  if (exists("monitora_correcao_console_msg", mode = "function")) monitora_correcao_console_msg(msg)

  if (isTRUE(abortar) && (resumo$linhas_com_residuo_total[1L] > 0L || length(ids_ausentes_nao_justificados) > 0L)) {
    stop(paste0(
      "Falha de persistência na limpeza atômica de outra(s) forma(s) de vida [", contexto, "]: ",
      resumo$linhas_com_residuo_total[1L], " linha(s) ainda com resíduo; ",
      length(ids_ausentes_nao_justificados), " alvo(s) ausente(s) sem exclusão de COLETA auditada. Ver ", arq_ult
    ), call. = FALSE)
  }
  invisible(resumo[])
}

monitora_correcao_marcar_checkpoint_por_persistencia <- function(resumo, contexto = "persistencia_pos_correcoes") {
  resumo <- data.table::as.data.table(resumo)
  n_res <- if (nrow(resumo) && "linhas_com_residuo_total" %in% names(resumo)) suppressWarnings(as.integer(resumo$linhas_com_residuo_total[1L])) else 0L
  if (is.na(n_res)) n_res <- 0L
  if (n_res > 0L) {
    assign("MONITORA_PERSISTENCIA_DERIVACOES_PENDENTES", TRUE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS", TRUE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", FALSE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_CORRIG_CONTRATO_CONTEXTO", paste0(contexto, "_checkpoint_pendente"), envir = .GlobalEnv)
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento(
        "checkpoint_persistencia_pendente", "ERRO", NA_character_,
        paste0(n_res, " linha(s) com resíduo persistente em ", contexto, "; registros_corrig será materializado como checkpoint e registros_validados permanecerá bloqueado"),
        "não abortar antes da materialização; consultar auditoria específica"
      )
    }
  }
  invisible(n_res)
}

### a auditoria genérica de operações pode apontar uma divergência depois
### que o checkpoint já foi escrito. Nessa situação, a evidência deve bloquear
### registros_validados e marcar registros_corrig, nunca abortar a execução e
### fazer o usuário interpretar o checkpoint materializado como trabalho perdido.
monitora_correcao_marcar_checkpoint_por_auditoria_operacoes <- function(resumo, contexto = "persistencia_operacoes_pos_export") {
  resumo <- data.table::as.data.table(resumo)
  if (!nrow(resumo) || !("status_persistencia" %in% names(resumo))) return(invisible(0L))
  falhas <- resumo[grepl("^(erro|falha|bloqueada)", as.character(status_persistencia))]
  if (!nrow(falhas)) return(invisible(0L))
  assign("MONITORA_PERSISTENCIA_DERIVACOES_PENDENTES", TRUE, envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS", TRUE, envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", FALSE, envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_CORRIG_CONTRATO_CONTEXTO", paste0(contexto, "_checkpoint_pendente"), envir = .GlobalEnv)
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento(
      "checkpoint_persistencia_operacoes_pendente", "ERRO", NA_character_,
      paste0(nrow(falhas), " divergência(s) de operação em ", contexto,
             "; registros_corrig permanece materializado como checkpoint e registros_validados fica bloqueado"),
      "consultar auditoria_persistencia_correcoes_* e corrigir a causa sem descartar o checkpoint"
    )
  }
  invisible(nrow(falhas))
}



monitora_correcao_acao_normalizar <- function(acao) {
  acao <- tolower(trimws(as.character(acao)[1L]))
  if (is.na(acao)) acao <- ""
  data.table::fcase(
    acao %in% c("update", "substituir_valor"), "update",
    acao %in% c("clear", "limpar", "limpar_valor"), "clear",
    acao %in% c("append_token", "adicionar_token"), "append_token",
    acao %in% c("remove_token", "remover_token"), "remove_token",
    acao %in% c("replace_token", "substituir_token"), "replace_token",
    acao %in% c("recalcular_tipo_forma_vida", "atualizar_tipo_forma_vida"), "recalcular_tipo_forma_vida",
    default = acao
  )
}

monitora_correcao_acoes_rotulos <- function() {
  c(
    "Substituir valor" = "update",
    "Limpar valor" = "clear",
    "Adicionar token" = "append_token",
    "Remover token" = "remove_token",
    "Substituir token" = "replace_token",
    "Recalcular Encostam/tipo_forma_vida" = "recalcular_tipo_forma_vida"
  )
}

monitora_correcao_rotulo_humanizado_ptbr <- function(x) {
  x <- as.character(x)
  vazio <- is.na(x) | !nzchar(trimws(x))
  out <- gsub("_+", " ", trimws(x), perl = TRUE)
  out <- tolower(out)
  idx <- which(!vazio & nzchar(out))
  if (length(idx)) out[idx] <- paste0(toupper(substr(out[idx], 1L, 1L)), substring(out[idx], 2L))
  out[vazio] <- NA_character_
  out
}

### Tradução exclusiva da camada visual. Os códigos internos continuam em
### inglês/canônicos nos CSVs e na trilha de auditoria para não alterar o
### contrato de aplicação nem a reprodutibilidade de runs anteriores.
monitora_correcao_acao_rotulo_ptbr <- function(acao) {
  bruto <- as.character(acao)
  norm <- vapply(bruto, monitora_correcao_acao_normalizar, character(1))
  mapa <- c(
    update = "Substituir valor",
    clear = "Limpar valor",
    append_token = "Adicionar token",
    remove_token = "Remover token",
    replace_token = "Substituir token",
    recalcular_tipo_forma_vida = "Recalcular Encostam/tipo_forma_vida",
    mover_forma_vida = "Mover forma de vida",
    mover_forma_vida_lote = "Mover formas de vida em lote",
    substituir_desconhecida = "Substituir forma de vida desconhecida",
    limpar_outras_formas_vida = "Sanitizar outras formas de vida",
    excluir_coleta = "Excluir coleta"
  )
  out <- unname(mapa[norm])
  faltante <- is.na(out) & !is.na(bruto) & nzchar(trimws(bruto))
  out[faltante] <- monitora_correcao_rotulo_humanizado_ptbr(bruto[faltante])
  out
}

monitora_correcao_tipo_rotulo_ptbr <- function(tipo) {
  bruto <- as.character(tipo)
  norm <- tolower(trimws(bruto))
  mapa <- c(
    simples_ou_lote = "Correção simples ou em lote",
    lote_multicoletas_campo_superior = "Correção de campo superior em lote",
    pendencia_sem_forma_vida_lote = "Correção de pendência sem forma de vida",
    pendencia_habito_lote = "Correção de hábito em lote",
    sanitizacao_habito_obrigatorio_ausente = "Sanitização ampla de hábito obrigatório ausente",
    triagem_substituir_desconhecida_atomica = "Substituição assistida de desconhecida",
    triagem_limpar_outras_formas_vida_atomica = "Sanitização de outras formas de vida",
    triagem_mover_forma_vida = "Movimento assistido de forma de vida",
    movimento_forma_vida_lote = "Movimento assistido em lote",
    exclusao_coleta = "Exclusão de coleta"
  )
  out <- unname(mapa[norm])
  faltante <- is.na(out) & !is.na(bruto) & nzchar(trimws(bruto))
  out[faltante] <- monitora_correcao_rotulo_humanizado_ptbr(bruto[faltante])
  out
}

monitora_correcao_split_serial <- function(x) {
  x <- as.character(x)[1L]
  if (is.na(x) || !nzchar(trimws(x))) return(character(0))
  unique(strsplit(x, "\\s*;\\s*", perl = TRUE)[[1]])
}

monitora_correcao_serializar_acoes <- function(x) {
  x <- unique(as.character(x))
  x <- x[!is.na(x) & nzchar(trimws(x))]
  paste(x, collapse = ";")
}

monitora_correcao_xlsform_meta_atual <- function(meta_xls = NULL) {
  meta_tem_conteudo <- function(meta) {
    if (is.null(meta) || !is.list(meta)) return(FALSE)
    chaves <- intersect(c("arquivos", "campos", "opcoes", "dependencias"), names(meta))
    any(vapply(chaves, function(cc) {
      obj <- meta[[cc]]
      inherits(obj, c("data.frame", "data.table")) && nrow(obj) > 0L
    }, logical(1L)))
  }
  if (meta_tem_conteudo(meta_xls)) return(meta_xls)
  if (exists("MONITORA_META_XLSFORMS_CORRECOES", inherits = TRUE)) {
    meta <- get("MONITORA_META_XLSFORMS_CORRECOES", inherits = TRUE)
    if (meta_tem_conteudo(meta)) return(meta)
  }
  if (exists("monitora_correcao_xlsforms_embutidos", mode = "function")) return(monitora_correcao_xlsforms_embutidos_cache_publicacao_ae())
  list(campos = data.table::data.table(), opcoes = data.table::data.table(), dependencias = data.table::data.table())
}

monitora_correcao_ultima_versao_xlsform <- function(campos) {
  campos <- data.table::as.data.table(campos)
  if (!nrow(campos) || !("arquivo_xlsform" %in% names(campos))) return(NA_character_)
  arqs <- unique(as.character(campos$arquivo_xlsform))
  arqs <- arqs[!is.na(arqs) & nzchar(arqs)]
  if (!length(arqs)) return(NA_character_)
  hit_21 <- arqs[grepl("21FEV25", arqs, ignore.case = TRUE)]
  if (length(hit_21)) return(hit_21[1L])
  arqs[order(arqs, decreasing = TRUE)][1L]
}

monitora_correcao_choices_xlsform <- function(list_name, meta_xls = NULL, preferir_ultima = TRUE) {
  list_name <- as.character(list_name)[1L]
  if (is.na(list_name) || !nzchar(trimws(list_name))) return(character(0))
  meta <- monitora_correcao_xlsform_meta_atual(meta_xls)
  op <- if (!is.null(meta$opcoes)) data.table::as.data.table(meta$opcoes) else data.table::data.table()
  if (!nrow(op)) return(character(0))
  for (cc in c("arquivo_xlsform", "list_name", "name")) if (!(cc %in% names(op))) op[, (cc) := NA_character_]
  lista_alvo <- list_name
  op <- op[list_name == lista_alvo & !is.na(name) & nzchar(as.character(name))]
  if (!nrow(op)) return(character(0))
  if (isTRUE(preferir_ultima)) {
    arq <- monitora_correcao_ultima_versao_xlsform(op)
    if (!is.na(arq) && nzchar(arq)) {
      op2 <- op[arquivo_xlsform == arq]
      if (nrow(op2)) op <- op2
    }
  }
  choices <- unique(as.character(op$name))
  choices <- choices[!is.na(choices) & nzchar(trimws(choices))]
  if (length(choices) <= 2L && all(choices %in% c("num_key", "label"))) return(character(0))
  choices
}

monitora_correcao_tokens_valor <- function(valor) {
  valor <- as.character(valor)[1L]
  if (is.na(valor) || !nzchar(trimws(valor))) return(character(0))
  toks <- unlist(strsplit(gsub("[|;,]+", " ", valor, perl = TRUE), "\\s+", perl = TRUE), use.names = FALSE)
  unique(toks[!is.na(toks) & nzchar(trimws(toks))])
}

monitora_correcao_tipo_campo_inferir <- function(col, papel, tipo_xls = NA_character_, tipo_inferido = NA_character_, list_name = NA_character_, chaves = NULL) {
  col <- as.character(col)[1L]
  papel <- as.character(papel)[1L]
  tipo_xls <- as.character(tipo_xls)[1L]
  tipo_inferido <- as.character(tipo_inferido)[1L]
  list_name <- as.character(list_name)[1L]
  base <- NA_character_
  if (!is.na(tipo_xls) && nzchar(trimws(tipo_xls))) base <- monitora_correcao_tipo_xlsform(tipo_xls)$tipo_base[1L]
  if (is.na(base) || !nzchar(base)) {
    ti <- tolower(trimws(tipo_inferido))
    if (grepl("select_multiple", ti)) base <- "select_multiple"
    else if (grepl("select_one", ti)) base <- "select_one"
    else if (grepl("geopoint", ti)) base <- "geopoint"
    else if (grepl("decimal", ti)) base <- "decimal"
    else if (grepl("inteiro|integer", ti)) base <- "integer"
    else if (grepl("hora|time", ti)) base <- "time"
    else if (grepl("data|date", ti)) base <- "date"
    else if (grepl("uuid", ti)) base <- "uuid"
    else base <- "text"
  }
  cn <- monitora_correcao_normalizar_nome_coluna(col)
  if (!is.null(chaves) && !is.na(chaves$data_hora) && identical(col, chaves$data_hora)) base <- "date"
 ### "Horário (data_hora)" normaliza para algo como
 ### "horario_data_hora" -- contém a substring "data_hora" do próprio
 ### qualificador de grupo, então a regra abaixo (pensada para "Data
 ### (data_hora)") forçava "date" também para HORÁRIO, e a regra seguinte
 ### de "time" nunca disparava (exige ausência de "data" em cn, que também
 ### falha pelo mesmo motivo). Checar o prefixo "horário"/"hora" primeiro
 ### resolve genericamente por nome, sem depender de um atributo
 ### específico: qualquer coluna cujo nome comece com hora/horário vira
 ### "time" antes de qualquer regra de "data_hora" ser avaliada.
  if (grepl("^hor[aá]rio|^hora($|_)", cn)) {
    base <- "time"
  } else if (cn %in% c("data_data_hora", "data_hora_data") || grepl("(^|_)data(_|$).*hora|data_hora", cn)) {
    base <- "date"
  } else if (grepl("hora", cn) && !grepl("data", cn)) {
    base <- "time"
  }
  if (identical(papel, "campo_superior_tipo_forma_vida")) base <- "select_multiple"
  if (identical(papel, "lista_principal_forma_vida")) base <- "select_multiple"
  if (identical(papel, "atributo_dependente_habito") && (is.na(list_name) || !nzchar(list_name))) base <- "select_one"
  base
}

monitora_correcao_contrato_edicao <- function(dt, meta_xls = NULL, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  meta_xls <- monitora_correcao_xlsform_meta_atual(meta_xls)
  chaves <- monitora_correcao_colunas_chave(dt)
  dicionario_invalido <- is.null(dicionario) || !nrow(data.table::as.data.table(dicionario)) || !("atributo_coluna_registros_corrig" %in% names(data.table::as.data.table(dicionario)))
  if (!isTRUE(dicionario_invalido)) {
    dd_tmp <- data.table::as.data.table(dicionario)
    dicionario_invalido <- all(is.na(dd_tmp$atributo_coluna_registros_corrig) | !nzchar(as.character(dd_tmp$atributo_coluna_registros_corrig)))
  }
  if (isTRUE(dicionario_invalido)) {
    dicionario <- monitora_correcao_dicionario_atributos(dt, meta_xls)
  }
  d <- data.table::as.data.table(data.table::copy(dicionario))
  if (!nrow(d)) {
    d <- data.table::data.table(atributo_coluna_registros_corrig = names(dt))
  }
  for (cc in c("atributo_coluna_registros_corrig", "xlsform_tipo", "tipo_valor_inferido", "papel_coluna", "categoria_coluna", "xlsform_name", "xlsform_list_name", "xlsform_required")) {
    if (!(cc %in% names(d))) d[, (cc) := NA_character_]
  }
  tipo_parse <- monitora_correcao_tipo_xlsform(d$xlsform_tipo)
  d[, xlsform_tipo_base := tipo_parse$tipo_base]
  d[, xlsform_list_name_calc := tipo_parse$list_name]
  d[is.na(xlsform_list_name) | !nzchar(xlsform_list_name), xlsform_list_name := xlsform_list_name_calc]
  d <- monitora_contrato_aplicar_metadados_categorias_movimento(d)
  d[papel_coluna == "campo_superior_tipo_forma_vida", xlsform_list_name := "tipo_forma_vida"]
  d[papel_coluna == "atributo_dependente_habito" & (is.na(xlsform_list_name) | !nzchar(xlsform_list_name)), xlsform_list_name := "habito_forma_vida"]
  d[, tipo_base_edicao := mapply(
    monitora_correcao_tipo_campo_inferir,
    atributo_coluna_registros_corrig,
    papel_coluna,
    xlsform_tipo,
    tipo_valor_inferido,
    xlsform_list_name,
    MoreArgs = list(chaves = chaves),
    SIMPLIFY = TRUE,
    USE.NAMES = FALSE
  )]
  d[, protegido := monitora_correcao_coluna_protegida(atributo_coluna_registros_corrig)]
  d[, required_bool := tolower(trimws(as.character(xlsform_required))) %in% c("yes", "true", "1", "sim", "required")]
  d[, motivo_bloqueio_edicao := NA_character_]
  d[protegido == TRUE, motivo_bloqueio_edicao := "coluna estrutural, chave operacional ou derivada protegida"]
  d[tipo_base_edicao %in% c("calculate", "hidden", "start", "end", "deviceid", "phonenumber", "barcode", "acknowledge", "rank", "range", "file") & is.na(motivo_bloqueio_edicao), motivo_bloqueio_edicao := paste0("tipo XLSForm não editável diretamente: ", tipo_base_edicao)]
  d[papel_coluna %in% c("imagem_foto") & is.na(motivo_bloqueio_edicao), motivo_bloqueio_edicao := "imagem/foto não deve ser substituída livremente no painel"]
  d[, acoes_permitidas := ""]
  d[is.na(motivo_bloqueio_edicao) & papel_coluna == "campo_superior_tipo_forma_vida", acoes_permitidas := "recalcular_tipo_forma_vida"]
  d[is.na(motivo_bloqueio_edicao) & tipo_base_edicao == "select_multiple" & papel_coluna != "campo_superior_tipo_forma_vida", acoes_permitidas := "append_token;remove_token;replace_token"]
  d[is.na(motivo_bloqueio_edicao) & tipo_base_edicao == "select_one", acoes_permitidas := "update;clear"]
  d[is.na(motivo_bloqueio_edicao) & tipo_base_edicao %in% c("text", "note"), acoes_permitidas := "update;clear"]
  d[is.na(motivo_bloqueio_edicao) & tipo_base_edicao %in% c("date", "datetime", "time", "integer", "decimal", "geopoint", "uuid"), acoes_permitidas := "update;clear"]
  d[required_bool == TRUE, acoes_permitidas := gsub("(^|;)clear(;|$)", "\\1", acoes_permitidas, perl = TRUE)]
  d[, acoes_permitidas := gsub(";+", ";", gsub("^;|;$", "", acoes_permitidas))]
  d[tipo_base_edicao == "uuid", motivo_bloqueio_edicao := "UUID não deve ser editado diretamente"]
  d[tipo_base_edicao == "uuid", acoes_permitidas := ""]
  d[, painel_editavel := !protegido & nzchar(acoes_permitidas)]
  if (!("motivo_escopo_contrato_unico" %in% names(d))) d[, motivo_escopo_contrato_unico := ""]
  if (all(c("escopo_operacional_contrato_unico", "escopos_permitidos_contrato_unico") %in% names(d))) {
    d[is.na(escopos_permitidos_contrato_unico), escopos_permitidos_contrato_unico := ""]
    d[!nzchar(as.character(escopos_permitidos_contrato_unico)), motivo_bloqueio_edicao := data.table::fifelse(
      is.na(motivo_bloqueio_edicao) | !nzchar(as.character(motivo_bloqueio_edicao)),
      data.table::fifelse(!is.na(motivo_escopo_contrato_unico) & nzchar(as.character(motivo_escopo_contrato_unico)), motivo_escopo_contrato_unico, "fora do escopo operacional do perfil_painel_edicao"),
      paste0(motivo_bloqueio_edicao, "; ", data.table::fifelse(!is.na(motivo_escopo_contrato_unico) & nzchar(as.character(motivo_escopo_contrato_unico)), motivo_escopo_contrato_unico, "fora do escopo operacional do perfil_painel_edicao"))
    )]
    d[!nzchar(as.character(escopos_permitidos_contrato_unico)), acoes_permitidas := ""]
    d[!nzchar(as.character(escopos_permitidos_contrato_unico)), painel_editavel := FALSE]
  }

  if (exists("monitora_correcao_anotar_contrato_template_sismonitora", mode = "function")) {
    d <- monitora_correcao_anotar_contrato_template_sismonitora(d, dt)
    d[atende_template_sismonitora != TRUE, motivo_bloqueio_edicao := data.table::fifelse(
      is.na(motivo_bloqueio_edicao) | !nzchar(as.character(motivo_bloqueio_edicao)),
      "fora do contrato do template SISMONITORA/XLSForm 2025",
      paste0(motivo_bloqueio_edicao, "; fora do contrato do template SISMONITORA/XLSForm 2025")
    )]
    d[atende_template_sismonitora != TRUE, acoes_permitidas := ""]
    d[atende_template_sismonitora != TRUE, painel_editavel := FALSE]
  } else {
    d[, atende_template_sismonitora := NA]
    d[, atributos_template_sismonitora := ""]
    d[, posicoes_template_sismonitora := ""]
    d[, estrategias_template_sismonitora := ""]
  }
  for (cc in c("escopo_operacional_contrato_unico", "escopos_permitidos_contrato_unico", "motivo_escopo_contrato_unico")) {
    if (!(cc %in% names(d))) d[, (cc) := ""]
  }

  d[, painel_motivo_bloqueio := data.table::fifelse(painel_editavel, "", data.table::fifelse(!is.na(motivo_bloqueio_edicao), motivo_bloqueio_edicao, "sem ação permitida para edição direta"))]
  d[, .(
    atributo_coluna_registros_corrig,
    tipo_base_edicao,
    xlsform_tipo,
    xlsform_list_name,
    papel_coluna,
    categoria_coluna,
    required_bool,
    atende_template_sismonitora,
    ordem_template_sismonitora,
    atributos_template_sismonitora,
    posicoes_template_sismonitora,
    estrategias_template_sismonitora,
    escopo_operacional_contrato_unico,
    escopos_permitidos_contrato_unico,
    motivo_escopo_contrato_unico,
    painel_editavel,
    painel_motivo_bloqueio,
    acoes_permitidas
  )]
}


### publicação: restringe atributos do painel aos campos de registros_corrig que
### constam no template SISMONITORA/XLSForm 2025 usado como contrato de atributos.
### O painel continua operando sobre registros_corrig, mas só lista atributos
### que aparecem como coluna de origem na matriz de herança para os 129 atributos
### do contrato final. Campos técnicos, auxiliares, diagnósticos ou legados que
### não constam nesse template ficam bloqueados para edição livre.
monitora_correcao_colunas_template_sismonitora <- function(dt, schema = NULL) {
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório.", call. = FALSE)
  dt <- data.table::as.data.table(dt)
  if (is.null(schema)) {
    if (!exists("monitora_validados_schema_embutido", mode = "function")) {
      return(data.table::data.table(
        atributo_coluna_registros_corrig = character(),
        atende_template_sismonitora = logical(),
        ordem_template_sismonitora = integer(),
        atributos_template_sismonitora = character(),
        posicoes_template_sismonitora = character(),
        estrategias_template_sismonitora = character()
      ))
    }
    schema <- monitora_validados_schema_embutido()
  }
  schema <- data.table::as.data.table(schema)
  if (!nrow(schema) || !("atributo" %in% names(schema))) {
    return(data.table::data.table(
      atributo_coluna_registros_corrig = character(),
      atende_template_sismonitora = logical(),
      ordem_template_sismonitora = integer(),
      atributos_template_sismonitora = character(),
      posicoes_template_sismonitora = character(),
      estrategias_template_sismonitora = character()
    ))
  }

  for (cc in c("posicao", "atributo", "formato", "obrigatorio_valor", "nivel")) {
    if (!(cc %in% names(schema))) schema[, (cc) := NA_character_]
  }
  schema[, atributo := as.character(atributo)]
  schema <- schema[!is.na(atributo) & nzchar(trimws(atributo))]

 ### Garantia defensiva para atributos atuais do XLSForm 2025 que são relevantes
 ### para as operações do painel, mas historicamente podem não aparecer nos dados
 ### de uma execução específica.
  obrigatorios_painel <- data.table::data.table(
    posicao = c(NA_integer_, NA_integer_),
    atributo = c("amostragem/registro/forma_serrapilheira", "amostragem/registro/forma_vida_outros"),
    formato = c("select_multiple", "select_multiple"),
    obrigatorio_valor = c("yes", "yes"),
    nivel = c("registro", "registro")
  )
  faltantes <- obrigatorios_painel[!atributo %in% schema$atributo]
  if (nrow(faltantes)) schema <- data.table::rbindlist(list(schema, faltantes), fill = TRUE, use.names = TRUE)

  meta <- tryCatch(monitora_correcao_xlsform_meta_atual(NULL), error = function(e) NULL)
  campos <- if (!is.null(meta) && !is.null(meta$campos)) data.table::as.data.table(meta$campos) else data.table::data.table()
  if (nrow(campos)) {
    for (cc in c("name", "type", "label", "caminho_registro", "list_name", "arquivo_xlsform")) {
      if (!(cc %in% names(campos))) campos[, (cc) := NA_character_]
    }
    campos[, name_chr := as.character(name)]
    campos[, type_chr := as.character(type)]
    campos[, label_chr := as.character(label)]
    campos[, caminho_chr := as.character(caminho_registro)]
    campos[, list_chr := as.character(list_name)]
    arq_atual <- tryCatch(monitora_correcao_ultima_versao_xlsform(campos), error = function(e) NA_character_)
    if (!is.na(arq_atual) && nzchar(arq_atual) && "arquivo_xlsform" %in% names(campos)) {
      campos_atual <- campos[arquivo_xlsform == arq_atual]
      if (nrow(campos_atual)) campos <- campos_atual
    }
  }

  nms <- names(dt)
  nms_norm <- monitora_correcao_normalizar_nome_coluna(nms)
  rows <- vector("list", nrow(schema))
  for (ii in seq_len(nrow(schema))) {
    att <- as.character(schema$atributo[ii])
    att_final <- sub("^.*/", "", att)
    pos_raw <- if ("posicao" %in% names(schema)) schema$posicao[ii] else ii
    pos_num <- suppressWarnings(as.integer(pos_raw))
    if (is.na(pos_num)) pos_num <- ii

    hit <- data.table::data.table()
    if (nrow(campos)) {
      hit <- campos[caminho_chr == att | name_chr == att | name_chr == att_final]
      if (!nrow(hit)) {
        pad <- paste0("(^|/)", gsub("([][{}()+*^$|\\\\?.])", "\\\\\\1", att_final, perl = TRUE), "$")
        hit <- campos[grepl(pad, caminho_chr, ignore.case = TRUE)]
      }
    }

    nome_xls <- if (nrow(hit)) as.character(hit$name_chr[1L]) else att_final
    lab_xls <- if (nrow(hit)) as.character(hit$label_chr[1L]) else ""
    tipo_xls <- if (nrow(hit)) as.character(hit$type_chr[1L]) else as.character(schema$formato[ii])
    list_xls <- if (nrow(hit)) as.character(hit$list_chr[1L]) else ""
    tipo_hit <- tryCatch(monitora_correcao_tipo_xlsform(tipo_xls), error = function(e) data.table::data.table(tipo_base = "text", list_name = ""))
    tipo_base <- as.character(tipo_hit$tipo_base[1L])
    if (is.na(tipo_base) || !nzchar(tipo_base)) tipo_base <- "text"
    if (is.na(list_xls) || !nzchar(list_xls)) list_xls <- as.character(tipo_hit$list_name[1L])

    parent <- sub("/[^/]+$", "", att)
    lab_limpo <- trimws(gsub("\\s+", " ", gsub("\\u200b", "", lab_xls)))
    lab_sem_dois <- sub(":$", "", lab_limpo)
    candidatos <- unique(c(
      att, att_final, nome_xls,
      if (nzchar(lab_limpo)) lab_limpo else character(0),
      if (nzchar(lab_sem_dois)) lab_sem_dois else character(0),
      if (nzchar(lab_limpo) && nzchar(parent)) paste0(lab_limpo, " (", parent, ")") else character(0),
      if (nzchar(lab_sem_dois) && nzchar(parent)) paste0(lab_sem_dois, ": (", parent, ")") else character(0),
      if (nzchar(lab_sem_dois) && nzchar(parent)) paste0(lab_sem_dois, " (", parent, ")") else character(0)
    ))
    candidatos <- candidatos[!is.na(candidatos) & nzchar(candidatos)]

 ### checar primeiro os candidatos EXATOS (att, att_final,
 ### nome_xls -- o name canônico do próprio atributo, com e sem o prefixo
 ### "amostragem/registro/") antes de monitora_validados_resolver_coluna .
 ### Esse resolvedor consulta monitora_validados_aliases_xlsform_historico ,
 ### que mapeia o atributo canônico para o RÓTULO histórico esperado (ex.:
 ### "A erva bromelioide observada é: (amostragem/registro)"); quando
 ### registros_corrig já traz a coluna canônica com o name CURTO (ex.:
 ### forma_vida_nativa_bromelioide, sem o prefixo), o resolvedor por alias
 ### ainda encontrava o rótulo histórico ambíguo primeiro (falso positivo) e
 ### nunca chegava a checar o candidato exato -- por isso o atributo curto,
 ### mesmo existindo fisicamente em registros_corrig, nunca era marcado
 ### atende_template_sismonitora=TRUE, ficando fora do seletor "Atributos a
 ### corrigir", enquanto o alias histórico aparecia como se fosse o
 ### atributo canônico. Preferir sempre o name canônico (exato) como
 ### identidade antes de qualquer resolução por rótulo/alias histórico.
    col <- NA_character_
    hit_exato <- candidatos[candidatos %in% nms]
    if (length(hit_exato)) col <- hit_exato[1L]
    if (is.na(col) || !nzchar(col)) {
      col_res <- tryCatch(monitora_validados_resolver_coluna(nms, att), error = function(e) NA_character_)
      if (!is.na(col_res) && nzchar(col_res) && col_res %in% nms) col <- col_res
    }
    if (is.na(col) || !nzchar(col)) {
      cand_norm <- monitora_correcao_normalizar_nome_coluna(candidatos)
      idx <- match(TRUE, nms_norm %in% cand_norm)
      if (!is.na(idx)) col <- nms[idx]
    }
    if (is.na(col) || !nzchar(col)) col <- att

    protegido <- isTRUE(monitora_correcao_coluna_protegida(col)) ||
      isTRUE(monitora_correcao_coluna_protegida(att)) ||
      grepl("(^|/)uuid$|foto|imagem|image", att, ignore.case = TRUE)
    tipos_bloq <- c("calculate", "hidden", "start", "end", "deviceid", "phonenumber", "barcode", "acknowledge", "rank", "range", "file", "image", "audio", "video")
    if (isTRUE(protegido) || tolower(tipo_base) %in% tipos_bloq) next

    rows[[ii]] <- data.table::data.table(
      atributo_coluna_registros_corrig = as.character(col),
      atende_template_sismonitora = TRUE,
      ordem_template_sismonitora = as.integer(pos_num),
      atributos_template_sismonitora = as.character(att),
      posicoes_template_sismonitora = as.character(pos_raw),
      estrategias_template_sismonitora = data.table::fifelse(col %in% nms, "coluna_existente_registros_corrig", "coluna_contratual_criada_pre_painel"),
      xlsform_name = nome_xls,
      xlsform_label = lab_xls,
      xlsform_tipo = tipo_xls,
      xlsform_tipo_base = tipo_base,
      xlsform_list_name = list_xls
    )
  }
  h <- data.table::rbindlist(rows, fill = TRUE, use.names = TRUE)
  if (!nrow(h)) {
    return(data.table::data.table(
      atributo_coluna_registros_corrig = character(), atende_template_sismonitora = logical(),
      ordem_template_sismonitora = integer(), atributos_template_sismonitora = character(),
      posicoes_template_sismonitora = character(), estrategias_template_sismonitora = character()
    ))
  }
  h <- h[!duplicated(atributo_coluna_registros_corrig)]
  data.table::setorder(h, ordem_template_sismonitora, atributo_coluna_registros_corrig)
  h[]
}

monitora_correcao_anotar_contrato_template_sismonitora <- function(d, dt) {
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório.", call. = FALSE)
  d <- data.table::as.data.table(data.table::copy(d))
  if (!("atributo_coluna_registros_corrig" %in% names(d))) return(d)
  heranca <- tryCatch(monitora_correcao_colunas_template_sismonitora(dt), error = function(e) data.table::data.table())
  cols_h <- c("atende_template_sismonitora", "ordem_template_sismonitora", "atributos_template_sismonitora", "posicoes_template_sismonitora", "estrategias_template_sismonitora")
  cols_h_existentes <- intersect(cols_h, names(d))
  if (length(cols_h_existentes)) d[, (cols_h_existentes) := NULL]
  if (nrow(heranca)) {
    cols_h_merge <- c("atributo_coluna_registros_corrig", cols_h)
    d <- merge(d, heranca[, ..cols_h_merge], by = "atributo_coluna_registros_corrig", all.x = TRUE, sort = FALSE)
  } else {
    d[, atende_template_sismonitora := FALSE]
    d[, atributos_template_sismonitora := ""]
    d[, posicoes_template_sismonitora := ""]
    d[, estrategias_template_sismonitora := ""]
  }
  for (cc in c("atende_template_sismonitora", "ordem_template_sismonitora", "atributos_template_sismonitora", "posicoes_template_sismonitora", "estrategias_template_sismonitora")) {
    if (!(cc %in% names(d))) d[, (cc) := if (identical(cc, "atende_template_sismonitora")) FALSE else if (identical(cc, "ordem_template_sismonitora")) NA_integer_ else ""]
  }
  d[is.na(atende_template_sismonitora), atende_template_sismonitora := FALSE]
  d[is.na(ordem_template_sismonitora), ordem_template_sismonitora := 999999L]
  for (cc in c("atributos_template_sismonitora", "posicoes_template_sismonitora", "estrategias_template_sismonitora")) {
    d[is.na(get(cc)), (cc) := ""]
  }
  d[]
}


monitora_correcao_colapsar_opcoes_msg <- function(opcoes, max_n = 35L) {
  opcoes <- unique(trimws(as.character(opcoes)))
  opcoes <- opcoes[!is.na(opcoes) & nzchar(opcoes)]
  if (!length(opcoes)) return("sem opções enumeradas no contrato")
  opcoes <- sort(opcoes)
  txt <- paste(utils::head(opcoes, max_n), collapse = ", ")
  if (length(opcoes) > max_n) txt <- paste0(txt, " ... [", length(opcoes), " opções no contrato]")
  txt
}

monitora_correcao_sugerir_opcoes_msg <- function(invalidos, opcoes, max_n = 5L) {
  invalidos <- unique(trimws(as.character(invalidos)))
  invalidos <- invalidos[!is.na(invalidos) & nzchar(invalidos)]
  opcoes <- unique(trimws(as.character(opcoes)))
  opcoes <- opcoes[!is.na(opcoes) & nzchar(opcoes)]
  if (!length(invalidos) || !length(opcoes)) return("")
  out <- character(0)
  for (inv in invalidos) {
    dd <- utils::adist(tolower(inv), tolower(opcoes))
    ord <- order(as.numeric(dd[1, ]), opcoes)
    cand <- opcoes[ord]
    cand <- cand[seq_len(min(max_n, length(cand)))]
    out <- c(out, paste0("Para '", inv, "', opções próximas: ", paste(cand, collapse = ", ")))
  }
  paste(out, collapse = "; ")
}

monitora_correcao_exemplos_formato_msg <- function(tipo_base, atributo = NA_character_) {
  tipo_base <- as.character(tipo_base)[1L]
  if (is.na(tipo_base)) tipo_base <- ""
 ### atributo é opcional (default NA) para manter
 ### compatibilidade com as chamadas já existentes em
 ### monitora_correcao_validar_formato_valor ; só adiciona dica de padrão
 ### para atributos administrativos específicos (UA/EA), sem criar nova lista
 ### de domínio nem restringir o valor a ela — é só texto de ajuda.
  att_final <- tolower(sub("^.*/", "", as.character(atributo)[1L]))
  if (!is.na(att_final) && identical(att_final, "ua")) {
    return("Padrão observado/contratual do atributo UA: ex. UA-001_VgCS. Informe o valor completo conforme o padrão já usado na coleta; não é restrito a uma lista de domínio.")
  }
  if (!is.na(att_final) && identical(att_final, "ea")) {
    return("Padrão observado/contratual do atributo EA: siga o padrão já usado no template/coleta para esta UC. Informe o valor completo; não é restrito a uma lista de domínio.")
  }
  if (tipo_base == "date") {
    return("Exemplo válido: 2025-05-23. Use exatamente YYYY-MM-DD; espaços, pontos, barras, texto e datas parciais são bloqueados.")
  }
  if (tipo_base == "datetime") {
    return("Exemplo válido: 2025-05-23T15:40:00-03:00. Use datetime ISO; espaços extras, pontos soltos, barras e texto são bloqueados.")
  }
  if (tipo_base == "time") {
    return("Exemplos válidos: 15:40; 15:40:00; 15:40:00.000-03:00. Use apenas caracteres do contrato de hora.")
  }
  if (tipo_base == "integer") return("Exemplo válido: 101. Use apenas número inteiro, sem texto adicional.")
  if (tipo_base == "decimal") return("Exemplo válido: 3.33. Use número decimal com ponto, sem vírgula, texto ou espaços.")
  if (tipo_base == "geopoint") {
    return("Exemplos válidos: -7.7267858 -63.7942423; -7.7267858 -63.7942423 88.8; -7.7267858 -63.7942423 88.8 3.33. Latitude e longitude são obrigatórias; altitude e acurácia são opcionais.")
  }
  if (tipo_base %in% c("select_one", "select_multiple")) return("Use exatamente os tokens definidos no contrato XLSForm vigente.")
  "Preencha conforme o tipo do campo no contrato XLSForm."
}

monitora_correcao_validar_formato_valor <- function(valor, tipo_base, acao, list_name = NA_character_, meta_xls = NULL, valor_original = NA_character_, escolhas_fallback = character(0)) {
  acao <- monitora_correcao_acao_normalizar(acao)
  tipo_base <- as.character(tipo_base)[1L]
  valor <- as.character(valor)[1L]
  valor_original <- as.character(valor_original)[1L]
  if (is.na(valor)) valor <- ""
  if (is.na(valor_original)) valor_original <- ""
  if (acao %in% c("clear", "recalcular_tipo_forma_vida")) return(list(ok = TRUE, status = "ok", mensagem = "formato compatível"))
  if (tipo_base %in% c("select_one", "select_multiple")) {
    escolhas <- monitora_correcao_choices_xlsform(list_name, meta_xls)
    if (!length(escolhas) && tipo_base == "select_one") {
      escolhas <- unique(trimws(as.character(escolhas_fallback)))
      escolhas <- escolhas[!is.na(escolhas) & nzchar(escolhas)]
    }
    if (!length(escolhas)) {
      return(list(ok = FALSE, status = "bloqueada_dominio_xlsform_ausente", mensagem = paste0("Correção bloqueada: o atributo usa lista XLSForm, mas o domínio de tokens não foi carregado para list_name='", list_name, "'.")))
    }
    if (tipo_base == "select_multiple" && acao %in% c("update", "substituir_valor", "clear", "limpar")) {
      return(list(ok = FALSE, status = "bloqueada_lista_tokens_sem_substituir_valor", mensagem = "Atributos de lista de tokens não aceitam substituir ou limpar o valor inteiro. Use Adicionar token, Remover token ou Substituir token."))
    }
    valor_validar <- valor
    if (acao %in% c("remove_token", "remover_token") && !nzchar(trimws(valor_validar))) valor_validar <- valor_original
    if (!nzchar(trimws(valor_validar))) {
      return(list(ok = FALSE, status = "bloqueada_valor_vazio", mensagem = "Informe o token/valor da operação. Em lista de tokens, use operação tokenizada; não substitua o valor inteiro do campo."))
    }
    if (tipo_base == "select_multiple" && acao %in% c("remove_token", "remover_token")) {
      return(list(ok = TRUE, status = "ok", mensagem = "remoção de token validada quanto à presença pela pré-condição operacional"))
    }
    toks <- if (tipo_base == "select_multiple") monitora_correcao_tokens_valor(valor_validar) else valor_validar
    invalidos <- setdiff(toks, escolhas)
    if (length(invalidos)) {
      opcoes_msg <- monitora_correcao_colapsar_opcoes_msg(escolhas)
      sugestoes_msg <- monitora_correcao_sugerir_opcoes_msg(invalidos, escolhas)
      msg <- paste0(
        "Valor/token fora do domínio XLSForm da lista '", list_name, "'. ",
        "Token(s) inválido(s): ", paste(invalidos, collapse = ", "), ". ",
        "Opções válidas: ", opcoes_msg, "."
      )
      if (nzchar(sugestoes_msg)) msg <- paste0(msg, " ", sugestoes_msg, ".")
      return(list(ok = FALSE, status = "bloqueada_dominio_xlsform", mensagem = msg))
    }
    return(list(ok = TRUE, status = "ok", mensagem = "domínio XLSForm compatível"))
  }
  if (!nzchar(trimws(valor))) return(list(ok = FALSE, status = "bloqueada_valor_vazio", mensagem = "valor novo vazio; use Limpar valor quando a ausência for permitida"))
  if (tipo_base == "date") {
    vv <- as.character(valor)[1L]
    ok <- grepl("^\\d{4}-\\d{2}-\\d{2}$", vv, perl = TRUE)
    if (!ok) return(list(ok = FALSE, status = "bloqueada_formato_data", mensagem = paste("Data inválida: use exatamente YYYY-MM-DD. Qualquer caractere fora desse contrato é bloqueado no painel.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    d <- suppressWarnings(as.Date(vv, format = "%Y-%m-%d"))
    if (is.na(d) || !identical(format(d, "%Y-%m-%d"), vv)) return(list(ok = FALSE, status = "bloqueada_formato_data", mensagem = paste("Data inexistente ou fora do contrato YYYY-MM-DD.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    return(list(ok = TRUE, status = "ok", mensagem = "data válida no contrato YYYY-MM-DD"))
  }
  if (tipo_base == "datetime") {
    vv <- as.character(valor)[1L]
    ok <- grepl("^\\d{4}-\\d{2}-\\d{2}[T ]([01]\\d|2[0-3]):[0-5]\\d(:[0-5]\\d(\\.\\d{1,3})?)?([+-]([01]\\d|2[0-3]):?[0-5]\\d|Z)?$", vv, perl = TRUE)
    if (!ok) return(list(ok = FALSE, status = "bloqueada_formato_datetime", mensagem = paste("Datetime inválido: use formato ISO compatível com o contrato, sem caracteres extras.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    return(list(ok = TRUE, status = "ok", mensagem = "datetime válido no contrato ISO"))
  }
  if (tipo_base == "time") {
    vv <- as.character(valor)[1L]
    ok <- grepl("^([01]\\d|2[0-3]):[0-5]\\d(:[0-5]\\d(\\.\\d{1,3})?)?([+-]([01]\\d|2[0-3]):?[0-5]\\d|Z)?$", vv, perl = TRUE)
    if (!ok) return(list(ok = FALSE, status = "bloqueada_formato_hora", mensagem = paste("Hora inválida: somente caracteres do contrato de hora são aceitos.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    return(list(ok = TRUE, status = "ok", mensagem = "hora válida"))
  }
  if (tipo_base == "integer") {
    vv <- as.character(valor)[1L]
    ok <- grepl("^-?\\d+$", vv, perl = TRUE)
    if (!ok) return(list(ok = FALSE, status = "bloqueada_formato_inteiro", mensagem = paste("Valor deve ser inteiro e conter apenas caracteres do contrato numérico inteiro.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    return(list(ok = TRUE, status = "ok", mensagem = "inteiro válido"))
  }
  if (tipo_base == "decimal") {
    vv <- as.character(valor)[1L]
    ok <- grepl("^-?\\d+(\\.\\d+)?$", vv, perl = TRUE)
    if (!ok) return(list(ok = FALSE, status = "bloqueada_formato_decimal", mensagem = paste("Valor deve ser decimal com ponto e conter apenas caracteres do contrato numérico decimal.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    num <- suppressWarnings(as.numeric(vv))
    if (!is.finite(num)) return(list(ok = FALSE, status = "bloqueada_formato_decimal", mensagem = paste("Valor decimal fora de faixa ou inválido.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    return(list(ok = TRUE, status = "ok", mensagem = "decimal válido"))
  }
  if (tipo_base == "geopoint") {
    vv <- as.character(valor)[1L]
    num_re <- "[-+]?\\d+(?:\\.\\d+)?"
    ok <- grepl(paste0("^", num_re, "\\s+", num_re, "(?:\\s+", num_re, "){0,2}$"), vv, perl = TRUE)
    if (!ok) return(list(ok = FALSE, status = "bloqueada_formato_geopoint", mensagem = paste("Coordenada inválida: use apenas 2 a 4 números separados por espaço, com ponto decimal.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    nums <- as.numeric(strsplit(vv, "\\s+", perl = TRUE)[[1L]])
    if (length(nums) < 2L || length(nums) > 4L || any(!is.finite(nums))) return(list(ok = FALSE, status = "bloqueada_formato_geopoint", mensagem = paste("Coordenada incompleta ou inválida.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    if (nums[1L] < -90 || nums[1L] > 90 || nums[2L] < -180 || nums[2L] > 180) return(list(ok = FALSE, status = "bloqueada_formato_geopoint", mensagem = paste("Latitude/longitude fora de faixa.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    return(list(ok = TRUE, status = "ok", mensagem = "geopoint válido"))
  }
  list(ok = TRUE, status = "ok", mensagem = "texto compatível")
}

monitora_correcao_validar_contrato_edicao <- function(dt, col, acao, valor_novo, corr_linha = NULL, dicionario = NULL, meta_xls = NULL) {
  col <- as.character(col)[1L]
  acao_norm <- monitora_correcao_acao_normalizar(acao)
  if (is.na(col) || !nzchar(col) || !(col %in% names(dt))) return(list(ok = FALSE, status = "falha", mensagem = "coluna de destino inexistente"))
 ### Campos de hábito podem estar materializados sob rótulos físicos
 ### históricos desambiguados (.1/.2), enquanto o perfil genérico do painel
 ### os mantém deliberadamente fora da lista "Atributos a corrigir". As
 ### operações semânticas não podem, porém, ser bloqueadas por essa decisão de
 ### UI quando o destino físico corresponde univocamente a um caminho
 ### required/select_one do XLSForm atual e ao schema SISMONITORA.
 ### Esta validação é restrita ao motor semântico: não altera dicionário,
 ### editabilidade, rótulos nem elementos exibidos no painel.
  regra_habito_fisica <- tryCatch(
    monitora_correcao_regra_habito_por_coluna_fisica(dt, col, meta_xls),
    error = function(e) data.table::data.table()
  )
  if (nrow(regra_habito_fisica) == 1L) {
    schema_atributos <- tryCatch(
      as.character(data.table::as.data.table(monitora_validados_schema_embutido())$atributo),
      error = function(e) character(0)
    )
    atributo_habito <- as.character(regra_habito_fisica$atributo_canonico[1L])
    if (!(atributo_habito %in% schema_atributos) ||
        !monitora_correcao_coluna_habito_segura(
          dt, col, regra_habito_fisica$categoria[1L], regra_habito_fisica$forma[1L]
        )) {
      return(list(ok = FALSE, status = "bloqueada_regra_xlsform_insegura", mensagem = paste0(
        "atributo físico de hábito sem correspondência unívoca XLSForm 2025 + template SISMONITORA: ", col
      )))
    }
    if (!(acao_norm %in% c("update", "clear"))) {
      return(list(ok = FALSE, status = "bloqueada_acao_incompativel", mensagem = paste0(
        "ação '", acao_norm, "' incompatível com hábito select_one canônico"
      )))
    }
    required_habito <- tolower(trimws(as.character(regra_habito_fisica$required[1L]))) %in% c("yes", "true", "1", "sim")
    if (isTRUE(required_habito) && identical(acao_norm, "clear")) {
      return(list(ok = FALSE, status = "bloqueada_acao_incompativel", mensagem = "campo de hábito required não pode ser limpo por edição direta enquanto relevante"))
    }
    valor_original <- if (!is.null(corr_linha) && "valor_original_esperado" %in% names(corr_linha)) as.character(corr_linha$valor_original_esperado[1L]) else NA_character_
    return(monitora_correcao_validar_formato_valor(
      valor_novo, "select_one", acao_norm,
      as.character(regra_habito_fisica$list_name[1L]), meta_xls,
      valor_original, escolhas_fallback = unique(as.character(dt[[col]]))
    ))
  }
 ### ### monitora_correcao_contrato_edicao reaplica o gate "escopos_permitidos_
 ### contrato_unico vazio -> painel_editavel=FALSE; acoes_permitidas=''" (regra
 ### pré-existente, não criada aqui) sempre que o `dicionario` de entrada já
 ### carrega escopo_operacional_contrato_unico/escopos_permitidos_contrato_unico
 ### (mesclados por monitora_correcao_dicionario_atributos ). A resolução de
 ### atributo_canonico_2025 usada por esse gate (monitora_perfil_painel_edicao_
 ### operacional_contrato_unico ) falha sistematicamente tanto para colunas
 ### administrativas (UC/CICLO/CAMPANHA/EA/UA/...) quanto, na prática observada
 ### na validação operacional, para colunas reais do XLSForm como forma_vida_nativa — motivo
 ### "atributo nao resolvido no perfil_painel_edicao" — bloqueando com
 ### "bloqueada_regra_xlsform_insegura" atributos que o próprio dict do painel
 ### já reconhece como editáveis (mesmo bug de consumo corrigido no ajuste
 ### 0-H2C para monitora_painel_acoes_atributo /monitora_painel_info_contrato_
 ### atributo ; aqui o ponto de consumo é esta validação, usada tanto por
 ### monitora_painel_validar_entrada quanto pela aplicação atômica de TRIDESC).
 ### Corrigido removendo apenas esses 3 campos do dicionário antes de repassar a
 ### monitora_correcao_contrato_edicao — a função e sua regra de gate
 ### permanecem intocadas; nenhuma coluna nem regra nova foi criada.
  dicionario_validacao <- if (!is.null(dicionario) && nrow(data.table::as.data.table(dicionario))) {
    data.table::as.data.table(dicionario)
  } else {
    monitora_correcao_dicionario_atributos(dt, meta_xls)
  }
  cols_gate_escopo_cu <- intersect(
    c("escopo_operacional_contrato_unico", "escopos_permitidos_contrato_unico", "motivo_escopo_contrato_unico"),
    names(dicionario_validacao)
  )
  if (length(cols_gate_escopo_cu)) {
    dicionario_validacao <- dicionario_validacao[, setdiff(names(dicionario_validacao), cols_gate_escopo_cu), with = FALSE]
  }
  contrato <- monitora_correcao_contrato_edicao(dt, meta_xls, dicionario_validacao)
  info <- contrato[atributo_coluna_registros_corrig == col]
  if (!nrow(info)) return(list(ok = FALSE, status = "bloqueada_contrato_ausente", mensagem = paste0("atributo sem contrato de edição: ", col)))
  info <- info[1L]
  if (!isTRUE(info$painel_editavel)) {
    return(list(ok = FALSE, status = "bloqueada_regra_xlsform_insegura", mensagem = paste0("edição bloqueada para '", col, "': ", info$painel_motivo_bloqueio)))
  }
  acoes <- monitora_correcao_split_serial(info$acoes_permitidas)
  if (!(acao_norm %in% acoes)) {
    return(list(ok = FALSE, status = "bloqueada_acao_incompativel", mensagem = paste0("ação '", acao_norm, "' não permitida para '", col, "' (tipo=", info$tipo_base_edicao, "; ações permitidas=", paste(acoes, collapse = ", "), ")")))
  }
  valor_original <- if (!is.null(corr_linha) && "valor_original_esperado" %in% names(corr_linha)) as.character(corr_linha$valor_original_esperado[1L]) else NA_character_
  escolhas_fallback <- character(0)
  if (identical(as.character(info$tipo_base_edicao[1L]), "select_one") && col %in% names(dt)) {
    escolhas_fallback <- unique(trimws(as.character(dt[[col]])))
    escolhas_fallback <- escolhas_fallback[!is.na(escolhas_fallback) & nzchar(escolhas_fallback)]
  }
  monitora_correcao_validar_formato_valor(valor_novo, info$tipo_base_edicao, acao_norm, info$xlsform_list_name, meta_xls, valor_original, escolhas_fallback = escolhas_fallback)
}

monitora_correcao_validar_destino_operacao <- function(dt, col, acao, valor_novo, corr_linha, dicionario = NULL, meta_xls = NULL) {
  if (is.na(col) || !nzchar(col) || !(col %in% names(dt))) {
    return(list(ok = FALSE, status = "falha", mensagem = "coluna de destino inexistente"))
  }
  valid_contrato <- monitora_correcao_validar_contrato_edicao(dt, col, acao, valor_novo, corr_linha, dicionario = dicionario, meta_xls = meta_xls)
  if (!isTRUE(valid_contrato$ok)) return(valid_contrato)
  papel <- monitora_correcao_papel_coluna_canonico(col)
  acao <- monitora_correcao_acao_normalizar(acao)
  valor <- as.character(valor_novo)[1L]
  valor_norm_tokens <- monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokenizar(valor))
  forma_tokens <- setdiff(monitora_correcao_tokens_forma_vida_catalogo(), c("outra", "outros", "desconhecida"))
  forma_tokens_norm <- monitora_correcao_normalizar_nome_coluna(forma_tokens)
  habitos_norm <- monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokens_habito_catalogo())
  token_pai <- if ("token_pai" %in% names(corr_linha)) as.character(corr_linha$token_pai[1L]) else NA_character_
  forma_escolhida <- if ("forma_valida_escolhida" %in% names(corr_linha)) as.character(corr_linha$forma_valida_escolhida[1L]) else NA_character_
  categoria_destino <- if ("categoria_destino" %in% names(corr_linha)) as.character(corr_linha$categoria_destino[1L]) else NA_character_
  tipo_corr <- if ("tipo_correcao" %in% names(corr_linha)) as.character(corr_linha$tipo_correcao[1L]) else ""

  grava_forma <- length(intersect(valor_norm_tokens, forma_tokens_norm)) > 0L
  if (acao %in% c("append_token", "adicionar_token") && monitora_correcao_normalizar_nome_coluna(forma_escolhida) %in% forma_tokens_norm) grava_forma <- TRUE
  grava_habito <- length(intersect(valor_norm_tokens, habitos_norm)) > 0L

  if (acao %in% c("append_token", "adicionar_token", "update", "substituir_valor") && isTRUE(grava_forma) && papel %in% c("especie_nome_popular", "atributo_dependente_habito")) {
    return(list(ok = FALSE, status = "bloqueada_destino_semantico", mensagem = paste0("token de forma de vida não pode ser gravado em coluna com papel ", papel, ": ", col)))
  }
  if (acao %in% c("append_token", "adicionar_token") && isTRUE(grava_forma) && !identical(papel, "lista_principal_forma_vida") && categoria_destino %in% c("nativa", "exotica", "seca_morta")) {
    return(list(ok = FALSE, status = "bloqueada_destino_semantico", mensagem = paste0("adição de forma de vida exige lista principal; papel encontrado=", papel, ": ", col)))
  }
  if (isTRUE(grava_habito) && !identical(papel, "atributo_dependente_habito")) {
    return(list(ok = FALSE, status = "bloqueada_destino_semantico", mensagem = paste0("hábito/atributo dependente exige coluna de hábito; papel encontrado=", papel, ": ", col)))
  }
  if (identical(papel, "lista_principal_forma_vida") && isTRUE(grava_habito)) {
    return(list(ok = FALSE, status = "bloqueada_destino_semantico", mensagem = "hábito não pode ser gravado em lista principal de forma de vida"))
  }
  list(ok = TRUE, status = "ok", mensagem = "destino semanticamente compatível")
}


monitora_correcao_atributo_lote_multicoletas_seguro <- function(dt, col, chaves = monitora_correcao_colunas_chave(dt)) {
  col <- as.character(col)[1L]
  if (is.na(col) || !nzchar(col) || !(col %in% names(dt))) {
    return(list(ok = FALSE, status = "falha", mensagem = "atributo inexistente para lote de COLETAS"))
  }
  if (monitora_correcao_coluna_protegida(col)) {
    return(list(ok = FALSE, status = "bloqueada_coluna_protegida", mensagem = paste0("coluna estrutural/protegida não pode ser alterada em lote: ", col)))
  }
  papel <- monitora_correcao_papel_coluna_canonico(col)
  if (identical(papel, "lista_principal_forma_vida")) {
    return(list(ok = TRUE, status = "ok_lista_principal_forma_vida", mensagem = paste0("lista principal de forma de vida elegível para operação tokenizada/contextual: ", col)))
  }
  if (papel %in% c("atributo_dependente_habito", "especie_nome_popular", "campo_superior_tipo_forma_vida")) {
    return(list(ok = FALSE, status = "bloqueada_destino_semantico", mensagem = paste0("atributo com papel '", papel, "' não é elegível para lote de COLETAS: ", col)))
  }
  col_norm <- monitora_correcao_normalizar_nome_coluna(col)
  padroes_bloqueio <- c("ponto_amostral", "ponto_metro", "tipo_forma_vida", "forma_vida", "especie", "especies", "exotica", "nativa", "seca_morta", "encostam", "vareta")
  if (any(grepl(paste(padroes_bloqueio, collapse = "|"), col_norm, perl = TRUE))) {
    return(list(ok = FALSE, status = "bloqueada_destino_semantico", mensagem = paste0("atributo parece ser de nível do ponto/forma de vida e foi bloqueado para lote de COLETAS: ", col)))
  }
  list(ok = TRUE, status = "ok", mensagem = "atributo elegível para lote de COLETAS")
}

monitora_correcao_valores_uniformes_linhas <- function(dt, linhas, col) {
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas) || is.na(col) || !(col %in% names(dt))) {
    return(list(ok = FALSE, n_valores = NA_integer_, valor_resumo = NA_character_))
  }
  vals <- as.character(dt[[col]][linhas])
  vals_norm <- monitora_correcao_na_para_vazio(vals)
  vals_norm[is.na(vals_norm)] <- ""
  vals_unicos_norm <- unique(trimws(vals_norm))
  vals_unicos_norm <- vals_unicos_norm[!is.na(vals_unicos_norm)]
  vals_unicos_orig <- unique(vals)
  valor_resumo <- monitora_correcao_colapsar_contexto_valores(vals_unicos_orig)
  list(ok = length(vals_unicos_norm) <= 1L, n_valores = length(vals_unicos_norm), valor_resumo = valor_resumo)
}



monitora_correcao_acao_exclusao_coleta <- function(acao, tipo_correcao = "") {
  acao <- tolower(trimws(as.character(acao)[1L]))
  tipo_correcao <- tolower(trimws(as.character(tipo_correcao)[1L]))
  if (is.na(acao)) acao <- ""
  if (is.na(tipo_correcao)) tipo_correcao <- ""
  acao %in% c("excluir_coleta", "delete_coleta", "delete_collection", "excluir_registros_coleta") ||
    grepl("exclusao_coleta", tipo_correcao, fixed = TRUE) ||
    grepl("excluir_coleta", tipo_correcao, fixed = TRUE)
}

monitora_correcao_prevalidar_operacao <- function(dt, linha_corr, chaves, dicionario = NULL, indice = NULL) {
  col_req <- as.character(linha_corr$atributo_coluna_registros_corrig[1])
  col <- monitora_correcao_resolver_coluna_operacao(dt, linha_corr, dicionario)
  acao <- tolower(trimws(as.character(linha_corr$acao[1])))
  linhas <- monitora_correcao_linhas_alvo_operacao(dt, linha_corr, chaves, indice)
  linhas <- monitora_correcao_aplicar_escopo_conciliado(dt, linhas, linha_corr)
  n_esperado <- suppressWarnings(as.integer(linha_corr$n_linhas_esperado[1]))
  status <- "ok"; msg <- "OK"
  tipo_corr <- if ("tipo_correcao" %in% names(linha_corr)) tolower(trimws(as.character(linha_corr$tipo_correcao[1]))) else ""
  if (is.na(tipo_corr)) tipo_corr <- ""
  if (isTRUE(monitora_correcao_acao_exclusao_coleta(acao, tipo_corr))) {
    escopo_corr <- if ("escopo_aplicacao" %in% names(linha_corr)) tolower(trimws(as.character(linha_corr$escopo_aplicacao[1]))) else ""
    if (is.na(escopo_corr)) escopo_corr <- ""
    if (!identical(escopo_corr, "coleta_inteira")) {
      status <- "bloqueada_exclusao_coleta"; msg <- "exclusão de COLETA exige escopo_aplicacao='coleta_inteira'"
    } else if (is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) {
      status <- "falha"; msg <- "Coluna de COLETA não localizada; exclusão bloqueada"
    } else if (length(linhas) == 0L) {
      status <- "falha"; msg <- "Nenhuma linha-alvo localizada para exclusão da COLETA"
    } else if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) {
      status <- "falha"; msg <- paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado, " para exclusão da COLETA")
    }
    return(data.table::data.table(status_prevalidacao = status, mensagem_prevalidacao = msg, atributo_resolvido = chaves$coleta, n_linhas = length(linhas)))
  }
  if (acao %in% c("recalcular_tipo_forma_vida", "atualizar_tipo_forma_vida")) {
    if (length(linhas) == 0L) {
      status <- "falha"; msg <- "Nenhuma linha-alvo localizada para recalcular tipo_forma_vida"
    } else if (is.na(chaves$tipo_forma_vida) || !(chaves$tipo_forma_vida %in% names(dt))) {
      status <- "falha"; msg <- "Coluna tipo_forma_vida/Encostam não localizada para recálculo"
    }
    return(data.table::data.table(status_prevalidacao = status, mensagem_prevalidacao = msg, atributo_resolvido = chaves$tipo_forma_vida, n_linhas = length(linhas)))
  }
  if (!is.na(col) && col %in% names(dt) && monitora_correcao_coluna_protegida(col)) {
    status <- "bloqueada_coluna_protegida"; msg <- paste0("Correção bloqueada: coluna estrutural/protegida não pode ser alterada: ", col)
  } else if (monitora_correcao_coluna_protegida(col_req)) {
    status <- "bloqueada_coluna_protegida"; msg <- paste0("Correção bloqueada: atributo solicitado é coluna estrutural/protegida: ", col_req)
  } else if (is.na(col) || !(col %in% names(dt))) {
    status <- "falha"; msg <- paste0("Coluna não encontrada: ", col_req)
  } else if (length(linhas) == 0L) {
    status <- "falha"; msg <- "Nenhuma linha-alvo localizada"
  } else if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) {
    status <- "falha"; msg <- paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado)
  } else {
    if (grepl("lote_multicoletas", tipo_corr, fixed = TRUE)) {
      escopo_corr <- if ("escopo_aplicacao" %in% names(linha_corr)) tolower(trimws(as.character(linha_corr$escopo_aplicacao[1]))) else ""
      if (is.na(escopo_corr)) escopo_corr <- ""
      if (!identical(escopo_corr, "coleta_inteira")) {
        status <- "bloqueada_lote_multicoletas"; msg <- "lote de COLETAS exige escopo_aplicacao='coleta_inteira'"
      } else if (!(acao %in% c("update", "substituir_valor", "clear", "limpar"))) {
        status <- "bloqueada_lote_multicoletas"; msg <- "lote de COLETAS permite apenas substituir valor ou limpar valor"
      } else {
        valid_lote <- monitora_correcao_atributo_lote_multicoletas_seguro(dt, col, chaves)
        if (!isTRUE(valid_lote$ok)) {
          status <- valid_lote$status; msg <- valid_lote$mensagem
        } else {
          unif <- monitora_correcao_valores_uniformes_linhas(dt, linhas, col)
          if (!isTRUE(unif$ok)) {
            status <- "bloqueada_lote_multicoletas"
            msg <- paste0("atributo não é uniforme nas linhas-alvo da coleta; n_valores_atuais=", unif$n_valores, "; valor_resumo=", unif$valor_resumo)
          }
        }
      }
    }
    valid_dest <- if (identical(status, "ok")) monitora_correcao_validar_destino_operacao(dt, col, acao, linha_corr$valor_novo[1], linha_corr, dicionario) else list(ok = FALSE, status = status, mensagem = msg)
    if (!isTRUE(valid_dest$ok)) {
      status <- valid_dest$status; msg <- valid_dest$mensagem
    } else {
      valor_atual <- as.character(dt[[col]][linhas])
      esperado <- linha_corr$valor_original_esperado[1]
      id_corr <- if ("id_correcao" %in% names(linha_corr)) toupper(trimws(as.character(linha_corr$id_correcao[1]))) else ""
      eh_sanhab <- grepl("^SANHAB", id_corr) || identical(tipo_corr, "sanitizacao_habito_obrigatorio_ausente")
 ### uma fila SANHAB pode ficar obsoleta depois de uma correção
 ### específica ou de uma reconciliação. Revalida a precondição no motor
 ### atômico e nunca sobrescreve hábito contratual já preenchido.
      atual_norm <- tolower(trimws(valor_atual))
      if (isTRUE(eh_sanhab) && any(!is.na(atual_norm) & atual_norm %in% c("terrestre", "epifita", "rupicola"))) {
        status <- "bloqueada_sanhab_alvo_ja_preenchido"
        msg <- "SANHAB bloqueada: o hábito-alvo já está preenchido; preservar correção específica/valor reconciliado"
      } else {
        precond <- monitora_publicacao_d_precondicao_valor_original(valor_atual, acao, linha_corr$valor_novo[1], esperado)
        if (!isTRUE(precond$ok)) {
          status <- "falha"
          msg <- precond$mensagem
        } else if (!identical(precond$mensagem, "OK")) {
          msg <- precond$mensagem
        }
      }
    }
  }
  data.table::data.table(status_prevalidacao = status, mensagem_prevalidacao = msg, atributo_resolvido = col, n_linhas = length(linhas))
}

### reconcilia SANHAB com a fonte diagnóstica única imediatamente antes
### da transação. Filas antigas, exclusões e correções específicas podem mudar
### o conjunto de alvos desde o clique; somente ocorrências que continuam com
### hábito efetivamente vazio permanecem. Alvo preenchido é auditado e retirado
### sem bloquear os demais itens do mesmo grupo.
monitora_correcao_reconciliar_sanhab_estado_corrente <- function(dt, corr, chaves, dicionario = NULL, indice = NULL, arquivo_correcao = NA_character_) {
  dt <- data.table::as.data.table(dt)
  corr <- data.table::copy(data.table::as.data.table(corr))
  vazio <- list(corr = corr, audit = data.table::data.table(), n_removidos = 0L)
  if (!nrow(corr)) return(vazio)
  fam <- monitora_correcao_classificar_tipo_operacao(corr)
  idx_san <- which(fam == "sanitizacao_habito_obrigatorio_ausente")
  if (!length(idx_san)) return(vazio)
  det <- tryCatch(
    monitora_correcao_ocorrencias_habito_detalhadas(dt),
    error = function(e) stop("SANHAB não pôde ser reconciliada com o diagnóstico atual: ", conditionMessage(e), call. = FALSE)
  )
  audit <- list()
  remover <- integer()
  n_rem <- 0L
  for (ii in idx_san) {
    op <- corr[ii]
    linhas <- monitora_correcao_linhas_alvo_operacao(dt, op, chaves, indice)
    linhas <- monitora_correcao_aplicar_escopo_conciliado(dt, linhas, op)
    regra_op <- tryCatch(monitora_correcao_regra_habito_operacao(op), error = function(e) data.table::data.table())
    col <- monitora_correcao_resolver_coluna_operacao(dt, op, dicionario)
    cat_op <- if (nrow(regra_op) == 1L) as.character(regra_op$categoria[1L]) else NA_character_
    forma_op <- if (nrow(regra_op) == 1L) as.character(regra_op$forma[1L]) else NA_character_
    det_att <- if (nrow(det)) det[
      linha_indice %in% linhas & categoria_superior == cat_op &
        monitora_correcao_normalizar_forma_habito(forma_de_vida_detectada) == forma_op
    ] else data.table::data.table()
    linhas_det <- unique(as.integer(det_att$linha_indice))
    linhas_det <- linhas_det[!is.na(linhas_det) & linhas_det >= 1L & linhas_det <= nrow(dt)]
 ### SANHAB trata ausência. Valor não vazio fora do domínio permanece para
 ### correção específica, sem perda silenciosa do conteúdo observado.
    linhas_ef <- if (!is.na(col) && col %in% names(dt)) {
      linhas_det[monitora_correcao_vazio_vec(dt[[col]][linhas_det])]
    } else integer(0)
    linhas_retiradas <- setdiff(linhas, linhas_ef)
    ids_ef <- if (MONITORA_COL_ROW_ID %in% names(dt)) as.character(dt[[MONITORA_COL_ROW_ID]][linhas_ef]) else character(0)
    ids_ret <- if (MONITORA_COL_ROW_ID %in% names(dt)) as.character(dt[[MONITORA_COL_ROW_ID]][linhas_retiradas]) else character(0)
    ids_ret_ant <- if ("alvos_excluidos_monitora_row_id" %in% names(corr)) monitora_correcao_parse_ids_estaveis(corr$alvos_excluidos_monitora_row_id[ii]) else character(0)
    for (cc in c("alvos_efetivos_monitora_row_id", "alvos_excluidos_monitora_row_id", "linhas_alvo_efetivas_serializadas")) {
      if (!(cc %in% names(corr))) data.table::set(corr, j = cc, value = NA_character_)
    }
    data.table::set(corr, i = ii, j = "alvos_efetivos_monitora_row_id", value = monitora_correcao_serializar_ids_estaveis(ids_ef))
    data.table::set(corr, i = ii, j = "alvos_excluidos_monitora_row_id", value = monitora_correcao_serializar_ids_estaveis(unique(c(ids_ret_ant, ids_ret))))
    data.table::set(corr, i = ii, j = "linhas_alvo_efetivas_serializadas", value = monitora_correcao_colapsar_lista_serializada(as.character(linhas_ef)))
    for (cc in intersect(c("n_linhas_esperado", "n_linhas_alvo", "n_linhas_efetivas", "n_itens_efetivos", "n_itens_auditaveis"), names(corr))) {
      data.table::set(corr, i = ii, j = cc, value = as.integer(length(linhas_ef)))
    }
    if ("n_linhas_excluidas" %in% names(corr)) data.table::set(corr, i = ii, j = "n_linhas_excluidas", value = as.integer(length(unique(c(ids_ret_ant, ids_ret)))))
    if ("status_conciliacao_semantica" %in% names(corr)) {
      data.table::set(corr, i = ii, j = "status_conciliacao_semantica", value = if (length(linhas_retiradas)) "reconciliada_diagnostico_atual_remove_alvos_resolvidos" else "reconciliada_diagnostico_atual_sem_divergencia")
    }
    if (length(linhas_retiradas)) {
      n_rem <- n_rem + length(linhas_retiradas)
      audit[[length(audit) + 1L]] <- data.table::data.table(
        id_correcao = as.character(op$id_correcao[1L]),
        ordem_operacao = as.character(op$ordem_operacao[1L]),
        status = "ok_sanhab_alvo_fora_diagnostico_atual_preservado",
        mensagem = "Alvo SANHAB retirado no estado corrente: hábito já preenchido, inválido não vazio, excluído ou fora da ocorrência diagnóstica atual",
        atributo = as.character(col)[1L], linha_indice = linhas_retiradas,
        valor_antes = if (!is.na(col) && col %in% names(dt)) as.character(dt[[col]][linhas_retiradas]) else NA_character_,
        valor_depois = if (!is.na(col) && col %in% names(dt)) as.character(dt[[col]][linhas_retiradas]) else NA_character_,
        arquivo_correcao = arquivo_correcao
      )
    }
    if (!length(linhas_ef)) remover <- c(remover, ii)
  }
  if (length(remover)) corr <- corr[-unique(remover)]
  list(
    corr = corr[],
    audit = if (length(audit)) data.table::rbindlist(audit, fill = TRUE, use.names = TRUE) else data.table::data.table(),
    n_removidos = n_rem
  )
}


monitora_correcao_comparar_auditoria_semantica_pre_pos <- function(pre, pos, contexto = "correcoes") {
  pre <- data.table::as.data.table(pre)
  pos <- data.table::as.data.table(pos)
  chave_cols <- c("tipo_achado", "coluna", "linha_indice", "valor")
  for (cc in chave_cols) {
    if (!(cc %in% names(pre))) pre[, (cc) := NA_character_]
    if (!(cc %in% names(pos))) pos[, (cc) := NA_character_]
  }
  if ("linha_indice" %in% names(pre)) pre[, linha_indice := as.integer(linha_indice)]
  if ("linha_indice" %in% names(pos)) pos[, linha_indice := as.integer(linha_indice)]
  pre_key <- unique(pre[, ..chave_cols])
  pos_key <- unique(pos[, ..chave_cols])
  pre_key[, achado_pre := TRUE]
  pos_key[, achado_pos := TRUE]
  comp <- merge(pre_key, pos_key, by = chave_cols, all = TRUE)
  comp[is.na(achado_pre), achado_pre := FALSE]
  comp[is.na(achado_pos), achado_pos := FALSE]
  comp[, classificacao := data.table::fcase(
    achado_pre == FALSE & achado_pos == TRUE, "erro_introduzido_pela_correcao",
    achado_pre == TRUE & achado_pos == TRUE, "erro_pre_existente_mantido",
    achado_pre == TRUE & achado_pos == FALSE, "erro_pre_existente_corrigido",
    default = "sem_classificacao"
  )]
  arq <- file.path(if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) get("MONITORA_CORRECOES_DIR", inherits = TRUE) else file.path("output", "correcoes_campos"), paste0("auditoria_semantica_papeis_colunas_pre_pos_", contexto, ".csv"))
  dir.create(dirname(arq), recursive = TRUE, showWarnings = FALSE)
  try(monitora_fwrite(comp, arq, na = ""), silent = TRUE)
  try(monitora_fwrite(comp, file.path(dirname(arq), "auditoria_semantica_papeis_colunas_pre_pos_ultima_execucao.csv"), na = ""), silent = TRUE)
  comp[]
}

monitora_correcao_auditar_lotes_multicoletas <- function(dt, corr, linhas_list, chaves, arquivo_correcao = NA_character_) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(data.table::data.table())
  tipo <- if ("tipo_correcao" %in% names(corr)) tolower(trimws(as.character(corr$tipo_correcao))) else rep("", nrow(corr))
  idx_lote <- which(grepl("lote_multicoletas", tipo, fixed = TRUE))
  if (!length(idx_lote)) return(data.table::data.table())
  pegar <- function(ii, nm) if (nm %in% names(corr)) as.character(corr[[nm]][ii]) else NA_character_
  out <- vector("list", length(idx_lote))
  for (kk in seq_along(idx_lote)) {
    ii <- idx_lote[kk]
    linhas <- if (length(linhas_list) >= ii) as.integer(linhas_list[[ii]]) else integer(0)
    linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
    col <- pegar(ii, "atributo_coluna_registros_corrig")
    unif <- if (col %in% names(dt)) monitora_correcao_valores_uniformes_linhas(dt, linhas, col) else list(ok = FALSE, n_valores = NA_integer_, valor_resumo = NA_character_)
    n_exp <- suppressWarnings(as.integer(pegar(ii, "n_linhas_esperado")))
    out[[kk]] <- data.table::data.table(
      id_correcao = pegar(ii, "id_correcao"),
      ordem_operacao = suppressWarnings(as.integer(pegar(ii, "ordem_operacao"))),
      tipo_correcao = pegar(ii, "tipo_correcao"),
      escopo_aplicacao = pegar(ii, "escopo_aplicacao"),
      coleta = pegar(ii, "coleta"),
      coleta_uuid = pegar(ii, "coleta_uuid"),
      UC = pegar(ii, "UC"),
      EA = pegar(ii, "EA"),
      UA = pegar(ii, "UA"),
      CICLO = pegar(ii, "CICLO"),
      CAMPANHA = pegar(ii, "CAMPANHA"),
      ANO = pegar(ii, "ANO"),
      `Data (data_hora)` = pegar(ii, "Data (data_hora)"),
      atributo_coluna_registros_corrig = col,
      acao = pegar(ii, "acao"),
      valor_original_esperado = pegar(ii, "valor_original_esperado"),
      valor_novo = pegar(ii, "valor_novo"),
      n_linhas_esperado = n_exp,
      n_linhas_alvo_localizadas = length(linhas),
      n_valores_atuais_no_atributo = unif$n_valores,
      atributo_uniforme_na_coleta = isTRUE(unif$ok),
      valor_atual_resumo = unif$valor_resumo,
      status_pre_auditoria_lote = ifelse(isTRUE(unif$ok) && !is.na(n_exp) && length(linhas) == n_exp, "ok", "revisar"),
      arquivo_correcao = arquivo_correcao
    )
  }
  aud <- data.table::rbindlist(out, fill = TRUE, use.names = TRUE)
  if (nrow(aud) > 0L) {
    saida <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_lote_multicoletas_", MONITORA_EXEC_ID, ".csv"))
    monitora_fwrite(aud, saida, na = "")
    monitora_fwrite(aud, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_lote_multicoletas_ultima_execucao.csv"), na = "")
    nivel <- if (any(aud$status_pre_auditoria_lote != "ok", na.rm = TRUE)) "AVISO" else "INFO"
    monitora_log_registrar_evento(
      "correcoes_campos_lote_multicoletas", nivel, saida,
      paste0(nrow(aud), " operação(ões) de lote multicoletas pré-auditada(s)"),
      "uma operação por COLETA; alterações linha a linha continuam na auditoria principal"
    )
  }
  aud[]
}


### Movimento atômico em lote de formas de vida
### -------------------------------------------------------------------------
### Operação semântica para mover uma ou mais formas de vida entre listas
### nativa/exótica/seca-morta em várias COLETAS. O lote é validado antes de
### qualquer escrita. Ocorrências ambíguas são separadas, mantidas sem
### alteração e relatadas; as demais ocorrências migráveis seguem no lote.
monitora_correcao_eh_operacao_movimento_forma_vida_lote <- function(corr) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(logical(0))
  idc <- if ("id_correcao" %in% names(corr)) trimws(as.character(corr$id_correcao)) else rep("", nrow(corr))
  tipo <- if ("tipo_correcao" %in% names(corr)) tolower(trimws(as.character(corr$tipo_correcao))) else rep("", nrow(corr))
  acao <- if ("acao" %in% names(corr)) tolower(trimws(as.character(corr$acao))) else rep("", nrow(corr))
  atributo <- if ("atributo_coluna_registros_corrig" %in% names(corr)) tolower(trimws(as.character(corr$atributo_coluna_registros_corrig))) else rep("", nrow(corr))
  grepl("^MVLOTE_", idc) |
    tipo %in% c("movimento_forma_vida_lote_atomico", "movimento_lote_forma_vida_atomico") |
    acao %in% c("mover_forma_vida_lote", "movimento_forma_vida_lote_atomico") |
    atributo %in% c("__mover_forma_vida_lote__", "__movimento_forma_vida_lote__")
}

monitora_correcao_forma_canonica_lote <- function(x) {
  x <- as.character(x)
  if (!length(x)) return(character(0))
  z <- tryCatch(monitora_relatorio_exoticas_normalizar_token(x), error = function(e) monitora_correcao_normalizar_nome_coluna(x))
  z <- monitora_correcao_normalizar_nome_coluna(z)
  z[z == "liana"] <- "lianas"
  z[z == "ervas_bromelioides"] <- "bromelioide"
  z[z == "erva_bromelioide"] <- "bromelioide"
  z[z == "bromelia"] <- "bromelioide"
  z[z == "bromelias"] <- "bromelioide"
  z[z == "cacto"] <- "cactacea"
  z[z == "cactos"] <- "cactacea"
  z[z == "orquideas"] <- "orquidea"
  z[z == "samambaias"] <- "samambaia"
  z <- unique(z[!is.na(z) & nzchar(z)])
  z
}

monitora_correcao_localizar_linhas_movimento_lote <- function(dt, linha_lote, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  linha_lote <- data.table::as.data.table(linha_lote)
  if (!nrow(dt) || !nrow(linha_lote)) return(integer(0))

 ### quando o MVLOTE representa a correção semântica de
 ### "desconhecida" em uma categoria-base, as linhas serializadas da
 ### sessão anterior não são estáveis entre versões/reruns. Nesse caso,
 ### o replay deve reconstruir o escopo por COLETA no estado corrente; a
 ### filtragem fina da ocorrência desconhecida é feita depois por
 ### monitora_correcao_linhas_desconhecida_categoria_base .
  mv_desc_vals <- character(0)
  for (cc_mv in intersect(c("escopo_diagnostico_mvlote", "categoria_base_diagnostica", "token_pai", "token_removido", "valor_original_esperado"), names(linha_lote))) {
    mv_desc_vals <- c(mv_desc_vals, as.character(linha_lote[[cc_mv]][1L]))
  }
  mv_desc_norm <- tryCatch(monitora_correcao_limpar_texto(mv_desc_vals), error = function(e) tolower(trimws(mv_desc_vals)))
  mv_desc_semantica <- any(mv_desc_norm %in% c("forma_vida_desconhecida_categoria_base", "forma_vida_desconhecida", "desconhecida", "desconhecido"), na.rm = TRUE)
  if (isTRUE(mv_desc_semantica) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt) && "coleta" %in% names(linha_lote)) {
    coletas_desc <- monitora_correcao_parse_lista_serializada(linha_lote$coleta[1L])
    coletas_desc <- unique(as.character(coletas_desc))
    coletas_desc <- coletas_desc[!is.na(coletas_desc) & nzchar(trimws(coletas_desc))]
    if (length(coletas_desc)) {
      idx_coletas_desc <- which(as.character(dt[[chaves$coleta]]) %chin% coletas_desc)
      idx_coletas_desc <- unique(as.integer(idx_coletas_desc))
      if (length(idx_coletas_desc)) return(idx_coletas_desc)
    }
  }

 ### diagnóstico: MVLOTE pode carregar um escopo diagnóstico já
 ### calculado pelo painel (ex.: nativa/desconhecida -> nativa/samambaia).
 ### Nesse caso, o alvo correto são as linhas diagnósticas serializadas, não
 ### as 101 linhas de cada COLETA do lote. Isto evita comparar 8*101 linhas
 ### contra o total real da ocorrência de desconhecida na categoria-base.
  linhas_serial <- integer(0)
  if ("linhas_alvo_serializadas" %in% names(linha_lote)) {
    linhas_serial <- suppressWarnings(as.integer(monitora_correcao_parse_serial_generico(linha_lote$linhas_alvo_serializadas[1L])))
  }
  if (!length(linhas_serial) && "linha_indice" %in% names(linha_lote)) {
    linhas_serial <- suppressWarnings(as.integer(monitora_correcao_parse_serial_generico(linha_lote$linha_indice[1L])))
  }
  linhas_serial <- unique(linhas_serial[!is.na(linhas_serial) & linhas_serial >= 1L & linhas_serial <= nrow(dt)])
  if (length(linhas_serial)) return(linhas_serial)

  if (is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) return(integer(0))
  coletas <- if ("coleta" %in% names(linha_lote)) monitora_correcao_parse_lista_serializada(linha_lote$coleta[1L]) else character(0)
  coletas <- unique(as.character(coletas))
  coletas <- coletas[!is.na(coletas) & nzchar(trimws(coletas))]
  if (!length(coletas)) return(integer(0))
  which(as.character(dt[[chaves$coleta]]) %chin% coletas)
}

monitora_correcao_dependentes_nao_migraveis_lote <- function(dt, linhas, origem, formas, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas) || !length(formas)) return(data.table::data.table())
  out <- list()
  for (forma in formas) {
    deps <- tryCatch(monitora_correcao_colunas_dependentes_por_token(dt, origem, forma, dicionario), error = function(e) character(0))
    if (!length(deps)) next
    deps <- unique(deps[deps %in% names(dt)])
    if (!length(deps)) next
    nao_hab <- deps[!vapply(deps, function(cc) monitora_correcao_coluna_habito_segura(dt, cc, origem, forma), logical(1))]
    if (!length(nao_hab)) next
    for (dep in nao_hab) {
      vals <- as.character(dt[[dep]][linhas])
      preench <- !monitora_correcao_vazio_vec(vals)
      if (any(preench, na.rm = TRUE)) {
        out[[length(out) + 1L]] <- data.table::data.table(
          forma = forma,
          categoria_origem = origem,
          coluna_dependente = dep,
          n_linhas_com_valor = sum(preench, na.rm = TRUE),
          exemplo_valor = monitora_correcao_colapsar_contexto_valores(vals[preench], max_valores = 3L)
        )
      }
    }
  }
  if (length(out)) data.table::rbindlist(out, fill = TRUE, use.names = TRUE) else data.table::data.table()
}


monitora_correcao_valor_marcador_outra_especie <- function(x) {
  x <- as.character(x)
  if (!length(x)) return(logical(0))
  z <- monitora_correcao_normalizar_nome_coluna(x)
  z <- trimws(z)
  !monitora_correcao_vazio_vec(x) & grepl("(^|_)outra(_|$)|(^|_)outro(_|$)|outra_especie|outro_especie|outra_sp|outro_sp", z)
}

monitora_correcao_resolver_dependente_destino_lote <- function(dt, origem, destino, forma, coluna_origem, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  if (monitora_correcao_vazio(coluna_origem) || !(coluna_origem %in% names(dt))) return(NA_character_)
  mapa <- tryCatch(monitora_correcao_mapa_colunas_canonicas(dt), error = function(e) data.table::data.table())
  if (!nrow(mapa)) return(NA_character_)
  src <- mapa[coluna_registros_corrig == coluna_origem]
  if (!nrow(src)) return(NA_character_)
  papel <- src$papel_coluna[1L]
  if (!papel %in% c("especie_nome_popular", "outro")) return(NA_character_)
  cand <- tryCatch(monitora_correcao_colunas_dependentes_por_token(dt, destino, forma, dicionario), error = function(e) character(0))
  cand <- unique(cand[cand %in% names(dt)])
  cand <- cand[!vapply(cand, function(cc) monitora_correcao_coluna_habito_segura(dt, cc, destino, forma), logical(1))]
  if (!length(cand)) return(NA_character_)
  meta <- mapa[coluna_registros_corrig %in% cand & papel_coluna == papel]
  if (!nrow(meta)) meta <- mapa[coluna_registros_corrig %in% cand]
  if (!nrow(meta)) return(NA_character_)
  src_norm <- src$coluna_norm[1L]
  src_outra <- grepl("outra|outro", src_norm)
  meta[, score := 0L]
  meta[grepl("outra|outro", coluna_norm) == src_outra, score := score + 100L]
  meta[papel_coluna == papel, score := score + 50L]
  meta[categoria == destino, score := score + 20L]
  meta[grepl("especie|nome_popular|outra|outro", coluna_norm), score := score + 10L]
  data.table::setorder(meta, -score, coluna_registros_corrig)
  top_score <- meta$score[1L]
  top <- meta[score == top_score]
  if (nrow(top) != 1L) return(NA_character_)
  top$coluna_registros_corrig[1L]
}

monitora_correcao_planejar_migracao_dependentes_lote <- function(dt, linhas, origem, destino, formas_efetivas, presenca, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  plano <- data.table::data.table(
    forma = character(),
    linha_indice = integer(),
    atributo = character(),
    valor_antes = character(),
    valor_depois = character(),
    mensagem = character()
  )
  bloqueios <- data.table::data.table(
    forma = character(),
    linha_indice = integer(),
    coluna_dependente = character(),
    motivo = character(),
    exemplo_valor = character()
  )
  if (!length(linhas) || !length(formas_efetivas)) return(list(plano = plano, bloqueios = bloqueios))
  for (forma in formas_efetivas) {
    rows_f <- linhas[presenca[[forma]]]
    rows_f <- rows_f[!is.na(rows_f) & rows_f >= 1L & rows_f <= nrow(dt)]
    if (!length(rows_f)) next
    deps_src <- tryCatch(monitora_correcao_colunas_dependentes_por_token(dt, origem, forma, dicionario), error = function(e) character(0))
    deps_src <- unique(deps_src[deps_src %in% names(dt)])
    deps_src <- deps_src[!vapply(deps_src, function(cc) monitora_correcao_coluna_habito_segura(dt, cc, origem, forma), logical(1))]
    if (!length(deps_src)) next

    vals_por_dep <- lapply(deps_src, function(dep) as.character(dt[[dep]][rows_f]))
    names(vals_por_dep) <- deps_src
    for (k in seq_along(rows_f)) {
      rr <- rows_f[k]
      vals_linha <- vapply(vals_por_dep, function(v) v[k], character(1))
      preench <- !monitora_correcao_vazio_vec(vals_linha)
      if (!any(preench, na.rm = TRUE)) next
      vals_preench <- vals_linha[preench]
      marcadores <- monitora_correcao_valor_marcador_outra_especie(vals_preench)
      ha_valor_textual <- any(!marcadores, na.rm = TRUE)

      for (dep in names(vals_linha)[preench]) {
        val_src <- vals_linha[[dep]]
        if (monitora_correcao_vazio(val_src)) next
        if (isTRUE(monitora_correcao_valor_marcador_outra_especie(val_src))) {
          if (!isTRUE(ha_valor_textual)) {
            bloqueios <- data.table::rbindlist(list(
              bloqueios,
              data.table::data.table(
                forma = forma,
                linha_indice = as.integer(rr),
                coluna_dependente = dep,
                motivo = "marcador 'outra espécie' preenchido sem campo textual migrável na mesma linha",
                exemplo_valor = as.character(val_src)
              )
            ), fill = TRUE, use.names = TRUE)
          } else {
            plano <- data.table::rbindlist(list(
              plano,
              data.table::data.table(
                forma = forma,
                linha_indice = as.integer(rr),
                atributo = dep,
                valor_antes = as.character(val_src),
                valor_depois = NA_character_,
                mensagem = "Movimento em lote: marcador de outra espécie limpo após migração do texto associado"
              )
            ), fill = TRUE, use.names = TRUE)
          }
          next
        }

        dep_dst <- monitora_correcao_resolver_dependente_destino_lote(dt, origem, destino, forma, dep, dicionario)
        if (monitora_correcao_vazio(dep_dst) || !(dep_dst %in% names(dt))) {
          bloqueios <- data.table::rbindlist(list(
            bloqueios,
            data.table::data.table(
              forma = forma,
              linha_indice = as.integer(rr),
              coluna_dependente = dep,
              motivo = "coluna de destino correspondente não localizada com segurança",
              exemplo_valor = as.character(val_src)
            )
          ), fill = TRUE, use.names = TRUE)
          next
        }
        val_dst <- as.character(dt[[dep_dst]][rr])
        if (!monitora_correcao_vazio(val_dst) && !identical(monitora_correcao_na_para_vazio(val_dst), monitora_correcao_na_para_vazio(val_src))) {
          bloqueios <- data.table::rbindlist(list(
            bloqueios,
            data.table::data.table(
              forma = forma,
              linha_indice = as.integer(rr),
              coluna_dependente = dep_dst,
              motivo = "destino já preenchido com valor diferente",
              exemplo_valor = paste0("origem=", val_src, " | destino=", val_dst)
            )
          ), fill = TRUE, use.names = TRUE)
          next
        }
        if (monitora_correcao_na_para_vazio(val_dst) != monitora_correcao_na_para_vazio(val_src)) {
          plano <- data.table::rbindlist(list(
            plano,
            data.table::data.table(
              forma = forma,
              linha_indice = as.integer(rr),
              atributo = dep_dst,
              valor_antes = as.character(val_dst),
              valor_depois = as.character(val_src),
              mensagem = "Movimento em lote: espécie/outro dependente migrado para destino"
            )
          ), fill = TRUE, use.names = TRUE)
        }
        plano <- data.table::rbindlist(list(
          plano,
          data.table::data.table(
            forma = forma,
            linha_indice = as.integer(rr),
            atributo = dep,
            valor_antes = as.character(val_src),
            valor_depois = NA_character_,
            mensagem = "Movimento em lote: espécie/outro dependente limpo na origem após migração"
          )
        ), fill = TRUE, use.names = TRUE)
      }
    }
  }
  if (nrow(plano)) {
    plano_cmp <- plano[, .(valores = list(unique(monitora_correcao_na_para_vazio(valor_depois))), n_valores = data.table::uniqueN(monitora_correcao_na_para_vazio(valor_depois))), by = .(linha_indice, atributo)]
    conflito <- plano_cmp[n_valores > 1L]
    if (nrow(conflito)) {
      bloqueios <- data.table::rbindlist(list(
        bloqueios,
        conflito[, data.table::data.table(
          forma = NA_character_,
          linha_indice = as.integer(linha_indice),
          coluna_dependente = atributo,
          motivo = "plano de migração gerou mais de um valor final para a mesma célula",
          exemplo_valor = vapply(valores, function(v) paste(v, collapse = " | "), character(1))
        )]
      ), fill = TRUE, use.names = TRUE)
    }
  }
  list(plano = plano[], bloqueios = bloqueios[])
}


monitora_correcao_anexar_contexto_ambiguidades_mvlote <- function(dt, ambiguidades, id_correcao = NA_character_, origem = NA_character_, destino = NA_character_, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  ambiguidades <- data.table::as.data.table(ambiguidades)
  if (!nrow(ambiguidades)) return(ambiguidades[])
  for (cc in c("forma", "linha_indice", "coluna_dependente", "motivo", "exemplo_valor")) if (!(cc %in% names(ambiguidades))) data.table::set(ambiguidades, j = cc, value = NA_character_)
  pegar <- function(col, idx) {
    if (is.na(col) || !nzchar(col) || !(col %in% names(dt))) return(rep(NA_character_, length(idx)))
    ok <- !is.na(idx) & idx >= 1L & idx <= nrow(dt)
    out <- rep(NA_character_, length(idx))
    out[ok] <- as.character(dt[[col]][idx[ok]])
    out
  }
  idx <- suppressWarnings(as.integer(ambiguidades$linha_indice))
  data.table::data.table(
    id_correcao = id_correcao,
    status = "ambigua_mantida_sem_migracao",
    categoria_origem = origem,
    categoria_destino = destino,
    forma = as.character(ambiguidades$forma),
    COLETA = pegar(chaves$coleta, idx),
    EA = pegar(chaves$ea, idx),
    UA = pegar(chaves$ua, idx),
    CICLO = pegar(chaves$ciclo, idx),
    CAMPANHA = pegar(chaves$campanha, idx),
    ANO = pegar(chaves$ano, idx),
    `Data (data_hora)` = pegar(chaves$data_hora, idx),
    ponto_amostral = pegar(chaves$ponto_amostral, idx),
    ponto_metro = pegar(chaves$ponto_metro, idx),
    linha_indice = idx,
    coluna_dependente = as.character(ambiguidades$coluna_dependente),
    motivo_ambiguidade = as.character(ambiguidades$motivo),
    valor_observado = as.character(ambiguidades$exemplo_valor),
    acao_adotada = "ocorrencia_ambigua_mantida_sem_alteracao; demais ocorrencias migraveis do lote continuam processadas"
  )[]
}

monitora_correcao_gravar_relatorio_ambiguidades_mvlote <- function(relatorio, contexto = "movimento_lote_forma_vida") {
  relatorio <- data.table::as.data.table(relatorio)
  if (!nrow(relatorio)) return(invisible(relatorio))
  exec_id <- if (exists("MONITORA_EXEC_ID", inherits = TRUE)) MONITORA_EXEC_ID else format(Sys.time(), "%Y%m%d_%H%M%S")
  arqs <- character(0)
  if (exists("MONITORA_LOG_DIR", inherits = TRUE)) {
    arqs <- c(arqs, file.path(MONITORA_LOG_DIR, paste0("relatorio_ambiguidades_", contexto, "_", exec_id, ".csv")))
  }
  if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) {
    arqs <- c(arqs, file.path(MONITORA_CORRECOES_DIR, paste0("relatorio_ambiguidades_", contexto, "_ultima_execucao.csv")))
  }
  for (aa in arqs) {
    old <- data.table::data.table()
    if (file.exists(aa)) old <- tryCatch(data.table::fread(aa, encoding = "UTF-8", showProgress = FALSE), error = function(e) data.table::data.table())
    out <- data.table::rbindlist(list(old, relatorio), fill = TRUE, use.names = TRUE)
    out <- unique(out)
    try(monitora_fwrite(out, aa, na = ""), silent = TRUE)
  }
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento(
      "movimento_lote_forma_vida_ambiguidades", "AVISO",
      if (length(arqs)) arqs[1L] else NA_character_,
      paste0(nrow(relatorio), " ocorrência(s) ambígua(s) mantida(s) sem migração no movimento em lote de formas de vida"),
      "demais ocorrências migráveis do lote foram preservadas para aplicação atômica"
    )
  }
  invisible(relatorio)
}

monitora_correcao_filtrar_presenca_mvlote <- function(presenca, linhas, ambiguidades) {
  presenca <- presenca
  ambiguidades <- data.table::as.data.table(ambiguidades)
  if (!length(presenca) || !nrow(ambiguidades)) return(presenca)
  for (rr in seq_len(nrow(ambiguidades))) {
    forma <- as.character(ambiguidades$forma[rr])
    idx_linha <- suppressWarnings(as.integer(ambiguidades$linha_indice[rr]))
    if (is.na(forma) || !nzchar(forma) || !(forma %in% names(presenca)) || is.na(idx_linha)) next
    pos <- which(as.integer(linhas) == idx_linha)
    if (length(pos)) presenca[[forma]][pos] <- FALSE
  }
  presenca
}

monitora_correcao_formas_efetivas_presenca <- function(presenca) {
  if (!length(presenca)) return(character(0))
  names(presenca)[vapply(presenca, function(x) any(isTRUE(x) | (is.logical(x) & x), na.rm = TRUE), logical(1))]
}



### Sanitização de dependentes históricos/atuais de forma de vida desconhecida
### -------------------------------------------------------------------------
### Contrato: fotos, imagens, uploads, anexos e descritores de "desconhecida"
### só são relevantes enquanto a sublista correspondente contém o token
### desconhecida. Quando o token é removido por movimento/triagem assistida,
### todos os dependentes da categoria devem ser limpos, independentemente da
### versão/fonte do XLSForm que originou a coluna.
monitora_correcao_tokens_desconhecida <- function() {
  c("desconhecida", "desconhecido", "indeterminada", "indeterminado", "nao_identificada", "nao_identificado", "não_identificada", "não_identificado")
}

monitora_correcao_categoria_variantes_norm <- function(categoria) {
  categoria <- tolower(trimws(as.character(categoria)[1L]))
  switch(
    categoria,
    nativa = c("nativa", "nativo", "planta_nativa", "plantas_nativas"),
    exotica = c("exotica", "exotico", "exoticas", "exoticos", "planta_exotica", "plantas_exoticas"),
    seca_morta = c("seca_morta", "seca", "morta", "seca_ou_morta", "seca_e_morta", "planta_seca", "planta_morta", "seca_morta"),
    character(0)
  )
}

monitora_correcao_colunas_desconhecida_por_categoria <- function(dt, categoria, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  nms <- names(dt)
  nms_norm <- monitora_correcao_normalizar_nome_coluna(nms)
  cat_norms <- monitora_correcao_categoria_variantes_norm(categoria)
  cat_norms <- unique(monitora_correcao_normalizar_nome_coluna(cat_norms))
  tem_cat <- function(z) {
    if (!length(cat_norms)) return(rep(FALSE, length(z)))
    out <- rep(FALSE, length(z))
    for (cc in cat_norms) out <- out | grepl(cc, z, fixed = TRUE)
    out
  }
  eh_dep <- function(z) {
    grepl("desconhecid|indeterminad|nao_identific|nao identific|não_identific|não identific", z, perl = TRUE) &
      tem_cat(z) &
      grepl("foto|imagem|image|upload|arquivo|anexo|midia|media|descr|descricao|descritor|observ|obs", z, perl = TRUE) &
      !grepl("especie|especies|outra_sp|_sp($|_)", z, perl = TRUE)
  }

  resolver_dt <- function(vals) {
    vals <- unique(as.character(vals))
    vals <- vals[!is.na(vals) & nzchar(vals)]
    out <- character(0)
    for (vv in vals) {
      hit <- nms[nms == vv]
      if (length(hit)) out <- c(out, hit)
      vv_norm <- monitora_correcao_normalizar_nome_coluna(vv)
      hit2 <- which(nms_norm == vv_norm)
      if (length(hit2)) out <- c(out, nms[hit2])
      col_res <- tryCatch(monitora_correcao_resolver_coluna(dt, vv, dicionario, permitir_heuristica = FALSE), error = function(e) NA_character_)
      if (!is.na(col_res) && nzchar(col_res) && col_res %in% nms) out <- c(out, col_res)
    }
    unique(out[out %in% nms])
  }

  canon <- character(0)
  base <- paste0("foto_forma_vida_", categoria, "_desconhecida")
  if (identical(categoria, "seca_morta")) base <- "foto_forma_vida_seca_morta_desconhecida"
  canon <- c(
    base, paste0(base, "02"), paste0(base, "03"),
    paste0("amostragem/registro/", base), paste0("amostragem/registro/", base, "02"), paste0("amostragem/registro/", base, "03")
  )
  cols <- resolver_dt(canon)

  if (!is.null(dicionario) && nrow(data.table::as.data.table(dicionario)) > 0L) {
    d <- data.table::as.data.table(dicionario)
    for (cc in c("name", "caminho_registro", "label", "type", "list_name", "relevant")) if (!(cc %in% names(d))) d[, (cc) := NA_character_]
    d[, texto_busca := paste(name, caminho_registro, label, type, list_name, relevant, sep = " ")]
    d[, texto_norm := monitora_correcao_normalizar_nome_coluna(texto_busca)]
    d[, dep_desconhecida := eh_dep(texto_norm)]
    if (any(d$dep_desconhecida, na.rm = TRUE)) {
      cand_vals <- unique(unlist(d[dep_desconhecida == TRUE, .(name, caminho_registro, label)], use.names = FALSE))
      cols <- c(cols, resolver_dt(cand_vals))
    }
  }

  fallback <- nms[eh_dep(nms_norm)]
  cols <- unique(c(cols, fallback))
  cols <- cols[cols %in% nms]
  if (!length(cols)) {
    return(data.table::data.table(categoria = character(), coluna = character(), tipo_dependente = character(), origem_resolucao = character()))
  }
  tipo <- ifelse(grepl("foto|imagem|image", monitora_correcao_normalizar_nome_coluna(cols), perl = TRUE), "foto_imagem",
                 ifelse(grepl("upload|arquivo|anexo|midia|media", monitora_correcao_normalizar_nome_coluna(cols), perl = TRUE), "arquivo_midia", "descritor_obs"))
  data.table::data.table(
    categoria = categoria,
    coluna = cols,
    tipo_dependente = tipo,
    origem_resolucao = "xlsform_embutido_alias_label_fallback_normalizado"
  )[]
}

### fonte única para a validade contratual de `desconhecida` ----------
### O XLSForm 2025 admite `desconhecida` nas listas nativa, exótica e
### seca/morta. A ocorrência é apenas de revisão quando a categoria superior
### está selecionada e a primeira foto required está preenchida. Estados
### incompatíveis são impeditivos e nunca são simultaneamente classificados
### como revisão para a mesma linha.
monitora_correcao_colunas_lista_desconhecida_categoria <- function(dt, categoria) {
  dt <- data.table::as.data.table(dt)
  categoria <- tolower(trimws(as.character(categoria)[1L]))
  if (!(categoria %in% c("nativa", "exotica", "seca_morta"))) return(character(0))
  cols <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(dt, categoria), error = function(e) character(0))
  cols <- unique(cols[cols %in% names(dt)])
  candidatos <- c(paste0("amostragem/registro/forma_vida_", categoria), paste0("forma_vida_", categoria))
  nms <- names(dt)
  nms_norm <- monitora_correcao_normalizar_nome_coluna(nms)
  cand_norm <- monitora_correcao_normalizar_nome_coluna(candidatos)
  cat_hit <- switch(
    categoria,
    nativa = grepl("nativ", nms_norm),
    exotica = grepl("exotic|exotica|exotico", nms_norm),
    seca_morta = grepl("seca.*mort|morta.*seca", nms_norm)
  )
  eh_lista <- nms_norm %in% cand_norm | grepl("formas?_de_vida_de_plantas?", nms_norm)
  excluir <- grepl("foto|imagem|habito|especie|outra_forma|desconhecid|_sp($|_)", nms_norm)
  unique(c(cols, nms[eh_lista & cat_hit & !excluir]))
}

monitora_correcao_coluna_foto_desconhecida_obrigatoria <- function(dt, categoria, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  categoria <- tolower(trimws(as.character(categoria)[1L]))
  if (!(categoria %in% c("nativa", "exotica", "seca_morta"))) return(NA_character_)
  base <- paste0("foto_forma_vida_", categoria, "_desconhecida")
  candidatos <- c(paste0("amostragem/registro/", base), base)
  nms <- names(dt)
  nms_norm <- monitora_correcao_normalizar_nome_coluna(nms)
  cand_norm <- monitora_correcao_normalizar_nome_coluna(candidatos)
  for (alvo in cand_norm) {
    hit <- which(nms_norm == alvo | endsWith(nms_norm, paste0("_", alvo)))
    if (length(hit)) return(nms[hit[1L]])
  }
  deps <- tryCatch(
    monitora_correcao_colunas_desconhecida_por_categoria(dt, categoria, dicionario),
    error = function(e) data.table::data.table()
  )
  if (!nrow(deps)) return(NA_character_)
  deps <- deps[tipo_dependente == "foto_imagem" & coluna %in% nms]
  if (!nrow(deps)) return(NA_character_)
  deps[, coluna_norm := monitora_correcao_normalizar_nome_coluna(coluna)]
  deps[, score_required := 0L]
  deps[!grepl("(02|03|_2|_3)$", coluna_norm), score_required := score_required + 100L]
  deps[!grepl("outra_foto|segunda|terceira", coluna_norm), score_required := score_required + 50L]
  deps[endsWith(coluna_norm, monitora_correcao_normalizar_nome_coluna(base)), score_required := score_required + 500L]
  data.table::setorder(deps, -score_required, coluna)
  as.character(deps$coluna[1L])
}

monitora_correcao_classificar_desconhecida <- function(dt,
                                                        chaves = monitora_correcao_colunas_chave(dt),
                                                        dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  vazio_out <- data.table::data.table(
    linha_indice = integer(), categoria = character(), tipo_ocorrencia = character(),
    status_contrato = character(), severidade = character(), bloqueia_registros_validados = logical(),
    atributo_lista = character(), atributo_foto_obrigatoria = character(), atributo_problema = character(),
    valor_observado = character(), atributos_dependentes_preenchidos = character(),
    regra_contrato = character(), motivo_rejeicao = character()
  )
  n <- nrow(dt)
  if (!n) return(vazio_out)
  tipo_col <- tryCatch(as.character(chaves$tipo_forma_vida)[1L], error = function(e) NA_character_)
  tipo <- if (!is.na(tipo_col) && nzchar(tipo_col) && tipo_col %in% names(dt)) as.character(dt[[tipo_col]]) else rep("", n)
  vazio <- function(x) {
    z <- tryCatch(monitora_correcao_vazio_vec(x), error = function(e) is.na(x) | !nzchar(trimws(as.character(x))))
    z[is.na(z)] <- TRUE
    z
  }
  contem <- function(x, tokens) {
    z <- tryCatch(monitora_correcao_contem_qualquer_token_vec(x, tokens), error = function(e) rep(FALSE, length(x)))
    z[is.na(z)] <- FALSE
    z
  }
  toks_desc <- tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) c("desconhecida", "desconhecido"))
  partes <- list()
  for (categoria in c("nativa", "exotica", "seca_morta")) {
    cols_lista <- monitora_correcao_colunas_lista_desconhecida_categoria(dt, categoria)
    col_lista <- tryCatch(monitora_correcao_coluna_forma_vida(dt, categoria), error = function(e) NA_character_)
    if (is.na(col_lista) || !(col_lista %in% names(dt))) col_lista <- if (length(cols_lista)) cols_lista[1L] else paste0("amostragem/registro/forma_vida_", categoria)
    tem_token <- rep(FALSE, n)
    valor_lista <- rep("", n)
    if (length(cols_lista)) {
      for (cc in cols_lista) {
        hit <- contem(dt[[cc]], toks_desc)
        tem_token <- tem_token | hit
        preencher <- hit & !nzchar(valor_lista)
        valor_lista[preencher] <- as.character(dt[[cc]][preencher])
      }
    }
    tem_categoria <- tryCatch(
      monitora_relatorio_exoticas_tem_token(tipo, monitora_correcao_categoria_variantes_norm(categoria)),
      error = function(e) rep(FALSE, n)
    )
    tem_categoria[is.na(tem_categoria)] <- FALSE
    deps <- tryCatch(monitora_correcao_colunas_desconhecida_por_categoria(dt, categoria, dicionario), error = function(e) data.table::data.table())
    dep_cols <- if (nrow(deps)) unique(as.character(deps$coluna[deps$coluna %in% names(dt)])) else character(0)
    tem_dep <- rep(FALSE, n)
    deps_preenchidos <- rep("", n)
    deps_atributos <- rep("", n)
    if (length(dep_cols)) {
      for (cc in dep_cols) {
        preenchido <- !vazio(dt[[cc]])
        tem_dep <- tem_dep | preenchido
        idx <- which(preenchido)
        if (length(idx)) {
          novo <- paste0(cc, " = ", as.character(dt[[cc]][idx]))
          deps_preenchidos[idx] <- ifelse(nzchar(deps_preenchidos[idx]), paste(deps_preenchidos[idx], novo, sep = " | "), novo)
          deps_atributos[idx] <- ifelse(nzchar(deps_atributos[idx]), paste(deps_atributos[idx], cc, sep = " | "), cc)
        }
      }
    }
    col_foto <- monitora_correcao_coluna_foto_desconhecida_obrigatoria(dt, categoria, dicionario)
    atributo_foto <- if (!is.na(col_foto) && nzchar(col_foto)) col_foto else paste0("amostragem/registro/foto_forma_vida_", categoria, "_desconhecida")
    tem_foto <- if (!is.na(col_foto) && col_foto %in% names(dt)) !vazio(dt[[col_foto]]) else rep(FALSE, n)

    status <- rep("", n)
    status[tem_dep & !tem_token] <- "dependente_desconhecida_sem_token"
    status[tem_token & !tem_categoria] <- "desconhecida_sem_categoria_superior"
    status[tem_token & tem_categoria & !tem_foto] <- "foto_obrigatoria_desconhecida_ausente"
    status[tem_token & tem_categoria & tem_foto] <- "revisao_desconhecida_valida"
    idx <- which(nzchar(status))
    if (!length(idx)) next
    bloqueia <- status[idx] != "revisao_desconhecida_valida"
    atributo_problema <- ifelse(
      status[idx] == "foto_obrigatoria_desconhecida_ausente", atributo_foto,
      ifelse(status[idx] == "dependente_desconhecida_sem_token", deps_atributos[idx], col_lista)
    )
    motivo <- data.table::fcase(
      status[idx] == "dependente_desconhecida_sem_token", "Foto/descritor de forma de vida desconhecida preenchido sem token desconhecida na categoria correspondente.",
      status[idx] == "desconhecida_sem_categoria_superior", "Token desconhecida preenchido em lista irrelevante porque a categoria superior não está selecionada em Encostam.",
      status[idx] == "foto_obrigatoria_desconhecida_ausente", "A primeira foto de forma de vida desconhecida é required quando o token desconhecida está selecionado.",
      default = "Token desconhecida válido no XLSForm 2025; ocorrência mantida apenas para revisão humana."
    )
    partes[[length(partes) + 1L]] <- data.table::data.table(
      linha_indice = idx,
      categoria = categoria,
      tipo_ocorrencia = ifelse(bloqueia, "forma_vida_desconhecida_invalida", "forma_vida_desconhecida"),
      status_contrato = status[idx],
      severidade = ifelse(bloqueia, "impeditiva", "revisao"),
      bloqueia_registros_validados = bloqueia,
      atributo_lista = col_lista,
      atributo_foto_obrigatoria = atributo_foto,
      atributo_problema = atributo_problema,
      valor_observado = ifelse(status[idx] == "dependente_desconhecida_sem_token", deps_preenchidos[idx], valor_lista[idx]),
      atributos_dependentes_preenchidos = deps_preenchidos[idx],
      regra_contrato = paste0(
        "selected(${forma_vida_", categoria, "}, 'desconhecida') => ",
        "required(${foto_forma_vida_", categoria, "_desconhecida}); categoria superior ", categoria, " relevante"
      ),
      motivo_rejeicao = motivo
    )
  }

 ### Token desconhecida no próprio Encostam nunca pertence ao domínio 2025.
  tem_desc_superior <- contem(tipo, toks_desc)
  idx_sup <- which(tem_desc_superior)
  if (length(idx_sup)) {
    partes[[length(partes) + 1L]] <- data.table::data.table(
      linha_indice = idx_sup, categoria = "encostam",
      tipo_ocorrencia = "forma_vida_desconhecida_invalida",
      status_contrato = "desconhecida_fora_lista_de_categoria",
      severidade = "impeditiva", bloqueia_registros_validados = TRUE,
      atributo_lista = tipo_col, atributo_foto_obrigatoria = NA_character_, atributo_problema = tipo_col,
      valor_observado = tipo[idx_sup], atributos_dependentes_preenchidos = "",
      regra_contrato = "desconhecida pertence somente a forma_vida_nativa|forma_vida_exotica|forma_vida_seca_morta",
      motivo_rejeicao = "Token desconhecida está em Encostam/tipo_forma_vida, fora das listas de categoria admitidas pelo XLSForm 2025."
    )
  }
  if (!length(partes)) return(vazio_out)
  out <- data.table::rbindlist(partes, fill = TRUE, use.names = TRUE)
 ### Se qualquer estado de desconhecida na linha é inválido, a mesma linha não
 ### aparece simultaneamente como revisão. Após o saneamento ela migra de grupo.
  linhas_invalidas <- unique(out[bloqueia_registros_validados == TRUE, linha_indice])
  if (length(linhas_invalidas)) out <- out[!(linha_indice %in% linhas_invalidas & bloqueia_registros_validados == FALSE)]
  unique(out, by = c("linha_indice", "categoria", "tipo_ocorrencia", "status_contrato", "atributo_problema"))[]
}

monitora_correcao_canonicalizar_aliases_desconhecida <- function(dt,
                                                                  output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = tempdir(), inherits = TRUE),
                                                                  log_dir = get0("MONITORA_LOG_DIR", ifnotfound = tempdir(), inherits = TRUE),
                                                                  exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                                                  contexto = "pre_painel") {
  dt <- monitora_dt_referenciar(dt)
  alias_norm <- setdiff(unique(monitora_correcao_limpar_texto(monitora_correcao_tokens_desconhecida())), "desconhecida")
  audit <- list()
  afetacoes <- list()
  for (categoria in c("nativa", "exotica", "seca_morta")) {
    cols <- monitora_correcao_colunas_lista_desconhecida_categoria(dt, categoria)
    for (cc in cols) {
      antes <- as.character(dt[[cc]])
      depois <- vapply(antes, function(v) {
        toks <- monitora_correcao_tokenizar(v)
        if (!length(toks)) return(NA_character_)
        hit <- toks %in% alias_norm
        if (!any(hit)) return(v)
        toks[hit] <- "desconhecida"
        monitora_correcao_colapsar_tokens(toks)
      }, character(1))
      mudou <- which(!is.na(antes) & !is.na(depois) & antes != depois)
      if (!length(mudou)) next
      data.table::set(dt, i = mudou, j = cc, value = depois[mudou])
      audit[[length(audit) + 1L]] <- data.table::data.table(
        id_correcao = "CANON_DESC_ALIAS_PRE_PAINEL", ordem_operacao = NA_character_,
        status = "alias_harmonizado", mensagem = paste0("Alias histórico de desconhecida harmonizado para token canônico; contexto=", contexto),
        atributo = cc, linha_indice = mudou, valor_antes = antes[mudou], valor_depois = depois[mudou],
        arquivo_correcao = "canonicalizacao_aliases_desconhecida"
      )
      afetacoes[[length(afetacoes) + 1L]] <- data.table::data.table(linha_indice = mudou, atributo = cc)
    }
  }
  audit_dt <- if (length(audit)) data.table::rbindlist(audit, fill = TRUE, use.names = TRUE) else data.table::data.table()
  afetacoes_dt <- if (length(afetacoes)) unique(data.table::rbindlist(afetacoes, fill = TRUE, use.names = TRUE)) else data.table::data.table(linha_indice = integer(), atributo = character())
  if (nrow(audit_dt)) {
    if (exists("monitora_publicacao_ac_registrar_dirty", mode = "function", inherits = TRUE)) {
      try(monitora_publicacao_ac_registrar_dirty(
        motivo = "canonicalizacao_aliases_desconhecida_pre_painel",
        linhas = afetacoes_dt$linha_indice,
        colunas = afetacoes_dt$atributo,
        desconhecida = TRUE
      ), silent = TRUE)
    }
    arqs <- c(
      file.path(output_dir, "02_painel_correcoes", "relatorios_pre_painel", "canonicalizacao_aliases_desconhecida.csv"),
      file.path(log_dir, paste0("canonicalizacao_aliases_desconhecida_", exec_id, ".csv"))
    )
    for (aa in arqs) try({ dir.create(dirname(aa), recursive = TRUE, showWarnings = FALSE); monitora_fwrite(audit_dt, aa, na = "") }, silent = TRUE)
  }
  list(dt = dt[], audit = audit_dt[], linhas = unique(afetacoes_dt$linha_indice), afetacoes = afetacoes_dt[])
}

monitora_correcao_auditoria_desconhecida_vazia <- function() {
  data.table::data.table(
    id_correcao = character(), ordem_operacao = character(), status = character(), mensagem = character(),
    atributo = character(), linha_indice = integer(), valor_antes = character(), valor_depois = character(),
    arquivo_correcao = character(), categoria = character(), tipo_dependente = character(), origem_resolucao = character()
  )
}

monitora_correcao_sanitizar_dependentes_desconhecida <- function(dt, linhas = NULL, categorias = c("nativa", "exotica", "seca_morta"), id_correcao = NA_character_, ordem_operacao = NA_character_, arquivo_correcao = NA_character_, dicionario = NULL, registrar_preservadas = TRUE) {
  dt <- monitora_dt_referenciar(dt)
  if (is.null(linhas)) linhas <- seq_len(nrow(dt))
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  audit <- monitora_correcao_auditoria_desconhecida_vazia()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  if (!length(linhas)) return(list(dt = dt[], audit = audit, afetacoes = afetacoes, falha = FALSE))
  tokens_desc <- monitora_correcao_tokens_desconhecida()

  for (cat in categorias) {
    col_lista <- tryCatch(monitora_correcao_coluna_forma_vida(dt, cat), error = function(e) NA_character_)
    if (is.na(col_lista) || !(col_lista %in% names(dt))) next
    lista_vals <- as.character(dt[[col_lista]][linhas])
    tem_desc <- monitora_correcao_contem_qualquer_token_vec(lista_vals, tokens_desc)
    cols_dep <- monitora_correcao_colunas_desconhecida_por_categoria(dt, cat, dicionario)
    if (!nrow(cols_dep)) next
    for (ii in seq_len(nrow(cols_dep))) {
      dep_col <- cols_dep$coluna[ii]
      if (!(dep_col %in% names(dt)) || monitora_correcao_coluna_protegida(dep_col)) next
      antes <- as.character(dt[[dep_col]][linhas])
      preenchido <- !monitora_correcao_vazio_vec(antes)
      limpar <- preenchido & !tem_desc
      preservar <- preenchido & tem_desc
      if (any(limpar, na.rm = TRUE)) {
        idx <- linhas[limpar]
        depois <- rep(NA_character_, length(idx))
        data.table::set(dt, i = idx, j = dep_col, value = depois)
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = as.character(id_correcao),
          ordem_operacao = as.character(ordem_operacao),
          status = paste0(cols_dep$tipo_dependente[ii], "_desconhecida_limpa_token_removido"),
          mensagem = paste0("Dependente histórico/atual de forma de vida desconhecida limpo porque a categoria ", cat, " não contém mais o token desconhecida"),
          atributo = dep_col,
          linha_indice = idx,
          valor_antes = antes[limpar],
          valor_depois = depois,
          arquivo_correcao = as.character(arquivo_correcao),
          categoria = cat,
          tipo_dependente = cols_dep$tipo_dependente[ii],
          origem_resolucao = cols_dep$origem_resolucao[ii]
        )), fill = TRUE, use.names = TRUE)
        afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = idx, atributo = dep_col)), fill = TRUE, use.names = TRUE)
      }
      if (isTRUE(registrar_preservadas) && any(preservar, na.rm = TRUE)) {
        idxp <- linhas[preservar]
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = as.character(id_correcao),
          ordem_operacao = as.character(ordem_operacao),
          status = paste0(cols_dep$tipo_dependente[ii], "_desconhecida_preservada_token_ainda_presente"),
          mensagem = paste0("Dependente de forma de vida desconhecida preservado porque a categoria ", cat, " ainda contém o token desconhecida"),
          atributo = dep_col,
          linha_indice = idxp,
          valor_antes = antes[preservar],
          valor_depois = antes[preservar],
          arquivo_correcao = as.character(arquivo_correcao),
          categoria = cat,
          tipo_dependente = cols_dep$tipo_dependente[ii],
          origem_resolucao = cols_dep$origem_resolucao[ii]
        )), fill = TRUE, use.names = TRUE)
      }
    }
  }
  list(dt = dt[], audit = audit[], afetacoes = unique(afetacoes), falha = FALSE)
}

### Reconhece somente a intenção explícita de remover um token de desconhecida
### de uma das três listas inferiores de forma de vida. Esta guarda impede que a
### limpeza de fotos/descritores seja disparada por uma correção qualquer na
### mesma linha e preserva o contrato de não sanitização global não operada.
monitora_correcao_eh_remocao_desconhecida_lista <- function(dt,
                                                            acao,
                                                            valor_novo,
                                                            valor_original_esperado,
                                                            coluna,
                                                            dicionario = NULL) {
  acao <- tolower(trimws(as.character(acao)[1L]))
  if (is.na(acao) || !(acao %in% c("remove_token", "remover_token"))) return(FALSE)
  token_remover <- if (monitora_correcao_vazio(valor_novo)) valor_original_esperado else valor_novo
  tokens_remover <- tryCatch(monitora_correcao_tokenizar(token_remover), error = function(e) character(0))
  tokens_desc <- tryCatch(monitora_correcao_tokenizar(monitora_correcao_tokens_desconhecida()), error = function(e) character(0))
  if (!length(tokens_remover) || !any(tokens_remover %in% tokens_desc)) return(FALSE)

  dt <- data.table::as.data.table(dt)
  coluna <- as.character(coluna)[1L]
  if (is.na(coluna) || !nzchar(coluna) || !(coluna %in% names(dt))) return(FALSE)
  cols_listas <- unique(vapply(
    c("nativa", "exotica", "seca_morta"),
    function(cat) tryCatch(monitora_correcao_coluna_forma_vida(dt, cat), error = function(e) NA_character_),
    character(1L)
  ))
  coluna %in% cols_listas[!is.na(cols_listas) & nzchar(cols_listas)]
}

monitora_correcao_gravar_auditoria_sanitizacao_desconhecida <- function(audit) {
  audit <- data.table::as.data.table(audit)
  if (!nrow(audit)) return(invisible(audit))
  exec_id <- if (exists("MONITORA_EXEC_ID", inherits = TRUE)) MONITORA_EXEC_ID else format(Sys.time(), "%Y%m%d_%H%M%S")
  arqs <- character(0)
  if (exists("MONITORA_LOG_DIR", inherits = TRUE)) arqs <- c(arqs, file.path(MONITORA_LOG_DIR, paste0("auditoria_sanitizacao_forma_vida_desconhecida_", exec_id, ".csv")))
  if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) arqs <- c(arqs, file.path(MONITORA_CORRECOES_DIR, "auditoria_sanitizacao_forma_vida_desconhecida_ultima_execucao.csv"))
  for (aa in arqs) try(monitora_fwrite(audit, aa, na = ""), silent = TRUE)
  invisible(audit)
}

monitora_correcao_aplicar_movimento_forma_vida_lote_atomico <- function(dt, linha_lote, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL, gravar_relatorio_ambiguidades = TRUE) {
  dt <- monitora_dt_referenciar(dt)
  linha_lote <- data.table::as.data.table(linha_lote)
  if (!nrow(linha_lote)) return(list(dt = dt[], audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE))
  id_cor <- if ("id_correcao" %in% names(linha_lote)) as.character(linha_lote$id_correcao[1L]) else NA_character_
  ordem <- if ("ordem_operacao" %in% names(linha_lote)) linha_lote$ordem_operacao[1L] else NA_character_
  falhar <- function(status, msg, atributo = "__mover_forma_vida_lote__", extra = data.table::data.table()) {
    audit <- data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = paste0("Movimento atômico em lote bloqueado: ", msg), atributo = atributo, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao)
    if (nrow(extra)) audit <- data.table::rbindlist(list(audit, extra), fill = TRUE, use.names = TRUE)
    list(dt = dt[], audit = audit[], linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = TRUE)
  }
  origem <- if ("categoria_origem" %in% names(linha_lote)) tolower(trimws(as.character(linha_lote$categoria_origem[1L]))) else NA_character_
  destino <- if ("categoria_destino" %in% names(linha_lote)) tolower(trimws(as.character(linha_lote$categoria_destino[1L]))) else NA_character_
  if (monitora_correcao_vazio(origem) || monitora_correcao_vazio(destino) || !origem %in% c("nativa", "exotica", "seca_morta") || !destino %in% c("nativa", "exotica", "seca_morta")) {
    return(falhar("falha_lote_categoria", "origem/destino ausentes ou inválidos"))
  }
  if (identical(origem, destino)) return(falhar("falha_lote_origem_destino_iguais", "origem e destino são iguais"))
  col_origem <- tryCatch(monitora_correcao_coluna_forma_vida(dt, origem), error = function(e) NA_character_)
  col_destino <- tryCatch(monitora_correcao_coluna_forma_vida(dt, destino), error = function(e) NA_character_)
  if (is.na(col_origem) || !(col_origem %in% names(dt))) return(falhar("falha_coluna_origem", paste0("coluna de origem não localizada para ", origem)))
  if (is.na(col_destino) || !(col_destino %in% names(dt))) return(falhar("falha_coluna_destino", paste0("coluna de destino não localizada para ", destino)))
  if (monitora_correcao_coluna_protegida(col_origem) || monitora_correcao_coluna_protegida(col_destino)) return(falhar("bloqueada_coluna_protegida", "origem ou destino é coluna protegida"))

  linhas <- unique(as.integer(monitora_correcao_localizar_linhas_movimento_lote(dt, linha_lote, chaves)))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  n_esperado <- if ("n_linhas_esperado" %in% names(linha_lote)) suppressWarnings(as.integer(linha_lote$n_linhas_esperado[1L])) else NA_integer_
  if (!length(linhas)) return(falhar("falha_sem_linhas", "nenhuma linha-alvo localizada nas COLETAS do lote"))
  if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) return(falhar("falha_n_linhas", paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado)))

  formas_raw <- character(0)
  if ("token_pai" %in% names(linha_lote)) formas_raw <- c(formas_raw, monitora_correcao_parse_lista_serializada(linha_lote$token_pai[1L]))
  if (!length(formas_raw) && "valor_novo" %in% names(linha_lote)) formas_raw <- c(formas_raw, monitora_correcao_parse_lista_serializada(linha_lote$valor_novo[1L]))
  formas_raw <- unique(trimws(as.character(formas_raw)))
  formas_raw <- formas_raw[!is.na(formas_raw) & nzchar(formas_raw)]
  mover_todas <- any(formas_raw %in% c("__todas__", "todas", "todos", "all"))
  origem_vals <- as.character(dt[[col_origem]][linhas])
  if (isTRUE(mover_todas)) {
    formas <- unique(unlist(lapply(origem_vals, monitora_correcao_tokenizar), use.names = FALSE))
  } else {
    formas <- formas_raw
  }
  formas <- monitora_correcao_forma_canonica_lote(formas)
  formas <- setdiff(formas, c("", "na", "nan", "null", "desconhecida", "desconhecido", "outra", "outro", "outras", "outros", "outra_forma_vida", "forma_vida_outros", "nativa", "exotica", "seca", "morta", "seca_morta", "solo_nu", "serrapilheira", "fragmentos_botanicos", "material_inundado"))
  formas <- unique(formas[!is.na(formas) & nzchar(formas)])
  if (!length(formas)) return(falhar("falha_lote_sem_formas", "nenhuma forma de vida válida informada ou encontrada na origem"))

  presenca <- list()
  for (forma in formas) {
    toks <- unique(c(forma, monitora_correcao_sinonimos_forma(forma)))
    hit <- rep(FALSE, length(linhas))
    for (tok in toks) hit <- hit | monitora_correcao_token_presente_vec(origem_vals, tok)
    if (any(hit, na.rm = TRUE)) presenca[[forma]] <- hit
  }
  formas_efetivas <- names(presenca)
  if (!length(formas_efetivas)) return(falhar("bloqueada_operacao_repetida_sem_efeito", "nenhuma das formas selecionadas está presente na origem; possível operação repetida ou seleção incompatível"))

  ambiguidades_mvlote <- data.table::data.table()
  presenca_aplicavel <- presenca

  plano_dep_res <- monitora_correcao_planejar_migracao_dependentes_lote(
    dt = dt,
    linhas = linhas,
    origem = origem,
    destino = destino,
    formas_efetivas = formas_efetivas,
    presenca = presenca_aplicavel,
    dicionario = dicionario
  )
  plano_dep <- plano_dep_res$plano
  bloqueios_dep <- plano_dep_res$bloqueios
  if (nrow(bloqueios_dep)) {
    ambiguidades_mvlote <- data.table::rbindlist(list(
      ambiguidades_mvlote,
      monitora_correcao_anexar_contexto_ambiguidades_mvlote(dt, bloqueios_dep, id_cor, origem, destino, chaves)
    ), fill = TRUE, use.names = TRUE)
    presenca_aplicavel <- monitora_correcao_filtrar_presenca_mvlote(presenca_aplicavel, linhas, bloqueios_dep)
    formas_efetivas <- monitora_correcao_formas_efetivas_presenca(presenca_aplicavel)
    if (length(formas_efetivas)) {
      plano_dep_res <- monitora_correcao_planejar_migracao_dependentes_lote(
        dt = dt,
        linhas = linhas,
        origem = origem,
        destino = destino,
        formas_efetivas = formas_efetivas,
        presenca = presenca_aplicavel,
        dicionario = dicionario
      )
      plano_dep <- plano_dep_res$plano
      bloqueios_dep <- plano_dep_res$bloqueios
      if (nrow(bloqueios_dep)) {
        ambiguidades_mvlote <- data.table::rbindlist(list(
          ambiguidades_mvlote,
          monitora_correcao_anexar_contexto_ambiguidades_mvlote(dt, bloqueios_dep, id_cor, origem, destino, chaves)
        ), fill = TRUE, use.names = TRUE)
        presenca_aplicavel <- monitora_correcao_filtrar_presenca_mvlote(presenca_aplicavel, linhas, bloqueios_dep)
        formas_efetivas <- monitora_correcao_formas_efetivas_presenca(presenca_aplicavel)
        plano_dep_res <- monitora_correcao_planejar_migracao_dependentes_lote(
          dt = dt,
          linhas = linhas,
          origem = origem,
          destino = destino,
          formas_efetivas = formas_efetivas,
          presenca = presenca_aplicavel,
          dicionario = dicionario
        )
        plano_dep <- plano_dep_res$plano
      }
    }
  }
  if (!length(formas_efetivas)) {
    if (nrow(ambiguidades_mvlote) && isTRUE(gravar_relatorio_ambiguidades)) monitora_correcao_gravar_relatorio_ambiguidades_mvlote(ambiguidades_mvlote)
    extra <- if (nrow(ambiguidades_mvlote)) ambiguidades_mvlote[, data.table::data.table(
      id_correcao = id_cor,
      ordem_operacao = ordem,
      status = "ambigua_mantida_sem_migracao",
      mensagem = paste0("Ocorrência ambígua mantida sem migração: forma=", forma, "; coluna=", coluna_dependente, "; motivo=", motivo_ambiguidade),
      atributo = coluna_dependente,
      linha_indice = as.integer(linha_indice),
      valor_antes = valor_observado,
      valor_depois = valor_observado,
      arquivo_correcao = arquivo_correcao
    )] else data.table::data.table()
    return(falhar("bloqueada_sem_ocorrencias_migraveis", "todas as ocorrências do lote eram ambíguas; nenhuma alteração foi aplicada", extra = extra))
  }

  final_origem <- origem_vals
  final_destino <- as.character(dt[[col_destino]][linhas])
  for (forma in formas_efetivas) {
    toks <- unique(c(forma, monitora_correcao_sinonimos_forma(forma)))
    idx_f <- which(presenca_aplicavel[[forma]])
    if (length(idx_f)) {
      for (tok in toks) final_origem[idx_f] <- vapply(final_origem[idx_f], monitora_correcao_remove_token_valor, character(1), token = tok)
      final_destino[idx_f] <- vapply(final_destino[idx_f], monitora_correcao_append_token_valor, character(1), token = forma)
    }
  }

  habito_padrao <- if ("habito_escolhido" %in% names(linha_lote)) trimws(as.character(linha_lote$habito_escolhido[1L])) else ""
  if (is.na(habito_padrao)) habito_padrao <- ""
  habitos_validos <- c("terrestre", "epifita", "rupicola")
  plano_hab <- data.table::data.table(linha_indice = integer(), atributo = character(), valor_antes = character(), valor_depois = character(), mensagem = character())
  bloqueios_hab <- list()
  formas_cond <- intersect(formas_efetivas, c("bromelioide", "erva_bromelioide", "cactacea", "orquidea", "samambaia"))
  for (forma in formas_cond) {
    rows_f <- linhas[presenca_aplicavel[[forma]]]
    for (rr in rows_f) {
      dep_origem <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, origem, forma, dicionario, linha = rr, meta_xls = NULL), error = function(e) NA_character_)
      dep_destino <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, destino, forma, dicionario, linha = rr, meta_xls = NULL), error = function(e) NA_character_)
      if (!monitora_correcao_coluna_habito_segura(dt, dep_destino, destino, forma) || identical(dep_destino, col_destino)) {
        bloqueios_hab[[length(bloqueios_hab) + 1L]] <- data.table::data.table(forma = forma, linha_indice = rr, atributo = dep_destino, motivo = paste0("coluna de hábito do destino não localizada com segurança para ", forma))
        next
      }
      origem_segura <- monitora_correcao_coluna_habito_segura(dt, dep_origem, origem, forma) && !identical(dep_origem, col_origem)
      valor_origem_hab <- if (isTRUE(origem_segura)) as.character(dt[[dep_origem]][rr]) else NA_character_
      valor_dest_hab <- as.character(dt[[dep_destino]][rr])
      candidato <- if (!monitora_correcao_vazio(valor_origem_hab)) valor_origem_hab else habito_padrao
      candidato <- trimws(as.character(candidato))
      if (is.na(candidato) || !nzchar(candidato) || !(candidato %in% habitos_validos)) {
        bloqueios_hab[[length(bloqueios_hab) + 1L]] <- data.table::data.table(forma = forma, linha_indice = rr, atributo = dep_destino, motivo = paste0("hábito obrigatório ausente para ", forma, "; informe hábito padrão ou preencha a origem"))
        next
      }
      if (!monitora_correcao_vazio(valor_dest_hab) && !identical(monitora_correcao_na_para_vazio(valor_dest_hab), monitora_correcao_na_para_vazio(candidato))) {
        bloqueios_hab[[length(bloqueios_hab) + 1L]] <- data.table::data.table(forma = forma, linha_indice = rr, atributo = dep_destino, motivo = paste0("hábito de destino já preenchido com valor diferente para ", forma))
        next
      }
      if (monitora_correcao_na_para_vazio(valor_dest_hab) != monitora_correcao_na_para_vazio(candidato)) {
        plano_hab <- data.table::rbindlist(list(plano_hab, data.table::data.table(linha_indice = rr, atributo = dep_destino, valor_antes = valor_dest_hab, valor_depois = candidato, mensagem = "Movimento em lote: hábito obrigatório copiado/preenchido no destino")), fill = TRUE, use.names = TRUE)
      }
      if (isTRUE(origem_segura) && !monitora_correcao_vazio(valor_origem_hab)) {
        plano_hab <- data.table::rbindlist(list(plano_hab, data.table::data.table(linha_indice = rr, atributo = dep_origem, valor_antes = valor_origem_hab, valor_depois = NA_character_, mensagem = "Movimento em lote: hábito/dependente da origem limpo após migração")), fill = TRUE, use.names = TRUE)
      }
    }
  }
  if (length(bloqueios_hab)) {
    bb <- data.table::rbindlist(bloqueios_hab, fill = TRUE, use.names = TRUE)
    bb_rep <- data.table::data.table(
      forma = as.character(bb$forma),
      linha_indice = as.integer(bb$linha_indice),
      coluna_dependente = as.character(bb$atributo),
      motivo = as.character(bb$motivo),
      exemplo_valor = NA_character_
    )
    ambiguidades_mvlote <- data.table::rbindlist(list(
      ambiguidades_mvlote,
      monitora_correcao_anexar_contexto_ambiguidades_mvlote(dt, bb_rep, id_cor, origem, destino, chaves)
    ), fill = TRUE, use.names = TRUE)
 ### Restaura os tokens principais nas ocorrências com hábito ambíguo para que
 ### elas permaneçam intactas; demais ocorrências migráveis seguem no lote.
    for (rr in seq_len(nrow(bb_rep))) {
      forma_bb <- as.character(bb_rep$forma[rr])
      linha_bb <- suppressWarnings(as.integer(bb_rep$linha_indice[rr]))
      pos <- which(as.integer(linhas) == linha_bb)
      if (length(pos) && forma_bb %in% names(presenca_aplicavel)) {
        presenca_aplicavel[[forma_bb]][pos] <- FALSE
        final_origem[pos] <- origem_vals[pos]
        final_destino[pos] <- as.character(dt[[col_destino]][linhas[pos]])
      }
    }
    formas_efetivas <- monitora_correcao_formas_efetivas_presenca(presenca_aplicavel)
    if (nrow(plano_dep) && "forma" %in% names(plano_dep)) {
      pares_bloq <- unique(bb_rep[, .(forma = as.character(forma), linha_indice = as.integer(linha_indice))])
      plano_dep <- merge(
        plano_dep,
        pares_bloq[, .bloq := TRUE],
        by = c("forma", "linha_indice"),
        all.x = TRUE,
        sort = FALSE
      )
      plano_dep <- plano_dep[is.na(.bloq)]
      plano_dep[, .bloq := NULL]
    }
    if (!length(formas_efetivas)) {
      if (nrow(ambiguidades_mvlote) && isTRUE(gravar_relatorio_ambiguidades)) monitora_correcao_gravar_relatorio_ambiguidades_mvlote(ambiguidades_mvlote)
      extra <- ambiguidades_mvlote[, data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = "ambigua_mantida_sem_migracao", mensagem = paste0("Ocorrência ambígua mantida sem migração: forma=", forma, "; motivo=", motivo_ambiguidade), atributo = coluna_dependente, linha_indice = as.integer(linha_indice), valor_antes = valor_observado, valor_depois = valor_observado, arquivo_correcao = arquivo_correcao)]
      return(falhar("bloqueada_sem_ocorrencias_migraveis", "todas as ocorrências do lote eram ambíguas; nenhuma alteração foi aplicada", extra = extra))
    }
  }

  registrar <- function(status, msg, atributo, idx, antes, depois) {
    data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = msg, atributo = atributo, linha_indice = as.integer(idx), valor_antes = as.character(antes), valor_depois = as.character(depois), arquivo_correcao = arquivo_correcao)
  }
  audit <- data.table::data.table(); afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  mudou_origem <- monitora_correcao_na_para_vazio(origem_vals) != monitora_correcao_na_para_vazio(final_origem)
  mudou_destino <- monitora_correcao_na_para_vazio(as.character(dt[[col_destino]][linhas])) != monitora_correcao_na_para_vazio(final_destino)
  if (any(mudou_origem, na.rm = TRUE)) {
    data.table::set(dt, i = linhas[mudou_origem], j = col_origem, value = final_origem[mudou_origem])
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento em lote: token(s) removido(s) da categoria de origem", col_origem, linhas[mudou_origem], origem_vals[mudou_origem], final_origem[mudou_origem])), fill = TRUE, use.names = TRUE)
    afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_origem], atributo = col_origem)), fill = TRUE, use.names = TRUE)
  }
  if (any(mudou_destino, na.rm = TRUE)) {
    antes_destino <- as.character(dt[[col_destino]][linhas])
    data.table::set(dt, i = linhas[mudou_destino], j = col_destino, value = final_destino[mudou_destino])
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento em lote: forma(s) garantida(s) na categoria de destino", col_destino, linhas[mudou_destino], antes_destino[mudou_destino], final_destino[mudou_destino])), fill = TRUE, use.names = TRUE)
    afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_destino], atributo = col_destino)), fill = TRUE, use.names = TRUE)
  }
  if (nrow(plano_hab)) {
    plano_hab <- unique(plano_hab, by = c("linha_indice", "atributo", "valor_depois"))
    for (cc in unique(plano_hab$atributo)) {
      z <- plano_hab[atributo == cc]
      data.table::set(dt, i = z$linha_indice, j = cc, value = z$valor_depois)
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", z$mensagem, cc, z$linha_indice, z$valor_antes, z$valor_depois)), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = z$linha_indice, atributo = cc)), fill = TRUE, use.names = TRUE)
    }
  }
  if (nrow(plano_dep)) {
    plano_dep <- unique(plano_dep, by = c("linha_indice", "atributo", "valor_depois"))
    for (cc in unique(plano_dep$atributo)) {
      z <- plano_dep[atributo == cc]
      data.table::set(dt, i = z$linha_indice, j = cc, value = z$valor_depois)
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", z$mensagem, cc, z$linha_indice, z$valor_antes, z$valor_depois)), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = z$linha_indice, atributo = cc)), fill = TRUE, use.names = TRUE)
    }
  }
  tipo_col <- chaves$tipo_forma_vida
  if (!is.na(tipo_col) && tipo_col %in% names(dt)) {
    antes_tipo <- as.character(dt[[tipo_col]][linhas])
    monitora_correcao_recalcular_tipo_forma_vida(dt, linhas)
    depois_tipo <- as.character(dt[[tipo_col]][linhas])
    mudou_tipo <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_tipo)
    if (any(mudou_tipo, na.rm = TRUE)) {
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento em lote: tipo_forma_vida recalculado após origem/destino", tipo_col, linhas[mudou_tipo], antes_tipo[mudou_tipo], depois_tipo[mudou_tipo])), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_tipo], atributo = tipo_col)), fill = TRUE, use.names = TRUE)
    }
  }
  if (!nrow(audit)) {
    audit <- registrar("ignorada_operacao_repetida_sem_efeito", "Movimento em lote ignorado: origem, destino e dependentes já estavam coerentes", "__mover_forma_vida_lote__", linhas, NA_character_, NA_character_)
    return(list(dt = dt[], audit = audit[], linhas = linhas, afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE))
  }
  if (nrow(ambiguidades_mvlote)) {
    if (isTRUE(gravar_relatorio_ambiguidades)) monitora_correcao_gravar_relatorio_ambiguidades_mvlote(ambiguidades_mvlote)
    audit_amb <- ambiguidades_mvlote[, data.table::data.table(
      id_correcao = id_cor,
      ordem_operacao = ordem,
      status = "ambigua_mantida_sem_migracao",
      mensagem = paste0("Movimento em lote: ocorrência ambígua mantida sem migração; forma=", forma, "; motivo=", motivo_ambiguidade),
      atributo = coluna_dependente,
      linha_indice = as.integer(linha_indice),
      valor_antes = valor_observado,
      valor_depois = valor_observado,
      arquivo_correcao = arquivo_correcao,
      COLETA = COLETA,
      EA = EA,
      UA = UA,
      CICLO = CICLO,
      CAMPANHA = CAMPANHA,
      ANO = ANO,
      `Data (data_hora)` = `Data (data_hora)`,
      `Ponto amostral` = ponto_amostral,
      `Ponto metro` = ponto_metro
    )]
    audit <- data.table::rbindlist(list(audit, audit_amb), fill = TRUE, use.names = TRUE)
  }
  audit[, formas_movidas := monitora_correcao_colapsar_lista_serializada(formas_efetivas)]
  list(dt = dt[], audit = audit[], linhas = unique(linhas), afetacoes = unique(afetacoes), falha = FALSE)
}

monitora_correcao_aplicar_movimentos_forma_vida_lote_atomicos <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::copy(data.table::as.data.table(corr))
  if (!nrow(corr)) return(list(dt = dt[], corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  corr <- monitora_correcao_normalizar_mvlote_sessao(corr, contexto = arquivo_correcao)
  audit_norm_mvlote <- attr(corr, "auditoria_normalizacao_mvlote")
  if (is.null(audit_norm_mvlote)) audit_norm_mvlote <- data.table::data.table()
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  data.table::set(corr, j = ".grupo_mvlote_atom", value = data.table::fifelse(!is.na(corr$id_correcao) & nzchar(as.character(corr$id_correcao)), as.character(corr$id_correcao), paste0("__linha_", corr$ordem_tmp)))
  idx <- which(monitora_correcao_eh_operacao_movimento_forma_vida_lote(corr))
  if (!length(idx)) {
    if (".grupo_mvlote_atom" %in% names(corr)) corr[, .grupo_mvlote_atom := NULL]
    return(list(dt = dt[], corr = corr, audit = audit_norm_mvlote, linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  }
  grupos <- unique(corr[idx, .grupo_mvlote_atom])
  audit <- data.table::as.data.table(audit_norm_mvlote); linhas <- integer(); afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character()); falha <- FALSE
  for (gid in grupos) {
    grp <- corr[.grupo_mvlote_atom == gid]
    linha <- data.table::copy(grp[1L])
    if ("tipo_correcao" %in% names(linha)) linha[, tipo_correcao := "movimento_forma_vida_lote_atomico"]
    if ("acao" %in% names(linha)) linha[, acao := "mover_forma_vida_lote"]
    if ("atributo_coluna_registros_corrig" %in% names(linha)) linha[, atributo_coluna_registros_corrig := "__mover_forma_vida_lote__"]
    res <- monitora_correcao_aplicar_movimento_forma_vida_lote_atomico(dt, linha, chaves, indice, arquivo_correcao, dicionario, gravar_relatorio_ambiguidades = TRUE)
    dt <- res$dt
    if (nrow(res$audit)) audit <- data.table::rbindlist(list(audit, res$audit), fill = TRUE, use.names = TRUE)
    if (length(res$linhas)) linhas <- unique(c(linhas, res$linhas))
    if (nrow(res$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res$afetacoes), fill = TRUE, use.names = TRUE)
    status_res <- if (!is.null(res$audit) && data.table::is.data.table(res$audit) && "status" %in% names(res$audit)) res$audit$status else character(0)
    falha_res <- isTRUE(res$falha) && isTRUE(monitora_correcao_status_mvlote_fatal(status_res))
    falha <- isTRUE(falha) || isTRUE(falha_res)
  }
  corr_out <- corr[!(.grupo_mvlote_atom %in% grupos)]
  corr_out[, .grupo_mvlote_atom := NULL]
  corr[, .grupo_mvlote_atom := NULL]
  list(dt = dt[], corr = corr_out[], audit = audit[], linhas = linhas, afetacoes = unique(afetacoes), falha = falha, n_grupos = length(grupos))
}

### MVLOTE generalizado (movimento entre categorias e substituição intralista)
### -------------------------------------------------------------------------
### A busca dinâmica em runtime permite origem==destino quando a forma de
### origem difere da forma de destino
### (ex.: nativa/desconhecida -> nativa/samambaia), mantendo bloqueio apenas para
### operação realmente nula. A auditoria continua linha-a-linha; a aplicação é
### vetorizada por operação semântica.
monitora_correcao_aplicar_movimento_forma_vida_lote_atomico <- function(dt, linha_lote, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL, gravar_relatorio_ambiguidades = TRUE) {
  dt <- monitora_dt_referenciar(dt)
  linha_lote <- data.table::as.data.table(linha_lote)
  vazio_res <- list(dt = dt[], audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE)
  if (!nrow(linha_lote)) return(vazio_res)
  id_cor <- if ("id_correcao" %in% names(linha_lote)) as.character(linha_lote$id_correcao[1L]) else NA_character_
  ordem <- if ("ordem_operacao" %in% names(linha_lote)) linha_lote$ordem_operacao[1L] else NA_character_
  falhar <- function(status, msg, atributo = "__mover_forma_vida_lote__", extra = data.table::data.table()) {
    audit <- data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = paste0("Movimento/substituição atômica em lote bloqueado: ", msg), atributo = atributo, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao)
    if (nrow(extra)) audit <- data.table::rbindlist(list(audit, extra), fill = TRUE, use.names = TRUE)
    list(dt = dt[], audit = audit[], linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = TRUE)
  }
  informar <- function(status, msg, atributo = "__mover_forma_vida_lote__", linhas_info = integer()) {
    audit <- data.table::data.table(
      id_correcao = id_cor, ordem_operacao = ordem, status = status,
      mensagem = paste0("Movimento/substituição atômica em lote sem alteração fatal: ", msg),
      atributo = atributo, linha_indice = if (length(linhas_info)) as.integer(linhas_info) else NA_integer_,
      valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao
    )
    list(dt = dt[], audit = audit[], linhas = unique(as.integer(linhas_info)), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE)
  }
  origem <- if ("categoria_origem" %in% names(linha_lote)) tolower(trimws(as.character(linha_lote$categoria_origem[1L]))) else NA_character_
  destino <- if ("categoria_destino" %in% names(linha_lote)) tolower(trimws(as.character(linha_lote$categoria_destino[1L]))) else NA_character_
  cats <- tryCatch(monitora_contrato_categorias_movimento()$categoria, error = function(e) character(0))
  if (monitora_correcao_vazio(origem) || monitora_correcao_vazio(destino) || !origem %in% cats || !destino %in% cats) {
    return(falhar("falha_lote_categoria", "origem/destino ausentes ou inválidos"))
  }
  mv_desc_vals <- character(0)
  for (cc_mv in intersect(c("escopo_diagnostico_mvlote", "categoria_base_diagnostica", "token_pai", "token_removido", "valor_original_esperado"), names(linha_lote))) {
    mv_desc_vals <- c(mv_desc_vals, as.character(linha_lote[[cc_mv]][1L]))
  }
  mv_desc_norm <- tryCatch(monitora_correcao_limpar_texto(mv_desc_vals), error = function(e) tolower(trimws(mv_desc_vals)))
  mv_lote_desconhecida_semantica <- any(mv_desc_norm %in% c("forma_vida_desconhecida_categoria_base", "forma_vida_desconhecida", "desconhecida", "desconhecido"), na.rm = TRUE)

  col_origem <- tryCatch(monitora_correcao_coluna_forma_vida(dt, origem), error = function(e) NA_character_)
  col_destino <- tryCatch(monitora_correcao_coluna_forma_vida(dt, destino), error = function(e) NA_character_)
  if (is.na(col_origem) || !(col_origem %in% names(dt))) return(falhar("falha_coluna_origem", paste0("coluna de origem não localizada para ", origem)))
  if (is.na(col_destino) || !(col_destino %in% names(dt))) return(falhar("falha_coluna_destino", paste0("coluna de destino não localizada para ", destino)))
  if (monitora_correcao_coluna_protegida(col_origem) || monitora_correcao_coluna_protegida(col_destino)) return(falhar("bloqueada_coluna_protegida", "origem ou destino é coluna protegida"))

  linhas <- unique(as.integer(monitora_correcao_localizar_linhas_movimento_lote(dt, linha_lote, chaves)))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  n_esperado <- if ("n_linhas_esperado" %in% names(linha_lote)) suppressWarnings(as.integer(linha_lote$n_linhas_esperado[1L])) else NA_integer_
  if (!length(linhas)) return(falhar("falha_sem_linhas", "nenhuma linha-alvo diagnóstica localizada para o movimento em lote"))
  if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado && !isTRUE(mv_lote_desconhecida_semantica)) {
    return(falhar("falha_n_linhas", paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado, "; o MVLOTE deve usar as linhas diagnósticas serializadas, não a COLETA inteira")))
  }

  parse_vals <- function(...) {
    vals <- character(0)
    for (x in list(...)) vals <- c(vals, monitora_correcao_parse_serial_generico(x))
    vals <- unique(trimws(as.character(vals)))
    vals[!is.na(vals) & nzchar(vals)]
  }
 ### token_pai/token_removido são a intenção explícita. A fotografia
 ### valor_original_esperado não pode ampliar o conjunto a remover. Só há
 ### fallback para ela em ledger legado que não possua nenhum token explícito.
  formas_raw <- parse_vals(
    if ("token_removido" %in% names(linha_lote)) linha_lote$token_removido[1L] else NA_character_,
    if ("token_pai" %in% names(linha_lote)) linha_lote$token_pai[1L] else NA_character_
  )
  if (!length(formas_raw) && "valor_original_esperado" %in% names(linha_lote)) {
    formas_raw <- parse_vals(linha_lote$valor_original_esperado[1L])
  }
  mover_todas <- any(tolower(formas_raw) %in% c("__todas__", "todas", "todos", "all"))
  origem_vals <- as.character(dt[[col_origem]][linhas])
  if (isTRUE(mover_todas)) {
    formas_origem <- unique(unlist(lapply(origem_vals, monitora_correcao_tokenizar), use.names = FALSE))
  } else {
    formas_origem <- formas_raw
  }
  formas_origem <- monitora_correcao_forma_canonica_lote(formas_origem)
  formas_origem <- unique(formas_origem[!is.na(formas_origem) & nzchar(formas_origem)])
  formas_origem <- setdiff(formas_origem, c("", "na", "nan", "null", "outra", "outro", "outras", "outros", "outra_forma_vida", "forma_vida_outros", "nativa", "exotica", "seca", "morta", "seca_morta", "solo_nu", "serrapilheira", "fragmentos_botanicos", "material_inundado"))
  if (!length(formas_origem)) return(falhar("falha_lote_sem_formas", "nenhuma forma de vida de origem válida informada ou encontrada"))

  forma_destino <- parse_vals(if ("forma_valida_escolhida" %in% names(linha_lote)) linha_lote$forma_valida_escolhida[1L] else NA_character_, if ("valor_novo" %in% names(linha_lote)) linha_lote$valor_novo[1L] else NA_character_)
  forma_destino <- monitora_correcao_forma_canonica_lote(forma_destino)
  forma_destino <- unique(forma_destino[!is.na(forma_destino) & nzchar(forma_destino) & !forma_destino %in% c("__todas__", "todas", "todos", "all")])
  if (!length(forma_destino)) {
 ### Compatibilidade com movimento antigo: se não houver forma de destino explícita,
 ### preserva os próprios tokens migrados como destino.
    forma_destino <- formas_origem
  }
  forma_destino <- forma_destino[1L]
  dominio_destino <- tryCatch(monitora_contrato_tokens_categoria_movimento(destino), error = function(e) character(0))
  if (!length(dominio_destino) || !(forma_destino %in% dominio_destino)) {
    return(falhar("falha_forma_destino_fora_contrato", paste0("forma de destino '", forma_destino, "' não pertence ao domínio ", destino, " do contrato único")))
  }
  if (identical(origem, destino) && length(formas_origem) == 1L && identical(monitora_correcao_limpar_texto(formas_origem[1L]), monitora_correcao_limpar_texto(forma_destino))) {
    return(falhar("bloqueada_operacao_nula", "origem e destino são a mesma categoria e a mesma forma de vida; nada seria alterado"))
  }

  tokens_de_forma <- function(forma) {
    if (monitora_correcao_limpar_texto(forma) %in% c("desconhecida", "desconhecido")) return(unique(c("desconhecida", "desconhecido")))
    unique(c(forma, monitora_correcao_sinonimos_forma(forma)))
  }
  presenca <- list()
  for (forma in formas_origem) {
    toks <- tokens_de_forma(forma)
    hit <- rep(FALSE, length(linhas))
    if (monitora_correcao_limpar_texto(forma) %in% c("desconhecida", "desconhecido")) {
 ### MVLOTE de desconhecida usa linhas diagnósticas calculadas no painel.
 ### Essas linhas podem ser identificadas por dependentes/fotos de desconhecida,
 ### mesmo quando o token literal não aparece na lista principal; portanto, se
 ### linhas_alvo_serializadas chegou até aqui, ela já é o alvo correto.
      linhas_desc_cat <- tryCatch(monitora_correcao_linhas_desconhecida_categoria_base(dt, origem, linhas, dicionario = dicionario), error = function(e) integer(0))
      if (length(linhas_desc_cat)) {
        hit <- linhas %in% linhas_desc_cat
      } else if ("linhas_alvo_serializadas" %in% names(linha_lote) && nzchar(trimws(as.character(linha_lote$linhas_alvo_serializadas[1L])))) {
 ### linhas_alvo_serializadas define o universo candidato, mas não autoriza
 ### aplicação cega: no estado corrente, a ocorrência diagnóstica ainda deve
 ### ter desconhecida na categoria-base indicada. Se uma operação anterior já
 ### corrigiu a linha, o MVLOTE vira no-op auditado, não falha fatal.
        hit <- monitora_correcao_contem_qualquer_token_vec(origem_vals, tokens_de_forma(forma))
        hit[is.na(hit)] <- FALSE
      }
    } else {
      for (tok in toks) hit <- hit | monitora_correcao_token_presente_vec(origem_vals, tok)
    }
    if (any(hit, na.rm = TRUE)) presenca[[forma]] <- hit
  }
  if (!length(presenca)) return(informar("ignorada_sem_efeito_estado_ja_corrigido", "nenhuma das formas de origem selecionadas permanece no estado corrente para a categoria-base escolhida", linhas))
  linhas_migraveis <- rep(FALSE, length(linhas))
  for (hh in presenca) linhas_migraveis <- linhas_migraveis | hh
  linhas_alvo <- linhas[linhas_migraveis]
  if (!length(linhas_alvo)) return(informar("sem_ocorrencias_migraveis_estado_ja_corrigido", "nenhuma ocorrência migrável restou no estado corrente; provável operação substituída ou já aplicada", linhas))

  final_origem <- origem_vals
  final_destino <- as.character(dt[[col_destino]][linhas])
  for (forma in names(presenca)) {
    idx_f <- which(presenca[[forma]])
    if (!length(idx_f)) next
    for (tok in tokens_de_forma(forma)) final_origem[idx_f] <- vapply(final_origem[idx_f], monitora_correcao_remove_token_valor, character(1), token = tok)
    final_destino[idx_f] <- vapply(final_destino[idx_f], monitora_correcao_append_token_valor, character(1), token = forma_destino)
  }
 ### Se origem e destino são a mesma lista, aplicar substituição no mesmo vetor.
  if (identical(col_origem, col_destino)) {
    final_mesma <- origem_vals
    for (forma in names(presenca)) {
      idx_f <- which(presenca[[forma]])
      for (tok in tokens_de_forma(forma)) final_mesma[idx_f] <- vapply(final_mesma[idx_f], monitora_correcao_remove_token_valor, character(1), token = tok)
      final_mesma[idx_f] <- vapply(final_mesma[idx_f], monitora_correcao_append_token_valor, character(1), token = forma_destino)
    }
    final_origem <- final_mesma
    final_destino <- final_mesma
  }

 ### Validar todos os condicionantes do destino antes da primeira escrita,
 ### preservando a atomicidade real do movimento em lote.
  habito_destino <- if ("habito_escolhido" %in% names(linha_lote)) trimws(as.character(linha_lote$habito_escolhido[1L])) else ""
  if (is.na(habito_destino)) habito_destino <- ""
  forma_exige_habito <- monitora_correcao_limpar_texto(forma_destino) %in% monitora_correcao_tokens_formas_exigem_habito()
  dep_destino <- NA_character_
  if (isTRUE(forma_exige_habito)) {
    if (!nzchar(habito_destino) || !(habito_destino %in% c("terrestre", "epifita", "rupicola"))) return(falhar("falha_habito_obrigatorio", paste0("forma de destino '", forma_destino, "' exige hábito terrestre/epifita/rupicola")))
    dep_destino <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, destino, forma_destino, dicionario, linha = linhas_alvo[1L], meta_xls = NULL), error = function(e) NA_character_)
    if (!monitora_correcao_coluna_habito_segura(dt, dep_destino, destino, forma_destino) || identical(dep_destino, col_destino)) return(falhar("falha_coluna_habito_destino", "coluna de hábito segura não localizada para o destino"))
  } else if (nzchar(habito_destino)) {
    return(falhar("falha_habito_indevido", paste0("hábito informado para forma que não exige hábito: ", forma_destino)))
  }

 ### Gate de conservação antes da primeira escrita. Mesmo em lote ou
 ### substituição intralista, somente os tokens explicitamente selecionados
 ### (e seus aliases contratuais) podem desaparecer.
  remocoes_permitidas <- unique(unlist(lapply(names(presenca), tokens_de_forma), use.names = FALSE))
  cons_origem <- monitora_correcao_validar_conservacao_tokens(origem_vals, final_origem, remocoes_permitidas)
  if (!isTRUE(cons_origem$ok)) {
    return(falhar("falha_invariante_conservacao_origem", paste0("token(s) não selecionado(s) desapareceriam da origem; linhas_relativas=", cons_origem$detalhes)))
  }
  if (!identical(col_origem, col_destino)) {
    antes_destino_conservacao <- as.character(dt[[col_destino]][linhas])
    cons_destino <- monitora_correcao_validar_conservacao_tokens(antes_destino_conservacao, final_destino, character(0))
    if (!isTRUE(cons_destino$ok)) {
      return(falhar("falha_invariante_conservacao_destino", paste0("token(s) preexistente(s) desapareceriam do destino; linhas_relativas=", cons_destino$detalhes)))
    }
  }

  registrar <- function(status, msg, atributo, idx, antes, depois) {
    data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = msg, atributo = atributo, linha_indice = as.integer(idx), valor_antes = as.character(antes), valor_depois = as.character(depois), arquivo_correcao = arquivo_correcao)
  }
  audit <- data.table::data.table(); afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  mudou_origem <- monitora_correcao_na_para_vazio(origem_vals) != monitora_correcao_na_para_vazio(final_origem)
  antes_destino <- as.character(dt[[col_destino]][linhas])
  mudou_destino <- monitora_correcao_na_para_vazio(antes_destino) != monitora_correcao_na_para_vazio(final_destino)
  if (identical(col_origem, col_destino)) mudou_destino <- rep(FALSE, length(mudou_destino))

  if (any(mudou_origem, na.rm = TRUE)) {
    data.table::set(dt, i = linhas[mudou_origem], j = col_origem, value = final_origem[mudou_origem])
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", if (identical(origem, destino)) "Substituição intralista em lote: forma de origem removida e forma de destino garantida" else "Movimento em lote: token(s) removido(s) da categoria de origem", col_origem, linhas[mudou_origem], origem_vals[mudou_origem], final_origem[mudou_origem])), fill = TRUE, use.names = TRUE)
    afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_origem], atributo = col_origem)), fill = TRUE, use.names = TRUE)
  }
  if (any(mudou_destino, na.rm = TRUE)) {
    data.table::set(dt, i = linhas[mudou_destino], j = col_destino, value = final_destino[mudou_destino])
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento em lote: forma de destino garantida na categoria de destino", col_destino, linhas[mudou_destino], antes_destino[mudou_destino], final_destino[mudou_destino])), fill = TRUE, use.names = TRUE)
    afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_destino], atributo = col_destino)), fill = TRUE, use.names = TRUE)
  }

 ### Limpeza contratual dos dependentes da forma removida. O índice é montado
 ### somente para as formas efetivamente presentes e as escritas continuam
 ### vetorizadas por coluna; não há varredura adicional do data.table inteiro.
  deps_limpar <- list()
  for (forma_origem in names(presenca)) {
    pos_forma <- which(presenca[[forma_origem]])
    if (!length(pos_forma)) next
    cols_dep <- tryCatch(monitora_correcao_colunas_dependentes_por_token(dt, origem, forma_origem, dicionario), error = function(e) character(0))
    cols_dep <- setdiff(unique(cols_dep[cols_dep %in% names(dt) & !monitora_correcao_coluna_protegida(cols_dep)]), c(col_origem, col_destino))
    for (dep_col in cols_dep) deps_limpar[[dep_col]] <- unique(c(deps_limpar[[dep_col]], linhas[pos_forma]))
  }
  for (dep_col in names(deps_limpar)) {
    idx_dep <- unique(as.integer(deps_limpar[[dep_col]]))
    antes_dep <- as.character(dt[[dep_col]][idx_dep])
    limpar_dep <- !monitora_correcao_vazio_vec(antes_dep)
    if (!any(limpar_dep, na.rm = TRUE)) next
    idx_dep <- idx_dep[limpar_dep]
    antes_dep <- antes_dep[limpar_dep]
    depois_dep <- rep(NA_character_, length(idx_dep))
    data.table::set(dt, i = idx_dep, j = dep_col, value = depois_dep)
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento/substituição em lote: dependente da forma removida limpo", dep_col, idx_dep, antes_dep, depois_dep)), fill = TRUE, use.names = TRUE)
    afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = idx_dep, atributo = dep_col)), fill = TRUE, use.names = TRUE)
  }

  if (isTRUE(forma_exige_habito)) {
    antes_h <- as.character(dt[[dep_destino]][linhas_alvo])
    depois_h <- rep(habito_destino, length(linhas_alvo))
    mudou_h <- monitora_correcao_na_para_vazio(antes_h) != monitora_correcao_na_para_vazio(depois_h)
    if (any(mudou_h, na.rm = TRUE)) {
      data.table::set(dt, i = linhas_alvo[mudou_h], j = dep_destino, value = depois_h[mudou_h])
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento/substituição em lote: hábito obrigatório preenchido no destino", dep_destino, linhas_alvo[mudou_h], antes_h[mudou_h], depois_h[mudou_h])), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas_alvo[mudou_h], atributo = dep_destino)), fill = TRUE, use.names = TRUE)
    }
  }

  if (any(monitora_correcao_limpar_texto(formas_origem) %in% c("desconhecida", "desconhecido"))) {
    categorias_desc <- tryCatch(monitora_contrato_categorias_movimento()[admite_desconhecida == TRUE, categoria], error = function(e) c("nativa", "exotica", "seca_morta"))
    res_desc_dep <- monitora_correcao_sanitizar_dependentes_desconhecida(
      dt, linhas = linhas_alvo, categorias = categorias_desc, id_correcao = id_cor,
      ordem_operacao = ordem, arquivo_correcao = arquivo_correcao, dicionario = dicionario, registrar_preservadas = TRUE
    )
    dt <- res_desc_dep$dt
    if (nrow(res_desc_dep$audit)) audit <- data.table::rbindlist(list(audit, res_desc_dep$audit), fill = TRUE, use.names = TRUE)
    if (nrow(res_desc_dep$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res_desc_dep$afetacoes), fill = TRUE, use.names = TRUE)
  }
  tipo_col <- chaves$tipo_forma_vida
  if (!is.na(tipo_col) && tipo_col %in% names(dt)) {
    antes_tipo <- as.character(dt[[tipo_col]][linhas_alvo])
    monitora_correcao_recalcular_tipo_forma_vida(dt, linhas_alvo)
    depois_tipo <- as.character(dt[[tipo_col]][linhas_alvo])
    mudou_tipo <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_tipo)
    if (any(mudou_tipo, na.rm = TRUE)) {
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento/substituição em lote: tipo_forma_vida recalculado", tipo_col, linhas_alvo[mudou_tipo], antes_tipo[mudou_tipo], depois_tipo[mudou_tipo])), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas_alvo[mudou_tipo], atributo = tipo_col)), fill = TRUE, use.names = TRUE)
    }
  }
  if (!nrow(audit)) return(informar("ignorada_operacao_repetida_sem_efeito", "estado final já estava coerente; nenhuma alteração necessária", linhas_info = linhas_alvo))
  audit[, formas_origem := monitora_correcao_colapsar_lista_serializada(formas_origem)]
  audit[, forma_destino := forma_destino]
  audit[, modo_movimento := ifelse(identical(origem, destino), "substituicao_intralista", "movimento_entre_categorias")]
  list(dt = dt[], audit = audit[], linhas = unique(linhas_alvo), afetacoes = unique(afetacoes), falha = FALSE)
}


### Movimento atômico de forma de vida
### -------------------------------------------------------------------------
### Movimento de forma de vida altera origem, destino, dependentes e campo
### superior. Aqui o grupo é tratado como transação semântica: ou o conjunto
### validado é aplicado, ou nada é aplicado.
monitora_correcao_eh_operacao_movimento_forma_vida <- function(corr) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(logical(0))
  tipo <- if ("tipo_correcao" %in% names(corr)) tolower(trimws(as.character(corr$tipo_correcao))) else rep("", nrow(corr))
  acao <- if ("acao" %in% names(corr)) tolower(trimws(as.character(corr$acao))) else rep("", nrow(corr))
  atributo <- if ("atributo_coluna_registros_corrig" %in% names(corr)) tolower(trimws(as.character(corr$atributo_coluna_registros_corrig))) else rep("", nrow(corr))
  tipo %in% c("movimento_forma_vida_atomico", "movimento_forma_vida_condicional", "movimento_forma_vida") |
    acao %in% c("mover_forma_vida", "movimento_forma_vida_atomico") |
    atributo %in% c("__mover_forma_vida__", "__movimento_forma_vida__")
}

monitora_correcao_compactar_movimento_forma_vida_atomico <- function(grupo) {
  grupo <- data.table::as.data.table(grupo)
  if (!nrow(grupo)) return(grupo)
  if ("ordem_operacao" %in% names(grupo)) {
    grupo[, .ordem_atom_tmp := suppressWarnings(as.integer(ordem_operacao))]
    data.table::setorder(grupo, .ordem_atom_tmp, na.last = TRUE)
    grupo[, .ordem_atom_tmp := NULL]
  }
  pegar_primeiro <- function(col, default = NA_character_) {
    if (!(col %in% names(grupo))) return(default)
    vals <- as.character(grupo[[col]])
    vals <- vals[!is.na(vals) & nzchar(trimws(vals))]
    if (length(vals)) vals[1L] else default
  }
  linha <- data.table::copy(grupo[1L])
  if ("acao" %in% names(linha)) linha[, acao := "mover_forma_vida"]
  if ("tipo_correcao" %in% names(linha)) linha[, tipo_correcao := "movimento_forma_vida_atomico"]
  if ("atributo_coluna_registros_corrig" %in% names(linha)) linha[, atributo_coluna_registros_corrig := "__mover_forma_vida__"]
  if ("ordem_operacao" %in% names(linha)) {
    ord_vals <- suppressWarnings(as.integer(grupo$ordem_operacao))
    ord_vals <- ord_vals[!is.na(ord_vals) & is.finite(ord_vals)]
    linha[, ordem_operacao := if (length(ord_vals)) min(ord_vals) else NA_integer_]
  }
  if ("valor_novo" %in% names(linha)) {
    destino <- pegar_primeiro("valor_novo", pegar_primeiro("token_pai"))
    if (all(c("acao", "valor_novo") %in% names(grupo))) {
      vals_append <- unique(as.character(grupo[tolower(trimws(as.character(acao))) %in% c("append_token", "adicionar_token", "mover_forma_vida"), valor_novo]))
      vals_append <- vals_append[!is.na(vals_append) & nzchar(trimws(vals_append))]
      if (length(vals_append)) destino <- vals_append[1L]
    }
    linha[, valor_novo := destino]
  }
  tokens_remover <- character(0)
  if (all(c("acao", "valor_novo") %in% names(grupo))) {
    tokens_remover <- c(tokens_remover, as.character(grupo[tolower(trimws(as.character(acao))) %in% c("remove_token", "remover_token"), valor_novo]))
  }
  if ("token_removido" %in% names(grupo)) tokens_remover <- c(tokens_remover, monitora_correcao_parse_lista_serializada(pegar_primeiro("token_removido")))
  if ("token_pai" %in% names(grupo)) tokens_remover <- c(tokens_remover, as.character(grupo$token_pai))
  tokens_remover <- unique(trimws(tokens_remover))
  tokens_remover <- tokens_remover[!is.na(tokens_remover) & nzchar(tokens_remover)]
  if ("token_removido" %in% names(linha)) linha[, token_removido := monitora_correcao_colapsar_lista_serializada(tokens_remover)]
  if ("token_pai" %in% names(linha) && monitora_correcao_vazio(linha$token_pai[1L])) linha[, token_pai := pegar_primeiro("valor_novo")]
  if ("categoria_origem" %in% names(linha) && monitora_correcao_vazio(linha$categoria_origem[1L])) linha[, categoria_origem := pegar_primeiro("categoria_origem")]
  if ("categoria_destino" %in% names(linha) && monitora_correcao_vazio(linha$categoria_destino[1L])) linha[, categoria_destino := pegar_primeiro("categoria_destino")]
  if ("habito_escolhido" %in% names(linha)) {
    hab <- pegar_primeiro("habito_escolhido")
    if (monitora_correcao_vazio(hab) && all(c("acao", "valor_novo") %in% names(grupo))) {
      cand <- as.character(grupo[tolower(trimws(as.character(acao))) %in% c("update", "substituir_valor"), valor_novo])
      cand <- cand[!is.na(cand) & nzchar(trimws(cand)) & cand %in% c("terrestre", "epifita", "rupicola")]
      if (length(cand)) hab <- cand[1L]
    }
    linha[, habito_escolhido := hab]
  }
  linha[]
}

monitora_correcao_aplicar_movimento_forma_vida_atomico <- function(dt, linha_mov, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL) {
  dt <- monitora_dt_referenciar(dt)
  linha_mov <- data.table::as.data.table(linha_mov)
  if (!nrow(linha_mov)) return(list(dt = dt[], audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE))
  id_cor <- if ("id_correcao" %in% names(linha_mov)) as.character(linha_mov$id_correcao[1L]) else NA_character_
  ordem <- if ("ordem_operacao" %in% names(linha_mov)) linha_mov$ordem_operacao[1L] else NA_character_
  falhar <- function(status, msg, atributo = "__mover_forma_vida__") {
    list(
      dt = dt[],
      audit = data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = paste0("Movimento atômico de forma de vida bloqueado: ", msg), atributo = atributo, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao),
      linhas = integer(),
      afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()),
      falha = TRUE
    )
  }
  origem <- if ("categoria_origem" %in% names(linha_mov)) tolower(trimws(as.character(linha_mov$categoria_origem[1L]))) else NA_character_
  destino <- if ("categoria_destino" %in% names(linha_mov)) tolower(trimws(as.character(linha_mov$categoria_destino[1L]))) else NA_character_
  forma_destino <- if ("valor_novo" %in% names(linha_mov)) trimws(as.character(linha_mov$valor_novo[1L])) else NA_character_
  token_pai <- if ("token_pai" %in% names(linha_mov)) trimws(as.character(linha_mov$token_pai[1L])) else NA_character_
  if (monitora_correcao_vazio(forma_destino)) forma_destino <- token_pai
  if (monitora_correcao_vazio(token_pai)) token_pai <- forma_destino
  if (monitora_correcao_vazio(origem) || monitora_correcao_vazio(destino) || monitora_correcao_vazio(forma_destino)) return(falhar("falha_movimento_atomico_incompleto", "categoria de origem/destino ou forma de vida não informada"))
  cats <- tryCatch(monitora_contrato_categorias_movimento()$categoria, error = function(e) character(0))
  if (!(origem %in% cats) || !(destino %in% cats)) return(falhar("falha_movimento_categoria", "categoria de origem/destino fora do contrato único"))
  dominio_destino <- tryCatch(monitora_contrato_tokens_categoria_movimento(destino), error = function(e) character(0))
  if (!length(dominio_destino) || !(forma_destino %in% dominio_destino)) return(falhar("falha_forma_destino_fora_contrato", paste0("forma de destino '", forma_destino, "' não pertence ao domínio ", destino, " do contrato único")))
  col_origem <- tryCatch(monitora_correcao_coluna_forma_vida(dt, origem), error = function(e) NA_character_)
  col_destino <- tryCatch(monitora_correcao_coluna_forma_vida(dt, destino), error = function(e) NA_character_)
  if (is.na(col_origem) || !(col_origem %in% names(dt))) return(falhar("falha_coluna_origem", paste0("coluna de origem não localizada para ", origem)))
  if (is.na(col_destino) || !(col_destino %in% names(dt))) return(falhar("falha_coluna_destino", paste0("coluna de destino não localizada para ", destino)))
  if (monitora_correcao_coluna_protegida(col_origem) || monitora_correcao_coluna_protegida(col_destino)) return(falhar("bloqueada_coluna_protegida", "origem ou destino é coluna protegida"))

  linhas <- unique(as.integer(monitora_correcao_localizar_linhas(dt, linha_mov, chaves, indice)))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  n_esperado <- if ("n_linhas_esperado" %in% names(linha_mov)) suppressWarnings(as.integer(linha_mov$n_linhas_esperado[1L])) else NA_integer_
  if (!length(linhas)) return(falhar("falha_sem_linhas", "nenhuma linha-alvo localizada"))
  if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) return(falhar("falha_n_linhas", paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado)))

  tokens_remover <- character(0)
  if ("token_removido" %in% names(linha_mov)) tokens_remover <- c(tokens_remover, monitora_correcao_parse_lista_serializada(linha_mov$token_removido[1L]))
 ### Origem e destino agora são escolhas independentes. Somente o token de
 ### origem (e seus aliases serializados) pode ser removido da lista de origem;
 ### a forma de destino é apenas adicionada à lista de destino. A fotografia
 ### valor_original_esperado é usada abaixo somente como pré-condição.
  if (!length(tokens_remover)) tokens_remover <- token_pai
  tokens_remover <- unique(monitora_correcao_limpar_texto(tokens_remover))
  tokens_remover <- tokens_remover[!is.na(tokens_remover) & nzchar(tokens_remover)]
  if (!length(tokens_remover)) tokens_remover <- forma_destino
  tokens_origem_canon <- tryCatch(monitora_correcao_forma_canonica_lote(tokens_remover), error = function(e) tokens_remover)
  forma_destino_canon <- tryCatch(monitora_correcao_forma_canonica_lote(forma_destino)[1L], error = function(e) forma_destino)
  if (identical(col_origem, col_destino) && length(tokens_origem_canon) == 1L && identical(tokens_origem_canon[1L], forma_destino_canon)) {
    return(falhar("bloqueada_operacao_nula", "origem e destino indicam a mesma categoria e a mesma forma de vida"))
  }

  registrar <- function(status, msg, atributo, idx, antes, depois) {
    data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = msg, atributo = atributo, linha_indice = as.integer(idx), valor_antes = as.character(antes), valor_depois = as.character(depois), arquivo_correcao = arquivo_correcao)
  }
  audit <- data.table::data.table()
  linhas_afetadas <- integer()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())

  antes_origem <- as.character(dt[[col_origem]][linhas])
  depois_origem <- antes_origem
  for (tok in tokens_remover) depois_origem <- vapply(depois_origem, monitora_correcao_remove_token_valor, character(1), token = tok)
  esperado <- if ("valor_original_esperado" %in% names(linha_mov)) linha_mov$valor_original_esperado[1L] else NA_character_
  if (!monitora_correcao_vazio(esperado)) {
    iguais <- monitora_correcao_na_para_vazio(antes_origem) == monitora_correcao_na_para_vazio(esperado)
    contem_algum <- Reduce(`|`, lapply(tokens_remover, function(tok) monitora_correcao_token_presente_vec(antes_origem, tok)))
    if (!all(iguais) && !all(contem_algum)) return(falhar("falha_precondicao_origem", "valor_original_esperado divergiu e token-alvo não estava presente em todas as linhas-alvo", col_origem))
  }
  antes_destino <- as.character(dt[[col_destino]][linhas])
  depois_destino <- vapply(antes_destino, monitora_correcao_append_token_valor, character(1), token = forma_destino)
  if (identical(col_origem, col_destino)) {
 ### Substituição intralista: remover e adicionar no mesmo vetor, com uma
 ### única escrita. O caminho anterior escrevia origem e depois destino a
 ### partir de fotografias independentes e podia restaurar o token removido.
    depois_mesma_lista <- vapply(depois_origem, monitora_correcao_append_token_valor, character(1), token = forma_destino)
    depois_origem <- depois_mesma_lista
    depois_destino <- depois_mesma_lista
  }
  cons_origem <- monitora_correcao_validar_conservacao_tokens(antes_origem, depois_origem, tokens_remover)
  if (!isTRUE(cons_origem$ok)) {
    return(falhar("falha_invariante_conservacao_origem", paste0("token(s) não selecionado(s) desapareceriam da origem; linhas_relativas=", cons_origem$detalhes), col_origem))
  }
  if (!identical(col_origem, col_destino)) {
    cons_destino <- monitora_correcao_validar_conservacao_tokens(antes_destino, depois_destino, character(0))
    if (!isTRUE(cons_destino$ok)) {
      return(falhar("falha_invariante_conservacao_destino", paste0("token(s) preexistente(s) desapareceriam do destino; linhas_relativas=", cons_destino$detalhes), col_destino))
    }
  }
  mudou_origem <- monitora_correcao_na_para_vazio(antes_origem) != monitora_correcao_na_para_vazio(depois_origem)
  mudou_destino <- monitora_correcao_na_para_vazio(antes_destino) != monitora_correcao_na_para_vazio(depois_destino)
  if (identical(col_origem, col_destino)) mudou_destino <- rep(FALSE, length(mudou_destino))

  deps_origem_cols <- character(0)
  deps <- if (exists("MONITORA_DEPENDENCIAS_CORRECOES", inherits = TRUE)) get("MONITORA_DEPENDENCIAS_CORRECOES", inherits = TRUE) else NULL
  if (!is.null(deps) && nrow(data.table::as.data.table(deps)) > 0L) {
    deps_dt <- data.table::as.data.table(deps)
    if (all(c("parent_name", "token", "dependent_name") %in% names(deps_dt))) {
      deps_mov <- deps_dt[parent_name == paste0("forma_vida_", origem) & token %in% tokens_remover]
      if (nrow(deps_mov) > 0L) deps_origem_cols <- unique(vapply(deps_mov$dependent_name, function(nn) monitora_correcao_resolver_coluna(dt, nn, dicionario, permitir_heuristica = FALSE), character(1)))
    }
  }
  deps_origem_cols <- unique(deps_origem_cols[
    !is.na(deps_origem_cols) & deps_origem_cols %in% names(dt) &
      !monitora_correcao_coluna_protegida(deps_origem_cols)
  ])
  if (!length(deps_origem_cols)) deps_origem_cols <- unique(unlist(lapply(tokens_remover, function(tok) monitora_correcao_colunas_dependentes_por_token(dt, origem, tok, dicionario)), use.names = FALSE))
  deps_origem_cols <- unique(deps_origem_cols[!is.na(deps_origem_cols) & deps_origem_cols %in% names(dt) & !monitora_correcao_coluna_protegida(deps_origem_cols)])
  deps_origem_cols <- setdiff(deps_origem_cols, c(col_origem, col_destino))
  atualizacoes_deps <- list()
  for (dep_col in deps_origem_cols) {
    antes_dep <- as.character(dt[[dep_col]][linhas])
    limpar <- !monitora_correcao_vazio_vec(antes_dep)
    if (any(limpar, na.rm = TRUE)) atualizacoes_deps[[dep_col]] <- list(idx = linhas[limpar], antes = antes_dep[limpar], depois = rep(NA_character_, sum(limpar, na.rm = TRUE)))
  }

  habito <- if ("habito_escolhido" %in% names(linha_mov)) trimws(as.character(linha_mov$habito_escolhido[1L])) else ""
  if (is.na(habito)) habito <- ""
  forma_exige_habito <- monitora_correcao_limpar_texto(forma_destino) %in% monitora_correcao_tokens_formas_exigem_habito()
 ### O campo gravado na fila é descritivo; a transação sempre resolve de novo
 ### o destino físico pelo contrato vigente para não confiar em alias legado.
  dep_destino <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, destino, forma_destino, dicionario, linha = linhas[1L], meta_xls = NULL), error = function(e) NA_character_)
  atualizacao_habito <- NULL
  if (isTRUE(forma_exige_habito)) {
    if (!nzchar(habito) || !(habito %in% c("terrestre", "epifita", "rupicola"))) return(falhar("falha_habito_obrigatorio", paste0("forma '", forma_destino, "' exige hábito terrestre/epifita/rupicola")))
    if (!monitora_correcao_coluna_habito_segura(dt, dep_destino, destino, forma_destino) || identical(dep_destino, col_destino)) return(falhar("falha_coluna_habito_destino", "coluna de hábito segura não localizada para o destino"))
    antes_hab <- as.character(dt[[dep_destino]][linhas])
    depois_hab <- rep(habito, length(linhas))
    mudou_hab <- monitora_correcao_na_para_vazio(antes_hab) != monitora_correcao_na_para_vazio(depois_hab)
    if (any(mudou_hab, na.rm = TRUE)) atualizacao_habito <- list(col = dep_destino, idx = linhas[mudou_hab], antes = antes_hab[mudou_hab], depois = depois_hab[mudou_hab])
  } else if (nzchar(habito)) {
    return(falhar("falha_habito_indevido", paste0("hábito informado para forma que não exige hábito: ", forma_destino)))
  }

  if (any(mudou_origem, na.rm = TRUE)) {
    data.table::set(dt, i = linhas[mudou_origem], j = col_origem, value = depois_origem[mudou_origem])
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", if (identical(col_origem, col_destino)) "Substituição intralista atômica: forma de origem removida e forma de destino garantida" else "Movimento atômico: token(s) removido(s) da categoria de origem", col_origem, linhas[mudou_origem], antes_origem[mudou_origem], depois_origem[mudou_origem])), fill = TRUE, use.names = TRUE)
    linhas_afetadas <- unique(c(linhas_afetadas, linhas[mudou_origem])); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_origem], atributo = col_origem)), fill = TRUE, use.names = TRUE)
  }
  if (any(mudou_destino, na.rm = TRUE)) {
    data.table::set(dt, i = linhas[mudou_destino], j = col_destino, value = depois_destino[mudou_destino])
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento atômico: forma garantida na categoria de destino", col_destino, linhas[mudou_destino], antes_destino[mudou_destino], depois_destino[mudou_destino])), fill = TRUE, use.names = TRUE)
    linhas_afetadas <- unique(c(linhas_afetadas, linhas[mudou_destino])); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_destino], atributo = col_destino)), fill = TRUE, use.names = TRUE)
  }
  for (dep_col in names(atualizacoes_deps)) {
    zz <- atualizacoes_deps[[dep_col]]
    data.table::set(dt, i = zz$idx, j = dep_col, value = zz$depois)
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento atômico: campo inferior/dependente da origem limpo", dep_col, zz$idx, zz$antes, zz$depois)), fill = TRUE, use.names = TRUE)
    linhas_afetadas <- unique(c(linhas_afetadas, zz$idx)); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = zz$idx, atributo = dep_col)), fill = TRUE, use.names = TRUE)
  }
  if (!is.null(atualizacao_habito)) {
    data.table::set(dt, i = atualizacao_habito$idx, j = atualizacao_habito$col, value = atualizacao_habito$depois)
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento atômico: hábito obrigatório preenchido no destino", atualizacao_habito$col, atualizacao_habito$idx, atualizacao_habito$antes, atualizacao_habito$depois)), fill = TRUE, use.names = TRUE)
    linhas_afetadas <- unique(c(linhas_afetadas, atualizacao_habito$idx)); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = atualizacao_habito$idx, atributo = atualizacao_habito$col)), fill = TRUE, use.names = TRUE)
  }
  if (any(monitora_correcao_normalizar_nome_coluna(tokens_remover) %in% monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokens_desconhecida()))) {
    categorias_desc <- tryCatch(monitora_contrato_categorias_movimento()[admite_desconhecida == TRUE, categoria], error = function(e) c("nativa", "exotica", "seca_morta"))
    res_desc_dep <- monitora_correcao_sanitizar_dependentes_desconhecida(
      dt,
      linhas = linhas,
      categorias = intersect(c(origem, destino), categorias_desc),
      id_correcao = id_cor,
      ordem_operacao = ordem,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario,
      registrar_preservadas = TRUE
    )
    dt <- res_desc_dep$dt
    if (nrow(res_desc_dep$audit)) audit <- data.table::rbindlist(list(audit, res_desc_dep$audit), fill = TRUE, use.names = TRUE)
    if (nrow(res_desc_dep$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res_desc_dep$afetacoes), fill = TRUE, use.names = TRUE)
    if (nrow(res_desc_dep$afetacoes)) linhas_afetadas <- unique(c(linhas_afetadas, res_desc_dep$afetacoes$linha_indice))
  }
  tipo_col <- chaves$tipo_forma_vida
  if (!is.na(tipo_col) && tipo_col %in% names(dt)) {
    antes_tipo <- as.character(dt[[tipo_col]][linhas])
    monitora_correcao_recalcular_tipo_forma_vida(dt, linhas)
    depois_tipo <- as.character(dt[[tipo_col]][linhas])
    mudou_tipo <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_tipo)
    if (any(mudou_tipo, na.rm = TRUE)) {
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento atômico: tipo_forma_vida recalculado após origem/destino", tipo_col, linhas[mudou_tipo], antes_tipo[mudou_tipo], depois_tipo[mudou_tipo])), fill = TRUE, use.names = TRUE)
      linhas_afetadas <- unique(c(linhas_afetadas, linhas[mudou_tipo])); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_tipo], atributo = tipo_col)), fill = TRUE, use.names = TRUE)
    }
  }
  if (!nrow(audit)) {
    audit <- registrar("bloqueada_operacao_repetida_sem_efeito", "Movimento atômico bloqueado: operação repetida ou sem efeito; origem, destino, dependentes e tipo_forma_vida já estavam coerentes antes da aplicação", "__mover_forma_vida__", linhas, NA_character_, NA_character_)
    return(list(dt = dt[], audit = audit[], linhas = linhas, afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = TRUE))
  }
  list(dt = dt[], audit = audit[], linhas = unique(c(linhas, linhas_afetadas)), afetacoes = unique(afetacoes), falha = FALSE)
}

monitora_correcao_aplicar_movimentos_forma_vida_atomicos <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(list(dt = dt[], corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  corr[, .grupo_mov_atom := fifelse(!is.na(id_correcao) & nzchar(as.character(id_correcao)), as.character(id_correcao), paste0("__linha_", ordem_tmp))]
  idx_mov <- which(monitora_correcao_eh_operacao_movimento_forma_vida(corr))
  if (!length(idx_mov)) {
    corr[, .grupo_mov_atom := NULL]
    return(list(dt = dt[], corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  }
  grupos <- unique(corr[idx_mov, .grupo_mov_atom])
  audit <- data.table::data.table(); linhas <- integer(); afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character()); falha <- FALSE
  for (gid in grupos) {
    grp <- corr[.grupo_mov_atom == gid]
    linha_atom <- monitora_correcao_compactar_movimento_forma_vida_atomico(grp)
    res <- monitora_correcao_aplicar_movimento_forma_vida_atomico(dt, linha_atom, chaves, indice, arquivo_correcao, dicionario)
    dt <- res$dt
    if (nrow(res$audit)) audit <- data.table::rbindlist(list(audit, res$audit), fill = TRUE, use.names = TRUE)
    if (length(res$linhas)) linhas <- unique(c(linhas, res$linhas))
    if (nrow(res$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res$afetacoes), fill = TRUE, use.names = TRUE)
    falha <- isTRUE(falha) || isTRUE(res$falha)
  }
  corr_out <- corr[!(.grupo_mov_atom %in% grupos)]
  corr_out[, .grupo_mov_atom := NULL]
  corr[, .grupo_mov_atom := NULL]
  list(dt = dt[], corr = corr_out[], audit = audit[], linhas = linhas, afetacoes = unique(afetacoes), falha = falha, n_grupos = length(grupos))
}


### Substituição atômica de forma de vida desconhecida
### -------------------------------------------------------------------------
### A triagem de "desconhecida" altera potencialmente várias células: remove
### token(s) históricos de listas principais, garante a forma válida na lista de
### destino, preenche hábito obrigatório quando aplicável e recalcula o campo
### superior. O bloco abaixo trata tudo como uma transação semântica única.
monitora_correcao_eh_operacao_triagem_desconhecida <- function(corr) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(logical(0))
  idc <- if ("id_correcao" %in% names(corr)) trimws(as.character(corr$id_correcao)) else rep("", nrow(corr))
  tipo <- if ("tipo_correcao" %in% names(corr)) tolower(trimws(as.character(corr$tipo_correcao))) else rep("", nrow(corr))
  acao <- if ("acao" %in% names(corr)) tolower(trimws(as.character(corr$acao))) else rep("", nrow(corr))
  atributo <- if ("atributo_coluna_registros_corrig" %in% names(corr)) tolower(trimws(as.character(corr$atributo_coluna_registros_corrig))) else rep("", nrow(corr))
  grepl("^TRIDESC_", idc) |
    tipo %in% c("triagem_substituir_desconhecida", "triagem_substituir_desconhecida_atomica") |
    acao %in% c("substituir_desconhecida", "substituir_forma_desconhecida") |
    atributo %in% c("__substituir_desconhecida__", "__triagem_desconhecida__")
}

monitora_correcao_compactar_triagem_desconhecida_atomica <- function(grupo) {
  grupo <- data.table::as.data.table(grupo)
  if (!nrow(grupo)) return(grupo)
  if ("ordem_operacao" %in% names(grupo)) {
    grupo[, .ordem_tridesc_tmp := suppressWarnings(as.integer(ordem_operacao))]
    data.table::setorder(grupo, .ordem_tridesc_tmp, na.last = TRUE)
    grupo[, .ordem_tridesc_tmp := NULL]
  }
  pegar_primeiro <- function(col, default = NA_character_) {
    if (!(col %in% names(grupo))) return(default)
    vals <- as.character(grupo[[col]])
    vals <- vals[!is.na(vals) & nzchar(trimws(vals))]
    if (length(vals)) vals[1L] else default
  }
  linha <- data.table::copy(grupo[1L])
  if ("tipo_correcao" %in% names(linha)) linha[, tipo_correcao := "triagem_substituir_desconhecida_atomica"]
  if ("acao" %in% names(linha)) linha[, acao := "substituir_desconhecida"]
  if ("atributo_coluna_registros_corrig" %in% names(linha)) linha[, atributo_coluna_registros_corrig := "__substituir_desconhecida__"]
  if ("ordem_operacao" %in% names(linha)) {
    ord_vals <- suppressWarnings(as.integer(grupo$ordem_operacao))
    ord_vals <- ord_vals[!is.na(ord_vals) & is.finite(ord_vals)]
    linha[, ordem_operacao := if (length(ord_vals)) min(ord_vals) else NA_integer_]
  }

  acao_grupo <- if ("acao" %in% names(grupo)) tolower(trimws(as.character(grupo$acao))) else rep("", nrow(grupo))
  attr_grupo <- if ("atributo_coluna_registros_corrig" %in% names(grupo)) as.character(grupo$atributo_coluna_registros_corrig) else rep(NA_character_, nrow(grupo))
  valor_novo_grupo <- if ("valor_novo" %in% names(grupo)) as.character(grupo$valor_novo) else rep(NA_character_, nrow(grupo))
  valor_orig_grupo <- if ("valor_original_esperado" %in% names(grupo)) as.character(grupo$valor_original_esperado) else rep(NA_character_, nrow(grupo))

  tokens <- character(0)
  if ("token_removido" %in% names(grupo)) tokens <- c(tokens, unlist(lapply(as.character(grupo$token_removido), monitora_correcao_parse_lista_serializada), use.names = FALSE))
  if (all(c("acao", "valor_novo") %in% names(grupo))) tokens <- c(tokens, as.character(grupo[tolower(trimws(as.character(acao))) %in% c("remove_token", "remover_token"), valor_novo]))
  if ("token_pai" %in% names(grupo)) tokens <- c(tokens, as.character(grupo$token_pai))
  tokens <- unique(monitora_correcao_limpar_texto(tokens))
  tokens <- tokens[!is.na(tokens) & nzchar(tokens)]
  tokens_norm <- monitora_correcao_normalizar_nome_coluna(tokens)
  if (!length(tokens)) tokens <- c("desconhecida", "indeterminada", "nao_identificada", "não_identificada")
  if (!length(tokens_norm)) tokens_norm <- monitora_correcao_normalizar_nome_coluna(tokens)

  forma <- pegar_primeiro("forma_valida_escolhida")
  if (monitora_correcao_vazio(forma) && all(c("acao", "valor_novo") %in% names(grupo))) {
    idx_append <- acao_grupo %in% c("append_token", "adicionar_token", "substituir_desconhecida")
    vals_append <- valor_novo_grupo[idx_append]
    vals_append <- vals_append[!is.na(vals_append) & nzchar(trimws(vals_append))]
    if (length(vals_append)) {
      tokens_append <- unlist(lapply(vals_append, monitora_correcao_tokenizar), use.names = FALSE)
      tokens_old <- unlist(lapply(valor_orig_grupo, monitora_correcao_tokenizar), use.names = FALSE)
      old_norm <- monitora_correcao_normalizar_nome_coluna(tokens_old)
      cand_norm <- monitora_correcao_normalizar_nome_coluna(tokens_append)
      catalogo <- monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokens_forma_vida_catalogo())
      habitos <- monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokens_habito_catalogo())
      keep <- cand_norm %in% catalogo & !(cand_norm %in% unique(c(old_norm, tokens_norm, habitos, "desconhecida", "indeterminada", "nao_identificada")))
      if (any(keep, na.rm = TRUE)) {
        forma <- tokens_append[which(keep)[1L]]
      } else if (length(vals_append) == 1L && length(monitora_correcao_tokenizar(vals_append[1L])) == 1L) {
        forma <- vals_append[1L]
      }
    }
  }
  if (monitora_correcao_vazio(forma)) forma <- pegar_primeiro("valor_novo")
  forma <- monitora_correcao_limpar_texto(forma)
  if ("forma_valida_escolhida" %in% names(linha)) linha[, forma_valida_escolhida := forma]
  if ("valor_novo" %in% names(linha)) linha[, valor_novo := forma]

  destino <- pegar_primeiro("lista_destino", pegar_primeiro("categoria_destino"))
  if (monitora_correcao_vazio(destino) && all(c("acao", "categoria_destino") %in% names(grupo))) {
    vals_dest <- unique(as.character(grupo[tolower(trimws(as.character(acao))) %in% c("append_token", "adicionar_token", "substituir_desconhecida"), categoria_destino]))
    vals_dest <- vals_dest[!is.na(vals_dest) & nzchar(trimws(vals_dest))]
    if (length(vals_dest)) destino <- vals_dest[1L]
  }
  if (monitora_correcao_vazio(destino)) {
    idx_append <- acao_grupo %in% c("append_token", "adicionar_token", "substituir_desconhecida")
    cats <- monitora_correcao_categoria_coluna_canonica(attr_grupo[idx_append])
    cats <- cats[!is.na(cats) & nzchar(cats)]
    if (length(cats)) destino <- cats[1L]
  }
  if ("lista_destino" %in% names(linha)) linha[, lista_destino := destino]
  if ("categoria_destino" %in% names(linha)) linha[, categoria_destino := destino]
  if ("categoria_origem" %in% names(linha)) linha[, categoria_origem := "desconhecida"]

  tokens <- unique(monitora_correcao_limpar_texto(tokens))
  tokens <- tokens[!is.na(tokens) & nzchar(tokens) & !(monitora_correcao_normalizar_nome_coluna(tokens) %in% monitora_correcao_normalizar_nome_coluna(c(forma, destino)))]
  if (!length(tokens)) tokens <- c("desconhecida", "indeterminada", "nao_identificada", "não_identificada")
  if ("token_removido" %in% names(linha)) linha[, token_removido := monitora_correcao_colapsar_lista_serializada(tokens)]
  if ("token_pai" %in% names(linha)) linha[, token_pai := monitora_correcao_colapsar_tokens(tokens)]

  hab <- pegar_primeiro("habito_escolhido")
  if (monitora_correcao_vazio(hab) && all(c("acao", "valor_novo") %in% names(grupo))) {
    cand <- valor_novo_grupo[acao_grupo %in% c("update", "substituir_valor")]
    cand <- cand[!is.na(cand) & nzchar(trimws(cand)) & cand %in% c("terrestre", "epifita", "rupicola")]
    if (length(cand)) hab <- cand[1L]
  }
  if ("habito_escolhido" %in% names(linha)) linha[, habito_escolhido := hab]

  dep <- pegar_primeiro("campo_dependente_preenchido")
  if (monitora_correcao_vazio(dep)) {
    idx_hab <- acao_grupo %in% c("update", "substituir_valor") & valor_novo_grupo %in% c("terrestre", "epifita", "rupicola")
    cand_dep <- attr_grupo[idx_hab]
    cand_dep <- cand_dep[!is.na(cand_dep) & nzchar(trimws(cand_dep))]
    if (length(cand_dep)) dep <- cand_dep[1L]
  }
  if ("campo_dependente_preenchido" %in% names(linha)) linha[, campo_dependente_preenchido := dep]
  linha[]
}

monitora_correcao_aplicar_triagem_desconhecida_atomica <- function(dt, linha_tri, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL) {
  dt <- monitora_dt_referenciar(dt)
  linha_tri <- data.table::as.data.table(linha_tri)
  if (!nrow(linha_tri)) return(list(dt = dt[], audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE))
  id_cor <- if ("id_correcao" %in% names(linha_tri)) as.character(linha_tri$id_correcao[1L]) else NA_character_
  ordem <- if ("ordem_operacao" %in% names(linha_tri)) linha_tri$ordem_operacao[1L] else NA_character_
  falhar <- function(status, msg, atributo = "__substituir_desconhecida__") {
    list(
      dt = dt[],
      audit = data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = paste0("Substituição atômica de desconhecida bloqueada: ", msg), atributo = atributo, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao),
      linhas = integer(),
      afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()),
      falha = TRUE
    )
  }
  forma <- if ("forma_valida_escolhida" %in% names(linha_tri)) trimws(as.character(linha_tri$forma_valida_escolhida[1L])) else NA_character_
  if (monitora_correcao_vazio(forma) && "valor_novo" %in% names(linha_tri)) forma <- trimws(as.character(linha_tri$valor_novo[1L]))
  destino <- if ("lista_destino" %in% names(linha_tri)) trimws(as.character(linha_tri$lista_destino[1L])) else NA_character_
  if (monitora_correcao_vazio(destino) && "categoria_destino" %in% names(linha_tri)) destino <- trimws(as.character(linha_tri$categoria_destino[1L]))
  tokens_remover <- character(0)
  if ("token_removido" %in% names(linha_tri)) tokens_remover <- c(tokens_remover, monitora_correcao_parse_lista_serializada(linha_tri$token_removido[1L]))
  if ("token_pai" %in% names(linha_tri)) tokens_remover <- c(tokens_remover, monitora_correcao_tokenizar(linha_tri$token_pai[1L]))
  tokens_remover <- unique(monitora_correcao_limpar_texto(tokens_remover))
  tokens_remover <- tokens_remover[!is.na(tokens_remover) & nzchar(tokens_remover) & !(tokens_remover %in% monitora_correcao_limpar_texto(c(forma, destino)))]
  if (!length(tokens_remover)) tokens_remover <- c("desconhecida", "indeterminada", "nao_identificada", "não_identificada")
  if (monitora_correcao_vazio(forma) || monitora_correcao_vazio(destino)) return(falhar("falha_triagem_incompleta", "forma válida ou lista de destino não informada"))
  dominio_destino <- tryCatch(monitora_contrato_tokens_categoria_movimento(destino), error = function(e) character(0))
  if (!length(dominio_destino) || !(forma %in% dominio_destino)) return(falhar("falha_forma_destino_fora_contrato", paste0("forma de destino '", forma, "' não pertence ao domínio ", destino, " do contrato único")))
  col_destino <- tryCatch(monitora_correcao_coluna_forma_vida(dt, destino), error = function(e) NA_character_)
  if (is.na(col_destino) || !(col_destino %in% names(dt))) return(falhar("falha_coluna_destino", paste0("coluna de destino não localizada para ", destino)))
  if (monitora_correcao_coluna_protegida(col_destino)) return(falhar("bloqueada_coluna_protegida", "destino é coluna protegida"))
  valid_dest <- monitora_correcao_validar_destino_operacao(dt, col_destino, "append_token", forma, linha_tri)
  if (!isTRUE(valid_dest$ok)) return(falhar(valid_dest$status, valid_dest$mensagem, col_destino))

  linhas <- unique(as.integer(monitora_correcao_linhas_triagem_desconhecida_lote(dt, linha_tri, chaves, indice)))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  n_esperado <- if ("n_linhas_esperado" %in% names(linha_tri)) suppressWarnings(as.integer(linha_tri$n_linhas_esperado[1L])) else NA_integer_
  if (!length(linhas)) return(falhar("falha_sem_linhas", "nenhuma linha-alvo localizada"))
  if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) return(falhar("falha_n_linhas", paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado)))

  categorias <- tryCatch(monitora_contrato_categorias_movimento()[admite_desconhecida == TRUE, categoria], error = function(e) c("nativa", "exotica", "seca_morta"))
  cols_origem <- unique(vapply(categorias, function(cat) tryCatch(monitora_correcao_coluna_forma_vida(dt, cat), error = function(e) NA_character_), character(1)))
  cols_origem <- cols_origem[!is.na(cols_origem) & cols_origem %in% names(dt) & !monitora_correcao_coluna_protegida(cols_origem)]
  registrar <- function(status, msg, atributo, idx, antes, depois) {
    data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = msg, atributo = atributo, linha_indice = as.integer(idx), valor_antes = as.character(antes), valor_depois = as.character(depois), arquivo_correcao = arquivo_correcao)
  }
  audit <- data.table::data.table()
  linhas_afetadas <- integer()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())

  atualizacoes_colunas <- list()
  token_presente_algum <- FALSE
  cols_plano <- unique(c(cols_origem, col_destino))
  cols_plano <- cols_plano[!is.na(cols_plano) & cols_plano %in% names(dt)]
  for (cc in cols_plano) {
    antes <- as.character(dt[[cc]][linhas])
    depois <- antes
    remove_nesta_coluna <- cc %in% cols_origem
    adiciona_nesta_coluna <- identical(cc, col_destino)
    if (isTRUE(remove_nesta_coluna)) {
      presente <- Reduce(`|`, lapply(tokens_remover, function(tok) monitora_correcao_token_presente_vec(depois, tok)))
      token_presente_algum <- isTRUE(token_presente_algum) || any(presente, na.rm = TRUE)
      for (tok in tokens_remover) depois <- vapply(depois, monitora_correcao_remove_token_valor, character(1), token = tok)
    }
    if (isTRUE(adiciona_nesta_coluna)) {
      depois <- vapply(depois, monitora_correcao_append_token_valor, character(1), token = forma)
    }
    mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
    if (any(mudou, na.rm = TRUE)) {
      msg <- if (isTRUE(remove_nesta_coluna) && isTRUE(adiciona_nesta_coluna)) {
        "Substituição atômica: desconhecida removida e forma válida garantida na mesma lista"
      } else if (isTRUE(remove_nesta_coluna)) {
        "Substituição atômica: token(s) de desconhecida removido(s) da origem"
      } else {
        "Substituição atômica: forma válida garantida na lista de destino"
      }
      atualizacoes_colunas[[cc]] <- list(idx = linhas[mudou], antes = antes[mudou], depois = depois[mudou], mensagem = msg)
    }
  }

  habito <- if ("habito_escolhido" %in% names(linha_tri)) trimws(as.character(linha_tri$habito_escolhido[1L])) else ""
  if (is.na(habito)) habito <- ""
  forma_exige_habito <- monitora_correcao_limpar_texto(forma) %in% monitora_correcao_tokens_formas_exigem_habito()
 ### A intenção semântica categoria×forma é soberana sobre qualquer nome
 ### físico armazenado na fila, inclusive em replay de versões anteriores.
  dep_destino <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, destino, forma, dicionario, linha = linhas[1L], meta_xls = NULL), error = function(e) NA_character_)
  atualizacao_habito <- NULL
  if (isTRUE(forma_exige_habito)) {
    if (!nzchar(habito) || !(habito %in% c("terrestre", "epifita", "rupicola"))) return(falhar("falha_habito_obrigatorio", paste0("forma '", forma, "' exige hábito terrestre/epifita/rupicola")))
    if (!monitora_correcao_coluna_habito_segura(dt, dep_destino, destino, forma) || identical(dep_destino, col_destino)) return(falhar("falha_coluna_habito_destino", "coluna de hábito segura não localizada para o destino"))
    antes_hab <- as.character(dt[[dep_destino]][linhas])
    depois_hab <- rep(habito, length(linhas))
    mudou_hab <- monitora_correcao_na_para_vazio(antes_hab) != monitora_correcao_na_para_vazio(depois_hab)
    if (any(mudou_hab, na.rm = TRUE)) atualizacao_habito <- list(col = dep_destino, idx = linhas[mudou_hab], antes = antes_hab[mudou_hab], depois = depois_hab[mudou_hab])
  } else if (nzchar(habito)) {
    return(falhar("falha_habito_indevido", paste0("hábito informado para forma que não exige hábito: ", forma)))
  }

  for (cc in names(atualizacoes_colunas)) {
    zz <- atualizacoes_colunas[[cc]]
    data.table::set(dt, i = zz$idx, j = cc, value = zz$depois)
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", zz$mensagem, cc, zz$idx, zz$antes, zz$depois)), fill = TRUE, use.names = TRUE)
    linhas_afetadas <- unique(c(linhas_afetadas, zz$idx)); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = zz$idx, atributo = cc)), fill = TRUE, use.names = TRUE)
  }
  if (!is.null(atualizacao_habito)) {
    data.table::set(dt, i = atualizacao_habito$idx, j = atualizacao_habito$col, value = atualizacao_habito$depois)
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Substituição atômica: hábito obrigatório preenchido", atualizacao_habito$col, atualizacao_habito$idx, atualizacao_habito$antes, atualizacao_habito$depois)), fill = TRUE, use.names = TRUE)
    linhas_afetadas <- unique(c(linhas_afetadas, atualizacao_habito$idx)); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = atualizacao_habito$idx, atributo = atualizacao_habito$col)), fill = TRUE, use.names = TRUE)
  }
  if (any(monitora_correcao_normalizar_nome_coluna(tokens_remover) %in% monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokens_desconhecida()))) {
    res_desc_dep <- monitora_correcao_sanitizar_dependentes_desconhecida(
      dt,
      linhas = linhas,
      categorias = c("nativa", "exotica", "seca_morta"),
      id_correcao = id_cor,
      ordem_operacao = ordem,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario,
      registrar_preservadas = TRUE
    )
    dt <- res_desc_dep$dt
    if (nrow(res_desc_dep$audit)) audit <- data.table::rbindlist(list(audit, res_desc_dep$audit), fill = TRUE, use.names = TRUE)
    if (nrow(res_desc_dep$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res_desc_dep$afetacoes), fill = TRUE, use.names = TRUE)
    if (nrow(res_desc_dep$afetacoes)) linhas_afetadas <- unique(c(linhas_afetadas, res_desc_dep$afetacoes$linha_indice))
  }
  tipo_col <- chaves$tipo_forma_vida
  if (!is.na(tipo_col) && tipo_col %in% names(dt)) {
    antes_tipo <- as.character(dt[[tipo_col]][linhas])
    monitora_correcao_recalcular_tipo_forma_vida(dt, linhas)
    depois_tipo <- as.character(dt[[tipo_col]][linhas])
    mudou_tipo <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_tipo)
    if (any(mudou_tipo, na.rm = TRUE)) {
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Substituição atômica: tipo_forma_vida recalculado após triagem", tipo_col, linhas[mudou_tipo], antes_tipo[mudou_tipo], depois_tipo[mudou_tipo])), fill = TRUE, use.names = TRUE)
      linhas_afetadas <- unique(c(linhas_afetadas, linhas[mudou_tipo])); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_tipo], atributo = tipo_col)), fill = TRUE, use.names = TRUE)
    }
  }
  if (!isTRUE(token_presente_algum)) {
    audit <- data.table::rbindlist(list(audit, registrar("aviso_sem_token_origem_atomica", "Substituição atômica: token(s) de desconhecida não estavam mais presentes; forma de destino/hábito/tipo foram harmonizados", "__substituir_desconhecida__", linhas, NA_character_, forma)), fill = TRUE, use.names = TRUE)
  }
  if (!nrow(audit)) {
 ### operação sem qualquer efeito (origem, destino,
 ### hábito e tipo_forma_vida já coerentes) deixa de ser erro fatal. Isso
 ### cobre o caso de TRIDESC duplicado por um MVLOTE/movimento equivalente já
 ### ter resolvido as mesmas linhas/destino/forma antes desta operação ser
 ### aplicada — tratado como no-op auditado (não interrompe as demais
 ### correções pendentes), não como falha que aborta toda a aplicação.
    audit <- registrar("bloqueada_operacao_repetida_sem_efeito", "Substituição atômica: nenhum efeito (operação repetida ou já resolvida por outra operação equivalente, ex.: MVLOTE); origem, destino, hábito e tipo_forma_vida já estavam coerentes antes da aplicação", "__substituir_desconhecida__", linhas, NA_character_, NA_character_)
    return(list(dt = dt[], audit = audit[], linhas = linhas, afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE))
  }
  list(dt = dt[], audit = audit[], linhas = unique(c(linhas, linhas_afetadas)), afetacoes = unique(afetacoes), falha = FALSE)
}

monitora_correcao_aplicar_triagens_desconhecida_atomicas <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(list(dt = dt[], corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  corr[, .grupo_tridesc_atom := fifelse(!is.na(id_correcao) & nzchar(as.character(id_correcao)), as.character(id_correcao), paste0("__linha_", ordem_tmp))]
  idx_tri <- which(monitora_correcao_eh_operacao_triagem_desconhecida(corr))
  if (!length(idx_tri)) {
    corr[, .grupo_tridesc_atom := NULL]
    return(list(dt = dt[], corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  }
  grupos <- unique(corr[idx_tri, .grupo_tridesc_atom])
  audit <- data.table::data.table(); linhas <- integer(); afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character()); falha <- FALSE
  for (gid in grupos) {
    grp <- corr[.grupo_tridesc_atom == gid]
    linha_atom <- monitora_correcao_compactar_triagem_desconhecida_atomica(grp)
    res <- monitora_correcao_aplicar_triagem_desconhecida_atomica(dt, linha_atom, chaves, indice, arquivo_correcao, dicionario)
    dt <- res$dt
    if (nrow(res$audit)) audit <- data.table::rbindlist(list(audit, res$audit), fill = TRUE, use.names = TRUE)
    if (length(res$linhas)) linhas <- unique(c(linhas, res$linhas))
    if (nrow(res$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res$afetacoes), fill = TRUE, use.names = TRUE)
    falha <- isTRUE(falha) || isTRUE(res$falha)
  }
  corr_out <- corr[!(.grupo_tridesc_atom %in% grupos)]
  corr_out[, .grupo_tridesc_atom := NULL]
  corr[, .grupo_tridesc_atom := NULL]

  list(dt = dt[], corr = corr_out[], audit = audit[], linhas = linhas, afetacoes = unique(afetacoes), falha = falha, n_grupos = length(grupos))
}

### transação semântica agrupada para operações do painel
### -------------------------------------------------------------------------
### O painel pode gerar muitos itens auditáveis para uma única decisão do
### usuário. A partir daqui, a regra é: a fila guarda operações semânticas
### agrupadas; os itens por linha ficam apenas na auditoria expandida; a
### aplicação usa máscaras vetorizadas por grupos semânticos.
monitora_correcao_parse_serial_generico <- function(x) {
  x <- as.character(x)
  x <- x[!is.na(x) & nzchar(trimws(x))]
  if (!length(x)) return(character(0))
  vals <- unlist(strsplit(paste(x, collapse = "|"), "\\s*(\\||;|,)\\s*"), use.names = FALSE)
  vals <- unique(trimws(as.character(vals)))
  vals[!is.na(vals) & nzchar(vals)]
}


monitora_correcao_linhas_desconhecida_sem_categoria_base <- function(dt, linhas_base = NULL, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (!n) return(integer(0))
  if (is.null(linhas_base)) linhas_base <- seq_len(n)
  linhas_base <- unique(as.integer(linhas_base))
  linhas_base <- linhas_base[!is.na(linhas_base) & linhas_base >= 1L & linhas_base <= n]
  if (!length(linhas_base)) return(integer(0))
  tipo_col <- tryCatch(chaves$tipo_forma_vida, error = function(e) NA_character_)
  if (is.na(tipo_col) || !nzchar(as.character(tipo_col)[1L]) || !(as.character(tipo_col)[1L] %in% names(dt))) {
    cand <- grep("encostam|tipo_forma_vida", names(dt), ignore.case = TRUE, value = TRUE)
    tipo_col <- if (length(cand)) cand[1L] else NA_character_
  }
  if (is.na(tipo_col) || !(tipo_col %in% names(dt))) return(integer(0))
  tipo <- as.character(dt[[tipo_col]][linhas_base])
  toks_desc <- tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) c("desconhecida", "desconhecido", "indeterminada", "nao_identificada", "não_identificada"))
  tem_desc_sup <- tryCatch(monitora_correcao_contem_qualquer_token_vec(tipo, toks_desc), error = function(e) rep(FALSE, length(linhas_base)))
  tem_desc_sup[is.na(tem_desc_sup)] <- FALSE
  toks_base <- c("nativa", "nativas", "nativo", "nativos", "exotica", "exoticas", "exotico", "exoticos", "seca_morta", "seca", "secas", "seco", "secos", "morta", "mortas", "morto", "mortos", "solo_nu", "solo", "serrapilheira", "outras_plantas_terrestres", "forma_vida_outros")
  tem_base_sup <- tryCatch(monitora_correcao_contem_qualquer_token_vec(tipo, toks_base), error = function(e) rep(FALSE, length(linhas_base)))
  tem_base_sup[is.na(tem_base_sup)] <- FALSE
  tem_inferior <- rep(FALSE, length(linhas_base))
  for (cat_desc in c("nativa", "exotica", "seca_morta")) {
    cols_d <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(dt, cat_desc), error = function(e) character(0))
    cols_d <- cols_d[cols_d %in% names(dt)]
    for (cc in cols_d) {
      hit <- tryCatch(!monitora_correcao_vazio_vec(dt[[cc]][linhas_base]), error = function(e) rep(FALSE, length(linhas_base)))
      hit[is.na(hit)] <- FALSE
      tem_inferior <- tem_inferior | hit
    }
  }
  cols_outros <- grep("forma_vida_outros|outras_plantas_terrestres|forma_serrapilheira", names(dt), ignore.case = TRUE, value = TRUE)
  for (cc in unique(cols_outros)) {
    hit <- tryCatch(!monitora_correcao_vazio_vec(dt[[cc]][linhas_base]), error = function(e) rep(FALSE, length(linhas_base)))
    hit[is.na(hit)] <- FALSE
    tem_inferior <- tem_inferior | hit
  }
  linhas_base[tem_desc_sup & !tem_base_sup & !tem_inferior]
}

monitora_correcao_linhas_desconhecida_dados <- function(dt, linhas_base = NULL, chaves = monitora_correcao_colunas_chave(dt), dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (!n) return(integer(0))
  if (is.null(linhas_base)) linhas_base <- seq_len(n)
  linhas_base <- unique(as.integer(linhas_base))
  linhas_base <- linhas_base[!is.na(linhas_base) & linhas_base >= 1L & linhas_base <= n]
  if (!length(linhas_base)) return(integer(0))
  toks_desc <- tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) c("desconhecida", "desconhecido", "indeterminada", "nao_identificada", "não_identificada"))
  hit_total <- rep(FALSE, length(linhas_base))
  for (cat_desc in c("nativa", "exotica", "seca_morta")) {
    col_princ <- tryCatch(monitora_correcao_coluna_forma_vida(dt, cat_desc), error = function(e) NA_character_)
    if (!is.na(col_princ) && col_princ %in% names(dt)) {
      h <- tryCatch(monitora_correcao_contem_qualquer_token_vec(dt[[col_princ]][linhas_base], toks_desc), error = function(e) rep(FALSE, length(linhas_base)))
      h[is.na(h)] <- FALSE
      hit_total <- hit_total | h
    }
    dep <- tryCatch(monitora_correcao_colunas_desconhecida_por_categoria(dt, cat_desc, dicionario), error = function(e) data.table::data.table())
    if (nrow(dep)) {
      for (cc in unique(as.character(dep$coluna[dep$coluna %in% names(dt)]))) {
        h <- tryCatch(!monitora_correcao_vazio_vec(dt[[cc]][linhas_base]), error = function(e) rep(FALSE, length(linhas_base)))
        h[is.na(h)] <- FALSE
        hit_total <- hit_total | h
      }
    }
  }
  idx_superior_only <- tryCatch(monitora_correcao_linhas_desconhecida_sem_categoria_base(dt, linhas_base, chaves = chaves), error = function(e) integer(0))
  if (length(idx_superior_only)) hit_total <- hit_total | (linhas_base %in% idx_superior_only)
  linhas_base[hit_total]
}

monitora_correcao_linhas_desconhecida_categoria_base <- function(dt, categoria, linhas_base = NULL, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (!n) return(integer(0))
  if (is.null(linhas_base)) linhas_base <- seq_len(n)
  linhas_base <- unique(as.integer(linhas_base))
  linhas_base <- linhas_base[!is.na(linhas_base) & linhas_base >= 1L & linhas_base <= n]
  if (!length(linhas_base)) return(integer(0))
  categoria <- tolower(trimws(as.character(categoria)[1L]))
  if (!(categoria %in% c("nativa", "exotica", "seca_morta"))) return(integer(0))
  toks_desc <- tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) c("desconhecida", "desconhecido"))
  hit_total <- rep(FALSE, length(linhas_base))
  col_princ <- tryCatch(monitora_correcao_coluna_forma_vida(dt, categoria), error = function(e) NA_character_)
  if (!is.na(col_princ) && col_princ %in% names(dt)) {
    h <- tryCatch(monitora_correcao_contem_qualquer_token_vec(dt[[col_princ]][linhas_base], toks_desc), error = function(e) rep(FALSE, length(linhas_base)))
    h[is.na(h)] <- FALSE
    hit_total <- hit_total | h
  }
  dep <- tryCatch(monitora_correcao_colunas_desconhecida_por_categoria(dt, categoria, dicionario), error = function(e) data.table::data.table())
  if (nrow(dep)) {
    for (cc in unique(as.character(dep$coluna[dep$coluna %in% names(dt)]))) {
      h <- tryCatch(!monitora_correcao_vazio_vec(dt[[cc]][linhas_base]), error = function(e) rep(FALSE, length(linhas_base)))
      h[is.na(h)] <- FALSE
      hit_total <- hit_total | h
    }
  }
  linhas_base[hit_total]
}

monitora_correcao_linhas_triagem_desconhecida_lote <- function(dt, linha_tri, chaves = monitora_correcao_colunas_chave(dt), indice = NULL) {
  dt <- data.table::as.data.table(dt)
  linha_tri <- data.table::as.data.table(linha_tri)
  n <- nrow(dt)
  if (!n || !nrow(linha_tri)) return(integer(0))
 # 1) IDs estáveis de registro, quando gravados como lista serializada.
  uuid_cols <- intersect(c("uuid_registro", "uuid_registro_serializado", "uuids_registro"), names(linha_tri))
  uu <- character(0)
  for (cc in uuid_cols) uu <- c(uu, monitora_correcao_parse_serial_generico(linha_tri[[cc]][1L]))
  uu <- unique(uu[!is.na(uu) & nzchar(uu)])
  if (length(uu) && !is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) {
    idx <- which(trimws(as.character(dt[[chaves$uuid_registro]])) %chin% uu)
    idx <- unique(as.integer(idx))
    if (length(idx)) return(idx)
  }
 # 2) Índices gravados apenas para prévia/aplicação na mesma sessão.
  lin_cols <- intersect(c("linhas_alvo_serializadas", "linha_indice", "linhas_alvo"), names(linha_tri))
  li <- integer(0)
  for (cc in lin_cols) {
    z <- suppressWarnings(as.integer(monitora_correcao_parse_serial_generico(linha_tri[[cc]][1L])))
    li <- c(li, z)
  }
  li <- unique(li[!is.na(li) & li >= 1L & li <= n])
  if (length(li)) return(li)
 # 3) Escopo por COLETA, sempre reavaliando a ocorrência de desconhecida.
  coletas <- character(0)
  if ("coleta" %in% names(linha_tri)) coletas <- c(coletas, monitora_correcao_parse_serial_generico(linha_tri$coleta[1L]))
  if ("coletas" %in% names(linha_tri)) coletas <- c(coletas, monitora_correcao_parse_serial_generico(linha_tri$coletas[1L]))
  coletas <- unique(coletas[!is.na(coletas) & nzchar(coletas)])
  if (length(coletas) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    idx_base <- which(as.character(dt[[chaves$coleta]]) %chin% coletas)
    idx_desc <- monitora_correcao_linhas_desconhecida_dados(dt, idx_base, chaves = chaves, dicionario = NULL)
    if (length(idx_desc)) return(idx_desc)
  }
 # 4) Fallback para a regra histórica.
  unique(as.integer(monitora_correcao_localizar_linhas(dt, linha_tri, chaves, indice)))
}


monitora_correcao_classificar_tipo_operacao <- function(corr) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(character(0))
  getc <- function(nm) if (nm %in% names(corr)) as.character(corr[[nm]]) else rep("", nrow(corr))
  idc <- toupper(trimws(getc("id_correcao")))
  tipo <- tolower(trimws(getc("tipo_correcao")))
  acao <- tolower(trimws(getc("acao")))
  attr <- tolower(trimws(getc("atributo_coluna_registros_corrig")))
  out <- rep("operacao_generica", nrow(corr))
  out[grepl("^EXCCOL", idc) | tipo %in% c("exclusao_coletas_filtradas", "exclusao_coleta_atomica") | acao %in% c("excluir_coleta", "exclusao_coleta")] <- "exclusao_coleta_atomica"
  out[grepl("^PENDFV", idc) | tipo %in% c("pendencia_sem_forma_vida_lote", "pendencia_sem_forma_vida") | attr %in% c("__pendencia_sem_forma_vida__")] <- "pendencia_sem_forma_vida_lote"
  out[grepl("^TRIOUT", idc) | tipo %in% c("triagem_limpeza_outras_formas_vida_atomica", "limpeza_outras_formas_vida_atomica") | acao %in% c("limpar_outras_formas_vida", "limpeza_outras_formas_vida_atomica")] <- "limpeza_outras_formas_atomica"
  out[grepl("^TRIDESC", idc) | tipo %in% c("triagem_substituir_desconhecida", "triagem_substituir_desconhecida_atomica") | acao %in% c("substituir_desconhecida", "substituir_forma_desconhecida") | attr %in% c("__substituir_desconhecida__", "__triagem_desconhecida__")] <- "triagem_desconhecida_atomica"
  out[grepl("^MVLOTE", idc) | tipo %in% c("movimento_forma_vida_lote_atomico", "movimento_forma_vida_lote") | acao %in% c("mover_forma_vida_lote", "movimento_forma_vida_lote_atomico") | attr %in% c("__mover_forma_vida_lote__", "__movimento_forma_vida_lote__")] <- "movimento_forma_vida_lote_atomico"
  out[grepl("^MOVFV", idc) | tipo %in% c("movimento_forma_vida_atomico", "movimento_forma_vida_condicional", "movimento_forma_vida") | acao %in% c("mover_forma_vida", "movimento_forma_vida_atomico") | attr %in% c("__mover_forma_vida__", "__movimento_forma_vida__")] <- "movimento_forma_vida_atomico"
  out[grepl("^RECALC_SUPERIORES_XLSFORM$", idc)] <- "recalculo_superiores_xlsform"
  out[grepl("^FECHAMENTO_HIERARQUICO_CONTRATO$", idc)] <- "fechamento_hierarquico_contrato"
  out[grepl("^SYNC_ENCOSTAM_FINAL$", idc)] <- "sincronizacao_final_encostam"
  out[grepl("^SANHAB", idc) | tipo %in% c("sanitizacao_habito_obrigatorio_ausente") | grepl("habito_obrigatorio_ausente", attr, fixed = TRUE)] <- "sanitizacao_habito_obrigatorio_ausente"
  out[grepl("^SANEORF", idc) | grepl("sanitizar_orfaos_encostam", tipo, fixed = TRUE)] <- "sanitizacao_orfaos_encostam"
  out
}

monitora_correcao_chave_semantica_operacao <- function(corr) {
  corr <- data.table::as.data.table(corr)
  n <- nrow(corr)
  if (!n) return(character(0))
  getc <- function(nm) if (nm %in% names(corr)) as.character(corr[[nm]]) else rep("", n)
  fam <- monitora_correcao_classificar_tipo_operacao(corr)
  campos <- list(
    id_operacao = getc("id_correcao"), familia = fam,
    tipo = getc("tipo_correcao"), acao = getc("acao"),
    atributo = getc("atributo_coluna_registros_corrig"),
    categoria_origem = getc("categoria_origem"), categoria_destino = getc("categoria_destino"),
    lista_destino = getc("lista_destino"), token_pai = getc("token_pai"), token_removido = getc("token_removido"),
    valor_novo = getc("valor_novo"), forma = getc("forma_valida_escolhida"), habito = getc("habito_escolhido"),
    campo_dep = getc("campo_dependente_preenchido"), escopo = getc("escopo_aplicacao")
  )
  mat <- data.frame(lapply(campos, function(v) { v <- tolower(trimws(as.character(v))); v[is.na(v)] <- ""; v }), check.names = FALSE)
  apply(mat, 1L, paste, collapse = "\r")
}

monitora_correcao_agrupar_operacoes_semanticas <- function(ops) {
  ops <- data.table::as.data.table(ops)
  if (!nrow(ops)) return(ops)
  ops <- data.table::copy(ops)
  for (cc in c(
    "id_correcao", "uuid_registro", "monitora_row_id", "alvos_solicitados_monitora_row_id",
    "linha_indice", "linhas_alvo_serializadas", "linhas_alvo_serializadas_operacao",
    "coleta", "ponto_amostral", "ponto_metro", "n_linhas_esperado", "n_linhas_alvo",
    "n_linhas_solicitadas", "n_itens_solicitados", "n_itens_efetivos", "n_itens_auditaveis", "motivo",
    "tipo_correcao", "acao", "atributo_coluna_registros_corrig", "valor_novo", "habito_escolhido"
  )) if (!(cc %in% names(ops))) data.table::set(ops, j = cc, value = NA_character_)
 ### Congela a intenção antes de qualquer deduplicação/reconciliação. Para
 ### ledgers antigos, usa n_itens_auditaveis quando a operação já chegou
 ### compactada; caso contrário cada linha representa um item solicitado.
  for (ii in seq_len(nrow(ops))) {
    ids_i <- monitora_correcao_parse_ids_estaveis(c(
      as.character(ops$alvos_solicitados_monitora_row_id[ii]),
      as.character(ops$monitora_row_id[ii])
    ))
    if (length(ids_i) && monitora_correcao_vazio(ops$alvos_solicitados_monitora_row_id[ii])) {
      data.table::set(ops, i = ii, j = "alvos_solicitados_monitora_row_id", value = monitora_correcao_serializar_ids_estaveis(ids_i))
    }
    n_item_i <- suppressWarnings(as.integer(ops$n_itens_solicitados[ii]))
    if (!is.finite(n_item_i) || n_item_i < 1L) n_item_i <- suppressWarnings(as.integer(ops$n_itens_auditaveis[ii]))
    if (!is.finite(n_item_i) || n_item_i < 1L) n_item_i <- 1L
    data.table::set(ops, i = ii, j = "n_itens_solicitados", value = n_item_i)
  }
  key <- monitora_correcao_chave_semantica_operacao(ops)
  fam <- monitora_correcao_classificar_tipo_operacao(ops)
  idx_sanhab <- which(fam == "sanitizacao_habito_obrigatorio_ausente")
  if (length(idx_sanhab)) {
    key[idx_sanhab] <- apply(data.frame(
      id = as.character(ops$id_correcao[idx_sanhab]),
      familia = fam[idx_sanhab],
      tipo = as.character(ops$tipo_correcao[idx_sanhab]),
      acao = as.character(ops$acao[idx_sanhab]),
      atributo = as.character(ops$atributo_coluna_registros_corrig[idx_sanhab]),
      valor = as.character(ops$valor_novo[idx_sanhab]),
      habito = as.character(ops$habito_escolhido[idx_sanhab]),
      stringsAsFactors = FALSE
    ), 1L, function(v) paste(tolower(trimws(v)), collapse = "\r"))
  }
  idx_grp <- which(fam %in% c(
    "triagem_desconhecida_atomica", "pendencia_sem_forma_vida_lote",
    "limpeza_outras_formas_atomica", "movimento_forma_vida_lote_atomico",
    "movimento_forma_vida_atomico", "sanitizacao_habito_obrigatorio_ausente",
    "sanitizacao_orfaos_encostam"
  ))
  if (!length(idx_grp)) return(ops[])
  ops[, .semkey_agrupar := key]
  out <- list()
 # mantém operações não agrupáveis como estão
  if (length(setdiff(seq_len(nrow(ops)), idx_grp))) out[[length(out)+1L]] <- ops[setdiff(seq_len(nrow(ops)), idx_grp)]
  for (kk in unique(ops$.semkey_agrupar[idx_grp])) {
    g <- data.table::copy(ops[.semkey_agrupar == kk])
    if (nrow(g) == 1L) {
      ids1 <- monitora_correcao_parse_ids_estaveis(c(g$alvos_solicitados_monitora_row_id, g$monitora_row_id))
      uu1 <- unique(monitora_correcao_parse_serial_generico(g$uuid_registro))
      li1 <- suppressWarnings(as.integer(monitora_correcao_parse_serial_generico(c(g$linhas_alvo_serializadas_operacao, g$linhas_alvo_serializadas, g$linha_indice))))
      li1 <- unique(li1[!is.na(li1)])
      n1 <- max(c(length(ids1), length(uu1), length(li1), suppressWarnings(as.integer(g$n_linhas_esperado[1L])), 1L), na.rm = TRUE)
      n_item1 <- max(c(suppressWarnings(as.integer(g$n_itens_solicitados[1L])), n1), na.rm = TRUE)
      g[, `:=`(
        n_linhas_solicitadas = as.integer(n1),
        n_itens_efetivos = as.integer(n1),
        n_itens_solicitados = as.integer(n_item1),
        n_itens_auditaveis = as.integer(n_item1)
      )]
      g[, .semkey_agrupar := NULL]
      out[[length(out)+1L]] <- g
      next
    }
    linha <- data.table::copy(g[1L])
    ids <- monitora_correcao_parse_ids_estaveis(c(g$alvos_solicitados_monitora_row_id, g$monitora_row_id))
    uu <- unique(monitora_correcao_parse_serial_generico(g$uuid_registro))
    li <- suppressWarnings(as.integer(monitora_correcao_parse_serial_generico(c(g$linhas_alvo_serializadas_operacao, g$linhas_alvo_serializadas, g$linha_indice))))
    li <- unique(li[!is.na(li)])
    co <- unique(monitora_correcao_parse_serial_generico(g$coleta))
    pt <- unique(monitora_correcao_parse_serial_generico(g$ponto_amostral))
    pm <- if ("ponto_metro" %in% names(g)) unique(monitora_correcao_parse_serial_generico(g$ponto_metro)) else character(0)
    if (length(ids)) linha[, `:=`(
      monitora_row_id = monitora_correcao_serializar_ids_estaveis(ids),
      alvos_solicitados_monitora_row_id = monitora_correcao_serializar_ids_estaveis(ids)
    )]
    if (length(uu)) linha[, uuid_registro := monitora_correcao_colapsar_lista_serializada(uu)]
    if (length(li)) linha[, `:=`(
      linhas_alvo_serializadas = monitora_correcao_colapsar_lista_serializada(as.character(li)),
      linhas_alvo_serializadas_operacao = monitora_correcao_colapsar_lista_serializada(as.character(li))
    )]
    if (length(co)) linha[, coleta := monitora_correcao_colapsar_lista_serializada(co)]
    if (length(pt)) linha[, ponto_amostral := monitora_correcao_colapsar_lista_serializada(pt)]
    if (length(pm)) linha[, ponto_metro := monitora_correcao_colapsar_lista_serializada(pm)]
    if ("Ponto amostral" %in% names(linha) && length(pt)) linha[, `Ponto amostral` := monitora_correcao_colapsar_lista_serializada(pt)]
    if ("Ponto metro" %in% names(linha) && length(pm)) linha[, `Ponto metro` := monitora_correcao_colapsar_lista_serializada(pm)]
    n_alvos <- max(c(length(ids), length(uu), length(li), 1L), na.rm = TRUE)
    n_itens_solic <- sum(suppressWarnings(as.integer(g$n_itens_solicitados)), na.rm = TRUE)
    if (!is.finite(n_itens_solic) || n_itens_solic < 1L) n_itens_solic <- nrow(g)
 ### Um ledger efetivo pode já ter retirado uma linha protegida por decisão
 ### específica, mas conservar a cardinalidade original do grupo em sua
 ### lista de alvos/n_linhas_esperado. A intenção solicitada nunca pode ser
 ### menor que essa cardinalidade congelada.
    n_itens_solic <- max(as.integer(n_itens_solic), as.integer(n_alvos))
    linha[, `:=`(
      n_linhas_solicitadas = as.integer(n_alvos),
      n_linhas_esperado = as.integer(n_alvos),
      n_linhas_alvo = as.integer(n_alvos),
      n_itens_solicitados = as.integer(n_itens_solic),
      n_itens_efetivos = as.integer(n_alvos),
      n_itens_auditaveis = as.integer(n_itens_solic),
      operacao_semantica_agrupada = TRUE,
      motivo = paste0(as.character(motivo[1L]), " [", n_itens_solic, " item(ns) solicitado(s); ", n_alvos, " alvo(s) único(s) agrupado(s) em uma operação semântica]")
    )]
    linha[, .semkey_agrupar := NULL]
    out[[length(out)+1L]] <- linha
  }
  data.table::rbindlist(out, fill = TRUE, use.names = TRUE)
}

monitora_correcao_contar_operacoes_semanticas <- function(correcoes) {
  if (is.null(correcoes)) return(0L)
  cc <- data.table::as.data.table(correcoes)
  if (!nrow(cc)) return(0L)
  cc2 <- tryCatch(monitora_correcao_agrupar_operacoes_semanticas(cc), error = function(e) cc)
  if (!("id_correcao" %in% names(cc2))) return(nrow(cc2))
  ids <- trimws(as.character(cc2$id_correcao))
  ids[is.na(ids) | !nzchar(ids)] <- paste0("__linha_", which(is.na(ids) | !nzchar(ids)))
  as.integer(data.table::uniqueN(ids))
}

monitora_correcao_aplicar_triagens_desconhecida_atomicas <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(list(dt = dt[], corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  idx_tri <- which(monitora_correcao_eh_operacao_triagem_desconhecida(corr))
  if (!length(idx_tri)) return(list(dt = dt[], corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  corr_tri <- data.table::copy(corr[idx_tri])
  corr_tri <- monitora_correcao_agrupar_operacoes_semanticas(corr_tri)
  grupos <- if ("id_correcao" %in% names(corr_tri)) unique(as.character(corr_tri$id_correcao)) else paste0("__linha_", seq_len(nrow(corr_tri)))
  audit <- data.table::data.table(); linhas <- integer(); afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character()); falha <- FALSE
  for (gg in seq_along(grupos)) {
    gid <- grupos[gg]
    grp <- corr_tri[as.character(id_correcao) == gid]
    if (!nrow(grp)) grp <- corr_tri[gg]
    if (exists("monitora_correcao_console_msg", mode = "function")) {
      forma_msg <- if ("forma_valida_escolhida" %in% names(grp)) as.character(grp$forma_valida_escolhida[1L]) else as.character(grp$valor_novo[1L])
      dest_msg <- if ("categoria_destino" %in% names(grp)) as.character(grp$categoria_destino[1L]) else NA_character_
      monitora_correcao_console_msg("Aplicando operação semântica TRIDESC ", gg, "/", length(grupos), ": destino=", dest_msg, "; forma=", forma_msg, ".")
    }
    linha_atom <- monitora_correcao_compactar_triagem_desconhecida_atomica(grp)
 # A compactação antiga preserva o primeiro item; estes campos reintroduzem o escopo completo.
    for (cc in intersect(c("uuid_registro", "linhas_alvo_serializadas", "coleta", "ponto_amostral", "n_linhas_esperado", "n_linhas_alvo", "n_itens_auditaveis"), names(grp))) {
      if (cc %in% names(linha_atom)) data.table::set(linha_atom, j = cc, value = grp[[cc]][1L]) else linha_atom[, (cc) := grp[[cc]][1L]]
    }
    res <- monitora_correcao_aplicar_triagem_desconhecida_atomica(dt, linha_atom, chaves, indice, arquivo_correcao, dicionario)
    dt <- res$dt
    if (nrow(res$audit)) audit <- data.table::rbindlist(list(audit, res$audit), fill = TRUE, use.names = TRUE)
    if (length(res$linhas)) linhas <- unique(c(linhas, res$linhas))
    if (nrow(res$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res$afetacoes), fill = TRUE, use.names = TRUE)
    falha <- isTRUE(falha) || isTRUE(res$falha)
  }
 # remove do plano todas as operações de desconhecida originais, processadas pela transação agrupada
  corr_out <- corr[-idx_tri]
  list(dt = dt[], corr = corr_out[], audit = audit[], linhas = linhas, afetacoes = unique(afetacoes), falha = falha, n_grupos = length(grupos))
}

### Exclusão atômica de COLETAS
### -------------------------------------------------------------------------
### Aplica grupos de exclusão de COLETAS em lote: pré-valida todas as COLETAS
### do grupo, registra auditoria no estado pré-exclusão e remove as linhas em
### uma única operação data.table, evitando reconstruir índices a cada COLETA.
monitora_correcao_aplicar_exclusoes_coleta_atomicas <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), coletas = character(), linhas_removidas = integer(), falha = FALSE, n_grupos = 0L))
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  acao_vec <- if ("acao" %in% names(corr)) as.character(corr$acao) else rep("", nrow(corr))
  tipo_vec <- if ("tipo_correcao" %in% names(corr)) as.character(corr$tipo_correcao) else rep("", nrow(corr))
  idx_exc <- which(mapply(monitora_correcao_acao_exclusao_coleta, acao_vec, tipo_vec))
  if (!length(idx_exc)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), coletas = character(), linhas_removidas = integer(), falha = FALSE, n_grupos = 0L))
  corr[, .grupo_exc_atom := fifelse(!is.na(id_correcao) & nzchar(as.character(id_correcao)), as.character(id_correcao), paste0("__linha_", ordem_tmp))]
  grupos <- unique(corr[idx_exc, .grupo_exc_atom])
  audit <- data.table::data.table()
  linhas_remover_total <- integer()
  coletas_removidas <- character()
  falha <- FALSE
  grupos_processados <- character()
  for (gid in grupos) {
    grp <- corr[.grupo_exc_atom == gid]
    invalid <- data.table::data.table()
    linhas_por_op <- vector("list", nrow(grp))
    for (ii in seq_len(nrow(grp))) {
      linha_corr <- grp[ii]
      escopo_corr <- if ("escopo_aplicacao" %in% names(linha_corr)) tolower(trimws(as.character(linha_corr$escopo_aplicacao[1L]))) else ""
      linhas <- monitora_correcao_localizar_linhas(dt, linha_corr, chaves, indice)
      linhas <- unique(as.integer(linhas))
      linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
      linhas_por_op[[ii]] <- linhas
      n_esperado <- suppressWarnings(as.integer(linha_corr$n_linhas_esperado[1L]))
      status <- "ok"; msg <- "OK"
      if (!identical(escopo_corr, "coleta_inteira")) {
        status <- "bloqueada_exclusao_coleta"; msg <- "exclusão de COLETA exige escopo_aplicacao='coleta_inteira'"
      } else if (is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) {
        status <- "falha"; msg <- "Coluna de COLETA não localizada; exclusão bloqueada"
      } else if (length(linhas) == 0L) {
        status <- "falha"; msg <- "Nenhuma linha-alvo localizada para exclusão da COLETA"
      } else if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) {
        status <- "falha"; msg <- paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado, " para exclusão da COLETA")
      }
      if (!identical(status, "ok")) {
        invalid <- data.table::rbindlist(list(invalid, data.table::data.table(
          id_correcao = linha_corr$id_correcao[1L],
          ordem_operacao = linha_corr$ordem_operacao[1L],
          status = status,
          mensagem = paste0("Grupo de exclusão bloqueado atomicamente: ", msg),
          atributo = if (!is.na(chaves$coleta)) chaves$coleta else linha_corr$atributo_coluna_registros_corrig[1L],
          linha_indice = NA_integer_,
          valor_antes = NA_character_,
          valor_depois = NA_character_,
          arquivo_correcao = arquivo_correcao
        )), fill = TRUE, use.names = TRUE)
      }
    }
    grupos_processados <- unique(c(grupos_processados, gid))
    if (nrow(invalid) > 0L) {
      audit <- data.table::rbindlist(list(audit, invalid), fill = TRUE, use.names = TRUE)
      falha <- TRUE
      next
    }
    for (ii in seq_len(nrow(grp))) {
      linha_corr <- grp[ii]
      linhas <- linhas_por_op[[ii]]
      coleta_val <- if ("coleta" %in% names(linha_corr)) as.character(linha_corr$coleta[1L]) else NA_character_
      audit_del <- data.table::data.table(
        id_correcao = linha_corr$id_correcao[1L],
        ordem_operacao = linha_corr$ordem_operacao[1L],
        status = "excluida_coleta",
        mensagem = paste0("Exclusão atômica de COLETA: ", length(linhas), " registro(s) removido(s) em lote"),
        atributo = chaves$coleta,
        linha_indice = linhas,
        valor_antes = if (!is.na(chaves$coleta) && chaves$coleta %in% names(dt)) as.character(dt[[chaves$coleta]][linhas]) else NA_character_,
        valor_depois = "<REGISTRO_REMOVIDO>",
        arquivo_correcao = arquivo_correcao
      )
      audit_del <- monitora_correcao_anexar_contexto_auditoria(audit_del, dt, chaves)
      audit <- data.table::rbindlist(list(audit, audit_del), fill = TRUE, use.names = TRUE)
      linhas_remover_total <- unique(c(linhas_remover_total, linhas))
      if (!is.na(coleta_val) && nzchar(trimws(coleta_val))) coletas_removidas <- unique(c(coletas_removidas, coleta_val))
    }
  }
  linhas_remover_total <- sort(unique(linhas_remover_total))
  linhas_remover_total <- linhas_remover_total[!is.na(linhas_remover_total) & linhas_remover_total >= 1L & linhas_remover_total <= nrow(dt)]
  if (length(linhas_remover_total) > 0L) dt <- dt[-linhas_remover_total]
  corr_out <- corr[!(.grupo_exc_atom %in% grupos_processados)]
  corr_out[, .grupo_exc_atom := NULL]
  corr[, .grupo_exc_atom := NULL]
  list(dt = dt[], corr = corr_out[], audit = audit[], coletas = coletas_removidas, linhas_removidas = linhas_remover_total, falha = falha, n_grupos = length(grupos_processados))
}


### -----------------------------------------------------------------
### Replay semântico em nova execução: o arquivo de correções é uma trilha de
### intenção, não um vetor de posições. Este bloco corrige três pontos críticos:
### 1) PENDFV agrupado não pode parar nos poucos UUIDs que ainda batem; deve
### reconstruir o escopo corrente por COLETA e filtrar pendências reais.
### 2) EXCCOL em replay não deve falhar quando a COLETA já não existe no input
### corrente; isso é estado já materializado/ausente, não erro fatal.
### 3) MVLOTE de desconhecida não deve depender de linha_indice antigo; deve
### reaplicar a intenção "desconhecida -> forma válida/destino" sobre as
### ocorrências diagnósticas atuais da categoria-base no escopo de COLETAS.

monitora_replay_v263_parse_lista <- function(x) {
  if (is.null(x)) return(character(0))
  x <- as.character(x)
  x <- x[!is.na(x)]
  if (!length(x)) return(character(0))
  vals <- unlist(strsplit(x, "[|;\n\r]+", perl = TRUE), use.names = FALSE)
  vals <- trimws(as.character(vals))
  vals <- vals[!is.na(vals) & nzchar(vals)]
  vals <- vals[!(toupper(vals) %in% c("NA", "NAN", "NULL", "NONE", "---"))]
  unique(vals)
}

monitora_replay_v263_parse_colunas <- function(tab, cols) {
  tab <- data.table::as.data.table(tab)
  vals <- character(0)
  for (cc in intersect(cols, names(tab))) {
    vals <- c(vals, unlist(lapply(as.character(tab[[cc]]), monitora_replay_v263_parse_lista), use.names = FALSE))
  }
  vals <- trimws(as.character(vals))
  vals <- vals[!is.na(vals) & nzchar(vals)]
  unique(vals)
}

monitora_replay_v263_filtrar_valores <- function(dt, linhas, col, vals) {
  dt <- data.table::as.data.table(dt)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  vals <- unique(trimws(as.character(vals)))
  vals <- vals[!is.na(vals) & nzchar(vals)]
  if (!length(linhas) || is.na(col) || !nzchar(col) || !(col %in% names(dt)) || !length(vals)) return(linhas)
  linhas[trimws(as.character(dt[[col]][linhas])) %chin% vals]
}

monitora_correcao_linhas_pendfv_grupo <- function(dt, grupo, col, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  grupo <- data.table::as.data.table(grupo)
  if (!nrow(dt) || !nrow(grupo) || is.na(col) || !(col %in% names(dt))) return(integer(0))

 ### Escopo preferencial para replay: COLETA(s) + estado diagnóstico corrente.
 ### Isso evita perder a maior parte de um lote quando apenas alguns UUIDs da
 ### rodada antiga ainda batem no input reprocessado.
  idx <- integer(0)
  coletas <- monitora_replay_v263_parse_colunas(grupo, c("coleta", "COLETA", "coletas", "coletas_alvo", "coletas_lote"))
  if (length(coletas) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    idx <- which(trimws(as.character(dt[[chaves$coleta]])) %chin% coletas)
  }

 ### UUIDs continuam úteis para arquivos não agrupados, mas são união, não
 ### condição de parada. Em grupos grandes eles costumam ser incompletos.
  uuids <- monitora_replay_v263_parse_colunas(grupo, c("uuid_registro", "uuid_registro_serializado", "uuids_registro"))
  if (length(uuids) && !is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) {
    idx_uuid <- which(trimws(as.character(dt[[chaves$uuid_registro]])) %chin% uuids)
    idx <- unique(c(idx, idx_uuid))
  }

 ### Fallback por linha antiga apenas se não houver escopo estável.
  if (!length(idx) && !length(coletas) && !length(uuids)) {
    li <- suppressWarnings(as.integer(monitora_replay_v263_parse_colunas(grupo, c("linhas_alvo_serializadas", "linha_indice", "linhas_alvo"))))
    li <- unique(li[!is.na(li) & li >= 1L & li <= nrow(dt)])
    if (length(li)) idx <- li
  }

  idx <- unique(as.integer(idx))
  idx <- idx[!is.na(idx) & idx >= 1L & idx <= nrow(dt)]
  if (!length(idx)) return(integer(0))

  categoria <- monitora_correcao_inferir_categoria_pendfv(grupo, col)
  vazio_destino <- monitora_correcao_vazio_vec(dt[[col]][idx])
  if (!is.na(categoria) && nzchar(categoria) && !is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% names(dt)) {
    tem_cat <- monitora_correcao_contem_qualquer_token_vec(dt[[chaves$tipo_forma_vida]][idx], categoria)
  } else {
    tem_cat <- rep(TRUE, length(idx))
  }
  idx[tem_cat & vazio_destino]
}

monitora_correcao_aplicar_exclusoes_coleta_atomicas <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), coletas = character(), linhas_removidas = integer(), falha = FALSE, n_grupos = 0L))
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  acao_vec <- if ("acao" %in% names(corr)) as.character(corr$acao) else rep("", nrow(corr))
  tipo_vec <- if ("tipo_correcao" %in% names(corr)) as.character(corr$tipo_correcao) else rep("", nrow(corr))
  idx_exc <- which(mapply(monitora_correcao_acao_exclusao_coleta, acao_vec, tipo_vec))
  if (!length(idx_exc)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), coletas = character(), linhas_removidas = integer(), falha = FALSE, n_grupos = 0L))

  corr[, .grupo_exc_atom := data.table::fifelse(!is.na(id_correcao) & nzchar(as.character(id_correcao)), as.character(id_correcao), paste0("__linha_", ordem_tmp))]
  grupos <- unique(corr[idx_exc, .grupo_exc_atom])
  audit <- data.table::data.table()
  linhas_remover_total <- integer()
  coletas_removidas <- character()
  grupos_processados <- character()
  falha <- FALSE

  for (gid in grupos) {
    grp <- corr[.grupo_exc_atom == gid]
    grupos_processados <- unique(c(grupos_processados, gid))
    coletas_grp <- monitora_replay_v263_parse_colunas(grp, c("coleta", "COLETA", "coletas", "coletas_alvo"))
    if (is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) {
      falha <- TRUE
      audit <- data.table::rbindlist(list(audit, data.table::data.table(
        id_correcao = grp$id_correcao[1L], ordem_operacao = NA_character_,
        status = "falha_coluna_coleta_exclusao", mensagem = "Coluna de COLETA não localizada; exclusão bloqueada",
        atributo = "COLETA", linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao
      )), fill = TRUE, use.names = TRUE)
      next
    }
    if (!length(coletas_grp)) {
      falha <- TRUE
      audit <- data.table::rbindlist(list(audit, data.table::data.table(
        id_correcao = grp$id_correcao[1L], ordem_operacao = NA_character_,
        status = "falha_sem_coleta_exclusao", mensagem = "Operação de exclusão sem COLETA identificável",
        atributo = chaves$coleta, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao
      )), fill = TRUE, use.names = TRUE)
      next
    }

    for (co in coletas_grp) {
      linhas <- which(trimws(as.character(dt[[chaves$coleta]])) == trimws(as.character(co)))
      linhas <- unique(as.integer(linhas))
      linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
      if (!length(linhas)) {
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = grp$id_correcao[1L], ordem_operacao = NA_character_,
          status = "ok_coleta_ausente_estado_corrente",
          mensagem = "Exclusão em replay sem ação: COLETA não existe no input/estado corrente ou já foi removida anteriormente",
          atributo = chaves$coleta, linha_indice = NA_integer_, valor_antes = as.character(co),
          valor_depois = "<COLETA_AUSENTE_ESTADO_CORRENTE>", arquivo_correcao = arquivo_correcao
        )), fill = TRUE, use.names = TRUE)
        next
      }
      audit_del <- data.table::data.table(
        id_correcao = grp$id_correcao[1L],
        ordem_operacao = NA_character_,
        status = "excluida_coleta",
        mensagem = paste0("Exclusão atômica/replay de COLETA: ", length(linhas), " registro(s) removido(s)"),
        atributo = chaves$coleta,
        linha_indice = linhas,
        valor_antes = as.character(dt[[chaves$coleta]][linhas]),
        valor_depois = "<REGISTRO_REMOVIDO>",
        arquivo_correcao = arquivo_correcao
      )
      audit_del <- monitora_correcao_anexar_contexto_auditoria(audit_del, dt, chaves)
      audit <- data.table::rbindlist(list(audit, audit_del), fill = TRUE, use.names = TRUE)
      linhas_remover_total <- unique(c(linhas_remover_total, linhas))
      coletas_removidas <- unique(c(coletas_removidas, as.character(co)))
    }
  }

  linhas_remover_total <- sort(unique(as.integer(linhas_remover_total)))
  linhas_remover_total <- linhas_remover_total[!is.na(linhas_remover_total) & linhas_remover_total >= 1L & linhas_remover_total <= nrow(dt)]
  if (length(linhas_remover_total) > 0L) dt <- dt[-linhas_remover_total]
  corr_out <- corr[!(.grupo_exc_atom %in% grupos_processados)]
  corr_out[, .grupo_exc_atom := NULL]
  corr[, .grupo_exc_atom := NULL]
  list(dt = dt[], corr = corr_out[], audit = audit[], coletas = coletas_removidas, linhas_removidas = linhas_remover_total, falha = falha, n_grupos = length(grupos_processados))
}

monitora_correcao_localizar_linhas_movimento_lote <- function(dt, linha_lote, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  linha_lote <- data.table::as.data.table(linha_lote)
  if (!nrow(dt) || !nrow(linha_lote)) return(integer(0))

  mv_desc_vals <- character(0)
  for (cc_mv in intersect(c("escopo_diagnostico_mvlote", "categoria_base_diagnostica", "token_pai", "token_removido", "valor_original_esperado"), names(linha_lote))) {
    mv_desc_vals <- c(mv_desc_vals, as.character(linha_lote[[cc_mv]][1L]))
  }
  mv_desc_norm <- tryCatch(monitora_correcao_limpar_texto(mv_desc_vals), error = function(e) tolower(trimws(mv_desc_vals)))
  mv_desc_semantica <- any(mv_desc_norm %in% c("forma_vida_desconhecida_categoria_base", "forma_vida_desconhecida", "desconhecida", "desconhecido"), na.rm = TRUE)

  n_esperado <- suppressWarnings(as.integer(c(
    if ("n_linhas_esperado" %in% names(linha_lote)) linha_lote$n_linhas_esperado[1L] else NA,
    if ("n_linhas_alvo" %in% names(linha_lote)) linha_lote$n_linhas_alvo[1L] else NA
  )))
  n_esperado <- n_esperado[is.finite(n_esperado) & n_esperado > 0L]
  n_esperado <- if (length(n_esperado)) n_esperado[1L] else NA_integer_
  coletas <- monitora_replay_v263_parse_colunas(linha_lote, c("coleta", "COLETA", "coletas", "coletas_alvo"))
  limitar_coletas <- function(idx) {
    idx <- unique(as.integer(idx))
    idx <- idx[!is.na(idx) & idx >= 1L & idx <= nrow(dt)]
    if (length(coletas) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
      idx <- idx[trimws(as.character(dt[[chaves$coleta]][idx])) %chin% coletas]
    }
    monitora_correcao_aplicar_escopo_conciliado(dt, idx, linha_lote)
  }
  aceitar_exato <- function(idx) {
    idx <- limitar_coletas(idx)
    if (!length(idx)) return(integer(0))
    if (is.finite(n_esperado) && length(idx) != n_esperado) return(integer(0))
    idx
  }

 ### Autoridade 1: identidades estáveis já conciliadas/solicitadas.
  if (MONITORA_COL_ROW_ID %in% names(dt)) {
    ids <- character(0)
    for (cc in intersect(c("alvos_efetivos_monitora_row_id", "alvos_solicitados_monitora_row_id", "monitora_row_id"), names(linha_lote))) {
      ids <- c(ids, monitora_correcao_parse_ids_estaveis(as.character(linha_lote[[cc]])))
    }
    ids <- unique(ids[!is.na(ids) & nzchar(ids)])
    if (length(ids)) {
      idx <- aceitar_exato(match(ids, as.character(dt[[MONITORA_COL_ROW_ID]]), nomatch = 0L))
      if (length(idx)) return(idx)
    }
  }
 ### Autoridade 2: UUIDs de registro serializados.
  if (!is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt) && "uuid_registro" %in% names(linha_lote)) {
    uuids <- monitora_replay_v263_parse_colunas(linha_lote, "uuid_registro")
    if (length(uuids)) {
      idx <- aceitar_exato(which(as.character(dt[[chaves$uuid_registro]]) %chin% uuids))
      if (length(idx)) return(idx)
    }
  }
 ### Autoridade 3: posições congeladas na mesma execução. Só são aceitas
 ### quando preservam a cardinalidade e permanecem dentro das COLETAS.
  linhas_serial <- suppressWarnings(as.integer(monitora_replay_v263_parse_colunas(
    linha_lote, c("linhas_alvo_efetivas_serializadas", "linhas_alvo_serializadas_operacao", "linhas_alvo_serializadas", "linha_indice", "linhas_alvo")
  )))
  linhas_serial <- aceitar_exato(linhas_serial)
  if (length(linhas_serial)) return(linhas_serial)

 ### Compatibilidade de replay legado sem identidades estáveis: reconstrói o
 ### universo apenas dentro das COLETAS e filtra pela categoria/forma de
 ### origem. Nunca retorna a COLETA inteira para uma operação por ocorrência.
  if (length(coletas) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    idx <- which(trimws(as.character(dt[[chaves$coleta]])) %chin% coletas)
    origem <- if ("categoria_origem" %in% names(linha_lote)) tolower(trimws(as.character(linha_lote$categoria_origem[1L]))) else ""
    col_origem <- tryCatch(monitora_correcao_coluna_forma_vida(dt, origem), error = function(e) NA_character_)
    if (!is.na(col_origem) && col_origem %in% names(dt)) {
      formas <- monitora_replay_v263_parse_colunas(linha_lote, c("token_pai", "token_removido", "valor_original_esperado"))
      todas <- any(tolower(formas) %in% c("__todas__", "todas", "todos", "all"))
      if (isTRUE(mv_desc_semantica)) {
        idx <- tryCatch(monitora_correcao_linhas_desconhecida_categoria_base(dt, origem, idx), error = function(e) integer(0))
      } else if (isTRUE(todas)) {
        idx <- idx[!monitora_correcao_vazio_vec(dt[[col_origem]][idx])]
      } else if (length(formas)) {
        hit <- rep(FALSE, length(idx))
        for (ff in formas) {
          toks <- unique(c(ff, tryCatch(monitora_correcao_sinonimos_forma(ff), error = function(e) character(0))))
          for (tok in toks) hit <- hit | monitora_correcao_token_presente_vec(dt[[col_origem]][idx], tok)
        }
        hit[is.na(hit)] <- FALSE
        idx <- idx[hit]
      } else {
        idx <- integer(0)
      }
    } else {
      idx <- integer(0)
    }
    idx <- aceitar_exato(idx)
    if (length(idx)) return(idx)
  }
  integer(0)
}

monitora_correcao_aplicar_movimento_forma_vida_lote_atomico__v262 <- monitora_correcao_aplicar_movimento_forma_vida_lote_atomico

monitora_correcao_aplicar_movimento_forma_vida_lote_atomico <- function(dt, linha_lote, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL, gravar_relatorio_ambiguidades = TRUE) {
  dt <- monitora_dt_referenciar(dt)
  linha_lote <- data.table::as.data.table(linha_lote)
  if (!nrow(linha_lote)) return(list(dt = dt[], audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE))

  mv_desc_vals <- character(0)
  for (cc_mv in intersect(c("escopo_diagnostico_mvlote", "categoria_base_diagnostica", "token_pai", "token_removido", "valor_original_esperado"), names(linha_lote))) {
    mv_desc_vals <- c(mv_desc_vals, as.character(linha_lote[[cc_mv]][1L]))
  }
  mv_desc_norm <- tryCatch(monitora_correcao_limpar_texto(mv_desc_vals), error = function(e) tolower(trimws(mv_desc_vals)))
  mv_desc_semantica <- any(mv_desc_norm %in% c("forma_vida_desconhecida_categoria_base", "forma_vida_desconhecida", "desconhecida", "desconhecido"), na.rm = TRUE)
  if (!isTRUE(mv_desc_semantica)) {
    return(monitora_correcao_aplicar_movimento_forma_vida_lote_atomico__v262(dt, linha_lote, chaves, indice, arquivo_correcao, dicionario, gravar_relatorio_ambiguidades))
  }

  id_cor <- if ("id_correcao" %in% names(linha_lote)) as.character(linha_lote$id_correcao[1L]) else NA_character_
  ordem <- if ("ordem_operacao" %in% names(linha_lote)) linha_lote$ordem_operacao[1L] else NA_character_
  registrar <- function(status, msg, atributo, idx, antes, depois) {
    data.table::data.table(
      id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = msg,
      atributo = atributo, linha_indice = as.integer(idx), valor_antes = as.character(antes),
      valor_depois = as.character(depois), arquivo_correcao = arquivo_correcao
    )
  }
  nofatal <- function(status, msg, linhas_info = integer()) {
    list(
      dt = dt[],
      audit = registrar(status, paste0("Replay MVLOTE desconhecida sem alteração fatal: ", msg), "__mover_forma_vida_lote__", if (length(linhas_info)) linhas_info else NA_integer_, NA_character_, NA_character_),
      linhas = unique(as.integer(linhas_info)),
      afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()),
      falha = FALSE
    )
  }
  falhar <- function(status, msg) {
    list(
      dt = dt[],
      audit = registrar(status, paste0("Replay MVLOTE desconhecida bloqueado: ", msg), "__mover_forma_vida_lote__", NA_integer_, NA_character_, NA_character_),
      linhas = integer(),
      afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()),
      falha = TRUE
    )
  }

  origem <- if ("categoria_origem" %in% names(linha_lote)) tolower(trimws(as.character(linha_lote$categoria_origem[1L]))) else NA_character_
  destino <- if ("categoria_destino" %in% names(linha_lote)) tolower(trimws(as.character(linha_lote$categoria_destino[1L]))) else NA_character_
  cats_info <- tryCatch(monitora_contrato_categorias_movimento(), error = function(e) data.table::data.table())
  cats_origem_desc <- cats_info[admite_desconhecida == TRUE, categoria]
  cats_destino <- cats_info$categoria
  if (monitora_correcao_vazio(origem) || !(origem %in% cats_origem_desc)) return(falhar("falha_categoria_origem", "categoria de origem de desconhecida ausente/inválida"))
  if (monitora_correcao_vazio(destino) || !(destino %in% cats_destino)) destino <- origem

  col_origem <- tryCatch(monitora_correcao_coluna_forma_vida(dt, origem), error = function(e) NA_character_)
  col_destino <- tryCatch(monitora_correcao_coluna_forma_vida(dt, destino), error = function(e) NA_character_)
  if (is.na(col_origem) || !(col_origem %in% names(dt))) return(falhar("falha_coluna_origem", paste0("coluna de origem não localizada para ", origem)))
  if (is.na(col_destino) || !(col_destino %in% names(dt))) return(falhar("falha_coluna_destino", paste0("coluna de destino não localizada para ", destino)))

  forma_destino <- monitora_replay_v263_parse_colunas(linha_lote, c("forma_valida_escolhida", "valor_novo", "forma_destino_lote"))
  forma_destino <- forma_destino[!tolower(forma_destino) %in% c("__todas__", "todas", "todos", "all", "desconhecida", "desconhecido")]
  forma_destino <- tryCatch(monitora_correcao_forma_canonica_lote(forma_destino), error = function(e) forma_destino)
  forma_destino <- unique(forma_destino[!is.na(forma_destino) & nzchar(forma_destino)])
  if (!length(forma_destino)) return(falhar("falha_forma_destino", "forma válida de destino não informada"))
  forma_destino <- forma_destino[1L]
  dominio_destino <- tryCatch(monitora_contrato_tokens_categoria_movimento(destino), error = function(e) character(0))
  if (!length(dominio_destino) || !(forma_destino %in% dominio_destino)) return(falhar("falha_forma_destino_fora_contrato", paste0("forma de destino '", forma_destino, "' não pertence ao domínio ", destino, " do contrato único")))

  linhas_base <- monitora_correcao_localizar_linhas_movimento_lote(dt, linha_lote, chaves)
  linhas_base <- unique(as.integer(linhas_base))
  linhas_base <- linhas_base[!is.na(linhas_base) & linhas_base >= 1L & linhas_base <= nrow(dt)]
  if (!length(linhas_base)) return(nofatal("ok_sem_escopo_corrente", "nenhuma COLETA/linha do escopo foi localizada no estado corrente"))

  linhas_alvo <- tryCatch(monitora_correcao_linhas_desconhecida_categoria_base(dt, origem, linhas_base, dicionario = dicionario), error = function(e) integer(0))
  linhas_alvo <- unique(as.integer(linhas_alvo))
  linhas_alvo <- linhas_alvo[!is.na(linhas_alvo) & linhas_alvo >= 1L & linhas_alvo <= nrow(dt)]
  if (!length(linhas_alvo)) {
 ### Em replay, o MVLOTE de "desconhecida" pode ser executado
 ### é executado antes da sanitização que transforma Encostam=desconhecida
 ### superior-only em categoria-base nativa + forma_vida_nativa=desconhecida.
 ### Nesse intervalo, a intenção semântica do usuário só está visível no
 ### campo superior Encostam/tipo_forma_vida. Portanto, antes de declarar
 ### "sem efeito", reconstruímos o alvo por COLETA + ponto/métro da operação
 ### e presença de desconhecida superior-only no estado corrente.
    linhas_sup <- tryCatch(monitora_correcao_linhas_desconhecida_sem_categoria_base(dt, linhas_base, chaves), error = function(e) integer(0))
    linhas_sup <- unique(as.integer(linhas_sup))
    linhas_sup <- linhas_sup[!is.na(linhas_sup) & linhas_sup >= 1L & linhas_sup <= nrow(dt)]
    if (length(linhas_sup)) {
      pa_vals <- tryCatch(monitora_replay_v263_parse_colunas(linha_lote, c("ponto_amostral", "Ponto amostral")), error = function(e) character(0))
      pm_vals <- tryCatch(monitora_replay_v263_parse_colunas(linha_lote, c("ponto_metro", "Ponto metro")), error = function(e) character(0))
      pa_vals <- unique(trimws(as.character(pa_vals)))
      pm_vals <- unique(trimws(as.character(pm_vals)))
      pa_vals <- pa_vals[!is.na(pa_vals) & nzchar(pa_vals) & !grepl("^multiplos\\(", pa_vals, ignore.case = TRUE)]
      pm_vals <- pm_vals[!is.na(pm_vals) & nzchar(pm_vals) & !grepl("^multiplos\\(", pm_vals, ignore.case = TRUE)]
      if (length(pa_vals) && !is.na(chaves$ponto_amostral) && chaves$ponto_amostral %in% names(dt)) {
        linhas_sup <- linhas_sup[trimws(as.character(dt[[chaves$ponto_amostral]][linhas_sup])) %chin% pa_vals]
      }
      if (length(pm_vals) && !is.na(chaves$ponto_metro) && chaves$ponto_metro %in% names(dt)) {
        linhas_sup <- linhas_sup[trimws(as.character(dt[[chaves$ponto_metro]][linhas_sup])) %chin% pm_vals]
      }
    }
    if (length(linhas_sup)) {
      linhas_alvo <- unique(as.integer(linhas_sup))
 ### A auditoria detalhada será registrada nos blocos de aplicação abaixo,
 ### quando o valor efetivamente mudar.
    } else {
      return(nofatal("ok_sem_desconhecida_estado_corrente", paste0("nenhuma ocorrência de desconhecida permaneceu em ", origem, " no escopo corrente"), linhas_base))
    }
  }

  audit <- data.table::data.table()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  tokens_desc <- unique(c("desconhecida", "desconhecido", tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) character(0))))

  if (identical(col_origem, col_destino)) {
    antes <- as.character(dt[[col_origem]][linhas_alvo])
    depois <- antes
    for (tok in tokens_desc) depois <- vapply(depois, monitora_correcao_remove_token_valor, character(1), token = tok)
    depois <- vapply(depois, monitora_correcao_append_token_valor, character(1), token = forma_destino)
    mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
    if (any(mudou, na.rm = TRUE)) {
      data.table::set(dt, i = linhas_alvo[mudou], j = col_origem, value = depois[mudou])
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Replay MVLOTE: desconhecida substituída por forma válida na mesma categoria", col_origem, linhas_alvo[mudou], antes[mudou], depois[mudou])), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas_alvo[mudou], atributo = col_origem)), fill = TRUE, use.names = TRUE)
    }
  } else {
    antes_o <- as.character(dt[[col_origem]][linhas_alvo])
    depois_o <- antes_o
    for (tok in tokens_desc) depois_o <- vapply(depois_o, monitora_correcao_remove_token_valor, character(1), token = tok)
    mudou_o <- monitora_correcao_na_para_vazio(antes_o) != monitora_correcao_na_para_vazio(depois_o)
    if (any(mudou_o, na.rm = TRUE)) {
      data.table::set(dt, i = linhas_alvo[mudou_o], j = col_origem, value = depois_o[mudou_o])
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Replay MVLOTE: desconhecida removida da categoria-base de origem", col_origem, linhas_alvo[mudou_o], antes_o[mudou_o], depois_o[mudou_o])), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas_alvo[mudou_o], atributo = col_origem)), fill = TRUE, use.names = TRUE)
    }
    antes_d <- as.character(dt[[col_destino]][linhas_alvo])
    depois_d <- vapply(antes_d, monitora_correcao_append_token_valor, character(1), token = forma_destino)
    mudou_d <- monitora_correcao_na_para_vazio(antes_d) != monitora_correcao_na_para_vazio(depois_d)
    if (any(mudou_d, na.rm = TRUE)) {
      data.table::set(dt, i = linhas_alvo[mudou_d], j = col_destino, value = depois_d[mudou_d])
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Replay MVLOTE: forma válida garantida na categoria de destino", col_destino, linhas_alvo[mudou_d], antes_d[mudou_d], depois_d[mudou_d])), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas_alvo[mudou_d], atributo = col_destino)), fill = TRUE, use.names = TRUE)
    }
  }

  res_desc_dep <- tryCatch(monitora_correcao_sanitizar_dependentes_desconhecida(
    dt, linhas = linhas_alvo, categorias = c("nativa", "exotica", "seca_morta"), id_correcao = id_cor,
    ordem_operacao = ordem, arquivo_correcao = arquivo_correcao, dicionario = dicionario, registrar_preservadas = TRUE
  ), error = function(e) NULL)
  if (is.list(res_desc_dep)) {
    dt <- res_desc_dep$dt
    if (data.table::is.data.table(res_desc_dep$audit) && nrow(res_desc_dep$audit)) audit <- data.table::rbindlist(list(audit, res_desc_dep$audit), fill = TRUE, use.names = TRUE)
    if (data.table::is.data.table(res_desc_dep$afetacoes) && nrow(res_desc_dep$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res_desc_dep$afetacoes), fill = TRUE, use.names = TRUE)
  }

  tipo_col <- chaves$tipo_forma_vida
  if (!is.na(tipo_col) && tipo_col %in% names(dt)) {
    antes_tipo <- as.character(dt[[tipo_col]][linhas_alvo])
    try(monitora_correcao_recalcular_tipo_forma_vida(dt, linhas_alvo), silent = TRUE)
    depois_tipo <- as.character(dt[[tipo_col]][linhas_alvo])
    mudou_tipo <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_tipo)
    if (any(mudou_tipo, na.rm = TRUE)) {
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Replay MVLOTE: Encostam/tipo_forma_vida recalculado após substituição de desconhecida", tipo_col, linhas_alvo[mudou_tipo], antes_tipo[mudou_tipo], depois_tipo[mudou_tipo])), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas_alvo[mudou_tipo], atributo = tipo_col)), fill = TRUE, use.names = TRUE)
    }
  }

  if (!nrow(audit)) return(nofatal("ok_estado_final_ja_coerente", "as linhas-alvo já estavam coerentes após avaliação semântica", linhas_alvo))
  audit[, formas_origem := "desconhecida"]
  audit[, forma_destino := forma_destino]
  audit[, modo_movimento := ifelse(identical(origem, destino), "substituicao_intralista_replay", "movimento_entre_categorias_replay")]
  list(dt = dt[], audit = audit[], linhas = unique(linhas_alvo), afetacoes = unique(afetacoes), falha = FALSE)
}
