monitora_correcao_arquivo_ler_defensivo <- function(arquivo_correcao) {
  if (is.null(arquivo_correcao) || !file.exists(arquivo_correcao)) return(data.table::data.table())
  tryCatch(
    data.table::fread(arquivo_correcao, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character", showProgress = FALSE),
    error = function(e) data.table::data.table()
  )
}

monitora_correcao_norm_nome_campo <- function(x) {
  x <- tolower(trimws(as.character(x)))
  x <- iconv(x, to = "ASCII//TRANSLIT", sub = "")
  gsub("[^a-z0-9]+", "_", x)
}

monitora_correcao_operacoes_alteram_data_hora <- function(corr) {
  if (is.null(corr)) return(FALSE)
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(FALSE)
  cols_busca <- intersect(
    c("atributo_coluna_registros_corrig", "atributo", "coluna", "campo", "campo_alvo", "acao", "tipo_correcao"),
    names(corr)
  )
  if (!length(cols_busca)) return(FALSE)
  txt <- unique(unlist(lapply(cols_busca, function(cc) as.character(corr[[cc]])), use.names = FALSE))
  txt <- txt[!is.na(txt) & nzchar(trimws(txt))]
  if (!length(txt)) return(FALSE)
  n <- monitora_correcao_norm_nome_campo(txt)
  padroes_data <- c(
    "^data_data_hora$", "^data_hora_data$", "^data_hora$", "^data$",
    "^amostragem_registro_data$", "^data_do_registro$"
  )
  any(vapply(padroes_data, function(p) any(grepl(p, n, perl = TRUE)), logical(1L))) ||
    any(grepl("data_hora|data_data_hora|data_hora_data|amostragem_registro_data", n, perl = TRUE))
}

monitora_correcao_arquivo_altera_data_hora <- function(arquivo_correcao = NULL, corr = NULL) {
  if (is.null(corr)) corr <- monitora_correcao_arquivo_ler_defensivo(arquivo_correcao)
  monitora_correcao_operacoes_alteram_data_hora(corr)
}

monitora_correcao_operacoes_afetam_relatorios_suporte <- function(corr) {
  if (is.null(corr)) return(FALSE)
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(FALSE)
  cols_busca <- intersect(
    c("tipo_correcao", "acao", "atributo_coluna_registros_corrig", "atributo", "categoria_origem", "categoria_destino", "tipo_triagem", "token_removido", "forma_valida_escolhida", "lista_destino", "campo_dependente_preenchido"),
    names(corr)
  )
  if (!length(cols_busca)) return(FALSE)
  txt <- unique(unlist(lapply(cols_busca, function(cc) as.character(corr[[cc]])), use.names = FALSE))
  txt <- txt[!is.na(txt) & nzchar(trimws(txt))]
  if (!length(txt)) return(FALSE)
  n <- monitora_correcao_norm_nome_campo(txt)
 ### Relatórios diagnósticos dependem também do universo de registros e
 ### das chaves superiores. Excluir COLETAS não altera uma coluna botânica,
 ### mas invalida contagens, listas de ocorrência e duplicidade UC+UA+ANO.
 ### Tratar EXCCOL como irrelevante pode reaproveitar linhas pré-painel já
 ### removidas. Mantenha a otimização somente quando
 ### nenhuma semântica biológica, exclusão ou chave diagnóstica foi tocada.
  afeta_biologia <- any(grepl("exotica|nativa|desconhecida|outra|forma|vida|habito|especie|encostam|tipo_forma_vida|mv|mvlote|limpeza", n, perl = TRUE))
  altera_universo <- any(grepl("excluir_coleta|exclusao_coleta|exclusao_coletas|coleta_inteira|exccol", n, perl = TRUE))
  altera_chave_diagnostica <- any(n %in% c(
    "uc", "ea", "ua", "ano", "ciclo", "campanha", "coleta",
    "data", "data_hora", "data_data_hora", "ponto_amostral", "ponto_metro"
  ))
  isTRUE(afeta_biologia || altera_universo || altera_chave_diagnostica)
}

monitora_correcao_arquivo_afeta_relatorios_suporte <- function(arquivo_correcao = NULL, corr = NULL) {
  if (is.null(corr)) corr <- monitora_correcao_arquivo_ler_defensivo(arquivo_correcao)
  monitora_correcao_operacoes_afetam_relatorios_suporte(corr)
}

monitora_recalcular_derivados_data_hora_se_necessario <- function(dt, arquivo_correcao = NULL, corr = NULL, contexto = "pos_correcoes_assistidas", forcar = FALSE) {
  deve <- isTRUE(forcar) || !isTRUE(get0("MONITORA_OPCAO_PULAR_RECALCULO_DATA_HORA_SEM_ALTERACAO", ifnotfound = "S", inherits = TRUE) == "S") ||
    monitora_correcao_arquivo_altera_data_hora(arquivo_correcao, corr)
  if (isTRUE(deve)) {
    out <- monitora_recalcular_derivados_data_hora(dt, contexto = contexto)
    assign("MONITORA_RECALC_DATA_HORA_EXECUTADO_ULTIMO", TRUE, envir = .GlobalEnv)
    if (isTRUE(get0("MONITORA_OPCAO_CHECKPOINTS_GRANULARES_CORRECOES", ifnotfound = "S", inherits = TRUE) == "S") && exists("monitora_perf_registrar_checkpoint", mode = "function")) {
      monitora_perf_registrar_checkpoint("recalculo_data_hora_pos_correcoes", "DATA_MONITORA_PARSEADA e ANO recalculados porque Data (data_hora) foi alterada", out)
    }
    return(out)
  }
  assign("MONITORA_RECALC_DATA_HORA_EXECUTADO_ULTIMO", FALSE, envir = .GlobalEnv)
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento("datas", "INFO", if (is.null(arquivo_correcao)) NA_character_ else arquivo_correcao, paste0("Recálculo de DATA_MONITORA_PARSEADA/ANO pulado em ", contexto, ": nenhuma correção de Data (data_hora) detectada"), "derivados preservados")
  }
  if (isTRUE(get0("MONITORA_OPCAO_CHECKPOINTS_GRANULARES_CORRECOES", ifnotfound = "S", inherits = TRUE) == "S") && exists("monitora_perf_registrar_checkpoint", mode = "function")) {
    monitora_perf_registrar_checkpoint("recalculo_data_hora_pos_correcoes_pulado", "recálculo de data/hora pulado por ausência de alteração em Data (data_hora)", dt)
  }
  dt[]
}

monitora_correcao_finalizar_estado_plano <- function(dt,
                                                     corr,
                                                     linhas_semantica_alvo = integer(),
                                                     linhas_afetadas_vinculos = integer(),
                                                     afetacoes_vinculos = NULL,
                                                     chaves = monitora_correcao_colunas_chave(dt),
                                                     dicionario = NULL,
                                                     contexto = "pos_operacoes_painel",
                                                     gravar_placeholders = FALSE,
                                                     registrar_log = TRUE) {
 ### Motor único de finalização semântica. Preview e aplicação definitiva
 ### chamam esta mesma função, na mesma ordem: reforço de movimentos,
 ### sanitização de placeholders, fechamento hierárquico e sincronização
 ### final de Encostam/tipo_forma_vida. A única diferença permitida é de
 ### efeitos externos: o preview não grava relatórios nem eventos de log.
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::as.data.table(corr)
  linhas_semantica_alvo <- unique(as.integer(linhas_semantica_alvo))
  linhas_afetadas_vinculos <- unique(as.integer(linhas_afetadas_vinculos))
  linhas_semantica_alvo <- linhas_semantica_alvo[!is.na(linhas_semantica_alvo) & linhas_semantica_alvo >= 1L & linhas_semantica_alvo <= nrow(dt)]
  linhas_afetadas_vinculos <- linhas_afetadas_vinculos[!is.na(linhas_afetadas_vinculos) & linhas_afetadas_vinculos >= 1L & linhas_afetadas_vinculos <= nrow(dt)]
  afetacoes_vinculos <- data.table::as.data.table(if (is.null(afetacoes_vinculos)) {
    data.table::data.table(linha_indice = integer(), atributo = character())
  } else afetacoes_vinculos)
  audit <- data.table::data.table()

  reforco <- monitora_correcao_reforcar_movimentos_forma_vida(dt, corr, chaves, dicionario)
  if (nrow(reforco$audit)) audit <- data.table::rbindlist(list(audit, reforco$audit), fill = TRUE, use.names = TRUE)
  linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, reforco$linhas))
  linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, reforco$linhas))
  if (nrow(reforco$afetacoes)) afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, reforco$afetacoes), fill = TRUE, use.names = TRUE)

  linhas_placeholder <- unique(as.integer(c(linhas_afetadas_vinculos, linhas_semantica_alvo)))
  linhas_placeholder <- linhas_placeholder[!is.na(linhas_placeholder) & linhas_placeholder >= 1L & linhas_placeholder <= nrow(dt)]
  placeholders <- monitora_correcao_sanitizar_placeholders_semanticos(
    dt,
    linhas = linhas_placeholder,
    contexto = paste0(contexto, "_antes_fechamento_hierarquico"),
    gravar = isTRUE(gravar_placeholders)
  )
  dt <- data.table::as.data.table(placeholders$dt)
  audit_placeholders <- data.table::data.table()
  if (nrow(placeholders$audit)) {
    audit_placeholders <- data.table::data.table(
      id_correcao = "SANITIZACAO_PLACEHOLDER_SEMANTICO",
      ordem_operacao = NA_character_,
      status = "aplicada_automatica_auditada",
      mensagem = paste0("Placeholder serializado sanitizado antes do fechamento hierárquico: ", placeholders$audit$atributo),
      atributo = placeholders$audit$atributo,
      linha_indice = placeholders$audit$linha_indice,
      valor_antes = placeholders$audit$valor_antes,
      valor_depois = placeholders$audit$valor_depois,
      arquivo_correcao = "sanitizacao_placeholders_semanticos_r24"
    )
    audit <- data.table::rbindlist(list(audit, audit_placeholders), fill = TRUE, use.names = TRUE)
    linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, placeholders$linhas))
  }

  audit_vinculos <- data.table::data.table()
  if (length(linhas_afetadas_vinculos)) {
    deps_vinculos <- get0("MONITORA_DEPENDENCIAS_CORRECOES", ifnotfound = NULL, inherits = TRUE)
    audit_vinculos <- monitora_correcao_recalcular_superiores_vinculados_seguro(
      dt,
      linhas_afetadas_vinculos,
      deps_vinculos,
      dicionario,
      afetacoes_vinculos,
      registrar_log = isTRUE(registrar_log)
    )
    if (nrow(audit_vinculos)) {
      audit_vinculos[, fase_fechamento := "pos_operacoes_painel"]
      audit <- data.table::rbindlist(list(audit, audit_vinculos), fill = TRUE, use.names = TRUE)
    }
  }

  linhas_sync <- unique(as.integer(c(
    linhas_afetadas_vinculos,
    linhas_semantica_alvo,
    if (nrow(audit) && "linha_indice" %in% names(audit)) suppressWarnings(as.integer(audit$linha_indice)) else integer()
  )))
  linhas_sync <- linhas_sync[!is.na(linhas_sync) & linhas_sync >= 1L & linhas_sync <= nrow(dt)]
  sync <- monitora_correcao_sincronizar_encostam_final(
    dt,
    linhas = linhas_sync,
    chaves = chaves,
    contexto = contexto
  )
  dt <- sync$dt
  if (nrow(sync$audit)) {
    audit <- data.table::rbindlist(list(audit, sync$audit), fill = TRUE, use.names = TRUE)
    linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, sync$linhas))
    afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, sync$afetacoes), fill = TRUE, use.names = TRUE)
  }

  list(
    dt = dt[], audit = audit[],
    audit_reforco = reforco$audit[],
    audit_placeholders = audit_placeholders[],
    audit_placeholders_raw = placeholders$audit[],
    audit_vinculos = audit_vinculos[], sync = sync,
    linhas_semantica_alvo = unique(linhas_semantica_alvo),
    linhas_afetadas_vinculos = unique(linhas_afetadas_vinculos),
    afetacoes_vinculos = unique(afetacoes_vinculos)
  )
}


monitora_correcao_aplicar_plano_atomico_sessao <- function(dt,
                                                           corr,
                                                           chaves = monitora_correcao_colunas_chave(dt),
                                                           dicionario = NULL,
                                                           arquivo_correcao = "preview_painel_motor_unico",
                                                           aplicar_exclusoes = TRUE,
                                                           silencioso = TRUE,
                                                           registrar_perf = FALSE) {
 ### motor único de preview/modal/aplicação lógica.
 ### A ordem replica o backend real: MVLOTE/TRIDESC, sanitizações vinculadas,
 ### PENDFV/TRIOUT por ocorrência diagnóstica, exclusões de COLETA e só então
 ### operações genéricas restantes.
 ### Assim a janela modal não pode divergir do que será aplicado ao salvar.
 ### Preview e preflight trabalham sobre candidato privado. Se qualquer grupo
 ### falhar, nenhuma mutação por referência alcança o objeto fornecido.
  dt <- data.table::copy(data.table::as.data.table(dt))
  corr <- data.table::copy(data.table::as.data.table(corr))
  audit <- data.table::data.table()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  linhas_semantica_alvo <- integer(0)
  linhas_afetadas_vinculos <- integer(0)
  linhas_remocao_desconhecida_generica <- integer(0)
  falha <- FALSE
  if (!nrow(corr)) return(list(dt = dt[], corr = corr[], audit = audit, linhas = integer(), afetacoes = afetacoes, falha = FALSE))
  template <- tryCatch(monitora_correcao_template(), error = function(e) data.table::data.table())
  for (cc in setdiff(names(template), names(corr))) data.table::set(corr, j = cc, value = template[[cc]][1L])
  corr <- monitora_correcao_agrupar_operacoes_semanticas(corr)
  rec_sem <- monitora_correcao_reconciliar_plano_semantico(
    dt, corr,
    contexto = paste0("motor_atomico_", arquivo_correcao),
    gravar = FALSE,
    abortar = FALSE
  )
  if (rec_sem$n_conflitos > 0L) {
    aud_conf <- data.table::copy(rec_sem$conflitos)
    aud_conf[, `:=`(
      id_correcao = ids_operacoes,
      ordem_operacao = NA_character_,
      atributo = dominio_semantico,
      valor_antes = efeitos,
      valor_depois = NA_character_,
      arquivo_correcao = arquivo_correcao
    )]
    return(list(
      dt = dt[], corr = corr[], audit = aud_conf[], linhas = integer(),
      afetacoes = afetacoes, falha = TRUE,
      conflitos_semanticos = rec_sem$conflitos[]
    ))
  }
  corr <- data.table::copy(rec_sem$corr)
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  sig_corr <- tryCatch(monitora_correcao_assinatura_operacoes(corr), error = function(e) rep(NA_character_, nrow(corr)))
  if (length(sig_corr) == nrow(corr)) corr <- corr[!duplicated(sig_corr)]
  corr[, ordem_tmp := seq_len(.N)]
  corr_plano_finalizacao <- data.table::copy(corr)
  indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)

  add_res <- function(res) {
    if (is.list(res) && "dt" %in% names(res)) dt <<- res$dt
    if (is.list(res) && !is.null(res$audit) && data.table::is.data.table(res$audit) && nrow(res$audit)) audit <<- data.table::rbindlist(list(audit, res$audit), fill = TRUE, use.names = TRUE)
    if (is.list(res) && !is.null(res$afetacoes) && data.table::is.data.table(res$afetacoes) && nrow(res$afetacoes)) afetacoes <<- data.table::rbindlist(list(afetacoes, res$afetacoes), fill = TRUE, use.names = TRUE)
    if (is.list(res) && length(res$linhas)) {
      linhas_semantica_alvo <<- unique(c(linhas_semantica_alvo, as.integer(res$linhas)))
      linhas_afetadas_vinculos <<- unique(c(linhas_afetadas_vinculos, as.integer(res$linhas)))
    }
    if (is.list(res) && isTRUE(res$falha)) falha <<- TRUE
    invisible(TRUE)
  }

  if (nrow(corr)) {
    res_mvlote <- monitora_correcao_aplicar_movimentos_forma_vida_lote_atomicos(dt, corr, chaves = chaves, indice = indice_linhas, arquivo_correcao = arquivo_correcao, dicionario = dicionario)
    add_res(res_mvlote)
    if (is.list(res_mvlote) && "corr" %in% names(res_mvlote)) corr <- data.table::copy(data.table::as.data.table(res_mvlote$corr))
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  }

  if (nrow(corr)) {
    res_mov <- monitora_correcao_aplicar_movimentos_forma_vida_atomicos(dt, corr, chaves = chaves, indice = indice_linhas, arquivo_correcao = arquivo_correcao, dicionario = dicionario)
    add_res(res_mov)
    if (is.list(res_mov) && "corr" %in% names(res_mov)) corr <- data.table::copy(data.table::as.data.table(res_mov$corr))
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  }

  if (nrow(corr)) {
    res_desc <- monitora_correcao_aplicar_triagens_desconhecida_atomicas(dt, corr, chaves = chaves, indice = indice_linhas, arquivo_correcao = arquivo_correcao, dicionario = dicionario)
    add_res(res_desc)
    if (is.list(res_desc) && "corr" %in% names(res_desc)) corr <- data.table::copy(data.table::as.data.table(res_desc$corr))
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  }

  linhas_desc_alvo <- unique(c(linhas_semantica_alvo, linhas_afetadas_vinculos))
  linhas_desc_alvo <- linhas_desc_alvo[!is.na(linhas_desc_alvo) & linhas_desc_alvo >= 1L & linhas_desc_alvo <= nrow(dt)]
  if (length(linhas_desc_alvo)) {
    res_desc_cons <- tryCatch(monitora_correcao_sanitizar_dependentes_desconhecida(dt, linhas = linhas_desc_alvo, categorias = c("nativa", "exotica", "seca_morta"), id_correcao = "__PREVIEW_SANITIZACAO_DESCONHECIDA_POS_OPERACOES__", ordem_operacao = NA_character_, arquivo_correcao = arquivo_correcao, dicionario = dicionario, registrar_preservadas = FALSE), error = function(e) NULL)
    if (is.list(res_desc_cons)) add_res(res_desc_cons)
  }



 ### TRIOUT precisa anteceder PENDFV: a limpeza/conversão de outras formas
 ### pode preencher/normalizar listas inferiores e, portanto, resolver parte
 ### das pendências "sem forma". Se PENDFV roda antes, cria conflito e auditoria
 ### intermediária falsa.
  if (nrow(corr)) {
    res_triout_pre <- monitora_correcao_aplicar_limpezas_outras_formas_estado_corrente(dt, corr, chaves = chaves, indice = indice_linhas, arquivo_correcao = arquivo_correcao, dicionario = dicionario, silencioso = silencioso, registrar_perf = registrar_perf)
    add_res(res_triout_pre)
    if (is.list(res_triout_pre) && "corr" %in% names(res_triout_pre)) corr <- data.table::copy(data.table::as.data.table(res_triout_pre$corr))
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  }

  if (nrow(corr)) {
    res_pend <- monitora_correcao_aplicar_pendencias_sem_forma_atomicas(dt, corr, chaves = chaves, arquivo_correcao = arquivo_correcao, dicionario = dicionario, silencioso = silencioso, registrar_perf = registrar_perf)
    add_res(res_pend)
    if (is.list(res_pend) && "corr" %in% names(res_pend)) corr <- data.table::copy(data.table::as.data.table(res_pend$corr))
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  }

  if (nrow(corr)) {
    res_triout <- monitora_correcao_aplicar_limpezas_outras_formas_estado_corrente(dt, corr, chaves = chaves, indice = indice_linhas, arquivo_correcao = arquivo_correcao, dicionario = dicionario, silencioso = silencioso, registrar_perf = registrar_perf)
    add_res(res_triout)
    if (is.list(res_triout) && "corr" %in% names(res_triout)) corr <- data.table::copy(data.table::as.data.table(res_triout$corr))
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  }

  if (isTRUE(aplicar_exclusoes) && nrow(corr)) {
    ids_semantica_pre_exc <- if (MONITORA_COL_ROW_ID %in% names(dt)) as.character(dt[[MONITORA_COL_ROW_ID]][linhas_semantica_alvo]) else character(0)
    ids_vinculos_pre_exc <- if (MONITORA_COL_ROW_ID %in% names(dt)) as.character(dt[[MONITORA_COL_ROW_ID]][linhas_afetadas_vinculos]) else character(0)
    res_exc <- monitora_correcao_aplicar_exclusoes_coleta_atomicas(dt, corr, chaves = chaves, indice = indice_linhas, arquivo_correcao = arquivo_correcao)
    add_res(res_exc)
    if (is.list(res_exc) && "corr" %in% names(res_exc)) corr <- data.table::copy(data.table::as.data.table(res_exc$corr))
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    if (MONITORA_COL_ROW_ID %in% names(dt)) {
      linhas_semantica_alvo <- unique(match(ids_semantica_pre_exc, as.character(dt[[MONITORA_COL_ROW_ID]]), nomatch = 0L))
      linhas_afetadas_vinculos <- unique(match(ids_vinculos_pre_exc, as.character(dt[[MONITORA_COL_ROW_ID]]), nomatch = 0L))
      linhas_semantica_alvo <- linhas_semantica_alvo[linhas_semantica_alvo > 0L]
      linhas_afetadas_vinculos <- linhas_afetadas_vinculos[linhas_afetadas_vinculos > 0L]
    } else {
      linhas_semantica_alvo <- linhas_semantica_alvo[linhas_semantica_alvo <= nrow(dt)]
      linhas_afetadas_vinculos <- linhas_afetadas_vinculos[linhas_afetadas_vinculos <= nrow(dt)]
    }
    indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  }

 ### SANEORF pode gerar centenas de itens auditáveis com a mesma ação
 ### derivada. Recalcular a matriz inteira uma vez por item tornava o preview
 ### quase quadrático. Localiza todos os alvos, recalcula uma única vez e
 ### mantém as mesmas linhas/afetações sem alterar a semântica da fila.
  if (nrow(corr)) {
    acoes_r21 <- tolower(trimws(as.character(corr$acao)))
    idx_recalc_r21 <- which(acoes_r21 %in% c("recalcular_tipo_forma_vida", "atualizar_tipo_forma_vida"))
    if (length(idx_recalc_r21)) {
      linhas_recalc_r21 <- unique(as.integer(unlist(lapply(idx_recalc_r21, function(ii) {
        li_r21 <- tryCatch(monitora_correcao_linhas_alvo_operacao(dt, corr[ii], chaves = chaves, indice = indice_linhas), error = function(e) integer(0))
        monitora_correcao_aplicar_escopo_conciliado(dt, li_r21, corr[ii])
      }), use.names = FALSE)))
      linhas_recalc_r21 <- linhas_recalc_r21[!is.na(linhas_recalc_r21) & linhas_recalc_r21 >= 1L & linhas_recalc_r21 <= nrow(dt)]
      if (length(linhas_recalc_r21)) {
        monitora_correcao_recalcular_tipo_forma_vida(dt, linhas_recalc_r21)
        linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, linhas_recalc_r21))
        afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(
          linha_indice = linhas_recalc_r21, atributo = chaves$tipo_forma_vida
        )), fill = TRUE, use.names = TRUE)
      }
      corr <- corr[-idx_recalc_r21]
      if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    }
  }

  if (nrow(corr)) {
    for (ii in seq_len(nrow(corr))) {
      ac <- tolower(trimws(as.character(corr$acao[ii])))
      tipo <- if ("tipo_correcao" %in% names(corr)) as.character(corr$tipo_correcao[ii]) else ""
      if (ac %in% c("excluir_coleta", "exclusao_coleta")) next
      if (grepl("limpar_outras_formas_vida", tipo) || ac %in% c("limpar_outras_formas_vida", "limpar_outras_formas")) next
      if (grepl("pendencia_sem_forma_vida|movimento_forma_vida|triagem_substituir_desconhecida", tipo)) next
      linha_corr <- corr[ii]
      attr_solicitado <- as.character(linha_corr$atributo_coluna_registros_corrig[1L])
      attr <- tryCatch(
        monitora_correcao_resolver_coluna_operacao(dt, linha_corr, dicionario),
        error = function(e) NA_character_
      )
 ### a prévia usa obrigatoriamente o mesmo resolvedor
 ### canônico->físico da aplicação definitiva. Antes, um atributo canônico
 ### (por exemplo, forma_vida_nativa_bromelioide) era ignorado aqui quando
 ### o CSV expunha somente o label físico do XLSForm; a aplicação real o
 ### encontrava e o resultado da prévia ficava uma ocorrência atrás.
 ### Falha de resolução nunca pode produzir uma prévia aparentemente válida.
      if (is.na(attr) || !nzchar(attr) || !(attr %in% names(dt))) {
        falha <- TRUE
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = as.character(linha_corr$id_correcao[1L]),
          ordem_operacao = as.character(linha_corr$ordem_operacao[1L]),
          status = "falha_preview_coluna_nao_resolvida",
          mensagem = paste0("Prévia bloqueada: atributo não resolvido pelo localizador canônico: ", attr_solicitado),
          atributo = attr_solicitado,
          linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_,
          arquivo_correcao = arquivo_correcao
        )), fill = TRUE, use.names = TRUE)
        next
      }
      lin <- tryCatch(monitora_correcao_linhas_alvo_operacao(dt, corr[ii], chaves = chaves, indice = indice_linhas), error = function(e) integer(0))
      lin <- monitora_correcao_aplicar_escopo_conciliado(dt, lin, corr[ii])
      lin <- unique(as.integer(lin[!is.na(lin) & lin >= 1L & lin <= nrow(dt)]))
      if (!length(lin)) {
        falha <- TRUE
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = as.character(linha_corr$id_correcao[1L]),
          ordem_operacao = as.character(linha_corr$ordem_operacao[1L]),
          status = "falha_preview_alvo_nao_localizado",
          mensagem = "Prévia bloqueada: nenhuma linha-alvo localizada pelo mesmo escopo da aplicação definitiva",
          atributo = attr,
          linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_,
          arquivo_correcao = arquivo_correcao
        )), fill = TRUE, use.names = TRUE)
        next
      }
 ### `recalcular_tipo_forma_vida` depende do estado matricial das listas
 ### inferiores e dos materiais botânicos. O backend real trata esta ação
 ### antes do aplicador escalar; o preview deve fazer o mesmo. Aplicá-la
 ### como valor escalar com `valor_novo = NA` cria Encostam vazio apenas
 ### na simulação e falsos `ponto_sem_interceptacao`. A chamada abaixo é a
 ### mesma usada pelo backend, sobre a
 ### cópia `dt` do preview, sem qualquer efeito no objeto vivo do painel.
      if (ac %in% c("recalcular_tipo_forma_vida", "atualizar_tipo_forma_vida")) {
        monitora_correcao_recalcular_tipo_forma_vida(dt, lin)
        linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, lin))
        afetacoes <- data.table::rbindlist(list(
          afetacoes,
          data.table::data.table(linha_indice = lin, atributo = chaves$tipo_forma_vida)
        ), fill = TRUE, use.names = TRUE)
        next
      }
      valid_dest <- monitora_correcao_validar_destino_operacao(dt, attr, ac, linha_corr$valor_novo[1L], linha_corr, dicionario)
      antes <- as.character(dt[[attr]][lin])
      esperado <- linha_corr$valor_original_esperado[1L]
      precond <- monitora_publicacao_d_precondicao_valor_original(antes, ac, linha_corr$valor_novo[1L], esperado)
      if (!isTRUE(valid_dest$ok) || !isTRUE(precond$ok)) {
        falha <- TRUE
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = as.character(linha_corr$id_correcao[1L]),
          ordem_operacao = as.character(linha_corr$ordem_operacao[1L]),
          status = if (!isTRUE(valid_dest$ok)) as.character(valid_dest$status) else "falha_preview_precondicao",
          mensagem = if (!isTRUE(valid_dest$ok)) as.character(valid_dest$mensagem) else as.character(precond$mensagem),
          atributo = attr,
          linha_indice = lin, valor_antes = antes, valor_depois = NA_character_,
          arquivo_correcao = arquivo_correcao
        )), fill = TRUE, use.names = TRUE)
        next
      }
      novo <- tryCatch(
        monitora_correcao_aplicar_operacao(antes, ac, linha_corr$valor_novo[1L], esperado),
        error = function(e) stop("Prévia bloqueada ao aplicar operação no atributo ", attr, ": ", conditionMessage(e), call. = FALSE)
      )
      mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(novo)
      data.table::set(dt, i = lin, j = attr, value = novo)
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, lin))
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = lin, atributo = attr)), fill = TRUE, use.names = TRUE)
      if (any(mudou, na.rm = TRUE) && isTRUE(monitora_correcao_eh_remocao_desconhecida_lista(
        dt, ac, linha_corr$valor_novo[1L], esperado, attr, dicionario
      ))) {
        linhas_remocao_desconhecida_generica <- unique(c(linhas_remocao_desconhecida_generica, lin[mudou]))
      }
    }
  }

 ### A remoção manual do token desconhecida é uma resolução válida quando já
 ### existem formas válidas na lista. Como `remove_token` é operação genérica,
 ### esta repercussão deve ocorrer depois do loop genérico; antes dele o token
 ### ainda existe e fotos/descritores permanecem preservados.
  if (length(linhas_remocao_desconhecida_generica)) {
    res_desc_remove <- tryCatch(
      monitora_correcao_sanitizar_dependentes_desconhecida(
        dt,
        linhas = linhas_remocao_desconhecida_generica,
        categorias = c("nativa", "exotica", "seca_morta"),
        id_correcao = "__PREVIEW_SANITIZACAO_DESCONHECIDA_APOS_REMOVE_TOKEN__",
        ordem_operacao = NA_character_,
        arquivo_correcao = arquivo_correcao,
        dicionario = dicionario,
        registrar_preservadas = FALSE
      ),
      error = function(e) NULL
    )
    if (is.list(res_desc_remove)) add_res(res_desc_remove)
  }
  finalizacao <- monitora_correcao_finalizar_estado_plano(
    dt,
    corr_plano_finalizacao,
    linhas_semantica_alvo = linhas_semantica_alvo,
    linhas_afetadas_vinculos = linhas_afetadas_vinculos,
    afetacoes_vinculos = afetacoes,
    chaves = chaves,
    dicionario = dicionario,
    contexto = paste0("motor_atomico_", arquivo_correcao),
    gravar_placeholders = FALSE,
    registrar_log = FALSE
  )
  dt <- finalizacao$dt
  if (nrow(finalizacao$audit)) audit <- data.table::rbindlist(list(audit, finalizacao$audit), fill = TRUE, use.names = TRUE)
  linhas_semantica_alvo <- unique(finalizacao$linhas_semantica_alvo)
  linhas_afetadas_vinculos <- unique(finalizacao$linhas_afetadas_vinculos)
  afetacoes <- data.table::rbindlist(list(afetacoes, finalizacao$afetacoes_vinculos), fill = TRUE, use.names = TRUE)
  list(dt = dt[], corr = corr[], audit = audit[], linhas = unique(linhas_semantica_alvo), afetacoes = unique(afetacoes), falha = falha)
}

monitora_correcao_aplicar_arquivo <- function(dt, arquivo_correcao = MONITORA_ARQUIVO_CORRECOES_CAMPOS, dicionario = NULL) {
  if (!file.exists(arquivo_correcao)) {
    monitora_log_registrar_evento("correcoes_campos", "INFO", arquivo_correcao, "Arquivo de correções não encontrado; nenhuma correção aplicada", "opcional")
    return(dt)
  }
 ### Transação de sessão: todos os aplicadores recebem uma cópia privada.
 ### Qualquer `stop ` posterior abandona esta cópia e preserva integralmente
 ### o objeto fornecido pelo chamador.
  dt <- data.table::copy(data.table::as.data.table(dt))
  dt <- monitora_identidade_assegurar(dt, contexto = "pre_aplicacao_arquivo_correcoes")
  meta_schema_publicacao_b <- list(campos = if (!is.null(dicionario)) data.table::as.data.table(dicionario) else data.table::data.table(), dependencias = get0("MONITORA_DEPENDENCIAS_CORRECOES", ifnotfound = data.table::data.table(), inherits = TRUE))
  dt <- monitora_correcao_preparar_schema_edicao_painel(dt, meta_schema_publicacao_b, contexto = "pre_aplicacao_arquivo_correcoes")
  corr <- tryCatch(data.table::fread(arquivo_correcao, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character"), error = function(e) data.table::data.table())
  if (nrow(corr) == 0) {
    monitora_log_registrar_evento("correcoes_campos", "AVISO", arquivo_correcao, "Arquivo de correções vazio ou ilegível", "nenhuma correção aplicada")
    return(dt)
  }
  template <- monitora_correcao_template()
  for (cc in setdiff(names(template), names(corr))) corr[, (cc) := NA_character_]
  data.table::setDT(corr)
  corr[, ordem_tmp := seq_len(.N)]
 ### Agrupar antes da deduplicação preserva a cardinalidade solicitada de
 ### operações auditáveis repetidas (por exemplo, SANHAB) no grupo atômico.
  corr <- monitora_correcao_agrupar_operacoes_semanticas(corr)
  sig_corr_original <- monitora_correcao_assinatura_operacoes(corr)
  manter_corr <- !duplicated(sig_corr_original)
  n_corr_dup <- sum(!manter_corr)
  if (n_corr_dup > 0L) {
    corr <- corr[manter_corr]
    monitora_log_registrar_evento(
      "correcoes_campos", "AVISO", arquivo_correcao,
      paste0(n_corr_dup, " operação(ões) duplicada(s) removida(s) antes da aplicação"),
      "deduplicação defensiva por assinatura semântica"
    )
  }
  rec_sem <- monitora_correcao_reconciliar_plano_semantico(
    dt, corr,
    contexto = "pre_aplicacao_arquivo_correcoes",
    gravar = TRUE,
    abortar = TRUE
  )
  corr <- data.table::copy(rec_sem$corr)
  corr_plano_finalizacao <- data.table::copy(corr)
  assign("MONITORA_PLANO_CORRECOES_EFETIVO_ULTIMO", data.table::copy(corr), envir = .GlobalEnv)
  if (!nrow(corr)) {
    monitora_log_registrar_evento(
      "conciliacao_semantica_operacoes", "INFO", arquivo_correcao,
      paste0("Todas as operações amplas/lote foram subsumidas por decisões específicas; alvos excluídos=", rec_sem$n_excluidos),
      "nenhuma mutação restante; intenções originais preservadas na trilha e auditoria"
    )
    return(dt[])
  }
  contagens_plano_operacoes <- corr[, .(
    n_operacoes_atomicas = .N,
    n_itens_solicitados = sum(suppressWarnings(as.integer(n_itens_solicitados)), na.rm = TRUE),
    n_itens_efetivos = sum(suppressWarnings(as.integer(n_itens_efetivos)), na.rm = TRUE),
    n_linhas_solicitadas = sum(suppressWarnings(as.integer(n_linhas_solicitadas)), na.rm = TRUE),
    n_linhas_efetivas = sum(suppressWarnings(as.integer(n_linhas_efetivas)), na.rm = TRUE),
    n_linhas_excluidas = sum(suppressWarnings(as.integer(n_linhas_excluidas)), na.rm = TRUE)
  ), by = id_correcao]
  perf_operacoes_r24e2 <- function(etapa, detalhe) {
    if (isTRUE(get0("MONITORA_OPCAO_CHECKPOINTS_GRANULARES_CORRECOES", ifnotfound = "S", inherits = TRUE) == "S") && exists("monitora_perf_registrar_checkpoint", mode = "function")) {
      try(monitora_perf_registrar_checkpoint(etapa, detalhe, dt), silent = TRUE)
    }
    invisible(NULL)
  }
  perf_operacoes_r24e2(
    "painel_correcoes_plano_compilado_r24e2",
    paste0(nrow(corr), " operação(ões) atômica(s) após agrupamento; ", sum(contagens_plano_operacoes$n_itens_solicitados), " item(ns) solicitado(s); ", sum(contagens_plano_operacoes$n_linhas_efetivas), " alvo(s) efetivo(s)")
  )
  corr[, ordem_tmp := seq_len(.N)]
  n_sem_plano <- tryCatch(monitora_correcao_contar_operacoes_semanticas(corr), error = function(e) nrow(corr))
  if (exists("monitora_correcao_console_msg", mode = "function")) {
    monitora_correcao_console_msg("Plano de aplicação das correções: ", n_sem_plano, " operação(ões) semântica(s), ", nrow(corr), " item(ns) auditável(is). Aplicação será agrupada por operações atômicas quando possível.")
  }
  snapshot_colunas_protegidas_antes <- monitora_correcao_snapshot_colunas_protegidas(dt)
  chaves <- monitora_correcao_colunas_chave(dt)
  indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
  auditoria_semantica_pre <- data.table::data.table()
  linhas_semantica_alvo <- integer(0)
  auditoria_semantica_completa <- isTRUE(if (exists("MONITORA_AUDITORIA_SEMANTICA_CORRECOES_COMPLETA", inherits = TRUE)) get("MONITORA_AUDITORIA_SEMANTICA_CORRECOES_COMPLETA", inherits = TRUE) else FALSE)
  audit <- data.table::data.table()
  linhas_afetadas_vinculos <- integer(0)
  afetacoes_vinculos <- data.table::data.table(linha_indice = integer(), atributo = character())
  coletas_excluidas_aplicadas <- character(0)
  coletas_exclusao_dominante_sessao <- monitora_publicacao_q_coletas_exclusao_dominante(corr)
  if (length(coletas_exclusao_dominante_sessao) > 0L) {
    monitora_log_registrar_evento(
      "correcoes_campos",
      "INFO",
      arquivo_correcao,
      paste0("v2.5.4: exclusões dominantes detectadas na sessão: ", length(coletas_exclusao_dominante_sessao), " COLETA(s)"),
      "operações modificadoras totalmente cobertas por essas exclusões serão auditadas como subsumidas, não como falha"
    )
  }

 ### limpeza de outras formas (TRIOUT) é normalização de base.
 ### Deve rodar antes de PENDFV e antes das exclusões, sempre recalculando
 ### resíduos no estado corrente por filtro estável de COLETA/contexto.
  falha_limpeza_outras_formas <- FALSE

 ### Movimentos em lote de forma de vida: aplicar como transações atômicas
 ### antes da pré-validação célula-a-célula. O lote é uma operação semântica
 ### única para várias COLETAS e uma ou mais formas de vida.
  falha_movimento_forma_vida_lote <- FALSE
  if (nrow(corr) > 0L) {
    res_mvlote_atom <- monitora_correcao_aplicar_movimentos_forma_vida_lote_atomicos(
      dt,
      corr,
      chaves = chaves,
      indice = indice_linhas,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario
    )
    dt <- res_mvlote_atom$dt
    if (nrow(res_mvlote_atom$audit) > 0L) audit <- data.table::rbindlist(list(audit, res_mvlote_atom$audit), fill = TRUE, use.names = TRUE)
    if (length(res_mvlote_atom$linhas) > 0L) {
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_mvlote_atom$linhas))
      linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_mvlote_atom$linhas))
    }
    if (nrow(res_mvlote_atom$afetacoes) > 0L) afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_mvlote_atom$afetacoes), fill = TRUE, use.names = TRUE)
    falha_movimento_forma_vida_lote <- isTRUE(res_mvlote_atom$falha)
    if (isTRUE(res_mvlote_atom$n_grupos > 0L)) {
      corr <- res_mvlote_atom$corr
      corr[, ordem_tmp := seq_len(.N)]
      indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
      monitora_log_registrar_evento(
        "correcoes_campos",
        ifelse(isTRUE(falha_movimento_forma_vida_lote), "ERRO", "INFO"),
        arquivo_correcao,
        paste0(res_mvlote_atom$n_grupos, " grupo(s) de movimento em lote de forma de vida processado(s) atomicamente"),
        "movimento semântico multicoletas aplicado sem expansão célula-a-célula"
      )
    }
  }

  if (isTRUE(falha_movimento_forma_vida_lote)) {
    if (nrow(audit) > 0) {
      audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
      saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
      monitora_fwrite(audit, saida_audit, na = "")
      monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
    }
    stop("Movimento atômico em lote de forma de vida falhou; ver auditoria_correcoes_campos_ultima_execucao.csv", call. = FALSE)
  }

 ### Movimentos de forma de vida: aplicar como transações atômicas antes da
 ### pré-validação célula-a-célula. Isso cobre tanto as novas operações
 ### movimento_forma_vida_atomico quanto grupos legados MOVFV expandidos em
 ### remove_token/append_token/clear/recalcular_tipo_forma_vida.
  falha_movimento_forma_vida <- FALSE
  if (nrow(corr) > 0L) {
    res_mov_atom <- monitora_correcao_aplicar_movimentos_forma_vida_atomicos(
      dt,
      corr,
      chaves = chaves,
      indice = indice_linhas,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario
    )
    dt <- res_mov_atom$dt
    if (nrow(res_mov_atom$audit) > 0L) audit <- data.table::rbindlist(list(audit, res_mov_atom$audit), fill = TRUE, use.names = TRUE)
    if (length(res_mov_atom$linhas) > 0L) {
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_mov_atom$linhas))
      linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_mov_atom$linhas))
    }
    if (nrow(res_mov_atom$afetacoes) > 0L) afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_mov_atom$afetacoes), fill = TRUE, use.names = TRUE)
    falha_movimento_forma_vida <- isTRUE(res_mov_atom$falha)
    if (isTRUE(res_mov_atom$n_grupos > 0L)) {
      corr <- res_mov_atom$corr
      corr[, ordem_tmp := seq_len(.N)]
      indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
      monitora_log_registrar_evento(
        "correcoes_campos",
        ifelse(isTRUE(falha_movimento_forma_vida), "ERRO", "INFO"),
        arquivo_correcao,
        paste0(res_mov_atom$n_grupos, " grupo(s) de movimento de forma de vida processado(s) atomicamente"),
        "movimento semântico aplicado sem expansão célula-a-célula"
      )
    }
  }

  if (isTRUE(falha_movimento_forma_vida)) {
    if (nrow(audit) > 0) {
      audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
      saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
      monitora_fwrite(audit, saida_audit, na = "")
      monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
    }
    stop("Movimento atômico de forma de vida falhou; ver auditoria_correcoes_campos_ultima_execucao.csv", call. = FALSE)
  }

 ### Substituição de forma de vida desconhecida: processar como transação
 ### atômica antes da validação célula-a-célula. Isso impede aplicação parcial
 ### do grupo TRIDESC quando a remoção do token antigo fica sem efeito, mas a
 ### adição da forma válida e o recálculo seriam executados separadamente.
  falha_triagem_desconhecida <- FALSE
  if (nrow(corr) > 0L) {
    res_tridesc_atom <- monitora_correcao_aplicar_triagens_desconhecida_atomicas(
      dt,
      corr,
      chaves = chaves,
      indice = indice_linhas,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario
    )
    dt <- res_tridesc_atom$dt
    if (nrow(res_tridesc_atom$audit) > 0L) audit <- data.table::rbindlist(list(audit, res_tridesc_atom$audit), fill = TRUE, use.names = TRUE)
    if (length(res_tridesc_atom$linhas) > 0L) {
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_tridesc_atom$linhas))
      linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_tridesc_atom$linhas))
    }
    if (nrow(res_tridesc_atom$afetacoes) > 0L) afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_tridesc_atom$afetacoes), fill = TRUE, use.names = TRUE)
    falha_triagem_desconhecida <- isTRUE(res_tridesc_atom$falha)
    if (isTRUE(res_tridesc_atom$n_grupos > 0L)) {
      corr <- res_tridesc_atom$corr
      corr[, ordem_tmp := seq_len(.N)]
      indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
      monitora_log_registrar_evento(
        "correcoes_campos",
        ifelse(isTRUE(falha_triagem_desconhecida), "ERRO", "INFO"),
        arquivo_correcao,
        paste0(res_tridesc_atom$n_grupos, " grupo(s) de triagem de desconhecida processado(s) atomicamente"),
        "substituição semântica aplicada sem expansão célula-a-célula"
      )
    }
  }

  if (isTRUE(falha_triagem_desconhecida)) {
    if (nrow(audit) > 0) {
      audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
      saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
      monitora_fwrite(audit, saida_audit, na = "")
      monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
    }
    stop("Substituição atômica de desconhecida falhou; ver auditoria_correcoes_campos_ultima_execucao.csv", call. = FALSE)
  }

 ### Consistência pós-sanitização/triagem: dependentes históricos de forma de
 ### vida desconhecida só podem permanecer preenchidos quando a sublista da
 ### categoria correspondente ainda contém o token desconhecida.
  linhas_desc_alvo <- unique(c(linhas_semantica_alvo, linhas_afetadas_vinculos))
  linhas_desc_alvo <- linhas_desc_alvo[!is.na(linhas_desc_alvo) & linhas_desc_alvo >= 1L & linhas_desc_alvo <= nrow(dt)]
  if (length(linhas_desc_alvo)) {
    res_desc_cons <- monitora_correcao_sanitizar_dependentes_desconhecida(
      dt,
      linhas = linhas_desc_alvo,
      categorias = c("nativa", "exotica", "seca_morta"),
      id_correcao = "__SANITIZACAO_DESCONHECIDA_POS_CORRECOES__",
      ordem_operacao = NA_character_,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario,
      registrar_preservadas = TRUE
    )
    dt <- res_desc_cons$dt
    if (nrow(res_desc_cons$audit)) {
      monitora_correcao_gravar_auditoria_sanitizacao_desconhecida(res_desc_cons$audit)
      audit <- data.table::rbindlist(list(audit, res_desc_cons$audit), fill = TRUE, use.names = TRUE)
    }
    if (nrow(res_desc_cons$afetacoes)) {
      afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_desc_cons$afetacoes), fill = TRUE, use.names = TRUE)
      linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_desc_cons$afetacoes$linha_indice))
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_desc_cons$afetacoes$linha_indice))
    }
  }

 ### Antes de remover linhas, fixa o contexto estável das alterações já
 ### auditadas. Assim a auditoria não passa a apontar para linhas deslocadas
 ### após exclusões de COLETA.
  if (nrow(audit) > 0L) audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)



 ### TRIOUT antes de PENDFV: a sanitização/conversão de outras formas é
 ### normalização de base e deve ocorrer antes de preencher pendências sem forma.
 ### Mantém aplicação atômica e vetorizada; o backend posterior de TRIOUT ficará
 ### sem operações restantes quando esta etapa consumir o grupo.
  if (nrow(corr) > 0L) {
    res_triout_pre_pendfv <- monitora_correcao_aplicar_limpezas_outras_formas_estado_corrente(
      dt,
      corr,
      chaves = chaves,
      indice = indice_linhas,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario
    )
    dt <- res_triout_pre_pendfv$dt
    if (nrow(res_triout_pre_pendfv$audit) > 0L) audit <- data.table::rbindlist(list(audit, res_triout_pre_pendfv$audit), fill = TRUE, use.names = TRUE)
    if (length(res_triout_pre_pendfv$linhas) > 0L) {
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_triout_pre_pendfv$linhas))
      linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_triout_pre_pendfv$linhas))
    }
    if (nrow(res_triout_pre_pendfv$afetacoes) > 0L) afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_triout_pre_pendfv$afetacoes), fill = TRUE, use.names = TRUE)
    falha_limpeza_outras_formas <- isTRUE(res_triout_pre_pendfv$falha)
    if (isTRUE(res_triout_pre_pendfv$n_grupos > 0L)) {
      corr <- res_triout_pre_pendfv$corr
      if (nrow(corr) > 0L) corr[, ordem_tmp := seq_len(.N)]
      indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
      monitora_log_registrar_evento(
        "correcoes_campos",
        ifelse(isTRUE(falha_limpeza_outras_formas), "ERRO", "INFO"),
        arquivo_correcao,
        paste0(res_triout_pre_pendfv$n_grupos, " operação(ões) semântica(s) TRIOUT processada(s) antes de PENDFV; ", length(res_triout_pre_pendfv$linhas), " linha(s) alterada(s)"),
        "TRIOUT vetorizado por filtro estável de COLETA; evita conflito com pendências sem forma"
      )
    }
  }

  if (isTRUE(falha_limpeza_outras_formas)) {
    if (nrow(audit) > 0) {
      audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
      saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
      monitora_fwrite(audit, saida_audit, na = "")
      monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
    }
    stop("Limpeza atômica de outras formas de vida falhou antes de PENDFV; ver auditoria_correcoes_campos_ultima_execucao.csv", call. = FALSE)
  }

 ### Correções contextuais de pendências sem forma de vida (PENDFV).
 ### Aplicação vetorizada por id_correcao: cada decisão do painel é uma operação
 ### semântica; os itens auditáveis são usados apenas para rastreabilidade.
  falha_pendencia_sem_forma <- FALSE
  if (nrow(corr) > 0L) {
    res_pendfv_atom <- monitora_correcao_aplicar_pendencias_sem_forma_atomicas(
      dt,
      corr,
      chaves = chaves,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario
    )
    dt <- res_pendfv_atom$dt
    if (nrow(res_pendfv_atom$audit) > 0L) audit <- data.table::rbindlist(list(audit, res_pendfv_atom$audit), fill = TRUE, use.names = TRUE)
    if (length(res_pendfv_atom$linhas) > 0L) {
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_pendfv_atom$linhas))
      linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_pendfv_atom$linhas))
    }
    if (nrow(res_pendfv_atom$afetacoes) > 0L) afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_pendfv_atom$afetacoes), fill = TRUE, use.names = TRUE)
    falha_pendencia_sem_forma <- isTRUE(res_pendfv_atom$falha)
    if (isTRUE(res_pendfv_atom$n_grupos > 0L)) {
      corr <- res_pendfv_atom$corr
      if (nrow(corr) > 0L) corr[, ordem_tmp := seq_len(.N)]
      indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
      monitora_log_registrar_evento(
        "correcoes_campos",
        ifelse(isTRUE(falha_pendencia_sem_forma), "ERRO", "INFO"),
        arquivo_correcao,
        paste0(res_pendfv_atom$n_grupos, " operação(ões) semântica(s) PENDFV processada(s) vetorialmente; ", length(res_pendfv_atom$linhas), " linha(s) alterada(s)"),
        "itens auditáveis preservados; aplicação agrupada por id_correcao"
      )
    }
  }

  if (isTRUE(falha_pendencia_sem_forma)) {
    if (nrow(audit) > 0) {
      audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
      saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
      monitora_fwrite(audit, saida_audit, na = "")
      monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
    }
    stop("Correção contextual de pendências sem forma de vida falhou; ver auditoria_correcoes_campos_ultima_execucao.csv", call. = FALSE)
  }

 ### Limpeza de outras formas de vida (TRIOUT) no estado corrente.
 ### Operação por ocorrência diagnóstica aplicada antes das exclusões de COLETA,
 ### usando UUID/chave composta; linha_indice é apenas fallback auditável.
  if (nrow(corr) > 0L) {
    res_triout_atom <- monitora_correcao_aplicar_limpezas_outras_formas_estado_corrente(
      dt,
      corr,
      chaves = chaves,
      indice = indice_linhas,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario
    )
    dt <- res_triout_atom$dt
    if (nrow(res_triout_atom$audit) > 0L) audit <- data.table::rbindlist(list(audit, res_triout_atom$audit), fill = TRUE, use.names = TRUE)
    if (length(res_triout_atom$linhas) > 0L) {
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_triout_atom$linhas))
      linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_triout_atom$linhas))
    }
    if (nrow(res_triout_atom$afetacoes) > 0L) afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_triout_atom$afetacoes), fill = TRUE, use.names = TRUE)
    falha_limpeza_outras_formas <- isTRUE(res_triout_atom$falha)
    if (isTRUE(res_triout_atom$n_grupos > 0L)) {
      corr <- res_triout_atom$corr
      if (nrow(corr) > 0L) corr[, ordem_tmp := seq_len(.N)]
      indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
      monitora_log_registrar_evento(
        "correcoes_campos",
        ifelse(isTRUE(falha_limpeza_outras_formas), "ERRO", "INFO"),
        arquivo_correcao,
        paste0(res_triout_atom$n_grupos, " operação(ões) semântica(s) TRIOUT processada(s) no estado corrente; ", length(res_triout_atom$linhas), " linha(s) alterada(s)"),
        "alvo por UUID/chave composta aplicado antes de exclusões; sem índices antigos"
      )
    }
  }

  if (isTRUE(falha_limpeza_outras_formas)) {
    if (nrow(audit) > 0) {
      audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
      saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
      monitora_fwrite(audit, saida_audit, na = "")
      monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
    }
    stop("Limpeza atômica de outras formas de vida falhou na auditoria pós-aplicação; ver auditoria_correcoes_campos_ultima_execucao.csv", call. = FALSE)
  }

 ### Exclusões de COLETAS: aplicar grupos em lote, com auditoria pré-exclusão
 ### e uma única remoção vetorizada. Isso evita reconstruir o índice após cada
 ### COLETA e reduz risco de inconsistência por deslocamento de linha.
  if (nrow(corr) > 0L) {
    if (nrow(audit) > 0L) audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
    ids_semantica_pre_exc <- if (MONITORA_COL_ROW_ID %in% names(dt)) as.character(dt[[MONITORA_COL_ROW_ID]][linhas_semantica_alvo]) else character(0)
    ids_vinculos_pre_exc <- if (MONITORA_COL_ROW_ID %in% names(dt)) as.character(dt[[MONITORA_COL_ROW_ID]][linhas_afetadas_vinculos]) else character(0)
    if (nrow(afetacoes_vinculos) && MONITORA_COL_ROW_ID %in% names(dt) && "linha_indice" %in% names(afetacoes_vinculos)) {
      idx_af <- suppressWarnings(as.integer(afetacoes_vinculos$linha_indice))
      if (!("monitora_row_id" %in% names(afetacoes_vinculos))) afetacoes_vinculos[, monitora_row_id := NA_character_]
      ok_af <- !is.na(idx_af) & idx_af >= 1L & idx_af <= nrow(dt)
      afetacoes_vinculos[ok_af, monitora_row_id := as.character(dt[[MONITORA_COL_ROW_ID]][idx_af[ok_af]])]
    }
    res_exc_atom <- monitora_correcao_aplicar_exclusoes_coleta_atomicas(
      dt,
      corr,
      chaves = chaves,
      indice = indice_linhas,
      arquivo_correcao = arquivo_correcao
    )
    dt <- res_exc_atom$dt
    if (nrow(res_exc_atom$audit) > 0L) audit <- data.table::rbindlist(list(audit, res_exc_atom$audit), fill = TRUE, use.names = TRUE)
    if (length(res_exc_atom$coletas) > 0L) coletas_excluidas_aplicadas <- unique(c(coletas_excluidas_aplicadas, res_exc_atom$coletas))
    if (isTRUE(res_exc_atom$n_grupos > 0L)) {
      corr <- res_exc_atom$corr
      corr[, ordem_tmp := seq_len(.N)]
      indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
      if (MONITORA_COL_ROW_ID %in% names(dt)) {
        linhas_semantica_alvo <- unique(match(ids_semantica_pre_exc, as.character(dt[[MONITORA_COL_ROW_ID]]), nomatch = 0L))
        linhas_afetadas_vinculos <- unique(match(ids_vinculos_pre_exc, as.character(dt[[MONITORA_COL_ROW_ID]]), nomatch = 0L))
        linhas_semantica_alvo <- linhas_semantica_alvo[linhas_semantica_alvo > 0L]
        linhas_afetadas_vinculos <- linhas_afetadas_vinculos[linhas_afetadas_vinculos > 0L]
        if (nrow(afetacoes_vinculos) && "monitora_row_id" %in% names(afetacoes_vinculos)) {
          afetacoes_vinculos[, linha_indice := match(monitora_row_id, as.character(dt[[MONITORA_COL_ROW_ID]]), nomatch = 0L)]
          afetacoes_vinculos <- afetacoes_vinculos[linha_indice > 0L]
        }
      } else {
        linhas_semantica_alvo <- linhas_semantica_alvo[linhas_semantica_alvo <= nrow(dt)]
        linhas_afetadas_vinculos <- linhas_afetadas_vinculos[linhas_afetadas_vinculos <= nrow(dt)]
      }
      monitora_log_registrar_evento(
        "correcoes_campos",
        ifelse(isTRUE(res_exc_atom$falha), "AVISO", "INFO"),
        arquivo_correcao,
        paste0(res_exc_atom$n_grupos, " grupo(s) de exclusão de COLETAS processado(s) atomicamente; ", length(res_exc_atom$linhas_removidas), " linha(s) removida(s)"),
        "exclusão em lote por data.table; índice reconstruído uma única vez"
      )
    }
  }

  if (nrow(corr) > 0L && length(coletas_excluidas_aplicadas) > 0L) {
    idx_subsumidas_publicacao_q <- which(vapply(seq_len(nrow(corr)), function(ii) {
      monitora_publicacao_q_operacao_totalmente_subsumida_por_exclusao(corr[ii], coletas_excluidas_aplicadas)
    }, logical(1L)))
    if (length(idx_subsumidas_publicacao_q) > 0L) {
      audit_sub_gen <- data.table::rbindlist(lapply(idx_subsumidas_publicacao_q, function(ii) {
        monitora_publicacao_q_auditoria_subsumida_por_exclusao(
          corr[ii],
          arquivo_correcao = arquivo_correcao,
          atributo = if ("atributo_coluna_registros_corrig" %in% names(corr)) corr$atributo_coluna_registros_corrig[ii] else NA_character_,
          status = "ok_subsumida_por_exclusao",
          n_linhas_alvo_original = suppressWarnings(as.integer(corr$n_linhas_esperado[ii])),
          n_linhas_subsumidas = suppressWarnings(as.integer(corr$n_linhas_esperado[ii])),
          n_linhas_aplicadas = 0L,
          coletas_subsumidas = monitora_publicacao_q_parse_coletas_operacao(corr[ii]),
          mensagem_extra = "v2.5.4: operação modificadora removida do plano porque suas COLETAS já foram excluídas"
        )
      }), fill = TRUE, use.names = TRUE)
      audit <- data.table::rbindlist(list(audit, audit_sub_gen), fill = TRUE, use.names = TRUE)
      corr <- corr[-idx_subsumidas_publicacao_q]
      if (nrow(corr) > 0L) corr[, ordem_tmp := seq_len(.N)]
      monitora_log_registrar_evento(
        "correcoes_campos",
        "INFO",
        arquivo_correcao,
        paste0("v2.5.4: ", length(idx_subsumidas_publicacao_q), " operação(ões) modificadora(s) subsumida(s) por exclusão dominante e removida(s) do plano de aplicação"),
        "orquestrador de operações atômicas"
      )
    }
  }

 ### a fila SANHAB é reavaliada no estado corrente, depois das
 ### operações atômicas/exclusões e antes da pré-validação transacional.
 ### Assim, um alvo já resolvido não bloqueia nem contamina os demais itens.
  if (nrow(corr) > 0L) {
    sanhab_corrente <- monitora_correcao_reconciliar_sanhab_estado_corrente(
      dt, corr, chaves = chaves, dicionario = dicionario,
      indice = indice_linhas, arquivo_correcao = arquivo_correcao
    )
    corr <- sanhab_corrente$corr
    if (nrow(sanhab_corrente$audit)) {
      audit <- data.table::rbindlist(list(audit, sanhab_corrente$audit), fill = TRUE, use.names = TRUE)
    }
    if (isTRUE(sanhab_corrente$n_removidos > 0L)) {
      monitora_log_registrar_evento(
        "correcoes_campos", "INFO", arquivo_correcao,
        paste0("SANHAB reconciliada com a ocorrência diagnóstica atual; ", sanhab_corrente$n_removidos, " alvo(s) já resolvido(s)/fora do escopo retirado(s) sem sobrescrita"),
        "fonte única ocorrência×categoria×forma; demais itens do grupo preservados"
      )
    }
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
  }

  if (nrow(corr) > 0L) {
    if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
    corr[, grupo_correcao := fifelse(!is.na(id_correcao) & nzchar(as.character(id_correcao)), as.character(id_correcao), paste0("__linha_", ordem_tmp))]
 ### reclassificar operações ambíguas de token antes da pré-validação
 ### transacional. Isso evita que um update em lista select_multiple com
 ### valor_original_esperado parcial ("graminoide") bloqueie um grupo cuja
 ### intenção operacional é substituir token ("graminoide" -> "samambaia").
  res_publicacao_s_token <- monitora_publicacao_s_reclassificar_updates_tokenizados(
    dt,
    corr,
    chaves,
    dicionario = dicionario,
    indice_linhas = indice_linhas,
    arquivo_correcao = arquivo_correcao
  )
  corr <- res_publicacao_s_token$corr
  if (nrow(res_publicacao_s_token$audit) > 0L) {
    audit <- data.table::rbindlist(list(audit, res_publicacao_s_token$audit), fill = TRUE, use.names = TRUE)
    monitora_log_registrar_evento(
      "correcoes_campos",
      "INFO",
      arquivo_correcao,
      paste0("v2.5.4: ", res_publicacao_s_token$n, " operação(ões) update reclassificada(s) para replace_token antes da pré-validação"),
      "preserva update estrito para valor completo e corrige operações tokenizadas ambíguas em select_multiple"
    )
  }

  pre_list <- vector("list", nrow(corr))
  for (pp in seq_len(nrow(corr))) {
    pre <- monitora_correcao_prevalidar_operacao(dt, corr[pp], chaves, dicionario, indice_linhas)
    pre[, ordem_tmp := corr$ordem_tmp[pp]]
    pre[, grupo_correcao := corr$grupo_correcao[pp]]
    pre_list[[pp]] <- pre
  }
  prevalidacao <- data.table::rbindlist(pre_list, fill = TRUE, use.names = TRUE)
  grupos_invalidos <- unique(prevalidacao[status_prevalidacao != "ok", grupo_correcao])
  grupos_invalidos <- grupos_invalidos[!is.na(grupos_invalidos) & nzchar(grupos_invalidos)]
  if (length(grupos_invalidos)) {
    corr_invalidas <- prevalidacao[grupo_correcao %in% grupos_invalidos]
    corr_invalidas <- merge(corr, corr_invalidas, by = "ordem_tmp", all.y = TRUE, sort = FALSE)
    audit_bloq <- corr_invalidas[, .(
      id_correcao = id_correcao,
      ordem_operacao = ordem_operacao,
      status = fifelse(status_prevalidacao == "ok", "bloqueada_grupo_incompleto", status_prevalidacao),
      mensagem = paste0("Grupo de correção bloqueado transacionalmente: ", mensagem_prevalidacao),
      atributo = atributo_coluna_registros_corrig,
      linha_indice = NA_integer_,
      valor_antes = NA_character_,
      valor_depois = NA_character_,
      arquivo_correcao = arquivo_correcao
    )]
    audit <- data.table::rbindlist(list(audit, audit_bloq), fill = TRUE, use.names = TRUE)
    corr <- corr[!(grupo_correcao %in% grupos_invalidos)]
    if (nrow(corr) == 0L) {
      if (nrow(audit) > 0) {
        audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
        saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
        monitora_fwrite(audit, saida_audit, na = "")
        monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
        monitora_log_registrar_evento("correcoes_campos", "AVISO", saida_audit, paste0(nrow(audit), " operação(ões) bloqueada(s) por validação transacional"), "nenhuma correção aplicada")
      }
      return(dt[])
    }
  }

  }

  perf_operacoes_r24e2("painel_correcoes_prevalidacao_concluida_r24e2", "pré-validação transacional concluída; nenhum grupo inválido chegou à mutação genérica")

  if (nrow(corr) > 0L) {
    linhas_list <- vector("list", nrow(corr))
    for (pp2 in seq_len(nrow(corr))) {
      linhas_list[[pp2]] <- tryCatch(monitora_correcao_linhas_alvo_operacao(dt, corr[pp2], chaves, indice_linhas), error = function(e) integer(0))
      linhas_list[[pp2]] <- monitora_correcao_aplicar_escopo_conciliado(dt, linhas_list[[pp2]], corr[pp2])
    }
    linhas_semantica_alvo_generica <- unique(as.integer(unlist(linhas_list, use.names = FALSE)))
    linhas_semantica_alvo_generica <- linhas_semantica_alvo_generica[!is.na(linhas_semantica_alvo_generica) & linhas_semantica_alvo_generica >= 1L & linhas_semantica_alvo_generica <= nrow(dt)]
 ### Não sobrescrever alvos semânticos acumulados por operações atômicas.
 ### Linhas de MVLOTE ambíguas devem ser avaliadas de forma coerente no pré e no pós-teste, pois
 ### podiam ser removidas do pré-teste quando ainda havia correções genéricas
 ### remanescentes. Isso gerava falso "erro introduzido" para valores que
 ### foram mantidos intocados, como marcadores "Outra espécie..." em linhas
 ### ambíguas preservadas para revisão.
    linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, linhas_semantica_alvo_generica))
    try(monitora_correcao_auditar_lotes_multicoletas(dt, corr, linhas_list, chaves, arquivo_correcao), silent = TRUE)
  }
  contexto_semantica_pre <- paste0("pre_correcoes_", if (exists("MONITORA_EXEC_ID", inherits = TRUE)) MONITORA_EXEC_ID else format(Sys.time(), "%Y%m%d_%H%M%S"))
  auditoria_semantica_pre <- monitora_correcao_auditar_papeis_colunas_semantica(
    dt,
    contexto = contexto_semantica_pre,
    abortar = FALSE,
    linhas = if (isTRUE(auditoria_semantica_completa)) NULL else linhas_semantica_alvo
  )

 ### aplica todas as ações derivadas de tipo_forma_vida em uma única
 ### passagem vetorizada. O ledger continua recebendo uma linha de auditoria
 ### por item/alvo original, mas a função matricial cara roda apenas uma vez.
  if (nrow(corr) > 0L) {
    acoes_recalc_r21 <- tolower(trimws(as.character(corr$acao)))
    idx_recalc_r21 <- which(acoes_recalc_r21 %in% c("recalcular_tipo_forma_vida", "atualizar_tipo_forma_vida"))
    if (length(idx_recalc_r21)) {
      corr_recalc_r21 <- data.table::copy(corr[idx_recalc_r21])
      linhas_recalc_list_r21 <- linhas_list[idx_recalc_r21]
      linhas_recalc_r21 <- unique(as.integer(unlist(linhas_recalc_list_r21, use.names = FALSE)))
      linhas_recalc_r21 <- linhas_recalc_r21[!is.na(linhas_recalc_r21) & linhas_recalc_r21 >= 1L & linhas_recalc_r21 <= nrow(dt)]
      antes_recalc_r21 <- if (length(linhas_recalc_r21) && !is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% names(dt)) as.character(dt[[chaves$tipo_forma_vida]][linhas_recalc_r21]) else rep(NA_character_, length(linhas_recalc_r21))
      if (length(linhas_recalc_r21)) monitora_correcao_recalcular_tipo_forma_vida(dt, linhas_recalc_r21)
      depois_recalc_r21 <- if (length(linhas_recalc_r21) && !is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% names(dt)) as.character(dt[[chaves$tipo_forma_vida]][linhas_recalc_r21]) else rep(NA_character_, length(linhas_recalc_r21))
      for (jj in seq_along(linhas_recalc_list_r21)) {
        lin_jj <- unique(as.integer(linhas_recalc_list_r21[[jj]]))
        lin_jj <- lin_jj[!is.na(lin_jj) & lin_jj %in% linhas_recalc_r21]
        pos_jj <- match(lin_jj, linhas_recalc_r21)
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = corr_recalc_r21$id_correcao[jj],
          ordem_operacao = corr_recalc_r21$ordem_operacao[jj],
          status = if (length(lin_jj)) "aplicada" else "falha",
          mensagem = if (length(lin_jj)) "OK; recálculo derivado vetorizado R21" else "Nenhuma linha-alvo localizada para recalcular tipo_forma_vida",
          atributo = chaves$tipo_forma_vida,
          linha_indice = if (length(lin_jj)) lin_jj else NA_integer_,
          valor_antes = if (length(lin_jj)) antes_recalc_r21[pos_jj] else NA_character_,
          valor_depois = if (length(lin_jj)) depois_recalc_r21[pos_jj] else NA_character_,
          arquivo_correcao = arquivo_correcao
        )), fill = TRUE, use.names = TRUE)
      }
      if (length(linhas_recalc_r21)) {
        linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, linhas_recalc_r21))
        linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, linhas_recalc_r21))
        if (!is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% names(dt)) {
          afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, data.table::data.table(linha_indice = linhas_recalc_r21, atributo = chaves$tipo_forma_vida)), fill = TRUE, use.names = TRUE)
        }
      }
      corr <- corr[-idx_recalc_r21]
      linhas_list <- linhas_list[-idx_recalc_r21]
      if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    }
  }

  remocoes_desconhecida_genericas_aplicadas <- list()
  for (rr in seq_len(nrow(corr))) {
    linha_corr <- corr[rr]
    col <- monitora_correcao_resolver_coluna_operacao(dt, linha_corr, dicionario)
    acao <- tolower(trimws(as.character(linha_corr$acao[1])))
    linhas <- monitora_correcao_linhas_alvo_operacao(dt, linha_corr, chaves, indice_linhas)
    linhas <- monitora_correcao_aplicar_escopo_conciliado(dt, linhas, linha_corr)
    n_esperado <- suppressWarnings(as.integer(linha_corr$n_linhas_esperado[1]))
    status <- "aplicada"
    msg <- "OK"
    tipo_corr <- if ("tipo_correcao" %in% names(linha_corr)) tolower(trimws(as.character(linha_corr$tipo_correcao[1]))) else ""
    if (is.na(tipo_corr)) tipo_corr <- ""

    if (isTRUE(monitora_correcao_acao_exclusao_coleta(acao, tipo_corr))) {
      linhas <- monitora_correcao_localizar_linhas(dt, linha_corr, chaves, monitora_correcao_criar_indice_linhas(dt, chaves))
      if (length(linhas) == 0L) {
        status <- "falha"; msg <- "Nenhuma linha-alvo localizada para exclusão da COLETA"
      } else if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) {
        status <- "falha"; msg <- paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado, " para exclusão da COLETA")
      } else {
        audit_del <- data.table::data.table(
          id_correcao = linha_corr$id_correcao[1],
          ordem_operacao = linha_corr$ordem_operacao[1],
          status = "excluida_coleta",
          mensagem = paste0("COLETA excluída integralmente por correção auditável; ", length(linhas), " registro(s) removido(s)"),
          atributo = chaves$coleta,
          linha_indice = linhas,
          valor_antes = if (!is.na(chaves$coleta) && chaves$coleta %in% names(dt)) as.character(dt[[chaves$coleta]][linhas]) else NA_character_,
          valor_depois = "<REGISTRO_REMOVIDO>",
          arquivo_correcao = arquivo_correcao
        )
        audit_del <- monitora_correcao_anexar_contexto_auditoria(audit_del, dt, chaves)
        audit <- data.table::rbindlist(list(audit, audit_del), fill = TRUE, use.names = TRUE)
        coleta_excluida_val <- if ("coleta" %in% names(linha_corr)) as.character(linha_corr$coleta[1L]) else NA_character_
        if (!is.na(coleta_excluida_val) && nzchar(trimws(coleta_excluida_val))) {
          coletas_excluidas_aplicadas <- unique(c(coletas_excluidas_aplicadas, coleta_excluida_val))
        }
        dt <- dt[-linhas]
        indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
        linhas_semantica_alvo <- linhas_semantica_alvo[linhas_semantica_alvo <= nrow(dt)]
      }
      if (!identical(status, "aplicada")) {
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = linha_corr$id_correcao[1], ordem_operacao = linha_corr$ordem_operacao[1],
          status = status, mensagem = msg, atributo = linha_corr$atributo_coluna_registros_corrig[1],
          linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_,
          arquivo_correcao = arquivo_correcao
        )), fill = TRUE, use.names = TRUE)
      }
      next
    }

    if (acao %in% c("recalcular_tipo_forma_vida", "atualizar_tipo_forma_vida")) {
      if (length(linhas) == 0) {
        status <- "falha"; msg <- "Nenhuma linha-alvo localizada para recalcular tipo_forma_vida"
      } else {
        antes_tipo <- if (!is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% names(dt)) as.character(dt[[chaves$tipo_forma_vida]][linhas]) else NA_character_
        monitora_correcao_recalcular_tipo_forma_vida(dt, linhas)
        depois_tipo <- if (!is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% names(dt)) as.character(dt[[chaves$tipo_forma_vida]][linhas]) else NA_character_
        linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, linhas))
        if (!is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% names(dt)) {
          afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, data.table::data.table(linha_indice = linhas, atributo = chaves$tipo_forma_vida)), fill = TRUE, use.names = TRUE)
        }
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = linha_corr$id_correcao[1], ordem_operacao = linha_corr$ordem_operacao[1],
          status = status, mensagem = msg, atributo = chaves$tipo_forma_vida,
          linha_indice = linhas, valor_antes = antes_tipo, valor_depois = depois_tipo,
          arquivo_correcao = arquivo_correcao
        )), fill = TRUE, use.names = TRUE)
      }
      next
    }

    if (!is.na(col) && col %in% names(dt) && monitora_correcao_coluna_protegida(col)) {
      status <- "bloqueada_coluna_protegida"
      msg <- paste0("Correção bloqueada: coluna estrutural/protegida não pode ser alterada: ", col)
    } else if (monitora_correcao_coluna_protegida(linha_corr$atributo_coluna_registros_corrig[1])) {
      status <- "bloqueada_coluna_protegida"
      msg <- paste0("Correção bloqueada: atributo solicitado é coluna estrutural/protegida: ", linha_corr$atributo_coluna_registros_corrig[1])
    } else if (is.na(col) || !(col %in% names(dt))) {
      status <- "falha"; msg <- paste0("Coluna não encontrada: ", linha_corr$atributo_coluna_registros_corrig[1])
    } else if (length(linhas) == 0) {
      status <- "falha"; msg <- "Nenhuma linha-alvo localizada"
    } else if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) {
      status <- "falha"; msg <- paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado)
    } else {
      valid_dest <- monitora_correcao_validar_destino_operacao(dt, col, acao, linha_corr$valor_novo[1], linha_corr, dicionario)
      if (!isTRUE(valid_dest$ok)) {
        status <- valid_dest$status
        msg <- valid_dest$mensagem
      }
      valor_atual <- as.character(dt[[col]][linhas])
      esperado <- linha_corr$valor_original_esperado[1]
      precond <- monitora_publicacao_d_precondicao_valor_original(valor_atual, acao, linha_corr$valor_novo[1], esperado)
      if (!isTRUE(precond$ok)) {
        status <- "falha"
        msg <- precond$mensagem
      } else if (!identical(precond$mensagem, "OK")) {
        msg <- precond$mensagem
      }
      if (identical(status, "aplicada")) {
        novo <- monitora_correcao_aplicar_operacao(valor_atual, acao, linha_corr$valor_novo[1], esperado)
        mudou <- monitora_correcao_na_para_vazio(valor_atual) != monitora_correcao_na_para_vazio(novo)
        if (any(mudou, na.rm = TRUE)) {
          data.table::set(dt, i = linhas[mudou], j = col, value = novo[mudou])
          linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, linhas[mudou]))
          afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, data.table::data.table(linha_indice = linhas[mudou], atributo = col)), fill = TRUE, use.names = TRUE)
          audit <- data.table::rbindlist(list(audit, data.table::data.table(
            id_correcao = linha_corr$id_correcao[1], ordem_operacao = linha_corr$ordem_operacao[1],
            status = status, mensagem = msg, atributo = col,
            linha_indice = linhas[mudou], valor_antes = valor_atual[mudou], valor_depois = novo[mudou],
            arquivo_correcao = arquivo_correcao
          )), fill = TRUE, use.names = TRUE)
          if (isTRUE(monitora_correcao_eh_remocao_desconhecida_lista(
            dt, acao, linha_corr$valor_novo[1], esperado, col, dicionario
          ))) {
            remocoes_desconhecida_genericas_aplicadas[[length(remocoes_desconhecida_genericas_aplicadas) + 1L]] <- data.table::copy(linha_corr)
          }
        } else {
          audit <- data.table::rbindlist(list(audit, data.table::data.table(
            id_correcao = linha_corr$id_correcao[1], ordem_operacao = linha_corr$ordem_operacao[1],
            status = "ignorada_sem_alteracao", mensagem = "Operação sem efeito: valor final igual ao valor inicial", atributo = col,
            linha_indice = linhas, valor_antes = valor_atual, valor_depois = novo,
            arquivo_correcao = arquivo_correcao
          )), fill = TRUE, use.names = TRUE)
        }
      }
    }
    if (!identical(status, "aplicada")) {
      audit <- data.table::rbindlist(list(audit, data.table::data.table(
        id_correcao = linha_corr$id_correcao[1], ordem_operacao = linha_corr$ordem_operacao[1],
        status = status, mensagem = msg, atributo = linha_corr$atributo_coluna_registros_corrig[1],
        linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_,
        arquivo_correcao = arquivo_correcao
      )), fill = TRUE, use.names = TRUE)
    }
  }

  perf_operacoes_r24e2("painel_correcoes_aplicacao_generica_vetorizada_r24e2", "operações genéricas restantes aplicadas por grupos/atributos já compactados")

 ### Finalização vinculada à remoção manual de desconhecida. As linhas são
 ### relocalizadas por suas chaves estáveis depois de todas as operações
 ### genéricas, evitando índices obsoletos caso uma exclusão de COLETA tenha
 ### alterado a posição física dos registros durante a mesma sessão.
  if (length(remocoes_desconhecida_genericas_aplicadas)) {
    corr_desc_remove <- data.table::rbindlist(remocoes_desconhecida_genericas_aplicadas, fill = TRUE, use.names = TRUE)
    indice_desc_remove <- monitora_correcao_criar_indice_linhas(dt, chaves)
    linhas_desc_remove <- unique(as.integer(unlist(lapply(
      seq_len(nrow(corr_desc_remove)),
      function(ii) tryCatch(
        monitora_correcao_localizar_linhas(dt, corr_desc_remove[ii], chaves, indice_desc_remove),
        error = function(e) integer(0)
      )
    ), use.names = FALSE)))
    linhas_desc_remove <- linhas_desc_remove[
      !is.na(linhas_desc_remove) & linhas_desc_remove >= 1L & linhas_desc_remove <= nrow(dt)
    ]
    if (length(linhas_desc_remove)) {
      res_desc_remove <- monitora_correcao_sanitizar_dependentes_desconhecida(
        dt,
        linhas = linhas_desc_remove,
        categorias = c("nativa", "exotica", "seca_morta"),
        id_correcao = "__SANITIZACAO_DESCONHECIDA_APOS_REMOVE_TOKEN__",
        ordem_operacao = NA_character_,
        arquivo_correcao = arquivo_correcao,
        dicionario = dicionario,
        registrar_preservadas = TRUE
      )
      dt <- res_desc_remove$dt
      if (nrow(res_desc_remove$audit)) {
        monitora_correcao_gravar_auditoria_sanitizacao_desconhecida(res_desc_remove$audit)
        audit <- data.table::rbindlist(list(audit, res_desc_remove$audit), fill = TRUE, use.names = TRUE)
      }
      if (nrow(res_desc_remove$afetacoes)) {
        afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_desc_remove$afetacoes), fill = TRUE, use.names = TRUE)
        linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_desc_remove$afetacoes$linha_indice))
        linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_desc_remove$afetacoes$linha_indice))
      }
    }
  }

  if (length(coletas_excluidas_aplicadas) > 0L && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    coletas_excluidas_aplicadas <- unique(coletas_excluidas_aplicadas[!is.na(coletas_excluidas_aplicadas) & nzchar(trimws(coletas_excluidas_aplicadas))])
    if (length(coletas_excluidas_aplicadas) > 0L) {
      idx_vestigios <- which(as.character(dt[[chaves$coleta]]) %chin% coletas_excluidas_aplicadas)
      if (length(idx_vestigios) > 0L) {
        vestigios <- dt[idx_vestigios, .(
          linha_indice_pos_correcoes = idx_vestigios,
          COLETA = as.character(get(chaves$coleta))
        )]
        exec_id_vest <- if (exists("MONITORA_EXEC_ID", inherits = TRUE)) MONITORA_EXEC_ID else format(Sys.time(), "%Y%m%d_%H%M%S")
        arq_vest_log <- file.path(MONITORA_LOG_DIR, paste0("auditoria_exclusao_coletas_vestigios_", exec_id_vest, ".csv"))
        arq_vest_ult <- file.path(MONITORA_CORRECOES_DIR, "auditoria_exclusao_coletas_vestigios_ultima_execucao.csv")
        monitora_fwrite(vestigios, arq_vest_log, na = "")
        monitora_fwrite(vestigios, arq_vest_ult, na = "")
        monitora_log_registrar_evento(
          "exclusao_coletas", "ERRO", arq_vest_log,
          paste0(length(idx_vestigios), " vestígio(s) de COLETA excluída permaneceram em registros_corrig"),
          "execução bloqueada; revisar auditoria de vestígios"
        )
        stop("Exclusão de COLETAS falhou: ainda há linhas das COLETAS excluídas em registros_corrig. Ver auditoria_exclusao_coletas_vestigios_ultima_execucao.csv", call. = FALSE)
      } else {
        monitora_log_registrar_evento(
          "exclusao_coletas", "INFO", NA_character_,
          paste0(length(coletas_excluidas_aplicadas), " COLETA(s) excluída(s) sem vestígios em registros_corrig"),
          "OK"
        )
      }
    }
  }

  finalizacao_estado <- monitora_correcao_finalizar_estado_plano(
    dt,
    corr_plano_finalizacao,
    linhas_semantica_alvo = linhas_semantica_alvo,
    linhas_afetadas_vinculos = linhas_afetadas_vinculos,
    afetacoes_vinculos = afetacoes_vinculos,
    chaves = chaves,
    dicionario = dicionario,
    contexto = "pos_aplicacao_objeto",
    gravar_placeholders = TRUE,
    registrar_log = TRUE
  )
  dt <- finalizacao_estado$dt
  if (nrow(finalizacao_estado$audit)) audit <- data.table::rbindlist(list(audit, finalizacao_estado$audit), fill = TRUE, use.names = TRUE)
  linhas_semantica_alvo <- unique(finalizacao_estado$linhas_semantica_alvo)
  linhas_afetadas_vinculos <- unique(finalizacao_estado$linhas_afetadas_vinculos)
  afetacoes_vinculos <- data.table::copy(finalizacao_estado$afetacoes_vinculos)
  audit_vinculos <- data.table::copy(finalizacao_estado$audit_vinculos)
  sync_encostam_final <- finalizacao_estado$sync

  if (nrow(finalizacao_estado$audit_reforco)) {
    monitora_log_registrar_evento(
      "correcoes_campos",
      "INFO",
      NA_character_,
      paste0(nrow(finalizacao_estado$audit_reforco), " reforço(s) semântico(s) aplicado(s) em movimentos de forma de vida"),
      "movimentos interpretados antes do recálculo de campos superiores"
    )
  }
  if (nrow(audit_vinculos)) {
    monitora_log_registrar_evento(
      "correcoes_campos", "INFO", NA_character_,
      paste0(nrow(audit_vinculos), " atualização(ões) automática(s) de campos superiores vinculados ao XLSForm"),
      "campos superiores recalculados após correções"
    )
  }
  if (nrow(sync_encostam_final$audit)) {
    monitora_log_registrar_evento(
      "correcoes_campos", "INFO", NA_character_,
      paste0(nrow(sync_encostam_final$audit), " sincronização(ões) final(is) de Encostam/tipo_forma_vida aplicada(s)"),
      "campo superior harmonizado pelo contrato derivado das listas inferiores finais"
    )
  }
  regras_fechamento_relatorio <- tryCatch(monitora_correcao_contrato_fechamento_hierarquico(dt), error = function(e) data.table::data.table())

 ### relatório dedicado e sempre materializado. Separa o catálogo de
 ### relações (inclusive ambiguidades recusadas) das mutações realmente
 ### executadas, sem usar ausência de linha como sinônimo de sucesso.
  rel_regras_fechamento <- if (nrow(regras_fechamento_relatorio)) {
    regras_fechamento_relatorio[, .(
      tipo_registro = "regra_contratual",
      fase_fechamento = "contrato",
      status = status_regra,
      campo_inferior, papel_inferior, categoria, token,
      campo_superior, papel_superior,
      linha_indice = NA_integer_,
      valor_antes = NA_character_, valor_depois = NA_character_,
      mensagem = data.table::fifelse(
        status_regra == "ok",
        "Relação canônica liberada para fechamento ascendente quando o inferior estiver preenchido",
        "Relação não usada para mutação automática por ausência de associação inequívoca"
      )
    )]
  } else data.table::data.table()
  audit_fechamento_pre <- data.table::as.data.table(get0("MONITORA_AUDITORIA_FECHAMENTO_HIERARQUICO_PRE_PAINEL", ifnotfound = data.table::data.table(), inherits = TRUE))
  audit_fechamento_todas_fases <- data.table::rbindlist(list(audit_fechamento_pre, audit_vinculos), fill = TRUE, use.names = TRUE)
  rel_aplicacoes_fechamento <- if (nrow(audit_fechamento_todas_fases)) {
    av <- data.table::copy(audit_fechamento_todas_fases)
    for (cc in c("fase_fechamento", "status", "dependent_name", "parent_name", "token", "atributo", "linha_indice", "valor_antes", "valor_depois", "mensagem")) {
      if (!(cc %in% names(av))) data.table::set(av, j = cc, value = NA_character_)
    }
    data.table::data.table(
      tipo_registro = "sanitizacao_aplicada",
      fase_fechamento = as.character(av$fase_fechamento),
      status = as.character(av$status),
      campo_inferior = as.character(av$dependent_name),
      papel_inferior = monitora_correcao_papel_coluna_canonico(av$dependent_name),
      categoria = monitora_correcao_categoria_coluna_canonica(av$dependent_name),
      token = as.character(av$token),
      campo_superior = data.table::fcoalesce(as.character(av$parent_name), as.character(av$atributo)),
      papel_superior = monitora_correcao_papel_coluna_canonico(data.table::fcoalesce(as.character(av$parent_name), as.character(av$atributo))),
      linha_indice = suppressWarnings(as.integer(av$linha_indice)),
      valor_antes = as.character(av$valor_antes),
      valor_depois = as.character(av$valor_depois),
      mensagem = as.character(av$mensagem)
    )
  } else data.table::data.table()
  rel_fechamento_hierarquico <- data.table::rbindlist(
    list(rel_regras_fechamento, rel_aplicacoes_fechamento),
    fill = TRUE, use.names = TRUE
  )
  arq_fechamento_hierarquico <- file.path(MONITORA_CORRECOES_DIR, paste0("auditoria_fechamento_hierarquico_r24_", MONITORA_EXEC_ID, ".csv"))
  arq_fechamento_hierarquico_ult <- file.path(MONITORA_CORRECOES_DIR, "auditoria_fechamento_hierarquico_ultima_execucao.csv")
  try(monitora_fwrite(rel_fechamento_hierarquico, arq_fechamento_hierarquico, na = ""), silent = TRUE)
  try(monitora_fwrite(rel_fechamento_hierarquico, arq_fechamento_hierarquico_ult, na = ""), silent = TRUE)
  assign("MONITORA_AUDITORIA_FECHAMENTO_HIERARQUICO_ULTIMA", rel_fechamento_hierarquico, envir = .GlobalEnv)
  if (isTRUE(get0("MONITORA_OPCAO_CHECKPOINTS_GRANULARES_CORRECOES", ifnotfound = "S", inherits = TRUE) == "S") && exists("monitora_perf_registrar_checkpoint", mode = "function")) {
    monitora_perf_registrar_checkpoint("painel_correcoes_operacoes_atomicas_pre_recalculo_data", "operações atômicas de correção de campos aplicadas; antes de derivados de data/hora", dt)
  }
  dt <- monitora_recalcular_derivados_data_hora_se_necessario(
    dt,
    corr = corr,
    contexto = "pos_aplicacao_arquivo_correcoes",
    forcar = FALSE
  )
  chaves <- monitora_correcao_colunas_chave(dt)

  if (nrow(audit) > 0) {
    cols_contagem_plano <- setdiff(names(contagens_plano_operacoes), "id_correcao")
    cols_contagem_existentes <- intersect(cols_contagem_plano, names(audit))
    if (length(cols_contagem_existentes)) audit[, (cols_contagem_existentes) := NULL]
    audit <- merge(audit, contagens_plano_operacoes, by = "id_correcao", all.x = TRUE, sort = FALSE)
    audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
    MONITORA_AUDITORIA_CORRECOES_CAMPOS_ULTIMA <<- data.table::copy(audit)
    MONITORA_COLETAS_EXCLUIDAS_CORRECOES_ULTIMA <<- unique(coletas_excluidas_aplicadas)
    persist_objeto <- monitora_correcao_auditar_persistencia_operacoes(
      dt,
      audit,
      chaves = chaves,
      coletas_excluidas = coletas_excluidas_aplicadas,
      contexto = "pos_aplicacao_objeto",
      abortar = FALSE
    )
    persist_objeto_dt <- data.table::as.data.table(persist_objeto)
    erros_persist_objeto <- if ("status_persistencia" %in% names(persist_objeto_dt)) persist_objeto_dt[grepl("^(erro|falha|bloqueada)", as.character(status_persistencia)) & !grepl("removido_por_EXCCOL", as.character(status_persistencia))] else data.table::data.table()
    if (nrow(erros_persist_objeto)) {
      MONITORA_PERSISTENCIA_DERIVACOES_PENDENTES <<- TRUE
      MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS <<- TRUE
      monitora_log_registrar_evento("persistencia_correcoes", "ERRO", NA_character_, paste0(nrow(erros_persist_objeto), " falha(s) de persistência; checkpoint será materializado e registros_validados ficará bloqueado"), "consultar auditoria_persistencia_correcoes_pos_aplicacao_objeto_ultima_execucao.csv")
    }
    aud_sanhab_ap <- audit[grepl("^SANHAB", as.character(id_correcao))]
    pers_sanhab_ap <- if ("id_correcao" %in% names(persist_objeto_dt)) persist_objeto_dt[grepl("^SANHAB", as.character(id_correcao))] else data.table::data.table()
    if (nrow(aud_sanhab_ap) || nrow(pers_sanhab_ap)) {
      aud_sanhab_ap[, fase_relatorio := "aplicacao_objeto"]
      if (nrow(pers_sanhab_ap)) pers_sanhab_ap[, fase_relatorio := "persistencia_objeto"]
      rel_sanhab_ap <- data.table::rbindlist(list(aud_sanhab_ap, pers_sanhab_ap), fill = TRUE, use.names = TRUE)
      monitora_fwrite(rel_sanhab_ap, file.path(MONITORA_CORRECOES_DIR, "auditoria_sanitizacao_habito_obrigatorio_ausente_aplicacao_ultima_execucao.csv"), na = "")
      monitora_fwrite(rel_sanhab_ap, file.path(MONITORA_LOG_DIR, paste0("auditoria_sanitizacao_habito_obrigatorio_ausente_aplicacao_", MONITORA_EXEC_ID, ".csv")), na = "")
    }
    saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
    monitora_fwrite(audit, saida_audit, na = "")
    monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
    nivel_audit <- if (any(grepl("^(falha|bloqueada)", as.character(audit$status)) | audit$status %in% c("excluida_coleta"), na.rm = TRUE)) "AVISO" else "INFO"
    monitora_log_registrar_evento("correcoes_campos", nivel_audit, saida_audit, paste0(nrow(audit), " linha(s) de auditoria de correções"), "verificar falhas/bloqueios antes de liberar produtos")
  }

 ### Trava final de integridade: qualquer alteração em coluna estrutural aborta a execução.
  contexto_integridade <- paste0("pos_correcoes_", if (exists("MONITORA_EXEC_ID", inherits = TRUE)) MONITORA_EXEC_ID else format(Sys.time(), "%Y%m%d_%H%M%S"))
  monitora_correcao_auditar_colunas_protegidas(
    snapshot_colunas_protegidas_antes,
    dt,
    contexto = contexto_integridade,
    abortar = TRUE
  )
  monitora_correcao_mapa_colunas_canonicas(dt, contexto = contexto_integridade, gravar = TRUE)
  linhas_semantica_pos <- unique(as.integer(c(linhas_semantica_alvo, linhas_afetadas_vinculos)))
  linhas_semantica_pos <- linhas_semantica_pos[!is.na(linhas_semantica_pos) & linhas_semantica_pos >= 1L & linhas_semantica_pos <= nrow(dt)]
  auditoria_semantica_pos <- monitora_correcao_auditar_papeis_colunas_semantica(
    dt,
    contexto = contexto_integridade,
    abortar = FALSE,
    linhas = if (isTRUE(auditoria_semantica_completa)) NULL else linhas_semantica_pos
  )
  auditoria_semantica_pre_pos <- monitora_correcao_comparar_auditoria_semantica_pre_pos(auditoria_semantica_pre, auditoria_semantica_pos, contexto = contexto_integridade)
  erros_introduzidos <- auditoria_semantica_pre_pos[classificacao == "erro_introduzido_pela_correcao"]
  if (nrow(erros_introduzidos) > 0L) {
    MONITORA_PERSISTENCIA_DERIVACOES_PENDENTES <<- TRUE
    MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS <<- TRUE
    monitora_log_registrar_evento("auditoria_semantica_papeis", "ERRO", NA_character_, paste0(nrow(erros_introduzidos), " erro(s) semântico(s) introduzido(s) por correção"), "checkpoint obrigatório; registros_validados bloqueado; revisar auditoria_semantica_papeis_colunas_pre_pos_ultima_execucao.csv")
  }
  dt[]
}

### - trilha semântica e reaplicação de correções anteriores ---------
monitora_correcao_arquivo_tem_operacoes <- function(arquivo) {
  if (is.na(arquivo) || !nzchar(as.character(arquivo)[1]) || !file.exists(arquivo)) return(FALSE)
  info <- tryCatch(file.info(arquivo), error = function(e) NULL)
  if (is.null(info) || is.na(info$size[1]) || info$size[1] <= 0) return(FALSE)
  x <- tryCatch(data.table::fread(arquivo, nrows = 2L, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character"), error = function(e) data.table::data.table())
  nrow(x) > 0L
}

monitora_correcao_ler_operacoes_semanticas <- function(arquivo) {
  if (!monitora_correcao_arquivo_tem_operacoes(arquivo)) return(data.table::data.table())
 ### Ledgers v2 contêm JSON dentro do CSV. read.csv faz o unescape canônico
 ### de aspas duplicadas; fread em algumas combinações R/data.table preserva
 ### as aspas físicas e cada nova escrita pode voltar a duplicá-las.
  corr <- tryCatch(
    data.table::as.data.table(utils::read.csv(
      arquivo, header = TRUE, stringsAsFactors = FALSE, check.names = FALSE,
      na.strings = c("", "NA"), quote = "\"", fileEncoding = "UTF-8",
      colClasses = "character"
    )),
    error = function(e) tryCatch(data.table::fread(arquivo, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character"), error = function(e2) data.table::data.table())
  )
  if (!nrow(corr)) return(data.table::data.table())
  template <- monitora_correcao_template()
  for (cc in setdiff(names(template), names(corr))) corr[, (cc) := NA_character_]
  data.table::setDT(corr)
  corr[]
}

monitora_correcao_hash_texto <- function(x) {
  x <- paste(as.character(x), collapse = "|")
  if (requireNamespace("digest", quietly = TRUE)) return(digest::digest(x, algo = "sha256"))
  paste0("hash_indisponivel_", nchar(x), "_", sum(utf8ToInt(enc2utf8(x)), na.rm = TRUE))
}

monitora_correcao_assinatura_linha_semantica <- function(corr) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(character())
  campos <- intersect(
    c("id_correcao", "tipo_correcao", "ordem_operacao", "escopo_aplicacao", "coleta", "UC", "EA", "UA", "CICLO", "CAMPANHA", "ANO", "Ponto amostral", "Ponto metro", "uuid_registro", "monitora_row_id", "atributo_coluna_registros_corrig", "acao", "token_pai", "categoria_origem", "categoria_destino", "tipo_triagem", "token_removido", "forma_valida_escolhida", "lista_destino", "campo_dependente_preenchido", "habito_escolhido", "valor_original_esperado", "valor_novo", "motivo"),
    names(corr)
  )
  if (!length(campos)) return(rep(NA_character_, nrow(corr)))
  apply(as.data.frame(corr[, ..campos]), 1L, monitora_correcao_hash_texto)
}

### Contrato executável do ledger semântico v2 ------------------------------
### A trilha v1 continua importável, mas é migrada e validada antes de qualquer
### mutação. O v2 preserva as colunas operacionais v1 como representação
### compilável e acrescenta identidade, intenção declarativa e contrato.
MONITORA_REPLAY_SCHEMAS_SUPORTADOS <- c("correcoes_semanticas_v1", "replay_semantico_v1", "correcoes_semanticas_v2")
MONITORA_REPLAY_SCHEMA_ATUAL <- "correcoes_semanticas_v2"

monitora_replay_operation_kinds_suportados <- function() {
  c(
    "adicionar_token", "remover_token", "substituir_token",
    "atribuir_valor_canonico", "limpar_valor_canonico", "recalcular_derivados",
    "mover_forma_vida", "mover_forma_vida_lote", "substituir_desconhecida",
    "sanitizar_outras_formas_vida", "sanitizar_orfaos_encostam", "sanitizar_habito_obrigatorio_ausente",
    "corrigir_pendencia_sem_forma", "corrigir_habito", "excluir_coleta"
  )
}

monitora_replay_handlers_registrados <- function() {
  data.table::data.table(
    operation_kind = monitora_replay_operation_kinds_suportados(),
    handler_version = "compilador_contrato_unico_v2",
    ativo = TRUE
  )
}

monitora_replay_operation_kind <- function(corr) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(character(0))
  fam <- tryCatch(monitora_correcao_classificar_tipo_operacao(corr), error = function(e) rep("operacao_generica", nrow(corr)))
  acao <- if ("acao" %in% names(corr)) vapply(as.character(corr$acao), monitora_correcao_acao_normalizar, character(1)) else rep("", nrow(corr))
  tipo <- if ("tipo_correcao" %in% names(corr)) tolower(trimws(as.character(corr$tipo_correcao))) else rep("", nrow(corr))
  attr <- if ("atributo_coluna_registros_corrig" %in% names(corr)) tolower(trimws(as.character(corr$atributo_coluna_registros_corrig))) else rep("", nrow(corr))
  data.table::fcase(
    fam == "exclusao_coleta_atomica", "excluir_coleta",
    fam == "movimento_forma_vida_atomico", "mover_forma_vida",
    fam == "movimento_forma_vida_lote_atomico", "mover_forma_vida_lote",
    fam == "triagem_desconhecida_atomica", "substituir_desconhecida",
    fam == "limpeza_outras_formas_atomica", "sanitizar_outras_formas_vida",
    grepl("sanitizar_orfaos_encostam", tipo), "sanitizar_orfaos_encostam",
    grepl("sanitizacao_habito_obrigatorio_ausente", tipo), "sanitizar_habito_obrigatorio_ausente",
    grepl("pendencia_sem_forma", tipo) | grepl("__pendencia_sem_forma", attr), "corrigir_pendencia_sem_forma",
    grepl("habito", tipo) | grepl("habito", attr), "corrigir_habito",
    acao == "append_token", "adicionar_token",
    acao == "remove_token", "remover_token",
    acao == "replace_token", "substituir_token",
    acao == "update", "atribuir_valor_canonico",
    acao == "clear", "limpar_valor_canonico",
    acao == "recalcular_tipo_forma_vida", "recalcular_derivados",
    default = "nao_suportada"
  )
}

monitora_replay_target_policy <- function(corr, operation_kind = monitora_replay_operation_kind(corr)) {
  corr <- data.table::as.data.table(corr)
  n <- nrow(corr)
  if (!n) return(character(0))
  getc <- function(cc) if (cc %in% names(corr)) as.character(corr[[cc]]) else rep("", n)
  uuid <- trimws(getc("uuid_registro")); coleta <- trimws(getc("coleta"))
  data.table::fcase(
    operation_kind %in% c("sanitizar_outras_formas_vida", "sanitizar_orfaos_encostam", "sanitizar_habito_obrigatorio_ausente", "corrigir_pendencia_sem_forma"), "predicado_diagnostico_versionado",
    operation_kind == "excluir_coleta", "coleta_exata",
    !is.na(uuid) & nzchar(uuid), "uuid_exato",
    !is.na(coleta) & nzchar(coleta), "contexto_coleta_ponto",
    default = "alvo_nao_resolvido"
  )
}

monitora_replay_atributo_canonico <- function(atributo) {
  atributo <- as.character(atributo)
  out <- atributo
  idx <- tryCatch(monitora_contrato_unico_indices_cache(), error = function(e) NULL)
  aliases <- if (!is.null(idx) && !is.null(idx$indices$por_alias_normalizado)) data.table::as.data.table(idx$indices$por_alias_normalizado) else data.table::data.table()
  if (!nrow(aliases) || !all(c("alias_normalizado", "caminho_registro") %in% names(aliases))) return(out)
  for (ii in seq_along(atributo)) {
    an <- monitora_contrato_unico_normalizar_texto_seguro(atributo[ii])
    hit <- aliases[alias_normalizado == an]
    if (nrow(hit)) out[ii] <- as.character(hit$caminho_registro[1L])
  }
  out
}

monitora_replay_contract_fingerprint <- function() {
  idx <- tryCatch(monitora_contrato_unico_indices_cache(), error = function(e) NULL)
  attrs <- if (!is.null(idx) && !is.null(idx$indices$por_atributo_canonico)) data.table::as.data.table(idx$indices$por_atributo_canonico) else data.table::data.table()
  if (!nrow(attrs)) return("contrato_indisponivel")
  cols <- intersect(c("caminho_registro", "name_curto", "tipo_base", "list_name", "relevant", "required"), names(attrs))
  if (!length(cols)) return("contrato_sem_campos_fingerprint")
  ord <- if ("caminho_registro" %in% names(attrs)) order(as.character(attrs$caminho_registro), na.last = TRUE) else seq_len(nrow(attrs))
  monitora_correcao_hash_texto(unlist(lapply(cols, function(cc) as.character(attrs[[cc]][ord])), use.names = FALSE))
}

monitora_replay_migrar_para_v2 <- function(corr, origem = NA_character_) {
  corr <- data.table::copy(data.table::as.data.table(corr))
  if (!nrow(corr)) return(corr)
  schema_origem <- if ("event_schema_version" %in% names(corr)) as.character(corr$event_schema_version) else if ("trilha_schema" %in% names(corr)) as.character(corr$trilha_schema) else rep("correcoes_semanticas_v1", nrow(corr))
  schema_origem[is.na(schema_origem) | !nzchar(trimws(schema_origem))] <- "correcoes_semanticas_v1"
  desconhecidos <- setdiff(unique(schema_origem), MONITORA_REPLAY_SCHEMAS_SUPORTADOS)
  if (length(desconhecidos)) stop("Replay bloqueado antes da mutação: schema(s) não suportado(s): ", paste(desconhecidos, collapse = ", "), call. = FALSE)
  template <- monitora_correcao_template()
  for (cc in setdiff(names(template), names(corr))) data.table::set(corr, j = cc, value = NA_character_)
 ### Fast path e garantia de imutabilidade: ledger já v2 não é remigrado,
 ### recanonizado nem marcado com o caminho da cópia atual. A validação v2
 ### subsequente continua fail-closed, mas evita reconstruir o contrato único
 ### em toda abertura incremental.
  if (all(schema_origem == MONITORA_REPLAY_SCHEMA_ATUAL)) {
    return(corr[])
  }
  kind <- monitora_replay_operation_kind(corr)
  policy <- monitora_replay_target_policy(corr, kind)
  hash_base <- monitora_correcao_assinatura_linha_semantica(corr)
  cols_v2 <- c("event_id", "event_item_id", "contract_fingerprint", "created_build", "origin_exec_id", "selector_version", "preconditions_json", "postconditions_json", "event_sequence", "depends_on_event_ids", "created_at", "responsavel_original", "justificativa_original", "migrated_from_schema", "operation_kind", "target_policy", "atributo_canonico", "arquivo_ledger_origem")
  for (cc in setdiff(cols_v2, names(corr))) data.table::set(corr, j = cc, value = NA_character_)
  ids_grupo <- if ("id_correcao" %in% names(corr)) as.character(corr$id_correcao) else rep(NA_character_, nrow(corr))
  faltam_grupo <- is.na(ids_grupo) | !nzchar(trimws(ids_grupo))
  ids_grupo[faltam_grupo] <- hash_base[faltam_grupo]
  corr[is.na(event_id) | !nzchar(trimws(event_id)), event_id := paste0("evt_", vapply(ids_grupo, monitora_correcao_hash_texto, character(1)))]
  corr[is.na(event_item_id) | !nzchar(trimws(event_item_id)), event_item_id := paste0("item_", hash_base)]
  build_atual <- as.character(get0("MONITORA_SCRIPT_BUILD_ID", ifnotfound = "indefinido", inherits = TRUE))
  exec_atual <- as.character(get0("MONITORA_EXEC_ID", ifnotfound = NA_character_, inherits = TRUE))
  faltam_fp <- is.na(corr$contract_fingerprint) | !nzchar(corr$contract_fingerprint)
  if (any(faltam_fp)) corr[faltam_fp, contract_fingerprint := monitora_replay_contract_fingerprint()]
  corr[is.na(created_build) | !nzchar(created_build), created_build := build_atual]
  if ("exec_id_registro" %in% names(corr)) corr[is.na(origin_exec_id) | !nzchar(origin_exec_id), origin_exec_id := as.character(exec_id_registro)]
  corr[is.na(origin_exec_id) | !nzchar(origin_exec_id), origin_exec_id := exec_atual]
  corr[is.na(selector_version) | !nzchar(selector_version), selector_version := "seletor_alvo_v1"]
  corr[is.na(preconditions_json) | !nzchar(preconditions_json), preconditions_json := '{"policy":"match_original_when_informed","source":"legacy_operational_fields"}']
  corr[is.na(postconditions_json) | !nzchar(postconditions_json), postconditions_json := '{"policy":"semantic_effect_satisfied","derived_fields":"recalculate_by_current_contract"}']
  corr[is.na(event_sequence) | !nzchar(event_sequence), event_sequence := as.character(seq_len(.N))]
  if ("data_hora" %in% names(corr)) corr[is.na(created_at) | !nzchar(created_at), created_at := as.character(data_hora)]
  if ("responsavel" %in% names(corr)) corr[is.na(responsavel_original) | !nzchar(responsavel_original), responsavel_original := as.character(responsavel)]
  if ("motivo" %in% names(corr)) corr[is.na(justificativa_original) | !nzchar(justificativa_original), justificativa_original := as.character(motivo)]
  corr[is.na(created_at) | !nzchar(created_at), created_at := format(Sys.time(), "%Y-%m-%d %H:%M:%S %z")]
  corr[, event_schema_version := MONITORA_REPLAY_SCHEMA_ATUAL]
  idx_mig <- which(is.na(corr$migrated_from_schema) | !nzchar(corr$migrated_from_schema))
  idx_kind <- which(is.na(corr$operation_kind) | !nzchar(corr$operation_kind))
  idx_policy <- which(is.na(corr$target_policy) | !nzchar(corr$target_policy))
  if (length(idx_mig)) data.table::set(corr, i = idx_mig, j = "migrated_from_schema", value = schema_origem[idx_mig])
  if (length(idx_kind)) data.table::set(corr, i = idx_kind, j = "operation_kind", value = kind[idx_kind])
  if (length(idx_policy)) data.table::set(corr, i = idx_policy, j = "target_policy", value = policy[idx_policy])
  faltam_attr_canonico <- is.na(corr$atributo_canonico) | !nzchar(corr$atributo_canonico)
  if (any(faltam_attr_canonico)) corr[faltam_attr_canonico, atributo_canonico := monitora_replay_atributo_canonico(atributo_coluna_registros_corrig)]
  corr[is.na(arquivo_ledger_origem) | !nzchar(arquivo_ledger_origem), arquivo_ledger_origem := as.character(origem)[1L]]
  corr[]
}

monitora_replay_validar_v2 <- function(corr, abortar = TRUE) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(data.table::data.table())
  obrig <- c("event_id", "event_item_id", "event_schema_version", "operation_kind", "target_policy", "atributo_canonico")
  faltam <- setdiff(obrig, names(corr))
  if (length(faltam)) stop("Replay v2 inválido: campos obrigatórios ausentes: ", paste(faltam, collapse = ", "), call. = FALSE)
  status <- rep("ok", nrow(corr)); mensagem <- rep("evento compatível", nrow(corr))
  bad_schema <- as.character(corr$event_schema_version) != MONITORA_REPLAY_SCHEMA_ATUAL
  bad_kind <- !(as.character(corr$operation_kind) %in% monitora_replay_operation_kinds_suportados())
  bad_target <- as.character(corr$target_policy) == "alvo_nao_resolvido"
  bad_id <- is.na(corr$event_id) | !nzchar(trimws(as.character(corr$event_id)))
  bad_item <- is.na(corr$event_item_id) | !nzchar(trimws(as.character(corr$event_item_id))) | duplicated(as.character(corr$event_item_id))
  status[bad_schema] <- "schema_incompativel"; mensagem[bad_schema] <- "schema não migrado para v2"
  status[bad_kind] <- "operacao_nao_suportada"; mensagem[bad_kind] <- "operation_kind desconhecido nesta versão"
  status[bad_target] <- "alvo_nao_resolvido"; mensagem[bad_target] <- "evento sem UUID, coleta/ponto ou predicado versionado"
  status[bad_id] <- "event_id_invalido"; mensagem[bad_id] <- "event_id da decisão semântica vazio"
  status[bad_item] <- "event_item_id_invalido_ou_duplicado"; mensagem[bad_item] <- "item auditável vazio ou repetido no ledger"
  aud <- data.table::data.table(
    event_id = as.character(corr$event_id), event_item_id = as.character(corr$event_item_id), operation_kind = as.character(corr$operation_kind),
    target_policy = as.character(corr$target_policy), status_validacao_replay = status,
    mensagem_validacao_replay = mensagem
  )
  if (isTRUE(abortar) && any(status != "ok")) stop("Replay bloqueado antes da mutação: ", sum(status != "ok"), " evento(s) incompatível(is).", call. = FALSE)
  aud[]
}

monitora_replay_preparar_ledger <- function(corr, origem = NA_character_, abortar = TRUE) {
  mig <- monitora_replay_migrar_para_v2(corr, origem = origem)
  aud <- monitora_replay_validar_v2(mig, abortar = abortar)
  data.table::setattr(mig, "auditoria_validacao_replay", aud)
  mig[]
}

monitora_replay_classificar_preflight <- function(corr, preflight) {
  corr <- data.table::as.data.table(corr)
  out <- data.table::data.table(event_id = as.character(corr$event_id), classificacao_preflight = "aplicavel", mensagem_preflight = "plano validado no motor atômico")
  aud <- if (is.list(preflight) && !is.null(preflight$audit)) data.table::as.data.table(preflight$audit) else data.table::data.table()
  if (!nrow(aud) || !("id_correcao" %in% names(aud)) || !("id_correcao" %in% names(corr))) return(out)
  status_col <- intersect(c("status", "status_aplicacao"), names(aud))[1L]
  if (is.na(status_col)) return(out)
  falha_pat <- "^(falha|bloqueada|bloqueado)|ausente|incompativel|não suportado|nao_suportado"
  noop_pat <- "ignorada_sem_alteracao|ja_preenchido|ok_sem_|ok_subsumida|sem_alteracao"
  for (ii in seq_len(nrow(corr))) {
    aa <- aud[as.character(id_correcao) == as.character(corr$id_correcao[ii])]
    if (!nrow(aa)) next
    ss <- tolower(as.character(aa[[status_col]]))
    if (any(grepl(falha_pat, ss))) out[ii, `:=`(classificacao_preflight = "conflito", mensagem_preflight = paste(unique(ss[grepl(falha_pat, ss)]), collapse = "; "))]
    else if (all(grepl(noop_pat, ss))) out[ii, `:=`(classificacao_preflight = "ja_satisfeito", mensagem_preflight = "pós-condição já satisfeita; evento não requer nova alteração")]
  }
  out[, .(
    classificacao_preflight = if (any(classificacao_preflight == "conflito")) "conflito" else if (all(classificacao_preflight == "ja_satisfeito")) "ja_satisfeito" else "aplicavel",
    mensagem_preflight = paste(unique(mensagem_preflight), collapse = "; ")
  ), by = event_id]
}

monitora_replay_compilar_para_atual <- function(corr, dt, dicionario = NULL, abortar = TRUE) {
  corr <- data.table::copy(data.table::as.data.table(corr))
  dt <- data.table::as.data.table(dt)
  if (!nrow(corr)) return(corr)
  if (!("atributo_compilado" %in% names(corr))) corr[, atributo_compilado := NA_character_]
  virtuais <- grepl("^__.*__$", as.character(corr$atributo_coluna_registros_corrig))
  falhas <- character(0)
  for (ii in seq_len(nrow(corr))) {
    if (virtuais[ii] || identical(as.character(corr$operation_kind[ii]), "excluir_coleta")) {
      corr$atributo_compilado[ii] <- as.character(corr$atributo_coluna_registros_corrig[ii])
      next
    }
    candidatos <- unique(c(as.character(corr$atributo_canonico[ii]), as.character(corr$atributo_coluna_registros_corrig[ii])))
    candidatos <- candidatos[!is.na(candidatos) & nzchar(trimws(candidatos))]
    resolvido <- NA_character_
    for (cand in candidatos) {
      rr <- tryCatch(monitora_correcao_resolver_coluna(dt, cand, dicionario, permitir_heuristica = FALSE), error = function(e) NA_character_)
      if (!is.na(rr) && rr %in% names(dt)) { resolvido <- rr; break }
    }
    if (is.na(resolvido)) {
      falhas <- c(falhas, paste0(corr$event_id[ii], ": atributo canônico não resolvido: ", paste(candidatos, collapse = " | ")))
    } else {
      corr$atributo_compilado[ii] <- resolvido
      corr$atributo_coluna_registros_corrig[ii] <- resolvido
    }
  }
  if (isTRUE(abortar) && length(falhas)) stop("Replay bloqueado na compilação do contrato atual: ", paste(utils::head(falhas, 10L), collapse = "; "), call. = FALSE)
  corr[]
}

### Linhagem cumulativa -----------------------------------------------------
### O registros_corrig incremental já contém o efeito materializado das
### execuções anteriores. A trilha herdada é importada como proveniência e
### jamais reaplicada sobre esse arquivo. Somente eventos novos da sessão são
### aplicados; ambos são consolidados para a próxima geração.
monitora_linhagem_hash_arquivo <- function(path) {
  if (is.na(path) || !nzchar(path) || !file.exists(path)) return(NA_character_)
  if (requireNamespace("digest", quietly = TRUE)) return(digest::digest(file = path, algo = "sha256"))
  as.character(tools::md5sum(path)[1L])
}

monitora_linhagem_sanitizacoes_automaticas_consolidar <- function(dir_lin) {
  herdada <- data.table::as.data.table(get0("MONITORA_AUDITORIA_SANITIZACOES_HERDADA", ifnotfound = data.table::data.table(), inherits = TRUE))
  cpf <- data.table::as.data.table(get0("MONITORA_AUDITORIA_CPF_SESSAO", ifnotfound = data.table::data.table(), inherits = TRUE))
  uuid <- data.table::as.data.table(get0("MONITORA_AUDITORIA_UUID_REGISTRO_SESSAO", ifnotfound = data.table::data.table(), inherits = TRUE))
  preparar <- function(x, tipo) {
    x <- data.table::copy(data.table::as.data.table(x))
    if (!nrow(x)) return(x)
    if (!("tipo_sanitizacao" %in% names(x))) x[, tipo_sanitizacao := tipo]
    if (!("exec_id_origem" %in% names(x))) x[, exec_id_origem := as.character(get0("MONITORA_EXEC_ID", ifnotfound = "", inherits = TRUE))]
    if (!("build_origem" %in% names(x))) x[, build_origem := as.character(get0("MONITORA_SCRIPT_BUILD_ID", ifnotfound = "", inherits = TRUE))]
    if (!("origem_auditoria" %in% names(x))) x[, origem_auditoria := "sessao_atual"]
    x
  }
  cpf <- preparar(cpf, "cpf")
  uuid <- preparar(uuid, "uuid_registro")
  if (nrow(herdada)) herdada[, origem_auditoria := "herdada_incremental"]
  consolidada <- data.table::rbindlist(list(herdada, cpf, uuid), fill = TRUE, use.names = TRUE)
  if (!ncol(consolidada)) {
    consolidada <- data.table::data.table(
      tipo_sanitizacao = character(), monitora_row_id = character(), COLETA = character(),
      ponto_amostral = character(), atributo = character(), status = character(), acao = character(),
      motivo = character(), resultado_produto = character(), exec_id_origem = character(),
      build_origem = character(), origem_auditoria = character()
    )
  }
  if (nrow(consolidada)) {
    for (cc in c("tipo_sanitizacao", "monitora_row_id", "motivo", "acao", "exec_id_origem")) {
      if (!(cc %in% names(consolidada))) data.table::set(consolidada, j = cc, value = rep("", nrow(consolidada)))
    }
    chave <- do.call(paste, c(consolidada[, .(tipo_sanitizacao, monitora_row_id, motivo, acao, exec_id_origem)], sep = "||"))
    consolidada <- consolidada[!duplicated(chave)]
  }
  arq <- file.path(dir_lin, "auditoria_sanitizacoes_automaticas.csv")
  monitora_fwrite(consolidada, arq, na = "")
  assign("MONITORA_AUDITORIA_SANITIZACOES_CONSOLIDADA", consolidada, envir = .GlobalEnv)
  arq
}

monitora_linhagem_registrar_aplicacoes <- function(eventos, fase, status, arquivo_ledger = NA_character_) {
  eventos <- data.table::copy(data.table::as.data.table(eventos))
  if (!nrow(eventos)) return(invisible(data.table::data.table()))
  ids_existentes <- if ("event_id" %in% names(eventos)) as.character(eventos$event_id) else rep(NA_character_, nrow(eventos))
  if (!length(ids_existentes) || all(is.na(ids_existentes) | !nzchar(trimws(ids_existentes)))) {
 ### O painel devolve a representação operacional v1; a trilha persistida
 ### recebe event_id apenas ao passar pelo contrato v2. Compile aqui também
 ### para que a evidência de aplicação use exatamente a mesma identidade
 ### determinística e nunca desapareça como `sem_registros`.
    eventos <- monitora_replay_preparar_ledger(
      eventos,
      origem = as.character(arquivo_ledger)[1L],
      abortar = TRUE
    )
  }
  ids <- if ("event_id" %in% names(eventos)) unique(as.character(eventos$event_id)) else character(0)
  ids <- ids[!is.na(ids) & nzchar(ids)]
  if (!length(ids)) stop("Aplicação semântica concluída sem event_id v2; linhagem bloqueada.", call. = FALSE)
  exec_atual <- as.character(get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE))
  assinatura_apps <- paste(exec_atual, as.character(fase), as.character(status), ids, sep = "|")
  x <- data.table::data.table(
    event_id = ids,
    application_id = paste0("app_", vapply(assinatura_apps, monitora_correcao_hash_texto, character(1))),
    exec_id = exec_atual,
    fase = as.character(fase), status_aplicacao = as.character(status),
    data_hora = format(Sys.time(), "%Y-%m-%d %H:%M:%S %z"),
    build = as.character(get0("MONITORA_SCRIPT_BUILD_ID", ifnotfound = "indefinido", inherits = TRUE)),
    arquivo_ledger = as.character(arquivo_ledger)[1L]
  )
  old <- get0("MONITORA_REPLAY_APLICACOES", ifnotfound = data.table::data.table(), inherits = TRUE)
  MONITORA_REPLAY_APLICACOES <<- data.table::rbindlist(list(old, x), fill = TRUE, use.names = TRUE)
  if ("application_id" %in% names(MONITORA_REPLAY_APLICACOES)) MONITORA_REPLAY_APLICACOES <<- MONITORA_REPLAY_APLICACOES[!duplicated(application_id)]
  invisible(x)
}

monitora_linhagem_importar_incremental <- function(arquivo_registros) {
  tempo_ini <- proc.time()[["elapsed"]]
  input_dir <- get0("MONITORA_INPUT_DIR", ifnotfound = "input", inherits = TRUE)
  candidatos <- c(
    file.path(input_dir, "linhagem", "correcoes_semanticas_consolidada.csv"),
    file.path(input_dir, "correcoes_semanticas_consolidada.csv"),
    file.path(input_dir, "correcoes_semanticas.csv")
  )
  candidatos <- candidatos[file.exists(candidatos)]
  MONITORA_LINHAGEM_INPUT_SHA256 <<- monitora_linhagem_hash_arquivo(arquivo_registros)
  MONITORA_LINHAGEM_PARENT_REVISION <<- NA_character_
  man <- NULL
  manifestos <- c(file.path(input_dir, "linhagem", "manifesto_linhagem.json"), file.path(input_dir, "manifesto_linhagem.json"))
  manifestos <- manifestos[file.exists(manifestos)]
  if (length(manifestos) && requireNamespace("jsonlite", quietly = TRUE)) {
    man <- tryCatch(jsonlite::read_json(manifestos[1L], simplifyVector = TRUE), error = function(e) NULL)
    if (!is.null(man)) {
      MONITORA_LINHAGEM_PARENT_REVISION <<- as.character(man$revision_id)[1L]
      esperado <- as.character(man$output_data_sha256)[1L]
      if (length(esperado) && !is.na(esperado) && nzchar(esperado) && !identical(esperado, MONITORA_LINHAGEM_INPUT_SHA256)) {
        stop("Checkpoint incremental bloqueado: hash do registros_corrig de entrada diverge do manifesto de linhagem.", call. = FALSE)
      }
    }
  }
  if (!length(candidatos)) {
    MONITORA_TRILHA_SEMANTICA_HERDADA <<- data.table::data.table()
    MONITORA_LINHAGEM_STATUS <<- "proveniencia_historica_incompleta"
    return(invisible(MONITORA_TRILHA_SEMANTICA_HERDADA))
  }
  arq <- candidatos[1L]
  if (!is.null(man)) {
    hash_ledger_esperado <- as.character(man$ledger_sha256)[1L]
    hash_ledger_observado <- monitora_linhagem_hash_arquivo(arq)
    if (length(hash_ledger_esperado) && !is.na(hash_ledger_esperado) && nzchar(hash_ledger_esperado) && !identical(hash_ledger_esperado, hash_ledger_observado)) {
      stop("Linhagem incremental bloqueada: hash do ledger diverge do manifesto. Não misture registros_corrig e pasta linhagem de runs diferentes.", call. = FALSE)
    }
  }
  herdada <- monitora_correcao_ler_operacoes_semanticas(arq)
 ### Para schema v2 esta chamada usa fast path: valida o envelope sem
 ### recalcular fingerprint/aliases e sem modificar conteúdo histórico.
  herdada <- monitora_replay_preparar_ledger(herdada, origem = arq, abortar = TRUE)
  MONITORA_TRILHA_SEMANTICA_HERDADA <<- herdada
  hash_dados_esperado <- if (!is.null(man)) as.character(man$output_data_sha256)[1L] else NA_character_
  MONITORA_LINHAGEM_STATUS <<- if (is.null(man)) {
    "proveniencia_historica_importada_manifesto_ausente"
  } else if (is.na(hash_dados_esperado) || !nzchar(hash_dados_esperado)) {
    "proveniencia_historica_importada_hash_dados_ausente_legado"
  } else {
    "proveniencia_historica_importada_hash_verificado"
  }
  MONITORA_LINHAGEM_ARQUIVO_HERDADO <<- arq
  MONITORA_LINHAGEM_LEDGER_HERDADO_RAW <<- arq
 ### Preserva o ledger cumulativo de aplicações; a observação desta run é
 ### anexada, nunca usada para substituir a aplicação histórica original.
  candidatos_apps <- c(file.path(input_dir, "linhagem", "aplicacoes_correcoes.csv"), file.path(input_dir, "aplicacoes_correcoes.csv"))
  candidatos_apps <- candidatos_apps[file.exists(candidatos_apps)]
  apps_herdadas <- data.table::data.table()
  if (length(candidatos_apps)) {
    apps_herdadas <- tryCatch(data.table::as.data.table(utils::read.csv(candidatos_apps[1L], stringsAsFactors = FALSE, check.names = FALSE, colClasses = "character", na.strings = c("", "NA"), fileEncoding = "UTF-8")), error = function(e) data.table::data.table())
    if (!("event_id" %in% names(apps_herdadas))) apps_herdadas <- data.table::data.table()
  }
  MONITORA_REPLAY_APLICACOES <<- apps_herdadas
  candidatos_sanitizacoes <- c(
    file.path(input_dir, "linhagem", "auditoria_sanitizacoes_automaticas.csv"),
    file.path(input_dir, "auditoria_sanitizacoes_automaticas.csv")
  )
  candidatos_sanitizacoes <- candidatos_sanitizacoes[file.exists(candidatos_sanitizacoes)]
  sanitizacoes_herdadas <- data.table::data.table()
  if (length(candidatos_sanitizacoes)) {
    arq_sanitizacoes <- candidatos_sanitizacoes[1L]
    if (!is.null(man)) {
      esperado_sanitizacoes <- as.character(man$sanitizacoes_automaticas_sha256)[1L]
      observado_sanitizacoes <- monitora_linhagem_hash_arquivo(arq_sanitizacoes)
      if (length(esperado_sanitizacoes) && !is.na(esperado_sanitizacoes) && nzchar(esperado_sanitizacoes) && !identical(esperado_sanitizacoes, observado_sanitizacoes)) {
        stop("Linhagem incremental bloqueada: hash da auditoria de sanitizações automáticas diverge do manifesto.", call. = FALSE)
      }
    }
    sanitizacoes_herdadas <- tryCatch(data.table::fread(arq_sanitizacoes, colClasses = "character", na.strings = NULL, showProgress = FALSE), error = function(e) data.table::data.table())
  }
  MONITORA_AUDITORIA_SANITIZACOES_HERDADA <<- sanitizacoes_herdadas
  monitora_linhagem_registrar_aplicacoes(herdada, "heranca_incremental", "herdada_ja_materializada", arq)
 ### Intencionalmente não chama qualquer aplicador: os efeitos já estão no CSV.
 ### Também não cria um segundo arquivo chamado "consolidada" no staging do
 ### painel. A única trilha cumulativa canônica é materializada por
 ### monitora_linhagem_finalizar em 02_painel_correcoes/linhagem/.
  duracao <- proc.time()[["elapsed"]] - tempo_ini
  try(monitora_correcao_console_msg("Linhagem incremental importada sem replay: ", data.table::uniqueN(herdada$event_id), " evento(s); status=", MONITORA_LINHAGEM_STATUS, "; duração=", sprintf("%.3f", duracao), "s."), silent = TRUE)
  invisible(herdada)
}

monitora_linhagem_resumo_dt <- function() {
  herd <- data.table::as.data.table(get0("MONITORA_TRILHA_SEMANTICA_HERDADA", ifnotfound = data.table::data.table(), inherits = TRUE))
  replay <- data.table::as.data.table(get0("MONITORA_TRILHA_SEMANTICA_REPLAY", ifnotfound = data.table::data.table(), inherits = TRUE))
  atual <- data.table::as.data.table(get0("MONITORA_TRILHA_SEMANTICA_SESSAO", ifnotfound = data.table::data.table(), inherits = TRUE))
  n_evt <- function(x) if (!nrow(x)) 0L else if ("event_id" %in% names(x)) data.table::uniqueN(x$event_id) else nrow(x)
  data.table::data.table(
    componente = c("histórico herdado já materializado", "histórico reaplicado por replay", "decisões novas da sessão", "histórico acumulado", "estado da proveniência"),
    valor = c(as.character(n_evt(herd)), as.character(n_evt(replay)), as.character(n_evt(atual)), as.character(n_evt(data.table::rbindlist(list(herd, replay, atual), fill = TRUE))), as.character(get0("MONITORA_LINHAGEM_STATUS", ifnotfound = "execucao_sem_heranca_incremental", inherits = TRUE)))
  )
}

monitora_linhagem_finalizar <- function(arquivo_registros_saida = NA_character_) {
  out <- get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE)
  dir_lin <- file.path(out, "02_painel_correcoes", "linhagem")
  dir.create(dir_lin, recursive = TRUE, showWarnings = FALSE)
  herd <- data.table::as.data.table(get0("MONITORA_TRILHA_SEMANTICA_HERDADA", ifnotfound = data.table::data.table(), inherits = TRUE))
  replay <- data.table::as.data.table(get0("MONITORA_TRILHA_SEMANTICA_REPLAY", ifnotfound = data.table::data.table(), inherits = TRUE))
  sess <- data.table::as.data.table(get0("MONITORA_TRILHA_SEMANTICA_SESSAO", ifnotfound = data.table::data.table(), inherits = TRUE))
  ledger <- data.table::rbindlist(list(herd, replay, sess), fill = TRUE, use.names = TRUE)
  if (nrow(ledger) && "event_item_id" %in% names(ledger)) ledger <- ledger[is.na(event_item_id) | !duplicated(event_item_id)]
  if (nrow(ledger)) monitora_replay_validar_v2(ledger, abortar = TRUE)
  arq_ledger <- file.path(dir_lin, "correcoes_semanticas_consolidada.csv")
  raw_herdado <- as.character(get0("MONITORA_LINHAGEM_LEDGER_HERDADO_RAW", ifnotfound = "", inherits = TRUE))[1L]
  herdado_ja_v2 <- nrow(herd) > 0L && "event_schema_version" %in% names(herd) &&
    all(as.character(herd$event_schema_version) == MONITORA_REPLAY_SCHEMA_ATUAL)
  somente_heranca_sem_novos <- isTRUE(herdado_ja_v2) && !nrow(replay) && !nrow(sess) && nzchar(raw_herdado) && file.exists(raw_herdado)
  if (isTRUE(somente_heranca_sem_novos)) {
    ok_copy <- file.copy(raw_herdado, arq_ledger, overwrite = TRUE, copy.mode = FALSE, copy.date = FALSE)
    if (!isTRUE(ok_copy)) stop("Falha ao preservar ledger herdado imutável em ", arq_ledger, call. = FALSE)
  } else {
    monitora_fwrite(ledger, arq_ledger, na = "")
  }
  apps <- data.table::as.data.table(get0("MONITORA_REPLAY_APLICACOES", ifnotfound = data.table::data.table(), inherits = TRUE))
  monitora_fwrite(apps, file.path(dir_lin, "aplicacoes_correcoes.csv"), na = "")
  resumo <- monitora_linhagem_resumo_dt()
  monitora_fwrite(resumo, file.path(dir_lin, "resumo_linhagem.csv"), na = "")
  arq_sanitizacoes <- monitora_linhagem_sanitizacoes_automaticas_consolidar(dir_lin)
  candidatos_saida <- unique(c(
    as.character(arquivo_registros_saida)[1L],
    tryCatch(monitora_produtos_path_canonico("registros_corrig.csv", out), error = function(e) NA_character_),
    file.path(out, "01_produtos_dados", "registros_corrig.csv"),
    file.path(out, "registros_corrig.csv")
  ))
  candidatos_saida <- candidatos_saida[!is.na(candidatos_saida) & nzchar(candidatos_saida) & file.exists(candidatos_saida)]
  if (!length(candidatos_saida)) stop("Manifesto de linhagem bloqueado: registros_corrig.csv materializado não foi localizado no caminho canônico.", call. = FALSE)
  arq_saida_canonico <- candidatos_saida[1L]
  output_hash <- monitora_linhagem_hash_arquivo(arq_saida_canonico)
  ledger_hash <- monitora_linhagem_hash_arquivo(arq_ledger)
  sanitizacoes_hash <- monitora_linhagem_hash_arquivo(arq_sanitizacoes)
  if (is.na(output_hash) || !nzchar(output_hash) || is.na(ledger_hash) || !nzchar(ledger_hash) || is.na(sanitizacoes_hash) || !nzchar(sanitizacoes_hash)) stop("Manifesto de linhagem bloqueado: não foi possível calcular hashes obrigatórios de dados/ledger/sanitizações.", call. = FALSE)
  revision <- paste0("rev_", substr(monitora_correcao_hash_texto(c(ledger_hash, output_hash, get0("MONITORA_EXEC_ID", ifnotfound = "", inherits = TRUE))), 1L, 16L))
  manifesto <- list(
    lineage_schema = "monitora_linhagem_v2", revision_id = revision,
    parent_revision_id = get0("MONITORA_LINHAGEM_PARENT_REVISION", ifnotfound = NA_character_, inherits = TRUE),
    exec_id = get0("MONITORA_EXEC_ID", ifnotfound = NA_character_, inherits = TRUE),
    build = get0("MONITORA_SCRIPT_BUILD_ID", ifnotfound = NA_character_, inherits = TRUE),
    modo = get0("MONITORA_MODO_EXECUCAO", ifnotfound = NA_character_, inherits = TRUE),
    status_proveniencia = get0("MONITORA_LINHAGEM_STATUS", ifnotfound = "execucao_sem_heranca_incremental", inherits = TRUE),
    input_data_sha256 = get0("MONITORA_LINHAGEM_INPUT_SHA256", ifnotfound = NA_character_, inherits = TRUE),
    output_data_path = "01_produtos_dados/registros_corrig.csv",
    ledger_path = "02_painel_correcoes/linhagem/correcoes_semanticas_consolidada.csv",
    sanitizacoes_automaticas_path = "02_painel_correcoes/linhagem/auditoria_sanitizacoes_automaticas.csv",
    output_data_sha256 = output_hash,
    ledger_sha256 = ledger_hash,
    sanitizacoes_automaticas_sha256 = sanitizacoes_hash,
    event_count = if (nrow(ledger)) data.table::uniqueN(ledger$event_id) else 0L
  )
  arq_manifesto <- file.path(dir_lin, "manifesto_linhagem.json")
  if (requireNamespace("jsonlite", quietly = TRUE)) {
    jsonlite::write_json(manifesto, arq_manifesto, pretty = TRUE, auto_unbox = TRUE, na = "null")
  } else {
    writeLines(c("{", paste0('  "lineage_schema": "monitora_linhagem_v2",'), paste0('  "revision_id": "', revision, '"'), "}"), arq_manifesto)
  }
  MONITORA_LINHAGEM_MANIFESTO <<- arq_manifesto
  invisible(list(ledger = ledger, aplicacoes = apps, resumo = resumo, manifesto = manifesto))
}

### O organizador final pode atualizar referências documentais dentro do ledger
### depois da primeira assinatura. Reassinar os arquivos físicos já canônicos
### evita que o manifesto descreva os bytes anteriores à organização.
monitora_linhagem_reassinar_pos_organizacao <- function(output_dir, contexto = "fechamento_final") {
  dir_lin <- file.path(output_dir, "02_painel_correcoes", "linhagem")
  arq_dados <- file.path(output_dir, "01_produtos_dados", "registros_corrig.csv")
  arq_ledger <- file.path(dir_lin, "correcoes_semanticas_consolidada.csv")
  arq_sanitizacoes <- file.path(dir_lin, "auditoria_sanitizacoes_automaticas.csv")
  arq_manifesto <- file.path(dir_lin, "manifesto_linhagem.json")
  if (!all(file.exists(c(arq_dados, arq_ledger, arq_sanitizacoes)))) return(invisible(NULL))
  if (!requireNamespace("jsonlite", quietly = TRUE)) {
    stop("Integridade pós-organização da linhagem exige o pacote jsonlite.", call. = FALSE)
  }

  anterior <- if (file.exists(arq_manifesto)) {
    tryCatch(jsonlite::read_json(arq_manifesto, simplifyVector = TRUE), error = function(e) list())
  } else list()
  valor_anterior <- function(nome, fallback = NA_character_) {
    valor <- anterior[[nome]]
    if (is.null(valor) || !length(valor)) fallback else valor[[1L]]
  }
  output_hash <- monitora_linhagem_hash_arquivo(arq_dados)
  ledger_hash <- monitora_linhagem_hash_arquivo(arq_ledger)
  sanitizacoes_hash <- monitora_linhagem_hash_arquivo(arq_sanitizacoes)
  if (any(is.na(c(output_hash, ledger_hash, sanitizacoes_hash))) || any(!nzchar(c(output_hash, ledger_hash, sanitizacoes_hash)))) {
    stop("Integridade pós-organização bloqueada: hashes físicos de dados/ledger/sanitizações indisponíveis.", call. = FALSE)
  }
  ledger <- data.table::fread(arq_ledger, colClasses = "character", na.strings = NULL, showProgress = FALSE)
  n_eventos <- if (nrow(ledger) && "event_id" %in% names(ledger)) data.table::uniqueN(ledger$event_id) else 0L
  exec_id <- as.character(valor_anterior("exec_id", get0("MONITORA_EXEC_ID", ifnotfound = NA_character_, inherits = TRUE)))
  revision <- paste0("rev_", substr(monitora_correcao_hash_texto(c(ledger_hash, output_hash, exec_id)), 1L, 16L))
  manifesto <- list(
    lineage_schema = as.character(valor_anterior("lineage_schema", "monitora_linhagem_v2")),
    revision_id = revision,
    parent_revision_id = valor_anterior("parent_revision_id", get0("MONITORA_LINHAGEM_PARENT_REVISION", ifnotfound = NA_character_, inherits = TRUE)),
    exec_id = exec_id,
    build = as.character(valor_anterior("build", get0("MONITORA_SCRIPT_BUILD_ID", ifnotfound = NA_character_, inherits = TRUE))),
    modo = as.character(valor_anterior("modo", get0("MONITORA_MODO_EXECUCAO", ifnotfound = NA_character_, inherits = TRUE))),
    status_proveniencia = as.character(valor_anterior("status_proveniencia", get0("MONITORA_LINHAGEM_STATUS", ifnotfound = "execucao_sem_heranca_incremental", inherits = TRUE))),
    input_data_sha256 = valor_anterior("input_data_sha256", get0("MONITORA_LINHAGEM_INPUT_SHA256", ifnotfound = NA_character_, inherits = TRUE)),
    output_data_path = "01_produtos_dados/registros_corrig.csv",
    ledger_path = "02_painel_correcoes/linhagem/correcoes_semanticas_consolidada.csv",
    sanitizacoes_automaticas_path = "02_painel_correcoes/linhagem/auditoria_sanitizacoes_automaticas.csv",
    output_data_sha256 = output_hash,
    ledger_sha256 = ledger_hash,
    sanitizacoes_automaticas_sha256 = sanitizacoes_hash,
    event_count = as.integer(n_eventos)
  )
  jsonlite::write_json(manifesto, arq_manifesto, pretty = TRUE, auto_unbox = TRUE, na = "null")
  conferido <- jsonlite::read_json(arq_manifesto, simplifyVector = TRUE)
  if (!identical(as.character(conferido$output_data_sha256), output_hash) ||
      !identical(as.character(conferido$ledger_sha256), ledger_hash) ||
      !identical(as.character(conferido$sanitizacoes_automaticas_sha256), sanitizacoes_hash) ||
      !identical(as.integer(conferido$event_count), as.integer(n_eventos))) {
    stop("Manifesto de linhagem não preservou a assinatura física pós-organização.", call. = FALSE)
  }
  dir_aud <- file.path(output_dir, "03_auditorias", "persistencia")
  dir.create(dir_aud, recursive = TRUE, showWarnings = FALSE)
  monitora_fwrite(data.table::data.table(
    contexto = as.character(contexto)[1L],
    revision_id_anterior = as.character(valor_anterior("revision_id", NA_character_)),
    revision_id_final = revision,
    ledger_sha256_anterior = as.character(valor_anterior("ledger_sha256", NA_character_)),
    ledger_sha256_final = ledger_hash,
    sanitizacoes_automaticas_sha256_final = sanitizacoes_hash,
    output_data_sha256_final = output_hash,
    event_count = as.integer(n_eventos), status = "hash_fisico_pos_organizacao_verificado",
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
  ), file.path(dir_aud, "auditoria_linhagem_integridade_pos_organizacao.csv"), na = "")
  MONITORA_LINHAGEM_MANIFESTO <<- arq_manifesto
  invisible(manifesto)
}

### relatório ponta a ponta da cadeia de dados -------------------------
### Consolida produtos, transições e eventos reais da execução. Não substitui
### auditorias detalhadas: aponta explicitamente os arquivos que fundamentam
### cada passagem e registra por que um produto foi criado, não aplicável ou
### bloqueado.
monitora_cadeia_dados_relatorio_gerar <- function(contexto = "fim_execucao") {
  out <- get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE)
  input_dir <- get0("MONITORA_INPUT_DIR", ifnotfound = "input", inherits = TRUE)
  exec_id <- as.character(get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE))[1L]
  dir_rel <- file.path(out, "00_manifesto_execucao", "cadeia_dados")
  dir.create(dir_rel, recursive = TRUE, showWarnings = FALSE)

  caminho_produto <- function(nome) {
    cand <- unique(c(
      tryCatch(monitora_produtos_path_canonico(nome, out), error = function(e) NA_character_),
      file.path(out, "01_produtos_dados", nome), file.path(out, nome)
    ))
    cand <- cand[!is.na(cand) & nzchar(cand)]
    hit <- cand[file.exists(cand)]
    if (length(hit)) hit[1L] else cand[1L]
  }
  ler_primeiro <- function(caminhos) {
    hit <- caminhos[file.exists(caminhos)]
    if (!length(hit)) return(data.table::data.table())
    tryCatch(data.table::fread(hit[1L], showProgress = FALSE, fill = TRUE), error = function(e) data.table::data.table())
  }
  resumo_import <- ler_primeiro(c(
    file.path(out, "auditoria_registros_importados_resumo.csv"),
    file.path(out, "03_auditorias", "importacao", "auditoria_registros_importados_resumo.csv"),
    file.path(out, "03_auditorias", "execucao", "auditoria_registros_importados_resumo.csv")
  ))
  hashes <- ler_primeiro(c(file.path(out, "03_auditorias", "importacao", "auditoria_produtos_canonicos_md5.csv")))
  resumo_produto <- function(nome) {
    if (!nrow(resumo_import) || !("produto" %in% names(resumo_import))) return(list(n_linhas = NA_integer_, n_colunas = NA_integer_))
    rr <- resumo_import[as.character(produto) == nome]
    if (!nrow(rr)) return(list(n_linhas = NA_integer_, n_colunas = NA_integer_))
    list(
      n_linhas = if ("n_linhas" %in% names(rr)) suppressWarnings(as.integer(tail(rr$n_linhas, 1L))) else NA_integer_,
      n_colunas = if ("n_colunas" %in% names(rr)) suppressWarnings(as.integer(tail(rr$n_colunas, 1L))) else NA_integer_
    )
  }
  info_produto <- function(nome) {
    p <- caminho_produto(nome)
    existe <- !is.na(p) && nzchar(p) && file.exists(p)
    sum_p <- resumo_produto(nome)
    if (is.na(sum_p$n_linhas) && nome %in% c("registros_corrig.csv", "registros_validados.csv") && exists("registros_corrig", inherits = TRUE)) {
      obj_corrig <- get("registros_corrig", inherits = TRUE)
      if (inherits(obj_corrig, c("data.frame", "data.table"))) sum_p$n_linhas <- as.integer(nrow(obj_corrig))
    }
    n_cols <- sum_p$n_colunas
    if (isTRUE(existe) && is.na(n_cols)) {
      n_cols <- tryCatch(ncol(data.table::fread(p, nrows = 0L, showProgress = FALSE, fill = TRUE, check.names = FALSE)), error = function(e) NA_integer_)
    }
    md5 <- NA_character_
    if (nrow(hashes) && all(c("produto", "md5_canonico") %in% names(hashes))) {
      hh <- hashes[as.character(produto) == nome]
      if (nrow(hh)) md5 <- as.character(tail(hh$md5_canonico, 1L))
    }
    list(
      caminho = p, existe = existe,
      tamanho = if (isTRUE(existe)) as.numeric(file.info(p)$size[1L]) else NA_real_,
      n_linhas = sum_p$n_linhas, n_colunas = n_cols, md5 = md5
    )
  }

  arqs_input <- if (dir.exists(input_dir)) list.files(input_dir, recursive = TRUE, full.names = TRUE, all.files = FALSE) else character()
  arqs_input <- arqs_input[file.exists(arqs_input) & !dir.exists(arqs_input)]
  n_input <- length(arqs_input)
  bytes_input <- if (n_input) sum(as.numeric(file.info(arqs_input)$size), na.rm = TRUE) else 0

  produtos <- c("registros_importados_bruto.csv", "registros_importados.csv", "registros_importados_operacional_pre_painel.csv", "registros_corrig.csv", "registros_validados.csv")
  info <- lapply(produtos, info_produto)
  nomes_etapa <- c("input", "registros_importados_bruto", "registros_importados", "registros_importados_operacional_pre_painel", "registros_corrig", "registros_validados")
  descricoes <- c(
    "Arquivos fornecidos em input/, inclusive ZIPs, CSVs e planilhas aceitas pelo importador.",
    "Snapshot da leitura/montagem antes das sanitizações semânticas.",
    "Entrada comparável após normalização inicial de cabeçalhos, aliases e saneamento preliminar.",
    "Camada operacional pós-tokenização e pré-painel.",
    "Base corrigida após deduplicação, painel, sanitizações automáticas tipadas e auditorias de persistência.",
    "Projeção opcional de registros_corrig no schema contratual SISMONITORA/XLSForm."
  )
  transformacoes <- c(
    "Inventário, extração recursiva, classificação de fonte, tamanho e MD5 dos arquivos elegíveis.",
    "Leitura dos CSVs elegíveis, preservação de proveniência e concatenação; arquivos vazios/excluídos permanecem em auditoria.",
    "Consolidação de aliases, cabeçalhos duplicados/mojibake e auditoria de pipes pré-tokenização.",
    "Padronização de categorias, formas, espécies, datas e ponto/metro; deduplicação e quarentena de coletas incompletas.",
    "Operações do painel conciliadas por especificidade, exclusões, movimentos, sanitização auditada de placeholders/hábitos, fechamento hierárquico forma→categoria→Encostam e validações pós-painel.",
    "Validação de pendências impeditivas, aplicação do schema, aliases contratuais e domínios; nenhuma pendência é ocultada."
  )
  evidencias <- c(
    "auditoria_arquivos_csv_*; auditoria_tipos_entrada; auditoria_csvs_nao_biologicos_excluidos_*",
    "auditoria_registros_importados_resumo.csv; auditoria_compatibilidade_fontes_pre_dedup_*",
    "resumo_auditoria_pipe_pretokenizacao_*; auditoria_duplicidades_semanticas_*",
    "performance_execucao_*; auditorias de datas, ponto/metro, completude e ocorrências pré-painel",
    "correcoes_semanticas_solicitadas_*; auditoria_conciliacao_semantica_operacoes_*; auditoria_sanitizacao_placeholders_semanticos_*; auditoria_sanitizacao_habito_obrigatorio_ausente_*; auditoria_fechamento_hierarquico_*; auditoria_persistencia_correcoes_*; ocorrências pós-painel",
    "auditoria_pendencias_impeditivas_registros_corrig.csv; auditoria_registros_validados_*; manifesto_linhagem.json"
  )
  validados_pedido <- isTRUE(get0("MONITORA_GERAR_REGISTROS_VALIDADOS", ifnotfound = FALSE, inherits = TRUE))
  validados_gerado_run <- isTRUE(get0("MONITORA_REGISTROS_VALIDADOS_GERADO", ifnotfound = FALSE, inherits = TRUE))
  pendente <- isTRUE(get0("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS", ifnotfound = FALSE, inherits = TRUE)) ||
    isTRUE(get0("MONITORA_PERSISTENCIA_DERIVACOES_PENDENTES", ifnotfound = FALSE, inherits = TRUE))
  status_validados <- if (info[[5L]]$existe && validados_gerado_run) {
    "criado_nesta_execucao"
  } else if (info[[5L]]$existe && !validados_gerado_run) {
    "arquivo_preexistente_nao_aprovado_nesta_execucao"
  } else if (!validados_pedido) {
    "nao_solicitado"
  } else if (pendente) {
    "bloqueado_por_pendencias_explicitas"
  } else {
    "ausente_inesperado"
  }
  status_prod <- c("detectado", vapply(info[1:4], function(x) if (isTRUE(x$existe)) "criado" else "nao_materializado", character(1L)), status_validados)

  etapas <- data.table::data.table(
    exec_id = exec_id, build = as.character(get0("MONITORA_SCRIPT_BUILD_ID", ifnotfound = NA_character_, inherits = TRUE)),
    contexto = as.character(contexto)[1L], ordem = seq_along(nomes_etapa), etapa = nomes_etapa,
    origem = c(NA_character_, head(nomes_etapa, -1L)),
    status = status_prod, descricao = descricoes, transformacoes = transformacoes,
    n_arquivos_input = c(n_input, rep(NA_integer_, 5L)),
    tamanho_input_bytes = c(bytes_input, rep(NA_real_, 5L)),
    arquivo_produto = c(NA_character_, vapply(info, `[[`, character(1L), "caminho")),
    tamanho_produto_bytes = c(NA_real_, vapply(info, `[[`, numeric(1L), "tamanho")),
    n_linhas = c(NA_integer_, vapply(info, `[[`, integer(1L), "n_linhas")),
    n_colunas = c(NA_integer_, vapply(info, `[[`, integer(1L), "n_colunas")),
    md5_canonico = c(NA_character_, vapply(info, `[[`, character(1L), "md5")),
    evidencias = evidencias,
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S %z")
  )

  eventos <- data.table::copy(data.table::as.data.table(get0("MONITORA_LOG_EXECUCAO", ifnotfound = data.table::data.table(), inherits = TRUE)))
  if (nrow(eventos)) {
    eventos[, `:=`(exec_id = exec_id, build = as.character(get0("MONITORA_SCRIPT_BUILD_ID", ifnotfound = NA_character_, inherits = TRUE)), ordem_evento = seq_len(.N))]
    data.table::setcolorder(eventos, c("exec_id", "build", "ordem_evento", setdiff(names(eventos), c("exec_id", "build", "ordem_evento"))))
  }
  arq_etapas <- file.path(dir_rel, paste0("cadeia_dados_etapas_", exec_id, ".csv"))
  arq_eventos <- file.path(dir_rel, paste0("cadeia_dados_eventos_", exec_id, ".csv"))
  monitora_fwrite(etapas, arq_etapas, na = "")
  monitora_fwrite(eventos, arq_eventos, na = "")
  monitora_fwrite(etapas, file.path(dir_rel, "cadeia_dados_etapas_ultima_execucao.csv"), na = "")
  monitora_fwrite(eventos, file.path(dir_rel, "cadeia_dados_eventos_ultima_execucao.csv"), na = "")

  linhas_md <- c(
    "# Cadeia de dados da execução", "",
    paste0("- Execução: `", exec_id, "`"),
    paste0("- Build: `", get0("MONITORA_SCRIPT_BUILD_ID", ifnotfound = "indefinido", inherits = TRUE), "`"),
    paste0("- Contexto: `", contexto, "`"), "",
    "| Ordem | Etapa | Status | Produto | Evidências |", "|---:|---|---|---|---|",
    vapply(seq_len(nrow(etapas)), function(ii) paste0(
      "| ", etapas$ordem[ii], " | ", etapas$etapa[ii], " | ", etapas$status[ii], " | ",
      ifelse(is.na(etapas$arquivo_produto[ii]), "—", etapas$arquivo_produto[ii]), " | ", etapas$evidencias[ii], " |"
    ), character(1L)), "",
    "O CSV de etapas registra dimensões, tamanhos e hashes disponíveis. O CSV de eventos preserva, na ordem da execução, as transformações, avisos, bloqueios e ações recomendadas. Auditorias detalhadas permanecem nos caminhos indicados; nenhum bloqueio é convertido silenciosamente em aprovação."
  )
  writeLines(linhas_md, file.path(dir_rel, "RELATORIO_CADEIA_DADOS.md"), useBytes = TRUE)
  invisible(list(etapas = etapas, eventos = eventos, diretorio = dir_rel))
}

monitora_correcao_gravar_trilha_semantica <- function(corr,
                                                      arquivo_origem = NA_character_,
                                                      fase = "sessao_painel",
                                                      status = "registrada",
                                                      contexto = "") {
  if (!isTRUE(get0("MONITORA_GRAVAR_TRILHA_SEMANTICA_CORRECOES", ifnotfound = TRUE, inherits = TRUE))) return(invisible(data.table::data.table()))
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(invisible(data.table::data.table()))
  template <- monitora_correcao_template()
  for (cc in setdiff(names(template), names(corr))) corr[, (cc) := NA_character_]
  corr <- monitora_replay_preparar_ledger(corr, origem = arquivo_origem, abortar = TRUE)
  corr[, trilha_schema := MONITORA_REPLAY_SCHEMA_ATUAL]
  corr[, script_versao_replay := as.character(get0("MONITORA_SCRIPT_VERSAO", ifnotfound = "indefinida", inherits = TRUE))]
  corr[, exec_id_registro := get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)]
  corr[, fase_trilha := as.character(fase)]
  corr[, status_trilha := as.character(status)]
  corr[, contexto_trilha := as.character(contexto)]
  corr[, arquivo_origem_trilha := as.character(arquivo_origem)[1]]
  corr[, data_hora_trilha := format(Sys.time(), "%Y-%m-%d %H:%M:%S %z")]
  corr[, hash_operacao_semantica := monitora_correcao_assinatura_linha_semantica(.SD)]
  corr_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE)
  dir.create(corr_dir, showWarnings = FALSE, recursive = TRUE)
  exec_id <- get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)
  if (grepl("^replay", as.character(fase))) {
    replay_old <- get0("MONITORA_TRILHA_SEMANTICA_REPLAY", ifnotfound = data.table::data.table(), inherits = TRUE)
    MONITORA_TRILHA_SEMANTICA_REPLAY <<- data.table::rbindlist(list(replay_old, corr), fill = TRUE, use.names = TRUE)
    if ("event_item_id" %in% names(MONITORA_TRILHA_SEMANTICA_REPLAY)) MONITORA_TRILHA_SEMANTICA_REPLAY <<- MONITORA_TRILHA_SEMANTICA_REPLAY[!duplicated(event_item_id)]
    MONITORA_LINHAGEM_STATUS <<- "estado_reconstruido_por_replay_semantico"
  } else {
    sess_old <- get0("MONITORA_TRILHA_SEMANTICA_SESSAO", ifnotfound = data.table::data.table(), inherits = TRUE)
    MONITORA_TRILHA_SEMANTICA_SESSAO <<- data.table::rbindlist(list(sess_old, corr), fill = TRUE, use.names = TRUE)
    if ("event_item_id" %in% names(MONITORA_TRILHA_SEMANTICA_SESSAO)) MONITORA_TRILHA_SEMANTICA_SESSAO <<- MONITORA_TRILHA_SEMANTICA_SESSAO[!duplicated(event_item_id)]
  }
 ### Evidência operacional da sessão: nome explícito, nunca "consolidada".
 ### O ledger cumulativo e portátil é escrito exclusivamente em linhagem/.
  sessao_exportar <- if (grepl("^replay", as.character(fase))) MONITORA_TRILHA_SEMANTICA_REPLAY else MONITORA_TRILHA_SEMANTICA_SESSAO
  arq_exec <- file.path(corr_dir, paste0("correcoes_semanticas_", fase, "_", exec_id, ".csv"))
  monitora_fwrite(sessao_exportar, arq_exec, na = "")
  if (!file.exists(arq_exec) || !isTRUE(file.info(arq_exec)$size > 0L)) {
    stop("Trilha semântica não materializada; aplicação bloqueada antes do checkpoint (evidência da sessão): ", arq_exec, call. = FALSE)
  }
  if (exists("monitora_log_registrar_evento", mode = "function", inherits = TRUE)) {
    monitora_log_registrar_evento("trilha_semantica_correcoes", "INFO", arq_exec, paste0(nrow(corr), " item(ns) auditável(is) registrados na trilha semântica da sessão"), "para replay futuro use somente 02_painel_correcoes/linhagem/correcoes_semanticas_consolidada.csv")
  }
  invisible(corr[])
}

monitora_correcao_preparar_arquivo_sessao_pos_replay <- function() {
  corr_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE)
  dir.create(corr_dir, showWarnings = FALSE, recursive = TRUE)
  exec_id <- get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)
  arq <- file.path(corr_dir, paste0("correcoes_campos_sessao_", exec_id, ".csv"))
  try(unlink(arq), silent = TRUE)
  MONITORA_ARQUIVO_CORRECOES_CAMPOS <<- arq
  MONITORA_CORRECOES_ARQUIVO_EXISTE <<- FALSE
  arq
}

monitora_correcao_reaplicar_arquivo_semantico <- function(dt,
                                                          arquivo,
                                                          dicionario = NULL,
                                                          contexto = "pre_painel") {
  tempo_replay_inicio <- proc.time()[["elapsed"]]
  perf_replay <- function(etapa, detalhe, objeto = NULL) {
    if (exists("monitora_perf_registrar_checkpoint", mode = "function", inherits = TRUE)) {
      try(monitora_perf_registrar_checkpoint(etapa, detalhe, objeto), silent = TRUE)
    }
    invisible(NULL)
  }
 ### marcar replay semântico antes da auditoria interna de persistência.
 ### A própria função audita persistência antes de retornar; portanto o marcador
 ### precisa existir antes de chamar monitora_correcao_aplicar_operacoes .
  MONITORA_REPLAY_SEMANTICO_EM_EXECUCAO <<- TRUE
  MONITORA_ARQUIVO_CORRECOES_CAMPOS_REAPLICADO <<- arquivo
  on.exit({
    MONITORA_REPLAY_SEMANTICO_EM_EXECUCAO <<- FALSE
  }, add = TRUE)
  if (!monitora_correcao_arquivo_tem_operacoes(arquivo)) {
    if (exists("monitora_log_registrar_evento", mode = "function", inherits = TRUE)) {
      monitora_log_registrar_evento("reaplicacao_correcoes", "INFO", arquivo, "Arquivo de correções anteriores não encontrado, vazio ou sem operações", "replay ignorado")
    }
    return(dt)
  }
  corr <- monitora_correcao_ler_operacoes_semanticas(arquivo)
  corr <- monitora_replay_preparar_ledger(corr, origem = arquivo, abortar = TRUE)
  aud_validacao <- attr(corr, "auditoria_validacao_replay")
  corr <- monitora_replay_compilar_para_atual(corr, dt, dicionario = dicionario, abortar = TRUE)
  perf_replay("replay_semantico_preflight_inicio", "ledger v2 validado/compilado; iniciando preflight sem mutação", dt)
  n_sem <- tryCatch(monitora_correcao_contar_operacoes_semanticas(corr), error = function(e) nrow(corr))
  if (exists("monitora_correcao_console_msg", mode = "function", inherits = TRUE)) {
    monitora_correcao_console_msg("Reaplicando correções semânticas anteriores antes do painel: ", n_sem, " operação(ões) semântica(s), arquivo=", arquivo, ".")
  }
 ### Preflight no motor único sobre cópia isolada. Qualquer falha é bloqueada
 ### antes da mutação da base viva; o ledger compilado é o único plano aplicado.
  preflight <- monitora_correcao_aplicar_plano_atomico_sessao(
    data.table::copy(dt), data.table::copy(corr), dicionario = dicionario,
    arquivo_correcao = "preflight_replay_semantico_v2", silencioso = TRUE, registrar_perf = FALSE
  )
  classificacao_preflight <- monitora_replay_classificar_preflight(corr, preflight)
  if (isTRUE(preflight$falha) || any(classificacao_preflight$classificacao_preflight == "conflito")) stop("Replay bloqueado no preflight atômico; nenhuma mutação foi consolidada.", call. = FALSE)
  rm(preflight)
  perf_replay("replay_semantico_preflight_fim", "preflight atômico aprovado; nenhuma mutação consolidada até este marco", dt)
  monitora_correcao_gravar_trilha_semantica(corr, arquivo_origem = arquivo, fase = "replay_pre_painel", status = "validada_preflight", contexto = contexto)
  ids_noop <- classificacao_preflight[classificacao_preflight == "ja_satisfeito", event_id]
  corr_aplicar <- corr[!(event_id %in% ids_noop)]
  if (nrow(corr_aplicar)) {
    arq_compilado <- tempfile(pattern = "monitora_replay_compilado_", fileext = ".csv")
    on.exit(try(unlink(arq_compilado), silent = TRUE), add = TRUE)
    monitora_fwrite(corr_aplicar, arq_compilado, na = "")
    dt2 <- monitora_correcao_aplicar_arquivo(dt, arq_compilado, dicionario = dicionario)
    monitora_linhagem_registrar_aplicacoes(corr_aplicar, "replay_pre_painel", "aplicada", arquivo)
  } else {
    dt2 <- dt
  }
  if (length(ids_noop)) monitora_linhagem_registrar_aplicacoes(corr[event_id %in% ids_noop], "replay_pre_painel", "ja_satisfeito", arquivo)
  duracao_total_replay <- proc.time()[["elapsed"]] - tempo_replay_inicio
  perf_replay("replay_semantico_aplicacao_fim", paste0("replay aplicado/confirmado; duração integral observada=", sprintf("%.3f", duracao_total_replay), "s"), dt2)
  MONITORA_CORRECOES_REAPLICADAS_ARQUIVO <<- arquivo
  MONITORA_CORRECOES_REAPLICADAS_N_ITENS <<- nrow(corr)
  MONITORA_CORRECOES_REAPLICADAS_N_OPERACOES_SEMANTICAS <<- n_sem
  MONITORA_CORRECOES_REAPLICADAS_PRE_PAINEL <<- TRUE
  aud <- data.table::data.table(
    data_hora = format(Sys.time(), "%Y-%m-%d %H:%M:%S %z"),
    exec_id = get0("MONITORA_EXEC_ID", ifnotfound = NA_character_, inherits = TRUE),
    contexto = contexto,
    arquivo_reaplicado = arquivo,
    n_itens_auditaveis = nrow(corr),
    n_operacoes_semanticas = n_sem,
    duracao_total_replay_seg = round(duracao_total_replay, 3),
    observacao = "Correções anteriores reaplicadas antes dos relatórios pré-painel e antes da abertura do Shiny. O arquivo de sessão atual foi separado para evitar reaplicação duplicada."
  )
  corr_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE)
  log_dir <- get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE)
  dir.create(corr_dir, showWarnings = FALSE, recursive = TRUE)
  dir.create(log_dir, showWarnings = FALSE, recursive = TRUE)
  if (!is.null(aud_validacao)) try(monitora_fwrite(aud_validacao, file.path(corr_dir, "auditoria_validacao_replay_v2_ultima_execucao.csv"), na = ""), silent = TRUE)
  try(monitora_fwrite(classificacao_preflight, file.path(corr_dir, "auditoria_preflight_replay_v2_ultima_execucao.csv"), na = ""), silent = TRUE)
  try(monitora_fwrite(aud, file.path(corr_dir, "auditoria_reaplicacao_correcoes_anteriores_ultima_execucao.csv"), na = ""), silent = TRUE)
  try(monitora_fwrite(aud, file.path(log_dir, paste0("auditoria_reaplicacao_correcoes_anteriores_", get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE), ".csv")), na = ""), silent = TRUE)
  if (exists("monitora_log_registrar_evento", mode = "function", inherits = TRUE)) {
    monitora_log_registrar_evento("reaplicacao_correcoes", "INFO", arquivo, paste0(n_sem, " operação(ões) semântica(s) anteriores reaplicadas antes do painel"), "diagnósticos pré-painel e contadores devem refletir o estado reaplicado")
  }
  dt2[]
}


### - replay semântico estável e comparação por oráculo ----------------
### O oráculo é somente uma referência de validação. Nenhum arquivo da pasta do
### oráculo é usado como entrada operacional do pipeline. O resultado esperado é
### que o input bruto + correcoes_semanticas.csv reproduza o estado corrigido da
### run-oráculo, ignorando apenas metadados legitimamente dependentes do caminho
### local de execução, como MONITORA_CAMINHO_ARQUIVO_ENTRADA.

monitora_oraculo_fwrite <- function(x, path) {
  dir.create(dirname(path), showWarnings = FALSE, recursive = TRUE)
  if (exists("monitora_fwrite", mode = "function", inherits = TRUE)) {
    monitora_fwrite(x, path, na = "")
  } else {
    data.table::fwrite(x, path, na = "")
  }
  invisible(path)
}

monitora_oraculo_ler_csv <- function(path) {
  if (!nzchar(path) || !file.exists(path)) return(data.table::data.table())
  tryCatch(
    data.table::fread(path, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character", showProgress = FALSE),
    error = function(e) data.table::data.table(.erro_leitura = conditionMessage(e), .arquivo = path)
  )
}

monitora_oraculo_dir_resolver <- function() {
  if (!isTRUE(get0("MONITORA_COMPARAR_REPLAY_COM_ORACULO", ifnotfound = FALSE, inherits = TRUE))) return("")
  dir_cfg <- trimws(as.character(get0("MONITORA_DIR_RUN_ORACULO", ifnotfound = "", inherits = TRUE))[1])
  candidatos <- c(
    dir_cfg,
    file.path(get0("MONITORA_INPUT_DIR", ifnotfound = "input", inherits = TRUE), "oraculo_replay"),
    file.path(get0("MONITORA_INPUT_DIR", ifnotfound = "input", inherits = TRUE), "referencia_replay"),
    file.path(get0("MONITORA_INPUT_DIR", ifnotfound = "input", inherits = TRUE), "diagnostico_run_referencia")
  )
  candidatos <- unique(candidatos[nzchar(candidatos)])
  candidatos[file.exists(candidatos) & file.info(candidatos)$isdir][1] %||% ""
}

monitora_oraculo_localizar <- function(subcaminhos) {
  base <- monitora_oraculo_dir_resolver()
  if (!nzchar(base)) return("")
  candidatos <- file.path(base, subcaminhos)
  candidatos <- candidatos[file.exists(candidatos)]
  if (length(candidatos)) normalizePath(candidatos[1], winslash = "/", mustWork = FALSE) else ""
}

monitora_oraculo_output_dir <- function() {
  file.path(
    get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
    "03_auditorias", "replay_semantico"
  )
}

monitora_oraculo_identidade <- function(dt) {
  if (!is.data.table(dt)) dt <- data.table::as.data.table(dt)
  candidatos <- c(
    "MONITORA_UUID_REGISTRO_CANONICO",
    "uuid (amostragem/registro)",
    "amostragem/registro/uuid",
    "uuid_registro"
  )
  diagnosticos <- lapply(candidatos, function(cc) {
    existe <- cc %in% names(dt)
    chave <- if (existe) trimws(as.character(dt[[cc]])) else character()
    if (length(chave)) chave[is.na(chave)] <- ""
    n_vazios <- if (existe) sum(!nzchar(chave)) else NA_integer_
    duplicadas <- if (existe && length(chave)) unique(chave[nzchar(chave) & duplicated(chave)]) else character()
    data.table::data.table(
      coluna = cc,
      existe = existe,
      n_linhas = nrow(dt),
      n_vazios = n_vazios,
      n_chaves_unicas = if (existe) data.table::uniqueN(chave[nzchar(chave)]) else NA_integer_,
      n_grupos_duplicados = if (existe) length(duplicadas) else NA_integer_,
      identidade_valida = existe && nrow(dt) > 0L && n_vazios == 0L && length(duplicadas) == 0L
    )
  })
  diagnostico <- data.table::rbindlist(diagnosticos, fill = TRUE)
  escolhida <- diagnostico[identidade_valida %in% TRUE, coluna][1L]
  if (!length(escolhida) || is.na(escolhida) || !nzchar(escolhida)) {
    return(list(
      chave = sprintf("identidade_invalida_linha_%08d", seq_len(nrow(dt))),
      coluna = NA_character_,
      tipo = "identidade_unica_indisponivel",
      valida = FALSE,
      diagnostico = diagnostico
    ))
  }
  chave <- trimws(as.character(dt[[escolhida]]))
  chave[is.na(chave)] <- ""
  list(
    chave = chave,
    coluna = escolhida,
    tipo = if (identical(escolhida, "MONITORA_UUID_REGISTRO_CANONICO")) "uuid_registro_canonico" else "uuid_registro_compativel",
    valida = TRUE,
    diagnostico = diagnostico
  )
}

monitora_oraculo_key <- function(dt, preferir_uuid = TRUE) {
  identidade <- monitora_oraculo_identidade(dt)
  chave <- identidade$chave
  attr(chave, "coluna_identidade") <- identidade$coluna
  attr(chave, "identidade_valida") <- identidade$valida
  chave
}

monitora_oraculo_reconciliar_colunas <- function(ref, cur) {
  ref <- data.table::as.data.table(data.table::copy(ref))
  cur <- data.table::as.data.table(cur)
  somente_ref <- setdiff(names(ref), names(cur))
  somente_cur <- setdiff(names(cur), names(ref))
  if (!length(somente_ref) || !length(somente_cur) ||
      !exists("monitora_correcao_normalizar_nome_coluna", mode = "function", inherits = TRUE)) {
    return(list(ref = ref, mapa = data.table::data.table(), ambiguidades = data.table::data.table()))
  }
  mapa_ref <- data.table::data.table(
    coluna_oraculo = somente_ref,
    identidade_semantica = monitora_correcao_normalizar_nome_coluna(somente_ref)
  )
  mapa_cur <- data.table::data.table(
    coluna_atual = somente_cur,
    identidade_semantica = monitora_correcao_normalizar_nome_coluna(somente_cur)
  )
  cont_ref <- mapa_ref[, .(n_oraculo = .N), by = identidade_semantica]
  cont_cur <- mapa_cur[, .(n_atual = .N), by = identidade_semantica]
  mapa <- merge(mapa_ref, mapa_cur, by = "identidade_semantica", all = FALSE, allow.cartesian = TRUE)
  mapa <- merge(mapa, cont_ref, by = "identidade_semantica", all.x = TRUE)
  mapa <- merge(mapa, cont_cur, by = "identidade_semantica", all.x = TRUE)
  mapa[, pareamento_unico := nzchar(identidade_semantica) & n_oraculo == 1L & n_atual == 1L]
  ambiguidades <- mapa[pareamento_unico %in% FALSE]
  mapa_unico <- mapa[pareamento_unico %in% TRUE]
  if (nrow(mapa_unico)) {
    data.table::setnames(ref, old = mapa_unico$coluna_oraculo, new = mapa_unico$coluna_atual, skip_absent = FALSE)
  }
  list(ref = ref, mapa = mapa_unico[], ambiguidades = ambiguidades[])
}

monitora_oraculo_comparar_registros_corrig <- function(dt_atual, fase = "pos_replay_final_reconciliado") {
  if (!isTRUE(get0("MONITORA_COMPARAR_REPLAY_COM_ORACULO", ifnotfound = FALSE, inherits = TRUE))) return(invisible(NULL))
  arq_ref <- monitora_oraculo_localizar(c(
    "output_01_produtos_dados/registros_corrig.csv",
    "output/01_produtos_dados/registros_corrig.csv",
    "01_produtos_dados/registros_corrig.csv",
    "registros_corrig.csv"
  ))
  out_dir <- monitora_oraculo_output_dir()
  dir.create(out_dir, showWarnings = FALSE, recursive = TRUE)
  exec_id <- get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)
  resumo_base <- data.table::data.table(
    data_hora = format(Sys.time(), "%Y-%m-%d %H:%M:%S %z"),
    exec_id = exec_id,
    fase = fase,
    oraculo_dir = monitora_oraculo_dir_resolver(),
    arquivo_oraculo_registros_corrig = arq_ref,
    status = if (nzchar(arq_ref)) "oraculo_encontrado" else "oraculo_nao_encontrado"
  )
  if (!nzchar(arq_ref)) {
    resumo_base[, `:=`(
      status_convergencia = "oraculo_nao_encontrado",
      replay_equivalente_ao_oraculo = "NAO",
      interpretacao = "A comparação foi solicitada, mas registros_corrig.csv não foi encontrado na pasta-oráculo."
    )]
    arq_resumo_ausente <- file.path(out_dir, paste0("oraculo_registros_corrig_resumo_", fase, ".csv"))
    monitora_oraculo_fwrite(resumo_base, arq_resumo_ausente)
    monitora_oraculo_fwrite(resumo_base, file.path(out_dir, paste0("oraculo_replay_selo_convergencia_", fase, ".csv")))
    msg_ausente <- paste0("Comparação de replay solicitada, mas o registros_corrig.csv da run-oráculo não foi encontrado. Ver ", arq_resumo_ausente, ".")
    if (isTRUE(get0("MONITORA_REPLAY_ORACULO_ABORTAR_DIVERGENCIA", ifnotfound = FALSE, inherits = TRUE))) {
      stop(msg_ausente, call. = FALSE)
    }
    warning(msg_ausente, call. = FALSE)
    return(invisible(resumo_base[]))
  }
  ref <- monitora_oraculo_ler_csv(arq_ref)
  cur <- data.table::as.data.table(data.table::copy(dt_atual))
  if (!nrow(ref) || ".erro_leitura" %in% names(ref)) {
    erro_ref <- if (".erro_leitura" %in% names(ref)) as.character(ref$.erro_leitura[1L]) else "arquivo sem registros"
    resumo_base[, `:=`(
      status = "oraculo_invalido",
      status_convergencia = "oraculo_invalido",
      replay_equivalente_ao_oraculo = "NAO",
      interpretacao = paste0("O registros_corrig.csv da run-oráculo não pôde ser validado: ", erro_ref)
    )]
    arq_resumo_invalido <- file.path(out_dir, paste0("oraculo_registros_corrig_resumo_", fase, ".csv"))
    monitora_oraculo_fwrite(resumo_base, arq_resumo_invalido)
    monitora_oraculo_fwrite(resumo_base, file.path(out_dir, paste0("oraculo_replay_selo_convergencia_", fase, ".csv")))
    msg_invalido <- paste0("O registros_corrig.csv da run-oráculo é inválido: ", erro_ref, ". Ver ", arq_resumo_invalido, ".")
    if (isTRUE(get0("MONITORA_REPLAY_ORACULO_ABORTAR_DIVERGENCIA", ifnotfound = FALSE, inherits = TRUE))) {
      stop(msg_invalido, call. = FALSE)
    }
    warning(msg_invalido, call. = FALSE)
    return(invisible(resumo_base[]))
  }
  reconc_colunas <- monitora_oraculo_reconciliar_colunas(ref, cur)
  ref <- reconc_colunas$ref
  monitora_oraculo_fwrite(reconc_colunas$mapa, file.path(out_dir, paste0("oraculo_registros_corrig_reconciliacao_colunas_", fase, ".csv")))
  monitora_oraculo_fwrite(reconc_colunas$ambiguidades, file.path(out_dir, paste0("oraculo_registros_corrig_reconciliacao_colunas_ambiguas_", fase, ".csv")))
  for (cc in names(ref)) data.table::set(ref, j = cc, value = as.character(ref[[cc]]))
  for (cc in names(cur)) data.table::set(cur, j = cc, value = as.character(cur[[cc]]))
  col_ref <- names(ref); col_cur <- names(cur); col_comuns <- intersect(col_ref, col_cur)
  resumo <- data.table::copy(resumo_base)
  resumo[, `:=`(
    n_linhas_oraculo = nrow(ref),
    n_linhas_atual = nrow(cur),
    n_colunas_oraculo = length(col_ref),
    n_colunas_atual = length(col_cur),
    n_colunas_comuns = length(col_comuns),
    n_colunas_reconciliadas_por_alias = nrow(reconc_colunas$mapa),
    n_pareamentos_coluna_ambiguos = nrow(reconc_colunas$ambiguidades),
    n_colunas_so_oraculo = length(setdiff(col_ref, col_cur)),
    n_colunas_so_atual = length(setdiff(col_cur, col_ref))
  )]
  diagnostico_colunas <- data.table::rbindlist(list(
    data.table::data.table(tipo = "coluna_so_oraculo", coluna = setdiff(col_ref, col_cur)),
    data.table::data.table(tipo = "coluna_so_atual", coluna = setdiff(col_cur, col_ref)),
    data.table::data.table(tipo = "coluna_comum", coluna = col_comuns)
  ), fill = TRUE)
  monitora_oraculo_fwrite(diagnostico_colunas, file.path(out_dir, paste0("oraculo_registros_corrig_colunas_", fase, ".csv")))
  identidade_ref <- monitora_oraculo_identidade(ref)
  identidade_cur <- monitora_oraculo_identidade(cur)
  diagnostico_identidade <- data.table::rbindlist(list(
    data.table::copy(identidade_ref$diagnostico)[, origem := "oraculo"],
    data.table::copy(identidade_cur$diagnostico)[, origem := "atual"]
  ), fill = TRUE, use.names = TRUE)
  data.table::setcolorder(diagnostico_identidade, c("origem", setdiff(names(diagnostico_identidade), "origem")))
  monitora_oraculo_fwrite(diagnostico_identidade, file.path(out_dir, paste0("oraculo_registros_corrig_identidade_", fase, ".csv")))
  identidade_compativel <- isTRUE(identidade_ref$valida) && isTRUE(identidade_cur$valida) &&
    identical(as.character(identidade_ref$coluna), as.character(identidade_cur$coluna))
  data.table::set(ref, j = ".chave_oraculo_replay", value = identidade_ref$chave)
  data.table::set(cur, j = ".chave_oraculo_replay", value = identidade_cur$chave)
  dup_ref <- ref[, .N, by = .chave_oraculo_replay][N > 1]
  dup_cur <- cur[, .N, by = .chave_oraculo_replay][N > 1]
  keys_ref <- unique(ref$.chave_oraculo_replay); keys_cur <- unique(cur$.chave_oraculo_replay)
  somente_ref <- setdiff(keys_ref, keys_cur)
  somente_cur <- setdiff(keys_cur, keys_ref)
  comum <- intersect(keys_ref, keys_cur)
  resumo[, `:=`(
    identidade_coluna_oraculo = as.character(identidade_ref$coluna),
    identidade_coluna_atual = as.character(identidade_cur$coluna),
    identidade_tipo_oraculo = as.character(identidade_ref$tipo),
    identidade_tipo_atual = as.character(identidade_cur$tipo),
    identidade_unica_oraculo = isTRUE(identidade_ref$valida),
    identidade_unica_atual = isTRUE(identidade_cur$valida),
    identidade_compativel = identidade_compativel,
    n_chaves_oraculo = length(keys_ref),
    n_chaves_atual = length(keys_cur),
    n_chaves_comuns = length(comum),
    n_chaves_so_oraculo = length(somente_ref),
    n_chaves_so_atual = length(somente_cur),
    n_chaves_duplicadas_oraculo = nrow(dup_ref),
    n_chaves_duplicadas_atual = nrow(dup_cur)
  )]
  amostra_chaves <- data.table::rbindlist(list(
    data.table::data.table(tipo = "chave_so_oraculo", chave = head(somente_ref, 5000)),
    data.table::data.table(tipo = "chave_so_atual", chave = head(somente_cur, 5000))
  ), fill = TRUE)
  monitora_oraculo_fwrite(amostra_chaves, file.path(out_dir, paste0("oraculo_registros_corrig_chaves_diferentes_", fase, ".csv")))
  cols_ignorar_padrao <- grep("^(linha_|arquivo_|data_hora_auditoria|exec_id$|\\.chave_oraculo_replay$)", col_comuns, value = TRUE)
  cols_ignorar_config <- as.character(get0("MONITORA_ORACULO_COLUNAS_IGNORAR", ifnotfound = character(0), inherits = TRUE))
  cols_ignorar_config <- cols_ignorar_config[!is.na(cols_ignorar_config) & nzchar(cols_ignorar_config)]
  cols_ignorar <- unique(c(cols_ignorar_padrao, intersect(cols_ignorar_config, col_comuns)))
  cols_cmp <- setdiff(col_comuns, cols_ignorar)
  comum_comparavel <- if (isTRUE(identidade_compativel)) comum else character()
  ref_u <- ref[!duplicated(.chave_oraculo_replay) & .chave_oraculo_replay %in% comum_comparavel]
  cur_u <- cur[!duplicated(.chave_oraculo_replay) & .chave_oraculo_replay %in% comum_comparavel]
  data.table::setkey(ref_u, .chave_oraculo_replay)
  data.table::setkey(cur_u, .chave_oraculo_replay)
  ref_u <- ref_u[comum_comparavel]
  cur_u <- cur_u[comum_comparavel]
  dif_cols <- data.table::data.table()
  dif_cells <- data.table::data.table()
  if (length(cols_cmp) && length(comum_comparavel)) {
    dif_list <- vector("list", length(cols_cmp))
    names(dif_list) <- cols_cmp
    sample_list <- list(); si <- 0L
    for (cc in cols_cmp) {
      a <- ref_u[[cc]]; b <- cur_u[[cc]]
      a[is.na(a)] <- ""; b[is.na(b)] <- ""
      idx <- which(a != b)
      dif_list[[cc]] <- data.table::data.table(coluna = cc, n_diferencas = length(idx), n_chaves_comparadas = length(comum_comparavel))
      if (length(idx) && si < 5000L) {
        take <- head(idx, min(length(idx), 5000L - si))
        sample_list[[length(sample_list) + 1L]] <- data.table::data.table(
          chave = ref_u$.chave_oraculo_replay[take], coluna = cc, valor_oraculo = a[take], valor_atual = b[take]
        )
        si <- si + length(take)
      }
    }
    dif_cols <- data.table::rbindlist(dif_list, fill = TRUE)
    dif_cols <- dif_cols[order(-n_diferencas, coluna)]
    dif_cells <- if (length(sample_list)) data.table::rbindlist(sample_list, fill = TRUE) else data.table::data.table()
  }
  resumo[, n_colunas_com_diferencas_valor := if (nrow(dif_cols)) sum(dif_cols$n_diferencas > 0, na.rm = TRUE) else 0L]
  resumo[, n_celulas_diferentes := if (nrow(dif_cols)) sum(dif_cols$n_diferencas, na.rm = TRUE) else 0L]
  resumo[, n_celulas_diferentes_amostradas := nrow(dif_cells)]
  resumo[, colunas_ignoradas_na_comparacao := paste(cols_ignorar, collapse = " | ")]
  resumo[, status_convergencia := ifelse(
    identidade_compativel %in% TRUE & n_linhas_oraculo == n_linhas_atual &
      n_chaves_duplicadas_oraculo == 0 & n_chaves_duplicadas_atual == 0 &
      n_chaves_so_oraculo == 0 & n_chaves_so_atual == 0 &
      n_colunas_so_oraculo == 0 & n_colunas_so_atual == 0 &
      n_colunas_com_diferencas_valor == 0,
    "convergente_com_oraculo", "divergente_do_oraculo"
  )]
  resumo[, replay_equivalente_ao_oraculo := ifelse(status_convergencia == "convergente_com_oraculo", "SIM", "NAO")]
  resumo[, interpretacao := ifelse(
    replay_equivalente_ao_oraculo == "SIM",
    "O input bruto somado à trilha semântica reproduziu o registros_corrig da run-oráculo; diferenças de caminho local foram ignoradas quando configuradas.",
    "O replay semântico ainda diverge do oráculo, ou não há identidade única compatível; consultar identidade, chaves, colunas e amostras de células divergentes."
  )]
  selo_oraculo <- resumo[, .(
    data_hora, exec_id, fase, replay_equivalente_ao_oraculo, status_convergencia,
    n_linhas_oraculo, n_linhas_atual, identidade_coluna_oraculo,
    identidade_coluna_atual, identidade_compativel,
    n_chaves_so_oraculo, n_chaves_so_atual,
    n_colunas_so_oraculo, n_colunas_so_atual, n_colunas_com_diferencas_valor,
    n_celulas_diferentes, colunas_ignoradas_na_comparacao, interpretacao
  )]
  monitora_oraculo_fwrite(resumo, file.path(out_dir, paste0("oraculo_registros_corrig_resumo_", fase, ".csv")))
  monitora_oraculo_fwrite(selo_oraculo, file.path(out_dir, paste0("oraculo_replay_selo_convergencia_", fase, ".csv")))
  monitora_oraculo_fwrite(dif_cols, file.path(out_dir, paste0("oraculo_registros_corrig_diferencas_por_coluna_", fase, ".csv")))
  monitora_oraculo_fwrite(dif_cells, file.path(out_dir, paste0("oraculo_registros_corrig_amostra_celulas_diferentes_", fase, ".csv")))
  if (exists("monitora_log_registrar_evento", mode = "function", inherits = TRUE)) {
    nivel <- if (identical(resumo$status_convergencia[1], "convergente_com_oraculo")) "INFO" else "AVISO"
    monitora_log_registrar_evento("oraculo_replay", nivel, file.path(out_dir, paste0("oraculo_registros_corrig_resumo_", fase, ".csv")), paste0("Comparação do registros_corrig pós-replay com oráculo: ", resumo$status_convergencia[1]), "não usa o oráculo como entrada; apenas audita a convergência")
  }
  if (isTRUE(get0("MONITORA_REPLAY_ORACULO_ABORTAR_DIVERGENCIA", ifnotfound = FALSE, inherits = TRUE)) && !identical(resumo$status_convergencia[1], "convergente_com_oraculo")) {
    stop("Replay semântico divergiu do oráculo em registros_corrig final. Ver output/03_auditorias/replay_semantico/.", call. = FALSE)
  }
  invisible(resumo[])
}

monitora_replay_oraculo_validar_final <- function(dt_final, contexto = "pre_export_registros_corrig") {
  if (!isTRUE(get0("MONITORA_REAPLICAR_CORRECOES_ANTERIORES", ifnotfound = FALSE, inherits = TRUE)) ||
      !isTRUE(get0("MONITORA_COMPARAR_REPLAY_COM_ORACULO", ifnotfound = FALSE, inherits = TRUE))) {
    return(invisible(NULL))
  }
  if (isTRUE(get0("MONITORA_REPLAY_ORACULO_VALIDADO_FINAL", ifnotfound = FALSE, inherits = TRUE))) {
    return(invisible(get0("MONITORA_REPLAY_ORACULO_RESULTADO_FINAL", ifnotfound = NULL, inherits = TRUE)))
  }
  fase <- "pos_replay_final_reconciliado"
  executar <- function() monitora_oraculo_comparar_registros_corrig(dt_final, fase = fase)
  resultado <- if (isTRUE(get0("MONITORA_REPLAY_ORACULO_ABORTAR_DIVERGENCIA", ifnotfound = FALSE, inherits = TRUE))) {
    executar()
  } else {
    tryCatch(executar(), error = function(e) {
      warning("Falha na auditoria opcional do oráculo de replay: ", conditionMessage(e), call. = FALSE)
      NULL
    })
  }
  assign("MONITORA_REPLAY_ORACULO_RESULTADO_FINAL", resultado, envir = .GlobalEnv)
  assign("MONITORA_REPLAY_ORACULO_VALIDADO_FINAL", TRUE, envir = .GlobalEnv)
  if (!is.null(resultado) && nrow(resultado)) {
    status <- as.character(resultado$status_convergencia[1L])
    message("[monitora] Gate final do oráculo de replay: ", status,
            " | contexto=", contexto,
            " | relatórios=output/03_auditorias/replay_semantico/.")
  }
  invisible(resultado)
}

monitora_oraculo_resumo_ocorrencias_localizar <- function(fase_oraculo = "pos_painel") {
  nome <- paste0("resumo_ocorrencias_diagnosticas_", fase_oraculo, ".csv")
  monitora_oraculo_localizar(c(
    file.path("output_correcoes_campos", "ocorrencias_diagnosticas", fase_oraculo, nome),
    file.path("output_correcoes_campos", "relatorios_pos_painel", "ocorrencias_diagnosticas", nome),
    file.path("output_correcoes_campos", "relatorios_pos_correcoes", "ocorrencias_diagnosticas", nome),
    file.path("output_02_painel_correcoes", "ocorrencias_diagnosticas", fase_oraculo, nome),
    file.path("output_02_painel_correcoes", "relatorios_pos_painel", "ocorrencias_diagnosticas", nome),
    file.path("output_02_painel_correcoes", "relatorios_pos_correcoes", "ocorrencias_diagnosticas", nome),
    file.path("output/02_painel_correcoes", "ocorrencias_diagnosticas", fase_oraculo, nome),
    file.path("output/02_painel_correcoes", "relatorios_pos_painel", "ocorrencias_diagnosticas", nome),
    file.path("output/02_painel_correcoes", "relatorios_pos_correcoes", "ocorrencias_diagnosticas", nome),
    nome
  ))
}

monitora_oraculo_comparar_resumo_ocorrencias <- function(fase_atual = "pre_painel", fase_oraculo = "pos_painel") {
  if (!isTRUE(get0("MONITORA_COMPARAR_REPLAY_COM_ORACULO", ifnotfound = FALSE, inherits = TRUE))) return(invisible(NULL))
  out_dir <- monitora_oraculo_output_dir()
  dir.create(out_dir, showWarnings = FALSE, recursive = TRUE)
  arq_ref <- monitora_oraculo_resumo_ocorrencias_localizar(fase_oraculo)
  nome_atual <- paste0("resumo_ocorrencias_diagnosticas_", fase_atual, ".csv")
  candidatos_atual <- c(
    file.path(get0("MONITORA_CORRECOES_DIR", ifnotfound = "output/02_painel_correcoes", inherits = TRUE), "ocorrencias_diagnosticas", fase_atual, nome_atual),
    file.path(get0("MONITORA_CORRECOES_DIR", ifnotfound = "output/02_painel_correcoes", inherits = TRUE), "relatorios_pre_painel", "ocorrencias_diagnosticas", nome_atual),
    file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "02_painel_correcoes", "ocorrencias_diagnosticas", fase_atual, nome_atual),
    file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "02_painel_correcoes", "relatorios_pre_painel", "ocorrencias_diagnosticas", nome_atual)
  )
  arq_atual <- candidatos_atual[file.exists(candidatos_atual)][1] %||% ""
  resumo <- data.table::data.table(
    data_hora = format(Sys.time(), "%Y-%m-%d %H:%M:%S %z"),
    exec_id = get0("MONITORA_EXEC_ID", ifnotfound = NA_character_, inherits = TRUE),
    fase_atual = fase_atual,
    fase_oraculo = fase_oraculo,
    arquivo_atual = arq_atual,
    arquivo_oraculo = arq_ref,
    status = if (nzchar(arq_atual) && nzchar(arq_ref)) "arquivos_encontrados" else "arquivo_ausente"
  )
  if (!nzchar(arq_atual) || !nzchar(arq_ref)) {
    monitora_oraculo_fwrite(resumo, file.path(out_dir, paste0("oraculo_ocorrencias_resumo_", fase_atual, "_vs_", fase_oraculo, ".csv")))
    return(invisible(resumo))
  }
  atual <- monitora_oraculo_ler_csv(arq_atual)
  ref <- monitora_oraculo_ler_csv(arq_ref)
  key <- intersect(c("tipo_ocorrencia", "rotulo_ocorrencia", "severidade"), intersect(names(atual), names(ref)))
  if (!length(key)) key <- intersect(names(atual), names(ref))[1]
  for (cc in names(atual)) data.table::set(atual, j = cc, value = as.character(atual[[cc]]))
  for (cc in names(ref)) data.table::set(ref, j = cc, value = as.character(ref[[cc]]))
  data.table::set(atual, j = ".origem_comparacao", value = "atual")
  data.table::set(ref, j = ".origem_comparacao", value = "oraculo")
  cmp <- merge(
    ref[, c(key, intersect(c("n_linhas", "n_coletas"), names(ref))), with = FALSE],
    atual[, c(key, intersect(c("n_linhas", "n_coletas"), names(atual))), with = FALSE],
    by = key, all = TRUE, suffixes = c("_oraculo", "_atual")
  )
  for (cc in grep("^n_(linhas|coletas)_", names(cmp), value = TRUE)) cmp[[cc]] <- suppressWarnings(as.integer(cmp[[cc]]))
  if (all(c("n_linhas_oraculo", "n_linhas_atual") %in% names(cmp))) cmp[, dif_n_linhas := n_linhas_atual - n_linhas_oraculo]
  if (all(c("n_coletas_oraculo", "n_coletas_atual") %in% names(cmp))) cmp[, dif_n_coletas := n_coletas_atual - n_coletas_oraculo]
  cmp[, status_convergencia := ifelse((is.na(dif_n_linhas) | dif_n_linhas == 0) & (is.na(dif_n_coletas) | dif_n_coletas == 0), "convergente", "divergente")]
  resumo[, `:=`(
    n_ocorrencias_comparadas = nrow(cmp),
    n_ocorrencias_divergentes = sum(cmp$status_convergencia == "divergente", na.rm = TRUE),
    status_convergencia = ifelse(sum(cmp$status_convergencia == "divergente", na.rm = TRUE) == 0, "convergente_com_oraculo", "divergente_do_oraculo")
  )]
  resumo[, ocorrencias_equivalentes_ao_oraculo := ifelse(status_convergencia == "convergente_com_oraculo", "SIM", "NAO")]
  resumo[, interpretacao := ifelse(
    ocorrencias_equivalentes_ao_oraculo == "SIM",
    "As ocorrências diagnósticas da nova run, após replay, convergiram com a fase comparada da run-oráculo.",
    "Há diferenças entre ocorrências diagnósticas da nova run e da run-oráculo; consultar comparativo por tipo."
  )]
  arq_cmp <- file.path(out_dir, paste0("oraculo_ocorrencias_comparativo_", fase_atual, "_vs_", fase_oraculo, ".csv"))
  arq_res <- file.path(out_dir, paste0("oraculo_ocorrencias_resumo_", fase_atual, "_vs_", fase_oraculo, ".csv"))
  arq_selo <- file.path(out_dir, paste0("oraculo_ocorrencias_selo_convergencia_", fase_atual, "_vs_", fase_oraculo, ".csv"))
  monitora_oraculo_fwrite(cmp, arq_cmp)
  monitora_oraculo_fwrite(resumo, arq_res)
  monitora_oraculo_fwrite(resumo[, .(data_hora, exec_id, fase_atual, fase_oraculo, ocorrencias_equivalentes_ao_oraculo, status_convergencia, n_ocorrencias_comparadas, n_ocorrencias_divergentes, interpretacao)], arq_selo)
  if (exists("monitora_log_registrar_evento", mode = "function", inherits = TRUE)) {
    nivel <- if (identical(resumo$status_convergencia[1], "convergente_com_oraculo")) "INFO" else "AVISO"
    monitora_log_registrar_evento("oraculo_replay_ocorrencias", nivel, arq_res, paste0("Comparação de ocorrências diagnósticas: ", resumo$status_convergencia[1]), "esperado: pre_painel pós-replay igual ao pos_painel da run-oráculo")
  }
  invisible(resumo[])
}


monitora_correcao_corrigir_ponto_metro <- function(dt) {
  if (!isTRUE(MONITORA_CORRIGIR_PONTO_METRO_AUTOMATICO)) return(dt)
  dt <- monitora_dt_referenciar(dt)
  chaves <- monitora_correcao_colunas_chave(dt)
  if (is.na(chaves$ponto_amostral) || is.na(chaves$ponto_metro)) return(dt)
  if (!(chaves$ponto_amostral %in% names(dt)) || !(chaves$ponto_metro %in% names(dt))) return(dt)
  ponto <- suppressWarnings(as.numeric(gsub(",", ".", as.character(dt[[chaves$ponto_amostral]]))))
  metro_atual <- suppressWarnings(as.numeric(gsub(",", ".", as.character(dt[[chaves$ponto_metro]]))))
  metro_esperado <- (ponto - 1) / 2
  corrigir <- !is.na(ponto) & ponto >= 1 & ponto <= 101 & !is.na(metro_atual) & abs(metro_atual - metro_esperado) > 1e-9
  if (any(corrigir)) {
    aud <- data.table::data.table(
      linha_indice = which(corrigir),
      ponto_amostral = as.character(dt[[chaves$ponto_amostral]][corrigir]),
      ponto_metro_antes = as.character(dt[[chaves$ponto_metro]][corrigir]),
      ponto_metro_depois = as.character(metro_esperado[corrigir])
    )
    monitora_fwrite(aud, file.path(MONITORA_LOG_DIR, paste0("auditoria_correcao_ponto_metro_", MONITORA_EXEC_ID, ".csv")), na = "")
    data.table::set(dt, i = which(corrigir), j = chaves$ponto_metro, value = as.character(metro_esperado[corrigir]))
    monitora_log_registrar_evento("correcao_ponto_metro", "AVISO", NA_character_, paste0(sum(corrigir), " valor(es) de ponto_metro corrigidos por ponto_amostral"), "ver auditoria_correcao_ponto_metro")
  } else {
    monitora_log_registrar_evento("correcao_ponto_metro", "INFO", NA_character_, "Nenhuma inconformidade detectada", "ponto_metro validado por ponto_amostral")
  }
  dt[]
}

monitora_correcao_validar_dependencias <- function(dt, deps, dicionario = NULL) {
  if (!isTRUE(MONITORA_VALIDAR_CONDICIONAIS_CORRECOES)) return(data.table::data.table())
  if (is.null(deps) || nrow(deps) == 0) return(data.table::data.table())
  dt <- data.table::as.data.table(dt)

  deps_dt <- data.table::as.data.table(deps)
  regras_brutas <- deps_dt[!is.na(parent_name) & nzchar(parent_name) & !is.na(token) & nzchar(token) & !is.na(dependent_name) & nzchar(dependent_name)]
  n_regras_brutas <- nrow(regras_brutas)
  regras_unicas <- unique(regras_brutas, by = c("parent_name", "token", "dependent_name", "fonte"))
  n_regras_unicas <- nrow(regras_unicas)
  if (n_regras_brutas > 0L) {
    monitora_fwrite(regras_brutas, file.path(MONITORA_LOG_DIR, paste0("auditoria_dependencias_condicionais_regras_brutas_", MONITORA_EXEC_ID, ".csv")), na = "")
    monitora_fwrite(regras_brutas, file.path(MONITORA_CORRECOES_DIR, "auditoria_dependencias_condicionais_regras_brutas_ultima_execucao.csv"), na = "")
    monitora_fwrite(regras_unicas, file.path(MONITORA_LOG_DIR, paste0("auditoria_dependencias_condicionais_regras_unicas_", MONITORA_EXEC_ID, ".csv")), na = "")
    monitora_fwrite(regras_unicas, file.path(MONITORA_CORRECOES_DIR, "auditoria_dependencias_condicionais_regras_unicas_ultima_execucao.csv"), na = "")
  }

  regras_todas <- monitora_correcao_resolver_dependencias(dt, deps, dicionario, incluir_bloqueadas = TRUE)
  if (nrow(regras_todas) > 0L) {
    arq_regras <- file.path(MONITORA_LOG_DIR, paste0("auditoria_dependencias_condicionais_regras_resolvidas_", MONITORA_EXEC_ID, ".csv"))
    monitora_fwrite(regras_todas, arq_regras, na = "")
    monitora_fwrite(regras_todas, file.path(MONITORA_CORRECOES_DIR, "auditoria_dependencias_condicionais_regras_resolvidas_ultima_execucao.csv"), na = "")
  }
  regras <- regras_todas[status_regra == "ok"]
  n_deps <- nrow(regras)
  n_ignoradas <- nrow(regras_todas[status_regra != "ok"])
  monitora_correcao_console_msg(
    "Iniciando validação de dependências condicionais: ",
    n_regras_brutas, " regra(s) bruta(s) extraída(s) do(s) XLSForm(s); ",
    n_regras_unicas, " regra(s) única(s) por parent/token/dependent/fonte; ",
    nrow(regras_todas), " regra(s) resolvida(s)/classificada(s); ",
    n_deps, " regra(s) validadas linha-a-linha; ",
    n_ignoradas, " regra(s) documentadas mas ignoradas/bloqueadas/sem coluna resolvida."
  )
  if (n_deps == 0L) {
    monitora_log_registrar_evento(
      "dependencias_condicionais", "INFO", NA_character_,
      paste0("Nenhuma regra condicional acionável para validação linha-a-linha; regras_brutas=", n_regras_brutas, "; regras_unicas=", n_regras_unicas, "; regras_resolvidas=", nrow(regras_todas)),
      "OK; consultar auditoria_dependencias_condicionais_regras_resolvidas_* para universo completo"
    )
    return(data.table::data.table())
  }

  out <- vector("list", n_deps)
  parent_cache <- new.env(parent = emptyenv())
  vazio_cache <- new.env(parent = emptyenv())

  for (ii in seq_len(n_deps)) {
    if (ii == 1L || ii == n_deps || ii %% 25L == 0L) {
      monitora_correcao_console_msg("Validação de dependências condicionais: regra ", ii, "/", n_deps, ".")
    }

    parent_col <- regras$parent_col[ii]
    dep_col <- regras$dependent_col[ii]
    token <- regras$token[ii]
    if (is.na(parent_col) || is.na(dep_col) || !(parent_col %in% names(dt)) || !(dep_col %in% names(dt))) next
    if (monitora_correcao_coluna_protegida(parent_col) || monitora_correcao_coluna_protegida(dep_col)) next

    chave_parent <- paste(parent_col, token, sep = "\r")
    if (exists(chave_parent, envir = parent_cache, inherits = FALSE)) {
      ativo <- get(chave_parent, envir = parent_cache, inherits = FALSE)
    } else {
      ativo <- monitora_correcao_token_presente_vec(dt[[parent_col]], token)
      assign(chave_parent, ativo, envir = parent_cache)
    }

    if (exists(dep_col, envir = vazio_cache, inherits = FALSE)) {
      vazio_dep <- get(dep_col, envir = vazio_cache, inherits = FALSE)
    } else {
      vazio_dep <- monitora_correcao_vazio_vec(dt[[dep_col]])
      assign(dep_col, vazio_dep, envir = vazio_cache)
    }

    falha_mask <- ativo & vazio_dep
    dep_name_norm <- monitora_correcao_normalizar_nome_coluna(as.character(regras$dependent_name[ii]))
    partes_habito <- regmatches(
      dep_name_norm,
      regexec("^forma_vida_(nativa|exotica|seca_morta)_(bromelioide|erva_bromelioide|cactacea|orquidea|samambaia)$", dep_name_norm, perl = TRUE)
    )[[1L]]
    if (length(partes_habito) == 3L && identical(monitora_correcao_normalizar_nome_coluna(token), "samambaia")) {
      exigido_por_versao <- monitora_correcao_habito_requerido_por_linha(
        dt,
        categoria = partes_habito[2L],
        forma = partes_habito[3L],
        meta_xls = get0("MONITORA_META_XLSFORMS_CORRECOES", ifnotfound = NULL, inherits = TRUE),
        linhas_com_forma = which(ativo)
      )
      falha_mask <- falha_mask & exigido_por_versao
    }

    falha <- which(falha_mask)
    if (length(falha) > 0) {
      out[[ii]] <- data.table::data.table(
        parent_col = parent_col,
        token = token,
        dependent_col = dep_col,
        severidade = regras$severidade[ii],
        n_falhas = length(falha),
        linhas_exemplo = paste(utils::head(falha, 20), collapse = ";"),
        fonte = regras$fonte[ii]
      )
    }
  }

  out <- out[!vapply(out, is.null, logical(1))]
  res <- if (length(out) > 0) data.table::rbindlist(out, fill = TRUE, use.names = TRUE) else data.table::data.table()
  if (nrow(res) > 0) {
    res <- unique(res, by = c("parent_col", "token", "dependent_col"))
    data.table::setorderv(res, c("severidade", "parent_col", "token", "dependent_col"))
    arq <- file.path(MONITORA_LOG_DIR, paste0("auditoria_dependencias_condicionais_", MONITORA_EXEC_ID, ".csv"))
    monitora_fwrite(res, arq, na = "")
    n_crit <- sum(res$severidade == "critica_forma_vida", na.rm = TRUE)
    nivel <- if (n_crit > 0L) "AVISO" else "INFO"
    monitora_log_registrar_evento(
      "dependencias_condicionais", nivel, arq,
      paste0(
        nrow(res), " regra(s) com pendências condicionais consolidadas; críticas=", n_crit,
        "; informativas=", nrow(res) - n_crit,
        "; regras_brutas_xlsform=", n_regras_brutas,
        "; regras_unicas_xlsform=", n_regras_unicas,
        "; regras_resolvidas=", nrow(regras_todas),
        "; regras_validadas_linha_a_linha=", n_deps,
        "; regras_documentadas_nao_validadas=", n_ignoradas
      ),
      "corrigir críticas antes de validar; consultar auditoria_dependencias_condicionais_regras_resolvidas_* para universo completo"
    )
  } else {
    monitora_log_registrar_evento("dependencias_condicionais", "INFO", NA_character_, "Nenhuma pendência condicional detectada nas regras mapeadas", "OK")
  }
  monitora_correcao_console_msg("Validação de dependências condicionais concluída: ", nrow(res), " pendência(s) consolidada(s).")
  res
}

monitora_correcao_resumo_coleta <- function(dt, coleta_valor, chaves = monitora_correcao_colunas_chave(dt)) {
  if (is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) return(data.table::data.table())
  dt[as.character(get(chaves$coleta)) == as.character(coleta_valor)]
}

