    aplicar_todos_registros_coleta = ifelse(identical(escopo, "coleta_inteira"), "sim", "nao"),
    validar_opcao = "sim",
    fonte_validacao = "painel_dinamico_xlsform_historico",
    motivo = motivo,
    status_validacao = "pendente",
    mensagem_validacao = NA_character_
  )
}

monitora_painel_motivo_movimento_triagem <- function(motivo_digitado, forma, ponto) {
  motivo_digitado <- trimws(as.character(motivo_digitado)[1L])
  if (is.na(motivo_digitado)) motivo_digitado <- ""
  forma <- trimws(as.character(forma)[1L])
  ponto <- trimws(as.character(ponto)[1L])
  motivo_automatico <- !nzchar(motivo_digitado) || (
    startsWith(motivo_digitado, "Triagem de formas de vida: avaliar/mover '") &&
    endsWith(motivo_digitado, paste0(" para nativa no ponto amostral ", ponto, "."))
  )
  if (isTRUE(motivo_automatico)) {
    return(paste0("Triagem de formas de vida: avaliar/mover '", forma, "' para nativa no ponto amostral ", ponto, "."))
  }
  motivo_digitado
}



