### Auditoria/quarentena pré-painel de completude de 101 pontos ---------------
### COLETAS incompletas não são corrigíveis no painel: o usuário não pode
### criar pontos amostrais ausentes com todos os atributos. A rotina abaixo roda
### antes do painel, gera relatórios específicos e remove essas COLETAS do
### universo editável. Se a incompletude for erro de importação/tokenização, a
### correção deve ser no script/processamento; se existir na fonte, a COLETA deve
### permanecer quarentenada ou ser excluída em fluxo próprio.
monitora_pre_painel_quarentenar_coletas_incompletas <- function(dt,
                                                               output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                               log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                               exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                                               contexto = "pre_painel") {
  if (!requireNamespace("data.table", quietly = TRUE)) return(list(dt = dt, auditoria = data.frame(), quarentenadas = character(0)))
  d <- data.table::as.data.table(dt)
  n <- nrow(d)
  dir_comp <- file.path(output_dir, "03_auditorias", "completude")
  dir_painel <- file.path(output_dir, "correcoes_campos", "relatorios_pre_painel", "completude")
  dir.create(dir_comp, recursive = TRUE, showWarnings = FALSE)
  dir.create(dir_painel, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
  fw <- function(x, file) {
    x <- data.table::as.data.table(x)
    dir.create(dirname(file), recursive = TRUE, showWarnings = FALSE)
    data.table::fwrite(x, file, na = "")
    invisible(file)
  }
  empty_aud <- data.table::data.table(
    contexto = character(), COLETA = character(), UC = character(), EA = character(), UA = character(), CICLO = character(), CAMPANHA = character(), ANO = character(),
    n_linhas = integer(), n_pontos_validos = integer(), n_pontos_distintos = integer(), n_pontos_duplicados = integer(), n_pontos_fora_1_101 = integer(),
    pontos_ausentes = character(), pontos_duplicados = character(), pontos_fora_exemplo = character(), completa_101 = logical(), acao_recomendada = character()
  )
  if (!n) return(list(dt = d, auditoria = empty_aud, quarentenadas = character(0)))
  ch <- tryCatch(monitora_correcao_colunas_chave(d), error = function(e) list())
  col_ok <- function(col) !is.null(col) && length(col) && !is.na(as.character(col)[1L]) && nzchar(as.character(col)[1L]) && as.character(col)[1L] %in% names(d)
  if (!col_ok(ch$coleta) || !col_ok(ch$ponto_amostral)) {
    aud <- empty_aud
    fw(aud, file.path(dir_comp, "auditoria_completude_101_pontos_por_coleta_pre_painel.csv"))
    fw(aud, file.path(dir_painel, "auditoria_completude_101_pontos_por_coleta_pre_painel.csv"))
    return(list(dt = d, auditoria = aud, quarentenadas = character(0)))
  }
  getv <- function(nm) {
    cc <- ch[[nm]]
    if (col_ok(cc)) as.character(d[[as.character(cc)[1L]]]) else rep(NA_character_, n)
  }
  ponto_chr <- as.character(d[[as.character(ch$ponto_amostral)[1L]]])
  ponto_num <- suppressWarnings(as.integer(gsub(",", ".", ponto_chr)))
  aux <- data.table::data.table(
    linha_indice = seq_len(n),
    COLETA = as.character(d[[as.character(ch$coleta)[1L]]]),
    UC = getv("uc"), EA = getv("ea"), UA = getv("ua"), CICLO = getv("ciclo"), CAMPANHA = getv("campanha"), ANO = getv("ano"),
    ponto = ponto_num, ponto_original = ponto_chr
  )
  aux <- aux[!is.na(COLETA) & nzchar(COLETA)]
  if (!nrow(aux)) {
    fw(empty_aud, file.path(dir_comp, "auditoria_completude_101_pontos_por_coleta_pre_painel.csv"))
    fw(empty_aud, file.path(dir_painel, "auditoria_completude_101_pontos_por_coleta_pre_painel.csv"))
    return(list(dt = d, auditoria = empty_aud, quarentenadas = character(0)))
  }
  by_cols <- c("COLETA", "UC", "EA", "UA", "CICLO", "CAMPANHA", "ANO")
  aud <- aux[, {
    p_valid <- ponto[!is.na(ponto) & ponto >= 1L & ponto <= 101L]
    tab <- table(p_valid)
    dup <- as.integer(names(tab)[tab > 1L])
    miss <- setdiff(1:101, sort(unique(p_valid)))
    fora <- ponto_original[is.na(ponto) | ponto < 1L | ponto > 101L]
    data.table::data.table(
      n_linhas = .N,
      n_pontos_validos = length(p_valid),
      n_pontos_distintos = data.table::uniqueN(p_valid),
      n_pontos_duplicados = length(dup),
      n_pontos_fora_1_101 = length(fora),
      pontos_ausentes = paste(miss, collapse = " | "),
      pontos_duplicados = paste(sort(dup), collapse = " | "),
      pontos_fora_exemplo = paste(utils::head(unique(fora), 20L), collapse = " | ")
    )
  }, by = by_cols]
  aud[, contexto := contexto]
  aud[, completa_101 := n_linhas == 101L & n_pontos_distintos == 101L & n_pontos_duplicados == 0L & n_pontos_fora_1_101 == 0L]
  aud[, acao_recomendada := ifelse(completa_101,
    "COLETA atende à completude de 101 pontos e pode entrar no painel.",
    "COLETA não atende à completude de 101 pontos. Não é corrigível por criação manual de ponto no painel; investigar importação/tokenização ou manter/excluir a COLETA em fluxo próprio."
  )]
  data.table::setcolorder(aud, c("contexto", by_cols, "n_linhas", "n_pontos_validos", "n_pontos_distintos", "n_pontos_duplicados", "n_pontos_fora_1_101", "pontos_ausentes", "pontos_duplicados", "pontos_fora_exemplo", "completa_101", "acao_recomendada"))
  bad <- sort(unique(as.character(aud[completa_101 == FALSE, COLETA])))
  bad <- bad[!is.na(bad) & nzchar(bad)]
  quar <- aud[COLETA %in% bad]
  regs_quar <- if (length(bad)) d[as.character(d[[as.character(ch$coleta)[1L]]]) %chin% bad] else d[0]
  fw(aud, file.path(dir_comp, "auditoria_completude_101_pontos_por_coleta_pre_painel.csv"))
  fw(quar, file.path(dir_comp, "coletas_quarentenadas_por_incompletude_pre_painel.csv"))
  fw(regs_quar, file.path(dir_comp, "registros_quarentenados_por_incompletude_pre_painel.csv"))
  fw(aud, file.path(dir_painel, "auditoria_completude_101_pontos_por_coleta_pre_painel.csv"))
  fw(quar, file.path(dir_painel, "coletas_quarentenadas_por_incompletude_pre_painel.csv"))
  try(fw(aud, file.path(log_dir, paste0("auditoria_completude_101_pontos_por_coleta_pre_painel_", exec_id, ".csv"))), silent = TRUE)
  if (length(bad)) {
    d2 <- d[!(as.character(d[[as.character(ch$coleta)[1L]]]) %chin% bad)]
    msg <- paste0("Completude pré-painel: ", length(bad), " COLETA(s) quarentenada(s) por não atenderem a 101 pontos; removidas do painel. Relatório: ", file.path(dir_comp, "coletas_quarentenadas_por_incompletude_pre_painel.csv"))
    if (exists("monitora_correcao_console_msg", mode = "function")) monitora_correcao_console_msg(msg) else message(msg)
    if (exists("monitora_log_registrar_evento", mode = "function")) monitora_log_registrar_evento("completude_pre_painel", "AVISO", file.path(dir_comp, "coletas_quarentenadas_por_incompletude_pre_painel.csv"), msg, "COLETAS incompletas fora do painel")
    return(list(dt = d2, auditoria = aud, quarentenadas = bad, registros_quarentenados = regs_quar))
  }
  msg <- "Completude pré-painel: todas as COLETAS avaliadas atendem a 101 pontos."
  if (exists("monitora_correcao_console_msg", mode = "function")) monitora_correcao_console_msg(msg) else message(msg)
  list(dt = d, auditoria = aud, quarentenadas = character(0), registros_quarentenados = regs_quar)
}

### - ------------------------------------------------------------
### Máscaras de qualidade fase-independentes para as ocorrências solo_nu e
### hábito obrigatório, reutilizadas pelo catálogo/relatórios diagnósticos
### pré/pós-painel (monitora_diag_rel_gerar_ocorrencias ) e pelos contadores
### de checkbox do painel (monitora_painel_coletas_diagnosticas_preferir_relatorios ),
### para não duplicar a mesma regra de negócio em dois lugares divergentes.
### O bloqueio final em registros_validados.csv continua em
### monitora_validados_validar_condicionais_xlsform21 ; esta função apenas
### antecipa a mesma detecção para revisão assistida no painel.
monitora_correcao_mask_solo_nu_incompativel <- function(dt, chaves = NULL) {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (!n) return(rep(FALSE, 0L))
  if (is.null(chaves)) chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list())
  tipo_col <- chaves[["tipo_forma_vida"]]
  if (is.null(tipo_col) || is.na(as.character(tipo_col)[1L]) || !nzchar(as.character(tipo_col)[1L]) || !(as.character(tipo_col)[1L] %in% names(dt))) {
    return(rep(FALSE, n))
  }
  tipo_val <- dt[[as.character(tipo_col)[1L]]]
  tem_solo <- tryCatch(monitora_relatorio_exoticas_tem_token(tipo_val, "solo_nu"), error = function(e) rep(FALSE, n))
  tem_outro <- tryCatch(monitora_relatorio_exoticas_tem_token(tipo_val, c("serrapilheira", "nativa", "exotica", "seca_morta", "outra_forma_vida")), error = function(e) rep(FALSE, n))
  tem_solo[is.na(tem_solo)] <- FALSE
  tem_outro[is.na(tem_outro)] <- FALSE
  tem_solo & tem_outro
}

### ### Aliases históricos de hábito: o atributo canônico "forma_vida_<categoria>_
### <forma>" teve rótulos DIFERENTES em cada versão do XLSForm ao longo dos
### anos (ex.: 2022-2024 chamavam o mesmo `name` de "Espécie ou nome popular
### (Samambaia)" -- campo de texto/espécie -- enquanto 21FEV25 o redefiniu como
### "A samambaia nativa observada é:" -- select_one de hábito). A etapa de
### importação renomeia caminho->rótulo por `name`, não por versão/linha, e
### escolhe um único rótulo "vencedor"; isso faz o valor real de hábito das
### linhas mais recentes acabar fisicamente sob o rótulo histórico mais antigo
### (ou sob variantes ".1"/".2" quando rótulos colidem entre arquivos
### mesclados). monitora_correcao_aliases_historicos_habito descobre essas
### colunas físicas 100% a partir dos rótulos que o próprio XLSForm embutido
### (meta_xls$campos, mesma fonte de monitora_correcao_resolver_coluna_habito )
### já associa ao `name` canônico, em qualquer versão -- nenhuma lista/rótulo é
### inventado aqui. O sufixo numérico opcional (".1"/".2"...) é o mecanismo
### genérico e documentado de desambiguação de nomes duplicados no import
### (não é inferência semântica).
monitora_correcao_aliases_historicos_habito <- function(dt, col_def, meta_xls = NULL, linha = NULL) {
 ### recebe o atributo definitivo JÁ RESOLVIDO
 ### (via monitora_correcao_resolver_coluna_habito , que já trata sinônimos
 ### como "erva_bromelioide"<->"bromelioide" -- fonte única pré-existente) e
 ### consulta os rótulos históricos pelo `name` desse definitivo, não pelo
 ### token bruto. Reconstruir "forma_vida_<categoria>_<forma>" a partir do
 ### token bruto falha para sinônimos, pois
 ### "forma_vida_nativa_erva_bromelioide" nunca existe como `name` no XLSForm
 ### -- o `name` real é sempre "forma_vida_nativa_bromelioide".
  col_def <- as.character(col_def)[1L]
  if (is.na(col_def) || !nzchar(col_def) || is.null(dt) || !length(names(dt))) return(character(0))
  meta_xls <- tryCatch(monitora_correcao_xlsform_meta_atual(meta_xls), error = function(e) meta_xls)
  campos <- if (!is.null(meta_xls) && !is.null(meta_xls$campos)) data.table::as.data.table(meta_xls$campos) else data.table::data.table()
  if (!nrow(campos) || !("name" %in% names(campos)) || !("label" %in% names(campos))) return(character(0))
 ### col_def chega aqui SEMPRE como o nome
 ### completo da coluna em dt (ex.: amostragem/registro/forma_vida_nativa_
 ### bromelioide, devolvido por monitora_correcao_resolver_coluna_habito ),
 ### nunca como o `name` curto do XLSForm (ex.: forma_vida_nativa_bromelioide).
 ### Comparar só contra `name` nunca casava (0 linhas sempre), fazendo esta
 ### função devolver character(0) incondicionalmente -- nenhum alias histórico
 ### de hábito jamais era encontrado, nem para conciliação (monitora_correcao_
 ### conciliar_habito_historico_definitivo) nem para ocultar do seletor
 ### (dict_sem_aliases_habito_painel). Casa também por caminho_registro, que é
 ### exatamente o nome completo de coluna do contrato único.
  dd <- campos[name == col_def]
  if (!nrow(dd) && ("caminho_registro" %in% names(campos))) dd <- campos[caminho_registro == col_def]
  if (!nrow(dd)) return(character(0))
 ### (causa raiz 97x98): o mesmo `name` de XLSForm pode ter sido
 ### reaproveitado por uma versão histórica para um campo de NATUREZA
 ### diferente do hábito select_one atual (ex.: em plantas_herb_e_lenhosas_
 ### campsav_ago2022.xlsx, o name "forma_vida_nativa_cactacea" foi usado para
 ### o campo de texto "Espécie ou nome popular (Cactácea)", que só nas
 ### versões seguintes passou a existir como "forma_vida_nativa_cactacea_sp").
 ### Sem este filtro, o rótulo desse campo de texto entrava na lista de
 ### aliases históricos do hábito e ocultava do seletor uma coluna de dados
 ### de espécie real (não-hábito, nunca migrada por monitora_correcao_
 ### conciliar_habito_historico_definitivo porque seu conteúdo não está no
 ### domínio terrestre/epifita/rupicola) -- ocultando dado genuíno e não
 ### editável em lugar nenhum. Um alias histórico de hábito só pode vir de um
 ### registro cujo tipo_base/type também é select_one nessa versão.
  col_tipo <- if ("tipo_base" %in% names(dd)) as.character(dd$tipo_base) else if ("type" %in% names(dd)) as.character(dd$type) else NA_character_
  eh_select_one <- grepl("select_one", col_tipo, ignore.case = TRUE)
  eh_select_one[is.na(col_tipo)] <- TRUE ### sem informação de tipo: mantém comportamento anterior (conservador)
  dd <- dd[eh_select_one]
  if (!nrow(dd)) return(character(0))
  arquivo_linha <- if (!is.null(linha)) tryCatch(monitora_correcao_xlsform_registro(dt, linha, meta_xls), error = function(e) NA_character_) else NA_character_
 ### os candidatos físicos precisam abranger todos os rótulos
 ### históricos. O importador consolida cabeçalhos de arquivos diferentes e
 ### pode manter o valor de uma linha 2025 sob o rótulo físico vencedor de
 ### 2022/2023/2024. Restringir `dd` apenas à versão da linha tornava esse
 ### valor invisível e criou falsos positivos de hábito ausente. A versão da
 ### linha continua sendo usada abaixo, onde é necessária: decidir se um
 ### rótulo é ambíguo entre categorias. Ela não limita onde o importador pode
 ### ter materializado fisicamente o valor.
  labels <- unique(trimws(as.character(dd$label)))
  labels <- labels[!is.na(labels) & nzchar(labels)]
  if (!length(labels)) return(character(0))

 ### ### Um rótulo histórico do XLSForm pode ser IDÊNTICO entre categorias
 ### diferentes para a mesma forma, mas SÓ EM ALGUMAS versões (ex.: em 3 das 4
 ### versões, "forma_vida_nativa_bromelioide" e "forma_vida_seca_morta_
 ### bromelioide" compartilham o mesmo label; na versão mais recente, 21FEV25,
 ### os labels já diferenciam a categoria com um qualificador). Quando o
 ### rótulo é compartilhado NA VERSÃO QUE PRODUZIU A LINHA sendo avaliada, a
 ### coluna física derivada dele não pode ser atribuída com segurança a
 ### nenhuma das categorias para ESSA linha -- mas se a linha vier de uma
 ### versão cujos rótulos já diferenciam a categoria, não há ambiguidade
 ### real para ela, mesmo que outras versões historicamente colidissem.
 ### Por isso, quando `linha` é informada, a comparação de rótulos é
 ### restrita à versão (arquivo_xlsform) que produziu aquela linha
 ### especificamente (via monitora_correcao_xlsform_registro , o mesmo
 ### mecanismo por-registro já usado por monitora_correcao_resolver_coluna_
 ### habito ); sem `linha`, mantém a checagem agregada (mais conservadora,
 ### usada apenas para a lista de aliases a ocultar do seletor do painel,
 ### onde não há uma linha específica). Confirmado empiricamente (COLETA
 ### 6173/ponto 90, validação operacional, versão ago2022 -- rótulos idênticos nessa versão):
 ### nativa/bromelioide estava genuinamente vazio no CSV original, mas o
 ### alias compartilhado carregava o valor de seca_morta/bromelioide
 ### ("terrestre"). Nenhuma lista nova, nenhuma inferência por valor
 ### observado -- só cruzamento do metadado já existente, agora por versão.
  col_def_base <- sub("^.*/", "", col_def)
  categoria_col_def <- sub("^forma_vida_(nativa|exotica|seca_morta)_.+$", "\\1", col_def_base)
  outras_categorias <- setdiff(c("nativa", "exotica", "seca_morta"), categoria_col_def)
 ### Regex base do R não reconhece grupo não capturante `(?:...)`. O padrão
 ### anterior deixava de extrair a forma e anulava a detecção de colisão entre
 ### categorias. Usa grupos POSIX explícitos e retorna o segundo grupo.
  forma_col_def <- sub("^forma_vida_(nativa|exotica|seca_morta)_(.+)$", "\\2", col_def_base)
  names_outras_categorias <- paste0("forma_vida_", outras_categorias, "_", forma_col_def)
  labels_outras_categorias <- character(0)
  if (identical(categoria_col_def, col_def_base) || identical(forma_col_def, col_def_base)) {
 ### col_def não segue o padrão "forma_vida_<categoria>_<forma>" -- não há
 ### como cruzar por categoria; segue sem checagem de ambiguidade (não é o
 ### caso de nenhum atributo de hábito real, mas mantém a função segura).
    labels_outras_categorias <- character(0)
  } else {
    dd_outras <- campos[name %in% names_outras_categorias]
    if (nrow(dd_outras)) {
      if (!is.na(arquivo_linha) && nzchar(arquivo_linha) && "arquivo_xlsform" %in% names(dd_outras)) {
 ### Linha com versão conhecida: compara só dentro dessa versão.
        labels_outras_categorias <- unique(trimws(as.character(dd_outras[arquivo_xlsform == arquivo_linha, label])))
      } else if ("arquivo_xlsform" %in% names(dd) && "arquivo_xlsform" %in% names(dd_outras)) {
 ### Sem linha específica (uso agregado, ex.: ocultar do seletor):
 ### mantém a checagem por versão, mas agregando todas as versões de
 ### col_def -- mais conservador (marca ambíguo se ALGUMA versão colidir).
        for (arq in unique(dd$arquivo_xlsform)) {
          labs_arq <- unique(trimws(as.character(dd_outras[arquivo_xlsform == arq, label])))
          labels_outras_categorias <- c(labels_outras_categorias, labs_arq)
        }
      } else {
        labels_outras_categorias <- unique(trimws(as.character(dd_outras$label)))
      }
    }
  }
  labels_outras_categorias <- unique(labels_outras_categorias[!is.na(labels_outras_categorias) & nzchar(labels_outras_categorias)])
  labels_ambiguos <- intersect(labels, labels_outras_categorias)
  labels_seguros <- setdiff(labels, labels_ambiguos)

  nms <- names(dt)
  coletar_colunas <- function(labs) {
    achados <- character(0)
    normalizar_aspas_html <- function(x) gsub('"{2,}', '"', as.character(x), perl = TRUE)
    nms_html <- normalizar_aspas_html(nms)
    for (lab in labs) {
      base_cand <- paste0(lab, " (amostragem/registro)")
      base_html <- normalizar_aspas_html(base_cand)
      achados <- c(achados, nms[nms_html == base_html])
      pref <- paste0(base_html, ".")
      tem_pref <- startsWith(nms_html, pref)
      if (any(tem_pref)) {
        sufixo <- substring(nms_html[tem_pref], nchar(pref) + 1L)
        achados <- c(achados, nms[tem_pref][grepl("^[0-9]+$", sufixo)])
      }
    }
    unique(achados)
  }
  achados <- setdiff(coletar_colunas(labels_seguros), col_def)
  achados_ambiguos <- setdiff(coletar_colunas(labels_ambiguos), col_def)
  attr(achados, "ambiguos") <- achados_ambiguos
  achados
}

### ### Concilia, ANTES do diagnóstico/gate, o atributo definitivo de hábito
### (forma_vida_<categoria>_<forma>, o único que permanece em registros_corrig/
### registros_validados) com seus aliases históricos (acima). Regra: só migra
### quando o definitivo está vazio E exatamente um alias tem um token dentro do
### domínio contratual de hábito (terrestre/epifita/rupicola -- mesmo domínio
### já usado pela máscara, não uma lista nova); nunca escolhe silenciosamente
### em caso de conflito (múltiplos aliases com tokens válidos DIFERENTES);
### nunca trata um alias com texto livre (ex.: nome de espécie herdado de
### versões antigas do XLSForm) como valor de hábito -- isso não é inferir
### regra pelos dados, é validar contra o domínio já contratualmente definido.
monitora_correcao_conciliar_habito_historico_definitivo <- function(dt, meta_xls = NULL, gravar = TRUE, output_dir = NULL, contexto = "pre_diagnostico_habito") {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  vazio_registro <- list(dt = dt, audit = data.table::data.table(), n_migrado = 0L, n_ja_preenchido = 0L, n_conflito = 0L, n_sem_valor = 0L, n_valor_invalido = 0L)
  if (!n) return(vazio_registro)
 ### o painel consulta a mesma base repetidamente para montar filtros e
 ### preview. A conciliação é idempotente e altera somente atributos de hábito;
 ### portanto, uma base já conciliada não deve ser varrida inteira novamente.
  if (isTRUE(attr(dt, "monitora_habito_historico_conciliado"))) {
    audit_cache <- attr(dt, "monitora_habito_historico_audit")
    if (data.table::is.data.table(audit_cache)) vazio_registro$audit <- audit_cache
    return(vazio_registro)
  }
  meta_xls <- tryCatch(monitora_correcao_xlsform_meta_atual(meta_xls), error = function(e) meta_xls)
  habitos_validos <- c("terrestre", "epifita", "rupicola")
  normalizar_alias_habito <- function(x) {
    x <- tolower(trimws(as.character(x)))
    vapply(x, function(valor) {
      if (is.na(valor) || !nzchar(valor)) return(NA_character_)
      tokens <- trimws(strsplit(valor, "|", fixed = TRUE)[[1L]])
      tokens <- tokens[nzchar(tokens)]
      unicos <- unique(tokens)
      if (length(unicos) == 1L && unicos %in% habitos_validos) return(unicos)
      valor
    }, character(1L), USE.NAMES = FALSE)
  }
  formas <- tryCatch(monitora_correcao_tokens_formas_exigem_habito(), error = function(e) character(0))
  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list())
  get_col <- function(nm) {
    val <- chaves[[nm]]
    if (is.null(val) || is.na(val) || !nzchar(as.character(val)[1L]) || !(as.character(val)[1L] %in% names(dt))) return(rep(NA_character_, n))
    as.character(dt[[as.character(val)[1L]]])
  }
  coleta <- get_col("coleta"); uc <- get_col("uc"); ea <- get_col("ea"); ua <- get_col("ua")
  ponto <- get_col("ponto_amostral"); ponto_metro <- get_col("ponto_metro")
  col_marca_canonica <- tryCatch(monitora_habito_col_canonicos_preservados(), error = function(e) NA_character_)
  canonico_preservado_na_linha <- function(linhas, identidade_canonica) {
    linhas <- as.integer(linhas)
    if (is.na(col_marca_canonica) || !(col_marca_canonica %in% names(dt))) return(rep(FALSE, length(linhas)))
    marca <- as.character(dt[[col_marca_canonica]][linhas])
 ### A marca técnica contém o `name`/caminho canônico, não o rótulo físico
 ### final de registros_corrig. Comparar com `col_def` fazia a proteção
 ### falhar e permitia copiar o hábito de outra categoria quando dois
 ### XLSForms históricos reutilizavam rótulos semelhantes.
    token <- sub("^.*/", "", as.character(identidade_canonica)[1L])
    vapply(marca, function(x) {
      if (is.na(x) || !nzchar(trimws(x))) return(FALSE)
      token %in% trimws(unlist(strsplit(x, ";", fixed = TRUE), use.names = FALSE))
    }, logical(1L))
  }

  registros_audit <- vector("list", 0L)
  for (categoria in c("nativa", "exotica", "seca_morta")) {
    col_lista <- tryCatch(monitora_correcao_coluna_forma_vida(dt, categoria), error = function(e) NA_character_)
    if (is.na(col_lista) || !nzchar(col_lista) || !(col_lista %in% names(dt))) next
 ### col_def é resolvido via
 ### monitora_correcao_resolver_coluna_habito (trata sinônimos como
 ### "erva_bromelioide"<->"bromelioide" pela fonte única já existente).
 ### Formas-sinônimo diferentes podem resolver para o MESMO atributo
 ### definitivo (ex.: "bromelioide" e "erva_bromelioide"); por isso primeiro
 ### agrupa os tokens de forma por col_def resolvido e acumula a presença
 ### (hit) na lista principal pela UNIÃO de todos os tokens do grupo, em vez
 ### de processar/possivelmente pular tokens sinônimos isoladamente (o que
 ### perderia linhas que só usam um dos tokens sinônimos como valor literal).
    col_def_por_forma <- vapply(formas, function(fm) {
      cd <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, categoria, fm, meta_xls = meta_xls), error = function(e) NA_character_)
      if (is.na(cd) || !nzchar(cd) || !(cd %in% names(dt))) NA_character_ else cd
    }, character(1))
    for (col_def in unique(col_def_por_forma[!is.na(col_def_por_forma)])) {
      formas_grupo <- formas[!is.na(col_def_por_forma) & col_def_por_forma == col_def]
      hit <- rep(FALSE, n)
      for (fm in formas_grupo) {
        hit_fm <- tryCatch(monitora_correcao_contem_qualquer_token_vec(dt[[col_lista]], fm), error = function(e) rep(FALSE, n))
        hit_fm[is.na(hit_fm)] <- FALSE
        hit <- hit | hit_fm
      }
      forma <- formas_grupo[1L]
      regra_forma <- tryCatch(monitora_correcao_regra_habito_contrato_atual(categoria, forma, meta_xls), error = function(e) data.table::data.table())
      identidade_canonica <- if (nrow(regra_forma) == 1L) as.character(regra_forma$atributo_canonico[1L]) else paste0("amostragem/registro/forma_vida_", categoria, "_", monitora_correcao_normalizar_forma_habito(forma))
      idx <- which(hit)
      if (!length(idx)) next
 ### Quando o caminho canônico preservado já contém valor, ele é soberano.
 ### Quando está vazio, ainda é necessário consultar os aliases históricos
 ### seguros da versão da linha. A proteção contra propagação entre categorias
 ### permanece no teste `hit_outras_categorias` abaixo; descartar toda linha
 ### canônica vazia aqui produziria falso positivo e divergência física depois
 ### de SANHAB em exportações históricas que guardam o fato apenas no rótulo.
      linhas_preservadas <- canonico_preservado_na_linha(idx, identidade_canonica)
      if (any(linhas_preservadas)) {
        idx_pres <- idx[linhas_preservadas]
        def_pres <- tolower(trimws(as.character(dt[[col_def]][idx_pres])))
        preenchido_pres <- !is.na(def_pres) & nzchar(def_pres)
        for (kk in which(preenchido_pres)) {
          ii <- idx_pres[[kk]]
          registros_audit[[length(registros_audit) + 1L]] <- data.table::data.table(
            linha_indice = ii, COLETA = coleta[ii], UC = uc[ii], EA = ea[ii], UA = ua[ii],
            ponto_amostral = ponto[ii], ponto_metro = ponto_metro[ii], categoria = categoria, forma = forma,
            atributo_definitivo = col_def, alias_origem = NA_character_, valor_migrado = NA_character_,
            status = "ja_preenchido_fonte_canonica"
          )
        }
        idx <- setdiff(idx, idx_pres[preenchido_pres])
        if (!length(idx)) next
      }
 ### A descoberta histórica usa a identidade do contrato (path/name),
 ### enquanto a escrita permanece no campo físico vigente `col_def`.
 ### Passar o rótulo físico à função histórica apaga categoria×forma e
 ### impede a migração dos XLSForms 2022–2024.
      aliases_res <- tryCatch(monitora_correcao_aliases_historicos_habito(dt, identidade_canonica, meta_xls), error = function(e) character(0))
      aliases <- aliases_res[aliases_res %in% names(dt)]
 ### aliases_ambiguos são colunas cujo rótulo
 ### histórico é compartilhado com o atributo definitivo de hábito de
 ### OUTRA categoria na mesma versão do XLSForm (ver monitora_correcao_
 ### aliases_historicos_habito ) -- nunca usados para preencher o
 ### definitivo, mas auditados para não mascarar a ambiguidade em
 ### silêncio.
      aliases_ambiguos <- attr(aliases_res, "ambiguos")
      if (is.null(aliases_ambiguos)) aliases_ambiguos <- character(0)
      aliases_ambiguos <- aliases_ambiguos[aliases_ambiguos %in% names(dt)]
      if (!length(aliases) && !length(aliases_ambiguos)) next
 ### a ambiguidade de rótulo só é um conflito REAL
 ### para uma linha específica quando outra categoria TAMBÉM reivindica a
 ### mesma forma NESSA MESMA LINHA (por exemplo, "bromelioide" em nativa E
 ### em seca_morta simultaneamente). Se a(s)
 ### outra(s) categoria(s) não têm a forma presente nessa linha, não há
 ### disputa real pelo alias compartilhado, e ele pode ser usado com
 ### segurança -- daí o cálculo de hit_outras_categorias por linha, em vez
 ### de descartar o rótulo compartilhado globalmente (o que reverteria
 ### migrações legítimas em linhas sem qualquer ambiguidade real).
      hit_outras_categorias <- rep(FALSE, n)
      if (length(aliases_ambiguos)) {
        for (outra_cat in setdiff(c("nativa", "exotica", "seca_morta"), categoria)) {
          col_lista_outra <- tryCatch(monitora_correcao_coluna_forma_vida(dt, outra_cat), error = function(e) NA_character_)
          if (is.na(col_lista_outra) || !nzchar(col_lista_outra) || !(col_lista_outra %in% names(dt))) next
          for (fm in formas_grupo) {
            h <- tryCatch(monitora_correcao_contem_qualquer_token_vec(dt[[col_lista_outra]], fm), error = function(e) rep(FALSE, n))
            h[is.na(h)] <- FALSE
            hit_outras_categorias <- hit_outras_categorias | h
          }
        }
      }
      def_val <- tolower(trimws(as.character(dt[[col_def]][idx])))
      def_vazio <- is.na(def_val) | !nzchar(def_val)
      for (kk in seq_along(idx)) {
        ii <- idx[kk]
        if (!def_vazio[kk]) {
          registros_audit[[length(registros_audit) + 1L]] <- data.table::data.table(
            linha_indice = ii, COLETA = coleta[ii], UC = uc[ii], EA = ea[ii], UA = ua[ii],
            ponto_amostral = ponto[ii], ponto_metro = ponto_metro[ii], categoria = categoria, forma = forma,
            atributo_definitivo = col_def, alias_origem = NA_character_, valor_migrado = NA_character_, status = "ja_preenchido"
          )
          next
        }
 ### quando outra categoria também
 ### reivindica a forma NESTA linha, a ambiguidade agregada (todas as
 ### versões) pode ser imprecisa demais -- reavalia com `linha = ii`
 ### para restringir a comparação de rótulos à versão do XLSForm que
 ### produziu ESSA linha especificamente. No XLSForm 21FEV25, os rótulos de
 ### nativa/exotica já são diferenciados por
 ### qualificador -- não deveria contar como ambíguo mesmo que outras
 ### versões historicamente colidissem).
        if (isTRUE(hit_outras_categorias[ii])) {
          aliases_res_linha <- tryCatch(monitora_correcao_aliases_historicos_habito(dt, identidade_canonica, meta_xls, linha = ii), error = function(e) character(0))
          aliases_linha_seguros <- aliases_res_linha[aliases_res_linha %in% names(dt)]
          aliases_linha_ambiguos <- attr(aliases_res_linha, "ambiguos")
          if (is.null(aliases_linha_ambiguos)) aliases_linha_ambiguos <- character(0)
          aliases_linha_ambiguos <- aliases_linha_ambiguos[aliases_linha_ambiguos %in% names(dt)]
        } else {
          aliases_linha_seguros <- c(aliases, aliases_ambiguos)
          aliases_linha_ambiguos <- character(0)
        }
        vals_alias <- if (length(aliases_linha_seguros)) {
          v <- vapply(aliases_linha_seguros, function(cc) normalizar_alias_habito(dt[[cc]][ii]), character(1)); names(v) <- aliases_linha_seguros; v
        } else character(0)
        preenchidos <- vals_alias[!is.na(vals_alias) & nzchar(vals_alias)]
        validos <- preenchidos[preenchidos %in% habitos_validos]
        if (length(validos) && length(unique(validos)) == 1L) {
          status <- "migrado"; alias_origem <- paste(names(validos), collapse = " | "); valor_migrado <- unique(validos)[1L]
          data.table::set(dt, i = ii, j = col_def, value = valor_migrado)
          for (alias_col in unique(names(validos))) {
            data.table::set(dt, i = ii, j = alias_col, value = valor_migrado)
          }
        } else if (length(validos) > 1L) {
          status <- "conflito"; alias_origem <- paste(names(validos), collapse = " | "); valor_migrado <- paste(unique(validos), collapse = " | ")
        } else if (length(preenchidos)) {
          status <- "valor_invalido"; alias_origem <- paste(names(preenchidos), collapse = " | "); valor_migrado <- paste(unique(preenchidos), collapse = " | ")
        } else {
 ### Sem alias seguro preenchido; verifica se havia alias AMBÍGUO
 ### (nesta versão específica) preenchido só para fins de auditoria --
 ### nunca usado para migrar.
          vals_amb <- if (length(aliases_linha_ambiguos)) {
            va <- vapply(aliases_linha_ambiguos, function(cc) tolower(trimws(as.character(dt[[cc]][ii]))), character(1)); names(va) <- aliases_linha_ambiguos; va
          } else character(0)
          preenchidos_amb <- vals_amb[!is.na(vals_amb) & nzchar(vals_amb)]
          if (length(preenchidos_amb)) {
            status <- "alias_ambiguo_ignorado"; alias_origem <- paste(names(preenchidos_amb), collapse = " | "); valor_migrado <- NA_character_
          } else {
            status <- "sem_valor"; alias_origem <- NA_character_; valor_migrado <- NA_character_
          }
        }
        registros_audit[[length(registros_audit) + 1L]] <- data.table::data.table(
          linha_indice = ii, COLETA = coleta[ii], UC = uc[ii], EA = ea[ii], UA = ua[ii],
          ponto_amostral = ponto[ii], ponto_metro = ponto_metro[ii], categoria = categoria, forma = forma,
          atributo_definitivo = col_def, alias_origem = alias_origem, valor_migrado = valor_migrado, status = status
        )
      }
    }
  }
  audit <- if (length(registros_audit)) data.table::rbindlist(registros_audit, fill = TRUE, use.names = TRUE) else data.table::data.table()
  if (isTRUE(gravar) && nrow(audit)) {
    out_dir <- if (!is.null(output_dir)) output_dir else get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path("output", "correcoes_campos"), inherits = TRUE)
    dir.create(out_dir, recursive = TRUE, showWarnings = FALSE)
    arq_audit <- file.path(out_dir, paste0("auditoria_conciliacao_habito_historico_definitivo_", contexto, ".csv"))
 ### a primeira fotografia pré-painel é evidência imutável. Chamadas
 ### posteriores do preview/finalização não podem reescrever o arquivo com
 ### um estado já saneado e fazê-lo passar por diagnóstico de entrada.
    if (!identical(as.character(contexto)[1L], "pre_mascara_habito") || !file.exists(arq_audit)) {
      try(monitora_fwrite(audit, arq_audit, na = ""), silent = TRUE)
    }
    arq_ultima <- file.path(out_dir, paste0("auditoria_conciliacao_habito_historico_definitivo_", contexto, "_ultima_avaliacao.csv"))
    try(monitora_fwrite(audit, arq_ultima, na = ""), silent = TRUE)
  }
  data.table::setattr(dt, "monitora_habito_historico_conciliado", TRUE)
  data.table::setattr(dt, "monitora_habito_historico_audit", audit)
  assign("MONITORA_AUDITORIA_CONCILIACAO_HABITO_CACHE", audit, envir = .GlobalEnv)
  list(
    dt = dt, audit = audit,
    n_migrado = if (nrow(audit)) sum(audit$status == "migrado") else 0L,
    n_ja_preenchido = if (nrow(audit)) sum(audit$status == "ja_preenchido") else 0L,
    n_conflito = if (nrow(audit)) sum(audit$status == "conflito") else 0L,
    n_sem_valor = if (nrow(audit)) sum(audit$status == "sem_valor") else 0L,
    n_valor_invalido = if (nrow(audit)) sum(audit$status == "valor_invalido") else 0L,
    n_alias_ambiguo_ignorado = if (nrow(audit)) sum(audit$status == "alias_ambiguo_ignorado") else 0L
  )
}

### Ocorrência diagnóstica "hábito obrigatório ausente": para as formas
### condicionais (monitora_correcao_tokens_formas_exigem_habito ), o campo
### dependente de hábito (terrestre/epifita/rupicola) precisa estar preenchido
### com um valor válido. Sem esta antecipação, a única checagem existente era
### monitora_validados_validar_condicionais_xlsform21 no fechamento de
### registros_validados.csv -- tarde demais para revisão assistida no painel.
### agora roda monitora_correcao_conciliar_habito_
### historico_definitivo primeiro (por referência -- dt já sai conciliado
### para o chamador também), então a máscara em si passa a operar só sobre o
### atributo definitivo já reconciliado.
monitora_correcao_mask_habito_obrigatorio_ausente <- function(dt, meta_xls = NULL) {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  mask <- rep(FALSE, n)
  cols_forma_hit <- character(0)
  cols_habito_hit <- character(0)
  if (!n) return(list(mask = mask, cols_forma_hit = cols_forma_hit, cols_habito_hit = cols_habito_hit))
 ### concilia aliases históricos -> atributo definitivo
 ### ANTES de checar ausência. Sem isso, o atributo definitivo materializado
 ### vazio pela preparação de schema pré-painel "vence" a resolução mesmo
 ### quando o valor real está sob um alias histórico (ex.: samambaia/2026 sob
 ### o rótulo herdado de 2022-2024) — causa raiz confirmada dos 705 falsos
 ### positivos na validação operacional. Reatribui explicitamente dt <- resultado$dt em vez de
 ### confiar em mutação por referência através da fronteira de função (data.
 ### table::as.data.table no início da função de conciliação pode reatribuir
 ### para um objeto novo internamente).
  res_conciliacao_habito <- tryCatch(
    monitora_correcao_conciliar_habito_historico_definitivo(dt, meta_xls = meta_xls, gravar = TRUE, contexto = "pre_mascara_habito"),
    error = function(e) NULL
  )
  if (is.list(res_conciliacao_habito) && !is.null(res_conciliacao_habito$dt)) dt <- res_conciliacao_habito$dt
  detalhes <- monitora_correcao_ocorrencias_habito_detalhadas(dt, meta_xls = meta_xls)
  if (nrow(detalhes)) {
    mask[unique(detalhes$linha_indice)] <- TRUE
    cols_forma_hit <- unique(as.character(detalhes$atributo_forma_vida))
    cols_habito_hit <- unique(as.character(detalhes$atributo_habito_obrigatorio))
  }
 ### monitora_correcao_conciliar_habito_
 ### historico_definitivo já materializa (data.table::set, por referência)
 ### os valores históricos seguros no atributo canônico, em `dt` -- mas até
 ### aqui essa função descartava o `dt` conciliado ao retornar só mask/cols_*.
 ### Devolver `dt` permite que os chamadores (ex.: monitora_publicacao_ab_
 ### auditar_pendencias_impeditivas) capturem a harmonização e a levem até a
 ### exportação de registros_corrig.csv, em vez de ela morrer dentro desta
 ### chamada. Não é uma regra nova: é o mesmo `dt` já conciliado logo acima.
  list(mask = mask, cols_forma_hit = cols_forma_hit, cols_habito_hit = cols_habito_hit, detalhes = detalhes, dt = dt)
}

monitora_correcao_xlsform_por_linha <- function(dt, meta_xls = NULL) {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (!n) return(character())
  meta_xls <- tryCatch(monitora_correcao_xlsform_meta_atual(meta_xls), error = function(e) meta_xls)
  if (is.null(meta_xls) || is.null(meta_xls$arquivos) || !nrow(meta_xls$arquivos)) {
    stop("Metadados das versões XLSForm indisponíveis para validar hábitos por registro.", call. = FALSE)
  }

  cols_versao <- intersect(
    c("controle_versao", "PROTOCOLO", "protocolo", "n_form_ref", "form_id", "form_version", "version"),
    names(dt)
  )
  if (!length(cols_versao)) {
    stop("Nenhuma coluna de versão XLSForm disponível para validar hábitos por registro.", call. = FALSE)
  }
  partes <- lapply(cols_versao, function(cc) {
    x <- as.character(dt[[cc]])
    x[is.na(x)] <- ""
    x
  })
  chave <- do.call(paste, c(partes, sep = "\034"))
  arqs_meta <- data.table::as.data.table(meta_xls$arquivos)
  cols_meta <- intersect(c("arquivo_xlsform", "form_id", "version"), names(arqs_meta))
  chave_meta <- if (length(cols_meta) && nrow(arqs_meta)) {
    linhas_meta <- do.call(paste, c(lapply(cols_meta, function(cc) {
      x <- as.character(arqs_meta[[cc]])
      x[is.na(x)] <- ""
      x
    }), sep = "\034"))
    paste(sort(unique(linhas_meta)), collapse = "\035")
  } else ""
  cache <- attr(dt, "monitora_xlsform_por_linha_cache", exact = TRUE)
  if (is.list(cache) && identical(cache$chave, chave) && identical(cache$chave_meta, chave_meta) && length(cache$arquivo) == n) {
    return(as.character(cache$arquivo))
  }

  chaves_unicas <- unique(chave)
  linhas_ref <- match(chaves_unicas, chave)
  arquivo_unico <- vapply(linhas_ref, function(ii) {
    monitora_correcao_xlsform_registro(dt, ii, meta_xls)
  }, character(1L), USE.NAMES = FALSE)
  arquivo <- arquivo_unico[match(chave, chaves_unicas)]
  data.table::setattr(dt, "monitora_xlsform_por_linha_cache", list(chave = chave, chave_meta = chave_meta, arquivo = arquivo))
  arquivo
}

monitora_correcao_habito_requerido_por_linha <- function(
  dt,
  categoria,
  forma,
  meta_xls = NULL,
  arquivo_por_linha = NULL,
  linhas_com_forma = NULL
) {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (!n) return(logical())
  categoria <- tolower(as.character(categoria)[1L])
  forma <- monitora_correcao_normalizar_nome_coluna(as.character(forma)[1L])
  if (forma %in% c("erva_bromelioide", "bromelioides")) forma <- "bromelioide"
  meta_xls <- tryCatch(monitora_correcao_xlsform_meta_atual(meta_xls), error = function(e) meta_xls)
  campos <- if (!is.null(meta_xls) && !is.null(meta_xls$campos)) data.table::as.data.table(meta_xls$campos) else data.table::data.table()
  if (!nrow(campos)) stop("Contrato XLSForm sem campos para validar hábito obrigatório.", call. = FALSE)
  for (cc in c("arquivo_xlsform", "name", "caminho_registro", "type", "tipo_base", "required")) {
    if (!(cc %in% names(campos))) campos[, (cc) := NA_character_]
  }

  dep_name <- paste0("forma_vida_", categoria, "_", forma)
  dep_path <- paste0("amostragem/registro/", dep_name)
  requerido <- tolower(trimws(as.character(campos$required))) %in% c("yes", "true", "1", "sim")
  select_one <- grepl("select_one", paste(campos$type, campos$tipo_base), ignore.case = TRUE)
 ### O domínio e o required do atributo canônico são validados contra o
 ### XLSForm-alvo 2025. A única exceção multiversão é samambaia: o mesmo
 ### `name` era texto de espécie/descritor em 2022--2024 e só passou a ser
 ### select_one de hábito em 2025 (Contrato Único, cláusula 39). Portanto não
 ### se pode impor esse hábito retroativamente às ocorrências históricas.
  arquivo_canonico <- grepl("21FEV25", as.character(campos$arquivo_xlsform), ignore.case = TRUE)
  regras <- campos[
    arquivo_canonico &
      (name == dep_name | caminho_registro == dep_path) &
      select_one & requerido
  ]
  regras_canonicas <- unique(as.character(regras$arquivo_xlsform))
  regras_canonicas <- regras_canonicas[!is.na(regras_canonicas) & nzchar(regras_canonicas)]
  if (length(regras_canonicas) != 1L) {
    stop(
      "Contrato canônico XLSForm 21FEV25 não resolveu de forma única o hábito obrigatório `",
      dep_path, "`.",
      call. = FALSE
    )
  }
  if (is.null(linhas_com_forma)) linhas_com_forma <- seq_len(n)
  linhas_com_forma <- unique(as.integer(linhas_com_forma))
  linhas_com_forma <- linhas_com_forma[!is.na(linhas_com_forma) & linhas_com_forma >= 1L & linhas_com_forma <= n]
  out <- rep(FALSE, n)
  out[linhas_com_forma] <- TRUE
  if (identical(forma, "samambaia")) {
 ### O protocolo observado já foi validado e reconciliado pelo resolvedor
 ### vetorial de aliases antes do painel. Reutilizá-lo aqui evita reconstruir
 ### o mapa completo XLSForm por linha em cada relatório/preview/gate. O
 ### cache pertence ao próprio data.table e não altera nenhuma coluna.
    protocolo_canonico <- NULL
    if (is.null(arquivo_por_linha) && "PROTOCOLO" %in% names(dt) &&
        exists("monitora_especie_protocolo_canonico", mode = "function")) {
      protocolo_canonico <- attr(dt, "monitora_protocolo_canonico_habito_cache", exact = TRUE)
      if (is.null(protocolo_canonico) || length(protocolo_canonico) != n) {
        protocolo_canonico <- monitora_especie_protocolo_canonico(dt[["PROTOCOLO"]])
        data.table::setattr(dt, "monitora_protocolo_canonico_habito_cache", protocolo_canonico)
      }
      arquivo_por_linha <- protocolo_canonico
    } else if (is.null(arquivo_por_linha)) {
      arquivo_por_linha <- monitora_correcao_xlsform_por_linha(dt, meta_xls = meta_xls)
    }
    arquivo_por_linha <- as.character(arquivo_por_linha)
    if (length(arquivo_por_linha) != n) {
      stop("Resolvedor multiversão de samambaia retornou cardinalidade incompatível.", call. = FALSE)
    }
    sem_versao <- is.na(arquivo_por_linha) | !nzchar(trimws(arquivo_por_linha))
    if (any(sem_versao[linhas_com_forma])) {
      stop(
        "Versão XLSForm não resolvida para ocorrência de samambaia; obrigação de hábito não pode ser inferida com segurança.",
        call. = FALSE
      )
    }
    out[linhas_com_forma] <- grepl("21FEV25", arquivo_por_linha[linhas_com_forma], ignore.case = TRUE)
  }
  out
}

monitora_correcao_ocorrencias_habito_detalhadas <- function(dt, meta_xls = NULL) {
 ### Fonte única, linha × categoria × forma, compartilhada por relatório,
 ### índice do painel e prévia integral. Não colapsa duas categorias pendentes
 ### na mesma linha física.
  dt <- data.table::as.data.table(dt)
  vazio <- data.table::data.table(
    linha_indice = integer(), monitora_row_id = character(), categoria_superior = character(),
    forma_de_vida_detectada = character(), atributo_forma_vida = character(),
    valor_forma_vida_principal = character(), atributo_canonico_habito = character(),
    atributo_habito_obrigatorio = character(),
    valor_habito_atual = character(), valores_validos_habito = character()
  )
  if (!nrow(dt)) return(vazio)
  conc <- tryCatch(monitora_correcao_conciliar_habito_historico_definitivo(dt, meta_xls = meta_xls, gravar = FALSE, contexto = "ocorrencias_habito_detalhadas"), error = function(e) NULL)
  if (is.list(conc) && !is.null(conc$dt)) dt <- data.table::as.data.table(conc$dt)
  meta_xls <- tryCatch(monitora_correcao_xlsform_meta_atual(meta_xls), error = function(e) meta_xls)
  habitos_validos <- c("terrestre", "epifita", "rupicola")
  regras_contrato <- monitora_correcao_regras_habito_contrato_atual(meta_xls)
 ### A versão de origem é uma propriedade da linha, não da categoria/forma.
 ### Resolva uma única vez por fotografia do estado e compartilhe o vetor com
 ### todas as 12 regras categoria×forma desta ocorrência diagnóstica.
  arquivo_habito_por_linha <- if (
    "PROTOCOLO" %in% names(dt) &&
      exists("monitora_especie_protocolo_canonico", mode = "function")
  ) {
    monitora_especie_protocolo_canonico(dt[["PROTOCOLO"]])
  } else {
    monitora_correcao_xlsform_por_linha(dt, meta_xls = meta_xls)
  }
  out <- list()
  for (categoria_alvo in unique(regras_contrato$categoria)) {
    col_lista <- tryCatch(monitora_correcao_coluna_forma_vida(dt, categoria_alvo), error = function(e) NA_character_)
    if (is.na(col_lista) || !(col_lista %in% names(dt))) next
    regras_cat <- regras_contrato[as.character(regras_contrato$categoria) == categoria_alvo]
    for (rr in seq_len(nrow(regras_cat))) {
      forma <- as.character(regras_cat$forma[rr])
      atributo_canonico <- as.character(regras_cat$atributo_canonico[rr])
      formas_busca <- unique(c(forma, if (identical(forma, "bromelioide")) "erva_bromelioide" else character()))
      hits_forma <- lapply(formas_busca, function(tok) {
        tryCatch(monitora_correcao_contem_qualquer_token_vec(dt[[col_lista]], tok), error = function(e) rep(FALSE, nrow(dt)))
      })
      hit <- Reduce(`|`, hits_forma)
      hit[is.na(hit)] <- FALSE
      if (!any(hit)) next
      exigido <- monitora_correcao_habito_requerido_por_linha(
        dt,
        categoria_alvo,
        forma,
        meta_xls = meta_xls,
        arquivo_por_linha = arquivo_habito_por_linha,
        linhas_com_forma = which(hit)
      )
      hit <- hit & exigido
      if (!any(hit)) next
      dep_col <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, categoria_alvo, forma, meta_xls = meta_xls), error = function(e) NA_character_)
      if (is.na(dep_col) || !(dep_col %in% names(dt))) next
      valor <- tolower(trimws(as.character(dt[[dep_col]])))
      faltando <- hit & (is.na(valor) | !nzchar(valor) | !(valor %in% habitos_validos))
      idx <- which(faltando)
      if (!length(idx)) next
      forma_exibida <- rep(forma, length(idx))
      if (identical(forma, "bromelioide") && length(hits_forma) > 1L) {
        apenas_alias <- hits_forma[[2L]][idx] & !hits_forma[[1L]][idx]
        forma_exibida[apenas_alias] <- "erva_bromelioide"
      }
      out[[length(out) + 1L]] <- data.table::data.table(
        linha_indice = idx,
        monitora_row_id = if (MONITORA_COL_ROW_ID %in% names(dt)) as.character(dt[[MONITORA_COL_ROW_ID]][idx]) else NA_character_,
        categoria_superior = categoria_alvo,
        forma_de_vida_detectada = forma_exibida,
        atributo_forma_vida = col_lista,
        valor_forma_vida_principal = as.character(dt[[col_lista]][idx]),
        atributo_canonico_habito = atributo_canonico,
        atributo_habito_obrigatorio = dep_col,
        valor_habito_atual = as.character(dt[[dep_col]][idx]),
        valores_validos_habito = "epifita|terrestre|rupicola"
      )
    }
  }
  if (length(out)) unique(
    data.table::rbindlist(out, fill = TRUE, use.names = TRUE),
    by = c("linha_indice", "categoria_superior", "atributo_canonico_habito")
  ) else vazio
}

### resolve um rótulo de hábito sem aceitar a pergunta histórica de
### espécie que reutilizava o mesmo `name`. A coluna operacional já foi
### resolvida por versão; aqui só escolhemos uma descrição segura para o
### relatório, priorizando select_one/domínio de hábito e rejeitando texto de
### espécie/nome popular.
monitora_correcao_label_habito_seguro <- function(campos_meta, dep_col, categoria, forma) {
  cm <- data.table::copy(data.table::as.data.table(campos_meta))
  if (!nrow(cm) || !("label" %in% names(cm))) return(as.character(dep_col))
  for (cc in c("caminho_registro", "name", "type", "list_name", "label")) {
    if (!(cc %in% names(cm))) cm[, (cc) := NA_character_]
  }
  cand <- cm[caminho_registro == dep_col | name == dep_col]
  if (!nrow(cand)) return(as.character(dep_col))
  texto <- tolower(paste(cand$type, cand$list_name, cand$label, sep = " | "))
  eh_especie <- grepl("esp[eé]cie|nome popular|species|_sp(\\b|_)", texto)
  eh_habito <- grepl("select_one|h[aá]bito|terrestre|ep[ií]fita|rup[ií]cola", texto)
  cand <- cand[!eh_especie]
  eh_habito <- eh_habito[!eh_especie]
  if (!nrow(cand)) return(as.character(dep_col))
  cand[, prioridade_label_r21 := as.integer(eh_habito)]
  data.table::setorder(cand, -prioridade_label_r21)
  lab <- as.character(cand$label[1L])
  if (is.na(lab) || !nzchar(trimws(lab))) as.character(dep_col) else lab
}
