### - ------------------------------------------------------------
### Catálogo operacional (fase-independente) dos tipos de ocorrência
### diagnóstica pré/pós-painel. Extraído de monitora_diag_rel_gerar_ocorrencias
### para ser a única fonte consultada tanto por ela quanto pela ponte de
### validações (monitora_ponte_pre_painel_regras_contrato_unico ,,
### definida perto de monitora_validacao_regras_por_perfil_contrato_unico),
### evitando duas listas hard-coded divergentes do mesmo catálogo.
monitora_diag_rel_catalogo_ocorrencias_base <- function() {
  data.table::data.table(
    tipo_ocorrencia = c(
      "uas_duplicadas_mesmo_ano", "ponto_sem_interceptacao", "nativa_sem_forma_vida", "exotica_sem_forma_vida", "seca_morta_sem_forma_vida", "outra_forma_vida", "forma_vida_desconhecida_invalida", "forma_vida_desconhecida", "forma_vida_exotica_sem_especie", "forma_vida_exotica_com_especie", "solo_nu_com_outra_categoria", "habito_obrigatorio_ausente"
    ),
    rotulo_ocorrencia = c(
      "UAs duplicadas no mesmo ano", "Ponto amostral sem interceptação", "Nativa sem forma de vida", "Exótica sem forma de vida", "Seca ou morta sem forma de vida", "Outra forma de vida", "Forma de vida desconhecida inválida", "Forma de vida desconhecida", "Revisão: forma de vida exótica sem espécie", "Revisão: forma de vida exótica com espécie", "Solo nu com outra categoria (exclusividade violada)", "Hábito obrigatório ausente"
    ),
    severidade = c(rep("impeditiva", 7L), rep("revisao", 3L), rep("impeditiva", 2L))
  )
}

### Resume somente ocorrências não impeditivas usando o mesmo catálogo e o
### mesmo índice multialvo do painel. Não cria nova regra de diagnóstico e não
### interfere no gate de registros_validados.
monitora_diag_resumo_revisoes_painel <- function(resumo) {
  resumo <- data.table::copy(data.table::as.data.table(resumo))
  catalogo <- monitora_diag_rel_catalogo_ocorrencias_base()[severidade == "revisao", .(
    tipo_ocorrencia, ocorrencia = rotulo_ocorrencia
  )]
  for (cc in c("tipo_ocorrencia", "n_ocorrencias", "n_linhas", "n_coletas")) {
    if (!(cc %in% names(resumo))) data.table::set(resumo, j = cc, value = if (cc == "tipo_ocorrencia") character(nrow(resumo)) else integer(nrow(resumo)))
  }
  resumo <- resumo[, .(
    n_ocorrencias = sum(suppressWarnings(as.integer(n_ocorrencias)), na.rm = TRUE),
    n_linhas = sum(suppressWarnings(as.integer(n_linhas)), na.rm = TRUE),
    n_coletas = sum(suppressWarnings(as.integer(n_coletas)), na.rm = TRUE)
  ), by = tipo_ocorrencia]
  out <- merge(catalogo, resumo, by = "tipo_ocorrencia", all.x = TRUE, sort = FALSE)
  for (cc in c("n_ocorrencias", "n_linhas", "n_coletas")) out[is.na(get(cc)), (cc) := 0L]
  data.table::setnames(out, "tipo_ocorrencia", "tipo")
  out[]
}

### Fonte canônica de ocorrências de revisão de exóticas. A unidade é
### linha×forma, não apenas linha: uma mesma vareta pode conter, por exemplo,
### bromelioide com espécie vinculada e árvore sem espécie. A classificação de
### uma forma nunca é propagada para outra forma da mesma linha.
monitora_diag_exoticas_ocorrencias_detalhadas <- function(dt) {
  dt <- data.table::as.data.table(dt)
  vazio <- data.table::data.table(
    linha_indice = integer(), monitora_row_id = character(),
    forma_de_vida_detectada = character(), tipo_ocorrencia = character(),
    status_vinculo = character(), atributo_forma_vida = character(),
    valor_forma_vida_atual = character(), atributos_especie_vinculados = character(),
    valores_especie_vinculados = character()
  )
  if (!nrow(dt)) return(vazio)
  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list(tipo_forma_vida = NA_character_))
  tipo_col <- chaves$tipo_forma_vida
  if (is.null(tipo_col) || is.na(tipo_col) || !(tipo_col %in% names(dt))) return(vazio)
  forma_cols <- tryCatch(monitora_relatorio_exoticas_detectar_colunas_forma(dt), error = function(e) character(0))
  forma_cols <- unique(forma_cols[!is.na(forma_cols) & nzchar(forma_cols) & forma_cols %in% names(dt)])
  if (!length(forma_cols)) return(vazio)
  tem_exotica <- tryCatch(
    monitora_relatorio_exoticas_tem_token(dt[[tipo_col]], c("exotica", "exoticas", "exotico", "exoticos")),
    error = function(e) rep(FALSE, nrow(dt))
  )
  tem_exotica[is.na(tem_exotica)] <- FALSE
  candidatos <- which(tem_exotica)
  if (!length(candidatos)) return(vazio)
  mapa <- tryCatch(monitora_correcao_mapa_colunas_canonicas(dt), error = function(e) data.table::data.table())
  esp_cols_fisicos <- tryCatch(monitora_relatorio_exoticas_detectar_colunas_especies(dt), error = function(e) character(0))
  mapa_especie_fisico <- if (length(esp_cols_fisicos)) tryCatch(monitora_relatorio_exoticas_mapa_forma_especie(esp_cols_fisicos), error = function(e) list()) else list()
  dominio <- tryCatch(monitora_contrato_tokens_categoria_movimento("exotica"), error = function(e) character(0))
  dominio <- unique(monitora_correcao_forma_canonica_lote(dominio))
  partes <- vector("list", length(candidatos))
  for (kk in seq_along(candidatos)) {
    ii <- candidatos[kk]
    vals <- as.character(unlist(dt[ii, ..forma_cols], use.names = FALSE))
    tokens <- unique(unlist(lapply(vals, monitora_correcao_tokenizar), use.names = FALSE))
    tokens <- unique(monitora_correcao_forma_canonica_lote(tokens))
    tokens <- tokens[!is.na(tokens) & nzchar(tokens)]
    if (length(dominio)) tokens <- tokens[tokens %in% dominio]
    if (!length(tokens)) next
    linhas_forma <- vector("list", length(tokens))
    for (jj in seq_along(tokens)) {
      tok <- tokens[jj]
      esp_cols <- tryCatch(monitora_correcao_colunas_especie_exotica_por_forma(dt, tok, mapa = mapa), error = function(e) character(0))
 ### O mapa canônico pode não classificar como `especie_nome_popular`
 ### rótulos físicos de XLSForms históricos (notadamente árvores D30).
 ### Une, portanto, a resolução contratual ao reconhecedor multiversão
 ### de cabeçalhos já usado pelos relatórios; a espécie continua estrita
 ### à forma correspondente e nunca vaza para outra forma da linha.
      if (length(mapa_especie_fisico)) {
        tok_fisico <- if (identical(tok, "liana")) "lianas" else if (identical(tok, "erva_bromelioide")) "bromelioide" else tok
        if (tok_fisico %in% names(mapa_especie_fisico)) esp_cols <- unique(c(esp_cols, mapa_especie_fisico[[tok_fisico]]))
      }
      esp_cols <- unique(esp_cols[esp_cols %in% names(dt)])
      esp_ok_cols <- character(0); esp_ok_vals <- character(0)
      if (length(esp_cols)) {
        esp_vals <- as.character(unlist(dt[ii, ..esp_cols], use.names = FALSE))
        ok <- tryCatch(monitora_relatorio_exoticas_tem_especie_valida(esp_vals), error = function(e) !is.na(esp_vals) & nzchar(trimws(esp_vals)))
        ok[is.na(ok)] <- FALSE
        esp_ok_cols <- esp_cols[ok]
        esp_ok_vals <- esp_vals[ok]
      }
      tem_sp <- length(esp_ok_cols) > 0L
      campos_tok <- forma_cols[vapply(forma_cols, function(cc) {
        tryCatch(monitora_relatorio_exoticas_tem_token(dt[[cc]][ii], tok), error = function(e) FALSE)
      }, logical(1L))]
      linhas_forma[[jj]] <- data.table::data.table(
        linha_indice = as.integer(ii),
        monitora_row_id = if (MONITORA_COL_ROW_ID %in% names(dt)) as.character(dt[[MONITORA_COL_ROW_ID]][ii]) else NA_character_,
        forma_de_vida_detectada = tok,
        tipo_ocorrencia = if (tem_sp) "forma_vida_exotica_com_especie" else "forma_vida_exotica_sem_especie",
        status_vinculo = if (tem_sp) "exotica_com_forma_e_sp_vinculada" else "exotica_com_forma_sem_sp_vinculada",
        atributo_forma_vida = paste(campos_tok, collapse = " | "),
        valor_forma_vida_atual = paste(paste0(campos_tok, " = ", as.character(unlist(dt[ii, ..campos_tok], use.names = FALSE))), collapse = " | "),
        atributos_especie_vinculados = paste(esp_ok_cols, collapse = " | "),
        valores_especie_vinculados = paste(paste0(esp_ok_cols, " = ", esp_ok_vals), collapse = " | ")
      )
    }
    partes[[kk]] <- data.table::rbindlist(linhas_forma, fill = TRUE, use.names = TRUE)
  }
  partes <- partes[!vapply(partes, is.null, logical(1L))]
  if (!length(partes)) return(vazio)
  unique(data.table::rbindlist(partes, fill = TRUE, use.names = TRUE), by = c("linha_indice", "forma_de_vida_detectada"))
}

### gate entre a fonte canônica detalhada e os consumidores do painel.
### A verificação é por identidade linha×forma×tipo, não apenas por totais.
### Assim, uma compensação entre "com espécie" e "sem espécie" não pode
### produzir uma prévia aparentemente reconciliada.
monitora_diag_reconciliar_exoticas_painel <- function(dt, triagem, contexto = "painel", base_dir = NULL, falhar = TRUE, esperado_precomputado = NULL) {
  esperado <- if (data.table::is.data.table(esperado_precomputado)) {
    data.table::copy(esperado_precomputado)
  } else {
    data.table::copy(monitora_diag_exoticas_ocorrencias_detalhadas(dt))
  }
  observado <- data.table::copy(data.table::as.data.table(triagem))
  tipos <- c("forma_vida_exotica_sem_especie", "forma_vida_exotica_com_especie")
  status_tipo <- c(
    exotica_com_forma_sem_sp_vinculada = "forma_vida_exotica_sem_especie",
    exotica_com_forma_e_sp_vinculada = "forma_vida_exotica_com_especie"
  )
  duplicadas <- data.table::data.table(linha_indice = integer(), forma_de_vida_detectada = character(), tipo_ocorrencia = character())
  if (!nrow(esperado)) {
    esperado <- data.table::data.table(linha_indice = integer(), forma_de_vida_detectada = character(), tipo_ocorrencia = character())
  } else {
    esperado <- unique(esperado[tipo_ocorrencia %in% tipos, .(
      linha_indice = as.integer(linha_indice),
      forma_de_vida_detectada = as.character(forma_de_vida_detectada),
      tipo_ocorrencia = as.character(tipo_ocorrencia)
    )])
  }
  if (!nrow(observado) || !("status_vinculo" %in% names(observado))) {
    observado <- data.table::data.table(linha_indice = integer(), forma_de_vida_detectada = character(), tipo_ocorrencia = character())
  } else {
    if (!("linha_indice_global" %in% names(observado))) observado[, linha_indice_global := NA_integer_]
    if (!("linha_filtro" %in% names(observado))) observado[, linha_filtro := NA_integer_]
    if (!("token_detectado" %in% names(observado))) observado[, token_detectado := NA_character_]
    observado <- observado[status_vinculo %in% names(status_tipo)]
    observado[, linha_indice := suppressWarnings(as.integer(linha_indice_global))]
    observado[is.na(linha_indice), linha_indice := suppressWarnings(as.integer(linha_filtro))]
    observado[, `:=`(
      forma_de_vida_detectada = vapply(as.character(token_detectado), function(z) {
        zz <- monitora_correcao_forma_canonica_lote(z)
        if (length(zz)) as.character(zz[1L]) else ""
      }, character(1L)),
      tipo_ocorrencia = unname(status_tipo[as.character(status_vinculo)])
    )]
    duplicadas <- unique(observado[
      duplicated(observado, by = c("linha_indice", "forma_de_vida_detectada", "tipo_ocorrencia")) |
        duplicated(observado, by = c("linha_indice", "forma_de_vida_detectada", "tipo_ocorrencia"), fromLast = TRUE),
      .(linha_indice, forma_de_vida_detectada, tipo_ocorrencia)
    ])
    observado <- unique(observado[, .(linha_indice, forma_de_vida_detectada, tipo_ocorrencia)])
  }
  cols_id <- c("linha_indice", "forma_de_vida_detectada", "tipo_ocorrencia")
  faltantes <- esperado[!observado, on = cols_id]
  extras <- observado[!esperado, on = cols_id]
  ok <- nrow(faltantes) == 0L && nrow(extras) == 0L && nrow(duplicadas) == 0L
  auditoria <- data.table::rbindlist(list(
    esperado[, `:=`(presente_fonte_canonica = TRUE, presente_consumidor_painel = TRUE)][observado, on = cols_id, nomatch = 0L],
    faltantes[, `:=`(presente_fonte_canonica = TRUE, presente_consumidor_painel = FALSE)],
    extras[, `:=`(presente_fonte_canonica = FALSE, presente_consumidor_painel = TRUE)]
  ), fill = TRUE, use.names = TRUE)
  auditoria[, `:=`(contexto = as.character(contexto)[1L], reconciliado = ok, ocorrencia_duplicada_consumidor = FALSE)]
  if (nrow(duplicadas)) auditoria[duplicadas, on = cols_id, ocorrencia_duplicada_consumidor := TRUE]
  if (!is.null(base_dir) && length(base_dir) && !is.na(base_dir[1L]) && nzchar(base_dir[1L])) {
    dir.create(base_dir[1L], recursive = TRUE, showWarnings = FALSE)
    arq <- file.path(base_dir[1L], paste0("auditoria_reconciliacao_exoticas_", gsub("[^a-zA-Z0-9_-]+", "_", contexto), ".csv"))
    monitora_fwrite(auditoria, arq, na = "")
  }
  if (!ok && isTRUE(falhar)) {
    stop(
      "Divergência entre a fonte canônica de exóticas e ", contexto,
      ": ", nrow(faltantes), " identidade(s) faltante(s), ", nrow(extras), " extra(s) e ", nrow(duplicadas), " duplicada(s).",
      call. = FALSE
    )
  }
  list(ok = ok, esperado = esperado, observado = observado, faltantes = faltantes, extras = extras, duplicadas = duplicadas, auditoria = auditoria)
}

monitora_diag_chave_ocorrencia <- function(x) {
  x <- data.table::as.data.table(x)
  n <- nrow(x)
  if (!n) return(character(0))
  campo <- function(nm) {
    if (!(nm %in% names(x))) return(rep("", n))
    z <- as.character(x[[nm]]); z[is.na(z)] <- ""; trimws(z)
  }
  id <- campo("monitora_row_id")
  id[!nzchar(id)] <- paste0("LINHA::", campo("linha_indice")[!nzchar(id)])
  atributo_habito <- campo("atributo_habito_obrigatorio")
  atributo_habito[!nzchar(atributo_habito)] <- campo("atributo_canonico_habito")[!nzchar(atributo_habito)]
  paste(
    campo("tipo_ocorrencia"), id, campo("categoria_superior"),
    campo("forma_de_vida_detectada"), atributo_habito,
    sep = "\034"
  )
}

monitora_diag_validar_ocorrencias_materializadas <- function(todos, fase, base_dir) {
  todos <- data.table::as.data.table(todos)
  assign("MONITORA_OCORRENCIAS_DIAGNOSTICAS_INTEGRIDADE_OK", FALSE, envir = .GlobalEnv)
  chaves <- monitora_diag_chave_ocorrencia(todos)
  dup <- duplicated(chaves) | duplicated(chaves, fromLast = TRUE)
  campo <- function(nm) {
    if (!(nm %in% names(todos))) return(rep("", nrow(todos)))
    z <- as.character(todos[[nm]]); z[is.na(z)] <- ""; trimws(z)
  }
  tipo <- campo("tipo_ocorrencia")
  sem_id <- !nzchar(campo("monitora_row_id")) & !nzchar(campo("linha_indice"))
  ex <- tipo %in% c("forma_vida_exotica_sem_especie", "forma_vida_exotica_com_especie")
  ex_sem_forma <- ex & !nzchar(campo("forma_de_vida_detectada"))
  hab <- tipo == "habito_obrigatorio_ausente"
  hab_incompleto <- hab & (!nzchar(campo("categoria_superior")) |
    !nzchar(campo("forma_de_vida_detectada")) |
    !nzchar(campo("atributo_habito_obrigatorio")))

  ler <- function(path) {
    tryCatch(data.table::fread(path, encoding = "UTF-8", na.strings = NULL, colClasses = "character", showProgress = FALSE),
      error = function(e) structure(data.table::data.table(), erro_leitura = conditionMessage(e)))
  }
  fase_rx <- gsub("([][{}()+*^$|\\?.])", "\\\\\\1", as.character(fase)[1L])
  arqs_tipo <- list.files(base_dir, pattern = paste0("^registros_.*_", fase_rx, "\\.csv$"), full.names = TRUE)
  arqs_tipo <- arqs_tipo[!grepl(paste0("/registros_ocorrencias_diagnosticas_", fase_rx, "\\.csv$"), arqs_tipo)]
  partes <- lapply(arqs_tipo, ler)
  erro_leitura <- vapply(partes, function(x) !is.null(attr(x, "erro_leitura")), logical(1L))
  tipos_materializados <- if (length(partes)) data.table::rbindlist(partes, fill = TRUE, use.names = TRUE) else data.table::data.table()
  chaves_tipos <- monitora_diag_chave_ocorrencia(tipos_materializados)
  arquivo_unificado <- file.path(base_dir, paste0("registros_ocorrencias_diagnosticas_", fase, ".csv"))
  unificado <- if (file.exists(arquivo_unificado)) ler(arquivo_unificado) else data.table::data.table()
  chaves_unificado <- monitora_diag_chave_ocorrencia(unificado)
  iguais_tipos <- !any(erro_leitura) && length(chaves_tipos) == length(chaves) && identical(sort(chaves_tipos), sort(chaves))
  iguais_unificado <- file.exists(arquivo_unificado) && is.null(attr(unificado, "erro_leitura")) &&
    length(chaves_unificado) == length(chaves) && identical(sort(chaves_unificado), sort(chaves))

  catalogo <- monitora_diag_rel_catalogo_ocorrencias_base()
  esperado_resumo <- if (nrow(todos)) todos[, .(
    n_linhas = data.table::uniqueN(linha_indice), n_ocorrencias_detalhadas = .N,
    n_coletas = data.table::uniqueN(COLETA[!is.na(COLETA) & nzchar(COLETA)])
  ), by = tipo_ocorrencia] else data.table::data.table(tipo_ocorrencia = character(), n_linhas = integer(), n_ocorrencias_detalhadas = integer(), n_coletas = integer())
  esperado_resumo <- merge(catalogo[, .(tipo_ocorrencia)], esperado_resumo, by = "tipo_ocorrencia", all.x = TRUE)
  for (cc in c("n_linhas", "n_ocorrencias_detalhadas", "n_coletas")) esperado_resumo[is.na(get(cc)), (cc) := 0L]
  validar_tabela_contagens <- function(path) {
    if (!file.exists(path)) return(FALSE)
    z <- ler(path)
    if (!is.null(attr(z, "erro_leitura")) || !all(c("tipo_ocorrencia", "n_linhas", "n_ocorrencias_detalhadas", "n_coletas") %in% names(z))) return(FALSE)
    z <- z[, .(
      tipo_ocorrencia = as.character(tipo_ocorrencia),
      n_linhas = suppressWarnings(as.integer(n_linhas)),
      n_ocorrencias_detalhadas = suppressWarnings(as.integer(n_ocorrencias_detalhadas)),
      n_coletas = suppressWarnings(as.integer(n_coletas))
    )]
    z <- z[tipo_ocorrencia %in% esperado_resumo$tipo_ocorrencia]
    cmp <- merge(esperado_resumo, z, by = "tipo_ocorrencia", all = TRUE, suffixes = c("_esperado", "_observado"))
    nrow(cmp) == nrow(esperado_resumo) && all(
      cmp$n_linhas_esperado == cmp$n_linhas_observado &
      cmp$n_ocorrencias_detalhadas_esperado == cmp$n_ocorrencias_detalhadas_observado &
      cmp$n_coletas_esperado == cmp$n_coletas_observado
    )
  }
  resumo_ok <- validar_tabela_contagens(file.path(base_dir, paste0("resumo_ocorrencias_diagnosticas_", fase, ".csv")))
  indice_ok <- validar_tabela_contagens(file.path(base_dir, "indice_relatorios_ocorrencias_diagnosticas.csv"))
  n_tipos_esperados <- nrow(catalogo)
  tipos_arquivos <- if (nrow(tipos_materializados) && "tipo_ocorrencia" %in% names(tipos_materializados)) unique(as.character(tipos_materializados$tipo_ocorrencia)) else character(0)
  cobertura_tipos_ok <- length(arqs_tipo) == n_tipos_esperados && setequal(tipos_arquivos, unique(tipo))

  falha <- any(dup) || any(sem_id) || any(ex_sem_forma) || any(hab_incompleto) ||
    !iguais_tipos || !iguais_unificado || !resumo_ok || !indice_ok || !cobertura_tipos_ok
  aud <- data.table::data.table(
    fase = as.character(fase)[1L], n_ocorrencias = length(chaves), n_chaves_unicas = data.table::uniqueN(chaves),
    n_duplicatas_identidade_semantica = sum(dup), n_sem_identidade_linha = sum(sem_id),
    n_exoticas_sem_forma_identificada = sum(ex_sem_forma), n_habitos_com_identidade_incompleta = sum(hab_incompleto),
    n_arquivos_tipos = length(arqs_tipo), n_arquivos_tipos_esperado = n_tipos_esperados,
    tipos_vs_fonte_exata = iguais_tipos, unificado_vs_fonte_exata = iguais_unificado,
    resumo_vs_fonte_exata = resumo_ok, indice_vs_fonte_exata = indice_ok,
    cobertura_tipos_ok = cobertura_tipos_ok,
    status = if (falha) "falha_integridade_materializacao_ocorrencias" else "ok_identidades_e_contagens_exatas"
  )
  monitora_fwrite(aud, file.path(base_dir, paste0("auditoria_identidades_ocorrencias_diagnosticas_", fase, ".csv")), na = "")
  if (falha) stop("Integridade dos relatórios de ocorrências diagnósticas falhou em ", fase, "; publicação de registros_validados bloqueada. Ver auditoria_identidades_ocorrencias_diagnosticas_", fase, ".csv.", call. = FALSE)
  assign("MONITORA_OCORRENCIAS_DIAGNOSTICAS_INTEGRIDADE_OK", TRUE, envir = .GlobalEnv)
  aud
}
### - ----------------------------------------------------

### Relatórios diagnósticos de ocorrências do painel ------------------------
### Gera relatórios operacionais pré/pós-painel para todas as ocorrências
### diagnósticas exibidas no filtro. Esta rotina é independente dos relatórios
### históricos de apoio e grava somente arquivos regulares dentro de
### ocorrencias_diagnosticas/, evitando interferência na comparação MD5 antiga.
monitora_diag_rel_enriquecer_habito_contrato <- function(x) {
  x <- data.table::as.data.table(x)
  if (!nrow(x) || !("tipo_ocorrencia" %in% names(x))) return(x)
  idx <- which(as.character(x$tipo_ocorrencia) == "habito_obrigatorio_ausente")
  if (!length(idx)) return(x)

  cols_char <- c(
    "categoria", "status_contrato", "atributo_lista", "atributo_problema",
    "valor_observado", "regra_contrato", "motivo_rejeicao"
  )
  for (cc in cols_char) {
    if (!(cc %in% names(x))) data.table::set(x, j = cc, value = rep(NA_character_, nrow(x)))
    else if (!is.character(x[[cc]])) data.table::set(x, j = cc, value = as.character(x[[cc]]))
  }
  if (!("bloqueia_registros_validados" %in% names(x))) {
    data.table::set(x, j = "bloqueia_registros_validados", value = rep(NA, nrow(x)))
  }
  valor <- if ("valor_habito_atual" %in% names(x)) as.character(x$valor_habito_atual[idx]) else rep(NA_character_, length(idx))
  valor_vazio <- is.na(valor) | !nzchar(trimws(valor))
  categoria <- if ("categoria_superior" %in% names(x)) as.character(x$categoria_superior[idx]) else rep(NA_character_, length(idx))
  forma <- if ("forma_de_vida_detectada" %in% names(x)) as.character(x$forma_de_vida_detectada[idx]) else rep(NA_character_, length(idx))
  atributo_habito <- if ("atributo_habito_obrigatorio" %in% names(x)) as.character(x$atributo_habito_obrigatorio[idx]) else rep(NA_character_, length(idx))

  data.table::set(x, i = idx, j = "categoria", value = categoria)
  data.table::set(x, i = idx, j = "status_contrato", value = ifelse(valor_vazio, "campo_required_relevante_vazio", "valor_habito_fora_dominio"))
  data.table::set(x, i = idx, j = "bloqueia_registros_validados", value = TRUE)
  data.table::set(x, i = idx, j = "atributo_lista", value = paste0("amostragem/registro/forma_vida_", categoria))
  data.table::set(x, i = idx, j = "atributo_problema", value = atributo_habito)
  data.table::set(x, i = idx, j = "valor_observado", value = ifelse(valor_vazio, "<vazio>", valor))
  data.table::set(x, i = idx, j = "regra_contrato", value = paste0(
    "required=yes; relevant=selected(${forma_vida_", categoria, "}, '",
    monitora_correcao_normalizar_forma_habito(forma), "'); domínio=epifita|terrestre|rupicola"
  ))
  data.table::set(x, i = idx, j = "motivo_rejeicao", value = ifelse(
    valor_vazio,
    "campo required vazio para forma presente e relevante",
    paste0("valor fora do domínio epifita|terrestre|rupicola: ", valor)
  ))
  x[]
}

monitora_diag_rel_gerar_ocorrencias <- function(dt,
                                                fase = c("pre_painel", "pos_painel"),
                                                base_dir = NULL,
                                                coletas_triagem_por_tipo = NULL,
                                                triagem_painel_unificada = NULL,
                                                indices_precomputados = NULL,
                                                habito_detalhes_precomputados = NULL,
                                                validar_contagens = TRUE) {
  fase <- as.character(fase)[1L]
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório para relatórios diagnósticos.", call. = FALSE)
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (is.null(base_dir)) {
    corr_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE)
    pasta_fase <- if (grepl("^pre", fase)) "relatorios_pre_painel" else "relatorios_pos_painel"
    base_dir <- file.path(corr_dir, pasta_fase, "ocorrencias_diagnosticas")
  }
  dir.create(base_dir, recursive = TRUE, showWarnings = FALSE)

  write_dt <- function(x, arquivo) {
    x <- data.table::as.data.table(x)
    dir.create(dirname(arquivo), recursive = TRUE, showWarnings = FALSE)
    tryCatch(
      data.table::fwrite(x, arquivo, na = "", encoding = "UTF-8", bom = TRUE, eol = "\n"),
      error = function(e) utils::write.csv(as.data.frame(x), arquivo, row.names = FALSE, na = "", fileEncoding = "UTF-8")
    )
    invisible(arquivo)
  }

  empty_rel <- function() {
    data.table::data.table(
      etapa = character(), tipo_ocorrencia = character(), rotulo_ocorrencia = character(), severidade = character(),
      linha_indice = integer(), monitora_row_id = character(), COLETA = character(), UC = character(), EA = character(), UA = character(), CICLO = character(), CAMPANHA = character(), ANO = character(),
      `Data (data_hora)` = character(), PROTOCOLO = character(), num_placa_formatado = character(), ponto_amostral = character(), ponto_metro = character(), Encostam = character(),
      campo_superior = character(), token_problematico = character(), campo_forma_vida_esperado = character(), valor_forma_vida_atual = character(),
      campos_dependentes_preenchidos = character(), acao_recomendada = character()
    )
  }

  catalogo <- data.table::copy(monitora_diag_rel_catalogo_ocorrencias_base())
  prefixos_arquivo_catalogo <- c(
    uas_duplicadas_mesmo_ano = "registros_ua_duplicada_mesmo_ano_",
    ponto_sem_interceptacao = "registros_ponto_sem_interceptacao_",
    nativa_sem_forma_vida = "registros_nativa_sem_forma_vida_",
    exotica_sem_forma_vida = "registros_exotica_sem_forma_vida_",
    seca_morta_sem_forma_vida = "registros_seca_morta_sem_forma_vida_",
    outra_forma_vida = "registros_outra_forma_vida_",
    forma_vida_desconhecida_invalida = "registros_forma_vida_desconhecida_invalida_",
    forma_vida_desconhecida = "registros_forma_vida_desconhecida_",
    forma_vida_exotica_sem_especie = "registros_forma_vida_exotica_sem_especie_",
    forma_vida_exotica_com_especie = "registros_forma_vida_exotica_com_especie_",
    solo_nu_com_outra_categoria = "registros_solo_nu_com_outra_categoria_",
    habito_obrigatorio_ausente = "registros_habito_obrigatorio_ausente_"
  )
  catalogo[, arquivo := paste0(prefixos_arquivo_catalogo[tipo_ocorrencia], fase, ".csv")]

  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list())
  col_ok <- function(col) !is.null(col) && length(col) && !is.na(as.character(col)[1L]) && nzchar(as.character(col)[1L]) && as.character(col)[1L] %in% names(dt)
  cache_vetores_rel <- new.env(parent = emptyenv())
  get_col <- function(col) {
    if (!col_ok(col)) return(rep(NA_character_, n))
    chave <- as.character(col)[1L]
    if (!exists(chave, envir = cache_vetores_rel, inherits = FALSE)) {
      assign(chave, as.character(dt[[chave]]), envir = cache_vetores_rel)
    }
    get(chave, envir = cache_vetores_rel, inherits = FALSE)
  }
  primeira_col <- function(nomes = character(), regex = character()) {
    out <- tryCatch(monitora_correcao_primeira_coluna(dt, nomes, regex), error = function(e) NA_character_)
    if (col_ok(out)) as.character(out)[1L] else NA_character_
  }
  col_data <- chaves[["data_hora"]]
  col_prot <- primeira_col(c("PROTOCOLO", "protocolo"), c("^protocolo$"))
  col_placa <- primeira_col(c("num_placa_formatado", "amostragem/num_placa_formatado", "Número da placa", "numero_placa", "num_placa"), c("num.*placa", "numero.*placa", "placa"))
  tipo_col <- chaves[["tipo_forma_vida"]]
  tipo_val <- get_col(tipo_col)
  coleta <- get_col(chaves[["coleta"]])

  vec_ch <- function(nm) get_col(chaves[[nm]])
  vazio <- function(x) {
    out <- tryCatch(monitora_correcao_vazio_vec(x), error = function(e) is.na(x) | !nzchar(trimws(as.character(x))))
    out[is.na(out)] <- TRUE
    out
  }
  tem_token <- function(tokens) {
    if (!n) return(logical(0))
    out <- tryCatch(monitora_relatorio_exoticas_tem_token(tipo_val, tokens), error = function(e) rep(FALSE, n))
    out[is.na(out)] <- FALSE
    out
  }
  cols_categoria <- function(categoria) {
    cols <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(dt, categoria), error = function(e) character(0))
    unique(cols[!is.na(cols) & nzchar(cols) & cols %in% names(dt)])
  }
  tem_forma_categoria <- function(categoria) {
    cols <- cols_categoria(categoria)
    if (!length(cols)) return(rep(FALSE, n))
    out <- rep(FALSE, n)
    for (cc in cols) out <- out | !vazio(dt[[cc]])
    out[is.na(out)] <- FALSE
    out
  }
  collapse_cols_linha <- function(cols, idx) {
    cols <- unique(cols[!is.na(cols) & nzchar(cols) & cols %in% names(dt)])
    if (!length(cols) || !length(idx)) return(rep("", length(idx)))
 ### Montagem vetorizada por coluna evita um vapply por linha combinado a
 ### outro vapply por coluna, principal custo dos relatórios pré-painel em
 ### datasets largos.
    out_txt <- rep("", length(idx))
    for (cc in cols) {
      vv <- as.character(dt[[cc]][idx])
      hit <- !is.na(vv) & nzchar(trimws(vv))
      if (!any(hit)) next
      pedaco <- paste0(cc, " = ", vv[hit])
      out_txt[hit] <- ifelse(nzchar(out_txt[hit]), paste0(out_txt[hit], " | ", pedaco), pedaco)
    }
    out_txt
  }
  dependentes_categoria <- function(categoria, idx, excluir = character()) {
    if (!length(idx)) return(character(0))
    z <- tryCatch(monitora_correcao_normalizar_nome_coluna(names(dt)), error = function(e) tolower(names(dt)))
    cat_pat <- switch(categoria, nativa = "nativ", exotica = "exotic|exotica|exotico", seca_morta = "seca|morta", outras = "outra|outro|forma_vida_outros", "")
    if (!nzchar(cat_pat)) return(rep("", length(idx)))
    cols <- names(dt)[grepl(cat_pat, z)]
    cols <- setdiff(cols, excluir)
    cols <- cols[!grepl("^(monitora_|DATA_MONITORA|HASH_|hash_|arquivo_|origem_)", cols)]
    if (length(cols) > 30L) cols <- cols[seq_len(30L)]
    collapse_cols_linha(cols, idx)
  }
  idx_pre <- function(tipo, fallback) {
    if (is.list(indices_precomputados) && !is.null(indices_precomputados[[tipo]])) {
      z <- unique(suppressWarnings(as.integer(indices_precomputados[[tipo]])))
      return(z[!is.na(z) & z >= 1L & z <= n])
    }
    valor_fallback <- if (is.function(fallback)) fallback() else fallback
    unique(suppressWarnings(as.integer(valor_fallback)))
  }

  add_rows <- function(tipo_ocorrencia, mask = NULL, idx = NULL, token = NA_character_, campo_forma = NA_character_, valor_forma = NULL, dependentes = NULL, acao = "") {
    tipo_key <- as.character(tipo_ocorrencia)[1L]
    cat_row <- catalogo[catalogo$tipo_ocorrencia == tipo_key]
    if (!nrow(cat_row)) return(empty_rel())
    if (is.null(idx)) {
      mask <- as.logical(mask); mask[is.na(mask)] <- FALSE
      if (length(mask) != n) mask <- rep(FALSE, n)
      idx <- which(mask)
    }
    idx <- unique(as.integer(idx[!is.na(idx) & idx >= 1L & idx <= n]))
    if (!length(idx)) return(empty_rel())
    if (is.null(valor_forma)) valor_forma <- rep("", length(idx))
    if (length(valor_forma) == 1L) valor_forma <- rep(as.character(valor_forma), length(idx))
    if (is.null(dependentes)) dependentes <- rep("", length(idx))
    if (length(dependentes) == 1L) dependentes <- rep(as.character(dependentes), length(idx))
    data.table::data.table(
      etapa = fase,
      tipo_ocorrencia = tipo_key,
      rotulo_ocorrencia = cat_row$rotulo_ocorrencia[1L],
      severidade = cat_row$severidade[1L],
      linha_indice = idx,
      monitora_row_id = if (MONITORA_COL_ROW_ID %in% names(dt)) as.character(dt[[MONITORA_COL_ROW_ID]][idx]) else NA_character_,
      COLETA = coleta[idx],
      UC = vec_ch("uc")[idx],
      EA = vec_ch("ea")[idx],
      UA = vec_ch("ua")[idx],
      CICLO = vec_ch("ciclo")[idx],
      CAMPANHA = vec_ch("campanha")[idx],
      ANO = vec_ch("ano")[idx],
      `Data (data_hora)` = get_col(col_data)[idx],
      PROTOCOLO = get_col(col_prot)[idx],
      num_placa_formatado = get_col(col_placa)[idx],
      ponto_amostral = vec_ch("ponto_amostral")[idx],
      ponto_metro = vec_ch("ponto_metro")[idx],
      Encostam = tipo_val[idx],
      campo_superior = ifelse(col_ok(tipo_col), as.character(tipo_col)[1L], ""),
      token_problematico = as.character(token)[1L],
      campo_forma_vida_esperado = as.character(campo_forma)[1L],
      valor_forma_vida_atual = as.character(valor_forma),
      campos_dependentes_preenchidos = as.character(dependentes),
      acao_recomendada = acao
    )
  }

  rels <- list()

  if (n && all(vapply(list(vec_ch("uc"), vec_ch("ua"), vec_ch("ano"), coleta), function(x) any(!is.na(x) & nzchar(x)), logical(1)))) {
    aux <- data.table::data.table(linha_indice = seq_len(n), UC = vec_ch("uc"), UA = vec_ch("ua"), ANO = vec_ch("ano"), COLETA = coleta)
    aux <- aux[!is.na(UC) & nzchar(UC) & !is.na(UA) & nzchar(UA) & !is.na(ANO) & nzchar(ANO) & !is.na(COLETA) & nzchar(COLETA)]
    if (nrow(aux)) {
      grupos <- aux[, .(n_coletas = data.table::uniqueN(COLETA)), by = .(UC, UA, ANO)][n_coletas > 1L]
      idx_dup <- if (nrow(grupos)) aux[grupos, on = .(UC, UA, ANO), linha_indice] else integer(0)
      rels[["uas_duplicadas_mesmo_ano"]] <- add_rows("uas_duplicadas_mesmo_ano", idx = idx_dup, token = "UC+UA+ANO", campo_forma = "UC+UA+ANO+COLETA", acao = "Resolver no painel por exclusão de COLETA excedente, correção de UA/ANO quando houver erro documental ou outra modificação auditável.")
    }
  }


  idx_ponto <- idx_pre("ponto_sem_interceptacao", function() which(vazio(tipo_val)))
  rels[["ponto_sem_interceptacao"]] <- add_rows("ponto_sem_interceptacao", idx = idx_ponto, token = "Encostam vazio", campo_forma = ifelse(col_ok(tipo_col), as.character(tipo_col)[1L], ""), acao = "Conferir o registro original; se não houver interceptação registrada de forma válida, excluir a COLETA.")

  cols_nat <- cols_categoria("nativa")
  cols_exo <- cols_categoria("exotica")
  cols_sec <- cols_categoria("seca_morta")
  idx_nat <- idx_pre("nativa_sem_forma_vida", function() which(tem_token(c("nativa", "nativas", "nativo", "nativos")) & !tem_forma_categoria("nativa")))
  rels[["nativa_sem_forma_vida"]] <- add_rows("nativa_sem_forma_vida", idx = idx_nat, token = "nativa", campo_forma = paste(cols_nat, collapse = " | "), valor_forma = collapse_cols_linha(cols_nat, idx_nat), dependentes = dependentes_categoria("nativa", idx_nat, cols_nat), acao = "Conferir a planilha original. Se a forma de vida constar na planilha, preencher o campo inferior correspondente; se não foi registrada em campo, excluir a COLETA.")

  idx_exo <- idx_pre("exotica_sem_forma_vida", function() which(tem_token(c("exotica", "exoticas", "exotico", "exoticos")) & !tem_forma_categoria("exotica")))
  rels[["exotica_sem_forma_vida"]] <- add_rows("exotica_sem_forma_vida", idx = idx_exo, token = "exotica", campo_forma = paste(cols_exo, collapse = " | "), valor_forma = collapse_cols_linha(cols_exo, idx_exo), dependentes = dependentes_categoria("exotica", idx_exo, cols_exo), acao = "Conferir a planilha original. Se a forma de vida constar na planilha, preencher o campo inferior correspondente; se não foi registrada em campo, excluir a COLETA.")

  idx_sec <- idx_pre("seca_morta_sem_forma_vida", function() which(tem_token(c("seca_morta", "seca", "secas", "seco", "secos", "morta", "mortas", "morto", "mortos")) & !tem_forma_categoria("seca_morta")))
  rels[["seca_morta_sem_forma_vida"]] <- add_rows("seca_morta_sem_forma_vida", idx = idx_sec, token = "seca_morta/seca/morta", campo_forma = paste(cols_sec, collapse = " | "), valor_forma = collapse_cols_linha(cols_sec, idx_sec), dependentes = dependentes_categoria("seca_morta", idx_sec, cols_sec), acao = "Conferir a planilha original. Se a forma de vida constar na planilha, preencher o campo inferior correspondente; se não foi registrada em campo, excluir a COLETA.")

  mask_outra <- rep(FALSE, n); cols_outra_hit <- character(0)
  cols_info <- tryCatch(monitora_correcao_colunas_limpeza_outras_formas(dt, NULL), error = function(e) data.table::data.table())
  if (nrow(cols_info)) {
    tokens_outra <- tryCatch(monitora_correcao_tokens_residuo_historico_outras_formas(), error = function(e) c("outra_forma_vida", "outras_formas_vida", "outra", "outro", "outras", "outros"))
    listas <- cols_info[classe == "lista_principal_forma_vida" & coluna %in% names(dt), unique(coluna)]
    descritores <- cols_info[classe == "descritor_outra_forma_vida" & coluna %in% names(dt), unique(coluna)]
    fotos <- cols_info[classe == "foto_outra_forma_vida" & coluna %in% names(dt), unique(coluna)]
    for (cc in listas) {
      hit <- tryCatch(monitora_correcao_contem_qualquer_token_vec(dt[[cc]], tokens_outra), error = function(e) rep(FALSE, n)); hit[is.na(hit)] <- FALSE
      if (any(hit)) cols_outra_hit <- unique(c(cols_outra_hit, cc))
      mask_outra <- mask_outra | hit
    }
    for (cc in unique(c(descritores, fotos))) {
      hit <- !vazio(dt[[cc]]); hit[is.na(hit)] <- FALSE
      if (any(hit)) cols_outra_hit <- unique(c(cols_outra_hit, cc))
      mask_outra <- mask_outra | hit
    }
  }
  idx_outra <- which(mask_outra)
  rels[["outra_forma_vida"]] <- add_rows("outra_forma_vida", idx = idx_outra, token = "outra_forma_vida/outra/outros", campo_forma = paste(cols_outra_hit, collapse = " | "), valor_forma = collapse_cols_linha(cols_outra_hit, idx_outra), dependentes = dependentes_categoria("outras", idx_outra, cols_outra_hit), acao = "Aplicar a sanitização assistida no painel ou corrigir manualmente; se a pendência permanecer, registros_corrig.csv será checkpoint pendente e registros_validados.csv ficará bloqueado.")

 ### Forma de vida desconhecida: o mesmo classificador contratual alimenta
 ### relatórios, painel, prévia e gate. A unidade é linha×categoria; não se
 ### generaliza a ocorrência para toda a coleta nem se duplica revisão e
 ### impedimento para a mesma linha.
  det_desc <- tryCatch(
    monitora_correcao_classificar_desconhecida(dt, chaves = chaves, dicionario = NULL),
    error = function(e) data.table::data.table()
  )
  montar_rel_desc <- function(tipo_desc, acao_desc) {
    det <- det_desc[tipo_ocorrencia == tipo_desc]
    if (!nrow(det)) return(empty_rel())
    base <- add_rows(
      tipo_desc, idx = unique(det$linha_indice), token = "desconhecida",
      campo_forma = "", valor_forma = "", dependentes = "", acao = acao_desc
    )
    extra <- det[, .(
      linha_indice,
      categoria_desconhecida = categoria,
      status_contrato_desconhecida = status_contrato,
      atributo_lista_desconhecida = atributo_lista,
      atributo_foto_obrigatoria_desconhecida = atributo_foto_obrigatoria,
      atributo_problema_desconhecida = atributo_problema,
      valor_observado_desconhecida = valor_observado,
      dependentes_preenchidos_desconhecida = atributos_dependentes_preenchidos,
      regra_contrato_desconhecida = regra_contrato,
      motivo_rejeicao_desconhecida = motivo_rejeicao,
      bloqueia_registros_validados_desconhecida = bloqueia_registros_validados
    )]
    out_desc <- merge(base, extra, by = "linha_indice", all.y = TRUE, allow.cartesian = TRUE, sort = FALSE)
    out_desc[, `:=`(
      campo_forma_vida_esperado = atributo_problema_desconhecida,
      valor_forma_vida_atual = valor_observado_desconhecida,
      campos_dependentes_preenchidos = dependentes_preenchidos_desconhecida,
      acao_recomendada = acao_desc
    )]
    out_desc[]
  }
  rels[["forma_vida_desconhecida_invalida"]] <- montar_rel_desc(
    "forma_vida_desconhecida_invalida",
    "Corrigir o motivo contratual detalhado no painel. Foto required ausente deve ser preenchida; dependente órfão ou token fora de relevância deve ser limpo/corrigido. A substituição assistida permanece disponível quando a decisão for trocar desconhecida por forma válida."
  )
  rels[["forma_vida_desconhecida"]] <- montar_rel_desc(
    "forma_vida_desconhecida",
    "Revisar a identificação. O token desconhecida é válido no XLSForm 2025 e, com a primeira foto preenchida, não bloqueia registros_validados; substituir somente quando houver decisão técnica."
  )


 ### Ocorrências de revisão exótica: fonte única linha×forma para pré, pós,
 ### preview e relatórios. Nunca colapsar espécies entre formas da mesma linha.
  det_exoticas <- monitora_diag_exoticas_ocorrencias_detalhadas(dt)
  montar_rel_exotica <- function(tipo_ex, acao_ex) {
    det <- det_exoticas[tipo_ocorrencia == tipo_ex]
    if (!nrow(det)) return(empty_rel())
    base <- add_rows(
      tipo_ex, idx = unique(det$linha_indice), token = tipo_ex,
      campo_forma = paste(cols_exo, collapse = " | "),
      valor_forma = collapse_cols_linha(cols_exo, unique(det$linha_indice)),
      dependentes = dependentes_categoria("exotica", unique(det$linha_indice), cols_exo),
      acao = acao_ex
    )
    merge(
      base, det,
      by = c("linha_indice", "monitora_row_id", "tipo_ocorrencia"),
      all.y = TRUE, allow.cartesian = TRUE, sort = FALSE,
      suffixes = c("", "_detalhe")
    )
  }
  rels[["forma_vida_exotica_sem_especie"]] <- montar_rel_exotica(
    "forma_vida_exotica_sem_especie",
    "Revisar espécie exótica vinculada à forma de vida. Ocorrência de revisão; não bloqueia sozinha registros_corrig.csv."
  )
  rels[["forma_vida_exotica_com_especie"]] <- montar_rel_exotica(
    "forma_vida_exotica_com_especie",
    "Revisar consistência taxonômica da espécie exótica vinculada. Ocorrência informativa/revisão."
  )

 ### -: antecipa para o painel (pré e pós) as duas checagens que
 ### hoje só bloqueiam no fechamento de registros_validados.csv via
 ### monitora_validados_validar_condicionais_xlsform21 .
  idx_solo_incompat <- idx_pre("solo_nu_com_outra_categoria", function() which(monitora_correcao_mask_solo_nu_incompativel(dt, chaves)))
  rels[["solo_nu_com_outra_categoria"]] <- add_rows("solo_nu_com_outra_categoria", idx = idx_solo_incompat, token = "solo_nu", campo_forma = ifelse(col_ok(tipo_col), as.character(tipo_col)[1L], ""), valor_forma = collapse_cols_linha(if (col_ok(tipo_col)) as.character(tipo_col)[1L] else character(0), idx_solo_incompat), acao = "solo_nu é exclusivo (constraint XLSForm: count-selected(.)=1 quando solo_nu selecionado). Remover solo_nu ou a(s) outra(s) categoria(s) conforme o registro original.")

  if (data.table::is.data.table(habito_detalhes_precomputados)) {
    det_hab_pre <- data.table::copy(habito_detalhes_precomputados)
    mask_hab_pre <- rep(FALSE, n)
    if (nrow(det_hab_pre)) mask_hab_pre[unique(det_hab_pre$linha_indice)] <- TRUE
    habito_res <- list(
      mask = mask_hab_pre,
      cols_forma_hit = unique(as.character(det_hab_pre$atributo_forma_vida)),
      cols_habito_hit = unique(as.character(det_hab_pre$atributo_habito_obrigatorio)),
      detalhes = det_hab_pre,
      dt = dt
    )
  } else {
    habito_res <- monitora_correcao_mask_habito_obrigatorio_ausente(dt)
  }
  idx_habito_ausente <- idx_pre("habito_obrigatorio_ausente", function() which(habito_res$mask))
  cols_habito_forma <- c(habito_res$cols_forma_hit, habito_res$cols_habito_hit)
  rels[["habito_obrigatorio_ausente"]] <- add_rows("habito_obrigatorio_ausente", idx = idx_habito_ausente, token = paste(monitora_correcao_tokens_formas_exigem_habito(), collapse = "/"), campo_forma = paste(cols_habito_forma, collapse = " | "), valor_forma = collapse_cols_linha(cols_habito_forma, idx_habito_ausente), acao = "Preencher o hábito (terrestre/epifita/rupicola) exigido para bromelioide/erva_bromelioide/cactacea/orquidea/samambaia; usar a operação assistida no painel ou corrigir manualmente.")

 ### Enriquece o relatório de
 ### hábito com colunas metadata-operacionais que respondem "qual forma de
 ### vida está presente neste ponto e qual hábito falta preencher?".
 ### Um único vetor por linha (`categoria_superior_v[preencher] <-...`, guardado por
 ### `is.na(categoria_superior_v)`) que só registrava a PRIMEIRA categoria×
 ### forma cujo TOKEN estivesse presente na lista principal -- nem sequer
 ### verificava se aquele hábito específico estava realmente vazio. Uma
 ### linha com a mesma forma em duas categorias (ex.: bromelioide em nativa
 ### E em seca_morta) só aparecia no relatório uma vez, atribuída à
 ### categoria processada primeiro. Se essa fosse a categoria já resolvida e
 ### a pendência real estivesse na outra, o relatório escondia a pendência
 ### de verdade; e se o usuário resolvesse só a categoria reportada, o
 ### mask/gate (monitora_correcao_mask_habito_obrigatorio_ausente , não
 ### tocado aqui) continuava corretamente bloqueando pela categoria que
 ### nunca apareceu no relatório -- a "pendência residual" confusa da validação operacional.
 ### Correção: emitir uma linha por PAR (linha, categoria, forma) realmente
 ### pendente (token presente E hábito vazio/inválido, mesmo teste do mask),
 ### sem descartar pares adicionais na mesma linha_indice.
  if (nrow(rels[["habito_obrigatorio_ausente"]]) && length(idx_habito_ausente)) {
    habitos_validos_hab <- c("terrestre", "epifita", "rupicola")
    meta_xls_hab <- tryCatch(monitora_correcao_xlsform_meta_atual(NULL), error = function(e) NULL)
    campos_meta_hab <- if (!is.null(meta_xls_hab) && !is.null(meta_xls_hab$campos)) data.table::as.data.table(meta_xls_hab$campos) else data.table::data.table()
    enr_habito <- if (data.table::is.data.table(habito_res$detalhes)) data.table::copy(habito_res$detalhes) else monitora_correcao_ocorrencias_habito_detalhadas(dt, meta_xls = meta_xls_hab)
    if (nrow(enr_habito)) {
      cache_label_hab <- new.env(parent = emptyenv())
      enr_habito[, label_habito := vapply(seq_len(.N), function(ii) {
        chave <- paste(atributo_habito_obrigatorio[ii], categoria_superior[ii], forma_de_vida_detectada[ii], sep = "\r")
        if (!exists(chave, envir = cache_label_hab, inherits = FALSE)) {
          assign(chave, monitora_correcao_label_habito_seguro(campos_meta_hab, atributo_habito_obrigatorio[ii], categoria_superior[ii], forma_de_vida_detectada[ii]), envir = cache_label_hab)
        }
        get(chave, envir = cache_label_hab, inherits = FALSE)
      }, character(1L))]
    }
    if (nrow(enr_habito)) {
 ### Se outra categoria também reivindica a mesma forma nesta linha,
 ### registra explicitamente se ela já está resolvida (dep preenchido) ou
 ### se também está pendente -- em vez de colapsar em uma "ambiguidade"
 ### única, como pedido no etapa_validacao.
      out_status_v <- character(nrow(enr_habito))
      cache_col_hab <- new.env(parent = emptyenv())
      for (kk in seq_len(nrow(enr_habito))) {
        li <- enr_habito$linha_indice[kk]
        cat_kk <- enr_habito$categoria_superior[kk]
        forma_kk <- enr_habito$forma_de_vida_detectada[kk]
        outras <- character(0)
        for (outra_cat in setdiff(c("nativa", "exotica", "seca_morta"), cat_kk)) {
          col_lista_outra <- tryCatch(monitora_correcao_coluna_forma_vida(dt, outra_cat), error = function(e) NA_character_)
          if (is.na(col_lista_outra) || !(col_lista_outra %in% names(dt))) next
          tem_outra <- tryCatch(monitora_correcao_contem_qualquer_token_vec(dt[[col_lista_outra]][li], forma_kk), error = function(e) FALSE)
          if (!isTRUE(tem_outra)) next
          chave_col_hab <- paste(outra_cat, forma_kk, sep = "\r")
          if (!exists(chave_col_hab, envir = cache_col_hab, inherits = FALSE)) {
            assign(chave_col_hab, tryCatch(monitora_correcao_resolver_coluna_habito(dt, outra_cat, forma_kk, meta_xls = meta_xls_hab), error = function(e) NA_character_), envir = cache_col_hab)
          }
          dep_col_outra <- get(chave_col_hab, envir = cache_col_hab, inherits = FALSE)
          if (is.na(dep_col_outra) || !(dep_col_outra %in% names(dt))) { outras <- c(outras, paste0(outra_cat, ":coluna_nao_resolvida")); next }
          val_outra <- tolower(trimws(as.character(dt[[dep_col_outra]][li])))
          resolvida <- !is.na(val_outra) && nzchar(val_outra) && val_outra %in% habitos_validos_hab
          outras <- c(outras, paste0(outra_cat, ":", if (resolvida) "ja_resolvida" else "tambem_pendente"))
        }
        out_status_v[kk] <- if (length(outras)) paste(outras, collapse = " | ") else "nenhuma"
      }
      enr_habito[, outra_categoria_mesma_forma := out_status_v]
    }
 ### Junta a auditoria de conciliação histórico->canônico já existente
 ### (mesma função usada na harmonização real, sem recálculo de regra) para
 ### as colunas origem_harmonizacao/status_harmonizacao, quando disponível.
 ### alias_ambiguo_ignorado chega aqui só como observação (nunca migra
 ### valor, nunca altera `faltando_dep`/o mask acima).
 ### a conciliação já ocorreu antes da máscara. Reutilizar seu ledger
 ### evita copiar e revarrer toda a matriz larga apenas para enriquecer CSV.
    audit_concil_cache <- attr(dt, "monitora_habito_historico_audit")
    if (!data.table::is.data.table(audit_concil_cache)) audit_concil_cache <- get0("MONITORA_AUDITORIA_CONCILIACAO_HABITO_CACHE", ifnotfound = data.table::data.table(), inherits = TRUE)
    concil_hab <- list(audit = data.table::as.data.table(audit_concil_cache))
    if (!is.null(concil_hab) && data.table::is.data.table(concil_hab$audit) && nrow(concil_hab$audit) && all(c("linha_indice", "atributo_definitivo", "alias_origem", "status") %in% names(concil_hab$audit))) {
      aud_hab <- unique(concil_hab$audit[, .(linha_indice, atributo_definitivo, origem_harmonizacao = alias_origem, status_harmonizacao = status)], by = c("linha_indice", "atributo_definitivo"))
      enr_habito <- merge(enr_habito, aud_hab, by.x = c("linha_indice", "atributo_habito_obrigatorio"), by.y = c("linha_indice", "atributo_definitivo"), all.x = TRUE, sort = FALSE)
    } else {
      enr_habito[, `:=`(origem_harmonizacao = NA_character_, status_harmonizacao = NA_character_)]
    }
 ### fan-out proposital: uma linha_indice pode gerar N>1 linhas no relatório
 ### quando há N pares categoria×forma pendentes nessa mesma linha.
 ### identidade estável participa do vínculo. O merge apenas por
 ### posição criava monitora_row_id.x/.y e deixava a coluna canônica vazia
 ### justamente nas ocorrências de hábito; após exclusão/reordenação, a
 ### posição também não é uma identidade segura.
    by_habito <- "linha_indice"
    if ("monitora_row_id" %in% names(rels[["habito_obrigatorio_ausente"]]) &&
        "monitora_row_id" %in% names(enr_habito)) {
      by_habito <- c("linha_indice", "monitora_row_id")
    }
    rels[["habito_obrigatorio_ausente"]] <- merge(
      rels[["habito_obrigatorio_ausente"]], enr_habito,
      by = by_habito, all.x = TRUE, sort = FALSE, allow.cartesian = TRUE
    )
  }

  for (tp in catalogo$tipo_ocorrencia) if (is.null(rels[[tp]])) rels[[tp]] <- empty_rel()
  todos <- data.table::rbindlist(rels[catalogo$tipo_ocorrencia], fill = TRUE, use.names = TRUE)
  todos <- monitora_diag_rel_enriquecer_habito_contrato(todos)
  if (nrow(todos)) {
    todos[, COLETA := as.character(COLETA)]
 ### Não deduplicar por linha física. A unidade contratual é a ocorrência:
 ### uma linha pode conter várias formas exóticas e vários pares
 ### categoria×forma com hábito obrigatório. Duplicatas verdadeiras são
 ### detectadas e bloqueadas pelo gate de identidade abaixo.
    data.table::setorder(todos, severidade, tipo_ocorrencia, UC, UA, ANO, COLETA, ponto_amostral, ponto_metro, linha_indice)
  }

  for (ii in seq_len(nrow(catalogo))) {
    tp <- catalogo$tipo_ocorrencia[ii]
    arq <- file.path(base_dir, catalogo$arquivo[ii])
    x <- if (nrow(todos)) todos[tipo_ocorrencia == tp] else empty_rel()
    write_dt(x, arq)
  }
  write_dt(todos, file.path(base_dir, paste0("registros_ocorrencias_diagnosticas_", fase, ".csv")))

  resumo <- if (nrow(todos)) {
    todos[, .(
 ### Uma linha física pode emitir mais de uma ocorrência de hábito
 ### (ex.: a mesma erva_bromelioide pendente em nativa e seca_morta).
 ### `n_linhas` volta a significar registros físicos únicos, como no
 ### modal/gate final; a granularidade categoria×forma fica explícita em
 ### `n_ocorrencias_detalhadas` e continua preservada no CSV detalhado.
      n_linhas = data.table::uniqueN(linha_indice),
      n_ocorrencias_detalhadas = .N,
      n_coletas = data.table::uniqueN(COLETA[!is.na(COLETA) & nzchar(COLETA)]),
      coletas_exemplo = paste(utils::head(unique(COLETA[!is.na(COLETA) & nzchar(COLETA)]), 30L), collapse = " | ")
    ), by = .(etapa, severidade, tipo_ocorrencia, rotulo_ocorrencia)]
  } else {
    data.table::data.table(etapa = character(), severidade = character(), tipo_ocorrencia = character(), rotulo_ocorrencia = character(), n_linhas = integer(), n_ocorrencias_detalhadas = integer(), n_coletas = integer(), coletas_exemplo = character())
  }
  resumo_all <- merge(catalogo[, .(tipo_ocorrencia, rotulo_ocorrencia, severidade)], resumo, by = c("tipo_ocorrencia", "rotulo_ocorrencia", "severidade"), all.x = TRUE)
  resumo_all[is.na(etapa), etapa := fase]
  resumo_all[is.na(n_linhas), n_linhas := 0L]
  resumo_all[is.na(n_ocorrencias_detalhadas), n_ocorrencias_detalhadas := 0L]
  resumo_all[is.na(n_coletas), n_coletas := 0L]
  resumo_all[is.na(coletas_exemplo), coletas_exemplo := ""]
  data.table::setcolorder(resumo_all, c("etapa", "severidade", "tipo_ocorrencia", "rotulo_ocorrencia", "n_linhas", "n_ocorrencias_detalhadas", "n_coletas", "coletas_exemplo"))
  data.table::setorder(resumo_all, severidade, tipo_ocorrencia)

  write_dt(resumo_all[severidade == "impeditiva"], file.path(base_dir, paste0("resumo_ocorrencias_impeditivas_", fase, ".csv")))
  write_dt(resumo_all, file.path(base_dir, paste0("resumo_ocorrencias_diagnosticas_", fase, ".csv")))

  indice <- catalogo[, .(etapa = fase, tipo_ocorrencia, rotulo_ocorrencia, severidade, arquivo, caminho = file.path(base_dir, arquivo))]
  indice <- resumo_all[indice, on = .(tipo_ocorrencia, rotulo_ocorrencia, severidade)]
  if ("i.etapa" %in% names(indice)) {
    indice[is.na(etapa) | !nzchar(as.character(etapa)), etapa := as.character(i.etapa)]
    indice[, i.etapa := NULL]
  }
  indice[, arquivo_existe := file.exists(caminho)]
  data.table::setcolorder(indice, c("etapa", "severidade", "tipo_ocorrencia", "rotulo_ocorrencia", "arquivo", "caminho", "arquivo_existe", "n_linhas", "n_ocorrencias_detalhadas", "n_coletas", "coletas_exemplo"))
  write_dt(indice, file.path(base_dir, "indice_relatorios_ocorrencias_diagnosticas.csv"))
  monitora_diag_validar_ocorrencias_materializadas(todos, fase, base_dir)

  validacao <- data.table::data.table()
  if (isTRUE(validar_contagens) && is.list(coletas_triagem_por_tipo)) {
    validacao <- data.table::rbindlist(lapply(intersect(names(coletas_triagem_por_tipo), catalogo$tipo_ocorrencia), function(tp) {
      exp <- coletas_triagem_por_tipo[[tp]]
      exp <- unique(as.character(exp)); exp <- exp[!is.na(exp) & nzchar(exp)]
      obs <- if (nrow(todos)) unique(as.character(todos[tipo_ocorrencia == tp, COLETA])) else character(0)
      obs <- obs[!is.na(obs) & nzchar(obs)]
      data.table::data.table(
        etapa = fase,
        tipo_ocorrencia = tp,
        n_coletas_triagem_painel = length(exp),
        n_coletas_relatorio = length(obs),
        consistente = identical(sort(exp), sort(obs)),
        coletas_na_triagem_nao_relatorio = paste(setdiff(sort(exp), sort(obs)), collapse = " | "),
        coletas_no_relatorio_nao_triagem = paste(setdiff(sort(obs), sort(exp)), collapse = " | ")
      )
    }), fill = TRUE)
    write_dt(validacao, file.path(base_dir, paste0("validacao_contagens_triagem_vs_relatorios_", fase, ".csv")))
  }

  n_csv <- length(list.files(base_dir, pattern = "\\.csv$", full.names = TRUE, recursive = FALSE))
  n_tipos_com_ocorrencia <- sum(resumo_all$n_coletas > 0L, na.rm = TRUE)
  soma_imp <- sum(resumo_all[severidade == "impeditiva", n_coletas], na.rm = TRUE)
  msg <- paste0("Relatórios de ocorrências diagnósticas [", fase, "] gerados em ", base_dir, "; arquivos_csv=", n_csv, "; tipos_com_ocorrencia=", n_tipos_com_ocorrencia, "; soma coletas impeditivas por tipo=", soma_imp, ".")
  if (exists("monitora_correcao_console_msg", mode = "function")) monitora_correcao_console_msg(msg) else message(msg)
  if (nrow(validacao) && any(!validacao$consistente, na.rm = TRUE)) {
    msg2 <- paste0("AVISO: contagens dos relatórios diagnósticos divergem da triagem do painel em ", sum(!validacao$consistente, na.rm = TRUE), " tipo(s). Ver validacao_contagens_triagem_vs_relatorios_", fase, ".csv.")
    if (exists("monitora_correcao_console_msg", mode = "function")) monitora_correcao_console_msg(msg2) else warning(msg2, call. = FALSE)
  }
  invisible(list(diretorio = base_dir, indice = indice, resumo = resumo_all, registros = todos, validacao = validacao))
}

### materialização leve do diagnóstico pré-painel. Os predicados e
### detalhes já foram calculados para o painel; repetir todo o enriquecimento
### largo antes de runApp tem custo elevado. Esta rotina grava os mesmos
### tipos, identidades, contexto e contagens a partir desses índices, enquanto
### o relatório enriquecido completo é gerado uma única vez no pós-painel.
monitora_diag_rel_gerar_ocorrencias_leve <- function(dt, fase = "pre_painel", base_dir,
                                                      coletas_triagem_por_tipo,
                                                      indices_precomputados = NULL,
                                                      habito_detalhes_precomputados = NULL) {
  dt <- data.table::as.data.table(dt)
  dir.create(base_dir, recursive = TRUE, showWarnings = FALSE)
  catalogo <- data.table::copy(monitora_diag_rel_catalogo_ocorrencias_base())
  prefixos <- c(
    uas_duplicadas_mesmo_ano = "registros_ua_duplicada_mesmo_ano_",
    ponto_sem_interceptacao = "registros_ponto_sem_interceptacao_",
    nativa_sem_forma_vida = "registros_nativa_sem_forma_vida_",
    exotica_sem_forma_vida = "registros_exotica_sem_forma_vida_",
    seca_morta_sem_forma_vida = "registros_seca_morta_sem_forma_vida_",
    outra_forma_vida = "registros_outra_forma_vida_",
    forma_vida_desconhecida_invalida = "registros_forma_vida_desconhecida_invalida_",
    forma_vida_desconhecida = "registros_forma_vida_desconhecida_",
    forma_vida_exotica_sem_especie = "registros_forma_vida_exotica_sem_especie_",
    forma_vida_exotica_com_especie = "registros_forma_vida_exotica_com_especie_",
    solo_nu_com_outra_categoria = "registros_solo_nu_com_outra_categoria_",
    habito_obrigatorio_ausente = "registros_habito_obrigatorio_ausente_"
  )
  catalogo[, arquivo := paste0(prefixos[tipo_ocorrencia], fase, ".csv")]
  chaves <- monitora_correcao_colunas_chave(dt)
  getv <- function(col, idx) {
    if (is.null(col) || is.na(col) || !(col %in% names(dt))) return(rep(NA_character_, length(idx)))
    as.character(dt[[col]][idx])
  }
  idx_tipo <- function(tp) {
    z <- if (is.list(indices_precomputados) && tp %in% names(indices_precomputados)) indices_precomputados[[tp]] else integer(0)
    if (is.logical(z)) z <- which(z)
    z <- unique(as.integer(z))
    z[!is.na(z) & z >= 1L & z <= nrow(dt)]
  }
  partes <- list()
  det_exoticas <- monitora_diag_exoticas_ocorrencias_detalhadas(dt)
  det_desconhecida <- tryCatch(monitora_correcao_classificar_desconhecida(dt, chaves = chaves, dicionario = NULL), error = function(e) data.table::data.table())
  for (tp in catalogo$tipo_ocorrencia) {
    det_tp <- if (tp %in% c("forma_vida_exotica_sem_especie", "forma_vida_exotica_com_especie")) {
      det_exoticas[tipo_ocorrencia == tp]
    } else if (tp %in% c("forma_vida_desconhecida_invalida", "forma_vida_desconhecida") && nrow(det_desconhecida)) {
      det_desconhecida[tipo_ocorrencia == tp]
    } else data.table::data.table()
    idx <- if (nrow(det_tp)) as.integer(det_tp$linha_indice) else idx_tipo(tp)
    coletas_tp <- if (is.list(coletas_triagem_por_tipo) && tp %in% names(coletas_triagem_por_tipo)) unique(as.character(coletas_triagem_por_tipo[[tp]])) else character(0)
    coletas_tp <- coletas_tp[!is.na(coletas_tp) & nzchar(coletas_tp)]
    if (!length(idx) && length(coletas_tp) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) idx <- which(as.character(dt[[chaves$coleta]]) %chin% coletas_tp)
    if (!length(idx)) next
    cat_row <- catalogo[tipo_ocorrencia == tp][1L]
    x <- data.table::data.table(
      etapa = fase, modo_relatorio = "indice_operacional_leve_pre_painel",
      tipo_ocorrencia = tp, rotulo_ocorrencia = cat_row$rotulo_ocorrencia,
      severidade = cat_row$severidade, linha_indice = idx,
      monitora_row_id = if (MONITORA_COL_ROW_ID %in% names(dt)) as.character(dt[[MONITORA_COL_ROW_ID]][idx]) else NA_character_,
      COLETA = getv(chaves$coleta, idx), UC = getv(chaves$uc, idx), EA = getv(chaves$ea, idx),
      UA = getv(chaves$ua, idx), CICLO = getv(chaves$ciclo, idx), CAMPANHA = getv(chaves$campanha, idx),
      ANO = getv(chaves$ano, idx), ponto_amostral = getv(chaves$ponto_amostral, idx), ponto_metro = getv(chaves$ponto_metro, idx),
      origem_indice = "predicado_precomputado_compartilhado_com_painel"
    )
    if (nrow(det_tp)) {
      cols_det <- setdiff(names(det_tp), c("linha_indice", "monitora_row_id", "tipo_ocorrencia"))
      for (cc in cols_det) data.table::set(x, j = cc, value = det_tp[[cc]])
    }
    if (identical(tp, "habito_obrigatorio_ausente") && data.table::is.data.table(habito_detalhes_precomputados) && nrow(habito_detalhes_precomputados)) {
      det <- data.table::copy(habito_detalhes_precomputados)
      x <- merge(x, det, by = c("linha_indice", "monitora_row_id"), all.x = TRUE, allow.cartesian = TRUE, sort = FALSE)
    }
    partes[[tp]] <- x
  }
  todos <- if (length(partes)) data.table::rbindlist(partes, fill = TRUE, use.names = TRUE) else data.table::data.table(
    etapa = character(), modo_relatorio = character(), tipo_ocorrencia = character(), rotulo_ocorrencia = character(), severidade = character(),
    linha_indice = integer(), monitora_row_id = character(), COLETA = character(), UC = character(), EA = character(), UA = character(), CICLO = character(), CAMPANHA = character(), ANO = character(),
    ponto_amostral = character(), ponto_metro = character(), origem_indice = character()
  )
  todos <- monitora_diag_rel_enriquecer_habito_contrato(todos)
  for (ii in seq_len(nrow(catalogo))) {
    tp <- catalogo$tipo_ocorrencia[ii]
    x <- todos[tipo_ocorrencia == tp]
    monitora_diag_rel_write_dt(x, file.path(base_dir, catalogo$arquivo[ii]))
  }
  monitora_diag_rel_write_dt(todos, file.path(base_dir, paste0("registros_ocorrencias_diagnosticas_", fase, ".csv")))
  resumo <- if (nrow(todos)) todos[, .(
    n_linhas = data.table::uniqueN(linha_indice), n_ocorrencias_detalhadas = .N,
    n_coletas = data.table::uniqueN(COLETA[!is.na(COLETA) & nzchar(COLETA)]),
    coletas_exemplo = paste(utils::head(unique(COLETA[!is.na(COLETA) & nzchar(COLETA)]), 30L), collapse = " | ")
  ), by = .(etapa, severidade, tipo_ocorrencia, rotulo_ocorrencia)] else data.table::data.table(
    etapa = character(), severidade = character(), tipo_ocorrencia = character(), rotulo_ocorrencia = character(),
    n_linhas = integer(), n_ocorrencias_detalhadas = integer(), n_coletas = integer(), coletas_exemplo = character()
  )
  resumo_all <- merge(catalogo[, .(tipo_ocorrencia, rotulo_ocorrencia, severidade)], resumo, by = c("tipo_ocorrencia", "rotulo_ocorrencia", "severidade"), all.x = TRUE)
  resumo_all[is.na(etapa), etapa := fase]
  for (cc in c("n_linhas", "n_ocorrencias_detalhadas", "n_coletas")) resumo_all[is.na(get(cc)), (cc) := 0L]
  resumo_all[is.na(coletas_exemplo), coletas_exemplo := ""]
  monitora_diag_rel_write_dt(resumo_all[severidade == "impeditiva"], file.path(base_dir, paste0("resumo_ocorrencias_impeditivas_", fase, ".csv")))
  monitora_diag_rel_write_dt(resumo_all, file.path(base_dir, paste0("resumo_ocorrencias_diagnosticas_", fase, ".csv")))
  indice <- catalogo[, .(etapa = fase, tipo_ocorrencia, rotulo_ocorrencia, severidade, arquivo, caminho = file.path(base_dir, arquivo))]
  indice <- resumo_all[indice, on = .(tipo_ocorrencia, rotulo_ocorrencia, severidade)]
  if ("i.etapa" %in% names(indice)) {
    indice[is.na(etapa) | !nzchar(as.character(etapa)), etapa := as.character(i.etapa)]
    indice[, i.etapa := NULL]
  }
  indice[, arquivo_existe := file.exists(caminho)]
  monitora_diag_rel_write_dt(indice, file.path(base_dir, "indice_relatorios_ocorrencias_diagnosticas.csv"))
  monitora_diag_validar_ocorrencias_materializadas(todos, fase, base_dir)
  monitora_correcao_console_msg("Relatórios diagnósticos pré-painel materializados pelo caminho leve a partir dos índices já calculados; linhas=", nrow(todos), "; varredura enriquecida larga adiada para o pós-painel.")
  invisible(list(diretorio = base_dir, indice = indice, resumo = resumo_all, registros = todos, validacao = data.table::data.table(), modo = "leve_pre_painel"))
}

### - ------------------------------------------------------------
### Grava um data.table em CSV com o mesmo fallback (fwrite -> write.csv) usado
### dentro de monitora_diag_rel_gerar_ocorrencias ; extraído para nível
### superior para ser reaproveitado por monitora_diag_rel_reutilizar_ocorrencias_pos_painel
### sem duplicar a lógica de fallback em dois lugares divergentes.
monitora_diag_rel_write_dt <- function(x, arquivo) {
  x <- data.table::as.data.table(x)
  dir.create(dirname(arquivo), recursive = TRUE, showWarnings = FALSE)
  tryCatch(
    data.table::fwrite(x, arquivo, na = "", encoding = "UTF-8", bom = TRUE, eol = "\n"),
    error = function(e) utils::write.csv(as.data.frame(x), arquivo, row.names = FALSE, na = "", fileEncoding = "UTF-8")
  )
  invisible(arquivo)
}

### Reaproveita o resultado já calculado de monitora_diag_rel_gerar_ocorrencias
### numa fase anterior (fase_origem, tipicamente "pre_painel") como o resultado
### da fase seguinte (fase_pos, tipicamente "pos_painel"), quando o chamador já
### verificou que nada relevante ao catálogo de ocorrências mudou entre as duas
### fases (ver uso em MONITORA_RELATORIOS_DIAGNOSTICOS_POS_PAINEL, marco
### evita revarrer `dt` inteiro -- grepl/token por categoria de forma
### de vida em todas as linhas -- quando o resultado seria idêntico ao já
### calculado). Relabela `etapa` e os nomes de arquivo/caminho para a fase de
### destino e regrava os CSVs no diretório de destino, para que os produtos em
### disco também reflitam a fase correta (auditabilidade), sem reprocessar
### `dt`.
monitora_diag_rel_reutilizar_ocorrencias_pos_painel <- function(pre_result, base_dir_pos, fase_pos = "pos_painel", fase_origem = "pre_painel") {
  relabel_etapa <- function(x) {
    if (!data.table::is.data.table(x) || !("etapa" %in% names(x))) return(x)
    x <- data.table::copy(x)
    x[, etapa := fase_pos]
    x[]
  }
  relabel_nome_fase <- function(txt) {
    txt <- as.character(txt)
    padrao <- paste0("_", fase_origem, "(\\.[a-zA-Z0-9]+)$")
    ifelse(grepl(padrao, txt), sub(padrao, paste0("_", fase_pos, "\\1"), txt), txt)
  }

  dir.create(base_dir_pos, recursive = TRUE, showWarnings = FALSE)

  registros_pos <- relabel_etapa(pre_result$registros)
  resumo_pos <- relabel_etapa(pre_result$resumo)
  validacao_pos <- relabel_etapa(pre_result$validacao)

  indice_pos <- data.table::copy(pre_result$indice)
  if (data.table::is.data.table(indice_pos) && nrow(indice_pos)) {
    indice_pos[, etapa := fase_pos]
    indice_pos[, arquivo := relabel_nome_fase(arquivo)]
    indice_pos[, caminho := file.path(base_dir_pos, arquivo)]
  }

  if (data.table::is.data.table(registros_pos) && data.table::is.data.table(indice_pos) && nrow(indice_pos)) {
    for (ii in seq_len(nrow(indice_pos))) {
      tp <- indice_pos$tipo_ocorrencia[ii]
      arq <- indice_pos$caminho[ii]
      x <- if (nrow(registros_pos)) registros_pos[tipo_ocorrencia == tp] else registros_pos
      monitora_diag_rel_write_dt(x, arq)
    }
  }
  monitora_diag_rel_write_dt(
    if (data.table::is.data.table(registros_pos)) registros_pos else data.table::data.table(),
    file.path(base_dir_pos, paste0("registros_ocorrencias_diagnosticas_", fase_pos, ".csv"))
  )
  if (data.table::is.data.table(resumo_pos) && "severidade" %in% names(resumo_pos)) {
    monitora_diag_rel_write_dt(resumo_pos[severidade == "impeditiva"], file.path(base_dir_pos, paste0("resumo_ocorrencias_impeditivas_", fase_pos, ".csv")))
    monitora_diag_rel_write_dt(resumo_pos, file.path(base_dir_pos, paste0("resumo_ocorrencias_diagnosticas_", fase_pos, ".csv")))
  }
  if (data.table::is.data.table(indice_pos) && nrow(indice_pos)) {
    indice_pos[, arquivo_existe := file.exists(caminho)]
    monitora_diag_rel_write_dt(indice_pos, file.path(base_dir_pos, "indice_relatorios_ocorrencias_diagnosticas.csv"))
  }
  if (data.table::is.data.table(validacao_pos) && nrow(validacao_pos)) {
    monitora_diag_rel_write_dt(validacao_pos, file.path(base_dir_pos, paste0("validacao_contagens_triagem_vs_relatorios_", fase_pos, ".csv")))
  }
  monitora_diag_validar_ocorrencias_materializadas(registros_pos, fase_pos, base_dir_pos)

  list(diretorio = base_dir_pos, indice = indice_pos, resumo = resumo_pos, registros = registros_pos, validacao = validacao_pos)
}
### - ----------------------------------------------------

### persistência leve dos metadados da sessão do painel -----------------
### Mantém o retorno principal como data.table de operações, preservando toda a
### compatibilidade existente. Metadados escalares seguem em atributos e em um
### sidecar de uma linha; nenhuma varredura da base é adicionada.
monitora_painel_metadados_sessao_persistir <- function(responsavel,
                                                        n_operacoes_semanticas = 0L,
                                                        n_itens_auditaveis = 0L,
                                                        acao_encerramento = "salvar_checkpoint_e_fechar") {
  inteiro_escalar <- function(x) {
    x <- suppressWarnings(as.integer(x)[1L])
    if (!length(x) || is.na(x) || x < 0L) 0L else x
  }
  exec_id <- as.character(get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE))[1L]
  responsavel_sessao <- monitora_responsavel_normalizar(responsavel, "não informado")
  meta <- data.table::data.table(
    exec_id = exec_id,
    data_hora = format(Sys.time(), "%Y-%m-%d %H:%M:%S %z"),
    modo_execucao = as.character(get0("MONITORA_MODO_EXECUCAO", ifnotfound = "não informado", inherits = TRUE))[1L],
    responsavel_sessao = responsavel_sessao,
    instituicao = as.character(get0("MONITORA_INSTITUICAO_RESPONSAVEL", ifnotfound = "ICMBio", inherits = TRUE))[1L],
    acao_encerramento = as.character(acao_encerramento)[1L],
    n_operacoes_sessao = inteiro_escalar(n_operacoes_semanticas),
    n_itens_auditaveis_sessao = inteiro_escalar(n_itens_auditaveis)
  )
  base_dir <- as.character(get0(
    "MONITORA_CORRECOES_DIR",
    ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"),
    inherits = TRUE
  ))[1L]
  arquivo <- file.path(base_dir, paste0("metadados_sessao_painel_", exec_id, ".csv"))
  persistido <- tryCatch({
    dir.create(dirname(arquivo), recursive = TRUE, showWarnings = FALSE)
    if (exists("monitora_fwrite", mode = "function", inherits = TRUE)) {
      monitora_fwrite(meta, arquivo, na = "")
    } else {
      data.table::fwrite(meta, arquivo, na = "")
    }
    isTRUE(file.exists(arquivo) && !isTRUE(file.info(arquivo)$isdir) && file.info(arquivo)$size > 0L)
  }, error = function(e) {
    warning("Falha ao persistir metadados da sessão do painel: ", conditionMessage(e), call. = FALSE)
    FALSE
  })
  arquivo_registrado <- if (isTRUE(persistido)) arquivo else ""
  assign("MONITORA_RESPONSAVEL_SESSAO_PAINEL", responsavel_sessao, envir = .GlobalEnv)
  assign("MONITORA_METADADOS_SESSAO_PAINEL_ULTIMA", meta, envir = .GlobalEnv)
  assign("MONITORA_ARQUIVO_METADADOS_SESSAO_PAINEL", arquivo_registrado, envir = .GlobalEnv)
  list(dados = meta, arquivo = arquivo_registrado, persistido = isTRUE(persistido))
}

monitora_painel_retorno_anexar_metadados <- function(resultado, metadados_sessao) {
  if (is.null(metadados_sessao) || !is.list(metadados_sessao)) return(resultado)
  meta <- metadados_sessao$dados
  if (!is.null(meta)) {
    meta <- data.table::as.data.table(meta)
    attr(resultado, "painel_metadados_sessao") <- meta
    if (nrow(meta) && "responsavel_sessao" %in% names(meta)) {
      attr(resultado, "painel_responsavel_sessao") <- as.character(meta$responsavel_sessao[1L])
    }
  }
  arquivo_meta <- metadados_sessao$arquivo
  arquivo_meta <- if (is.null(arquivo_meta) || !length(arquivo_meta) || is.na(arquivo_meta[1L])) "" else as.character(arquivo_meta[1L])
  attr(resultado, "painel_metadados_sessao_arquivo") <- arquivo_meta
  attr(resultado, "painel_metadados_sessao_persistidos") <- isTRUE(metadados_sessao$persistido)
  resultado
}

monitora_painel_retorno_publicar_metadados <- function(resultado) {
  meta <- attr(resultado, "painel_metadados_sessao", exact = TRUE)
  responsavel <- monitora_responsavel_normalizar(attr(resultado, "painel_responsavel_sessao", exact = TRUE), "")
  arquivo <- attr(resultado, "painel_metadados_sessao_arquivo", exact = TRUE)
  if (!is.null(meta)) {
    meta <- tryCatch(data.table::as.data.table(meta), error = function(e) NULL)
    if (!is.null(meta) && nrow(meta)) {
      assign("MONITORA_METADADOS_SESSAO_PAINEL_ULTIMA", meta, envir = .GlobalEnv)
      if (!nzchar(responsavel) && "responsavel_sessao" %in% names(meta)) {
        responsavel <- monitora_responsavel_normalizar(meta$responsavel_sessao, "")
      }
    }
  }
  if (nzchar(responsavel)) assign("MONITORA_RESPONSAVEL_SESSAO_PAINEL", responsavel, envir = .GlobalEnv)
  arquivo <- if (is.null(arquivo) || !length(arquivo) || is.na(arquivo[1L])) "" else as.character(arquivo[1L])
  if (nzchar(arquivo)) assign("MONITORA_ARQUIVO_METADADOS_SESSAO_PAINEL", arquivo, envir = .GlobalEnv)
  invisible(meta)
}

monitora_correcao_painel <- function(dt, meta_xls = NULL, arquivo_saida = MONITORA_ARQUIVO_CORRECOES_CAMPOS) {
  dt <- monitora_identidade_assegurar(dt, contexto = "abertura_painel")
  monitora_correcao_carregar_dependencias_painel()
  dt <- data.table::as.data.table(dt)
  dt <- monitora_correcao_preparar_schema_edicao_painel(dt, meta_xls, contexto = "pre_painel_shiny")
  chaves <- monitora_correcao_colunas_chave(dt)
  dict <- monitora_correcao_dicionario_atributos(dt, meta_xls)
 ### ### dict já chega aqui com painel_editavel/acoes_permitidas/tipo_base_edicao
 ### corretos (monitora_correcao_dicionario_atributos já mescla
 ### monitora_correcao_contrato_edicao internamente, com a lista completa de
 ### registros_corrig, ANTES de anexar escopo_operacional_contrato_unico/
 ### escopos_permitidos_contrato_unico do perfil_painel_edicao do contrato
 ### único). Recalcular contrato_edicao aqui de novo, já com esses dois campos
 ### presentes em dict, fazia monitora_correcao_contrato_edicao reaplicar o
 ### gate "escopos_permitidos_contrato_unico vazio -> painel_editavel=FALSE;
 ### acoes_permitidas=''" (linhas ~10416-10424) — gate que só dispara quando os
 ### dois campos já estão presentes no dicionário de entrada. Para atributos
 ### administrativos que a Monitora anexa a registros_corrig mas que não são
 ### campo XLSForm (UC, CICLO, CAMPANHA, EA, UA, USUARIO, VALIDADO, VALIDADO
 ### POR, data_validacao, obs_validacao, planilha_upload), o perfil do contrato
 ### único não consegue resolver atributo_canonico_2025 (não há caminho/name
 ### XLSForm correspondente para eles), então escopos_permitidos_contrato_unico
 ### fica vazio e o gate zerava acoes_permitidas só nesta segunda chamada —
 ### exatamente os atributos que o dict (usado para montar o seletor) já
 ### mostrava como editáveis. Resultado: apareciam no seletor mas com "Ação"
 ### vazia. Reaproveitar dict diretamente elimina a segunda chamada redundante
 ### e inconsistente, sem alterar monitora_correcao_contrato_edicao nem
 ### inventar nenhuma regra nova — usa exatamente os mesmos valores já
 ### corretos e já exibidos no seletor.
  contrato_edicao <- data.table::copy(dict)
  if (!("painel_editavel" %in% names(dict)) && "atributo_coluna_registros_corrig" %in% names(dict) && nrow(contrato_edicao)) {
    cols_merge_contrato_ini <- intersect(c(
      "atributo_coluna_registros_corrig", "tipo_base_edicao", "painel_editavel",
      "painel_motivo_bloqueio", "acoes_permitidas", "escopo_operacional_contrato_unico",
      "escopos_permitidos_contrato_unico", "motivo_escopo_contrato_unico"
    ), names(contrato_edicao))
    dict <- merge(dict, contrato_edicao[, ..cols_merge_contrato_ini], by = "atributo_coluna_registros_corrig", all.x = TRUE, sort = FALSE)
  }
  if ("atributo_coluna_registros_corrig" %in% names(dict) && "painel_editavel" %in% names(dict)) {
    dict <- dict[painel_editavel %in% TRUE]
  } else if ("atributo_coluna_registros_corrig" %in% names(dict)) {
    dict <- dict[!monitora_correcao_coluna_protegida(atributo_coluna_registros_corrig)]
  }
 ### publicação: a lista do seletor deve seguir o contrato global do template
 ### SISMONITORA/XLSForm 2025 e a ordem do template, não a ordem caótica das
 ### colunas de registros_corrig nem a presença de valores na coleta filtrada.
  if (exists("monitora_correcao_colunas_template_sismonitora", mode = "function")) {
    dict_template <- tryCatch(monitora_correcao_colunas_template_sismonitora(dt), error = function(e) data.table::data.table())
    if (nrow(dict_template) && "atributo_coluna_registros_corrig" %in% names(dict_template)) {
 ### Garante fisicamente no objeto os campos contratuais ainda ausentes.
      cols_criar_tpl <- setdiff(as.character(dict_template$atributo_coluna_registros_corrig), names(dt))
      cols_criar_tpl <- cols_criar_tpl[!is.na(cols_criar_tpl) & nzchar(cols_criar_tpl) & !monitora_correcao_coluna_protegida(cols_criar_tpl)]
      if (length(cols_criar_tpl)) {
        data.table::setalloccol(dt, ncol(dt) + length(cols_criar_tpl) + 16L)
        for (cc_tpl in cols_criar_tpl) data.table::set(dt, j = cc_tpl, value = NA_character_)
        monitora_correcao_limpar_cache_mapa_colunas_publicacao_b()
      }
 ### dict já chega aqui com painel_editavel/atende_template_sismonitora/ordem_template_sismonitora
 ### corretos, herdados de monitora_correcao_dicionario_atributos (que já mescla
 ### monitora_correcao_contrato_edicao com all.x sobre a lista completa de registros_corrig).
 ### Remesclar dict_template aqui e recalcular contrato_edicao a partir do resultado reintroduzia
 ### o "formato" interno do schema (ex.: "texto") como xlsform_tipo quando não há correspondência
 ### no XLSForm, quebrando a inferência de tipo e zerando acoes_permitidas/painel_editavel para
 ### atributos administrativos sem campo XLSForm próprio (UC, CICLO, CAMPANHA, EA, UA, USUARIO,
 ### VALIDADO, VALIDADO POR, data_validacao, obs_validacao, planilha_upload). dict_template serve
 ### só para garantir as colunas contratuais físicas ausentes (acima) — nunca como autoridade que
 ### filtra ou substitui o que o adaptador contratual (monitora_correcao_contrato_edicao) já decidiu.
    }
  }
  if (!("ordem_template_sismonitora" %in% names(dict))) dict[, ordem_template_sismonitora := 999999L]
  dict[is.na(ordem_template_sismonitora), ordem_template_sismonitora := 999999L]
  data.table::setorder(dict, ordem_template_sismonitora, atributo_coluna_registros_corrig)
  if (!nrow(dict)) stop("Nenhum atributo editável seguro foi identificado para o painel de correções.", call. = FALSE)
  mapa_colunas_painel <- monitora_correcao_mapa_colunas_canonicas(dt, meta_xls, contexto = paste0("painel_", if (exists("MONITORA_EXEC_ID", inherits = TRUE)) get("MONITORA_EXEC_ID", inherits = TRUE) else format(Sys.time(), "%Y%m%d_%H%M%S")), gravar = TRUE)
  deps <- monitora_correcao_unificar_dependencias(if (!is.null(meta_xls)) meta_xls$dependencias else data.table::data.table())

  monitora_painel_valor <- function(x) {
    if (is.null(x) || length(x) == 0L) return("")
    z <- as.character(x)
    z <- z[!is.na(z) & nzchar(trimws(z))]
    if (!length(z)) return("")
    paste(unique(z), collapse = " | ")
  }
  monitora_painel_valores_coluna <- function(x, col) {
    if (is.na(col) || !col %in% names(x)) return(character(0))
    vals <- unique(as.character(x[[col]]))
    vals <- vals[!is.na(vals) & nzchar(trimws(vals))]
    sort(vals)
  }
  monitora_painel_choices <- function(rotulo_todos, vals) {
    vals <- vals[!is.na(vals) & nzchar(trimws(vals))]
    vals <- sort(unique(as.character(vals)))
    stats::setNames(c("", vals), c(rotulo_todos, vals))
  }
  monitora_painel_choices_obrigatorio <- function(rotulo_vazio, vals) {
    vals <- vals[!is.na(vals) & nzchar(trimws(vals))]
    vals <- sort(unique(as.character(vals)))
    if (length(vals) == 0L) return(stats::setNames("", rotulo_vazio))
    stats::setNames(vals, vals)
  }
  monitora_painel_acoes_atributo <- function(atributo) {
    info <- contrato_edicao[atributo_coluna_registros_corrig == as.character(atributo)[1L]]
    if (!nrow(info)) return(stats::setNames(character(0), character(0)))
    acoes <- monitora_correcao_split_serial(info$acoes_permitidas[1L])
    rot <- monitora_correcao_acoes_rotulos()
    rot <- rot[unname(rot) %in% acoes]
    if (!length(rot)) stats::setNames(character(0), character(0)) else rot
  }

  monitora_painel_limpar_html_rotulo <- function(x) {
    x <- as.character(x)
    x[is.na(x)] <- ""
    x <- gsub("<[^>]+>", "", x, perl = TRUE)
    x <- gsub("&nbsp;", " ", x, fixed = TRUE)
    x <- gsub("&lt;", "<", x, fixed = TRUE)
    x <- gsub("&gt;", ">", x, fixed = TRUE)
    x <- gsub("&amp;", "&", x, fixed = TRUE)
    trimws(gsub("\\s+", " ", gsub("\u200b", "", x), perl = TRUE))
  }

  monitora_painel_rotulo_token <- function(label, token) {
    token <- as.character(token)
    label <- monitora_painel_limpar_html_rotulo(label)
    label[is.na(label) | !nzchar(label)] <- token[is.na(label) | !nzchar(label)]
    igual <- monitora_correcao_normalizar_nome_coluna(label) == monitora_correcao_normalizar_nome_coluna(token)
    ja_concatenado <- endsWith(trimws(label), paste0("— ", token))
    out <- ifelse(igual | ja_concatenado, label, paste0(label, " — ", token))
    out[is.na(out) | !nzchar(out)] <- token[is.na(out) | !nzchar(out)]
    out
  }

 ### Camada visual única para seletores: mantém o `name` como valor enviado ao
 ### servidor e exibe `label — name`. Nunca altera o domínio operacional.
  monitora_painel_choices_label_name <- function(choices,
                                                  incluir_vazio = FALSE,
                                                  rotulo_vazio = "(selecione)") {
 ### Capturar os nomes antes da coerção. as.character pode descartar o
 ### atributo names; isso fazia o navegador exibir os códigos internos
 ### update/clear/append_token em vez dos rótulos pt-BR.
    labs <- names(choices)
    vals <- as.character(unname(choices))
    if (is.null(labs)) labs <- vals
    labs[is.na(labs) | !nzchar(labs)] <- vals[is.na(labs) | !nzchar(labs)]
    out <- stats::setNames(vals, monitora_painel_rotulo_token(labs, vals))
    if (isTRUE(incluir_vazio)) out <- c(stats::setNames("", rotulo_vazio), out[vals != ""])
    out
  }

  monitora_painel_choices_categorias_movimento <- function(incluir_outra = FALSE) {
    info_mov <- monitora_contrato_categorias_movimento()
    permitidas <- info_mov$categoria
    dom <- monitora_painel_choices_dominio_xlsform("tipo_forma_vida", meta_xls, fallback = permitidas)
    dom <- dom[unname(dom) %in% permitidas]
    faltantes <- setdiff(permitidas, unname(dom))
    if (length(faltantes)) dom <- c(dom, stats::setNames(faltantes, faltantes))
    monitora_painel_choices_label_name(dom, incluir_vazio = TRUE)
  }

  monitora_painel_choices_dominio_xlsform <- function(list_name, meta_xls = NULL, fallback = character(0)) {
    list_name_alvo <- as.character(list_name)[1L]
    meta <- monitora_correcao_xlsform_meta_atual(meta_xls)
    op <- if (!is.null(meta$opcoes)) data.table::as.data.table(meta$opcoes) else data.table::data.table()
    if (nrow(op) && all(c("list_name", "name") %in% names(op)) && !is.na(list_name_alvo) && nzchar(list_name_alvo)) {
      for (cc in c("arquivo_xlsform", "list_name", "name", "label")) if (!(cc %in% names(op))) op[, (cc) := NA_character_]
      cand <- op[list_name == list_name_alvo & !is.na(name) & nzchar(as.character(name))]
 ### (causa raiz do bloqueio de "UC"): listas de choices
 ### dinâmicas do XLSForm (search /pulldata , ex.: "uc") não trazem
 ### opções embutidas -- o extrator só captura os cabeçalhos literais
 ### "num_key"/"label" da planilha de choices como se fossem uma opção
 ### real. monitora_correcao_choices_xlsform já despreza esse caso (ver
 ### linha ~11100); aqui a mesma checagem faltava, então o widget de
 ### valor ofereceria "num_key" como única opção selecionável -- pior que
 ### bloquear. Ao invés de expor essa opção falsa, cai no mesmo fallback
 ### de domínio observado (dados reais já presentes em registros_corrig
 ### para este atributo) usado quando não há list_name/opções nenhuma.
      nomes_unicos_cand <- unique(as.character(cand$name))
      if (length(nomes_unicos_cand) <= 2L && all(nomes_unicos_cand %in% c("num_key", "label"))) cand <- cand[0]
      if (nrow(cand)) {
        arq <- tryCatch(monitora_correcao_ultima_versao_xlsform(cand), error = function(e) NA_character_)
        if (!is.na(arq) && nzchar(arq)) {
          cand2 <- cand[arquivo_xlsform == arq]
          if (nrow(cand2)) cand <- cand2
        }
        cand <- unique(cand[, .(name = as.character(name), label = as.character(label))], by = "name")
        vals <- as.character(cand$name)
        labs <- monitora_painel_rotulo_token(cand$label, vals)
        o <- order(monitora_correcao_normalizar_nome_coluna(labs), vals)
        return(stats::setNames(vals[o], labs[o]))
      }
    }
    vals <- unique(trimws(as.character(fallback)))
    vals <- vals[!is.na(vals) & nzchar(vals)]
    vals <- sort(vals)
    stats::setNames(vals, monitora_painel_rotulo_token(vals, vals))
  }

  monitora_painel_choices_atributos_template <- function(d) {
    d <- data.table::as.data.table(data.table::copy(d))
    if ("ordem_template_sismonitora" %in% names(d)) {
      d[is.na(ordem_template_sismonitora), ordem_template_sismonitora := 999999L]
      data.table::setorder(d, ordem_template_sismonitora, atributo_coluna_registros_corrig)
    }
    vals <- as.character(d$atributo_coluna_registros_corrig)
    labels_base <- vals
    if ("xlsform_label" %in% names(d)) {
      lab <- monitora_painel_limpar_html_rotulo(d$xlsform_label)
      labels_base <- ifelse(nzchar(lab), monitora_painel_rotulo_token(lab, vals), labels_base)
    }
    labels <- labels_base
    if ("atributos_template_sismonitora" %in% names(d)) {
      tpl <- as.character(d$atributos_template_sismonitora)
      tpl[is.na(tpl)] <- ""
      labels <- ifelse(nzchar(tpl), paste0(labels_base, "  |  ", tpl), labels_base)
    }
 ### Termos auxiliares explícitos ajudam a busca do selectize por expressões
 ### naturais usadas pelos usuários e pelo contrato do XLSForm 2025.
    extras <- rep("", length(vals))
    extras[vals %in% c("amostragem/registro/forma_serrapilheira", "forma_serrapilheira")] <- " material botanico materiais botanicos decomposicao solo serrapilheira fragmentos botanicos material inundado"
    extras[vals %in% c("amostragem/registro/forma_vida_outros", "forma_vida_outros")] <- " outras plantas terrestres liquens fungos musgos hepaticas antoceros"
    labels <- monitora_painel_limpar_html_rotulo(paste0(labels, extras))
    stats::setNames(vals, labels)
  }
 ### oculta do seletor "Atributo a corrigir" as colunas
 ### que são aliases históricos de hábito (rótulos herdados de versões
 ### antigas do XLSForm para o mesmo atributo definitivo, incluindo variantes
 ### ".1"/".2" geradas pela mesclagem de arquivos duplicados no import) — o
 ### usuário deve editar só o atributo definitivo (forma_vida_<categoria>_
 ### <forma>), nunca escolher entre versões históricas. Os aliases já foram
 ### conciliados para o definitivo por monitora_correcao_conciliar_habito_
 ### historico_definitivo (chamada dentro de monitora_correcao_mask_habito_
 ### obrigatorio_ausente ); aqui só removemos do dicionário de escolhas do
 ### seletor, sem tocar nos dados em si.
  dict_sem_aliases_habito_painel <- tryCatch({
    aliases_ocultar <- character(0)
    formas_hab <- monitora_correcao_tokens_formas_exigem_habito()
    for (categoria_hab in c("nativa", "exotica", "seca_morta")) {
      cds_hab <- unique(vapply(formas_hab, function(fm) {
        cd <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, categoria_hab, fm, meta_xls = meta_xls), error = function(e) NA_character_)
        if (is.na(cd) || !nzchar(cd)) NA_character_ else cd
      }, character(1)))
      cds_hab <- cds_hab[!is.na(cds_hab)]
      for (cd_hab in cds_hab) {
        aliases_ocultar <- c(aliases_ocultar, tryCatch(monitora_correcao_aliases_historicos_habito(dt, cd_hab, meta_xls), error = function(e) character(0)))
      }
    }
    aliases_ocultar <- unique(aliases_ocultar)
    if (length(aliases_ocultar)) dict[!(atributo_coluna_registros_corrig %in% aliases_ocultar)] else dict
  }, error = function(e) dict)
  escolhas_atributos_painel <- monitora_painel_choices_atributos_template(dict_sem_aliases_habito_painel)
  if (exists("monitora_correcao_console_msg", mode = "function")) {
    alvos_tpl <- c("amostragem/registro/forma_serrapilheira", "amostragem/registro/forma_vida_outros", "forma_serrapilheira", "forma_vida_outros")
    presentes_tpl <- intersect(alvos_tpl, unname(escolhas_atributos_painel))
    monitora_correcao_console_msg(
      "Seletor de atributos do painel: ", length(escolhas_atributos_painel),
      " atributo(s) contratuais exibidos em ordem do template SISMONITORA/XLSForm 2025; alvos materiais/outros presentes=",
      paste(presentes_tpl, collapse = " | ")
    )
  }
  monitora_painel_choices_valor_atributo <- function(atributo, acao = NULL, incluir_observados = FALSE) {
    info <- monitora_painel_info_contrato_atributo(atributo)
    fallback <- character(0)
    if (isTRUE(incluir_observados) && !is.na(info$col) && nzchar(info$col) && info$col %in% names(dt)) {
      obs <- unique(unlist(lapply(as.character(dt[[info$col]]), monitora_correcao_tokens_valor), use.names = FALSE))
      obs <- obs[!is.na(obs) & nzchar(trimws(obs))]
      fallback <- unique(c(fallback, obs))
    } else if (!is.na(info$col) && nzchar(info$col) && info$col %in% names(dt)) {
      fallback <- unique(c(fallback, as.character(dt[[info$col]])))
    }
    monitora_painel_choices_dominio_xlsform(info$list_name, meta_xls, fallback = fallback)
  }

  monitora_painel_widget_valor_atributo <- function(atributo, acao = NULL) {
    info <- monitora_painel_info_contrato_atributo(atributo)
    tipo <- as.character(info$tipo)[1L]
    acao_norm <- monitora_correcao_acao_normalizar(acao)
    if (is.na(tipo) || !nzchar(tipo)) tipo <- "text"
    if (acao_norm %in% c("clear", "recalcular_tipo_forma_vida")) return("sem_valor_novo")
    if (tipo == "select_one") return("selectize_unico")
    if (tipo == "select_multiple") return("selectize_tokens")
    if (tipo == "date") return("date")
    if (tipo %in% c("integer", "decimal")) return("numeric")
    if (tipo %in% c("time", "datetime", "geopoint")) return("texto_formatado")
    "texto_livre"
  }

  monitora_painel_gravar_auditoria_controle_atributos <- function() {
    aud <- data.table::as.data.table(data.table::copy(contrato_edicao))
    if (!nrow(aud)) return(invisible(FALSE))
    if ("atende_template_sismonitora" %in% names(aud)) aud <- aud[atende_template_sismonitora %in% TRUE]
    if ("painel_editavel" %in% names(aud)) aud <- aud[painel_editavel %in% TRUE]
    if (!nrow(aud)) return(invisible(FALSE))
    aud[, n_opcoes_xlsform := vapply(xlsform_list_name, function(ll) length(monitora_correcao_choices_xlsform(ll, meta_xls)), integer(1))]
    aud[, widget_valor := vapply(atributo_coluna_registros_corrig, function(aa) monitora_painel_widget_valor_atributo(aa, "update"), character(1))]
    aud[tipo_base_edicao == "select_multiple", widget_valor := "selectize_tokens"]
    aud[tipo_base_edicao == "select_one", widget_valor := "selectize_unico"]
 ### quando o domínio estático do XLSForm está ausente
 ### (lista dinâmica externa tipo search /pulldata , ex.: "uc" -- só
 ### existe como itemset externo, nunca embutida no XLSForm), mas o widget
 ### de valor (monitora_painel_choices_dominio_xlsform, já corrigido para
 ### rejeitar o placeholder "num_key"/"label" dessas listas dinâmicas) cai
 ### com segurança no domínio OBSERVADO -- valores reais já presentes em
 ### registros_corrig para o próprio atributo, nunca inventados -- o
 ### atributo continua editável de fato e não deve ser marcado como
 ### bloqueado. Restrito a select_one: monitora_painel_choices_valor_
 ### atributo sempre popula esse fallback para select_one mesmo com
 ### incluir_observados=FALSE; para select_multiple o fallback observado só
 ### é seguro na ação remove_token, não em append/replace/valor novo
 ### digitado, então continua exigindo domínio XLSForm estático.
    aud[, n_opcoes_dominio_observado := 0L]
    alvo_obs_idx <- which(aud$tipo_base_edicao == "select_one" & aud$n_opcoes_xlsform < 1L)
    if (length(alvo_obs_idx)) {
      aud[alvo_obs_idx, n_opcoes_dominio_observado := vapply(atributo_coluna_registros_corrig, function(aa) {
        if (!(aa %in% names(dt))) return(0L)
        v <- as.character(dt[[aa]])
        length(unique(v[!is.na(v) & nzchar(trimws(v))]))
      }, integer(1))]
    }
    aud[, status_controle := "ok"]
    aud[tipo_base_edicao %in% c("select_one", "select_multiple") & n_opcoes_xlsform < 1L, status_controle := "bloqueado_sem_dominio_xlsform"]
    aud[tipo_base_edicao == "select_one" & n_opcoes_xlsform < 1L & n_opcoes_dominio_observado >= 1L, status_controle := "ok"]
    aud[tipo_base_edicao == "select_multiple" & grepl("(^|;)update(;|$)|(^|;)clear(;|$)", acoes_permitidas, perl = TRUE), status_controle := "erro_lista_tokens_com_operacao_valor_total"]
    aud[, timestamp := format(Sys.time(), "%Y-%m-%d %H:%M:%S")]
    cols <- intersect(c(
      "timestamp", "atributo_coluna_registros_corrig", "ordem_template_sismonitora", "atributos_template_sismonitora",
      "tipo_base_edicao", "xlsform_tipo", "xlsform_list_name", "n_opcoes_xlsform", "n_opcoes_dominio_observado", "acoes_permitidas",
      "widget_valor", "status_controle", "painel_motivo_bloqueio"
    ), names(aud))
    arq <- file.path(monitora_publicacao_b_output_dir(), "auditoria_painel_controle_atributos.csv")
    dir.create(dirname(arq), recursive = TRUE, showWarnings = FALSE)
    try(monitora_fwrite(aud[, ..cols], arq, na = ""), silent = TRUE)
    if (exists("monitora_correcao_console_msg", mode = "function")) {
      tab <- aud[, .N, by = status_controle]
      monitora_correcao_console_msg("Auditoria de controle de atributos do painel gravada: ", arq, "; ", paste(paste0(tab$status_controle, "=", tab$N), collapse = "; "))
    }
    invisible(TRUE)
  }
  monitora_painel_validar_entrada <- function(atributo, acao, valor_novo, valor_original = NA_character_, escopo = NULL) {
    col <- monitora_correcao_resolver_coluna(dt, atributo, dict, permitir_heuristica = FALSE)
    fake <- data.table::data.table(valor_original_esperado = valor_original)
    valid_destino <- monitora_correcao_validar_destino_operacao(dt, col, acao, valor_novo, fake, dict, meta_xls)
    if (!isTRUE(valid_destino$ok)) return(valid_destino)
    if (!is.null(escopo) && exists("monitora_correcao_validar_escopo_operacional_contrato_unico", mode = "function")) {
      valid_escopo <- monitora_correcao_validar_escopo_operacional_contrato_unico(col, escopo, dict)
      if (!isTRUE(valid_escopo$ok)) return(valid_escopo)
    }
    valid_destino
  }
  monitora_painel_coluna_ok <- function(col, x = dt) {
 ### normaliza para comprimento 1 antes do &&/if — uma
 ### coluna-chave não resolvida podia chegar aqui como character(0) (não
 ### NA_character_), e character(0) &&... lança erro em vez de FALSE. Usada
 ### em dezenas de pontos do painel/preview, incluindo o caminho de
 ### preview_lote_multicoletas_dt (erro "missing value where TRUE/FALSE
 ### needed" reproduzido na validação operacional).
    col <- as.character(col)[1L]
    isTRUE(!is.na(col) && nzchar(col) && col %in% names(x))
  }
 ### normaliza input$n_esperado antes de qualquer
 ### comparação reativa — o widget é remontado via renderUI conforme o
 ### escopo (ui_n_esperado_contextual) e pode chegar aqui como NULL,
 ### character(0), NA, NaN, "", texto não numérico ou infinito durante a
 ### janela de remontagem, o que disparava "missing value where TRUE/FALSE
 ### needed"/"argument is of length zero" em vez de cair num fallback.
  monitora_painel_n_esperado_seguro <- function(valor, fallback = 101L) {
    fallback <- suppressWarnings(as.integer(fallback[1L]))
    if (is.null(valor) || length(valor) == 0L) return(fallback)
    v <- suppressWarnings(as.integer(valor[1L]))
    if (length(v) != 1L || is.na(v) || !is.finite(v) || v < 1L) return(fallback)
    v
  }
  monitora_painel_linhas_sem_forma_categoria <- function(x, categoria) {
 ### reaproveita exatamente a mesma detecção de
 ### token superior sem lista inferior (Encostam "órfão") já usada em
 ### monitora_painel_coletas_diagnosticas_preferir_relatorios e em
 ### monitora_diag_rel_gerar_ocorrencias (nativa/exotica/seca_morta_sem_
 ### forma_vida), devolvendo índices de linha (não COLETAs) para permitir o
 ### escopo "linhas da ocorrência" no botão de sanitização assistida. Não é
 ### uma regra nova: os tokens e as colunas vêm das mesmas funções de
 ### resolução do contrato único já usadas nesses dois pontos.
    tipo_col <- chaves$tipo_forma_vida
    if (is.na(tipo_col) || !nzchar(tipo_col) || !(tipo_col %in% names(x))) return(integer(0))
    toks <- switch(categoria,
      nativa = c("nativa", "nativas", "nativo", "nativos"),
      exotica = c("exotica", "exoticas", "exotico", "exoticos"),
      seca_morta = c("seca_morta", "seca", "secas", "seco", "secos", "morta", "mortas", "morto", "mortos"),
      character(0)
    )
    if (!length(toks)) return(integer(0))
    tem_tok <- tryCatch(monitora_relatorio_exoticas_tem_token(x[[tipo_col]], toks), error = function(e) rep(FALSE, nrow(x)))
    tem_tok[is.na(tem_tok)] <- FALSE
    cols <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(x, categoria), error = function(e) character(0))
    cols <- unique(cols[!is.na(cols) & nzchar(cols) & cols %in% names(x)])
    tem_forma <- if (length(cols)) Reduce(`|`, lapply(cols, function(cc) !monitora_correcao_vazio_vec(x[[cc]]))) else rep(FALSE, nrow(x))
    which(tem_tok & !tem_forma)
  }
  monitora_painel_n_coletas <- function(x) {
    if (!monitora_painel_coluna_ok(chaves$coleta, x)) return(NA_integer_)
    data.table::uniqueN(as.character(x[[chaves$coleta]]))
  }
  monitora_painel_coleta_unica <- function(x) {
    if (!monitora_painel_coluna_ok(chaves$coleta, x)) return(NA_character_)
    vals <- unique(as.character(x[[chaves$coleta]]))
    vals <- vals[!is.na(vals) & nzchar(vals)]
    if (length(vals) == 1L) vals[1] else NA_character_
  }

  valores_uc <- monitora_painel_valores_coluna(dt, chaves$uc)
  valores_ea <- monitora_painel_valores_coluna(dt, chaves$ea)
  valores_ano <- monitora_painel_valores_coluna(dt, chaves$ano)
  valores_ciclo <- monitora_painel_valores_coluna(dt, chaves$ciclo)
  valores_campanha <- monitora_painel_valores_coluna(dt, chaves$campanha)
  valores_ua <- monitora_painel_valores_coluna(dt, chaves$ua)
  valores_coleta <- monitora_painel_valores_coluna(dt, chaves$coleta)
  coleta_inicial <- ""
  col_forma_exotica <- monitora_correcao_coluna_forma_vida(dt, "exotica")
  cols_forma_exotica <- monitora_correcao_colunas_forma_vida_categoria(dt, "exotica")

 ### Regras assistidas da triagem unificada
 ### - exóticas: movimento controlado exótica -> nativa;
 ### - desconhecidas: substituição por forma de vida válida do XLSForm atual,
 ### mantendo ou mudando a lista de destino;
 ### - outras formas de vida: remoção do token histórico e registro de solo_nu
 ### quando a remoção deixaria o ponto sem nenhuma categoria tocando a vareta.
  MONITORA_TRIAGEM_TOKENS_DESCONHECIDOS <- c("desconhecida", "desconhecido")
  MONITORA_TRIAGEM_TOKENS_OUTRAS <- c("outra_forma_vida", "outras_formas_vida", "forma_vida_outros", "outra", "outro", "outras", "outros")
  MONITORA_TRIAGEM_TOKENS_INVALIDOS <- unique(c(MONITORA_TRIAGEM_TOKENS_DESCONHECIDOS, MONITORA_TRIAGEM_TOKENS_OUTRAS))
  MONITORA_TRIAGEM_CATEGORIAS_INFO <- monitora_contrato_categorias_movimento()
  MONITORA_TRIAGEM_CATEGORIAS_FORMA <- MONITORA_TRIAGEM_CATEGORIAS_INFO$categoria
  MONITORA_TRIAGEM_CATEGORIAS_BIOLOGICAS <- MONITORA_TRIAGEM_CATEGORIAS_INFO[admite_desconhecida == TRUE, categoria]
 ### Apenas estas formas possuem atributo dependente de hábito no fluxo operacional.
 ### Todas as demais formas de vida devem ignorar/bloquear qualquer hábito selecionado.
 ### Os tokens canônicos abaixo são os names do XLSForm mais recente embutido
 ### (21FEV25/2025): bromelioide, cactacea, orquidea e samambaia.
  MONITORA_TRIAGEM_FORMAS_CONDICIONAIS <- c("bromelioide", "cactacea", "orquidea", "samambaia")
  MONITORA_TRIAGEM_ALIASES_FORMAS_CONDICIONAIS <- list(
    bromelioide = c("bromelioide", "bromelioides", "erva_bromelioide", "erva_bromelioides", "ervas_bromelioides", "bromelia", "bromelias", "bromeliacea", "bromeliaceas"),
    cactacea = c("cactacea", "cactaceas", "cacto", "cactos"),
    orquidea = c("orquidea", "orquideas"),
    samambaia = c("samambaia", "samambaias")
  )
  monitora_painel_canonizar_forma_habito <- function(forma) {
    z <- monitora_relatorio_exoticas_normalizar_token(as.character(forma)[1L])
    if (is.na(z) || !nzchar(z)) return("")
    for (canon in names(MONITORA_TRIAGEM_ALIASES_FORMAS_CONDICIONAIS)) {
      aliases <- monitora_relatorio_exoticas_normalizar_token(MONITORA_TRIAGEM_ALIASES_FORMAS_CONDICIONAIS[[canon]])
      if (z %in% aliases) return(canon)
    }
    z
  }
 ### a constante hard-coded MONITORA_TRIAGEM_HABITO_CHOICES
 ### (terrestre/epifita/rupicola) foi removida — substituída em todos os usos por
 ### monitora_painel_habito_choices_contratuais , que resolve o domínio real do
 ### XLSForm embutido. MONITORA_TRIAGEM_HABITO_NAO_APLICA_CHOICES não é um
 ### domínio de tokens (é só o placeholder "não se aplica" quando a forma
 ### selecionada não exige hábito) e permanece.
  MONITORA_TRIAGEM_HABITO_NAO_APLICA_CHOICES <- c("(não se aplica a esta forma de vida)" = "")
  monitora_painel_forma_exige_habito <- function(forma) {
    forma <- monitora_painel_canonizar_forma_habito(forma)
    !is.na(forma) && nzchar(forma) && forma %in% MONITORA_TRIAGEM_FORMAS_CONDICIONAIS
  }

  monitora_painel_split_barra <- function(x) {
    x <- as.character(x)
    if (!length(x) || is.na(x[1]) || !nzchar(trimws(x[1]))) return(character(0))
    z <- unlist(strsplit(x[1], "\\s*\\|\\s*", perl = TRUE), use.names = FALSE)
    z <- trimws(z)
    unique(z[!is.na(z) & nzchar(z)])
  }

  monitora_painel_split_tokens_triagem <- function(x) {
    x <- as.character(x)
    if (!length(x) || is.na(x[1]) || !nzchar(trimws(x[1]))) return(character(0))
    z <- unlist(strsplit(x[1], "\\s*;\\s*", perl = TRUE), use.names = FALSE)
    z <- monitora_relatorio_exoticas_normalizar_token(z)
    unique(z[!is.na(z) & nzchar(z)])
  }

  monitora_painel_categoria_por_coluna_forma <- function(col) {
    if (is.na(col) || !nzchar(col)) return(NA_character_)
    r <- mapa_colunas_painel[coluna_registros_corrig == col]
    if (nrow(r) && identical(r$papel_coluna[1L], "lista_principal_forma_vida")) return(r$categoria[1L])
    NA_character_
  }

  monitora_painel_coluna_forma_categoria <- function(categoria, x = dt) {
    categoria <- as.character(categoria)[1]
    if (!categoria %in% MONITORA_TRIAGEM_CATEGORIAS_FORMA) return(NA_character_)
    col <- monitora_correcao_coluna_forma_vida(x, categoria)
    if (is.na(col) || !(col %in% names(x))) return(NA_character_)
    if (!monitora_correcao_coluna_principal_segura(x, col, categoria)) return(NA_character_)
    col
  }

  monitora_painel_formas_validas_choices_categoria <- function(categoria) {
    categoria_alvo <- as.character(categoria)[1L]
    info_categoria <- MONITORA_TRIAGEM_CATEGORIAS_INFO[categoria == categoria_alvo]
    if (nrow(info_categoria) != 1L) return(character(0))
    lista <- info_categoria$list_name[1L]
    escolhas_cu <- tryCatch({
      cu <- monitora_contrato_unico_indices_cache()
      ch <- data.table::as.data.table(cu$indices$por_choice_name)
      attrs <- data.table::as.data.table(cu$indices$por_list_name)
      if (!nrow(ch) || !all(c("list_name", "name") %in% names(ch))) data.table::data.table() else {
        for (cc in c("arquivo_xlsform", "list_name", "name", "label")) if (!(cc %in% names(ch))) ch[, (cc) := NA_character_]
        ch <- ch[grepl("21FEV25", as.character(arquivo_xlsform), ignore.case = TRUE)]
        ch <- ch[list_name == lista & !is.na(name) & nzchar(as.character(name))]
        if (nrow(attrs) && all(c("list_name", "cardinalidade_operacional", "relevant", "campo_pai") %in% names(attrs))) {
          attrs <- unique(attrs[list_name == lista, .(list_name, cardinalidade_operacional, relevant, campo_pai)])
          ch <- merge(ch, attrs, by = "list_name", all.x = TRUE, sort = FALSE)
          ch <- ch[
            is.na(cardinalidade_operacional) |
              cardinalidade_operacional %in% c("select_multiple", "estruturado_completo_por_ponto", "estruturado_condicional_esparso")
          ]
          ch <- ch[is.na(campo_pai) | !nzchar(as.character(campo_pai)) | campo_pai %in% c("tipo_forma_vida", lista)]
        }
        ch[, token_norm := monitora_relatorio_exoticas_normalizar_token(name)]
        ch <- ch[!is.na(token_norm) & nzchar(token_norm) & !(token_norm %in% MONITORA_TRIAGEM_TOKENS_INVALIDOS)]
        unique(ch[, .(name = token_norm, label = as.character(label))], by = "name")
      }
    }, error = function(e) data.table::data.table())
    if (nrow(escolhas_cu)) {
      escolhas_cu[, rotulo := monitora_painel_rotulo_token(label, name)]
      vals <- as.character(escolhas_cu$name)
      labs <- as.character(escolhas_cu$rotulo)
      o <- order(vals)
      return(stats::setNames(vals[o], labs[o]))
    }
    op <- if (!is.null(meta_xls) && !is.null(meta_xls$opcoes)) data.table::as.data.table(meta_xls$opcoes) else data.table::data.table()
    if (nrow(op) && all(c("list_name", "name", "label") %in% names(op))) {
      op[, arquivo_xlsform_chr := if ("arquivo_xlsform" %in% names(op)) as.character(arquivo_xlsform) else ""]
      cand <- op[list_name == lista]
      if (nrow(cand)) {
 ### Preferir explicitamente o XLSForm mais recente embutido; cair para
 ### qualquer versão histórica se necessário.
        cand_atual <- cand[grepl("21FEV25|2025", arquivo_xlsform_chr, ignore.case = TRUE)]
        if (nrow(cand_atual)) cand <- cand_atual
        cand[, token_norm := monitora_relatorio_exoticas_normalizar_token(name)]
        cand <- cand[!is.na(token_norm) & nzchar(token_norm) & !(token_norm %in% MONITORA_TRIAGEM_TOKENS_INVALIDOS)]
        if (nrow(cand)) {
          cand <- unique(cand[, .(name = token_norm, label = as.character(label))], by = "name")
          cand[, rotulo := monitora_painel_rotulo_token(label, name)]
          vals <- as.character(cand$name)
          labs <- as.character(cand$rotulo)
          o <- order(vals)
          return(stats::setNames(vals[o], labs[o]))
        }
      }
    }
 ### O fallback só existe para as três listas históricas. A quarta categoria
 ### deve necessariamente vir do contrato único; nunca inventar seu domínio.
    if (identical(categoria_alvo, "outra_forma_vida")) return(character(0))
    vals <- sort(setdiff(c(
      "bromelioide", "erva_bromelioide", "cactacea", "orquidea", "samambaia",
      "arbusto_acima", "arbusto_abaixo", "arvore_acima", "arvore_abaixo",
      "graminoide", "erva_nao_graminoide", "bambu", "lianas", "palmeira"
    ), MONITORA_TRIAGEM_TOKENS_INVALIDOS))
    stats::setNames(vals, vals)
  }

  formas_validas_por_categoria <- list(
    nativa = monitora_painel_formas_validas_choices_categoria("nativa"),
    exotica = monitora_painel_formas_validas_choices_categoria("exotica"),
    seca_morta = monitora_painel_formas_validas_choices_categoria("seca_morta"),
    outra_forma_vida = monitora_painel_formas_validas_choices_categoria("outra_forma_vida")
  )

  monitora_painel_info_contrato_atributo <- function(atributo) {
    col <- monitora_correcao_resolver_coluna(dt, atributo, dict, permitir_heuristica = FALSE)
    info <- contrato_edicao[atributo_coluna_registros_corrig == col]
    if (!nrow(info)) return(list(col = col, tipo = NA_character_, list_name = NA_character_, papel = NA_character_, categoria = NA_character_, escolhas = character(0)))
    info <- info[1L]
    escolhas <- monitora_correcao_choices_xlsform(info$xlsform_list_name, meta_xls)
    list(
      col = col,
      tipo = as.character(info$tipo_base_edicao[1L]),
      list_name = as.character(info$xlsform_list_name[1L]),
      papel = as.character(info$papel_coluna[1L]),
      categoria = as.character(info$categoria_coluna[1L]),
      escolhas = escolhas
    )
  }

 ### ### domínio de hábito (terrestre/epifita/rupicola) deixa de vir da constante
 ### hard-coded MONITORA_TRIAGEM_HABITO_CHOICES e passa a ser resolvido a
 ### partir do list_name real do XLSForm embutido — mesma coluna/categoria que
 ### monitora_correcao_resolver_coluna_habito e monitora_painel_info_contrato_
 ### atributo já usam para o restante do contrato (nenhuma fonte nova, só
 ### reaproveitamento). Confirmado por consulta direta ao XLSForm embutido: os
 ### campos forma_vida_{nativa,exotica,seca_morta}_{bromelioide,cactacea,
 ### orquidea,samambaia} têm cada um seu próprio list_name, mas todos com o
 ### mesmo domínio de 3 opções (epifita/terrestre/rupicola) — por isso basta
 ### resolver via qualquer uma das 3 categorias para a forma pedida.
  monitora_painel_habito_choices_contratuais <- function(forma = NULL) {
    forma_norm <- monitora_painel_canonizar_forma_habito(forma)
    if (!nzchar(forma_norm)) {
      formas_padrao <- tryCatch(monitora_correcao_tokens_formas_exigem_habito(), error = function(e) character(0))
      if (length(formas_padrao)) forma_norm <- monitora_painel_canonizar_forma_habito(formas_padrao[1L])
    }
    if (!nzchar(forma_norm)) return(character(0))
    for (categoria in c("nativa", "exotica", "seca_morta")) {
      col <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, categoria, forma_norm, dicionario = dict, meta_xls = meta_xls), error = function(e) NA_character_)
      if (is.na(col) || !nzchar(col)) next
      info <- tryCatch(monitora_painel_info_contrato_atributo(col), error = function(e) list(escolhas = character(0)))
      if (length(info$escolhas)) return(info$escolhas)
    }
    character(0)
  }

  try(monitora_painel_gravar_auditoria_controle_atributos(), silent = TRUE)

  monitora_painel_detalhar_forma_vida_contratual <- function(atributo, acao, valor_novo) {
    info <- monitora_painel_info_contrato_atributo(atributo)
    acao_norm <- monitora_correcao_acao_normalizar(acao)
    if (!identical(info$papel, "lista_principal_forma_vida") || !(acao_norm %in% c("append_token", "adicionar_token", "update", "replace_token"))) {
      return(list(eh = FALSE, categoria = NA_character_, tokens = character(0), tokens_invalidos = character(0), exige_habito = character(0), info = info))
    }
    categoria <- info$categoria
    if (is.na(categoria) || !nzchar(categoria)) categoria <- monitora_painel_categoria_por_coluna_forma(info$col)
    tokens <- monitora_correcao_tokenizar(valor_novo)
    tokens <- unique(vapply(tokens, monitora_painel_canonizar_forma_habito, character(1)))
    tokens <- tokens[!is.na(tokens) & nzchar(tokens)]
    validos <- unname(formas_validas_por_categoria[[categoria]])
    validos_norm <- unique(vapply(validos, monitora_painel_canonizar_forma_habito, character(1)))
    invalidos <- setdiff(tokens, validos_norm)
    exige <- tokens[vapply(tokens, monitora_painel_forma_exige_habito, logical(1))]
    list(eh = TRUE, categoria = categoria, tokens = tokens, tokens_invalidos = invalidos, exige_habito = exige, info = info, validos = validos_norm)
  }

  monitora_painel_mensagem_contrato_entrada <- function(atributo, acao, valor_novo) {
    info <- monitora_painel_info_contrato_atributo(atributo)
    acao_norm <- monitora_correcao_acao_normalizar(acao)
    partes <- c(
      paste0("Tipo XLSForm inferido: ", ifelse(is.na(info$tipo) || !nzchar(info$tipo), "não identificado", info$tipo)),
      paste0("Papel da coluna: ", ifelse(is.na(info$papel) || !nzchar(info$papel), "não identificado", info$papel))
    )
    if (!is.na(info$list_name) && nzchar(info$list_name)) partes <- c(partes, paste0("Lista XLSForm: ", info$list_name))
    if (length(info$escolhas)) partes <- c(partes, paste0("Opções válidas: ", monitora_correcao_colapsar_opcoes_msg(info$escolhas, 20L)))
 ### instrução operacional explícita por tipo de ação,
 ### derivada apenas do tipo já classificado pelo contrato (token vs valor) —
 ### nenhuma nova fonte de contrato, só texto de ajuda.
    if (info$tipo %in% c("select_multiple")) {
      partes <- c(partes, switch(acao_norm,
        append_token = "Adicionar token: escolha apenas o(s) token(s) a incluir; a operação não substitui a lista/célula inteira.",
        remove_token = "Remover token: remove apenas o(s) token(s) selecionado(s), preservando os demais já presentes na lista.",
        replace_token = "Substituir token: troca apenas o token origem pelo token destino; os demais tokens da lista permanecem.",
        "Escolha apenas o(s) token(s) da operação; nenhuma ação desta lista substitui a lista/célula inteira."
      ))
    } else if (nzchar(as.character(acao_norm)) && !(acao_norm %in% c("clear", "recalcular_tipo_forma_vida"))) {
      partes <- c(partes, "Informe o valor completo a ser gravado. O valor será validado por formato, não por domínio de choices, salvo regra contratual específica.")
    }
    exemplos <- monitora_correcao_exemplos_formato_msg(info$tipo, info$col)
    if (nzchar(exemplos)) partes <- c(partes, exemplos)
    det <- monitora_painel_detalhar_forma_vida_contratual(atributo, acao, valor_novo)
    if (isTRUE(det$eh) && length(det$exige_habito)) {
      partes <- c(partes, paste0("Forma(s) de vida com hábito obrigatório detectada(s): ", paste(det$exige_habito, collapse = ", "), ". Selecione o hábito na mesma operação."))
    }
    paste(partes, collapse = " | ")
  }

  monitora_painel_expandir_operacao_contratual <- function(op_base, x, linhas, atributo, acao, valor_novo, habito_val, n_esperado, n_alvo) {
    det <- monitora_painel_detalhar_forma_vida_contratual(atributo, acao, valor_novo)
    if (!isTRUE(det$eh)) return(list(ok = TRUE, ops = op_base, mensagem = ""))
    if (length(det$tokens_invalidos)) {
      msg <- paste0("Token(s) inválido(s) para lista de forma de vida ", det$categoria, ": ", paste(det$tokens_invalidos, collapse = ", "), ". Opções válidas: ", monitora_correcao_colapsar_opcoes_msg(det$validos), ".")
      return(list(ok = FALSE, mensagem = msg, ops = data.table::data.table()))
    }
    extras <- list()
    ordem <- suppressWarnings(max(as.integer(op_base$ordem_operacao), na.rm = TRUE))
    if (!is.finite(ordem)) ordem <- 1L
    habito_val <- monitora_painel_valor(habito_val)
 ### opções válidas resolvidas do XLSForm embutido
 ### (mesma fonte do widget), não mais de MONITORA_TRIAGEM_HABITO_CHOICES.
    habito_opcoes_validas <- if (length(det$exige_habito)) monitora_painel_habito_choices_contratuais(det$exige_habito[1L]) else character(0)
    if (length(det$exige_habito) && !nzchar(habito_val)) {
      return(list(ok = FALSE, mensagem = paste0("A forma de vida '", paste(det$exige_habito, collapse = ", "), "' exige hábito. Selecione uma opção válida: ", paste(unname(habito_opcoes_validas), collapse = ", "), "."), ops = data.table::data.table()))
    }
    if (length(det$exige_habito)) {
      if (!habito_val %in% unname(habito_opcoes_validas) || !nzchar(habito_val)) {
        return(list(ok = FALSE, mensagem = paste0("Hábito inválido. Opções válidas: ", paste(unname(habito_opcoes_validas), collapse = ", "), "."), ops = data.table::data.table()))
      }
      for (ff in det$exige_habito) {
        dep_col <- tryCatch(monitora_correcao_resolver_coluna_habito(x, det$categoria, ff, if (!is.null(meta_xls)) meta_xls$campos else NULL, linha = if (length(linhas)) linhas[1L] else NA_integer_, meta_xls = meta_xls), error = function(e) NA_character_)
        if (!monitora_correcao_coluna_habito_segura(x, dep_col, det$categoria, ff) || identical(dep_col, det$info$col)) {
          return(list(ok = FALSE, mensagem = paste0("Não foi localizada coluna segura de hábito para '", ff, "' na categoria ", det$categoria, ". Correção bloqueada para evitar preenchimento em coluna errada."), ops = data.table::data.table()))
        }
        ordem <- ordem + 1L
        val_orig <- if (dep_col %in% names(x) && length(linhas)) unique(as.character(x[[dep_col]][linhas])) else NA_character_
        val_orig <- val_orig[!is.na(val_orig) & nzchar(trimws(val_orig))]
        val_orig <- if (length(val_orig) == 1L) val_orig[1L] else NA_character_
        op_h <- monitora_correcao_criar_operacao(
          id = as.character(op_base$id_correcao[1L]), responsavel = as.character(op_base$responsavel[1L]), tipo = "correcao_contratual_xlsform_habito", ordem = ordem,
          escopo = as.character(op_base$escopo_aplicacao[1L]), coleta = as.character(op_base$coleta[1L]), coleta_uuid = as.character(op_base$coleta_uuid[1L]),
          atributo = dep_col, acao = "update", valor_original = val_orig, valor_novo = habito_val,
          n_esperado = n_esperado, n_alvo = n_alvo, motivo = paste0(as.character(op_base$motivo[1L]), " [ação composta: hábito obrigatório pelo contrato XLSForm]"),
          token_pai = ff, categoria_destino = det$categoria, forma_valida_escolhida = ff, lista_destino = det$categoria,
          campo_dependente_preenchido = dep_col, habito_escolhido = habito_val
        )
        op_h <- monitora_correcao_anexar_contexto_operacao(op_h, x, linhas, chaves)
        extras[[length(extras) + 1L]] <- op_h
      }
    }
    tipo_col <- chaves$tipo_forma_vida
    if (!is.na(tipo_col) && nzchar(tipo_col) && tipo_col %in% names(x)) {
      ordem <- ordem + 1L
      val_orig_tipo <- if (length(linhas)) unique(as.character(x[[tipo_col]][linhas])) else NA_character_
      val_orig_tipo <- val_orig_tipo[!is.na(val_orig_tipo) & nzchar(trimws(val_orig_tipo))]
      val_orig_tipo <- if (length(val_orig_tipo) == 1L) val_orig_tipo[1L] else NA_character_
      op_t <- monitora_correcao_criar_operacao(
        id = as.character(op_base$id_correcao[1L]), responsavel = as.character(op_base$responsavel[1L]), tipo = "correcao_contratual_xlsform_encostam", ordem = ordem,
        escopo = as.character(op_base$escopo_aplicacao[1L]), coleta = as.character(op_base$coleta[1L]), coleta_uuid = as.character(op_base$coleta_uuid[1L]),
        atributo = tipo_col, acao = "recalcular_tipo_forma_vida", valor_original = val_orig_tipo, valor_novo = NA_character_,
        n_esperado = n_esperado, n_alvo = n_alvo, motivo = paste0(as.character(op_base$motivo[1L]), " [ação composta: recálculo de Encostam/tipo_forma_vida pelo contrato XLSForm]"),
        token_pai = det$categoria, categoria_destino = det$categoria, lista_destino = det$categoria
      )
      op_t <- monitora_correcao_anexar_contexto_operacao(op_t, x, linhas, chaves)
      extras[[length(extras) + 1L]] <- op_t
    }
    ops <- data.table::rbindlist(c(list(op_base), extras), fill = TRUE, use.names = TRUE)
    msg <- if (nrow(ops) > nrow(op_base)) paste0("Operação composta pelo contrato XLSForm: ", nrow(ops), " ação(ões) atômica(s), incluindo atualização de Encostam e hábito quando obrigatório.") else ""
    list(ok = TRUE, ops = ops, mensagem = msg)
  }

 ### Performance: não tokenizar todos os registros na abertura do painel apenas
 ### para montar opções do movimento assistido. A lista fixa cobre os tokens
 ### operacionais esperados; tokens diagnósticos observados na triagem unificada
 ### são reaproveitados porque essa tabela já foi montada antes da abertura do
 ### painel.
  formas_exoticas_observadas <- character(0)
  formas_diagnosticas_mv <- character(0)
  if (exists("triagem_painel_unificada", inherits = FALSE)) {
    tri_mv <- tryCatch(data.table::as.data.table(triagem_painel_unificada), error = function(e) data.table::data.table())
    if (nrow(tri_mv) && all(c("tipo_triagem", "token_detectado") %in% names(tri_mv))) {
      tok_mv <- tri_mv[tipo_triagem %in% c("forma_vida_desconhecida", "outras_formas_vida"), token_detectado]
      formas_diagnosticas_mv <- unique(unlist(lapply(tok_mv, monitora_painel_split_tokens_triagem), use.names = FALSE))
      formas_diagnosticas_mv <- formas_diagnosticas_mv[!is.na(formas_diagnosticas_mv) & nzchar(formas_diagnosticas_mv)]
    }
  }
  formas_diagnosticas_mv <- setdiff(formas_diagnosticas_mv, MONITORA_TRIAGEM_TOKENS_OUTRAS)

  monitora_painel_montar_choices_formas_mv <- function() {
 ### Lista do movimento assistido apresentada por LABEL do XLSForm mais
 ### recente (21FEV25/2025). Os names atuais e históricos ficam vinculados
 ### internamente ao label/canônico, mas não são exibidos como opções ao
 ### usuário. A lista é restrita às formas de vida das listas
 ### forma_vida_nativa, forma_vida_exotica e forma_vida_seca_morta; portanto
 ### não inclui atributos de Encostam na vareta, como serrapilheira,
 ### fragmentos_botanicos ou material_inundado, nem forma_vida_outros.
    listas_forma <- MONITORA_TRIAGEM_CATEGORIAS_INFO$list_name
    tokens_excluir_mv <- unique(c(
      c("outra_forma_vida", "outras_formas_vida", "forma_vida_outros", "outra", "outro", "outras", "outros"),
      "serrapilheira", "fragmentos_botanicos", "material_inundado",
      "solo_nu", "nativa", "exotica", "seca", "morta", "seca_morta"
    ))

    fallback_atual <- data.table::data.table(
      token_representativo = c(
        "graminoide", "erva_nao_graminoide", "arbusto_abaixo", "arbusto_acima",
        "arvore_abaixo", "arvore_acima", "bambu", "bromelioide", "cactacea",
        "lianas", "ervas_de_passarinho", "orquidea", "palmeira", "samambaia",
        "canela_de_ema", "desconhecida"
      ),
      label_exibicao = c(
        "Erva graminoide (gramíneas, ciperáceas e juncáceas)",
        "Erva não graminoide",
        "Arbusto tocando a vareta a uma altura inferior a 50cm",
        "Arbusto tocando a vareta a uma altura igual ou superior a 50cm",
        "Árvore com diâmetro do tronco menor que 5cm a 30cm do solo (D30)",
        "Árvore com diâmetro do tronco igual ou maior que 5cm a 30cm do solo (D30)",
        "Bambu ou taquara",
        "Erva bromelioide (bromeliáceas, apiáceas, eriocauláceas)",
        "Cacto",
        "Liana, cipó ou trepadeira",
        "Erva-de-passarinho (hemiparasita)",
        "Orquídea",
        "Palmeira",
        "Samambaia",
        "Velósia (Velloziaceae)",
        "Forma de vida desconhecida"
      ),
      ordem = seq_len(16L)
    )
    fallback_atual[, tokens_historicos := token_representativo]

    out <- fallback_atual
    contrato_mv <- tryCatch({
      cu <- monitora_contrato_unico_indices_cache()
      ch <- data.table::as.data.table(cu$indices$por_choice_name)
      attrs <- data.table::as.data.table(cu$indices$por_list_name)
      if (!nrow(ch) || !all(c("list_name", "name") %in% names(ch))) data.table::data.table() else {
        for (cc in c("list_name", "name", "label")) if (!(cc %in% names(ch))) ch[, (cc) := NA_character_]
        ch <- ch[list_name %in% listas_forma]
        if (nrow(attrs) && all(c("list_name", "cardinalidade_operacional", "relevant", "campo_pai") %in% names(attrs))) {
          attrs <- unique(attrs[list_name %in% listas_forma, .(list_name, cardinalidade_operacional, relevant, campo_pai)])
          ch <- merge(ch, attrs, by = "list_name", all.x = TRUE, sort = FALSE)
          ch <- ch[
            is.na(cardinalidade_operacional) |
              cardinalidade_operacional %in% c("select_multiple", "estruturado_completo_por_ponto", "estruturado_condicional_esparso")
          ]
          ch <- ch[is.na(campo_pai) | !nzchar(as.character(campo_pai)) | campo_pai %in% c("tipo_forma_vida", listas_forma)]
        }
        ch[, token_norm := monitora_relatorio_exoticas_normalizar_token(name)]
        ch[, label_chr := trimws(as.character(label))]
        ch[is.na(label_chr) | !nzchar(label_chr), label_chr := token_norm]
        ch <- ch[!is.na(token_norm) & nzchar(token_norm)]
        ch <- ch[!(token_norm %in% tokens_excluir_mv)]
        if (!nrow(ch)) data.table::data.table() else {
          ch[, label_key := monitora_correcao_normalizar_nome_coluna(label_chr)]
          ch[, ordem := seq_len(.N)]
          atuais <- unique(ch[, .(
            token_representativo = token_norm,
            label_exibicao = label_chr,
            label_key = label_key,
            ordem = ordem
          )], by = "token_representativo")
          atuais[, tokens_historicos := token_representativo]
          atuais[, .(token_representativo, label_exibicao, tokens_historicos, ordem)]
        }
      }
    }, error = function(e) data.table::data.table())
    if (nrow(contrato_mv)) out <- contrato_mv

    op <- if (!nrow(contrato_mv) && !is.null(meta_xls) && !is.null(meta_xls$opcoes)) data.table::as.data.table(meta_xls$opcoes) else data.table::data.table()
    if (nrow(op) && all(c("list_name", "name", "label") %in% names(op))) {
      op[, arquivo_xlsform_chr := if ("arquivo_xlsform" %in% names(op)) as.character(arquivo_xlsform) else ""]
      cand <- op[list_name %in% listas_forma]
      if (nrow(cand)) {
        cand[, token_norm := monitora_relatorio_exoticas_normalizar_token(name)]
        cand[, label_chr := trimws(as.character(label))]
        cand[is.na(label_chr) | !nzchar(label_chr), label_chr := token_norm]
        cand[, label_key := monitora_correcao_normalizar_nome_coluna(label_chr)]
        cand[, atual := grepl("21FEV25|2025", arquivo_xlsform_chr, ignore.case = TRUE)]
        cand <- cand[!is.na(token_norm) & nzchar(token_norm)]
        cand <- cand[!(token_norm %in% tokens_excluir_mv)]

        cand_atual <- cand[atual == TRUE]
        if (nrow(cand_atual)) {
          cand_atual[, ordem_atual := seq_len(.N)]
 ### Usar os names e labels do XLSForm mais recente como canônicos.
          atuais <- unique(cand_atual[, .(
            token_representativo = token_norm,
            label_exibicao = label_chr,
            label_key = label_key,
            ordem = ordem_atual
          )], by = "token_representativo")

          hist <- atuais[, {
            toks <- cand[token_norm == .BY$token_representativo | label_key == .BY$label_key, token_norm]
            toks <- sort(unique(c(toks, .BY$token_representativo)))
            list(tokens_historicos = paste(toks, collapse = "|"))
          }, by = .(token_representativo, label_exibicao, label_key, ordem)]
          out <- hist[, .(token_representativo, label_exibicao, tokens_historicos, ordem)]
        } else if (nrow(cand)) {
 ### Fallback raro: se o XLSForm mais recente não estiver nos metadados,
 ### usar somente tokens observados nas listas forma_vida_* históricas,
 ### sem incluir atributos de Encostam/forma_vida_outros.
          cand[, ordem_hist := seq_len(.N)]
          out <- unique(cand[, .(
            token_representativo = token_norm,
            label_exibicao = label_chr,
            tokens_historicos = token_norm,
            ordem = ordem_hist
          )], by = "token_representativo")
        }
      }
    }

 ### Consolidar explicitamente aliases históricos de desconhecida em uma
 ### única opção operacional com o label atual.
    if (nrow(out)) {
      out[token_representativo %in% MONITORA_TRIAGEM_TOKENS_DESCONHECIDOS | grepl("desconhecid", monitora_correcao_normalizar_nome_coluna(label_exibicao)),
          `:=`(
            token_representativo = "desconhecida",
            label_exibicao = "Forma de vida desconhecida",
            tokens_historicos = paste(sort(unique(MONITORA_TRIAGEM_TOKENS_DESCONHECIDOS)), collapse = "|")
          )]
      out <- out[!(token_representativo %in% tokens_excluir_mv)]
      data.table::setorder(out, ordem, label_exibicao, token_representativo)
      out <- unique(out, by = "token_representativo")
    }

    choices <- stats::setNames(
      as.character(out$token_representativo),
      monitora_painel_rotulo_token(out$label_exibicao, out$token_representativo)
    )
    tokens_historicos <- stats::setNames(strsplit(as.character(out$tokens_historicos), "|", fixed = TRUE), as.character(out$token_representativo))
    token_para_representativo <- stats::setNames(as.character(out$token_representativo), as.character(out$token_representativo))
    for (ii in seq_len(nrow(out))) {
      toks <- unlist(strsplit(as.character(out$tokens_historicos[ii]), "|", fixed = TRUE), use.names = FALSE)
      toks <- unique(monitora_relatorio_exoticas_normalizar_token(toks))
      toks <- toks[!is.na(toks) & nzchar(toks)]
      if (length(toks)) token_para_representativo[toks] <- as.character(out$token_representativo[ii])
    }
    list(choices = choices, tokens_historicos = tokens_historicos, token_para_representativo = token_para_representativo)
  }

  formas_mv_choices_info <- monitora_painel_montar_choices_formas_mv()
  formas_mv_choices <- formas_mv_choices_info$choices
  formas_mv_tokens_historicos <- formas_mv_choices_info$tokens_historicos
  formas_mv_token_para_representativo <- formas_mv_choices_info$token_para_representativo

  monitora_painel_forma_representativa_mv <- function(forma) {
    forma <- monitora_relatorio_exoticas_normalizar_token(monitora_painel_valor(forma))
    if (!nzchar(forma)) return("")
    z <- formas_mv_token_para_representativo[[forma]]
    if (is.null(z) || !length(z) || is.na(z)) return(forma)
    as.character(z)[1L]
  }

  monitora_painel_forma_tokens_historicos_mv <- function(forma) {
    forma <- monitora_painel_forma_representativa_mv(forma)
    if (!nzchar(forma)) return(character(0))
    z <- formas_mv_tokens_historicos[[forma]]
    if (is.null(z) || !length(z)) z <- forma
    z <- unique(monitora_relatorio_exoticas_normalizar_token(z))
    z[!is.na(z) & nzchar(z)]
  }

  monitora_painel_mv_choices_com_token <- function(token) {
    token <- monitora_painel_valor(token)
    choices <- formas_mv_choices
    token_rep <- monitora_painel_forma_representativa_mv(token)
    if (nzchar(token_rep) && !(token_rep %in% unname(choices))) {
      choices <- c(choices, stats::setNames(token_rep, token_rep))
    }
    choices
  }

  monitora_painel_valor_celula <- function(x, col, i) {
    if (is.na(col) || !(col %in% names(x)) || length(i) != 1L || is.na(i) || i < 1L || i > nrow(x)) return(NA_character_)
    as.character(x[[col]][i])
  }

  monitora_painel_tabela_exoticas <- function(x) {
 ### Triagem unificada dos registros atualmente selecionados no painel.
 ### Mantém o nome interno histórico da função para reduzir risco de quebra
 ### nos observadores existentes, mas passa a listar:
 ### - formas de vida exóticas;
 ### - formas de vida desconhecida;
 ### - outras formas de vida.
 ###
 ### A montagem é restrita aos registros filtrados pela coleta ativa e usa
 ### data.table/listas pré-resolvidas para evitar resolução repetida de
 ### colunas no Shiny.
    if (nrow(x) == 0L) return(data.table::data.table())

    n <- nrow(x)
    campos_ctx <- list(
      COLETA = chaves$coleta,
      UC = chaves$uc,
      EA = chaves$ea,
      UA = chaves$ua,
      CICLO = chaves$ciclo,
      CAMPANHA = chaves$campanha,
      ANO = chaves$ano,
      `Data (data_hora)` = chaves$data_hora,
      ponto_amostral = chaves$ponto_amostral,
      ponto_metro = chaves$ponto_metro,
      uuid_registro = chaves$uuid_registro
    )

    valor_col <- function(col) {
      if (length(col) != 1L || is.na(col) || !nzchar(col) || !(col %in% names(x))) return(rep(NA_character_, n))
      as.character(x[[col]])
    }

    contexto_dt <- data.table::data.table(linha_filtro = seq_len(n), linha_indice_global = seq_len(n))
    for (nm in names(campos_ctx)) data.table::set(contexto_dt, j = nm, value = valor_col(campos_ctx[[nm]]))

    forma_cols_todas <- unique(na.omit(monitora_correcao_colunas_forma_vida_principais(x)))
    forma_cols_todas <- forma_cols_todas[forma_cols_todas %in% names(x)]

    meta_campos <- if (!is.null(meta_xls)) meta_xls$campos else NULL
    out <- list()

 ### 1) Exóticas: registros com token exotica em Encostam são triados.
 ### A classificação separa: (a) forma + sp vinculada, (b) forma sem sp,
 ### (c) erro: exótica em Encostam sem forma de vida exótica detalhada.
    tipo_col <- chaves$tipo_forma_vida
    tem_token_ex <- if (!is.na(tipo_col) && tipo_col %in% names(x)) {
      monitora_relatorio_exoticas_tem_token(x[[tipo_col]], c("exotica", "exoticas", "exotico", "exoticos"))
    } else {
      rep(FALSE, n)
    }
    det_exoticas_painel <- monitora_diag_exoticas_ocorrencias_detalhadas(x)
    if (any(tem_token_ex, na.rm = TRUE)) {
      cols_ex_x <- cols_forma_exotica[cols_forma_exotica %in% names(x)]
      forma_chr <- if (length(cols_ex_x)) monitora_relatorio_exoticas_colapsar_valores(x, cols_ex_x, incluir_nomes = FALSE) else rep(NA_character_, n)
      tem_forma_ex <- !monitora_correcao_vazio_vec(forma_chr)
      linhas_forma <- which(tem_token_ex & tem_forma_ex)
      linhas_sem_forma <- which(tem_token_ex & !tem_forma_ex)

      if (length(linhas_forma)) {
 ### Preserva os tokens exibidos pelo painel, mas aceita somente formas
 ### reconhecidas pela fonte canônica e herda dela a classificação do
 ### vínculo de espécie. Isso mantém a UI/operações e elimina o segundo
 ### classificador que divergia nos cabeçalhos históricos de árvores.
        tokens_por_linha <- lapply(linhas_forma, function(ii) {
          toks <- unique(monitora_correcao_tokenizar(forma_chr[ii]))
          toks <- toks[!is.na(toks) & nzchar(toks)]
          if (!length(toks)) return(character(0))
          toks_canon <- vapply(toks, function(z) {
            zz <- monitora_correcao_forma_canonica_lote(z)
            if (length(zz)) as.character(zz[1L]) else ""
          }, character(1L))
          formas_canon <- unique(as.character(det_exoticas_painel[linha_indice == ii, forma_de_vida_detectada]))
          toks[toks_canon %in% formas_canon & !duplicated(toks_canon)]
        })
        tokens_unicos <- sort(unique(unlist(tokens_por_linha, use.names = FALSE)))
        tokens_unicos <- tokens_unicos[!is.na(tokens_unicos) & nzchar(tokens_unicos)]

        hab_cols <- stats::setNames(rep(NA_character_, length(tokens_unicos)), tokens_unicos)
        if (length(tokens_unicos)) {
          hab_cols[] <- vapply(tokens_unicos, function(tok) monitora_correcao_resolver_coluna_habito(x, "exotica", tok, meta_campos, linha = NA_integer_, meta_xls = meta_xls), character(1))
        }

        exoticas <- vector("list", length(linhas_forma))
        for (kk in seq_along(linhas_forma)) {
          ii <- linhas_forma[kk]
          tokens <- unique(tokens_por_linha[[kk]])
          tokens <- tokens[!is.na(tokens) & nzchar(tokens)]
          if (!length(tokens)) next
          exoticas[[kk]] <- data.table::rbindlist(lapply(tokens, function(tok) {
            hab_col <- hab_cols[[tok]]
            tok_canon <- monitora_correcao_forma_canonica_lote(tok)[1L]
            det_tok <- det_exoticas_painel[
              linha_indice == ii & forma_de_vida_detectada == tok_canon
            ]
            if (nrow(det_tok) > 1L) det_tok <- det_tok[1L]
            tem_sp <- nrow(det_tok) == 1L && identical(as.character(det_tok$tipo_ocorrencia), "forma_vida_exotica_com_especie")
            esp_campos <- if (nrow(det_tok)) as.character(det_tok$atributos_especie_vinculados) else ""
            esp_valores <- if (nrow(det_tok)) as.character(det_tok$valores_especie_vinculados) else ""
            campos_tok <- if (nrow(det_tok)) as.character(det_tok$atributo_forma_vida) else ""
            valores_tok <- if (nrow(det_tok)) as.character(det_tok$valor_forma_vida_atual) else ""
            data.table::data.table(
              linha_filtro = ii,
              tipo_triagem = "exotica",
              categoria_forma_vida = "exotica",
              token_detectado = tok,
              status_vinculo = ifelse(tem_sp, "exotica_com_forma_e_sp_vinculada", "exotica_com_forma_sem_sp_vinculada"),
              motivo_triagem = ifelse(tem_sp, "Encostam=exotica + forma exótica + espécie no atributo específico da forma", "Encostam=exotica + forma exótica sem espécie no atributo específico da forma"),
              campo_forma_vida = paste(campos_tok, collapse = " | "),
              valor_forma_vida_original = valores_tok,
              forma_vida_exotica = tok,
              forma_vida_exotica_original = valores_tok,
              campo_habito_exotica = hab_col,
              habito_exotica = monitora_painel_valor_celula(x, hab_col, ii),
              campo_especies_exoticas = esp_campos,
              especies_exoticas = esp_valores,
              campos_forma_vida_com_token = paste(campos_tok, collapse = " | "),
              valores_forma_vida_com_token = valores_tok,
              acao_assistida_sugerida = "mover_exotica_para_nativa"
            )
          }), fill = TRUE, use.names = TRUE)
        }
        exoticas <- exoticas[!vapply(exoticas, is.null, logical(1))]
        if (length(exoticas)) out[[length(out) + 1L]] <- data.table::rbindlist(exoticas, fill = TRUE, use.names = TRUE)
      }

      if (length(linhas_sem_forma)) {
        sem_forma <- data.table::data.table(
          linha_filtro = linhas_sem_forma,
          tipo_triagem = "exotica",
          categoria_forma_vida = "exotica",
          token_detectado = "exotica_sem_forma_detalhada",
          status_vinculo = "erro_exotica_sem_forma_vida_detalhada",
          motivo_triagem = "Erro de dado: Encostam contém exotica, mas a lista de formas de vida exóticas está vazia",
          campo_forma_vida = paste(cols_ex_x, collapse = " | "),
          valor_forma_vida_original = forma_chr[linhas_sem_forma],
          forma_vida_exotica = NA_character_,
          forma_vida_exotica_original = NA_character_,
          campo_habito_exotica = NA_character_,
          habito_exotica = NA_character_,
          campo_especies_exoticas = NA_character_,
          especies_exoticas = NA_character_,
          campos_forma_vida_com_token = tipo_col,
          valores_forma_vida_com_token = paste0(tipo_col, " = ", as.character(x[[tipo_col]][linhas_sem_forma])),
          acao_assistida_sugerida = "corrigir_forma_exotica_ausente"
        )
        out[[length(out) + 1L]] <- sem_forma
      }
    }

 ### 2) Desconhecidas e outras formas de vida: varre todas as colunas de
 ### forma de vida detectadas e registra os campos/valores onde os tokens
 ### apareceram. A geração é feita por grupo de token para evitar expandir
 ### desnecessariamente todos os registros.
    adicionar_tokens <- function(tokens, tipo_label, categoria_label, acao_label) {
      if (!length(forma_cols_todas)) return(NULL)
      tokens_norm <- unique(monitora_relatorio_exoticas_normalizar_token(tokens))
      tokens_norm <- tokens_norm[!is.na(tokens_norm) & nzchar(tokens_norm)]
      if (!length(tokens_norm)) return(NULL)
      info <- monitora_relatorio_colapsar_campos_com_tokens(x, forma_cols_todas, tokens_norm)
      linhas <- which(nzchar(info$tokens))
      if (!length(linhas)) return(NULL)
      data.table::data.table(
        linha_filtro = linhas,
        tipo_triagem = tipo_label,
        categoria_forma_vida = categoria_label,
        token_detectado = info$tokens[linhas],
        campo_forma_vida = info$campos[linhas],
        valor_forma_vida_original = info$valores[linhas],
        forma_vida_exotica = NA_character_,
        forma_vida_exotica_original = NA_character_,
        campo_habito_exotica = NA_character_,
        habito_exotica = NA_character_,
        campo_especies_exoticas = NA_character_,
        especies_exoticas = NA_character_,
        campos_forma_vida_com_token = info$campos[linhas],
        valores_forma_vida_com_token = info$valores[linhas],
        acao_assistida_sugerida = acao_label
      )
    }

 ### uma única classificação contratual separa revisão válida de
 ### estado impeditivo sem mudar o tipo de triagem consumido pelas operações
 ### assistidas. `tipo_ocorrencia_painel` controla apenas filtros/contagens.
    det_desc_tri <- tryCatch(
      monitora_correcao_classificar_desconhecida(x, chaves = monitora_correcao_colunas_chave(x), dicionario = NULL),
      error = function(e) data.table::data.table()
    )
    if (nrow(det_desc_tri)) {
      desconhecidas <- det_desc_tri[, .(
        linha_filtro = linha_indice,
        tipo_triagem = "forma_vida_desconhecida",
        tipo_ocorrencia_painel = tipo_ocorrencia,
        status_contrato_desconhecida = status_contrato,
        bloqueia_registros_validados = bloqueia_registros_validados,
        categoria_forma_vida = categoria,
        token_detectado = ifelse(status_contrato == "dependente_desconhecida_sem_token", "dependente_desconhecida_sem_token", "desconhecida"),
        motivo_triagem = motivo_rejeicao,
        campo_forma_vida = atributo_problema,
        valor_forma_vida_original = valor_observado,
        forma_vida_exotica = NA_character_,
        forma_vida_exotica_original = NA_character_,
        campo_habito_exotica = NA_character_,
        habito_exotica = NA_character_,
        campo_especies_exoticas = NA_character_,
        especies_exoticas = NA_character_,
        campos_forma_vida_com_token = atributo_lista,
        valores_forma_vida_com_token = valor_observado,
        acao_assistida_sugerida = ifelse(
          status_contrato == "revisao_desconhecida_valida",
          "avaliar_token_desconhecido",
          ifelse(status_contrato == "foto_obrigatoria_desconhecida_ausente", "preencher_foto_obrigatoria_desconhecida", "corrigir_estado_desconhecida_invalida")
        )
      )]
      out[[length(out) + 1L]] <- desconhecidas
    }


    outras <- adicionar_tokens(
      c("outra_forma_vida", "outras_formas_vida", "forma_vida_outros", "outra", "outro", "outras", "outros"),
      "outras_formas_vida",
      "outras_formas_vida",
      "avaliar_outras_formas_vida"
    )
    if (!is.null(outras) && nrow(outras)) out[[length(out) + 1L]] <- outras

    if (!length(out)) {
      triagem_vazia <- data.table::data.table()
      data.table::setattr(triagem_vazia, "monitora_exoticas_canonicas", data.table::copy(det_exoticas_painel))
      return(triagem_vazia)
    }
    triagem <- data.table::rbindlist(out, fill = TRUE, use.names = TRUE)
    triagem <- contexto_dt[triagem, on = "linha_filtro"]
    if ("especies_exoticas" %in% names(triagem)) {
      triagem[, tem_especie_vinculada_painel := monitora_relatorio_exoticas_tem_especie_valida(especies_exoticas)]
    } else {
      triagem[, tem_especie_vinculada_painel := FALSE]
    }
    cols_ordem <- c(
      "tipo_triagem", "status_vinculo", "motivo_triagem", "categoria_forma_vida", "token_detectado", "COLETA", "UC", "EA", "UA", "CICLO", "CAMPANHA", "ANO",
      "Data (data_hora)", "ponto_amostral", "ponto_metro", "uuid_registro", "linha_filtro",
      "campo_forma_vida", "valor_forma_vida_original", "campos_forma_vida_com_token", "valores_forma_vida_com_token",
      "forma_vida_exotica", "forma_vida_exotica_original", "campo_habito_exotica", "habito_exotica",
      "campo_especies_exoticas", "especies_exoticas", "tem_especie_vinculada_painel", "acao_assistida_sugerida"
    )
    cols_ordem <- unique(c(cols_ordem[cols_ordem %in% names(triagem)], setdiff(names(triagem), cols_ordem)))
    data.table::setcolorder(triagem, cols_ordem)
    data.table::setorder(triagem, tipo_triagem, UC, UA, ANO, ponto_amostral, ponto_metro, token_detectado)
    data.table::setattr(triagem, "monitora_exoticas_canonicas", data.table::copy(det_exoticas_painel))
    triagem[]
  }

  triagem_painel_unificada <- monitora_painel_tabela_exoticas(dt)
  reconciliacao_exoticas_pre <- monitora_diag_reconciliar_exoticas_painel(
    dt,
    triagem_painel_unificada,
    contexto = "pre_painel",
    base_dir = file.path(MONITORA_OUTPUT_DIR, "03_auditorias", "diagnosticos"),
    falhar = TRUE,
    esperado_precomputado = attr(triagem_painel_unificada, "monitora_exoticas_canonicas", exact = TRUE)
  )
  monitora_correcao_console_msg(
    "Reconciliação canônica de exóticas pré-painel aprovada: ",
    nrow(reconciliacao_exoticas_pre$esperado), " identidade(s) linha×forma×tipo."
  )
  if (nrow(triagem_painel_unificada) > 0L) {
    if (!("linha_indice_global" %in% names(triagem_painel_unificada))) triagem_painel_unificada[, linha_indice_global := as.integer(linha_filtro)]
    arq_triagem_unificada <- file.path(MONITORA_CORRECOES_DIR, "triagem_painel_unificada_pre_painel.csv")
    try(monitora_fwrite(triagem_painel_unificada, arq_triagem_unificada, na = ""), silent = TRUE)
    try(monitora_fwrite(triagem_painel_unificada, file.path(MONITORA_LOG_DIR, paste0("triagem_painel_unificada_pre_painel_", MONITORA_EXEC_ID, ".csv")), na = ""), silent = TRUE)
    monitora_correcao_console_msg("Triagem unificada do painel preparada: ", nrow(triagem_painel_unificada), " ocorrência(s) em ", data.table::uniqueN(triagem_painel_unificada$COLETA), " coleta(s).")
  } else {
    monitora_correcao_console_msg("Triagem unificada do painel preparada sem ocorrências diagnósticas.")
  }

  monitora_painel_coletas_com_token_forma <- function(tokens) {
    if (!monitora_painel_coluna_ok(chaves$coleta, dt)) return(character(0))
    cols_forma <- unique(na.omit(monitora_relatorio_formas_vida_detectar_colunas_todas(dt)))
    cols_forma <- cols_forma[cols_forma %in% names(dt)]
    if (!length(cols_forma)) return(character(0))
    tokens_norm <- unique(monitora_relatorio_exoticas_normalizar_token(tokens))
    tokens_norm <- tokens_norm[!is.na(tokens_norm) & nzchar(tokens_norm)]
    if (!length(tokens_norm)) return(character(0))
    mask <- rep(FALSE, nrow(dt))
    for (cc in cols_forma) {
      mask <- mask | monitora_relatorio_exoticas_tem_token(dt[[cc]], tokens_norm)
    }
    vals <- unique(as.character(dt[[chaves$coleta]][mask]))
    vals <- vals[!is.na(vals) & nzchar(vals)]
    sort(vals)
  }

  monitora_painel_coletas_exoticas_por_especie <- function() {
 ### Atalhos globais de coletas para os filtros do painel. A classificação
 ### segue a regra operacional: Encostam=exotica + forma exótica + espécie no
 ### atributo específico da forma. Casos sem forma detalhada são erro de dado.
    vazio <- list(sem_sp = character(0), com_sp = character(0), sem_forma = character(0))
    if (!monitora_painel_coluna_ok(chaves$coleta, dt)) return(vazio)
    tipo_col <- chaves$tipo_forma_vida
    if (is.na(tipo_col) || !(tipo_col %in% names(dt))) return(vazio)
    col_ex <- cols_forma_exotica[cols_forma_exotica %in% names(dt)]
    coleta_vals <- as.character(dt[[chaves$coleta]])
    tem_token_ex <- monitora_relatorio_exoticas_tem_token(dt[[tipo_col]], c("exotica", "exoticas", "exotico", "exoticos"))
    tem_forma <- if (length(col_ex)) Reduce(`|`, lapply(col_ex, function(cc) !monitora_correcao_vazio_vec(dt[[cc]]))) else rep(FALSE, nrow(dt))
    especie_cols <- tryCatch(monitora_relatorio_exoticas_detectar_colunas_especies(dt), error = function(e) character(0))
    vinc <- tryCatch(
      monitora_relatorio_exoticas_especies_vinculadas_por_linha(dt, col_ex, especie_cols)$tem,
      error = function(e) rep(FALSE, nrow(dt))
    )
    sem_sp <- sort(unique(coleta_vals[tem_token_ex & tem_forma & !vinc]))
    com_sp <- sort(unique(coleta_vals[tem_token_ex & tem_forma & vinc]))
    sem_forma <- sort(unique(coleta_vals[tem_token_ex & !tem_forma]))
    list(
      sem_sp = sem_sp[!is.na(sem_sp) & nzchar(sem_sp)],
      com_sp = com_sp[!is.na(com_sp) & nzchar(com_sp)],
      sem_forma = sem_forma[!is.na(sem_forma) & nzchar(sem_forma)]
    )
  }

  monitora_painel_coletas_relatorio_pre <- function(nome_arquivo) {
 ### Leitura rápida das coletas já triadas nos relatórios pré-painel.
 ### Evita revarrer registros_corrig inteiro para alimentar os checkboxes.
    base_dir_rel <- if (exists("MONITORA_CORRECOES_DIR", inherits = FALSE)) MONITORA_CORRECOES_DIR else file.path(MONITORA_OUTPUT_DIR, "correcoes_campos")
    arq <- file.path(base_dir_rel, "relatorios_pre_painel", nome_arquivo)
    if (!file.exists(arq) || is.na(file.info(arq)$size) || file.info(arq)$size <= 0) return(character(0))
    hdr <- tryCatch(names(data.table::fread(arq, nrows = 0L, encoding = "UTF-8", showProgress = FALSE)), error = function(e) character(0))
    col_coleta <- intersect(c("COLETA", chaves$coleta, "coleta"), hdr)
    col_coleta <- col_coleta[!is.na(col_coleta) & nzchar(col_coleta)]
    if (!length(col_coleta)) return(character(0))
    vals <- tryCatch(
      data.table::fread(arq, select = col_coleta[1L], encoding = "UTF-8", showProgress = FALSE)[[1L]],
      error = function(e) character(0)
    )
    vals <- unique(as.character(vals))
    sort(vals[!is.na(vals) & nzchar(vals)])
  }

  monitora_painel_coletas_diagnosticas_preferir_relatorios <- function() {
 ### Fonte única para os filtros diagnósticos do painel. Usa a triagem
 ### unificada pré-painel quando disponível e complementa ocorrências
 ### impeditivas diretamente em registros_corrig para evitar depender de
 ### relatórios auxiliares específicos.
    tri <- tryCatch(data.table::as.data.table(triagem_painel_unificada), error = function(e) data.table::data.table())
    if (!("COLETA" %in% names(tri))) tri[, COLETA := character()]
    if (!("status_vinculo" %in% names(tri))) tri[, status_vinculo := character()]
    if (!("tipo_triagem" %in% names(tri))) tri[, tipo_triagem := character()]

    coleta_vals <- function(i) {
      if (!nrow(i) || !("COLETA" %in% names(i))) return(character(0))
      z <- unique(as.character(i$COLETA))
      sort(z[!is.na(z) & nzchar(z)])
    }

    coleta_vals_mask <- function(mask) {
      if (!monitora_painel_coluna_ok(chaves$coleta, dt)) return(character(0))
      mask <- as.logical(mask)
      mask[is.na(mask)] <- FALSE
      if (length(mask) != nrow(dt)) mask <- rep(FALSE, nrow(dt))
      z <- unique(as.character(dt[[chaves$coleta]][mask]))
      sort(z[!is.na(z) & nzchar(z)])
    }

    tem_token_tipo <- function(tokens) {
      tipo_col <- chaves$tipo_forma_vida
      if (is.na(tipo_col) || !nzchar(tipo_col) || !(tipo_col %in% names(dt))) return(rep(FALSE, nrow(dt)))
      tryCatch(monitora_relatorio_exoticas_tem_token(dt[[tipo_col]], tokens), error = function(e) rep(FALSE, nrow(dt)))
    }

    tem_forma_categoria <- function(categoria) {
      cols <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(dt, categoria), error = function(e) character(0))
      cols <- unique(cols[!is.na(cols) & nzchar(cols) & cols %in% names(dt)])
      if (!length(cols)) return(rep(FALSE, nrow(dt)))
      Reduce(`|`, lapply(cols, function(cc) !monitora_correcao_vazio_vec(dt[[cc]])))
    }

    tipo_col <- chaves$tipo_forma_vida
    ponto_sem_interceptacao <- if (!is.na(tipo_col) && nzchar(tipo_col) && tipo_col %in% names(dt)) {
      coleta_vals_mask(monitora_correcao_vazio_vec(dt[[tipo_col]]))
    } else {
      character(0)
    }

    mask_ponto <- if (!is.na(tipo_col) && nzchar(tipo_col) && tipo_col %in% names(dt)) monitora_correcao_vazio_vec(dt[[tipo_col]]) else rep(FALSE, nrow(dt))
    mask_nativa <- tem_token_tipo(c("nativa", "nativas", "nativo", "nativos")) & !tem_forma_categoria("nativa")
    mask_exotica <- tem_token_tipo(c("exotica", "exoticas", "exotico", "exoticos")) & !tem_forma_categoria("exotica")
    mask_seca <- tem_token_tipo(c("seca_morta", "seca", "secas", "seco", "secos", "morta", "mortas", "morto", "mortos")) & !tem_forma_categoria("seca_morta")
    mask_solo <- tryCatch(monitora_correcao_mask_solo_nu_incompativel(dt, chaves), error = function(e) rep(FALSE, nrow(dt)))
    habito_cache <- tryCatch(monitora_correcao_mask_habito_obrigatorio_ausente(dt), error = function(e) list(mask = rep(FALSE, nrow(dt)), detalhes = data.table::data.table()))
    mask_habito <- as.logical(habito_cache$mask); mask_habito[is.na(mask_habito)] <- FALSE
    desc_cache <- tryCatch(monitora_correcao_classificar_desconhecida(dt, chaves = chaves, dicionario = NULL), error = function(e) data.table::data.table())
    idx_desc_tipo <- function(tipo) {
      if (!nrow(desc_cache)) return(integer(0))
      unique(as.integer(desc_cache[tipo_ocorrencia == tipo, linha_indice]))
    }
    exoticas_cache <- monitora_diag_exoticas_ocorrencias_detalhadas(dt)
    idx_exotica_sem_sp <- unique(as.integer(exoticas_cache[tipo_ocorrencia == "forma_vida_exotica_sem_especie", linha_indice]))
    idx_exotica_com_sp <- unique(as.integer(exoticas_cache[tipo_ocorrencia == "forma_vida_exotica_com_especie", linha_indice]))
    idx_tri_tipo <- function(tipo) {
      if (!nrow(tri)) return(integer(0))
      sub <- tri[tipo_triagem == tipo]
      li <- if ("linha_indice_global" %in% names(sub)) suppressWarnings(as.integer(sub$linha_indice_global)) else rep(NA_integer_, nrow(sub))
      if ("linha_filtro" %in% names(sub)) li[is.na(li)] <- suppressWarnings(as.integer(sub$linha_filtro[is.na(li)]))
      unique(li[!is.na(li) & li >= 1L & li <= nrow(dt)])
    }
    indices_precomputados <- list(
      ponto_sem_interceptacao = which(mask_ponto), nativa_sem_forma_vida = which(mask_nativa),
      exotica_sem_forma_vida = which(mask_exotica), seca_morta_sem_forma_vida = which(mask_seca),
      outra_forma_vida = idx_tri_tipo("outras_formas_vida"),
      forma_vida_desconhecida_invalida = idx_desc_tipo("forma_vida_desconhecida_invalida"),
      forma_vida_desconhecida = idx_desc_tipo("forma_vida_desconhecida"),
      forma_vida_exotica_sem_especie = idx_exotica_sem_sp,
      forma_vida_exotica_com_especie = idx_exotica_com_sp,
      solo_nu_com_outra_categoria = which(mask_solo), habito_obrigatorio_ausente = which(mask_habito)
    )

    resultado <- list(
      ponto_sem_interceptacao = ponto_sem_interceptacao,
      nativa_sem_forma_vida = coleta_vals_mask(
        mask_nativa
      ),
      exotica_sem_forma_vida = sort(unique(c(
        coleta_vals_mask(mask_exotica),
        coleta_vals(tri[status_vinculo == "erro_exotica_sem_forma_vida_detalhada"])
      ))),
      seca_morta_sem_forma_vida = coleta_vals_mask(
        mask_seca
      ),
      outra_forma_vida = coleta_vals(tri[tipo_triagem == "outras_formas_vida"]),
      forma_vida_desconhecida_invalida = coleta_vals_mask(seq_len(nrow(dt)) %in% idx_desc_tipo("forma_vida_desconhecida_invalida")),
      forma_vida_desconhecida = coleta_vals_mask(seq_len(nrow(dt)) %in% idx_desc_tipo("forma_vida_desconhecida")),
      forma_vida_exotica_sem_especie = coleta_vals_mask(seq_len(nrow(dt)) %in% idx_exotica_sem_sp),
      forma_vida_exotica_com_especie = coleta_vals_mask(seq_len(nrow(dt)) %in% idx_exotica_com_sp),
 ### -: mesma máscara usada em monitora_diag_rel_gerar_ocorrencias
 ### (fonte única monitora_correcao_mask_solo_nu_incompativel /
 ### monitora_correcao_mask_habito_obrigatorio_ausente ).
      solo_nu_com_outra_categoria = coleta_vals_mask(
        mask_solo
      ),
      habito_obrigatorio_ausente = coleta_vals_mask(
        mask_habito
      )
    )
    attr(resultado, "indices_precomputados") <- indices_precomputados
    attr(resultado, "habito_detalhes_precomputados") <- habito_cache$detalhes
    resultado
  }

  monitora_painel_coletas_ua_ano_duplicadas <- function() {
    if (!all(vapply(list(chaves$uc, chaves$ua, chaves$ano, chaves$coleta), monitora_painel_coluna_ok, logical(1), x = dt))) return(character(0))
    aux <- dt[, .(UC = as.character(get(chaves$uc)), UA = as.character(get(chaves$ua)), ANO = as.character(get(chaves$ano)), COLETA = as.character(get(chaves$coleta)))]
    aux <- aux[!is.na(UC) & nzchar(UC) & !is.na(UA) & nzchar(UA) & !is.na(ANO) & nzchar(ANO) & !is.na(COLETA) & nzchar(COLETA)]
    if (!nrow(aux)) return(character(0))
    grupos <- aux[, .(n_coletas = data.table::uniqueN(COLETA)), by = .(UC, UA, ANO)][n_coletas > 1L]
    if (!nrow(grupos)) return(character(0))
    vals <- unique(aux[grupos, on = .(UC, UA, ANO), COLETA])
    vals <- vals[!is.na(vals) & nzchar(vals)]
    sort(vals)
  }

  coletas_triagem_por_tipo <- monitora_painel_coletas_diagnosticas_preferir_relatorios()
  indices_diagnosticos_precomputados <- attr(coletas_triagem_por_tipo, "indices_precomputados")
  habito_detalhes_precomputados <- attr(coletas_triagem_por_tipo, "habito_detalhes_precomputados")
  coletas_triagem_por_tipo$uas_duplicadas_mesmo_ano <- monitora_painel_coletas_ua_ano_duplicadas()
  if (!is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    indices_diagnosticos_precomputados$uas_duplicadas_mesmo_ano <- which(as.character(dt[[chaves$coleta]]) %chin% coletas_triagem_por_tipo$uas_duplicadas_mesmo_ano)
  }
  coletas_triagem_por_tipo <- lapply(coletas_triagem_por_tipo, function(z) {
    z <- unique(as.character(z))
    sort(z[!is.na(z) & nzchar(z)])
  })
  monitora_correcao_console_msg(
    "Listas diagnósticas do painel preparadas: ",
    length(coletas_triagem_por_tipo$uas_duplicadas_mesmo_ano), " coleta(s) com UA duplicada no mesmo ano; ",
    length(coletas_triagem_por_tipo$ponto_sem_interceptacao), " com ponto amostral sem interceptação; ",
    length(coletas_triagem_por_tipo$nativa_sem_forma_vida), " com nativa sem forma de vida; ",
    length(coletas_triagem_por_tipo$exotica_sem_forma_vida), " com exótica sem forma de vida; ",
    length(coletas_triagem_por_tipo$seca_morta_sem_forma_vida), " com seca ou morta sem forma de vida; ",
    length(coletas_triagem_por_tipo$outra_forma_vida), " com outra forma de vida; ",
    length(coletas_triagem_por_tipo$forma_vida_desconhecida_invalida), " com forma de vida desconhecida inválida; ",
    length(coletas_triagem_por_tipo$forma_vida_desconhecida), " em revisão não impeditiva de forma de vida desconhecida; ",
    length(coletas_triagem_por_tipo$forma_vida_exotica_sem_especie), " em lista de revisão de exótica sem espécie; ",
    length(coletas_triagem_por_tipo$forma_vida_exotica_com_especie), " em lista de revisão de exótica com espécie; ",
    length(coletas_triagem_por_tipo$solo_nu_com_outra_categoria), " com solo nu incompatível com outra categoria; ",
    length(coletas_triagem_por_tipo$habito_obrigatorio_ausente), " com hábito obrigatório ausente."
  )

  tryCatch({
    base_diag_pre <- file.path(get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE), "relatorios_pre_painel", "ocorrencias_diagnosticas")
    usar_diag_leve <- isTRUE(get0("MONITORA_OPCAO_RELATORIOS_DIAGNOSTICOS_PRE_PAINEL_LEVES", ifnotfound = "S", inherits = TRUE) == "S")
    MONITORA_RELATORIOS_DIAGNOSTICOS_PRE_PAINEL <<- if (usar_diag_leve) {
      monitora_diag_rel_gerar_ocorrencias_leve(
        dt, fase = "pre_painel", base_dir = base_diag_pre,
        coletas_triagem_por_tipo = coletas_triagem_por_tipo,
        indices_precomputados = indices_diagnosticos_precomputados,
        habito_detalhes_precomputados = habito_detalhes_precomputados
      )
    } else {
      monitora_diag_rel_gerar_ocorrencias(
        dt, fase = "pre_painel", base_dir = base_diag_pre,
        coletas_triagem_por_tipo = coletas_triagem_por_tipo,
        triagem_painel_unificada = triagem_painel_unificada,
        indices_precomputados = indices_diagnosticos_precomputados,
        habito_detalhes_precomputados = habito_detalhes_precomputados,
        validar_contagens = TRUE
      )
    }
  }, error = function(e) {
    assign("MONITORA_OCORRENCIAS_DIAGNOSTICAS_INTEGRIDADE_OK", FALSE, envir = .GlobalEnv)
    arq_erro <- file.path(get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE), "relatorios_pre_painel", "ocorrencias_diagnosticas", paste0("erro_relatorios_ocorrencias_diagnosticas_pre_painel_", get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE), ".txt"))
    dir.create(dirname(arq_erro), recursive = TRUE, showWarnings = FALSE)
    writeLines(conditionMessage(e), arq_erro, useBytes = TRUE)
    monitora_correcao_console_msg("ERRO ao gerar relatórios diagnósticos [pre_painel]: ", conditionMessage(e), ". Detalhes: ", arq_erro)
    stop(
      "Execução interrompida antes do painel: a fonte de ocorrências diagnósticas pré-painel não passou pelo gate de integridade. ",
      "Nenhuma correção pode ser aplicada com índice degradado. Detalhes: ", arq_erro,
      call. = FALSE
    )
  })

 ### -: ponte diagnóstica de cobertura entre o catálogo
 ### operacional de ocorrências pré-painel acima e o contrato único. Somente
 ### auditoria (não bloqueia o painel); qualquer falha aqui é registrada, não
 ### silenciada, para não ocultar uma possível divergência de cobertura.
  tryCatch({
    monitora_ponte_pre_painel_regras_contrato_unico()
  }, error = function(e) {
    arq_erro <- file.path(get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE), "relatorios_pre_painel", paste0("erro_ponte_regras_contrato_unico_pre_painel_", get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE), ".txt"))
    dir.create(dirname(arq_erro), recursive = TRUE, showWarnings = FALSE)
    writeLines(conditionMessage(e), arq_erro, useBytes = TRUE)
    monitora_correcao_console_msg("ERRO na ponte de validacoes pre-painel (03.5V-C): ", conditionMessage(e), ". Detalhes: ", arq_erro)
  })
  if (exists("monitora_output_organizar_produtos", mode = "function")) {
    try(monitora_output_organizar_produtos(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE), contexto = "pos_relatorios_diagnosticos_pre_painel"), silent = TRUE)
  }

  monitora_painel_choices_triagem_coleta <- function(vals_base = NULL, coletas_por_tipo_base = NULL) {
 ### Monta os rótulos dos checkboxes diagnósticos com contagens restritas
 ### ao universo de COLETAS atualmente disponível nos filtros superiores.
 ### Quando vals_base é NULL, usa todas as COLETAS como estado inicial.
    if (is.null(vals_base)) vals_base <- valores_coleta
    vals_base <- unique(as.character(vals_base))
    vals_base <- vals_base[!is.na(vals_base) & nzchar(vals_base)]
    if (is.null(coletas_por_tipo_base) || !is.list(coletas_por_tipo_base)) coletas_por_tipo_base <- coletas_triagem_por_tipo
    n_tipo <- function(nm) {
      z <- coletas_por_tipo_base[[nm]]
      if (is.null(z) || !length(vals_base)) return(0L)
      length(intersect(vals_base, unique(as.character(z))))
    }
    list(
      impeditivas = stats::setNames(
        c(
          "uas_duplicadas_mesmo_ano",
          "ponto_sem_interceptacao",
          "nativa_sem_forma_vida",
          "exotica_sem_forma_vida",
          "seca_morta_sem_forma_vida",
          "outra_forma_vida",
          "forma_vida_desconhecida_invalida",
          "solo_nu_com_outra_categoria",
          "habito_obrigatorio_ausente"
        ),
        c(
          paste0("UAs duplicadas no mesmo ano (", n_tipo("uas_duplicadas_mesmo_ano"), " coletas para triagem)"),
          paste0("Ponto amostral sem interceptação (", n_tipo("ponto_sem_interceptacao"), " coletas com ocorrência)"),
          paste0("Nativa sem forma de vida (", n_tipo("nativa_sem_forma_vida"), " coletas com ocorrência)"),
          paste0("Exótica sem forma de vida (", n_tipo("exotica_sem_forma_vida"), " coletas com ocorrência)"),
          paste0("Seca ou morta sem forma de vida (", n_tipo("seca_morta_sem_forma_vida"), " coletas com ocorrência)"),
          paste0("Outra forma de vida (", n_tipo("outra_forma_vida"), " coletas com ocorrência)"),
          paste0("Forma de vida desconhecida inválida (", n_tipo("forma_vida_desconhecida_invalida"), " coletas com ocorrência)"),
          paste0("Solo nu com outra categoria (", n_tipo("solo_nu_com_outra_categoria"), " coletas com ocorrência)"),
          paste0("Hábito obrigatório ausente (", n_tipo("habito_obrigatorio_ausente"), " coletas com ocorrência)")
        )
      ),
      outras = stats::setNames(
        c(
          "forma_vida_desconhecida",
          "forma_vida_exotica_sem_especie",
          "forma_vida_exotica_com_especie"
        ),
        c(
          paste0("Forma de vida desconhecida (", n_tipo("forma_vida_desconhecida"), " coletas com ocorrência)"),
          paste0("Revisão: forma de vida exótica sem espécie (", n_tipo("forma_vida_exotica_sem_especie"), " coletas com ocorrência)"),
          paste0("Revisão: forma de vida exótica com espécie (", n_tipo("forma_vida_exotica_com_especie"), " coletas com ocorrência)")
        )
      )
    )
  }

  choices_triagem_coleta <- monitora_painel_choices_triagem_coleta(valores_coleta)

  monitora_painel_ocorrencias_idx_leve <- function(triagem, coletas_por_tipo, usar_relatorio_pre = TRUE, dt_estado = NULL) {
    out <- list()
    primeiro_preenchido <- function(...) {
      candidatos <- list(...)
      if (!length(candidatos)) return(character(0))
      ans <- rep("", length(candidatos[[1L]]))
      for (z in candidatos) {
        z <- as.character(z); z[is.na(z)] <- ""; z <- trimws(z)
        preencher <- !nzchar(ans) & nzchar(z)
        ans[preencher] <- z[preencher]
      }
      ans
    }
    tri <- tryCatch(data.table::as.data.table(triagem), error = function(e) data.table::data.table())
    if (nrow(tri)) {
      for (cc in c("tipo_triagem", "tipo_ocorrencia_painel", "status_vinculo", "token_detectado", "campo_forma_vida", "categoria_forma_vida", "COLETA", "linha_indice_global", "linha_filtro", "UC", "EA", "UA", "CICLO", "CAMPANHA", "ANO")) {
        if (!(cc %in% names(tri))) tri[, (cc) := NA_character_]
      }
      map_tipo <- data.table::data.table(
        tipo_ocorrencia = c("outra_forma_vida", "forma_vida_desconhecida_invalida", "forma_vida_desconhecida", "forma_vida_exotica_sem_especie", "forma_vida_exotica_com_especie", "exotica_sem_forma_vida"),
        pred_col = c("tipo_triagem", "tipo_ocorrencia_painel", "tipo_ocorrencia_painel", "status_vinculo", "status_vinculo", "status_vinculo"),
        pred_val = c("outras_formas_vida", "forma_vida_desconhecida_invalida", "forma_vida_desconhecida", "exotica_com_forma_sem_sp_vinculada", "exotica_com_forma_e_sp_vinculada", "erro_exotica_sem_forma_vida_detalhada")
      )
      for (ii in seq_len(nrow(map_tipo))) {
        cc <- map_tipo$pred_col[ii]
        vv <- map_tipo$pred_val[ii]
        sub <- tri[as.character(get(cc)) == vv]
        if (!nrow(sub)) next
        linha_idx <- suppressWarnings(as.integer(sub$linha_indice_global))
        linha_idx[is.na(linha_idx)] <- suppressWarnings(as.integer(sub$linha_filtro[is.na(linha_idx)]))
        out[[length(out) + 1L]] <- data.table::data.table(
          tipo_ocorrencia = map_tipo$tipo_ocorrencia[ii],
          COLETA = as.character(sub$COLETA),
          linha_indice = linha_idx,
          UC = as.character(sub$UC),
          EA = as.character(sub$EA),
          UA = as.character(sub$UA),
          CICLO = as.character(sub$CICLO),
          CAMPANHA = as.character(sub$CAMPANHA),
          ANO = as.character(sub$ANO),
          monitora_row_id = NA_character_,
          ocorrencia_token = as.character(sub$token_detectado),
          ocorrencia_atributo = as.character(sub$campo_forma_vida),
          ocorrencia_categoria = as.character(sub$categoria_forma_vida),
          ocorrencia_status = as.character(sub$status_vinculo),
          ocorrencia_detalhe = paste(
            monitora_correcao_na_para_vazio(sub$token_detectado),
            monitora_correcao_na_para_vazio(sub$campo_forma_vida),
            monitora_correcao_na_para_vazio(sub$status_vinculo),
            sep = "|"
          ),
          fonte_indice = "triagem_painel_unificada"
        )
      }
    }
 ### o relatório detalhado é a fonte única das ocorrências que já
 ### possuem linha física identificada (inclusive N pares de hábito na mesma
 ### linha). Painel e modal passam a consumir exatamente o mesmo universo.
    rel_pre <- get0("MONITORA_RELATORIOS_DIAGNOSTICOS_PRE_PAINEL", ifnotfound = NULL, inherits = TRUE)
    rel_regs <- if (is.list(rel_pre) && data.table::is.data.table(rel_pre$registros)) data.table::as.data.table(rel_pre$registros) else data.table::data.table()
    if (!isTRUE(usar_relatorio_pre)) {
 ### No checkpoint integral, não reutilizar ocorrências pré-painel. Os
 ### pares detalhados de hábito são reconstruídos pela mesma fonte única
 ### usada pelo relatório; os demais tipos vêm da triagem/máscaras atuais.
      estado <- tryCatch(data.table::as.data.table(dt_estado), error = function(e) data.table::data.table())
      rel_regs <- data.table::data.table()
      det_hab <- tryCatch(monitora_correcao_ocorrencias_habito_detalhadas(estado), error = function(e) data.table::data.table())
      if (nrow(det_hab)) {
        ch_estado <- monitora_correcao_colunas_chave(estado)
        pegar_estado <- function(col) {
          if (is.null(col) || is.na(col) || !(col %in% names(estado))) return(rep(NA_character_, nrow(det_hab)))
          as.character(estado[[col]][det_hab$linha_indice])
        }
        rel_regs <- det_hab[, .(
          tipo_ocorrencia = "habito_obrigatorio_ausente", linha_indice, monitora_row_id,
          atributo_habito_obrigatorio, categoria_superior, forma_de_vida_detectada
        )]
        rel_regs[, `:=`(
          COLETA = pegar_estado(ch_estado$coleta), UC = pegar_estado(ch_estado$uc),
          EA = pegar_estado(ch_estado$ea), UA = pegar_estado(ch_estado$ua),
          CICLO = pegar_estado(ch_estado$ciclo), CAMPANHA = pegar_estado(ch_estado$campanha),
          ANO = pegar_estado(ch_estado$ano)
        )]
      }
    }
    if (nrow(rel_regs) && all(c("tipo_ocorrencia", "COLETA", "linha_indice") %in% names(rel_regs))) {
      for (cc in c("UC", "EA", "UA", "CICLO", "CAMPANHA", "ANO", "monitora_row_id", "atributo_habito_obrigatorio", "atributo_canonico_habito", "forma_de_vida_detectada", "token_problematico", "atributo_forma_vida", "atributo_lista", "categoria_superior", "categoria", "atributo_problema", "status_contrato")) if (!(cc %in% names(rel_regs))) rel_regs[, (cc) := NA_character_]
      detalhe_rel <- rep("", nrow(rel_regs))
      for (cc_det in c("atributo_habito_obrigatorio", "forma_de_vida_detectada", "atributo_forma_vida", "categoria", "atributo_problema", "status_contrato")) {
        z_det <- monitora_correcao_na_para_vazio(rel_regs[[cc_det]])
        detalhe_rel <- paste(detalhe_rel, z_det, sep = "|")
      }
      detalhe_rel <- sub("^\\|+", "", detalhe_rel)
      out[[length(out) + 1L]] <- rel_regs[, .(
        tipo_ocorrencia = as.character(tipo_ocorrencia), COLETA = as.character(COLETA),
        linha_indice = suppressWarnings(as.integer(linha_indice)), monitora_row_id = as.character(monitora_row_id),
        ocorrencia_token = primeiro_preenchido(forma_de_vida_detectada, token_problematico),
        ocorrencia_atributo = primeiro_preenchido(atributo_habito_obrigatorio, atributo_canonico_habito, atributo_problema, atributo_forma_vida, atributo_lista),
        ocorrencia_categoria = primeiro_preenchido(categoria_superior, categoria),
        ocorrencia_status = as.character(status_contrato),
        ocorrencia_detalhe = detalhe_rel,
        UC = as.character(UC), EA = as.character(EA), UA = as.character(UA), CICLO = as.character(CICLO),
        CAMPANHA = as.character(CAMPANHA), ANO = as.character(ANO), fonte_indice = "relatorio_diagnostico_unico"
      )]
    }
    if (is.list(coletas_por_tipo) && length(coletas_por_tipo)) {
      tipos_com_linha <- unique(vapply(out, function(x) as.character(x$tipo_ocorrencia[1L]), character(1)))
      for (nm in setdiff(names(coletas_por_tipo), tipos_com_linha)) {
        vals <- unique(as.character(coletas_por_tipo[[nm]]))
        vals <- vals[!is.na(vals) & nzchar(vals)]
        if (!length(vals)) next
        out[[length(out) + 1L]] <- data.table::data.table(
          tipo_ocorrencia = nm,
          COLETA = vals,
          linha_indice = NA_integer_,
          UC = NA_character_,
          EA = NA_character_,
          UA = NA_character_,
          CICLO = NA_character_,
          CAMPANHA = NA_character_,
          ANO = NA_character_,
          fonte_indice = "coletas_triagem_por_tipo"
        )
      }
    }
    idx <- if (length(out)) data.table::rbindlist(out, fill = TRUE, use.names = TRUE) else data.table::data.table(
      tipo_ocorrencia = character(), COLETA = character(), linha_indice = integer(),
      UC = character(), EA = character(), UA = character(), CICLO = character(), CAMPANHA = character(),
      ANO = character(), fonte_indice = character()
    )
    if (nrow(idx)) {
      for (cc in c("monitora_row_id", "ocorrencia_token", "ocorrencia_atributo", "ocorrencia_categoria", "ocorrencia_status", "ocorrencia_detalhe")) {
        if (!(cc %in% names(idx))) idx[, (cc) := NA_character_]
      }
 ### identidade física estável é transportada separadamente do
 ### texto de exibição. Isso impede que uma mudança em ocorrencia_detalhe
 ### quebre consumidores como SANHAB ou colapse tokens irmãos na mesma linha.
      estado_ids <- tryCatch(data.table::as.data.table(if (!is.null(dt_estado)) dt_estado else dt), error = function(e) data.table::data.table())
      if (nrow(estado_ids) && MONITORA_COL_ROW_ID %in% names(estado_ids)) {
        li_idx <- suppressWarnings(as.integer(idx$linha_indice))
        preencher_id <- (is.na(idx$monitora_row_id) | !nzchar(trimws(as.character(idx$monitora_row_id)))) &
          !is.na(li_idx) & li_idx >= 1L & li_idx <= nrow(estado_ids)
        if (any(preencher_id)) data.table::set(idx, i = which(preencher_id), j = "monitora_row_id", value = as.character(estado_ids[[MONITORA_COL_ROW_ID]][li_idx[preencher_id]]))
      }
      idx[, ocorrencia_alvo_estavel := data.table::fifelse(
        !is.na(monitora_row_id) & nzchar(trimws(as.character(monitora_row_id))),
        as.character(monitora_row_id), paste0("LINHA::", as.character(linha_indice))
      )]
      tipos_relatorio <- unique(as.character(idx[fonte_indice == "relatorio_diagnostico_unico", tipo_ocorrencia]))
      if (length(tipos_relatorio)) idx <- idx[!(tipo_ocorrencia %in% tipos_relatorio & fonte_indice != "relatorio_diagnostico_unico")]
      idx <- unique(idx, by = c("tipo_ocorrencia", "COLETA", "ocorrencia_alvo_estavel", "ocorrencia_categoria", "ocorrencia_token", "ocorrencia_atributo", "ocorrencia_status"))
      data.table::setorder(idx, tipo_ocorrencia, COLETA, linha_indice, na.last = TRUE)
    }
    idx[]
  }

  monitora_painel_ocorrencias_resumo_leve <- function(idx) {
    idx <- data.table::as.data.table(idx)
    if (!nrow(idx)) {
      return(data.table::data.table(tipo_ocorrencia = character(), n_ocorrencias = integer(), n_linhas = integer(), n_coletas = integer()))
    }
    idx[, .(
      n_ocorrencias = .N,
      n_linhas = data.table::uniqueN(linha_indice[!is.na(linha_indice)]),
      n_coletas = data.table::uniqueN(COLETA[!is.na(COLETA) & nzchar(COLETA)])
    ), by = tipo_ocorrencia][order(tipo_ocorrencia)][]
  }

  monitora_painel_resumo_impeditivas_do_indice <- function(resumo_idx) {
    tipos <- c(
      "uas_duplicadas_mesmo_ano", "ponto_sem_interceptacao",
      "nativa_sem_forma_vida", "exotica_sem_forma_vida",
      "seca_morta_sem_forma_vida", "outra_forma_vida",
      "forma_vida_desconhecida_invalida", "habito_obrigatorio_ausente"
    )
    rotulos <- c(
      "UAs duplicadas no mesmo ano", "Ponto amostral sem interceptação",
      "Nativa sem forma de vida", "Exótica sem forma de vida",
      "Seca ou morta sem forma de vida", "Outra forma de vida",
      "Forma de vida desconhecida inválida", "Hábito obrigatório ausente"
    )
    out <- data.table::data.table(tipo = tipos, ocorrencia = rotulos, n_linhas = 0L, n_coletas = 0L)
    resumo_idx <- data.table::as.data.table(resumo_idx)
    if (!nrow(resumo_idx) || !("tipo_ocorrencia" %in% names(resumo_idx))) return(out)
    for (cc in c("n_linhas", "n_coletas")) if (!(cc %in% names(resumo_idx))) data.table::set(resumo_idx, j = cc, value = rep(0L, nrow(resumo_idx)))
    valores <- resumo_idx[tipo_ocorrencia %in% tipos, .(
      n_linhas = sum(as.integer(n_linhas), na.rm = TRUE),
      n_coletas = max(as.integer(n_coletas), na.rm = TRUE)
    ), by = tipo_ocorrencia]
    if (nrow(valores)) {
      pos <- match(valores$tipo_ocorrencia, out$tipo)
      ok <- !is.na(pos)
      if (any(ok)) {
        out$n_linhas[pos[ok]] <- valores$n_linhas[ok]
        out$n_coletas[pos[ok]] <- valores$n_coletas[ok]
      }
    }
    out[]
  }

