  painel_estado$modal_impeditivas_salvar_ativo <- FALSE

  monitora_painel_notificar <- function(ui, type = "message", duration = 8, ...) {
 ### Notificações são auxiliares de interface e nunca devem derrubar uma
 ### operação já validada. Usa chamada protegida para evitar erros como
 ### variáveis de mensagem ausentes ou sessão Shiny em encerramento.
    tryCatch({
      notify_fun <- get("showNotification", envir = asNamespace("shiny"), inherits = FALSE)
      notify_fun(ui, type = type, duration = duration, ...)
    }, error = function(e) {
      try(monitora_correcao_console_msg("Falha não crítica ao exibir notificação no painel: ", conditionMessage(e)), silent = TRUE)
      invisible(NULL)
    })
  }

  monitora_painel_iniciar_botao <- function(id_botao, descricao = id_botao) {
    id_botao <- as.character(id_botao)[1L]
    if (is.na(id_botao) || !nzchar(id_botao)) id_botao <- "botao_sem_id"
    if (isTRUE(painel_estado$botoes_processando[[id_botao]])) {
      monitora_painel_notificar(
        paste0("Ação já em processamento: ", descricao, ". Aguarde a conclusão antes de clicar novamente."),
        type = "warning", duration = 8
      )
      try(monitora_correcao_console_msg("Clique repetido ignorado enquanto o botão ainda estava em processamento: ", id_botao), silent = TRUE)
      return(FALSE)
    }
    ultima_conclusao <- painel_estado$botoes_ultima_conclusao[[id_botao]]
    if (!is.null(ultima_conclusao)) {
      desde_conclusao <- suppressWarnings(as.numeric(difftime(Sys.time(), ultima_conclusao, units = "secs")))
      if (is.finite(desde_conclusao) && desde_conclusao >= 0 && desde_conclusao < 1.25) {
        monitora_painel_notificar(
          paste0("Clique repetido ignorado: ", descricao, "."),
          type = "warning", duration = 5
        )
        try(monitora_correcao_console_msg("Evento repetido ignorado pela proteção idempotente: ", id_botao), silent = TRUE)
        return(FALSE)
      }
    }
    painel_estado$botoes_processando[[id_botao]] <- TRUE
    monitora_painel_notificar(
      paste0("Processando: ", descricao, ". Aguarde a conclusão antes de clicar novamente."),
      type = "message", duration = 4
    )
    try(monitora_correcao_console_msg("Iniciando ação no painel: ", descricao), silent = TRUE)
    TRUE
  }

  monitora_painel_liberar_botao <- function(id_botao) {
    id_botao <- as.character(id_botao)[1L]
    if (is.na(id_botao) || !nzchar(id_botao)) id_botao <- "botao_sem_id"
    painel_estado$botoes_processando[[id_botao]] <- FALSE
    painel_estado$botoes_ultima_conclusao[[id_botao]] <- Sys.time()
    invisible(TRUE)
  }


  monitora_painel_registrar_rejeicao <- function(etapa, mensagem, atributo = NA_character_, acao = NA_character_, detalhe = NA_character_) {
    linha <- data.table::data.table(
      data_hora = format(Sys.time(), "%Y-%m-%d %H:%M:%S"),
      etapa = as.character(etapa)[1L],
      atributo = as.character(atributo)[1L],
      acao = as.character(acao)[1L],
      mensagem = as.character(mensagem)[1L],
      detalhe = as.character(detalhe)[1L]
    )
    rv$auditoria_rejeicoes <- data.table::rbindlist(list(data.table::as.data.table(rv$auditoria_rejeicoes), linha), fill = TRUE, use.names = TRUE)
    arq_rej <- file.path(MONITORA_CORRECOES_DIR, "auditoria_painel_tentativas_rejeitadas_ultima_execucao.csv")
    try({ dir.create(dirname(arq_rej), recursive = TRUE, showWarnings = FALSE); monitora_fwrite(rv$auditoria_rejeicoes, arq_rej, na = "") }, silent = TRUE)
    try(monitora_correcao_console_msg("Tentativa rejeitada no painel [", etapa, "]: ", mensagem), silent = TRUE)
    invisible(linha)
  }

  monitora_painel_bloquear_operacao <- function(mensagem, etapa = "operacao_painel", atributo = NA_character_, acao = NA_character_, detalhe = NA_character_, duration = 12) {
    monitora_painel_notificar(mensagem, type = "error", duration = duration)
    monitora_painel_registrar_rejeicao(etapa = etapa, mensagem = mensagem, atributo = atributo, acao = acao, detalhe = detalhe)
    invisible(FALSE)
  }

  monitora_painel_id_operacao_semantica <- function(correcoes) {
    correcoes <- data.table::as.data.table(correcoes)
    if (!nrow(correcoes)) return(character(0))
    if (!"id_correcao" %in% names(correcoes)) return(paste0("__linha_", seq_len(nrow(correcoes))))
    ids <- as.character(correcoes$id_correcao)
    ids[is.na(ids) | !nzchar(trimws(ids))] <- paste0("__linha_", which(is.na(ids) | !nzchar(trimws(ids))))
    ids
  }

  monitora_painel_n_operacoes_semanticas <- function(correcoes = rv$correcoes) {
    correcoes <- data.table::as.data.table(correcoes)
    if (!nrow(correcoes)) return(0L)
    length(unique(monitora_painel_id_operacao_semantica(correcoes)))
  }

  monitora_painel_resumir_operacoes_semanticas <- function(correcoes = rv$correcoes) {
    correcoes <- data.table::as.data.table(correcoes)
    if (!nrow(correcoes)) return(data.table::data.table())
    ids <- monitora_painel_id_operacao_semantica(correcoes)
    x <- data.table::copy(correcoes)
    x[, .id_operacao_semantica := ids]
    for (cc in c("id_correcao", "tipo_correcao", "acao", "coleta", "categoria_origem", "categoria_destino", "token_pai", "token_removido", "valor_original_esperado", "valor_novo", "forma_valida_escolhida", "habito_escolhido", "escopo_aplicacao", "atributo_coluna_registros_corrig", "motivo", "n_linhas_alvo", "n_linhas_esperado", "n_itens_auditaveis")) {
      if (!(cc %in% names(x))) data.table::set(x, j = cc, value = NA_character_)
    }
    colapsar <- function(v, max_valores = 8L) {
      v <- unique(trimws(as.character(v)))
      v <- v[!is.na(v) & nzchar(v)]
      if (!length(v)) return(NA_character_)
      paste0(paste(utils::head(v, max_valores), collapse = "; "), if (length(v) > max_valores) " ..." else "")
    }
    expandir_serializados <- function(v) {
      v <- trimws(as.character(v))
      v <- v[!is.na(v) & nzchar(v)]
      if (!length(v)) return(character())
      out <- unique(unlist(lapply(v, function(z) {
        tryCatch(monitora_correcao_parse_lista_serializada(z), error = function(e) z)
      }), use.names = FALSE))
      out <- unique(trimws(as.character(out)))
      out <- out[!is.na(out) & nzchar(out)]
      nums <- suppressWarnings(as.numeric(out))
      if (length(out) && all(!is.na(nums))) out <- out[order(nums)] else out <- sort(out)
      out
    }
    x[, .eh_sanhab := grepl("^SANHAB", toupper(trimws(as.character(id_correcao)))) |
      tolower(trimws(as.character(tipo_correcao))) == "sanitizacao_habito_obrigatorio_ausente"]
    x[, .(
      id_correcao = colapsar(id_correcao, 1L),
      tipo_correcao = colapsar(monitora_correcao_tipo_rotulo_ptbr(tipo_correcao), 2L),
      acao = colapsar(monitora_correcao_acao_rotulo_ptbr(acao), 2L),
      coleta = colapsar(expandir_serializados(coleta), 10L),
      categoria_origem = colapsar(categoria_origem, 2L),
      categoria_destino = colapsar(categoria_destino, 2L),
      movimento = {
        if (any(.eh_sanhab, na.rm = TRUE)) NA_character_ else {
          ori <- colapsar(categoria_origem, 2L); des <- colapsar(categoria_destino, 2L)
          if (!is.na(ori) || !is.na(des)) paste0(ifelse(is.na(ori), "—", ori), " → ", ifelse(is.na(des), "—", des)) else NA_character_
        }
      },
      tokens_removidos = colapsar(c(
        token_removido,
 ### Em movimentos, valor_original_esperado é fotografia da célula e
 ### não deve ser exibido nem tratado como token removido.
        valor_original_esperado[tolower(trimws(as.character(acao))) %in% c("remove_token", "remover_token", "replace_token", "substituir_token")]
      ), 8L),
      tokens_adicionados = colapsar(c(
        valor_novo[tolower(trimws(as.character(acao))) %in% c("append_token", "adicionar_token", "replace_token", "substituir_token", "mover_forma_vida", "mover_forma_vida_lote", "substituir_desconhecida")],
        forma_valida_escolhida
      ), 8L),
      habito = colapsar(habito_escolhido, 3L),
      escopo = colapsar(escopo_aplicacao, 3L),
      atributo = colapsar(atributo_coluna_registros_corrig, 3L),
      n_coletas = length(expandir_serializados(coleta)),
      itens_auditaveis = {
        n_it <- suppressWarnings(as.integer(n_itens_auditaveis))
        if (any(!is.na(n_it) & n_it > 0L)) sum(n_it[!is.na(n_it) & n_it > 0L]) else .N
      },
      linhas_alvo = suppressWarnings(sum(as.integer(n_linhas_alvo), na.rm = TRUE)),
      motivo = colapsar(motivo, 1L)
    ), by = .id_operacao_semantica][order(.id_operacao_semantica)][]
  }

  monitora_painel_dt_options <- function(scroll_x = TRUE) {
