        "    if (cell) {",
        "      var txt = $(cell).text();",
        "      if (txt && txt.length > 30) { $(cell).attr('title', txt); }",
        "      else { $(cell).removeAttr('title'); }",
        "    }",
        "  });",
        "}"
      )
    )
  }

