  server <- function(input, output, session) {
    dicionario_painel <- if (!is.null(meta_xls) && !is.null(meta_xls$campos)) meta_xls$campos else NULL

    monitora_painel_atualizar_habito_select <- function(input_id, forma, selected = "") {
      forma <- monitora_painel_canonizar_forma_habito(forma)
      if (monitora_painel_forma_exige_habito(forma)) {
 ### tokens vêm do XLSForm embutido via
 ### monitora_painel_habito_choices_contratuais , não mais de uma
 ### constante hard-coded.
        choices_contratuais <- c("(não informado)" = "", monitora_painel_habito_choices_contratuais(forma))
        selected <- monitora_painel_valor(selected)
        if (!selected %in% unname(choices_contratuais)) selected <- ""
        shiny::updateSelectInput(session, input_id, choices = choices_contratuais, selected = selected)
      } else {
        shiny::updateSelectInput(session, input_id, choices = MONITORA_TRIAGEM_HABITO_NAO_APLICA_CHOICES, selected = "")
      }
      invisible(NULL)
    }

    monitora_painel_limpar_apos_correcao <- function() {
 ### Reinicia filtros de busca e campos de justificativa após uma correção simples/lote
 ### ter sido adicionada à sessão. Mantém apenas o responsável e a lista de
 ### correções pendentes, para reduzir o risco de reaplicar o mesmo filtro por engano.
      for (id in c("filtro_uc", "filtro_ea", "filtro_ano", "filtro_ciclo", "filtro_campanha", "filtro_ua")) {
        try(shiny::updateSelectizeInput(session, id, selected = character(0)), silent = TRUE)
      }
      try(shiny::updateRadioButtons(session, "escopo_coletas", selected = "coleta_individual"), silent = TRUE)
      try(shiny::updateSelectizeInput(session, "coletas_lote", selected = character(0)), silent = TRUE)
      try(shiny::updateSelectInput(session, "ponto", selected = ""), silent = TRUE)
      try(shiny::updateSelectizeInput(session, "atributo", selected = ""), silent = TRUE)
      try(shiny::updateTextAreaInput(session, "valor_original", value = ""), silent = TRUE)
      try(shiny::updateTextAreaInput(session, "valor_novo", value = ""), silent = TRUE)
      try(shiny::updateTextInput(session, "valor_novo", value = ""), silent = TRUE)
      try(shiny::updateSelectizeInput(session, "valor_novo", selected = character(0)), silent = TRUE)
 ### updateDateInput/updateNumericInput removidos —
 ### "valor_novo" nunca mais é dateInput/numericInput (a regra-H2D trocou
 ### para textInput em todos os tipos); manter essas chamadas era código
 ### morto que arriscava reintroduzir valor por engano em qualquer mudança
 ### futura de binding do cliente Shiny.
      try(shiny::updateTextAreaInput(session, "motivo", value = ""), silent = TRUE)
      try(shiny::updateRadioButtons(session, "escopo", selected = "coleta_inteira"), silent = TRUE)
      try(shiny::updateSelectInput(session, "acao", choices = c("(selecione)" = ""), selected = ""), silent = TRUE)
      for (id in c("mv_forma", "mv_origem", "mv_destino", "mv_forma_destino", "mv_habito", "mv_lote_origem", "mv_lote_habito_padrao", "mv_lote_destino", "mv_lote_forma_destino", "mv_lote_habito_destino", "triagem_destino_desconhecida", "triagem_habito")) {
        try(shiny::updateSelectInput(session, id, selected = ""), silent = TRUE)
      }
      try(shiny::updateSelectizeInput(session, "mv_lote_formas", selected = character(0)), silent = TRUE)
      try(shiny::updateSelectizeInput(session, "triagem_forma_valida", selected = ""), silent = TRUE)
      try(shiny::updateNumericInput(session, "n_esperado", value = 101), silent = TRUE)
      try(shiny::updateCheckboxInput(session, "confirmar_abrangencia", value = FALSE), silent = TRUE)
      try(monitora_painel_atualizar_habito_select("mv_habito", input$mv_forma_destino), silent = TRUE)
      try(monitora_painel_atualizar_habito_select("triagem_habito", input$triagem_forma_valida), silent = TRUE)
      rv$ponto_alvo <- ""
    }

    monitora_painel_usar_lote_coletas <- function() {
 ### Fonte única de escopo: a operação em lote usa exatamente as
 ### COLETAS listadas em input$coletas_lote quando escopo_coletas ==
 ### "coletas_do_lote". Mantém fallback defensivo para sessões que
 ### ainda exponham input$usar_lote_multicoletas.
      identical(monitora_painel_valor(input$escopo_coletas), "coletas_do_lote") || isTRUE(input[["usar_lote_multicoletas"]])
    }

 ### "Adicionar movimento" só fica
 ### habilitado quando forma/origem/destino (e, no lote, forma de destino)
 ### estiverem explicitamente preenchidos — sem isso, o clique já era
 ### bloqueado com notificação de erro pelo próprio observeEvent, mas o
 ### botão continuava clicável; agora fica visualmente desabilitado
 ### (atributo HTML disabled via htmltools, sem depender do pacote shinyjs,
 ### que não é dependência deste projeto).
    output$ui_add_mv_botao <- shiny::renderUI({
      preenchido <- nzchar(monitora_painel_valor(input$mv_forma)) &&
        nzchar(monitora_painel_valor(input$mv_origem)) &&
        nzchar(monitora_painel_valor(input$mv_destino)) &&
        nzchar(monitora_painel_valor(input$mv_forma_destino)) &&
        nzchar(monitora_painel_valor(input$escopo))
      btn <- shiny::actionButton("add_mv", "Adicionar movimento de forma de vida")
      if (!isTRUE(preenchido)) btn <- htmltools::tagAppendAttributes(btn, disabled = NA)
      btn
    })

    output$ui_add_mv_lote_botao <- shiny::renderUI({
      preenchido <- nzchar(monitora_painel_valor(input$mv_lote_origem)) &&
        nzchar(monitora_painel_valor(input$mv_lote_destino)) &&
        nzchar(monitora_painel_valor(input$mv_lote_forma_destino)) &&
        length(input$mv_lote_formas) > 0L
      btn <- shiny::actionButton("add_mv_lote", "Adicionar movimento em lote de formas de vida", class = "btn-warning")
      if (!isTRUE(preenchido)) btn <- htmltools::tagAppendAttributes(btn, disabled = NA)
      btn
    })

    output$ui_valor_novo_controle <- shiny::renderUI({
      atributo <- monitora_painel_valor(input$atributo)
      acao_norm <- monitora_correcao_acao_normalizar(input$acao)
      if (!nzchar(atributo)) return(NULL)
      info <- tryCatch(monitora_painel_info_contrato_atributo(atributo), error = function(e) list(tipo = "text", list_name = NA_character_, escolhas = character(0)))
      tipo <- as.character(info$tipo)[1L]
      if (is.na(tipo) || !nzchar(tipo)) tipo <- "text"
      if (acao_norm %in% c("clear", "recalcular_tipo_forma_vida")) {
        return(shiny::div(class = "alert alert-warning", "Esta ação não usa valor novo. O valor será limpo ou recalculado pelo contrato do script."))
      }
      if (tipo == "select_one") {
        choices <- monitora_painel_choices_valor_atributo(atributo, acao_norm, incluir_observados = FALSE)
        if (!length(choices)) return(shiny::div(class = "alert alert-danger", "Domínio XLSForm indisponível para este atributo; edição bloqueada até o dicionário ser saneado."))
        return(shiny::selectizeInput("valor_novo", "Valor novo", choices = choices, selected = character(0), multiple = FALSE, options = list(placeholder = "Escolha um valor do domínio XLSForm")))
      }
      if (tipo == "select_multiple") {
        incluir_obs <- acao_norm %in% c("remove_token", "remover_token")
        choices <- monitora_painel_choices_valor_atributo(atributo, acao_norm, incluir_observados = incluir_obs)
        if (!length(choices)) return(shiny::div(class = "alert alert-danger", "Domínio XLSForm indisponível para esta lista de tokens; edição bloqueada até o dicionário ser saneado."))
        lab <- if (acao_norm %in% c("append_token", "adicionar_token")) "Token(s) a adicionar" else if (acao_norm %in% c("remove_token", "remover_token")) "Token(s) a remover" else "Token novo"
        mult <- acao_norm %in% c("append_token", "adicionar_token", "remove_token", "remover_token")
        return(shiny::selectizeInput("valor_novo", lab, choices = choices, selected = character(0), multiple = mult, options = list(placeholder = "Escolha token(s); não digite valor total do campo", plugins = if (mult) list("remove_button") else NULL)))
      }
 ### dateInput(value = NULL) do shiny cai para
 ### Sys.Date (mostra a data de hoje, não vazio) e numericInput(value = NA)
 ### renderiza literalmente o texto "NA" no campo — ambos violam "Valor novo
 ### deve vir sempre vazio". Trocados por textInput vazio com placeholder de
 ### formato; a validação de formato (monitora_correcao_validar_formato_valor,
 ### inalterada) continua exigindo o padrão correto na aplicação da correção.
      if (tipo == "date") return(shiny::textInput("valor_novo", "Valor novo", value = "", placeholder = "YYYY-MM-DD"))
      if (tipo == "integer") return(shiny::textInput("valor_novo", "Valor novo inteiro", value = "", placeholder = "Número inteiro, ex.: 101"))
      if (tipo == "decimal") return(shiny::textInput("valor_novo", "Valor novo decimal", value = "", placeholder = "Número decimal com ponto, ex.: 3.33"))
      if (tipo == "time") return(shiny::textInput("valor_novo", "Valor novo de hora", value = "", placeholder = "HH:MM:SS.000-03:00"))
      if (tipo == "datetime") return(shiny::textInput("valor_novo", "Valor novo de data/hora", value = "", placeholder = "YYYY-MM-DDTHH:MM:SS-03:00"))
      if (tipo == "geopoint") return(shiny::textInput("valor_novo", "Valor novo de coordenada", value = "", placeholder = "lat lon [alt acc]"))
      shiny::textAreaInput("valor_novo", "Valor novo", value = "", rows = 2)
    })

