    shiny::observeEvent(input$excluir_correcoes_pendentes, {
      if (!monitora_painel_iniciar_botao("excluir_correcoes_pendentes", "excluir operações pendentes")) return(NULL)
      on.exit(monitora_painel_liberar_botao("excluir_correcoes_pendentes"), add = TRUE)
      sel <- input$correcoes_rows_selected
      n_ops <- tryCatch(monitora_painel_n_operacoes_semanticas(rv$correcoes), error = function(e) 0L)
      if (length(sel) == 0L || n_ops == 0L) {
        monitora_painel_notificar("Selecione uma ou mais operações pendentes para excluir.", type = "warning", duration = 6)
        return(NULL)
      }
      sel <- unique(as.integer(sel))
      ids_vis <- as.character(rv$correcoes_vis_ids)
      sel <- sel[!is.na(sel) & sel >= 1L & sel <= length(ids_vis)]
      if (!length(sel)) return(NULL)
      ids_remover <- unique(ids_vis[sel])
      solicitadas <- data.table::as.data.table(rv$correcoes_solicitadas)
      ids_sol <- monitora_painel_id_operacao_semantica(solicitadas)
      solicitadas <- solicitadas[!(ids_sol %in% ids_remover)]
      rec_pos_exclusao <- monitora_painel_reconciliar_fila_semantica(solicitadas, gravar = TRUE, bloquear = TRUE)
      if (rec_pos_exclusao$n_conflitos > 0L) return(NULL)
      rv$correcoes_solicitadas <- data.table::copy(solicitadas)
      hist_exc <- data.table::as.data.table(rv$correcoes_historico_intencoes)
      if (nrow(hist_exc)) {
        ids_hist_exc <- monitora_painel_id_operacao_semantica(hist_exc)
        hist_exc[ids_hist_exc %in% ids_remover, `:=`(status_intencao_painel = "removida_pelo_usuario_antes_salvar", data_hora_status_intencao = format(Sys.time(), "%Y-%m-%d %H:%M:%S"))]
        rv$correcoes_historico_intencoes <- data.table::copy(hist_exc)
      }
      rv$correcoes <- data.table::copy(rec_pos_exclusao$corr)
      rv$auditoria_conciliacao_semantica <- data.table::copy(rec_pos_exclusao$auditoria)
      rv$preview_dirty <- TRUE
      rv$ocorrencias_idx <- data.table::copy(ocorrencias_idx_base_painel)
      rv$ocorrencias_resumo <- data.table::copy(ocorrencias_resumo_base_painel)
      monitora_painel_notificar(paste0(length(ids_remover), " operação(ões) semântica(s) pendente(s) excluída(s)."), type = "message", duration = 6)
    })

    shiny::observeEvent(input$usar_exotica_selecionada, {
      if (!monitora_painel_iniciar_botao("usar_exotica_selecionada", "usar linha selecionada para movimento exótica para nativa")) return(NULL)
      on.exit(monitora_painel_liberar_botao("usar_exotica_selecionada"), add = TRUE)
      ex <- triagem_formas_vida_coleta()
      sel <- input$tabela_exoticas_rows_selected
      if (length(sel) < 1L || nrow(ex) == 0L || any(sel < 1L | sel > nrow(ex))) {
        monitora_painel_notificar("Selecione uma ou mais linhas exóticas na tabela de triagem antes de usar esta ação.", type = "error")
        return(NULL)
      }
      r <- ex[unique(as.integer(sel))]
      if ("tipo_triagem" %in% names(r)) {
        n_sel_total <- nrow(r)
        r <- r[tipo_triagem == "exotica"]
        if ("status_vinculo" %in% names(r)) r <- r[!grepl("^erro_", status_vinculo)]
        if ("forma_vida_exotica" %in% names(r)) r <- r[!is.na(forma_vida_exotica) & nzchar(as.character(forma_vida_exotica))]
        n_ignoradas <- n_sel_total - nrow(r)
        if (n_ignoradas > 0L) {
          monitora_painel_notificar(paste0(n_ignoradas, " linha(s) de forma desconhecida/outras foram mantidas apenas para diagnóstico e ignoradas no movimento exótica → nativa."), type = "warning", duration = 8)
        }
      }
      if (!nrow(r)) {
        monitora_painel_notificar("A ação de movimento exótica → nativa só pode usar linhas de tipo_triagem = 'exotica'.", type = "error", duration = 8)
        return(NULL)
      }
      r1 <- r[1]
      coleta_sel <- monitora_painel_valor(r1$COLETA)
      ponto_sel <- monitora_painel_valor(r1$ponto_amostral)
      forma_sel <- monitora_painel_valor(r1$forma_vida_exotica)
      if (!nzchar(ponto_sel) || !nzchar(forma_sel)) {
        monitora_painel_notificar("A seleção não possui ponto amostral ou forma de vida exótica identificável.", type = "error")
        return(NULL)
      }
      rv$ponto_alvo <- ponto_sel
      rv$movimento_alvo <- data.table::copy(r)
 ### seleção de COLETA/ponto é navegação (mostra onde
 ### está o contexto detectado), não é o mesmo que pré-selecionar campos
 ### operacionais de decisão (forma/origem/destino/hábito) -- estes ficam
 ### em placeholder mesmo após esta ação; o contexto detectado (forma
 ### exótica '", forma_sel, "') é mostrado só em texto/notificação,
 ### cabendo ao usuário escolher explicitamente mv_forma/mv_origem/
 ### mv_destino/mv_habito antes de adicionar a correção.
 ### A tabela só possui linhas quando a COLETA já está selecionada. Evita
 ### reinicializar desnecessariamente o selectize: essa reinicialização
 ### alterava transitoriamente o schema da DT server-side enquanto seu
 ### filtro ainda referenciava as colunas anteriores, causando
 ### `[.data.frame: colunas indefinidas selecionadas`.
      if (nzchar(coleta_sel) && !identical(monitora_painel_valor(input$coleta), coleta_sel)) {
        shiny::updateSelectizeInput(session, "coleta", selected = coleta_sel, server = TRUE)
      }
      shiny::updateSelectInput(session, "ponto", selected = ponto_sel)
      shiny::updateSelectInput(session, "mv_forma", choices = c("(selecione)" = "", monitora_painel_mv_choices_com_token(forma_sel)), selected = "")
      shiny::updateSelectInput(session, "mv_origem", selected = "")
      shiny::updateSelectInput(session, "mv_destino", selected = "")
      shiny::updateRadioButtons(session, "escopo", selected = "ponto")
      shiny::updateNumericInput(session, "n_esperado", value = 1)
      shiny::updateCheckboxInput(session, "confirmar_abrangencia", value = FALSE)
      monitora_painel_atualizar_habito_select("mv_habito", "", selected = "")
      shiny::updateTextAreaInput(session, "motivo", value = paste0("Triagem de formas de vida: avaliar/mover '", forma_sel, "' para nativa no ponto amostral ", ponto_sel, "."))
      monitora_painel_notificar(paste0(nrow(r), " linha(s) preparada(s) para revisão: forma exótica detectada '", forma_sel, "' no ponto amostral ", ponto_sel, ". Selecione explicitamente 'Forma de vida', 'Origem'='exotica', 'Destino'='nativa' e o hábito (quando exigido) antes de clicar em 'Adicionar correção simples/lote'."), type = "message", duration = 10)
    })

    shiny::observeEvent(input$triagem_destino_desconhecida, {
 ### ao trocar o destino, apenas atualiza as opções
 ### disponíveis -- não seleciona automaticamente a 1a forma válida real.
 ### O usuário precisa escolher explicitamente.
      destino <- monitora_painel_valor(input$triagem_destino_desconhecida)
      choices <- if (nzchar(destino)) formas_validas_por_categoria[[destino]] else NULL
      if (is.null(choices) || !length(choices)) choices <- character(0)
      choices <- c("(selecione)" = "", choices)
      shiny::updateSelectizeInput(session, "triagem_forma_valida", choices = choices, selected = "", server = TRUE)
      monitora_painel_atualizar_habito_select("triagem_habito", "")
    }, ignoreInit = TRUE)

