      monitora_painel_atualizar_habito_select("triagem_habito", input$triagem_forma_valida)
    }, ignoreInit = FALSE)

    monitora_painel_choices_origem_movimento <- function(categoria, lote = FALSE) {
      categoria <- monitora_painel_valor(categoria)
      escolhas <- if (nzchar(categoria)) formas_validas_por_categoria[[categoria]] else character(0)
      if (is.null(escolhas)) escolhas <- character(0)
      if (categoria %in% MONITORA_TRIAGEM_CATEGORIAS_BIOLOGICAS) {
        escolhas <- c(escolhas, stats::setNames("desconhecida", monitora_painel_rotulo_token("Forma de vida desconhecida", "desconhecida")))
      }
      escolhas <- escolhas[!duplicated(unname(escolhas))]
      if (isTRUE(lote)) {
        c(stats::setNames("__todas__", "Todas as formas encontradas na origem — __todas__"), escolhas)
      } else {
        c("(selecione)" = "", escolhas)
      }
    }

