monitora_progresso_backend_resolver <- function() {
  if (!isTRUE(MONITORA_PROGRESSO_HABILITADO)) return("desligado")
  backend <- as.character(MONITORA_PROGRESSO_BACKEND)[1]
  if (is.na(backend) || !(backend %in% c("auto", "cli", "txt"))) backend <- "cli"

  cli_ok <- isTRUE(MONITORA_PROGRESSO_CLI_DISPONIVEL) &&
    !isTRUE(MONITORA_PROGRESSO_CLI_FALHOU) &&
    requireNamespace("cli", quietly = TRUE)

  if (identical(backend, "cli") && !cli_ok) {
    msg <- "MONITORA_PROGRESSO_BACKEND = 'cli', mas o backend cli está indisponível ou falhou."
    if (identical(MONITORA_PROGRESSO_CLI_FALLBACK_TXT, "S")) {
      if (!isTRUE(MONITORA_PROGRESSO_CLI_AVISO_AUSENTE_EMITIDO)) {
        message(msg, " Usando utils::txtProgressBar() porque MONITORA_PROGRESSO_CLI_FALLBACK_TXT='S'.")
        MONITORA_PROGRESSO_CLI_AVISO_AUSENTE_EMITIDO <<- TRUE
      }
      return("txt")
    }
    stop(msg, " Instale o pacote 'cli' ou use MONITORA_PROGRESSO_BACKEND='auto'/'txt'.", call. = FALSE)
  }

  if (identical(backend, "txt")) return("txt")
  if (identical(backend, "cli") && cli_ok) return("cli")
  if (identical(backend, "auto") && cli_ok) return("cli")
  "txt"
}

monitora_progresso_texto_valido <- function(x) {
  x <- as.character(x)[1]
  !is.na(x) && nzchar(trimws(x))
}

monitora_progresso_limitar_texto <- function(x, max_chars = 120L) {
  x <- as.character(x)[1]
  if (is.na(x) || !nzchar(trimws(x))) return(NA_character_)
  x <- trimws(gsub("[\r\n\t]+", " ", x))
  max_chars <- suppressWarnings(as.integer(max_chars))[1]
  if (is.na(max_chars) || max_chars < 20L) max_chars <- 120L
  if (nchar(x, type = "chars", allowNA = FALSE) > max_chars) {
    x <- paste0(substr(x, 1L, max_chars - 3L), "...")
  }
  x
}

monitora_progresso_status <- function(etapa = NA_character_, detalhe = NA_character_) {
  etapa <- as.character(etapa)[1]
  detalhe <- as.character(detalhe)[1]
  partes <- character(0)
  if (monitora_progresso_texto_valido(etapa)) partes <- c(partes, etapa)
  if (monitora_progresso_texto_valido(detalhe)) partes <- c(partes, detalhe)
  if (!length(partes)) partes <- "processando"
  partes <- gsub("_", " ", partes, fixed = TRUE)
  monitora_progresso_limitar_texto(
    paste(partes, collapse = " | "),
    MONITORA_PROGRESSO_CLI_STATUS_MAX_CHARS
  )
}

monitora_progresso_iniciar_txt <- function() {
  MONITORA_PROGRESSO_BACKEND_ATIVO <<- "txt"
  MONITORA_PROGRESSO_PB <<- utils::txtProgressBar(min = 0, max = MONITORA_PROGRESSO_TOTAL, style = 3)
  utils::setTxtProgressBar(MONITORA_PROGRESSO_PB, MONITORA_PROGRESSO_VALOR)
  invisible(TRUE)
}

monitora_progresso_iniciar_cli <- function() {
  manter_historico <- identical(MONITORA_PROGRESSO_CLI_MANTER_HISTORICO, "S")
  largura_cli <- max(
    suppressWarnings(as.integer(MONITORA_PROGRESSO_CLI_LARGURA))[1],
    suppressWarnings(as.integer(getOption("width", 80L)))[1],
    na.rm = TRUE
  )
  if (!is.finite(largura_cli) || is.na(largura_cli)) largura_cli <- 180L
  tryCatch(options(cli.progress_show_after = 0, cli.width = largura_cli), error = function(e) NULL)
  pb <- tryCatch(
    cli::cli_progress_bar(
      name = "Execução geral",
      status = "início",
      type = "custom",
      total = MONITORA_PROGRESSO_TOTAL,
      format = MONITORA_PROGRESSO_CLI_FORMAT,
      format_done = MONITORA_PROGRESSO_CLI_FORMAT_DONE,
      clear = !manter_historico,
      auto_terminate = FALSE,
      .envir = .GlobalEnv
    ),
    error = function(e) {
      MONITORA_PROGRESSO_CLI_FALHOU <<- TRUE
      msg <- paste0("Falha ao iniciar barra cli. Motivo: ", conditionMessage(e))
      if (identical(MONITORA_PROGRESSO_CLI_FALLBACK_TXT, "S")) {
        message(msg, " Usando utils::txtProgressBar() porque MONITORA_PROGRESSO_CLI_FALLBACK_TXT='S'.")
        return(NULL)
      }
      stop(msg, call. = FALSE)
    }
  )
  if (is.null(pb)) return(monitora_progresso_iniciar_txt())
  MONITORA_PROGRESSO_BACKEND_ATIVO <<- "cli"
  MONITORA_PROGRESSO_PB <<- pb
  tryCatch(
    cli::cli_progress_update(id = MONITORA_PROGRESSO_PB, set = MONITORA_PROGRESSO_VALOR, status = "início", force = TRUE, .envir = .GlobalEnv),
    error = function(e) {
      MONITORA_PROGRESSO_CLI_FALHOU <<- TRUE
      msg <- paste0("Falha ao atualizar barra cli. Motivo: ", conditionMessage(e))
      if (identical(MONITORA_PROGRESSO_CLI_FALLBACK_TXT, "S")) {
        message(msg, " Usando utils::txtProgressBar() porque MONITORA_PROGRESSO_CLI_FALLBACK_TXT='S'.")
        MONITORA_PROGRESSO_PB <<- NULL
        return(monitora_progresso_iniciar_txt())
      }
      stop(msg, call. = FALSE)
    }
  )
  invisible(TRUE)
}

monitora_progresso_iniciar <- function() {
  if (!isTRUE(MONITORA_PROGRESSO_HABILITADO)) return(invisible(FALSE))
  if (is.null(MONITORA_PROGRESSO_PB)) {
    backend <- monitora_progresso_backend_resolver()
    if (identical(backend, "cli")) monitora_progresso_iniciar_cli() else monitora_progresso_iniciar_txt()
    if (identical(MONITORA_PROGRESSO_BACKEND_ATIVO, "cli")) {
      message("[PROGRESSO] backend ativo: ", MONITORA_PROGRESSO_BACKEND_ATIVO, " | layout: ", MONITORA_PROGRESSO_CLI_LAYOUT)
    } else {
      message("[PROGRESSO] backend ativo: ", MONITORA_PROGRESSO_BACKEND_ATIVO)
    }
    monitora_progresso_flush(force = TRUE)
  }
  invisible(TRUE)
}

monitora_progresso_percentual <- function() {
  if (!isTRUE(MONITORA_PROGRESSO_HABILITADO) || is.null(MONITORA_PROGRESSO_TOTAL) || MONITORA_PROGRESSO_TOTAL <= 0) return(NA_real_)
  round(100 * min(MONITORA_PROGRESSO_VALOR, MONITORA_PROGRESSO_TOTAL) / MONITORA_PROGRESSO_TOTAL, 1)
}

monitora_progresso_nova_linha <- function(force = FALSE) {
  if (isTRUE(MONITORA_PROGRESSO_HABILITADO) && !is.null(MONITORA_PROGRESSO_PB)) {
 # Não redesenha a barra aqui: o checkpoint já atualizou o backend.
 # A quebra de linha preserva a legibilidade dos [PERF] sem duplicar custo de console.
    cat("\n")
    monitora_progresso_flush(force = isTRUE(force))
  }
  invisible(TRUE)
}

monitora_progresso_elapsed_seg <- function(ts) {
  out <- suppressWarnings(as.numeric(difftime(Sys.time(), ts, units = "secs")))
  if (is.na(out) || !is.finite(out)) out <- Inf
  out
}

monitora_progresso_flush <- function(force = FALSE) {
  if (!isTRUE(force) && monitora_progresso_elapsed_seg(MONITORA_PROGRESSO_ULTIMO_FLUSH_TS) < MONITORA_PROGRESSO_FLUSH_MIN_INTERVALO_SEG) {
    return(invisible(FALSE))
  }
  MONITORA_PROGRESSO_ULTIMO_FLUSH_TS <<- Sys.time()
  tryCatch(flush.console(), error = function(e) NULL)
  invisible(TRUE)
}

monitora_progresso_deve_renderizar <- function(status = NA_character_, force = FALSE, finalizar = FALSE) {
  if (isTRUE(force) || isTRUE(finalizar)) return(TRUE)
  if (is.na(MONITORA_PROGRESSO_ULTIMO_VALOR_RENDERIZADO) || MONITORA_PROGRESSO_ULTIMO_VALOR_RENDERIZADO < 0L) return(TRUE)
  delta <- abs(MONITORA_PROGRESSO_VALOR - MONITORA_PROGRESSO_ULTIMO_VALOR_RENDERIZADO)
  if (delta >= MONITORA_PROGRESSO_RENDER_MIN_DELTA) return(TRUE)
  if (monitora_progresso_elapsed_seg(MONITORA_PROGRESSO_ULTIMO_RENDER_TS) >= MONITORA_PROGRESSO_RENDER_MIN_INTERVALO_SEG) return(TRUE)
  FALSE
}

monitora_progresso_registrar_render <- function(status = NA_character_) {
  MONITORA_PROGRESSO_ULTIMO_VALOR_RENDERIZADO <<- MONITORA_PROGRESSO_VALOR
  MONITORA_PROGRESSO_ULTIMO_STATUS_RENDERIZADO <<- as.character(status)[1]
  MONITORA_PROGRESSO_ULTIMO_RENDER_TS <<- Sys.time()
  invisible(TRUE)
}

monitora_progresso_atualizar_backend <- function(status = NA_character_, force = FALSE) {
  if (is.null(MONITORA_PROGRESSO_PB)) return(invisible(FALSE))
  if (identical(MONITORA_PROGRESSO_BACKEND_ATIVO, "cli")) {
    ok <- tryCatch({
      cli::cli_progress_update(
        id = MONITORA_PROGRESSO_PB,
        set = MONITORA_PROGRESSO_VALOR,
        status = status,
        force = isTRUE(force),
        .envir = .GlobalEnv
      )
      TRUE
    }, error = function(e) {
      MONITORA_PROGRESSO_CLI_FALHOU <<- TRUE
      structure(FALSE, monitora_cli_erro = conditionMessage(e))
    })
    if (!isTRUE(ok)) {
      motivo <- attr(ok, "monitora_cli_erro")
      if (is.null(motivo) || is.na(motivo)) motivo <- "erro não informado"
      tryCatch(cli::cli_progress_done(id = MONITORA_PROGRESSO_PB, result = "failed", .envir = .GlobalEnv), error = function(e) NULL)
      if (identical(MONITORA_PROGRESSO_CLI_FALLBACK_TXT, "S")) {
        message("Falha durante atualização da barra cli; alternando para utils::txtProgressBar() porque MONITORA_PROGRESSO_CLI_FALLBACK_TXT='S'. Motivo: ", motivo)
        MONITORA_PROGRESSO_PB <<- NULL
        monitora_progresso_iniciar_txt()
        utils::setTxtProgressBar(MONITORA_PROGRESSO_PB, MONITORA_PROGRESSO_VALOR)
      } else {
        stop("Falha durante atualização da barra cli. Motivo: ", motivo, call. = FALSE)
      }
    }
  } else {
    utils::setTxtProgressBar(MONITORA_PROGRESSO_PB, MONITORA_PROGRESSO_VALOR)
  }
  invisible(TRUE)
}

monitora_progresso_definir_valor <- function(valor, etapa = NA_character_, detalhe = NA_character_, finalizar = FALSE, force = FALSE) {
  if (!isTRUE(MONITORA_PROGRESSO_HABILITADO)) return(NA_real_)
  monitora_progresso_iniciar()
  valor <- suppressWarnings(as.integer(round(valor)))
  if (is.na(valor)) valor <- MONITORA_PROGRESSO_VALOR
  limite <- if (isTRUE(finalizar)) MONITORA_PROGRESSO_TOTAL else MONITORA_PROGRESSO_LIMITE_PRE_FINAL
 # Nunca permite recuo da barra; apenas avança até o limite aplicável.
  valor_novo <- max(MONITORA_PROGRESSO_VALOR, max(0L, min(limite, valor)))
  MONITORA_PROGRESSO_VALOR <<- valor_novo
  MONITORA_PROGRESSO_ULTIMA_ETAPA <<- as.character(etapa)[1]
  MONITORA_PROGRESSO_ULTIMO_STATUS <<- monitora_progresso_status(etapa, detalhe)
  renderizar <- monitora_progresso_deve_renderizar(
    status = MONITORA_PROGRESSO_ULTIMO_STATUS,
    force = isTRUE(force),
    finalizar = isTRUE(finalizar)
  )
  if (isTRUE(renderizar)) {
    monitora_progresso_atualizar_backend(status = MONITORA_PROGRESSO_ULTIMO_STATUS, force = isTRUE(force) || isTRUE(finalizar))
    monitora_progresso_registrar_render(MONITORA_PROGRESSO_ULTIMO_STATUS)
    monitora_progresso_flush(force = isTRUE(force) || isTRUE(finalizar))
  }
  monitora_progresso_percentual()
}

monitora_progresso_alvo_checkpoint <- function(etapa) {
  etapa <- as.character(etapa)[1]
  if (is.na(etapa) || !nzchar(etapa)) return(NA_integer_)

 # Em modos parciais que encerram em registros_corrig.csv, a faixa pós-painel
 # precisa representar o fechamento contratual e a materialização do produto,
 # não as estatísticas/gráficos que não serão executados. Isso evita o salto
 # visual 50% -> 100% observado em painel_e_parar.
  if (isTRUE(get0("MONITORA_PARAR_APOS_REGISTROS_CORRIG", ifnotfound = FALSE, inherits = TRUE))) {
    mapa_parcial_registros_corrig <- c(
      painel_correcoes_campos = 5000L,
      checkpoint_registros_corrig_inicio = 5150L,
      sanitizacao_contratual_pos_painel_pre_registros_corrig = 5700L,
      fechamento_contratual_registros_corrig = 6350L,
      reordenacao_registros_corrig_pre_materializacao = 6500L,
      contrato_xlsform_matriz_mapeamento = 9000L,
      contrato_xlsform_regras_relevance_normalizacao = 9220L,
      contrato_xlsform_validacao_dominios = 9350L,
      contrato_xlsform_validacao_condicionais = 9450L,
      contrato_xlsform_validacao_sanitizacao = 9520L,
      auditoria_contrato_registros_corrig_xlsform21 = 9580L,
      selo_dirty_flags_registros_corrig = 9640L,
      checkpoint_materializacao_registros_corrig_inicio = 9700L,
      checkpoint_materializacao_registros_corrig_fim = 9780L,
      checkpoint_auditoria_persistencia_correcoes = 9820L,
      checkpoint_parcial_registros_corrig = 9850L,
      fim_execucao = 9950L
    )
    if (etapa %in% names(mapa_parcial_registros_corrig)) {
      return(as.integer(mapa_parcial_registros_corrig[[etapa]]))
    }
  }

  if (etapa %in% names(MONITORA_PROGRESSO_ALVO_CHECKPOINT)) {
    return(as.integer(MONITORA_PROGRESSO_ALVO_CHECKPOINT[[etapa]]))
  }
  if (grepl("^exportacao_graficos_png_lote_", etapa)) return(NA_integer_) # PNG é controlado pelo loop.
  if (grepl("^preparacao_stat_", etapa)) return(5250L)
  if (grepl("^analise_", etapa)) return(5700L)
  NA_integer_
}

monitora_progresso_avancar_etapa <- function(etapa, detalhe = NA_character_) {
  if (!isTRUE(MONITORA_PROGRESSO_HABILITADO)) return(NA_real_)
  alvo <- monitora_progresso_alvo_checkpoint(etapa)
  if (is.na(alvo)) return(monitora_progresso_percentual())
  monitora_progresso_definir_valor(alvo, etapa = etapa, detalhe = detalhe, finalizar = FALSE, force = TRUE)
}

monitora_progresso_loop_configurar <- function(id, total, peso = NULL, descricao = NA_character_) {
  if (!isTRUE(MONITORA_PROGRESSO_HABILITADO)) return(invisible(FALSE))
  id <- as.character(id)[1]
  total <- suppressWarnings(as.integer(total))
  if (is.na(total) || total <= 0L || is.na(id) || !nzchar(id)) return(invisible(FALSE))
  faixa <- MONITORA_PROGRESSO_FAIXA_LOOPS[[id]]
  if (is.null(faixa)) {
    inicio <- MONITORA_PROGRESSO_VALOR
    fim <- min(MONITORA_PROGRESSO_LIMITE_PRE_FINAL, inicio + 100L)
  } else {
    inicio <- as.integer(faixa[["inicio"]])
    fim <- as.integer(faixa[["fim"]])
  }
  inicio <- max(MONITORA_PROGRESSO_VALOR, min(MONITORA_PROGRESSO_LIMITE_PRE_FINAL, inicio))
  fim <- max(inicio, min(MONITORA_PROGRESSO_LIMITE_PRE_FINAL, fim))
  assign(
    id,
    list(total = total, inicio = inicio, fim = fim, atual = 0L, descricao = as.character(descricao)[1]),
    envir = MONITORA_PROGRESSO_LOOPS
  )
  detalhe <- if (monitora_progresso_texto_valido(descricao)) paste0("0/", total, ": ", descricao) else paste0("0/", total)
  monitora_progresso_definir_valor(inicio, etapa = id, detalhe = detalhe, finalizar = FALSE, force = TRUE)
  invisible(TRUE)
}

monitora_progresso_loop_avancar <- function(id, atual = NULL, incremento = 1L, detalhe = NA_character_) {
  if (!isTRUE(MONITORA_PROGRESSO_HABILITADO)) return(NA_real_)
  id <- as.character(id)[1]
  if (is.na(id) || !nzchar(id) || !exists(id, envir = MONITORA_PROGRESSO_LOOPS, inherits = FALSE)) return(NA_real_)
  loop <- get(id, envir = MONITORA_PROGRESSO_LOOPS, inherits = FALSE)
  if (is.null(atual)) {
    incremento <- suppressWarnings(as.integer(incremento))
    if (is.na(incremento) || incremento < 1L) incremento <- 1L
    loop$atual <- min(loop$total, loop$atual + incremento)
  } else {
    atual <- suppressWarnings(as.integer(atual))
    if (!is.na(atual)) loop$atual <- max(loop$atual, min(loop$total, atual))
  }
  fracao <- if (loop$total > 0L) loop$atual / loop$total else 1
  alvo <- loop$inicio + floor((loop$fim - loop$inicio) * fracao)
  assign(id, loop, envir = MONITORA_PROGRESSO_LOOPS)
  if (!monitora_progresso_texto_valido(detalhe)) detalhe <- paste0(loop$atual, "/", loop$total)
  monitora_progresso_definir_valor(alvo, etapa = id, detalhe = detalhe, finalizar = FALSE, force = loop$atual >= loop$total)
}

# Chamadas preservadas não alteram denominador nem imprimem mensagens.
monitora_progresso_adicionar_total <- function(n, motivo = NA_character_) {
  invisible(FALSE)
}

monitora_progresso_avancar <- function(incremento = 1L, etapa = NA_character_, detalhe = NA_character_) {
 # O progresso real é controlado por marcos absolutos.
  if (!isTRUE(MONITORA_PROGRESSO_HABILITADO)) return(NA_real_)
  monitora_progresso_percentual()
}

monitora_progresso_finalizar <- function() {
  if (!isTRUE(MONITORA_PROGRESSO_HABILITADO)) return(invisible(FALSE))
  monitora_progresso_definir_valor(MONITORA_PROGRESSO_TOTAL, etapa = "fim_execucao", detalhe = "finalização controlada", finalizar = TRUE, force = TRUE)
  if (!is.null(MONITORA_PROGRESSO_PB)) {
    if (identical(MONITORA_PROGRESSO_BACKEND_ATIVO, "cli") && requireNamespace("cli", quietly = TRUE)) {
      tryCatch(cli::cli_progress_done(id = MONITORA_PROGRESSO_PB, result = "done", .envir = .GlobalEnv), error = function(e) NULL)
    } else {
      tryCatch(close(MONITORA_PROGRESSO_PB), error = function(e) NULL)
    }
    MONITORA_PROGRESSO_PB <<- NULL
  }
  message("[PROGRESSO] execução concluída: 100%")
  monitora_progresso_flush(force = TRUE)
  invisible(TRUE)
}

### Instrumentação de performance
### Registra a duração incremental e acumulada das principais etapas do script.
### O objetivo é identificar gargalos, especialmente em normalização, consolidação de colunas,
### deduplicação semântica, análises e exportações.

MONITORA_PERF_ENABLED <- TRUE
MONITORA_PERF_START_TIME <- Sys.time()
MONITORA_PERF_LAST_TIME <- MONITORA_PERF_START_TIME
MONITORA_PERF_PAUSED_SEC <- 0
MONITORA_PERF_PAUSE_START <- monitora_posixct_na()
MONITORA_PERF_PAINEL_COMPUTE_SEC <- 0
MONITORA_PERF_PAUSE_COMPUTE_BASE <- 0
MONITORA_PERF_PAINEL_EVENTOS <- data.table(
  ordem_evento = integer(),
  etapa = character(),
  inicio = character(),
  fim = character(),
  duracao_seg = numeric(),
  detalhe = character()
)
MONITORA_PERF_EXECUCAO <- data.table(
  ordem = integer(),
  etapa = character(),
  inicio = character(),
  fim = character(),
  duracao_seg = numeric(),
  duracao_acumulada_seg = numeric(),
  n_linhas = integer(),
  n_colunas = integer(),
  objeto_mb = numeric(),
  rss_mb = numeric(),
  mem_available_mb = numeric(),
  detalhe = character(),
  tipo_tempo = character(),
  tempo_usuario_pausado_seg = numeric(),
  tempo_preview_painel_acumulado_seg = numeric()
)

monitora_perf_registrar_computacao_painel <- function(etapa, inicio, fim = Sys.time(), detalhe = NA_character_) {
  if (!isTRUE(MONITORA_PERF_ENABLED)) return(invisible(0))
  inicio <- as.POSIXct(inicio)
  fim <- as.POSIXct(fim)
  dur <- suppressWarnings(as.numeric(difftime(fim, inicio, units = "secs")))
  if (!is.finite(dur) || dur < 0) dur <- 0
  MONITORA_PERF_PAINEL_COMPUTE_SEC <<- MONITORA_PERF_PAINEL_COMPUTE_SEC + dur
  MONITORA_PERF_PAINEL_EVENTOS <<- data.table::rbindlist(list(
    MONITORA_PERF_PAINEL_EVENTOS,
    data.table::data.table(
      ordem_evento = nrow(MONITORA_PERF_PAINEL_EVENTOS) + 1L,
      etapa = as.character(etapa)[1L],
      inicio = format(inicio, "%Y-%m-%d %H:%M:%S"),
      fim = format(fim, "%Y-%m-%d %H:%M:%S"),
      duracao_seg = round(dur, 3),
      detalhe = as.character(detalhe)[1L]
    )
  ), fill = TRUE, use.names = TRUE)
  if (exists("monitora_correcao_console_msg", mode = "function")) {
    monitora_correcao_console_msg("PERF painel: ", etapa, " consumiu ", round(dur, 3), "s de computação, separados do tempo humano.")
  }
  invisible(dur)
}

monitora_perf_pausar <- function(motivo = "pausa_usuario") {
  if (!isTRUE(MONITORA_PERF_ENABLED)) return(invisible(FALSE))
  if (is.na(MONITORA_PERF_PAUSE_START)) {
    MONITORA_PERF_PAUSE_START <<- Sys.time()
    MONITORA_PERF_PAUSE_COMPUTE_BASE <<- MONITORA_PERF_PAINEL_COMPUTE_SEC
    if (exists("monitora_correcao_console_msg", mode = "function")) {
      monitora_correcao_console_msg("PERF pausada para ", motivo, "; tempo humano não entrará na duração computacional.")
    }
  }
  invisible(TRUE)
}

monitora_perf_retomar <- function(motivo = "pausa_usuario") {
  if (!isTRUE(MONITORA_PERF_ENABLED)) return(invisible(0))
  if (is.na(MONITORA_PERF_PAUSE_START)) return(invisible(0))
  now <- Sys.time()
  delta_bruto <- as.numeric(difftime(now, MONITORA_PERF_PAUSE_START, units = "secs"))
  if (!is.finite(delta_bruto) || delta_bruto < 0) delta_bruto <- 0
  delta_preview <- MONITORA_PERF_PAINEL_COMPUTE_SEC - MONITORA_PERF_PAUSE_COMPUTE_BASE
  if (!is.finite(delta_preview) || delta_preview < 0) delta_preview <- 0
  delta_humano <- max(0, delta_bruto - delta_preview)
  MONITORA_PERF_PAUSED_SEC <<- MONITORA_PERF_PAUSED_SEC + delta_humano
  MONITORA_PERF_LAST_TIME <<- now
  MONITORA_PERF_PAUSE_START <<- monitora_posixct_na()
  if (exists("monitora_correcao_console_msg", mode = "function")) {
    monitora_correcao_console_msg("PERF retomada: ", round(delta_humano, 3), "s de interação humana desconsiderados; ", round(delta_preview, 3), "s de preview mantidos como computação.")
  }
  invisible(delta_humano)
}

monitora_perf_tempo_acumulado <- function(now = Sys.time()) {
  pausado_atual <- 0
  if (!is.na(MONITORA_PERF_PAUSE_START)) {
    pausa_bruta_atual <- as.numeric(difftime(now, MONITORA_PERF_PAUSE_START, units = "secs"))
    preview_atual <- MONITORA_PERF_PAINEL_COMPUTE_SEC - MONITORA_PERF_PAUSE_COMPUTE_BASE
    if (!is.finite(pausa_bruta_atual) || pausa_bruta_atual < 0) pausa_bruta_atual <- 0
    if (!is.finite(preview_atual) || preview_atual < 0) preview_atual <- 0
    pausado_atual <- max(0, pausa_bruta_atual - preview_atual)
  }
  total <- as.numeric(difftime(now, MONITORA_PERF_START_TIME, units = "secs")) - MONITORA_PERF_PAUSED_SEC - pausado_atual
  if (!is.finite(total) || total < 0) total <- 0
  total
}

monitora_perf_registrar_checkpoint <- function(etapa, detalhe = NA_character_, objeto = NULL) {
  if (!isTRUE(MONITORA_PERF_ENABLED)) return(invisible(TRUE))
  now <- Sys.time()
  inicio <- MONITORA_PERF_LAST_TIME
  dur <- as.numeric(difftime(now, inicio, units = "secs"))
  dur_total <- monitora_perf_tempo_acumulado(now)
  n_linhas <- NA_integer_
  n_colunas <- NA_integer_
  objeto_mb <- NA_real_

  obj <- NULL
  if (!is.null(objeto)) {
    if (is.character(objeto) && length(objeto) == 1 && exists(objeto, inherits = TRUE)) {
      obj <- get(objeto, inherits = TRUE)
    } else if (!is.character(objeto)) {
      obj <- objeto
    }
  }

  if (!is.null(obj)) {
    n_linhas <- tryCatch(as.integer(NROW(obj)), error = function(e) NA_integer_)
    n_colunas <- tryCatch(if (!is.null(dim(obj))) as.integer(NCOL(obj)) else NA_integer_, error = function(e) NA_integer_)
    objeto_mb <- tryCatch(round(as.numeric(object.size(obj)) / 1024^2, 3), error = function(e) NA_real_)
  }

  MONITORA_PERF_EXECUCAO <<- data.table::rbindlist(
    list(MONITORA_PERF_EXECUCAO,
    data.table::data.table(
      ordem = nrow(MONITORA_PERF_EXECUCAO) + 1L,
      etapa = as.character(etapa),
      inicio = format(inicio, "%Y-%m-%d %H:%M:%S"),
      fim = format(now, "%Y-%m-%d %H:%M:%S"),
      duracao_seg = round(dur, 3),
      duracao_acumulada_seg = round(dur_total, 3),
      n_linhas = n_linhas,
      n_colunas = n_colunas,
      objeto_mb = objeto_mb,
      rss_mb = monitora_recurso_memoria_rss_mb(),
      mem_available_mb = monitora_recurso_memoria_sistema()$mem_available_mb,
      detalhe = as.character(detalhe),
      tipo_tempo = "computacao_script",
      tempo_usuario_pausado_seg = round(MONITORA_PERF_PAUSED_SEC, 3),
      tempo_preview_painel_acumulado_seg = round(MONITORA_PERF_PAINEL_COMPUTE_SEC, 3)
    )),
    fill = TRUE,
    use.names = TRUE
  )

  MONITORA_PERF_LAST_TIME <<- now
  monitora_progresso_avancar_etapa(etapa, detalhe = detalhe)
  monitora_progresso_nova_linha()
  message(sprintf("[PERF] %s: %.3fs acumulado %.3fs", etapa, dur, dur_total))
  invisible(TRUE)
}

monitora_perf_gravar_relatorio <- function() {
  if (!isTRUE(MONITORA_PERF_ENABLED)) return(invisible(TRUE))
  monitora_perf_registrar_checkpoint("fim_execucao", "checkpoint final antes da gravação do relatório de performance")
  eventos <- data.table::copy(MONITORA_PERF_PAINEL_EVENTOS)
  if (nrow(eventos)) {
    eventos_rel <- eventos[, .(
      ordem = NA_integer_, etapa, inicio, fim, duracao_seg,
      duracao_acumulada_seg = NA_real_,
      n_linhas = NA_integer_, n_colunas = NA_integer_, objeto_mb = NA_real_,
      rss_mb = NA_real_, mem_available_mb = NA_real_, detalhe,
      tipo_tempo = "computacao_preview_painel",
      tempo_usuario_pausado_seg = NA_real_,
      tempo_preview_painel_acumulado_seg = cumsum(duracao_seg)
    )]
    perf_out <- data.table::rbindlist(list(data.table::copy(MONITORA_PERF_EXECUCAO), eventos_rel), fill = TRUE, use.names = TRUE)
    data.table::setorder(perf_out, inicio, fim, na.last = TRUE)
    perf_out[, ordem := seq_len(.N)]
  } else {
    perf_out <- data.table::copy(MONITORA_PERF_EXECUCAO)
  }
  monitora_fwrite(eventos, file.path(MONITORA_LOG_DIR, paste0("performance_painel_computacao_", MONITORA_EXEC_ID, ".csv")))
  monitora_fwrite(eventos, file.path(MONITORA_OUTPUT_DIR, "performance_painel_computacao_ultima_execucao.csv"))
  monitora_fwrite(perf_out, file.path(MONITORA_LOG_DIR, paste0("performance_execucao_", MONITORA_EXEC_ID, ".csv")))
  monitora_fwrite(perf_out, file.path(MONITORA_OUTPUT_DIR, "performance_execucao_ultima_execucao.csv"))
  invisible(TRUE)
}


monitora_registros_importados_reordenar <- function(dt) {
  dt <- monitora_dt_referenciar(dt)
  cols_meta <- intersect(c(
    "MONITORA_ARQUIVO_ENTRADA", "MONITORA_ARQUIVO_ORIGEM_EXECUCAO",
    "MONITORA_CAMINHO_ARQUIVO_ENTRADA", "MONITORA_TIPO_ENTRADA", ".id"
  ), names(dt))
  cols_id <- intersect(c(
    "COLETA", "coleta", "UC", "uc", "CICLO", "ciclo", "CAMPANHA", "campanha",
    "EA", "ea", "UA", "ua", "PROTOCOLO", "protocolo",
    "Data (data_hora)", "data_hora/data", "data_hora/hora",
    "ponto_amostral (amostragem/registro)", "ponto_metro (amostragem/registro)",
    "amostragem/registro/ponto_amostral", "amostragem/registro/ponto_metro"
  ), names(dt))
  ordem <- unique(c(cols_meta, cols_id, names(dt)))
  data.table::setcolorder(dt, ordem)
  invisible(dt)
}


### ------------------------
### ----------------------------------
### Escreve registros_importados.csv mesmo quando os CSVs históricos geram
### cabeçalhos duplicados. O data.table::fwrite não aceita nomes duplicados no
### objeto, mesmo quando col.names = FALSE em alguns caminhos. Por isso o corpo é
### escrito em arquivo temporário com nomes internos garantidamente únicos e o
### cabeçalho original é recomposto no arquivo final. Este procedimento não
### normaliza valores nem harmoniza contratos; apenas viabiliza o snapshot bruto.

monitora_publicacao_i_csv_quote <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  x <- gsub('"', '""', x, fixed = TRUE)
  paste0('"', x, '"')
}

monitora_publicacao_i_file_append_binary <- function(destino, arquivos) {
  con_out <- file(destino, open = "wb")
  on.exit(try(close(con_out), silent = TRUE), add = TRUE)
  for (aa in arquivos) {
    if (!file.exists(aa)) next
    con_in <- file(aa, open = "rb")
    on.exit(try(close(con_in), silent = TRUE), add = TRUE)
    repeat {
      z <- readBin(con_in, what = "raw", n = 1024L * 1024L)
      if (!length(z)) break
      writeBin(z, con_out)
    }
    close(con_in)
  }
  invisible(TRUE)
}

monitora_publicacao_h_csv_quote <- monitora_publicacao_i_csv_quote

monitora_publicacao_h_fwrite_registros_importados <- function(x, file, ...) {
 ### caminho único e robusto de escrita do snapshot bruto.
 ### Requisitos:
 ### - aceitar nomes duplicados herdados de XLSForms históricos;
 ### - não normalizar valores;
 ### - não chamar monitora_fwrite , que sanitiza ausências e exige nomes úteis
 ### para produtos normalizados;
 ### - não executar reordenação por nome quando há duplicatas;
 ### - preservar o cabeçalho original no arquivo final.
  dir_destino <- dirname(as.character(file)[1L])
  if (!is.na(dir_destino) && nzchar(dir_destino) && dir_destino != ".") {
    dir.create(dir_destino, showWarnings = FALSE, recursive = TRUE)
  }

  out <- if (data.table::is.data.table(x)) data.table::copy(x) else data.table::as.data.table(x)
 ### publicação: copiar explicitamente o vetor de nomes antes de setnames .
 ### Em data.table, names(out) pode compartilhar referência interna; se o vetor
 ### for mantido por referência, o setnames(out, nomes_internos) pode vazar para
 ### o cabeçalho manual e produzir MONITORA_COL_00001... no CSV final.
 ### ajuste: enc2utf8(as.character(...)) sozinho NÃO garante uma
 ### cópia independente (ambos podem devolver o mesmo objeto quando o vetor já
 ### é character/UTF-8), e setnames muta por referência -- confirmado por
 ### teste isolado que isso corrompia nomes_originais na prática, produzindo
 ### MONITORA_COL_00001... em TODAS as colunas do CSV final, mesmo sem
 ### duplicatas. paste0 sempre aloca um vetor novo, forçando a cópia real.
  nomes_originais <- paste0(enc2utf8(as.character(base::names(out))))
  if (!length(nomes_originais)) stop("registros_importados.csv bruto sem colunas.", call. = FALSE)

  duplicadas <- nomes_originais[duplicated(nomes_originais)]
  nomes_internos <- sprintf("MONITORA_COL_%05d", seq_along(nomes_originais))
  if (anyDuplicated(nomes_internos)) {
    stop("Falha interna: nomes temporários de registros_importados não são únicos.", call. = FALSE)
  }

 ### setnames(x, new) opera por posição e não depende de nomes antigos únicos.
  data.table::setnames(out, nomes_internos)
  if (anyDuplicated(names(out))) {
    stop("Falha interna: objeto temporário ainda possui nomes duplicados antes do fwrite.", call. = FALSE)
  }

  ts <- format(Sys.time(), "%Y%m%d%H%M%S")
  pid <- Sys.getpid()
  header_tmp <- paste0(as.character(file), ".header_tmp_", pid, "_", ts)
  body_tmp <- paste0(as.character(file), ".body_tmp_", pid, "_", ts)
  final_tmp <- paste0(as.character(file), ".final_tmp_", pid, "_", ts)
  on.exit({
    for (zz in c(header_tmp, body_tmp, final_tmp)) {
      if (file.exists(zz)) try(unlink(zz, force = TRUE), silent = TRUE)
    }
  }, add = TRUE)

  extras <- list(...)
  sep <- if (!is.null(extras$sep)) extras$sep else ","
  quote <- if (!is.null(extras$quote)) extras$quote else TRUE
  bom <- if (!is.null(extras$bom)) extras$bom else FALSE
  eol <- if (!is.null(extras$eol)) extras$eol else "\n"
  encoding <- if (!is.null(extras$encoding)) extras$encoding else "UTF-8"
  header <- paste(monitora_publicacao_i_csv_quote(nomes_originais), collapse = sep)
 ### Escrita binária evita que o Windows traduza LF para CRLF e mantém o BOM
 ### exatamente no byte zero, inclusive quando o cabeçalho contém duplicatas.
  con_header <- file(header_tmp, open = "wb")
  tryCatch({
    if (isTRUE(bom)) writeBin(as.raw(c(0xEF, 0xBB, 0xBF)), con_header)
    writeBin(charToRaw(enc2utf8(header)), con_header)
    writeBin(charToRaw(eol), con_header)
  }, finally = close(con_header))
 ### Produto bruto: ausências estruturais introduzidas por fill=TRUE são vazias,
 ### não string "NA". Valores literais "NA" lidos dos CSVs permanecem texto.
  data.table::fwrite(
    x = out,
    file = body_tmp,
    col.names = FALSE,
    row.names = FALSE,
    na = "",
    sep = sep,
    quote = quote,
 ### O BOM pertence ao byte zero do cabeçalho manual, nunca ao início do
 ### corpo anexado. Assim não há BOM interno após a primeira quebra de linha.
    bom = FALSE,
    eol = eol,
    encoding = encoding
  )

  monitora_publicacao_i_file_append_binary(final_tmp, c(header_tmp, body_tmp))
  if (file.exists(file)) unlink(file, force = TRUE)
  ok_rename <- file.rename(final_tmp, file)
  if (!isTRUE(ok_rename)) {
    ok_copy <- file.copy(final_tmp, file, overwrite = TRUE)
    if (!isTRUE(ok_copy)) stop("Falha ao mover arquivo temporário para registros_importados.csv.", call. = FALSE)
    unlink(final_tmp, force = TRUE)
  }

  invisible(list(ok = TRUE, colunas_duplicadas = unique(duplicadas)))
}
