### definição anterior sobrescrita:
### Primeira definicao de monitora_registros_importados_exportar , preservada
### apenas para auditoria de linhagem. E sobrescrita lexicalmente pela
### Implementação operacional vigente posterior, em torno da linha 33596.
monitora_registros_importados_exportar <- function(dt, output_dir = MONITORA_OUTPUT_DIR, log_dir = MONITORA_LOG_DIR, exec_id = MONITORA_EXEC_ID, contexto = "pos_concatenacao_csv", permitir_apenas_bruto = TRUE) {
  tryCatch({
    contexto_chr <- as.character(contexto)[1L]
    contexto_bruto <- grepl("pos_concatenacao_csv|pre_padronizacao|leitura_csv|importacao_bruta", contexto_chr, ignore.case = TRUE)
    if (isTRUE(permitir_apenas_bruto) && !isTRUE(contexto_bruto)) {
      warning(
        "registros_importados.csv não foi gerado: este produto deve refletir os arquivos de entrada lidos e não será reconstruído a partir de objetos já normalizados/corrigidos. Contexto=",
        contexto_chr,
        call. = FALSE
      )
      return(invisible(FALSE))
    }
    if (!inherits(dt, c("data.frame", "data.table"))) return(invisible(FALSE))
    dir.create(output_dir, showWarnings = FALSE, recursive = TRUE)
    dir.create(log_dir, showWarnings = FALSE, recursive = TRUE)

 ### materialização bruta e robusta. Duplicidades de cabeçalho são
 ### preservadas no CSV de saída, pois fazem parte do snapshot fiel dos dados
 ### lidos. Para contornar a restrição de data.table::fwrite a nomes
 ### duplicados, usamos nomes internos temporários únicos e escrevemos o
 ### cabeçalho original manualmente.
 ### não reordenar por nomes neste snapshot bruto. Bases históricas
 ### podem conter nomes duplicados; a reordenação por nome aciona erros no
 ### data.table antes do gravador robusto. A ordem da montagem pós-rbindlist é
 ### preservada como melhor aproximação fiel da entrada consolidada.
    out <- if (data.table::is.data.table(dt)) data.table::copy(dt) else data.table::as.data.table(dt)
    caminho <- file.path(output_dir, "registros_importados_bruto.csv")
    escrita <- monitora_publicacao_h_fwrite_registros_importados(out, caminho, row.names = FALSE)

    duplicadas_dt <- data.table::data.table(
      coluna = as.character(escrita$colunas_duplicadas),
      n_ocorrencias = as.integer(tabulate(match(as.character(escrita$colunas_duplicadas), unique(as.character(escrita$colunas_duplicadas))), nbins = length(unique(as.character(escrita$colunas_duplicadas)))))
    )
    if (length(escrita$colunas_duplicadas)) {
      dup_all <- names(out)[duplicated(names(out)) | duplicated(names(out), fromLast = TRUE)]
      duplicadas_dt <- data.table::data.table(coluna = names(table(dup_all)), n_ocorrencias = as.integer(table(dup_all)))
      monitora_fwrite(duplicadas_dt, file.path(output_dir, "auditoria_registros_importados_colunas_duplicadas.csv"), row.names = FALSE)
    }

    resumo <- data.table::data.table(
      exec_id = as.character(exec_id),
      produto = "registros_importados_bruto.csv",
      contexto = as.character(contexto),
      descricao = "Snapshot técnico fiel da leitura/montagem dos arquivos de entrada antes de padronizações semânticas, harmonização de contratos históricos, deduplicação semântica e correções do usuário.",
      n_linhas = as.integer(nrow(out)),
      n_colunas = as.integer(ncol(out)),
      n_colunas_duplicadas = as.integer(length(unique(escrita$colunas_duplicadas))),
      caminho = monitora_privacidade_caminho_relativo(caminho),
      observacao = "Arquivo técnico bruto montado pelo script a partir dos CSVs lidos; preserva valores como texto e preserva cabeçalhos duplicados quando presentes. O produto comparável para o usuário é registros_importados.csv saneado.",
      timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    )
    monitora_registros_importados_resumo_auditoria_gravar(
      resumo, output_dir = output_dir, log_dir = log_dir, exec_id = exec_id,
      produto = "registros_importados_bruto.csv", contexto = contexto_chr, camada = "bruto"
    )
    assign("MONITORA_REGISTROS_IMPORTADOS_BRUTO_MATERIALIZADO", TRUE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_IMPORTADOS_BRUTO_CONTEXTO", contexto_chr, envir = .GlobalEnv)
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("registros_importados_bruto_exportado", "INFO", caminho, paste0("registros_importados_bruto.csv gerado com ", nrow(out), " linhas e ", ncol(out), " colunas"), "snapshot técnico fiel de leitura/montagem; produto bruto não comparável diretamente")
    }
    invisible(TRUE)
  }, error = function(e) {
    warning("Falha ao gerar registros_importados_bruto.csv: ", conditionMessage(e), call. = FALSE)
    invisible(FALSE)
  })
}


### publicação ---------------------------------
### registros_importados.csv passa a ser produto saneado/comparável para uso do
### usuário. O snapshot fiel e potencialmente heterogêneo fica em
### registros_importados_bruto.csv. A geração saneada ocorre depois do merge de
### colunas duplicadas e da consolidação de aliases críticos, mas antes de
### deduplicações finais, painel, exclusões e correções assistidas.

monitora_registros_importados_chaves_preferenciais <- function() {
  c(
    "COLETA", "UC", "CICLO", "CAMPANHA", "EA", "UA", "PROTOCOLO",
    "Data (data_hora)", "Horário (data_hora)", "ANO",
    "ponto_amostral (amostragem/registro)", "ponto_metro (amostragem/registro)",
    "**Encostam** na vareta: (amostragem/registro)",
    "MONITORA_ARQUIVO_ORIGEM_EXECUCAO", "MONITORA_CAMINHO_ARQUIVO_ENTRADA",
    "MONITORA_ARQUIVO_ENTRADA", "MONITORA_TIPO_ENTRADA", ".id"
  )
}

monitora_registros_importados_saneado_preparar <- function(dt, contexto = "pos_consolidacao_aliases_importacao") {
  if (!inherits(dt, c("data.frame", "data.table"))) stop("registros_importados saneado exige data.frame/data.table.", call. = FALSE)
  out <- if (data.table::is.data.table(dt)) data.table::copy(dt) else data.table::as.data.table(dt)

 ### Segurança: se a função for chamada fora do ponto previsto, ainda consolida
 ### duplicatas/aliases antes de materializar o produto de comparação.
  if (anyDuplicated(names(out)) && exists("monitora_dt_consolidar_colunas_duplicadas", mode = "function")) {
    out <- monitora_dt_consolidar_colunas_duplicadas(out)
  }
  if (exists("monitora_dt_consolidar_aliases_colunas", mode = "function")) {
    out <- monitora_dt_consolidar_aliases_colunas(out)
  }

  if (anyDuplicated(names(out))) {
    data.table::setnames(out, make.unique(names(out), sep = "__dup"))
  }

  chaves <- monitora_registros_importados_chaves_preferenciais()
  ordem <- unique(c(intersect(chaves, names(out)), names(out)))
  data.table::setcolorder(out, ordem)

  attr(out, "monitora_contexto_registros_importados_saneado") <- contexto
  out[]
}

### definição anterior sobrescrita:
### Primeira definicao de monitora_registros_importados_saneado_exportar ,
### preservada apenas para auditoria de linhagem. E sobrescrita lexicalmente
### pela Implementação operacional vigente posterior, em torno da linha 33645.
monitora_registros_importados_saneado_exportar <- function(dt,
                                                           output_dir = MONITORA_OUTPUT_DIR,
                                                           log_dir = MONITORA_LOG_DIR,
                                                           exec_id = MONITORA_EXEC_ID,
                                                           contexto = "pos_consolidacao_aliases_importacao") {
  tryCatch({
    dir.create(output_dir, showWarnings = FALSE, recursive = TRUE)
    dir.create(log_dir, showWarnings = FALSE, recursive = TRUE)
    out <- monitora_registros_importados_saneado_preparar(dt, contexto = contexto)
    if (exists("monitora_produtos_resolver_pipes_por_ponto", mode = "function")) {
      out <- monitora_produtos_resolver_pipes_por_ponto(
        out,
        produto = "registros_importados.csv",
        output_dir = output_dir,
        log_dir = log_dir,
        exec_id = exec_id,
        contexto = paste0(contexto, "_pipes_operacionais"),
        corrigir = TRUE
      )
    }
    caminho <- file.path(output_dir, "registros_importados.csv")
    monitora_fwrite(out, caminho, row.names = FALSE, na = "")

    chaves <- monitora_registros_importados_chaves_preferenciais()
    resumo <- data.table::data.table(
      exec_id = as.character(exec_id),
      produto = "registros_importados.csv",
      contexto = as.character(contexto)[1L],
      descricao = "Produto saneado de entrada, com cabeçalhos canônicos/legíveis e comparável a registros_corrig.csv e registros_validados.csv por COLETA e demais chaves.",
      n_linhas = as.integer(nrow(out)),
      n_colunas = as.integer(ncol(out)),
      chaves_presentes = paste(intersect(chaves, names(out)), collapse = " | "),
      chaves_ausentes = paste(setdiff(chaves, names(out)), collapse = " | "),
      caminho = monitora_privacidade_caminho_relativo(caminho),
      observacao = "Gerado após normalização inicial de nomes/aliases e antes de deduplicação final, painel, exclusões e correções assistidas. Use este arquivo para comparação operacional; use registros_importados_bruto.csv para auditoria técnica fiel da leitura.",
      timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    )
    monitora_registros_importados_resumo_auditoria_gravar(
      resumo, output_dir = output_dir, log_dir = log_dir, exec_id = exec_id,
      produto = "registros_importados.csv", contexto = as.character(contexto)[1L],
      camada = "operacional", na = ""
    )

    assign("MONITORA_REGISTROS_IMPORTADOS_SANEADO_MATERIALIZADO", TRUE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_IMPORTADOS_SANEADO_CONTEXTO", as.character(contexto)[1L], envir = .GlobalEnv)
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("registros_importados_saneado_exportado", "INFO", caminho, paste0("registros_importados.csv saneado gerado com ", nrow(out), " linhas e ", ncol(out), " colunas"), "produto comparável para curadoria")
    }
    invisible(TRUE)
  }, error = function(e) {
    warning("Falha ao gerar registros_importados.csv saneado: ", conditionMessage(e), call. = FALSE)
    invisible(FALSE)
  })
}

### -------------------------------------------------------------
### Auditoria/correção de pipes residuais e organização de output.
if (!exists("MONITORA_OPCAO_ORGANIZAR_OUTPUT_SUBPASTAS", inherits = FALSE)) MONITORA_OPCAO_ORGANIZAR_OUTPUT_SUBPASTAS <- "S"
if (!exists("MONITORA_OPCAO_MANTER_COPIAS_COMPAT_RAIZ", inherits = FALSE)) MONITORA_OPCAO_MANTER_COPIAS_COMPAT_RAIZ <- "S"

monitora_produtos_coluna_coleta_generica <- function(dt) {
  nms <- names(dt)
  if ("COLETA" %in% nms) return("COLETA")
  cand <- nms[tolower(nms) %in% c("coleta", "amostragem/coleta")]
  if (length(cand)) cand[1L] else NA_character_
}

monitora_produtos_coluna_ponto_generica <- function(dt) {
  nms <- names(dt)
  prefer <- c("ponto_amostral", "ponto_amostral (amostragem/registro)", "Ponto amostral", "amostragem/registro/ponto_amostral")
  cand <- prefer[prefer %in% nms]
  if (length(cand)) return(cand[1L])
  cand <- nms[grepl("ponto.*amostral", tolower(nms))]
  if (length(cand)) cand[1L] else NA_character_
}

monitora_produtos_classificar_pipe_coluna <- function(coluna, produto = "") {
  cc <- tolower(as.character(coluna))
  prod <- tolower(as.character(produto)[1L])
  if (grepl("bruto", prod)) return("pipe_esperado_em_bruto")
  if (grepl("^(monitora_|arquivo_|origem_|hash_|md5|tipo_entrada|\\.id$)", cc)) return("pipe_residual_tecnico_tolerado")
  if (grepl("ponto|encostam|forma.*vida|especie|uuid|habito|observacao|foto", cc)) return("pipe_residual_operacional")
  "pipe_residual_revisar"
}

monitora_produtos_resolver_pipes_por_ponto <- function(dt,
                                                       produto = "registros_operacional.csv",
                                                       output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                       log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                       exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                                       contexto = "produto_operacional",
                                                       corrigir = TRUE) {
  if (!inherits(dt, c("data.frame", "data.table"))) return(dt)
  if (!requireNamespace("data.table", quietly = TRUE)) return(dt)
  d <- data.table::as.data.table(dt)
  n <- nrow(d)
  if (!n || !ncol(d)) return(d)

  col_coleta <- monitora_produtos_coluna_coleta_generica(d)
  col_ponto <- monitora_produtos_coluna_ponto_generica(d)
  pos_linha <- seq_len(n)
  if (!is.na(col_coleta) && col_coleta %in% names(d)) {
    aux_pos <- data.table::data.table(.i = seq_len(n), .coleta = as.character(d[[col_coleta]]))
    aux_pos[, .pos := seq_len(.N), by = .coleta]
    pos_linha[aux_pos$.i] <- aux_pos$.pos
  }
  seletor <- pos_linha
  if (!is.na(col_ponto) && col_ponto %in% names(d)) {
    p_chr <- as.character(d[[col_ponto]])
    p_num <- suppressWarnings(as.integer(gsub(",", ".", p_chr)))
    sem_pipe_ponto <- !grepl("|", p_chr, fixed = TRUE)
    usar <- sem_pipe_ponto & !is.na(p_num) & p_num >= 1L & p_num <= 10000L
    seletor[usar] <- p_num[usar]
  }

  cols_char <- names(d)[vapply(d, function(x) is.character(x) || is.factor(x), logical(1))]
  if (!length(cols_char)) return(d)
  audit <- vector("list", length(cols_char)); k <- 0L
  for (cc in cols_char) {
    x0 <- as.character(d[[cc]])
    hit <- !is.na(x0) & grepl("|", x0, fixed = TRUE)
    if (!any(hit)) next
    classe <- monitora_produtos_classificar_pipe_coluna(cc, produto)
    n_antes <- sum(hit, na.rm = TRUE)
    alterar <- isTRUE(corrigir) && classe %in% c("pipe_residual_operacional", "pipe_residual_revisar")
    n_corr <- 0L; n_falha <- 0L; n_corr_dedup_seguro <- 0L
    exemplos_antes <- utils::head(unique(x0[hit]), 3L)
    if (alterar) {
      idx <- which(hit)
      x1 <- x0
      for (ii in idx) {
        toks <- strsplit(x0[ii], "|", fixed = TRUE)[[1L]]
        toks <- trimws(toks)
        kk <- seletor[ii]
        if (!is.na(kk) && kk >= 1L && kk <= length(toks)) {
          novo <- toks[kk]
          if (is.na(novo)) novo <- ""
          x1[ii] <- novo
          n_corr <- n_corr + 1L
        } else {
 ### resolução posicional (token[índice do ponto])
 ### só é correta quando a célula é de fato uma lista agregada com
 ### um token por ponto da COLETA -- não é o caso de uma célula que
 ### é, ela mesma, o valor de UM único ponto e que só teve "|" onde
 ### deveria ter espaço (ex.: "graminoide|graminoide" no ponto 99 de
 ### uma COLETA com só ~101 pontos ao todo: índice 99 nunca vai
 ### bater com uma lista de 2 tokens). Quando TODOS os tokens dessa
 ### célula são o mesmo valor, a resolução por posição é irrelevante
 ### -- a informação real da célula é só esse valor único, e usá-lo
 ### não inventa nada (nenhum token é descartado que não seja
 ### repetição exata de outro já usado). Só se aplica quando os
 ### tokens são estritamente idênticos; qualquer divergência entre
 ### tokens continua exigindo resolução posicional real e, se não
 ### bater, fica residual para o gate de bloqueio decidir.
          toks_nao_vazios <- toks[nzchar(toks)]
          if (length(toks_nao_vazios) >= 1L && length(unique(toks_nao_vazios)) == 1L) {
            x1[ii] <- toks_nao_vazios[1L]
            n_corr <- n_corr + 1L
            n_corr_dedup_seguro <- n_corr_dedup_seguro + 1L
          } else {
            n_falha <- n_falha + 1L
          }
        }
      }
      data.table::set(d, j = cc, value = x1)
    }
    x2 <- as.character(d[[cc]])
    n_depois <- sum(!is.na(x2) & grepl("|", x2, fixed = TRUE), na.rm = TRUE)
    k <- k + 1L
    audit[[k]] <- data.table::data.table(
      exec_id = as.character(exec_id), produto = as.character(produto)[1L], contexto = as.character(contexto)[1L],
      coluna = cc, classificacao = classe, n_linhas_pipe_antes = as.integer(n_antes),
      n_linhas_corrigidas_por_indice_ponto = as.integer(n_corr), n_linhas_corrigidas_dedup_tokens_identicos = as.integer(n_corr_dedup_seguro),
      n_linhas_falha_correcao = as.integer(n_falha),
      n_linhas_pipe_depois = as.integer(n_depois), exemplo_antes = paste(exemplos_antes, collapse = " || "),
      timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    )
  }
  aud <- if (k) data.table::rbindlist(audit[seq_len(k)], fill = TRUE, use.names = TRUE) else data.table::data.table(
    exec_id = character(), produto = character(), contexto = character(), coluna = character(), classificacao = character(),
    n_linhas_pipe_antes = integer(), n_linhas_corrigidas_por_indice_ponto = integer(), n_linhas_corrigidas_dedup_tokens_identicos = integer(),
    n_linhas_falha_correcao = integer(), n_linhas_pipe_depois = integer(), exemplo_antes = character(), timestamp = character()
  )
  try({
    dir.create(file.path(output_dir, "03_auditorias", "importacao"), recursive = TRUE, showWarnings = FALSE)
    dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
    arq <- file.path(output_dir, "03_auditorias", "importacao", paste0("auditoria_pipes_", gsub("[^A-Za-z0-9]+", "_", produto), ".csv"))
    data.table::fwrite(aud, arq, na = "")
    data.table::fwrite(aud, file.path(log_dir, paste0("auditoria_pipes_", gsub("[^A-Za-z0-9]+", "_", produto), "_", exec_id, ".csv")), na = "")
  }, silent = TRUE)
  attr(d, "monitora_auditoria_pipes") <- aud
  d
}

### - ajuste ---------------------------------------------------
### monitora_produtos_resolver_pipes_por_ponto resolve resíduos de "|" por
### índice de ponto amostral/COLETA, mas não garante 100% de resolução: quando
### o número de tokens não bate com o índice do ponto (descompasso estrutural
### no dado de origem), a célula permanece com "|" (ver
###
### ). Esta função verifica,
### logo após a normalização, se algum resíduo de "|" sobreviveu e, se sim,
### bloqueia a exportação do produto. Nunca bloqueia o produto bruto, que tem
### permissão explícita de preservar "|" (é a leitura mais fiel do input).
monitora_bloquear_pipe_residual_produto <- function(dados,
                                                      produto,
                                                      auditoria_pipe = NULL,
                                                      output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                      log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                      exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                                      contexto = NA_character_,
                                                      bloquear = TRUE) {
  produto_chr <- as.character(produto)[1L]
  contexto_chr <- as.character(contexto)[1L]
  if (grepl("bruto", tolower(produto_chr))) return(invisible(dados))
  if (!inherits(dados, c("data.frame", "data.table"))) return(invisible(dados))
  dt <- data.table::as.data.table(dados)
  n <- nrow(dt)
  if (!n || !ncol(dt)) return(invisible(dados))

  cols_char <- names(dt)[vapply(dt, function(x) is.character(x) || is.factor(x), logical(1))]
  if (!length(cols_char)) return(invisible(dados))

 ### Três grupos, conforme a classificação (que já consulta o contrato
 ### XLSForm embutido para diferenciar texto livre de campo estruturado):
 ### - pipe_esperado_em_bruto / pipe_residual_tecnico_tolerado /
 ### pipe_permitido_texto_livre: nunca bloqueiam, nunca são reportados como
 ### problema (texto livre pode legitimamente conter "|" -- é escolha de
 ### digitação do observador, não artefato de importação).
 ### - pipe_indeterminado: coluna não reconhecida no contrato XLSForm
 ### embutido (não é texto livre nem estruturada confirmada); reportado à
 ### parte para revisão humana, mas NÃO bloqueia -- bloquear
 ### indiscriminadamente colunas desconhecidas repetiria o mesmo erro que
 ### motivou este ajuste (campos de texto livre não cobertos por nome).
 ### - pipe_residual_operacional / pipe_residual_revisar (== estruturado
 ### elegível): mesmas categorias já usadas por
 ### monitora_produtos_resolver_pipes_por_ponto para decidir o que
 ### corrigir; se resíduo de "|" sobrevive aqui, é falha real de resolução
 ### posicional em campo estruturado.
 ### - ajuste: quando `bloquear = FALSE` (checkpoint
 ### pré-tokenização, antes da cadeia padronizacao_* original), resíduo
 ### estruturado é reportado à parte (auditoria informativa), mas NÃO aborta
 ### -- essas colunas ainda serão tratadas por etapas posteriores da cadeia
 ### original antes do produto final. O bloqueio efetivo (stop ) só ocorre
 ### quando `bloquear = TRUE`, reservado ao checkpoint pós-tokenização
 ### operacional (produto final de registros_importados.csv/registros_corrig.csv).
 ### COLETA/UA/ponto identificam a linha em termos que um
 ### usuário consegue agir (a mensagem genérica anterior só citava a coluna
 ### e um relatório CSV à parte). Resolvidos uma única vez, fora do loop por
 ### coluna, reaproveitando os mesmos resolvedores genéricos já usados por
 ### monitora_produtos_resolver_pipes_por_ponto.
  col_coleta_id <- monitora_produtos_coluna_coleta_generica(dt)
  col_ponto_id <- monitora_produtos_coluna_ponto_generica(dt)
  chaves_id <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list())
  col_ua_id <- chaves_id$ua
  vec_coleta <- if (!is.na(col_coleta_id) && col_coleta_id %in% names(dt)) as.character(dt[[col_coleta_id]]) else rep(NA_character_, n)
  vec_ponto <- if (!is.na(col_ponto_id) && col_ponto_id %in% names(dt)) as.character(dt[[col_ponto_id]]) else rep(NA_character_, n)
  vec_ua <- if (!is.null(col_ua_id) && !is.na(col_ua_id) && col_ua_id %in% names(dt)) as.character(dt[[col_ua_id]]) else rep(NA_character_, n)

  achados <- vector("list", length(cols_char)); k <- 0L
  achados_indet <- vector("list", length(cols_char)); ki <- 0L
  n_colunas_preservadas <- 0L; n_linhas_preservadas <- 0L
  for (cc in cols_char) {
    classe <- tryCatch(monitora_produtos_classificar_pipe_coluna(cc, produto_chr), error = function(e) NA_character_)
    x <- as.character(dt[[cc]])
    idx <- which(!is.na(x) & grepl("|", x, fixed = TRUE))
    if (!length(idx)) next
    if (!is.na(classe) && classe %in% c("pipe_esperado_em_bruto", "pipe_residual_tecnico_tolerado", "pipe_permitido_texto_livre")) {
      n_colunas_preservadas <- n_colunas_preservadas + 1L
      n_linhas_preservadas <- n_linhas_preservadas + length(idx)
      next
    }
    if (!is.na(classe) && identical(classe, "pipe_indeterminado")) {
      ki <- ki + 1L
      achados_indet[[ki]] <- data.table::data.table(
        produto = produto_chr, coluna = cc, linha_indice = idx,
        valor_residual = x[idx], classificacao = classe,
        orientacao = "Coluna nao reconhecida no contrato XLSForm embutido como texto livre nem como campo estruturado; residuo de '|' preservado sem bloqueio. Revisar manualmente se a coluna e' um campo novo/legado nao mapeado."
      )
      next
    }
    k <- k + 1L
    achados[[k]] <- data.table::data.table(
      produto = produto_chr, coluna = cc, linha_indice = idx,
      COLETA = vec_coleta[idx], UA = vec_ua[idx], ponto_amostral = vec_ponto[idx],
      n_tokens = lengths(strsplit(x[idx], "|", fixed = TRUE)),
      n_tokens_distintos = vapply(strsplit(x[idx], "|", fixed = TRUE), function(tk) length(unique(trimws(tk))), integer(1)),
      valor_residual = x[idx], classificacao = classe,
      orientacao = "Residuo de '|' nao resolvido por indice de ponto amostral/COLETA em campo estruturado (provavel descompasso entre numero de pontos e numero de tokens, com mais de um token distinto na mesma celula -- nao e seguro resolver sem revisao humana); revisar o(s) arquivo(s) de origem desta(s) linha(s) ou tratar manualmente antes de reexportar."
    )
  }

  dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
  dir.create(file.path(output_dir, "03_auditorias", "importacao"), recursive = TRUE, showWarnings = FALSE)
  sufixo <- gsub("[^A-Za-z0-9]+", "_", produto_chr)

  if (ki) {
    achados_indet_dt <- data.table::rbindlist(achados_indet[seq_len(ki)], fill = TRUE, use.names = TRUE)
    arq_indet <- file.path(output_dir, "03_auditorias", "importacao", paste0("pipe_indeterminado_", sufixo, ".csv"))
    try({
      data.table::fwrite(achados_indet_dt, arq_indet, na = "")
      data.table::fwrite(achados_indet_dt, file.path(log_dir, paste0("pipe_indeterminado_", sufixo, "_", exec_id, ".csv")), na = "")
    }, silent = TRUE)
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      try(monitora_log_registrar_evento(
        "pipe_indeterminado", "AVISO", arq_indet,
        paste0(produto_chr, ": ", data.table::uniqueN(achados_indet_dt$linha_indice), " linha(s) com '|' em coluna(s) nao classificada(s) pelo contrato XLSForm: ", paste(unique(achados_indet_dt$coluna), collapse = ", "), " -- nao bloqueado, apenas reportado"),
        "ver relatorio pipe_indeterminado"
      ), silent = TRUE)
    }
  }

 ### - ajuste: resumo consolidado e auditável desta checagem,
 ### sempre gravado (bloqueando ou não), com contagens de preservado
 ### (texto livre/técnico tolerado), resolvido (via
 ### monitora_produtos_resolver_pipes_por_ponto, quando `auditoria_pipe` é
 ### informado), indeterminado e estruturado residual (bloqueado ou apenas
 ### reportado, conforme `bloquear`). Operação em bloco sobre os data.tables
 ### já calculados acima -- nenhuma nova varredura célula a célula.
  n_linhas_resolvidas <- 0L
  if (inherits(auditoria_pipe, "data.frame") && "n_linhas_corrigidas_por_indice_ponto" %in% names(auditoria_pipe)) {
    n_linhas_resolvidas <- sum(as.integer(auditoria_pipe$n_linhas_corrigidas_por_indice_ponto), na.rm = TRUE)
  }
  n_linhas_indeterminadas <- if (ki) data.table::uniqueN(data.table::rbindlist(achados_indet[seq_len(ki)], fill = TRUE)$linha_indice) else 0L
  n_linhas_estruturado_residual <- if (k) data.table::uniqueN(data.table::rbindlist(achados[seq_len(k)], fill = TRUE)$linha_indice) else 0L
  resumo_pipe <- data.table::data.table(
    exec_id = as.character(exec_id), produto = produto_chr, contexto = contexto_chr, bloqueio_ativo = isTRUE(bloquear),
    n_colunas_preservadas = n_colunas_preservadas, n_linhas_pipe_preservadas = n_linhas_preservadas,
    n_linhas_pipe_resolvidas_por_indice_ponto = n_linhas_resolvidas,
    n_colunas_indeterminadas = ki, n_linhas_pipe_indeterminadas = n_linhas_indeterminadas,
    n_colunas_estruturado_residual = k, n_linhas_pipe_estruturado_residual = n_linhas_estruturado_residual,
    abortou_exportacao = isTRUE(bloquear) && k > 0L,
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
  )
  try({
    data.table::fwrite(resumo_pipe, file.path(output_dir, "03_auditorias", "importacao", paste0("auditoria_pipe_residual_resumo_", sufixo, ".csv")), na = "")
    data.table::fwrite(resumo_pipe, file.path(log_dir, paste0("auditoria_pipe_residual_resumo_", sufixo, "_", exec_id, ".csv")), na = "")
  }, silent = TRUE)

  if (!k) return(invisible(dados))
  achados_dt <- data.table::rbindlist(achados[seq_len(k)], fill = TRUE, use.names = TRUE)

  n_linhas <- data.table::uniqueN(achados_dt$linha_indice)
  colunas_afetadas <- unique(achados_dt$coluna)

 ### - ajuste: `bloquear = FALSE` é reservado ao checkpoint
 ### pré-tokenização (antes da cadeia padronizacao_* original). Resíduo
 ### estruturado aqui não é necessariamente erro final -- as colunas
 ### elegíveis (ex.: as 5 colunas de forma de vida do dataset de validação) ainda serão
 ### tratadas por padronizacao_categorias_e_material_botanico,
 ### padronizacao_formas_vida_condicionais_basicas,
 ### padronizacao_formas_vida_outras, padronizacao_especies_nativas e
 ### padronizacao_especies_exoticas_e_campos_condicionais antes do produto
 ### final. Reporta para auditoria, mas não aborta a execução.
  if (!isTRUE(bloquear)) {
    detalhar_pretok <- isTRUE(get0("MONITORA_OPCAO_AUDITORIA_PRETOKENIZACAO_DETALHADA", ifnotfound = "N", inherits = TRUE) == "S")
    comprimir_pretok <- isTRUE(get0("MONITORA_OPCAO_COMPRIMIR_AUDITORIAS_VOLUMOSAS", ifnotfound = "S", inherits = TRUE) == "S")
    duplicar_log_volumoso <- isTRUE(get0("MONITORA_OPCAO_DUPLICAR_AUDITORIAS_VOLUMOSAS_LOG", ifnotfound = "N", inherits = TRUE) == "S")
    resumo_pretok <- achados_dt[, .(
      n_linhas = data.table::uniqueN(linha_indice),
      n_ocorrencias = .N,
      coletas_exemplo = paste(utils::head(unique(COLETA[!is.na(COLETA) & nzchar(COLETA)]), 20L), collapse = " | "),
      uas_exemplo = paste(utils::head(unique(UA[!is.na(UA) & nzchar(UA)]), 20L), collapse = " | "),
      valores_exemplo = paste(utils::head(unique(valor_residual[!is.na(valor_residual) & nzchar(valor_residual)]), 5L), collapse = " | ")
    ), by = .(produto, coluna, classificacao, orientacao)]
    arq_resumo <- file.path(output_dir, "03_auditorias", "importacao", paste0("resumo_auditoria_pipe_pretokenizacao_", sufixo, ".csv"))
    arq_info <- if (isTRUE(detalhar_pretok)) {
      file.path(output_dir, "03_auditorias", "importacao", paste0("auditoria_pipe_pretokenizacao_", sufixo, if (isTRUE(comprimir_pretok)) ".csv.gz" else ".csv"))
    } else arq_resumo
    try({
      data.table::fwrite(resumo_pretok, arq_resumo, na = "")
      data.table::fwrite(resumo_pretok, file.path(log_dir, paste0("resumo_auditoria_pipe_pretokenizacao_", sufixo, "_", exec_id, ".csv")), na = "")
    }, silent = TRUE)
    if (isTRUE(detalhar_pretok)) {
      gravou_detalhe <- tryCatch({ data.table::fwrite(achados_dt, arq_info, na = ""); TRUE }, error = function(e) FALSE)
      if (!isTRUE(gravou_detalhe) && isTRUE(comprimir_pretok)) {
        arq_info <- sub("\\.gz$", "", arq_info)
        data.table::fwrite(achados_dt, arq_info, na = "")
      }
      if (isTRUE(duplicar_log_volumoso)) {
        arq_log_detalhe <- file.path(log_dir, paste0("auditoria_pipe_pretokenizacao_", sufixo, "_", exec_id, if (isTRUE(comprimir_pretok)) ".csv.gz" else ".csv"))
        gravou_log_detalhe <- tryCatch({ data.table::fwrite(achados_dt, arq_log_detalhe, na = ""); TRUE }, error = function(e) FALSE)
        if (!isTRUE(gravou_log_detalhe) && isTRUE(comprimir_pretok)) {
          data.table::fwrite(achados_dt, sub("\\.gz$", "", arq_log_detalhe), na = "")
        }
      }
    }
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      try(monitora_log_registrar_evento(
        "pipe_pretokenizacao_nao_bloqueado", "AVISO", arq_info,
        paste0(produto_chr, " (contexto ", contexto_chr, "): ", n_linhas, " linha(s) com residuo de '|' em ", length(colunas_afetadas), " coluna(s) estruturada(s) (", paste(colunas_afetadas, collapse = ", "), ") no checkpoint pre-tokenizacao -- nao bloqueado, sera reavaliado apos a tokenizacao operacional (padronizacao_*)."),
        if (isTRUE(detalhar_pretok)) "ver auditoria detalhada e resumo de pré-tokenização" else "ver resumo de pré-tokenização; detalhe célula a célula está desativado por padrão para economizar I/O"
      ), silent = TRUE)
    }
    return(invisible(dados))
  }

  arq_saida <- file.path(output_dir, "03_auditorias", "importacao", paste0("bloqueio_pipe_residual_", sufixo, ".csv"))
  try({
    data.table::fwrite(achados_dt, arq_saida, na = "")
    data.table::fwrite(achados_dt, file.path(log_dir, paste0("bloqueio_pipe_residual_", sufixo, "_", exec_id, ".csv")), na = "")
  }, silent = TRUE)

 ### substitui o erro genérico ("Falha ao materializar...
 ### apos extracao de tokens por ponto") por um diagnóstico específico e
 ### legível por COLETA/UA/coluna -- exatamente a informação que alguém
 ### revisando precisa para ir direto ao arquivo de origem problemático, sem
 ### precisar abrir o CSV de auditoria primeiro. Nenhum dado novo: só
 ### agrupamento/formatação do que já está em achados_dt (COLETA/UA/ponto já
 ### resolvidos acima, uma vez, fora do loop por linha).
  resumo_coleta_ua <- if (all(c("COLETA", "UA", "coluna", "ponto_amostral") %in% names(achados_dt))) {
    ach <- data.table::as.data.table(achados_dt)
    ach[, ponto_num := suppressWarnings(as.integer(ponto_amostral))]
    ach[, .(
      n_pontos_afetados = data.table::uniqueN(linha_indice),
      pontos_min = suppressWarnings(min(ponto_num, na.rm = TRUE)),
      pontos_max = suppressWarnings(max(ponto_num, na.rm = TRUE)),
      n_tokens_tipico = as.integer(stats::median(n_tokens, na.rm = TRUE))
    ), by = .(COLETA, UA, coluna)]
  } else {
    data.table::data.table()
  }
  arq_resumo_coleta_ua <- file.path(output_dir, "03_auditorias", "importacao", paste0("bloqueio_pipe_residual_resumo_coleta_ua_", sufixo, ".csv"))
  try({
    data.table::fwrite(resumo_coleta_ua, arq_resumo_coleta_ua, na = "")
    data.table::fwrite(resumo_coleta_ua, file.path(log_dir, paste0("bloqueio_pipe_residual_resumo_coleta_ua_", sufixo, "_", exec_id, ".csv")), na = "")
  }, silent = TRUE)

  linhas_msg_coleta <- if (nrow(resumo_coleta_ua)) {
    data.table::setorder(resumo_coleta_ua, COLETA, UA)
    n_mostrar <- min(nrow(resumo_coleta_ua), 15L)
    partes <- sprintf(
      "COLETA %s / UA %s / coluna \"%s\": %d ponto(s) afetado(s) (pontos %s-%s, ~%d token(s)/celula)",
      resumo_coleta_ua$COLETA[seq_len(n_mostrar)], resumo_coleta_ua$UA[seq_len(n_mostrar)], resumo_coleta_ua$coluna[seq_len(n_mostrar)],
      resumo_coleta_ua$n_pontos_afetados[seq_len(n_mostrar)], resumo_coleta_ua$pontos_min[seq_len(n_mostrar)], resumo_coleta_ua$pontos_max[seq_len(n_mostrar)],
      resumo_coleta_ua$n_tokens_tipico[seq_len(n_mostrar)]
    )
    if (nrow(resumo_coleta_ua) > n_mostrar) partes <- c(partes, sprintf("... e mais %d grupo(s) COLETA/UA/coluna (ver %s)", nrow(resumo_coleta_ua) - n_mostrar, arq_resumo_coleta_ua))
    paste(partes, collapse = " | ")
  } else {
    paste0(length(colunas_afetadas), " coluna(s) estruturada(s) (", paste(colunas_afetadas, collapse = ", "), ")")
  }

  if (exists("monitora_log_registrar_evento", mode = "function")) {
    try(monitora_log_registrar_evento(
      "bloqueio_pipe_residual", "ERRO", arq_saida,
      paste0(produto_chr, " bloqueado: ", n_linhas, " linha(s) com residuo de '|' -- ", linhas_msg_coleta),
      "ver relatorio de bloqueio de pipe residual"
    ), silent = TRUE)
  }
  stop(
    "ACTION_REQUIRED: descompasso token×ponto em campo estruturado. Exportacao de ", produto_chr, " bloqueada: ",
    n_linhas, " linha(s) com residuo de '|' nao resolvido (mais de um token distinto na mesma celula, sem contagem de tokens compativel com o numero de pontos da COLETA -- nao resolvido as cegas para nao inventar dado). Detalhe por COLETA/UA/coluna: ",
    linhas_msg_coleta, ". Relatorio linha a linha: ", arq_saida, "; relatorio resumido por COLETA/UA: ", arq_resumo_coleta_ua, ". ",
    "Revise o(s) arquivo(s) de origem dessas COLETAs/UAs (provavel descompasso entre numero de pontos amostrais e numero de tokens separados por '|') ou trate manualmente antes de reexportar.",
    call. = FALSE
  )
}
