monitora_registros_corrig_reordenar_colunas <- function(dt) {
  dt <- monitora_dt_referenciar(dt)
  nms <- names(dt)
  cols_schema <- character(0)
  if (exists("monitora_validados_schema_embutido", mode = "function") &&
      exists("monitora_validados_resolver_coluna", mode = "function")) {
    schema <- tryCatch(monitora_validados_schema_embutido(), error = function(e) NULL)
    if (!is.null(schema) && "atributo" %in% names(schema)) {
      for (atr in schema$atributo) {
        cc <- tryCatch(monitora_validados_resolver_coluna(nms, atr), error = function(e) NA_character_)
        if (!is.na(cc) && nzchar(cc) && cc %in% nms) cols_schema <- c(cols_schema, cc)
      }
    }
  }
  cols_schema <- unique(cols_schema)
  cols_operacionais <- intersect(c(
    "DATA_MONITORA_PARSEADA", "ANO", "COLETA", "UC", "CICLO", "CAMPANHA", "EA", "UA",
    "num_placa_formatado", "PROTOCOLO", "Data (data_hora)", "Horário (data_hora)"
  ), nms)
 ### As quatro flags de checkpoint usam prefixo `monitora_` minúsculo. Elas
 ### também são metadados de auditoria e precisam permanecer junto das colunas
 ### MONITORA_* no fim do arquivo. Sem isso, uma retomada incremental sem
 ### qualquer operação apenas mudava a ordem dessas colunas e, por consequência,
 ### o hash físico do checkpoint.
  cols_auditoria <- nms[grepl("^(MONITORA_|monitora_|\\.id$|arquivo_|nome_arquivo_|md5$|tipo_entrada$)", nms, ignore.case = FALSE)]
  ordem <- unique(c(cols_schema, cols_operacionais, setdiff(nms, c(cols_schema, cols_operacionais, cols_auditoria)), cols_auditoria))
  ordem <- ordem[ordem %in% nms]
  if (length(ordem) == length(nms)) data.table::setcolorder(dt, ordem)
  invisible(dt)
}

monitora_execucao_gravar_checkpoint_parcial <- function(obj, produto = "registros_corrig.csv", motivo = MONITORA_MODO_EXECUCAO) {
  if (!inherits(obj, c("data.frame", "data.table"))) {
    stop("Checkpoint parcial exige objeto data.frame/data.table para gravação: ", produto, call. = FALSE)
  }
  dir.create(MONITORA_OUTPUT_DIR, showWarnings = FALSE, recursive = TRUE)
  dir.create(MONITORA_LOG_DIR, showWarnings = FALSE, recursive = TRUE)

  if (identical(basename(produto), "registros_corrig.csv") &&
      exists("monitora_publicacao_aa_preparar_validar_registros_corrig", mode = "function")) {
    prep <- monitora_publicacao_aa_preparar_validar_registros_corrig(
      obj,
      contexto = "pre_checkpoint_registros_corrig",
      output_dir = MONITORA_OUTPUT_DIR,
      log_dir = MONITORA_LOG_DIR,
      exec_id = MONITORA_EXEC_ID,
      abortar = TRUE
    )
    obj <- prep$registros_corrig
  }
  if (identical(basename(produto), "registros_corrig.csv") &&
      exists("monitora_replay_oraculo_validar_final", mode = "function", inherits = TRUE)) {
    monitora_replay_oraculo_validar_final(
      obj,
      contexto = paste0("checkpoint_parcial_", as.character(motivo)[1L])
    )
  }
  caminho_produto <- file.path(MONITORA_OUTPUT_DIR, produto)
  if (exists("monitora_perf_registrar_checkpoint", mode = "function")) {
    monitora_perf_registrar_checkpoint(
      "checkpoint_materializacao_registros_corrig_inicio",
      paste0("iniciando materialização do produto parcial: ", produto),
      obj
    )
  }
  if (identical(basename(produto), "registros_corrig.csv") &&
      exists("monitora_publicacao_aa_exportar_registros_corrig_aprovado", mode = "function")) {
    monitora_publicacao_aa_exportar_registros_corrig_aprovado(obj, caminho_produto, contexto = "checkpoint_parcial_registros_corrig", abortar = TRUE)
  } else {
    monitora_fwrite(obj, caminho_produto, row.names = FALSE)
  }
  if (identical(basename(produto), "registros_corrig.csv") &&
      exists("monitora_linhagem_finalizar", mode = "function", inherits = TRUE)) {
    monitora_linhagem_finalizar(caminho_produto)
  }
  if (exists("monitora_perf_registrar_checkpoint", mode = "function")) {
    monitora_perf_registrar_checkpoint(
      "checkpoint_materializacao_registros_corrig_fim",
      paste0("produto parcial gravado em disco: ", produto),
      obj
    )
  }
  if (identical(basename(produto), "registros_corrig.csv") &&
      exists("monitora_correcao_auditar_releitura_pos_export", mode = "function")) {
    monitora_correcao_auditar_releitura_pos_export(
      caminho_produto,
      contexto = "pos_export_checkpoint_registros_corrig"
    )
  }
  if (exists("monitora_perf_registrar_checkpoint", mode = "function")) {
    monitora_perf_registrar_checkpoint(
      "checkpoint_auditoria_persistencia_correcoes",
      "auditoria de persistência das correções no produto parcial concluída ou não aplicável",
      obj
    )
  }

  if (isTRUE(get0("MONITORA_GERAR_REGISTROS_VALIDADOS", ifnotfound = FALSE, inherits = TRUE)) &&
      identical(basename(produto), "registros_corrig.csv") &&
      exists("monitora_registros_validados_exportar", mode = "function")) {
    monitora_registros_validados_exportar(
      obj,
      output_dir = MONITORA_OUTPUT_DIR,
      log_dir = MONITORA_LOG_DIR,
      exec_id = MONITORA_EXEC_ID,
      abortar = FALSE,
      forcar = FALSE,
      contrato_corrig_validado = isTRUE(get0("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", ifnotfound = FALSE, inherits = TRUE))
    )
  }

  if (identical(basename(produto), "registros_corrig.csv") &&
      exists("monitora_registros_importados_auditar_comparacao_produtos", mode = "function")) {
    monitora_registros_importados_auditar_comparacao_produtos(
      output_dir = MONITORA_OUTPUT_DIR,
      log_dir = MONITORA_LOG_DIR,
      exec_id = MONITORA_EXEC_ID,
      contexto = paste0("checkpoint_parcial_", as.character(motivo)[1L])
    )
  }

  if (identical(basename(produto), "registros_corrig.csv") &&
      isTRUE(get0("MONITORA_GERAR_RELATORIO_VALIDACAO_CONSOLIDADO", ifnotfound = TRUE, inherits = TRUE)) &&
      exists("monitora_relatorio_validacao_consolidado_tentar", mode = "function")) {
    monitora_relatorio_validacao_consolidado_tentar(
      obj,
      contexto = paste0("checkpoint_parcial_", as.character(motivo)[1L])
    )
  }

  auditoria_parcial <- data.table::data.table(
    exec_id = as.character(MONITORA_EXEC_ID),
    modo_execucao = as.character(MONITORA_MODO_EXECUCAO),
    produto_checkpoint = basename(caminho_produto),
    caminho_produto = normalizePath(caminho_produto, winslash = "/", mustWork = FALSE),
    n_linhas = as.integer(NROW(obj)),
    n_colunas = as.integer(NCOL(obj)),
    estatisticas_geradas = identical(produto, "registros_corrig_stat.csv"),
    graficos_gerados = FALSE,
    kml_gerado = FALSE,
    encerramento_controlado = TRUE,
    motivo = as.character(motivo),
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
  )

  monitora_fwrite(auditoria_parcial, file.path(MONITORA_OUTPUT_DIR, "auditoria_execucao_parcial_ultima_execucao.csv"), row.names = FALSE)
  monitora_fwrite(auditoria_parcial, file.path(MONITORA_LOG_DIR, paste0("auditoria_execucao_parcial_", MONITORA_EXEC_ID, ".csv")), row.names = FALSE)

  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento(
      "execucao_parcial_controlada",
      "INFO",
      caminho_produto,
      paste0("Execução encerrada intencionalmente por MONITORA_MODO_EXECUCAO=", MONITORA_MODO_EXECUCAO, "; produto=", produto),
      "não executar auditoria final completa neste modo"
    )
  }
  if (exists("monitora_perf_registrar_checkpoint", mode = "function")) {
    monitora_perf_registrar_checkpoint(
      paste0("checkpoint_parcial_", tools::file_path_sans_ext(produto)),
      paste0("produto parcial gravado: ", produto),
      obj
    )
  }
  if (exists("monitora_gravar_manifesto_execucao", mode = "function")) {
    tryCatch(monitora_gravar_manifesto_execucao("execucao_parcial"), error = function(e) NULL)
  }
  if (exists("monitora_perf_gravar_relatorio", mode = "function")) {
    tryCatch(monitora_perf_gravar_relatorio(), error = function(e) NULL)
  }
  if (exists("MONITORA_LOG_EXECUCAO")) {
    monitora_fwrite(MONITORA_LOG_EXECUCAO, file.path(MONITORA_LOG_DIR, paste0("relatorio_execucao_", MONITORA_EXEC_ID, ".csv")), row.names = FALSE)
    monitora_fwrite(MONITORA_LOG_EXECUCAO, file.path(MONITORA_OUTPUT_DIR, "relatorio_execucao_ultima_execucao.csv"), row.names = FALSE)
  }
  if (exists("monitora_output_organizar_produtos", mode = "function")) {
    tryCatch(monitora_output_organizar_produtos(MONITORA_OUTPUT_DIR, MONITORA_EXEC_ID, contexto = paste0("checkpoint_parcial_", as.character(motivo)[1L])), error = function(e) warning("Falha ao organizar output em subpastas: ", conditionMessage(e), call. = FALSE))
  }

  if (exists("monitora_diagnostico_posix_restaurar", mode = "function")) {
    monitora_diagnostico_posix_restaurar()
  }
  message("Execução parcial concluída de forma controlada: ", produto, " | modo=", MONITORA_MODO_EXECUCAO)
  invisible(auditoria_parcial)
}



### Helpers de relatório necessários antes do modo cache.
### Em modo abrir_painel_cache, o painel é aberto antes do bloco pesado de
### processamento; portanto estes helpers precisam existir antes do desvio de cache.
monitora_relatorio_exoticas_normalizar_texto <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  x <- gsub("\\s+", " ", x, perl = TRUE)
  trimws(x)
}

monitora_relatorio_exoticas_sem_valor <- function(x) {
  z <- monitora_relatorio_exoticas_normalizar_texto(x)
  zl <- tolower(z)
 ### A concatenação nome=valor pode materializar ausência como " = ".
 ### Sequências compostas somente por separadores continuam sendo ausência.
  somente_separadores <- !nzchar(gsub("[=|;,[:space:]]+", "", z, perl = TRUE))
  !nzchar(z) | somente_separadores | zl %in% c(
    "na", "nan", "null", "none", "n/a", "não se aplica", "nao se aplica",
    "sem registro", "sem_registro", "não informado", "nao informado",
    "---", "--", "-", ".", "...", "_", "[]", "{}", "false", "falso", "0"
  )
}

monitora_relatorio_exoticas_tem_valor <- function(x) {
  !monitora_relatorio_exoticas_sem_valor(x)
}

monitora_relatorio_exoticas_normalizar_token <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  x2 <- suppressWarnings(iconv(x, from = "", to = "ASCII//TRANSLIT"))
  x[!is.na(x2)] <- x2[!is.na(x2)]
  x <- tolower(x)
  x <- gsub("[^a-z0-9_]+", "_", x, perl = TRUE)
  x <- gsub("_+", "_", x, perl = TRUE)
  x <- gsub("^_|_$", "", x, perl = TRUE)
  x
}

monitora_relatorio_exoticas_tokenizar <- function(x) {
  z <- monitora_relatorio_exoticas_normalizar_texto(x)
  z2 <- suppressWarnings(iconv(z, from = "", to = "ASCII//TRANSLIT"))
  z[!is.na(z2)] <- z2[!is.na(z2)]
  z <- tolower(z)
  z <- gsub("[,;|/]+", " ", z, perl = TRUE)
  z <- gsub("\\s+", " ", z, perl = TRUE)
  z <- trimws(z)
  lapply(strsplit(z, " ", fixed = TRUE), function(v) {
    v <- v[!is.na(v) & nzchar(v)]
    v <- monitora_relatorio_exoticas_normalizar_token(v)
    v[!is.na(v) & nzchar(v)]
  })
}

monitora_relatorio_exoticas_tem_token <- function(x, tokens) {
  tokens <- unique(monitora_relatorio_exoticas_normalizar_token(tokens))
  tokens <- tokens[!is.na(tokens) & nzchar(tokens)]
  n <- length(x)
  if (!length(tokens)) return(rep(FALSE, n))

 ### Caminho vetorizado por regex para evitar lapply +vapply
 ### linha-a-linha em relatórios pré/pós-painel. A normalização preserva a regra
 ### operacional de token completo: "exotica" não casa como substring de outra palavra.
  if (isTRUE(get0("MONITORA_OPCAO_RELATORIOS_SUPORTE_TOKEN_REGEX_VETORIZADO", ifnotfound = "S", inherits = TRUE) == "S")) {
    z <- as.character(x)
    z[is.na(z)] <- ""
    z2 <- suppressWarnings(iconv(z, from = "", to = "ASCII//TRANSLIT"))
    z[!is.na(z2)] <- z2[!is.na(z2)]
    z <- tolower(z)
    z <- gsub("[,;|/]+", " ", z, perl = TRUE)
    z <- gsub("[^a-z0-9_]+", " ", z, perl = TRUE)
    z <- gsub("\\s+", " ", z, perl = TRUE)
    z <- trimws(z)
    if (!length(z)) return(logical(0))
    tok_regex <- paste(tokens, collapse = "|")
    return(grepl(paste0("(^|\\s)(", tok_regex, ")($|\\s)"), z, perl = TRUE))
  }

  lx <- monitora_relatorio_exoticas_tokenizar(x)
  vapply(lx, function(v) any(v %in% tokens), logical(1))
}

monitora_relatorio_exoticas_resolver_colunas <- function(dt, candidatos = character(0), permitir_multiplas = TRUE) {
  nms <- names(dt)
  if (!length(nms) || !length(candidatos)) return(character(0))
  out <- character(0)
  nms_norm <- monitora_relatorio_exoticas_normalizar_token(nms)

  for (cand in candidatos) {
    if (is.na(cand) || !nzchar(as.character(cand))) next
    cand <- as.character(cand)
    if (cand %in% nms) {
      out <- c(out, cand)
      if (!isTRUE(permitir_multiplas)) return(out[1])
      next
    }

    hit_ci <- nms[tolower(nms) == tolower(cand)]
    if (length(hit_ci)) {
      out <- c(out, hit_ci[1])
      if (!isTRUE(permitir_multiplas)) return(out[1])
      next
    }

    cand_norm <- monitora_relatorio_exoticas_normalizar_token(cand)
    hit_norm <- which(nms_norm == cand_norm)
    if (length(hit_norm)) {
      out <- c(out, nms[hit_norm[1]])
      if (!isTRUE(permitir_multiplas)) return(out[1])
      next
    }
  }

  unique(out)
}

monitora_relatorio_exoticas_detectar_colunas_forma <- function(dt) {
  preferenciais <- c(
    "amostragem/registro/forma_vida_exotica",
    "forma_vida_exotica",
    "Formas de vida de plantas <span style=\"\"color:red\"\">exóticas:</span> (amostragem/registro)",
    "Formas de vida de plantas <span style=\"color:red\">exóticas:</span> (amostragem/registro)",
    "Formas de vida de plantas <span style=\"\"color:red\"\">exoticas:</span> (amostragem/registro)",
    "Formas de vida de plantas exóticas: (amostragem/registro)",
    "Formas de vida de plantas exoticas: (amostragem/registro)"
  )
  cols <- monitora_relatorio_exoticas_resolver_colunas(dt, preferenciais, permitir_multiplas = TRUE)
  nms <- names(dt)
  nms_norm <- monitora_relatorio_exoticas_normalizar_token(nms)
  padrao <- grepl("formas_de_vida_de_plantas.*exotic", nms_norm) |
    grepl("^amostragem_registro_forma_vida_exotica$", nms_norm) |
    grepl("^forma_vida_exotica$", nms_norm)
  unique(c(cols, nms[padrao]))
}

