    "amostragem/registro/forma_vida_seca_morta_palmeira" = c("Espécie ou nome popular (<span style=\"\"color:red\"\">Palmeira seca ou morta</span>) (amostragem/registro)"),
    "amostragem/registro/forma_vida_seca_morta_canela_de_ema" = c("Espécie ou nome popular (<span style=\"\"color:red\"\"> Velloziaceae seca ou morta</span>) (amostragem/registro)"),
    "amostragem/registro/foto_forma_vida_seca_morta_desconhecida02" = c("Outra foto da forma de vida desconhecida de planta seca ou morta, caso ache necessário: (amostragem/registro)"),
    "amostragem/registro/foto_forma_vida_seca_morta_desconhecida03" = c("Outra foto da forma de vida desconhecida de planta seca ou morta, caso ache necessário: (amostragem/registro)__dup1"),
    "amostragem/registro/observacao" = c("Descreva observações gerais do ponto amostral, caso necessário: (amostragem/registro)", "observacao (amostragem/registro)")
  )
}


monitora_validados_opcao_ativa <- function() {
  opcao <- get0("MONITORA_OPCAO_GERAR_REGISTROS_VALIDADOS", ifnotfound = "N", inherits = TRUE)
  opcao <- toupper(trimws(as.character(opcao)[1]))
  identical(opcao, "S")
}

monitora_validados_limpar_ausencia_saida <- function(x) {
  y <- as.character(x)
  y[is.na(y)] <- ""
  y <- trimws(y)
  z <- tolower(y)
  y[z %in% c("", "na", "n/a", "null", "nan") | y %in% c("---")] <- ""
  y
}

monitora_validados_normalizar_nome <- function(x) {
  x <- as.character(x)
  x <- gsub("<[^>]+>", " ", x, perl = TRUE)
  x <- gsub("&nbsp;", " ", x, fixed = TRUE)
  x <- gsub("[​-‍﻿]", "", x, perl = TRUE)
  y <- suppressWarnings(iconv(x, from = "", to = "ASCII//TRANSLIT"))
  y[is.na(y)] <- x[is.na(y)]
  y <- tolower(y)
  y <- gsub("__dup[0-9]+$", "", y, perl = TRUE)
  y <- gsub("\\.[0-9]+$", "", y, perl = TRUE)
  y <- gsub("[^a-z0-9]+", "_", y, perl = TRUE)
  y <- gsub("_+", "_", y, perl = TRUE)
  y <- gsub("^_|_$", "", y, perl = TRUE)
  y
}

monitora_validados_unir_aliases <- function(a, b) {
  out <- a
  for (nm in names(b)) {
    out[[nm]] <- unique(c(out[[nm]], b[[nm]]))
  }
  out
}

monitora_validados_aliases <- function() {
  monitora_validados_unir_aliases(
    monitora_validados_aliases_xlsform_historico(),
    monitora_validados_aliases_adicionais()
  )
}

monitora_validados_colunas_versãos <- function(col_template) {
  aliases <- monitora_validados_aliases()
  cand <- unique(c(
    col_template,
    aliases[[col_template]],
    sub("^.*/", "", col_template),
    toupper(col_template),
    gsub("_", " ", col_template, fixed = TRUE),
    gsub("/", " ", col_template, fixed = TRUE)
  ))
  cand[!is.na(cand) & nzchar(cand)]
}

monitora_validados_resolver_coluna <- function(nomes_dt, col_template) {
  if (is.null(nomes_dt) || !length(nomes_dt)) return(NA_character_)
  cand <- monitora_validados_colunas_versãos(col_template)
  hit <- cand[cand %in% nomes_dt]
  if (length(hit)) return(hit[1])
  nomes_lower <- tolower(nomes_dt)
  for (cc in cand) {
    hit_i <- which(nomes_lower == tolower(cc))
    if (length(hit_i)) return(nomes_dt[hit_i[1]])
  }
  nomes_norm <- monitora_validados_normalizar_nome(nomes_dt)
  cand_norm <- monitora_validados_normalizar_nome(cand)
  hit_i <- match(cand_norm, nomes_norm, nomatch = 0L)
  hit_i <- hit_i[hit_i > 0L]
  if (length(hit_i)) return(nomes_dt[hit_i[1]])
  NA_character_
}

monitora_validados_primeira_coluna <- function(dt, candidatos) {
  for (cc in candidatos) {
    col <- monitora_validados_resolver_coluna(names(dt), cc)
    if (!is.na(col) && col %in% names(dt)) return(col)
  }
  NA_character_
}

monitora_validados_colunas_presentes <- function(dt, candidatos) {
  nomes_dt <- names(dt)
  if (!length(nomes_dt)) return(character())
  candidatos <- unique(unlist(lapply(
    as.character(candidatos),
    monitora_validados_colunas_versãos
  ), use.names = FALSE))
  candidatos <- candidatos[!is.na(candidatos) & nzchar(candidatos)]
  if (!length(candidatos)) return(character())

  nomes_lower <- tolower(nomes_dt)
  nomes_norm <- monitora_validados_normalizar_nome(nomes_dt)
  presentes <- character()
  for (cc in candidatos) {
    hit <- which(nomes_dt == cc)
    if (!length(hit)) hit <- which(nomes_lower == tolower(cc))
    if (!length(hit)) {
      cc_norm <- monitora_validados_normalizar_nome(cc)
      hit <- which(nomes_norm == cc_norm)
    }
    if (length(hit)) presentes <- c(presentes, nomes_dt[hit])
  }
  unique(presentes)
}

monitora_validados_pegar <- function(
  dt,
  candidatos,
  n = nrow(dt),
  bloquear_conflito = TRUE
) {
  cols <- monitora_validados_colunas_presentes(dt, candidatos)
  if (!length(cols)) {
    return(list(valor = rep("", n), coluna = NA_character_, colunas = character()))
  }

  valores <- lapply(cols, function(col) {
    monitora_validados_limpar_ausencia_saida(dt[[col]])
  })
  out <- rep("", n)
  origem_linha <- rep("", n)
  for (ii in seq_along(cols)) {
    valor <- valores[[ii]]
    conflito <- nzchar(out) & nzchar(valor) & out != valor
    if (isTRUE(bloquear_conflito) && any(conflito)) {
      exemplos <- utils::head(which(conflito), 10L)
      stop(
        "Aliases físicos divergentes para o mesmo atributo nas linhas ",
        paste(exemplos, collapse = " | "),
        ": ", paste(cols, collapse = " | "),
        ". A publicação foi bloqueada para não escolher um valor silenciosamente.",
        call. = FALSE
      )
    }
    preencher <- !nzchar(out) & nzchar(valor)
    if (any(preencher)) {
      out[preencher] <- valor[preencher]
      origem_linha[preencher] <- cols[ii]
    }
  }
  contribuintes <- cols[vapply(valores, function(x) any(nzchar(x)), logical(1L))]
  list(
    valor = out,
    coluna = if (length(contribuintes)) paste(contribuintes, collapse = " + ") else cols[1L],
    colunas = cols,
    coluna_por_linha = origem_linha
  )
}

monitora_validados_pegar_normalizado <- function(dt, candidatos, formato, largura = NA_integer_, n = nrow(dt)) {
 ### Aliases do mesmo atributo podem usar representações textuais equivalentes
 ### (data ISO, datetime, timezone). Compara somente depois de normalizar pelo
 ### formato do schema; divergência semântica real continua bloqueante.
  cols <- monitora_validados_colunas_presentes(dt, candidatos)
  if (!length(cols)) return(list(valor = rep("", n), coluna = NA_character_, colunas = character()))
  valores <- lapply(cols, function(col) {
    monitora_validados_formatar_valor(dt[[col]], formato, largura)
  })
  out <- rep("", n)
  for (ii in seq_along(cols)) {
    valor <- valores[[ii]]
    conflito <- nzchar(out) & nzchar(valor) & out != valor
    if (any(conflito)) {
      exemplos <- utils::head(which(conflito), 10L)
      stop(
        "Aliases físicos divergentes após normalização para ", formato,
        " nas linhas ", paste(exemplos, collapse = " | "),
        ": ", paste(cols, collapse = " | "),
        ". A publicação foi bloqueada para não escolher um valor silenciosamente.",
        call. = FALSE
      )
    }
    preencher <- !nzchar(out) & nzchar(valor)
    if (any(preencher)) out[preencher] <- valor[preencher]
  }
  contribuintes <- cols[vapply(valores, function(x) any(nzchar(x)), logical(1L))]
  list(
    valor = out,
    coluna = if (length(contribuintes)) paste(contribuintes, collapse = " + ") else cols[1L],
    colunas = cols
  )
}


monitora_validados_hora_hms_millis_tz_regex <- function() {
  "^(?:[01][0-9]|2[0-3]):[0-5][0-9]:[0-5][0-9][.][0-9]{3}-03:00$"
}

monitora_validados_normalizar_hora_hms_millis_tz <- function(x, tz_padrao = "-03:00") {
  y <- monitora_validados_limpar_ausencia_saida(x)
  y[is.na(y)] <- ""
  vazio <- !nzchar(y)
  out <- y
  if (all(vazio)) return(out)

  tz_padrao <- as.character(tz_padrao)[1]
  if (is.na(tz_padrao) || !grepl("^[+-][0-9]{2}:[0-9]{2}$", tz_padrao, perl = TRUE)) tz_padrao <- "-03:00"

  yy <- trimws(y[!vazio])
  yy <- gsub("T", " ", yy, fixed = TRUE)
  yy <- gsub(",", ".", yy, fixed = TRUE)

 ## contrato único para data_hora/hora. Aceita HH:MM,
 ## HH:MM:SS, HH:MM:SS.mmm, hora com fuso -0300/-03:00, datetime
 ## completo/ISO com T e separador histórico com hífen (HH-MM ou
 ## HH-MM-SS). Emite sempre HH:MM:SS.mmm-03:00. Valores não
 ## interpretáveis são preservados para bloqueio explícito pelo validador.
  yy <- sub(
    "^([0-9]{1,2})-([0-9]{2})(?:-([0-9]{2})([.][0-9]{1,9})?)?\\s*([+-][0-9]{2}:?[0-9]{2}|Z)?$",
    "\\1:\\2:\\3\\4\\5",
    yy,
    perl = TRUE
  )
  yy <- sub(":([+-][0-9]{2}:?[0-9]{2}|Z)$", ":00\\1", yy, perl = TRUE)
  yy <- sub(":$", ":00", yy, perl = TRUE)
  yy <- sub(
    "([[:space:]])([0-9]{1,2})-([0-9]{2})(?:-([0-9]{2})([.][0-9]{1,9})?)?\\s*([+-][0-9]{2}:?[0-9]{2}|Z)?$",
    "\\1\\2:\\3:\\4\\5\\6",
    yy,
    perl = TRUE
  )
  yy <- sub(":([+-][0-9]{2}:?[0-9]{2}|Z)$", ":00\\1", yy, perl = TRUE)
  yy <- sub(":$", ":00", yy, perl = TRUE)

  pat <- "(^|[^0-9+-])([0-9]{1,2}):([0-9]{2})(?::([0-9]{2})([.][0-9]{1,9})?)?\\s*([+-][0-9]{2}:?[0-9]{2}|Z)?"
  m <- regexec(pat, yy, perl = TRUE)
  r <- regmatches(yy, m)
  ok <- lengths(r) > 0L

  if (any(ok)) {
    idx_ok <- which(ok)
    norm <- yy[idx_ok]
    for (jj in seq_along(idx_ok)) {
      z <- r[[idx_ok[jj]]]
      hh <- suppressWarnings(as.integer(z[3L]))
      mi <- suppressWarnings(as.integer(z[4L]))
      ss_txt <- if (length(z) >= 5L && nzchar(z[5L])) z[5L] else "00"
      ss <- suppressWarnings(as.integer(ss_txt))
      frac <- if (length(z) >= 6L) z[6L] else ""

      valido <- !is.na(hh) && !is.na(mi) && !is.na(ss) &&
        hh >= 0L && hh <= 23L && mi >= 0L && mi <= 59L && ss >= 0L && ss <= 59L

      if (isTRUE(valido)) {
        ms <- if (nzchar(frac)) sub("^[.]", "", frac, perl = TRUE) else ""
        ms <- substr(paste0(ms, "000"), 1L, 3L)
        norm[jj] <- sprintf("%02d:%02d:%02d.%s%s", hh, mi, ss, ms, tz_padrao)
      }
    }
    yy[idx_ok] <- norm
  }

  out[!vazio] <- yy
  out[is.na(out)] <- ""
  out
}

monitora_validados_auditar_hora_hms_millis_tz <- function(original,
                                                           normalizado,
                                                           atributo = "data_hora/hora",
                                                           coluna_origem = NA_character_) {
  ori <- monitora_validados_limpar_ausencia_saida(original)
  nor <- monitora_validados_limpar_ausencia_saida(normalizado)
  ori[is.na(ori)] <- ""
  nor[is.na(nor)] <- ""
  contrato <- monitora_validados_hora_hms_millis_tz_regex()
  tem_origem <- nzchar(ori)
  ok <- nzchar(nor) & grepl(contrato, nor, perl = TRUE)
  incompat <- tem_origem & !ok
  normalizados <- tem_origem & ok
  alterados <- normalizados & ori != nor

  exemplos_idx <- which(incompat)
  if (!length(exemplos_idx)) exemplos_idx <- which(alterados)
  exemplos <- character()
  if (length(exemplos_idx)) {
    exemplos <- unique(paste0(ori[exemplos_idx], " -> ", nor[exemplos_idx]))
  }

  data.table::data.table(
    atributo = as.character(atributo)[1],
    coluna_origem_registros_corrig = ifelse(is.na(as.character(coluna_origem)[1]) || !nzchar(as.character(coluna_origem)[1]), NA_character_, as.character(coluna_origem)[1]),
    contrato_saida = "HH:MM:SS.mmm-03:00",
    regex_contrato = contrato,
    n_total = length(ori),
    n_vazios = sum(!tem_origem),
    n_normalizados = sum(normalizados),
    n_alterados_pela_normalizacao = sum(alterados),
    n_incompativeis = sum(incompat),
    exemplos_protegidos = paste(utils::head(exemplos, 10L), collapse = " | "),
    bloqueante = sum(incompat) > 0L,
    motivo_bloqueio = if (sum(incompat) > 0L) "hora_incompativel_com_contrato_hms_millis_tz" else ""
  )
}

monitora_validados_formatar_valor <- function(x, formato = "texto", largura = NA_integer_) {
  y <- monitora_validados_limpar_ausencia_saida(x)
  vazio <- !nzchar(y)
  if (identical(formato, "datetime_iso_espaco")) {
    y[!vazio] <- gsub("T", " ", y[!vazio], fixed = TRUE)
    y[!vazio] <- sub("^([0-9]{4}-[0-9]{2}-[0-9]{2})[[:space:]]+([0-9]{2}:[0-9]{2}:[0-9]{2}).*$", "\\1 \\2", y[!vazio], perl = TRUE)
    y[!vazio & grepl("^[0-9]{4}-[0-9]{2}-[0-9]{2}$", y, perl = TRUE)] <- paste0(y[!vazio & grepl("^[0-9]{4}-[0-9]{2}-[0-9]{2}$", y, perl = TRUE)], " 00:00:00")
  } else if (identical(formato, "data_iso")) {
    idx_dt <- !vazio & grepl("^[0-9]{4}-[0-9]{2}-[0-9]{2}", y, perl = TRUE)
    y[idx_dt] <- sub("^([0-9]{4}-[0-9]{2}-[0-9]{2}).*$", "\\1", y[idx_dt], perl = TRUE)
  } else if (identical(formato, "hora_hms_millis_tz")) {
    y <- monitora_validados_normalizar_hora_hms_millis_tz(y, tz_padrao = "-03:00")
  } else if (identical(formato, "inteiro_texto_zero_esquerda")) {
    idx <- !vazio & grepl("^[0-9]+(\\.0+)?$", y, perl = TRUE)
    dig <- sub("\\.0+$", "", y[idx], perl = TRUE)
    if (!is.na(largura) && largura > 1L && length(dig)) {
      dig <- paste0(vapply(pmax(0L, largura - nchar(dig)), function(nz) paste(rep("0", nz), collapse = ""), character(1)), dig)
    }
    y[idx] <- dig
  } else if (identical(formato, "inteiro_texto")) {
    idx <- !vazio & grepl("^[0-9]+(\\.0+)?$", y, perl = TRUE)
    y[idx] <- sub("\\.0+$", "", y[idx], perl = TRUE)
  } else if (identical(formato, "numero_texto_ponto")) {
    y[!vazio] <- gsub(",", ".", y[!vazio], fixed = TRUE)
    y[!vazio] <- sub("^([0-9]+)\\.0+$", "\\1", y[!vazio], perl = TRUE)
  }
  y[is.na(y)] <- ""
  y
}

### ativação tardia do wrapper por valores distintos. Este ponto fica
### depois da definição original de monitora_validados_formatar_valor; a seção
### de helpers é carregada antes, então o if inicial pode ter sido falso.
if (exists("monitora_validados_formatar_valor", mode = "function") &&
    !exists("monitora_validados_formatar_valor_base_publicacao_aj", mode = "function")) {
  monitora_validados_formatar_valor_base_publicacao_aj <- monitora_validados_formatar_valor
  monitora_validados_formatar_valor <- function(x, formato = "texto", largura = NA_integer_) {
    n <- length(x)
    if (n < 512L) return(monitora_validados_formatar_valor_base_publicacao_aj(x, formato, largura))
    y0 <- monitora_validados_limpar_ausencia_saida(x)
    y0[is.na(y0)] <- ""
    u <- unique(y0)
    if (length(u) > max(512L, as.integer(n * 0.80))) {
      return(monitora_validados_formatar_valor_base_publicacao_aj(x, formato, largura))
    }
    fu <- monitora_validados_formatar_valor_base_publicacao_aj(u, formato, largura)
    fu[is.na(fu)] <- ""
    unname(fu[match(y0, u)])
  }
}

monitora_validados_hex8_num <- function(num) {
  digs <- strsplit("0123456789abcdef", "", fixed = TRUE)[[1]]
  vapply(num, function(z) {
    z <- floor(as.numeric(z) %% 4294967296)
    out <- rep("0", 8L)
    for (ii in 8L:1L) {
      r <- z %% 16
      out[ii] <- digs[r + 1L]
      z <- floor(z / 16)
    }
    paste0(out, collapse = "")
  }, character(1))
}

monitora_validados_hash32 <- function(x, salt = "") {
  x <- paste0(as.character(salt), "||", as.character(x))
  vapply(x, function(s) {
    raw <- charToRaw(enc2utf8(s))
    h <- 2166136261
    if (length(raw)) {
      for (bb in as.integer(raw)) {
        h <- bitwXor(as.integer(h %% 2147483647), as.integer(bb))
        h <- (as.numeric(h) * 16777619) %% 4294967296
      }
    }
    monitora_validados_hex8_num(h)
  }, character(1), USE.NAMES = FALSE)
}

monitora_validados_uuid_deterministico <- function(chave, nivel = "registro") {
  chave <- monitora_validados_limpar_ausencia_saida(chave)
  chave[!nzchar(chave)] <- paste0("sem_chave_", seq_along(chave))
  h1 <- monitora_validados_hash32(chave, paste0(nivel, "_1"))
  h2 <- monitora_validados_hash32(chave, paste0(nivel, "_2"))
  h3 <- monitora_validados_hash32(chave, paste0(nivel, "_3"))
  h4 <- monitora_validados_hash32(chave, paste0(nivel, "_4"))
  h5 <- monitora_validados_hash32(chave, paste0(nivel, "_5"))
  paste0(h1, "-", substr(h2, 1L, 4L), "-", substr(h3, 1L, 4L), "-", substr(h4, 1L, 4L), "-", h5, substr(h2, 5L, 8L))
}

monitora_validados_uuid_valido <- function(x) {
  x <- monitora_validados_limpar_ausencia_saida(x)
  nzchar(x) & grepl("^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$", x, perl = TRUE)
}

monitora_validados_chave_coleta <- function(dt) {
  n <- nrow(dt)
  campos <- c("PROTOCOLO", "UC", "CICLO", "CAMPANHA", "EA", "UA", "COLETA")
  vals <- lapply(campos, function(cc) {
    col <- monitora_validados_primeira_coluna(dt, c(cc, tolower(cc)))
    if (!is.na(col) && col %in% names(dt)) monitora_validados_limpar_ausencia_saida(dt[[col]]) else rep("", n)
  })
  do.call(paste, c(vals, sep = "|"))
}

monitora_validados_chave_registro <- function(dt) {
  n <- nrow(dt)
  campos <- list(
    c("PROTOCOLO", "protocolo"), c("UC", "uc"), c("CICLO", "ciclo"), c("CAMPANHA", "campanha"),
    c("EA", "ea"), c("UA", "ua"), c("COLETA", "coleta"),
    c("ponto_amostral (amostragem/registro)", "amostragem/registro/ponto_amostral"),
    c("ponto_metro (amostragem/registro)", "amostragem/registro/ponto_metro")
  )
  vals <- lapply(campos, function(cands) {
    col <- monitora_validados_primeira_coluna(dt, cands)
    if (!is.na(col) && col %in% names(dt)) monitora_validados_limpar_ausencia_saida(dt[[col]]) else rep("", n)
  })
  do.call(paste, c(vals, sep = "|"))
}

monitora_validados_uuid_por_coleta_ou_sintetico <- function(dt, alvo = c("coleta_uuid", "uuid")) {
  alvo <- match.arg(alvo)
  n <- nrow(dt)
  coleta <- monitora_validados_limpar_ausencia_saida(
    monitora_validados_pegar(dt, c("COLETA", "coleta"), n)$valor
  )
  chave_coleta <- monitora_validados_chave_coleta(dt)
  nivel_sintetico <- paste0(alvo, "_deterministico")
 ### O fallback precisa ter cardinalidade de COLETA, não cardinalidade de
 ### linha. Campos administrativos esparsos podem produzir chaves compostas
 ### diferentes dentro da mesma COLETA; por isso COLETA, quando presente, é a
 ### identidade determinística comum. Linhas sem COLETA conservam a chave
 ### composta e, em último caso, o índice global.
  uuid_sintetico_indices <- function(idx) {
    idx <- unique(as.integer(idx))
    idx <- idx[!is.na(idx) & idx >= 1L & idx <= n]
    if (!length(idx)) return(character())
    ch <- monitora_validados_limpar_ausencia_saida(chave_coleta[idx])
    tem_coleta <- nzchar(coleta[idx])
    if (any(tem_coleta)) ch[tem_coleta] <- paste0("coleta=", coleta[idx][tem_coleta])
    vazio <- !nzchar(ch)
    if (any(vazio)) ch[vazio] <- paste0("sem_chave_", idx[vazio])
    monitora_validados_uuid_deterministico(ch, nivel_sintetico)
  }
  candidatos <- if (identical(alvo, "coleta_uuid")) {
    c("coleta_uuid", "COLETA_UUID", "uuid_coleta", "UUID_COLETA")
  } else {
    c("uuid", "UUID_COLETA_FORMULARIO", "uuid_formulario", "uuid_coleta_formulario")
  }
 ### `uuid` minúsculo é UUID pai da coleta no template; `UUID` maiúsculo e
 ### `uuid (amostragem/registro)` são identidades de linha. O resolvedor geral
 ### é intencionalmente case-insensitive, portanto não pode ser usado para o
 ### candidato curto `uuid`, sob risco de promover UUID de registro a UUID de
 ### coleta. Nomes longos e inequívocos continuam aceitos sem depender do
 ### conjunto de colunas do dataset.
  if (identical(alvo, "uuid")) {
    nomes_dt <- names(dt)
    if ("uuid" %in% nomes_dt) {
      col <- "uuid"
    } else {
      especificos <- candidatos[-1L]
      hit <- match(tolower(especificos), tolower(nomes_dt), nomatch = 0L)
      hit <- hit[hit > 0L]
      col <- if (length(hit)) nomes_dt[hit[1L]] else NA_character_
    }
  } else {
    col <- monitora_validados_primeira_coluna(dt, candidatos)
  }
  if (!is.na(col) && col %in% names(dt)) {
    v <- monitora_validados_limpar_ausencia_saida(dt[[col]])
    ok_uuid <- nzchar(v) & monitora_validados_uuid_valido(v)
    aux <- data.table::data.table(coleta = coleta, valor = v)
    aux <- aux[nzchar(coleta) & ok_uuid]
    card <- if (nrow(aux)) {
      aux[, .(
        n_valores = data.table::uniqueN(valor),
        valor = sort(unique(valor))[1L]
      ), by = coleta]
    } else {
      data.table::data.table(coleta = character(), n_valores = integer(), valor = character())
    }
    if (nrow(card)) {
      data.table::setkey(card, coleta)
      idx_fill <- which(!ok_uuid & nzchar(coleta))
      if (length(idx_fill)) {
        chave_fill <- data.table::data.table(as.character(coleta[idx_fill]))
        data.table::setnames(chave_fill, "coleta")
        preench <- card[chave_fill, on = "coleta", valor]
        ok <- !is.na(preench) & nzchar(preench)
        if (any(ok)) v[idx_fill[ok]] <- preench[ok]
      }
    }
    idx_sint <- which(!monitora_validados_uuid_valido(v))
    if (length(idx_sint)) v[idx_sint] <- uuid_sintetico_indices(idx_sint)
   ## COLETAS com mais de um UUID válido observado permanecem divergentes:
   ## não são sobrescritas pelo fallback e serão bloqueadas pela auditoria de
   ## cardinalidade. Apenas ausências/valores inválidos recebem complemento.
    return(list(valor = v, coluna = col, estrategia = paste0("mapeada_complementada_", alvo, "_deterministico_por_coleta")))
  }
  v_sint <- uuid_sintetico_indices(seq_len(n))
  list(valor = v_sint, coluna = NA_character_, estrategia = paste0("sintetizada_", alvo, "_deterministico_por_coleta"))
}

monitora_validados_uuid_registro_ou_sintetico <- function(dt) {
  n <- nrow(dt)
  candidatos <- c("MONITORA_UUID_REGISTRO_CANONICO", "amostragem/registro/uuid", "uuid (amostragem/registro)", "UUID_REGISTRO", "uuid_registro", "UUID")
  out <- rep("", n)
  fonte <- rep("", n)
  for (cc in candidatos) {
    col <- monitora_validados_primeira_coluna(dt, cc)
    if (!is.na(col) && col %in% names(dt)) {
      v <- monitora_validados_limpar_ausencia_saida(dt[[col]])
      ok <- nzchar(v) & !grepl("\\|", v, fixed = FALSE) & monitora_validados_uuid_valido(v)
      preencher <- !nzchar(out) & ok
      if (any(preencher)) {
        out[preencher] <- v[preencher]
        fonte[preencher] <- col
      }
    }
  }
  row_id_col <- intersect(c("MONITORA_ROW_ID", ".id"), names(dt))[1L]
  row_id <- if (!is.na(row_id_col)) monitora_validados_limpar_ausencia_saida(dt[[row_id_col]]) else rep("", n)
  seed <- paste0(monitora_validados_chave_registro(dt), "|row_id=", row_id, "|linha=", seq_len(n))
  ausente <- !nzchar(out)
  if (any(ausente)) {
    out[ausente] <- monitora_validados_uuid_deterministico(seed[ausente], "uuid_registro_deterministico_por_linha")
    fonte[ausente] <- "sintese_deterministica_por_linha"
  }
  duplicado <- duplicated(out) | duplicated(out, fromLast = TRUE)
  if (any(duplicado)) {
    grupos <- split(which(duplicado), out[duplicado])
    for (idx_grupo in grupos) {
      if (length(idx_grupo) <= 1L) next
      idx_substituir <- idx_grupo[-1L]
      out[idx_substituir] <- monitora_validados_uuid_deterministico(seed[idx_substituir], "uuid_registro_colisao_validado")
      fonte[idx_substituir] <- "sintese_deterministica_colisao_por_linha"
    }
  }
  colunas_usadas <- unique(fonte[nzchar(fonte) & !grepl("^sintese_", fonte)])
  list(
    valor = out,
    coluna = if (length(colunas_usadas) == 1L) colunas_usadas[1L] else NA_character_,
    estrategia = if (all(!grepl("^sintese_", fonte))) "mapeada_uuid_unico_por_registro" else "mapeada_com_fallback_deterministico_somente_por_linha"
  )
}

monitora_validados_derive_datetime <- function(dt, alvo = c("data_do_registro", "data_do_recebimento")) {
  alvo <- match.arg(alvo)
  n <- nrow(dt)
  direto <- monitora_validados_pegar_normalizado(
    dt, c(alvo, toupper(alvo), gsub("_", " ", alvo, fixed = TRUE)),
    formato = "datetime_iso_espaco", n = n
  )
  v <- direto$valor
  if (any(nzchar(v))) return(list(valor = v, coluna = direto$coluna, estrategia = "mapeada_datetime"))
  if (identical(alvo, "data_do_registro")) {
    rec <- monitora_validados_pegar_normalizado(
      dt, c("data_do_recebimento", "DATA DO RECEBIMENTO", "Data do recebimento"),
      formato = "datetime_iso_espaco", n = n
    )
    v <- rec$valor
    if (any(nzchar(v))) return(list(valor = v, coluna = rec$coluna, estrategia = "derivada_de_data_do_recebimento"))
  }
  data <- monitora_validados_pegar_normalizado(
    dt, c("data_hora/data", "Data (data_hora)", "DATA_MONITORA_PARSEADA"),
    formato = "data_iso", n = n
  )
  hora <- monitora_validados_pegar_normalizado(
    dt, c("data_hora/hora", "Horário (data_hora)", "Hora (data_hora)"),
    formato = "hora_hms_millis_tz", n = n
  )
  d <- data$valor
  h <- hora$valor
  h <- sub("^([0-9]{2}:[0-9]{2}:[0-9]{2}).*$", "\\1", h, perl = TRUE)
  h[!grepl("^[0-9]{2}:[0-9]{2}:[0-9]{2}$", h, perl = TRUE)] <- "00:00:00"
  v <- ifelse(nzchar(d), paste(d, h), "")
  list(valor = v, coluna = paste(c(data$coluna, hora$coluna)[!is.na(c(data$coluna, hora$coluna))], collapse = " + "), estrategia = "derivada_de_data_hora_campo")
}

monitora_validados_derive_data_hora <- function(dt, alvo = c("data", "hora")) {
  alvo <- match.arg(alvo)
  n <- nrow(dt)
  if (identical(alvo, "data")) {
    p <- monitora_validados_pegar_normalizado(
      dt, c("data_hora/data", "Data (data_hora)", "DATA_MONITORA_PARSEADA"),
      formato = "data_iso", n = n
    )
    if (!any(nzchar(p$valor))) {
      p <- monitora_validados_pegar_normalizado(
        dt, c("data_do_registro", "DATA DO REGISTRO"),
        formato = "data_iso", n = n
      )
    }
    if (!any(nzchar(p$valor))) {
      p <- monitora_validados_pegar_normalizado(
        dt, c("data_do_recebimento", "DATA DO RECEBIMENTO"),
        formato = "data_iso", n = n
      )
    }
    return(list(valor = p$valor, coluna = p$coluna, estrategia = ifelse(is.na(p$coluna), "sem_origem", "mapeada_ou_derivada_data")))
  }
  p <- monitora_validados_pegar_normalizado(
    dt, c("data_hora/hora", "Horário (data_hora)", "Hora (data_hora)"),
    formato = "hora_hms_millis_tz", n = n
  )
  if (!any(nzchar(p$valor))) {
    p <- monitora_validados_pegar_normalizado(
      dt, c("data_do_registro", "DATA DO REGISTRO"),
      formato = "hora_hms_millis_tz", n = n
    )
  }
  if (!any(nzchar(p$valor))) {
    p <- monitora_validados_pegar_normalizado(
      dt, c("data_do_recebimento", "DATA DO RECEBIMENTO"),
      formato = "hora_hms_millis_tz", n = n
    )
  }
  v <- p$valor
  if (!any(nzchar(v))) v <- rep("00:00:00.000-03:00", n)
  list(valor = v, coluna = p$coluna, estrategia = ifelse(is.na(p$coluna), "sintetizada_hora_padrao_00", "mapeada_ou_derivada_hora"))
}

monitora_validados_numero_ua <- function(dt, n = nrow(dt)) {
  ua <- monitora_validados_pegar(dt, c("UA", "ua"), n)
  v <- monitora_validados_limpar_ausencia_saida(ua$valor)
  out <- rep("", n)
  idx <- nzchar(v) & grepl("UA[-_ ]*0*[0-9]+", toupper(v), perl = TRUE)
  if (any(idx)) {
    out[idx] <- sub("^.*UA[-_ ]*0*([0-9]+).*$", "\\1", toupper(v[idx]), perl = TRUE)
  }
  list(valor = out, coluna = ua$coluna)
}

monitora_validados_extrair_digitos <- function(x) {
  y <- monitora_validados_limpar_ausencia_saida(x)
  out <- rep("", length(y))
  idx_num <- nzchar(y) & grepl("^[0-9]+([,.]0+)?$", y, perl = TRUE)
  if (any(idx_num)) {
    out[idx_num] <- sub("[,.]0+$", "", y[idx_num], perl = TRUE)
  }
  idx_emb <- !nzchar(out) & nzchar(y) & grepl("[0-9]+", y, perl = TRUE)
  if (any(idx_emb)) {
    out[idx_emb] <- sub("^.*?([0-9]+).*$", "\\1", y[idx_emb], perl = TRUE)
  }
  out
}

monitora_validados_formatar_inteiro_largura <- function(x, largura = NA_integer_) {
  y <- monitora_validados_extrair_digitos(x)
  idx <- nzchar(y)
  if (!is.na(largura) && largura > 1L && any(idx)) {
    y[idx] <- paste0(vapply(pmax(0L, largura - nchar(y[idx])), function(nz) paste(rep("0", nz), collapse = ""), character(1)), y[idx])
  }
  y
}

monitora_validados_coalesce_nao_vazio <- function(vals, n) {
  out <- rep("", n)
  for (vv in vals) {
    vv <- monitora_validados_limpar_ausencia_saida(vv)
    idx <- !nzchar(out) & nzchar(vv)
    if (any(idx)) out[idx] <- vv[idx]
  }
  out
}

monitora_validados_preencher_por_coleta <- function(dt, v, padrao = "") {
  v <- monitora_validados_limpar_ausencia_saida(v)
  n <- length(v)
  coleta <- monitora_validados_pegar(dt, c("COLETA", "coleta"), n)$valor
  if (length(coleta) == n && any(!nzchar(v) & nzchar(coleta))) {
    aux <- data.table::data.table(.coleta = coleta, .valor = v)
    mapa <- aux[nzchar(.coleta) & nzchar(.valor), .(.valor = .valor[1L]), by = .coleta]
    if (nrow(mapa)) {
      setkey(mapa, .coleta)
      idx <- which(!nzchar(v) & nzchar(coleta))
      preench <- mapa[data.table::data.table(.coleta = coleta[idx]), on = ".coleta", .valor]
      ok <- !is.na(preench) & nzchar(preench)
      if (any(ok)) v[idx[ok]] <- preench[ok]
    }
  }
  if (nzchar(padrao)) v[!nzchar(v)] <- padrao
  v
}

monitora_validados_coalesce_vetor <- function(..., n) {
  vals <- list(...)
  out <- rep("", n)
  for (vv in vals) {
    vv <- monitora_validados_limpar_ausencia_saida(vv)
    idx <- !nzchar(out) & nzchar(vv)
    if (any(idx)) out[idx] <- vv[idx]
  }
  out
}

monitora_validados_derivar_num_placa <- function(dt, alvo = c("num_placa", "num_placa_formatado")) {
  alvo <- match.arg(alvo)
  n <- nrow(dt)
  p_fmt <- monitora_validados_pegar(dt, c("Número da plaqueta formatado (amostragem)", "amostragem/num_placa_formatado", "num_placa_formatado"), n)
  p_num <- monitora_validados_pegar(dt, c("Número da plaqueta (amostragem)", "amostragem/num_placa", "num_placa"), n)
  p_ua <- monitora_validados_numero_ua(dt, n)

 ## não preservar texto inválido em campos de plaqueta. Usa-se
 ## extração numérica defensiva e fallback para UA; isso mantém o contrato
 ## de inteiro textual com zero à esquerda sem inventar valores quando já há
 ## número recuperável.
  if (identical(alvo, "num_placa")) {
    v <- monitora_validados_coalesce_nao_vazio(list(
      monitora_validados_extrair_digitos(p_num$valor),
      monitora_validados_extrair_digitos(p_fmt$valor),
      monitora_validados_extrair_digitos(p_ua$valor)
    ), n = n)
    v <- monitora_validados_formatar_inteiro_largura(v, 3L)
    origem <- paste(unique(c(p_num$coluna, p_fmt$coluna, p_ua$coluna)[!is.na(c(p_num$coluna, p_fmt$coluna, p_ua$coluna))]), collapse = " + ")
    return(list(valor = v, coluna = origem, estrategia = "mapeada_ou_derivada_num_placa_por_digitos_ua"))
  }

  v <- monitora_validados_coalesce_nao_vazio(list(
    monitora_validados_extrair_digitos(p_fmt$valor),
    monitora_validados_extrair_digitos(p_num$valor),
    monitora_validados_extrair_digitos(p_ua$valor)
  ), n = n)
  v <- monitora_validados_formatar_inteiro_largura(v, 4L)
  origem <- paste(unique(c(p_fmt$coluna, p_num$coluna, p_ua$coluna)[!is.na(c(p_fmt$coluna, p_num$coluna, p_ua$coluna))]), collapse = " + ")
  list(valor = v, coluna = origem, estrategia = "mapeada_ou_derivada_num_placa_formatado_por_digitos_ua")
}


monitora_validados_norm_ascii <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  y <- iconv(x, from = "", to = "ASCII//TRANSLIT", sub = "")
  y[is.na(y)] <- ""
  y <- tolower(y)
  y <- gsub("[^a-z0-9]+", "_", y, perl = TRUE)
  y <- gsub("^_+|_+$", "", y, perl = TRUE)
  y
}

monitora_validados_xlsform21_meta <- function() {
  cache <- get0("MONITORA_PUBLICACAO_AE_XLSFORM21_META_CACHE", ifnotfound = NULL, inherits = TRUE)
  if (is.list(cache) && !is.null(cache$campos) && !is.null(cache$opcoes)) return(cache)
  if (exists("monitora_correcao_xlsforms_embutidos", mode = "function")) {
    meta <- monitora_correcao_xlsforms_embutidos_cache_publicacao_ae()
  } else {
    meta <- list(campos = data.table::data.table(), opcoes = data.table::data.table(), dependencias = data.table::data.table(), arquivos = data.table::data.table())
  }
  if (is.null(meta$campos)) meta$campos <- data.table::data.table()
  if (is.null(meta$opcoes)) meta$opcoes <- data.table::data.table()
  meta$campos <- data.table::as.data.table(meta$campos)
  meta$opcoes <- data.table::as.data.table(meta$opcoes)
  if (!is.null(meta$dependencias)) meta$dependencias <- data.table::as.data.table(meta$dependencias)
  if (!is.null(meta$arquivos)) meta$arquivos <- data.table::as.data.table(meta$arquivos)
  assign("MONITORA_PUBLICACAO_AE_XLSFORM21_META_CACHE", meta, envir = .GlobalEnv)
  meta
}

monitora_validados_xlsform21_campo <- function(atributo, meta = NULL) {
  att_chr <- as.character(atributo)[1L]
  cache_key <- paste0("MONITORA_PUBLICACAO_AE_XLSFORM21_CAMPO__", gsub("[^A-Za-z0-9]+", "_", att_chr))
  cache <- get0(cache_key, ifnotfound = NULL, inherits = TRUE)
  if (!is.null(cache) && data.table::is.data.table(cache)) return(cache)
  if (is.null(meta)) meta <- monitora_validados_xlsform21_meta()
  campos <- data.table::as.data.table(meta$campos)
  if (!nrow(campos)) return(data.table::data.table())
  for (cc in c("arquivo_xlsform", "name", "caminho_registro", "tipo_base", "list_name")) if (!(cc %in% names(campos))) campos[, (cc) := ""]
  alvo_nome <- sub("^.*/", "", att_chr)
  alvo_caminho <- att_chr
  if ("arquivo_21fev25_publicacao_ae" %in% names(campos)) {
    ans <- campos[arquivo_21fev25_publicacao_ae == TRUE & (name == alvo_nome | caminho_registro == alvo_caminho)]
  } else {
    ans <- campos[grepl("21FEV25", arquivo_xlsform) & (name == alvo_nome | caminho_registro == alvo_caminho)]
  }
  assign(cache_key, ans, envir = .GlobalEnv)
  ans
}

monitora_validados_xlsform21_mapa_lista <- function(lista, meta = NULL) {
  lista <- as.character(lista)[1]
  cache_key <- paste0("MONITORA_PUBLICACAO_AE_XLSFORM21_MAPA_LISTA__", gsub("[^A-Za-z0-9]+", "_", lista))
  cache <- get0(cache_key, ifnotfound = NULL, inherits = TRUE)
  if (!is.null(cache) && data.table::is.data.table(cache)) return(cache)
  if (is.null(meta)) meta <- monitora_validados_xlsform21_meta()
  op <- data.table::as.data.table(meta$opcoes)
  if (!nrow(op)) return(data.table::data.table(norm = character(), name = character(), list_name = character()))
  for (cc in c("arquivo_xlsform", "list_name", "name", "label")) if (!(cc %in% names(op))) op[, (cc) := ""]
  if ("arquivo_21fev25_publicacao_ae" %in% names(op)) {
    op <- op[arquivo_21fev25_publicacao_ae == TRUE & list_name == lista & nzchar(name)]
  } else {
    op <- op[grepl("21FEV25", arquivo_xlsform) & list_name == lista & nzchar(name)]
  }
  if (!nrow(op)) return(data.table::data.table(norm = character(), name = character(), list_name = character()))
  base <- data.table::rbindlist(list(
    op[, .(norm = monitora_validados_norm_ascii(name), name = as.character(name), list_name = lista)],
    op[, .(norm = monitora_validados_norm_ascii(label), name = as.character(name), list_name = lista)]
  ), fill = TRUE)
 ## Aliases históricos e variações frequentes vindas de registros_corrig/planilhas.
  extras <- data.table::data.table(norm = character(), name = character(), list_name = character())
  add <- function(norm, name) data.table::data.table(norm = monitora_validados_norm_ascii(norm), name = name, list_name = lista)
  if (identical(lista, "form_veg")) {
    extras <- data.table::rbindlist(list(extras, add(c("campestre", "Campestre"), "campestre"), add(c("savanica", "savânica", "Savanica", "Savânica"), "savanica")), fill = TRUE)
  }
  if (identical(lista, "impacto_manejo_uso")) {
    extras <- data.table::rbindlist(list(extras, add(c("nao", "não", "Nao", "Não"), "não"), add(c("sim", "Sim"), "sim")), fill = TRUE)
  }
  if (identical(lista, "especie")) {
    extras <- data.table::rbindlist(list(extras, add(c("nao", "não", "Nao", "Não"), "nao"), add(c("sim", "Sim"), "sim")), fill = TRUE)
  }
  if (lista %in% c("forma_vida_nativa", "forma_vida_exotica", "forma_vida_seca_morta")) {
    extras <- data.table::rbindlist(list(extras, add(c("erva_bromelioide", "bromelia", "bromelioide"), "bromelioide"), add(c("outra", "outra_forma_vida"), "")), fill = TRUE)
  }
  if (identical(lista, "forma_vida_outros")) {
    extras <- data.table::rbindlist(list(extras, add(c("Musgos (\"lodo\")", "Musgos (\"\"lodo\"\")", "musgos lodo", "musgos"), "musgos"), add(c("Hepáticas (possuem filídios ou talóides)", "hepaticas", "hepaticas possuem filidios ou taloides"), "hepaticas")), fill = TRUE)
  }
  if (identical(lista, "tipos_impacto_manejo_uso")) {
    extras <- data.table::rbindlist(list(
      extras,
      add(c("Extrativismo", "extrativismo"), "extrativismo"),
      add(c("Outros", "outros"), "outros"),
      add(c("Pastejo", "pastejo"), "pisoteio")
    ), fill = TRUE)
  }
  ans <- data.table::rbindlist(list(base, extras), fill = TRUE)
  ans <- ans[nzchar(norm) & !is.na(name)]
  data.table::setorderv(ans, c("list_name", "norm", "name"))
  ans <- unique(ans, by = c("list_name", "norm"))
  assign(cache_key, ans, envir = .GlobalEnv)
  ans
}

monitora_validados_xlsform21_choices <- function(lista, meta = NULL) {
  lista <- as.character(lista)[1]
  cache_key <- paste0("MONITORA_PUBLICACAO_AE_XLSFORM21_CHOICES__", gsub("[^A-Za-z0-9]+", "_", lista))
  cache <- get0(cache_key, ifnotfound = NULL, inherits = TRUE)
  if (!is.null(cache) && is.character(cache)) return(cache)
  if (is.null(meta)) meta <- monitora_validados_xlsform21_meta()
  op <- data.table::as.data.table(meta$opcoes)
  if (!nrow(op)) return(character(0))
  for (cc in c("arquivo_xlsform", "list_name", "name")) if (!(cc %in% names(op))) op[, (cc) := ""]
  if ("arquivo_21fev25_publicacao_ae" %in% names(op)) {
    ans <- unique(as.character(op[arquivo_21fev25_publicacao_ae == TRUE & list_name == lista & nzchar(name), name]))
  } else {
    ans <- unique(as.character(op[grepl("21FEV25", arquivo_xlsform) & list_name == lista & nzchar(name), name]))
  }
  assign(cache_key, ans, envir = .GlobalEnv)
  ans
}

monitora_validados_normalizar_select_vetor <- function(x, lista, multiple = TRUE, meta = NULL) {
  x0 <- monitora_validados_limpar_ausencia_saida(x)
  if (!length(x0)) return(character(0))
  mapa <- monitora_validados_xlsform21_mapa_lista(lista, meta)
  choices <- monitora_validados_xlsform21_choices(lista, meta)
  if (!length(choices)) return(x0)
  choices_placeholder <- length(choices) <= 2L && all(choices %in% c("num_key", "label"))
  if (isTRUE(choices_placeholder)) return(x0)
  vals_ok_publicacao_ae <- unique(x0[nzchar(x0)])
  if (length(vals_ok_publicacao_ae)) {
    if (isTRUE(multiple)) {
      toks_ok_publicacao_ae <- unique(unlist(strsplit(vals_ok_publicacao_ae, "\\s+", perl = TRUE), use.names = FALSE))
      toks_ok_publicacao_ae <- toks_ok_publicacao_ae[nzchar(toks_ok_publicacao_ae)]
      if (length(toks_ok_publicacao_ae) && all(toks_ok_publicacao_ae %chin% choices)) return(x0)
    } else {
      if (all(vals_ok_publicacao_ae %chin% choices)) return(x0)
    }
  }
  env <- new.env(parent = emptyenv())
  for (ii in seq_len(nrow(mapa))) assign(mapa$norm[ii], mapa$name[ii], envir = env)
  choice_order <- stats::setNames(seq_along(choices), choices)
  mapa_frases <- data.table::copy(mapa[nzchar(norm) & nzchar(name)])
  if (nrow(mapa_frases)) {
    mapa_frases[, largura_norm := nchar(norm)]
    data.table::setorder(mapa_frases, -largura_norm, norm, name)
  }
  norm_one <- function(v) {
    v <- monitora_validados_limpar_ausencia_saida(v)
    if (!nzchar(v)) return("")
    nv <- monitora_validados_norm_ascii(v)
    nv <- as.character(nv)[1L]
    if (is.na(nv) || !nzchar(nv)) return("")
    if (exists(nv, envir = env, inherits = FALSE)) {
      vv <- get(nv, envir = env, inherits = FALSE)
      if (!is.na(vv) && nzchar(vv)) return(vv)
      return("")
    }
    if (!isTRUE(multiple)) {
 ## select_one não deve ser quebrado por palavras: isso corrompia valores como
 ## nomes completos de UC ("Floresta Nacional...") quando a lista do XLSForm
 ## usa placeholders/dinâmica. Sem correspondência exata, preserva o valor.
      return(v)
    }
   ## Select_multiple histórico pode chegar como sequência de labels com
   ## espaços, sem delimitador entre escolhas (por exemplo, "incendio Queima
   ## prescrita Uso público"). Resolve as frases pelo mapa derivado do XLSForm
   ## 21FEV25, da mais longa para a mais curta. Se qualquer fragmento não for
   ## reconhecido, preserva integralmente o valor original para que o gate de
   ## domínio o rejeite sem perda ou normalização parcial.
    restante <- paste0("_", nv, "_")
    out_frases <- character(0)
    if (nrow(mapa_frases)) {
      for (jj in seq_len(nrow(mapa_frases))) {
        alvo <- paste0("_", mapa_frases$norm[jj], "_")
        while (grepl(alvo, restante, fixed = TRUE, useBytes = TRUE)) {
          out_frases <- c(out_frases, mapa_frases$name[jj])
          restante <- sub(alvo, "_", restante, fixed = TRUE)
          restante <- gsub("_+", "_", restante, perl = TRUE)
        }
      }
    }
    sobra <- gsub("^_+|_+$", "", restante, perl = TRUE)
    if (length(out_frases) && !nzchar(sobra)) {
      out_frases <- unique(out_frases[nzchar(out_frases)])
      ord_frases <- choice_order[out_frases]
      out_frases <- out_frases[order(ifelse(is.na(ord_frases), length(choices) + seq_along(out_frases), ord_frases))]
      return(paste(out_frases, collapse = " "))
    }
    partes <- unlist(strsplit(gsub("[|;,]+", " ", v, perl = TRUE), "\\s+", perl = TRUE), use.names = FALSE)
    partes <- partes[nzchar(partes)]
    if (!length(partes)) return("")
    out <- character(0)
    for (pp in partes) {
      np <- monitora_validados_norm_ascii(pp)
      np <- as.character(np)[1L]
      if (is.na(np) || !nzchar(np)) next
      if (!exists(np, envir = env, inherits = FALSE)) return(v)
      val <- get(np, envir = env, inherits = FALSE)
      if (!is.na(val) && nzchar(val)) out <- c(out, val)
    }
    out <- unique(out[nzchar(out)])
    if (!length(out)) return("")
    ord <- choice_order[out]
    out <- out[order(ifelse(is.na(ord), length(choices) + seq_along(out), ord))]
    paste(out, collapse = " ")
  }
  vals <- unique(x0)
  res <- vapply(vals, norm_one, character(1), USE.NAMES = FALSE)
  unname(res[match(x0, vals)])
}

monitora_validados_tem_token <- function(x, token) {
 ### caminho genérico sem regex para selected de select_multiple.
 ### Vale para contratos 2022/2023/2024/2025 porque todos usam tokens separados por espaço.
  x <- monitora_validados_limpar_ausencia_saida(x)
  if (!length(x)) return(logical(0))
  token <- as.character(token)[1L]
  if (is.na(token) || !nzchar(token)) return(rep(FALSE, length(x)))
  alvo <- paste0(" ", token, " ")
  grepl(alvo, paste0(" ", x, " "), fixed = TRUE, useBytes = TRUE)
}

monitora_validados_adicionar_token <- function(x, token, lista_ordem = NULL) {
  x <- monitora_validados_limpar_ausencia_saida(x)
  tem <- monitora_validados_tem_token(x, token)
  y <- ifelse(tem, x, trimws(paste(x, token)))
  if (!is.null(lista_ordem) && length(lista_ordem)) {
    y <- monitora_validados_ordenar_multiselect(y, lista_ordem)
  }
  y
}

monitora_validados_remover_token <- function(x, token, lista_ordem = NULL) {
  x <- monitora_validados_limpar_ausencia_saida(x)
  vals <- unique(x)
  limpa <- function(v) {
    if (!nzchar(v)) return("")
    p <- unlist(strsplit(v, "\\s+", perl = TRUE), use.names = FALSE)
    p <- p[nzchar(p) & p != token]
    if (!length(p)) return("")
    if (!is.null(lista_ordem) && length(lista_ordem)) {
      ord <- stats::setNames(seq_along(lista_ordem), lista_ordem)[p]
      p <- p[order(ifelse(is.na(ord), length(lista_ordem) + seq_along(p), ord))]
    }
    paste(unique(p), collapse = " ")
  }
  res <- vapply(vals, limpa, character(1), USE.NAMES = FALSE)
  unname(res[match(x, vals)])
}

monitora_validados_ordenar_multiselect <- function(x, lista_ordem) {
  x <- monitora_validados_limpar_ausencia_saida(x)
  vals <- unique(x)
  ordem <- stats::setNames(seq_along(lista_ordem), lista_ordem)
  f <- function(v) {
    if (!nzchar(v)) return("")
    p <- unique(unlist(strsplit(v, "\\s+", perl = TRUE), use.names = FALSE))
    p <- p[nzchar(p)]
    if (!length(p)) return("")
    ord <- ordem[p]
    p <- p[order(ifelse(is.na(ord), length(lista_ordem) + seq_along(p), ord))]
    paste(p, collapse = " ")
  }
  res <- vapply(vals, f, character(1), USE.NAMES = FALSE)
  unname(res[match(x, vals)])
}

monitora_validados_campos_dependentes_categoria <- function(cols, categoria) {
  pref <- paste0("amostragem/registro/forma_vida_", categoria, "_")
  grep(paste0("^", pref), cols, value = TRUE)
}

monitora_validados_aplicar_regras_xlsform21 <- function(out, schema) {
  meta <- monitora_validados_xlsform21_meta()
  cols <- names(out)
  ajustes <- vector("list", 32L)
  kk <- 0L
  registrar <- function(regra, atributo, n_ajustes, detalhe = "") {
    if (!is.finite(n_ajustes) || n_ajustes <= 0L) return(invisible(NULL))
    n_avaliadas <- if (atributo %in% names(out)) length(out[[atributo]]) else nrow(out)
    kk <<- kk + 1L
    ajustes[[kk]] <<- data.table::data.table(
      regra = regra,
      atributo = atributo,
 ### Compatibilidade: n_ajustes continua existindo, agora explicitamente
 ### qualificado como células cujo valor realmente mudou nessa regra.
      n_ajustes = as.integer(n_ajustes),
      n_alteracoes_efetivas = as.integer(n_ajustes),
      n_celulas_avaliadas = as.integer(n_avaliadas),
      n_celulas_sem_alteracao = as.integer(max(0L, n_avaliadas - n_ajustes)),
      unidade_contagem = "celula_com_valor_alterado_por_regra",
      detalhe = detalhe
    )
    invisible(NULL)
  }
 ## 1. Normalização de campos select_one/select_multiple para os names do XLSForm 21FEV25.
  for (att in cols) {
    campo <- monitora_validados_xlsform21_campo(att, meta)
    if (!nrow(campo)) next
    campo <- campo[1L]
    if (!(campo$tipo_base %in% c("select_one", "select_multiple")) || !nzchar(campo$list_name)) next
    antes <- out[[att]]
    depois <- monitora_validados_normalizar_select_vetor(antes, campo$list_name, multiple = identical(campo$tipo_base, "select_multiple"), meta = meta)
    registrar("normalizacao_dominio_xlsform21", att, sum(antes != depois, na.rm = TRUE), campo$list_name)
    data.table::set(out, j = att, value = depois)
  }
  tipo_col <- "amostragem/registro/tipo_forma_vida"
  tipo_choices <- monitora_validados_xlsform21_choices("tipo_forma_vida", meta)
  if (tipo_col %in% cols) {
    tipo <- out[[tipo_col]]
 ## Remover token histórico indevido em sublistas e mapear bromelioide.
    for (cc in c("amostragem/registro/forma_vida_nativa", "amostragem/registro/forma_vida_exotica", "amostragem/registro/forma_vida_seca_morta")) {
      if (cc %in% cols) {
        antes <- out[[cc]]
        depois <- monitora_validados_remover_token(antes, "serrapilheira", monitora_validados_xlsform21_choices(sub("^.*/", "", cc), meta))
        depois <- monitora_validados_remover_token(depois, "outra", monitora_validados_xlsform21_choices(sub("^.*/", "", cc), meta))
        registrar("remocao_token_invalido_sublista_forma_vida", cc, sum(antes != depois, na.rm = TRUE), "serrapilheira/outra")
        data.table::set(out, j = cc, value = depois)
      }
    }
    nativa <- if ("amostragem/registro/forma_vida_nativa" %in% cols) nzchar(out[["amostragem/registro/forma_vida_nativa"]]) else rep(FALSE, nrow(out))
    exotica <- if ("amostragem/registro/forma_vida_exotica" %in% cols) nzchar(out[["amostragem/registro/forma_vida_exotica"]]) else rep(FALSE, nrow(out))
    seca <- if ("amostragem/registro/forma_vida_seca_morta" %in% cols) nzchar(out[["amostragem/registro/forma_vida_seca_morta"]]) else rep(FALSE, nrow(out))
    serr <- if ("amostragem/registro/forma_serrapilheira" %in% cols) nzchar(out[["amostragem/registro/forma_serrapilheira"]]) else rep(FALSE, nrow(out))
    outros <- if ("amostragem/registro/forma_vida_outros" %in% cols) nzchar(out[["amostragem/registro/forma_vida_outros"]]) else rep(FALSE, nrow(out))
    antes_tipo <- tipo
    solo_original <- monitora_validados_tem_token(tipo, "solo_nu")
    serr_original <- monitora_validados_tem_token(tipo, "serrapilheira")
    outra_original <- monitora_validados_tem_token(tipo, "outra_forma_vida")
 ## Reconstroi o multiselect superior a partir dos campos inferiores já
 ## normalizados para o XLSForm 21FEV25. Isso remove categorias históricas
 ## que ficaram sem sublista válida, como seca_morta/exotica com sublista
 ## apenas "serrapilheira", e migra "outra" histórica para outra_forma_vida.
    tipo_novo <- rep("", nrow(out))
    tipo_novo <- ifelse(serr | serr_original, monitora_validados_adicionar_token(tipo_novo, "serrapilheira", tipo_choices), tipo_novo)
    tipo_novo <- ifelse(nativa, monitora_validados_adicionar_token(tipo_novo, "nativa", tipo_choices), tipo_novo)
    tipo_novo <- ifelse(exotica, monitora_validados_adicionar_token(tipo_novo, "exotica", tipo_choices), tipo_novo)
    tipo_novo <- ifelse(seca, monitora_validados_adicionar_token(tipo_novo, "seca_morta", tipo_choices), tipo_novo)
    tipo_novo <- ifelse(outros | outra_original, monitora_validados_adicionar_token(tipo_novo, "outra_forma_vida", tipo_choices), tipo_novo)
    tem_alguma_categoria <- nzchar(tipo_novo)
    tipo_novo <- ifelse(!tem_alguma_categoria & solo_original, monitora_validados_adicionar_token(tipo_novo, "solo_nu", tipo_choices), tipo_novo)
    tem_solo <- monitora_validados_tem_token(tipo_novo, "solo_nu")
    tem_outro_tipo <- Reduce(`|`, lapply(c("serrapilheira", "nativa", "exotica", "seca_morta", "outra_forma_vida"), function(tt) monitora_validados_tem_token(tipo_novo, tt)))
    tipo_novo <- ifelse(tem_solo & tem_outro_tipo, monitora_validados_remover_token(tipo_novo, "solo_nu", tipo_choices), tipo_novo)
    registrar("sincronizacao_tipo_forma_vida_com_campos_inferiores", tipo_col, sum(antes_tipo != tipo_novo, na.rm = TRUE), "reconstroi a partir dos campos inferiores XLSForm 21FEV25; remove categorias sem sublista valida")
    tipo <- tipo_novo
    data.table::set(out, j = tipo_col, value = tipo)
 ## Relevance de serrapilheira/outros e categorias principais.
    if ("amostragem/registro/forma_serrapilheira" %in% cols) {
      antes <- out[["amostragem/registro/forma_serrapilheira"]]
      rel <- monitora_validados_tem_token(tipo, "serrapilheira")
      depois <- ifelse(rel & !nzchar(antes), "serrapilheira", ifelse(rel, antes, ""))
      registrar("relevance_forma_serrapilheira", "amostragem/registro/forma_serrapilheira", sum(antes != depois, na.rm = TRUE), "selected(tipo_forma_vida, 'serrapilheira')")
      data.table::set(out, j = "amostragem/registro/forma_serrapilheira", value = depois)
    }
    if ("amostragem/registro/forma_vida_outros" %in% cols) {
      antes <- out[["amostragem/registro/forma_vida_outros"]]
      rel <- monitora_validados_tem_token(tipo, "outra_forma_vida")
      depois <- ifelse(rel, antes, "")
      registrar("relevance_forma_vida_outros", "amostragem/registro/forma_vida_outros", sum(antes != depois, na.rm = TRUE), "selected(tipo_forma_vida, 'outra_forma_vida')")
      data.table::set(out, j = "amostragem/registro/forma_vida_outros", value = depois)
    }
    for (cat in c("nativa", "exotica", "seca_morta")) {
      main <- paste0("amostragem/registro/forma_vida_", cat)
      if (!(main %in% cols)) next
      rel <- monitora_validados_tem_token(tipo, cat)
      antes <- out[[main]]
      depois <- ifelse(rel, antes, "")
      registrar("relevance_lista_principal_forma_vida", main, sum(antes != depois, na.rm = TRUE), paste0("selected(tipo_forma_vida, '", cat, "')"))
      data.table::set(out, j = main, value = depois)
      dep_cols <- monitora_validados_campos_dependentes_categoria(cols, cat)
      if (length(dep_cols)) {
        for (dc in dep_cols) {
          antes_dep <- out[[dc]]
          form <- sub(paste0("^amostragem/registro/forma_vida_", cat, "_"), "", dc)
          form <- sub("_sp$", "", form)
          rel_dep <- rel & monitora_validados_tem_token(out[[main]], form)
          depois_dep <- ifelse(rel_dep, antes_dep, "")
          registrar("relevance_dependente_forma_vida", dc, sum(antes_dep != depois_dep, na.rm = TRUE), paste0("selected(", main, ", '", form, "')"))
          data.table::set(out, j = dc, value = depois_dep)
        }
      }
    }
  }
 ## 2. Relevance de impactos/manejo.
  impact_col <- "impact_manejo_uso/impacto_manejo_uso"
  tipos_col <- "impact_manejo_uso/tipos_impacto_manejo_uso"
  if (impact_col %in% cols) {
    impact <- out[[impact_col]]
    tipos <- if (tipos_col %in% cols) out[[tipos_col]] else rep("", nrow(out))
    antes <- impact
    impact <- ifelse(nzchar(tipos), "sim", ifelse(!nzchar(impact), "não", impact))
    registrar("sincronizacao_impacto_com_tipos", impact_col, sum(antes != impact, na.rm = TRUE), "tipos preenchidos implicam impacto=sim; vazio implica não")
    data.table::set(out, j = impact_col, value = impact)
    if (tipos_col %in% cols) {
      antes_t <- out[[tipos_col]]
      depois_t <- ifelse(impact == "sim", antes_t, "")
      registrar("relevance_tipos_impacto_manejo_uso", tipos_col, sum(antes_t != depois_t, na.rm = TRUE), "${impacto_manejo_uso}=sim")
      data.table::set(out, j = tipos_col, value = depois_t)
    }
    for (cc in c("impact_manejo_uso/tipos_impacto_manejo_uso_descricao", "impact_manejo_uso/tipos_impacto_manejo_uso_outro")) {
      if (cc %in% cols) {
        antes_c <- out[[cc]]
        if (identical(cc, "impact_manejo_uso/tipos_impacto_manejo_uso_outro") && tipos_col %in% cols) {
          rel_c <- impact == "sim" & monitora_validados_tem_token(out[[tipos_col]], "outros")
        } else {
          rel_c <- impact == "sim"
        }
        depois_c <- ifelse(rel_c, antes_c, "")
        registrar("relevance_impacto_manejo_uso_dependente", cc, sum(antes_c != depois_c, na.rm = TRUE), "relevance XLSForm 21FEV25")
        data.table::set(out, j = cc, value = depois_c)
      }
    }
  }
  ajustes_dt <- if (kk) data.table::rbindlist(ajustes[seq_len(kk)], fill = TRUE) else data.table::data.table(
    regra = character(), atributo = character(), n_ajustes = integer(), n_alteracoes_efetivas = integer(),
    n_celulas_avaliadas = integer(), n_celulas_sem_alteracao = integer(), unidade_contagem = character(), detalhe = character()
  )
  list(out = out, ajustes = ajustes_dt, meta = meta)
}

monitora_validados_validar_dominios_xlsform21 <- function(out, schema, meta = NULL) {
  if (is.null(meta)) meta <- monitora_validados_xlsform21_meta()
  problemas <- vector("list", ncol(out))
  k <- 0L
  for (att in names(out)) {
    campo <- monitora_validados_xlsform21_campo(att, meta)
    if (!nrow(campo)) next
    campo <- campo[1L]
    if (!(campo$tipo_base %in% c("select_one", "select_multiple")) || !nzchar(campo$list_name)) next
    choices <- monitora_validados_xlsform21_choices(campo$list_name, meta)
    if (!length(choices)) next
 ## Listas dinâmicas do XLSForm embutido aparecem como placeholders
 ## (num_key/label). O domínio real vem do Sismonitora/base operacional,
 ## portanto não deve bloquear o CSV validado.
    choices_placeholder <- length(choices) <= 2L && all(choices %in% c("num_key", "label"))
    if (isTRUE(choices_placeholder)) next
    x <- monitora_validados_limpar_ausencia_saida(out[[att]])
    vals <- unique(x[nzchar(x)])
    if (!length(vals)) next
    if (identical(campo$tipo_base, "select_one")) {
      invalid <- setdiff(vals, choices)
      exemplos_invalidos <- invalid
    } else {
      toks <- unique(unlist(strsplit(vals, "\\s+", perl = TRUE), use.names = FALSE))
      toks <- toks[nzchar(toks)]
      invalid <- setdiff(toks, choices)
      exemplos_invalidos <- if (length(invalid)) {
        vals[vapply(
          strsplit(vals, "\\s+", perl = TRUE),
          function(tokens_valor) any(tokens_valor %in% invalid),
          logical(1L)
        )]
      } else character(0)
    }
    if (length(invalid)) {
      k <- k + 1L
      motivo <- if (identical(att, "amostragem/registro/forma_vida_outros")) {
        "residuo_outra_forma_vida_sem_sanitizacao_previa"
      } else {
        "token_fora_dominio_xlsform21"
      }
      problemas[[k]] <- data.table::data.table(
        atributo = att, list_name = campo$list_name, tipo_base = campo$tipo_base,
        n_tokens_invalidos = length(invalid), tokens_invalidos = paste(utils::head(invalid, 20L), collapse = " | "),
        exemplos = paste(utils::head(exemplos_invalidos, 5L), collapse = " | "),
        bloqueante = TRUE, motivo_bloqueio = motivo
      )
    }
  }
  if (!k) return(data.table::data.table(atributo = character(), list_name = character(), tipo_base = character(), n_tokens_invalidos = integer(), tokens_invalidos = character(), exemplos = character(), bloqueante = logical(), motivo_bloqueio = character()))
  data.table::rbindlist(problemas[seq_len(k)], fill = TRUE)
}

monitora_validados_validar_condicionais_xlsform21 <- function(out) {
  problemas <- list()
  k <- 0L
  add <- function(regra, atributo, idx, detalhe = "") {
    n <- sum(idx, na.rm = TRUE)
    if (!n) return(invisible(NULL))
    k <<- k + 1L
    exemplos <- ""
    if ("coleta" %in% names(out)) exemplos <- paste(utils::head(out[["coleta"]][which(idx)], 10L), collapse = " | ")
    problemas[[k]] <<- data.table::data.table(regra = regra, atributo = atributo, n_problemas = as.integer(n), exemplos_coleta = exemplos, detalhe = detalhe, bloqueante = TRUE, motivo_bloqueio = regra)
    invisible(NULL)
  }
  tipo_col <- "amostragem/registro/tipo_forma_vida"
  if (tipo_col %in% names(out)) {
    tipo <- out[[tipo_col]]
    tem_solo <- monitora_validados_tem_token(tipo, "solo_nu")
    tem_outro <- Reduce(`|`, lapply(c("serrapilheira", "nativa", "exotica", "seca_morta", "outra_forma_vida"), function(tt) monitora_validados_tem_token(tipo, tt)))
    add("solo_nu_com_outra_categoria", tipo_col, tem_solo & tem_outro, "solo_nu é exclusivo")
    pares <- list(
      serrapilheira = "amostragem/registro/forma_serrapilheira",
      outra_forma_vida = "amostragem/registro/forma_vida_outros",
      nativa = "amostragem/registro/forma_vida_nativa",
      exotica = "amostragem/registro/forma_vida_exotica",
      seca_morta = "amostragem/registro/forma_vida_seca_morta"
    )
    for (tok in names(pares)) {
      cc <- pares[[tok]]
      if (cc %in% names(out)) {
        add("campo_obrigatorio_relevante_vazio", cc, monitora_validados_tem_token(tipo, tok) & !nzchar(out[[cc]]), paste0("selected(tipo_forma_vida, '", tok, "')"))
        add("campo_irrelevante_preenchido", cc, !monitora_validados_tem_token(tipo, tok) & nzchar(out[[cc]]), paste0("not selected(tipo_forma_vida, '", tok, "')"))
      }
    }
  }
 ### XLSForm 2025: a primeira foto de desconhecida é required nas três
 ### categorias; as fotos 02/03 permanecem opcionais e progressivamente
 ### relevantes. O token desconhecida, por si só, é válido e não bloqueia.
  for (categoria in c("nativa", "exotica", "seca_morta")) {
    pai <- paste0("amostragem/registro/forma_vida_", categoria)
    foto <- paste0("amostragem/registro/foto_forma_vida_", categoria, "_desconhecida")
    if (pai %in% names(out) && foto %in% names(out)) {
      tem_desc <- monitora_validados_tem_token(out[[pai]], "desconhecida")
      add(
        "campo_obrigatorio_relevante_vazio",
        foto,
        tem_desc & !nzchar(monitora_validados_limpar_ausencia_saida(out[[foto]])),
        paste0("selected(${forma_vida_", categoria, "}, 'desconhecida'); required=yes")
      )
    }
  }
  impact_col <- "impact_manejo_uso/impacto_manejo_uso"
  tipos_col <- "impact_manejo_uso/tipos_impacto_manejo_uso"
  if (impact_col %in% names(out) && tipos_col %in% names(out)) {
    impact <- out[[impact_col]]
    tipos <- out[[tipos_col]]
    add("tipos_impacto_obrigatorio_quando_impacto_sim", tipos_col, impact == "sim" & !nzchar(tipos), "${impacto_manejo_uso}=sim")
    add("tipos_impacto_irrelevante_quando_impacto_nao", tipos_col, impact != "sim" & nzchar(tipos), "${impacto_manejo_uso}!=sim")
  }
  if (!k) return(data.table::data.table(regra = character(), atributo = character(), n_problemas = integer(), exemplos_coleta = character(), detalhe = character(), bloqueante = logical(), motivo_bloqueio = character()))
  data.table::rbindlist(problemas[seq_len(k)], fill = TRUE)
}

### Confere a herança dos hábitos já preenchidos em registros_corrig. Esta
### validação não cria requisito retroativo: só compara linhas nas quais a forma
### está selecionada e o hábito de origem é não vazio. O required versionado
### permanece sob monitora_correcao_ocorrencias_habito_detalhadas .
monitora_validados_validar_heranca_habitos <- function(registros_corrig, out) {
  registros_corrig <- data.table::as.data.table(registros_corrig)
  out <- data.table::as.data.table(out)
  vazio <- data.table::data.table(
    regra = character(), atributo = character(), n_problemas = integer(),
    exemplos_coleta = character(), detalhe = character(),
    bloqueante = logical(), motivo_bloqueio = character()
  )
  if (nrow(registros_corrig) != nrow(out)) {
    return(data.table::data.table(
      regra = "cardinalidade_heranca_registros_corrig",
      atributo = "amostragem/registro/forma_vida_*_habito",
      n_problemas = abs(nrow(registros_corrig) - nrow(out)),
      exemplos_coleta = "",
      detalhe = paste0("registros_corrig=", nrow(registros_corrig), "; validados=", nrow(out)),
      bloqueante = TRUE,
      motivo_bloqueio = "cardinalidade_divergente_na_heranca_de_habitos"
    ))
  }
  problemas <- list()
  k <- 0L
  for (categoria in c("nativa", "exotica", "seca_morta")) {
    att_pai <- paste0("amostragem/registro/forma_vida_", categoria)
    pai <- monitora_validados_pegar(registros_corrig, att_pai)$valor
    for (forma in c("bromelioide", "cactacea", "orquidea", "samambaia")) {
      att <- paste0(att_pai, "_", forma)
      if (!(att %in% names(out))) next
      esperado <- monitora_validados_derivar_ou_mapear_coluna(
        registros_corrig, att, formato = "texto", largura = NA_integer_
      )$valor
      esperado <- monitora_validados_limpar_ausencia_saida(esperado)
      observado <- monitora_validados_limpar_ausencia_saida(out[[att]])
      relevante <- monitora_validados_tem_token(pai, forma)
      if (identical(forma, "bromelioide")) {
        relevante <- relevante | monitora_validados_tem_token(pai, "erva_bromelioide")
      }
      divergente <- relevante & nzchar(esperado) & observado != esperado
      divergente[is.na(divergente)] <- FALSE
      if (!any(divergente)) next
      idx <- which(divergente)
      coleta <- if ("coleta" %in% names(out)) as.character(out$coleta[idx]) else rep("", length(idx))
      ponto <- if ("amostragem/registro/ponto_amostral" %in% names(out)) {
        as.character(out[["amostragem/registro/ponto_amostral"]][idx])
      } else rep("", length(idx))
      exemplos <- paste(utils::head(paste(coleta, ponto, sep = ":"), 10L), collapse = " | ")
      exemplos_valor <- paste(
        utils::head(paste0(idx, "=", esperado[idx], "->", observado[idx]), 10L),
        collapse = " | "
      )
      k <- k + 1L
      problemas[[k]] <- data.table::data.table(
        regra = "habito_preenchido_em_registros_corrig_nao_herdado",
        atributo = att,
        n_problemas = as.integer(length(idx)),
        exemplos_coleta = exemplos,
        detalhe = paste0("linhas/valor esperado->validado: ", exemplos_valor),
        bloqueante = TRUE,
        motivo_bloqueio = "perda_de_habito_na_projecao_registros_corrig_para_registros_validados"
      )
    }
  }
  if (k) data.table::rbindlist(problemas, fill = TRUE, use.names = TRUE) else vazio
}



monitora_validados_auditar_sanitizacao_desconhecida <- function(out) {
  out <- data.table::as.data.table(out)
  cols <- names(out)
  categorias <- c("nativa", "exotica", "seca_morta")
  problemas <- vector("list", length(categorias) * 3L)
  kk <- 0L
  normaliza <- function(x) {
    x <- as.character(x); x[is.na(x)] <- ""; x <- tolower(x); x <- iconv(x, from = "", to = "ASCII//TRANSLIT"); x[is.na(x)] <- ""; gsub("[^a-z0-9]+", "_", x, perl = TRUE)
  }
  for (cat in categorias) {
    main <- paste0("amostragem/registro/forma_vida_", cat)
    if (!(main %in% cols)) next
    tem_desc <- monitora_validados_tem_token(out[[main]], "desconhecida")
    nms_norm <- normaliza(cols)
    cat_pat <- if (identical(cat, "seca_morta")) "seca.*morta|seca_ou_morta|seca_e_morta" else cat
    dep_cols <- cols[
      grepl("desconhecid|indeterminad|nao_identific|nao_identificado", nms_norm, perl = TRUE) &
        grepl(cat_pat, nms_norm, perl = TRUE) &
        grepl("foto|imagem|image|upload|arquivo|anexo|midia|media|descr|descricao|descritor|observ|obs", nms_norm, perl = TRUE)
    ]
    dep_cols <- setdiff(dep_cols, main)
    for (dc in dep_cols) {
      preenchido <- nzchar(monitora_validados_limpar_ausencia_saida(out[[dc]]))
      viol <- preenchido & !tem_desc
      if (any(viol, na.rm = TRUE)) {
        kk <- kk + 1L
        problemas[[kk]] <- data.table::data.table(
          tipo = "dependente_desconhecida_preenchido_sem_token",
          categoria = cat,
          atributo = dc,
          n_linhas = sum(viol, na.rm = TRUE),
          exemplos = paste(utils::head(which(viol), 10L), collapse = " | "),
          motivo_bloqueio = "foto/descritor de forma de vida desconhecida preenchido sem token desconhecida na categoria correspondente"
        )
      }
    }
  }
  if (kk) data.table::rbindlist(problemas[seq_len(kk)], fill = TRUE, use.names = TRUE) else data.table::data.table(tipo = character(), categoria = character(), atributo = character(), n_linhas = integer(), exemplos = character(), motivo_bloqueio = character())
}

monitora_validados_auditar_sanitizacao_outras_formas <- function(out, meta = NULL) {
 ## Diagnóstico específico para resíduos de versões antigas do XLSForm.
 ## Nas primeiras versões, "outra forma de vida" permitia texto livre em campos
 ## descritivos. Na versão 21FEV25, esses campos/textos livres não fazem parte
 ## do contrato final de registros_validados.csv. Portanto, valores como
 ## "Musgo", "M" ou erros de digitação não são convertidos automaticamente em
 ## tokens atuais; devem ser triados pela rotina de sanitização antes da
 ## exportação final.
  vazio <- data.table::data.table(
    COLETA = character(), UC = character(), CICLO = character(), CAMPANHA = character(),
    EA = character(), UA = character(), ponto_amostral = character(), ponto_metro = character(),
    atributo = character(), valor_residual = character(), tokens_invalidos = character(),
    motivo_bloqueio = character(), orientacao = character()
  )
  att <- "amostragem/registro/forma_vida_outros"
  if (!(att %in% names(out))) return(vazio)
  if (is.null(meta)) meta <- monitora_validados_xlsform21_meta()
  choices <- monitora_validados_xlsform21_choices("forma_vida_outros", meta)
  if (!length(choices)) return(vazio)
  x <- monitora_validados_limpar_ausencia_saida(out[[att]])
  vals <- unique(x[nzchar(x)])
  if (!length(vals)) return(vazio)
  tokenizar <- function(v) {
    toks <- unlist(strsplit(gsub("[|;,]+", " ", v, perl = TRUE), "\\s+", perl = TRUE), use.names = FALSE)
    unique(toks[nzchar(toks)])
  }
  invalidos_por_valor <- vapply(vals, function(v) {
    inv <- setdiff(tokenizar(v), choices)
    if (!length(inv)) "" else paste(inv, collapse = " | ")
  }, character(1), USE.NAMES = FALSE)
  inv_map <- stats::setNames(invalidos_por_valor, vals)
  inv_linha <- unname(inv_map[x])
  inv_linha[is.na(inv_linha)] <- ""
  idx <- which(nzchar(x) & nzchar(inv_linha))
  if (!length(idx)) return(vazio)
  pegar <- function(cc) if (cc %in% names(out)) as.character(out[[cc]]) else rep("", nrow(out))
  data.table::data.table(
    COLETA = pegar("coleta")[idx],
    UC = pegar("uc")[idx],
    CICLO = pegar("ciclo")[idx],
    CAMPANHA = pegar("campanha")[idx],
    EA = pegar("estacao_amostral")[idx],
    UA = pegar("unidade_amostral")[idx],
    ponto_amostral = pegar("amostragem/registro/ponto_amostral")[idx],
    ponto_metro = pegar("amostragem/registro/ponto_metro")[idx],
    atributo = att,
    valor_residual = x[idx],
    tokens_invalidos = inv_linha[idx],
    motivo_bloqueio = "residuo_outra_forma_vida_sem_sanitizacao_previa",
    orientacao = "Aplicar a rotina de sanitização/triagem de outra forma de vida em registros_corrig antes de gerar registros_validados.csv; não converter texto livre legado automaticamente."
  )
}

### Representação esparsa do repeat de coletores -----------------------------
### Coletores são um repeat de coleta no XLSForm e o template SISMONITORA os
### representa de forma esparsa: um par nome/CPF por linha, na ordem original,
### seguido de ausências nas demais linhas da coleta. `registros_corrig` e
### `registros_validados` devem conservar exatamente essa projeção; nunca
### concatenar a equipe, repeti-la em todas as linhas ou inferir CPF.
### Checkpoints históricos que carreguem o JSON técnico/broadcast são lidos
### somente para restauração compatível e voltam a ser gravados no layout do
### template, sem as colunas auxiliares transitórias.
monitora_coletores_repeat_col_json <- function() "MONITORA_COLETORES_REPEAT_JSON"
monitora_coletores_repeat_col_versao <- function() "MONITORA_COLETORES_REPEAT_VERSAO"

monitora_coletores_repeat_limpar <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  x <- trimws(x)
  x[tolower(x) %in% c("na", "n/a", "null", "nan") | x == "---"] <- ""
  x
}

monitora_coletores_repeat_coleta <- function(dt) {
  n <- nrow(dt)
  cc <- intersect(c("COLETA", "coleta", "coleta_uuid", "UUID", "uuid"), names(dt))
  if (!length(cc)) return(paste0(".__linha_sem_coleta__", seq_len(n)))
  v <- monitora_coletores_repeat_limpar(dt[[cc[1L]]])
  vazio <- !nzchar(v)
  if (any(vazio)) v[vazio] <- paste0(".__linha_sem_coleta__", which(vazio))
  v
}

monitora_coletores_repeat_json_ler <- function(x) {
  x <- monitora_coletores_repeat_limpar(x)
  if (!length(x) || !nzchar(x[1L])) return(NULL)
  if (!requireNamespace("jsonlite", quietly = TRUE)) stop("Preservação do repeat de coletores exige o pacote jsonlite.", call. = FALSE)
  obj <- tryCatch(jsonlite::fromJSON(x[1L], simplifyVector = TRUE), error = function(e) NULL)
 ### O leitor central de checkpoints usa fread e alguns registros_corrig
 ### históricos/round-trips chegam com o escape CSV ainda visível (`""` para
 ### cada aspas do JSON). Tenta primeiro o JSON literal; somente após falha e
 ### quando o prefixo comprova esse escape, desfaz uma camada e tenta de novo.
 ### Isso mantém compatibilidade entre modos sem interpretar `|` ou conteúdo
 ### de campo como estrutura.
  if (is.null(obj) && startsWith(x[1L], "{\"\"")) {
    x_csv <- gsub("\"\"", "\"", x[1L], fixed = TRUE)
    obj <- tryCatch(jsonlite::fromJSON(x_csv, simplifyVector = TRUE), error = function(e) NULL)
  }
  if (is.null(obj) || !is.list(obj)) return(NULL)
  nomes <- monitora_coletores_repeat_limpar(obj$nomes)
  cpfs <- monitora_coletores_repeat_limpar(obj$cpfs)
  m <- max(length(nomes), length(cpfs), 0L)
  if (!m) return(list(nomes = character(), cpfs = character()))
  length(nomes) <- m; length(cpfs) <- m
  nomes[is.na(nomes)] <- ""; cpfs[is.na(cpfs)] <- ""
  list(nomes = nomes, cpfs = cpfs)
}

monitora_coletores_repeat_json_gravar <- function(nomes, cpfs) {
  if (!requireNamespace("jsonlite", quietly = TRUE)) stop("Preservação do repeat de coletores exige o pacote jsonlite.", call. = FALSE)
  nomes <- monitora_coletores_repeat_limpar(nomes)
  cpfs <- monitora_coletores_repeat_limpar(cpfs)
  m <- max(length(nomes), length(cpfs), 0L)
  length(nomes) <- m; length(cpfs) <- m
  nomes[is.na(nomes)] <- ""; cpfs[is.na(cpfs)] <- ""
  as.character(jsonlite::toJSON(list(nomes = unname(nomes), cpfs = unname(cpfs)), auto_unbox = FALSE, na = "null"))
}

monitora_coletores_repeat_extrair_grupo <- function(dt, linhas) {
  col_json <- monitora_coletores_repeat_col_json()
  if (col_json %in% names(dt)) {
    js <- unique(monitora_coletores_repeat_limpar(dt[[col_json]][linhas]))
    js <- js[nzchar(js)]
    if (length(js) > 1L) stop("Repeat de coletores divergente dentro da mesma coleta; preservação bloqueada.", call. = FALSE)
    if (length(js) == 1L) {
      rec <- monitora_coletores_repeat_json_ler(js)
      if (is.null(rec)) stop("JSON técnico do repeat de coletores é inválido; preservação bloqueada.", call. = FALSE)
 ### Não aceitar que um checkpoint com JSON técnico e colunas visíveis
 ### divergentes escolha silenciosamente uma das versões. A única exceção
 ### reconhecida é o broadcast `; ` criado pelos próprios checkpoints históricos.
      col_nome_vis <- intersect(c("coletor/nome", "COLETORES", "Coletores"), names(dt))[1L]
      col_cpf_vis <- intersect(c("coletor/cpf", "CPF (coletor)", "cpf (coletor)"), names(dt))[1L]
      nomes_vis <- if (!is.na(col_nome_vis)) monitora_coletores_repeat_limpar(dt[[col_nome_vis]][linhas]) else character()
      cpfs_vis <- if (!is.na(col_cpf_vis)) monitora_coletores_repeat_limpar(dt[[col_cpf_vis]][linhas]) else character()
      nomes_nv <- nomes_vis[nzchar(nomes_vis)]
      if (length(nomes_nv)) {
        nomes_obs <- if (length(nomes_nv) > 1L && length(unique(nomes_nv)) == 1L) {
          if (grepl(";", nomes_nv[1L], fixed = TRUE)) trimws(strsplit(nomes_nv[1L], ";", fixed = TRUE)[[1L]]) else nomes_nv[1L]
        } else {
          nomes_nv
        }
        nomes_obs <- nomes_obs[nzchar(nomes_obs)]
        nomes_json <- rec$nomes[nzchar(rec$nomes)]
        if (!identical(unname(nomes_obs), unname(nomes_json))) {
          stop("JSON técnico e nomes visíveis do repeat de coletores divergem; preservação bloqueada sem adivinhar a fonte correta.", call. = FALSE)
        }
      }
      cpfs_obs <- cpfs_vis[nzchar(cpfs_vis)]
      cpfs_json <- rec$cpfs[nzchar(rec$cpfs)]
      if (length(cpfs_obs) && !identical(unname(cpfs_obs), unname(cpfs_json))) {
        stop("JSON técnico e CPFs visíveis do repeat de coletores divergem; preservação bloqueada sem adivinhar a fonte correta.", call. = FALSE)
      }
      return(c(rec, list(fonte = "json_tecnico_herdado")))
    }
  }
  escolher_coluna_preenchida <- function(candidatos) {
    candidatos <- intersect(candidatos, names(dt))
    if (!length(candidatos)) return(NA_character_)
    n_preenchidos <- vapply(candidatos, function(cc) {
      sum(nzchar(monitora_coletores_repeat_limpar(dt[[cc]][linhas])))
    }, integer(1L))
    candidatos[which.max(n_preenchidos)]
  }
  col_nome <- escolher_coluna_preenchida(c("coletor/nome", "COLETORES", "Coletores"))
  col_cpf <- escolher_coluna_preenchida(c("coletor/cpf", "CPF (coletor)", "cpf (coletor)"))
  nomes_linha <- if (!is.na(col_nome)) monitora_coletores_repeat_limpar(dt[[col_nome]][linhas]) else rep("", length(linhas))
  cpfs_linha <- if (!is.na(col_cpf)) monitora_coletores_repeat_limpar(dt[[col_cpf]][linhas]) else rep("", length(linhas))

 ### Fallback para um registros_corrig histórico sem o JSON técnico:
 ### reconhece somente o broadcast `; ` criado por essas versões e recompõe os
 ### membros. Nunca interpreta `|` nem fabrica CPF.
  nomes_nv <- nomes_linha[nzchar(nomes_linha)]
  broadcast <- length(nomes_nv) > 1L && length(unique(nomes_nv)) == 1L
  if (broadcast) {
    nomes <- trimws(strsplit(nomes_nv[1L], ";", fixed = TRUE)[[1L]])
    nomes <- nomes[nzchar(nomes)]
    cpfs <- cpfs_linha[nzchar(cpfs_linha)]
    m <- max(length(nomes), length(cpfs), 0L)
    length(nomes) <- m; length(cpfs) <- m
    nomes[is.na(nomes)] <- ""; cpfs[is.na(cpfs)] <- ""
    return(list(nomes = nomes, cpfs = cpfs, fonte = "fallback_broadcast_sem_json"))
  }

  pos <- which(nzchar(nomes_linha) | nzchar(cpfs_linha))
  if (!length(pos)) return(list(nomes = character(), cpfs = character(), fonte = "repeat_vazio"))
  list(nomes = nomes_linha[pos], cpfs = cpfs_linha[pos], fonte = "repeat_esparso_observado")
}

monitora_coletores_repeat_materializar_corrig <- function(dt,
                                                           output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                           log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                           exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                                           contexto = "pre_materializacao_registros_corrig") {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (!n) return(dt)
  tem_nome <- any(c("coletor/nome", "COLETORES", "Coletores") %in% names(dt))
  tem_cpf <- any(c("coletor/cpf", "CPF (coletor)", "cpf (coletor)") %in% names(dt))
  col_json <- monitora_coletores_repeat_col_json()
  if (!tem_nome && !tem_cpf && !(col_json %in% names(dt))) return(dt)

  if (!("coletor/nome" %in% names(dt))) data.table::set(dt, j = "coletor/nome", value = rep("", n))
  if (!("COLETORES" %in% names(dt))) data.table::set(dt, j = "COLETORES", value = rep("", n))
  col_ver <- monitora_coletores_repeat_col_versao()
  if (!("coletor/cpf" %in% names(dt)) && (tem_cpf || col_json %in% names(dt))) data.table::set(dt, j = "coletor/cpf", value = rep("", n))
  col_cpf <- intersect(c("coletor/cpf", "CPF (coletor)", "cpf (coletor)"), names(dt))[1L]
 ### fread pode inferir CPF como numérico em checkpoints sem máscara. O repeat
 ### escreve vazios e zeros à esquerda, portanto a coluna precisa ser textual
 ### antes da redistribuição esparsa; o conteúdo é apenas convertido, não
 ### concatenado, replicado ou inferido.
  if (!is.na(col_cpf) && !is.character(dt[[col_cpf]])) {
    data.table::set(dt, j = col_cpf, value = as.character(dt[[col_cpf]]))
  }

  coleta <- monitora_coletores_repeat_coleta(dt)
  grupos <- split(seq_len(n), coleta, drop = TRUE)
  audit <- vector("list", length(grupos))
  kk <- 0L
  for (chave in names(grupos)) {
    ii <- grupos[[chave]]
    rec <- monitora_coletores_repeat_extrair_grupo(dt, ii)
    m <- max(length(rec$nomes), length(rec$cpfs), 0L)
    if (m > length(ii)) stop("Há mais membros no repeat de coletores do que linhas disponíveis na coleta; exportação bloqueada para evitar perda.", call. = FALSE)
    nomes_saida <- rep("", length(ii))
    cpfs_saida <- rep("", length(ii))
    if (m) {
      nomes_saida[seq_len(m)] <- rec$nomes
      cpfs_saida[seq_len(m)] <- rec$cpfs
    }
    data.table::set(dt, i = ii, j = "coletor/nome", value = nomes_saida)
    data.table::set(dt, i = ii, j = "COLETORES", value = nomes_saida)
    if (!is.na(col_cpf)) {
      data.table::set(dt, i = ii, j = col_cpf, value = cpfs_saida)
    }
    kk <- kk + 1L
    audit[[kk]] <- data.table::data.table(
      contexto = as.character(contexto)[1L], COLETA = if (startsWith(chave, ".__linha_sem_coleta__")) "" else chave,
      n_linhas = length(ii), n_membros_repeat = m,
      n_nomes_preenchidos = sum(nzchar(rec$nomes)), n_cpfs_preenchidos = sum(nzchar(rec$cpfs)),
      fonte_repeat = rec$fonte, equipe_exposta_todas_linhas = FALSE,
      cpf_inferido = FALSE, status = "preservado_repeat_esparso_template"
    )
  }
  cols_tecnicas <- intersect(c(col_json, col_ver), names(dt))
  if (length(cols_tecnicas)) dt[, (cols_tecnicas) := NULL]
  aud <- data.table::rbindlist(audit[seq_len(kk)], fill = TRUE, use.names = TRUE)
  dir_aud <- file.path(output_dir, "03_auditorias", "persistencia")
  dir.create(dir_aud, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
  try(data.table::fwrite(aud, file.path(dir_aud, "auditoria_coletores_repeat_linhagem.csv"), na = ""), silent = TRUE)
  try(data.table::fwrite(aud, file.path(log_dir, paste0("auditoria_coletores_repeat_linhagem_", exec_id, ".csv")), na = ""), silent = TRUE)
  data.table::setattr(dt, "monitora_coletores_repeat_auditoria", aud)
  dt[]
}

monitora_coletores_repeat_projetar_validado <- function(dt, atributo) {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  out <- rep("", n)
  coleta <- monitora_coletores_repeat_coleta(dt)
  grupos <- split(seq_len(n), coleta, drop = TRUE)
  for (ii in grupos) {
    rec <- monitora_coletores_repeat_extrair_grupo(dt, ii)
    vals <- if (identical(atributo, "coletor/nome")) rec$nomes else rec$cpfs
    if (length(vals) > length(ii)) stop("Repeat de coletores não cabe no grupo de registros_validados; exportação bloqueada.", call. = FALSE)
    if (length(vals)) out[ii[seq_along(vals)]] <- vals
  }
  list(valor = out, coluna = atributo, estrategia = "repeat_coletor_esparso_template_ordem_sismonitora")
}

monitora_validados_derivar_ou_mapear_coluna <- function(dt, atributo, formato, largura) {
  n <- nrow(dt)
  if (atributo %in% c("coletor/nome", "coletor/cpf")) return(monitora_coletores_repeat_projetar_validado(dt, atributo))
  if (identical(atributo, "data_do_registro")) return(monitora_validados_derive_datetime(dt, "data_do_registro"))
  if (identical(atributo, "data_do_recebimento")) return(monitora_validados_derive_datetime(dt, "data_do_recebimento"))
  if (identical(atributo, "data_hora/data")) return(monitora_validados_derive_data_hora(dt, "data"))
  if (identical(atributo, "data_hora/hora")) return(monitora_validados_derive_data_hora(dt, "hora"))
  if (identical(atributo, "coleta_uuid")) return(monitora_validados_uuid_por_coleta_ou_sintetico(dt, "coleta_uuid"))
  if (identical(atributo, "uuid")) return(monitora_validados_uuid_por_coleta_ou_sintetico(dt, "uuid"))
  if (identical(atributo, "amostragem/registro/uuid")) return(monitora_validados_uuid_registro_ou_sintetico(dt))

 ### Os 12 hábitos obrigatórios são descobertos no XLSForm atual e já
 ### chegam a esta etapa reconciliados, por versão e por posição, no campo
 ### físico canônico de registros_corrig. Aliases históricos podem conservar o
 ### vetor bruto do repeat (por exemplo, "---|terrestre|terrestre") e não podem
 ### ser comparados novamente como se fossem escalares da linha. A projeção
 ### validada usa a mesma regra contratual/resolvedor do diagnóstico e do SANHAB;
 ### os aliases brutos continuam preservados em registros_corrig e na linhagem.
  regras_habito <- tryCatch(
    monitora_correcao_regras_habito_contrato_atual(),
    error = function(e) data.table::data.table()
  )
  regra_habito <- if (nrow(regras_habito)) {
    regras_habito[as.character(atributo_canonico) == as.character(atributo)]
  } else data.table::data.table()
  if (nrow(regra_habito) == 1L) {
    col_habito <- tryCatch(
      monitora_correcao_resolver_coluna_habito(
        dt,
        regra_habito$categoria[1L],
        regra_habito$forma[1L]
      ),
      error = function(e) NA_character_
    )
    valor_habito <- if (!is.na(col_habito) && col_habito %in% names(dt)) {
      monitora_validados_limpar_ausencia_saida(dt[[col_habito]])
    } else rep("", n)
    return(list(
      valor = monitora_validados_formatar_valor(valor_habito, formato, largura),
      coluna = col_habito,
      estrategia = "mapeada_habito_canonico_contrato_atual_pos_reconciliacao"
    ))
  }

  if (identical(atributo, "ciclo")) {
    p <- monitora_validados_pegar(dt, c("CICLO", "ciclo", "amostragem/ciclo"), n)
    v <- monitora_validados_preencher_por_coleta(dt, p$valor, padrao = "nao_informado")
    return(list(valor = v, coluna = p$coluna, estrategia = "mapeada_completada_por_coleta_ou_nao_informado"))
  }
  if (identical(atributo, "campanha")) {
    p <- monitora_validados_pegar(dt, c("CAMPANHA", "campanha", "amostragem/campanha"), n)
    v <- monitora_validados_preencher_por_coleta(dt, p$valor, padrao = "nao_informada")
    return(list(valor = v, coluna = p$coluna, estrategia = "mapeada_completada_por_coleta_ou_nao_informada"))
  }

 ## Campos de controle/domínio do XLSForm alvo 21FEV25.
 ## Devem ser resolvidos antes do mapeamento genérico, pois registros_corrig
 ## pode conter "NA" textual, protocolo histórico ou proveniência interna.
  if (identical(atributo, "validado")) {
    p <- monitora_validados_pegar(dt, c("validado", "VALIDADO"), n)
    v <- monitora_validados_limpar_ausencia_saida(p$valor)
    v[!nzchar(v)] <- "nao"
    v <- tolower(v)
    v[!(v %in% c("sim", "nao"))] <- "nao"
    return(list(valor = v, coluna = p$coluna, estrategia = "mapeada_ou_sintetizada_padrao_nao"))
  }
  if (identical(atributo, "controle_versao")) {
    p <- monitora_validados_pegar(dt, c("controle_versao", "CONTROLE_VERSAO"), n)
    v <- monitora_validados_formatar_valor(p$valor, "inteiro_texto")
    v[!nzchar(v)] <- "2025022101"
    return(list(valor = v, coluna = p$coluna, estrategia = "mapeada_ou_sintetizada_versao_xlsform_21FEV25"))
  }
  if (identical(atributo, "protocolo")) {
    return(list(valor = rep("PLANTASHERBACEASELENHOSAS_CAMPSAV_21FEV25", n), coluna = NA_character_, estrategia = "sintetizada_protocolo_xlsform_21FEV25"))
  }
  if (identical(atributo, "planilha_upload")) {
    tipo <- monitora_validados_pegar(
      dt,
      c("MONITORA_TIPO_ENTRADA", "planilha_upload"),
      n,
      bloquear_conflito = FALSE
    )
    tv <- tolower(monitora_validados_limpar_ausencia_saida(tipo$valor))
    v <- ifelse(grepl("planilha|digital", tv, perl = TRUE), "sim", "nao")
    return(list(valor = v, coluna = tipo$coluna, estrategia = "sintetizada_dominio_planilha_upload"))
  }
  if (identical(atributo, "amostragem/num_placa")) {
    return(monitora_validados_derivar_num_placa(dt, "num_placa"))
  }
  if (identical(atributo, "amostragem/num_placa_formatado")) {
    return(monitora_validados_derivar_num_placa(dt, "num_placa_formatado"))
  }
  if (identical(atributo, "amostragem/registro/forma_vida_outros")) {
 ## registros_validados.csv não herda diretamente campos históricos
 ## de "outra forma de vida". Esses campos são consumidos e auditados pela
 ## sanitização validados em registros_corrig. A saída validada deve usar
 ## somente o campo atual 21FEV25 já sanitizado.
    atual <- monitora_validados_pegar(dt, c(
      "amostragem/registro/forma_vida_outros",
      "Outras plantas terrestres, líquens e/ou fungos\u200b: (amostragem/registro)",
      "Outras plantas terrestres, líquens e/ou fungos: (amostragem/registro)"
    ), n)
    return(list(valor = atual$valor, coluna = atual$coluna, estrategia = "mapeada_campo_atual_pos_sanitizacao_antes_registros_validados"))
  }
  if (identical(atributo, "amostragem/registro/forma_serrapilheira")) {
    atual <- monitora_validados_pegar(dt, c(
      "amostragem/registro/forma_serrapilheira",
      "Materiais botânicos em decomposição no solo observados: (amostragem/registro)",
      "Material botânico em decomposição no solo observado: (amostragem/registro)"
    ), n)
    tipo <- monitora_validados_pegar(dt, c(
      "amostragem/registro/tipo_forma_vida",
      "**Encostam** na vareta: (amostragem/registro)"
    ), n)
    nat <- monitora_validados_pegar(dt, c("amostragem/registro/forma_vida_nativa", "Formas de vida de plantas <span style=\"\"color:red\"\">nativas:</span> (amostragem/registro)"), n)
    exo <- monitora_validados_pegar(dt, c("amostragem/registro/forma_vida_exotica", "Formas de vida de plantas <span style=\"\"color:red\"\">exóticas:</span> (amostragem/registro)"), n)
    seca <- monitora_validados_pegar(dt, c("amostragem/registro/forma_vida_seca_morta", "Formas de vida de plantas <span style=\"\"color:red\"\">secas ou mortas:</span> (amostragem/registro)"), n)
    v <- monitora_validados_limpar_ausencia_saida(atual$valor)
    contem_serrapilheira <- monitora_validados_tem_token(tipo$valor, "serrapilheira") |
      monitora_validados_tem_token(nat$valor, "serrapilheira") |
      monitora_validados_tem_token(exo$valor, "serrapilheira") |
      monitora_validados_tem_token(seca$valor, "serrapilheira")
    idx <- !nzchar(v) & contem_serrapilheira
    if (any(idx)) v[idx] <- "serrapilheira"
    origem <- paste(unique(c(atual$coluna, tipo$coluna, nat$coluna, exo$coluna, seca$coluna)[!is.na(c(atual$coluna, tipo$coluna, nat$coluna, exo$coluna, seca$coluna))]), collapse = " + ")
    return(list(valor = v, coluna = origem, estrategia = "mapeada_ou_derivada_serrapilheira_historica"))
  }
  if (identical(atributo, "amostragem/especie")) return(list(valor = rep("sim", n), coluna = NA_character_, estrategia = "sintetizada_padrao_sim"))

  mapeado <- monitora_validados_pegar(dt, atributo, n)
  if (length(mapeado$colunas)) {
    return(list(
      valor = monitora_validados_formatar_valor(mapeado$valor, formato, largura),
      coluna = mapeado$coluna,
      estrategia = "mapeada_coalescencia_multiversao"
    ))
  }

  list(valor = rep("", n), coluna = NA_character_, estrategia = "opcional_sem_origem_vazio")
}

monitora_validados_validar_formatos_saida <- function(out, schema) {
  problemas <- vector("list", nrow(schema))
  k <- 0L
  for (ii in seq_len(nrow(schema))) {
    col <- schema$atributo[ii]
    fmt <- schema$formato[ii]
    x <- as.character(out[[col]])
    x <- x[!is.na(x) & nzchar(x)]
    ok <- TRUE
    if (length(x)) {
      if (identical(fmt, "datetime_iso_espaco")) ok <- all(grepl("^[0-9]{4}-[0-9]{2}-[0-9]{2} [0-9]{2}:[0-9]{2}:[0-9]{2}$", x, perl = TRUE))
      if (identical(fmt, "data_iso")) ok <- all(grepl("^[0-9]{4}-[0-9]{2}-[0-9]{2}$", x, perl = TRUE))
      if (identical(fmt, "hora_hms_millis_tz")) ok <- all(grepl(monitora_validados_hora_hms_millis_tz_regex(), x, perl = TRUE))
      if (identical(fmt, "inteiro_texto")) ok <- all(grepl("^[0-9]+$", x, perl = TRUE))
      if (identical(fmt, "inteiro_texto_zero_esquerda")) ok <- all(grepl("^[0-9]+$", x, perl = TRUE) & (is.na(schema$largura[ii]) | nchar(x) >= schema$largura[ii]))
      if (identical(fmt, "numero_texto_ponto")) ok <- all(grepl("^[0-9]+(\\.[0-9]+)?$", x, perl = TRUE))
      if (identical(fmt, "uuid_texto")) ok <- all(monitora_validados_uuid_valido(x))
    }
    if (!isTRUE(ok)) {
      k <- k + 1L
      problemas[[k]] <- data.table::data.table(
        posicao = schema$posicao[ii], atributo = col, formato_esperado = fmt,
        n_valores_nao_vazios = length(x), exemplos = paste(utils::head(unique(x), 5L), collapse = " | "),
        bloqueante = TRUE, motivo_bloqueio = "formato_incompativel"
      )
    }
  }
  if (!k) {
    return(data.table::data.table(
      posicao = integer(), atributo = character(), formato_esperado = character(),
      n_valores_nao_vazios = integer(), exemplos = character(),
      bloqueante = logical(), motivo_bloqueio = character()
    ))
  }
  data.table::rbindlist(problemas[seq_len(k)], fill = TRUE)
}

monitora_validados_auditar_cardinalidade <- function(out) {
  coleta <- out[["coleta"]]
  aux <- data.table::data.table(
    atributo = c("coleta_uuid", "uuid", "amostragem/registro/uuid"),
    nivel_esperado = c("um_valor_por_coleta", "um_valor_por_coleta", "um_valor_por_linha"),
    status = "ok",
    n_problemas = 0L,
    detalhe = ""
  )
  for (att in c("coleta_uuid", "uuid")) {
    dt <- data.table::data.table(coleta = coleta, valor = out[[att]])
    bad <- dt[nzchar(coleta) & nzchar(valor), .(n_valores = data.table::uniqueN(valor)), by = coleta][n_valores > 1L]
    aux[atributo == att, `:=`(status = if (nrow(bad)) "falha" else "ok", n_problemas = nrow(bad), detalhe = if (nrow(bad)) paste(utils::head(bad$coleta, 5L), collapse = " | ") else "")]
  }
  vreg <- out[["amostragem/registro/uuid"]]
  dup <- sum(duplicated(vreg[nzchar(vreg)]))
  vaz <- sum(!nzchar(vreg))
  aux[atributo == "amostragem/registro/uuid", `:=`(status = if ((dup + vaz) > 0L) "falha" else "ok", n_problemas = dup + vaz, detalhe = paste0("duplicados=", dup, "; vazios=", vaz))]
  aux
}


### --------------------
### Auditoria contratual do produto registros_corrig.csv nos atributos que
### alimentam registros_validados.csv. Ela reaproveita as interpretações,
### normalizações e validações do exportador validado, mas materializa o status no
### nível do produto de origem para deixar explícito que registros_validados.csv é
### apenas a exportação estruturada quando registros_corrig já está coerente.
monitora_publicacao_z_atributos_problema <- function(dt, preferir = c("atributo", "att", "campo")) {
  dt <- tryCatch(data.table::as.data.table(dt), error = function(e) data.table::data.table())
  if (!nrow(dt)) return(character())
  cc <- intersect(preferir, names(dt))
  if (!length(cc)) return(character())
  unique(as.character(dt[[cc[1L]]]))
}

monitora_publicacao_z_motivos_por_atributo <- function(dt, atributo) {
  dt <- tryCatch(data.table::as.data.table(dt), error = function(e) data.table::data.table())
  if (!nrow(dt) || !("atributo" %in% names(dt))) return("")
  z <- dt[as.character(atributo) == as.character(dt$atributo)]
  if (!nrow(z)) return("")
  cols_motivo <- intersect(c("motivo_bloqueio", "regra", "tipo", "detalhe"), names(z))
  vals <- character()
  for (cc in cols_motivo) vals <- c(vals, as.character(z[[cc]]))
  vals <- unique(vals[!is.na(vals) & nzchar(vals)])
  paste(vals, collapse = "; ")
}



### -------------------------------------------------------------
### Governança de bloqueios de registros_validados.csv. Bloqueios contratuais
### da exportação validada NÃO podem impedir a materialização de
### registros_corrig.csv; eles apenas bloqueiam registros_validados.csv e geram
### auditoria explícita para correção posterior.
monitora_registros_validados_gravar_bloqueios <- function(resumo = NULL,
                                                           vazias_obrig = NULL,
                                                           problemas_fmt = NULL,
                                                           problemas_dom = NULL,
                                                           problemas_cond = NULL,
                                                           problemas_sanitizacao_outras = NULL,
                                                           problemas_sanitizacao_desconhecida = NULL,
                                                           card = NULL,
                                                           problemas_chave = NULL,
                                                           mensagem = "",
                                                           contexto = "bloqueio_registros_validados",
                                                           output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                           log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                           exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)) {
  dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
  dir.create(file.path(output_dir, "03_auditorias", "contrato_xlsform"), recursive = TRUE, showWarnings = FALSE)
  dir.create(file.path(output_dir, "02_painel_correcoes", "ocorrencias_diagnosticas", "pos_painel"), recursive = TRUE, showWarnings = FALSE)
  linhas <- list()
  add <- function(origem, dt, atributo_col = "atributo", motivo_padrao = origem) {
    dd <- tryCatch(data.table::as.data.table(dt), error = function(e) data.table::data.table())
    if (!nrow(dd)) return(invisible(NULL))
    atributo <- if (atributo_col %in% names(dd)) as.character(dd[[atributo_col]]) else if ("att" %in% names(dd)) as.character(dd$att) else rep(NA_character_, nrow(dd))
    motivo_cols <- intersect(c("motivo_bloqueio", "regra", "tipo", "detalhe", "mensagem", "status"), names(dd))
    detalhe <- if (length(motivo_cols)) apply(as.data.frame(dd[, ..motivo_cols]), 1L, function(z) paste(unique(z[!is.na(z) & nzchar(z)]), collapse = "; ")) else rep("", nrow(dd))
    if (!length(detalhe)) detalhe <- rep("", nrow(dd))
    linhas[[length(linhas) + 1L]] <<- data.table::data.table(
      exec_id = as.character(exec_id), contexto = as.character(contexto)[1L],
      produto = "registros_validados.csv", status = "bloqueado",
      origem_bloqueio = as.character(origem), atributo = atributo,
      n_linhas = as.integer(nrow(dd)), detalhe = detalhe,
      mensagem_geral = as.character(mensagem)[1L], timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    )
    invisible(NULL)
  }
  add("obrigatorio_vazio", vazias_obrig)
  add("formato_invalido", problemas_fmt)
  add("dominio_xlsform_invalido", problemas_dom)
  add("condicional_xlsform_invalido", problemas_cond)
  add("sanitizacao_outras_formas", problemas_sanitizacao_outras)
  add("sanitizacao_desconhecida", problemas_sanitizacao_desconhecida)
  card_bloq <- tryCatch(data.table::as.data.table(card), error = function(e) data.table::data.table())
  if (nrow(card_bloq) && "status" %in% names(card_bloq)) card_bloq <- card_bloq[is.na(status) | status != "ok"]
  add("cardinalidade_uuid", card_bloq)
  add("chave_unica", problemas_chave)
  bloq <- if (length(linhas)) data.table::rbindlist(linhas, fill = TRUE, use.names = TRUE) else data.table::data.table(
    exec_id = as.character(exec_id), contexto = as.character(contexto)[1L], produto = "registros_validados.csv",
    status = "ok", origem_bloqueio = character(), atributo = character(), n_linhas = integer(), detalhe = character(), mensagem_geral = character(), timestamp = character()
  )
  resumo_dt <- tryCatch(data.table::as.data.table(resumo), error = function(e) data.table::data.table())
  if (nrow(bloq)) {
    data.table::fwrite(bloq, file.path(output_dir, "03_auditorias", "contrato_xlsform", "auditoria_registros_validados_bloqueios.csv"), sep = ",", quote = "auto", na = "")
    data.table::fwrite(bloq, file.path(log_dir, paste0("auditoria_registros_validados_bloqueios_", exec_id, ".csv")), sep = ",", quote = "auto", na = "")
  }
  if (nrow(resumo_dt)) {
    resumo_dt[, `:=`(produto = "registros_validados.csv", status_validacao = ifelse(any(suppressWarnings(as.integer(n_bloqueios)) > 0L, na.rm = TRUE), "bloqueado", "ok"), contexto_bloqueio = as.character(contexto)[1L])]
    data.table::fwrite(resumo_dt, file.path(output_dir, "03_auditorias", "contrato_xlsform", "resumo_registros_validados_bloqueios.csv"), sep = ",", quote = "auto", na = "")
  }
 ### Ocorrência diagnóstica específica para o caso que antes aparecia tarde
 ### demais: descritor/foto de desconhecida sem token desconhecida. Não corrige
 ### automaticamente; explicita a pendência contratual para próxima ação.
  desc <- tryCatch(data.table::as.data.table(problemas_sanitizacao_desconhecida), error = function(e) data.table::data.table())
  if (nrow(desc)) {
    desc_out <- data.table::copy(desc)
    desc_out[, `:=`(exec_id = as.character(exec_id), tipo_ocorrencia = "desconhecida_dependente_sem_token", status = "bloqueia_registros_validados", timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S"))]
    data.table::fwrite(desc_out, file.path(output_dir, "02_painel_correcoes", "ocorrencias_diagnosticas", "pos_painel", "registros_desconhecida_dependente_sem_token_pos_painel.csv"), sep = ",", quote = "auto", na = "")
  }
  assign("MONITORA_REGISTROS_VALIDADOS_BLOQUEADO", nrow(bloq) > 0L, envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_VALIDADOS_BLOQUEIOS_ULTIMA", bloq, envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_VALIDADOS_GERADO", FALSE, envir = .GlobalEnv)
  if (exists("monitora_publicacao_g_log", mode = "function") && nrow(bloq)) {
    monitora_publicacao_g_log("registros_validados.csv bloqueado sem bloquear registros_corrig.csv [", contexto, "]: ", nrow(bloq), " linha(s) de auditoria de bloqueio; ver 03_auditorias/contrato_xlsform/auditoria_registros_validados_bloqueios.csv")
  }
  invisible(bloq)
}
### ---------------------------------------------------------

### - -----------------------------------------------------------
### Enriquecimento opt-in (MONITORA_DIAGNOSTICO_CONTRATO_UNICO_REGISTROS_VALIDADOS,
### default "N") da auditoria contratual XLSForm21 (função abaixo) com
### severidade/bloqueio já derivados em monitora_contrato_unico_indices
### (nenhum fato novo). Reaproveita
### monitora_contrato_unico_diagnosticar_observado_canonico , o mesmo mapeador
### observado->canônico já testado em /, evitando duplicar regra
### de match fora do contrato único. Com a flag desligada, ausência da função ou
### qualquer falha, retorna data.table vazio -- degradação segura: o merge do
### chamador é left-join por `atributo`, nunca remove/duplica linha da
### auditoria e nunca participa do cálculo de `bloqueante`.
monitora_registros_corrig_severidade_contrato_unico <- function(atributos) {
  vazio <- data.table::data.table(
    atributo = character(),
    severidade_contrato_unico = character(),
    bloqueia_migracao_automatica_contrato_unico = logical()
  )
  flag <- get0("MONITORA_DIAGNOSTICO_CONTRATO_UNICO_REGISTROS_VALIDADOS", ifnotfound = "N", inherits = TRUE)
  if (!identical(as.character(flag)[1L], "S")) return(vazio)
  if (!exists("monitora_contrato_unico_diagnosticar_observado_canonico", mode = "function")) return(vazio)
  tryCatch({
    mapa <- data.table::as.data.table(monitora_contrato_unico_diagnosticar_observado_canonico(
      colunas_observadas = atributos,
      contexto = "pos_validacao_registros_corrig_xlsform21"
    ))
    if (!nrow(mapa) || !all(c("coluna_observada", "severidade", "bloqueia_migracao_automatica") %in% names(mapa))) return(vazio)
    data.table::data.table(
      atributo = as.character(mapa$coluna_observada),
      severidade_contrato_unico = as.character(mapa$severidade),
      bloqueia_migracao_automatica_contrato_unico = as.logical(mapa$bloqueia_migracao_automatica)
    )
  }, error = function(e) vazio)
}
### - ---------------------------------------------------

monitora_registros_corrig_gravar_auditoria_contrato_xlsform21 <- function(auditoria,
                                                                           vazias_obrig = NULL,
                                                                           problemas_fmt = NULL,
                                                                           problemas_dom = NULL,
                                                                           problemas_cond = NULL,
                                                                           problemas_sanitizacao_outras = NULL,
                                                                           problemas_sanitizacao_desconhecida = NULL,
                                                                           card = NULL,
                                                                           problemas_chave = NULL,
                                                                           ajustes_xlsform21 = NULL,
                                                                           output_dir = MONITORA_OUTPUT_DIR,
                                                                           log_dir = MONITORA_LOG_DIR,
                                                                           exec_id = MONITORA_EXEC_ID,
                                                                           contexto = "pre_materializacao_registros_corrig") {
  aud <- data.table::as.data.table(auditoria)
  if (!nrow(aud)) return(invisible(data.table::data.table()))
  dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)

  attrs_fmt <- monitora_publicacao_z_atributos_problema(problemas_fmt)
  attrs_dom <- monitora_publicacao_z_atributos_problema(problemas_dom)
  attrs_cond <- monitora_publicacao_z_atributos_problema(problemas_cond)
  attrs_san_outras <- monitora_publicacao_z_atributos_problema(problemas_sanitizacao_outras)
  attrs_san_desc <- monitora_publicacao_z_atributos_problema(problemas_sanitizacao_desconhecida)
  attrs_obrig <- monitora_publicacao_z_atributos_problema(vazias_obrig)
  attrs_card <- character()
  card_dt <- tryCatch(data.table::as.data.table(card), error = function(e) data.table::data.table())
  if (nrow(card_dt) && all(c("atributo", "status") %in% names(card_dt))) attrs_card <- unique(as.character(card_dt[status != "ok"]$atributo))
  chave_bloq <- tryCatch(nrow(data.table::as.data.table(problemas_chave)) > 0L, error = function(e) FALSE)

  aj <- tryCatch(data.table::as.data.table(ajustes_xlsform21), error = function(e) data.table::data.table())
  if (nrow(aj) && all(c("atributo", "n_ajustes") %in% names(aj))) {
    aj_sum <- aj[, .(n_ajustes_xlsform21 = sum(suppressWarnings(as.integer(n_ajustes)), na.rm = TRUE)), by = atributo]
  } else {
    aj_sum <- data.table::data.table(atributo = character(), n_ajustes_xlsform21 = integer())
  }

  contrato <- data.table::copy(aud)
  contrato[, `:=`(
    produto = "registros_corrig.csv",
    contexto = as.character(contexto)[1L],
    mapeado = !is.na(coluna_origem_registros_corrig) | grepl("^(sintetizada|derivada|mapeada_ou_derivada|mapeada_campo_atual|opcional_sem_origem)", as.character(estrategia), perl = TRUE),
    formato_ok = !(atributo %in% unique(c(attrs_fmt, attrs_obrig))),
    dominio_ok = !(atributo %in% attrs_dom),
    condicional_ok = !(atributo %in% attrs_cond),
    sanitizacao_ok = !(atributo %in% unique(c(attrs_san_outras, attrs_san_desc))),
    uuid_cardinalidade_ok = !(atributo %in% attrs_card),
    chave_unica_ok = TRUE,
    bloqueante = FALSE,
    motivo = ""
  )]
  if (isTRUE(chave_bloq) && "coleta" %in% contrato$atributo) contrato[atributo == "coleta", chave_unica_ok := FALSE]
  if (nrow(aj_sum)) contrato <- merge(contrato, aj_sum, by = "atributo", all.x = TRUE, sort = FALSE) else contrato[, n_ajustes_xlsform21 := 0L]
  contrato[is.na(n_ajustes_xlsform21), n_ajustes_xlsform21 := 0L]

  contrato[, bloqueante := !formato_ok | !dominio_ok | !condicional_ok | !sanitizacao_ok | !uuid_cardinalidade_ok | !chave_unica_ok]
  if (nrow(contrato)) {
    motivos <- vapply(contrato$atributo, function(aa) {
      m <- character()
      if (aa %in% attrs_obrig) m <- c(m, "atributo_obrigatorio_vazio_apos_interpretacao")
      if (aa %in% attrs_fmt) m <- c(m, monitora_publicacao_z_motivos_por_atributo(problemas_fmt, aa))
      if (aa %in% attrs_dom) m <- c(m, monitora_publicacao_z_motivos_por_atributo(problemas_dom, aa))
      if (aa %in% attrs_cond) m <- c(m, monitora_publicacao_z_motivos_por_atributo(problemas_cond, aa))
      if (aa %in% attrs_san_outras) m <- c(m, monitora_publicacao_z_motivos_por_atributo(problemas_sanitizacao_outras, aa))
      if (aa %in% attrs_san_desc) m <- c(m, monitora_publicacao_z_motivos_por_atributo(problemas_sanitizacao_desconhecida, aa))
      if (aa %in% attrs_card) m <- c(m, "uuid_cardinalidade_invalida")
      if (isTRUE(chave_bloq) && identical(aa, "coleta")) m <- c(m, "duplicidade_coleta_ponto_amostral")
      m <- unique(m[!is.na(m) & nzchar(m)])
      paste(m, collapse = "; ")
    }, character(1L))
    contrato[, motivo := motivos]
  }
  contrato[, status_contrato := ifelse(bloqueante, "bloqueante", "ok")]

 ### -: enriquecimento opt-in aditivo (ver
 ### monitora_registros_corrig_severidade_contrato_unico acima). Colunas
 ### novas ficam NA quando a flag está desligada ou o match falha; não
 ### alteram `bloqueante`/`status_contrato` nem removem/duplicam linha.
  contrato[, `:=`(severidade_contrato_unico = NA_character_, bloqueia_migracao_automatica_contrato_unico = NA)]
  sev_contrato_unico <- monitora_registros_corrig_severidade_contrato_unico(contrato$atributo)
  if (nrow(sev_contrato_unico)) {
    contrato[sev_contrato_unico, on = "atributo",
             `:=`(severidade_contrato_unico = i.severidade_contrato_unico,
                  bloqueia_migracao_automatica_contrato_unico = i.bloqueia_migracao_automatica_contrato_unico)]
  }
  contrato_logico <- data.table::copy(contrato)
  contrato_auditoria <- monitora_privacidade_sanitizar_auditoria(contrato, mascarar_exemplos = FALSE)

  resumo <- data.table::data.table(
    exec_id = as.character(exec_id),
    produto = "registros_corrig.csv",
    contrato = "atributos_que_alimentam_registros_validados_xlsform21",
    contexto = as.character(contexto)[1L],
    n_atributos = nrow(contrato_logico),
    n_bloqueios = sum(contrato_logico$bloqueante, na.rm = TRUE),
    n_formato_invalido = sum(!contrato_logico$formato_ok, na.rm = TRUE),
    n_dominio_invalido = sum(!contrato_logico$dominio_ok, na.rm = TRUE),
    n_condicional_invalido = sum(!contrato_logico$condicional_ok, na.rm = TRUE),
    n_sanitizacao_invalida = sum(!contrato_logico$sanitizacao_ok, na.rm = TRUE),
    n_ajustes_xlsform21 = sum(suppressWarnings(as.integer(contrato_logico$n_ajustes_xlsform21)), na.rm = TRUE),
    n_bloqueios_alta_severidade_contrato_unico = sum(contrato_logico$bloqueante &
      !is.na(contrato_logico$severidade_contrato_unico) &
      contrato_logico$severidade_contrato_unico == "alta", na.rm = TRUE),
    status = ifelse(any(contrato_logico$bloqueante, na.rm = TRUE), "bloqueante", "ok"),
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
  )

  arq_log <- file.path(log_dir, paste0("auditoria_registros_corrig_contrato_xlsform21_", exec_id, ".csv"))
  arq_out <- file.path(output_dir, "auditoria_registros_corrig_contrato_xlsform21.csv")
  arq_resumo_log <- file.path(log_dir, paste0("auditoria_registros_corrig_contrato_xlsform21_resumo_", exec_id, ".csv"))
  arq_resumo_out <- file.path(output_dir, "auditoria_registros_corrig_contrato_xlsform21_resumo.csv")
  data.table::fwrite(contrato_auditoria, arq_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(contrato_auditoria, arq_out, sep = ",", quote = "auto", na = "")
  data.table::fwrite(resumo, arq_resumo_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(resumo, arq_resumo_out, sep = ",", quote = "auto", na = "")
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento(
      "registros_corrig_contrato_xlsform21",
      ifelse(any(contrato_logico$bloqueante, na.rm = TRUE), "ERRO", "INFO"),
      arq_log,
      paste0("auditoria contratual de registros_corrig nos atributos do XLSForm 21FEV25: ", nrow(contrato_logico), " atributo(s), bloqueios=", sum(contrato_logico$bloqueante, na.rm = TRUE)),
      "registros_validados herda de registros_corrig saneado"
    )
  }
 ### -: alerta opt-in complementar (mesma flag do
 ### enriquecimento acima) -- cruza os atributos já bloqueantes por regra
 ### própria do XLSForm21 com a severidade do contrato único, só para
 ### visibilidade extra; não é uma nova condição de bloqueio.
  n_bloq_alta_sev_cu <- sum(contrato_logico$bloqueante &
    !is.na(contrato_logico$severidade_contrato_unico) &
    contrato_logico$severidade_contrato_unico == "alta", na.rm = TRUE)
  if (isTRUE(n_bloq_alta_sev_cu > 0L)) {
    warning(
      n_bloq_alta_sev_cu, " atributo(s) bloqueante(s) na auditoria contratual de registros_corrig (contexto=",
      as.character(contexto)[1L], ") correspondem a alta severidade do contrato único; revisar ", basename(arq_log),
      " (diagnóstico opt-in, não introduz bloqueio além da regra já existente)",
      call. = FALSE
    )
  }
  invisible(list(auditoria = contrato_auditoria, resumo = resumo))
}
### ----------------

### materializa no produto mestre somente o efeito determinístico das
### regras XLSForm já existentes. Recebe a matriz antes/depois calculada pelo
### próprio exportador, evitando uma segunda projeção integral de 129 colunas.
### A verificação reprojeta apenas os atributos efetivamente alterados.
monitora_publicacao_aa_materializar_regras_xlsform21_corrig <- function(registros_corrig,
                                                                        out_antes,
                                                                        out_depois,
                                                                        ajustes,
                                                                        schema,
                                                                        output_dir = MONITORA_OUTPUT_DIR,
                                                                        log_dir = MONITORA_LOG_DIR,
                                                                        exec_id = MONITORA_EXEC_ID) {
  dt <- registros_corrig
  if (!data.table::is.data.table(dt)) data.table::setDT(dt)
  antes <- data.table::as.data.table(out_antes)
  depois <- data.table::as.data.table(out_depois)
  aj <- data.table::as.data.table(ajustes)
  schema <- data.table::as.data.table(schema)
  vazio_prob <- data.table::data.table(
    regra = character(), atributo = character(), n_problemas = integer(),
    exemplos_coleta = character(), detalhe = character(),
    bloqueante = logical(), motivo_bloqueio = character()
  )
  if (!nrow(aj) || nrow(dt) != nrow(antes) || nrow(dt) != nrow(depois)) {
    return(list(dt = dt, auditoria = data.table::data.table(), problemas = vazio_prob))
  }

  atributos <- unique(as.character(aj[n_ajustes > 0L]$atributo))
  atributos <- atributos[atributos %in% names(antes) & atributos %in% names(depois)]
  auditoria <- vector("list", length(atributos))
  problemas <- vector("list", length(atributos))
  kp <- 0L
  limpar <- function(x) {
    y <- monitora_validados_limpar_ausencia_saida(x)
    y[is.na(y)] <- ""
    y
  }
  cache_aliases_habito <- new.env(parent = emptyenv())
  arquivos_xlsform_por_linha <- NULL

  for (ii in seq_along(atributos)) {
    att <- atributos[ii]
    va <- limpar(antes[[att]])
    vd <- limpar(depois[[att]])
    idx <- which(va != vd)
    candidatos <- monitora_validados_colunas_presentes(dt, att)

 ### Hábitos priorizam o atributo interno curto preservado antes dos rótulos.
 ### Aliases históricos só podem ser materializados quando o resolvedor por
 ### versão/linha os classificar como seguros; um rótulo compartilhado com
 ### outra categoria permanece bloqueado se essa categoria também reivindicar
 ### a mesma forma na linha.
    eh_habito <- grepl("^amostragem/registro/forma_vida_(nativa|exotica|seca_morta)_(bromelioide|cactacea|orquidea|samambaia)$", att, perl = TRUE)
    categoria_habito <- NA_character_
    forma_habito <- NA_character_
    outra_categoria_reivindica <- rep(FALSE, nrow(dt))
    if (eh_habito) {
      curto <- sub("^.*/", "", att)
      candidatos <- if (curto %in% names(dt)) curto else intersect(att, names(dt))
      categoria_habito <- sub(
        "^amostragem/registro/forma_vida_(nativa|exotica|seca_morta)_.+$",
        "\\1", att
      )
      forma_habito <- sub(
        "^amostragem/registro/forma_vida_(nativa|exotica|seca_morta)_",
        "", att
      )
      for (outra_cat in setdiff(c("nativa", "exotica", "seca_morta"), categoria_habito)) {
        lista_outra <- tryCatch(monitora_correcao_coluna_forma_vida(dt, outra_cat), error = function(e) NA_character_)
        if (is.na(lista_outra) || !(lista_outra %in% names(dt))) next
        hit_outra <- tryCatch(
          monitora_correcao_contem_qualquer_token_vec(dt[[lista_outra]], forma_habito),
          error = function(e) rep(FALSE, nrow(dt))
        )
        hit_outra[is.na(hit_outra)] <- FALSE
        outra_categoria_reivindica <- outra_categoria_reivindica | hit_outra
      }
      if (is.null(arquivos_xlsform_por_linha)) {
        arquivos_xlsform_por_linha <- tryCatch(
          monitora_correcao_xlsform_por_linha(dt),
          error = function(e) rep(NA_character_, nrow(dt))
        )
      }
    }

    n_materializado <- 0L
    sem_origem <- integer()
    if (length(idx)) {
      if (!length(candidatos) && !eh_habito) {
        sem_origem <- idx
      } else {
        for (cc in candidatos) {
          if (!is.character(dt[[cc]])) data.table::set(dt, j = cc, value = as.character(dt[[cc]]))
        }
 ### Calcula por linha para preservar todos os aliases contribuintes.
        for (rr in idx) {
          candidatos_rr <- candidatos
          if (eh_habito && exists("monitora_correcao_aliases_historicos_habito", mode = "function")) {
            versao_rr <- if (length(arquivos_xlsform_por_linha) >= rr) arquivos_xlsform_por_linha[[rr]] else NA_character_
            chave_cache <- paste(att, ifelse(is.na(versao_rr), "<NA>", versao_rr), sep = "\r")
            if (exists(chave_cache, envir = cache_aliases_habito, inherits = FALSE)) {
              aliases_rr <- get(chave_cache, envir = cache_aliases_habito, inherits = FALSE)
            } else {
              aliases_rr <- tryCatch(
                monitora_correcao_aliases_historicos_habito(dt, att, linha = rr),
                error = function(e) character(0)
              )
              assign(chave_cache, aliases_rr, envir = cache_aliases_habito)
            }
            seguros_rr <- aliases_rr[aliases_rr %in% names(dt)]
            ambiguos_rr <- attr(aliases_rr, "ambiguos")
            if (is.null(ambiguos_rr)) ambiguos_rr <- character(0)
            ambiguos_rr <- ambiguos_rr[ambiguos_rr %in% names(dt)]

            if (!isTRUE(outra_categoria_reivindica[[rr]])) seguros_rr <- unique(c(seguros_rr, ambiguos_rr))
            candidatos_rr <- unique(c(candidatos_rr, seguros_rr))
            for (cc in candidatos_rr) {
              if (!is.character(dt[[cc]])) data.table::set(dt, j = cc, value = as.character(dt[[cc]]))
            }
          }

          contrib <- candidatos_rr[vapply(candidatos_rr, function(cc) nzchar(limpar(dt[[cc]][rr])), logical(1L))]
          if (length(contrib)) {
            for (cc in contrib) data.table::set(dt, i = rr, j = cc, value = vd[rr])
            n_materializado <- n_materializado + 1L
          } else if (nzchar(vd[rr])) {
            if (length(candidatos_rr)) {
              data.table::set(dt, i = rr, j = candidatos_rr[1L], value = vd[rr])
              n_materializado <- n_materializado + 1L
            } else {
              sem_origem <- c(sem_origem, rr)
            }
          }
        }
      }
    }

 ### Confirma a herança no mesmo mapeador do template, mas apenas para o
 ### atributo tocado. Uma divergência permanece bloqueante e relatada.
    pos_schema <- match(att, schema$atributo)
    reproj <- if (!is.na(pos_schema)) tryCatch(
      monitora_validados_derivar_ou_mapear_coluna(dt, att, schema$formato[pos_schema], schema$largura[pos_schema])$valor,
      error = function(e) rep(NA_character_, nrow(dt))
    ) else rep(NA_character_, nrow(dt))
    reproj <- limpar(reproj)
    diverg <- if (length(idx)) idx[is.na(reproj[idx]) | reproj[idx] != vd[idx]] else integer()
    falhas <- unique(c(sem_origem, diverg))
    status <- if (!length(idx)) "efeito_liquido_zero" else if (!length(falhas)) "materializado_e_reprojetado" else "bloqueado_sem_heranca_segura"
    regras_att <- unique(as.character(aj[atributo == att]$regra))
    auditoria[[ii]] <- data.table::data.table(
      atributo = att,
      regras = paste(regras_att, collapse = " | "),
      colunas_fisicas = paste(candidatos, collapse = " | "),
      n_linhas_efeito_liquido = length(idx),
      n_linhas_materializadas = n_materializado,
      n_linhas_sem_heranca_segura = length(falhas),
      status = status
    )
    if (length(falhas)) {
      kp <- kp + 1L
      coleta <- if ("coleta" %in% names(depois)) as.character(depois$coleta[falhas]) else rep("", length(falhas))
      problemas[[kp]] <- data.table::data.table(
        regra = "materializacao_deterministica_xlsform21_sem_heranca_segura",
        atributo = att,
        n_problemas = length(falhas),
        exemplos_coleta = paste(utils::head(unique(coleta[nzchar(coleta)]), 10L), collapse = " | "),
        detalhe = paste0("linhas=", paste(utils::head(falhas, 20L), collapse = " | "), "; origens=", paste(candidatos, collapse = " | ")),
        bloqueante = TRUE,
        motivo_bloqueio = "registros_corrig_nao_materializou_regra_xlsform21_com_seguranca"
      )
    }
  }
  aud <- if (length(auditoria)) data.table::rbindlist(auditoria, fill = TRUE, use.names = TRUE) else data.table::data.table()
  prob <- if (kp) data.table::rbindlist(problemas[seq_len(kp)], fill = TRUE, use.names = TRUE) else vazio_prob
  dir_aud <- file.path(output_dir, "03_auditorias", "contrato_xlsform")
  dir.create(dir_aud, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
  try(data.table::fwrite(aud, file.path(dir_aud, "auditoria_materializacao_regras_xlsform21_em_registros_corrig.csv"), na = ""), silent = TRUE)
  try(data.table::fwrite(aud, file.path(log_dir, paste0("auditoria_materializacao_regras_xlsform21_em_registros_corrig_", exec_id, ".csv")), na = ""), silent = TRUE)
  list(dt = dt, auditoria = aud, problemas = prob)
}

monitora_registros_validados_exportar <- function(registros_corrig,
                                                  output_dir = MONITORA_OUTPUT_DIR,
                                                  log_dir = MONITORA_LOG_DIR,
                                                  exec_id = MONITORA_EXEC_ID,
                                                  abortar = TRUE,
                                                  forcar = FALSE,
                                                  somente_auditar_contrato_corrig = FALSE,
                                                  contrato_corrig_validado = FALSE,
                                                  materializar_regras_deterministicas_corrig = FALSE) {
  if (!monitora_validados_opcao_ativa() && !isTRUE(somente_auditar_contrato_corrig)) return(invisible(NULL))
  status_linhagem_atual <- as.character(get0("MONITORA_LINHAGEM_STATUS", ifnotfound = "", inherits = TRUE))[1L]
  proveniencia_incompleta <- grepl(
    "proveniencia_historica_incompleta|manifesto_ausente|hash_dados_ausente",
    status_linhagem_atual,
    fixed = FALSE
  )
  if (!isTRUE(somente_auditar_contrato_corrig) &&
      isTRUE(proveniencia_incompleta) &&
      !identical(toupper(trimws(as.character(get0("MONITORA_OPCAO_DISPENSAR_LINHAGEM_HISTORICA_INCOMPLETA", ifnotfound = "N", inherits = TRUE))[1L])), "S")) {
    return(invisible(list(
      bloqueado = TRUE,
      motivo = status_linhagem_atual,
      orientacao = "Forneça correcoes_semanticas_consolidada.csv + manifesto_linhagem.json da run anterior ou registre dispensa institucional explícita."
    )))
  }
  if (isTRUE(get0("MONITORA_REGISTROS_VALIDADOS_GERADO", ifnotfound = FALSE, inherits = TRUE)) && !isTRUE(forcar)) {
    return(invisible(get0("MONITORA_REGISTROS_VALIDADOS_ULTIMA_AUDITORIA", ifnotfound = NULL, inherits = TRUE)))
  }
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório para registros_validados.csv.", call. = FALSE)
  registros_corrig <- data.table::as.data.table(registros_corrig)
  schema <- monitora_validados_schema_embutido()
  cols <- schema$atributo
  n <- nrow(registros_corrig)
  dir.create(output_dir, showWarnings = FALSE, recursive = TRUE)
  dir.create(log_dir, showWarnings = FALSE, recursive = TRUE)

  if (!isTRUE(somente_auditar_contrato_corrig) &&
      !isTRUE(get0("MONITORA_OCORRENCIAS_DIAGNOSTICAS_INTEGRIDADE_OK", ifnotfound = FALSE, inherits = TRUE))) {
    dir_gate_diag <- file.path(output_dir, "03_auditorias", "contrato_xlsform")
    dir.create(dir_gate_diag, recursive = TRUE, showWarnings = FALSE)
    aud_gate_diag <- data.table::data.table(
      produto = "registros_validados.csv",
      status = "bloqueado",
      regra = "integridade_ocorrencias_diagnosticas",
      motivo_bloqueio = "a_fonte_unica_de_ocorrencias_nao_foi_materializada_ou_falhou_validacao_de_identidade_exata"
    )
    data.table::fwrite(aud_gate_diag, file.path(dir_gate_diag, "auditoria_registros_validados_gate_ocorrencias_diagnosticas.csv"), na = "")
    data.table::fwrite(aud_gate_diag, file.path(log_dir, paste0("auditoria_registros_validados_gate_ocorrencias_diagnosticas_", exec_id, ".csv")), na = "")
    assign("MONITORA_REGISTROS_VALIDADOS_GERADO", FALSE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_VALIDADOS_BLOQUEADO", TRUE, envir = .GlobalEnv)
    msg_gate_diag <- "registros_validados.csv bloqueado: a auditoria de identidades exatas das ocorrências diagnósticas não foi concluída com sucesso."
    if (isTRUE(abortar)) stop(msg_gate_diag, call. = FALSE)
    warning(msg_gate_diag, call. = FALSE)
    return(invisible(list(bloqueado = TRUE, motivo = "integridade_ocorrencias_diagnosticas_nao_comprovada", detalhes = aud_gate_diag)))
  }

  caminho_saida_planejado <- if (exists("monitora_produtos_path_canonico", mode = "function")) {
    monitora_produtos_path_canonico("registros_validados.csv", output_dir)
  } else {
    file.path(output_dir, "01_produtos_dados", "registros_validados.csv")
  }
 ### Uma nova tentativa de publicação não pode deixar um produto antigo no
 ### caminho canônico caso o gate atual bloqueie. A auditoria contratual pura
 ### não toca em produto previamente materializado.
  if (!isTRUE(somente_auditar_contrato_corrig) && file.exists(caminho_saida_planejado)) {
    unlink(caminho_saida_planejado, force = TRUE)
  }
  if (!isTRUE(somente_auditar_contrato_corrig)) {
    assign("MONITORA_REGISTROS_VALIDADOS_GERADO", FALSE, envir = .GlobalEnv)
  }

 ### Gate independente e versionado: não confia apenas em flags globais de
 ### uma etapa anterior. Usa a mesma fonte linha×categoria×forma do painel em
 ### uma cópia, sem mutar registros_corrig durante a publicação.
  erro_gate_habito <- NULL
  pend_habito_corrig <- tryCatch(
    monitora_correcao_ocorrencias_habito_detalhadas(data.table::copy(registros_corrig)),
    error = function(e) {
      erro_gate_habito <<- conditionMessage(e)
      data.table::data.table()
    }
  )
  if (!is.null(erro_gate_habito) || nrow(pend_habito_corrig) > 0L) {
    dir_gate <- file.path(output_dir, "03_auditorias", "contrato_xlsform")
    dir.create(dir_gate, recursive = TRUE, showWarnings = FALSE)
    aud_gate <- if (nrow(pend_habito_corrig)) data.table::as.data.table(pend_habito_corrig) else data.table::data.table(
      tipo = "falha_execucao_gate_habito_versionado",
      motivo_bloqueio = erro_gate_habito
    )
    data.table::fwrite(aud_gate, file.path(dir_gate, "auditoria_registros_validados_gate_habito_corrig.csv"), na = "")
    data.table::fwrite(aud_gate, file.path(log_dir, paste0("auditoria_registros_validados_gate_habito_corrig_", exec_id, ".csv")), na = "")
    n_gate <- if (nrow(pend_habito_corrig)) nrow(pend_habito_corrig) else 1L
    msg_gate <- if (nrow(pend_habito_corrig)) {
      paste0(
        "registros_validados.csv bloqueado: ", n_gate,
        " ocorrência(s) de hábito obrigatório ausente em registros_corrig segundo a versão XLSForm de cada linha."
      )
    } else {
      paste0("registros_validados.csv bloqueado: o gate versionado de hábito não pôde ser executado: ", erro_gate_habito)
    }
    assign("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", FALSE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_VALIDADOS_GERADO", FALSE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_VALIDADOS_BLOQUEADO", TRUE, envir = .GlobalEnv)
    res_gate <- list(
      bloqueado = TRUE,
      motivo = "habito_obrigatorio_ausente_ou_gate_indisponivel",
      detalhes = aud_gate,
      resumo = data.table::data.table(n_bloqueios = as.integer(n_gate))
    )
    if (isTRUE(abortar) && !isTRUE(somente_auditar_contrato_corrig)) stop(msg_gate, call. = FALSE)
    warning(msg_gate, call. = FALSE)
    return(invisible(res_gate))
  }

  if (!isTRUE(somente_auditar_contrato_corrig) &&
      isTRUE(get0("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS", ifnotfound = FALSE, inherits = TRUE))) {
    resumo_pend <- get0("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS_RESUMO", ifnotfound = data.table::data.table(), inherits = TRUE)
    if (exists("monitora_publicacao_ab_logar_resumo_pendencias", mode = "function")) {
      monitora_publicacao_ab_logar_resumo_pendencias(resumo_pend, contexto = "bloqueio_registros_validados")
    }
    if (exists("monitora_publicacao_g_log", mode = "function")) {
      monitora_publicacao_g_log("registros_validados.csv não será criado: registros_corrig.csv ainda contém pendências impeditivas sinalizadas.")
    }
    return(invisible(list(bloqueado = TRUE, motivo = "registros_corrig_com_pendencias_impeditivas", resumo = resumo_pend)))
  }

 ### quando registros_corrig já foi saneado e validado pelo contrato
 ### XLSForm21 antes da materialização, registros_validados.csv deve herdar a
 ### matriz já montada/formatada na validação contratual. Isso evita repetir a
 ### interpretação completa do schema quando nada mudou desde o selo.
  cache_validados <- get0("MONITORA_REGISTROS_VALIDADOS_CACHE_PRE_CONTRATO", ifnotfound = NULL, inherits = TRUE)
  assinatura_atual <- if (exists("monitora_publicacao_z_assinatura_registros_corrig", mode = "function")) {
    tryCatch(monitora_publicacao_z_assinatura_registros_corrig(registros_corrig), error = function(e) NA_character_)
  } else NA_character_
  if (!isTRUE(somente_auditar_contrato_corrig) && isTRUE(contrato_corrig_validado) &&
      isTRUE(get0("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", ifnotfound = FALSE, inherits = TRUE)) &&
      !is.null(cache_validados) && is.list(cache_validados) &&
      identical(as.character(cache_validados$assinatura_registros_corrig)[1L], as.character(assinatura_atual)[1L]) &&
      inherits(cache_validados$out, c("data.frame", "data.table"))) {
    out_cache <- data.table::as.data.table(cache_validados$out)
    data.table::setcolorder(out_cache, cols)
    problemas_heranca_cache <- monitora_validados_validar_heranca_habitos(registros_corrig, out_cache)
    if (nrow(problemas_heranca_cache)) {
      dir_gate <- file.path(output_dir, "03_auditorias", "contrato_xlsform")
      dir.create(dir_gate, recursive = TRUE, showWarnings = FALSE)
      data.table::fwrite(problemas_heranca_cache, file.path(dir_gate, "auditoria_registros_validados_heranca_habitos.csv"), na = "")
      data.table::fwrite(problemas_heranca_cache, file.path(log_dir, paste0("auditoria_registros_validados_heranca_habitos_", exec_id, ".csv")), na = "")
      assign("MONITORA_REGISTROS_VALIDADOS_GERADO", FALSE, envir = .GlobalEnv)
      assign("MONITORA_REGISTROS_VALIDADOS_BLOQUEADO", TRUE, envir = .GlobalEnv)
      msg_cache <- paste0(
        "registros_validados.csv bloqueado: o cache contratual perdeu ",
        sum(problemas_heranca_cache$n_problemas), " hábito(s) preenchido(s) em registros_corrig."
      )
      if (isTRUE(abortar)) stop(msg_cache, call. = FALSE)
      warning(msg_cache, call. = FALSE)
      return(invisible(list(
        bloqueado = TRUE,
        motivo = "perda_heranca_habitos_cache",
        detalhes = problemas_heranca_cache,
        resumo = data.table::data.table(n_bloqueios = nrow(problemas_heranca_cache))
      )))
    }
    caminho_saida <- caminho_saida_planejado
    dir.create(dirname(caminho_saida), recursive = TRUE, showWarnings = FALSE)
    data.table::fwrite(out_cache, caminho_saida, sep = ",", quote = "auto", qmethod = "double", na = "", bom = TRUE, encoding = "UTF-8", eol = "\n", dateTimeAs = "ISO")
    header_saida <- names(data.table::fread(caminho_saida, sep = ",", nrows = 0, encoding = "UTF-8", check.names = FALSE, showProgress = FALSE, data.table = TRUE))
    if (!identical(header_saida, cols)) {
      stop("Cabeçalho de registros_validados.csv difere do schema SISMONITORA embutido; exportação bloqueada.", call. = FALSE)
    }
    MONITORA_REGISTROS_VALIDADOS_GERADO <<- TRUE
    MONITORA_REGISTROS_VALIDADOS_ULTIMA_AUDITORIA <<- cache_validados$auditoria
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("registros_validados_exportado", "INFO", caminho_saida, paste0("registros_validados.csv gerado por herança de registros_corrig validado com ", nrow(out_cache), " linhas e ", ncol(out_cache), " colunas"), "cache contratual v2.5.4; sem revalidação semântica")
    }
    return(invisible(MONITORA_REGISTROS_VALIDADOS_ULTIMA_AUDITORIA))
  }

  pre_sanitizacao_ja_aplicada <- isTRUE(get0("MONITORA_REGISTROS_VALIDADOS_PRE_SANITIZACAO_APLICADA", ifnotfound = FALSE, inherits = TRUE))
  if (!isTRUE(pre_sanitizacao_ja_aplicada) && !isTRUE(somente_auditar_contrato_corrig)) {
 ### Segurança metodológica: registros_validados não pode acionar saneamento
 ### tardio. A base deve chegar aqui já sem pendências impeditivas e com selo
 ### de registros_corrig aprovado ou a exportação é bloqueada pela auditoria.
    if (exists("monitora_publicacao_g_log", mode = "function")) {
      monitora_publicacao_g_log("sanitização automática pré-registros_validados bloqueada; registros_validados exige registros_corrig previamente aprovado.")
    }
    if (isTRUE(abortar)) stop("registros_validados.csv bloqueado: registros_corrig não possui pré-sanitização/selo aprovado; resolva pendências no painel.", call. = FALSE)
    return(invisible(list(bloqueado = TRUE, motivo = "sem_selo_previo_registros_corrig")))
  } else if (exists("monitora_publicacao_g_log", mode = "function")) {
    monitora_publicacao_g_log(if (isTRUE(somente_auditar_contrato_corrig)) {
      "auditoria contratual de registros_corrig executada sem sanitização semântica"
    } else {
      "registros_validados herda registros_corrig previamente auditado; sem sanitização tardia automática"
    })
  }
  n <- nrow(registros_corrig)

  if (exists("monitora_publicacao_aj_constroi_matriz_validados", mode = "function")) {
    matriz_publicacao_aj <- monitora_publicacao_aj_constroi_matriz_validados(
      registros_corrig = registros_corrig,
      schema = schema,
      somente_auditar_contrato_corrig = somente_auditar_contrato_corrig
    )
    out <- matriz_publicacao_aj$out
    auditoria <- matriz_publicacao_aj$auditoria
  } else {
    out <- data.table::as.data.table(stats::setNames(rep(list(rep("", n)), length(cols)), cols))
    auditoria <- vector("list", length(cols))
    for (ii in seq_along(cols)) {
      col_tpl <- cols[ii]
      res <- monitora_validados_derivar_ou_mapear_coluna(registros_corrig, col_tpl, schema$formato[ii], schema$largura[ii])
      novo <- monitora_validados_formatar_valor(res$valor, schema$formato[ii], schema$largura[ii])
      data.table::set(out, j = col_tpl, value = novo)
      estrategia_res <- if (is.null(res$estrategia) || is.na(res$estrategia) || !nzchar(as.character(res$estrategia)[1])) "mapeada" else as.character(res$estrategia)[1]
      auditoria[[ii]] <- data.table::data.table(
        posicao = schema$posicao[ii], atributo = col_tpl,
        coluna_origem_registros_corrig = ifelse(is.null(res$coluna) || is.na(res$coluna) || !nzchar(res$coluna), NA_character_, as.character(res$coluna)),
        estrategia = estrategia_res,
        status_mapeamento = if (any(nzchar(novo))) estrategia_res else "opcional_sem_origem_vazio",
        formato_esperado = schema$formato[ii], largura = schema$largura[ii], obrigatorio_valor = schema$obrigatorio_valor[ii],
        n_linhas_saida = n, n_vazios_saida = sum(!nzchar(novo)), n_distintos_saida = data.table::uniqueN(novo[nzchar(novo)]),
        exemplos = paste(utils::head(unique(novo[nzchar(novo)]), 5L), collapse = " | "),
        bloqueante = FALSE, motivo_bloqueio = ""
      )
    }
    data.table::setcolorder(out, cols)
    auditoria <- data.table::rbindlist(auditoria, fill = TRUE, use.names = TRUE)
  }
  if (isTRUE(somente_auditar_contrato_corrig) && exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("contrato_xlsform_matriz_mapeamento", "matriz de atributos do template construída/mapeda para auditoria de registros_corrig", out)
  }

  hora_origem <- monitora_validados_pegar(
    registros_corrig,
    c("data_hora/hora", "Horário (data_hora)", "Hora (data_hora)"),
    n
  )
  if (!any(nzchar(monitora_validados_limpar_ausencia_saida(hora_origem$valor)))) {
    hora_origem <- monitora_validados_pegar(registros_corrig, c("data_do_registro", "DATA DO REGISTRO"), n)
  }
  if (!any(nzchar(monitora_validados_limpar_ausencia_saida(hora_origem$valor)))) {
    hora_origem <- monitora_validados_pegar(registros_corrig, c("data_do_recebimento", "DATA DO RECEBIMENTO"), n)
  }
  auditoria_hora <- monitora_validados_auditar_hora_hms_millis_tz(
    original = hora_origem$valor,
    normalizado = out[["data_hora/hora"]],
    atributo = "data_hora/hora",
    coluna_origem = hora_origem$coluna
  )

 ### a projeção para registros_validados continua sendo somente
 ### herança/formatação. Durante o fechamento mestre de registros_corrig,
 ### porém, as regras determinísticas do XLSForm são materializadas na origem
 ### física e auditadas antes do selo; nenhuma decisão ecológica é inferida.
  out_herdado_pre_regras <- data.table::copy(out)
  regras_xlsform21 <- monitora_validados_aplicar_regras_xlsform21(data.table::copy(out), schema)
  ajustes_xlsform21 <- regras_xlsform21$ajustes
  meta_xlsform21 <- regras_xlsform21$meta
  materializacao_regras <- NULL
  if (isTRUE(somente_auditar_contrato_corrig) && isTRUE(materializar_regras_deterministicas_corrig)) {
    materializacao_regras <- monitora_publicacao_aa_materializar_regras_xlsform21_corrig(
      registros_corrig = registros_corrig,
      out_antes = out_herdado_pre_regras,
      out_depois = regras_xlsform21$out,
      ajustes = ajustes_xlsform21,
      schema = schema,
      output_dir = output_dir,
      log_dir = log_dir,
      exec_id = exec_id
    )
    registros_corrig <- materializacao_regras$dt
    out <- regras_xlsform21$out
    problemas_saneamento_tardio <- materializacao_regras$problemas
  } else {
    problemas_saneamento_tardio <- if (nrow(ajustes_xlsform21)) {
    ajustes_xlsform21[n_ajustes > 0L, .(
      regra = paste0("saneamento_tardio_proibido_", regra),
      atributo = as.character(atributo),
      n_problemas = as.integer(n_ajustes),
      exemplos_coleta = "",
      detalhe = paste0(
        "registros_corrig exige correção antes da projeção; ajuste apenas diagnosticado e não aplicado: ",
        as.character(detalhe)
      ),
      bloqueante = TRUE,
      motivo_bloqueio = "registros_corrig_nao_valido_sem_saneamento_tardio"
    )]
  } else {
    data.table::data.table(
      regra = character(), atributo = character(), n_problemas = integer(),
      exemplos_coleta = character(), detalhe = character(),
      bloqueante = logical(), motivo_bloqueio = character()
    )
    }
    out <- out_herdado_pre_regras
  }
  if (isTRUE(somente_auditar_contrato_corrig) && exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint(
      "contrato_xlsform_regras_relevance_normalizacao",
      if (isTRUE(materializar_regras_deterministicas_corrig)) "regras/relevance/normalizações XLSForm materializadas no registros_corrig e reprojetadas por atributo" else "regras/relevance/normalizações XLSForm simuladas; matriz herdada preservada",
      out
    )
  }

 ## Recalcula métricas da auditoria de mapeamento após normalização/relevance.
 ## em auditoria contratual pré-registros_corrig, a integridade depende
 ## de vazios/bloqueios. uniqueN/exemplos em 129 colunas são diagnóstico rico,
 ## mas custoso; por padrão, ficam leves nesse modo e continuam completos na
 ## exportação final sem cache, quando ela realmente precisar rodar.
  auditoria_leve_publicacao_ae <- isTRUE(somente_auditar_contrato_corrig) &&
    exists("monitora_publicacao_ae_auditoria_mapeamento_leve", mode = "function") &&
    isTRUE(monitora_publicacao_ae_auditoria_mapeamento_leve())
  for (ii in seq_len(nrow(auditoria))) {
    aa <- auditoria$atributo[ii]
    vv <- monitora_validados_limpar_ausencia_saida(out[[aa]])
    data.table::set(auditoria, i = ii, j = "n_vazios_saida", value = sum(!nzchar(vv)))
    if (isTRUE(auditoria_leve_publicacao_ae)) {
      data.table::set(auditoria, i = ii, j = "n_distintos_saida", value = NA_integer_)
      data.table::set(auditoria, i = ii, j = "exemplos", value = "[auditoria_leve_publicacao_ae; exemplos calculados apenas em bloqueios]")
    } else {
      data.table::set(auditoria, i = ii, j = "n_distintos_saida", value = data.table::uniqueN(vv[nzchar(vv)]))
      data.table::set(auditoria, i = ii, j = "exemplos", value = paste(utils::head(unique(vv[nzchar(vv)]), 5L), collapse = " | "))
    }
  }

  vazias_obrig <- auditoria[obrigatorio_valor == TRUE & n_vazios_saida > 0L]
  if (nrow(vazias_obrig)) {
    vazias_obrig[, `:=`(bloqueante = TRUE, motivo_bloqueio = "atributo_obrigatorio_vazio_apos_interpretacao")]
    auditoria[vazias_obrig, on = .(posicao, atributo), `:=`(bloqueante = TRUE, motivo_bloqueio = i.motivo_bloqueio)]
  }

  problemas_fmt <- monitora_validados_validar_formatos_saida(out, schema)
  card <- monitora_validados_auditar_cardinalidade(out)
  problemas_card <- card[status != "ok"]

  chave_dupl <- out[, .N, by = .(coleta, ponto_amostral = `amostragem/registro/ponto_amostral`)][nzchar(coleta) & nzchar(ponto_amostral) & N > 1L]
  problemas_chave <- data.table::data.table(
    tipo = character(), n_problemas = integer(), exemplos = character()
  )
  if (nrow(chave_dupl)) {
    problemas_chave <- data.table::data.table(
      tipo = "duplicidade_coleta_ponto_amostral",
      n_problemas = nrow(chave_dupl),
      exemplos = paste(utils::head(paste(chave_dupl$coleta, chave_dupl$ponto_amostral, sep = ":"), 10L), collapse = " | ")
    )
  }

  problemas_dom <- monitora_validados_validar_dominios_xlsform21(out, schema, meta_xlsform21)
  if (isTRUE(somente_auditar_contrato_corrig) && exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("contrato_xlsform_validacao_dominios", "domínios XLSForm validados por valores distintos/tokens", out)
  }
  problemas_cond <- monitora_validados_validar_condicionais_xlsform21(out)
  problemas_heranca_habitos <- monitora_validados_validar_heranca_habitos(registros_corrig, out)
  problemas_cond <- data.table::rbindlist(
    list(problemas_cond, problemas_heranca_habitos, problemas_saneamento_tardio),
    fill = TRUE,
    use.names = TRUE
  )
  if (isTRUE(somente_auditar_contrato_corrig) && exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("contrato_xlsform_validacao_condicionais", "condicionais/relevance finais validadas", out)
  }
  problemas_sanitizacao_outras <- monitora_validados_auditar_sanitizacao_outras_formas(out, meta_xlsform21)
  problemas_sanitizacao_desconhecida <- monitora_validados_auditar_sanitizacao_desconhecida(out)
  if (isTRUE(somente_auditar_contrato_corrig) && exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("contrato_xlsform_validacao_sanitizacao", "sanitizações finais de outras formas/desconhecida auditadas", out)
  }

  auditoria <- monitora_privacidade_sanitizar_auditoria(auditoria)
  auditoria_hora <- monitora_privacidade_sanitizar_auditoria(auditoria_hora, mascarar_exemplos = FALSE)
  problemas_fmt <- monitora_privacidade_sanitizar_auditoria(problemas_fmt)
  problemas_dom <- monitora_privacidade_sanitizar_auditoria(problemas_dom)
  problemas_cond <- monitora_privacidade_sanitizar_auditoria(problemas_cond)
  problemas_heranca_habitos <- monitora_privacidade_sanitizar_auditoria(problemas_heranca_habitos)
  problemas_sanitizacao_outras <- monitora_privacidade_sanitizar_auditoria(problemas_sanitizacao_outras)
  problemas_sanitizacao_desconhecida <- monitora_privacidade_sanitizar_auditoria(problemas_sanitizacao_desconhecida)
  ajustes_xlsform21 <- monitora_privacidade_sanitizar_auditoria(ajustes_xlsform21, mascarar_exemplos = FALSE)
  card <- monitora_privacidade_sanitizar_auditoria(card)
  problemas_chave <- monitora_privacidade_sanitizar_auditoria(problemas_chave)

  auditoria_contrato_corrig <- NULL
  if (exists("monitora_registros_corrig_gravar_auditoria_contrato_xlsform21", mode = "function")) {
    auditoria_contrato_corrig <- monitora_registros_corrig_gravar_auditoria_contrato_xlsform21(
      auditoria = auditoria,
      vazias_obrig = vazias_obrig,
      problemas_fmt = problemas_fmt,
      problemas_dom = problemas_dom,
      problemas_cond = problemas_cond,
      problemas_sanitizacao_outras = problemas_sanitizacao_outras,
      problemas_sanitizacao_desconhecida = problemas_sanitizacao_desconhecida,
      card = card,
      problemas_chave = problemas_chave,
      ajustes_xlsform21 = ajustes_xlsform21,
      output_dir = output_dir,
      log_dir = log_dir,
      exec_id = exec_id,
      contexto = if (isTRUE(somente_auditar_contrato_corrig)) "pre_materializacao_registros_corrig" else "assert_final_export_registros_validados"
    )
  }

 ### - -----------------------------------------------------
 ### Propaga, como metadado auxiliar opt-in (mesma flag
 ### MONITORA_DIAGNOSTICO_CONTRATO_UNICO_REGISTROS_VALIDADOS já usada em
 ### monitora_registros_corrig_severidade_contrato_unico /), a
 ### contagem de atributos bloqueantes de alta severidade do contrato único
 ### já calculada acima em auditoria_contrato_corrig$resumo. Não recalcula
 ### nada novo e não participa de n_bloq/decisão de bloqueio desta função;
 ### só torna visível no resumo da própria exportação (auditoria_registros_
 ### validados_resumo.csv), fora do schema de registros_validados.csv.
 ### Degrada com segurança (NA) quando a flag está desligada, a auditoria do
 ### contrato de registros_corrig não rodou ou a coluna não existe.
  n_bloqueios_alta_severidade_contrato_unico_registros_corrig <- NA_integer_
  if (!is.null(auditoria_contrato_corrig) && is.list(auditoria_contrato_corrig) &&
      !is.null(auditoria_contrato_corrig$resumo) &&
      "n_bloqueios_alta_severidade_contrato_unico" %in% names(auditoria_contrato_corrig$resumo)) {
    n_bloqueios_alta_severidade_contrato_unico_registros_corrig <- suppressWarnings(
      as.integer(auditoria_contrato_corrig$resumo$n_bloqueios_alta_severidade_contrato_unico[1L])
    )
  }
 ### - ---------------------------------------------------

  caminhos <- list(
    mapeamento_log = file.path(log_dir, paste0("auditoria_registros_validados_mapeamento_", exec_id, ".csv")),
    mapeamento_out = file.path(output_dir, "auditoria_registros_validados_mapeamento.csv"),
    formatos_log = file.path(log_dir, paste0("auditoria_registros_validados_formatos_", exec_id, ".csv")),
    hora_log = file.path(log_dir, paste0("auditoria_registros_validados_hora_", exec_id, ".csv")),
    hora_out = file.path(output_dir, "auditoria_registros_validados_hora.csv"),
    dominios_log = file.path(log_dir, paste0("auditoria_registros_validados_xlsform_dominios_", exec_id, ".csv")),
    condicionais_log = file.path(log_dir, paste0("auditoria_registros_validados_xlsform_condicionais_", exec_id, ".csv")),
    heranca_habitos_log = file.path(log_dir, paste0("auditoria_registros_validados_heranca_habitos_", exec_id, ".csv")),
    heranca_habitos_out = file.path(output_dir, "auditoria_registros_validados_heranca_habitos.csv"),
    sanitizacao_outras_log = file.path(log_dir, paste0("auditoria_registros_validados_sanitizacao_outras_formas_", exec_id, ".csv")),
    sanitizacao_desconhecida_log = file.path(log_dir, paste0("auditoria_registros_validados_sanitizacao_desconhecida_", exec_id, ".csv")),
    ajustes_xlsform21_log = file.path(log_dir, paste0("auditoria_registros_validados_xlsform_ajustes_", exec_id, ".csv")),
    cardinalidade_log = file.path(log_dir, paste0("auditoria_registros_validados_uuid_cardinalidade_", exec_id, ".csv")),
    chave_log = file.path(log_dir, paste0("auditoria_registros_validados_chaves_", exec_id, ".csv")),
    resumo_log = file.path(log_dir, paste0("auditoria_registros_validados_resumo_", exec_id, ".csv")),
    resumo_out = file.path(output_dir, "auditoria_registros_validados_resumo.csv")
  )
  data.table::fwrite(auditoria, caminhos$mapeamento_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(auditoria, caminhos$mapeamento_out, sep = ",", quote = "auto", na = "")
  data.table::fwrite(problemas_fmt, caminhos$formatos_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(auditoria_hora, caminhos$hora_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(auditoria_hora, caminhos$hora_out, sep = ",", quote = "auto", na = "")
  data.table::fwrite(problemas_dom, caminhos$dominios_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(problemas_cond, caminhos$condicionais_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(problemas_heranca_habitos, caminhos$heranca_habitos_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(problemas_heranca_habitos, caminhos$heranca_habitos_out, sep = ",", quote = "auto", na = "")
  data.table::fwrite(problemas_sanitizacao_outras, caminhos$sanitizacao_outras_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(problemas_sanitizacao_desconhecida, caminhos$sanitizacao_desconhecida_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(ajustes_xlsform21, caminhos$ajustes_xlsform21_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(card, caminhos$cardinalidade_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(problemas_chave, caminhos$chave_log, sep = ",", quote = "auto", na = "")

  n_bloq <- nrow(vazias_obrig) + nrow(problemas_fmt) + nrow(problemas_dom) + nrow(problemas_cond) + nrow(problemas_card) + nrow(problemas_chave) + nrow(problemas_sanitizacao_outras) + nrow(problemas_sanitizacao_desconhecida)
  resumo <- data.table::data.table(
    exec_id = as.character(exec_id), produto = "registros_validados.csv",
    schema = "SISMONITORA_21FEV25_embutido_com_regras_xlsform21",
    n_linhas_registros_corrig = nrow(registros_corrig), n_linhas_saida = nrow(out),
    n_colunas_schema = length(cols), n_colunas_saida = ncol(out),
    n_colunas_mapeadas_ou_derivadas = auditoria[n_vazios_saida < n_linhas_saida, .N],
    n_colunas_opcionais_vazias = auditoria[n_vazios_saida == n_linhas_saida & obrigatorio_valor == FALSE, .N],
    n_ajustes_xlsform21 = if (nrow(ajustes_xlsform21)) sum(ajustes_xlsform21$n_ajustes) else 0L,
    n_linhas_sanitizacao_outras_formas_pendente = nrow(problemas_sanitizacao_outras),
    n_linhas_sanitizacao_desconhecida_pendente = nrow(problemas_sanitizacao_desconhecida),
    n_bloqueios_formatos = nrow(problemas_fmt),
    n_hora_total = auditoria_hora$n_total[1],
    n_hora_vazios = auditoria_hora$n_vazios[1],
    n_hora_normalizados = auditoria_hora$n_normalizados[1],
    n_hora_alterados_pela_normalizacao = auditoria_hora$n_alterados_pela_normalizacao[1],
    n_hora_incompativeis = auditoria_hora$n_incompativeis[1],
    n_bloqueios_dominios_xlsform21 = nrow(problemas_dom),
    n_bloqueios_condicionais_xlsform21 = nrow(problemas_cond),
    n_habitos_preenchidos_nao_herdados = if (nrow(problemas_heranca_habitos)) sum(problemas_heranca_habitos$n_problemas) else 0L,
    n_bloqueios_sanitizacao_outras_formas = as.integer(nrow(problemas_sanitizacao_outras) > 0L),
    n_bloqueios_sanitizacao_desconhecida = nrow(problemas_sanitizacao_desconhecida),
    n_bloqueios = n_bloq,
    n_bloqueios_alta_severidade_contrato_unico_registros_corrig = n_bloqueios_alta_severidade_contrato_unico_registros_corrig,
    auditoria_mapeamento = monitora_privacidade_caminho_relativo(caminhos$mapeamento_log),
    auditoria_formatos = monitora_privacidade_caminho_relativo(caminhos$formatos_log),
    auditoria_hora = monitora_privacidade_caminho_relativo(caminhos$hora_log),
    auditoria_dominios_xlsform21 = monitora_privacidade_caminho_relativo(caminhos$dominios_log),
    auditoria_condicionais_xlsform21 = monitora_privacidade_caminho_relativo(caminhos$condicionais_log),
    auditoria_heranca_habitos = monitora_privacidade_caminho_relativo(caminhos$heranca_habitos_log),
    auditoria_sanitizacao_outras_formas = monitora_privacidade_caminho_relativo(caminhos$sanitizacao_outras_log),
    auditoria_sanitizacao_desconhecida = monitora_privacidade_caminho_relativo(caminhos$sanitizacao_desconhecida_log),
    auditoria_ajustes_xlsform21 = monitora_privacidade_caminho_relativo(caminhos$ajustes_xlsform21_log),
    auditoria_cardinalidade = monitora_privacidade_caminho_relativo(caminhos$cardinalidade_log),
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
  )
  data.table::fwrite(resumo, caminhos$resumo_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(resumo, caminhos$resumo_out, sep = ",", quote = "auto", na = "")

 ### modo de auditoria contratual de registros_corrig. Nesta chamada,
 ### o exportador monta a mesma matriz que alimentará registros_validados.csv,
 ### grava as auditorias e bloqueia antes da materialização de registros_corrig
 ### caso algum atributo do template 21FEV25 esteja inválido.
  if (isTRUE(somente_auditar_contrato_corrig)) {
    if (n_bloq > 0L) {
      msg <- paste0(
        "registros_corrig.csv bloqueado: ", n_bloq,
        " problema(s) bloqueante(s) nos atributos que alimentam registros_validados.csv após sanitização pós-painel e regras XLSForm 21FEV25. ",
        if (nrow(problemas_sanitizacao_outras) > 0L) "Há resíduos de outra forma de vida de versões antigas sem sanitização prévia. " else "",
        if (nrow(problemas_sanitizacao_desconhecida) > 0L) "Há foto/descritor de forma de vida desconhecida preenchido sem token desconhecida na categoria correspondente. " else "",
        "Auditorias: ",
        caminhos$mapeamento_log, "; ", caminhos$formatos_log, "; ", caminhos$hora_log, "; ", caminhos$dominios_log, "; ", caminhos$condicionais_log, "; ", caminhos$sanitizacao_outras_log, "; ", caminhos$sanitizacao_desconhecida_log, "; ", caminhos$cardinalidade_log,
        "; contrato registros_corrig: ", file.path(log_dir, paste0("auditoria_registros_corrig_contrato_xlsform21_", exec_id, ".csv"))
      )
      bloq <- tryCatch(monitora_registros_validados_gravar_bloqueios(
        resumo = resumo,
        vazias_obrig = vazias_obrig,
        problemas_fmt = problemas_fmt,
        problemas_dom = problemas_dom,
        problemas_cond = problemas_cond,
        problemas_sanitizacao_outras = problemas_sanitizacao_outras,
        problemas_sanitizacao_desconhecida = problemas_sanitizacao_desconhecida,
        card = card,
        problemas_chave = problemas_chave,
        mensagem = msg,
        contexto = "auditoria_contrato_corrig_bloqueio_registros_validados",
        output_dir = output_dir,
        log_dir = log_dir,
        exec_id = exec_id
      ), error = function(e) data.table::data.table())
      assign("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", FALSE, envir = .GlobalEnv)
      assign("MONITORA_REGISTROS_CORRIG_CONTRATO_CONTEXTO", "sem_pendencias_impeditivas_mas_bloqueio_registros_validados", envir = .GlobalEnv)
      warning(msg, call. = FALSE)
      return(invisible(list(registros_corrig = registros_corrig, auditoria = auditoria, resumo = resumo, contrato_registros_corrig = auditoria_contrato_corrig, bloqueios_registros_validados = bloq)))
    }
    assinatura_cache <- if (exists("monitora_publicacao_z_assinatura_registros_corrig", mode = "function")) {
      tryCatch(monitora_publicacao_z_assinatura_registros_corrig(registros_corrig), error = function(e) NA_character_)
    } else NA_character_
    assign("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", TRUE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_VALIDADOS_CACHE_PRE_CONTRATO", list(
      assinatura_registros_corrig = assinatura_cache,
      out = data.table::copy(out),
      auditoria = list(auditoria = auditoria, resumo = resumo, contrato_registros_corrig = auditoria_contrato_corrig),
      timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    ), envir = .GlobalEnv)
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("registros_corrig_contrato_aprovado", "INFO", caminhos$resumo_log, paste0("registros_corrig aprovado no contrato XLSForm21 antes da materialização; bloqueios=0; atributos=", length(cols)), "v2.5.4 pre-materializacao")
    }
    return(invisible(list(registros_corrig = registros_corrig, auditoria = auditoria, resumo = resumo, contrato_registros_corrig = auditoria_contrato_corrig)))
  }

  if (n_bloq > 0L) {
    msg <- paste0(
      "registros_validados.csv bloqueado: ", n_bloq,
      " problema(s) bloqueante(s) após interpretação de registros_corrig e regras XLSForm 21FEV25. ",
      if (nrow(problemas_sanitizacao_outras) > 0L) "Há resíduos de outra forma de vida de versões antigas sem sanitização prévia. " else "",
      if (nrow(problemas_sanitizacao_desconhecida) > 0L) "Há foto/descritor de forma de vida desconhecida preenchido sem token desconhecida na categoria correspondente. " else "",
      "Auditorias: ",
      caminhos$mapeamento_log, "; ", caminhos$formatos_log, "; ", caminhos$hora_log, "; ", caminhos$dominios_log, "; ", caminhos$condicionais_log, "; ", caminhos$sanitizacao_outras_log, "; ", caminhos$sanitizacao_desconhecida_log, "; ", caminhos$cardinalidade_log
    )
    bloq <- tryCatch(monitora_registros_validados_gravar_bloqueios(
      resumo = resumo,
      vazias_obrig = vazias_obrig,
      problemas_fmt = problemas_fmt,
      problemas_dom = problemas_dom,
      problemas_cond = problemas_cond,
      problemas_sanitizacao_outras = problemas_sanitizacao_outras,
      problemas_sanitizacao_desconhecida = problemas_sanitizacao_desconhecida,
      card = card,
      problemas_chave = problemas_chave,
      mensagem = msg,
      contexto = "bloqueio_exportacao_registros_validados",
      output_dir = output_dir,
      log_dir = log_dir,
      exec_id = exec_id
    ), error = function(e) data.table::data.table())
    assign("MONITORA_REGISTROS_VALIDADOS_GERADO", FALSE, envir = .GlobalEnv)
    warning(msg, call. = FALSE)
    return(invisible(list(auditoria = auditoria, resumo = resumo, bloqueios_registros_validados = bloq)))
  }

  caminho_saida <- if (exists("monitora_produtos_path_canonico", mode = "function")) {
      monitora_produtos_path_canonico("registros_validados.csv", output_dir)
    } else {
      file.path(output_dir, "01_produtos_dados", "registros_validados.csv")
    }
    dir.create(dirname(caminho_saida), recursive = TRUE, showWarnings = FALSE)
  data.table::fwrite(out, caminho_saida, sep = ",", quote = "auto", qmethod = "double", na = "", bom = TRUE, encoding = "UTF-8", eol = "\n", dateTimeAs = "ISO")
  header_saida <- names(data.table::fread(caminho_saida, sep = ",", nrows = 0, encoding = "UTF-8", check.names = FALSE, showProgress = FALSE, data.table = TRUE))
  if (!identical(header_saida, cols)) {
    stop("Cabeçalho de registros_validados.csv difere do schema SISMONITORA embutido; exportação bloqueada.", call. = FALSE)
  }
  MONITORA_REGISTROS_VALIDADOS_GERADO <<- TRUE
  MONITORA_REGISTROS_VALIDADOS_ULTIMA_AUDITORIA <<- list(produto = caminho_saida, auditoria = auditoria, resumo = resumo, contrato_registros_corrig = auditoria_contrato_corrig)
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento("registros_validados_exportado", "INFO", caminho_saida, paste0("registros_validados.csv gerado com ", nrow(out), " linhas e ", ncol(out), " colunas"), "schema embutido; entrada=registros_corrig")
  }
  invisible(MONITORA_REGISTROS_VALIDADOS_ULTIMA_AUDITORIA)
}

}
