### -------------------------------------------------------------
### Permite preservar o trabalho do usuário como checkpoint quando ainda houver
### pendências impeditivas. Essas pendências bloqueiam registros_validados.csv e
### produtos finais, mas não impedem a gravação marcada de registros_corrig.csv.
if (!exists("MONITORA_PERMITIR_REGISTROS_CORRIG_CHECKPOINT_PENDENTE", inherits = FALSE)) MONITORA_PERMITIR_REGISTROS_CORRIG_CHECKPOINT_PENDENTE <- TRUE

### Normalização contratual segura de CPF ----------------------------------
### O template SISMONITORA exige 11 dígitos. São recuperáveis sem inferência:
### dígitos puros (com zero à esquerda completado pela largura contratual) e a
### máscara canônica de CPF. Decimais expandidos, texto ou sequências com mais
### de 11 dígitos são excluídos dos produtos de dados sem inferência e com
### auditoria protegida; nenhuma linha/coleta é removida.
monitora_publicacao_ab_cpf_coluna <- function(dt) {
  cand <- intersect(c("coletor/cpf", "CPF (coletor)", "cpf (coletor)"), names(dt))
  if (length(cand)) cand[1L] else NA_character_
}

monitora_publicacao_ab_cpf_digitos_verificadores_validos <- function(x) {
  x <- trimws(as.character(x))
  x[is.na(x)] <- ""
  out <- rep(FALSE, length(x))
  candidatos <- grepl("^[0-9]{11}$", x, perl = TRUE) &
    !grepl("^([0-9])\\1{10}$", x, perl = TRUE)
  if (!any(candidatos)) return(out)
  validar_um <- function(valor) {
    d <- as.integer(strsplit(valor, "", fixed = TRUE)[[1L]])
    if (length(d) != 11L || anyNA(d)) return(FALSE)
    soma1 <- sum(d[1:9] * 10:2)
    dv1 <- (soma1 * 10L) %% 11L
    if (dv1 == 10L) dv1 <- 0L
    soma2 <- sum(d[1:10] * 11:2)
    dv2 <- (soma2 * 10L) %% 11L
    if (dv2 == 10L) dv2 <- 0L
    identical(as.integer(d[10:11]), as.integer(c(dv1, dv2)))
  }
  valores <- unique(x[candidatos])
  mapa <- stats::setNames(vapply(valores, validar_um, logical(1L)), valores)
  out[candidatos] <- unname(mapa[x[candidatos]])
  out
}

monitora_publicacao_ab_cpf_avaliar <- function(x) {
  bruto <- as.character(x)
  bruto[is.na(bruto)] <- ""
  bruto <- trimws(bruto)
  bruto[tolower(bruto) %in% c("na", "n/a", "null", "nan") | bruto == "---"] <- ""
  preenchido <- nzchar(bruto)
  somente_digitos <- preenchido & grepl("^[0-9]+$", bruto, perl = TRUE)
  mascara_canonica <- preenchido & grepl("^[0-9]{3}\\.[0-9]{3}\\.[0-9]{3}[-.]?[0-9]{2}$", bruto, perl = TRUE)
  digitos <- gsub("[^0-9]", "", bruto, perl = TRUE)
  recuperavel <- (somente_digitos & nchar(digitos) <= 11L) | (mascara_canonica & nchar(digitos) == 11L)
  valor <- bruto
  idx <- which(recuperavel)
  if (length(idx)) {
    zeros <- pmax(0L, 11L - nchar(digitos[idx]))
    valor[idx] <- paste0(vapply(zeros, function(nn) paste(rep("0", nn), collapse = ""), character(1L)), digitos[idx])
  }
  formato_11 <- grepl("^[0-9]{11}$", valor, perl = TRUE)
  sequencia_repetida <- formato_11 & grepl("^([0-9])\\1{10}$", valor, perl = TRUE)
  digitos_verificadores_validos <- monitora_publicacao_ab_cpf_digitos_verificadores_validos(valor)
  valido <- !preenchido | (formato_11 & digitos_verificadores_validos)
  invalido <- preenchido & !valido
  motivo <- rep("vazio", length(bruto))
  motivo[preenchido & bruto == valor & valido] <- "cpf_11_digitos_preservado"
  motivo[recuperavel & bruto != valor & somente_digitos] <- "zeros_esquerda_completados_pela_largura_contratual"
  motivo[recuperavel & bruto != valor & mascara_canonica] <- "pontuacao_canonica_removida"
  motivo[invalido & !formato_11] <- "cpf_formato_nao_recuperavel_sem_inferencia"
  motivo[invalido & sequencia_repetida] <- "cpf_sequencia_repetida_invalida"
  motivo[invalido & formato_11 & !sequencia_repetida] <- "cpf_digitos_verificadores_invalidos"
 ### Valores irrecuperáveis não seguem para registros_corrig/validados. A
 ### avaliação abaixo conserva apenas metadados mascarados para a auditoria.
  valor[invalido] <- ""
  list(
    bruto = bruto, valor = valor, preenchido = preenchido,
    recuperavel = recuperavel, valido = valido,
    invalido = invalido,
    motivo = motivo,
    padrao_observado = gsub("[0-9]", "#", bruto, perl = TRUE),
    n_caracteres = nchar(bruto), n_digitos = nchar(digitos),
    sequencia_repetida = sequencia_repetida,
    digitos_verificadores_validos = digitos_verificadores_validos
  )
}

monitora_publicacao_ab_normalizar_cpf_deterministico <- function(dt,
                                                                  output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                                  log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                                  exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                                                  contexto = "pre_materializacao_registros_corrig",
                                                                  somente_auditar = FALSE) {
  dt <- data.table::as.data.table(dt)
  col <- monitora_publicacao_ab_cpf_coluna(dt)
  vazio <- data.table::data.table(
    contexto = character(), linha_indice = integer(), COLETA = character(),
    ponto_amostral = character(), monitora_row_id = character(), atributo = character(),
    status = character(), acao = character(), motivo = character(), padrao_observado = character(),
    valor_original_sha256 = character(), criterio_validacao = character(), resultado_produto = character(),
    n_caracteres = integer(), n_digitos = integer()
  )
  if (is.na(col) || !(col %in% names(dt)) || !nrow(dt)) return(list(dt = dt, auditoria = vazio, linhas = integer()))
  av <- monitora_publicacao_ab_cpf_avaliar(dt[[col]])
  if (!is.character(dt[[col]])) data.table::set(dt, j = col, value = as.character(dt[[col]]))
  mudou <- av$bruto != av$valor
  idx_mudou <- which(mudou)
  if (!isTRUE(somente_auditar) && length(idx_mudou)) data.table::set(dt, i = idx_mudou, j = col, value = av$valor[idx_mudou])
  idx_aud <- which(mudou | av$invalido)
  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list())
  valor_chave <- function(nm) {
    cc <- chaves[[nm]]
    if (is.null(cc) || is.na(cc) || !(cc %in% names(dt))) return(rep("", nrow(dt)))
    as.character(dt[[cc]])
  }
  coleta <- valor_chave("coleta")
  ponto <- valor_chave("ponto_amostral")
  row_id <- if (exists("MONITORA_COL_ROW_ID", inherits = TRUE) && MONITORA_COL_ROW_ID %in% names(dt)) as.character(dt[[MONITORA_COL_ROW_ID]]) else rep("", nrow(dt))
  hash_valor <- function(valor) {
    if (!nzchar(valor)) return("")
    if (requireNamespace("digest", quietly = TRUE)) return(digest::digest(valor, algo = "sha256", serialize = FALSE))
    monitora_correcao_hash_texto(valor)
  }
  aud <- if (length(idx_aud)) data.table::data.table(
    contexto = as.character(contexto)[1L], linha_indice = idx_aud,
    COLETA = coleta[idx_aud], ponto_amostral = ponto[idx_aud], monitora_row_id = row_id[idx_aud],
    atributo = col,
    status = ifelse(av$invalido[idx_aud], "excluido_por_cpf_invalido_irrecuperavel", "normalizado_deterministicamente"),
    acao = ifelse(av$invalido[idx_aud], "valor_excluido_dos_produtos_de_dados", "valor_reformatado_sem_inferencia"),
    motivo = av$motivo[idx_aud],
    padrao_observado = av$padrao_observado[idx_aud],
    valor_original_sha256 = vapply(av$bruto[idx_aud], hash_valor, character(1L)),
    criterio_validacao = "11_digitos+digitos_verificadores+rejeicao_sequencia_repetida",
    resultado_produto = ifelse(av$invalido[idx_aud], "cpf_vazio", "cpf_normalizado_valido"),
    n_caracteres = av$n_caracteres[idx_aud], n_digitos = av$n_digitos[idx_aud]
  ) else vazio
  if (isTRUE(somente_auditar)) {
    return(list(dt = dt, auditoria = aud, linhas = integer()))
  }

  aud_pre <- data.table::as.data.table(get0("MONITORA_AUDITORIA_CPF_PRE_OPERACOES", ifnotfound = vazio, inherits = TRUE))
  if (nrow(aud_pre) && "status" %in% names(aud_pre)) {
    aud_pre <- aud_pre[status == "excluido_por_cpf_invalido_irrecuperavel"]
  }
  if (nrow(aud_pre)) {
    chave_auditoria <- function(x) {
      x <- data.table::as.data.table(x)
      for (cc in c("monitora_row_id", "COLETA", "ponto_amostral", "atributo", "valor_original_sha256")) {
        if (!(cc %in% names(x))) data.table::set(x, j = cc, value = rep("", nrow(x)))
      }
      rid <- trimws(as.character(x$monitora_row_id)); rid[is.na(rid)] <- ""
      fallback <- paste(x$COLETA, x$ponto_amostral, x$atributo, x$valor_original_sha256, sep = "||")
      ifelse(
        nzchar(rid),
        paste0("ROW_ID||", rid, "||", x$atributo, "||", x$valor_original_sha256),
        paste0("FALLBACK||", fallback)
      )
    }
    ch_pre <- chave_auditoria(aud_pre)
    ch_atual <- chave_auditoria(aud)
    aud_pre_extra <- data.table::copy(aud_pre[!(ch_pre %in% ch_atual)])
    if (nrow(aud_pre_extra)) {
      row_ids_atuais <- row_id[!is.na(row_id) & nzchar(trimws(row_id))]
      coletas_atuais <- coleta[!is.na(coleta) & nzchar(trimws(coleta))]
      rid_pre <- trimws(as.character(aud_pre_extra$monitora_row_id)); rid_pre[is.na(rid_pre)] <- ""
      coleta_pre <- trimws(as.character(aud_pre_extra$COLETA)); coleta_pre[is.na(coleta_pre)] <- ""
      linha_presente <- nzchar(rid_pre) & rid_pre %in% row_ids_atuais
      coleta_presente <- nzchar(coleta_pre) & coleta_pre %in% coletas_atuais
      removida_com_coleta <- !linha_presente & !coleta_presente
      aud_pre_extra[, `:=`(
        contexto = paste0(as.character(contexto)[1L], "_ocorrencia_detectada_pre_operacoes"),
        status = ifelse(
          removida_com_coleta,
          "cpf_invalido_subsumido_por_exclusao_coleta",
          "cpf_invalido_resolvido_antes_fechamento"
        ),
        acao = ifelse(
          removida_com_coleta,
          "registro_e_valor_removidos_por_operacao_exclusao_coleta",
          "valor_ja_ausente_ou_valido_no_fechamento"
        ),
        resultado_produto = ifelse(
          removida_com_coleta,
          "registro_ausente_dos_produtos_por_exclusao_coleta",
          "cpf_ausente_ou_valido_no_produto"
        )
      )]
    }
  } else {
    aud_pre_extra <- vazio
  }
  aud_sessao <- data.table::rbindlist(list(
    data.table::as.data.table(get0("MONITORA_AUDITORIA_CPF_SESSAO", ifnotfound = vazio, inherits = TRUE)),
    aud_pre_extra,
    aud
  ), fill = TRUE, use.names = TRUE)
  if (nrow(aud_sessao)) {
    chave_aud <- paste(aud_sessao$monitora_row_id, aud_sessao$atributo, aud_sessao$motivo, aud_sessao$acao, sep = "||")
    aud_sessao <- aud_sessao[!duplicated(chave_aud)]
  }
  assign("MONITORA_AUDITORIA_CPF_SESSAO", aud_sessao, envir = .GlobalEnv)
  dir_aud <- file.path(output_dir, "03_auditorias", "contrato_xlsform")
  dir.create(dir_aud, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
  try(monitora_fwrite(aud_sessao, file.path(dir_aud, "auditoria_registros_corrig_normalizacao_cpf.csv"), na = ""), silent = TRUE)
  try(monitora_fwrite(aud_sessao, file.path(log_dir, paste0("auditoria_registros_corrig_normalizacao_cpf_", exec_id, ".csv")), na = ""), silent = TRUE)
  list(dt = dt, auditoria = aud, linhas = idx_mudou)
}

monitora_publicacao_ab_cpf_formato_invalido <- function(dt) {
  dt <- data.table::as.data.table(dt)
  col <- monitora_publicacao_ab_cpf_coluna(dt)
  if (is.na(col) || !(col %in% names(dt))) return(list(mask = rep(FALSE, nrow(dt)), coluna = NA_character_, avaliacao = NULL))
  av <- monitora_publicacao_ab_cpf_avaliar(dt[[col]])
  list(mask = av$invalido, coluna = col, avaliacao = av)
}

### Identidade física do registro ------------------------------------------
### A identidade canônica já calculada pelo importador é a fonte prioritária.
### Pipes, ausências, valores malformados e duplicidades são resolvidos por
### linha. Um defeito isolado nunca aciona fallback para o dataset inteiro.
monitora_publicacao_ab_normalizar_uuid_registro_deterministico <- function(dt,
                                                                            output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                                            log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                                            exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                                                            contexto = "pre_materializacao_registros_corrig") {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  vazio <- data.table::data.table(
    contexto = character(), linha_indice = integer(), COLETA = character(), ponto_amostral = character(),
    monitora_row_id = character(), atributo = character(), status = character(), acao = character(),
    fonte_resolucao = character(), motivo = character(), padrao_observado = character(),
    valor_original_sha256 = character(), valor_final = character(), resultado_produto = character()
  )
  if (!n) return(list(dt = dt, auditoria = vazio, linhas = integer()))

  alvo <- intersect(c("uuid (amostragem/registro)", "amostragem/registro/uuid"), names(dt))[1L]
  if (is.na(alvo)) {
    alvo <- "uuid (amostragem/registro)"
    data.table::set(dt, j = alvo, value = rep("", n))
  }
  if (!is.character(dt[[alvo]])) data.table::set(dt, j = alvo, value = as.character(dt[[alvo]]))
  original <- trimws(as.character(dt[[alvo]])); original[is.na(original)] <- ""
  uuid_ok <- function(x) {
    x <- trimws(as.character(x)); x[is.na(x)] <- ""
    nzchar(x) & !grepl("|", x, fixed = TRUE) & monitora_validados_uuid_valido(x)
  }

  canon_col <- intersect(c("MONITORA_UUID_REGISTRO_CANONICO", "MONITORA_ROW_UUID"), names(dt))[1L]
  canon <- if (!is.na(canon_col)) trimws(as.character(dt[[canon_col]])) else rep("", n)
  canon[is.na(canon)] <- ""
  canon_ok <- uuid_ok(canon)
  original_ok <- uuid_ok(original)
  escolhido <- original
  fonte <- ifelse(original_ok, "uuid_fisico_valido", "")
  motivo <- ifelse(grepl("|", original, fixed = TRUE), "uuid_pipe_agregado", ifelse(!nzchar(original), "uuid_ausente", "uuid_malformado"))

  usar_canon <- canon_ok & (!original_ok | original != canon)
  escolhido[usar_canon] <- canon[usar_canon]
  fonte[usar_canon] <- "MONITORA_UUID_REGISTRO_CANONICO"
  motivo[usar_canon & original_ok] <- "fontes_uuid_divergentes_canonica_priorizada"
  motivo[usar_canon & !original_ok] <- "uuid_fisico_recuperado_da_identidade_canonica"

  alias_col <- intersect(c("UUID_REGISTRO", "uuid_registro", "UUID"), names(dt))[1L]
  alias <- if (!is.na(alias_col)) trimws(as.character(dt[[alias_col]])) else rep("", n)
  alias[is.na(alias)] <- ""
  usar_alias <- !uuid_ok(escolhido) & uuid_ok(alias)
  escolhido[usar_alias] <- alias[usar_alias]
  fonte[usar_alias] <- alias_col
  motivo[usar_alias] <- "uuid_fisico_recuperado_de_alias_univoco"

  row_id <- if (exists("MONITORA_COL_ROW_ID", inherits = TRUE) && MONITORA_COL_ROW_ID %in% names(dt)) {
    as.character(dt[[MONITORA_COL_ROW_ID]])
  } else rep("", n)
  row_id[is.na(row_id)] <- ""
  chave_registro <- tryCatch(monitora_validados_chave_registro(dt), error = function(e) rep("", n))
  chave_registro[is.na(chave_registro)] <- ""
  seed <- paste0(chave_registro, "|row_id=", row_id, "|linha=", seq_len(n))
  sintetizar <- !uuid_ok(escolhido)
  if (any(sintetizar)) {
    escolhido[sintetizar] <- monitora_validados_uuid_deterministico(seed[sintetizar], "uuid_registro_recuperacao_r24e19")
    fonte[sintetizar] <- "chave_estavel_registro+MONITORA_ROW_ID"
    motivo[sintetizar] <- "uuid_nao_recuperavel_sintetizado_deterministicamente"
  }

  duplicado <- duplicated(escolhido) | duplicated(escolhido, fromLast = TRUE)
  if (any(duplicado)) {
    grupos <- split(which(duplicado), escolhido[duplicado])
    for (idx_grupo in grupos) {
      if (length(idx_grupo) <= 1L) next
      idx_substituir <- idx_grupo[-1L]
      escolhido[idx_substituir] <- monitora_validados_uuid_deterministico(seed[idx_substituir], "uuid_registro_colisao_r24e19")
      fonte[idx_substituir] <- "chave_estavel_registro+MONITORA_ROW_ID"
      motivo[idx_substituir] <- "uuid_duplicado_substituido_deterministicamente"
    }
  }

  falha_final <- !uuid_ok(escolhido) | duplicated(escolhido) | duplicated(escolhido, fromLast = TRUE)
  if (any(falha_final)) {
    escolhido[falha_final] <- ""
    fonte[falha_final] <- "sem_fonte_resolvivel"
    motivo[falha_final] <- "uuid_removido_apos_falha_de_resolucao_automatica"
  }
  mudou <- original != escolhido
  idx_aud <- which(mudou | grepl("fontes_uuid_divergentes|duplicado|falha", motivo, perl = TRUE))
  if (any(mudou)) data.table::set(dt, i = which(mudou), j = alvo, value = escolhido[mudou])
  if (!("MONITORA_UUID_REGISTRO_CANONICO" %in% names(dt))) {
    data.table::set(dt, j = "MONITORA_UUID_REGISTRO_CANONICO", value = escolhido)
  } else {
    canon_atual <- as.character(dt[["MONITORA_UUID_REGISTRO_CANONICO"]])
    atualizar_canon <- canon_atual != escolhido | is.na(canon_atual)
    atualizar_canon[is.na(atualizar_canon)] <- TRUE
    if (any(atualizar_canon)) data.table::set(dt, i = which(atualizar_canon), j = "MONITORA_UUID_REGISTRO_CANONICO", value = escolhido[atualizar_canon])
  }

  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list())
  valor_chave <- function(nm) {
    cc <- chaves[[nm]]
    if (is.null(cc) || is.na(cc) || !(cc %in% names(dt))) return(rep("", n))
    as.character(dt[[cc]])
  }
  coleta <- valor_chave("coleta"); ponto <- valor_chave("ponto_amostral")
  hash_valor <- function(valor) {
    if (!nzchar(valor)) return("")
    if (requireNamespace("digest", quietly = TRUE)) return(digest::digest(valor, algo = "sha256", serialize = FALSE))
    monitora_correcao_hash_texto(valor)
  }
  padrao <- function(valor) {
    if (!nzchar(valor)) return("vazio")
    if (grepl("|", valor, fixed = TRUE)) return(paste0("pipe_", length(strsplit(valor, "|", fixed = TRUE)[[1L]]), "_tokens"))
    if (monitora_validados_uuid_valido(valor)) return("uuid_valido")
    "uuid_malformado"
  }
  aud <- if (length(idx_aud)) data.table::data.table(
    contexto = as.character(contexto)[1L], linha_indice = idx_aud,
    COLETA = coleta[idx_aud], ponto_amostral = ponto[idx_aud], monitora_row_id = row_id[idx_aud],
    atributo = alvo,
    status = ifelse(!nzchar(escolhido[idx_aud]), "removido_sem_resolucao_automatica", ifelse(grepl("sintetizado|duplicado", motivo[idx_aud]), "sintetizado_deterministicamente", "recuperado_automaticamente")),
    acao = ifelse(!nzchar(escolhido[idx_aud]), "valor_corrompido_removido", "uuid_fisico_substituido_por_identidade_valida"),
    fonte_resolucao = fonte[idx_aud], motivo = motivo[idx_aud],
    padrao_observado = vapply(original[idx_aud], padrao, character(1L)),
    valor_original_sha256 = vapply(original[idx_aud], hash_valor, character(1L)),
    valor_final = escolhido[idx_aud],
    resultado_produto = ifelse(nzchar(escolhido[idx_aud]), "uuid_valido_unico_por_registro", "uuid_vazio")
  ) else vazio

  aud_sessao <- data.table::rbindlist(list(
    data.table::as.data.table(get0("MONITORA_AUDITORIA_UUID_REGISTRO_SESSAO", ifnotfound = vazio, inherits = TRUE)),
    aud
  ), fill = TRUE, use.names = TRUE)
  if (nrow(aud_sessao)) {
    chave_aud <- paste(aud_sessao$monitora_row_id, aud_sessao$atributo, aud_sessao$motivo, aud_sessao$acao, sep = "||")
    aud_sessao <- aud_sessao[!duplicated(chave_aud)]
  }
  assign("MONITORA_AUDITORIA_UUID_REGISTRO_SESSAO", aud_sessao, envir = .GlobalEnv)
  dir_aud <- file.path(output_dir, "03_auditorias", "identidade")
  dir.create(dir_aud, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
  try(monitora_fwrite(aud_sessao, file.path(dir_aud, "auditoria_uuid_registro_resolucao_automatica.csv"), na = ""), silent = TRUE)
  try(monitora_fwrite(aud_sessao, file.path(log_dir, paste0("auditoria_uuid_registro_resolucao_automatica_", exec_id, ".csv")), na = ""), silent = TRUE)
  resumo <- data.table::data.table(
    contexto = as.character(contexto)[1L], n_linhas = n,
    n_preservadas = sum(!mudou), n_recuperadas_ou_sintetizadas = sum(mudou & nzchar(escolhido)),
    n_removidas = sum(!nzchar(escolhido)), n_uuid_finais_unicos = data.table::uniqueN(escolhido[nzchar(escolhido)]),
    n_pipes_finais = sum(grepl("|", escolhido, fixed = TRUE)),
    status = ifelse(any(falha_final), "concluido_com_valores_removidos", "concluido_sem_bloqueio")
  )
  try(monitora_fwrite(resumo, file.path(dir_aud, "resumo_uuid_registro_resolucao_automatica.csv"), na = ""), silent = TRUE)
  list(dt = dt, auditoria = aud, resumo = resumo, linhas = which(mudou))
}

### Auditoria de pendências impeditivas para registros_corrig.csv.
### Regra operacional consolidada:
### - registros_corrig.csv pode ser materializado como checkpoint de trabalho;
### - se houver pendências impeditivas, o arquivo recebe selo/flags explícitos;
### - registros_validados.csv e produtos finais contratuais não são liberados;
### - nenhuma dessas pendências é saneada automaticamente no fechamento.
monitora_publicacao_ab_coluna_segura <- function(dt, col) {
  if (is.null(col) || is.na(col) || !nzchar(as.character(col)[1L]) || !(as.character(col)[1L] %in% names(dt))) return(rep(NA_character_, nrow(dt)))
  as.character(dt[[as.character(col)[1L]]])
}

monitora_publicacao_ab_tem_forma_categoria <- function(dt, categoria) {
  cols <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(dt, categoria), error = function(e) character(0))
  cols <- unique(cols[!is.na(cols) & nzchar(cols) & cols %in% names(dt)])
  if (!length(cols)) return(rep(FALSE, nrow(dt)))
  out <- rep(FALSE, nrow(dt))
  for (cc in cols) out <- out | !monitora_correcao_vazio_vec(dt[[cc]])
  out[is.na(out)] <- FALSE
  out
}

### Enriquece somente a evidência textual das rejeições já detectadas. Não
### recalcula máscaras, não altera registros_corrig e não participa do gate.
monitora_publicacao_ab_enriquecer_rejeicoes <- function(audit, dt, chaves) {
  audit <- data.table::as.data.table(audit)
  dt <- data.table::as.data.table(dt)
  if (!nrow(audit)) return(audit)
  cols_meta <- c(
    "atributo_canonico_2025", "atributo_fisico_registros_corrig", "valor_observado",
    "categoria_superior", "forma_de_vida_detectada", "regra_contrato"
  )
  for (cc in cols_meta) {
    if (!(cc %in% names(audit))) data.table::set(audit, j = cc, value = rep(NA_character_, nrow(audit)))
    else if (!is.character(audit[[cc]])) data.table::set(audit, j = cc, value = as.character(audit[[cc]]))
  }
  linha <- suppressWarnings(as.integer(audit$linha_indice))
  linha_valida <- !is.na(linha) & linha >= 1L & linha <= nrow(dt)
  vazio <- function(x) is.na(x) | !nzchar(trimws(as.character(x)))
  atribuir_vazios <- function(sel, coluna, valor) {
    sel <- sel[linha_valida[sel]]
    if (!length(sel)) return(invisible(NULL))
    valor <- rep_len(as.character(valor), length(sel))
    atual <- as.character(audit[[coluna]][sel])
    hit <- vazio(atual)
    if (any(hit)) data.table::set(audit, i = sel[hit], j = coluna, value = valor[hit])
    invisible(NULL)
  }
  colapsar_observado <- function(cols, sel) {
    cols <- unique(cols[!is.na(cols) & nzchar(cols) & cols %in% names(dt)])
    out <- rep("", length(sel))
    if (length(cols)) for (cc in cols) {
      vv <- as.character(dt[[cc]][linha[sel]])
      hit <- !vazio(vv)
      if (any(hit)) {
        pedaco <- paste0(cc, " = ", vv[hit])
        out[hit] <- ifelse(nzchar(out[hit]), paste0(out[hit], " | ", pedaco), pedaco)
      }
    }
    out[!nzchar(out)] <- "<vazio>"
    out
  }
  aplicar_categoria_orfa <- function(tipo_pendencia, categoria, canonico, regra) {
    sel <- which(as.character(audit$tipo_pendencia) == tipo_pendencia)
    if (!length(sel)) return(invisible(NULL))
    cols <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(dt, categoria), error = function(e) character(0))
    atribuir_vazios(sel, "atributo_canonico_2025", canonico)
    atribuir_vazios(sel, "atributo_fisico_registros_corrig", paste(cols, collapse = " | "))
    atribuir_vazios(sel, "valor_observado", colapsar_observado(cols, sel))
    atribuir_vazios(sel, "categoria_superior", categoria)
    atribuir_vazios(sel, "forma_de_vida_detectada", "<ausente>")
    atribuir_vazios(sel, "regra_contrato", regra)
    invisible(NULL)
  }
  aplicar_categoria_orfa(
    "nativa_sem_forma_vida", "nativa", "amostragem/registro/forma_vida_nativa",
    "selected(${tipo_forma_vida}, 'nativa') exige ao menos uma forma válida em forma_vida_nativa"
  )
  aplicar_categoria_orfa(
    "exotica_sem_forma_vida", "exotica", "amostragem/registro/forma_vida_exotica",
    "selected(${tipo_forma_vida}, 'exotica') exige ao menos uma forma válida em forma_vida_exotica"
  )
  aplicar_categoria_orfa(
    "seca_morta_sem_forma_vida", "seca_morta", "amostragem/registro/forma_vida_seca_morta",
    "selected(${tipo_forma_vida}, 'seca_morta') exige ao menos uma forma válida em forma_vida_seca_morta"
  )

  tipo_col <- chaves[["tipo_forma_vida"]]
  cols_tipo <- if (!is.null(tipo_col) && !is.na(tipo_col) && tipo_col %in% names(dt)) tipo_col else character(0)
  for (tp in c("ponto_sem_interceptacao", "solo_nu_com_outra_categoria")) {
    sel <- which(as.character(audit$tipo_pendencia) == tp)
    if (!length(sel)) next
    atribuir_vazios(sel, "atributo_canonico_2025", "amostragem/registro/tipo_forma_vida")
    atribuir_vazios(sel, "atributo_fisico_registros_corrig", paste(cols_tipo, collapse = " | "))
    atribuir_vazios(sel, "valor_observado", colapsar_observado(cols_tipo, sel))
    atribuir_vazios(sel, "categoria_superior", "Encostam")
    atribuir_vazios(sel, "regra_contrato", if (tp == "ponto_sem_interceptacao") {
      "todo ponto amostral exige ao menos uma categoria válida em tipo_forma_vida"
    } else {
      "solo_nu é exclusivo e não pode coexistir com serrapilheira, nativa, exotica, seca_morta ou outra_forma_vida"
    })
  }

  sel_outra <- which(as.character(audit$tipo_pendencia) == "outra_forma_vida")
  if (length(sel_outra)) {
    info <- tryCatch(monitora_correcao_colunas_limpeza_outras_formas(dt, NULL), error = function(e) data.table::data.table())
    cols <- if (nrow(info) && "coluna" %in% names(info)) unique(as.character(info$coluna)) else character(0)
    atribuir_vazios(sel_outra, "atributo_canonico_2025", "amostragem/registro/forma_vida_outros e descritores/fotos relevantes")
    atribuir_vazios(sel_outra, "atributo_fisico_registros_corrig", paste(cols, collapse = " | "))
    atribuir_vazios(sel_outra, "valor_observado", colapsar_observado(cols, sel_outra))
    atribuir_vazios(sel_outra, "categoria_superior", "outra_forma_vida")
    atribuir_vazios(sel_outra, "forma_de_vida_detectada", "resíduo histórico de outra forma de vida")
    atribuir_vazios(sel_outra, "regra_contrato", "outra_forma_vida exige token válido e descritores relevantes; resíduos históricos devem ser resolvidos por TRIOUT")
  }

  sel_ua <- which(as.character(audit$tipo_pendencia) == "uas_duplicadas_mesmo_ano")
  if (length(sel_ua)) {
    atribuir_vazios(sel_ua, "atributo_canonico_2025", "UC+UA+ANO+coleta")
    atribuir_vazios(sel_ua, "atributo_fisico_registros_corrig", "UC | UA | ANO | coleta")
    atribuir_vazios(sel_ua, "valor_observado", paste0(
      "UC=", audit$UC[sel_ua], " | UA=", audit$UA[sel_ua], " | ANO=", audit$ANO[sel_ua], " | COLETA=", audit$COLETA[sel_ua]
    ))
    atribuir_vazios(sel_ua, "categoria_superior", "identidade_coleta")
    atribuir_vazios(sel_ua, "regra_contrato", "UC+UA+ANO deve resolver uma única COLETA operacional após decisão auditável")
  }

  audit[]
}

monitora_publicacao_ab_auditar_pendencias_impeditivas <- function(dt,
                                                                  contexto = "pre_registros_corrig",
                                                                  output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                                  log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                                  gravar = TRUE,
                                                                  marcar_base = TRUE) {
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório para auditar pendências impeditivas.", call. = FALSE)
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list())
  get_col <- function(nm) {
    val <- chaves[[nm]]
    if (is.null(val) || is.na(val) || !nzchar(as.character(val)[1L]) || !(as.character(val)[1L] %in% names(dt))) return(rep(NA_character_, n))
    as.character(dt[[as.character(val)[1L]]])
  }
  coleta <- get_col("coleta")
  uc <- get_col("uc")
  ea <- get_col("ea")
  ua <- get_col("ua")
  ano <- get_col("ano")
  ciclo <- get_col("ciclo")
  campanha <- get_col("campanha")
  ponto <- get_col("ponto_amostral")
  ponto_metro <- get_col("ponto_metro")
  row_id <- if (exists("MONITORA_COL_ROW_ID", inherits = TRUE) && MONITORA_COL_ROW_ID %in% names(dt)) as.character(dt[[MONITORA_COL_ROW_ID]]) else rep(NA_character_, n)
  tipo_col <- chaves[["tipo_forma_vida"]]
  tipo <- if (!is.null(tipo_col) && !is.na(tipo_col) && nzchar(as.character(tipo_col)[1L]) && as.character(tipo_col)[1L] %in% names(dt)) as.character(dt[[as.character(tipo_col)[1L]]]) else rep(NA_character_, n)

  issues <- list()
  add_issue <- function(tipo_pendencia, rotulo, mask, mensagem, atributo = NA_character_, severidade = "impeditiva") {
    mask <- as.logical(mask)
    mask[is.na(mask)] <- FALSE
    if (length(mask) != n) mask <- rep(FALSE, n)
    idx <- which(mask)
    if (!length(idx)) return(invisible(NULL))
    issues[[length(issues) + 1L]] <<- data.table::data.table(
      contexto = contexto,
      severidade = severidade,
      tipo_pendencia = tipo_pendencia,
      rotulo_pendencia = rotulo,
      linha_indice = idx,
      COLETA = coleta[idx],
      UC = uc[idx],
      EA = ea[idx],
      UA = ua[idx],
      ANO = ano[idx],
      CICLO = ciclo[idx],
      CAMPANHA = campanha[idx],
      ponto_amostral = ponto[idx],
      ponto_metro = ponto_metro[idx],
      monitora_row_id = row_id[idx],
      atributo = atributo,
      atributo_canonico_2025 = NA_character_,
      atributo_fisico_registros_corrig = atributo,
      valor_observado = NA_character_,
      categoria_superior = NA_character_,
      forma_de_vida_detectada = NA_character_,
      regra_contrato = NA_character_,
      motivo_rejeicao = mensagem,
      produto_rejeitado = "registros_validados.csv",
      bloqueia_registros_validados = TRUE,
      Encostam = tipo[idx],
      mensagem = mensagem
    )
    invisible(NULL)
  }

 ### UAs duplicadas: múltiplas COLETAS no mesmo conjunto UC+UA+ANO.
  if (n && all(!vapply(list(uc, ua, ano, coleta), function(x) all(is.na(x)), logical(1)))) {
    aux <- data.table::data.table(linha_indice = seq_len(n), UC = uc, UA = ua, ANO = ano, COLETA = coleta)
    aux <- aux[!is.na(UC) & nzchar(UC) & !is.na(UA) & nzchar(UA) & !is.na(ANO) & nzchar(ANO) & !is.na(COLETA) & nzchar(COLETA)]
    if (nrow(aux)) {
      grupos_dup <- aux[, .(n_coletas = data.table::uniqueN(COLETA)), by = .(UC, UA, ANO)][n_coletas > 1L]
      if (nrow(grupos_dup)) {
        idx_dup <- aux[grupos_dup, on = .(UC, UA, ANO), linha_indice]
        mask_dup <- rep(FALSE, n); mask_dup[idx_dup] <- TRUE
        add_issue(
          "uas_duplicadas_mesmo_ano",
          "UAs duplicadas no mesmo ano",
          mask_dup,
          "Há múltiplas COLETAS para a mesma UC+UA+ANO; resolver por exclusão/correção assistida antes de considerar registros_corrig final.",
          atributo = "UC+UA+ANO+COLETA"
        )
      }
    }
  }

 ### Ponto sem interceptação: campo superior Encostam/tipo_forma_vida vazio.
  add_issue(
    "ponto_sem_interceptacao",
    "Ponto amostral sem interceptação",
    monitora_correcao_vazio_vec(tipo),
    "Ponto sem categoria de interceptação em Encostam/tipo_forma_vida; corrigir a partir do registro original ou excluir a COLETA.",
    atributo = ifelse(is.null(tipo_col), NA_character_, as.character(tipo_col)[1L])
  )


  tem_token <- function(tokens) {
    if (all(is.na(tipo))) return(rep(FALSE, n))
    tryCatch(monitora_relatorio_exoticas_tem_token(tipo, tokens), error = function(e) rep(FALSE, n))
  }
  forma_nativa <- monitora_publicacao_ab_tem_forma_categoria(dt, "nativa")
  forma_exotica <- monitora_publicacao_ab_tem_forma_categoria(dt, "exotica")
  forma_seca <- monitora_publicacao_ab_tem_forma_categoria(dt, "seca_morta")

  add_issue(
    "nativa_sem_forma_vida",
    "Nativa sem forma de vida",
    tem_token(c("nativa", "nativas", "nativo", "nativos")) & !forma_nativa,
    "Encostam contém nativa, mas não há forma de vida nativa correspondente; conferir planilha original e corrigir a forma de vida ou excluir a COLETA.",
    atributo = "forma_vida_nativa"
  )
  add_issue(
    "exotica_sem_forma_vida",
    "Exótica sem forma de vida",
    tem_token(c("exotica", "exoticas", "exotico", "exoticos")) & !forma_exotica,
    "Encostam contém exotica, mas não há forma de vida exótica correspondente; conferir planilha original e corrigir a forma de vida ou excluir a COLETA.",
    atributo = "forma_vida_exotica"
  )
  add_issue(
    "seca_morta_sem_forma_vida",
    "Seca ou morta sem forma de vida",
    tem_token(c("seca_morta", "seca", "secas", "seco", "secos", "morta", "mortas", "morto", "mortos")) & !forma_seca,
    "Encostam contém seca_morta/seca/morta, mas não há forma de vida seca ou morta correspondente; conferir planilha original e corrigir a forma de vida ou excluir a COLETA.",
    atributo = "forma_vida_seca_morta"
  )

 ### Exclusividade de solo_nu é pendência assistida, não sanitização de
 ### fechamento. O checkpoint preserva o valor observado até decisão humana.
  mask_solo_nu <- tryCatch(
    monitora_correcao_mask_solo_nu_incompativel(dt, chaves),
    error = function(e) rep(FALSE, n)
  )
  add_issue(
    "solo_nu_com_outra_categoria",
    "Solo nu com outra categoria",
    mask_solo_nu,
    "solo_nu é exclusivo, mas coexiste com outra categoria; conferir o registro original e corrigir pelo painel.",
    atributo = ifelse(is.null(tipo_col), NA_character_, as.character(tipo_col)[1L])
  )

 ### Resíduos históricos de outra forma de vida: não sanitizar automaticamente.
  cols_info <- tryCatch(monitora_correcao_colunas_limpeza_outras_formas(dt, NULL), error = function(e) data.table::data.table())
  mask_outra <- rep(FALSE, n)
  cols_outra <- character(0)
  if (nrow(cols_info)) {
    tokens_outra <- tryCatch(monitora_correcao_tokens_residuo_historico_outras_formas(), error = function(e) c("outra_forma_vida", "outras_formas_vida", "outra", "outro", "outras", "outros"))
    listas <- cols_info[classe == "lista_principal_forma_vida" & coluna %in% names(dt), unique(coluna)]
    descritores <- cols_info[classe == "descritor_outra_forma_vida" & coluna %in% names(dt), unique(coluna)]
    fotos <- cols_info[classe == "foto_outra_forma_vida" & coluna %in% names(dt), unique(coluna)]
    for (cc in listas) {
      hit <- tryCatch(monitora_correcao_contem_qualquer_token_vec(dt[[cc]], tokens_outra), error = function(e) rep(FALSE, n))
      hit[is.na(hit)] <- FALSE
      if (any(hit)) cols_outra <- c(cols_outra, cc)
      mask_outra <- mask_outra | hit
    }
    for (cc in unique(c(descritores, fotos))) {
      hit <- !monitora_correcao_vazio_vec(dt[[cc]])
      hit[is.na(hit)] <- FALSE
      if (any(hit)) cols_outra <- c(cols_outra, cc)
      mask_outra <- mask_outra | hit
    }
  }
  add_issue(
    "outra_forma_vida",
    "Outra forma de vida",
    mask_outra,
    "Há resíduo histórico de outra forma de vida; aplicar sanitização assistida no painel ou corrigir manualmente antes de considerar registros_corrig final.",
    atributo = paste(unique(cols_outra), collapse = " | ")
  )

 ### somente estados inválidos de desconhecida entram no gate. O token
 ### válido com a primeira foto required permanece como revisão não impeditiva.
  det_desc_gate <- tryCatch(
    monitora_correcao_classificar_desconhecida(dt, chaves = chaves, dicionario = NULL),
    error = function(e) data.table::data.table()
  )
  if (!("bloqueia_registros_validados" %in% names(det_desc_gate))) det_desc_gate <- data.table::data.table()
  else det_desc_gate <- det_desc_gate[bloqueia_registros_validados == TRUE]
  if (nrow(det_desc_gate)) {
    idx <- as.integer(det_desc_gate$linha_indice)
    canon_desc <- ifelse(
      det_desc_gate$status_contrato == "foto_obrigatoria_desconhecida_ausente",
      paste0("amostragem/registro/foto_forma_vida_", det_desc_gate$categoria, "_desconhecida"),
      ifelse(
        det_desc_gate$categoria == "encostam",
        "amostragem/registro/tipo_forma_vida",
        paste0("amostragem/registro/forma_vida_", det_desc_gate$categoria)
      )
    )
    issues[[length(issues) + 1L]] <- data.table::data.table(
      contexto = contexto,
      severidade = "impeditiva",
      tipo_pendencia = "forma_vida_desconhecida_invalida",
      rotulo_pendencia = "Forma de vida desconhecida inválida",
      linha_indice = idx,
      COLETA = coleta[idx], UC = uc[idx], EA = ea[idx], UA = ua[idx], ANO = ano[idx],
      CICLO = ciclo[idx], CAMPANHA = campanha[idx], ponto_amostral = ponto[idx],
      ponto_metro = ponto_metro[idx], monitora_row_id = row_id[idx],
      atributo = as.character(det_desc_gate$atributo_problema),
      atributo_canonico_2025 = canon_desc,
      atributo_fisico_registros_corrig = as.character(det_desc_gate$atributo_problema),
      valor_observado = as.character(det_desc_gate$valor_observado),
      categoria_superior = as.character(det_desc_gate$categoria),
      forma_de_vida_detectada = "desconhecida",
      regra_contrato = as.character(det_desc_gate$regra_contrato),
      motivo_rejeicao = as.character(det_desc_gate$motivo_rejeicao),
      produto_rejeitado = "registros_validados.csv",
      bloqueia_registros_validados = TRUE,
      Encostam = tipo[idx],
      mensagem = as.character(det_desc_gate$motivo_rejeicao)
    )
  }

 ### habito_obrigatorio_ausente também precisa alimentar
 ### esta mesma auditoria (auditoria_pendencias_impeditivas_registros_corrig.csv
 ### / MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS), que é o que efetivamente
 ### condiciona o gate final de registros_validados.csv (linha ~40982). Antes,
 ### esta auditoria nunca considerava hábito obrigatório, então o gate final
 ### não bloqueava por essa ocorrência mesmo quando monitora_publicacao_g_checar_
 ### invariantes_contrato (a regra-H6) a contava — divergência entre os dois
 ### mecanismos de fechamento. Usa a MESMA máscara corrigida no a regra-H7
 ### (monitora_correcao_mask_habito_obrigatorio_ausente ), não uma nova regra.
  habito_res_aud <- tryCatch(monitora_correcao_mask_habito_obrigatorio_ausente(dt), error = function(e) list(mask = rep(FALSE, n), cols_forma_hit = character(0), cols_habito_hit = character(0)))
 ### captura o `dt` harmonizado devolvido
 ### pela máscara (ver comentário em monitora_correcao_mask_habito_
 ### obrigatorio_ausente ) para que os valores históricos seguros migrados
 ### para o atributo canônico sobrevivam até a exportação de
 ### registros_corrig.csv (monitora_publicacao_aa_exportar_registros_corrig_
 ### aprovado reatribui `dt <- res_imp$dt` logo após chamar esta função).
 ### Sem esta captura, a harmonização acontecia só dentro desta chamada e era
 ### descartada: o canônico ficava vazio no CSV mesmo com a auditoria de
 ### conciliação registrando status "migrado".
  if (!is.null(habito_res_aud$dt)) dt <- habito_res_aud$dt
  detalhes_hab <- if (!is.null(habito_res_aud$detalhes)) data.table::as.data.table(habito_res_aud$detalhes) else data.table::data.table()
  if (nrow(detalhes_hab)) {
    idx <- as.integer(detalhes_hab$linha_indice)
    valid_idx <- !is.na(idx) & idx >= 1L & idx <= n
    detalhes_hab <- detalhes_hab[valid_idx]
    idx <- as.integer(detalhes_hab$linha_indice)
    valor_obs <- as.character(detalhes_hab$valor_habito_atual)
    motivo <- ifelse(
      is.na(valor_obs) | !nzchar(trimws(valor_obs)),
      "campo required vazio para forma presente e relevante",
      paste0("valor fora do domínio epifita|terrestre|rupicola: ", valor_obs)
    )
    issues[[length(issues) + 1L]] <- data.table::data.table(
      contexto = contexto,
      severidade = "impeditiva",
      tipo_pendencia = "habito_obrigatorio_ausente",
      rotulo_pendencia = "Hábito obrigatório ausente",
      linha_indice = idx,
      COLETA = coleta[idx], UC = uc[idx], EA = ea[idx], UA = ua[idx], ANO = ano[idx],
      CICLO = ciclo[idx], CAMPANHA = campanha[idx], ponto_amostral = ponto[idx],
      ponto_metro = ponto_metro[idx], monitora_row_id = row_id[idx],
      atributo = as.character(detalhes_hab$atributo_habito_obrigatorio),
      atributo_canonico_2025 = as.character(detalhes_hab$atributo_canonico_habito),
      atributo_fisico_registros_corrig = as.character(detalhes_hab$atributo_habito_obrigatorio),
      valor_observado = valor_obs,
      categoria_superior = as.character(detalhes_hab$categoria_superior),
      forma_de_vida_detectada = as.character(detalhes_hab$forma_de_vida_detectada),
      regra_contrato = paste0(
        "required=yes; relevant=selected(${forma_vida_", as.character(detalhes_hab$categoria_superior),
        "}, '", monitora_correcao_normalizar_forma_habito(detalhes_hab$forma_de_vida_detectada),
        "'); domínio=epifita|terrestre|rupicola"
      ),
      motivo_rejeicao = motivo,
      produto_rejeitado = "registros_validados.csv",
      bloqueia_registros_validados = TRUE,
      Encostam = tipo[idx],
      mensagem = "Forma presente exige hábito válido no atributo físico canônico do XLSForm 2025; corrigir pelo painel antes da materialização."
    )
  }


  audit <- if (length(issues)) data.table::rbindlist(issues, fill = TRUE, use.names = TRUE) else data.table::data.table(
    contexto = character(), severidade = character(), tipo_pendencia = character(), rotulo_pendencia = character(), linha_indice = integer(),
    COLETA = character(), UC = character(), EA = character(), UA = character(), ANO = character(), CICLO = character(), CAMPANHA = character(),
    ponto_amostral = character(), ponto_metro = character(), monitora_row_id = character(), atributo = character(),
    atributo_canonico_2025 = character(), atributo_fisico_registros_corrig = character(), valor_observado = character(),
    categoria_superior = character(), forma_de_vida_detectada = character(), regra_contrato = character(), motivo_rejeicao = character(),
    produto_rejeitado = character(), bloqueia_registros_validados = logical(), Encostam = character(), mensagem = character()
  )
  audit <- monitora_publicacao_ab_enriquecer_rejeicoes(audit, dt, chaves)
  if (nrow(audit)) {
    audit[, COLETA := as.character(COLETA)]
    audit[, chave_linha := paste(tipo_pendencia, linha_indice, atributo_canonico_2025, atributo, sep = "::")]
    audit <- unique(audit, by = "chave_linha")
    audit[, chave_linha := NULL]
  }
  resumo <- if (nrow(audit)) {
    audit[, .(
      n_linhas = .N,
      n_coletas = data.table::uniqueN(COLETA[!is.na(COLETA) & nzchar(COLETA)]),
      coletas_exemplo = paste(utils::head(unique(COLETA[!is.na(COLETA) & nzchar(COLETA)]), 20L), collapse = " | "),
      mensagem = mensagem[1L]
    ), by = .(contexto, severidade, tipo_pendencia, rotulo_pendencia)][order(tipo_pendencia)]
  } else {
    data.table::data.table(contexto = contexto, severidade = character(), tipo_pendencia = character(), rotulo_pendencia = character(), n_linhas = integer(), n_coletas = integer(), coletas_exemplo = character(), mensagem = character())
  }

  if (isTRUE(marcar_base)) {
    status_val <- if (nrow(audit)) "corrigido_com_pendencias_impeditivas" else "corrigido_sem_pendencias_impeditivas"
    data.table::set(dt, j = "monitora_status_registros_corrig", value = rep(status_val, n))
    data.table::set(dt, j = "monitora_pendencia_impeditiva", value = rep(FALSE, n))
    data.table::set(dt, j = "monitora_pendencia_impeditiva_tipo", value = rep("", n))
    data.table::set(dt, j = "monitora_pendencia_impeditiva_msg", value = rep("", n))
    if (nrow(audit)) {
      por_linha <- audit[, .(
        tipo = paste(unique(tipo_pendencia), collapse = " | "),
        msg = paste(unique(mensagem), collapse = " | ")
      ), by = linha_indice]
      idx <- por_linha$linha_indice
      data.table::set(dt, i = idx, j = "monitora_pendencia_impeditiva", value = TRUE)
      data.table::set(dt, i = idx, j = "monitora_pendencia_impeditiva_tipo", value = por_linha$tipo)
      data.table::set(dt, i = idx, j = "monitora_pendencia_impeditiva_msg", value = por_linha$msg)
    }
  }

  if (isTRUE(gravar)) {
    dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
    dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
    arq_aud <- file.path(output_dir, "auditoria_pendencias_impeditivas_registros_corrig.csv")
    arq_det <- file.path(output_dir, "relatorio_detalhado_rejeicoes_validacao_registros_corrig.csv")
    arq_res <- file.path(output_dir, "resumo_pendencias_impeditivas_registros_corrig.csv")
    data.table::fwrite(audit, arq_aud, na = "", encoding = "UTF-8", bom = TRUE, eol = "\n")
    data.table::fwrite(audit, arq_det, na = "", encoding = "UTF-8", bom = TRUE, eol = "\n")
    data.table::fwrite(resumo, arq_res, na = "", encoding = "UTF-8", bom = TRUE, eol = "\n")
    exec_id <- get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)
    try(data.table::fwrite(audit, file.path(log_dir, paste0("auditoria_pendencias_impeditivas_registros_corrig_", exec_id, ".csv")), na = ""), silent = TRUE)
    try(data.table::fwrite(resumo, file.path(log_dir, paste0("resumo_pendencias_impeditivas_registros_corrig_", exec_id, ".csv")), na = ""), silent = TRUE)
  }

  assign("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS", nrow(audit) > 0L, envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS_AUDITORIA", audit, envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS_RESUMO", resumo, envir = .GlobalEnv)
  invisible(list(auditoria = audit, resumo = resumo, n_pendencias = nrow(audit), dt = dt))
}

monitora_publicacao_ab_logar_resumo_pendencias <- function(resumo, contexto = "registros_corrig") {
  resumo <- tryCatch(data.table::as.data.table(resumo), error = function(e) data.table::data.table())
  if (!nrow(resumo)) return(invisible(NULL))
  msg <- paste(paste0(resumo$rotulo_pendencia, ": ", resumo$n_coletas, " coleta(s), ", resumo$n_linhas, " linha(s)"), collapse = "; ")
  if (exists("monitora_publicacao_g_log", mode = "function")) {
    monitora_publicacao_g_log("ATENÇÃO: registros_corrig.csv será/foi tratado como checkpoint com pendências impeditivas [", contexto, "]: ", msg)
  } else if (exists("monitora_correcao_console_msg", mode = "function")) {
    monitora_correcao_console_msg("ATENÇÃO: registros_corrig.csv será/foi tratado como checkpoint com pendências impeditivas [", contexto, "]: ", msg)
  } else {
    message("ATENÇÃO: registros_corrig.csv com pendências impeditivas [", contexto, "]: ", msg)
  }
  invisible(NULL)
}
