### ------------------------

monitora_deduplicar_registros_amostrais <- function(dt, arquivos_entrada = NULL) {
 # Deduplicação semântica com tabela auxiliar estreita.
 # A tabela auxiliar contém apenas colunas necessárias para ordenar e selecionar registros.
 # Isso evita copiar todas as colunas durante a deduplicação.
  dt <- monitora_dt_referenciar(dt)
  source_col <- if ("MONITORA_ARQUIVO_ENTRADA" %in% names(dt)) {
    "MONITORA_ARQUIVO_ENTRADA"
  } else if (".id" %in% names(dt)) {
    ".id"
  } else {
    NA_character_
  }
  if (is.na(source_col)) {
    monitora_log_registrar_evento("deduplicacao_semantica", "AVISO", NA_character_, "Coluna de proveniência ausente; deduplicacao semantica por arquivo nao executada", "mantido sem alteracao")
    return(dt)
  }

  id_chr <- as.character(dt[[source_col]])
  tipo <- rep("desconhecido", nrow(dt))
  if (!is.null(arquivos_entrada) && all(c("basename", "tipo_entrada") %in% names(arquivos_entrada))) {
    tipo_map <- setNames(as.character(arquivos_entrada$tipo_entrada), as.character(arquivos_entrada$basename))
    tipo[!is.na(tipo_map[id_chr])] <- tipo_map[id_chr[!is.na(tipo_map[id_chr])]]
  }
  tipo <- monitora_io_normalizar_tipo_entrada(tipo)
  data.table::set(dt, j = "MONITORA_TIPO_ENTRADA", value = tipo)

  norm_key <- function(x) {
    x <- monitora_txt_normalizar_vazio(x)
    x <- monitora_txt_reparar_mojibake_utf8_latin1(x)
    x <- stringr::str_squish(toupper(as.character(x)))
 ### Exportações equivalentes já observadas usam CICLO-2023-VGCS ou
 ### CICLO_2023_VGCS. A chave semântica não pode divergir só pelo separador.
    x <- stringr::str_replace_all(x, "[[:space:]_-]+", "_")
    x
  }
  get_col <- function(nm) if (nm %in% names(dt)) dt[[nm]] else rep(NA_character_, nrow(dt))

  ponto_col <- if ("ponto_amostral (amostragem/registro)" %in% names(dt)) {
    "ponto_amostral (amostragem/registro)"
  } else if ("ponto_metro (amostragem/registro)" %in% names(dt)) {
    "ponto_metro (amostragem/registro)"
  } else {
    NA_character_
  }

  uuid_registro <- monitora_txt_normalizar_vazio(monitora_vetor_coalesce(
    get_col("uuid (amostragem/registro)"),
    get_col("amostragem/registro/uuid")
  ))
 ### Em exportações individuais, `UUID` identifica a linha do repeat;
 ### `uuid` minúsculo pode ser o UUID pai da coleta repetido em todos os 101
 ### pontos e por isso nunca é usado como identidade de registro. Campos
 ### pipeados/malformados também não são UUIDs confiáveis.
  uuid_fallback <- monitora_txt_normalizar_vazio(get_col("UUID"))
  uuid_fallback[as.character(dt$MONITORA_TIPO_ENTRADA) == "bruto_lote_sismonitora"] <- NA_character_
  uuid_registro[!monitora_uuid_registro_valido(uuid_registro)] <- NA_character_
  uuid_fallback[!monitora_uuid_registro_valido(uuid_fallback)] <- NA_character_
  uuid_reg <- monitora_txt_normalizar_vazio(monitora_vetor_coalesce(uuid_registro, uuid_fallback))
 ### Um UUID repetido dentro do mesmo arquivo não é identidade de linha
 ### confiável (tipicamente UUID pai); nesse caso a chave composta assume.
  uuid_fonte <- paste(id_chr, uuid_reg, sep = "::")
  uuid_repete_na_fonte <- !is.na(uuid_reg) & (duplicated(uuid_fonte) | duplicated(uuid_fonte, fromLast = TRUE))
  uuid_reg[uuid_repete_na_fonte] <- NA_character_
  key_uuid <- ifelse(!is.na(uuid_reg), paste0("UUID_REGISTRO::", uuid_reg), NA_character_)
  rm(uuid_registro, uuid_fallback, uuid_reg, uuid_fonte, uuid_repete_na_fonte); monitora_recurso_gc("dedup_chave_uuid")

  key_uc <- norm_key(get_col("UC"))
  key_ciclo <- norm_key(get_col("CICLO"))
  key_campanha <- norm_key(get_col("CAMPANHA"))
  key_ua <- norm_key(get_col("UA"))
  key_coleta <- norm_key(monitora_vetor_coalesce(get_col("COLETA"), get_col("coleta"), get_col("coleta_uuid")))
  key_ponto <- if (!is.na(ponto_col)) norm_key(get_col(ponto_col)) else rep(NA_character_, nrow(dt))
  key_campos_ok <- !is.na(key_uc) & !is.na(key_ciclo) & !is.na(key_campanha) & !is.na(key_ua) & !is.na(key_ponto)
  key_campos <- rep(NA_character_, nrow(dt))
  key_campos_com_coleta_ok <- key_campos_ok & !is.na(key_coleta) & nzchar(key_coleta)
  key_campos[key_campos_com_coleta_ok] <- paste(key_uc[key_campos_com_coleta_ok], key_ciclo[key_campos_com_coleta_ok], key_campanha[key_campos_com_coleta_ok], key_ua[key_campos_com_coleta_ok], key_coleta[key_campos_com_coleta_ok], key_ponto[key_campos_com_coleta_ok], sep = "||")
  key_campos_sem_coleta_ok <- key_campos_ok & is.na(key_campos)
  key_campos[key_campos_sem_coleta_ok] <- paste(key_uc[key_campos_sem_coleta_ok], key_ciclo[key_campos_sem_coleta_ok], key_campanha[key_campos_sem_coleta_ok], key_ua[key_campos_sem_coleta_ok], key_ponto[key_campos_sem_coleta_ok], sep = "||")
 # Para deduplicar corretamente exportações em lote e exportações individuais, a chave semântica
 # usa COLETA/coleta_uuid quando disponível. Isso mantém a deduplicação automática de registros
 # genuinamente idênticos da mesma coleta, mas evita colapsar automaticamente COLETAS distintas
 # que tenham recebido a mesma denominação de UA no mesmo ano por erro de campo.
 ### UUID de registro é a identidade mais forte e tem prioridade.
 ### A chave composta é somente fallback para fontes sem UUID confiável.
  key <- ifelse(!is.na(key_uuid), key_uuid, ifelse(!is.na(key_campos), ifelse(key_campos_com_coleta_ok, paste0("UC_CICLO_CAMPANHA_UA_COLETA_PONTO::", key_campos), paste0("UC_CICLO_CAMPANHA_UA_PONTO::", key_campos)), NA_character_))
  rm(key_uuid, key_uc, key_ciclo, key_campanha, key_ua, key_coleta, key_ponto, key_campos_ok, key_campos_com_coleta_ok, key_campos_sem_coleta_ok, key_campos); monitora_recurso_gc("dedup_chave_campos")

  prioridade <- data.table::fifelse(tipo == "pos_tratamento_script", 1L,
                                    data.table::fifelse(tipo == "bruto_lote_sismonitora", 2L,
                                                        data.table::fifelse(tipo == "bruto_individual_sismonitora", 3L, 9L)))
  aux <- data.table::data.table(
    MONITORA_ORDEM_ORIGINAL = seq_len(nrow(dt)),
    MONITORA_CHAVE_DEDUP = key,
    MONITORA_PRIORIDADE_DEDUP = prioridade,
    MONITORA_TIPO_ENTRADA = tipo,
    MONITORA_FONTE = id_chr
  )
  rm(key, prioridade, tipo, id_chr); monitora_recurso_gc("dedup_aux_estreito_criado")

  cand <- aux[!is.na(MONITORA_CHAVE_DEDUP)]
  if (nrow(cand) == 0) {
    monitora_log_registrar_evento("deduplicacao_semantica", "AVISO", NA_character_, "Nenhuma chave amostral confiavel encontrada para deduplicacao semantica", "mantido sem alteracao")
    rm(aux, cand); monitora_recurso_gc("dedup_sem_chaves")
    return(dt)
  }

  data.table::setorder(cand, MONITORA_CHAVE_DEDUP, MONITORA_PRIORIDADE_DEDUP, MONITORA_ORDEM_ORIGINAL)
  manter_ordem <- cand[, .SD[1L], by = MONITORA_CHAVE_DEDUP]$MONITORA_ORDEM_ORIGINAL
  duplicadas <- cand[, .N, by = MONITORA_CHAVE_DEDUP][N > 1L]

  if (nrow(duplicadas) > 0) {
    n_dup_total <- nrow(duplicadas)
    exportar_chaves <- head(duplicadas$MONITORA_CHAVE_DEDUP, MONITORA_MAX_CHAVES_AUDITORIA_DUP_SEMANTICA)
    detalhes <- cand[MONITORA_CHAVE_DEDUP %in% exportar_chaves,
      .(
        n_registros = .N,
        arquivos = paste(unique(as.character(MONITORA_FONTE)), collapse = " | "),
        tipos_entrada = paste(unique(MONITORA_TIPO_ENTRADA), collapse = " | "),
        linhas_originais = paste(MONITORA_ORDEM_ORIGINAL, collapse = " | "),
        linha_mantida = min(MONITORA_ORDEM_ORIGINAL[order(MONITORA_PRIORIDADE_DEDUP, MONITORA_ORDEM_ORIGINAL)])
      ),
      by = MONITORA_CHAVE_DEDUP
    ][n_registros > 1L]
    detalhes[, auditoria_truncada := n_dup_total > MONITORA_MAX_CHAVES_AUDITORIA_DUP_SEMANTICA]
    detalhes[, n_chaves_duplicadas_total := n_dup_total]
    detalhes[, n_chaves_duplicadas_exportadas := nrow(detalhes)]
    monitora_fwrite(detalhes, file.path(MONITORA_LOG_DIR, paste0("auditoria_duplicidades_semanticas_", MONITORA_EXEC_ID, ".csv")))
    if (n_dup_total > MONITORA_MAX_CHAVES_AUDITORIA_DUP_SEMANTICA) {
      monitora_log_registrar_evento("deduplicacao_semantica", "AVISO", NA_character_, paste0("Auditoria de duplicidades semânticas truncada: ", n_dup_total, " chaves duplicadas no total; ", nrow(detalhes), " exportadas"), "aumentar MONITORA_MAX_CHAVES_AUDITORIA_DUP_SEMANTICA se precisar do detalhe completo")
    }
    monitora_log_registrar_evento(
      "deduplicacao_semantica",
      "AVISO",
      NA_character_,
      paste0(n_dup_total, " chaves amostrais duplicadas detectadas; ", nrow(detalhes), " exportadas na auditoria; mantida uma linha por chave"),
      "preferência: pos_tratamento_script > bruto_lote_sismonitora > bruto_individual_sismonitora > desconhecido; ver auditoria_duplicidades_semanticas"
    )
    rm(detalhes); monitora_recurso_gc("auditoria_duplicidades_semanticas")
  }

  sem_chave <- aux[is.na(MONITORA_CHAVE_DEDUP), MONITORA_ORDEM_ORIGINAL]
  keep <- sort(unique(c(sem_chave, manter_ordem)))
  removidas_n <- nrow(dt) - length(keep)
  if (removidas_n > 0) {
    monitora_log_registrar_evento("deduplicacao_semantica", "INFO", NA_character_, paste0(removidas_n, " linhas removidas por duplicidade semantica"), "linhas sem chave confiavel foram mantidas")
  }
  rm(aux, cand, duplicadas, sem_chave, manter_ordem); monitora_recurso_gc("dedup_antes_subconjunto_final")
  out <- dt[keep]
  out[]
}

monitora_data_ano_plausivel <- function(d, ano_min = 2000L, ano_max = lubridate::year(Sys.Date()) + 1L) {
  ano <- suppressWarnings(as.integer(format(d, "%Y")))
  !is.na(d) & !is.na(ano) & ano >= ano_min & ano <= ano_max
}


monitora_deduplicar_final_por_ponto_ano <- function(dt) {
 # Trava final de integridade antes da construção de registros_corrig_stat.
 # Objetivo: impedir que a mesma unidade amostral/ponto/ano entre duas vezes
 # quando arquivos pós-tratamento são combinados com brutos individuais/lote.
 # A deduplicação inicial ocorre antes de algumas padronizações e pode deixar
 # passar sobreposições raras; esta etapa usa os campos já normalizados e ANO.
  dt <- monitora_dt_referenciar(dt)

  ponto_col <- if ("ponto_amostral (amostragem/registro)" %in% names(dt)) {
    "ponto_amostral (amostragem/registro)"
  } else if ("ponto_metro (amostragem/registro)" %in% names(dt)) {
    "ponto_metro (amostragem/registro)"
  } else {
    NA_character_
  }

  by_cols <- c("UC", "CICLO", "CAMPANHA", "UA", "ANO")
  by_cols <- by_cols[by_cols %in% names(dt)]
  if (is.na(ponto_col) || length(by_cols) < 4L) {
    monitora_log_registrar_evento(
      "deduplicacao_final_ponto_ano",
      "AVISO",
      NA_character_,
      paste0("Campos insuficientes para deduplicação final: by_cols=", paste(by_cols, collapse = ", "), "; ponto_col=", ponto_col),
      "mantido sem alteração"
    )
    return(dt)
  }

  norm_key <- function(x) {
    x <- monitora_txt_normalizar_vazio(x)
    stringr::str_squish(toupper(as.character(x)))
  }

  aux <- data.table::data.table(MONITORA_ORDEM_ORIGINAL = seq_len(nrow(dt)))
  for (cc in by_cols) {
    data.table::set(aux, j = cc, value = norm_key(dt[[cc]]))
  }
  data.table::set(aux, j = "ponto", value = norm_key(dt[[ponto_col]]))

  campos_chave <- c(by_cols, "ponto")
  ok <- Reduce(`&`, lapply(campos_chave, function(cc) !is.na(aux[[cc]]) & nzchar(aux[[cc]])))
  aux[, MONITORA_CHAVE_FINAL := NA_character_]
  if (any(ok)) {
    aux[ok, MONITORA_CHAVE_FINAL := do.call(paste, c(.SD, sep = "||")), .SDcols = campos_chave]
  }

  tipo <- if ("MONITORA_TIPO_ENTRADA" %in% names(dt)) monitora_io_normalizar_tipo_entrada(dt[["MONITORA_TIPO_ENTRADA"]]) else rep("desconhecido", nrow(dt))
  fonte <- if ("MONITORA_ARQUIVO_ENTRADA" %in% names(dt)) {
    as.character(dt[["MONITORA_ARQUIVO_ENTRADA"]])
  } else if (".id" %in% names(dt)) {
    as.character(dt[[".id"]])
  } else {
    rep(NA_character_, nrow(dt))
  }

  prioridade <- data.table::fifelse(tipo == "pos_tratamento_script", 1L,
    data.table::fifelse(tipo == "bruto_lote_sismonitora", 2L,
      data.table::fifelse(tipo == "bruto_individual_sismonitora", 3L, 9L)
    )
  )
  data.table::set(aux, j = "MONITORA_TIPO_ENTRADA", value = tipo)
  data.table::set(aux, j = "MONITORA_FONTE", value = fonte)
  data.table::set(aux, j = "MONITORA_PRIORIDADE_DEDUP", value = prioridade)
  coleta_col <- if ("COLETA" %in% names(dt)) "COLETA" else NA_character_
  data.table::set(aux, j = "MONITORA_COLETA", value = if (!is.na(coleta_col)) as.character(dt[[coleta_col]]) else NA_character_)
  aux[, MONITORA_BLOQUEAR_DEDUP_COLETA_UA_ANO := FALSE]
  if (all(c("UC", "UA", "ANO") %in% names(aux)) && !all(is.na(aux$MONITORA_COLETA))) {
    grupos_coleta <- aux[!is.na(UC) & nzchar(UC) & !is.na(UA) & nzchar(UA) & !is.na(ANO) & nzchar(ANO) & !is.na(MONITORA_COLETA) & nzchar(MONITORA_COLETA),
      .(n_coletas = data.table::uniqueN(MONITORA_COLETA)), by = .(UC, UA, ANO)][n_coletas > 1L]
    if (nrow(grupos_coleta) > 0L) {
      aux[grupos_coleta, on = .(UC, UA, ANO), MONITORA_BLOQUEAR_DEDUP_COLETA_UA_ANO := TRUE]
      monitora_log_registrar_evento(
        "deduplicacao_final_ponto_ano",
        "AVISO",
        NA_character_,
        paste0(nrow(grupos_coleta), " combinação(ões) UC+UA+ANO com múltiplas COLETAS detectada(s); deduplicação automática por ponto bloqueada para esses casos"),
        "esses conflitos devem ser resolvidos no painel e serão travados após correções"
      )
    }
  }

  cand <- aux[!is.na(MONITORA_CHAVE_FINAL)]
  if (nrow(cand) == 0) {
    monitora_log_registrar_evento("deduplicacao_final_ponto_ano", "AVISO", NA_character_, "Nenhuma chave final UC/CICLO/CAMPANHA/UA/ANO/ponto confiável encontrada", "mantido sem alteração")
    rm(aux, cand); monitora_recurso_gc("dedup_final_sem_chaves")
    return(dt)
  }

  duplicadas_todas <- cand[, .(N = .N, bloquear_dedup_coleta_ua_ano = any(MONITORA_BLOQUEAR_DEDUP_COLETA_UA_ANO, na.rm = TRUE)), by = MONITORA_CHAVE_FINAL][N > 1L]
  duplicadas_bloqueadas <- duplicadas_todas[bloquear_dedup_coleta_ua_ano == TRUE]
  duplicadas <- duplicadas_todas[bloquear_dedup_coleta_ua_ano == FALSE]
  if (nrow(duplicadas_bloqueadas) > 0L) {
    detalhes_bloq <- cand[MONITORA_CHAVE_FINAL %in% duplicadas_bloqueadas$MONITORA_CHAVE_FINAL, .(
      n_registros = .N,
      coletas = paste(sort(unique(MONITORA_COLETA[!is.na(MONITORA_COLETA) & nzchar(MONITORA_COLETA)])), collapse = " | "),
      tipos_entrada = paste(unique(MONITORA_TIPO_ENTRADA), collapse = " | "),
      arquivos = paste(unique(as.character(MONITORA_FONTE)), collapse = " | "),
      linhas_originais = paste(MONITORA_ORDEM_ORIGINAL, collapse = " | "),
      motivo_bloqueio = "múltiplas COLETAS para a mesma UC+UA+ANO; não remover automaticamente"
    ), by = MONITORA_CHAVE_FINAL]
    saida_bloq <- file.path(MONITORA_LOG_DIR, paste0("auditoria_deduplicacao_final_bloqueada_coletas_ua_ano_", MONITORA_EXEC_ID, ".csv"))
    monitora_fwrite(detalhes_bloq, saida_bloq)
    monitora_fwrite(detalhes_bloq, file.path(MONITORA_OUTPUT_DIR, "auditoria_deduplicacao_final_bloqueada_coletas_ua_ano_ultima_execucao.csv"))
    monitora_log_registrar_evento("deduplicacao_final_ponto_ano", "AVISO", saida_bloq, paste0(nrow(duplicadas_bloqueadas), " chave(s) finais duplicadas não deduplicadas por conflito de COLETAS em UC+UA+ANO"), "resolver no painel; trava pós-correções impedirá estatísticas se persistir")
    rm(detalhes_bloq)
  }
  if (nrow(duplicadas) == 0) {
    monitora_log_registrar_evento("deduplicacao_final_ponto_ano", "INFO", NA_character_, "Nenhuma duplicidade final segura UC/CICLO/CAMPANHA/UA/ANO/ponto encontrada para remoção automática", "conflitos de COLETAS por UC+UA+ANO foram preservados para triagem")
    rm(aux, cand, duplicadas_todas, duplicadas, duplicadas_bloqueadas); monitora_recurso_gc("dedup_final_sem_duplicidade")
    return(dt)
  }

  cand_auto <- cand[MONITORA_CHAVE_FINAL %in% duplicadas$MONITORA_CHAVE_FINAL | !(MONITORA_CHAVE_FINAL %in% duplicadas_todas$MONITORA_CHAVE_FINAL)]
  data.table::setorder(cand_auto, MONITORA_CHAVE_FINAL, MONITORA_PRIORIDADE_DEDUP, MONITORA_ORDEM_ORIGINAL)
  manter_ordem <- cand_auto[, .SD[1L], by = MONITORA_CHAVE_FINAL]$MONITORA_ORDEM_ORIGINAL
  sem_chave <- aux[is.na(MONITORA_CHAVE_FINAL), MONITORA_ORDEM_ORIGINAL]
  manter_bloqueadas <- if (exists("duplicadas_bloqueadas") && nrow(duplicadas_bloqueadas) > 0L) cand[MONITORA_CHAVE_FINAL %in% duplicadas_bloqueadas$MONITORA_CHAVE_FINAL, MONITORA_ORDEM_ORIGINAL] else integer(0)
  keep <- sort(unique(c(sem_chave, manter_ordem, manter_bloqueadas)))

  exportar_chaves <- head(duplicadas$MONITORA_CHAVE_FINAL, MONITORA_MAX_CHAVES_AUDITORIA_DUP_SEMANTICA)
  detalhes <- cand[MONITORA_CHAVE_FINAL %in% exportar_chaves,
    .(
      n_registros = .N,
      tipos_entrada = paste(unique(MONITORA_TIPO_ENTRADA), collapse = " | "),
      arquivos = paste(unique(as.character(MONITORA_FONTE)), collapse = " | "),
      linhas_originais = paste(MONITORA_ORDEM_ORIGINAL, collapse = " | "),
      linha_mantida = MONITORA_ORDEM_ORIGINAL[order(MONITORA_PRIORIDADE_DEDUP, MONITORA_ORDEM_ORIGINAL)][1L],
      tipo_mantido = MONITORA_TIPO_ENTRADA[order(MONITORA_PRIORIDADE_DEDUP, MONITORA_ORDEM_ORIGINAL)][1L],
      arquivo_mantido = MONITORA_FONTE[order(MONITORA_PRIORIDADE_DEDUP, MONITORA_ORDEM_ORIGINAL)][1L]
    ),
    by = MONITORA_CHAVE_FINAL
  ][n_registros > 1L]
  detalhes[, auditoria_truncada := nrow(duplicadas) > MONITORA_MAX_CHAVES_AUDITORIA_DUP_SEMANTICA]
  detalhes[, n_chaves_duplicadas_total := nrow(duplicadas)]
  detalhes[, n_chaves_duplicadas_exportadas := nrow(detalhes)]

  saida <- file.path(MONITORA_LOG_DIR, paste0("auditoria_deduplicacao_final_ponto_ano_", MONITORA_EXEC_ID, ".csv"))
  monitora_fwrite(detalhes, saida)
  monitora_fwrite(detalhes, file.path(MONITORA_OUTPUT_DIR, "auditoria_deduplicacao_final_ponto_ano_ultima_execucao.csv"))

  removidas_n <- nrow(dt) - length(keep)
  monitora_log_registrar_evento(
    "deduplicacao_final_ponto_ano",
    "AVISO",
    saida,
    paste0(nrow(duplicadas), " chaves UC/CICLO/CAMPANHA/UA/ANO/ponto duplicadas detectadas; ", removidas_n, " linha(s) removida(s) antes de registros_corrig_stat"),
    "preferência final: pos_tratamento_script > bruto_lote_sismonitora > bruto_individual_sismonitora > desconhecido"
  )

  rm(aux, cand, cand_auto, duplicadas_todas, duplicadas, duplicadas_bloqueadas, detalhes, manter_ordem, manter_bloqueadas, sem_chave); monitora_recurso_gc("dedup_final_antes_subconjunto")
  out <- dt[keep]
  out[]
}


monitora_auditar_coletas_ua_ano_duplicadas <- function(dt, fase = "pos_correcoes", abortar = FALSE) {
  dt <- data.table::as.data.table(dt)
  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list())
  coleta_col <- if (!is.null(chaves$coleta) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) chaves$coleta else if ("COLETA" %in% names(dt)) "COLETA" else NA_character_
  ua_col <- if (!is.null(chaves$ua) && !is.na(chaves$ua) && chaves$ua %in% names(dt)) chaves$ua else if ("UA" %in% names(dt)) "UA" else NA_character_
  ano_col <- if (!is.null(chaves$ano) && !is.na(chaves$ano) && chaves$ano %in% names(dt)) chaves$ano else if ("ANO" %in% names(dt)) "ANO" else NA_character_
  uc_col <- if (!is.null(chaves$uc) && !is.na(chaves$uc) && chaves$uc %in% names(dt)) chaves$uc else if ("UC" %in% names(dt)) "UC" else NA_character_
  fase_segura <- gsub("[^A-Za-z0-9_]+", "_", as.character(fase))
  saida_log_vazio <- file.path(MONITORA_LOG_DIR, paste0("auditoria_coletas_ua_ano_duplicadas_", fase_segura, "_", MONITORA_EXEC_ID, ".csv"))
  saida_out_vazio <- file.path(MONITORA_OUTPUT_DIR, paste0("auditoria_coletas_ua_ano_duplicadas_", fase_segura, "_ultima_execucao.csv"))

  aud_vazio_template <- function() {
    data.table::data.table(
      UC = character(), UA = character(), ANO = character(),
      n_coletas = integer(), n_linhas = integer(), coletas = character(),
      coleta_uuid = character(), EAs = character(), ciclos = character(), campanhas = character(),
      arquivos = character(), tipos_entrada = character(), datas_data_hora = character(),
      DATA_MONITORA_PARSEADA = character(), ANO_recalculado_de_Data = character(),
      n_linhas_ano_divergente = integer(), linhas_ano_divergente = character(),
      linhas_indice = character(), acao_recomendada = character()
    )
  }

  gravar_vazio <- function(motivo) {
    aud_vazio <- aud_vazio_template()
    try(monitora_fwrite(aud_vazio, saida_log_vazio, na = ""), silent = TRUE)
    try(monitora_fwrite(aud_vazio, saida_out_vazio, na = ""), silent = TRUE)
    if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) {
      try(monitora_fwrite(aud_vazio, file.path(MONITORA_CORRECOES_DIR, paste0("auditoria_coletas_ua_ano_duplicadas_", fase_segura, ".csv")), na = ""), silent = TRUE)
    }
    monitora_log_registrar_evento("coletas_ua_ano_duplicadas", "INFO", saida_log_vazio, motivo, "CSV vazio gravado para auditoria pós-correções")
    aud_vazio
  }

  if (any(is.na(c(coleta_col, ua_col, ano_col, uc_col)))) {
    monitora_log_registrar_evento(
      "coletas_ua_ano_duplicadas",
      "AVISO",
      NA_character_,
      paste0("Campos insuficientes para auditar COLETAS com UA duplicada no mesmo ANO: UC=", uc_col, "; UA=", ua_col, "; ANO=", ano_col, "; COLETA=", coleta_col),
      "auditoria não executada"
    )
    return(data.table::data.table())
  }

  norm <- function(x) {
 # Normalização mínima e rápida para chaves de auditoria. Evita stringr::str_squish
 # sobre dezenas de milhares de linhas quando a auditoria geralmente retorna vazia.
    x <- as.character(x)
    x <- trimws(x)
    x[is.na(x) | !nzchar(x)] <- NA_character_
    toupper(x)
  }
  norm_coleta <- function(x) {
    x <- as.character(x)
    x <- trimws(x)
    x[is.na(x) | !nzchar(x)] <- NA_character_
    x
  }

 # Caminho rápido real: usa vetores base para detectar se existe mais de uma
 # COLETA por UC+UA+ANO. Em bases sem conflito, retorna antes de qualquer
 # data.table::unique , join, parse de data ou montagem de contexto detalhado.
  v_uc <- norm(dt[[uc_col]])
  v_ua <- norm(dt[[ua_col]])
  v_ano <- norm(dt[[ano_col]])
  v_coleta <- norm_coleta(dt[[coleta_col]])
  valido <- !is.na(v_uc) & !is.na(v_ua) & !is.na(v_ano) & !is.na(v_coleta)
  if (!any(valido)) {
    rm(v_uc, v_ua, v_ano, v_coleta, valido)
    return(gravar_vazio(paste0("Nenhuma linha elegível para auditoria de COLETA duplicada por UC+UA+ANO detectada em ", fase)))
  }

  idx_validos <- which(valido)
  chave_coleta <- paste(v_uc[valido], v_ua[valido], v_ano[valido], v_coleta[valido], sep = "
")
  manter_coleta_unica <- !duplicated(chave_coleta)
  grupo_unico <- paste(v_uc[valido][manter_coleta_unica], v_ua[valido][manter_coleta_unica], v_ano[valido][manter_coleta_unica], sep = "
")
  grupo_duplicado_flag <- duplicated(grupo_unico) | duplicated(grupo_unico, fromLast = TRUE)
  if (!any(grupo_duplicado_flag)) {
    rm(v_uc, v_ua, v_ano, v_coleta, valido, idx_validos, chave_coleta, manter_coleta_unica, grupo_unico, grupo_duplicado_flag)
    return(gravar_vazio(paste0("Nenhuma COLETA duplicada por UC+UA+ANO detectada em ", fase)))
  }

  grupos_chave <- unique(grupo_unico[grupo_duplicado_flag])
  aux <- data.table::data.table(
    linha_indice = idx_validos,
    UC = v_uc[valido],
    UA = v_ua[valido],
    ANO = v_ano[valido],
    COLETA = v_coleta[valido]
  )
  aux[, MONITORA_GRUPO_UA_ANO := paste(UC, UA, ANO, sep = "
")]
  det <- aux[MONITORA_GRUPO_UA_ANO %in% grupos_chave]
  grupos <- det[, .(n_linhas = .N, n_coletas = data.table::uniqueN(COLETA)), by = .(UC, UA, ANO)][n_coletas > 1L]
  if (!nrow(grupos)) {
    rm(v_uc, v_ua, v_ano, v_coleta, valido, idx_validos, chave_coleta, manter_coleta_unica, grupo_unico, grupo_duplicado_flag, grupos_chave, aux, det, grupos)
    return(gravar_vazio(paste0("Nenhuma COLETA duplicada por UC+UA+ANO detectada em ", fase)))
  }
  det <- det[grupos, on = .(UC, UA, ANO), nomatch = 0L]
  det[, MONITORA_GRUPO_UA_ANO := NULL]
  rm(v_uc, v_ua, v_ano, v_coleta, valido, idx_validos, chave_coleta, manter_coleta_unica, grupo_unico, grupo_duplicado_flag, grupos_chave)
  idx <- det$linha_indice
  n_idx <- length(idx)

  contexto_col <- function(nome) {
    if (!is.null(chaves[[nome]]) && !is.na(chaves[[nome]]) && chaves[[nome]] %in% names(dt)) {
      as.character(dt[[chaves[[nome]]]][idx])
    } else {
      rep(NA_character_, n_idx)
    }
  }

  data_col <- if (!is.null(chaves$data_hora) && !is.na(chaves$data_hora) && chaves$data_hora %in% names(dt)) chaves$data_hora else NA_character_
  data_val <- if (!is.na(data_col)) as.character(dt[[data_col]][idx]) else rep(NA_character_, n_idx)
  data_parseada_val <- if ("DATA_MONITORA_PARSEADA" %in% names(dt)) as.character(dt[["DATA_MONITORA_PARSEADA"]][idx]) else rep(NA_character_, n_idx)

  ano_recalc_val <- rep(NA_character_, n_idx)
  if ("DATA_MONITORA_PARSEADA" %in% names(dt)) {
    ano_recalc_val <- tryCatch(as.character(lubridate::year(as.Date(dt[["DATA_MONITORA_PARSEADA"]][idx]))), error = function(e) rep(NA_character_, n_idx))
  }
  if (all(is.na(ano_recalc_val)) && !is.na(data_col) && exists("monitora_data_parsear", mode = "function")) {
    ano_recalc_val <- tryCatch(as.character(lubridate::year(monitora_data_parsear(dt[[data_col]][idx]))), error = function(e) rep(NA_character_, n_idx))
  }
  ano_recalc_norm <- norm(ano_recalc_val)

  det[, `:=`(
    Data_data_hora = data_val,
    DATA_MONITORA_PARSEADA = data_parseada_val,
    ANO_recalculado_de_Data = ano_recalc_norm,
    diverge_ano_data = ANO != ano_recalc_norm,
    EA = contexto_col("ea"),
    CICLO = contexto_col("ciclo"),
    CAMPANHA = contexto_col("campanha"),
    coleta_uuid = contexto_col("coleta_uuid"),
    arquivo_origem = if ("MONITORA_ARQUIVO_ENTRADA" %in% names(dt)) as.character(dt[["MONITORA_ARQUIVO_ENTRADA"]][idx]) else if (".id" %in% names(dt)) as.character(dt[[".id"]][idx]) else rep(NA_character_, n_idx),
    tipo_entrada = if ("MONITORA_TIPO_ENTRADA" %in% names(dt)) as.character(dt[["MONITORA_TIPO_ENTRADA"]][idx]) else rep(NA_character_, n_idx)
  )]
  det[is.na(ANO_recalculado_de_Data), diverge_ano_data := FALSE]

  aud <- det[, .(
    n_coletas = data.table::uniqueN(COLETA),
    n_linhas = .N,
    coletas = paste(sort(unique(COLETA)), collapse = " | "),
    coleta_uuid = paste(sort(unique(coleta_uuid[!is.na(coleta_uuid) & nzchar(coleta_uuid)])), collapse = " | "),
    EAs = paste(sort(unique(EA[!is.na(EA) & nzchar(EA)])), collapse = " | "),
    ciclos = paste(sort(unique(CICLO[!is.na(CICLO) & nzchar(CICLO)])), collapse = " | "),
    campanhas = paste(sort(unique(CAMPANHA[!is.na(CAMPANHA) & nzchar(CAMPANHA)])), collapse = " | "),
    arquivos = paste(sort(unique(arquivo_origem[!is.na(arquivo_origem) & nzchar(arquivo_origem)])), collapse = " | "),
    tipos_entrada = paste(sort(unique(tipo_entrada[!is.na(tipo_entrada) & nzchar(tipo_entrada)])), collapse = " | "),
    datas_data_hora = paste(sort(unique(Data_data_hora[!is.na(Data_data_hora) & nzchar(Data_data_hora)])), collapse = " | "),
    DATA_MONITORA_PARSEADA = paste(sort(unique(DATA_MONITORA_PARSEADA[!is.na(DATA_MONITORA_PARSEADA) & nzchar(DATA_MONITORA_PARSEADA)])), collapse = " | "),
    ANO_recalculado_de_Data = paste(sort(unique(ANO_recalculado_de_Data[!is.na(ANO_recalculado_de_Data) & nzchar(ANO_recalculado_de_Data)])), collapse = " | "),
    n_linhas_ano_divergente = sum(diverge_ano_data, na.rm = TRUE),
    linhas_ano_divergente = paste(sort(unique(linha_indice[diverge_ano_data %in% TRUE])), collapse = " | "),
    linhas_indice = paste(sort(unique(linha_indice)), collapse = " | "),
    acao_recomendada = "Resolver no painel: corrigir Data (data_hora), excluir COLETA equivocada, corrigir UA da COLETA ou revisar metadados superiores. Se Data (data_hora) for corrigida, DATA_MONITORA_PARSEADA e ANO são recalculados antes da trava pós-correções."
  ), by = .(UC, UA, ANO)]
  data.table::setorder(aud, UC, UA, ANO)

  saida_log <- file.path(MONITORA_LOG_DIR, paste0("auditoria_coletas_ua_ano_duplicadas_", fase_segura, "_", MONITORA_EXEC_ID, ".csv"))
  saida_out <- file.path(MONITORA_OUTPUT_DIR, paste0("auditoria_coletas_ua_ano_duplicadas_", fase_segura, "_ultima_execucao.csv"))
  try(monitora_fwrite(aud, saida_log, na = ""), silent = TRUE)
  try(monitora_fwrite(aud, saida_out, na = ""), silent = TRUE)
  if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) {
    try(monitora_fwrite(aud, file.path(MONITORA_CORRECOES_DIR, paste0("auditoria_coletas_ua_ano_duplicadas_", fase_segura, ".csv")), na = ""), silent = TRUE)
  }

  msg <- paste0(
    nrow(aud), " combinação(ões) UC+UA+ANO com mais de uma COLETA detectada(s) em ", fase,
    ". Esses casos NÃO são deduplicados automaticamente, pois podem indicar UA selecionada incorretamente ou reamostragem indevida da mesma UA no mesmo ano. ",
    "Resolva no painel por exclusão de COLETA, correção do atributo UA ou outra modificação auditável. Auditoria: ", saida_log
  )
  permitir_checkpoint_pendente <- isTRUE(get0("MONITORA_PERMITIR_REGISTROS_CORRIG_CHECKPOINT_PENDENTE", ifnotfound = TRUE, inherits = TRUE))
  nivel_log <- if (isTRUE(abortar) && !isTRUE(permitir_checkpoint_pendente)) "ERRO" else "AVISO"
  acao_log <- if (isTRUE(permitir_checkpoint_pendente)) {
    "pendência impeditiva para registros_corrig final; será incorporada ao checkpoint marcado quando registros_corrig.csv for materializado"
  } else {
    "triagem obrigatória antes de estatísticas"
  }
  monitora_log_registrar_evento("coletas_ua_ano_duplicadas", nivel_log, saida_log, msg, acao_log)
  if (isTRUE(abortar) && !isTRUE(permitir_checkpoint_pendente)) {
    stop(paste0("COLETAS com UA duplicada no mesmo ANO não resolvidas. ", msg), call. = FALSE)
  }
  aud[]
}

monitora_data_parsear <- function(x) {
  x0 <- monitora_txt_normalizar_vazio(x)
  x1 <- stringr::str_squish(x0)
  x1 <- stringr::str_replace(x1, "T", " ")
  x1 <- stringr::str_replace(x1, "Z$", "")
  x_date_only <- stringr::str_replace(x1, "^([^ ]+).*$", "\\1")
  out <- rep(as.IDate(NA), length(x1))

 # Datas numéricas do Excel: dias desde 1899-12-30.
  suppressWarnings(num <- as.numeric(x1))
  is_excel <- !is.na(num) & num > 20000 & num < 80000
  if (any(is_excel)) {
    d_excel <- as.IDate(as.Date(num[is_excel], origin = "1899-12-30"))
    ok_excel <- monitora_data_ano_plausivel(d_excel)
    out[which(is_excel)[ok_excel]] <- d_excel[ok_excel]
  }

 # Datas com ano de 4 dígitos no final, comuns em CSVs manipulados em planilhas.
 # valores como 3/3/2020 em ano 0003.
  idx_final4 <- which(is.na(out) & !is.na(x_date_only) & grepl("^\\d{1,2}[/-]\\d{1,2}[/-]\\d{4}$", x_date_only))
  if (length(idx_final4) > 0) {
    v <- x_date_only[idx_final4]
    suppressWarnings(d_br <- as.IDate(v, format = "%d/%m/%Y"))
    suppressWarnings(d_us <- as.IDate(v, format = "%m/%d/%Y"))
 # Para dia e mês iguais, d_br == d_us; ainda assim adota-se explicitamente d/m/Y.
    ok_br <- monitora_data_ano_plausivel(d_br)
    ok_us <- monitora_data_ano_plausivel(d_us)
    amb <- ok_br & ok_us & d_br != d_us
    if (any(amb, na.rm = TRUE)) {
      monitora_log_registrar_evento(
        "datas", "AVISO", NA_character_,
        paste0(sum(amb), " datas ambiguas dd/mm/yyyy vs mm/dd/yyyy; adotado dd/mm/yyyy por padrão brasileiro"),
        "verificar registros se o arquivo tiver sido exportado/configurado em locale norte-americano"
      )
    }
    escolhido <- rep(as.IDate(NA), length(v))
    escolhido[ok_br] <- d_br[ok_br]
    escolhido[!ok_br & ok_us] <- d_us[!ok_br & ok_us]
    ok_escolhido <- monitora_data_ano_plausivel(escolhido)
    out[idx_final4[ok_escolhido]] <- escolhido[ok_escolhido]
  }

 # ISO primeiro, depois padrão brasileiro, depois padrão norte-americano.
 # Formatos com ano de 4 dígitos ao final já foram priorizados acima.
  formats <- c(
    "%Y-%m-%d", "%Y/%m/%d", "%Y.%m.%d",
    "%Y-%m-%d %H:%M:%S", "%Y/%m/%d %H:%M:%S", "%Y-%m-%d %H:%M",
    "%d/%m/%Y", "%d-%m-%Y", "%d.%m.%Y",
    "%d/%m/%y", "%d-%m-%y", "%d.%m.%y",
    "%m/%d/%Y", "%m-%d-%Y", "%m.%d.%Y",
    "%m/%d/%y", "%m-%d-%y", "%m.%d.%y",
    "%d/%m/%Y %H:%M:%S", "%d-%m-%Y %H:%M:%S", "%d/%m/%Y %H:%M",
    "%m/%d/%Y %H:%M:%S", "%m-%d-%Y %H:%M:%S", "%m/%d/%Y %H:%M"
  )
  for (fmt in formats) {
    idx <- which(is.na(out) & !is.na(x1))
    if (length(idx) == 0) break
    suppressWarnings(parsed <- as.IDate(x1[idx], format = fmt))
    ok <- monitora_data_ano_plausivel(parsed)
    if (any(ok)) out[idx[ok]] <- parsed[ok]
  }

 # padronizados.
  for (fmt in formats[1:18]) {
    idx <- which(is.na(out) & !is.na(x_date_only))
    if (length(idx) == 0) break
    suppressWarnings(parsed <- as.IDate(x_date_only[idx], format = fmt))
    ok <- monitora_data_ano_plausivel(parsed)
    if (any(ok)) out[idx[ok]] <- parsed[ok]
  }

  n_fail <- sum(is.na(out) & !is.na(x1))
  if (n_fail > 0) {
    monitora_log_registrar_evento("datas", "AVISO", NA_character_, paste0(n_fail, " datas nao convertidas ou com ano fora da faixa plausivel"), "ANO ficará NA nesses registros; ver auditoria_anos_invalidos")
  }
  out
}


monitora_recalcular_derivados_data_hora <- function(dt, contexto = "recalculo_data_hora") {
  dt <- monitora_dt_referenciar(dt)
  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list(data_hora = NA_character_))
  data_col <- if (!is.null(chaves$data_hora) && !is.na(chaves$data_hora) && chaves$data_hora %in% names(dt)) chaves$data_hora else NA_character_
  if (is.na(data_col) || !nzchar(data_col)) {
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("datas", "AVISO", NA_character_, paste0("Coluna de data não encontrada para recálculo em ", contexto), "DATA_MONITORA_PARSEADA/ANO mantidos")
    }
    return(dt[])
  }
  ano_antes <- if ("ANO" %in% names(dt)) as.character(dt[["ANO"]]) else rep(NA_character_, nrow(dt))
  data_antes <- if ("DATA_MONITORA_PARSEADA" %in% names(dt)) as.character(dt[["DATA_MONITORA_PARSEADA"]]) else rep(NA_character_, nrow(dt))
  data_depois <- monitora_data_parsear(dt[[data_col]])
  ano_depois <- as.character(lubridate::year(data_depois))
  data.table::set(dt, j = "DATA_MONITORA_PARSEADA", value = data_depois)
  data.table::set(dt, j = "ANO", value = ano_depois)
  diferente <- function(a, b) {
    a <- as.character(a); b <- as.character(b)
    (is.na(a) != is.na(b)) | (!is.na(a) & !is.na(b) & a != b)
  }
  mudou <- diferente(ano_antes, ano_depois) | diferente(data_antes, as.character(data_depois))
  if (any(mudou, na.rm = TRUE)) {
    idx <- which(mudou)
    aud <- data.table::data.table(
      contexto = contexto,
      linha_indice = idx,
      coluna_data = data_col,
      Data_data_hora = as.character(dt[[data_col]][idx]),
      DATA_MONITORA_PARSEADA_antes = data_antes[idx],
      DATA_MONITORA_PARSEADA_depois = as.character(data_depois[idx]),
      ANO_antes = ano_antes[idx],
      ANO_depois = ano_depois[idx]
    )
    if (exists("MONITORA_LOG_DIR", inherits = TRUE) && exists("MONITORA_EXEC_ID", inherits = TRUE)) {
      arq <- file.path(MONITORA_LOG_DIR, paste0("auditoria_recalculo_data_hora_", gsub("[^A-Za-z0-9_]+", "_", contexto), "_", MONITORA_EXEC_ID, ".csv"))
      try(monitora_fwrite(aud, arq, na = ""), silent = TRUE)
      if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) {
        try(monitora_fwrite(aud, file.path(MONITORA_CORRECOES_DIR, "auditoria_recalculo_data_hora_ultima_execucao.csv"), na = ""), silent = TRUE)
      }
    }
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("datas", "INFO", NA_character_, paste0(length(idx), " linha(s) com DATA_MONITORA_PARSEADA/ANO recalculados em ", contexto), "derivado de Data (data_hora)")
    }
  }
  dt[]
}

monitora_geo_normalizar_coordenada <- function(x) {
  x0 <- monitora_txt_normalizar_vazio(x)
  out <- rep(NA_character_, length(x0))
  sep_type <- rep(NA_character_, length(x0))
  token_count <- rep(NA_integer_, length(x0))
  idx <- which(!is.na(x0))
  if (length(idx)) {
 ### stringi executa a extração em lote. O colapso final continua por
 ### registro porque cada coordenada pode ter 2 a 4 componentes, mas evita
 ### dezenas de milhares de chamadas R→stringi no Windows.
    v <- stringr::str_squish(x0[idx])
    nums <- stringr::str_extract_all(v, "[-+]?\\d+(?:[\\.,]\\d+)?")
    token_count[idx] <- lengths(nums)

    tem_pv <- grepl(";", v, fixed = TRUE)
    tem_pipe <- grepl("|", v, fixed = TRUE)
    tem_virg <- grepl(",", v, fixed = TRUE)
    tem_ponto <- grepl(".", v, fixed = TRUE)
    tem_decimal_virg <- grepl("[-+]?\\d+,\\d+", v, perl = TRUE)
    sep <- rep("espaco", length(idx))
    sep[tem_decimal_virg & !tem_ponto] <- "virgula_decimal_ou_separador"
    sep[tem_virg & tem_ponto] <- "virgula_separador_decimal_ponto"
    sep[tem_pipe] <- "pipe"
    sep[tem_pv] <- "ponto_e_virgula"
    sep_type[idx] <- sep

    ok <- which(lengths(nums) >= 2L)
    if (length(ok)) {
      out[idx[ok]] <- vapply(nums[ok], function(z) {
        z <- gsub(",", ".", z, fixed = TRUE)
        paste(z[seq_len(min(length(z), 4L))], collapse = " ")
      }, character(1L))
    }
  }
  attr(out, "coord_audit") <- data.table(separador_detectado = sep_type, n_tokens = token_count)
  out
}

monitora_io_extrair_zips_recursivos <- function(source_dirs, extract_dir) {
  if (dir.exists(extract_dir)) unlink(extract_dir, recursive = TRUE, force = TRUE)
  dir.create(extract_dir, recursive = TRUE, showWarnings = FALSE)
  seen <- character()
  repeat {
    zips <- unique(unlist(lapply(source_dirs, function(d) {
      if (!dir.exists(d)) character() else list.files(d, pattern = "\\.zip$", recursive = TRUE, full.names = TRUE, ignore.case = TRUE)
    })))
    zips <- zips[!grepl(paste0("^", normalizePath(extract_dir, winslash = "/", mustWork = FALSE)), normalizePath(zips, winslash = "/", mustWork = FALSE))]
    inner <- list.files(extract_dir, pattern = "\\.zip$", recursive = TRUE, full.names = TRUE, ignore.case = TRUE)
    zips <- unique(c(zips, inner))
    todo <- setdiff(normalizePath(zips, winslash = "/", mustWork = FALSE), seen)
    if (length(todo) == 0) break
    for (zf in todo) {
      dest <- file.path(extract_dir, tools::file_path_sans_ext(basename(zf)))
      dir.create(dest, recursive = TRUE, showWarnings = FALSE)
      ok <- tryCatch({ unzip(zf, exdir = dest); TRUE }, error = function(e) { monitora_log_registrar_evento("extracao_zip", "ERRO", zf, conditionMessage(e), "arquivo ignorado"); FALSE })
      if (ok) monitora_log_registrar_evento("extracao_zip", "INFO", zf, paste0("extraido em ", dest), "OK")
      seen <- c(seen, zf)
    }
  }
  invisible(seen)
}

# Identifica a cadeia de origem de cada CSV, incluindo ZIP externo e ZIP interno quando houver.
# Isso facilita a conferência operacional: o relatório mostra tanto o CSV interno quanto o ZIP
# baixado pelo usuário.
monitora_io_mapear_origem_arquivo <- function(paths, source_dirs = MONITORA_IO_DIRETORIOS_FONTE, extract_dir = MONITORA_EXTRACT_DIR) {
  paths_norm <- normalizePath(paths, winslash = "/", mustWork = FALSE)
  extract_norm <- normalizePath(extract_dir, winslash = "/", mustWork = FALSE)

  zip_sources <- unique(unlist(lapply(source_dirs, function(d) {
    if (!dir.exists(d)) character() else list.files(d, pattern = "\\.zip$", recursive = TRUE, full.names = TRUE, ignore.case = TRUE)
  })))
  zip_sources_norm <- normalizePath(zip_sources, winslash = "/", mustWork = FALSE)

 # Quando a origem é o diretório do script, list.files(..., recursive=TRUE)
 # também encontra ZIPs internos já extraídos em extracted/. Esses ZIPs internos não devem
 # ser tratados como "ZIP externo baixado pelo usuário". Mantê-los em zip_sources fazia
 # um ZIP interno aparecer como nome_zip_externo, em vez do pacote externo original
 # fornecido pelo usuário.
  if (length(zip_sources_norm) > 0) {
    bad_prefixes <- normalizePath(c(MONITORA_EXTRACT_DIR, MONITORA_OUTPUT_DIR, MONITORA_LOG_DIR), winslash = "/", mustWork = FALSE)
    keep <- rep(TRUE, length(zip_sources_norm))
    for (bp in bad_prefixes) {
      keep <- keep & !startsWith(zip_sources_norm, paste0(bp, "/")) & zip_sources_norm != bp
    }
    zip_sources_norm <- zip_sources_norm[keep]
  }

  zip_sources_base <- basename(zip_sources_norm)
  zip_sources_stem <- tools::file_path_sans_ext(zip_sources_base)

 # Indexa o conteúdo dos ZIPs externos originais.
 # Isso permite mapear um ZIP interno de coleta, como registros_j7n30yrt.zip,
 # de volta ao pacote baixado pelo usuário, mesmo que a extração recursiva
 # tenha colocado o CSV em extracted/registros_j7n30yrt/registros_*.csv.
  zip_index <- data.table::data.table(
    zip_externo = character(),
    nome_zip_externo = character(),
    item_zip = character(),
    nome_item_zip = character(),
    stem_item_zip = character()
  )
  if (length(zip_sources_norm) > 0) {
    for (zs in zip_sources_norm) {
      lst <- tryCatch(utils::unzip(zs, list = TRUE), error = function(e) NULL)
      if (!is.null(lst) && "Name" %in% names(lst) && nrow(lst) > 0) {
        zi <- data.table::data.table(
          zip_externo = zs,
          nome_zip_externo = basename(zs),
          item_zip = as.character(lst$Name),
          nome_item_zip = basename(as.character(lst$Name))
        )
        zi[, stem_item_zip := tools::file_path_sans_ext(nome_item_zip)]
        zip_index <- data.table::rbindlist(list(zip_index, zi), use.names = TRUE, fill = TRUE)
      }
    }
  }

 # ZIPs encontrados dentro da área extraída. Estes normalmente são ZIPs internos
 # de coleta, como registros_j7n30yrt.zip, contidos no pacote externo baixado.
  zip_extraidos <- if (dir.exists(extract_dir)) list.files(extract_dir, pattern = "\\.zip$", recursive = TRUE, full.names = TRUE, ignore.case = TRUE) else character()
  zip_extraidos_norm <- normalizePath(zip_extraidos, winslash = "/", mustWork = FALSE)
  zip_extraidos_base <- basename(zip_extraidos_norm)
  zip_extraidos_stem <- tools::file_path_sans_ext(zip_extraidos_base)

  top_zip_full_path <- function(nome_zip) {
    if (is.na(nome_zip) || !nzchar(nome_zip)) return(NA_character_)
    m <- which(zip_sources_base == nome_zip)
    if (length(m) > 0) return(zip_sources_norm[m[1]])
    NA_character_
  }

  external_from_inner_zip_name <- function(inner_zip_name) {
    if (is.na(inner_zip_name) || !nzchar(inner_zip_name) || nrow(zip_index) == 0) return(list(nome = NA_character_, arquivo = NA_character_))
    m <- zip_index[nome_item_zip == inner_zip_name]
    if (nrow(m) > 0) return(list(nome = m$nome_zip_externo[1], arquivo = m$zip_externo[1]))
    inner_stem <- tools::file_path_sans_ext(inner_zip_name)
    m <- zip_index[stem_item_zip == inner_stem]
    if (nrow(m) > 0) return(list(nome = m$nome_zip_externo[1], arquivo = m$zip_externo[1]))
    list(nome = NA_character_, arquivo = NA_character_)
  }

  external_from_rel_parts <- function(parts) {
    if (length(parts) < 1) return(list(nome = NA_character_, arquivo = NA_character_))

 # Caso 1: o primeiro componente do caminho extraído é o stem do pacote externo.
    cand_ext <- paste0(parts[1], ".zip")
    if (parts[1] %in% zip_sources_stem) {
      return(list(nome = cand_ext, arquivo = top_zip_full_path(cand_ext)))
    }

 # Caso 2: o primeiro componente é o stem do ZIP interno; procurar esse ZIP
 # dentro dos pacotes externos originais.
    cand_inner <- paste0(parts[1], ".zip")
    ext <- external_from_inner_zip_name(cand_inner)
    if (!is.na(ext$nome) && nzchar(ext$nome)) return(ext)

 # Caso 3: algum componente intermediário pode ser o stem do pacote externo.
    for (pp in parts) {
      cand <- paste0(pp, ".zip")
      if (pp %in% zip_sources_stem) {
        return(list(nome = cand, arquivo = top_zip_full_path(cand)))
      }
    }

    list(nome = NA_character_, arquivo = NA_character_)
  }

  inner_zip_from_rel_parts <- function(parts, nome_zip_externo = NA_character_) {
    if (length(parts) < 1) return(list(nome = NA_character_, arquivo = NA_character_))

 # Para CSVs extraídos de ZIP interno, o primeiro componente costuma ser
 # o stem do ZIP de coleta.
    cand_inner_name <- paste0(parts[1], ".zip")
    hits <- which(zip_extraidos_base == cand_inner_name | zip_extraidos_stem == parts[1])
    if (length(hits) > 0) {
      cand <- zip_extraidos_norm[hits]
      if (!is.na(nome_zip_externo) && nzchar(nome_zip_externo)) {
        top_stem <- tools::file_path_sans_ext(nome_zip_externo)
        preferred <- cand[grepl(paste0("/", top_stem, "/"), cand, fixed = TRUE)]
        if (length(preferred) > 0) cand <- preferred
      }
      return(list(nome = basename(cand[1]), arquivo = cand[1]))
    }

 # Se não houver o ZIP interno fisicamente no diretório extraído, mas ele
 # aparece indexado dentro do ZIP externo, ainda assim registrar o nome.
    ext <- external_from_inner_zip_name(cand_inner_name)
    if (!is.na(ext$nome) && nzchar(ext$nome)) {
      return(list(nome = cand_inner_name, arquivo = NA_character_))
    }

    list(nome = NA_character_, arquivo = NA_character_)
  }

  out <- data.table(
    arquivo = paths,
    arquivo_csv = paths_norm,
    nome_csv = basename(paths_norm),
    arquivo_entrada_externo = NA_character_,
    nome_arquivo_entrada_externo = NA_character_,
    arquivo_zip_externo = NA_character_,
    nome_zip_externo = NA_character_,
    arquivo_zip_interno = NA_character_,
    nome_zip_interno = NA_character_,
    caminho_relativo_extraido = NA_character_
  )

  for (i in seq_along(paths_norm)) {
    pn <- paths_norm[i]

    if (startsWith(pn, paste0(extract_norm, "/"))) {
      rel <- substring(pn, nchar(paste0(extract_norm, "/")) + 1)
      parts <- strsplit(rel, "/", fixed = TRUE)[[1]]
      out$caminho_relativo_extraido[i] <- rel

      ext <- external_from_rel_parts(parts)
      if (!is.na(ext$nome) && nzchar(ext$nome)) {
        out$nome_zip_externo[i] <- ext$nome
        out$arquivo_zip_externo[i] <- ext$arquivo
        out$nome_arquivo_entrada_externo[i] <- ext$nome
        out$arquivo_entrada_externo[i] <- ext$arquivo
      }

      inn <- inner_zip_from_rel_parts(parts, out$nome_zip_externo[i])
      if (!is.na(inn$nome) && nzchar(inn$nome)) {
 # Não registrar o pacote externo como ZIP interno quando o CSV está
 # diretamente no pacote externo, como no lote SISMONITORA.
        if (is.na(out$nome_zip_externo[i]) || !identical(inn$nome, out$nome_zip_externo[i])) {
          out$nome_zip_interno[i] <- inn$nome
          out$arquivo_zip_interno[i] <- inn$arquivo
        }
      }

      if ((is.na(out$arquivo_entrada_externo[i]) || !nzchar(out$arquivo_entrada_externo[i])) &&
          (!is.na(out$arquivo_zip_interno[i]) && nzchar(out$arquivo_zip_interno[i]))) {
        out$arquivo_entrada_externo[i] <- out$arquivo_zip_interno[i]
        out$nome_arquivo_entrada_externo[i] <- out$nome_zip_interno[i]
      }

    } else {
      out$arquivo_entrada_externo[i] <- pn
      out$nome_arquivo_entrada_externo[i] <- basename(pn)
      if (grepl("\\.zip$", pn, ignore.case = TRUE)) {
        out$arquivo_zip_externo[i] <- pn
        out$nome_zip_externo[i] <- basename(pn)
      }
    }
  }
  out[]
}

### ----------------------------------
### Modos registros_corrig_* e painel_incremental_* retomam de um produto
### corrigido já produzido pelo script. Essa entrada não reconstrói
### registros_importados.csv e não mistura correções antigas com a sessão atual.
if (!exists("monitora_auditoria_anos_invalidos", mode = "function", inherits = TRUE)) {
  monitora_auditoria_anos_invalidos <- function(dt) {
    dt <- monitora_dt_referenciar(dt)
    if (!("ANO" %in% names(dt))) return(invisible(data.table::data.table()))
    ano_num <- suppressWarnings(as.integer(dt[["ANO"]]))
    ano_min <- 2000L
    ano_max <- lubridate::year(Sys.Date()) + 1L
    invalido <- is.na(ano_num) | ano_num < ano_min | ano_num > ano_max
    if (!any(invalido, na.rm = TRUE)) return(invisible(data.table::data.table()))
    cols <- intersect(
      c("UC", "CICLO", "CAMPANHA", "UA", "COLETA", "Data (data_hora)", "DATA_MONITORA_PARSEADA", "ANO", "MONITORA_ARQUIVO_ENTRADA", "MONITORA_TIPO_ENTRADA"),
      names(dt)
    )
    aud <- unique(dt[invalido, ..cols])
    data.table::set(aud, j = "ano_min_plausivel", value = ano_min)
    data.table::set(aud, j = "ano_max_plausivel", value = ano_max)
    data.table::set(aud, j = "acao_recomendada", value = "Corrigir a data original ou verificar erro de parsing; registros com ANO inválido/NA não devem ser usados para gráficos ou estatísticas temporais sem validação.")
    saida <- file.path(MONITORA_LOG_DIR, paste0("auditoria_anos_invalidos_", MONITORA_EXEC_ID, ".csv"))
    monitora_fwrite(aud, saida)
    monitora_fwrite(aud, file.path(MONITORA_OUTPUT_DIR, "auditoria_anos_invalidos_ultima_execucao.csv"))
    monitora_log_registrar_evento("anos_invalidos", "AVISO", saida, paste0(nrow(aud), " combinações com ANO inválido/NA ou fora da faixa plausível"), "ver auditoria_anos_invalidos")
    invisible(aud)
  }
}
if (!exists("monitora_auditoria_completude_101_pontos", mode = "function", inherits = TRUE)) {
  monitora_auditoria_completude_101_pontos <- function(dt) {
    dt <- monitora_dt_referenciar(dt)
    ponto_col <- if ("ponto_amostral (amostragem/registro)" %in% names(dt)) {
      "ponto_amostral (amostragem/registro)"
    } else if ("ponto_metro (amostragem/registro)" %in% names(dt)) {
      "ponto_metro (amostragem/registro)"
    } else {
      NA_character_
    }
    required <- c("UC", "CICLO", "CAMPANHA", "UA", "ANO")
    if (is.na(ponto_col) || !all(required %in% names(dt))) return(invisible(data.table::data.table()))
    fonte_col <- if ("MONITORA_ARQUIVO_ENTRADA" %in% names(dt)) "MONITORA_ARQUIVO_ENTRADA" else NA_character_
    aux <- dt[, c(required, ponto_col, if (!is.na(fonte_col)) fonte_col else NULL), with = FALSE]
    data.table::setnames(aux, ponto_col, "ponto_original")
    data.table::set(aux, j = "ponto_num", value = suppressWarnings(as.integer(gsub("[^0-9]+", "", as.character(aux$ponto_original)))))
    by_cols <- required
    resumo <- aux[, .(
      n_registros = .N,
      n_pontos = data.table::uniqueN(ponto_num[!is.na(ponto_num)]),
      pontos_fora_1_101 = paste(sort(unique(ponto_num[!is.na(ponto_num) & !ponto_num %between% c(1L, 101L)])), collapse = " | "),
      arquivos_origem = if (!is.na(fonte_col)) paste(sort(unique(na.omit(as.character(get(fonte_col))))), collapse = " | ") else NA_character_
    ), by = by_cols]
    dup <- aux[!is.na(ponto_num), .N, by = c(by_cols, "ponto_num")][N > 1L]
    dup_sum <- dup[, .(pontos_duplicados = paste(sort(unique(ponto_num)), collapse = " | ")), by = by_cols]
    resumo <- merge(resumo, dup_sum, by = by_cols, all.x = TRUE, sort = FALSE)
    resumo[is.na(pontos_duplicados), pontos_duplicados := ""]
    resumo[, pontos_ausentes := ""]
    prob_idx <- which(resumo$n_pontos != 101L | resumo$n_registros != 101L | nzchar(resumo$pontos_duplicados) | nzchar(resumo$pontos_fora_1_101))
    if (length(prob_idx) > 0L) {
      chaves_prob <- resumo[prob_idx, ..by_cols]
      aux_prob <- merge(aux, chaves_prob, by = by_cols, all.y = TRUE, sort = FALSE)
      miss <- aux_prob[, .(
        pontos_ausentes = paste(setdiff(1:101, sort(unique(ponto_num[!is.na(ponto_num) & ponto_num %between% c(1L, 101L)]))), collapse = " | ")
      ), by = by_cols]
      resumo <- merge(resumo, miss, by = by_cols, all.x = TRUE, suffixes = c("", "_calc"), sort = FALSE)
      resumo[!is.na(pontos_ausentes_calc), pontos_ausentes := pontos_ausentes_calc]
      resumo[, pontos_ausentes_calc := NULL]
    }
    aud <- resumo[n_pontos != 101L | n_registros != 101L | nzchar(pontos_duplicados) | nzchar(pontos_ausentes) | nzchar(pontos_fora_1_101)]
    if (nrow(aud) > 0L) {
      data.table::set(aud, j = "acao_recomendada", value = "Conferir se a UA/ano possui exatamente 101 pontos; corrigir pontos ausentes, duplicados ou fora de 1:101 antes de aceitar análises e gráficos.")
      saida <- file.path(MONITORA_LOG_DIR, paste0("auditoria_completude_101_pontos_", MONITORA_EXEC_ID, ".csv"))
      monitora_fwrite(aud, saida)
      monitora_fwrite(aud, file.path(MONITORA_OUTPUT_DIR, "auditoria_completude_101_pontos_ultima_execucao.csv"))
      monitora_log_registrar_evento("completude_101_pontos", "AVISO", saida, paste0(nrow(aud), " grupos UC+CICLO+CAMPANHA+UA+ANO com n_registros/n_pontos diferente de 101, duplicidade ou lacuna"), "ver auditoria_completude_101_pontos")
    }
    invisible(aud)
  }
}

monitora_registros_corrig_entrada_arquivo <- function() {
  cand <- list.files(MONITORA_INPUT_DIR, pattern = "^registros_corrig.*\\.csv$", full.names = TRUE, ignore.case = TRUE)
  if (!length(cand)) {
    stop("Modo ", MONITORA_MODO_EXECUCAO, " solicitado, mas nenhum registros_corrig*.csv foi encontrado em input/. Copie output/registros_corrig.csv para input/ antes de rodar.", call. = FALSE)
  }
  if (length(cand) > 1L) {
    stop("Modo ", MONITORA_MODO_EXECUCAO, " exige exatamente um registros_corrig*.csv em input/. Foram encontrados: ", paste(basename(cand), collapse = ", "), call. = FALSE)
  }
  normalizePath(cand[1L], winslash = "/", mustWork = TRUE)
}

monitora_registros_corrig_carregar_entrada <- function(modo) {
  MONITORA_IO_DIRETORIOS_FONTE <<- MONITORA_INPUT_DIR
  arq <- monitora_registros_corrig_entrada_arquivo()
  dt <- monitora_registros_corrig_ler_csv_normalizado(arq, modo = modo)
  if (!("COLETA" %in% names(dt))) {
    stop("O arquivo ", basename(arq), " não possui coluna obrigatória COLETA. Use um registros_corrig.csv produzido pelo script.", call. = FALSE)
  }
  if (!("MONITORA_TIPO_ENTRADA" %in% names(dt))) data.table::set(dt, j = "MONITORA_TIPO_ENTRADA", value = "registros_corrig")
  if (!("MONITORA_ARQUIVO_ENTRADA" %in% names(dt))) data.table::set(dt, j = "MONITORA_ARQUIVO_ENTRADA", value = basename(arq))
  aud <- data.table::data.table(
    arquivo = arq,
    nome_arquivo = basename(arq),
    modo_execucao = modo,
    n_linhas = nrow(dt),
    n_colunas = ncol(dt),
    tamanho_bytes = as.numeric(file.info(arq)$size),
    status = "carregado_como_registros_corrig",
    observacao = "Entrada retomada a partir de registros_corrig.csv; registros_importados.csv não é reconstruído e correções antigas não são reaplicadas implicitamente."
  )
  monitora_fwrite(aud, file.path(MONITORA_LOG_DIR, paste0("auditoria_registros_corrig_entrada_", MONITORA_EXEC_ID, ".csv")), na = "")
  monitora_fwrite(aud, file.path(MONITORA_OUTPUT_DIR, "auditoria_registros_corrig_entrada_ultima_execucao.csv"), na = "")
  monitora_log_registrar_evento("registros_corrig_entrada", "INFO", arq, paste0("registros_corrig carregado com ", nrow(dt), " linhas e ", ncol(dt), " colunas"), "retomada por produto corrigido")
  if (exists("monitora_registros_importados_auditar_nao_aplicavel", mode = "function")) {
    monitora_registros_importados_auditar_nao_aplicavel(
      output_dir = MONITORA_OUTPUT_DIR,
      log_dir = MONITORA_LOG_DIR,
      exec_id = MONITORA_EXEC_ID,
      modo = modo,
      arquivo_entrada = arq
    )
  }
  monitora_publicacao_p_auditar_schema_pre_painel(dt, contexto = paste0("entrada_registros_corrig_", modo))
  dt[]
}

monitora_io_eh_csv_controle_correcao <- function(nome_arquivo) {
  bn <- tolower(basename(as.character(nome_arquivo)))
  grepl(
    paste0(
      "^(",
      "correcoes_semanticas",
      "|correcoes_campos",
      "|correcoes_espaciais",
      "|aplicacoes_correcoes",
      "|resumo_linhagem",
      "|modelo_correcoes_campos",
      "|auditoria_reaplicacao",
      "|auditoria_correcoes_campos",
      ")",
      "([_.].*)?\\.csv$"
    ),
    bn,
    perl = TRUE
  )
}

monitora_io_ler_metadados_csv <- function(path) {
  dt0 <- tryCatch(fread(path, nrows = 1, colClasses = "character", encoding = "UTF-8", na.strings = c("", "NA", "N/A", "NULL"), showProgress = FALSE), error = function(e) NULL)
  if (is.null(dt0) || nrow(dt0) == 0) {
    return(data.table(UC = NA_character_, CICLO = NA_character_, CAMPANHA = NA_character_, UA = NA_character_, COLETA = NA_character_, n_linhas = NA_integer_))
  }
  pega <- function(cands) {
    nm <- cands[cands %in% names(dt0)][1]
    if (is.na(nm) || length(nm) == 0) NA_character_ else as.character(dt0[[nm]][1])
  }
  data.table(
    UC = pega(c("UC", "uc", "uc...5", "uc...17")),
    CICLO = pega(c("CICLO", "ciclo")),
    CAMPANHA = pega(c("CAMPANHA", "campanha")),
    UA = pega(c("UA", "ua")),
    COLETA = pega(c("COLETA", "coleta")),
    n_linhas = tryCatch(nrow(fread(path, select = 1, colClasses = "character", encoding = "UTF-8", showProgress = FALSE)), error = function(e) NA_integer_)
  )
}

monitora_io_descarregar_lote_csv <- function(force = FALSE) {
  if (length(batch_lista) == 0) return(invisible(FALSE))
  if (!force && length(batch_lista) < monitora_recurso_batch_size_csv()) return(invisible(FALSE))
  batch_id <<- batch_id + 1L
  monitora_recurso_controlar(paste0("leitura_csv_batch_", batch_id, "_pre_rbind"), risco = if (length(batch_lista) >= 50) "alto" else "normal", force_log = TRUE)
  registros_batches[[batch_id]] <<- data.table::rbindlist(batch_lista, fill = TRUE, use.names = TRUE)
  batch_lista <<- list()
  monitora_recurso_controlar(paste0("leitura_csv_batch_", batch_id, "_pos_rbind"), risco = "normal", objeto = registros_batches[[batch_id]], force_log = TRUE)
  monitora_recurso_gc(paste0("leitura_csv_batch_", batch_id))
  invisible(TRUE)
}

monitora_produtos_nome_central <- function(produto) {
  bn <- basename(as.character(produto)[1L])
  bn %in% c(
    "registros_importados_bruto.csv", "registros_importados.csv",
    "registros_importados_operacional_pre_painel.csv",
    "registros_corrig.csv", "registros_validados.csv", "registros_corrig_stat.csv"
  )
}

monitora_produtos_path_canonico <- function(produto,
                                            output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE)) {
  produto <- basename(as.character(produto)[1L])
  file.path(output_dir, "01_produtos_dados", produto)
}

monitora_produtos_path_raiz <- function(produto,
                                        output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE)) {
  file.path(output_dir, basename(as.character(produto)[1L]))
}

monitora_produtos_md5_seguro <- function(path) {
  if (!length(path) || is.na(path[1L]) || !file.exists(path[1L]) || isTRUE(file.info(path[1L])$isdir)) return(NA_character_)
  unname(as.character(tools::md5sum(path[1L])))
}

monitora_produtos_auditar_espelhos_canonicos <- function(output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                         exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                                         contexto = "auditoria_produtos_canonicos") {
  produtos <- c("registros_importados_bruto.csv", "registros_importados.csv", "registros_importados_operacional_pre_painel.csv", "registros_corrig.csv", "registros_validados.csv", "registros_corrig_stat.csv")
  aud <- data.table::rbindlist(lapply(produtos, function(produto) {
    canon <- monitora_produtos_path_canonico(produto, output_dir)
    raiz <- monitora_produtos_path_raiz(produto, output_dir)
    md5_canon <- monitora_produtos_md5_seguro(canon)
    md5_raiz <- monitora_produtos_md5_seguro(raiz)
    data.table::data.table(
      exec_id = as.character(exec_id), contexto = as.character(contexto)[1L], produto = produto,
      caminho_canonico = gsub("\\\\", "/", file.path("01_produtos_dados", produto)),
      existe_canonico = file.exists(canon), md5_canonico = md5_canon,
      caminho_raiz_compat = produto, existe_raiz_compat = file.exists(raiz), md5_raiz_compat = md5_raiz,
      espelho_identico = !is.na(md5_canon) && !is.na(md5_raiz) && identical(md5_canon, md5_raiz),
      timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    )
  }), fill = TRUE)
  dir.create(file.path(output_dir, "03_auditorias", "importacao"), recursive = TRUE, showWarnings = FALSE)
  try(data.table::fwrite(aud, file.path(output_dir, "03_auditorias", "importacao", "auditoria_produtos_canonicos_md5.csv"), na = ""), silent = TRUE)
  invisible(aud)
}

monitora_produtos_copiar_canonico_para_raiz <- function(produto,
                                                        output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                        exigir_identico = TRUE) {
  produto <- basename(as.character(produto)[1L])
  canon <- monitora_produtos_path_canonico(produto, output_dir)
  raiz <- monitora_produtos_path_raiz(produto, output_dir)
  if (!file.exists(canon)) return(invisible(FALSE))
  dir.create(dirname(raiz), recursive = TRUE, showWarnings = FALSE)
  ok <- file.copy(canon, raiz, overwrite = TRUE, copy.date = TRUE)
  if (!isTRUE(ok)) stop("Falha ao copiar produto canônico para raiz de compatibilidade: ", produto, call. = FALSE)
  if (isTRUE(exigir_identico)) {
    md5_canon <- monitora_produtos_md5_seguro(canon)
    md5_raiz <- monitora_produtos_md5_seguro(raiz)
    if (is.na(md5_canon) || is.na(md5_raiz) || !identical(md5_canon, md5_raiz)) {
      stop("Espelho raiz/canônico divergiu após cópia: ", produto, call. = FALSE)
    }
  }
  invisible(TRUE)
}

monitora_produtos_escrever_csv_canonico <- function(dt,
                                                    produto,
                                                    output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                    row.names = FALSE,
                                                    na = "",
                                                    ...) {
  produto <- basename(as.character(produto)[1L])
  canon <- monitora_produtos_path_canonico(produto, output_dir)
  dir.create(dirname(canon), recursive = TRUE, showWarnings = FALSE)
  monitora_fwrite(dt, canon, row.names = row.names, na = na, encoding = "UTF-8", bom = TRUE, eol = "\n", ...)
  monitora_produtos_copiar_canonico_para_raiz(produto, output_dir = output_dir, exigir_identico = TRUE)
  invisible(canon)
}

monitora_produtos_escrever_bruto_canonico <- function(dt,
                                                      produto = "registros_importados_bruto.csv",
                                                      output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                      row.names = FALSE,
                                                      ...) {
  produto <- basename(as.character(produto)[1L])
  canon <- monitora_produtos_path_canonico(produto, output_dir)
  dir.create(dirname(canon), recursive = TRUE, showWarnings = FALSE)
  escrita <- monitora_publicacao_h_fwrite_registros_importados(dt, canon, row.names = row.names, encoding = "UTF-8", bom = TRUE, eol = "\n", ...)
  monitora_produtos_copiar_canonico_para_raiz(produto, output_dir = output_dir, exigir_identico = TRUE)
  escrita
}

monitora_pipe_aliases_campos_conhecidos <- function() {
  data.table::data.table(
    alias_coluna = c(
      "impact_manejo_uso/tipos_impacto_manejo_uso_outro",
      "tipos_impacto_manejo_uso_outro",
      "Espécie ou nome popular (Liana nativa) (amostragem/registro)"
    ),
    nome_canonico = c(
      "tipos_impacto_manejo_uso_outro",
      "tipos_impacto_manejo_uso_outro",
      "forma_vida_nativa_lianas"
    ),
    motivo = c(
      "Path real do template usa o grupo impact_manejo_uso/; dump XLSForm embutido registra amostragem/registro/ para este campo folha; tipo_base=text confirmado sem ambiguidade nas 4 versões embutidas.",
      "Mesma causa, cobrindo a variante já reduzida ao nome curto isolado.",
      "Dump embutido (versão 21FEV25) traz o rótulo sem o sufixo de grupo '(amostragem/registro)' presente no cabeçalho real do produto; tipo_base=text confirmado sem ambiguidade nas 4 versões embutidas; mesma associação já usada por monitora_validados_aliases_adicionais()."
    )
  )
}

monitora_pipe_decidir_natureza_candidatos <- function(cand) {
  if (is.null(cand) || !nrow(cand)) return(NA_character_)
  tipos <- unique(tolower(trimws(as.character(cand$tipo_base))))
  tipos <- tipos[!is.na(tipos) & nzchar(tipos)]
  if (!length(tipos)) return(NA_character_)
  eh_texto <- "text" %in% tipos
  eh_estruturado <- any(tipos %in% c("select_multiple", "select_one"))
  if (eh_texto && eh_estruturado) return("ambiguo")
  if (eh_texto) return("pipe_permitido_texto_livre")
  if (eh_estruturado) return("pipe_residual_estruturado_elegivel")
  NA_character_
}

monitora_pipe_coluna_classificar_natureza <- function(coluna) {
  meta <- tryCatch(monitora_correcao_xlsforms_embutidos_cache_publicacao_ae(), error = function(e) NULL)
  if (is.null(meta) || is.null(meta$campos) || !is.data.frame(meta$campos) || !nrow(meta$campos)) return("pipe_indeterminado")
  campos <- data.table::as.data.table(meta$campos)
  cols_norm <- c("name_norm_publicacao_ae", "caminho_norm_publicacao_ae", "label_norm_publicacao_ae")
  if (!all(cols_norm %in% names(campos))) return("pipe_indeterminado")

  coluna_chr <- as.character(coluna)[1L]
  alvo <- tryCatch(monitora_correcao_normalizar_nome_coluna(coluna_chr), error = function(e) NA_character_)
  if (is.na(alvo) || !nzchar(alvo)) return("pipe_indeterminado")
  segmento_final <- sub(".*/", "", coluna_chr)
  alvo_curto <- tryCatch(monitora_correcao_normalizar_nome_coluna(segmento_final), error = function(e) NA_character_)
  if (is.na(alvo_curto)) alvo_curto <- ""

 ### 1) Path canônico completo.
  res <- monitora_pipe_decidir_natureza_candidatos(campos[caminho_norm_publicacao_ae == alvo])
  if (identical(res, "ambiguo")) return("pipe_ambiguo")
  if (!is.na(res)) return(res)

 ### 2) Alias explícito auditado (tabela pequena, documentada acima).
  aliases <- monitora_pipe_aliases_campos_conhecidos()
  alias_norm <- monitora_correcao_normalizar_nome_coluna(aliases$alias_coluna)
  alias_hit <- aliases[alias_norm == alvo | (nzchar(alvo_curto) & alias_norm == alvo_curto)]
  if (nrow(alias_hit)) {
    nome_canon <- monitora_correcao_normalizar_nome_coluna(alias_hit$nome_canonico[1L])
    res <- monitora_pipe_decidir_natureza_candidatos(campos[name_norm_publicacao_ae == nome_canon])
    if (identical(res, "ambiguo")) return("pipe_ambiguo")
    if (!is.na(res)) return(res)
  }

 ### 3) Nome curto exato (último segmento do path).
  if (nzchar(alvo_curto)) {
    res <- monitora_pipe_decidir_natureza_candidatos(campos[name_norm_publicacao_ae == alvo_curto])
    if (identical(res, "ambiguo")) return("pipe_ambiguo")
    if (!is.na(res)) return(res)
  }

 ### 4) Label exato.
  res <- monitora_pipe_decidir_natureza_candidatos(campos[label_norm_publicacao_ae == alvo])
  if (identical(res, "ambiguo")) return("pipe_ambiguo")
  if (!is.na(res)) return(res)

  "pipe_indeterminado"
}

monitora_produtos_classificar_pipe_coluna <- function(coluna, produto = "") {
  cc <- tolower(as.character(coluna))
  prod <- tolower(as.character(produto)[1L])
  if (grepl("bruto", prod)) return("pipe_esperado_em_bruto")
  if (grepl("foto|imagem|image|media|arquivo_midias|anexo", cc)) return("pipe_residual_tecnico_tolerado")
  if (grepl("^(monitora_|arquivo_|origem_|hash_|md5|tipo_entrada|\\.id$)", cc)) return("pipe_residual_tecnico_tolerado")
  natureza <- tryCatch(monitora_pipe_coluna_classificar_natureza(coluna), error = function(e) "pipe_indeterminado")
  if (identical(natureza, "pipe_permitido_texto_livre")) return("pipe_permitido_texto_livre")
 ### - ajuste: ambiguidade confirmada pelo contrato (mesmo
 ### path/nome/label resolve para texto E estruturado em versões diferentes
 ### do XLSForm embutido) tem prioridade sobre o padrão de nome legado
 ### abaixo -- nunca deixar o regex "forçar" uma classificação estruturada
 ### sobre um campo que o próprio contrato não consegue decidir sozinho.
  if (identical(natureza, "pipe_ambiguo")) return("pipe_indeterminado")
  if (grepl("ponto|encostam|forma.*vida|especie|uuid|habito|observacao", cc)) return("pipe_residual_operacional")
  if (identical(natureza, "pipe_residual_estruturado_elegivel")) return("pipe_residual_revisar")
  "pipe_indeterminado"
}

monitora_contrato_unico_labels_sem_html <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  x <- gsub("<[^>]+>", "", x, perl = TRUE)
  x <- gsub("&quot;", "", x, fixed = TRUE)
  x <- gsub("\\s+", " ", x, perl = TRUE)
  trimws(x)
}

monitora_contrato_unico_cardinalidade_operacional <- function(tipo_base, relevant, ambiguo = FALSE) {
  n <- max(length(tipo_base), length(relevant), length(ambiguo))
  tipo_base <- tolower(trimws(as.character(rep_len(tipo_base, n))))
  relevant <- as.character(rep_len(relevant, n))
  ambiguo <- as.logical(rep_len(ambiguo, n))
  ambiguo[is.na(ambiguo)] <- FALSE
  tem_relevant <- !is.na(relevant) & nzchar(trimws(relevant))
  tecnico <- tipo_base %in% c(
    "image", "hidden", "start", "deviceid", "phonenumber", "note",
    "begin_group", "end_group", "begin", "end", "calculate", "uuid"
  )
  out <- rep(NA_character_, n)
  out[tecnico] <- "tecnico_midia"
 ### Tipos escalares de coleta são editáveis e validados pelo contrato; não
 ### são mídia nem ambiguidade. O escopo é derivado depois pelo perfil.
  out[is.na(out) & tipo_base %in% c("date", "time", "geopoint")] <- "estruturado_coleta"
  out[is.na(out) & tipo_base == "text"] <- "texto_livre"
  out[is.na(out) & tipo_base == "select_multiple"] <- "select_multiple"
  eh_select_one <- is.na(out) & tipo_base == "select_one"
  out[eh_select_one & tem_relevant] <- "estruturado_condicional_esparso"
  out[eh_select_one & !tem_relevant] <- "estruturado_completo_por_ponto"
  out[is.na(out)] <- "ambiguo_indeterminado"
  out[ambiguo] <- "ambiguo_indeterminado"
  out
}

monitora_contrato_unico_embutido <- function() {
  meta <- tryCatch(monitora_correcao_xlsforms_embutidos_cache_publicacao_ae(), error = function(e) NULL)
  if (is.null(meta) || is.null(meta$campos) || !is.data.frame(meta$campos) || !nrow(meta$campos)) {
    meta <- if (exists("monitora_correcao_xlsforms_embutidos", mode = "function")) {
      monitora_correcao_xlsforms_embutidos()
    } else {
      list(campos = data.table::data.table(), opcoes = data.table::data.table(),
           dependencias = data.table::data.table(), arquivos = data.table::data.table())
    }
  }
  campos <- data.table::copy(data.table::as.data.table(meta$campos))
  opcoes <- data.table::copy(if (!is.null(meta$opcoes)) data.table::as.data.table(meta$opcoes) else data.table::data.table())
  dependencias_xls <- data.table::copy(if (!is.null(meta$dependencias)) data.table::as.data.table(meta$dependencias) else data.table::data.table())

  for (cc in c("arquivo_xlsform", "name", "caminho_registro", "type", "tipo_base", "list_name", "label", "relevant", "required",
               "caminho_norm_publicacao_ae", "name_norm_publicacao_ae", "label_norm_publicacao_ae", "arquivo_21fev25_publicacao_ae")) {
    if (!(cc %in% names(campos))) campos[, (cc) := NA_character_]
  }
  campos[, caminho_registro := as.character(caminho_registro)]
  campos[, name := as.character(name)]
  campos[, caminho_norm_publicacao_ae := as.character(caminho_norm_publicacao_ae)]
  campos[, name_norm_publicacao_ae := as.character(name_norm_publicacao_ae)]
  campos[is.na(caminho_norm_publicacao_ae), caminho_norm_publicacao_ae := ""]
  campos[is.na(name_norm_publicacao_ae), name_norm_publicacao_ae := ""]

  dependencias <- if (exists("monitora_correcao_unificar_dependencias", mode = "function")) {
    tryCatch(monitora_correcao_unificar_dependencias(dependencias_xls), error = function(e) dependencias_xls)
  } else {
    dependencias_xls
  }

 ### Ambiguidade entre versões embutidas (mesma regra usada por
 ### monitora_pipe_decidir_natureza_candidatos): mesmo caminho com tipo_base
 ### de natureza diferente (texto vs. estruturado) em alguma outra versão.
 ### confirmado por auditoria (caso dourado forma_vida_
 ### nativa_cactacea/forma_vida_nativa_samambaia) que, em pelo menos uma
 ### versão histórica do XLSForm embutido, o campo de ESPÉCIE/nome popular
 ### ("Espécie ou nome popular (Cactácea)"/"(Samambaia)", tipo text) reusa o
 ### mesmo caminho_registro normalizado do campo de HÁBITO (select_one) --
 ### uma colisão real do schema histórico bruto, não um bug de resolução.
 ### Mas essa colisão é exatamente com o conceito que o próprio contrato já
 ### distingue em outro lugar como atributo "_sp" (espécie), usando o MESMO
 ### padrão de regex já usado para essa finalidade em monitora_correcao_
 ### resolver_coluna_habito (eh_especie). Sem esta exclusão, QUALQUER
 ### atributo de hábito cujo campo de espécie histórico tenha colidido de
 ### caminho com o campo estruturado era marcado ambiguo_indeterminado e
 ### ficava fora do perfil_painel_edicao (não editável) -- mesmo quando a
 ### importação já separa essas duas colunas fisicamente em registros_corrig
 ### (confirmado: "forma_vida_nativa_cactacea" e "Espécie ou nome popular
 ### (Cactácea) (amostragem/registro)" são colunas distintas nos dados
 ### reais). Não é lista nova: reaproveita só o padrão de regex já existente
 ### para "isto é um campo de espécie", aplicado à mesma tabela de campos já
 ### calculada aqui.
  eh_campo_especie_regex <- "especie|esp[eé]cie|nome popular|_sp($|_)|outra esp[eé]cie"
  amb <- campos[nzchar(caminho_norm_publicacao_ae), .(
    eh_texto = any(tolower(tipo_base) == "text" & !grepl(eh_campo_especie_regex, label, ignore.case = TRUE)),
    eh_estruturado = any(tolower(tipo_base) %in% c("select_one", "select_multiple"))
  ), by = caminho_norm_publicacao_ae]
  amb[, ambiguo_entre_versoes := eh_texto & eh_estruturado]

  hist <- campos[arquivo_21fev25_publicacao_ae != TRUE & nzchar(caminho_norm_publicacao_ae) & nzchar(label),
                 .(labels_historicos_com_html = paste(unique(label), collapse = " | ")),
                 by = caminho_norm_publicacao_ae]

  campos25 <- campos[arquivo_21fev25_publicacao_ae == TRUE & nzchar(caminho_registro)]
  campos25 <- unique(campos25, by = "caminho_norm_publicacao_ae")
  campos25 <- merge(campos25, amb[, .(caminho_norm_publicacao_ae, ambiguo_entre_versoes)], by = "caminho_norm_publicacao_ae", all.x = TRUE)
  campos25[is.na(ambiguo_entre_versoes), ambiguo_entre_versoes := FALSE]
  campos25 <- merge(campos25, hist, by = "caminho_norm_publicacao_ae", all.x = TRUE)
  campos25[, labels_historicos_com_html := data.table::fifelse(is.na(labels_historicos_com_html), "", labels_historicos_com_html)]
  campos25[, labels_historicos_sem_html := monitora_contrato_unico_labels_sem_html(labels_historicos_com_html)]
  campos25[, label_2025_sem_html := monitora_contrato_unico_labels_sem_html(label)]

 ### Schema hardcoded de 129 atributos (registros_validados) -- junção por
 ### caminho completo primeiro (estratégia mais forte, 91/113 casos na
 ### Auditoria ), name curto como reforço só para quem ainda não bateu.
  schema129 <- tryCatch(monitora_fonte_template_sismonitora_129_embutida(), error = function(e) data.table::data.table())
  schema129 <- data.table::copy(data.table::as.data.table(schema129))
  if (nrow(schema129)) {
    schema129[, atributo_norm := monitora_correcao_normalizar_nome_coluna(atributo)]
    schema129[, atributo_curto_norm := monitora_correcao_normalizar_nome_coluna(sub("^.*/", "", atributo))]
  }

  campos25[, `:=`(posicao_schema129 = NA_integer_, nivel_schema129 = NA_character_,
                   formato_schema129 = NA_character_, largura_schema129 = NA_integer_,
                   obrigatorio_valor_schema129 = NA, origem_schema129 = NA_character_,
                   atributo_schema129 = NA_character_)]
  if (nrow(schema129)) {
    m1 <- match(campos25$caminho_norm_publicacao_ae, schema129$atributo_norm)
    ok1 <- !is.na(m1)
    if (any(ok1)) {
      campos25[ok1, `:=`(posicao_schema129 = schema129$posicao[m1[ok1]],
                          nivel_schema129 = schema129$nivel[m1[ok1]],
                          formato_schema129 = schema129$formato[m1[ok1]],
                          largura_schema129 = schema129$largura[m1[ok1]],
                          obrigatorio_valor_schema129 = schema129$obrigatorio_valor[m1[ok1]],
                          origem_schema129 = "caminho_completo",
                          atributo_schema129 = schema129$atributo[m1[ok1]])]
    }
    faltam <- is.na(campos25$origem_schema129)
    if (any(faltam)) {
      m2 <- match(campos25$name_norm_publicacao_ae[faltam], schema129$atributo_curto_norm)
      ok2 <- !is.na(m2)
      if (any(ok2)) {
        idx <- which(faltam)[ok2]
        campos25[idx, `:=`(posicao_schema129 = schema129$posicao[m2[ok2]],
                            nivel_schema129 = schema129$nivel[m2[ok2]],
                            formato_schema129 = schema129$formato[m2[ok2]],
                            largura_schema129 = schema129$largura[m2[ok2]],
                            obrigatorio_valor_schema129 = schema129$obrigatorio_valor[m2[ok2]],
                            origem_schema129 = "name_curto",
                            atributo_schema129 = schema129$atributo[m2[ok2]])]
      }
    }

 ### Caso especial ea/ua (Requisito ): as posições 'ea'/'ua' do
 ### schema de 129 não têm campo XLSForm com esse `name` curto -- o campo
 ### real é estacao_amostral/unidade_amostral (mesmo alias já correto em
 ### monitora_esp_colunas_chave , consolidado como alias explícito mais
 ### abaixo). Em vez de deixar essas 2 posições caírem no fallback de
 ### "metadado de pipeline" (o que criaria um atributo canônico artificial
 ### chamado literalmente "ea"/"ua", nunca consultado pelo alias), a
 ### posição do schema é anexada diretamente no atributo XLSForm real,
 ### preservando a cobertura de 1:129 sem duplicar nem inventar atributo.
    for (par_ea_ua in list(c("ea", "estacao_amostral"), c("ua", "unidade_amostral"))) {
      pos_schema_ea_ua <- schema129[tolower(trimws(atributo)) == par_ea_ua[1]]
      if (nrow(pos_schema_ea_ua) == 1L) {
        alvo_idx_ea_ua <- which(campos25$name_norm_publicacao_ae == monitora_correcao_normalizar_nome_coluna(par_ea_ua[2]) & is.na(campos25$origem_schema129))
        if (length(alvo_idx_ea_ua) == 1L) {
          campos25[alvo_idx_ea_ua, `:=`(
            posicao_schema129 = pos_schema_ea_ua$posicao[1],
            nivel_schema129 = pos_schema_ea_ua$nivel[1],
            formato_schema129 = pos_schema_ea_ua$formato[1],
            largura_schema129 = pos_schema_ea_ua$largura[1],
            obrigatorio_valor_schema129 = pos_schema_ea_ua$obrigatorio_valor[1],
            origem_schema129 = "alias_035h3",
            atributo_schema129 = pos_schema_ea_ua$atributo[1]
          )]
        }
      }
    }
  }

  campos25[, cardinalidade_operacional := monitora_contrato_unico_cardinalidade_operacional(tipo_base, relevant, ambiguo_entre_versoes)]

 ### Campo pai: prioriza parent_name já resolvido em dependencias (inclui a
 ### regra padrão de 4 formas condicionais); cai para o path sem o último
 ### segmento quando não há dependência explícita.
  campos25[, campo_pai := NA_character_]
  if (nrow(dependencias) && all(c("dependent_name", "parent_name") %in% names(dependencias))) {
    mapa_pai <- unique(dependencias[nzchar(as.character(dependent_name)), .(dependent_name = as.character(dependent_name), parent_name = as.character(parent_name))])
    mapa_pai <- mapa_pai[!duplicated(dependent_name)]
    m3 <- match(campos25$name, mapa_pai$dependent_name)
    ok3 <- !is.na(m3)
    if (any(ok3)) campos25[ok3, campo_pai := mapa_pai$parent_name[m3[ok3]]]
  }
  campos25[is.na(campo_pai) & grepl("/", caminho_registro), campo_pai := sub("/[^/]+$", "", caminho_registro)]

  campos25[, status_confianca := "media_sem_schema129"]
  campos25[origem_schema129 == "caminho_completo", status_confianca := "alta"]
  campos25[origem_schema129 == "name_curto", status_confianca := "media"]
  campos25[origem_schema129 == "alias_035h3", status_confianca := "alta"]
  campos25[ambiguo_entre_versoes == TRUE, status_confianca := "baixa_ambiguo"]

  campos25[, origem_regra := data.table::fifelse(
    is.na(origem_schema129),
    "xlsform_embutido_21FEV25",
    paste0("xlsform_embutido_21FEV25+schema_129_", origem_schema129)
  )]

 ### Aliases explícitos: pipe, validados (histórico+adicionais), cópia de
 ### referência da consolidação de colunas, e o par ea/ua .
  alias_pipe <- tryCatch(monitora_pipe_aliases_campos_conhecidos(), error = function(e) data.table::data.table())
  alias_validados <- tryCatch(monitora_validados_aliases(), error = function(e) list())
  alias_consolidacao_colunas_ref <- list(
    "COLETA" = c("coleta", "id_coleta", "id coleta", "codigo coleta", "código coleta", "amostragem/coleta"),
    "UC" = c("uc", "unidade de conservacao", "unidade de conservação"),
    "UA" = c("ua", "unidade amostral", "amostragem/unidade_amostral"),
    "CICLO" = c("ciclo", "ano ciclo", "ano_ciclo"),
    "CAMPANHA" = c("campanha"),
    "PROTOCOLO" = c("protocolo", "formulario", "formulário"),
    "UUID" = c("uuid", "registro uuid", "registro_uuid"),
    "coleta_uuid" = c("coleta uuid", "coleta_uuid", "uuid_coleta", "amostragem/uuid"),
    "Data (data_hora)" = c("data (data_hora)", "data_hora/data", "amostragem/registro/data", "data"),
    "Horário (data_hora)" = c("horario (data_hora)", "horário (data_hora)", "data_hora/hora", "amostragem/registro/hora", "hora"),
    "Coordenada inicial da amostragem (amostragem)" = c("coordenada inicial da amostragem (amostragem)", "amostragem/ponto_inicio_transecto", "ponto inicio transecto", "ponto_inicio_transecto"),
    "Coordenada final da amostragem (amostragem)" = c("coordenada final da amostragem (amostragem)", "amostragem/ponto_fim_transecto", "ponto fim transecto", "ponto_fim_transecto"),
    "ponto_amostral (amostragem/registro)" = c("ponto_amostral (amostragem/registro)", "amostragem/registro/ponto_amostral", "ponto_amostral"),
    "ponto_metro (amostragem/registro)" = c("ponto_metro (amostragem/registro)", "amostragem/registro/ponto_metro", "ponto_metro"),
    "uuid (amostragem/registro)" = c("uuid (amostragem/registro)", "amostragem/registro/uuid")
  )

  aliases_lista <- list()
  add_alias_row <- function(caminho, alias, origem) {
    if (is.na(caminho) || !nzchar(caminho) || is.na(alias) || !nzchar(as.character(alias))) return(invisible(NULL))
    aliases_lista[[length(aliases_lista) + 1L]] <<- data.table::data.table(
      caminho_registro = caminho, alias = as.character(alias), origem_alias = origem
    )
  }
  primeiro_caminho_por_norm <- function(alvo_norm) {
    hit <- campos25[caminho_norm_publicacao_ae == alvo_norm | name_norm_publicacao_ae == alvo_norm]
    if (nrow(hit)) hit$caminho_registro[1] else NA_character_
  }

  if (nrow(alias_pipe)) {
    for (i in seq_len(nrow(alias_pipe))) {
      alvo <- primeiro_caminho_por_norm(monitora_correcao_normalizar_nome_coluna(alias_pipe$nome_canonico[i]))
      if (!is.na(alvo)) add_alias_row(alvo, alias_pipe$alias_coluna[i], "pipe_aliases_campos_conhecidos")
    }
  }
  if (length(alias_validados)) {
    for (chave in names(alias_validados)) {
      alvo <- primeiro_caminho_por_norm(monitora_correcao_normalizar_nome_coluna(chave))
      if (!is.na(alvo)) {
        for (al in alias_validados[[chave]]) add_alias_row(alvo, al, "validados_aliases")
      }
    }
  }
  for (chave in names(alias_consolidacao_colunas_ref)) {
    alvo <- primeiro_caminho_por_norm(monitora_correcao_normalizar_nome_coluna(chave))
    if (!is.na(alvo)) {
      for (al in alias_consolidacao_colunas_ref[[chave]]) add_alias_row(alvo, al, "dt_consolidar_aliases_colunas_ref")
    }
  }

 ### Requisito obrigatório: ea<->estacao_amostral, ua<->unidade_amostral,
 ### com o mesmo conteúdo já correto em monitora_esp_colunas_chave
 ### (L15191-15192) -- registrado aqui só como alias explícito, NÃO
 ### conectado a monitora_correcao_colunas_chave nem a nenhum outro
 ### consumidor.
  alvo_ea <- primeiro_caminho_por_norm(monitora_correcao_normalizar_nome_coluna("estacao_amostral"))
  if (!is.na(alvo_ea)) {
    add_alias_row(alvo_ea, "ea", "requisito_035h3")
    add_alias_row(alvo_ea, "EA", "requisito_035h3")
  }
  alvo_ua <- primeiro_caminho_por_norm(monitora_correcao_normalizar_nome_coluna("unidade_amostral"))
  if (!is.na(alvo_ua)) {
    add_alias_row(alvo_ua, "ua", "requisito_035h3")
    add_alias_row(alvo_ua, "UA", "requisito_035h3")
  }

  aliases <- if (length(aliases_lista)) {
    unique(data.table::rbindlist(aliases_lista))
  } else {
    data.table::data.table(caminho_registro = character(), alias = character(), origem_alias = character())
  }

  atributos <- campos25[, .(
    atributo_canonico_2025 = caminho_registro,
    caminho_registro,
    name_curto = name,
    label_2025_com_html = label,
    label_2025_sem_html,
    labels_historicos_com_html,
    labels_historicos_sem_html,
    type_xlsform = type,
    tipo_base,
    list_name,
    required,
    relevant,
    campo_pai,
    nivel_schema129,
    formato_schema129,
    largura_schema129,
    obrigatorio_valor_schema129,
    posicao_schema129,
    atributo_schema129,
    cardinalidade_operacional,
    ambiguo_entre_versoes,
    status_confianca,
    origem_regra
  )]

 ### Atributos de metadado de pipeline do schema de 129 sem correspondência
 ### em nenhuma versão embutida do XLSForm (Auditoria, seção 5):
 ### existem em registros_validados.csv mas nunca foram pergunta de
 ### formulário. Integram o contrato como metadado_pipeline, preservando
 ### sua origem e sem inventar uma pergunta XLSForm. Usa a posição já
 ### efetivamente atribuída em campos25 (não só a existência do nome em
 ### algum lugar do dump) para não perder posições como 129 ("uuid" de
 ### coleta), cujo único campo XLSForm com esse `name` curto
 ### ("amostragem/registro/uuid") já foi reivindicado pela posição 126.
  if (nrow(schema129)) {
    sem_correspondencia <- !(schema129$posicao %in% campos25$posicao_schema129)
    metadado_pipeline <- schema129[sem_correspondencia]
    if (nrow(metadado_pipeline)) {
      extra <- metadado_pipeline[, .(
        atributo_canonico_2025 = atributo,
        caminho_registro = NA_character_,
        name_curto = atributo,
        label_2025_com_html = NA_character_,
        label_2025_sem_html = NA_character_,
        labels_historicos_com_html = "",
        labels_historicos_sem_html = "",
        type_xlsform = NA_character_,
        tipo_base = data.table::fcase(
          tolower(formato) %in% c("date", "data"), "date",
          tolower(formato) %in% c("time", "hora"), "time",
          default = "text"
        ),
        list_name = NA_character_,
        required = NA_character_,
        relevant = NA_character_,
        campo_pai = NA_character_,
        nivel_schema129 = nivel,
        formato_schema129 = formato,
        largura_schema129 = largura,
        obrigatorio_valor_schema129 = obrigatorio_valor,
        posicao_schema129 = posicao,
        atributo_schema129 = atributo,
        cardinalidade_operacional = "metadado_pipeline",
        ambiguo_entre_versoes = FALSE,
        status_confianca = "alta",
        origem_regra = "schema_129_metadado_pipeline"
      )]
      atributos <- data.table::rbindlist(list(atributos, extra), use.names = TRUE, fill = TRUE)
    }
  }
  data.table::setorder(atributos, posicao_schema129, na.last = TRUE)

 ### inventario declarativo das regras impeditivas/diagnosticas
 ### hoje espalhadas pelos validadores e diagnosticos. Esta tabela e
 ### metadado de contrato: nao executa regra, nao muda decisor e nao substitui
 ### os validadores operacionais existentes.
  regras_base <- data.table::data.table(
    regra = c(
      "uas_duplicadas_mesmo_ano",
      "ponto_sem_interceptacao",
      "nativa_sem_forma_vida",
      "exotica_sem_forma_vida",
      "seca_morta_sem_forma_vida",
      "outra_forma_vida",
      "forma_vida_desconhecida_invalida",
      "forma_vida_desconhecida",
      "forma_vida_exotica_sem_especie",
      "forma_vida_exotica_com_especie",
      "solo_nu_com_outra_categoria",
      "habito_obrigatorio_ausente",
      "campo_obrigatorio_relevante_vazio",
      "valor_fora_dominio",
      "formato_final_invalido",
      "pipe_residual_estruturado"
    ),
    tipo_regra = c(
      "impeditiva", "impeditiva", "impeditiva", "impeditiva", "impeditiva",
      "impeditiva", "impeditiva", "diagnostica", "diagnostica", "diagnostica",
      "impeditiva", "impeditiva", "impeditiva", "impeditiva", "impeditiva",
      "diagnostica"
    ),
    severidade_contrato_unico = c(
      "alta", "alta", "alta", "alta", "alta",
      "alta", "alta", "media", "media", "media",
      "alta", "alta", "alta", "alta", "alta",
      "media"
    ),
    fonte_operacional_atual = c(
      rep("monitora_publicacao_ab_auditar_pendencias_impeditivas / monitora_diag_rel_gerar_ocorrencias", 7L),
      rep("monitora_diag_rel_gerar_ocorrencias", 3L),
 ### -: passam a ser diagnosticadas também antes do painel
 ### (monitora_diag_rel_gerar_ocorrencias , via
 ### monitora_correcao_mask_solo_nu_incompativel /
 ### monitora_correcao_mask_habito_obrigatorio_ausente ); o bloqueio final
 ### de registros_validados.csv continua em
 ### monitora_validados_validar_condicionais_xlsform21 .
      "monitora_diag_rel_gerar_ocorrencias / monitora_validados_validar_condicionais_xlsform21",
      "monitora_diag_rel_gerar_ocorrencias / monitora_validados_validar_condicionais_xlsform21",
      "monitora_validados_validar_condicionais_xlsform21",
      "monitora_validados_validar_dominios_xlsform21",
      "monitora_validados_validar_formatos_saida / monitora_validados_schema_embutido",
      "monitora_pipe_contrato_diagnosticar_dataset / monitora_bloquear_pipe_residual_produto"
    ),
    atributo_principal = c(
      "UC+UA+ANO+COLETA",
      "amostragem/registro/tipo_forma_vida",
      "amostragem/registro/forma_vida_nativa",
      "amostragem/registro/forma_vida_exotica",
      "amostragem/registro/forma_vida_seca_morta",
      "amostragem/registro/forma_vida_outros",
      "amostragem/registro/forma_vida_nativa",
      "amostragem/registro/forma_vida_nativa",
      "forma_vida_exotica",
      "forma_vida_exotica",
      "amostragem/registro/tipo_forma_vida",
      "habito",
      "campo_relevant_required",
      "select_one/select_multiple",
      "registros_validados.csv",
      "coluna_estruturada_com_pipe"
    ),
    bloqueia_registros_validados = c(TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, FALSE, FALSE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE),
    acao_contrato_unico = c(
      rep("diagnosticar_e_bloquear_exportacao_validada", 7L),
      rep("diagnosticar_sem_migrar_consumidor", 3L),
      rep("diagnosticar_e_bloquear_exportacao_validada", 5L),
      "diagnosticar_sem_migrar_consumidor"
    )
  )
  perfis_por_regra <- list(
    uas_duplicadas_mesmo_ano = c("perfil_pre_painel", "perfil_painel_edicao", "perfil_pos_painel_corrig", "perfil_export_registros_validados"),
    ponto_sem_interceptacao = c("perfil_pre_painel", "perfil_painel_edicao", "perfil_pos_painel_corrig", "perfil_export_registros_validados"),
    nativa_sem_forma_vida = c("perfil_pre_painel", "perfil_painel_edicao", "perfil_pos_painel_corrig", "perfil_export_registros_validados"),
    exotica_sem_forma_vida = c("perfil_pre_painel", "perfil_painel_edicao", "perfil_pos_painel_corrig", "perfil_export_registros_validados"),
    seca_morta_sem_forma_vida = c("perfil_pre_painel", "perfil_painel_edicao", "perfil_pos_painel_corrig", "perfil_export_registros_validados"),
    outra_forma_vida = c("perfil_pre_painel", "perfil_painel_edicao", "perfil_pos_painel_corrig", "perfil_export_registros_validados"),
    forma_vida_desconhecida_invalida = c("perfil_pre_painel", "perfil_painel_edicao", "perfil_pos_painel_corrig", "perfil_export_registros_validados"),
    forma_vida_desconhecida = c("perfil_pre_painel", "perfil_painel_edicao", "perfil_pos_painel_corrig", "perfil_export_registros_validados"),
    forma_vida_exotica_sem_especie = c("perfil_pre_painel", "perfil_painel_edicao", "perfil_pos_painel_corrig"),
    forma_vida_exotica_com_especie = c("perfil_pre_painel", "perfil_painel_edicao", "perfil_pos_painel_corrig"),
    solo_nu_com_outra_categoria = c("perfil_pre_painel", "perfil_painel_edicao", "perfil_pos_painel_corrig", "perfil_export_registros_validados"),
    habito_obrigatorio_ausente = c("perfil_pre_painel", "perfil_painel_edicao", "perfil_pos_painel_corrig", "perfil_export_registros_validados"),
    campo_obrigatorio_relevante_vazio = c("perfil_pos_painel_corrig", "perfil_export_registros_validados"),
    valor_fora_dominio = c("perfil_pos_painel_corrig", "perfil_export_registros_validados"),
    formato_final_invalido = "perfil_export_registros_validados",
    pipe_residual_estruturado = c("perfil_importacao", "perfil_pre_painel", "perfil_pos_painel_corrig")
  )
  regras_validacao <- data.table::rbindlist(lapply(seq_len(nrow(regras_base)), function(i) {
    rr <- regras_base$regra[i]
    data.table::data.table(
      perfil = perfis_por_regra[[rr]],
      regra = rr,
      tipo_regra = regras_base$tipo_regra[i],
      severidade_contrato_unico = regras_base$severidade_contrato_unico[i],
      fonte_operacional_atual = regras_base$fonte_operacional_atual[i],
      atributo_principal = regras_base$atributo_principal[i],
      bloqueia_registros_validados = regras_base$bloqueia_registros_validados[i],
      acao_contrato_unico = regras_base$acao_contrato_unico[i],
      origem = "contrato_unico_035v_b_c"
    )
  }), fill = TRUE, use.names = TRUE)
  data.table::setorder(regras_validacao, perfil, regra)

  list(
    atributos = atributos[],
    aliases = aliases[],
    choices = opcoes[],
    dependencias = dependencias[],
    regras_validacao = regras_validacao[],
    meta = data.table::data.table(
      versao_canonica_2025 = "21FEV25",
      n_atributos = nrow(atributos),
      n_aliases = nrow(aliases),
      n_regras_validacao = nrow(regras_validacao),
      gerado_em = as.character(Sys.time()),
      origem = "monitora_contrato_unico_embutido (03.5I, requisito diagnostics/requisitos_035i_fonte_unica_contrato)"
    )
  )
}

monitora_contrato_unico_normalizar_texto_seguro <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  if (exists("monitora_correcao_normalizar_nome_coluna", mode = "function")) {
    return(monitora_correcao_normalizar_nome_coluna(x))
  }
  trimws(tolower(x))
}

monitora_contrato_unico_validar_estrutura_indices <- function(indices, perfis = NULL) {
  nomes_indices_esperados <- c(
    "por_atributo_canonico", "por_caminho_registro", "por_name_curto",
    "por_label_normalizado", "por_alias_normalizado", "por_list_name",
    "por_choice_name", "por_relevance_campo_pai", "por_cardinalidade_operacional",
    "por_estagio_aplicavel", "por_severidade", "por_origem_regra",
    "template_sismonitora_129", "atributos_tecnicos_pipeline",
    "atributos_ambiguos_indeterminados", "campos_condicionais_esparsos"
  )
  faltando <- setdiff(nomes_indices_esperados, names(indices))
  if (length(faltando)) {
    stop("monitora_contrato_unico_indices: indices ausentes: ", paste(faltando, collapse = ", "), call. = FALSE)
  }

  tpl <- indices$template_sismonitora_129
  if (!data.table::is.data.table(tpl) || nrow(tpl) != 129L) {
    stop("monitora_contrato_unico_indices: template_sismonitora_129 deveria ter 129 linhas, tem ",
         if (data.table::is.data.table(tpl)) nrow(tpl) else "objeto invalido", call. = FALSE)
  }
  posicoes <- sort(as.integer(tpl$posicao_schema129))
  if (!identical(posicoes, seq_len(129L))) {
    stop("monitora_contrato_unico_indices: template_sismonitora_129 nao cobre 1:129 sem lacuna/duplicata", call. = FALSE)
  }

  categorias_validas <- c(
    "texto_livre", "select_multiple", "estruturado_completo_por_ponto",
    "estruturado_condicional_esparso", "estruturado_coleta", "metadado_pipeline",
    "tecnico_midia", "fora_do_contrato", "ambiguo_indeterminado"
  )
  cats_presentes <- unique(as.character(indices$por_cardinalidade_operacional$cardinalidade_operacional))
  cats_invalidas <- setdiff(cats_presentes, categorias_validas)
  if (length(cats_invalidas)) {
    stop("monitora_contrato_unico_indices: categorias de cardinalidade desconhecidas: ",
         paste(cats_invalidas, collapse = ", "), call. = FALSE)
  }

  alias_norm <- indices$por_alias_normalizado
  tem_ea <- nrow(alias_norm[tolower(alias) == "ea" & grepl("estacao_amostral", caminho_registro, fixed = TRUE)]) > 0L
  tem_ua <- nrow(alias_norm[tolower(alias) == "ua" & grepl("unidade_amostral", caminho_registro, fixed = TRUE)]) > 0L
  if (!tem_ea) stop("monitora_contrato_unico_indices: alias 'ea' -> estacao_amostral ausente (requisito 03.5H3)", call. = FALSE)
  if (!tem_ua) stop("monitora_contrato_unico_indices: alias 'ua' -> unidade_amostral ausente (requisito 03.5H3)", call. = FALSE)

  if (!is.null(perfis)) {
    nomes_perfis_esperados <- c(
      "perfil_importacao", "perfil_pre_painel", "perfil_painel_edicao",
      "perfil_pos_painel_corrig", "perfil_export_registros_validados",
      "perfil_estatisticas_graficos"
    )
    faltando_perfis <- setdiff(nomes_perfis_esperados, names(perfis))
    if (length(faltando_perfis)) {
      stop("monitora_contrato_unico_indices: perfis ausentes: ", paste(faltando_perfis, collapse = ", "), call. = FALSE)
    }
  }
  invisible(TRUE)
}

monitora_contrato_unico_indices <- function(contrato = NULL, validar = TRUE) {
  if (is.null(contrato)) contrato <- monitora_contrato_unico_embutido()

  atributos <- data.table::copy(data.table::as.data.table(contrato$atributos))
  aliases <- data.table::copy(data.table::as.data.table(contrato$aliases))
  choices <- data.table::copy(data.table::as.data.table(contrato$choices))
  dependencias <- data.table::copy(data.table::as.data.table(contrato$dependencias))

 ### Severidade e estágio aplicável são anotações de orquestração
 ### DERIVADAS só de colunas já existentes no contrato (cardinalidade,
 ### confiança, ambiguidade) -- não introduzem nenhum fato novo sobre o
 ### atributo, só reagrupam o que já está no contrato para consumo por
 ### etapa. As tabelas abaixo são a única fonte dessas duas anotações;
 ### nada aqui compete com o contrato único.
  atributos[, severidade := "baixa"]
  atributos[cardinalidade_operacional %in% c("estruturado_condicional_esparso") | status_confianca %in% c("media", "media_sem_schema129"), severidade := "media"]
  atributos[ambiguo_entre_versoes == TRUE | status_confianca == "baixa_ambiguo" | cardinalidade_operacional == "ambiguo_indeterminado", severidade := "alta"]

  mapa_estagios_por_cardinalidade <- data.table::data.table(
    cardinalidade_operacional = c(
      "texto_livre", "select_multiple", "estruturado_completo_por_ponto",
      "estruturado_condicional_esparso", "estruturado_coleta", "metadado_pipeline",
      "tecnico_midia", "fora_do_contrato", "ambiguo_indeterminado"
    ),
    estagios = list(
      c("importacao", "pre_painel", "painel_edicao", "pos_painel_corrig", "export_registros_validados", "estatisticas_graficos"),
      c("importacao", "pre_painel", "painel_edicao", "pos_painel_corrig", "export_registros_validados", "estatisticas_graficos"),
      c("importacao", "pre_painel", "painel_edicao", "pos_painel_corrig", "export_registros_validados", "estatisticas_graficos"),
      c("importacao", "pre_painel", "painel_edicao", "pos_painel_corrig"),
      c("importacao", "pre_painel", "painel_edicao", "pos_painel_corrig", "export_registros_validados", "estatisticas_graficos"),
      c("importacao", "pre_painel", "painel_edicao", "pos_painel_corrig", "export_registros_validados"),
      c("importacao", "pos_painel_corrig"),
      c("pre_painel", "painel_edicao", "export_registros_validados"),
      c("pre_painel")
    )
  )
  juncao_estagios <- merge(atributos, mapa_estagios_por_cardinalidade, by = "cardinalidade_operacional", all.x = TRUE)
  por_estagio_aplicavel <- juncao_estagios[
    !vapply(estagios, is.null, logical(1)),
    .(estagio = estagios[[1]]),
    by = .(atributo_canonico_2025, caminho_registro, cardinalidade_operacional)
  ]
  data.table::setkeyv(por_estagio_aplicavel, "estagio")

 ### --- índices mínimos (seção "Índices mínimos") ---------------------
  por_atributo_canonico <- data.table::copy(atributos)
  data.table::setkeyv(por_atributo_canonico, "atributo_canonico_2025")

  por_caminho_registro <- data.table::copy(atributos[!is.na(caminho_registro)])
  data.table::setkeyv(por_caminho_registro, "caminho_registro")

  por_name_curto <- data.table::copy(atributos[!is.na(name_curto) & nzchar(name_curto)])
  data.table::setkeyv(por_name_curto, "name_curto")

  por_label_normalizado <- data.table::copy(atributos)
  por_label_normalizado[, label_normalizado := monitora_contrato_unico_normalizar_texto_seguro(label_2025_sem_html)]
  por_label_normalizado <- por_label_normalizado[nzchar(label_normalizado)]
  data.table::setkeyv(por_label_normalizado, "label_normalizado")

  por_alias_normalizado <- data.table::copy(aliases)
  por_alias_normalizado[, alias_normalizado := monitora_contrato_unico_normalizar_texto_seguro(alias)]
  data.table::setkeyv(por_alias_normalizado, "alias_normalizado")

  por_list_name <- data.table::copy(atributos[!is.na(list_name) & nzchar(list_name)])
  data.table::setkeyv(por_list_name, "list_name")

  por_choice_name <- data.table::copy(choices)
  if (all(c("list_name", "name") %in% names(por_choice_name))) {
    data.table::setkeyv(por_choice_name, c("list_name", "name"))
  }

  por_relevance_campo_pai <- data.table::copy(atributos[!is.na(campo_pai) & nzchar(campo_pai)])
  data.table::setkeyv(por_relevance_campo_pai, "campo_pai")

  por_cardinalidade_operacional <- data.table::copy(atributos)
  data.table::setkeyv(por_cardinalidade_operacional, "cardinalidade_operacional")

  por_severidade <- data.table::copy(atributos)
  data.table::setkeyv(por_severidade, "severidade")

  por_origem_regra <- data.table::copy(atributos)
  data.table::setkeyv(por_origem_regra, "origem_regra")

  template_sismonitora_129 <- data.table::copy(atributos[!is.na(posicao_schema129)])
  data.table::setorder(template_sismonitora_129, posicao_schema129)

  atributos_tecnicos_pipeline <- data.table::copy(atributos[cardinalidade_operacional %in% c("tecnico_midia", "metadado_pipeline", "fora_do_contrato")])

  atributos_ambiguos_indeterminados <- data.table::copy(atributos[cardinalidade_operacional == "ambiguo_indeterminado" | ambiguo_entre_versoes == TRUE])

 ### A bromélia nativa condicional/esparsa (e demais formas condicionais)
 ### fica listada aqui só como INVENTÁRIO -- nenhuma resolução por ponto
 ### absoluto é feita nesta ou em nenhuma outra função de (ver ajuste
 ### /, causa-raiz da regressão que este índice existe para
 ### tornar visível, não para "corrigir" silenciosamente).
  campos_condicionais_esparsos <- data.table::copy(atributos[cardinalidade_operacional == "estruturado_condicional_esparso"])

  indices <- list(
    por_atributo_canonico = por_atributo_canonico[],
    por_caminho_registro = por_caminho_registro[],
    por_name_curto = por_name_curto[],
    por_label_normalizado = por_label_normalizado[],
    por_alias_normalizado = por_alias_normalizado[],
    por_list_name = por_list_name[],
    por_choice_name = por_choice_name[],
    por_relevance_campo_pai = por_relevance_campo_pai[],
    por_cardinalidade_operacional = por_cardinalidade_operacional[],
    por_estagio_aplicavel = por_estagio_aplicavel[],
    por_severidade = por_severidade[],
    por_origem_regra = por_origem_regra[],
    template_sismonitora_129 = template_sismonitora_129[],
    atributos_tecnicos_pipeline = atributos_tecnicos_pipeline[],
    atributos_ambiguos_indeterminados = atributos_ambiguos_indeterminados[],
    campos_condicionais_esparsos = campos_condicionais_esparsos[]
  )

 ### --- perfis derivados (seção "Perfis derivados mínimos") ----------
  aliases_por_caminho <- aliases[, .(aliases_conhecidos = list(unique(alias))), by = caminho_registro]
  perfil_importacao <- merge(
    atributos[!is.na(caminho_registro), .(
      atributo_canonico_2025, caminho_registro, name_curto,
      label_2025_com_html, label_2025_sem_html,
      labels_historicos_com_html, labels_historicos_sem_html,
      cardinalidade_operacional
    )],
    aliases_por_caminho, by = "caminho_registro", all.x = TRUE
  )
  perfil_importacao[, aliases_conhecidos := lapply(aliases_conhecidos, function(a) {
    if (is.null(a) || (length(a) == 1L && is.na(a[1]))) character(0) else a
  })]

  atributos_pre_painel <- por_estagio_aplicavel[estagio == "pre_painel", unique(atributo_canonico_2025)]
  perfil_pre_painel <- atributos[atributo_canonico_2025 %in% atributos_pre_painel, .(
    atributo_canonico_2025, caminho_registro, cardinalidade_operacional,
    status_confianca, severidade, campo_pai, relevant
  )]
  perfil_pre_painel[, bloqueia_registros_validados := cardinalidade_operacional == "ambiguo_indeterminado" | status_confianca == "baixa_ambiguo"]

  choices_por_list_name <- choices[, .(choices_disponiveis = list(unique(name))), by = list_name]
  perfil_painel_edicao <- atributos[!(cardinalidade_operacional %in% c("ambiguo_indeterminado", "tecnico_midia")), .(
    atributo_canonico_2025, caminho_registro, name_curto, label_2025_sem_html,
    list_name, tipo_base, cardinalidade_operacional, relevant, campo_pai
  )]
  perfil_painel_edicao <- merge(perfil_painel_edicao, choices_por_list_name, by = "list_name", all.x = TRUE)

  perfil_pos_painel_corrig <- atributos[cardinalidade_operacional != "ambiguo_indeterminado", .(
    atributo_canonico_2025, caminho_registro, tipo_base, cardinalidade_operacional,
    relevant, campo_pai, status_confianca
  )]

  projecao_129 <- template_sismonitora_129[, .(
    posicao_schema129, atributo_canonico_2025, caminho_registro,
    nivel_schema129, formato_schema129, cardinalidade_operacional, status_confianca
  )]
  assertivas_baratas_validados <- data.table::data.table(
    checagem = c(
      "n_posicoes_esperado", "n_posicoes_observado", "n_gaps_posicoes",
      "n_duplicatas_posicoes", "n_condicional_esparso_no_template"
    ),
    valor = c(
      "129",
      as.character(nrow(projecao_129)),
      as.character(length(setdiff(seq_len(129L), projecao_129$posicao_schema129))),
      as.character(sum(duplicated(projecao_129$posicao_schema129))),
      as.character(sum(projecao_129$cardinalidade_operacional == "estruturado_condicional_esparso", na.rm = TRUE))
    )
  )
 ### Só assertivas estruturais baratas sobre o próprio contrato -- nenhuma
 ### leitura de registros_validados.csv real, nenhuma revalidação linha a
 ### linha.
  perfil_export_registros_validados <- list(
    projecao = projecao_129[],
    assertivas = assertivas_baratas_validados[]
  )

  perfil_estatisticas_graficos <- atributos[
    cardinalidade_operacional %in% c("texto_livre", "select_multiple", "estruturado_completo_por_ponto", "estruturado_coleta") &
      status_confianca %in% c("alta", "media"),
    .(atributo_canonico_2025, caminho_registro, tipo_base, list_name, cardinalidade_operacional, status_confianca)
  ]

  perfis <- list(
    perfil_importacao = perfil_importacao[],
    perfil_pre_painel = perfil_pre_painel[],
    perfil_painel_edicao = perfil_painel_edicao[],
    perfil_pos_painel_corrig = perfil_pos_painel_corrig[],
    perfil_export_registros_validados = perfil_export_registros_validados,
    perfil_estatisticas_graficos = perfil_estatisticas_graficos[]
  )

  if (isTRUE(validar)) {
    monitora_contrato_unico_validar_estrutura_indices(indices, perfis)
  }

  list(
    indices = indices,
    perfis = perfis,
    meta = data.table::data.table(
      gerado_em = as.character(Sys.time()),
      n_indices = length(indices),
      n_perfis = length(perfis),
      validado = isTRUE(validar),
      origem = "monitora_contrato_unico_indices (03.5J, deriva de monitora_contrato_unico_embutido, sem conectar ao pipeline)"
    )
  )
}

monitora_contrato_unico_indices_cache <- function(contrato = NULL, validar = TRUE, forcar = FALSE) {
  if (!is.null(contrato)) return(monitora_contrato_unico_indices(contrato = contrato, validar = validar))
  env <- if (exists("monitora_publicacao_ae_cache_env", mode = "function")) monitora_publicacao_ae_cache_env("contrato_unico_indices") else .GlobalEnv
  chave <- paste0("indices_validar_", isTRUE(validar))
  if (!isTRUE(forcar) && exists(chave, envir = env, inherits = FALSE)) return(get(chave, envir = env, inherits = FALSE))
  out <- monitora_contrato_unico_indices(contrato = NULL, validar = validar)
  assign(chave, out, envir = env)
  out
}

### Compatibilidade pública derivada: o schema não mantém autoridade paralela;
### ele projeta exclusivamente o perfil 1:129 incorporado ao contrato único.
monitora_validados_schema_embutido <- function() {
  contrato_indices <- monitora_contrato_unico_indices_cache(validar = TRUE)
  tpl <- data.table::copy(data.table::as.data.table(
    contrato_indices$indices$template_sismonitora_129
  ))
  schema <- tpl[, .(
    posicao = as.integer(posicao_schema129),
    atributo = as.character(atributo_schema129),
    formato = as.character(formato_schema129),
    largura = as.integer(largura_schema129),
    obrigatorio_valor = as.logical(obrigatorio_valor_schema129),
    nivel = as.character(nivel_schema129)
  )]
  data.table::setorder(schema, posicao)
  if (nrow(schema) != 129L || !identical(schema$posicao, seq_len(129L)) || anyDuplicated(schema$atributo)) {
    stop("Perfil de exportação do contrato único não preserva o template SISMONITORA 1:129.", call. = FALSE)
  }
  schema[]
}

monitora_validacao_regras_por_perfil_contrato_unico <- function(perfil,
                                                                 contrato = NULL,
                                                                 incluir_todos = FALSE) {
  if (missing(perfil) || is.null(perfil) || !length(perfil)) {
    stop("Informe um perfil do contrato unico.", call. = FALSE)
  }
  if (is.null(contrato)) contrato <- monitora_contrato_unico_embutido()
  regras <- if (!is.null(contrato$regras_validacao)) {
    data.table::copy(data.table::as.data.table(contrato$regras_validacao))
  } else {
    data.table::data.table()
  }
  if (!nrow(regras)) {
    return(data.table::data.table(
      perfil = character(), regra = character(), tipo_regra = character(),
      severidade_contrato_unico = character(), fonte_operacional_atual = character(),
      atributo_principal = character(), bloqueia_registros_validados = logical(),
      acao_contrato_unico = character(), origem = character()
    ))
  }
  perfil_chr <- unique(trimws(as.character(perfil)))
  perfil_chr <- perfil_chr[!is.na(perfil_chr) & nzchar(perfil_chr)]
  if (!length(perfil_chr)) stop("Informe um perfil nao vazio do contrato unico.", call. = FALSE)
  if (!isTRUE(incluir_todos) && !all(perfil_chr %in% unique(regras$perfil))) {
    faltando <- setdiff(perfil_chr, unique(regras$perfil))
    stop("Perfil sem regras no contrato unico: ", paste(faltando, collapse = ", "), call. = FALSE)
  }
  out <- regras[perfil %in% perfil_chr]
  data.table::setorder(out, perfil, regra)
  out[]
}

monitora_ponte_pre_painel_regras_contrato_unico <- function(contrato = NULL, base_dir = NULL) {
  if (is.null(contrato)) contrato <- tryCatch(monitora_contrato_unico_embutido(), error = function(e) NULL)
  regras_pre_painel <- tryCatch(
    monitora_validacao_regras_por_perfil_contrato_unico("perfil_pre_painel", contrato = contrato, incluir_todos = TRUE),
    error = function(e) data.table::data.table(regra = character(), fonte_operacional_atual = character())
  )
  catalogo_base <- tryCatch(
    monitora_diag_rel_catalogo_ocorrencias_base(),
    error = function(e) data.table::data.table(tipo_ocorrencia = character(), severidade = character())
  )

  fonte_ocorrencias <- grepl(
    "monitora_diag_rel_gerar_ocorrencias|monitora_publicacao_ab_auditar_pendencias_impeditivas",
    regras_pre_painel$fonte_operacional_atual
  )
  regras_ocorrencias <- unique(regras_pre_painel$regra[fonte_ocorrencias])

  tipos_sem_regra_contrato <- sort(setdiff(catalogo_base$tipo_ocorrencia, regras_ocorrencias))
  regras_sem_tipo_operacional <- sort(setdiff(regras_ocorrencias, catalogo_base$tipo_ocorrencia))

  divergencias <- data.table::data.table(
    tipo_divergencia = c(
      rep("pendencia_operacional_sem_regra_contrato_unico", length(tipos_sem_regra_contrato)),
      rep("regra_contrato_unico_sem_pendencia_operacional_ativa", length(regras_sem_tipo_operacional))
    ),
    identificador = c(tipos_sem_regra_contrato, regras_sem_tipo_operacional)
  )
  status <- if (nrow(divergencias)) "divergencia_encontrada" else "cobertura_ok"

  out_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE)
  if (is.null(base_dir)) base_dir <- file.path(out_dir, "relatorios_pre_painel")
  dir.create(base_dir, recursive = TRUE, showWarnings = FALSE)
  arq <- file.path(base_dir, "ponte_regras_contrato_unico_pre_painel.csv")
  try(monitora_fwrite(divergencias, arq, na = ""), silent = TRUE)

  if (nrow(divergencias)) {
    msg <- paste0(
      "Ponte de validacoes pre-painel (03.5V-C): ", nrow(divergencias),
      " divergencia(s) entre o catalogo operacional de ocorrencias e o contrato unico. Ver ", arq, "."
    )
    if (exists("monitora_correcao_console_msg", mode = "function")) {
      monitora_correcao_console_msg(msg)
    } else {
      message(msg)
    }
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      try(monitora_log_registrar_evento("ponte_regras_pre_painel", "AVISO", arq, msg, "ponte 03.5V-C"), silent = TRUE)
    }
  }

  list(status = status, divergencias = divergencias[], arquivo = arq)
}

monitora_perfil_painel_edicao_contrato_unico <- function(contrato_indices = NULL, ocorrencias_painel = NULL) {
  if (!isTRUE(monitora_cfg_env_bool("MONITORA_AUDITORIA_PERFIL_PAINEL_CONTRATO_UNICO", FALSE))) {
    return(invisible(NULL))
  }

  tryCatch({
    if (is.null(contrato_indices)) contrato_indices <- monitora_contrato_unico_indices_cache()
    perfil_base <- contrato_indices$perfis$perfil_painel_edicao
    if (!data.table::is.data.table(perfil_base) || !nrow(perfil_base)) return(invisible(NULL))
    perfil_base <- data.table::copy(perfil_base)

    por_atributo <- contrato_indices$indices$por_atributo_canonico
    if (!data.table::is.data.table(por_atributo) ||
        !all(c("atributo_canonico_2025", "origem_regra", "status_confianca", "severidade") %in% names(por_atributo))) {
      return(invisible(NULL))
    }
    meta_atributo <- unique(por_atributo[, .(atributo_canonico_2025, origem_regra, status_confianca, severidade)])

    perfil_base <- merge(perfil_base, meta_atributo, by = "atributo_canonico_2025", all.x = TRUE)
 ### Mesma regra estrutural já usada em $perfis$perfil_pre_painel (linha
 ### ~32738) para "bloqueia_registros_validados" -- aqui só anotação de
 ### auditoria do painel, não participa de nenhuma decisão de bloqueio real.
    perfil_base[, bloqueio_estrutural_contrato_unico :=
      cardinalidade_operacional == "ambiguo_indeterminado" | status_confianca == "baixa_ambiguo"]

    if (!is.null(ocorrencias_painel) &&
        data.table::is.data.table(ocorrencias_painel) &&
        "atributo_canonico_2025" %in% names(ocorrencias_painel)) {
      contagem_ocorrencias <- ocorrencias_painel[, .(n_ocorrencias_painel = .N), by = atributo_canonico_2025]
      perfil_base <- merge(perfil_base, contagem_ocorrencias, by = "atributo_canonico_2025", all.x = TRUE)
      perfil_base[is.na(n_ocorrencias_painel), n_ocorrencias_painel := 0L]
    }

    data.table::setcolorder(perfil_base, intersect(c(
      "atributo_canonico_2025", "caminho_registro", "name_curto", "label_2025_sem_html",
      "origem_regra", "severidade", "bloqueio_estrutural_contrato_unico",
      "cardinalidade_operacional", "status_confianca", "list_name", "choices_disponiveis",
      "tipo_base", "relevant", "campo_pai", "n_ocorrencias_painel"
    ), names(perfil_base)))
    perfil_base[]
  }, error = function(e) invisible(NULL))
}

monitora_perfil_painel_edicao_operacional_contrato_unico <- function(colunas_observadas = NULL,
                                                                      contrato_indices = NULL) {
  if (is.null(contrato_indices)) {
    contrato_indices <- tryCatch(monitora_contrato_unico_indices_cache(), error = function(e) NULL)
  }
  perfil <- if (!is.null(contrato_indices) && !is.null(contrato_indices$perfis$perfil_painel_edicao)) {
    data.table::copy(data.table::as.data.table(contrato_indices$perfis$perfil_painel_edicao))
  } else {
    data.table::data.table()
  }
  if (!nrow(perfil)) {
    return(data.table::data.table(
      atributo_coluna_registros_corrig = character(),
      atributo_canonico_2025 = character(),
      caminho_registro = character(),
      name_curto = character(),
      cardinalidade_operacional_contrato_unico = character(),
      escopo_operacional_contrato_unico = character(),
      escopos_permitidos_contrato_unico = character(),
      motivo_escopo_contrato_unico = character()
    ))
  }
  for (cc in c("atributo_canonico_2025", "caminho_registro", "name_curto", "label_2025_sem_html", "tipo_base", "cardinalidade_operacional", "relevant", "campo_pai")) {
    if (!(cc %in% names(perfil))) perfil[, (cc) := NA_character_]
  }
  perfil[, `:=`(
    caminho_norm_035r = monitora_contrato_unico_normalizar_texto_seguro(caminho_registro),
    name_norm_035r = monitora_contrato_unico_normalizar_texto_seguro(name_curto),
    label_norm_035r = monitora_contrato_unico_normalizar_texto_seguro(label_2025_sem_html)
  )]

 ### aliases operacionais do contrato único (ex.: UA/EA
 ### -> unidade_amostral/estacao_amostral, já cadastrados em
 ### monitora_contrato_unico_embutido $aliases) nunca eram consultados
 ### aqui -- resolver_um só comparava contra caminho_registro/name_curto/
 ### label do próprio perfil_painel_edicao. Isso deixava atributos com
 ### alias explícito no contrato único "fora_do_perfil_painel_edicao" só
 ### porque o alias curto (ex. "UA") não é igual ao name_curto canônico
 ### (ex. "unidade_amostral") -- confirmado na execução real bloqueando a edição
 ### genérica de UA mesmo o painel a exibindo como editável. Resolução
 ### genérica: qualquer atributo com alias cadastrado no contrato único
 ### passa a resolver aqui, sem lista paralela por nome de atributo.
 ###
 ### Restrição deliberada por `origem_alias`: a tabela de aliases do
 ### contrato único também guarda variações de LABEL histórico usadas só
 ### para casar cabeçalho de import/normalização de valor
 ### (origem "pipe_aliases_campos_conhecidos"/"validados_aliases"), sem
 ### relação com permissão de edição no painel. Testado e confirmado: sem
 ### esta restrição, campos de espécie/nome popular (ex. "Espécie ou nome
 ### popular (Erva bromelioide) (amostragem/registro)") passavam a
 ### resolver contra o campo `_sp` do contrato e viravam editáveis por
 ### engano. Só as origens estruturais/administrativas explícitas
 ### ("dt_consolidar_aliases_colunas_ref", "requisito_035h3" -- UC/UA/EA/
 ### CICLO/CAMPANHA/COLETA/UUID/coleta_uuid/Data/Horário/Coordenadas/
 ### ponto_amostral/ponto_metro) valem aqui.
  alias_idx_035r <- if (!is.null(contrato_indices) && !is.null(contrato_indices$indices$por_alias_normalizado)) {
    data.table::copy(data.table::as.data.table(contrato_indices$indices$por_alias_normalizado))
  } else {
    data.table::data.table()
  }
  if (nrow(alias_idx_035r) && "origem_alias" %in% names(alias_idx_035r)) {
    alias_idx_035r <- alias_idx_035r[origem_alias %in% c("dt_consolidar_aliases_colunas_ref", "requisito_035h3")]
  }
  if (nrow(alias_idx_035r) && !("alias_normalizado" %in% names(alias_idx_035r))) {
    alias_idx_035r[, alias_normalizado := monitora_contrato_unico_normalizar_texto_seguro(alias)]
  }

  cols <- unique(as.character(colunas_observadas))
  cols <- cols[!is.na(cols) & nzchar(cols)]
  if (!length(cols)) cols <- unique(c(perfil$caminho_registro, perfil$name_curto))
  cols <- cols[!is.na(cols) & nzchar(cols)]
  obs <- data.table::data.table(
    atributo_coluna_registros_corrig = cols,
    coluna_norm_035r = monitora_contrato_unico_normalizar_texto_seguro(cols)
  )

  resolver_um <- function(col, norm_col) {
    hit <- perfil[caminho_registro == col | name_curto == col | label_2025_sem_html == col]
    if (!nrow(hit)) hit <- perfil[caminho_norm_035r == norm_col | name_norm_035r == norm_col | label_norm_035r == norm_col]
    if (!nrow(hit)) {
      final <- sub("^.*/", "", col)
      final_norm <- monitora_contrato_unico_normalizar_texto_seguro(final)
      hit <- perfil[name_curto == final | name_norm_035r == final_norm]
    }
 ### registros_corrig/registros_importados usa o cabeçalho no
 ### formato "<label> (<caminho_do_grupo>)" quando o label sozinho não é
 ### uma chave única (convenção já usada em toda a leitura/exportação de
 ### CSV deste script, não uma heurística nova). Sem este passo, colunas
 ### reais como "**Encostam** na vareta: (amostragem/registro)" nunca
 ### batiam contra label_2025_sem_html ("**Encostam** na vareta:"),
 ### caindo em "fora_do_perfil_painel_edicao" mesmo sendo um atributo
 ### plenamente editável -- confirmado na execução real bloqueando
 ### SANEORF para o próprio Encostam/tipo_forma_vida.
    if (!nrow(hit) && grepl("\\s\\([^()]*\\)\\s*$", col)) {
      sem_grupo <- trimws(sub("\\s\\([^()]*\\)\\s*$", "", col))
      sem_grupo_norm <- monitora_contrato_unico_normalizar_texto_seguro(sem_grupo)
      if (nzchar(sem_grupo)) {
        hit <- perfil[caminho_registro == sem_grupo | name_curto == sem_grupo | label_2025_sem_html == sem_grupo]
        if (!nrow(hit)) hit <- perfil[caminho_norm_035r == sem_grupo_norm | name_norm_035r == sem_grupo_norm | label_norm_035r == sem_grupo_norm]
      }
    }
 ### fallback por alias explícito do contrato único
 ### (ex.: "UA"/"EA"). Só é consultado depois de esgotadas as
 ### comparações diretas por caminho/name/label acima, preservando a
 ### precedência do próprio schema do XLSForm 2025 sobre aliases.
    if (!nrow(hit) && nrow(alias_idx_035r)) {
      alias_hit <- alias_idx_035r[alias == col | alias_normalizado == norm_col]
      if (nrow(alias_hit)) {
        caminho_alvo <- alias_hit$caminho_registro[1L]
        hit <- perfil[caminho_registro == caminho_alvo]
      }
    }
    if (!nrow(hit)) return(data.table::data.table())
    hit[1L]
  }
  mapa <- data.table::rbindlist(lapply(seq_len(nrow(obs)), function(i) {
    h <- resolver_um(obs$atributo_coluna_registros_corrig[i], obs$coluna_norm_035r[i])
    if (!nrow(h)) {
      return(data.table::data.table(
        atributo_coluna_registros_corrig = obs$atributo_coluna_registros_corrig[i],
        atributo_canonico_2025 = NA_character_, caminho_registro = NA_character_, name_curto = NA_character_,
        tipo_base_contrato_unico = NA_character_, cardinalidade_operacional_contrato_unico = NA_character_,
        relevant_contrato_unico = NA_character_, campo_pai_contrato_unico = NA_character_
      ))
    }
    data.table::data.table(
      atributo_coluna_registros_corrig = obs$atributo_coluna_registros_corrig[i],
      atributo_canonico_2025 = h$atributo_canonico_2025[1L],
      caminho_registro = h$caminho_registro[1L],
      name_curto = h$name_curto[1L],
      tipo_base_contrato_unico = h$tipo_base[1L],
      cardinalidade_operacional_contrato_unico = h$cardinalidade_operacional[1L],
      relevant_contrato_unico = h$relevant[1L],
      campo_pai_contrato_unico = h$campo_pai[1L]
    )
  }), fill = TRUE, use.names = TRUE)

  caminho_norm <- monitora_contrato_unico_normalizar_texto_seguro(mapa$caminho_registro)
  nome_norm <- monitora_contrato_unico_normalizar_texto_seguro(mapa$atributo_coluna_registros_corrig)
  padrao_superior_herdavel <- paste(
    "(^|_)(uc|ea|ua|ciclo|campanha|ano|usuario|validado|validado_por|data_validacao|obs_validacao|planilha_upload)($|_)",
    "form_veg|estrato|area_elegivel|data_hora|data_data_hora|hora_data_hora|protocolo|coordenad|latitude|longitude|num_placa",
    sep = "|"
  )
  superior_herdavel <- grepl(padrao_superior_herdavel, nome_norm, perl = TRUE) |
    grepl(padrao_superior_herdavel, caminho_norm, perl = TRUE)
  em_registro <- grepl("(^|_)amostragem_registro_|(^|/)amostragem/registro/", caminho_norm) |
    grepl("(^|_)registro_", caminho_norm)
  condicional <- !is.na(mapa$relevant_contrato_unico) & nzchar(as.character(mapa$relevant_contrato_unico)) |
    !is.na(mapa$campo_pai_contrato_unico) & nzchar(as.character(mapa$campo_pai_contrato_unico)) |
    mapa$cardinalidade_operacional_contrato_unico %in% c("select_multiple", "estruturado_completo_por_ponto", "estruturado_condicional_esparso")
  protegido <- monitora_correcao_coluna_protegida(mapa$atributo_coluna_registros_corrig) |
    mapa$cardinalidade_operacional_contrato_unico %in% c("tecnico_midia", "fora_do_contrato", "ambiguo_indeterminado") |
    grepl("(^|_)uuid$|(^|_)uuid_|foto|imagem|image", nome_norm)
  ponto <- !protegido & !superior_herdavel & (em_registro | condicional)
  coleta <- !protegido & !ponto & !is.na(mapa$atributo_canonico_2025) & nzchar(mapa$atributo_canonico_2025)
  mapa[, escopo_operacional_contrato_unico := data.table::fcase(
    protegido, "protegido",
    ponto, "ponto",
    coleta, "coleta_inteira",
    default = "fora_do_perfil_painel_edicao"
  )]
  mapa[, escopos_permitidos_contrato_unico := data.table::fcase(
    escopo_operacional_contrato_unico == "ponto", "ponto;uuid_registro;linhas_pendentes_ocorrencia",
    escopo_operacional_contrato_unico == "coleta_inteira", "coleta_inteira",
    default = ""
  )]
  mapa[, motivo_escopo_contrato_unico := data.table::fcase(
    escopo_operacional_contrato_unico == "protegido", "atributo protegido ou fora da edicao generica do perfil_painel_edicao",
    escopo_operacional_contrato_unico == "ponto", "atributo de registro/ponto ou condicional pelo perfil_painel_edicao",
    escopo_operacional_contrato_unico == "coleta_inteira", "atributo superior/herdavel pelo perfil_painel_edicao",
    default = "atributo nao resolvido no perfil_painel_edicao"
  )]
  mapa[]
}

monitora_correcao_validar_escopo_operacional_contrato_unico <- function(atributo, escopo, dict = NULL) {
  atributo <- as.character(atributo)[1L]
  escopo <- as.character(escopo)[1L]
  if (is.na(escopo) || !nzchar(escopo)) escopo <- "ponto"
  info <- data.table::data.table()
  if (!is.null(dict)) {
    d <- data.table::as.data.table(dict)
    if ("atributo_coluna_registros_corrig" %in% names(d)) {
      info <- d[atributo_coluna_registros_corrig == atributo]
    }
  }
  if (!nrow(info) || !("escopos_permitidos_contrato_unico" %in% names(info))) {
    info <- monitora_perfil_painel_edicao_operacional_contrato_unico(atributo)
  }
  if (!nrow(info)) {
    return(list(ok = FALSE, status = "bloqueada_escopo_contrato_ausente", mensagem = paste0("Atributo sem perfil_painel_edicao no contrato unico: ", atributo)))
  }
  info <- info[1L]
  permitido <- monitora_correcao_split_serial(info$escopos_permitidos_contrato_unico[1L])
  permitido <- unique(c(permitido, if ("ponto" %in% permitido) "uuid_registro" else character(0)))
  if (!length(permitido)) {
    return(list(ok = FALSE, status = "bloqueada_escopo_protegido_contrato_unico", mensagem = paste0("Edição genérica bloqueada pelo contrato único para '", atributo, "': ", info$motivo_escopo_contrato_unico[1L])))
  }
  if (!(escopo %in% permitido)) {
    return(list(ok = FALSE, status = "bloqueada_escopo_incompativel_contrato_unico", mensagem = paste0("Escopo '", escopo, "' incompatível com '", atributo, "' no perfil_painel_edicao do contrato único. Escopo(s) permitido(s): ", paste(permitido, collapse = ", "), ".")))
  }
  list(ok = TRUE, status = "ok", mensagem = "escopo compatível com perfil_painel_edicao")
}

monitora_contrato_unico_construir_candidatos_texto <- function(atributos) {
  base <- function(col, campo_origem) {
    if (!(col %in% names(atributos))) return(data.table::data.table())
    vals <- as.character(atributos[[col]])
    ok <- !is.na(vals) & nzchar(vals)
    if (!any(ok)) return(data.table::data.table())
    data.table::data.table(
      atributo_canonico_2025 = atributos$atributo_canonico_2025[ok],
      caminho_registro = atributos$caminho_registro[ok],
      candidato = vals[ok],
      campo_origem = campo_origem
    )
  }
  partes <- list(
    base("caminho_registro", "caminho_registro"),
 ### `atributo_schema129` é o path usado pelo template SISMonitora (schema
 ### de 129) para o mesmo atributo, quando difere do caminho_registro cru
 ### do XLSForm (ex.: "coletor/nome" vs. "amostragem/registro/coletor/nome")
 ### -- confirmado necessário ao testar contra um dataset real 21FEV25
 ### , cujo cabeçalho usa essa convenção de export. Tratado como
 ### mesma força de "caminho_registro" (tier 1), não uma estratégia nova.
    base("atributo_schema129", "caminho_registro"),
    base("name_curto", "name_curto"),
    base("label_2025_com_html", "label_2025_com_html"),
    base("label_2025_sem_html", "label_2025_sem_html")
  )
  explodir_historico <- function(col, campo_origem) {
    if (!(col %in% names(atributos))) return(data.table::data.table())
    sub <- atributos[!is.na(get(col)) & nzchar(get(col)), .(atributo_canonico_2025, caminho_registro, txt = get(col))]
    if (!nrow(sub)) return(data.table::data.table())
    out <- sub[, .(candidato = unlist(strsplit(txt, " | ", fixed = TRUE))), by = .(atributo_canonico_2025, caminho_registro)]
    out <- out[nzchar(trimws(candidato))]
    out[, campo_origem := campo_origem]
    out[]
  }
  partes[[length(partes) + 1L]] <- explodir_historico("labels_historicos_com_html", "label_historico_com_html")
  partes[[length(partes) + 1L]] <- explodir_historico("labels_historicos_sem_html", "label_historico_sem_html")
  data.table::rbindlist(partes, use.names = TRUE, fill = TRUE)
}

monitora_contrato_unico_diagnosticar_observado_canonico <- function(colunas_observadas, contrato = NULL, indices = NULL, contexto = "diagnostico_035k") {
  if (is.null(contrato)) contrato <- monitora_contrato_unico_embutido()
 ### `indices` aqui é a sublista plana (por_atributo_canonico, por_alias_normalizado
 ### etc.), não o retorno completo de monitora_contrato_unico_indices
 ### (que também traz $perfis/$meta) -- por isso o "$indices" abaixo.
  if (is.null(indices)) indices <- monitora_contrato_unico_indices(contrato)$indices

  atributos <- data.table::copy(data.table::as.data.table(indices$por_atributo_canonico))

  colunas_observadas <- as.character(colunas_observadas)
  colunas_observadas <- colunas_observadas[!is.na(colunas_observadas) & nzchar(colunas_observadas)]
  obs_dt <- data.table::data.table(
    coluna_observada = colunas_observadas,
    coluna_observada_normalizada = monitora_contrato_unico_normalizar_texto_seguro(colunas_observadas)
  )
  obs_dt <- unique(obs_dt, by = "coluna_observada")

  candidatos_texto <- monitora_contrato_unico_construir_candidatos_texto(atributos)

 ### Estratégia 6 (fuzzy) deliberadamente NÃO usada aqui: o único helper de
 ### fuzzy/score já existente no script
 ### (monitora_correcao_candidatos_coluna_xlsform) resolve na direção
 ### oposta (campo canônico conhecido -> melhor coluna de um dt real já
 ### carregado) e depende de dt/arquivo_xlsform/categoria, não de uma lista
 ### de nomes; adaptá-lo aqui exigiria ler dado real ou reimplementar uma
 ### segunda lógica de score, o que violaria "não duplicar regra fora do
 ### contrato único" e "não depender de ler dados inteiros quando só nomes
 ### bastarem". Colunas sem match nas 5 estratégias exatas ficam
 ### `sem_match`, nunca forçadas.

  tier <- function(campo_origens, metodo, prioridade) {
    cand <- candidatos_texto[campo_origem %in% campo_origens, .(atributo_canonico_2025, caminho_registro, coluna_observada = candidato)]
    if (!nrow(cand)) return(data.table::data.table())
    out <- merge(obs_dt[, .(coluna_observada)], unique(cand), by = "coluna_observada")
    if (!nrow(out)) return(data.table::data.table())
    out[, `:=`(metodo_match = metodo, prioridade_match = prioridade)]
    out[]
  }

  tier1 <- tier("caminho_registro", "caminho_registro", 1L)
  tier2 <- tier("name_curto", "name_curto", 2L)
  tier3 <- tier(c("label_2025_com_html", "label_2025_sem_html", "label_historico_com_html", "label_historico_sem_html"), "label", 3L)

  alias_idx <- data.table::copy(data.table::as.data.table(indices$por_alias_normalizado))
  tier4 <- if (nrow(alias_idx)) {
    cand4 <- unique(alias_idx[, .(coluna_observada = alias, atributo_canonico_2025 = caminho_registro, caminho_registro)])
    out4 <- merge(obs_dt[, .(coluna_observada)], cand4, by = "coluna_observada")
    if (nrow(out4)) out4[, `:=`(metodo_match = "alias_explicito", prioridade_match = 4L)]
    out4
  } else {
    data.table::data.table()
  }

  candidatos_norm <- data.table::copy(candidatos_texto)
  if (nrow(candidatos_norm)) candidatos_norm[, candidato_normalizado := monitora_contrato_unico_normalizar_texto_seguro(candidato)]
  alias_norm <- if (nrow(alias_idx)) {
    unique(alias_idx[, .(atributo_canonico_2025 = caminho_registro, caminho_registro, candidato_normalizado = alias_normalizado)])
  } else {
    data.table::data.table()
  }
  candidatos_norm_full <- data.table::rbindlist(list(
    if (nrow(candidatos_norm)) candidatos_norm[, .(atributo_canonico_2025, caminho_registro, candidato_normalizado)] else data.table::data.table(),
    alias_norm
  ), use.names = TRUE, fill = TRUE)
  if (nrow(candidatos_norm_full)) candidatos_norm_full <- candidatos_norm_full[nzchar(candidato_normalizado)]
  tier5 <- if (nrow(candidatos_norm_full)) {
    cand5 <- unique(candidatos_norm_full[, .(coluna_observada_normalizada = candidato_normalizado, atributo_canonico_2025, caminho_registro)])
    out5 <- merge(obs_dt[, .(coluna_observada, coluna_observada_normalizada)], cand5, by = "coluna_observada_normalizada")
    if (nrow(out5)) out5[, `:=`(metodo_match = "normalizado", prioridade_match = 5L)]
    out5
  } else {
    data.table::data.table()
  }

  todos <- data.table::rbindlist(list(tier1, tier2, tier3, tier4, tier5), use.names = TRUE, fill = TRUE)

  if (!nrow(todos)) {
    mapa <- data.table::copy(obs_dt)
    mapa[, `:=`(
      n_candidatos = 0L, metodo_match = NA_character_, prioridade_match = NA_integer_,
      atributo_canonico_sugerido = NA_character_, caminho_registro_sugerido = NA_character_,
      candidatos_resumo = ""
    )]
  } else {
    candidatos_unicos <- unique(todos[, .(coluna_observada, prioridade_match, metodo_match, atributo_canonico_2025, caminho_registro)])
    melhor_prioridade <- candidatos_unicos[, .(prioridade_match = min(prioridade_match)), by = coluna_observada]
    no_melhor_tier <- merge(candidatos_unicos, melhor_prioridade, by = c("coluna_observada", "prioridade_match"))
    resumo_match <- no_melhor_tier[, {
      n <- data.table::uniqueN(atributo_canonico_2025)
      .(
        n_candidatos = n,
        metodo_match = metodo_match[1],
        atributo_canonico_sugerido = if (n == 1L) atributo_canonico_2025[1] else NA_character_,
        caminho_registro_sugerido = if (n == 1L) caminho_registro[1] else NA_character_,
        candidatos_resumo = paste(sort(unique(atributo_canonico_2025)), collapse = " | ")
      )
    }, by = .(coluna_observada, prioridade_match)]
    mapa <- merge(obs_dt, resumo_match, by = "coluna_observada", all.x = TRUE)
    mapa[is.na(n_candidatos), `:=`(n_candidatos = 0L, candidatos_resumo = "")]
  }

  mapa[, status_match := data.table::fcase(
    n_candidatos == 0L, "sem_match",
    n_candidatos > 1L, "multiplo_ambiguo",
    prioridade_match == 1L, "exato_path",
    prioridade_match == 2L, "exato_name",
    prioridade_match == 3L, "exato_label",
    prioridade_match == 4L, "alias",
    prioridade_match == 5L, "normalizado",
    default = "sem_match"
  )]

 ### Score é uma projeção determinística e barata da prioridade do método
 ### (path=100 > name=90 > label=80 > alias=70 > normalizado=60) -- NÃO é
 ### uma métrica de similaridade fuzzy; ambíguo/sem_match ficam sem score.
  mapa[, score_match := data.table::fcase(
    status_match %in% c("sem_match", "multiplo_ambiguo"), NA_integer_,
    default = 110L - as.integer(prioridade_match) * 10L
  )]

  meta_atributo <- unique(atributos[, .(
    atributo_canonico_2025, name_curto, cardinalidade_operacional,
    origem_regra, status_confianca, severidade
  )])
  mapa <- merge(mapa, meta_atributo, by.x = "atributo_canonico_sugerido", by.y = "atributo_canonico_2025", all.x = TRUE)
  data.table::setnames(mapa, "name_curto", "name_curto_sugerido")

  estagios_por_atributo <- if (nrow(indices$por_estagio_aplicavel)) {
    data.table::as.data.table(indices$por_estagio_aplicavel)[, .(estagio_aplicavel = paste(sort(unique(estagio)), collapse = "|")), by = atributo_canonico_2025]
  } else {
    data.table::data.table(atributo_canonico_2025 = character(), estagio_aplicavel = character())
  }
  mapa <- merge(mapa, estagios_por_atributo, by.x = "atributo_canonico_sugerido", by.y = "atributo_canonico_2025", all.x = TRUE)

 ### "fora_do_contrato" é reportado como status_match distinto (mesmo tendo
 ### resolvido por path/name/label/alias/normalizado) porque é informação
 ### mais relevante para quem consome o diagnóstico: o atributo é
 ### metadado de pipeline (schema-129), nunca foi pergunta de XLSForm.
  mapa[!is.na(cardinalidade_operacional) & cardinalidade_operacional == "fora_do_contrato" &
         status_match %in% c("exato_path", "exato_name", "exato_label", "alias", "normalizado"),
       status_match := "fora_do_contrato"]

  mapa[, bloqueia_migracao_automatica :=
         status_match %in% c("multiplo_ambiguo", "sem_match") |
         (!is.na(cardinalidade_operacional) & cardinalidade_operacional %in% c("ambiguo_indeterminado", "estruturado_condicional_esparso"))]
  mapa[is.na(bloqueia_migracao_automatica), bloqueia_migracao_automatica := TRUE]

  mapa[, observacao_diagnostica := data.table::fcase(
    status_match == "sem_match",
    "Nenhum candidato nas 5 estrategias exatas (path/name/label/alias/normalizado); nao migrar automaticamente.",
    status_match == "multiplo_ambiguo",
    paste0("Multiplos atributos candidatos no mesmo nivel de prioridade (", candidatos_resumo, "); requer decisao humana, nao forcado."),
    status_match == "fora_do_contrato",
    "Atributo de metadado de pipeline (schema-129); nao corresponde a campo de formulario XLSForm.",
    !is.na(cardinalidade_operacional) & cardinalidade_operacional == "estruturado_condicional_esparso",
    "Campo condicional/esparso (relevance nao trivial); NAO resolvido por ponto absoluto -- requer 03.5M.",
    !is.na(cardinalidade_operacional) & cardinalidade_operacional == "ambiguo_indeterminado",
    "Tipo ambiguo entre versoes do XLSForm embutido; requer revisao manual antes de qualquer migracao.",
    default = "Match resolvido sem pendencia conhecida nesta etapa."
  )]

  mapa[, contexto := as.character(contexto)[1]]

  data.table::setcolorder(mapa, intersect(c(
    "coluna_observada", "coluna_observada_normalizada", "atributo_canonico_sugerido",
    "caminho_registro_sugerido", "name_curto_sugerido", "metodo_match", "prioridade_match",
    "score_match", "status_match", "n_candidatos", "candidatos_resumo",
    "cardinalidade_operacional", "origem_regra", "status_confianca", "severidade", "estagio_aplicavel",
    "observacao_diagnostica", "bloqueia_migracao_automatica", "contexto"
  ), names(mapa)))
  data.table::setorder(mapa, coluna_observada)
  mapa[]
}

monitora_registros_importados_diagnostico_contrato_unico <- function(registros_importados,
                                                                       contexto = "registros_importados",
                                                                       output_dir = MONITORA_OUTPUT_DIR,
                                                                       log_dir = MONITORA_LOG_DIR,
                                                                       exec_id = MONITORA_EXEC_ID) {
  flag_ativa <- identical(
    toupper(trimws(as.character(get0("MONITORA_DIAGNOSTICO_CONTRATO_UNICO_REGISTROS_IMPORTADOS", ifnotfound = "N", inherits = TRUE))[1L])),
    "S"
  )
  if (!isTRUE(flag_ativa)) return(invisible(NULL))
  if (!inherits(registros_importados, c("data.frame", "data.table"))) return(invisible(NULL))
  if (!exists("monitora_contrato_unico_diagnosticar_observado_canonico", mode = "function")) return(invisible(NULL))

 ### Só nomes de coluna -- nunca lê/copia valor de célula do objeto.
  colunas_observadas <- names(registros_importados)

  diagnostico <- tryCatch({
    contrato <- monitora_contrato_unico_embutido()
    indices <- monitora_contrato_unico_indices(contrato)$indices
    monitora_contrato_unico_diagnosticar_observado_canonico(
      colunas_observadas, contrato = contrato, indices = indices,
      contexto = paste0("registros_importados_", as.character(contexto)[1L])
    )
  }, error = function(e) {
    warning("Diagnóstico de contrato único (registros_importados) falhou e foi ignorado (produto não afetado): ",
            conditionMessage(e), call. = FALSE)
    NULL
  })
  if (is.null(diagnostico) || !data.table::is.data.table(diagnostico) || !nrow(diagnostico)) return(invisible(diagnostico))

  tryCatch({
    dir_diag <- file.path(output_dir, "diagnosticos_contrato_unico_registros_importados")
    dir.create(dir_diag, recursive = TRUE, showWarnings = FALSE)
    dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
    sufixo <- gsub("[^A-Za-z0-9]+", "_", as.character(contexto)[1L])
    exec_id_chr <- as.character(exec_id)[1L]

    caminho_mapa <- file.path(dir_diag, paste0("mapa_observado_canonico_", sufixo, "_", exec_id_chr, ".csv"))
    data.table::fwrite(diagnostico, caminho_mapa, na = "")

 ### -: o diagnóstico permanece opt-in e nunca altera
 ### registros_importados.csv, mas colunas de severidade "alta" (derivada
 ### em monitora_contrato_unico_indices , sem fato novo) que também
 ### bloqueiam migração automática deixam de ser só relatório silencioso
 ### -- viram alerta determinante (evento "AVISO" + warning visível),
 ### conforme recomendado no plano executivo do motor único (seção 4).
    tem_severidade <- "severidade" %in% names(diagnostico)
    n_alta_severidade_bloqueante <- if (tem_severidade) {
      sum(diagnostico$severidade == "alta" & diagnostico$bloqueia_migracao_automatica, na.rm = TRUE)
    } else {
      NA_integer_
    }

    resumo <- data.table::data.table(
      metrica = c(
        "total_colunas_observadas", "match_exato_path", "match_exato_name", "match_exato_label",
        "match_por_alias", "match_por_normalizacao", "ambiguas", "sem_match", "fora_do_contrato",
        "total_atributos_canonicos_distintos_mapeados", "campos_condicionais_esparsos_observados",
        "campos_ambiguos_indeterminados_observados", "colunas_bloqueiam_migracao_automatica",
        "colunas_alta_severidade_bloqueantes"
      ),
      valor = c(
        nrow(diagnostico),
        sum(diagnostico$status_match == "exato_path", na.rm = TRUE),
        sum(diagnostico$status_match == "exato_name", na.rm = TRUE),
        sum(diagnostico$status_match == "exato_label", na.rm = TRUE),
        sum(diagnostico$status_match == "alias", na.rm = TRUE),
        sum(diagnostico$status_match == "normalizado", na.rm = TRUE),
        sum(diagnostico$status_match == "multiplo_ambiguo", na.rm = TRUE),
        sum(diagnostico$status_match == "sem_match", na.rm = TRUE),
        sum(diagnostico$status_match == "fora_do_contrato", na.rm = TRUE),
        data.table::uniqueN(diagnostico$atributo_canonico_sugerido[!is.na(diagnostico$atributo_canonico_sugerido)]),
        sum(diagnostico$cardinalidade_operacional == "estruturado_condicional_esparso", na.rm = TRUE),
        sum(diagnostico$cardinalidade_operacional == "ambiguo_indeterminado", na.rm = TRUE),
        sum(diagnostico$bloqueia_migracao_automatica, na.rm = TRUE),
        n_alta_severidade_bloqueante
      )
    )
    caminho_resumo <- file.path(dir_diag, paste0("resumo_mapa_observado_canonico_", sufixo, "_", exec_id_chr, ".csv"))
    data.table::fwrite(resumo, caminho_resumo, na = "")
    data.table::fwrite(resumo, file.path(log_dir, paste0("resumo_mapa_observado_canonico_", sufixo, "_", exec_id_chr, ".csv")), na = "")

    txt <- c(
      paste0("Diagnóstico de contrato único (03.5L-B/03.5L-C) -- contexto: ", as.character(contexto)[1L]),
      paste0("Gerado em: ", format(Sys.time(), "%Y-%m-%d %H:%M:%S")),
      "Este relatório é só diagnóstico -- não altera registros_importados.csv nem nenhum outro produto.",
      paste0("Total de colunas observadas: ", nrow(diagnostico)),
      paste0("Fora do contrato (metadado de pipeline): ", sum(diagnostico$status_match == "fora_do_contrato", na.rm = TRUE)),
      paste0("Sem match: ", sum(diagnostico$status_match == "sem_match", na.rm = TRUE)),
      paste0("Ambíguas: ", sum(diagnostico$status_match == "multiplo_ambiguo", na.rm = TRUE)),
      paste0("Bloqueiam migração automática (não forçadas): ", sum(diagnostico$bloqueia_migracao_automatica, na.rm = TRUE)),
      paste0("Alta severidade e bloqueantes (alerta determinante): ", n_alta_severidade_bloqueante),
      paste0("Mapa completo: ", basename(caminho_mapa)),
      paste0("Resumo: ", basename(caminho_resumo))
    )
    writeLines(txt, file.path(dir_diag, paste0("resumo_", sufixo, "_", exec_id_chr, ".txt")))

    if (exists("monitora_log_registrar_evento", mode = "function")) {
      alerta_alta_severidade <- isTRUE(tem_severidade) && isTRUE(n_alta_severidade_bloqueante > 0L)
      monitora_log_registrar_evento(
        "diagnostico_contrato_unico_registros_importados",
        if (alerta_alta_severidade) "AVISO" else "INFO",
        caminho_mapa,
        paste0("Diagnóstico de contrato único gerado para ", as.character(contexto)[1L], " (", nrow(diagnostico), " colunas observadas",
               if (alerta_alta_severidade) paste0("; ", n_alta_severidade_bloqueante, " de alta severidade bloqueiam migração automática") else "", ")"),
        "produto diagnóstico opt-in; não altera registros_importados.csv"
      )
      if (alerta_alta_severidade) {
        warning(
          n_alta_severidade_bloqueante,
          " coluna(s) de alta severidade em ", as.character(contexto)[1L],
          " bloqueiam migração automática pelo contrato único; revisar ", basename(caminho_mapa),
          " (diagnóstico não altera registros_importados.csv)",
          call. = FALSE
        )
      }
    }
  }, error = function(e) {
    warning("Falha ao gravar diagnóstico de contrato único (registros_importados); produto não afetado: ",
            conditionMessage(e), call. = FALSE)
  })

  invisible(diagnostico)
}

monitora_registros_importados_comparar_ordem_legado_vs_contrato <- function(registros_importados,
                                                                              diagnostico,
                                                                              contrato = NULL,
                                                                              indices = NULL,
                                                                              contexto = "registros_importados",
                                                                              output_dir = MONITORA_OUTPUT_DIR,
                                                                              log_dir = MONITORA_LOG_DIR,
                                                                              exec_id = MONITORA_EXEC_ID) {
  if (!inherits(registros_importados, c("data.frame", "data.table"))) return(invisible(NULL))
  if (is.null(diagnostico) || !data.table::is.data.table(diagnostico) || !nrow(diagnostico)) return(invisible(NULL))

  resultado <- tryCatch({
    ordem_legado <- names(registros_importados)
    d <- data.table::copy(diagnostico)
    idx <- match(ordem_legado, d$coluna_observada)

    comparacao <- data.table::data.table(
      posicao_legado = seq_along(ordem_legado),
      coluna_observada = ordem_legado,
      atributo_canonico_sugerido = d$atributo_canonico_sugerido[idx],
      status_match = d$status_match[idx],
      cardinalidade_operacional = d$cardinalidade_operacional[idx],
      status_confianca = d$status_confianca[idx],
      bloqueia_migracao_automatica = d$bloqueia_migracao_automatica[idx]
    )

 ### Duplicidade: mais de uma coluna observada distinta sugerindo o mesmo
 ### atributo canônico -- sinal de possível redundância/alias não
 ### resolvido, nunca decidido automaticamente aqui.
    contagem_canon <- comparacao[!is.na(atributo_canonico_sugerido), .N, by = atributo_canonico_sugerido]
    dup_canon <- contagem_canon[N > 1L, atributo_canonico_sugerido]
    comparacao[, duplicata_atributo_canonico := !is.na(atributo_canonico_sugerido) & atributo_canonico_sugerido %in% dup_canon]

 ### Ordem sugerida: só para relatório, nunca aplicada. Usa a posição do
 ### template quando o contrato/índices estiverem disponíveis; senão fica
 ### NA e a ordem sugerida degrada para a ordem legada (sem reordenar).
    if (is.null(indices)) {
      indices <- tryCatch({
        if (is.null(contrato)) contrato <- monitora_contrato_unico_embutido()
        monitora_contrato_unico_indices(contrato)$indices
      }, error = function(e) NULL)
    }
    comparacao[, posicao_contrato_sugerida := NA_integer_]
    if (!is.null(indices) && !is.null(indices$template_sismonitora_129) && nrow(indices$template_sismonitora_129)) {
      tpl <- data.table::as.data.table(indices$template_sismonitora_129)
      m <- match(comparacao$atributo_canonico_sugerido, tpl$atributo_canonico_2025)
      ok <- !is.na(m)
      if (any(ok)) comparacao[ok, posicao_contrato_sugerida := as.integer(tpl$posicao_schema129[m[ok]])]
    }
    ordem_sugerida_idx <- order(is.na(comparacao$posicao_contrato_sugerida), comparacao$posicao_contrato_sugerida, comparacao$posicao_legado)
    comparacao[, ordem_sugerida_rank := match(seq_len(.N), ordem_sugerida_idx)]

    list(
      comparacao = comparacao[],
      fora_do_contrato = comparacao[status_match %in% c("sem_match", "fora_do_contrato")][],
      ambiguas = comparacao[status_match == "multiplo_ambiguo"][],
      duplicadas = comparacao[duplicata_atributo_canonico == TRUE][],
      resumo = data.table::data.table(
        metrica = c("total_colunas", "fora_do_contrato_ou_sem_match", "ambiguas", "colunas_em_duplicata_de_atributo"),
        valor = c(
          nrow(comparacao),
          sum(comparacao$status_match %in% c("sem_match", "fora_do_contrato")),
          sum(comparacao$status_match == "multiplo_ambiguo"),
          sum(comparacao$duplicata_atributo_canonico, na.rm = TRUE)
        )
      )
    )
  }, error = function(e) {
    warning("Comparação de ordem legado vs. contrato único (registros_importados) falhou e foi ignorada (produto não afetado): ",
            conditionMessage(e), call. = FALSE)
    NULL
  })
  if (is.null(resultado)) return(invisible(NULL))

  tryCatch({
    dir_diag <- file.path(output_dir, "diagnosticos_contrato_unico_registros_importados")
    dir.create(dir_diag, recursive = TRUE, showWarnings = FALSE)
    sufixo <- gsub("[^A-Za-z0-9]+", "_", as.character(contexto)[1L])
    exec_id_chr <- as.character(exec_id)[1L]
    data.table::fwrite(resultado$comparacao, file.path(dir_diag, paste0("comparacao_ordem_legado_vs_contrato_", sufixo, "_", exec_id_chr, ".csv")), na = "")
    data.table::fwrite(resultado$resumo, file.path(dir_diag, paste0("resumo_comparacao_ordem_", sufixo, "_", exec_id_chr, ".csv")), na = "")
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento(
        "comparacao_ordem_contrato_unico_registros_importados", "INFO", dir_diag,
        paste0("Comparação de ordem legado vs. contrato único gerada para ", as.character(contexto)[1L]),
        "produto diagnóstico opt-in; nunca reordena/renomeia o produto real"
      )
    }
  }, error = function(e) {
    warning("Falha ao gravar comparação de ordem (registros_importados); produto não afetado: ",
            conditionMessage(e), call. = FALSE)
  })

  invisible(resultado)
}

monitora_pipe_contrato_classificar_coluna <- function(coluna, contrato = NULL, indices = NULL) {
  if (is.null(indices)) {
    if (is.null(contrato)) contrato <- monitora_contrato_unico_embutido()
    indices <- monitora_contrato_unico_indices(contrato)$indices
  }
  diag <- monitora_contrato_unico_diagnosticar_observado_canonico(
    as.character(coluna), contrato = contrato, indices = indices,
    contexto = "pipe_contrato_classificar_coluna"
  )
 ### monitora_contrato_unico_diagnosticar_observado_canonico não expõe
 ### `relevant`/`campo_pai` (fora do escopo mínimo da ) -- junta aqui a
 ### partir do índice já existente, sem duplicar nem recalcular nada.
  atributos_idx <- data.table::as.data.table(indices$por_atributo_canonico)
  if (all(c("atributo_canonico_2025", "relevant", "campo_pai") %in% names(atributos_idx))) {
    meta_relevance <- unique(atributos_idx[, .(atributo_canonico_2025, relevant, campo_pai)])
    diag <- merge(diag, meta_relevance, by.x = "atributo_canonico_sugerido", by.y = "atributo_canonico_2025", all.x = TRUE)
  } else {
    diag[, `:=`(relevant = NA_character_, campo_pai = NA_character_)]
  }
  diag[, estrategia_pipe := data.table::fcase(
    cardinalidade_operacional == "texto_livre", "preservar_texto_livre",
    cardinalidade_operacional == "select_multiple", "tratar_como_conjunto_tokens",
    cardinalidade_operacional == "estruturado_completo_por_ponto", "resolver_por_ponto_absoluto_permitido",
    cardinalidade_operacional == "estruturado_condicional_esparso", "resolver_por_elegibilidade_relevance_necessaria",
    cardinalidade_operacional == "tecnico_midia", "nao_inferir_sem_regra_explicita",
    cardinalidade_operacional == "fora_do_contrato", "diagnosticar_fora_do_contrato",
    cardinalidade_operacional == "ambiguo_indeterminado", "diagnosticar_ambiguo_nao_forcar",
    status_match == "multiplo_ambiguo", "diagnosticar_ambiguo_nao_forcar",
    status_match == "sem_match", "diagnosticar_sem_match_nao_forcar",
    default = "diagnosticar_indeterminado_nao_forcar"
  )]
  diag[]
}

monitora_pipe_contrato_avaliar_relevance_simples <- function(relevant_expr, valores_parent) {
  relevant_expr <- as.character(relevant_expr)[1]
  if (is.na(relevant_expr) || !nzchar(trimws(relevant_expr))) return(NULL)
  if (grepl("\\bor\\b|\\bnot\\b|[<>]=?|!=", relevant_expr, ignore.case = TRUE)) return(NULL)
  partes <- trimws(strsplit(relevant_expr, "\\band\\b")[[1]])
  padrao <- "^selected\\(\\$\\{([^}]+)\\},\\s*'([^']+)'\\)$"
  n_ref <- NULL
  resultado <- NULL
  for (p in partes) {
    m <- regmatches(p, regexec(padrao, p))[[1]]
    if (length(m) != 3L) return(NULL)
    campo <- m[2]; token <- m[3]
    vals <- valores_parent[[campo]]
    if (is.null(vals)) return(NULL)
    if (is.null(n_ref)) n_ref <- length(vals)
    if (length(vals) != n_ref) return(NULL)
    hit <- if (exists("monitora_correcao_token_presente_vec", mode = "function")) {
      monitora_correcao_token_presente_vec(as.character(vals), token)
    } else {
      grepl(paste0("(^|\\s)", token, "(\\s|$)"), as.character(vals))
    }
    resultado <- if (is.null(resultado)) hit else (resultado & hit)
  }
  resultado
}

monitora_pipe_contrato_resolver_tokens_isolado <- function(valor, coluna, contexto_linha = NULL, contrato = NULL, indices = NULL) {
  if (is.null(indices)) {
    if (is.null(contrato)) contrato <- monitora_contrato_unico_embutido()
    indices <- monitora_contrato_unico_indices(contrato)$indices
  }
  classificacao <- monitora_pipe_contrato_classificar_coluna(coluna, contrato = contrato, indices = indices)[1L]
  estrategia <- classificacao$estrategia_pipe
  valor_chr <- as.character(valor)[1L]
  tem_pipe <- !is.na(valor_chr) && grepl("|", valor_chr, fixed = TRUE)

  base <- list(
    coluna = as.character(coluna)[1L],
    atributo_canonico = classificacao$atributo_canonico_sugerido,
    cardinalidade_operacional = classificacao$cardinalidade_operacional,
    estrategia_pipe = estrategia,
    tem_pipe = tem_pipe,
    valor_original = valor_chr,
    resultado = NA_character_,
    status_resolucao = NA_character_,
    observacao = NA_character_
  )

  if (!isTRUE(tem_pipe)) {
    base$status_resolucao <- "sem_pipe_nada_a_fazer"
    base$resultado <- valor_chr
    return(base)
  }

  tokens <- trimws(strsplit(valor_chr, "|", fixed = TRUE)[[1L]])

  if (identical(estrategia, "preservar_texto_livre")) {
    base$status_resolucao <- "preservado_texto_livre"
    base$resultado <- valor_chr
    return(base)
  }

  if (identical(estrategia, "tratar_como_conjunto_tokens")) {
    base$status_resolucao <- "conjunto_tokens"
    base$resultado <- paste(tokens, collapse = " | ")
    base$observacao <- paste0("select_multiple: ", length(tokens), " token(s) como conjunto, sem mapeamento posicional.")
    return(base)
  }

  if (identical(estrategia, "resolver_por_ponto_absoluto_permitido")) {
    ponto <- if (!is.null(contexto_linha)) contexto_linha$ponto_indice else NULL
    if (is.null(ponto) || is.na(ponto) || ponto < 1L || ponto > length(tokens)) {
      base$status_resolucao <- "sem_contexto_ponto_nao_resolvido"
      base$observacao <- "contexto_linha$ponto_indice ausente/inválido; resolução por ponto absoluto requer o índice do ponto dentro da COLETA."
      return(base)
    }
    base$status_resolucao <- "resolvido_por_ponto_absoluto"
    base$resultado <- tokens[ponto]
    return(base)
  }

  if (identical(estrategia, "resolver_por_elegibilidade_relevance_necessaria")) {
    relevant_expr <- classificacao$relevant
    valores_parent <- if (!is.null(contexto_linha)) contexto_linha$valores_parent else NULL
    ponto <- if (!is.null(contexto_linha)) contexto_linha$ponto_indice else NULL
    if (is.na(relevant_expr) || !nzchar(as.character(relevant_expr)) || is.null(valores_parent) || is.null(ponto)) {
      base$status_resolucao <- "depende_de_parent_relevance_contexto_insuficiente"
      base$observacao <- paste0(
        "Campo condicional/esparso (relevant='", relevant_expr, "'). NÃO resolvido por ponto absoluto -- ",
        "requer contexto_linha$valores_parent (valores do campo pai para todos os pontos do grupo) e ",
        "contexto_linha$ponto_indice para determinar o primeiro ponto elegível."
      )
      return(base)
    }
    elegibilidade <- monitora_pipe_contrato_avaliar_relevance_simples(relevant_expr, valores_parent)
    if (is.null(elegibilidade)) {
      base$status_resolucao <- "relevance_nao_parseavel_contexto_insuficiente"
      base$observacao <- paste0("Expressão de relevance não reconhecida pelo parser conservador (só 'selected(${campo}, ',valor,') [and ...]'): ", relevant_expr)
      return(base)
    }
    pontos_elegiveis <- which(elegibilidade)
    if (length(pontos_elegiveis) != length(tokens)) {
      base$status_resolucao <- "contagem_elegiveis_diverge_tokens_nao_resolvido"
      base$observacao <- paste0("n_tokens=", length(tokens), " mas n_pontos_elegiveis=", length(pontos_elegiveis), "; divergência estrutural, não resolve às cegas (mesma causa-raiz do Hotfix 03.5G).")
      return(base)
    }
    idx_no_grupo <- match(ponto, pontos_elegiveis)
    if (is.na(idx_no_grupo)) {
      base$status_resolucao <- "ponto_nao_elegivel_valor_esperado_vazio"
      base$resultado <- NA_character_
      return(base)
    }
    base$status_resolucao <- "resolvido_por_elegibilidade_relevance"
    base$resultado <- tokens[idx_no_grupo]
    return(base)
  }

  base$status_resolucao <- "diagnostico_nao_resolvido"
  base$observacao <- paste0("Estratégia '", estrategia, "' não resolve automaticamente; reportar para revisão humana, nunca forçar.")
  base
}

monitora_pipe_contrato_diagnosticar_dataset <- function(registros, max_colunas = Inf, incluir_valores = FALSE,
                                                          contrato = NULL, indices = NULL, produto = "registros_corrig.csv") {
  if (!inherits(registros, c("data.frame", "data.table"))) return(data.table::data.table())
  if (is.null(indices)) {
    if (is.null(contrato)) contrato <- monitora_contrato_unico_embutido()
    indices <- monitora_contrato_unico_indices(contrato)$indices
  }
  nms <- names(registros)
  if (is.finite(max_colunas) && max_colunas < length(nms)) nms <- nms[seq_len(max_colunas)]
  n_linhas_total <- nrow(registros)

  linhas_diag <- vector("list", length(nms))
  for (i in seq_along(nms)) {
    cc <- nms[i]
    vals <- registros[[cc]]
    vals_chr <- if (is.character(vals)) vals else if (is.factor(vals)) as.character(vals) else NA_character_
    tem_pipe_logico <- if (length(vals_chr) == n_linhas_total) (!is.na(vals_chr) & grepl("|", vals_chr, fixed = TRUE)) else rep(FALSE, n_linhas_total)
    n_pipe <- sum(tem_pipe_logico, na.rm = TRUE)

    class_legado <- tryCatch(monitora_produtos_classificar_pipe_coluna(cc, produto = produto), error = function(e) NA_character_)
    class_contrato_row <- tryCatch(monitora_pipe_contrato_classificar_coluna(cc, contrato = contrato, indices = indices)[1L], error = function(e) NULL)

    cardinalidade <- if (!is.null(class_contrato_row)) class_contrato_row$cardinalidade_operacional else NA_character_
    estrategia <- if (!is.null(class_contrato_row)) class_contrato_row$estrategia_pipe else NA_character_
    status_match <- if (!is.null(class_contrato_row)) class_contrato_row$status_match else NA_character_
    atributo_canon <- if (!is.null(class_contrato_row)) class_contrato_row$atributo_canonico_sugerido else NA_character_
 ### -: mesma severidade já derivada em
 ### monitora_contrato_unico_indices (nenhum fato novo) e já presente em
 ### class_contrato_row via monitora_pipe_contrato_classificar_coluna ->
 ### monitora_contrato_unico_diagnosticar_observado_canonico desde
 ### -- só propagada aqui para permitir o mesmo alerta
 ### determinante de alta severidade usado no ponto de importação.
    severidade <- if (!is.null(class_contrato_row) && "severidade" %in% names(class_contrato_row)) {
      class_contrato_row$severidade
    } else {
      NA_character_
    }
    bloqueia_migracao_automatica <- if (!is.null(class_contrato_row) && "bloqueia_migracao_automatica" %in% names(class_contrato_row)) {
      isTRUE(class_contrato_row$bloqueia_migracao_automatica)
    } else {
      NA
    }

 ### Mapa aproximado para comparar a decisão do classificador legado
 ### (categorias pipe_*) com a estratégia recomendada pelo contrato --
 ### só para diagnóstico de divergência, nunca aplicado a dado real.
    decisao_legado_normalizada <- data.table::fcase(
      identical(class_legado, "pipe_permitido_texto_livre"), "preservar_texto_livre",
      class_legado %in% c("pipe_residual_operacional", "pipe_residual_revisar"), "resolver_por_ponto_absoluto_permitido",
      identical(class_legado, "pipe_residual_tecnico_tolerado"), "nao_inferir_sem_regra_explicita",
      identical(class_legado, "pipe_esperado_em_bruto"), "nao_aplicavel_produto_bruto",
      identical(class_legado, "pipe_indeterminado"), "diagnosticar_indeterminado_nao_forcar",
      default = NA_character_
    )
    divergencia <- !is.na(decisao_legado_normalizada) & !is.na(estrategia) & !identical(decisao_legado_normalizada, estrategia)

    linha <- data.table::data.table(
      coluna = cc,
      n_linhas_total = n_linhas_total,
      n_linhas_com_pipe = as.integer(n_pipe),
      tem_pipe = n_pipe > 0L,
      classificacao_legado = class_legado,
      decisao_legado_normalizada = decisao_legado_normalizada,
      atributo_canonico_contrato = atributo_canon,
      cardinalidade_operacional = cardinalidade,
      estrategia_pipe_contrato = estrategia,
      status_match_contrato = status_match,
      severidade = severidade,
      bloqueia_migracao_automatica = bloqueia_migracao_automatica,
      divergencia_legado_vs_contrato = isTRUE(divergencia),
      deve_preservar_pipe = identical(estrategia, "preservar_texto_livre"),
      deve_tratar_select_multiple = identical(estrategia, "tratar_como_conjunto_tokens"),
      exige_relevance_elegibilidade = identical(estrategia, "resolver_por_elegibilidade_relevance_necessaria"),
      eh_ambiguo_ou_fora_contrato = isTRUE(estrategia %in% c(
        "diagnosticar_ambiguo_nao_forcar", "diagnosticar_fora_do_contrato",
        "diagnosticar_sem_match_nao_forcar", "diagnosticar_indeterminado_nao_forcar"
      ))
    )
    if (isTRUE(incluir_valores) && n_pipe > 0L) {
 ### Só estatísticas agregadas (comprimento/contagem de tokens) sobre os
 ### valores com pipe -- nunca o conteúdo da célula.
      v_com_pipe <- vals_chr[tem_pipe_logico]
      linha[, `:=`(
        comprimento_medio_valor_com_pipe = round(mean(nchar(v_com_pipe), na.rm = TRUE), 1),
        n_tokens_medio_valor_com_pipe = round(mean(lengths(strsplit(v_com_pipe, "|", fixed = TRUE)), na.rm = TRUE), 1)
      )]
    }
    linhas_diag[[i]] <- linha
  }
  data.table::rbindlist(linhas_diag, use.names = TRUE, fill = TRUE)[]
}

monitora_pipe_contrato_resumir_diagnostico_dataset <- function(diagnostico) {
  if (is.null(diagnostico) || !data.table::is.data.table(diagnostico) || !nrow(diagnostico)) return(list())
  d <- data.table::copy(diagnostico)
  d[, risco := data.table::fcase(
    exige_relevance_elegibilidade & tem_pipe, "alto_exige_relevance",
    deve_tratar_select_multiple & tem_pipe & classificacao_legado %in% c("pipe_residual_operacional", "pipe_residual_revisar"), "medio_select_multiple_tratado_como_posicional_pelo_legado",
    divergencia_legado_vs_contrato & tem_pipe, "medio_divergencia_legado_contrato",
    eh_ambiguo_ou_fora_contrato & tem_pipe, "baixo_diagnostico_apenas",
    default = "baixo_ou_sem_pipe"
  )]
  d[, acao_recomendada := data.table::fcase(
    eh_ambiguo_ou_fora_contrato, "diagnosticar_nao_migrar",
    exige_relevance_elegibilidade, "aguardar_contexto_relevance_antes_de_migrar",
    deve_tratar_select_multiple, "revisar_antes_de_migrar_tratar_como_conjunto",
    deve_preservar_pipe, "seguro_preservar_como_esta",
    estrategia_pipe_contrato == "resolver_por_ponto_absoluto_permitido", "seguro_manter_resolucao_por_ponto",
    default = "revisar_manualmente"
  )]
  list(
    por_cardinalidade = d[, .(
      n_colunas = .N, n_colunas_com_pipe = sum(tem_pipe, na.rm = TRUE),
      n_linhas_com_pipe_total = sum(n_linhas_com_pipe, na.rm = TRUE),
      n_divergencias = sum(divergencia_legado_vs_contrato, na.rm = TRUE)
    ), by = .(cardinalidade_operacional)][],
    por_decisao_contrato = d[, .(n_colunas = .N, n_colunas_com_pipe = sum(tem_pipe, na.rm = TRUE)), by = .(estrategia_pipe_contrato)][],
    por_decisao_legado = d[, .(n_colunas = .N, n_colunas_com_pipe = sum(tem_pipe, na.rm = TRUE)), by = .(classificacao_legado)][],
    por_divergencia = d[, .(n_colunas = .N, n_colunas_com_pipe = sum(tem_pipe, na.rm = TRUE)), by = .(divergencia_legado_vs_contrato)][],
    por_risco = d[, .(n_colunas = .N, n_colunas_com_pipe = sum(tem_pipe, na.rm = TRUE)), by = .(risco)][],
    por_acao_recomendada = d[, .(n_colunas = .N, n_colunas_com_pipe = sum(tem_pipe, na.rm = TRUE)), by = .(acao_recomendada)][],
    detalhado_com_acao = d[]
  )
}

monitora_pipe_contrato_relatorio_optin <- function(registros, contexto = "pipeline",
                                                     output_dir = MONITORA_OUTPUT_DIR,
                                                     log_dir = MONITORA_LOG_DIR,
                                                     exec_id = MONITORA_EXEC_ID) {
  flag_ativa <- identical(
    toupper(trimws(as.character(get0("MONITORA_DIAGNOSTICO_PIPES_CONTRATO", ifnotfound = "N", inherits = TRUE))[1L])),
    "S"
  )
  if (!isTRUE(flag_ativa)) return(invisible(NULL))
  if (!inherits(registros, c("data.frame", "data.table"))) return(invisible(NULL))
  if (!exists("monitora_pipe_contrato_diagnosticar_dataset", mode = "function") ||
      !exists("monitora_pipe_contrato_resumir_diagnostico_dataset", mode = "function")) {
    return(invisible(NULL))
  }

  resultado <- tryCatch({
    diagnostico <- monitora_pipe_contrato_diagnosticar_dataset(registros, incluir_valores = FALSE, produto = "registros_corrig.csv")
    resumo <- monitora_pipe_contrato_resumir_diagnostico_dataset(diagnostico)
    list(diagnostico = diagnostico, resumo = resumo)
  }, error = function(e) {
    warning("Relatório opt-in de pipes por contrato falhou e foi ignorado (nenhum produto real afetado): ",
            conditionMessage(e), call. = FALSE)
    NULL
  })
  if (is.null(resultado) || is.null(resultado$diagnostico) || !data.table::is.data.table(resultado$diagnostico) || !nrow(resultado$diagnostico)) {
    return(invisible(resultado))
  }

  tryCatch({
    dir_diag <- file.path(output_dir, "diagnosticos_pipes_contrato")
    dir.create(dir_diag, recursive = TRUE, showWarnings = FALSE)
    dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
    sufixo <- gsub("[^A-Za-z0-9]+", "_", as.character(contexto)[1L])
    exec_id_chr <- as.character(exec_id)[1L]

    diag <- resultado$diagnostico
    caminho_diag <- file.path(dir_diag, paste0("diagnostico_pipes_contrato_", sufixo, "_", exec_id_chr, ".csv"))
    data.table::fwrite(diag, caminho_diag, na = "")

    resumo_detalhado <- resultado$resumo$detalhado_com_acao
    caminho_resumo <- file.path(dir_diag, paste0("resumo_pipes_contrato_", sufixo, "_", exec_id_chr, ".csv"))
    if (!is.null(resumo_detalhado) && data.table::is.data.table(resumo_detalhado) && nrow(resumo_detalhado)) {
      data.table::fwrite(
        resumo_detalhado[, .(coluna, cardinalidade_operacional, estrategia_pipe_contrato, classificacao_legado,
                              tem_pipe, n_linhas_com_pipe, divergencia_legado_vs_contrato, risco, acao_recomendada)],
        caminho_resumo, na = ""
      )
    }

 ### Alerta seguro: só contagens agregadas + recomendação, nunca dado real.
    n_total_colunas <- nrow(diag)
    n_colunas_com_pipe <- sum(diag$tem_pipe, na.rm = TRUE)
    n_pipe_texto_livre <- sum(diag$tem_pipe & diag$cardinalidade_operacional == "texto_livre", na.rm = TRUE)
    n_pipe_select_multiple <- sum(diag$tem_pipe & diag$cardinalidade_operacional == "select_multiple", na.rm = TRUE)
    n_pipe_condicional_esparso <- sum(diag$tem_pipe & diag$cardinalidade_operacional == "estruturado_condicional_esparso", na.rm = TRUE)
    n_pipe_ambiguo_fora <- sum(diag$tem_pipe & diag$eh_ambiguo_ou_fora_contrato, na.rm = TRUE)
    exige_relevance <- n_pipe_condicional_esparso > 0L

 ### -: mesmo padrão de alerta determinante do incremento
 ### (importação) -- colunas com pipe cuja severidade (derivada em
 ### monitora_contrato_unico_indices , sem fato novo) é "alta" E que
 ### bloqueiam migração automática deixam de ser só relatório silencioso.
 ### Continua opt-in pela mesma flag, nunca altera `registros`.
    tem_severidade <- "severidade" %in% names(diag)
    n_pipe_alta_severidade_bloqueante <- if (tem_severidade) {
      sum(diag$tem_pipe & diag$severidade == "alta" & diag$bloqueia_migracao_automatica, na.rm = TRUE)
    } else {
      NA_integer_
    }

    recomendacao <- if (n_colunas_com_pipe == 0L) {
      "sem_acao"
    } else if (n_pipe_condicional_esparso > 0L || n_pipe_ambiguo_fora > 0L) {
      "nao_migrar_resolvedor"
    } else if (n_pipe_texto_livre > 0L || n_pipe_select_multiple > 0L) {
      "manter_diagnostico"
    } else {
      "avaliar_03_5M_D"
    }

    txt <- c(
      paste0("Relatório opt-in de pipes por contrato único (03.5M-C) -- contexto: ", as.character(contexto)[1L]),
      paste0("Gerado em: ", format(Sys.time(), "%Y-%m-%d %H:%M:%S")),
      "Este relatório é só diagnóstico -- não altera nenhum produto real, não resolve nem bloqueia nada.",
      paste0("Total de colunas: ", n_total_colunas),
      paste0("Colunas com pipe: ", n_colunas_com_pipe),
      paste0("Colunas com pipe em texto_livre: ", n_pipe_texto_livre),
      paste0("Colunas com pipe em select_multiple: ", n_pipe_select_multiple),
      paste0("Colunas com pipe em estruturado_condicional_esparso: ", n_pipe_condicional_esparso),
      paste0("Colunas com pipe ambíguas/fora do contrato: ", n_pipe_ambiguo_fora),
      paste0("Há caso que exigiria relevance/elegibilidade: ", if (isTRUE(exige_relevance)) "SIM" else "NÃO"),
      paste0("Colunas com pipe de alta severidade e bloqueantes (alerta determinante): ", n_pipe_alta_severidade_bloqueante),
      paste0("Recomendação operacional: ", recomendacao),
      paste0("Diagnóstico completo: ", basename(caminho_diag)),
      paste0("Resumo: ", basename(caminho_resumo))
    )
    caminho_txt <- file.path(dir_diag, paste0("relatorio_pipes_contrato_", sufixo, "_", exec_id_chr, ".txt"))
    writeLines(txt, caminho_txt)

    if (exists("monitora_log_registrar_evento", mode = "function")) {
      alerta_alta_severidade <- isTRUE(tem_severidade) && isTRUE(n_pipe_alta_severidade_bloqueante > 0L)
      monitora_log_registrar_evento(
        "relatorio_pipes_contrato_optin",
        if (alerta_alta_severidade) "AVISO" else "INFO",
        caminho_txt,
        paste0("Relatório opt-in de pipes por contrato gerado para ", as.character(contexto)[1L], "; recomendacao=", recomendacao,
               if (alerta_alta_severidade) paste0("; ", n_pipe_alta_severidade_bloqueante, " coluna(s) com pipe de alta severidade bloqueiam migração automática") else ""),
        "produto diagnóstico opt-in; não altera nenhum produto real"
      )
      if (alerta_alta_severidade) {
        warning(
          n_pipe_alta_severidade_bloqueante,
          " coluna(s) com pipe de alta severidade em ", as.character(contexto)[1L],
          " bloqueiam migração automática pelo contrato único; revisar ", basename(caminho_txt),
          " (diagnóstico não altera nenhum produto real)",
          call. = FALSE
        )
      }
    }
  }, error = function(e) {
    warning("Falha ao gravar relatório opt-in de pipes por contrato; nenhum produto real afetado: ",
            conditionMessage(e), call. = FALSE)
  })

  invisible(resultado)
}

monitora_pipe_contrato_relatorio_optin_seguro <- function(registros, contexto = "pipeline",
                                                            output_dir = MONITORA_OUTPUT_DIR,
                                                            log_dir = MONITORA_LOG_DIR,
                                                            exec_id = MONITORA_EXEC_ID) {
  if (!exists("monitora_pipe_contrato_relatorio_optin", mode = "function")) return(invisible(NULL))
  ja_gerado <- isTRUE(get0("MONITORA_DIAGNOSTICO_PIPES_CONTRATO_GERADO", ifnotfound = FALSE, inherits = TRUE))
  if (isTRUE(ja_gerado)) return(invisible(NULL))
  resultado <- tryCatch(
    monitora_pipe_contrato_relatorio_optin(registros, contexto = contexto, output_dir = output_dir, log_dir = log_dir, exec_id = exec_id),
    error = function(e) {
      warning("monitora_pipe_contrato_relatorio_optin_seguro: falha ignorada (nenhum produto real afetado): ",
              conditionMessage(e), call. = FALSE)
      NULL
    }
  )
  if (!is.null(resultado)) {
    assign("MONITORA_DIAGNOSTICO_PIPES_CONTRATO_GERADO", TRUE, envir = .GlobalEnv)
  }
  invisible(resultado)
}

monitora_pipe_contrato_fixture_condicional_esparso_035m_d0 <- function(n_pontos = 101L,
                                                                         pontos_elegiveis = c(90L, 91L),
                                                                         tokens = c("terrestre", "terrestre")) {
  stopifnot(length(pontos_elegiveis) == length(tokens), all(pontos_elegiveis >= 1L), all(pontos_elegiveis <= n_pontos))
  valores_parent <- rep("graminoide", n_pontos)
  valores_parent[pontos_elegiveis] <- "bromelioide"
  valor_pipe <- paste(tokens, collapse = "|")
  esperado <- rep(NA_character_, n_pontos)
  esperado[pontos_elegiveis] <- tokens
  list(
    n_pontos = n_pontos,
    pontos_elegiveis = pontos_elegiveis,
    valores_parent_forma_vida_nativa = valores_parent,
    valor_pipe_bromelioide = valor_pipe,
    esperado_por_ponto = esperado,
    descricao = paste0(
      "Fixture 100% sintético (03.5M-D0), sem nenhum dado real. Reproduz o padrão estrutural documentado em ",
      "diagnostics/hotfix_035g2_restringe_aliases_pipe/HOTFIX_035G2_RESTRINGE_ALIASES_PIPE.md (COLETA 11168): ",
      n_pontos, " pontos, bromelioide elegível só nos pontos ", paste(pontos_elegiveis, collapse = " e "),
      ", valor bruto '", valor_pipe, "'."
    )
  )
}

monitora_registros_importados_exportar <- function(dt, output_dir = MONITORA_OUTPUT_DIR, log_dir = MONITORA_LOG_DIR, exec_id = MONITORA_EXEC_ID, contexto = "pos_concatenacao_csv", permitir_apenas_bruto = TRUE) {
  tryCatch({
    contexto_chr <- as.character(contexto)[1L]
    contexto_bruto <- grepl("pos_concatenacao_csv|pre_padronizacao|leitura_csv|importacao_bruta", contexto_chr, ignore.case = TRUE)
    if (isTRUE(permitir_apenas_bruto) && !isTRUE(contexto_bruto)) {
      warning("registros_importados_bruto.csv não foi gerado fora do contexto bruto: ", contexto_chr, call. = FALSE)
      return(invisible(FALSE))
    }
    if (!inherits(dt, c("data.frame", "data.table"))) return(invisible(FALSE))
    dir.create(output_dir, showWarnings = FALSE, recursive = TRUE)
    dir.create(file.path(output_dir, "01_produtos_dados"), showWarnings = FALSE, recursive = TRUE)
    dir.create(log_dir, showWarnings = FALSE, recursive = TRUE)
    out <- if (data.table::is.data.table(dt)) data.table::copy(dt) else data.table::as.data.table(dt)

    escrita <- monitora_produtos_escrever_bruto_canonico(out, "registros_importados_bruto.csv", output_dir = output_dir, row.names = FALSE)
    caminho <- monitora_produtos_path_canonico("registros_importados_bruto.csv", output_dir)
    caminho_raiz <- monitora_produtos_path_raiz("registros_importados_bruto.csv", output_dir)

    if (length(escrita$colunas_duplicadas)) {
      dup_all <- names(out)[duplicated(names(out)) | duplicated(names(out), fromLast = TRUE)]
      duplicadas_dt <- data.table::data.table(coluna = names(table(dup_all)), n_ocorrencias = as.integer(table(dup_all)))
      monitora_fwrite(duplicadas_dt, file.path(output_dir, "auditoria_registros_importados_colunas_duplicadas.csv"), row.names = FALSE)
    }

    resumo <- data.table::data.table(
      exec_id = as.character(exec_id), produto = "registros_importados_bruto.csv", contexto = contexto_chr,
      descricao = "Snapshot técnico fiel da leitura/montagem dos arquivos de entrada antes de padronizações semânticas.",
      n_linhas = as.integer(nrow(out)), n_colunas = as.integer(ncol(out)),
      n_colunas_duplicadas = as.integer(length(unique(escrita$colunas_duplicadas))),
      caminho_canonico = monitora_privacidade_caminho_relativo(caminho), caminho_raiz_compat = monitora_privacidade_caminho_relativo(caminho_raiz),
      observacao = "Produto bruto técnico; pode preservar pipes e cabeçalhos duplicados. O produto operacional é registros_importados.csv.",
      timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    )
    monitora_registros_importados_resumo_auditoria_gravar(
      resumo, output_dir = output_dir, log_dir = log_dir, exec_id = exec_id,
      produto = "registros_importados_bruto.csv", contexto = contexto_chr, camada = "bruto"
    )
    assign("MONITORA_REGISTROS_IMPORTADOS_BRUTO_MATERIALIZADO", TRUE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_IMPORTADOS_BRUTO_CONTEXTO", contexto_chr, envir = .GlobalEnv)
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("registros_importados_bruto_exportado", "INFO", caminho, paste0("registros_importados_bruto.csv canônico gerado com ", nrow(out), " linhas e ", ncol(out), " colunas"), "produto canônico em 01_produtos_dados espelhado na raiz")
    }
    invisible(TRUE)
  }, error = function(e) {
    warning("Falha ao gerar registros_importados_bruto.csv: ", conditionMessage(e), call. = FALSE)
    invisible(FALSE)
  })
}

monitora_registros_importados_saneado_exportar <- function(dt,
                                                           output_dir = MONITORA_OUTPUT_DIR,
                                                           log_dir = MONITORA_LOG_DIR,
                                                           exec_id = MONITORA_EXEC_ID,
                                                           contexto = "pos_consolidacao_aliases_importacao",
                                                           bloquear_pipe_residual = TRUE,
                                                           produto_nome = "registros_importados.csv") {
 ### - ajuste: `produto_nome` permite que este mesmo
 ### exportador escreva um produto com identidade própria (nome de arquivo
 ### diferente), sem duplicar lógica de tokenização/resolução de pipe.
 ### Chamadas existentes que não informam `produto_nome` continuam
 ### escrevendo exatamente "registros_importados.csv" (comportamento
 ### inalterado). e
 ### auditoria interna.
  produto_nome <- as.character(produto_nome)[1L]
  tryCatch({
    dir.create(output_dir, showWarnings = FALSE, recursive = TRUE)
    dir.create(file.path(output_dir, "01_produtos_dados"), showWarnings = FALSE, recursive = TRUE)
    dir.create(log_dir, showWarnings = FALSE, recursive = TRUE)
 ### o produto operacional será CSV e não precisa transportar classes
 ### POSIXt para os resolvedores de aliases/pipes e para as auditorias do
 ### exportador. Normalizar somente uma cópia, antes de qualquer consumidor auxiliar,
 ### impede as.POSIXlt.POSIXct sobre payload legado sem alterar `dt`,
 ### `registros_corrig` ou qualquer produto central em memória.
    colunas_posix_export <- names(dt)[vapply(dt, inherits, logical(1L), what = "POSIXt")]
    entrada_export <- if (length(colunas_posix_export)) {
 ### O helper já copia antes de converter; não criar uma cópia redundante.
      monitora_sanitizar_posix_produto(dt)
    } else {
      dt
    }
    out <- monitora_registros_importados_saneado_preparar(entrada_export, contexto = contexto)
    rm(entrada_export)
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento(
        "registros_importados_posix_pre_exportacao",
        "INFO",
        NA_character_,
        paste0(length(colunas_posix_export), " coluna(s) POSIXt normalizada(s) na cópia exclusiva do exportador operacional"),
        "R19: normalização antecipada restrita ao CSV; objeto registros_corrig não alterado"
      )
    }
    if (exists("monitora_produtos_resolver_pipes_por_ponto", mode = "function")) {
      out <- monitora_produtos_resolver_pipes_por_ponto(
        out, produto = produto_nome, output_dir = output_dir, log_dir = log_dir,
        exec_id = exec_id, contexto = paste0(contexto, "_pipes_operacionais"), corrigir = TRUE
      )
    }
 ### - ajuste: registros_importados.csv não pode sair com
 ### resíduo de "|" não resolvido pela normalização acima.
 ### - ajuste: `bloquear_pipe_residual` permite que este
 ### mesmo exportador seja usado tanto no checkpoint pré-tokenização
 ### (produto comparável do usuário, logo após consolidacao_aliases_importacao,
 ### `bloquear_pipe_residual = FALSE` -- reporta, não aborta, pois as 5
 ### colunas de forma de vida do dataset de validação e afins ainda serão tratadas pela
 ### cadeia padronizacao_* original) quanto no checkpoint pós-tokenização
 ### operacional (produto final, `bloquear_pipe_residual = TRUE`, default
 ### -- aborta se sobrar resíduo estruturado real).
    if (exists("monitora_bloquear_pipe_residual_produto", mode = "function")) {
      monitora_bloquear_pipe_residual_produto(
        out, produto = produto_nome,
        auditoria_pipe = attr(out, "monitora_auditoria_pipes"),
        output_dir = output_dir, log_dir = log_dir, exec_id = exec_id,
        contexto = contexto, bloquear = bloquear_pipe_residual
      )
    }
    caminho <- monitora_produtos_escrever_csv_canonico(out, produto_nome, output_dir = output_dir, row.names = FALSE, na = "")
    caminho_raiz <- monitora_produtos_path_raiz(produto_nome, output_dir)

    chaves <- monitora_registros_importados_chaves_preferenciais()
    resumo <- data.table::data.table(
      exec_id = as.character(exec_id), produto = produto_nome, contexto = as.character(contexto)[1L],
      descricao = "Produto operacional saneado de entrada, com cabeçalhos canônicos/legíveis e repetição de pontos expandida.",
      n_linhas = as.integer(nrow(out)), n_colunas = as.integer(ncol(out)),
      chaves_presentes = paste(intersect(chaves, names(out)), collapse = " | "),
      chaves_ausentes = paste(setdiff(chaves, names(out)), collapse = " | "),
      caminho_canonico = monitora_privacidade_caminho_relativo(caminho), caminho_raiz_compat = monitora_privacidade_caminho_relativo(caminho_raiz),
      observacao = "Gerado após normalização/tokenização operacional e antes de correções assistidas; COLETAS quarentenadas por incompletude ficam fora deste produto.",
      timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    )
    monitora_registros_importados_resumo_auditoria_gravar(
      resumo, output_dir = output_dir, log_dir = log_dir, exec_id = exec_id,
      produto = produto_nome, contexto = as.character(contexto)[1L],
      camada = if (identical(produto_nome, "registros_importados_operacional_pre_painel.csv")) "operacional_pre_painel" else "operacional",
      na = ""
    )
    assign("MONITORA_REGISTROS_IMPORTADOS_SANEADO_MATERIALIZADO", TRUE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_IMPORTADOS_SANEADO_CONTEXTO", as.character(contexto)[1L], envir = .GlobalEnv)
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("registros_importados_saneado_exportado", "INFO", caminho, paste0(produto_nome, " canônico gerado com ", nrow(out), " linhas e ", ncol(out), " colunas"), "produto operacional canônico em 01_produtos_dados espelhado na raiz")
    }
    invisible(TRUE)
  }, error = function(e) {
    warning("Falha ao gerar ", produto_nome, " saneado: ", conditionMessage(e), call. = FALSE)
    invisible(FALSE)
  })
}

monitora_validar_encostam_rowlevel_minimo <- function(dt,
                                                        contexto = "encostam_rowlevel_minimo",
                                                        output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                        log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                        exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                                        gravar = TRUE) {
  dt <- monitora_dt_referenciar(dt)
  tipo_col <- "amostragem/registro/tipo_forma_vida"
  serr_col <- "amostragem/registro/forma_serrapilheira"
  outros_col <- "amostragem/registro/forma_vida_outros"
  if (!(tipo_col %in% names(dt))) return(invisible(dt))
  n <- nrow(dt)
  tipo <- as.character(dt[[tipo_col]])
  serr <- if (serr_col %in% names(dt)) as.character(dt[[serr_col]]) else rep(NA_character_, n)
  outros <- if (outros_col %in% names(dt)) as.character(dt[[outros_col]]) else rep(NA_character_, n)

  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list())
  col_chr <- function(nm) {
    cc <- chaves[[nm]]
    if (is.null(cc) || is.na(cc) || !(cc %in% names(dt))) return(rep(NA_character_, n))
    as.character(dt[[cc]])
  }
  coleta <- col_chr("coleta"); uc <- col_chr("uc"); ea <- col_chr("ea"); ua <- col_chr("ua")
  ciclo <- col_chr("ciclo"); campanha <- col_chr("campanha"); ano <- col_chr("ano")

  achados <- vector("list", 6L); k <- 0L
  add_achado <- function(regra, idx, mensagem, tipo_antes = NA_character_, tipo_depois = NA_character_) {
    idx <- idx[!is.na(idx) & idx >= 1L & idx <= n]
    if (!length(idx)) return(invisible(NULL))
    k <<- k + 1L
    achados[[k]] <<- data.table::data.table(
      contexto = contexto, regra = regra, linha_indice = idx,
      COLETA = coleta[idx], UC = uc[idx], EA = ea[idx], UA = ua[idx],
      CICLO = ciclo[idx], CAMPANHA = campanha[idx], ANO = ano[idx],
      tipo_forma_vida_antes = if (length(tipo_antes) == 1L) rep(tipo_antes, length(idx)) else tipo_antes[idx],
      tipo_forma_vida_depois = if (length(tipo_depois) == 1L) rep(tipo_depois, length(idx)) else tipo_depois[idx],
      mensagem = mensagem
    )
  }

  tipo_antes_original <- tipo

 ### Regra B — solo_nu é exclusivo (constraint XLSForm 21FEV25:
 ### count-selected(.)=1 quando solo_nu selecionado). Remove somente solo_nu,
 ### nunca os demais tokens. Pré-filtro vetorizado por espaço evita percorrer
 ### em loop as milhares de linhas legitimamente solo_nu-somente.
  tem_solo <- monitora_relatorio_exoticas_tem_token(tipo, "solo_nu")
  vazio_antes <- monitora_correcao_vazio_vec(tipo)
  idx_candidatos_excl <- which(tem_solo & !vazio_antes & grepl("\\s", tipo, perl = TRUE))
  idx_regra_b_aplicada <- integer(0)
  for (i in idx_candidatos_excl) {
    toks <- monitora_correcao_tokenizar(tipo[i])
    if (length(toks) > 1L && "solo_nu" %in% toks) {
      novo <- monitora_correcao_colapsar_tokens(setdiff(toks, "solo_nu"))
      if (!identical(novo, tipo[i])) {
        add_achado("solo_nu_exclusivo_removido", i, "solo_nu coexistia com outro(s) token(s); solo_nu removido, demais tokens preservados.", tipo[i], novo)
        tipo[i] <- novo
        idx_regra_b_aplicada <- c(idx_regra_b_aplicada, i)
      }
    }
  }

 ### Regra A — Encostam vazio é pendência, não evidência de solo nu.
 ### deixa a linha intacta: solo_nu só pode ser produzido pelo reconciliador
 ### de uma operação autorizada cujo write-set demonstre que nenhum contato
 ### real restou. Esta função de validação/preview não possui esse ledger e
 ### portanto não pode inventar o valor.
  idx_vazio <- which(monitora_correcao_vazio_vec(tipo))
  if (length(idx_vazio)) {
    add_achado(
      "encostam_vazio_pendente_sem_inferencia_solo_nu", idx_vazio,
      "Encostam/tipo_forma_vida vazio; solo_nu não foi inferido sem evidência auditável de operação autorizada.",
      tipo_antes_original[idx_vazio], tipo_antes_original[idx_vazio]
    )
  }

 ### - a regra -------------------------------------------------------
 ### monitora_pendencia_impeditiva/_tipo/_msg são gravados por
 ### monitora_publicacao_ab_auditar_pendencias_impeditivas ANTES desta função,
 ### no mesmo funil de exportação. Sem esta sincronização, uma linha corrigida
 ### pelas Regras A/B acima continuaria citando uma pendência já resolvida.
 ### Remove apenas a tag exata da condição resolvida por cada regra,
 ### preservando qualquer outra pendência da mesma linha, e nunca toca linhas
 ### afetadas somente pelas Regras C-F (que permanecem apenas relatadas).
  monitora_hotfix03_sincronizar_pendencia <- function(idx, tag_remover, msg_remover) {
    cols_meta <- c("monitora_pendencia_impeditiva", "monitora_pendencia_impeditiva_tipo", "monitora_pendencia_impeditiva_msg")
    if (!length(idx) || !all(cols_meta %in% names(dt))) return(invisible(NULL))
    tipo_meta <- as.character(dt[["monitora_pendencia_impeditiva_tipo"]])
    msg_meta <- as.character(dt[["monitora_pendencia_impeditiva_msg"]])
    for (i in idx) {
      tags_i <- strsplit(tipo_meta[i], "\\s*\\|\\s*", perl = TRUE)[[1]]
      if (!(tag_remover %in% tags_i)) next
      msgs_i <- strsplit(msg_meta[i], "\\s*\\|\\s*", perl = TRUE)[[1]]
      tipo_meta[i] <- paste(setdiff(tags_i, tag_remover), collapse = " | ")
      msg_meta[i] <- paste(msgs_i[!(msgs_i %in% msg_remover)], collapse = " | ")
    }
    data.table::set(dt, j = "monitora_pendencia_impeditiva_tipo", value = tipo_meta)
    data.table::set(dt, j = "monitora_pendencia_impeditiva_msg", value = msg_meta)
    data.table::set(dt, j = "monitora_pendencia_impeditiva", value = nzchar(tipo_meta))
    invisible(NULL)
  }
 ### Encostam vazio não foi resolvido nesta função; sua tag impeditiva deve
 ### permanecer. Não há sincronização de pendência para idx_vazio.
 ### Regra B resolvida: a auditoria atual não produz uma tag própria de
 ### exclusividade de solo_nu (essa checagem hoje só existe em
 ### monitora_validados_validar_condicionais_xlsform21); a chamada abaixo é um
 ### no-op nos dados de hoje e serve apenas para já sincronizar corretamente
 ### caso essa tag (mesmo nome/mensagem usados naquele motor) passe a ser
 ### produzida também aqui no futuro, sem exigir nova alteração neste ponto.
  monitora_hotfix03_sincronizar_pendencia(
    idx_regra_b_aplicada, "solo_nu_com_outra_categoria", "solo_nu é exclusivo"
  )
 ### - a regra ----------------------------------------------------

 ### Regra C — outra_forma_vida exige forma_vida_outros preenchido (apenas relatar; não inventar valor).
  tem_outra <- monitora_relatorio_exoticas_tem_token(tipo, "outra_forma_vida")
  add_achado("outra_forma_vida_sem_forma_vida_outros", which(tem_outra & monitora_correcao_vazio_vec(outros)),
             "tipo_forma_vida contém outra_forma_vida, mas forma_vida_outros está vazio; corrigir manualmente ou via painel.")

 ### Regra D — forma_vida_outros preenchido exige token pai (apenas relatar;
 ### não existe, nesta função, um padrão já comprovado e seguro para inserir
 ### outra_forma_vida automaticamente sem risco de efeito colateral).
  add_achado("forma_vida_outros_sem_token_pai", which(!monitora_correcao_vazio_vec(outros) & !tem_outra),
             "forma_vida_outros preenchido, mas tipo_forma_vida não contém outra_forma_vida; corrigir manualmente ou via painel (não corrigido automaticamente neste hotfix).")

 ### Regra E — serrapilheira exige forma_serrapilheira preenchido (apenas relatar; não inventar valor).
  tem_serr <- monitora_relatorio_exoticas_tem_token(tipo, "serrapilheira")
  add_achado("serrapilheira_sem_forma_serrapilheira", which(tem_serr & monitora_correcao_vazio_vec(serr)),
             "tipo_forma_vida contém serrapilheira, mas forma_serrapilheira está vazio; corrigir manualmente ou via painel.")

 ### Regra F — forma_serrapilheira preenchido exige token pai (apenas relatar, mesmo motivo da Regra D).
  add_achado("forma_serrapilheira_sem_token_pai", which(!monitora_correcao_vazio_vec(serr) & !tem_serr),
             "forma_serrapilheira preenchido, mas tipo_forma_vida não contém serrapilheira; corrigir manualmente ou via painel (não corrigido automaticamente neste hotfix).")

  if (!identical(tipo, tipo_antes_original)) data.table::set(dt, j = tipo_col, value = tipo)

  achados_dt <- if (k) data.table::rbindlist(achados[seq_len(k)], fill = TRUE, use.names = TRUE) else data.table::data.table()
  if (isTRUE(gravar) && nrow(achados_dt)) {
    try({
      dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
      dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
      data.table::fwrite(achados_dt, file.path(output_dir, "auditoria_encostam_rowlevel_minimo.csv"), na = "")
      data.table::fwrite(achados_dt, file.path(log_dir, paste0("auditoria_encostam_rowlevel_minimo_", exec_id, ".csv")), na = "")
    }, silent = TRUE)
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      try(monitora_log_registrar_evento(
        "encostam_rowlevel_minimo", "AVISO",
        file.path(output_dir, "auditoria_encostam_rowlevel_minimo.csv"),
        paste0(nrow(achados_dt), " ocorrência(s) de validação/sanitização row-level mínima de Encostam (hotfix 02) em ", contexto, "."),
        "ver auditoria_encostam_rowlevel_minimo.csv"
      ), silent = TRUE)
    }
  }
  invisible(dt)
}

monitora_publicacao_aa_exportar_registros_corrig_aprovado <- function(registros_corrig,
                                                                caminho_saida,
                                                                contexto = "materializacao_registros_corrig",
                                                                abortar = TRUE) {
  dt <- data.table::as.data.table(registros_corrig)

 ### Recalcula e grava selo/flags dentro da própria base antes da exportação.
  if (exists("monitora_publicacao_ab_auditar_pendencias_impeditivas", mode = "function")) {
    res_imp <- tryCatch(monitora_publicacao_ab_auditar_pendencias_impeditivas(
      dt,
      contexto = paste0(contexto, "_marcacao_pre_export"),
      output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE),
      log_dir = get0("MONITORA_LOG_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE),
      gravar = TRUE,
      marcar_base = TRUE
    ), error = function(e) {
      if (isTRUE(abortar)) stop(e) else { warning(conditionMessage(e), call. = FALSE); NULL }
    })
    if (!is.null(res_imp) && !is.null(res_imp$dt)) dt <- data.table::as.data.table(res_imp$dt)
  } else {
    data.table::set(dt, j = "monitora_status_registros_corrig", value = "status_nao_auditado")
    data.table::set(dt, j = "monitora_pendencia_impeditiva", value = FALSE)
    data.table::set(dt, j = "monitora_pendencia_impeditiva_tipo", value = "")
    data.table::set(dt, j = "monitora_pendencia_impeditiva_msg", value = "")
  }

 ### uma pendência de derivação interna detectada pela auditoria de
 ### persistência não pode ser apagada por uma auditoria diagnóstica posterior
 ### que examine apenas as regras biológicas. O checkpoint continua gravável,
 ### mas recebe marca explícita e nunca libera registros_validados.
  if (isTRUE(get0("MONITORA_PERSISTENCIA_DERIVACOES_PENDENTES", ifnotfound = FALSE, inherits = TRUE))) {
    assign("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS", TRUE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", FALSE, envir = .GlobalEnv)
    data.table::set(dt, j = "monitora_pendencia_derivacao_interna", value = TRUE)
    data.table::set(dt, j = "monitora_status_registros_corrig", value = "checkpoint_pendente_derivacao_interna")
  }

 ### registros_corrig.csv é checkpoint operacional: a auditoria acima marca
 ### pendências, mas a exportação não introduz solo_nu, não remove tokens e
 ### não fecha Encostam silenciosamente. O fechamento contratual pertence ao
 ### produto validado e só é liberado quando as pendências estiverem sanadas.

  pendente_imp <- isTRUE(get0("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS", ifnotfound = FALSE, inherits = TRUE))
  contrato_corrig_ok <- isTRUE(get0("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", ifnotfound = FALSE, inherits = TRUE)) &&
    !(exists("monitora_publicacao_z_selo_registros_corrig_valido", mode = "function") &&
      !isTRUE(monitora_publicacao_z_selo_registros_corrig_valido(dt)))
  validados_materializado_ok <- if (exists("monitora_registros_validados_materializado_sem_bloqueio", mode = "function")) {
    isTRUE(monitora_registros_validados_materializado_sem_bloqueio(output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE)))
  } else FALSE
  if (!isTRUE(pendente_imp) && isTRUE(validados_materializado_ok)) {
    contrato_corrig_ok <- TRUE
    assign("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", TRUE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_VALIDADOS_GERADO", TRUE, envir = .GlobalEnv)
  }
 ### o exportador de registros_corrig.csv não deve emitir
 ### warning sobre registros_validados.csv. A geração/bloqueio real de
 ### registros_validados é decidida pelo bloco contratual próprio, com auditoria
 ### XLSForm21. Este ponto só grava registros_corrig; manter warning aqui gerava
 ### falso positivo no final da execução, mesmo com registros_validados.csv
 ### materializado e n_bloqueios=0.
  contrato_validados_bloqueado <- FALSE
  if (!isTRUE(pendente_imp) && !isTRUE(contrato_corrig_ok) && !isTRUE(validados_materializado_ok)) {
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      try(monitora_log_registrar_evento(
        "registros_corrig_export_sem_trava_validados", "INFO", as.character(caminho_saida)[1L],
        paste0("Exportação de registros_corrig.csv sem pendências impeditivas no contexto ", contexto,
               "; status de registros_validados.csv será determinado apenas pelo bloco contratual XLSForm21 próprio."),
        "warning legado de falso bloqueio de registros_validados suprimido no exportador de registros_corrig"
      ), silent = TRUE)
    }
  }
  if (pendente_imp && exists("monitora_publicacao_ab_logar_resumo_pendencias", mode = "function")) {
    monitora_publicacao_ab_logar_resumo_pendencias(get0("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS_RESUMO", ifnotfound = data.table::data.table(), inherits = TRUE), contexto = contexto)
  }

  dt_export <- if (exists("monitora_publicacao_ae_preparar_registros_corrig_para_csv", mode = "function")) {
    monitora_publicacao_ae_preparar_registros_corrig_para_csv(
      dt, contexto = contexto,
      output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE),
      log_dir = get0("MONITORA_LOG_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE),
      exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)
    )
  } else dt
  if (exists("monitora_produtos_resolver_pipes_por_ponto", mode = "function")) {
    dt_export <- monitora_produtos_resolver_pipes_por_ponto(
      dt_export, produto = "registros_corrig.csv",
      output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE),
      log_dir = get0("MONITORA_LOG_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE),
      exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
      contexto = paste0(contexto, "_pipes_operacionais"), corrigir = FALSE
    )
  }
 ### Resíduos de pipe são diagnosticados, mas não corrigidos nem bloqueiam o
 ### checkpoint. A resolução semântica exige operação explícita; o produto
 ### registros_validados continua sujeito ao gate contratual próprio.

  output_dir <- get0("MONITORA_OUTPUT_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE)
  produto <- basename(caminho_saida)
  if (!monitora_produtos_nome_central(produto)) produto <- "registros_corrig.csv"
  caminho_canon <- monitora_produtos_escrever_csv_canonico(dt_export, produto, output_dir = output_dir, row.names = FALSE, na = "NA")

 ### Se o chamador passou caminho específico, garanta que ele também receba a
 ### versão canônica. Para os fluxos atuais, isso normalmente é a raiz.
  caminho_alvo <- if (dirname(caminho_saida) %in% c(".", "")) file.path(output_dir, basename(caminho_saida)) else caminho_saida
  if (!normalizePath(caminho_alvo, winslash = "/", mustWork = FALSE) %in% normalizePath(c(monitora_produtos_path_raiz(produto, output_dir), caminho_canon), winslash = "/", mustWork = FALSE)) {
    dir.create(dirname(caminho_alvo), recursive = TRUE, showWarnings = FALSE)
    file.copy(caminho_canon, caminho_alvo, overwrite = TRUE, copy.date = TRUE)
  }
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    if (isTRUE(pendente_imp)) {
      monitora_log_registrar_evento("registros_corrig_exportado_checkpoint_pendente", "AVISO", caminho_canon, paste0("registros_corrig.csv canônico materializado como checkpoint de trabalho COM PENDÊNCIAS IMPEDITIVAS: ", nrow(dt_export), " linhas e ", ncol(dt_export), " colunas; flags internas gravadas; registros_validados.csv bloqueado"), contexto)
    } else {
      monitora_log_registrar_evento("registros_corrig_exportado_aprovado", "INFO", caminho_canon, paste0("registros_corrig.csv canônico materializado sem pendências impeditivas: ", nrow(dt_export), " linhas e ", ncol(dt_export), " colunas; status de registros_validados.csv registrado pelo bloco contratual XLSForm21 próprio"), contexto)
    }
  }
  invisible(TRUE)
}




monitora_output_produtos_centrais <- function() {
  c(
    "registros_importados_bruto.csv", "registros_importados.csv",
    "registros_importados_operacional_pre_painel.csv",
    "registros_corrig.csv", "registros_validados.csv", "registros_corrig_stat.csv"
  )
}

monitora_output_raiz_whitelist <- function() {
  c("README_OUTPUT.txt", "indice_produtos.csv")
}

monitora_produtos_nome_central <- function(produto) {
  basename(as.character(produto)[1L]) %in% monitora_output_produtos_centrais()
}

monitora_produtos_path_canonico <- function(produto,
                                            output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE)) {
  file.path(output_dir, "01_produtos_dados", basename(as.character(produto)[1L]))
}

monitora_produtos_path_raiz <- function(produto,
                                        output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE)) {
  file.path(output_dir, basename(as.character(produto)[1L]))
}

monitora_produtos_md5_seguro <- function(path) {
  if (!length(path) || is.na(path[1L]) || !file.exists(path[1L]) || isTRUE(file.info(path[1L])$isdir)) return(NA_character_)
  unname(as.character(tools::md5sum(path[1L])))
}

monitora_produtos_copiar_canonico_para_raiz <- function(produto,
                                                        output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                        exigir_identico = TRUE) {
 ### Compatibilidade raiz desativada por desenho. Se houver espelho antigo
 ### idêntico ao canônico, remova-o; se divergir, o organizador final tratará.
  produto <- basename(as.character(produto)[1L])
  canon <- monitora_produtos_path_canonico(produto, output_dir)
  raiz <- monitora_produtos_path_raiz(produto, output_dir)
  if (file.exists(canon) && file.exists(raiz)) {
    md5_canon <- monitora_produtos_md5_seguro(canon)
    md5_raiz <- monitora_produtos_md5_seguro(raiz)
    if (!is.na(md5_canon) && !is.na(md5_raiz) && identical(md5_canon, md5_raiz)) {
      try(unlink(raiz), silent = TRUE)
    }
  }
  invisible(FALSE)
}

monitora_produtos_escrever_csv_canonico <- function(dt,
                                                    produto,
                                                    output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                    row.names = FALSE,
                                                    na = "",
                                                    ...) {
  produto <- basename(as.character(produto)[1L])
  canon <- monitora_produtos_path_canonico(produto, output_dir)
  dir.create(dirname(canon), recursive = TRUE, showWarnings = FALSE)
  monitora_fwrite_atomico(dt, canon, row.names = row.names, na = na, encoding = "UTF-8", bom = TRUE, eol = "\n", ...)
  invisible(canon)
}

monitora_produtos_escrever_bruto_canonico <- function(dt,
                                                      produto = "registros_importados_bruto.csv",
                                                      output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                      row.names = FALSE,
                                                      ...) {
  produto <- basename(as.character(produto)[1L])
  canon <- monitora_produtos_path_canonico(produto, output_dir)
  dir.create(dirname(canon), recursive = TRUE, showWarnings = FALSE)
  escrita <- monitora_publicacao_h_fwrite_registros_importados(dt, canon, row.names = row.names, encoding = "UTF-8", bom = TRUE, eol = "\n", ...)
  invisible(escrita)
}

monitora_produtos_auditar_espelhos_canonicos <- function(output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                         exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                                         contexto = "auditoria_produtos_canonicos") {
  produtos <- monitora_output_produtos_centrais()
  aud <- data.table::rbindlist(lapply(produtos, function(produto) {
    canon <- monitora_produtos_path_canonico(produto, output_dir)
    raiz <- monitora_produtos_path_raiz(produto, output_dir)
    md5_canon <- monitora_produtos_md5_seguro(canon)
    md5_raiz <- monitora_produtos_md5_seguro(raiz)
    data.table::data.table(
      exec_id = as.character(exec_id), contexto = as.character(contexto)[1L], produto = produto,
 ### a auditoria é produto portátil; os caminhos físicos continuam
 ### sendo usados nas verificações acima, mas não são persistidos no CSV.
      caminho_canonico = gsub("\\\\", "/", file.path("01_produtos_dados", produto)),
      existe_canonico = file.exists(canon), md5_canonico = md5_canon,
      caminho_raiz = produto, existe_raiz = file.exists(raiz), md5_raiz = md5_raiz,
      raiz_deve_existir = FALSE,
      raiz_limpa = !file.exists(raiz),
      produto_canonico_ok = file.exists(canon) && !file.exists(raiz),
      timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    )
  }), fill = TRUE)
  dir.create(file.path(output_dir, "03_auditorias", "importacao"), recursive = TRUE, showWarnings = FALSE)
  try(data.table::fwrite(aud, file.path(output_dir, "03_auditorias", "importacao", "auditoria_produtos_canonicos_md5.csv"), na = ""), silent = TRUE)
  invisible(aud)
}

monitora_output_classificar_arquivo_raiz <- function(bn) {
  bn <- basename(as.character(bn)[1L])
  if (bn %in% monitora_output_produtos_centrais()) return("01_produtos_dados")

 ### A classificação é semântica e ordenada. A extensão.csv nunca pode ser
 ### critério de importação: quase todos os produtos tabulares a possuem.
  if (grepl("manifesto|performance|memoria|hardware|controle_recursos|relatorio_execucao", bn, ignore.case = TRUE)) return("00_manifesto_execucao")
  if (grepl("cache|\\.rds$", bn, ignore.case = TRUE)) return("90_cache")
  if (grepl("espacial|\\.kml$|geometr|coordenad|mapa", bn, ignore.case = TRUE)) return("04_validacao_espacial")
  if (grepl("\\.(png|jpg|jpeg|svg|pdf)$|^indice_graficos|^graficos_temporais|auditoria_(layout_rotulos|simbolos_graficos)", bn, ignore.case = TRUE)) return("06_graficos")
  if (grepl("estat|bootstrap|permut|fdr|^cob_veg_|^prop_rel_|relatorio_textual_estatistico|esforco_amostral_temporal", bn, ignore.case = TRUE)) return("05_estatisticas")
  if (grepl("registros_formas_vida|formas_vida_|outras_formas|relatorio_ocorrencia|resumo_.*formas|exoticas|desconhecida", bn, ignore.case = TRUE)) return("02_painel_correcoes/relatorios_apoio_tematicos/avulsos")
  if (grepl("persistencia|operacoes_atomicas|colunas_protegidas", bn, ignore.case = TRUE)) return("03_auditorias/persistencia")
  if (grepl("painel|correcoes_campos", bn, ignore.case = TRUE)) return("02_painel_correcoes/auditorias_operacionais")
  if (grepl("completude", bn, ignore.case = TRUE)) return("03_auditorias/completude")
  if (grepl("pendencias_impeditivas|impeditiva|relatorio_detalhado_rejeicoes|rejeicoes_validacao", bn, ignore.case = TRUE)) return("03_auditorias/pendencias_impeditivas")
  if (grepl("xlsform|contrato|schema|template|validado|validados|dominio|condicion", bn, ignore.case = TRUE)) return("03_auditorias/contrato_xlsform")
  if (grepl("pipe|importa|md5|fonte|dedup|arquivo.*csv|esquema_colunas", bn, ignore.case = TRUE)) return("03_auditorias/importacao")
  if (grepl("^auditoria_|^resumo_achados", bn, ignore.case = TRUE)) return("03_auditorias/execucao")
  "99_legacy_compat"
}
monitora_output_mover_arquivo <- function(origem, destino) {
  if (!file.exists(origem) || isTRUE(file.info(origem)$isdir)) {
    return(list(ok = FALSE, md5_origem = NA_character_, md5_destino = NA_character_, acao = "origem_ausente"))
  }
  if (dir.exists(destino)) {
    return(list(ok = FALSE, md5_origem = monitora_produtos_md5_seguro(origem), md5_destino = NA_character_, acao = "destino_arquivo_e_diretorio"))
  }
  pai <- dirname(destino)
  if (file.exists(pai) && !dir.exists(pai)) {
    return(list(ok = FALSE, md5_origem = monitora_produtos_md5_seguro(origem), md5_destino = NA_character_, acao = "diretorio_pai_e_arquivo"))
  }
  dir.create(dirname(destino), recursive = TRUE, showWarnings = FALSE)
  md5_origem <- monitora_produtos_md5_seguro(origem)
  ok_copy <- tryCatch(file.copy(origem, destino, overwrite = TRUE, copy.date = TRUE), error = function(e) FALSE)
  md5_destino <- monitora_produtos_md5_seguro(destino)
  ok_hash <- isTRUE(ok_copy) && !is.na(md5_origem) && !is.na(md5_destino) && identical(md5_origem, md5_destino)
  ok_rm <- isTRUE(ok_hash) && tryCatch({ unlink(origem, force = TRUE); !file.exists(origem) }, error = function(e) FALSE)
  list(
    ok = isTRUE(ok_rm), md5_origem = md5_origem, md5_destino = md5_destino,
    acao = if (isTRUE(ok_rm)) "movido_hash_verificado" else if (isTRUE(ok_hash)) "copiado_hash_ok_falha_remover_origem" else "falha_copia_ou_hash"
  )
}

monitora_output_destino_correcao <- function(rel) {
  rel <- gsub("\\\\", "/", as.character(rel)[1L])
  bn <- basename(rel)
  if (grepl("^linhagem/", rel)) return(file.path("02_painel_correcoes", rel))
  if (grepl("^relatorios_pre_painel/completude/", rel)) {
    return(file.path("03_auditorias/completude", sub("^relatorios_pre_painel/completude/", "", rel)))
  }
  if (grepl("^relatorios_pre_painel/ocorrencias_diagnosticas/", rel)) {
    return(file.path("02_painel_correcoes/ocorrencias_diagnosticas/pre_painel", sub("^relatorios_pre_painel/ocorrencias_diagnosticas/", "", rel)))
  }
  if (grepl("^relatorios_pos_painel/ocorrencias_diagnosticas/", rel)) {
    return(file.path("02_painel_correcoes/ocorrencias_diagnosticas/pos_painel", sub("^relatorios_pos_painel/ocorrencias_diagnosticas/", "", rel)))
  }
  if (grepl("^relatorios_pre_painel/", rel)) {
    return(file.path("02_painel_correcoes/relatorios_apoio_tematicos/pre_painel", sub("^relatorios_pre_painel/", "", rel)))
  }
  if (grepl("^relatorios_pos_(correcoes|painel)/", rel)) {
    return(file.path("02_painel_correcoes/relatorios_apoio_tematicos/pos_painel", sub("^relatorios_pos_(correcoes|painel)/", "", rel)))
  }
  if (grepl("^debug_preview/", rel)) {
    return(file.path("03_auditorias/diagnosticos_dev", sub("^debug_preview/", "", rel)))
  }
  if (grepl("^diagnostico_oraculo_replay/", rel)) {
    return(file.path("03_auditorias/replay_semantico", sub("^diagnostico_oraculo_replay/", "", rel)))
  }
  if (identical(bn, "correcoes_semanticas_consolidada.csv")) {
    return("02_painel_correcoes/operacoes_sessao/correcoes_semanticas_sessao_staging.csv")
  }
  if (grepl("xlsform|schema|contrato|template|dependencias_condicionais|dicionario_xlsform", bn, ignore.case = TRUE)) {
    return(file.path("03_auditorias/contrato_xlsform", bn))
  }
  if (grepl("persistencia|operacoes_atomicas|colunas_protegidas", bn, ignore.case = TRUE)) {
    return(file.path("03_auditorias/persistencia", bn))
  }
  if (grepl("^dicionario_|^modelo_", bn, ignore.case = TRUE)) {
    return(file.path("02_painel_correcoes/dicionarios_painel", bn))
  }
  if (grepl("^auditoria_|^resumo_", bn, ignore.case = TRUE)) {
    return(file.path("02_painel_correcoes/auditorias_operacionais", bn))
  }
  if (grepl("registros_formas_vida|formas_vida_|outras_formas|relatorio_ocorrencia|exoticas|desconhecida", bn, ignore.case = TRUE)) {
    return(file.path("02_painel_correcoes/relatorios_apoio_tematicos/avulsos", bn))
  }
  file.path("02_painel_correcoes/operacoes_sessao", rel)
}

monitora_output_podar_diretorios_vazios <- function(output_dir) {
  dirs <- list.dirs(output_dir, recursive = TRUE, full.names = TRUE)
  dirs <- setdiff(dirs, output_dir)
  if (!length(dirs)) return(invisible(character()))
  dirs <- dirs[order(nchar(dirs), decreasing = TRUE)]
  removidos <- character()
  for (dd in dirs) {
    itens <- list.files(dd, all.files = TRUE, no.. = TRUE)
    if (!length(itens)) {
      try(unlink(dd, recursive = TRUE, force = TRUE), silent = TRUE)
      if (!dir.exists(dd)) removidos <- c(removidos, dd)
    }
  }
  invisible(removidos)
}

monitora_output_consolidar_legados_ja_organizados <- function(output_dir, exec_id, contexto) {
  base <- file.path(output_dir, "02_painel_correcoes")
  if (!dir.exists(base)) return(invisible(data.table::data.table()))
  fontes <- c(
    "relatorios_pre_painel", "relatorios_pos_correcoes", "relatorios_pos_painel", "debug_preview",
    "relatorios_apoio_tematicos/legacy_raiz",
    "relatorios_apoio_tematicos/pre_painel/ocorrencias_diagnosticas",
    "relatorios_apoio_tematicos/pre_painel/completude",
    "relatorios_apoio_tematicos/pos_painel/ocorrencias_diagnosticas"
  )
  linhas <- list()
  for (fonte in fontes) {
    raiz <- file.path(base, fonte)
    if (!dir.exists(raiz)) next
    arqs <- list.files(raiz, recursive = TRUE, full.names = TRUE, all.files = TRUE, no.. = TRUE)
    arqs <- arqs[file.info(arqs)$isdir == FALSE]
    for (ff in arqs) {
      rel_interno <- substring(ff, nchar(raiz) + 2L)
      rel_legado <- file.path(fonte, rel_interno)
      destino_rel <- if (identical(fonte, "relatorios_apoio_tematicos/legacy_raiz")) {
        file.path("02_painel_correcoes/relatorios_apoio_tematicos/avulsos", rel_interno)
      } else if (identical(fonte, "relatorios_apoio_tematicos/pre_painel/ocorrencias_diagnosticas")) {
        file.path("02_painel_correcoes/ocorrencias_diagnosticas/pre_painel", rel_interno)
      } else if (identical(fonte, "relatorios_apoio_tematicos/pre_painel/completude")) {
        file.path("03_auditorias/completude", rel_interno)
      } else if (identical(fonte, "relatorios_apoio_tematicos/pos_painel/ocorrencias_diagnosticas")) {
        file.path("02_painel_correcoes/ocorrencias_diagnosticas/pos_painel", rel_interno)
      } else monitora_output_destino_correcao(rel_legado)
      mov <- monitora_output_mover_arquivo(ff, file.path(output_dir, destino_rel))
      linhas[[length(linhas) + 1L]] <- data.table::data.table(
        exec_id = as.character(exec_id), contexto = as.character(contexto)[1L],
        raiz_origem = "02_painel_correcoes_legado_interno", caminho_origem = ff,
        caminho_origem_relativo = file.path("02_painel_correcoes", rel_legado),
        destino_relativo = gsub("\\\\", "/", destino_rel),
        md5_origem = mov$md5_origem, md5_destino = mov$md5_destino,
        hash_verificado = isTRUE(mov$ok), acao = mov$acao,
        timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
      )
    }
    monitora_output_podar_diretorios_vazios(raiz)
  }
 ### Arquivos anteriormente deixados soltos em 02 também recebem papel
 ### explícito. Subpastas canônicas não são reprocessadas.
  soltos <- list.files(base, recursive = FALSE, full.names = TRUE, all.files = FALSE)
  soltos <- soltos[file.info(soltos)$isdir == FALSE]
  for (ff in soltos) {
    destino_rel <- monitora_output_destino_correcao(basename(ff))
    mov <- monitora_output_mover_arquivo(ff, file.path(output_dir, destino_rel))
    linhas[[length(linhas) + 1L]] <- data.table::data.table(
      exec_id = as.character(exec_id), contexto = as.character(contexto)[1L],
      raiz_origem = "02_painel_correcoes_raiz_interna", caminho_origem = ff,
      caminho_origem_relativo = file.path("02_painel_correcoes", basename(ff)),
      destino_relativo = gsub("\\\\", "/", destino_rel),
      md5_origem = mov$md5_origem, md5_destino = mov$md5_destino,
      hash_verificado = isTRUE(mov$ok), acao = mov$acao,
      timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    )
  }
  monitora_output_podar_diretorios_vazios(base)
  if (length(linhas)) data.table::rbindlist(linhas, fill = TRUE) else data.table::data.table()
}

monitora_output_migrar_diretorios_legados <- function(output_dir, exec_id, contexto) {
  raizes <- data.table::data.table(
    origem_rel = c("correcoes_campos", "validacao_espacial", "cache_painel", "relatorios_validacao"),
    destino_base = c(NA_character_, "04_validacao_espacial", "90_cache/cache_painel", "03_auditorias/relatorios_validacao")
  )
  linhas <- list()
  for (ii in seq_len(nrow(raizes))) {
    raiz <- file.path(output_dir, raizes$origem_rel[ii])
    if (!dir.exists(raiz)) next
    arqs <- list.files(raiz, recursive = TRUE, full.names = TRUE, all.files = TRUE, no.. = TRUE)
    arqs <- arqs[file.info(arqs)$isdir == FALSE]
    for (ff in arqs) {
      rel <- substring(ff, nchar(raiz) + 2L)
      destino_rel <- if (identical(raizes$origem_rel[ii], "correcoes_campos")) {
        monitora_output_destino_correcao(rel)
      } else {
        file.path(raizes$destino_base[ii], rel)
      }
      destino <- file.path(output_dir, destino_rel)
      mov <- monitora_output_mover_arquivo(ff, destino)
      linhas[[length(linhas) + 1L]] <- data.table::data.table(
        exec_id = as.character(exec_id), contexto = as.character(contexto)[1L],
        raiz_origem = raizes$origem_rel[ii], caminho_origem = ff,
        caminho_origem_relativo = file.path(raizes$origem_rel[ii], rel),
        destino_relativo = gsub("\\\\", "/", destino_rel),
        md5_origem = mov$md5_origem, md5_destino = mov$md5_destino,
        hash_verificado = isTRUE(mov$ok), acao = mov$acao,
        timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
      )
    }
    monitora_output_podar_diretorios_vazios(raiz)
    if (dir.exists(raiz) && !length(list.files(raiz, all.files = TRUE, no.. = TRUE))) unlink(raiz, recursive = TRUE, force = TRUE)
  }
  aud_interno <- monitora_output_consolidar_legados_ja_organizados(output_dir, exec_id, contexto)
  if (nrow(aud_interno)) linhas[[length(linhas) + 1L]] <- aud_interno
  aud <- if (length(linhas)) data.table::rbindlist(linhas, fill = TRUE) else data.table::data.table(
    exec_id = character(), contexto = character(), raiz_origem = character(), caminho_origem = character(),
    caminho_origem_relativo = character(), destino_relativo = character(), md5_origem = character(),
    md5_destino = character(), hash_verificado = logical(), acao = character(), timestamp = character()
  )
  dir.create(file.path(output_dir, "03_auditorias", "importacao"), recursive = TRUE, showWarnings = FALSE)
  data.table::fwrite(aud, file.path(output_dir, "03_auditorias", "importacao", "auditoria_output_migracao_arquivo_a_arquivo.csv"), na = "")
  invisible(aud)
}

monitora_output_reescrever_referencias <- function(output_dir, mapa) {
  if (is.null(mapa) || !nrow(mapa)) return(invisible(data.table::data.table()))
  mapa <- data.table::as.data.table(mapa)[hash_verificado %in% TRUE]
  if (!nrow(mapa)) return(invisible(data.table::data.table()))
  candidatos <- list.files(output_dir, recursive = TRUE, full.names = TRUE, pattern = "\\.(csv|json|md|txt|rmd|html)$", ignore.case = TRUE)
  candidatos_norm <- gsub("\\\\", "/", candidatos)
  prefixo_dados <- paste0(gsub("\\\\", "/", file.path(output_dir, "01_produtos_dados")), "/")
  candidatos <- candidatos[!startsWith(candidatos_norm, prefixo_dados)]
  candidatos <- candidatos[!grepl("/90_cache/", gsub("\\\\", "/", candidatos), fixed = TRUE)]
  info <- file.info(candidatos)
  candidatos <- candidatos[!is.na(info$size) & info$size <= 12 * 1024^2]
  out_abs <- normalizePath(output_dir, winslash = "/", mustWork = FALSE)
  mapa_paths <- unique(data.table::data.table(
    origem_absoluta = gsub("\\\\", "/", as.character(mapa$caminho_origem)),
    origem_relativa = gsub("\\\\", "/", as.character(mapa$caminho_origem_relativo)),
    destino_relativo = gsub("\\\\", "/", as.character(mapa$destino_relativo))
  ))
  mapa_paths <- mapa_paths[
    !is.na(destino_relativo) & nzchar(destino_relativo)
  ]
  destinos <- unique(mapa_paths$destino_relativo)
  tokens <- paste0("__MONITORA_DESTINO_ATOMICO_", sprintf("%06d", seq_along(destinos)), "__")
  names(tokens) <- destinos

 ### substituição em duas fases. Primeiro todos os destinos corretos são
 ### protegidos por tokens; depois origens absolutas/relativas viram esses
 ### mesmos tokens. Só ao final os destinos são restaurados. Assim um basename
 ### presente dentro do destino recém-criado não recebe o prefixo uma segunda
 ### vez, e chamadas repetidas permanecem idempotentes.
  proteger_destinos <- function(txt) {
    ordem <- order(nchar(destinos), decreasing = TRUE)
    for (jj in ordem) txt <- gsub(destinos[jj], tokens[[destinos[jj]]], txt, fixed = TRUE)
    txt
  }
  substituir_origens <- function(txt) {
    fontes <- data.table::rbindlist(list(
      mapa_paths[, .(fonte = origem_absoluta, destino_relativo)],
      mapa_paths[, .(fonte = origem_relativa, destino_relativo)]
    ), use.names = TRUE)
    fontes <- unique(fontes[!is.na(fonte) & nzchar(fonte) & fonte != "."])
    fontes[, tamanho_fonte := nchar(fonte)]
    data.table::setorder(fontes, -tamanho_fonte)
    fontes[, tamanho_fonte := NULL]
    for (jj in seq_len(nrow(fontes))) {
      txt <- gsub(fontes$fonte[jj], tokens[[fontes$destino_relativo[jj]]], txt, fixed = TRUE)
    }
    txt
  }
  restaurar_destinos <- function(txt) {
    for (jj in seq_along(destinos)) txt <- gsub(tokens[[destinos[jj]]], destinos[jj], txt, fixed = TRUE)
    txt
  }

  linhas <- list()
  for (ff in candidatos) {
    txt <- tryCatch(readLines(ff, warn = FALSE, encoding = "UTF-8"), error = function(e) NULL)
    if (is.null(txt)) next
    antes <- txt
    txt <- proteger_destinos(txt)
    txt <- substituir_origens(txt)
    txt <- gsub(paste0(out_abs, "/"), "", txt, fixed = TRUE)
    txt <- restaurar_destinos(txt)

    dirs_destino <- unique(dirname(destinos))
    dirs_destino <- dirs_destino[nzchar(dirs_destino) & dirs_destino != "."]
    raizes_canonicas <- c(
      "00_manifesto_execucao", "01_produtos_dados", "02_painel_correcoes",
      "03_auditorias", "04_validacao_espacial", "05_estatisticas",
      "06_graficos", "90_cache", "99_legacy_compat"
    )
    alvos_repeticao <- unique(c(raizes_canonicas, dirs_destino))
 ### Se uma organização intermediária anterior já tiver gravado prefixo
 ### duplicado, reparar deterministicamente antes do gate final. Diretórios
 ### canônicos nunca podem conter a si próprios como filho imediato.
    for (dd in alvos_repeticao[order(nchar(alvos_repeticao), decreasing = TRUE)]) {
      duplicado <- paste0(dd, "/", dd, "/")
      simples <- paste0(dd, "/")
      while (any(grepl(duplicado, txt, fixed = TRUE))) {
        txt <- gsub(duplicado, simples, txt, fixed = TRUE)
      }
    }
    repetidos <- alvos_repeticao[vapply(
      alvos_repeticao,
      function(dd) any(grepl(paste0(dd, "/", dd, "/"), txt, fixed = TRUE)),
      logical(1L)
    )]
    if (length(repetidos)) {
      stop(
        "Reescrita pós-organização produziria destino duplicado em ",
        substring(ff, nchar(output_dir) + 2L), ": ",
        paste(repetidos, collapse = "; "),
        call. = FALSE
      )
    }
    mudou <- !identical(antes, txt)
    if (mudou) writeLines(txt, ff, useBytes = TRUE)
    linhas[[length(linhas) + 1L]] <- data.table::data.table(
      caminho_relativo = substring(ff, nchar(output_dir) + 2L),
      referencias_atualizadas = mudou
    )
  }
  aud <- if (length(linhas)) data.table::rbindlist(linhas) else data.table::data.table()
  if (nrow(aud)) {
    data.table::fwrite(aud, file.path(output_dir, "03_auditorias", "importacao", "auditoria_referencias_pos_organizacao.csv"), na = "")
  }
  invisible(aud)
}

monitora_output_papel_produto <- function(rel) {
  rel <- gsub("\\\\", "/", rel)
  if (identical(rel, "README_OUTPUT.txt")) return("documentacao_output")
  if (identical(rel, "indice_produtos.csv")) return("inventario_output")
  if (grepl("^01_produtos_dados/", rel)) return("produto_dados_canonico")
  if (identical(rel, "02_painel_correcoes/linhagem/correcoes_semanticas_consolidada.csv")) return("ledger_semantico_cumulativo_canonico")
  if (grepl("^02_painel_correcoes/linhagem/", rel)) return("sidecar_linhagem_canonico")
  if (grepl("^02_painel_correcoes/operacoes_sessao/", rel)) return("evidencia_operacional_sessao")
  if (grepl("^90_cache/", rel)) return("cache_efemero")
  if (grepl("^99_legacy_compat/", rel)) return("compatibilidade_nao_canonica")
  if (grepl("^03_auditorias/", rel)) return("auditoria")
  if (grepl("^02_painel_correcoes/", rel)) return("produto_painel")
  "produto_categorizado"
}

monitora_output_organizar_produtos <- function(output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                               exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                               contexto = "organizacao_output") {
  if (!dir.exists(output_dir) || !requireNamespace("data.table", quietly = TRUE)) return(invisible(NULL))
  output_dir <- sub("[/\\\\]+$", "", as.character(output_dir)[1L])
  manter_raiz <- monitora_output_raiz_whitelist()
  produtos_centrais <- monitora_output_produtos_centrais()

  aud_dirs <- monitora_output_migrar_diretorios_legados(output_dir, exec_id, contexto)

  arquivos <- list.files(output_dir, full.names = TRUE, recursive = FALSE, all.files = FALSE)
  arquivos <- arquivos[file.info(arquivos)$isdir == FALSE]
  aud_raiz_lista <- list()
  for (ff in arquivos) {
    bn <- basename(ff)
    if (bn %in% manter_raiz) next
    categoria_rel <- if (bn %in% produtos_centrais) "01_produtos_dados" else monitora_output_classificar_arquivo_raiz(bn)
    destino_rel <- file.path(categoria_rel, bn)
    destino <- file.path(output_dir, destino_rel)
    if (bn %in% produtos_centrais && file.exists(destino)) {
      md5_raiz <- monitora_produtos_md5_seguro(ff)
      md5_canon <- monitora_produtos_md5_seguro(destino)
      if (!is.na(md5_raiz) && identical(md5_raiz, md5_canon)) {
        ok_rm <- tryCatch({ unlink(ff, force = TRUE); !file.exists(ff) }, error = function(e) FALSE)
        mov <- list(ok = ok_rm, md5_origem = md5_raiz, md5_destino = md5_canon, acao = "espelho_raiz_identico_removido")
      } else {
        destino_rel <- file.path("99_legacy_compat/produtos_raiz_divergentes", bn)
        destino <- file.path(output_dir, destino_rel)
        mov <- monitora_output_mover_arquivo(ff, destino)
        mov$acao <- paste0("produto_raiz_divergente_", mov$acao)
      }
    } else {
      mov <- monitora_output_mover_arquivo(ff, destino)
    }
    aud_raiz_lista[[length(aud_raiz_lista) + 1L]] <- data.table::data.table(
      exec_id = as.character(exec_id), contexto = as.character(contexto)[1L], arquivo = bn,
      classificacao = gsub("\\\\", "/", categoria_rel), destino_esperado = gsub("\\\\", "/", destino_rel),
      acao = mov$acao, permanece_na_raiz = file.exists(ff), permitido_na_raiz = FALSE,
      existe_destino = file.exists(destino), md5_origem = mov$md5_origem, md5_destino = mov$md5_destino,
      md5_ok = isTRUE(mov$ok), timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    )
  }
  aud_raiz <- if (length(aud_raiz_lista)) data.table::rbindlist(aud_raiz_lista, fill = TRUE) else data.table::data.table(
    exec_id = character(), contexto = character(), arquivo = character(), classificacao = character(),
    destino_esperado = character(), acao = character(), permanece_na_raiz = logical(),
    permitido_na_raiz = logical(), existe_destino = logical(), md5_origem = character(),
    md5_destino = character(), md5_ok = logical(), timestamp = character()
  )
  dir.create(file.path(output_dir, "03_auditorias", "importacao"), recursive = TRUE, showWarnings = FALSE)
  data.table::fwrite(aud_raiz, file.path(output_dir, "03_auditorias", "importacao", "auditoria_output_raiz.csv"), na = "")

  mapa_raiz_atual <- if (nrow(aud_raiz)) data.table::data.table(
    caminho_origem = file.path(output_dir, aud_raiz$arquivo),
    caminho_origem_relativo = aud_raiz$arquivo,
    destino_relativo = aud_raiz$destino_esperado,
    hash_verificado = aud_raiz$md5_ok
  ) else data.table::data.table()
  mapa_atual <- data.table::rbindlist(list(aud_dirs, mapa_raiz_atual), fill = TRUE, use.names = TRUE)
  mapa_anterior <- data.table::as.data.table(get0("MONITORA_OUTPUT_MAPA_MOVIMENTACOES", ifnotfound = data.table::data.table(), inherits = TRUE))
  MONITORA_OUTPUT_MAPA_MOVIMENTACOES <<- data.table::rbindlist(list(mapa_anterior, mapa_atual), fill = TRUE, use.names = TRUE)
  if (nrow(MONITORA_OUTPUT_MAPA_MOVIMENTACOES) && all(c("caminho_origem_relativo", "destino_relativo") %in% names(MONITORA_OUTPUT_MAPA_MOVIMENTACOES))) {
    MONITORA_OUTPUT_MAPA_MOVIMENTACOES <<- unique(MONITORA_OUTPUT_MAPA_MOVIMENTACOES, by = c("caminho_origem_relativo", "destino_relativo"))
  }

 ### Organizações intermediárias apenas escoam o staging. Hash global,
 ### reescrita de referências, README e índice são consumidores finais e não
 ### devem atrasar a abertura/carregamento do painel em cada checkpoint PERF.
  fechamento <- grepl("checkpoint_parcial|fechamento_final", as.character(contexto)[1L])
  if (!isTRUE(fechamento)) return(invisible(data.table::rbindlist(list(aud_dirs, aud_raiz), fill = TRUE, use.names = TRUE)))

  falhas_dirs <- if (nrow(aud_dirs) && "hash_verificado" %in% names(aud_dirs)) aud_dirs[hash_verificado != TRUE] else data.table::data.table()
  falhas_raiz <- if (nrow(aud_raiz)) aud_raiz[md5_ok != TRUE] else data.table::data.table()
  if (nrow(falhas_dirs) || nrow(falhas_raiz)) {
    stop(
      "Organização final bloqueada: ", nrow(falhas_dirs), " migração(ões) interna(s) e ",
      nrow(falhas_raiz), " arquivo(s) da raiz falharam na cópia/hash. Consulte auditoria_output_migracao_arquivo_a_arquivo.csv e auditoria_output_raiz.csv.",
      call. = FALSE
    )
  }
  itens_pre_indice <- list.files(output_dir, full.names = TRUE, recursive = FALSE, all.files = FALSE)
  info_pre_indice <- file.info(itens_pre_indice)
  arquivos_pre_indice <- basename(itens_pre_indice[!info_pre_indice$isdir])
  dirs_pre_indice <- basename(itens_pre_indice[info_pre_indice$isdir])
  arquivos_pre_indice_sujos <- setdiff(arquivos_pre_indice, manter_raiz)
  dirs_pre_indice_sujos <- dirs_pre_indice[!grepl("^(00|01|02|03|04|05|06|90|99)_", dirs_pre_indice)]
  if (length(arquivos_pre_indice_sujos) || length(dirs_pre_indice_sujos)) {
    stop(
      "Organização final bloqueada antes do README/índice: arquivos=",
      paste(arquivos_pre_indice_sujos, collapse = "|"), "; diretorios=",
      paste(dirs_pre_indice_sujos, collapse = "|"), call. = FALSE
    )
  }

  mapa_total <- data.table::as.data.table(get0("MONITORA_OUTPUT_MAPA_MOVIMENTACOES", ifnotfound = mapa_atual, inherits = TRUE))
  monitora_output_reescrever_referencias(output_dir, mapa_total)
  if (exists("monitora_linhagem_reassinar_pos_organizacao", mode = "function", inherits = TRUE)) {
    monitora_linhagem_reassinar_pos_organizacao(output_dir, contexto = contexto)
  }
  monitora_produtos_auditar_espelhos_canonicos(output_dir = output_dir, exec_id = exec_id, contexto = contexto)
  monitora_output_podar_diretorios_vazios(output_dir)

  top <- list.dirs(output_dir, recursive = FALSE, full.names = FALSE)
  descricoes <- c(
    "00_manifesto_execucao" = "manifesto, desempenho e metadados da execução",
    "01_produtos_dados" = "produtos de dados canônicos",
    "02_painel_correcoes" = "operações, diagnósticos, relatórios do painel e linhagem",
    "03_auditorias" = "auditorias técnicas, contrato, persistência e validação",
    "04_validacao_espacial" = "produtos do módulo espacial",
    "05_estatisticas" = "produtos estatísticos",
    "06_graficos" = "figuras e índices gráficos",
    "90_cache" = "cache efêmero do painel; não é produto de dados",
    "99_legacy_compat" = "compatibilidade excepcional; não é fonte canônica"
  )
  linhas_dirs <- if (length(top)) paste0("- ", top, "/: ", unname(descricoes[top])) else "- Nenhuma categoria materializada."
  modo <- as.character(get0("MONITORA_MODO_EXECUCAO", ifnotfound = "não informado", inherits = TRUE))[1L]
  build <- as.character(get0("MONITORA_SCRIPT_BUILD_ID", ifnotfound = "não informado", inherits = TRUE))[1L]
  readme <- c(
    "Organização do output - Programa Monitora / Campestre Savânico",
    paste0("Execução: ", exec_id, " | modo: ", modo, " | build: ", build, " | contexto: ", contexto),
    "",
    "A raiz de output/ contém somente este README e indice_produtos.csv. Categorias opcionais só existem quando têm conteúdo.",
    "Produtos de dados são canônicos exclusivamente em 01_produtos_dados/.",
    "",
    "Diretórios materializados nesta execução:",
    linhas_dirs,
    "",
    "CURADORIA CONTINUADA A PARTIR DE REGISTROS_CORRIG",
    "Copie juntos 01_produtos_dados/registros_corrig.csv e toda a pasta 02_painel_correcoes/linhagem/ para input/.",
    "Use um modo painel_incremental_* e mantenha MONITORA_OPCAO_REAPLICAR_CORRECOES_ANTERIORES = \"N\".",
    "",
    "REPLAY SEMÂNTICO SOBRE INPUT ORIGINAL",
    "Use somente 02_painel_correcoes/linhagem/correcoes_semanticas_consolidada.csv como ledger cumulativo.",
    "Coloque-o em input/linhagem/, não inclua registros_corrig.csv e defina MONITORA_OPCAO_REAPLICAR_CORRECOES_ANTERIORES = \"S\".",
    "Arquivos em operacoes_sessao/ são evidências da rodada e não substituem o ledger cumulativo.",
    "",
    "indice_produtos.csv inventaria todos os arquivos. A própria linha do índice não possui tamanho/hash por ser autorreferente."
  )
  writeLines(readme, file.path(output_dir, "README_OUTPUT.txt"), useBytes = TRUE)

  indice_path <- file.path(output_dir, "indice_produtos.csv")
  if (file.exists(indice_path)) unlink(indice_path)
  todos <- list.files(output_dir, full.names = TRUE, recursive = TRUE, all.files = FALSE)
  todos <- todos[file.info(todos)$isdir == FALSE]
  rel <- gsub("\\\\", "/", substring(todos, nchar(output_dir) + 2L))
  hashes <- vapply(todos, monitora_produtos_md5_seguro, character(1))
  ind <- data.table::data.table(
    exec_id = as.character(exec_id), contexto = as.character(contexto)[1L],
    caminho_relativo = rel, arquivo = basename(todos), categoria = dirname(rel),
    raiz = dirname(rel) == ".", permitido_na_raiz = dirname(rel) == "." & basename(todos) %in% manter_raiz,
    papel_produto = vapply(rel, monitora_output_papel_produto, character(1)),
    status_canonico = ifelse(grepl("^99_legacy_compat/", rel), "nao_canonico_compatibilidade",
      ifelse(grepl("^02_painel_correcoes/operacoes_sessao/", rel), "evidencia_sessao", "canonico_na_categoria")),
    produto_dados_canonico = grepl("^01_produtos_dados/", rel) & basename(todos) %in% produtos_centrais,
    tamanho_bytes = file.info(todos)$size, md5 = hashes, hash_verificavel = TRUE,
    conteudo_identico_a = NA_character_
  )
  if (nrow(ind)) {
    primeiro <- match(ind$md5, ind$md5)
    dup <- duplicated(ind$md5) & !is.na(ind$md5) & nzchar(ind$md5)
    ind$conteudo_identico_a[dup] <- ind$caminho_relativo[primeiro[dup]]
  }
  self <- data.table::data.table(
    exec_id = as.character(exec_id), contexto = as.character(contexto)[1L],
    caminho_relativo = "indice_produtos.csv", arquivo = "indice_produtos.csv", categoria = ".",
    raiz = TRUE, permitido_na_raiz = TRUE, papel_produto = "inventario_output",
    status_canonico = "canonico_autorreferente", produto_dados_canonico = FALSE,
    tamanho_bytes = NA_real_, md5 = NA_character_, hash_verificavel = FALSE,
    conteudo_identico_a = NA_character_
  )
  ind <- data.table::rbindlist(list(ind, self), fill = TRUE, use.names = TRUE)
  data.table::setorder(ind, caminho_relativo)
  data.table::fwrite(ind, indice_path, na = "")

  itens_raiz <- list.files(output_dir, full.names = TRUE, recursive = FALSE, all.files = FALSE)
  info_raiz <- file.info(itens_raiz)
  arquivos_raiz <- basename(itens_raiz[!info_raiz$isdir])
  dirs_raiz <- basename(itens_raiz[info_raiz$isdir])
  arquivos_sujos <- setdiff(arquivos_raiz, manter_raiz)
  dirs_sujos <- dirs_raiz[!grepl("^(00|01|02|03|04|05|06|90|99)_", dirs_raiz)]
  if (length(arquivos_sujos) || length(dirs_sujos)) {
    msg <- paste0("Organização do output deixou itens não permitidos na raiz: arquivos=", paste(arquivos_sujos, collapse = "|"), "; diretorios=", paste(dirs_sujos, collapse = "|"))
    stop(msg, call. = FALSE)
  }
  invisible(ind)
}

monitora_renomear_ou_consolidar_coluna <- function(dt, old, new, etapa = "renomeacao_colunas_protocolo") {
  dt <- monitora_dt_referenciar(dt)
  if (!(old %in% names(dt))) return(invisible(dt))
  if (identical(old, new)) return(invisible(dt))

  if (!(new %in% names(dt))) {
    data.table::setnames(dt, old = old, new = new)
    return(invisible(dt))
  }

  n <- nrow(dt)
  chunk_n <- suppressWarnings(as.integer(Sys.getenv("MONITORA_RENAME_COALESCE_CHUNK_ROWS", unset = "50000")))
  if (is.na(chunk_n) || chunk_n < 1000L) chunk_n <- 50000L

  conflito_total <- 0L
  preenchidos_total <- 0L
  seq_starts <- seq.int(1L, max(1L, n), by = chunk_n)
  for (st in seq_starts) {
    en <- min(st + chunk_n - 1L, n)
    ii <- st:en
    alvo <- monitora_txt_normalizar_vazio(dt[[new]][ii])
    aux <- monitora_txt_normalizar_vazio(dt[[old]][ii])

    fill_idx <- is.na(alvo) & !is.na(aux)
    if (any(fill_idx)) {
      data.table::set(dt, i = ii[fill_idx], j = new, value = aux[fill_idx])
      preenchidos_total <- preenchidos_total + sum(fill_idx)
    }

    conflito <- !is.na(alvo) & !is.na(aux) & alvo != aux
    if (any(conflito)) conflito_total <- conflito_total + sum(conflito)
    rm(alvo, aux, fill_idx, conflito)
  }

  dt[, (old) := NULL]
  monitora_log_registrar_evento(
    etapa,
    if (conflito_total > 0L) "AVISO" else "INFO",
    NA_character_,
    paste0("Coluna técnica consolidada em nome final: ", old, " -> ", new,
           "; preenchidos=", preenchidos_total,
           "; conflitos_preservando_alvo=", conflito_total),
    "consolidacao_segura_sem_criar_colunas_duplicadas"
  )
  if (monitora_recurso_deve_gc()) gc(verbose = FALSE)
  invisible(dt)
}

### Preservação canônica de hábitos ------------------------------------------
### Preserva a propriedade categoria×forma dos hábitos antes de o protocolo
### converter caminhos canônicos em rótulos humanos. A preservação é somente
### de identidade/proveniência: o valor permanece no caminho e depois é
### consolidado pelo renomeador já existente no rótulo físico final. Não se
### cria nem se preenche alias curto, pois duplicar o dado foi a causa da
### resolução e da persistência incorretas na implementação anterior.
monitora_habito_col_canonicos_preservados <- function() "MONITORA_HABITOS_CANONICOS_PRESERVADOS"

monitora_habito_canonicos_preservados <- function(dt) {
  col <- monitora_habito_col_canonicos_preservados()
  if (is.null(dt) || !(col %in% names(dt))) return(character(0))
  x <- unique(as.character(dt[[col]]))
  x <- x[!is.na(x) & nzchar(trimws(x))]
  if (!length(x)) return(character(0))
  unique(trimws(unlist(strsplit(x, ";", fixed = TRUE), use.names = FALSE)))
}

monitora_habito_preservar_caminhos_canonicos_pre_rotulo <- function(dt,
                                                                    output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                                    log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                                    exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)) {
  dt <- monitora_dt_referenciar(dt)
  prefixo <- "amostragem/registro/"
  rx <- "^amostragem/registro/forma_vida_(nativa|exotica|seca_morta)_(bromelioide|cactacea|orquidea|samambaia)$"
  if (!nrow(dt)) return(invisible(dt))
  meta_xls <- tryCatch(monitora_correcao_xlsform_meta_atual(), error = function(e) NULL)
  campos_meta <- if (!is.null(meta_xls) && !is.null(meta_xls$campos)) data.table::as.data.table(meta_xls$campos) else data.table::data.table()
  if (nrow(campos_meta)) {
    for (cc in c("arquivo_xlsform", "caminho_registro")) if (!(cc %in% names(campos_meta))) campos_meta[, (cc) := NA_character_]
  }
  origens <- unique(c(
    grep(rx, names(dt), value = TRUE, perl = TRUE),
    if (nrow(campos_meta)) as.character(campos_meta[grepl(rx, caminho_registro, perl = TRUE), caminho_registro]) else character(0)
  ))
  origens <- sort(origens[!is.na(origens) & nzchar(origens)])
  if (!length(origens)) return(invisible(dt))

  habitos_validos <- c("terrestre", "epifita", "rupicola")
  col_marca <- monitora_habito_col_canonicos_preservados()
  marcas_existentes <- if (col_marca %in% names(dt)) as.character(dt[[col_marca]]) else rep("", nrow(dt))
  marcas_existentes[is.na(marcas_existentes)] <- ""
  arquivo_por_linha <- tryCatch(
    monitora_correcao_xlsform_por_linha(dt, meta_xls = meta_xls),
    error = function(e) rep(NA_character_, nrow(dt))
  )
  fonte_por_linha <- if ("MONITORA_CAMINHO_ARQUIVO_ENTRADA" %in% names(dt)) as.character(dt[["MONITORA_CAMINHO_ARQUIVO_ENTRADA"]]) else rep(NA_character_, nrow(dt))
  cabecalhos_fonte <- get0("MONITORA_CABECALHOS_ORIGINAIS_POR_FONTE", ifnotfound = list(), inherits = TRUE)
  marca_lista <- lapply(marcas_existentes, function(x) {
    z <- trimws(unlist(strsplit(x, ";", fixed = TRUE), use.names = FALSE))
    unique(z[!is.na(z) & nzchar(z)])
  })
  auditoria <- vector("list", length(origens))
  for (ii in seq_along(origens)) {
    origem <- origens[ii]
    alias_curto <- substring(origem, nchar(prefixo) + 1L)
 ### Evidência primária: o caminho existia no cabeçalho observado da fonte.
    por_cabecalho <- rep(FALSE, nrow(dt))
    fontes_unicas <- unique(fonte_por_linha[!is.na(fonte_por_linha) & nzchar(fonte_por_linha)])
    for (ff in fontes_unicas) {
      hdr <- cabecalhos_fonte[[ff]]
      if (length(hdr) && origem %in% hdr) por_cabecalho[fonte_por_linha == ff] <- TRUE
    }
 ### Evidência de retomada: marca já materializada na execução ancestral.
    por_marca_ancestral <- vapply(marca_lista, function(z) alias_curto %in% z, logical(1L))
 ### Fallback versionado: em entrada incremental o cabeçalho físico já foi
 ### rotulado. Nesse caso, a versão XLSForm resolvida por linha determina
 ### se o caminho existia no formulário que produziu o registro.
    por_contrato <- rep(FALSE, nrow(dt))
    if (nrow(campos_meta)) {
      arquivos_com_caminho <- unique(as.character(campos_meta[caminho_registro == origem, arquivo_xlsform]))
      arquivos_com_caminho <- arquivos_com_caminho[!is.na(arquivos_com_caminho) & nzchar(arquivos_com_caminho)]
      if (length(arquivos_com_caminho)) por_contrato <- !is.na(arquivo_por_linha) & arquivo_por_linha %in% arquivos_com_caminho
    }
    marcar <- por_cabecalho | por_marca_ancestral | por_contrato
    if (any(marcar)) {
      for (jj in which(marcar)) marca_lista[[jj]] <- unique(c(marca_lista[[jj]], alias_curto))
    }
    valor_origem <- if (origem %in% names(dt)) tolower(trimws(as.character(dt[[origem]]))) else rep(NA_character_, nrow(dt))
    origem_valida <- !is.na(valor_origem) & valor_origem %in% habitos_validos
    valor_alias <- if (alias_curto %in% names(dt)) tolower(trimws(as.character(dt[[alias_curto]]))) else rep(NA_character_, nrow(dt))
    alias_valido <- !is.na(valor_alias) & valor_alias %in% habitos_validos
    conflito <- origem_valida & alias_valido & valor_alias != valor_origem
    auditoria[[ii]] <- data.table::data.table(
      atributo_origem = origem,
      atributo_preservado = origem,
      alias_curto_apenas_auditado = if (alias_curto %in% names(dt)) alias_curto else NA_character_,
      n_linhas_marcadas = sum(marcar),
      n_marcadas_por_cabecalho_observado = sum(por_cabecalho),
      n_marcadas_por_linhagem_ancestral = sum(por_marca_ancestral),
      n_marcadas_por_contrato_versionado = sum(por_contrato),
      n_linhas_versao_nao_resolvida = sum(is.na(arquivo_por_linha) | !nzchar(as.character(arquivo_por_linha))),
      n_valores_contratuais_origem = sum(origem_valida & marcar),
      n_preservados = sum(origem_valida & marcar),
      n_ja_identicos = sum(origem_valida & alias_valido & valor_alias == valor_origem & marcar, na.rm = TRUE),
      n_conflitos_preservando_destino = sum(conflito & marcar, na.rm = TRUE),
      n_valores_nao_contratuais_ignorados = sum(!is.na(valor_origem) & nzchar(valor_origem) & !origem_valida & marcar)
    )
  }
  marca_por_linha <- vapply(marca_lista, function(z) paste(sort(unique(z[!is.na(z) & nzchar(z)])), collapse = ";"), character(1L))
  data.table::set(dt, j = col_marca, value = marca_por_linha)
  aud <- data.table::rbindlist(auditoria, fill = TRUE, use.names = TRUE)
  dir_aud <- file.path(output_dir, "03_auditorias", "contrato_xlsform")
  dir.create(dir_aud, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
  try(monitora_fwrite(aud, file.path(dir_aud, "auditoria_preservacao_habitos_caminho_canonico_pre_rotulo.csv"), na = ""), silent = TRUE)
  try(monitora_fwrite(aud, file.path(log_dir, paste0("auditoria_preservacao_habitos_caminho_canonico_pre_rotulo_", exec_id, ".csv")), na = ""), silent = TRUE)
  if (any(aud$n_conflitos_preservando_destino > 0L)) {
    monitora_log_registrar_evento(
      "preservacao_habito_canonico_pre_rotulo", "AVISO", NA_character_,
      paste0("Conflitos entre caminho canônico e alias curto legado=", sum(aud$n_conflitos_preservando_destino)),
      "caminho canônico preservado; alias não sobrescrito; publicação deve bloquear divergência"
    )
  }
  invisible(dt)
}
### FIM DA PRESERVAÇÃO CANÔNICA DE HÁBITOS ----------------------------------

monitora_correcao_resolver_encostam_flexivel <- function(dt,
                                                          output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                          log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                          exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)) {
  dt <- monitora_dt_referenciar(dt)
  col_label <- "**Encostam** na vareta: (amostragem/registro)"
  col_canon <- "amostragem/registro/tipo_forma_vida"
  tem_label <- col_label %in% names(dt)
  tem_canon <- col_canon %in% names(dt)

 ### Regra 1: nenhuma das duas existe -> nada a fazer, não criar coluna.
  if (!tem_label && !tem_canon) return(invisible(dt))
 ### Regra 2: só a canônica existe -> renomear (comportamento já existente,
 ### preservado; nenhuma linha é perdida, é apenas troca de nome).
  if (tem_canon && !tem_label) {
    data.table::setnames(dt, col_canon, col_label)
    return(invisible(dt))
  }
 ### Regra 2b: só a rotulada existe -> nada a fazer.
  if (tem_label && !tem_canon) return(invisible(dt))

 ### Regra 3: ambas existem. Consolidar linha a linha sem perda silenciosa.
 ### Nesta etapa os valores ainda são rótulos brutos (às vezes com múltiplos
 ### segmentos separados por vírgula, formato nativo de exportação
 ### multi-seleção do SISMONITORA); a tokenização real ocorre no bloco
 ### seguinte. Cada lado é tratado como um "blob" opaco (pode já ser
 ### multi-seleção internamente, em qualquer separador da fonte); a união de
 ### dois lados diferentes é feita concatenando os dois blobs com espaço, sem
 ### tentar reinterpretar o separador interno de cada um. O bloco de
 ### tokenização seguinte faz correspondência por substring, então cada label
 ### bruto embutido em qualquer um dos dois lados continua sendo reconhecido
 ### normalmente. Não usar vírgula como separador aqui: o próprio bloco de
 ### tokenização já usa "token," -> "token" na limpeza final, o que apagaria
 ### a vírgula entre dois tokens reais e colaria os dois em uma só palavra.
  n <- nrow(dt)
  a <- monitora_txt_normalizar_vazio(dt[[col_label]])
  b <- monitora_txt_normalizar_vazio(dt[[col_canon]])
  resultado <- a
  usar_b <- is.na(a) & !is.na(b)
  resultado[usar_b] <- b[usar_b]

  eh_solo_nu <- function(x) {
    grepl("^solo nu\\s*/\\s*rochas\\s*\\(sem plantas tocando a vareta\\),?$", tolower(trimws(x)), perl = TRUE)
  }
  conjunto_livre <- function(x) {
    toks <- unique(tolower(trimws(strsplit(gsub(",", " ", x, fixed = TRUE), "\\s+")[[1]])))
    toks[nzchar(toks)]
  }

  precisa_avaliar <- !is.na(a) & !is.na(b) & a != b
  idx_avaliar <- which(precisa_avaliar)
  diag_idx <- integer(0); diag_tipo <- character(0); diag_final <- character(0)
  for (i in idx_avaliar) {
    va <- a[i]; vb <- b[i]
    if (setequal(conjunto_livre(va), conjunto_livre(vb))) {
 ### Mesmo conjunto de tokens, só reordenado/reformatado: sem conflito,
 ### sem perda; mantém um dos dois lados (equivalentes).
      resultado[i] <- va
      next
    }
    a_solo <- eh_solo_nu(va); b_solo <- eh_solo_nu(vb)
    if (a_solo && !b_solo) {
 ### Conflito real: um lado é exclusivamente solo_nu e o outro tem
 ### conteúdo diferente. Remove solo_nu, preserva o outro lado -- mesma
 ### exclusividade contratual já aplicada pelo a regra (Regra B).
      resultado[i] <- vb
      tipo <- "conflito_solo_nu_removido"
    } else if (b_solo && !a_solo) {
      resultado[i] <- va
      tipo <- "conflito_solo_nu_removido"
    } else {
 ### Complementar: nenhum dos dois lados é solo_nu isolado. Une os dois
 ### blobs com espaço, sem perder nenhum dos dois lados.
      resultado[i] <- paste(va, vb)
      tipo <- "uniao_complementar"
    }
    diag_idx <- c(diag_idx, i)
    diag_tipo <- c(diag_tipo, tipo)
    diag_final <- c(diag_final, resultado[i])
  }

  data.table::set(dt, j = col_label, value = resultado)
  dt[, (col_canon) := NULL]

  if (length(diag_idx)) {
    diag <- data.table::data.table(
      linha_indice = diag_idx, tipo_resolucao = diag_tipo,
      valor_coluna_rotulada = a[diag_idx], valor_coluna_canonica = b[diag_idx],
      valor_final_unido = diag_final
    )
    try({
      dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
      dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
      data.table::fwrite(diag, file.path(output_dir, "auditoria_encostam_resolvedor_flexivel.csv"), na = "")
      data.table::fwrite(diag, file.path(log_dir, paste0("auditoria_encostam_resolvedor_flexivel_", exec_id, ".csv")), na = "")
    }, silent = TRUE)
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      try(monitora_log_registrar_evento(
        "encostam_resolvedor_flexivel", "AVISO",
        file.path(output_dir, "auditoria_encostam_resolvedor_flexivel.csv"),
        paste0(length(diag_idx), " linha(s) com Encostam presente em ambas as colunas (rotulada e canônica) com valores diferentes; ver auditoria_encostam_resolvedor_flexivel.csv"),
        "resolvedor_flexivel_hotfix_035b"
      ), silent = TRUE)
    }
  }
  invisible(dt)
}

monitora_auditoria_pontos_duplicados <- function(dt) {
  dt <- monitora_dt_referenciar(dt)
  ponto_col <- if ("ponto_amostral (amostragem/registro)" %in% names(dt)) {
    "ponto_amostral (amostragem/registro)"
  } else if ("ponto_metro (amostragem/registro)" %in% names(dt)) {
    "ponto_metro (amostragem/registro)"
  } else {
    NA_character_
  }
  required <- c("UC", "CICLO", "UA", "ANO")
  if (is.na(ponto_col) || !all(required %in% names(dt))) return(invisible(NULL))
  aud <- dt[, .N, by = c(required, ponto_col)][N > 1]
  if (nrow(aud) > 0) {
    setnames(aud, ponto_col, "ponto")
    monitora_fwrite(aud, file.path(MONITORA_LOG_DIR, paste0("auditoria_pontos_duplicados_", MONITORA_EXEC_ID, ".csv")))
    monitora_log_registrar_evento("pontos_duplicados", "AVISO", NA_character_, paste0(nrow(aud), " pontos duplicados dentro de UC+CICLO+UA+ANO"), "ver auditoria_pontos_duplicados; nao removido automaticamente")
  }
  invisible(aud)
}

monitora_auditoria_anos_invalidos <- function(dt) {
  dt <- monitora_dt_referenciar(dt)
  if (!"ANO" %in% names(dt)) return(invisible(data.table()))
  ano_num <- suppressWarnings(as.integer(dt[["ANO"]]))
  ano_min <- 2000L
  ano_max <- lubridate::year(Sys.Date()) + 1L
  invalido <- is.na(ano_num) | ano_num < ano_min | ano_num > ano_max
  if (!any(invalido, na.rm = TRUE)) return(invisible(data.table()))
  cols <- intersect(
    c("UC", "CICLO", "CAMPANHA", "UA", "COLETA", "Data (data_hora)", "DATA_MONITORA_PARSEADA", "ANO", "MONITORA_ARQUIVO_ENTRADA", "MONITORA_TIPO_ENTRADA"),
    names(dt)
  )
  aud <- unique(dt[invalido, ..cols])
  aud[, ano_min_plausivel := ano_min]
  aud[, ano_max_plausivel := ano_max]
  aud[, acao_recomendada := "Corrigir a data original ou verificar erro de parsing; registros com ANO inválido/NA não devem ser usados para gráficos ou estatísticas temporais sem validação."]
  saida <- file.path(MONITORA_LOG_DIR, paste0("auditoria_anos_invalidos_", MONITORA_EXEC_ID, ".csv"))
  monitora_fwrite(aud, saida)
  monitora_fwrite(aud, file.path(MONITORA_OUTPUT_DIR, "auditoria_anos_invalidos_ultima_execucao.csv"))
  monitora_log_registrar_evento("anos_invalidos", "AVISO", saida, paste0(nrow(aud), " combinações com ANO inválido/NA ou fora da faixa plausível"), "ver auditoria_anos_invalidos")
  invisible(aud)
}

monitora_auditoria_completude_101_pontos <- function(dt) {
  dt <- monitora_dt_referenciar(dt)
  ponto_col <- if ("ponto_amostral (amostragem/registro)" %in% names(dt)) {
    "ponto_amostral (amostragem/registro)"
  } else if ("ponto_metro (amostragem/registro)" %in% names(dt)) {
    "ponto_metro (amostragem/registro)"
  } else {
    NA_character_
  }
  required <- c("UC", "CICLO", "CAMPANHA", "UA", "ANO")
  if (is.na(ponto_col) || !all(required %in% names(dt))) return(invisible(data.table()))
  fonte_col <- if ("MONITORA_ARQUIVO_ENTRADA" %in% names(dt)) "MONITORA_ARQUIVO_ENTRADA" else NA_character_
  aux <- dt[, c(required, ponto_col, if (!is.na(fonte_col)) fonte_col else NULL), with = FALSE]
  setnames(aux, ponto_col, "ponto_original")
  aux[, ponto_num := suppressWarnings(as.integer(gsub("[^0-9]+", "", as.character(ponto_original))))]
  by_cols <- required
  resumo <- aux[, .(
    n_registros = .N,
    n_pontos = data.table::uniqueN(ponto_num[!is.na(ponto_num)]),
    pontos_fora_1_101 = paste(sort(unique(ponto_num[!is.na(ponto_num) & !ponto_num %between% c(1L, 101L)])), collapse = " | "),
    arquivos_origem = if (!is.na(fonte_col)) paste(sort(unique(na.omit(as.character(get(fonte_col))))), collapse = " | ") else NA_character_
  ), by = by_cols]
  dup <- aux[!is.na(ponto_num), .N, by = c(by_cols, "ponto_num")][N > 1L]
  dup_sum <- dup[, .(pontos_duplicados = paste(sort(unique(ponto_num)), collapse = " | ")), by = by_cols]
  resumo <- merge(resumo, dup_sum, by = by_cols, all.x = TRUE, sort = FALSE)
  resumo[is.na(pontos_duplicados), pontos_duplicados := ""]
 # Lista de pontos ausentes calculada apenas por grupo problemático para manter a etapa leve.
  resumo[, pontos_ausentes := ""]
  prob_idx <- which(resumo$n_pontos != 101L | resumo$n_registros != 101L | nzchar(resumo$pontos_duplicados) | nzchar(resumo$pontos_fora_1_101))
  if (length(prob_idx) > 0) {
    chaves_prob <- resumo[prob_idx, ..by_cols]
    aux_prob <- merge(aux, chaves_prob, by = by_cols, all.y = TRUE, sort = FALSE)
    miss <- aux_prob[, .(
      pontos_ausentes = paste(setdiff(1:101, sort(unique(ponto_num[!is.na(ponto_num) & ponto_num %between% c(1L, 101L)]))), collapse = " | ")
    ), by = by_cols]
    resumo <- merge(resumo, miss, by = by_cols, all.x = TRUE, suffixes = c("", "_calc"), sort = FALSE)
    resumo[!is.na(pontos_ausentes_calc), pontos_ausentes := pontos_ausentes_calc]
    resumo[, pontos_ausentes_calc := NULL]
  }
  aud <- resumo[n_pontos != 101L | n_registros != 101L | nzchar(pontos_duplicados) | nzchar(pontos_ausentes) | nzchar(pontos_fora_1_101)]
  if (nrow(aud) > 0) {
    aud[, acao_recomendada := "Conferir se a UA/ano possui exatamente 101 pontos; corrigir pontos ausentes, duplicados ou fora de 1:101 antes de aceitar análises e gráficos."]
    saida <- file.path(MONITORA_LOG_DIR, paste0("auditoria_completude_101_pontos_", MONITORA_EXEC_ID, ".csv"))
    monitora_fwrite(aud, saida)
    monitora_fwrite(aud, file.path(MONITORA_OUTPUT_DIR, "auditoria_completude_101_pontos_ultima_execucao.csv"))
    monitora_log_registrar_evento("completude_101_pontos", "AVISO", saida, paste0(nrow(aud), " grupos UC+CICLO+CAMPANHA+UA+ANO com n_registros/n_pontos diferente de 101, duplicidade ou lacuna"), "ver auditoria_completude_101_pontos")
  }
  invisible(aud)
}

monitora_correcao_normalizar_tokens_encostam <- function(x) {
  x <- as.character(x)
  vazio <- monitora_correcao_vazio_vec(x)
 ### Pré-filtro vetorizado (mesmo padrão da Regra B do a regra): só as
 ### linhas com separador residual ou risco de solo_nu coexistente passam
 ### pelo tokenizador linha a linha; a maioria das linhas já chega limpa
 ### (token único, ou já sem separador residual) e não é tocada.
  tem_separador_residual <- grepl("[,;]|\\s{2,}", x, perl = TRUE)
  tem_solo_nu_coexistente <- grepl("solo_nu", x, fixed = TRUE) & grepl("\\S+\\s+\\S+", trimws(x), perl = TRUE)
  candidato <- !vazio & (tem_separador_residual | tem_solo_nu_coexistente)

  out <- x
  idx <- which(candidato)
  for (i in idx) {
    v <- gsub("[,;]+|\\s+", " ", x[i], perl = TRUE)
    toks <- monitora_correcao_tokenizar(v)
    if (!length(toks)) { out[i] <- NA_character_; next }
    if ("solo_nu" %in% toks && length(toks) > 1L) toks <- setdiff(toks, "solo_nu")
    out[i] <- monitora_correcao_colapsar_tokens(toks)
  }
  out[vazio] <- NA_character_
  out
}

monitora_pipe_condicional_token_presente_035m_d3 <- function(x, token) {
  token <- monitora_correcao_limpar_texto(token)
  if (!nzchar(token)) return(rep(FALSE, length(x)))
  grepl(token, monitora_correcao_limpar_texto(x), fixed = TRUE)
}

monitora_pipe_condicional_resolver_035m_d3 <- function(valor, parent, token, grupo = NULL, ordem = NULL) {
  valor <- as.character(valor)
  n <- length(valor)
  if (!n) return(character(0))
  parent <- rep_len(as.character(parent), n)
  elegivel <- monitora_pipe_condicional_token_presente_035m_d3(parent, token)
  elegivel[is.na(elegivel)] <- FALSE
  out <- rep(NA_character_, n)
  if (!any(elegivel)) return(out)

  valor <- trimws(valor)
  valor[is.na(valor) | !nzchar(valor)] <- NA_character_
  grupo <- if (is.null(grupo)) rep("todos", n) else rep_len(as.character(grupo), n)
  grupo[is.na(grupo) | !nzchar(grupo)] <- "sem_grupo"
  ordem <- if (is.null(ordem)) seq_len(n) else rep_len(ordem, n)
  ordem_num <- suppressWarnings(as.numeric(ordem))
  ordem_num[is.na(ordem_num)] <- seq_len(n)[is.na(ordem_num)]

  for (g in unique(grupo[elegivel])) {
    idx_g <- which(grupo == g)
    idx_e <- idx_g[elegivel[idx_g]]
    if (!length(idx_e)) next
    idx_e <- idx_e[order(ordem_num[idx_e], idx_e)]

    sem_pipe <- !is.na(valor[idx_e]) & !grepl("|", valor[idx_e], fixed = TRUE)
    if (any(sem_pipe)) out[idx_e[sem_pipe]] <- valor[idx_e[sem_pipe]]

    cand_pipe <- unique(valor[idx_g][!is.na(valor[idx_g]) & grepl("|", valor[idx_g], fixed = TRUE)])
    cand_pipe <- cand_pipe[!is.na(cand_pipe) & nzchar(cand_pipe)]
    if (length(cand_pipe) != 1L) next
    toks <- trimws(strsplit(cand_pipe, "|", fixed = TRUE)[[1L]])
    toks[toks == ""] <- NA_character_
    if (length(toks) != length(idx_e)) next
    out[idx_e] <- toks
  }
  out
}

### Seleção multiversão estrita para campos condicionais. A coluna própria da
### versão continua prioritária quando preenchida; uma coluna canônica já
### importada só atua como fallback. Se ambas contiverem fatos divergentes, o
### pipeline falha fechado em vez de escolher ou sobrescrever silenciosamente.
monitora_pipe_condicional_preferir_preenchido_035m_d3 <- function(preferido,
                                                                  fallback,
                                                                  contexto = "campo_condicional_multiversao") {
  n <- max(length(preferido), length(fallback))
  if (!n) return(character(0))
  normalizar_ausencia <- function(x) {
    x <- trimws(rep_len(as.character(x), n))
    vazio <- is.na(x) | !nzchar(x) | toupper(x) %in% c("NA", "N/A", "NULL", "NAN", "---")
    x[vazio] <- NA_character_
    x
  }
  preferido <- normalizar_ausencia(preferido)
  fallback <- normalizar_ausencia(fallback)
  cmp_preferido <- monitora_correcao_limpar_texto(preferido)
  cmp_fallback <- monitora_correcao_limpar_texto(fallback)
  conflito <- !is.na(preferido) & !is.na(fallback) & cmp_preferido != cmp_fallback
  conflito[is.na(conflito)] <- FALSE
  ### Alguns exports históricos repetem o mesmo valor escalar no campo
  ### serializado (por exemplo, "terrestre|terrestre"), enquanto o alias
  ### canônico contém apenas "terrestre". Isso não representa divergência de
  ### fato. A reconciliação abaixo atua somente nos raros candidatos já
  ### divergentes e só colapsa sequências formadas por um único token distinto;
  ### sequências heterogêneas permanecem diferentes e continuam falhando
  ### fechado para preservar a correspondência posicional de origem.
  idx_conflito <- which(conflito)
  if (length(idx_conflito)) {
    normalizar_cmp_pipe_escalar <- function(x) {
      tokens <- trimws(strsplit(as.character(x), "|", fixed = TRUE)[[1L]])
      tokens <- monitora_correcao_limpar_texto(tokens)
      tokens <- tokens[!is.na(tokens) & nzchar(tokens)]
      if (!length(tokens)) return(NA_character_)
      if (data.table::uniqueN(tokens) == 1L) return(tokens[[1L]])
      paste(tokens, collapse = "|")
    }
    cmp_pipe_preferido <- vapply(preferido[idx_conflito], normalizar_cmp_pipe_escalar, character(1L))
    cmp_pipe_fallback <- vapply(fallback[idx_conflito], normalizar_cmp_pipe_escalar, character(1L))
    equivalente_pipe_escalar <- !is.na(cmp_pipe_preferido) & !is.na(cmp_pipe_fallback) &
      cmp_pipe_preferido == cmp_pipe_fallback
    conflito[idx_conflito[equivalente_pipe_escalar]] <- FALSE
  }
  if (any(conflito)) {
    stop(
      "Aliases físicos divergentes no seletor multiversão ", contexto,
      "; linhas: ", paste(utils::head(which(conflito), 10L), collapse = " | "),
      ". A consolidação foi bloqueada para preservar o fato de origem.",
      call. = FALSE
    )
  }
  out <- preferido
  preencher <- is.na(out) & !is.na(fallback)
  out[preencher] <- fallback[preencher]
  out
}

if (!(MONITORA_MODO_EXECUCAO %in% c("abrir_painel_cache", "painel_incremental_registros_corrig"))) {
if (isTRUE(MONITORA_MODO_USA_REGISTROS_CORRIG_ENTRADA)) {
  arquivo_registros_corrig_entrada <- monitora_registros_corrig_entrada_arquivo()
  registros_corrig <- monitora_registros_corrig_carregar_entrada(MONITORA_MODO_EXECUCAO)
 ### Todos os modos que partem de registros_corrig herdam a mesma proveniência.
 ### O efeito histórico já está materializado no CSV e nunca é reaplicado; o
 ### ledger e as aplicações anteriores são importados apenas para continuidade
 ### auditável e consolidação da próxima geração.
  monitora_linhagem_importar_incremental(arquivo_registros_corrig_entrada)
  MONITORA_AUDITORIA_ANOS_INVALIDOS <- monitora_auditoria_anos_invalidos(registros_corrig)
  MONITORA_AUDITORIA_COMPLETUDE_101_PONTOS <- monitora_auditoria_completude_101_pontos(registros_corrig)
  monitora_perf_registrar_checkpoint("leitura_registros_corrig_entrada", paste0("retomada por registros_corrig.csv no modo ", MONITORA_MODO_EXECUCAO), registros_corrig)
} else {

### Origem dos dados: arquivos de entrada são aceitos
### exclusivamente em input/. Arquivos ZIP/CSV/XLSX/XLS na raiz do diretório do
### script bloqueiam a execução para forçar conferência operacional explícita do
### conteúdo de input/ antes de cada rodada.
MONITORA_IO_DIRETORIOS_FONTE <- MONITORA_INPUT_DIR
monitora_input_conteudo <- if (dir.exists(MONITORA_INPUT_DIR)) {
  list.files(MONITORA_INPUT_DIR, recursive = TRUE, all.files = FALSE, no.. = TRUE)
} else character()
monitora_root_input_like <- list.files(
  MONITORA_BASE_DIR,
  pattern = "\\.(zip|csv|xlsx|xls)$",
  recursive = FALSE,
  full.names = TRUE,
  ignore.case = TRUE
)
if (length(monitora_root_input_like) > 0L) {
  aud_root <- data.table::data.table(
    arquivo = normalizePath(monitora_root_input_like, winslash = "/", mustWork = FALSE),
    nome_arquivo = basename(monitora_root_input_like),
    motivo = "arquivo_de_entrada_na_raiz_nao_aceito",
    acao_requerida = "mover para input/ se deve ser usado; remover da raiz se não deve ser usado"
  )
  monitora_fwrite(aud_root, file.path(MONITORA_LOG_DIR, paste0("arquivos_entrada_na_raiz_bloqueados_", MONITORA_EXEC_ID, ".csv")))
  monitora_fwrite(aud_root, file.path(MONITORA_OUTPUT_DIR, "arquivos_entrada_na_raiz_bloqueados_ultima_execucao.csv"))
  stop(
    "Arquivos ZIP/CSV/XLSX/XLS encontrados na raiz do diretório do script. ",
    "A entrada agora deve ficar exclusivamente em input/. ",
    "Mova os arquivos que deseja processar para input/ e remova os demais da raiz. ",
    "Ver log/arquivos_entrada_na_raiz_bloqueados_*.csv.",
    call. = FALSE
  )
}
if (length(monitora_input_conteudo) == 0L) {
  stop(
    "Nenhum arquivo encontrado em input/. A pasta input/ foi criada pelo script se não existia. ",
    "Coloque os ZIP/CSV/XLSX do SISMONITORA ou registros_corrig*.csv em input/ e execute novamente.",
    call. = FALSE
  )
}
monitora_log_registrar_evento("configuracao", "INFO", MONITORA_IO_DIRETORIOS_FONTE, "diretorio de origem selecionado", "input/ obrigatório")
monitora_perf_registrar_checkpoint("configuracao_inicial", paste0("origem obrigatória: ", MONITORA_IO_DIRETORIOS_FONTE))

### Extração recursiva de ZIPs, incluindo ZIPs internos dentro de ZIPs.
monitora_io_extrair_zips_recursivos(MONITORA_IO_DIRETORIOS_FONTE, MONITORA_EXTRACT_DIR)
monitora_recurso_controlar("apos_extracao_recursiva_zips", risco = "normal", force_log = TRUE)
monitora_perf_registrar_checkpoint("extracao_recursiva_zips", "extração de ZIPs externos e internos")

### Conversão defensiva de XLSX para CSV apenas nas áreas de entrada/extração, não em output/log.
xlsx_files <- list.files(c(MONITORA_IO_DIRETORIOS_FONTE, MONITORA_EXTRACT_DIR), pattern = "\\.xlsx$", recursive = TRUE, full.names = TRUE, ignore.case = TRUE)
xlsx_files <- xlsx_files[!grepl("/(output|log)/", normalizePath(xlsx_files, winslash = "/", mustWork = FALSE))]
for (xlsx_file in xlsx_files) {
  csv_file <- sub("\\.xlsx$", ".csv", xlsx_file, ignore.case = TRUE)
  if (!file.exists(csv_file)) {
    data <- read_excel(xlsx_file)
    data.table::fwrite(data.table::as.data.table(monitora_sanitizar_ausencias_produto(data)), file = csv_file, na = "NA")
    monitora_log_registrar_evento("conversao_xlsx", "INFO", xlsx_file, paste0("convertido para ", csv_file), "OK")
  } else {
    monitora_log_registrar_evento("conversao_xlsx", "INFO", xlsx_file, paste0("CSV ja existente: ", csv_file), "mantido")
  }
}
monitora_rm_seguro("data", "csv_file", "xlsx_file", "xlsx_files")
monitora_perf_registrar_checkpoint("conversao_xlsx", "conversão defensiva de XLSX para CSV, quando aplicável")

### Leitura e concatenação dos CSVs de entrada.
### Importante: arquivos registros_corrig*.csv são aceitos como entrada válida apenas quando colocados em
### input/, pois é comum usar produtos pós-tratamento como base para nova rodada.
### Apenas output/, log/ e produtos analíticos/relatórios são excluídos automaticamente.
all_csvfiles <- list.files(c(MONITORA_IO_DIRETORIOS_FONTE, MONITORA_EXTRACT_DIR), pattern = "\\.csv$", recursive = TRUE, full.names = TRUE, ignore.case = TRUE)
all_csvfiles_norm <- normalizePath(all_csvfiles, winslash = "/", mustWork = FALSE)
all_csvfiles_base <- basename(all_csvfiles_norm)

### Fronteira de governança: input/linhagem é sidecar, nunca dado de campo.
### O filtro é por caminho, não apenas por nomes conhecidos, para que novos
### arquivos do contrato de linhagem permaneçam seguros em versões futuras.
input_linhagem_norm <- normalizePath(file.path(MONITORA_INPUT_DIR, "linhagem"), winslash = "/", mustWork = FALSE)
exclude_linhagem <- startsWith(all_csvfiles_norm, paste0(input_linhagem_norm, "/"))

# Exclusões de diretórios gerenciados pelo próprio script.
# Importante: quando MONITORA_IO_DIRETORIOS_FONTE = MONITORA_BASE_DIR, list.files(recursive=TRUE)
# também encontraria produtos antigos em output/, log/ e extrações antigas.
exclude_dirs <- grepl("/(output|log|plots_png)/", all_csvfiles_norm)

# a pasta de oráculo/referência pode ficar dentro de input/ para
# comparação diagnóstica, mas seus CSVs nunca são dados de campo.
exclude_oraculo <- grepl("/(oraculo_replay|referencia_replay|diagnostico_run_referencia)/", all_csvfiles_norm, ignore.case = TRUE)

# Exclusões de produtos analíticos/relatórios conhecidos.
# NÃO exclui registros_corrig*.csv: estes podem ser insumos válidos de nova rodada
# quando o usuário os coloca deliberadamente em input/.
exclude_outputs <- grepl(
  "^(registros_corrig_stat|sum_|cob_|prop_rel_|relatorio_execucao|auditoria_|duplicidades_|conflitos_)",
  all_csvfiles_base,
  ignore.case = TRUE
)

# arquivos de controle de correção/replay não são dados de campo.
# Eles podem ficar em input/ para controlar a reaplicação, mas nunca podem ser
# lidos na concatenação de registros do SISMONITORA. A / aceitava
# input/correcoes_semanticas.csv como candidato a CSV de dados, o que contaminava
# registros_importados.csv com colunas como id_correcao, tipo_correcao, acao,
# responsavel e uuid_registro.
exclude_controle_correcao <- monitora_io_eh_csv_controle_correcao(all_csvfiles_base)

csvfiles_excluidos <- unique(all_csvfiles[exclude_dirs | exclude_oraculo | exclude_outputs | exclude_controle_correcao | exclude_linhagem])
if (length(csvfiles_excluidos) > 0) {
  idx_excl <- match(csvfiles_excluidos, all_csvfiles)
  motivos_excl <- ifelse(
    exclude_linhagem[idx_excl],
    "sidecar_input_linhagem_nao_importado_como_dado",
    ifelse(
      exclude_controle_correcao[idx_excl],
      "arquivo_controle_correcao_replay_nao_importado_como_dado",
      ifelse(
        exclude_oraculo[idx_excl],
        "arquivo_oraculo_replay_nao_importado_como_dado",
        ifelse(
          grepl("^(registros_corrig_stat|sum_|cob_|prop_rel_|relatorio_execucao|auditoria_|duplicidades_|conflitos_)",
                basename(csvfiles_excluidos), ignore.case = TRUE),
          "produto_analitico_saida_ou_relatorio",
          "diretorio_gerenciado_output_log"
        )
      )
    )
  )
  monitora_fwrite(
    data.table(
      arquivo = csvfiles_excluidos,
      motivo = motivos_excl
    ),
    file.path(MONITORA_LOG_DIR, paste0("arquivos_csv_excluidos_da_importacao_", MONITORA_EXEC_ID, ".csv"))
  )
  monitora_fwrite(
    data.table(
      arquivo = csvfiles_excluidos,
      motivo = motivos_excl
    ),
    file.path(MONITORA_OUTPUT_DIR, "arquivos_csv_excluidos_da_importacao_ultima_execucao.csv")
  )
  if (any(motivos_excl == "arquivo_controle_correcao_replay_nao_importado_como_dado")) {
    monitora_log_registrar_evento(
      "filtro_csv_entrada",
      "INFO",
      paste(basename(csvfiles_excluidos[motivos_excl == "arquivo_controle_correcao_replay_nao_importado_como_dado"]), collapse = " | "),
      paste0(sum(motivos_excl == "arquivo_controle_correcao_replay_nao_importado_como_dado"), " CSV(s) de controle de correção/replay excluído(s) da importação de dados"),
      "arquivo usado apenas como controle de reaplicação, não como registro SISMONITORA"
    )
  }
  if (any(motivos_excl == "sidecar_input_linhagem_nao_importado_como_dado")) {
    monitora_log_registrar_evento(
      "filtro_csv_entrada",
      "INFO",
      paste(basename(csvfiles_excluidos[motivos_excl == "sidecar_input_linhagem_nao_importado_como_dado"]), collapse = " | "),
      paste0(sum(motivos_excl == "sidecar_input_linhagem_nao_importado_como_dado"), " sidecar(s) de input/linhagem excluído(s) da importação de registros"),
      "pasta de linhagem usada somente para proveniência/replay, nunca como dado SISMONITORA"
    )
  }
  if (any(motivos_excl == "arquivo_oraculo_replay_nao_importado_como_dado")) {
    monitora_log_registrar_evento(
      "filtro_csv_entrada",
      "INFO",
      paste(basename(csvfiles_excluidos[motivos_excl == "arquivo_oraculo_replay_nao_importado_como_dado"]), collapse = " | "),
      paste0(sum(motivos_excl == "arquivo_oraculo_replay_nao_importado_como_dado"), " CSV(s) da run-oráculo excluído(s) da importação de dados"),
      "arquivos usados apenas como oráculo diagnóstico, não como registros SISMONITORA"
    )
  }
  monitora_log_registrar_evento(
    "filtro_csv_entrada",
    "INFO",
    NA_character_,
    paste0(length(csvfiles_excluidos), " CSVs excluidos da importacao por filtro de output/log/produtos/controle de correções"),
    "ver arquivos_csv_excluidos_da_importacao"
  )
}

csvfiles <- unique(all_csvfiles[!exclude_dirs & !exclude_oraculo & !exclude_outputs & !exclude_controle_correcao & !exclude_linhagem])
monitora_recurso_controlar("filtro_csv_entrada", risco = if (length(csvfiles) > 1000) "alto" else "normal", force_log = TRUE)
monitora_perf_registrar_checkpoint("filtro_csv_entrada", paste0(length(csvfiles), " CSV(s) candidatos após filtros"))

# Classificação formal de origem por nome de arquivo e cabeçalho.
# Essa informação será usada na auditoria e na deduplicação semântica, não para excluir o arquivo.
csvfiles_tipo_entrada <- vapply(csvfiles, monitora_io_detectar_tipo_csv, character(1))

### contrato positivo de entrada. A classificação "desconhecido" é uma
### evidência de exclusão, não uma quarta família permissiva de dados.
MONITORA_AUDITORIA_CSVS_NAO_BIOLOGICOS <- monitora_io_auditar_csvs_nao_biologicos(
  csvfiles, csvfiles_tipo_entrada
)
csv_biologico <- monitora_io_csv_eh_dado_biologico(csvfiles_tipo_entrada)
csvfiles <- csvfiles[csv_biologico]
csvfiles_tipo_entrada <- csvfiles_tipo_entrada[csv_biologico]
if (!length(csvfiles)) {
  stop(
    "Nenhum CSV com esquema biológico SISMONITORA reconhecido permaneceu após a triagem. ",
    "Consulte auditoria_csvs_nao_biologicos_excluidos_*.csv.",
    call. = FALSE
  )
}

if (any(csvfiles_tipo_entrada == "pos_tratamento_script")) {
  monitora_log_registrar_evento(
    "csv_pos_tratamento_entrada",
    "INFO",
    paste(csvfiles[csvfiles_tipo_entrada == "pos_tratamento_script"], collapse = " | "),
    paste0(sum(csvfiles_tipo_entrada == "pos_tratamento_script"), " CSV(s) pós-tratamento aceitos como entrada válida"),
    "serao deduplicados semanticamente contra registros brutos/novos quando houver sobreposicao"
  )
}
if (any(csvfiles_tipo_entrada == "bruto_lote_sismonitora")) {
  monitora_log_registrar_evento(
    "csv_lote_sismonitora_entrada",
    "INFO",
    paste(csvfiles[csvfiles_tipo_entrada == "bruto_lote_sismonitora"], collapse = " | "),
    paste0(sum(csvfiles_tipo_entrada == "bruto_lote_sismonitora"), " CSV(s) consolidado(s) por exportação em lote detectado(s)"),
    "CSV consolidado usado como fonte principal; XLSX acompanhante nao e somado quando houver CSV equivalente"
  )
}
if (any(csvfiles_tipo_entrada == "bruto_individual_sismonitora")) {
  monitora_log_registrar_evento(
    "csv_individual_sismonitora_entrada",
    "INFO",
    paste(utils::head(csvfiles[csvfiles_tipo_entrada == "bruto_individual_sismonitora"], 20), collapse = " | "),
    paste0(sum(csvfiles_tipo_entrada == "bruto_individual_sismonitora"), " CSV(s) individuais SISMONITORA detectado(s)"),
    "entrada tradicional exportada um a um"
  )
}

if (length(csvfiles) == 0) stop("Nenhum CSV de entrada encontrado em input/ ou em ZIP/XLSX extraído a partir de input/. Coloque os ZIP/CSV/XLSX do SISMONITORA ou registros_corrig*.csv em input/.")

csv_origem_audit <- monitora_io_mapear_origem_arquivo(csvfiles)
csv_audit <- data.table(
  arquivo = csvfiles,
  basename = basename(csvfiles),
  tamanho_bytes = file.info(csvfiles)$size,
  md5 = as.character(tools::md5sum(csvfiles)),
  n_linhas = NA_integer_,
  n_colunas = NA_integer_,
  status_leitura = NA_character_,
  tipo_entrada = csvfiles_tipo_entrada
)
csv_audit <- cbind(csv_audit, csv_origem_audit[, .(arquivo_csv, nome_csv, arquivo_entrada_externo, nome_arquivo_entrada_externo, arquivo_zip_externo, nome_zip_externo, arquivo_zip_interno, nome_zip_interno, caminho_relativo_extraido)])

monitora_recurso_controlar("auditoria_csv_hash_md5", risco = if (nrow(csv_audit) > 1000) "alto" else "normal", objeto = csv_audit, force_log = TRUE)
monitora_perf_registrar_checkpoint("auditoria_csv_hash_md5", paste0(nrow(csv_audit), " CSV(s) auditados por tamanho e MD5"), csv_audit)

csv_keep <- rep(TRUE, length(csvfiles))
# Duplicidade confiável: mesmo hash MD5 e mesmo tamanho em bytes. Nesses casos, mantém o primeiro
# arquivo.
# Registra CSV interno, ZIP externo e ZIP interno para facilitar a conferência operacional.
MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO_LISTA <- list()
MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO_I <- 0L
dup_groups <- split(seq_along(csvfiles), paste(csv_audit$md5, csv_audit$tamanho_bytes, sep = "::"))
for (g in dup_groups) {
  if (length(g) > 1 && !is.na(csv_audit$md5[g[1]])) {
    csv_keep[g[-1]] <- FALSE
    meta <- monitora_io_ler_metadados_csv(csvfiles[g[1]])
    for (excl in g[-1]) {
      MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO_I <- MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO_I + 1L
      MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO_LISTA[[MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO_I]] <- cbind(
        data.table::data.table(
          md5 = csv_audit$md5[g[1]],
          tamanho_bytes = csv_audit$tamanho_bytes[g[1]],
          arquivo_mantido = csvfiles[g[1]],
          arquivo_excluido = csvfiles[excl],
          basename_mantido = basename(csvfiles[g[1]]),
          basename_excluido = basename(csvfiles[excl]),
          arquivo_entrada_externo_mantido = csv_audit$arquivo_entrada_externo[g[1]],
          arquivo_entrada_externo_excluido = csv_audit$arquivo_entrada_externo[excl],
          nome_arquivo_entrada_externo_mantido = csv_audit$nome_arquivo_entrada_externo[g[1]],
          nome_arquivo_entrada_externo_excluido = csv_audit$nome_arquivo_entrada_externo[excl],
          arquivo_zip_externo_mantido = csv_audit$arquivo_zip_externo[g[1]],
          arquivo_zip_externo_excluido = csv_audit$arquivo_zip_externo[excl],
          nome_zip_externo_mantido = csv_audit$nome_zip_externo[g[1]],
          nome_zip_externo_excluido = csv_audit$nome_zip_externo[excl],
          arquivo_zip_interno_mantido = csv_audit$arquivo_zip_interno[g[1]],
          arquivo_zip_interno_excluido = csv_audit$arquivo_zip_interno[excl],
          nome_zip_interno_mantido = csv_audit$nome_zip_interno[g[1]],
          nome_zip_interno_excluido = csv_audit$nome_zip_interno[excl],
          caminho_relativo_extraido_mantido = csv_audit$caminho_relativo_extraido[g[1]],
          caminho_relativo_extraido_excluido = csv_audit$caminho_relativo_extraido[excl],
          tipo_entrada = csv_audit$tipo_entrada[g[1]]
        ),
        meta
      )
    }
    monitora_log_registrar_evento(
      "duplicidade_arquivo",
      "AVISO",
      paste(csvfiles[g], collapse = " | "),
      paste0("CSV duplicado exato: mesmo MD5 ", csv_audit$md5[g[1]], " e tamanho em bytes. Mantido: ", csvfiles[g[1]]),
      "duplicados excluidos da sequencia de tratamento"
    )
  }
}
MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO <- if (MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO_I > 0L) {
  data.table::rbindlist(MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO_LISTA[seq_len(MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO_I)], fill = TRUE, use.names = TRUE)
} else {
  data.table::data.table()
}
rm(MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO_LISTA, MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO_I)
if (nrow(MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO) > 0) {
  monitora_fwrite(MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO, file.path(MONITORA_LOG_DIR, paste0("auditoria_arquivos_csv_duplicados_exatos_", MONITORA_EXEC_ID, ".csv")))
}

csvfiles_lidos <- csvfiles[csv_keep]
monitora_progresso_loop_configurar("leitura_csv", length(csvfiles_lidos), descricao = "leitura dos CSVs de entrada")
csvfiles_sucesso <- character()
registros_batches <- list()
batch_lista <- list()
batch_n <- 0L
batch_id <- 0L
### Proveniência de schema por fonte. A lista guarda o cabeçalho observado
### antes da união de arquivos e antes da criação de colunas técnicas. Isso
### permite distinguir um campo realmente pertencente à versão/fonte de uma
### coluna criada depois por rbindlist(fill=TRUE), inclusive quando o valor
### observado do campo é vazio.
MONITORA_CABECALHOS_ORIGINAIS_POR_FONTE <- list()
MONITORA_AUDITORIA_LINHAS_NAO_OPERACIONAIS_INPUT_LISTA <- list()
MONITORA_AUDITORIA_LINHAS_NAO_OPERACIONAIS_INPUT_I <- 0L

### A proveniência só pode ser adicionada depois da admissão operacional. Sem
### este filtro, uma linha fisicamente vazia passa a parecer preenchida apenas
### porque recebeu o nome/caminho do arquivo de origem.
monitora_importacao_filtrar_linhas_operacionais <- function(x) {
  x <- data.table::as.data.table(x)
  n_total <- nrow(x)
  if (!n_total) {
    return(list(dt = x, linhas_excluidas = integer(0), n_total = 0L, n_operacionais = 0L))
  }
  operacional <- rep(FALSE, n_total)
  for (cc in names(x)) {
    valor <- x[[cc]]
    operacional <- operacional | (!is.na(valor) & nzchar(trimws(as.character(valor))))
    if (all(operacional)) break
  }
  list(
    dt = x[operacional],
    linhas_excluidas = which(!operacional),
    n_total = as.integer(n_total),
    n_operacionais = as.integer(sum(operacional))
  )
}

for (i in seq_along(csvfiles_lidos)) {
  f <- csvfiles_lidos[i]
  dt <- tryCatch({
    x <- fread(f, colClasses = "character", encoding = "UTF-8", na.strings = c("", "NA", "N/A", "NULL"), showProgress = FALSE, strip.white = FALSE)
    filtro_linhas_x <- monitora_importacao_filtrar_linhas_operacionais(x)
    n_linhas_nao_operacionais_x <- length(filtro_linhas_x$linhas_excluidas)
    if (n_linhas_nao_operacionais_x > 0L) {
      MONITORA_AUDITORIA_LINHAS_NAO_OPERACIONAIS_INPUT_I <- MONITORA_AUDITORIA_LINHAS_NAO_OPERACIONAIS_INPUT_I + 1L
      MONITORA_AUDITORIA_LINHAS_NAO_OPERACIONAIS_INPUT_LISTA[[MONITORA_AUDITORIA_LINHAS_NAO_OPERACIONAIS_INPUT_I]] <- data.table::data.table(
        arquivo = monitora_privacidade_caminho_entrada(f),
        nome_arquivo = basename(f),
        md5 = as.character(csv_audit[arquivo == f, md5][1L]),
        tamanho_bytes = as.numeric(csv_audit[arquivo == f, tamanho_bytes][1L]),
        causa_exclusao = "linha_fisicamente_vazia_antes_da_proveniencia",
        n_linhas_fisicas = filtro_linhas_x$n_total,
        n_linhas_excluidas = as.integer(n_linhas_nao_operacionais_x),
        n_linhas_operacionais = filtro_linhas_x$n_operacionais,
        linhas_fisicas_excluidas = paste(filtro_linhas_x$linhas_excluidas + 1L, collapse = "|")
      )
    }
    x <- filtro_linhas_x$dt
    chave_fonte_x <- monitora_privacidade_caminho_entrada(f)
    MONITORA_CABECALHOS_ORIGINAIS_POR_FONTE[[chave_fonte_x]] <- names(x)
    x[, MONITORA_ARQUIVO_ORIGEM_EXECUCAO := basename(f)]
    x[, MONITORA_CAMINHO_ARQUIVO_ENTRADA := chave_fonte_x]
    nm_x <- names(x)
    bytes_x <- nchar(nm_x, type = "bytes", allowNA = TRUE, keepNA = TRUE)
    csv_audit[arquivo == f, `:=`(
      n_linhas = nrow(x),
      n_linhas_fisicas_lidas = filtro_linhas_x$n_total,
      n_linhas_nao_operacionais_excluidas = as.integer(n_linhas_nao_operacionais_x),
      n_colunas = ncol(x),
      status_leitura = "OK",
      max_bytes_nome_coluna = if (length(bytes_x)) max(bytes_x, na.rm = TRUE) else 0L,
      soma_bytes_nomes_colunas = if (length(bytes_x)) sum(bytes_x, na.rm = TRUE) else 0L,
      n_colunas_com_html = sum(grepl("<[^>]+>|&[A-Za-z]+;", nm_x), na.rm = TRUE),
      n_colunas_com_sufixo_excel = sum(grepl("\\.[0-9]+$", nm_x), na.rm = TRUE),
      n_colunas_longas_100b = sum(bytes_x > 100L, na.rm = TRUE),
      esquema_extremo = ncol(x) > monitora_global_get("MONITORA_ESQUEMA_EXTREMO_NCOLS", 150L) |
        (if (length(bytes_x)) sum(bytes_x, na.rm = TRUE) else 0L) > monitora_global_get("MONITORA_ESQUEMA_EXTREMO_SOMA_BYTES", 9000L) |
        (if (length(bytes_x)) max(bytes_x, na.rm = TRUE) else 0L) > monitora_global_get("MONITORA_ESQUEMA_EXTREMO_MAX_BYTES", 120L)
    )]
    csvfiles_sucesso <- c(csvfiles_sucesso, f)
    x
  }, error = function(e) {
    csv_audit[arquivo == f, status_leitura = paste("ERRO:", conditionMessage(e))]
    monitora_log_registrar_evento("leitura_csv", "ERRO", f, conditionMessage(e), "arquivo ignorado")
    NULL
  })
  monitora_progresso_loop_avancar("leitura_csv", atual = i, detalhe = paste0(i, "/", length(csvfiles_lidos), ": ", basename(f)))
  if (!is.null(dt)) {
    batch_n <- batch_n + 1L
    batch_lista[[batch_n]] <- dt
    if (length(batch_lista) >= monitora_recurso_batch_size_csv()) {
      monitora_io_descarregar_lote_csv(force = TRUE)
      batch_n <- 0L
    }
  }
}
monitora_io_descarregar_lote_csv(force = TRUE)
rm(batch_lista); monitora_recurso_gc("leitura_csv_pos_batches")
if (length(registros_batches) == 0) stop("Nenhum CSV pôde ser lido com sucesso.")
MONITORA_AUDITORIA_LINHAS_NAO_OPERACIONAIS_INPUT <- if (MONITORA_AUDITORIA_LINHAS_NAO_OPERACIONAIS_INPUT_I > 0L) {
  data.table::rbindlist(
    MONITORA_AUDITORIA_LINHAS_NAO_OPERACIONAIS_INPUT_LISTA[seq_len(MONITORA_AUDITORIA_LINHAS_NAO_OPERACIONAIS_INPUT_I)],
    fill = TRUE,
    use.names = TRUE
  )
} else {
  data.table::data.table(
    arquivo = character(), nome_arquivo = character(), md5 = character(), tamanho_bytes = numeric(),
    causa_exclusao = character(), n_linhas_fisicas = integer(), n_linhas_excluidas = integer(),
    n_linhas_operacionais = integer(), linhas_fisicas_excluidas = character()
  )
}
rm(MONITORA_AUDITORIA_LINHAS_NAO_OPERACIONAIS_INPUT_LISTA, MONITORA_AUDITORIA_LINHAS_NAO_OPERACIONAIS_INPUT_I)
monitora_fwrite(
  MONITORA_AUDITORIA_LINHAS_NAO_OPERACIONAIS_INPUT,
  file.path(MONITORA_LOG_DIR, paste0("auditoria_linhas_nao_operacionais_input_", MONITORA_EXEC_ID, ".csv")),
  na = ""
)
monitora_fwrite(
  MONITORA_AUDITORIA_LINHAS_NAO_OPERACIONAIS_INPUT,
  file.path(MONITORA_OUTPUT_DIR, "auditoria_linhas_nao_operacionais_input_ultima_execucao.csv"),
  na = ""
)
monitora_perf_registrar_checkpoint("leitura_csv", paste0(length(csvfiles_sucesso), " CSV(s) lidos com sucesso em ", length(registros_batches), " lote(s)"))

monitora_recurso_controlar("concatenacao_rbindlist_pre", risco = "muito_alto", force_log = TRUE)
registros <- data.table::rbindlist(registros_batches, fill = TRUE, use.names = TRUE)

# trava diagnóstica contra contaminação de registros por arquivos de
# controle de correção/replay. Estes campos são esperados na trilha semântica,
# mas não podem aparecer na base concatenada de registros importados.
monitora_cols_controle_replay_vazaram <- intersect(
  c(
    "id_correcao", "tipo_correcao", "acao", "responsavel", "ordem_operacao",
    "escopo_aplicacao", "arquivo_origem_trilha", "hash_operacao_semantica",
    "linha_indice", "linhas_alvo_serializadas", "valor_original_esperado",
    "valor_novo", "forma_valida_escolhida", "token_removido", "uuid_registro"
  ),
  names(registros)
)
if (length(monitora_cols_controle_replay_vazaram) > 0L) {
  aud_vaz <- data.table::data.table(
    coluna_controle_detectada = monitora_cols_controle_replay_vazaram,
    motivo = "coluna_de_trilha_semantica_detectada_em_registros_importados",
    acao_requerida = "remover arquivos de controle de input/ ou garantir filtro de exclusao antes da importacao"
  )
  monitora_fwrite(aud_vaz, file.path(MONITORA_LOG_DIR, paste0("ERRO_vazamento_correcoes_semanticas_em_registros_", MONITORA_EXEC_ID, ".csv")))
  monitora_fwrite(aud_vaz, file.path(MONITORA_OUTPUT_DIR, "ERRO_vazamento_correcoes_semanticas_em_registros_ultima_execucao.csv"))
  stop(
    "Arquivos de controle de correção/replay foram importados como dados de campo. ",
    "Colunas de controle detectadas em registros: ",
    paste(monitora_cols_controle_replay_vazaram, collapse = ", "),
    ". O script interrompeu para evitar diagnósticos incorretos.",
    call. = FALSE
  )
}
rm(monitora_cols_controle_replay_vazaram)

monitora_auditar_esquema_colunas(registros, fase = "pos_concatenacao_csv", arquivo = "registros_concatenados")

