monitora_perf_registrar_checkpoint("padronizacao_categorias_e_material_botanico", "padronização de categorias gerais, materiais botânicos e campos condicionais", registros_corrig)

### - -----------------------------------------------------------
### Relatório opt-in de pipes por contrato único (default OFF, ver
### MONITORA_DIAGNOSTICO_PIPES_CONTRATO) capturado ANTES do bloco de extração
### do último token (abaixo) rodar sobre as colunas condicionais de forma de
### vida (bromelioide/cactacea/orquidea/samambaia × nativa/exótica/seca-morta)
### e sobre ponto_amostral/ponto_metro/Encostam. A auditoria encontrou que o
### pipe presente em
### registros_importados_bruto.csv já não aparece em nenhum diagnóstico
### posterior (registros_corrig) porque o bloco abaixo resolve
### (`word(x, sep = fixed("|"), -1)`) essas colunas bem antes de qualquer
### checkpoint existente -- este é o único ponto de integração que pode
### capturar o pipe ainda intacto, para fins de diagnóstico. Reaproveita
### integralmente o wrapper e a função já testados; não introduz lógica nova.
### Nunca bloqueia o fluxo nem altera
### `registros_corrig` -- envolvido em try além do wrapper já tratar erro
### internamente.
if (exists("monitora_pipe_contrato_relatorio_optin_seguro", mode = "function")) {
  try(monitora_pipe_contrato_relatorio_optin_seguro(
    registros_corrig, contexto = "pre_normalizacao_formas_vida_condicionais",
    output_dir = MONITORA_OUTPUT_DIR, log_dir = MONITORA_LOG_DIR, exec_id = MONITORA_EXEC_ID
  ), silent = TRUE)
}

### - -----------------------------------------------------------
### Resolve campos select_one condicionais/esparsos por elegibilidade no grupo
### (COLETA, quando disponivel), em vez de aplicar sempre o ultimo token do
### valor com pipe a todos os pontos elegiveis. Se a contagem de tokens nao
### bate com a contagem de pontos elegiveis, degrada para NA no campo filho:
### e preferivel manter pendencia explicita a propagar valor semanticamente
### errado e silencioso.


.monitora_pipe_cond_grupo_035m_d3 <- if ("COLETA" %in% names(registros_corrig)) {
  as.character(registros_corrig$COLETA)
} else {
  rep("todos", nrow(registros_corrig))
}
.monitora_pipe_cond_ordem_035m_d3 <- if ("ponto_amostral (amostragem/registro)" %in% names(registros_corrig)) {
  suppressWarnings(as.integer(gsub("[^0-9]+", "", as.character(registros_corrig$`ponto_amostral (amostragem/registro)`))))
} else {
  seq_len(nrow(registros_corrig))
}

### extração do último token em colunas específicas (o SISMONITORA exporta a lista concatenada por
### "|")

## ponto amostral

registros_corrig$`ponto_amostral (amostragem/registro)` <-
  word(registros_corrig$`ponto_amostral (amostragem/registro)`,
       sep = fixed("|"),
       -1)

## metro

registros_corrig$`ponto_metro (amostragem/registro)` <-
  word(registros_corrig$`ponto_metro (amostragem/registro)`,
       sep = fixed("|"),
       -1)

## encostam na vareta

registros_corrig$`**Encostam** na vareta: (amostragem/registro)` <-
  word(registros_corrig$`**Encostam** na vareta: (amostragem/registro)`,
       sep = fixed("|"),
       -1)

### descrição do ponto amostral (corrigido)

if (is.null(registros_corrig[['Descreva observações gerais do ponto amostral, caso necessário: (amostragem/registro)']]))
  set(registros_corrig, j = 'Descreva observações gerais do ponto amostral, caso necessário: (amostragem/registro)', value = NA_character_)

# Número de tokens e último token identificado.
obs_pa_tokens <- registros_corrig[, .(
  Tokens = lapply(strsplit(`Descreva observações gerais do ponto amostral, caso necessário: (amostragem/registro)`, "\\|"), length),
  Last_token = lapply(strsplit(`Descreva observações gerais do ponto amostral, caso necessário: (amostragem/registro)`, "\\|"), function(x) if(length(x) > 0) tail(x, 1) else NA)
), by = .(COLETA, `ponto_amostral (amostragem/registro)`)]

# Número máximo de tokens observado.
obs_pa_tokens[, MaxTokens_coleta := max(unlist(Tokens)), by = .(COLETA)]

# Token válido.
obs_pa_tokens[, `Descreva observações gerais do ponto amostral, caso necessário: (amostragem/registro)` := ifelse(Tokens == MaxTokens_coleta, Last_token, NA_character_)]

# Atualização dos tokens válidos em registros_corrig.
registros_corrig$`Descreva observações gerais do ponto amostral, caso necessário: (amostragem/registro)` <- obs_pa_tokens$`Descreva observações gerais do ponto amostral, caso necessário: (amostragem/registro)`

rm(obs_pa_tokens)

# Remoção de quebras de linha em campos descritivos, coletores e plaqueta.

registros_corrig$`Número da plaqueta (amostragem)` <-
  str_replace_all(
    registros_corrig$`Número da plaqueta (amostragem)`,
    "[[:punct:]]",
    " "
  )

registros_corrig$COLETORES <-
  str_replace_all(
    registros_corrig$COLETORES,
    "[\r\n]",
    " "
  )

registros_corrig$`Descreva observações gerais do ponto amostral, caso necessário: (amostragem/registro)` <-
  str_replace_all(
    registros_corrig$`Descreva observações gerais do ponto amostral, caso necessário: (amostragem/registro)`,
    "[\r\n]",
    " "
  )

registros_corrig$`Descreva observações gerais do transecto, caso necessário:` <-
  str_replace_all(
    registros_corrig$`Descreva observações gerais do transecto, caso necessário:`,
    "[\r\n]",
    " "
  )

registros_corrig$`Descreva os impactos, ações de manejo ou uso ocorridos (data, método, severidade, quando for o caso), caso conhecidos: (impact_manejo_uso)` <-
