monitora_especie_protocolos_suportados <- function() {
  c(
    "PLANTASHERBACEASELENHOSAS_CAMPSAV_11AGO22",
    "PLANTASHERBACEASELENHOSAS_CAMPSAV_11AGO22 Básico e Avançado",
    "PLANTASHERBACEASELENHOSAS_CAMPSAV_05MAI23",
    "PLANTASHERBACEASELENHOSAS_CAMPSAV_05MAI23 Básico e Avançado",
    "PLANTASHERBACEASELENHOSAS_CAMPSAV_03MAI24",
    "PLANTASHERBACEASELENHOSAS_CAMPSAV_03MAI24 Básico e Avançado",
    "PLANTASHERBACEASELENHOSAS_CAMPSAV_21FEV25"
  )
}

monitora_especie_protocolo_canonico <- function(protocolo) {
  p <- trimws(as.character(protocolo))
  p_ascii <- toupper(iconv(p, from = "", to = "ASCII//TRANSLIT", sub = ""))
  p_compacto <- gsub("[^A-Z0-9]", "", p_ascii)
  marcadores <- c("11AGO22", "05MAI23", "03MAI24", "21FEV25")
  canonicos <- c(
    "PLANTASHERBACEASELENHOSAS_CAMPSAV_11AGO22",
    "PLANTASHERBACEASELENHOSAS_CAMPSAV_05MAI23",
    "PLANTASHERBACEASELENHOSAS_CAMPSAV_03MAI24",
    "PLANTASHERBACEASELENHOSAS_CAMPSAV_21FEV25"
  )
  familia_campsav <- grepl("PLANTASHERBACEASELENHOSAS", p_compacto, fixed = TRUE) &
    grepl("CAMPSAV", p_compacto, fixed = TRUE)
  hits <- vapply(marcadores, function(m) grepl(m, p_compacto, fixed = TRUE), logical(length(p_compacto)))
  if (is.null(dim(hits))) hits <- matrix(hits, ncol = length(marcadores))
  n_hits <- rowSums(hits, na.rm = TRUE)
  out <- rep(NA_character_, length(p))
  for (jj in seq_along(marcadores)) out[familia_campsav & n_hits == 1L & hits[, jj]] <- canonicos[jj]
  out[is.na(p) | !nzchar(p)] <- NA_character_
  out
}

monitora_especie_validar_protocolos <- function(protocolo) {
  p <- as.character(protocolo)
  p_canonico <- monitora_especie_protocolo_canonico(p)
  invalido <- is.na(p_canonico)
  if (any(invalido)) {
    exemplos <- utils::head(unique(p[invalido]), 10L)
    exemplos[is.na(exemplos)] <- "<NA>"
    stop(
      "Protocolo de XLSForm ausente ou desconhecido na normalização de espécies: ",
      paste(exemplos, collapse = " | "),
      ". A execução foi bloqueada para impedir perda silenciosa de dados.",
      call. = FALSE
    )
  }
  invisible(p_canonico)
}

monitora_especie_normalizar_valor_por_protocolo <- function(x, protocolo) {
  x <- as.character(x)
  protocolo <- as.character(protocolo)
  if (length(protocolo) == 1L && length(x) != 1L) {
    protocolo <- rep(protocolo, length(x))
  }
  if (length(x) != length(protocolo)) {
    stop("Valor de espécie e protocolo possuem cardinalidades incompatíveis.", call. = FALSE)
  }
  protocolo_canonico <- monitora_especie_validar_protocolos(protocolo)
  historico <- protocolo_canonico != "PLANTASHERBACEASELENHOSAS_CAMPSAV_21FEV25"
  out <- x
  idx <- historico & !is.na(out) & nzchar(out)
  if (any(idx)) {
    out[idx] <- trimws(stringr::word(out[idx], sep = stringr::fixed("|"), -1L))
  }
  out
}

