  arquivo_espacial_antigo <- if (exists("MONITORA_ARQUIVO_CORRECOES_ESPACIAIS", inherits = FALSE)) MONITORA_ARQUIVO_CORRECOES_ESPACIAIS else file.path(MONITORA_INPUT_DIR, "correcoes_espaciais.csv")
