  monitora_correcao_console_msg("Modo ", MONITORA_MODO_EXECUCAO, ": painel incremental a partir de registros_corrig.csv; efeitos históricos não serão reaplicados, a linhagem será herdada e somente a sessão atual será aplicada.")
}

