  monitora_fwrite(monitora_correcao_template(), file.path(MONITORA_CORRECOES_DIR, "modelo_correcoes_campos.csv"), na = "")
  MONITORA_META_XLSFORMS_CORRECOES <- monitora_correcao_xlsforms_embutidos_cache_publicacao_ae()
  MONITORA_DEPENDENCIAS_CORRECOES <- monitora_correcao_unificar_dependencias(MONITORA_META_XLSFORMS_CORRECOES$dependencias)

  if (nrow(MONITORA_META_XLSFORMS_CORRECOES$arquivos) > 0) {
    monitora_fwrite(MONITORA_META_XLSFORMS_CORRECOES$arquivos, file.path(MONITORA_LOG_DIR, paste0("xlsforms_detectados_painel_correcoes_", MONITORA_EXEC_ID, ".csv")), na = "")
    monitora_fwrite(MONITORA_META_XLSFORMS_CORRECOES$campos, file.path(MONITORA_CORRECOES_DIR, "dicionario_xlsform_campos_detectados.csv"), na = "")
    monitora_fwrite(MONITORA_META_XLSFORMS_CORRECOES$opcoes, file.path(MONITORA_CORRECOES_DIR, "dicionario_xlsform_opcoes_detectadas.csv"), na = "")
    monitora_fwrite(MONITORA_DEPENDENCIAS_CORRECOES, file.path(MONITORA_CORRECOES_DIR, "dicionario_xlsform_dependencias_condicionais.csv"), na = "")
    monitora_log_registrar_evento("painel_correcoes_xlsform", "INFO", NA_character_, paste0(nrow(MONITORA_META_XLSFORMS_CORRECOES$arquivos), " XLSForm(s) embutido(s) carregado(s) para regras auxiliares"), "campos/opcoes/dependencias embutidos exportados em output/correcoes_campos")
  } else {
    monitora_log_registrar_evento("painel_correcoes_xlsform", "AVISO", NA_character_, "Nenhum metadado XLSForm embutido carregado; painel usará apenas a estrutura de registros_corrig", "ver seção de metadados XLSForm embutidos no script")
  }

  registros_corrig <- monitora_correcao_preparar_schema_edicao_painel(registros_corrig, MONITORA_META_XLSFORMS_CORRECOES, contexto = "pre_dicionario_painel")
  MONITORA_DICIONARIO_ATRIBUTOS_CORRECOES <- monitora_correcao_dicionario_atributos(registros_corrig, MONITORA_META_XLSFORMS_CORRECOES)
  monitora_fwrite(MONITORA_DICIONARIO_ATRIBUTOS_CORRECOES, file.path(MONITORA_CORRECOES_DIR, "dicionario_atributos_registros_corrig.csv"), na = "")
  MONITORA_N_ATRIBUTOS_PAINEL_EDITAVEIS <- if ("painel_editavel" %in% names(MONITORA_DICIONARIO_ATRIBUTOS_CORRECOES)) sum(MONITORA_DICIONARIO_ATRIBUTOS_CORRECOES$painel_editavel %in% TRUE, na.rm = TRUE) else nrow(MONITORA_DICIONARIO_ATRIBUTOS_CORRECOES)
  MONITORA_N_ATRIBUTOS_TEMPLATE_SISMONITORA <- if ("atende_template_sismonitora" %in% names(MONITORA_DICIONARIO_ATRIBUTOS_CORRECOES)) sum(MONITORA_DICIONARIO_ATRIBUTOS_CORRECOES$atende_template_sismonitora %in% TRUE, na.rm = TRUE) else NA_integer_
  monitora_correcao_console_msg("Dicionário do painel preparado: ", nrow(MONITORA_DICIONARIO_ATRIBUTOS_CORRECOES), " atributo(s) em registros_corrig; ", MONITORA_N_ATRIBUTOS_TEMPLATE_SISMONITORA, " constante(s) no template SISMONITORA/XLSForm 2025; ", MONITORA_N_ATRIBUTOS_PAINEL_EDITAVEIS, " editável(is) exibido(s) ao usuário.")

 ### replay de correções anteriores antes dos diagnósticos e do painel.
 ### Esse bloco transforma correcoes_campos.csv/correcoes_semanticas.csv em uma
 ### reaplicação explícita do estado corrigido, sem confundir o arquivo antigo
 ### com o arquivo de novas operações da sessão atual.
  if (isTRUE(get0("MONITORA_CORRECOES_REAPLICACAO_ARQUIVO_EXISTE", ifnotfound = FALSE, inherits = TRUE))) {
    arquivo_replay <- get0("MONITORA_ARQUIVO_CORRECOES_ANTERIORES", ifnotfound = file.path(MONITORA_INPUT_DIR, "correcoes_campos.csv"), inherits = TRUE)
    registros_corrig <- monitora_correcao_reaplicar_arquivo_semantico(
      registros_corrig,
      arquivo = arquivo_replay,
      dicionario = MONITORA_META_XLSFORMS_CORRECOES$campos,
      contexto = "pre_painel_fluxo_principal"
    )
    MONITORA_ARQUIVO_CORRECOES_CAMPOS_REAPLICADO <<- arquivo_replay
    MONITORA_ARQUIVO_CORRECOES_CAMPOS <<- monitora_correcao_preparar_arquivo_sessao_pos_replay()
    monitora_correcao_console_msg("Replay concluído. Novas operações do painel serão gravadas separadamente em ", MONITORA_ARQUIVO_CORRECOES_CAMPOS, ".")
    monitora_perf_registrar_checkpoint("reaplicacao_correcoes_anteriores_pre_painel", "correções anteriores reaplicadas antes dos diagnósticos pré-painel", registros_corrig)
  }

 ### aliases históricos nas listas de categoria são harmonizados para
 ### `desconhecida`, com auditoria. Encostam=desconhecida não é mais movido
 ### automaticamente para nativa: categoria não observada não pode ser
 ### inferida e permanece pendência impeditiva explícita no painel.
  MONITORA_CANONICALIZACAO_DESCONHECIDA_PRE_PAINEL <- monitora_correcao_canonicalizar_aliases_desconhecida(
    registros_corrig,
    output_dir = MONITORA_OUTPUT_DIR,
    log_dir = MONITORA_LOG_DIR,
    exec_id = MONITORA_EXEC_ID,
    contexto = "pre_painel_pos_dicionario"
  )
  registros_corrig <- data.table::as.data.table(MONITORA_CANONICALIZACAO_DESCONHECIDA_PRE_PAINEL$dt)
  if (length(MONITORA_CANONICALIZACAO_DESCONHECIDA_PRE_PAINEL$linhas) > 0L) {
    monitora_perf_registrar_checkpoint("canonicalizacao_aliases_desconhecida_pre_painel", "aliases históricos de desconhecida harmonizados nas listas de categoria com relatório auditável", registros_corrig)
  }

 ### normaliza placeholders serializados antes de qualquer derivação.
 ### O valor histórico "---|---" é ausência inequívoca e não pode recriar os
 ### tokens outra/outros removidos por uma sanitização assistida.
  MONITORA_SANITIZACAO_PLACEHOLDERS_PRE_PAINEL <- monitora_correcao_sanitizar_placeholders_semanticos(
    registros_corrig,
    linhas = seq_len(nrow(registros_corrig)),
    contexto = "pre_painel_antes_fechamento_hierarquico",
    gravar = TRUE
  )
  registros_corrig <- data.table::as.data.table(MONITORA_SANITIZACAO_PLACEHOLDERS_PRE_PAINEL$dt)
  if (nrow(MONITORA_SANITIZACAO_PLACEHOLDERS_PRE_PAINEL$audit)) {
    monitora_perf_registrar_checkpoint(
      "sanitizacao_placeholders_semanticos_pre_painel",
      paste0(nrow(MONITORA_SANITIZACAO_PLACEHOLDERS_PRE_PAINEL$audit), " placeholder(es) serializado(s) convertido(s) para ausência semântica com auditoria"),
      registros_corrig
    )
  }

  ### Fotografia exclusivamente auditiva de CPF antes das operações semânticas.
  ### Permite relatar também valores inválidos pertencentes a coletas que uma
  ### EXCCOL removerá depois, sem alterar o estado entregue ao painel.
  MONITORA_AUDITORIA_CPF_PRE_OPERACOES <- monitora_publicacao_ab_normalizar_cpf_deterministico(
    data.table::copy(registros_corrig),
    output_dir = MONITORA_OUTPUT_DIR,
    log_dir = MONITORA_LOG_DIR,
    exec_id = MONITORA_EXEC_ID,
    contexto = "pre_operacoes_semanticas_cpf",
    somente_auditar = TRUE
  )$auditoria

 ### /: fechamento ascendente global antes dos diagnósticos. Apenas
 ### acrescenta ancestrais inequívocos ausentes; não remove superiores órfãos,
 ### que continuam visíveis ao painel e exigem operação explícita.
  MONITORA_AUDITORIA_FECHAMENTO_HIERARQUICO_PRE_PAINEL <- tryCatch(
    monitora_correcao_recalcular_superiores_vinculados(
      registros_corrig,
      linhas = seq_len(nrow(registros_corrig)),
      deps = NULL,
      dicionario = MONITORA_META_XLSFORMS_CORRECOES$campos,
      afetacoes = NULL,
      modo_encostam = "acrescentar"
    ),
    error = function(e) {
      stop("Fechamento hierárquico pré-painel falhou; a execução não continuará ocultando sanitização obrigatória: ", conditionMessage(e), call. = FALSE)
    }
  )
  if (nrow(MONITORA_AUDITORIA_FECHAMENTO_HIERARQUICO_PRE_PAINEL)) {
    MONITORA_AUDITORIA_FECHAMENTO_HIERARQUICO_PRE_PAINEL[, fase_fechamento := "pre_painel"]
  } else {
    MONITORA_AUDITORIA_FECHAMENTO_HIERARQUICO_PRE_PAINEL <- data.table::data.table(
      id_correcao = "FECHAMENTO_HIERARQUICO_CONTRATO",
      status = "sem_alteracao_necessaria",
      mensagem = "Nenhum token superior inequívoco ausente foi encontrado antes do painel",
      atributo = NA_character_, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_,
      dependent_name = NA_character_, parent_name = NA_character_, token = NA_character_, fase_fechamento = "pre_painel"
    )
  }
  arq_fech_pre <- file.path(MONITORA_CORRECOES_DIR, paste0("auditoria_fechamento_hierarquico_pre_painel_", MONITORA_EXEC_ID, ".csv"))
  monitora_fwrite(MONITORA_AUDITORIA_FECHAMENTO_HIERARQUICO_PRE_PAINEL, arq_fech_pre, na = "")
  regras_fech_pre <- monitora_correcao_contrato_fechamento_hierarquico(registros_corrig)
  if (nrow(regras_fech_pre)) regras_fech_pre[, `:=`(tipo_registro = "regra_contratual", fase_fechamento = "contrato")]
  audit_fech_pre_rel <- data.table::copy(MONITORA_AUDITORIA_FECHAMENTO_HIERARQUICO_PRE_PAINEL)
  audit_fech_pre_rel[, tipo_registro := "sanitizacao_aplicada"]
  rel_fech_pre_completo <- data.table::rbindlist(list(regras_fech_pre, audit_fech_pre_rel), fill = TRUE, use.names = TRUE)
  monitora_fwrite(rel_fech_pre_completo, file.path(MONITORA_CORRECOES_DIR, "auditoria_fechamento_hierarquico_ultima_execucao.csv"), na = "")
  assign("MONITORA_AUDITORIA_FECHAMENTO_HIERARQUICO_ULTIMA", rel_fech_pre_completo, envir = .GlobalEnv)
  monitora_perf_registrar_checkpoint(
    "fechamento_hierarquico_pre_painel",
    paste0(sum(as.character(MONITORA_AUDITORIA_FECHAMENTO_HIERARQUICO_PRE_PAINEL$status) == "aplicada", na.rm = TRUE), " sanitização(ões) ascendentes inequívocas aplicadas e auditadas antes dos diagnósticos"),
    registros_corrig
  )

  if (isTRUE(MONITORA_GERAR_RELATORIOS_SUPORTE_PAINEL)) {
    MONITORA_RELATORIOS_SUPORTE_PRE_PAINEL <- monitora_relatorios_suporte_painel_gravar(registros_corrig, fase = "pre_painel", atualizar_saida_principal = FALSE)
    monitora_perf_registrar_checkpoint("relatorios_suporte_pre_painel", "relatórios de exóticas e apoio gerados antes da abertura do painel", registros_corrig)
    if (exists("monitora_oraculo_comparar_resumo_ocorrencias", mode = "function", inherits = TRUE)) {
      try(monitora_oraculo_comparar_resumo_ocorrencias(fase_atual = "pre_painel", fase_oraculo = "pos_painel"), silent = TRUE)
    }
  }

  if (isTRUE(MONITORA_ABRIR_PAINEL_CORRECOES)) {
    try(monitora_cache_painel_salvar(registros_corrig, MONITORA_META_XLSFORMS_CORRECOES, relatorios_pre = if (exists("MONITORA_RELATORIOS_SUPORTE_PRE_PAINEL", inherits = FALSE)) MONITORA_RELATORIOS_SUPORTE_PRE_PAINEL else NULL, validacao_espacial_pre = if (exists("MONITORA_VALIDACAO_ESPACIAL_PRE_PAINEL_RESULTADO", inherits = FALSE)) MONITORA_VALIDACAO_ESPACIAL_PRE_PAINEL_RESULTADO else NULL), silent = TRUE)
    monitora_correcao_console_msg("Preparando abertura do painel de correções assistidas.")
    monitora_perf_registrar_checkpoint("painel_correcoes_preparacao_shiny", "relatórios e metadados prontos; inicializando Shiny", registros_corrig)
    monitora_correcao_console_msg("A página do painel pode ficar cinza/opaca ao fechar; isso apenas indica que a sessão Shiny foi encerrada. Acompanhe o avanço pelo console.")
    monitora_log_registrar_evento("painel_correcoes", "INFO", NA_character_, "Abrindo painel Shiny de correções assistidas", "aguardar o fechamento do painel para continuar a execução")
    monitora_registros_importados_garantir_pre_painel(NULL, contexto = "fluxo_principal")
    monitora_publicacao_p_auditar_schema_pre_painel(registros_corrig, contexto = "pre_painel_fluxo_principal")
    monitora_correcao_console_msg("Chamando monitora_correcao_painel(); se o navegador não abrir, verificar porta Shiny no terminal.")
    MONITORA_TEMPO_USUARIO_PAINEL_SEG <- tryCatch({
      res_painel <- monitora_correcao_painel(registros_corrig, MONITORA_META_XLSFORMS_CORRECOES, MONITORA_ARQUIVO_CORRECOES_CAMPOS)
      MONITORA_CORRECOES_GERADAS_PAINEL <- res_painel
      MONITORA_EVENTOS_SEMANTICOS_GERADOS_PAINEL <<- data.table::data.table()
      if (exists("monitora_correcao_gravar_trilha_semantica", mode = "function", inherits = TRUE) &&
          isTRUE(nrow(data.table::as.data.table(res_painel)) > 0L)) {
        MONITORA_EVENTOS_SEMANTICOS_GERADOS_PAINEL <<- monitora_correcao_gravar_trilha_semantica(
          res_painel,
          arquivo_origem = MONITORA_ARQUIVO_CORRECOES_CAMPOS,
          fase = "sessao_painel",
          status = "salva_pelo_painel",
          contexto = "fluxo_principal"
        )
      }
      0
    }, error = function(e) {
      stop(e)
    })
    monitora_correcao_console_msg("Painel encerrado; retomando fluxo principal do script. O tempo humano de edição foi desconsiderado da PERF.")
    monitora_perf_registrar_checkpoint("painel_correcoes_painel_encerrado", "painel Shiny fechado; tempo de edição do usuário excluído da duração computacional", registros_corrig)
    if (exists("MONITORA_CORRECOES_GERADAS_PAINEL") && nrow(MONITORA_CORRECOES_GERADAS_PAINEL) > 0) {
      MONITORA_CORRECOES_ARQUIVO_EXISTE <- TRUE
      n_itens_painel <- nrow(MONITORA_CORRECOES_GERADAS_PAINEL)
      n_sem_painel <- tryCatch(monitora_correcao_contar_operacoes_semanticas(data.table::as.data.table(MONITORA_CORRECOES_GERADAS_PAINEL)), error = function(e) n_itens_painel)
      monitora_correcao_console_msg(n_sem_painel, " operação(ões) semântica(s) retornada(s) pelo painel, ", n_itens_painel, " item(ns) auditável(is); arquivo de correções será aplicado na sequência quando habilitado.")
      monitora_log_registrar_evento("painel_correcoes", "INFO", MONITORA_ARQUIVO_CORRECOES_CAMPOS, paste0(n_sem_painel, " operação(ões) semântica(s) e ", n_itens_painel, " item(ns) auditável(is) salvos pelo painel"), "correções serão aplicadas na sequência")
    } else {
      monitora_correcao_console_msg("Nenhuma correção nova retornada pelo painel; seguindo para a próxima etapa.")
      monitora_log_registrar_evento("painel_correcoes", "INFO", MONITORA_ARQUIVO_CORRECOES_CAMPOS, "Painel fechado sem correções novas", "seguir fluxo principal")
    }
  }

  if (isTRUE(MONITORA_APLICAR_CORRECOES_CAMPOS) && isTRUE(MONITORA_CORRECOES_ARQUIVO_EXISTE)) {
    monitora_correcao_console_msg("Aplicando correções assistidas registradas em ", MONITORA_ARQUIVO_CORRECOES_CAMPOS, ".")
 ### a linhagem não pode depender de o arquivo ter sido criado pelo
 ### painel nesta mesma sessão. Execuções headless/replay operacional também
 ### aplicam decisões semânticas reais e, até aqui, produziam Corrig correto
 ### com ledger cumulativo vazio. Registra o plano v2 antes da mutação e usa
 ### exatamente esses eventos para confirmar a aplicação depois do retorno
 ### bem-sucedido do motor atômico. O caminho interativo reutiliza os eventos
 ### já registrados pelo painel, sem duplicá-los.
    eventos_semanticos_aplicacao_atual <- data.table::data.table()
    if (exists("MONITORA_EVENTOS_SEMANTICOS_GERADOS_PAINEL", inherits = FALSE) &&
        nrow(data.table::as.data.table(MONITORA_EVENTOS_SEMANTICOS_GERADOS_PAINEL)) > 0L) {
      eventos_semanticos_aplicacao_atual <- data.table::as.data.table(MONITORA_EVENTOS_SEMANTICOS_GERADOS_PAINEL)
    } else if (exists("monitora_correcao_gravar_trilha_semantica", mode = "function", inherits = TRUE)) {
      plano_semantico_arquivo <- monitora_correcao_ler_operacoes_semanticas(MONITORA_ARQUIVO_CORRECOES_CAMPOS)
      eventos_semanticos_aplicacao_atual <- monitora_correcao_gravar_trilha_semantica(
        plano_semantico_arquivo,
        arquivo_origem = MONITORA_ARQUIVO_CORRECOES_CAMPOS,
        fase = "sessao_arquivo_correcoes",
        status = "validada_para_aplicacao",
        contexto = "fluxo_principal_headless_ou_arquivo_externo"
      )
    }
    if (isTRUE(get0("MONITORA_GRAVAR_TRILHA_SEMANTICA_CORRECOES", ifnotfound = TRUE, inherits = TRUE)) &&
        !nrow(data.table::as.data.table(eventos_semanticos_aplicacao_atual))) {
      stop("Aplicação bloqueada antes da mutação: arquivo de correções possui operações, mas a trilha semântica v2 não pôde ser materializada.", call. = FALSE)
    }
    registros_corrig <- monitora_correcao_preparar_schema_edicao_painel(registros_corrig, MONITORA_META_XLSFORMS_CORRECOES, contexto = "pre_aplicacao_correcoes_fluxo_principal")
    registros_corrig <- monitora_correcao_aplicar_arquivo(registros_corrig, MONITORA_ARQUIVO_CORRECOES_CAMPOS, MONITORA_META_XLSFORMS_CORRECOES$campos)
    if (isTRUE(get0("MONITORA_RECALC_DATA_HORA_EXECUTADO_ULTIMO", ifnotfound = FALSE, inherits = TRUE))) {
      monitora_correcao_console_msg("Recálculo de DATA_MONITORA_PARSEADA/ANO executado dentro da aplicação atômica das correções; checkpoint granular já registrado.")
    } else {
      monitora_correcao_console_msg("Recálculo de DATA_MONITORA_PARSEADA/ANO pulado: correções aplicadas não alteraram Data (data_hora).")
    }
    aud_persist_retorno <- monitora_correcao_auditar_persistencia_limpeza_outras_formas(
      registros_corrig,
      MONITORA_ARQUIVO_CORRECOES_CAMPOS,
      MONITORA_META_XLSFORMS_CORRECOES$campos,
      contexto = "pos_aplicacao_retorno",
      abortar = FALSE
    )
    monitora_correcao_marcar_checkpoint_por_persistencia(aud_persist_retorno, contexto = "pos_aplicacao_retorno")
    monitora_correcao_console_msg("Aplicação das correções assistidas concluída; seguindo para validações/estatísticas.")
    monitora_perf_registrar_checkpoint("painel_correcoes_aplicacao_arquivo", "arquivo de correções assistidas aplicado aos registros", registros_corrig)
    MONITORA_AUDITORIA_SEMANTICA_FORMAS_VIDA <- monitora_correcao_auditar_formas_vida_semantica(registros_corrig, contexto = paste0("pos_correcoes_", MONITORA_EXEC_ID), abortar = FALSE)
    if (nrow(MONITORA_AUDITORIA_SEMANTICA_FORMAS_VIDA)) {
      MONITORA_PERSISTENCIA_DERIVACOES_PENDENTES <- TRUE
      MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS <- TRUE
    }
    if (nrow(data.table::as.data.table(eventos_semanticos_aplicacao_atual)) > 0L) {
      monitora_linhagem_registrar_aplicacoes(
        eventos_semanticos_aplicacao_atual,
        fase = if (exists("MONITORA_EVENTOS_SEMANTICOS_GERADOS_PAINEL", inherits = FALSE) &&
                    nrow(data.table::as.data.table(MONITORA_EVENTOS_SEMANTICOS_GERADOS_PAINEL)) > 0L) "sessao_painel" else "sessao_arquivo_correcoes",
        status = "aplicada",
        arquivo_ledger = MONITORA_ARQUIVO_CORRECOES_CAMPOS
      )
    }
    monitora_perf_registrar_checkpoint("painel_correcoes_auditoria_semantica", "auditoria semântica de colunas principais de formas de vida após correções", registros_corrig)
  } else if (isTRUE(MONITORA_APLICAR_CORRECOES_CAMPOS)) {
 ### quando MONITORA_APLICAR_CORRECOES_CAMPOS foi pedido
 ### explicitamente (modo headless) e não há arquivo de correções
 ### aplicável, isso é erro de configuração -- não uma ausência normal do
 ### fluxo interativo (onde o painel é o próprio meio de criar o
 ### arquivo). Falhar de forma clara em vez de seguir silenciosamente.
    if (isTRUE(get0("MONITORA_APLICAR_CORRECOES_CAMPOS_PEDIDO_EXPLICITO", ifnotfound = FALSE, inherits = TRUE)) &&
        !isTRUE(MONITORA_ABRIR_PAINEL_CORRECOES)) {
      stop(
        "MONITORA_APLICAR_CORRECOES_CAMPOS=TRUE foi pedido explicitamente (modo headless), mas nenhum arquivo de correções válido foi encontrado em '",
        MONITORA_ARQUIVO_CORRECOES_CAMPOS, "' (inexistente ou vazio). Forneça um correcoes_campos.csv válido ou desligue MONITORA_APLICAR_CORRECOES_CAMPOS.",
        call. = FALSE
      )
    }
    monitora_correcao_console_msg("Nenhum arquivo de correções aplicável encontrado; seguindo sem aplicar correções assistidas.")
    monitora_log_registrar_evento("correcoes_campos", "INFO", MONITORA_ARQUIVO_CORRECOES_CAMPOS, "Arquivo de correções inexistente ou vazio; etapa de aplicação ignorada", "fluxo padrão sem painel")
  }

  if (isTRUE(MONITORA_VALIDAR_CONDICIONAIS_CORRECOES) && nrow(MONITORA_DEPENDENCIAS_CORRECOES) > 0) {
    monitora_correcao_console_msg("Iniciando validação de dependências condicionais após correções assistidas.")
    MONITORA_AUDITORIA_DEPENDENCIAS_CONDICIONAIS <- monitora_correcao_validar_dependencias(registros_corrig, MONITORA_DEPENDENCIAS_CORRECOES, MONITORA_META_XLSFORMS_CORRECOES$campos)
    monitora_perf_registrar_checkpoint("painel_correcoes_validacao_dependencias", "dependências condicionais revalidadas após painel/correções", registros_corrig)
  } else {
    MONITORA_AUDITORIA_DEPENDENCIAS_CONDICIONAIS <- data.table::data.table()
  }

  if (isTRUE(MONITORA_GERAR_RELATORIOS_SUPORTE_PAINEL) && isTRUE(MONITORA_GERAR_RELATORIOS_POS_CORRECOES)) {
    if (isTRUE(get0("MONITORA_OPCAO_OTIMIZAR_RELATORIOS_SUPORTE_POS", ifnotfound = "S", inherits = TRUE) == "S") &&
        isTRUE(MONITORA_CORRECOES_ARQUIVO_EXISTE) &&
        !monitora_correcao_arquivo_afeta_relatorios_suporte(MONITORA_ARQUIVO_CORRECOES_CAMPOS)) {
      MONITORA_RELATORIOS_SUPORTE_POS_CORRECOES <- MONITORA_RELATORIOS_SUPORTE_PRE_PAINEL
      monitora_correcao_console_msg("Relatórios pós-correções de apoio pulados: as correções não alteraram formas de vida, espécies, hábitos ou Encostam.")
      monitora_log_registrar_evento("relatorios_suporte_pos_correcoes", "INFO", NA_character_, "Relatórios pós-correções reutilizados do pré-painel por ausência de alteração relevante", "otimização de relatórios pós-correções")
      monitora_perf_registrar_checkpoint("relatorios_suporte_pos_correcoes_pulados", "relatórios pós-correções reutilizados sem recomputação", registros_corrig)
    } else {
      MONITORA_RELATORIOS_SUPORTE_POS_CORRECOES <- monitora_relatorios_suporte_painel_gravar(registros_corrig, fase = "pos_correcoes", atualizar_saida_principal = FALSE)
      MONITORA_COMPARACAO_RELATORIOS_PRE_POS_CORRECOES <- monitora_relatorios_comparar_pre_pos_correcoes(MONITORA_CORRECOES_DIR)
      monitora_perf_registrar_checkpoint("relatorios_suporte_pos_correcoes", "relatórios de exóticas e apoio atualizados após painel/correções, com comparação pré/pós", registros_corrig)
    }
  } else if (isTRUE(MONITORA_GERAR_RELATORIOS_SUPORTE_PAINEL)) {
    monitora_correcao_console_msg("Relatórios pós-correções completos foram pulados por MONITORA_GERAR_RELATORIOS_POS_CORRECOES=false; produtos principais seguem normalmente.")
    monitora_log_registrar_evento("relatorios_suporte_pos_correcoes", "INFO", NA_character_, "Relatórios pós-correções completos desativados por configuração", "use MONITORA_GERAR_RELATORIOS_POS_CORRECOES=true para validação final completa")
  }
} else {
  monitora_log_registrar_evento("painel_correcoes", "INFO", NA_character_, "Painel/correções ignorados: painel desligado e nenhum arquivo de correções encontrado", "não foram carregados metadados XLSForm nem gerados dicionários completos")
  MONITORA_AUDITORIA_DEPENDENCIAS_CONDICIONAIS <- data.table::data.table()
}


if (isTRUE(get0("MONITORA_VALIDAR_ESPACIAL_COLETAS", ifnotfound = FALSE, inherits = TRUE))) {
  monitora_esp_msg("Fluxo espacial ativo; versão do módulo: ", get0("MONITORA_VALIDACAO_ESPACIAL_VERSAO_MODULO", ifnotfound = "indefinida", inherits = TRUE), ".")
  if (!exists("MONITORA_ARQUIVO_CORRECOES_ESPACIAIS", inherits = FALSE)) {
    MONITORA_ARQUIVO_CORRECOES_ESPACIAIS <- file.path(MONITORA_INPUT_DIR, "correcoes_espaciais.csv")
  }
  MONITORA_CORRECOES_ESPACIAIS_ARQUIVO_EXISTE <- isTRUE(file.exists(MONITORA_ARQUIVO_CORRECOES_ESPACIAIS)) &&
    isTRUE(file.info(MONITORA_ARQUIVO_CORRECOES_ESPACIAIS)$size > 0)
  if (isTRUE(MONITORA_APLICAR_CORRECOES_ESPACIAIS) && isTRUE(MONITORA_CORRECOES_ESPACIAIS_ARQUIVO_EXISTE)) {
    monitora_esp_msg("Aplicando correções espaciais atômicas registradas em ", MONITORA_ARQUIVO_CORRECOES_ESPACIAIS, ".")
    MONITORA_COLETAS_EXCLUIDAS_POS_CORRECOES <- monitora_esp_coletas_excluidas_ultima_auditoria()
    MONITORA_CORRECOES_ESPACIAIS_RESULTADO <- monitora_espacial_aplicar_correcoes_atomicas(
      registros_corrig,
      arquivo = MONITORA_ARQUIVO_CORRECOES_ESPACIAIS,
      abortar_falha = TRUE,
      coletas_excluidas = MONITORA_COLETAS_EXCLUIDAS_POS_CORRECOES
    )
    registros_corrig <- MONITORA_CORRECOES_ESPACIAIS_RESULTADO$registros_corrig
    MONITORA_AUDITORIA_CORRECOES_ESPACIAIS_ULTIMA <- MONITORA_CORRECOES_ESPACIAIS_RESULTADO$auditoria
    monitora_perf_registrar_checkpoint("validacao_espacial_aplicacao_correcoes", "correções espaciais atômicas aplicadas", registros_corrig)
  } else {
    monitora_esp_msg("Nenhum arquivo de correções espaciais aplicável encontrado; seguindo apenas com relatórios espaciais.")
  }
  monitora_esp_msg("Gerando validação espacial pós-painel/correções.")
  MONITORA_VALIDACAO_ESPACIAL_POS_PAINEL_RESULTADO <- monitora_espacial_executar(
    registros_corrig,
    momento = "pos_painel",
    forcar = TRUE,
    output_dir = MONITORA_OUTPUT_DIR,
    log_dir = MONITORA_LOG_DIR
  )
  if (exists("MONITORA_VALIDACAO_ESPACIAL_PRE_PAINEL_RESULTADO", inherits = FALSE) &&
      is.list(MONITORA_VALIDACAO_ESPACIAL_PRE_PAINEL_RESULTADO) &&
      is.list(MONITORA_VALIDACAO_ESPACIAL_POS_PAINEL_RESULTADO)) {
    MONITORA_COMPARACAO_VALIDACAO_ESPACIAL_PRE_POS <- tryCatch(
      monitora_espacial_comparar_pre_pos(
        MONITORA_VALIDACAO_ESPACIAL_PRE_PAINEL_RESULTADO$validacao,
        MONITORA_VALIDACAO_ESPACIAL_POS_PAINEL_RESULTADO$validacao
      ),
      error = function(e) {
        monitora_espacial_gravar_falha_comparacao(
          e,
          MONITORA_VALIDACAO_ESPACIAL_PRE_PAINEL_RESULTADO$validacao,
          MONITORA_VALIDACAO_ESPACIAL_POS_PAINEL_RESULTADO$validacao,
          output_dir = MONITORA_OUTPUT_DIR,
          log_dir = MONITORA_LOG_DIR
        )
        stop(e)
      }
    )
  }
  monitora_perf_registrar_checkpoint("validacao_espacial_pos_painel", "relatórios espaciais pós-painel gerados", registros_corrig)
}

MONITORA_REUSAR_AUDITORIA_COLETAS_PRE_PARA_POS <- isFALSE(MONITORA_DEVE_PROCESSAR_CORRECOES_CAMPOS) &&
  !isTRUE(get0("MONITORA_VALIDAR_ESPACIAL_COLETAS", ifnotfound = FALSE, inherits = TRUE)) &&
  exists("MONITORA_AUDITORIA_COLETAS_UA_ANO_DUPLICADAS_PRE_CORRECOES", inherits = FALSE)

if (isTRUE(MONITORA_REUSAR_AUDITORIA_COLETAS_PRE_PARA_POS)) {
  MONITORA_AUDITORIA_COLETAS_UA_ANO_DUPLICADAS_POS_CORRECOES <- data.table::copy(MONITORA_AUDITORIA_COLETAS_UA_ANO_DUPLICADAS_PRE_CORRECOES)
  fase_segura_reuso <- "pos_correcoes"
  saida_log_reuso <- file.path(MONITORA_LOG_DIR, paste0("auditoria_coletas_ua_ano_duplicadas_", fase_segura_reuso, "_", MONITORA_EXEC_ID, ".csv"))
  saida_out_reuso <- file.path(MONITORA_OUTPUT_DIR, paste0("auditoria_coletas_ua_ano_duplicadas_", fase_segura_reuso, "_ultima_execucao.csv"))
  try(monitora_fwrite(MONITORA_AUDITORIA_COLETAS_UA_ANO_DUPLICADAS_POS_CORRECOES, saida_log_reuso, na = ""), silent = TRUE)
  try(monitora_fwrite(MONITORA_AUDITORIA_COLETAS_UA_ANO_DUPLICADAS_POS_CORRECOES, saida_out_reuso, na = ""), silent = TRUE)
  if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) {
    try(monitora_fwrite(MONITORA_AUDITORIA_COLETAS_UA_ANO_DUPLICADAS_POS_CORRECOES, file.path(MONITORA_CORRECOES_DIR, "auditoria_coletas_ua_ano_duplicadas_pos_correcoes.csv"), na = ""), silent = TRUE)
  }
  if (nrow(MONITORA_AUDITORIA_COLETAS_UA_ANO_DUPLICADAS_POS_CORRECOES) > 0) {
    monitora_log_registrar_evento(
      "coletas_ua_ano_duplicadas",
      "AVISO",
      saida_log_reuso,
      "COLETAS com UA duplicada no mesmo ANO continuam não resolvidas. Auditoria pré-correções reutilizada como pós-correções porque não houve painel/correções/validação espacial. A ocorrência será tratada como pendência impeditiva no checkpoint de registros_corrig.csv, não como stop antes da materialização.",
      "checkpoint pendente permitido; registros_validados.csv/produtos finais seguem bloqueados enquanto persistir"
    )
  }
  monitora_log_registrar_evento(
    "coletas_ua_ano_duplicadas",
    "INFO",
    saida_log_reuso,
    "Auditoria pós-correções reutilizada da auditoria pré-correções: painel/correções e validação espacial estavam desativados, sem mutação dos registros entre as fases.",
    "otimização segura da trava UC+UA+ANO"
  )
} else {
  MONITORA_AUDITORIA_COLETAS_UA_ANO_DUPLICADAS_POS_CORRECOES <- monitora_auditar_coletas_ua_ano_duplicadas(registros_corrig, fase = "pos_correcoes", abortar = FALSE)
}
monitora_perf_registrar_checkpoint("auditoria_coletas_ua_ano_duplicadas_pos_correcoes", "auditoria pós-correções de múltiplas COLETAS na mesma UC+UA+ANO; pendências seguem para checkpoint marcado", registros_corrig)

if (exists("monitora_diag_rel_gerar_ocorrencias", mode = "function")) {
  MONITORA_BASE_DIR_OCORRENCIAS_POS_PAINEL <- file.path(get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE), "relatorios_pos_painel", "ocorrencias_diagnosticas")

 ### -: mesmo critério já usado acima para pular
 ### monitora_relatorios_suporte_painel_gravar na fase pos_correcoes
 ### (MONITORA_OPCAO_OTIMIZAR_RELATORIOS_SUPORTE_POS +
 ### monitora_correcao_arquivo_afeta_relatorios_suporte ): se a sessão não
 ### gerou arquivo de correções de campos ou as correções geradas não tocam
 ### nenhum atributo relevante ao catálogo de ocorrências (forma de
 ### vida/hábito/espécie/Encostam), o catálogo pós-painel é idêntico ao
 ### pré-painel e não precisa revarrer `registros_corrig` inteiro de novo.
 ### Exclusões de COLETAS e alterações de chaves superiores também invalidam
 ### o catálogo, mesmo sem tocar forma de vida. Correções espaciais
 ### (MONITORA_ARQUIVO_CORRECOES_ESPACIAIS) só reescrevem coordenadas de
 ### início/fim e continuam fora deste critério.
  MONITORA_REUTILIZAR_OCORRENCIAS_POS_PAINEL <- tryCatch({
    isTRUE(get0("MONITORA_OPCAO_OTIMIZAR_RELATORIOS_SUPORTE_POS", ifnotfound = "S", inherits = TRUE) == "S") &&
      is.list(get0("MONITORA_RELATORIOS_DIAGNOSTICOS_PRE_PAINEL", ifnotfound = NULL, inherits = TRUE)) &&
      !(isTRUE(MONITORA_CORRECOES_ARQUIVO_EXISTE) && monitora_correcao_arquivo_afeta_relatorios_suporte(MONITORA_ARQUIVO_CORRECOES_CAMPOS))
  }, error = function(e) FALSE)

  if (isTRUE(MONITORA_REUTILIZAR_OCORRENCIAS_POS_PAINEL)) {
    MONITORA_RELATORIOS_DIAGNOSTICOS_POS_PAINEL <- tryCatch(
      monitora_diag_rel_reutilizar_ocorrencias_pos_painel(
        MONITORA_RELATORIOS_DIAGNOSTICOS_PRE_PAINEL,
        base_dir_pos = MONITORA_BASE_DIR_OCORRENCIAS_POS_PAINEL,
        fase_pos = "pos_painel",
        fase_origem = "pre_painel"
      ),
      error = function(e) NULL
    )
    if (is.null(MONITORA_RELATORIOS_DIAGNOSTICOS_POS_PAINEL)) MONITORA_REUTILIZAR_OCORRENCIAS_POS_PAINEL <- FALSE
  }

  if (isTRUE(MONITORA_REUTILIZAR_OCORRENCIAS_POS_PAINEL)) {
    monitora_correcao_console_msg("Relatórios diagnósticos de ocorrências pós-painel reaproveitados do pré-painel: nenhuma correção da sessão alterou forma de vida, hábito, espécie ou Encostam.")
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("relatorios_diagnosticos_ocorrencias_pos_painel", "INFO", NA_character_, "Relatórios diagnósticos de ocorrências pós-painel reutilizados do pré-painel por ausência de alteração relevante", "otimização 03.5Q-B: evita recomputação global quando não houve mudança")
    }
    if (exists("monitora_perf_registrar_checkpoint", mode = "function")) {
      monitora_perf_registrar_checkpoint("relatorios_diagnosticos_ocorrencias_pos_painel_reutilizados", "ocorrências diagnósticas pós-painel reutilizadas do pré-painel sem recomputação", registros_corrig)
    }
  } else {
    tryCatch({
      MONITORA_RELATORIOS_DIAGNOSTICOS_POS_PAINEL <- monitora_diag_rel_gerar_ocorrencias(
        registros_corrig,
        fase = "pos_painel",
        base_dir = MONITORA_BASE_DIR_OCORRENCIAS_POS_PAINEL,
        coletas_triagem_por_tipo = NULL,
        triagem_painel_unificada = NULL,
        validar_contagens = FALSE
      )
    }, error = function(e) {
      assign("MONITORA_OCORRENCIAS_DIAGNOSTICAS_INTEGRIDADE_OK", FALSE, envir = .GlobalEnv)
      arq_erro <- file.path(MONITORA_BASE_DIR_OCORRENCIAS_POS_PAINEL, paste0("erro_relatorios_ocorrencias_diagnosticas_pos_painel_", get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE), ".txt"))
      dir.create(dirname(arq_erro), recursive = TRUE, showWarnings = FALSE)
      writeLines(conditionMessage(e), arq_erro, useBytes = TRUE)
      monitora_correcao_console_msg("ERRO ao gerar relatórios diagnósticos [pos_painel]: ", conditionMessage(e), ". Detalhes: ", arq_erro)
    })
  }

  if (exists("monitora_output_organizar_produtos", mode = "function")) {
    try(monitora_output_organizar_produtos(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE), contexto = "pos_relatorios_diagnosticos_pos_painel"), silent = TRUE)
  }
}

monitora_perf_registrar_checkpoint("painel_correcoes_campos", "correções assistidas avaliadas/aplicadas quando habilitadas", registros_corrig)
if (exists("MONITORA_ABRIR_PAINEL_CORRECOES", inherits = FALSE) && isTRUE(MONITORA_ABRIR_PAINEL_CORRECOES)) {
  if (isTRUE(MONITORA_PARAR_APOS_REGISTROS_CORRIG)) {
    monitora_correcao_console_msg("Etapa do painel/correções finalizada. Gravando registros_corrig.csv e encerrando por modo de desenvolvimento.")
  } else {
    monitora_correcao_console_msg("Etapa do painel/correções finalizada. Iniciando construção das tabelas estatísticas.")
  }
}

if (isTRUE(MONITORA_PARAR_APOS_REGISTROS_CORRIG)) {
  monitora_execucao_gravar_checkpoint_parcial(
    registros_corrig,
    produto = "registros_corrig.csv",
    motivo = MONITORA_MODO_EXECUCAO
  )

 ### - ajuste: relatório opt-in de pipes por contrato único
 ### (default OFF, ver MONITORA_DIAGNOSTICO_PIPES_CONTRATO) também no
 ### caminho de checkpoint parcial (painel_e_parar/ate_registros_corrig/
 ### abrir_painel_cache/painel_incremental_registros_corrig) -- o caminho
 ### completo abaixo fica inalcançável quando
 ### MONITORA_EXECUCAO_ENCERRADA_CONTROLADAMENTE já foi marcado TRUE.
 ### registros_corrig já está em memória e o checkpoint parcial já foi
 ### gravado neste ponto. Nunca bloqueia o fluxo, nunca altera
 ### `registros_corrig` -- envolvido em try além do wrapper seguro já
 ### tratar erro internamente.
  if (exists("monitora_pipe_contrato_relatorio_optin_seguro", mode = "function")) {
    try(monitora_pipe_contrato_relatorio_optin_seguro(
      registros_corrig, contexto = "checkpoint_parcial_registros_corrig",
      output_dir = MONITORA_OUTPUT_DIR, log_dir = MONITORA_LOG_DIR, exec_id = MONITORA_EXEC_ID
    ), silent = TRUE)
  }

  MONITORA_EXECUCAO_ENCERRADA_CONTROLADAMENTE <- TRUE
}

if (!isTRUE(MONITORA_EXECUCAO_ENCERRADA_CONTROLADAMENTE)) {

### Exportação antecipada dos registros corrigidos/validados -----------------
### Esta etapa ocorre depois das correções finais e antes das estatísticas,
### evitando gasto computacional adicional caso registros_validados.csv esteja
### ativo e alguma inconsistência estrutural bloqueante seja detectada.



if (exists("registros_corrig")) {
  dir.create(MONITORA_OUTPUT_DIR, showWarnings = FALSE, recursive = TRUE)
  if (exists("monitora_publicacao_aa_preparar_validar_registros_corrig", mode = "function")) {
    prep_registros_corrig <- monitora_publicacao_aa_preparar_validar_registros_corrig(
      registros_corrig,
      contexto = "pre_analises_registros_corrig",
      output_dir = MONITORA_OUTPUT_DIR,
      log_dir = MONITORA_LOG_DIR,
      exec_id = MONITORA_EXEC_ID,
      abortar = TRUE
    )
    registros_corrig <- prep_registros_corrig$registros_corrig
  }
  if (exists("monitora_replay_oraculo_validar_final", mode = "function", inherits = TRUE)) {
    monitora_replay_oraculo_validar_final(
      registros_corrig,
      contexto = "pre_analises_registros_corrig"
    )
  }
  caminho_registros_corrig_preanalises <- file.path(MONITORA_OUTPUT_DIR, "registros_corrig.csv")
  if (exists("monitora_publicacao_aa_exportar_registros_corrig_aprovado", mode = "function")) {
    monitora_publicacao_aa_exportar_registros_corrig_aprovado(registros_corrig, caminho_registros_corrig_preanalises, contexto = "pre_analises_registros_corrig", abortar = TRUE)
  } else {
    monitora_fwrite(registros_corrig, caminho_registros_corrig_preanalises, row.names = FALSE)
  }
  if (exists("monitora_correcao_auditar_releitura_pos_export", mode = "function")) {
    monitora_correcao_auditar_releitura_pos_export(
      caminho_registros_corrig_preanalises,
      contexto = "pos_export_pre_analises_registros_corrig"
    )
  }
 ### O gate de registros_validados pode encerrar a execução imediatamente
 ### abaixo. Finalize a revisão de linhagem enquanto o checkpoint canônico já
 ### está materializado, para que inclusive o caminho bloqueado preserve
 ### parent_revision_id, hashes e o ledger herdado sem replay.
  if (exists("monitora_linhagem_finalizar", mode = "function", inherits = TRUE)) {
    monitora_linhagem_finalizar(caminho_registros_corrig_preanalises)
  }

 ### - /ajuste: relatório opt-in de pipes por contrato
 ### único (default OFF, ver MONITORA_DIAGNOSTICO_PIPES_CONTRATO).
 ### registros_corrig já está materializado e com persistência confirmada
 ### neste ponto. Usa o wrapper seguro (ajuste ) para não duplicar
 ### produto caso o caminho de checkpoint parcial acima já tenha gerado o
 ### relatório na mesma execução (normalmente mutuamente exclusivos, mas o
 ### wrapper protege mesmo assim). Nunca bloqueia o fluxo -- envolvido em
 ### try além do wrapper já tratar erro internamente.
  if (exists("monitora_pipe_contrato_relatorio_optin_seguro", mode = "function")) {
    try(monitora_pipe_contrato_relatorio_optin_seguro(
      registros_corrig, contexto = "pos_export_registros_corrig",
      output_dir = MONITORA_OUTPUT_DIR, log_dir = MONITORA_LOG_DIR, exec_id = MONITORA_EXEC_ID
    ), silent = TRUE)
  }
  if (isTRUE(get0("MONITORA_GERAR_REGISTROS_VALIDADOS", ifnotfound = FALSE, inherits = TRUE)) &&
      exists("monitora_registros_validados_exportar", mode = "function")) {
    monitora_registros_validados_exportar(
      registros_corrig,
      output_dir = MONITORA_OUTPUT_DIR,
      log_dir = MONITORA_LOG_DIR,
      exec_id = MONITORA_EXEC_ID,
      abortar = TRUE,
      forcar = FALSE,
      contrato_corrig_validado = isTRUE(get0("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", ifnotfound = FALSE, inherits = TRUE))
    )
    if (!isTRUE(get0("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS", ifnotfound = FALSE, inherits = TRUE))) {
      monitora_perf_registrar_checkpoint("exportacao_registros_validados", "schema SISMONITORA embutido aplicado a registros_corrig final", registros_corrig)
    }
  }

  if (isTRUE(get0("MONITORA_GERAR_RELATORIO_VALIDACAO_CONSOLIDADO", ifnotfound = TRUE, inherits = TRUE)) && exists("monitora_relatorio_validacao_consolidado_gerar", mode = "function")) {
    tryCatch({
      monitora_relatorio_validacao_consolidado_gerar(
        registros_corrig = registros_corrig,
        output_dir = MONITORA_OUTPUT_DIR,
        log_dir = MONITORA_LOG_DIR,
        exec_id = MONITORA_EXEC_ID,
        responsavel = get0("MONITORA_RESPONSAVEL_CORRECAO", ifnotfound = "", inherits = TRUE),
        instituicao = get0("MONITORA_INSTITUICAO_RESPONSAVEL", ifnotfound = "ICMBio", inherits = TRUE),
        formatos = get0("MONITORA_FORMATOS_RELATORIO_VALIDACAO", ifnotfound = c("html", "pdf"), inherits = TRUE)
      )
      monitora_perf_registrar_checkpoint("relatorio_validacao_consolidado_v2_6_0", "relatório consolidado de validação gerado em output/relatorios_validacao/", registros_corrig)
    }, error = function(e) {
      msg_relatorio_consolidado <- conditionMessage(e)
      warning("Falha ao gerar relatório consolidado de validação: ", msg_relatorio_consolidado, call. = FALSE)
 ### ajuste validação operacional (etapa_validacao): este é o ponto de chamada exercitado na
 ### validação operacional (fluxo completo, fora do checkpoint antecipado) -- confirmado
 ### pelo console real ("Falha ao gerar relatório consolidado de
 ### validação: 'unique' is not an exported object from
 ### 'namespace:data.table'"). Mesma correção do outro ponto de chamada
 ### (monitora_relatorio_validacao_consolidado_tentar ): nunca deixar a
 ### falha silenciosa em disco.
      if (exists("monitora_relatorio_validacao_consolidado_registrar_falha", mode = "function")) {
        monitora_relatorio_validacao_consolidado_registrar_falha(msg_relatorio_consolidado, "fluxo_principal_pos_export")
      }
    })
  }

if (isTRUE(get0("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS", ifnotfound = FALSE, inherits = TRUE)) &&
      isTRUE(get0("MONITORA_PARAR_SE_REGISTROS_CORRIG_COM_PENDENCIAS", ifnotfound = TRUE, inherits = TRUE))) {
    monitora_correcao_console_msg("Execução interrompida após materializar registros_corrig.csv como checkpoint com pendências impeditivas. Reinsira esse arquivo no input e continue em modo painel/incremental após resolver as pendências. Estatísticas, produtos finais e registros_validados.csv não serão gerados nesta execução.")
    MONITORA_EXECUCAO_ENCERRADA_CONTROLADAMENTE <- TRUE
 ### Este gate ocorre antes do fechamento geral do script. Materialize aqui
 ### a telemetria disponível e organize os artefatos já produzidos para que
 ### o checkpoint bloqueado tenha a mesma disciplina de diretórios dos modos
 ### parciais controlados; nenhuma auditoria deve permanecer na raiz.
    if (exists("monitora_gravar_manifesto_execucao", mode = "function")) {
      try(monitora_gravar_manifesto_execucao("checkpoint_pendencias_impeditivas"), silent = TRUE)
    }
    if (exists("monitora_perf_gravar_relatorio", mode = "function")) {
      try(monitora_perf_gravar_relatorio(), silent = TRUE)
    }
    if (exists("MONITORA_LOG_EXECUCAO", inherits = TRUE)) {
      try(monitora_fwrite(MONITORA_LOG_EXECUCAO, file.path(MONITORA_LOG_DIR, paste0("relatorio_execucao_", MONITORA_EXEC_ID, ".csv")), row.names = FALSE), silent = TRUE)
      try(monitora_fwrite(MONITORA_LOG_EXECUCAO, file.path(MONITORA_OUTPUT_DIR, "relatorio_execucao_ultima_execucao.csv"), row.names = FALSE), silent = TRUE)
    }
    if (exists("monitora_output_organizar_produtos", mode = "function")) {
      try(monitora_output_organizar_produtos(MONITORA_OUTPUT_DIR, MONITORA_EXEC_ID, contexto = "checkpoint_parcial_pendencias_impeditivas"), silent = TRUE)
    }
    stop("Execução encerrada após checkpoint de registros_corrig.csv com pendências impeditivas; ver auditoria_pendencias_impeditivas_registros_corrig.csv.", call. = FALSE)
  }
}

### - Incremento (motor único: estatísticas/gráficos) -------
### Declara, sem alterar nenhum cálculo, a camada/fonte real que alimenta as
### estatísticas e gráficos desta execução e o status contratual conhecido
### dessa fonte. Estatísticas/gráficos sempre partem de `registros_corrig_stat`
### (construído logo abaixo, a partir do `registros_corrig` já corrigido/
### deduplicado em memória) -- nunca de `registros_validados.csv`, que é
### produto opcional, gerado (quando gerado) a partir do mesmo
### `registros_corrig`, mas por regra própria (schema XLSForm21) que pode
### bloquear/abortar independentemente da construção das estatísticas (ver
### comentário de "Construção das tabelas estatísticas" acima e a
### seção 27/28 do contrato de governança). Reaproveita o helper já testado
### em (`monitora_registros_corrig_severidade_contrato_unico `) para
### também informar, sem introduzir nenhum fato novo, se as colunas de
### `registros_corrig` que alimentam as estatísticas têm severidade alta
### bloqueante do contrato único. Esta função só declara fatos já
### verdadeiros no fluxo existente -- não lê nem grava
### registros_importados*.csv/registros_corrig.csv/registros_validados.csv,
### não participa de nenhuma decisão de bloqueio e é estritamente
### informativa (log de execução apenas).
monitora_estatisticas_declarar_status_fonte <- function(registros_corrig) {
  if (!isTRUE(monitora_cfg_env_bool("MONITORA_DECLARAR_STATUS_FONTE_ESTATISTICAS", TRUE))) return(invisible(NULL))

  solicitado <- isTRUE(get0("MONITORA_GERAR_REGISTROS_VALIDADOS", ifnotfound = FALSE, inherits = TRUE))
  gerado <- isTRUE(get0("MONITORA_REGISTROS_VALIDADOS_GERADO", ifnotfound = FALSE, inherits = TRUE))

  status_validados <- if (gerado) {
    "registros_validados.csv foi gerado nesta execucao"
  } else if (solicitado) {
    "registros_validados.csv foi solicitado mas NAO foi gerado (bloqueado/abortado) nesta execucao; motivo exato nao capturado neste ponto -- ver auditoria_registros_validados_resumo.csv quando disponivel"
  } else {
    "registros_validados.csv nao foi solicitado nesta execucao (opcao inativa)"
  }

  n_alta_sev <- NA_integer_
  if (exists("monitora_registros_corrig_severidade_contrato_unico", mode = "function")) {
    sev <- tryCatch(
      monitora_registros_corrig_severidade_contrato_unico(names(registros_corrig)),
      error = function(e) data.table::data.table()
    )
    if (data.table::is.data.table(sev) && nrow(sev) &&
        all(c("severidade_contrato_unico", "bloqueia_migracao_automatica_contrato_unico") %in% names(sev))) {
      n_alta_sev <- sum(
        sev$severidade_contrato_unico == "alta" &
          sev$bloqueia_migracao_automatica_contrato_unico %in% TRUE,
        na.rm = TRUE
      )
    }
  }

  detalhe <- paste0(
    "estatisticas/graficos desta execucao partem de registros_corrig_stat ",
    "(derivado de registros_corrig em memoria), nunca de registros_validados.csv; ",
    status_validados, "; colunas de registros_corrig com severidade alta ",
    "bloqueante do contrato unico: ",
    if (is.na(n_alta_sev)) "nao avaliado (flag MONITORA_DIAGNOSTICO_CONTRATO_UNICO_REGISTROS_VALIDADOS desligada ou indisponivel)" else n_alta_sev
  )

  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento(
      "declaracao_fonte_estatisticas",
      if ((solicitado && !gerado) || (!is.na(n_alta_sev) && n_alta_sev > 0)) "AVISO" else "INFO",
      NA_character_,
      detalhe,
      "estritamente informativo; nao altera registros_corrig_stat, graficos ou qualquer decisao de bloqueio"
    )
  }

  invisible(list(
    registros_validados_solicitado = solicitado,
    registros_validados_gerado = gerado,
    n_colunas_alta_severidade_contrato_unico = n_alta_sev
  ))
}
try(monitora_estatisticas_declarar_status_fonte(registros_corrig), silent = TRUE)
