## Preparação de registros_corrig_stat com data.table e tabelas estreitas.
## Evita expandir todas as colunas de registros_corrig ao separar tokens,
## reduzindo o pico de memória em lotes grandes.

monitora_grupo_stat_cols <- c(
  ".id",
  "PROTOCOLO",
  "COLETA",
  "UC",
  "UA",
  "ANO",
  "Coordenada inicial da amostragem (amostragem)",
  "Coordenada final da amostragem (amostragem)"
)

monitora_chaves_stat_basicas <- c("COLETA", "UC", "UA", "ANO")

monitora_stat_resolver_colunas_estruturais <- function(dt) {
  dt <- data.table::as.data.table(dt)
  categorias <- c("nativa", "exotica", "seca_morta")
  atributos <- c(
    nativa = "forma_vida_nativa",
    exotica = "forma_vida_exotica",
    seca_morta = "forma_vida_seca_morta"
  )

  resolvidas <- vapply(categorias, function(cat) {
    col <- tryCatch(monitora_correcao_coluna_forma_vida(dt, cat), error = function(e) NA_character_)
    if (length(col) != 1L || is.na(col) || !nzchar(col) || !(col %in% names(dt))) NA_character_ else col
  }, character(1))
  names(resolvidas) <- categorias

  candidatas <- vapply(categorias, function(cat) {
    x <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(dt, cat), error = function(e) character(0))
    x <- unique(x[x %in% names(dt)])
    paste(x, collapse = " | ")
  }, character(1))

  seguras <- vapply(categorias, function(cat) {
    col <- resolvidas[[cat]]
    !is.na(col) && isTRUE(monitora_correcao_coluna_principal_segura(dt, col, categoria = cat))
  }, logical(1))

  encostam <- tryCatch(monitora_correcao_colunas_chave(dt)$tipo_forma_vida, error = function(e) NA_character_)
  encostam_ok <- length(encostam) == 1L && !is.na(encostam) && nzchar(encostam) && encostam %in% names(dt)

  aud_formas <- data.table::data.table(
    atributo_canonico = unname(atributos[categorias]),
    categoria = categorias,
    coluna_resolvida = unname(resolvidas),
    candidatos_detectados = unname(candidatas),
    papel_contratual_seguro = unname(seguras),
    status = data.table::fifelse(!is.na(resolvidas) & seguras, "resolvida", "nao_resolvida_ou_insegura")
  )
  aud_encostam <- data.table::data.table(
    atributo_canonico = "tipo_forma_vida",
    categoria = "encostam",
    coluna_resolvida = if (encostam_ok) encostam else NA_character_,
    candidatos_detectados = if (encostam_ok) encostam else "",
    papel_contratual_seguro = encostam_ok,
    status = if (encostam_ok) "resolvida" else "nao_resolvida_ou_insegura"
  )
  aud <- data.table::rbindlist(list(aud_formas, aud_encostam), fill = TRUE, use.names = TRUE)
  aud[, `:=`(
    exec_id = as.character(get0("MONITORA_EXEC_ID", ifnotfound = NA_character_, inherits = TRUE)),
    modo_execucao = as.character(get0("MONITORA_MODO_EXECUCAO", ifnotfound = NA_character_, inherits = TRUE)),
    origem_resolucao = "contrato_unico + mapa_colunas_canonicas_cache"
  )]
  data.table::setcolorder(
    aud,
    c("exec_id", "modo_execucao", "atributo_canonico", "categoria", "coluna_resolvida", "candidatos_detectados", "papel_contratual_seguro", "status", "origem_resolucao")
  )
  try(monitora_fwrite(
    aud,
    file.path(
      get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
      "03_auditorias", "estatisticas", "auditoria_resolucao_colunas_estruturais_estatisticas.csv"
    ),
    na = ""
  ), silent = TRUE)

  falhas <- aud[status != "resolvida"]
  colisao <- anyDuplicated(unname(resolvidas[!is.na(resolvidas)])) > 0L
  if (nrow(falhas) || isTRUE(colisao)) {
    detalhe <- paste(
      paste0(aud$atributo_canonico, "=", data.table::fifelse(is.na(aud$coluna_resolvida), "<NA>", aud$coluna_resolvida)),
      collapse = "; "
    )
    stop(
      "Preparação estatística interrompida antes de sumarizar: o contrato único não resolveu de forma segura e distinta as colunas estruturais. ",
      detalhe,
      ". Ver output/03_auditorias/estatisticas/auditoria_resolucao_colunas_estruturais_estatisticas.csv.",
      call. = FALSE
    )
  }

  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento(
      "resolucao_colunas_estruturais_estatisticas",
      "INFO",
      NA_character_,
      paste0(
        "Contrato único resolveu: ",
        paste(paste0(names(resolvidas), "=", unname(resolvidas)), collapse = "; "),
        "; encostam=", encostam
      ),
      "as mesmas colunas alimentam sumarização e presença; nenhuma busca por label HTML literal"
    )
  }

  list(formas_vida = resolvidas, encostam = encostam, auditoria = aud)
}

