monitora_stat_registrar_msg <- function(...) {
  if (isTRUE(MONITORA_STAT_VERBOSE)) message("[estatistica_mudanca] ", paste0(..., collapse = ""))
}

monitora_stat_controlar_recursos_execucao <- function(etapa, risco = "normal", objeto = NULL, force_log = FALSE) {
  if (exists("monitora_recurso_controlar", mode = "function")) {
    return(tryCatch(
      monitora_recurso_controlar(etapa, risco = risco, objeto = objeto, force_log = force_log),
      error = function(e) list(modo = "indefinido", threads = data.table::getDTthreads(), batch_csv = NA_integer_, mem_available_mb = NA_real_)
    ))
  }
  list(modo = "indefinido", threads = data.table::getDTthreads(), batch_csv = NA_integer_, mem_available_mb = NA_real_)
}

monitora_stat_definir_iteracoes_efetivas <- function(n_solicitado, tipo = c("perm", "boot"), etapa = "estatistica", risco = "normal", objeto = NULL) {
  tipo <- match.arg(tipo)
  n_solicitado <- as.integer(n_solicitado)
  if (!isTRUE(MONITORA_STAT_RECURSOS_ADAPTATIVO)) return(n_solicitado)
  rc <- monitora_stat_controlar_recursos_execucao(etapa, risco = risco, objeto = objeto, force_log = FALSE)
  modo <- as.character(rc$modo %||% "indefinido")
  n_eff <- n_solicitado
  if (tipo == "perm") {
    if (modo == "critico") n_eff <- min(n_eff, 999L)
    if (modo == "economico") n_eff <- min(n_eff, 1999L)
    if (modo == "equilibrado") n_eff <- min(n_eff, 4999L)
    n_eff <- max(499L, n_eff)
  } else {
    if (modo == "critico") n_eff <- min(n_eff, 499L)
    if (modo == "economico") n_eff <- min(n_eff, 999L)
    if (modo == "equilibrado") n_eff <- min(n_eff, 1999L)
    n_eff <- max(199L, n_eff)
  }
  if (!identical(n_eff, n_solicitado)) {
    monitora_stat_registrar_msg("ajuste adaptativo: ", etapa, "; tipo=", tipo, "; modo=", modo, "; iteracoes=", n_eff, "/", n_solicitado)
  }
  n_eff
}

`%||%` <- function(x, y) {
  if (is.null(x) || length(x) == 0 || all(is.na(x))) y else x
}

monitora_stat_derivar_semente <- function(...) {
  partes <- unlist(list(...), recursive = TRUE, use.names = FALSE)
  partes <- as.character(partes)
  partes[is.na(partes)] <- "NA"
  texto <- paste(c(as.character(MONITORA_STAT_SEMENTE_BASE), partes), collapse = "|")
  ints <- utf8ToInt(enc2utf8(texto))
  hash <- 0
  if (length(ints)) {
    for (vv in ints) hash <- (hash * 131 + as.numeric(vv)) %% 2147483647
  }
  seed <- as.integer((as.numeric(MONITORA_STAT_SEMENTE_BASE) + hash) %% 2147483647)
  if (is.na(seed) || seed <= 0L) seed <- 20260625L
  seed
}

monitora_stat_ativar_semente <- function(...) {
  if (!isTRUE(MONITORA_STAT_REPRODUTIBILIDADE_ATIVA)) return(invisible(NA_integer_))
  seed <- monitora_stat_derivar_semente(...)
  set.seed(seed)
  invisible(seed)
}

monitora_stat_calcular_p_permutacao_pareada <- function(dif, n_perm = MONITORA_STAT_PERM) {
  dif <- as.numeric(dif)
  dif <- dif[is.finite(dif)]
  n <- length(dif)
  if (n == 0) return(NA_real_)
  obs <- mean(dif)
  if (!is.finite(obs)) return(NA_real_)
  if (all(abs(dif) < .Machine$double.eps^0.5)) return(1)

  if (n <= 16) {
    grade <- expand.grid(rep(list(c(-1, 1)), n))
    medias <- as.matrix(grade) %*% dif / n
    return(mean(abs(medias) >= abs(obs)))
  }

  n_perm <- monitora_stat_definir_iteracoes_efetivas(n_perm, tipo = "perm", etapa = "permutacao_pareada", risco = "normal")
  chunk <- min(as.integer(MONITORA_STAT_PERM_CHUNK), n_perm)
  cont <- 0L
  feitas <- 0L
  while (feitas < n_perm) {
    k <- min(chunk, n_perm - feitas)
    sinais <- matrix(sample(c(-1, 1), n * k, replace = TRUE), nrow = k, ncol = n)
    medias <- as.vector(sinais %*% dif / n)
    cont <- cont + sum(abs(medias) >= abs(obs))
    feitas <- feitas + k
  }
  (cont + 1) / (n_perm + 1)
}

monitora_stat_calcular_ic_bootstrap <- function(dif, n_boot = MONITORA_STAT_BOOT, conf = 0.95) {
  dif <- as.numeric(dif)
  dif <- dif[is.finite(dif)]
  n <- length(dif)
  if (n == 0) return(c(NA_real_, NA_real_))
  if (n == 1 || all(abs(dif - dif[1]) < .Machine$double.eps^0.5)) return(c(mean(dif), mean(dif)))
  n_boot <- monitora_stat_definir_iteracoes_efetivas(n_boot, tipo = "boot", etapa = "bootstrap_pareado", risco = "normal")
  medias <- numeric(n_boot)
  chunk <- min(as.integer(MONITORA_STAT_PERM_CHUNK), n_boot)
  feitas <- 0L
  while (feitas < n_boot) {
    k <- min(chunk, n_boot - feitas)
    for (bb in seq_len(k)) medias[feitas + bb] <- mean(sample(dif, size = n, replace = TRUE))
    feitas <- feitas + k
  }
  stats::quantile(medias, probs = c((1 - conf) / 2, 1 - (1 - conf) / 2), na.rm = TRUE, names = FALSE)
}

monitora_stat_preparar_long_ua <- function(dt, cols, grupo_grafico, tipo_metrica, denominador = c("relativo", "101")) {
  denominador <- match.arg(denominador)
  cols <- intersect(cols, names(dt))
  if (length(cols) == 0) return(data.table::data.table())

  base_cols <- intersect(c("UC", "UA", "ANO", "form_veg"), names(dt))
  if (!all(c("UC", "UA", "ANO", "form_veg") %in% base_cols)) return(data.table::data.table())

  tmp <- data.table::as.data.table(data.table::copy(dt[, c(base_cols, cols), with = FALSE]))
  for (cc in cols) tmp[, (cc) := suppressWarnings(as.numeric(get(cc)))]

  if (denominador == "relativo") {
    tmp[, MONITORA_TOTAL_REL := rowSums(.SD, na.rm = TRUE), .SDcols = cols]
    long <- data.table::melt(
      tmp,
      id.vars = c(base_cols, "MONITORA_TOTAL_REL"),
      measure.vars = cols,
      variable.name = "categoria",
      value.name = "n_categoria"
    )
    long[, valor := fifelse(MONITORA_TOTAL_REL > 0, n_categoria / MONITORA_TOTAL_REL, NA_real_)]
    long[, total_referencia := MONITORA_TOTAL_REL]
    long[, MONITORA_TOTAL_REL := NULL]
  } else {
    long <- data.table::melt(
      tmp,
      id.vars = base_cols,
      measure.vars = cols,
      variable.name = "categoria",
      value.name = "n_categoria"
    )
    long[, valor := n_categoria / 101]
    long[, total_referencia := 101]
  }

  long <- long[!is.na(ANO) & !is.na(form_veg) & !is.na(categoria) & is.finite(valor)]
  long[, `:=`(
    ANO = suppressWarnings(as.integer(ANO)),
    UC = as.character(UC),
    UA = as.character(UA),
    form_veg = as.character(form_veg),
    grupo_grafico = grupo_grafico,
    tipo_metrica = tipo_metrica,
    categoria = as.character(categoria),
    categoria_label = monitora_plot_rotulo_categoria(as.character(categoria))
  )]
  long[]
}


monitora_stat_classificar_mudanca_categoria <- function(res, contexto = c("ano_anterior", "linha_base")) {
  contexto <- match.arg(contexto)
  if (is.null(res) || nrow(res) == 0) return(res)
  margem <- MONITORA_STAT_MARGEM_PP / 100
  min_efeito <- MONITORA_STAT_MIN_EFEITO_PP / 100
  p_col <- if (contexto == "linha_base") "p_ajustado_fdr_linha_base" else "p_ajustado_fdr"
  res[, classe_mudanca := data.table::fcase(
    is.na(get(p_col)) | n_UA_pareadas < MONITORA_STAT_MIN_PARES, "pares_insuficientes",
    get(p_col) <= MONITORA_STAT_ALPHA & ci95_lower > 0 & diferenca >= min_efeito, "aumento",
    get(p_col) <= MONITORA_STAT_ALPHA & ci95_upper < 0 & diferenca <= -min_efeito, "reducao",
    ci95_lower >= -margem & ci95_upper <= margem, "estabilidade_equivalente",
    default = "inconclusivo"
  )]
  if (contexto == "linha_base") {
    res[, simbolo_mudanca := data.table::fcase(
      classe_mudanca == "aumento", "△",
      classe_mudanca == "reducao", "▽",
      classe_mudanca == "estabilidade_equivalente", "≋",
      classe_mudanca == "pares_insuficientes", "?",
      default = "·"
    )]
    res[, legenda_mudanca := data.table::fcase(
      classe_mudanca == "aumento", "aumento estatisticamente sustentado em relação à linha de base acumulada anterior",
      classe_mudanca == "reducao", "redução estatisticamente sustentada em relação à linha de base acumulada anterior",
      classe_mudanca == "estabilidade_equivalente", paste0("mudança dentro da margem ecológica de ±", MONITORA_STAT_MARGEM_PP, " p.p. em relação à linha de base"),
      classe_mudanca == "pares_insuficientes", paste0("menos de ", MONITORA_STAT_MIN_PARES, " UAs pareadas ou menos de ", MONITORA_STAT_BASELINE_MIN_ANOS, " anos de linha de base"),
      default = "resultado inconclusivo em relação à linha de base"
    )]
  } else {
    res[, simbolo_mudanca := data.table::fcase(
      classe_mudanca == "aumento", "▲",
      classe_mudanca == "reducao", "▼",
      classe_mudanca == "estabilidade_equivalente", "≈",
      classe_mudanca == "pares_insuficientes", "?",
      default = "·"
    )]
    res[, legenda_mudanca := data.table::fcase(
      classe_mudanca == "aumento", "aumento estatisticamente sustentado em relação à medição anterior disponível da mesma UC",
      classe_mudanca == "reducao", "redução estatisticamente sustentada em relação à medição anterior disponível da mesma UC",
      classe_mudanca == "estabilidade_equivalente", paste0("mudança dentro da margem ecológica de ±", MONITORA_STAT_MARGEM_PP, " p.p."),
      classe_mudanca == "pares_insuficientes", paste0("menos de ", MONITORA_STAT_MIN_PARES, " UAs pareadas"),
      default = "resultado inconclusivo"
    )]
  }
  res[]
}

monitora_stat_comparar_anos_consecutivos <- function(long_dt) {
 # Compara cada ano-alvo com a medição imediatamente anterior disponível
 # dentro de cada UC. Versão otimizada: a montagem dos pares é vetorizada por
 # joins data.table; bootstrap, permutação, FDR e classificação são preservados.
  if (is.null(long_dt) || nrow(long_dt) == 0) return(data.table::data.table())
  long_dt <- data.table::as.data.table(long_dt)
  req <- c("grupo_grafico", "tipo_metrica", "form_veg", "categoria", "categoria_label", "UC", "UA", "ANO", "valor")
  faltantes <- setdiff(req, names(long_dt))
  if (length(faltantes)) stop("monitora_stat_comparar_anos_consecutivos: coluna(s) ausente(s): ", paste(faltantes, collapse = ", "), call. = FALSE)

  dt <- long_dt[, ..req]
  dt[, ANO := suppressWarnings(as.integer(ANO))]
  dt[, valor := suppressWarnings(as.numeric(valor))]
  dt <- dt[!is.na(UC) & !is.na(UA) & !is.na(ANO)]
  if (!nrow(dt)) return(data.table::data.table())

  keys_g <- c("grupo_grafico", "tipo_metrica", "form_veg", "categoria", "categoria_label")
  anos_uc <- unique(dt[, c(keys_g, "UC", "ANO"), with = FALSE])
  data.table::setorder(anos_uc, grupo_grafico, tipo_metrica, form_veg, categoria, categoria_label, UC, ANO)
  anos_uc[, ano_1 := data.table::shift(ANO, type = "lag"), by = c(keys_g, "UC")]
  pares_uc <- anos_uc[!is.na(ano_1), c(keys_g, "UC", "ano_1", "ANO"), with = FALSE]
  data.table::setnames(pares_uc, "ANO", "ano_2")
  pares_uc[, `:=`(ano_1 = as.integer(ano_1), ano_2 = as.integer(ano_2))]
  if (!nrow(pares_uc)) return(data.table::data.table())

  combos <- pares_uc[, .(
    ano_1_min = min(ano_1, na.rm = TRUE),
    anos_referencia = paste(sort(unique(ano_1)), collapse = ";")
  ), by = c(keys_g, "ano_2")]
  data.table::setorder(combos, grupo_grafico, tipo_metrica, form_veg, categoria, ano_2)

  dt1 <- dt[, c(keys_g, "UC", "UA", "ANO", "valor"), with = FALSE]
  dt2 <- data.table::copy(dt1)
  data.table::setnames(dt1, c("ANO", "valor"), c("ano_1", "valor_1"))
  data.table::setnames(dt2, c("ANO", "valor"), c("ano_2", "valor_2"))

  tmp <- merge(
    pares_uc,
    dt2,
    by = c(keys_g, "UC", "ano_2"),
    all = FALSE,
    allow.cartesian = TRUE,
    sort = FALSE
  )
  par <- merge(
    tmp,
    dt1,
    by = c(keys_g, "UC", "UA", "ano_1"),
    all = FALSE,
    allow.cartesian = TRUE,
    sort = FALSE
  )
  if (nrow(par)) data.table::setkeyv(par, c(keys_g, "ano_2"))

  out <- vector("list", nrow(combos))
  idx <- 0L
  monitora_progresso_loop_configurar("estatistica_categoria_ano_a_ano", nrow(combos), descricao = "estatística por categoria: ano a ano")
  for (ii in seq_len(nrow(combos))) {
    g <- combos[ii]
    if (nrow(par)) {
      par_i <- par[
        grupo_grafico == g$grupo_grafico &
          tipo_metrica == g$tipo_metrica &
          form_veg == g$form_veg &
          categoria == g$categoria &
          categoria_label == g$categoria_label &
          ano_2 == g$ano_2
      ]
    } else {
      par_i <- data.table::data.table()
    }
    n_pares <- nrow(par_i)
    dif <- par_i$valor_2 - par_i$valor_1
    efeito <- if (n_pares > 0) mean(dif, na.rm = TRUE) else NA_real_
    stat_id <- paste(g$grupo_grafico, g$tipo_metrica, g$form_veg, g$categoria, g$categoria_label, g$ano_2, g$anos_referencia, sep = "|")
    ci <- if (n_pares >= MONITORA_STAT_MIN_PARES) {
      monitora_stat_ativar_semente("mudanca_categoria_ano_a_ano_boot", stat_id)
      monitora_stat_calcular_ic_bootstrap(dif)
    } else c(NA_real_, NA_real_)
    p_val <- if (n_pares >= MONITORA_STAT_MIN_PARES) {
      monitora_stat_ativar_semente("mudanca_categoria_ano_a_ano_perm", stat_id)
      monitora_stat_calcular_p_permutacao_pareada(dif)
    } else NA_real_
    idx <- idx + 1L
    out[[idx]] <- data.table::data.table(
      grupo_grafico = g$grupo_grafico,
      tipo_metrica = g$tipo_metrica,
      form_veg = g$form_veg,
      categoria = g$categoria,
      categoria_label = g$categoria_label,
      ano_1 = if (n_pares > 0) min(par_i$ano_1, na.rm = TRUE) else g$ano_1_min,
      ano_2 = g$ano_2,
      anos_referencia = g$anos_referencia,
      comparacao = "medicao_anterior_disponivel_por_UC",
      n_UC_pareadas = data.table::uniqueN(par_i$UC),
      n_UA_pareadas = n_pares,
      media_ano_1 = if (n_pares > 0) mean(par_i$valor_1, na.rm = TRUE) else NA_real_,
      media_ano_2 = if (n_pares > 0) mean(par_i$valor_2, na.rm = TRUE) else NA_real_,
      diferenca = efeito,
      diferenca_pp = efeito * 100,
      ci95_lower = ci[1],
      ci95_upper = ci[2],
      ci95_lower_pp = ci[1] * 100,
      ci95_upper_pp = ci[2] * 100,
      p_valor_perm_pareado = p_val
    )
    monitora_progresso_loop_avancar("estatistica_categoria_ano_a_ano", atual = ii, detalhe = paste0(ii, "/", nrow(combos)))
  }
  res <- data.table::rbindlist(out, fill = TRUE)
  if (nrow(res) == 0) return(res)
  res[, p_ajustado_fdr := stats::p.adjust(p_valor_perm_pareado, method = "BH"), by = .(grupo_grafico, tipo_metrica)]
  res <- monitora_stat_classificar_mudanca_categoria(res, contexto = "ano_anterior")
  data.table::setorder(res, grupo_grafico, tipo_metrica, form_veg, categoria, ano_2)
  res[]
}

