  MONITORA_STAT_CONFIG <- data.table::data.table(
    parametro = c("alpha", "margem_equivalencia_pp", "efeito_minimo_pp", "min_UA_pareadas", "bootstrap_reamostragens_solicitadas", "permutacoes_monte_carlo_solicitadas", "perm_chunk", "recursos_adaptativo", "margem_composicao_dist_hellinger", "efeito_minimo_composicao_dist_hellinger", "baseline_ativo", "baseline_modo", "baseline_min_anos", "baseline_mostrar_apenas_mudanca", "reprodutibilidade_ativa", "semente_base_monte_carlo", "rng_kind", "rng_normal_kind", "rng_sample_kind"),
    valor = c(MONITORA_STAT_ALPHA, MONITORA_STAT_MARGEM_PP, MONITORA_STAT_MIN_EFEITO_PP, MONITORA_STAT_MIN_PARES, MONITORA_STAT_BOOT, MONITORA_STAT_PERM, MONITORA_STAT_PERM_CHUNK, MONITORA_STAT_RECURSOS_ADAPTATIVO, MONITORA_STAT_COMP_MARGEM_DIST, MONITORA_STAT_COMP_MIN_DIST, MONITORA_STAT_BASELINE_ATIVO, MONITORA_STAT_BASELINE_MODO, MONITORA_STAT_BASELINE_MIN_ANOS, MONITORA_STAT_BASELINE_MOSTRAR_APENAS_MUDANCA, MONITORA_STAT_REPRODUTIBILIDADE_ATIVA, MONITORA_STAT_SEMENTE_BASE, MONITORA_STAT_RNG_KIND, MONITORA_STAT_RNG_NORMAL_KIND, MONITORA_STAT_RNG_SAMPLE_KIND)
  )
  monitora_stat_registrar_msg("comparações por categoria concluídas: ", nrow(MONITORA_STAT_MUDANCA_ANO_A_ANO), " linhas")
  monitora_stat_registrar_msg("comparações contra linha de base concluídas: ", nrow(MONITORA_STAT_MUDANCA_LINHA_BASE), " linhas")
  monitora_stat_registrar_msg("comparações de composição geral concluídas: ", nrow(MONITORA_STAT_COMPOSICAO_GERAL), " linhas")
  monitora_stat_registrar_msg("comparações de composição geral contra linha de base concluídas: ", nrow(MONITORA_STAT_COMPOSICAO_LINHA_BASE), " linhas")
  monitora_log_registrar_evento(
    "estatistica_mudanca_ano_a_ano",
    "INFO",
    NA_character_,
    paste0("comparacoes=", nrow(MONITORA_STAT_MUDANCA_ANO_A_ANO), "; alpha=", MONITORA_STAT_ALPHA, "; margem_pp=", MONITORA_STAT_MARGEM_PP),
    "consultar estatisticas_mudanca_ano_a_ano.csv, estatisticas_mudanca_linha_base.csv, estatisticas_composicao_geral_ano_a_ano.csv e colunas de símbolos nos CSV auxiliares"
  )
  monitora_perf_registrar_checkpoint("estatistica_mudanca_ano_a_ano", "teste de permutação pareado, bootstrap e FDR por categoria", MONITORA_STAT_MUDANCA_ANO_A_ANO)
  monitora_perf_registrar_checkpoint("estatistica_mudanca_linha_base", "teste de permutação pareado contra linha de base acumulada anterior", MONITORA_STAT_MUDANCA_LINHA_BASE)
  monitora_perf_registrar_checkpoint("estatistica_composicao_geral", "teste multivariado pareado por permutação com transformação de Hellinger", MONITORA_STAT_COMPOSICAO_GERAL)
  monitora_perf_registrar_checkpoint("estatistica_composicao_linha_base", "teste multivariado pareado contra linha de base acumulada anterior", MONITORA_STAT_COMPOSICAO_LINHA_BASE)
}


### Relatório textual estatístico e ecológico

monitora_relatorio_formatar_numero <- function(x, digits = 2) {
  x <- suppressWarnings(as.numeric(x))
  ifelse(
    is.na(x),
    "NA",
    format(round(x, digits), decimal.mark = ",", big.mark = ".", trim = TRUE, scientific = FALSE)
  )
}

monitora_relatorio_formatar_pp <- function(x, digits = 1) {
  x <- suppressWarnings(as.numeric(x))
  ifelse(
    is.na(x),
    "NA",
    paste0(format(round(x, digits), decimal.mark = ",", big.mark = ".", trim = TRUE, scientific = FALSE), " p.p.")
  )
}

monitora_relatorio_formatar_p <- function(x) {
  x <- suppressWarnings(as.numeric(x))
  ifelse(
    is.na(x),
    "NA",
    ifelse(x < 0.001, "<0,001", format(round(x, 4), decimal.mark = ",", big.mark = ".", trim = TRUE, scientific = FALSE))
  )
}

monitora_relatorio_classe_portugues <- function(x) {
  x <- as.character(x)
  data.table::fcase(
    x %in% c("aumento"), "aumento",
    x %in% c("reducao", "redução"), "redução",
    x %in% c("estabilidade_equivalente"), "estabilidade/equivalência",
    x %in% c("estabilidade_composicional"), "estabilidade composicional",
    x %in% c("mudanca_composicao", "mudança_composição"), "mudança de composição",
    x %in% c("pares_insuficientes"), "pares insuficientes",
    x %in% c("inconclusivo"), "inconclusivo",
    default = x
  )
}

monitora_relatorio_rotulo_metrica <- function(x) {
  x <- as.character(x)
  data.table::fcase(
    x == "proporcao_relativa", "proporção relativa",
    x == "cobertura", "cobertura vegetal",
    default = x
  )
}

monitora_relatorio_rotulo_grupo <- function(x) {
  x <- as.character(x)
  data.table::fcase(
    x == "herbaceas_lenhosas", "herbáceas/lenhosas",
    x == "categorias_gerais", "categorias gerais",
    x == "material_botanico", "material botânico",
    x == "formas_vida_nativas", "formas de vida nativas",
    x == "formas_vida_exoticas", "formas de vida exóticas",
    x == "formas_vida_secas_mortas", "formas de vida secas ou mortas",
    default = x
  )
}

monitora_relatorio_criar_linha_categoria <- function(dt, linha_base = FALSE, uc_txt = NA_character_) {
  if (is.null(dt) || !nrow(dt)) return(character())
  d <- data.table::as.data.table(data.table::copy(dt))
  data.table::setorder(d, grupo_grafico, tipo_metrica, form_veg, ano_2, categoria_label)

  if (isTRUE(linha_base)) {
    p_col <- "p_ajustado_fdr_linha_base"
    d[, linha := paste0(
      "- UC: ", uc_txt,
      " | formação: ", form_veg,
      " | grupo: ", monitora_relatorio_rotulo_grupo(grupo_grafico),
      " | métrica: ", monitora_relatorio_rotulo_metrica(tipo_metrica),
      " | categoria: ", categoria_label,
      " | ano: ", ano_2,
      " | linha de base: ", anos_linha_base,
      " (", n_anos_linha_base, " ano(s))",
      " | n UAs pareadas: ", n_UA_pareadas,
      " | média linha de base: ", monitora_relatorio_formatar_numero(media_linha_base * 100, 1), "%",
      " | média do ano: ", monitora_relatorio_formatar_numero(media_ano_2 * 100, 1), "%",
      " | diferença: ", monitora_relatorio_formatar_pp(diferenca_pp, 1),
      " | IC95%: ", monitora_relatorio_formatar_pp(ci95_lower_pp, 1), " a ", monitora_relatorio_formatar_pp(ci95_upper_pp, 1),
      " | p ajustado FDR-BH: ", monitora_relatorio_formatar_p(get(p_col)),
      " | interpretação: ", monitora_relatorio_classe_portugues(classe_mudanca)
    )]
  } else {
    p_col <- "p_ajustado_fdr"
    d[, linha := paste0(
      "- UC: ", uc_txt,
      " | formação: ", form_veg,
      " | grupo: ", monitora_relatorio_rotulo_grupo(grupo_grafico),
      " | métrica: ", monitora_relatorio_rotulo_metrica(tipo_metrica),
      " | categoria: ", categoria_label,
      " | comparação: ", ano_1, " → ", ano_2,
      ifelse(!is.na(anos_referencia) & nzchar(as.character(anos_referencia)), paste0(" (referência real: ", anos_referencia, ")"), ""),
      " | n UAs pareadas: ", n_UA_pareadas,
      " | média referência: ", monitora_relatorio_formatar_numero(media_ano_1 * 100, 1), "%",
      " | média do ano: ", monitora_relatorio_formatar_numero(media_ano_2 * 100, 1), "%",
      " | diferença: ", monitora_relatorio_formatar_pp(diferenca_pp, 1),
      " | IC95%: ", monitora_relatorio_formatar_pp(ci95_lower_pp, 1), " a ", monitora_relatorio_formatar_pp(ci95_upper_pp, 1),
      " | p ajustado FDR-BH: ", monitora_relatorio_formatar_p(get(p_col)),
      " | interpretação: ", monitora_relatorio_classe_portugues(classe_mudanca)
    )]
  }
  d$linha
}

monitora_relatorio_criar_linha_composicao <- function(dt, linha_base = FALSE, uc_txt = NA_character_) {
  if (is.null(dt) || !nrow(dt)) return(character())
  d <- data.table::as.data.table(data.table::copy(dt))
  data.table::setorder(d, grupo_grafico, tipo_metrica, form_veg, ano_2)

  if (isTRUE(linha_base)) {
    d[, linha := paste0(
      "- UC: ", uc_txt,
      " | formação: ", form_veg,
      " | grupo: ", monitora_relatorio_rotulo_grupo(grupo_grafico),
      " | métrica: ", monitora_relatorio_rotulo_metrica(tipo_metrica),
      " | ano: ", ano_2,
      " | linha de base: ", anos_linha_base,
      " (", n_anos_linha_base, " ano(s))",
      " | n UAs pareadas: ", n_UA_pareadas,
      " | categorias incluídas: ", n_categorias,
      " | distância Hellinger do centróide: ", monitora_relatorio_formatar_numero(distancia_centroide_hellinger, 3),
      " | Bray-Curtis médio pareado: ", monitora_relatorio_formatar_numero(bray_curtis_medio_pareado, 3),
      " | p ajustado FDR-BH: ", monitora_relatorio_formatar_p(p_ajustado_fdr_composicao_linha_base),
      " | interpretação: ", monitora_relatorio_classe_portugues(classe_mudanca_composicao_linha_base),
      " | categorias: ", categorias_incluidas
    )]
  } else {
    d[, linha := paste0(
      "- UC: ", uc_txt,
      " | formação: ", form_veg,
      " | grupo: ", monitora_relatorio_rotulo_grupo(grupo_grafico),
      " | métrica: ", monitora_relatorio_rotulo_metrica(tipo_metrica),
      " | comparação: ", ano_1, " → ", ano_2,
      ifelse(!is.na(anos_referencia) & nzchar(as.character(anos_referencia)), paste0(" (referência real: ", anos_referencia, ")"), ""),
      " | n UAs pareadas: ", n_UA_pareadas,
      " | categorias incluídas: ", n_categorias,
      " | distância Hellinger do centróide: ", monitora_relatorio_formatar_numero(distancia_centroide_hellinger, 3),
      " | Bray-Curtis médio pareado: ", monitora_relatorio_formatar_numero(bray_curtis_medio_pareado, 3),
      " | p ajustado FDR-BH: ", monitora_relatorio_formatar_p(p_ajustado_fdr_composicao),
      " | interpretação: ", monitora_relatorio_classe_portugues(classe_mudanca_composicao),
      " | categorias: ", categorias_incluidas
    )]
  }
  d$linha
}

monitora_relatorio_resumir_classe <- function(dt, coluna_classe) {
  if (is.null(dt) || !nrow(dt) || !coluna_classe %in% names(dt)) return(character())
  d <- data.table::as.data.table(data.table::copy(dt))
  tab <- d[, .N, by = coluna_classe]
  data.table::setnames(tab, coluna_classe, "classe")
  data.table::setorder(tab, -N, classe)
  paste0("- ", monitora_relatorio_classe_portugues(tab$classe), ": ", tab$N)
}

monitora_relatorio_principais_mudancas_categoria <- function(dt, linha_base = FALSE, n_top = 12L) {
  if (is.null(dt) || !nrow(dt)) return(character())
  d <- data.table::as.data.table(data.table::copy(dt))
  d <- d[classe_mudanca %in% c("aumento", "reducao")]
  if (!nrow(d)) return("- Nenhuma mudança direcional sustentada foi detectada por categoria.")
  d[, abs_dif := abs(suppressWarnings(as.numeric(diferenca_pp)))]
  data.table::setorder(d, -abs_dif, grupo_grafico, tipo_metrica, form_veg, ano_2)
  d <- d[seq_len(min(n_top, .N))]
  if (isTRUE(linha_base)) {
    d[, paste0(
      "- ", form_veg, " | ", monitora_relatorio_rotulo_grupo(grupo_grafico), " | ",
      monitora_relatorio_rotulo_metrica(tipo_metrica), " | ", categoria_label,
      " | ", ano_2, " vs linha de base ", anos_linha_base,
      ": ", monitora_relatorio_classe_portugues(classe_mudanca),
      " de ", monitora_relatorio_formatar_pp(diferenca_pp, 1),
      " (n=", n_UA_pareadas, "; p adj.=", monitora_relatorio_formatar_p(p_ajustado_fdr_linha_base), ")"
    )]
  } else {
    d[, paste0(
      "- ", form_veg, " | ", monitora_relatorio_rotulo_grupo(grupo_grafico), " | ",
      monitora_relatorio_rotulo_metrica(tipo_metrica), " | ", categoria_label,
      " | ", ano_1, "→", ano_2,
      ": ", monitora_relatorio_classe_portugues(classe_mudanca),
      " de ", monitora_relatorio_formatar_pp(diferenca_pp, 1),
      " (n=", n_UA_pareadas, "; p adj.=", monitora_relatorio_formatar_p(p_ajustado_fdr), ")"
    )]
  }
}

monitora_relatorio_principais_mudancas_composicao <- function(dt, linha_base = FALSE, n_top = 10L) {
  if (is.null(dt) || !nrow(dt)) return(character())
