  monitora_stat_registrar_msg("gráficos temporais editoriais preparados: ", length(monitora_editorial_plot_names))
}

monitora_painel_ano_inicial_filtrar_series <- function(series_dt) {
  if (is.null(series_dt) || !nrow(series_dt)) return(data.table::data.table())
  dt <- data.table::as.data.table(data.table::copy(series_dt))
  anos <- sort(unique(as.integer(dt$ANO)))
  anos <- anos[is.finite(anos)]
  if (length(anos) < 2L) return(data.table::data.table())
  out <- vector("list", 0)
  idx <- 0L
  grupos_form <- unique(dt[, .(grupo_grafico, tipo_metrica, form_veg)])
  anos_loop <- anos[-length(anos)]
  monitora_progresso_loop_configurar("grafico_painel_ano_inicial", length(anos_loop), descricao = "preparação de painéis amostrais por ano inicial")
  for (ano_i in seq_along(anos_loop)) {
    ano_inicio <- anos_loop[[ano_i]]
    monitora_progresso_loop_avancar("grafico_painel_ano_inicial", atual = ano_i, detalhe = paste0(ano_i, "/", length(anos_loop), ": ano inicial ", ano_inicio))
    for (ii in seq_len(nrow(grupos_form))) {
      gf <- grupos_form[ii]
      base <- dt[
        grupo_grafico == gf$grupo_grafico &
          tipo_metrica == gf$tipo_metrica &
          form_veg == gf$form_veg &
          ANO >= ano_inicio
      ]
      if (!nrow(base)) next
      uas_base <- unique(base[ANO == ano_inicio, .(UC, UA)])
      if (!nrow(uas_base)) next
      data.table::setkeyv(base, c("UC", "UA"))
      data.table::setkeyv(uas_base, c("UC", "UA"))
      sub <- base[uas_base, nomatch = 0L]
      if (!nrow(sub) || data.table::uniqueN(sub$ANO) < 2L) next
      idx <- idx + 1L
      sub[, ano_inicial_painel := ano_inicio]
      out[[idx]] <- sub
    }
  }
  data.table::rbindlist(out, fill = TRUE, use.names = TRUE)
}

monitora_painel_ano_inicial_codigo_curto <- function(grupo_grafico, tipo_metrica) {
  monitora_plot_editorial_codigo_grupo(grupo_grafico, tipo_metrica)
}

monitora_painel_ano_inicial_texto <- function(grupo_grafico, tipo_metrica, ano_inicio, form_veg = NULL) {
  titulo_base <- monitora_plot_editorial_titulo_base(grupo_grafico, tipo_metrica)
  if (!is.null(form_veg)) {
    titulo_base <- sub(" em formações campestres e savânicas$", paste0(" em formações ", tolower(form_veg), "s"), titulo_base)
  }
  subt <- paste0(
    "Escopo: apenas UAs já amostradas em ", ano_inicio,
    "; anos exibidos a partir de ", ano_inicio,
    "."
  )
  list(
    titulo = titulo_base,
    subtitulo = subt,
    caption = "Símbolos estatísticos (UA/transecto pareada) e regras editoriais idênticas às dos gráficos originais; painel amostral restrito às UAs presentes no ano inicial indicado."
  )
}

