}

monitora_plot_painel_ano_inicial_proporcao <- function(dados, grupo_grafico, form_veg_alvo, com_rotulo = TRUE) {
  dados <- data.table::as.data.table(data.table::copy(dados))
  if (!nrow(dados)) return(NULL)
  ano_inicio <- unique(stats::na.omit(as.integer(as.character(dados$ano_inicial_painel))))[1]
  txt <- monitora_painel_ano_inicial_texto(grupo_grafico, "proporcao_relativa", ano_inicio = ano_inicio, form_veg = form_veg_alvo)
  dados <- dados[as.character(form_veg) == as.character(form_veg_alvo)]
  if (!nrow(dados)) return(NULL)
  dados_rot <- monitora_plot_preparar_rotulos_proporcao_obrigatorios(
    dados,
    prop_min_interno = if (grupo_grafico %in% c("herbaceas_lenhosas")) 0.001 else 0.10
  )
  dados_rot <- monitora_plot_editorial_compactar_rotulos_proporcao(dados_rot, grupo_grafico = grupo_grafico, escopo = "painel_ano_inicial")
 ## ANO_label_rotulo já é rótulo de exibição calculado sem afetar a chave interna
 ## de posicionamento. Não sobrescrever aqui, para preservar n UA quando disponível.
  p <- ggplot2::ggplot(data = dados_rot) +
    monitora_plot_camada_barras_proporcao_obrigatorios(dados_rot)
  if (isTRUE(com_rotulo)) {
    p <- p + monitora_plot_camadas_rotulos_proporcao_obrigatorios(dados_rot)
  } else {
    escala_anos <- unique(dados_rot[, .(ANO_factor_rotulo, ANO_label_rotulo)])
    data.table::setorder(escala_anos, ANO_factor_rotulo)
    p <- p + ggplot2::scale_y_continuous(
      breaks = escala_anos$ANO_factor_rotulo,
      labels = escala_anos$ANO_label_rotulo,
      expand = ggplot2::expansion(mult = c(0.10, 0.12))
    ) + monitora_plot_coord_cartesian(xlim = c(0, 1), clip = "on")
  }
  p +
    ggplot2::labs(
      title = txt$titulo,
      subtitle = txt$subtitulo,
      x = "Proporção relativa",
      y = "ANO",
      fill = "Categoria",
      caption = txt$caption
    ) +
    monitora_plot_scale_x_proporcao_obrigatorios(dados_rot) +
    monitora_plot_theme_proporcao_publicavel() +
    ggplot2::theme(
      legend.position = "right",
      panel.grid.major.y = ggplot2::element_blank(),
      panel.grid.minor = ggplot2::element_blank()
    )
}


monitora_plot_painel_ano_inicial_cobertura <- function(dados, grupo_grafico, com_rotulo = TRUE) {
  dados <- data.table::as.data.table(data.table::copy(dados))
  if (!nrow(dados)) return(NULL)
  ano_inicio <- unique(stats::na.omit(as.integer(as.character(dados$ano_inicial_painel))))[1]
  txt <- monitora_painel_ano_inicial_texto(grupo_grafico, "cobertura", ano_inicio = ano_inicio)

  complexo <- grupo_grafico %in% c("categorias_gerais", MONITORA_STAT_GRUPOS_MUITAS_CATEGORIAS)
  if (isTRUE(complexo)) {
    dados <- monitora_plot_adicionar_rotulo_cobertura_complexa(dados)
  }
  dados <- monitora_plot_editorial_compactar_rotulos_cobertura(dados, grupo_grafico = grupo_grafico, escopo = "painel_ano_inicial")
  dados <- monitora_plot_preparar_layout_rotulos_cobertura(
    dados,
    complexo = complexo,
    max_rotulos_complexo = if (grupo_grafico %in% c("formas_vida_secas_mortas")) 3L else 4L
  )

  x_ref <- suppressWarnings(max(pmax(dados$veg_cover, dados$ci_upper, dados$x_rotulo, na.rm = TRUE), na.rm = TRUE))
  if (!is.finite(x_ref) || x_ref <= 0) x_ref <- max(dados$veg_cover, na.rm = TRUE)
  if (!is.finite(x_ref) || x_ref <= 0) x_ref <- 5
  x_lim <- monitora_plot_calcular_xmax_cobertura_rotulos(dados, fallback = x_ref)
  x_lim <- max(x_lim, x_ref)
  breaks_x <- monitora_plot_breaks_eixo_x_cobertura(x_lim)

  cats <- unique(stats::na.omit(as.character(dados$categoria_label)))
  n_cats <- length(cats)
  legenda_inferior <- isTRUE(com_rotulo) && (isTRUE(complexo) || n_cats >= 6L)
  leg_cols <- if (legenda_inferior) min(4L, max(2L, ceiling(n_cats / 3))) else 1L

  p <- ggplot2::ggplot(
    dados,
    ggplot2::aes(x = veg_cover, y = factor(ANO), fill = categoria_label, group = categoria_label)
  ) +
    ggplot2::geom_col(position = ggplot2::position_dodge(width = 0.7), width = 0.6) +
    ggplot2::geom_errorbar(
      ggplot2::aes(xmin = ci_lower, xmax = ci_upper),
      position = ggplot2::position_dodge(width = 0.7),
      width = 0.2,
      orientation = "y",
      color = "black"
    )
  if (isTRUE(com_rotulo)) {
    p <- p +
      ggplot2::geom_label(
        data = function(d) d[!is.na(d$rotulo_cobertura_plot) & d$rotulo_cobertura_plot != "", , drop = FALSE],
        ggplot2::aes(x = x_rotulo, y = factor(ANO), label = rotulo_cobertura_plot, group = categoria_label),
        inherit.aes = FALSE,
        position = ggplot2::position_dodge(width = 0.7),
        hjust = 0,
        size = if (isTRUE(complexo)) MONITORA_FONTE_ROTULO_COB * 0.62 else MONITORA_FONTE_ROTULO_COB * 0.82,
        lineheight = MONITORA_LINEHEIGHT_ROTULO,
        linewidth = 0,
        label.padding = grid::unit(0.030, "lines"),
        fill = "white",
        color = "black",
        show.legend = FALSE
      )
  }
  p +
    ggplot2::facet_wrap(~form_veg) +
    ggplot2::labs(
      title = txt$titulo,
      subtitle = txt$subtitulo,
      x = "Cobertura vegetal (%)",
      y = "Ano",
      fill = "Categoria",
      caption = txt$caption
    ) +
    ggplot2::scale_y_discrete(drop = TRUE) +
    ggplot2::scale_x_continuous(
      breaks = breaks_x,
      labels = scales::label_number(accuracy = 1, decimal.mark = ","),
      expand = ggplot2::expansion(mult = c(0, 0.02))
    ) +
    monitora_plot_theme_cobertura_publicavel() +
    ggplot2::guides(fill = ggplot2::guide_legend(ncol = leg_cols, byrow = TRUE)) +
    ggplot2::theme(
      legend.position = if (legenda_inferior) "bottom" else "right",
      legend.box = "vertical",
      legend.text = ggplot2::element_text(size = if (legenda_inferior) 8.2 else 10),
      legend.title = ggplot2::element_text(size = if (legenda_inferior) 9 else 11, face = "bold"),
      panel.spacing.x = grid::unit(2.3, "lines"),
      panel.grid.major.y = ggplot2::element_blank(),
      panel.grid.minor = ggplot2::element_blank()
    ) +
 ## A janela usa o layout de rótulos calculado. Símbolos de composição não criam
 ## camadas em y incompatível, evitando anos duplicados no eixo.
    monitora_plot_coord_cartesian(xlim = c(0, x_lim), clip = "on")
}

monitora_plot_painel_ano_inicial_gerar_graficos <- function(series_painel_ano_inicial) {
  if (is.null(series_painel_ano_inicial) || !nrow(series_painel_ano_inicial)) return(character(0))
  nomes <- character(0)
  grupos <- unique(series_painel_ano_inicial[, .(ano_inicial_painel, grupo_grafico, tipo_metrica)])
  data.table::setorder(grupos, ano_inicial_painel, grupo_grafico, tipo_metrica)
  for (ii in seq_len(nrow(grupos))) {
    g <- grupos[ii]
    base <- series_painel_ano_inicial[
      ano_inicial_painel == g$ano_inicial_painel &
        grupo_grafico == g$grupo_grafico &
        tipo_metrica == g$tipo_metrica
    ]
    if (!nrow(base)) next
    codigo <- monitora_painel_ano_inicial_codigo_curto(g$grupo_grafico, g$tipo_metrica)
    dados_plot <- monitora_painel_ano_inicial_agregar(base)
    if (!nrow(dados_plot)) next
    dados_plot[, ano_inicial_painel := g$ano_inicial_painel]
    if (identical(g$tipo_metrica, "proporcao_relativa")) {
      for (fv in unique(as.character(dados_plot$form_veg))) {
        sub <- dados_plot[form_veg == fv]
        if (!nrow(sub)) next
        sufixo_form <- if (grepl("Camp", fv, ignore.case = TRUE)) "camp" else "sav"
        nome_com <- paste0("plot_", codigo, "_painel_ano_inicial_", g$ano_inicial_painel, "_", sufixo_form, "_com_rotulo")
        nome_sem <- paste0("plot_", codigo, "_painel_ano_inicial_", g$ano_inicial_painel, "_", sufixo_form, "_sem_rotulo")
        assign(nome_com, monitora_plot_painel_ano_inicial_proporcao(sub, g$grupo_grafico, form_veg_alvo = fv, com_rotulo = TRUE), envir = .GlobalEnv)
        assign(nome_sem, monitora_plot_painel_ano_inicial_proporcao(sub, g$grupo_grafico, form_veg_alvo = fv, com_rotulo = FALSE), envir = .GlobalEnv)
        nomes <- c(nomes, nome_com, nome_sem)
      }
    } else {
      nome_com <- paste0("plot_", codigo, "_painel_ano_inicial_", g$ano_inicial_painel, "_com_rotulo")
      nome_sem <- paste0("plot_", codigo, "_painel_ano_inicial_", g$ano_inicial_painel, "_sem_rotulo")
      assign(nome_com, monitora_plot_painel_ano_inicial_cobertura(dados_plot, g$grupo_grafico, com_rotulo = TRUE), envir = .GlobalEnv)
      assign(nome_sem, monitora_plot_painel_ano_inicial_cobertura(dados_plot, g$grupo_grafico, com_rotulo = FALSE), envir = .GlobalEnv)
      nomes <- c(nomes, nome_com, nome_sem)
    }
  }
  unique(nomes)
}


monitora_exportar_tabela_painel_ano_inicial <- function(dt, arquivo) {
  if (is.null(dt) || !is.data.frame(dt) || !nrow(dt)) return(invisible(FALSE))
  out <- data.table::as.data.table(data.table::copy(dt))
  if ("ano_inicial_painel" %in% names(out) && !"ano_inicial_painel" %in% names(out)) {
    data.table::setnames(out, "ano_inicial_painel", "ano_inicial_painel")
  }
  monitora_fwrite(out, file.path(MONITORA_OUTPUT_DIR, arquivo), row.names = FALSE)
  invisible(TRUE)
}

monitora_progresso_definir_valor(7520L, etapa = "preparacao_objetos_graficos", detalhe = "montando gráficos por painel amostral", force = TRUE)
monitora_painel_ano_inicial_plot_names <- character(0)
if (exists("MONITORA_STAT_SERIES_UA_ANO") && is.data.frame(MONITORA_STAT_SERIES_UA_ANO) && nrow(MONITORA_STAT_SERIES_UA_ANO) > 0) {
  MONITORA_STAT_SERIES_UA_ANO_PAINEL_ANO_INICIAL <- monitora_painel_ano_inicial_filtrar_series(MONITORA_STAT_SERIES_UA_ANO)
  if (nrow(MONITORA_STAT_SERIES_UA_ANO_PAINEL_ANO_INICIAL)) {
    monitora_stat_registrar_msg("rodando estatísticas para gráficos de painéis amostrais por ano inicial")
    partes_painel_ano_inicial <- split(MONITORA_STAT_SERIES_UA_ANO_PAINEL_ANO_INICIAL, MONITORA_STAT_SERIES_UA_ANO_PAINEL_ANO_INICIAL$ano_inicial_painel)
    MONITORA_STAT_MUDANCA_ANO_A_ANO_PAINEL_ANO_INICIAL <- data.table::rbindlist(lapply(names(partes_painel_ano_inicial), function(k) {
      d <- partes_painel_ano_inicial[[k]]
      out <- monitora_stat_comparar_anos_consecutivos(d)
      if (nrow(out)) out[, ano_inicial_painel := as.integer(k)]
      out
    }), fill = TRUE, use.names = TRUE)
    MONITORA_STAT_MUDANCA_LINHA_BASE_PAINEL_ANO_INICIAL <- data.table::rbindlist(lapply(names(partes_painel_ano_inicial), function(k) {
      d <- partes_painel_ano_inicial[[k]]
      out <- monitora_stat_comparar_linha_base(d)
      if (nrow(out)) out[, ano_inicial_painel := as.integer(k)]
      out
    }), fill = TRUE, use.names = TRUE)
    MONITORA_STAT_COMPOSICAO_GERAL_PAINEL_ANO_INICIAL <- data.table::rbindlist(lapply(names(partes_painel_ano_inicial), function(k) {
      d <- partes_painel_ano_inicial[[k]]
      out <- monitora_stat_comparar_composicao_anos_consecutivos(d)
      if (nrow(out)) out[, ano_inicial_painel := as.integer(k)]
      out
    }), fill = TRUE, use.names = TRUE)
    MONITORA_STAT_COMPOSICAO_LINHA_BASE_PAINEL_ANO_INICIAL <- data.table::rbindlist(lapply(names(partes_painel_ano_inicial), function(k) {
      d <- partes_painel_ano_inicial[[k]]
      out <- monitora_stat_comparar_composicao_linha_base(d)
      if (nrow(out)) out[, ano_inicial_painel := as.integer(k)]
      out
    }), fill = TRUE, use.names = TRUE)
    if (exists("MONITORA_OUTPUT_DIR") && dir.exists(MONITORA_OUTPUT_DIR)) {
      MONITORA_STAT_MUDANCA_ANO_A_ANO_PAINEL <- MONITORA_STAT_MUDANCA_ANO_A_ANO_PAINEL_ANO_INICIAL
      MONITORA_STAT_MUDANCA_LINHA_BASE_PAINEL <- MONITORA_STAT_MUDANCA_LINHA_BASE_PAINEL_ANO_INICIAL
      MONITORA_STAT_COMPOSICAO_GERAL_PAINEL <- MONITORA_STAT_COMPOSICAO_GERAL_PAINEL_ANO_INICIAL
      MONITORA_STAT_COMPOSICAO_LINHA_BASE_PAINEL <- MONITORA_STAT_COMPOSICAO_LINHA_BASE_PAINEL_ANO_INICIAL
      if (nrow(MONITORA_STAT_MUDANCA_ANO_A_ANO_PAINEL)) monitora_exportar_tabela_painel_ano_inicial(MONITORA_STAT_MUDANCA_ANO_A_ANO_PAINEL, "estatisticas_mudanca_ano_a_ano_paineis_ano_inicial.csv")
      if (nrow(MONITORA_STAT_MUDANCA_LINHA_BASE_PAINEL)) monitora_exportar_tabela_painel_ano_inicial(MONITORA_STAT_MUDANCA_LINHA_BASE_PAINEL, "estatisticas_mudanca_linha_base_paineis_ano_inicial.csv")
      if (nrow(MONITORA_STAT_COMPOSICAO_GERAL_PAINEL)) monitora_exportar_tabela_painel_ano_inicial(MONITORA_STAT_COMPOSICAO_GERAL_PAINEL, "estatisticas_composicao_geral_ano_a_ano_paineis_ano_inicial.csv")
      if (nrow(MONITORA_STAT_COMPOSICAO_LINHA_BASE_PAINEL)) monitora_exportar_tabela_painel_ano_inicial(MONITORA_STAT_COMPOSICAO_LINHA_BASE_PAINEL, "estatisticas_composicao_linha_base_paineis_ano_inicial.csv")
    }
    monitora_painel_ano_inicial_plot_names <- monitora_plot_painel_ano_inicial_gerar_graficos(MONITORA_STAT_SERIES_UA_ANO_PAINEL_ANO_INICIAL)
    monitora_stat_registrar_msg("gráficos de painéis amostrais por ano inicial preparados: ", length(monitora_painel_ano_inicial_plot_names))
  }
}

