monitora_grafico_detectar_tema <- function(nome_plot) {
  data.table::fcase(
    grepl("herb_lenh", nome_plot), "herbaceas_lenhosas",
    grepl("material_botanico", nome_plot), "material_botanico",
    grepl("categ", nome_plot), "categorias_gerais",
    grepl("nat", nome_plot), "formas_vida_nativas",
    grepl("exot", nome_plot), "formas_vida_exoticas",
    grepl("seca_morta", nome_plot), "formas_vida_secas_mortas",
    default = "nao_classificado"
  )
}

monitora_grafico_detectar_metrica <- function(nome_plot) {
  data.table::fcase(
    nome_plot == "plot_p5.3.2_seca_morta_sem_rotulo", "cobertura",
    grepl("prop_rel", nome_plot), "proporcao_relativa",
    grepl("veg_cover", nome_plot), "cobertura",
    default = "nao_classificada"
  )
}

monitora_grafico_detectar_formacao <- function(nome_plot) {
  data.table::fcase(
    grepl("_camp_", nome_plot), "campestre",
    grepl("_sav_", nome_plot), "savanica",
    default = "campestre_savanica"
  )
}

monitora_grafico_detectar_rotulo <- function(nome_plot) {
  data.table::fcase(
    grepl("_sem_rotulo$", nome_plot), "sem_rotulo",
    grepl("_com_rotulo$", nome_plot), "com_rotulo",
    grepl("^plot_ed_", nome_plot), "com_rotulo",
    default = "nao_aplicavel"
  )
}

monitora_grafico_detectar_escopo <- function(nome_plot) {
  if (grepl("^plot_ed_", nome_plot)) {
    return(data.table::fcase(
      grepl("_amostra_total$", nome_plot), "amostra_total",
      grepl("_pareado_total$", nome_plot), "pareado_total",
      grepl("_pareado_periodo$", nome_plot), "pareado_periodo",
      default = "temporal"
    ))
  }
  if (grepl("_painel_ano_inicial_[0-9]{4}", nome_plot)) {
    ano <- sub(".*_painel_ano_inicial_([0-9]{4}).*", "\\1", nome_plot)
    return(paste0("ano_inicial_", ano))
  }
  "amostra_total"
}

monitora_grafico_detectar_bloco <- function(nome_plot) {
  data.table::fcase(
    grepl("^plot_ed_", nome_plot), "temporal",
    grepl("_painel_ano_inicial_[0-9]{4}", nome_plot), "painel_ano_inicial",
    default = "sintese"
  )
}

monitora_grafico_detectar_ano_painel <- function(nome_plot) {
  if (!grepl("_painel_ano_inicial_[0-9]{4}", nome_plot)) return(NA_integer_)
  suppressWarnings(as.integer(sub(".*_painel_ano_inicial_([0-9]{4}).*", "\\1", nome_plot)))
}

monitora_grafico_arquivo_dados <- function(metrica, tema, bloco) {
  if (identical(bloco, "temporal")) return("graficos_temporais_editoriais_dados.csv")
  if (identical(bloco, "painel_ano_inicial")) {
    return("estatisticas_mudanca_ano_a_ano_paineis_ano_inicial.csv; estatisticas_mudanca_linha_base_paineis_ano_inicial.csv; estatisticas_composicao_geral_ano_a_ano_paineis_ano_inicial.csv; estatisticas_composicao_linha_base_paineis_ano_inicial.csv")
  }
  if (identical(metrica, "proporcao_relativa")) {
    return(data.table::fcase(
      tema == "herbaceas_lenhosas", "prop_rel_herb_lenh.csv",
      tema == "categorias_gerais", "prop_rel_categ.csv",
      tema == "material_botanico", "prop_rel_material_botanico.csv",
      tema == "formas_vida_nativas", "prop_rel_form_vida_nat.csv",
      tema == "formas_vida_exoticas", "prop_rel_form_vida_exot.csv",
      tema == "formas_vida_secas_mortas", "prop_rel_form_vida_seca_morta.csv",
      default = NA_character_
    ))
  }
  data.table::fcase(
    tema == "herbaceas_lenhosas", "cob_veg_herb_lenh.csv",
    tema == "categorias_gerais", "cob_veg_categ.csv",
    tema == "material_botanico", "cob_veg_material_botanico.csv",
    tema == "formas_vida_nativas", "cob_veg_form_vida_nat.csv",
    tema == "formas_vida_exoticas", "cob_veg_form_vida_exot.csv",
    tema == "formas_vida_secas_mortas", "cob_veg_form_vida_seca_morta.csv",
    default = NA_character_
  )
}

monitora_grafico_titulo_publico <- function(bloco, escopo, metrica, tema, formacao, ano_inicial = NA_integer_) {
  pref <- data.table::fcase(
    bloco == "sintese", "Síntese descritiva",
    bloco == "temporal", "Série temporal",
    bloco == "painel_ano_inicial", paste0("Painel amostral ", ano_inicial),
    default = "Gráfico"
  )
  paste0(
    pref, " — ", monitora_relatorio_rotulo_metrica(metrica),
    " — ", monitora_relatorio_rotulo_grupo(tema),
    " — ", gsub("_", "/", formacao),
    if (!is.na(escopo) && nzchar(escopo) && !identical(bloco, "painel_ano_inicial")) paste0(" — ", escopo) else ""
  )
}

monitora_grafico_nome_publico <- function(serial, bloco, escopo, metrica, tema, formacao, rotulo, ano_inicial = NA_integer_) {
  serial_txt <- sprintf("%03d", as.integer(serial))
  if (identical(bloco, "painel_ano_inicial")) {
    return(paste0("fig_", serial_txt, "_painel_", ano_inicial, "_", metrica, "_", tema, "_", formacao, "_", rotulo, ".png"))
  }
  paste0("fig_", serial_txt, "_", bloco, "_", escopo, "_", metrica, "_", tema, "_", formacao, "_", rotulo, ".png")
}

monitora_criar_indice_graficos_publicos <- function(nomes_plot) {
  nomes_plot <- unique(as.character(nomes_plot))
  nomes_plot <- nomes_plot[nzchar(nomes_plot)]
  if (!length(nomes_plot)) return(data.table::data.table())
  idx <- data.table::data.table(nome_plot = nomes_plot)
  idx[, bloco := vapply(nome_plot, monitora_grafico_detectar_bloco, character(1))]
  idx[, ordem_bloco := data.table::fcase(bloco == "sintese", 1L, bloco == "temporal", 2L, bloco == "painel_ano_inicial", 3L, default = 9L)]
  idx[, ordem_original := seq_len(.N)]
  data.table::setorder(idx, ordem_bloco, ordem_original)
  idx[, serial := seq_len(.N)]
  idx[, arquivo_png_anterior := paste0(nome_plot, ".png")]
  idx[, tema := vapply(nome_plot, monitora_grafico_detectar_tema, character(1))]
  idx[, metrica := vapply(nome_plot, monitora_grafico_detectar_metrica, character(1))]
  idx[, formacao := vapply(nome_plot, monitora_grafico_detectar_formacao, character(1))]
  idx[, rotulo := vapply(nome_plot, monitora_grafico_detectar_rotulo, character(1))]
  idx[, escopo := vapply(nome_plot, monitora_grafico_detectar_escopo, character(1))]
  idx[, ano_inicial := vapply(nome_plot, monitora_grafico_detectar_ano_painel, integer(1))]
  idx[, arquivo_png := mapply(monitora_grafico_nome_publico, serial, bloco, escopo, metrica, tema, formacao, rotulo, ano_inicial, USE.NAMES = FALSE)]
  idx[, arquivo_dados := mapply(monitora_grafico_arquivo_dados, metrica, tema, bloco, USE.NAMES = FALSE)]
  idx[, titulo := mapply(monitora_grafico_titulo_publico, bloco, escopo, metrica, tema, formacao, ano_inicial, USE.NAMES = FALSE)]
  idx[, uso_recomendado := data.table::fcase(
    bloco == "temporal", "principal_publicacao",
    rotulo == "com_rotulo", "principal_publicacao_ou_validacao",
    rotulo == "sem_rotulo", "apoio_visual_sem_rotulos",
    default = "apoio"
  )]
  idx[, observacao := data.table::fcase(
    bloco == "sintese", "Gráfico de síntese descritiva herdado do bloco histórico, exportado com nomenclatura pública seriada.",
    bloco == "temporal", "Gráfico temporal editorial com escopo amostral explícito.",
    bloco == "painel_ano_inicial", "Gráfico de painel amostral por ano inicial.",
    default = "Gráfico indexado."
  )]
  idx[, c("ordem_bloco", "ordem_original") := NULL]
  data.table::setcolorder(idx, c("serial", "arquivo_png", "nome_plot", "arquivo_png_anterior", "bloco", "escopo", "ano_inicial", "metrica", "tema", "formacao", "rotulo", "uso_recomendado", "arquivo_dados", "titulo", "observacao"))
  idx[]
}

### - disponibilidade semântica de dados para gráficos -----------------
### A existência de um objeto ggplot não prova que exista algo a desenhar.
### Isso ocorre, por exemplo, quando um subconjunto Campestre/Savânica fica
### vazio depois dos filtros de UC, período, painel ou denominador da métrica.
### O gate abaixo trabalha sobre os dados já escopados do próprio objeto e,
### portanto, vale para sínteses, gráficos temporais e painéis por ano inicial,
### sem listas especiais por UC, formação ou nome de gráfico.
monitora_plot_formacao_normalizar <- function(x) {
  y <- tolower(trimws(as.character(x)))
  data.table::fcase(
    grepl("camp", y), "campestre",
    grepl("sav", y), "savanica",
    default = NA_character_
  )
}

monitora_plot_dados_disponibilidade <- function(plot_obj) {
  if (!inherits(plot_obj, "ggplot")) return(data.table::data.table())
  dados_base <- tryCatch(plot_obj$data, error = function(e) NULL)
  if (is.data.frame(dados_base) && nrow(dados_base)) {
    return(data.table::as.data.table(data.table::copy(dados_base)))
  }

 ### Alguns gráficos mantêm os dados somente em camadas explícitas. Funções
 ### de dados de camada herdam a base; se a base está vazia, também não criam
 ### observações renderizáveis e não precisam ser avaliadas aqui.
  partes <- list()
  camadas <- tryCatch(plot_obj$layers, error = function(e) list())
  for (ii in seq_along(camadas)) {
    d <- tryCatch(camadas[[ii]]$data, error = function(e) NULL)
    if (is.data.frame(d) && nrow(d)) partes[[length(partes) + 1L]] <- data.table::as.data.table(data.table::copy(d))
  }
  if (length(partes)) data.table::rbindlist(partes, fill = TRUE, use.names = TRUE) else data.table::data.table()
}

monitora_plot_avaliar_disponibilidade <- function(nome_plot, plot_obj) {
  dados <- monitora_plot_dados_disponibilidade(plot_obj)
  n_linhas <- nrow(dados)
  formacao_alvo <- monitora_grafico_detectar_formacao(nome_plot)
  formacoes <- if (n_linhas && "form_veg" %in% names(dados)) {
    sort(unique(stats::na.omit(monitora_plot_formacao_normalizar(dados$form_veg))))
  } else character(0)

  formacao_ausente <- n_linhas > 0L &&
    formacao_alvo %in% c("campestre", "savanica") &&
    length(formacoes) > 0L && !(formacao_alvo %in% formacoes)

  metrica <- monitora_grafico_detectar_metrica(nome_plot)
  candidatos_valor <- if (identical(metrica, "proporcao_relativa")) {
    c("prop", "valor", "prop_percent", "valor_percent")
  } else if (identical(metrica, "cobertura")) {
    c("veg_cover", "cobertura", "cobertura_percent", "valor", "valor_percent")
  } else character(0)
  candidatos_presentes <- intersect(candidatos_valor, names(dados))
  tem_valor_finito <- TRUE
  if (n_linhas > 0L && length(candidatos_presentes)) {
    tem_valor_finito <- any(vapply(
      candidatos_presentes,
      function(cc) any(is.finite(suppressWarnings(as.numeric(dados[[cc]])))),
      logical(1L)
    ))
  }

  motivo <- data.table::fcase(
    n_linhas == 0L, "sem_linhas_apos_filtros_do_escopo",
    isTRUE(formacao_ausente), "formacao_vegetal_ausente_no_escopo",
    !isTRUE(tem_valor_finito), "metrica_sem_valor_finito_no_escopo",
    default = "dados_renderizaveis"
  )
  data.table::data.table(
    nome_plot = as.character(nome_plot),
    exportar_png = identical(motivo, "dados_renderizaveis"),
    status_exportacao = if (identical(motivo, "dados_renderizaveis")) "programado" else "omitido_sem_dados",
    motivo_disponibilidade = motivo,
    formacao_alvo = formacao_alvo,
    formacoes_observadas = paste(formacoes, collapse = "|"),
    n_linhas_dados_plot = as.integer(n_linhas),
    colunas_valor_avaliadas = paste(candidatos_presentes, collapse = "|"),
    metrica = metrica
  )
}

monitora_plot_avaliar_catalogo <- function(nomes_plot, envir = .GlobalEnv) {
  nomes_plot <- unique(as.character(nomes_plot))
  nomes_plot <- nomes_plot[nzchar(nomes_plot) & vapply(nomes_plot, exists, logical(1L), envir = envir, inherits = FALSE)]
  if (!length(nomes_plot)) return(data.table::data.table())
  data.table::rbindlist(lapply(nomes_plot, function(nm) {
    monitora_plot_avaliar_disponibilidade(nm, get(nm, envir = envir, inherits = FALSE))
  }), fill = TRUE, use.names = TRUE)
}


monitora_stat_largura_painel_gtable_in <- function(g, largura_total_in) {
 # Calcula a largura das colunas dos painéis no gtable, excluindo a legenda lateral.
  idx_painel <- which(grepl("^panel", g$layout$name))
  if (!length(idx_painel)) return(list(l = 1L, r = length(g$widths), largura_in = largura_total_in))

  l_painel <- min(g$layout$l[idx_painel])
  r_painel <- max(g$layout$r[idx_painel])

  tipos <- grid::unitType(g$widths)
  eh_null <- tipos == "null"
  larguras_fixas <- g$widths[!eh_null]
  largura_fixa_total <- tryCatch(
    sum(as.numeric(grid::convertWidth(larguras_fixas, "in", valueOnly = TRUE))),
    error = function(e) 0
  )

  null_total <- sum(as.numeric(g$widths[eh_null]))
  null_disp_in <- max(as.numeric(largura_total_in) - largura_fixa_total, 0.1)

  idx_sel <- seq.int(l_painel, r_painel)
  sel_null <- eh_null[idx_sel]
  largura_sel_fixa <- tryCatch(
    sum(as.numeric(grid::convertWidth(g$widths[idx_sel][!sel_null], "in", valueOnly = TRUE))),
    error = function(e) 0
  )
  largura_sel_null <- if (null_total > 0) null_disp_in * sum(as.numeric(g$widths[idx_sel][sel_null])) / null_total else 0
  largura_painel_in <- max(largura_sel_fixa + largura_sel_null, 0.1)

  list(l = l_painel, r = r_painel, largura_in = largura_painel_in)
}

monitora_stat_adicionar_caption_painel <- function(plot_obj, caption, largura_total_in, fontsize = 7.8, lineheight = 1.02) {
 # Insere a legenda inferior como grob próprio, alinhado às colunas do painel/eixo X.
 # Assim a legenda lateral não entra no cálculo da largura disponível.
  if (is.null(caption) || !nzchar(as.character(caption))) {
    return(list(plot = plot_obj, n_linhas_caption = 0L))
  }

  plot_sem_caption <- plot_obj +
    ggplot2::labs(caption = NULL) +
    ggplot2::theme(
      plot.caption = ggplot2::element_blank(),
      plot.caption.position = "panel"
    )

  g <- ggplot2::ggplotGrob(plot_sem_caption)
  painel <- monitora_stat_largura_painel_gtable_in(g, largura_total_in = largura_total_in)

 # Pequena folga interna para impedir encostar nas bordas do painel.
 # A estimativa de largura de texto pode subestimar glifos como ▲/▽/≈ e fontes
 # substituídas. Além disso, blocos textuais longos precisam ser quebrados por
 # palavras quando excedem sozinhos a largura útil. O fator de segurança abaixo
 # encurta as linhas e a quebra robusta evita que o rodapé atravesse o painel.
  largura_util_in <- max(painel$largura_in * 0.68 - 0.22, 0.1)
  linhas <- monitora_stat_quebrar_caption_painel(
    caption,
    largura_max_in = largura_util_in,
    fontsize = fontsize,
    lineheight = lineheight
  )
  if (!length(linhas)) return(list(plot = g, n_linhas_caption = 0L))

  texto_caption <- paste(linhas, collapse = "\n")
  gp <- grid::gpar(fontsize = fontsize, lineheight = lineheight)
  grob_caption <- grid::textGrob(
    label = texto_caption,
    x = grid::unit(0, "npc"),
    y = grid::unit(1, "npc"),
    just = c("left", "top"),
    gp = gp
  )

  altura_caption <- grid::grobHeight(grob_caption) + grid::unit(8, "pt")
  g <- gtable::gtable_add_rows(g, heights = altura_caption, pos = length(g$heights))
  linha_caption <- length(g$heights)
  g <- gtable::gtable_add_grob(
    g,
    grobs = grob_caption,
    t = linha_caption,
    l = painel$l,
    r = painel$r,
    clip = "on",
    name = "caption_painel"
  )
  list(plot = g, n_linhas_caption = length(linhas))
}

monitora_ajustar_layout_exportacao <- function(plot_obj, nome_plot = NULL, width = 11, height = 7) {
  if (!inherits(plot_obj, "ggplot")) return(list(plot = plot_obj, width = width, height = height))

  dados_plot <- tryCatch(data.table::as.data.table(plot_obj$data), error = function(e) data.table::data.table())
  n_categorias <- 0L
  maior_categoria <- 0L
  n_anos <- 0L
  if (nrow(dados_plot)) {
    if ("categoria_label" %in% names(dados_plot)) {
      cats <- unique(stats::na.omit(as.character(dados_plot$categoria_label)))
      n_categorias <- length(cats)
      maior_categoria <- max(nchar(cats, type = "width"), na.rm = TRUE)
      if (!is.finite(maior_categoria)) maior_categoria <- 0L
    }
    if ("ANO" %in% names(dados_plot)) n_anos <- length(unique(stats::na.omit(as.character(dados_plot$ANO))))
    if ("ANO_factor_rotulo" %in% names(dados_plot)) n_anos <- max(n_anos, length(unique(stats::na.omit(as.character(dados_plot$ANO_factor_rotulo)))))
  }

  titulo <- plot_obj$labels$title
  largura_titulo <- 78L
  if (n_categorias >= 10L || maior_categoria >= 30L) largura_titulo <- 68L
  if (!is.null(titulo) && nzchar(as.character(titulo))) {
    plot_obj <- plot_obj + ggplot2::labs(
      title = monitora_plot_quebrar_linhas_publicavel(titulo, largura = largura_titulo, justificar = FALSE)
    )
  }

  width_adj <- width
  if (n_categorias >= 8L) width_adj <- max(width_adj, 12.0)
  if (n_categorias >= 12L || maior_categoria >= 34L) width_adj <- max(width_adj, 13.2)
  if (!is.null(titulo) && nchar(as.character(titulo), type = "width") >= 90L) width_adj <- max(width_adj, 12.6)

  caption <- plot_obj$labels$caption
  n_linhas_titulo <- if (is.null(plot_obj$labels$title)) 1L else length(strsplit(as.character(plot_obj$labels$title), "\n", fixed = TRUE)[[1]])
  height_adj <- height
  if (n_anos >= 6L) height_adj <- max(height_adj, 7.0 + 0.18 * (n_anos - 5L))
  if (n_linhas_titulo > 1L) height_adj <- max(height_adj, height + 0.28 * (n_linhas_titulo - 1L))

  plot_obj <- plot_obj + ggplot2::theme(
    plot.title = monitora_plot_elemento_titulo_publicavel(size = if (n_linhas_titulo > 1L) 13.5 else 14),
    plot.title.position = "plot",
    plot.caption = ggplot2::element_blank(),
    plot.caption.position = "panel",
    plot.margin = ggplot2::margin(t = 18, r = 24, b = 22, l = 24)
  )

  caption_layout <- monitora_stat_adicionar_caption_painel(
    plot_obj,
    caption = caption,
    largura_total_in = width_adj,
    fontsize = 7.8,
    lineheight = 1.02
  )
  if (caption_layout$n_linhas_caption > 0L) {
    height_adj <- max(height_adj, 7.0 + 0.15 * caption_layout$n_linhas_caption)
  }

  list(plot = caption_layout$plot, width = width_adj, height = height_adj)
}

monitora_ggsave_publicavel <- function(filename, plot, width = 11, height = 7, dpi = 320, nome_plot = NULL) {
  if (!is.null(nome_plot) && grepl("^plot_ed_", nome_plot)) {
    width <- max(width, 12.8)
    height <- max(height, if (grepl("pareado_periodo", nome_plot)) 11.6 else 7.8)
  }
  if (!is.null(nome_plot) && grepl("_painel_ano_inicial_", nome_plot) && grepl("veg_cover", nome_plot) && grepl("_com_rotulo", nome_plot)) {
    width <- max(width, 12.8)
    height <- max(height, 8.8)
  }
  tem_rotulo <- !is.null(nome_plot) && exists("monitora_stat_plot_tem_rotulo", mode = "function") && monitora_stat_plot_tem_rotulo(nome_plot)
  if (!is.null(nome_plot)) {
    if (isTRUE(MONITORA_SUPRIMIR_MENSAGENS_GRAFICOS)) {
      plot <- suppressMessages(monitora_stat_anotar_plot_exportacao(plot, nome_plot))
      suppressMessages(monitora_plot_registrar_auditoria_layout(plot, nome_plot = nome_plot))
    } else {
      plot <- monitora_stat_anotar_plot_exportacao(plot, nome_plot)
      monitora_plot_registrar_auditoria_layout(plot, nome_plot = nome_plot)
    }
  }
 # Gráficos com rótulos estatísticos precisam de folga vertical para a legenda metodológica.
  if (isTRUE(tem_rotulo)) height <- max(height, 7.95)
  layout_exportacao <- if (isTRUE(MONITORA_SUPRIMIR_MENSAGENS_GRAFICOS)) {
    suppressMessages(monitora_ajustar_layout_exportacao(plot, nome_plot = nome_plot, width = width, height = height))
  } else {
    monitora_ajustar_layout_exportacao(plot, nome_plot = nome_plot, width = width, height = height)
  }
  if (isTRUE(MONITORA_SUPRIMIR_MENSAGENS_GRAFICOS)) {
    suppressMessages(ggplot2::ggsave(
      filename = filename,
      plot = layout_exportacao$plot,
      width = layout_exportacao$width,
      height = layout_exportacao$height,
      dpi = dpi,
      bg = "white",
      limitsize = FALSE
    ))
  } else {
    ggplot2::ggsave(
      filename = filename,
      plot = layout_exportacao$plot,
      width = layout_exportacao$width,
      height = layout_exportacao$height,
      dpi = dpi,
      bg = "white",
      limitsize = FALSE
    )
  }
}


monitora_perf_registrar_checkpoint(
  "preparacao_objetos_graficos",
  "objetos ggplot e metadados de gráficos preparados antes da decisão de exportação PNG"
)

# Objetos de gráfico existentes.
MONITORA_PAINEL_CORRECOES_ATIVO <- exists("MONITORA_ABRIR_PAINEL_CORRECOES", inherits = FALSE) && isTRUE(MONITORA_ABRIR_PAINEL_CORRECOES)
MONITORA_PNG_SKIP_POR_EDICAO <- identical(MONITORA_EXPORTAR_PNG_MODO, "edicao") && isTRUE(MONITORA_PAINEL_CORRECOES_ATIVO)
MONITORA_DEVE_EXPORTAR_PNG <- isTRUE(MONITORA_EXPORTAR_GRAFICOS) && isTRUE(MONITORA_EXPORTAR_GRAFICOS_PNG) &&
  !(MONITORA_EXPORTAR_PNG_MODO %in% c("desligado", "indice")) &&
  !isTRUE(MONITORA_PNG_SKIP_POR_EDICAO)
if (isTRUE(MONITORA_DEVE_EXPORTAR_PNG) && (!exists("registros_corrig") || nrow(registros_corrig) <= MONITORA_MAX_LINHAS_GRAFICOS_AUTO)) {
 ### o catálogo lógico permanece completo e com seriais estáveis, mas
 ### somente objetos com dados renderizáveis entram no loop de ggsave . A
 ### avaliação ocorre sobre o subconjunto já filtrado por UC/período/painel e
 ### form_veg, logo também cobre UCs sem Campestre ou sem Savânica.
  catalogo_plots <- plot_list_names[plot_list_names %in% ls()]
  MONITORA_AUDITORIA_DISPONIBILIDADE_GRAFICOS <- monitora_plot_avaliar_catalogo(catalogo_plots)
  existing_plots <- MONITORA_AUDITORIA_DISPONIBILIDADE_GRAFICOS[exportar_png %in% TRUE, nome_plot]
  n_plots_omitidos_sem_dados <- MONITORA_AUDITORIA_DISPONIBILIDADE_GRAFICOS[exportar_png %in% FALSE, .N]
  monitora_log_registrar_evento(
    "disponibilidade_graficos",
    "INFO",
    NA_character_,
    paste0(length(existing_plots), " gráfico(s) com dados renderizáveis; ", n_plots_omitidos_sem_dados, " omitido(s) sem dados no respectivo escopo/form_veg."),
    "R20: gate semântico amplo antes de ggsave; zeros observados com denominador válido permanecem elegíveis"
  )
  MONITORA_INDICE_GRAFICOS <- monitora_criar_indice_graficos_publicos(catalogo_plots)
  if (nrow(MONITORA_INDICE_GRAFICOS)) {
    pos_aud <- match(MONITORA_INDICE_GRAFICOS$nome_plot, MONITORA_AUDITORIA_DISPONIBILIDADE_GRAFICOS$nome_plot)
    MONITORA_INDICE_GRAFICOS[, `:=`(
      status_exportacao = MONITORA_AUDITORIA_DISPONIBILIDADE_GRAFICOS$status_exportacao[pos_aud],
      motivo_disponibilidade = MONITORA_AUDITORIA_DISPONIBILIDADE_GRAFICOS$motivo_disponibilidade[pos_aud],
      formacoes_observadas = MONITORA_AUDITORIA_DISPONIBILIDADE_GRAFICOS$formacoes_observadas[pos_aud],
      n_linhas_dados_plot = MONITORA_AUDITORIA_DISPONIBILIDADE_GRAFICOS$n_linhas_dados_plot[pos_aud]
    )]
    monitora_fwrite(
      MONITORA_INDICE_GRAFICOS,
      file.path(MONITORA_OUTPUT_DIR, "indice_graficos.csv"),
      row.names = FALSE
    )
  }
  dir.create(file.path(MONITORA_OUTPUT_DIR, "03_auditorias", "estatisticas"), recursive = TRUE, showWarnings = FALSE)
  monitora_fwrite(
    MONITORA_AUDITORIA_DISPONIBILIDADE_GRAFICOS,
    file.path(MONITORA_OUTPUT_DIR, "03_auditorias", "estatisticas", "auditoria_disponibilidade_graficos.csv"),
    row.names = FALSE
  )
  monitora_relatorio_gerar_textual_estatistico(file.path(MONITORA_OUTPUT_DIR, "relatorio_textual_estatistico.txt"))
  MONITORA_RELATORIO_TEXTUAL_GERADO <- TRUE
 ### diretório canônico dos gráficos finais é
 ### output/06_graficos/ (já era o destino documentado/esperado pela
 ### auditoria de organização de produtos -- monitora_output_classificar_arquivo_raiz ,
 ### que já classifica.png/.jpg/.svg/.pdf como "06_graficos"). A escrita em
 ### si, porém, usava o diretório relativo legado "plots_png" (fora de
 ### MONITORA_OUTPUT_DIR), corrigido aqui na origem -- sem copiar/duplicar
 ### PNGs depois.
  MONITORA_DIR_GRAFICOS_CANONICO <- file.path(MONITORA_OUTPUT_DIR, "06_graficos")
  dir.create(MONITORA_DIR_GRAFICOS_CANONICO, showWarnings = FALSE, recursive = TRUE)
  mapa_arquivo_png <- stats::setNames(MONITORA_INDICE_GRAFICOS$arquivo_png, MONITORA_INDICE_GRAFICOS$nome_plot)
  plots_omitidos <- MONITORA_AUDITORIA_DISPONIBILIDADE_GRAFICOS[exportar_png %in% FALSE, nome_plot]
  if (length(plots_omitidos)) {
    arquivos_omitidos <- unname(mapa_arquivo_png[plots_omitidos])
    arquivos_omitidos <- arquivos_omitidos[!is.na(arquivos_omitidos) & nzchar(arquivos_omitidos)]
    caminhos_omitidos <- file.path(MONITORA_DIR_GRAFICOS_CANONICO, arquivos_omitidos)
    stale <- caminhos_omitidos[file.exists(caminhos_omitidos)]
    if (length(stale)) unlink(stale, force = TRUE)
  }
  monitora_progresso_loop_configurar("exportacao_png", length(existing_plots), descricao = "exportação dos PNGs")
  if (length(existing_plots)) {
    for (plot_i in seq_along(existing_plots)) {
      plot_nm <- existing_plots[[plot_i]]
      plot_obj <- get(plot_nm, envir = .GlobalEnv, inherits = FALSE)
      arquivo_plot <- if (plot_nm %in% names(mapa_arquivo_png)) mapa_arquivo_png[[plot_nm]] else paste0(plot_nm, ".png")
      if (isTRUE(MONITORA_SUPRIMIR_MENSAGENS_GRAFICOS)) {
        suppressMessages(monitora_ggsave_publicavel(
          filename = file.path(MONITORA_DIR_GRAFICOS_CANONICO, arquivo_plot),
          plot = plot_obj,
          width = 11,
          height = 7,
          dpi = 320,
          nome_plot = plot_nm
        ))
      } else {
        monitora_ggsave_publicavel(
          filename = file.path(MONITORA_DIR_GRAFICOS_CANONICO, arquivo_plot),
          plot = plot_obj,
          width = 11,
          height = 7,
          dpi = 320,
          nome_plot = plot_nm
        )
      }
      monitora_progresso_loop_avancar("exportacao_png", atual = plot_i, detalhe = paste0(plot_i, "/", length(existing_plots), ": ", arquivo_plot))
      if (plot_i %% 5L == 0L || plot_i == length(existing_plots)) {
        monitora_perf_registrar_checkpoint(
          paste0("exportacao_graficos_png_lote_", sprintf("%03d", plot_i)),
          paste0("PNGs exportados: ", plot_i, "/", length(existing_plots)),
          MONITORA_INDICE_GRAFICOS[nome_plot %in% existing_plots[seq_len(plot_i)]]
        )
      }
    }
  }
  MONITORA_AUDITORIA_DISPONIBILIDADE_GRAFICOS[exportar_png %in% TRUE, status_exportacao := "gerado"]
  if (nrow(MONITORA_INDICE_GRAFICOS)) {
    pos_aud_final <- match(MONITORA_INDICE_GRAFICOS$nome_plot, MONITORA_AUDITORIA_DISPONIBILIDADE_GRAFICOS$nome_plot)
    MONITORA_INDICE_GRAFICOS[, status_exportacao := MONITORA_AUDITORIA_DISPONIBILIDADE_GRAFICOS$status_exportacao[pos_aud_final]]
    monitora_fwrite(
      MONITORA_INDICE_GRAFICOS,
      file.path(MONITORA_OUTPUT_DIR, "indice_graficos.csv"),
      row.names = FALSE
    )
  }
  monitora_fwrite(
    MONITORA_AUDITORIA_DISPONIBILIDADE_GRAFICOS,
    file.path(MONITORA_OUTPUT_DIR, "03_auditorias", "estatisticas", "auditoria_disponibilidade_graficos.csv"),
    row.names = FALSE
  )
  monitora_rm_seguro("plot_i", "plot_nm", "plot_obj", "arquivo_plot", "catalogo_plots", "plots_omitidos", "arquivos_omitidos", "caminhos_omitidos", "stale", "pos_aud", "pos_aud_final")
  monitora_recurso_gc("exportacao_graficos_png")
  if (exists("MONITORA_STAT_AUDITORIA_SIMBOLOS_PLOTS")) {
    monitora_fwrite(
      MONITORA_STAT_AUDITORIA_SIMBOLOS_PLOTS,
      file.path(MONITORA_OUTPUT_DIR, "auditoria_simbolos_graficos.csv"),
      row.names = FALSE
    )
    monitora_stat_registrar_msg("auditoria de símbolos dos gráficos gravada em output/auditoria_simbolos_graficos.csv")
  }
  if (exists("MONITORA_AUDITORIA_LAYOUT_ROTULOS")) {
    monitora_fwrite(
      MONITORA_AUDITORIA_LAYOUT_ROTULOS,
      file.path(MONITORA_OUTPUT_DIR, "auditoria_layout_rotulos.csv"),
      row.names = FALSE
    )
    monitora_stat_registrar_msg("auditoria de layout dos rótulos gravada em output/auditoria_layout_rotulos.csv")
  }
  monitora_perf_registrar_checkpoint("exportacao_graficos_png_concluida", "gravação dos gráficos PNG concluída")
} else {
  motivo <- if (!isTRUE(MONITORA_EXPORTAR_GRAFICOS)) {
    "MONITORA_EXPORTAR_GRAFICOS=false"
  } else if (!isTRUE(MONITORA_EXPORTAR_GRAFICOS_PNG)) {
    "MONITORA_EXPORTAR_GRAFICOS_PNG=false"
  } else if (identical(MONITORA_EXPORTAR_PNG_MODO, "desligado")) {
    "MONITORA_EXPORTAR_PNG_MODO=desligado"
  } else if (identical(MONITORA_EXPORTAR_PNG_MODO, "indice")) {
    "MONITORA_EXPORTAR_PNG_MODO=indice; índice/relatório textual gerados sem gravar PNGs"
  } else if (isTRUE(MONITORA_PNG_SKIP_POR_EDICAO)) {
    "MONITORA_EXPORTAR_PNG_MODO=edicao e painel de correções aberto; PNGs pulados por escolha explícita"
  } else {
    paste0("nrow(registros_corrig)>MONITORA_MAX_LINHAS_GRAFICOS_AUTO=", MONITORA_MAX_LINHAS_GRAFICOS_AUTO)
  }
  monitora_log_registrar_evento("exportacao_graficos_png", "AVISO", NA_character_, paste0("Exportação de gráficos PNG ignorada: ", motivo), "para forçar, ajustar variáveis de ambiente")
