### Auditoria final de produtos esperados.
### Objetivo: impedir que a execução termine silenciosamente sem produtos finais
### importantes (por exemplo, registros_corrig, índices ou PNGs esperados).
monitora_auditar_produtos_finais <- function() {
  produto_linha <- function(produto, caminho, tipo = "arquivo", esperado = TRUE, obrigatorio = TRUE, min_bytes = 1L, observacao = "") {
    caminho_chr <- as.character(caminho %||% NA_character_)
    existe <- if (is.na(caminho_chr) || !nzchar(caminho_chr)) FALSE else file.exists(caminho_chr)
    tamanho <- NA_real_
    n_arquivos <- NA_integer_
    if (existe && identical(tipo, "arquivo")) {
      tamanho <- suppressWarnings(as.numeric(file.info(caminho_chr)$size))
    } else if (existe && identical(tipo, "diretorio")) {
      arqs <- list.files(caminho_chr, full.names = TRUE, recursive = TRUE)
      arqs <- arqs[file.exists(arqs) & !dir.exists(arqs)]
      n_arquivos <- length(arqs)
      tamanho <- if (length(arqs)) sum(suppressWarnings(as.numeric(file.info(arqs)$size)), na.rm = TRUE) else 0
    }
    ok <- if (!isTRUE(esperado)) {
      TRUE
    } else if (!existe) {
      FALSE
    } else if (identical(tipo, "arquivo")) {
      is.finite(tamanho) && tamanho >= min_bytes
    } else if (identical(tipo, "diretorio")) {
      !is.na(n_arquivos) && n_arquivos >= min_bytes
    } else {
      TRUE
    }
    data.table::data.table(
      produto = produto,
      caminho = caminho_chr,
      tipo = tipo,
      esperado = isTRUE(esperado),
      obrigatorio = isTRUE(obrigatorio),
      existe = isTRUE(existe),
      tamanho_bytes = tamanho,
      n_arquivos = n_arquivos,
      status = if (!isTRUE(esperado)) "nao_esperado" else if (isTRUE(ok)) "ok" else "ausente_ou_vazio",
      observacao = as.character(observacao %||% ""),
      getwd_auditoria = normalizePath(getwd(), winslash = "/", mustWork = FALSE),
      output_dir_auditoria = as.character(out_dir),
      log_dir_auditoria = as.character(log_dir)
    )
  }

 ### Caminhos canônicos: nunca usar getwd como fallback aqui.
 ### A auditoria final pode rodar depois de setwd(MONITORA_OUTPUT_DIR), então
 ### depender de getwd recria o bug output/output. Os diretórios são lidos
 ### explicitamente do ambiente global e validados contra aninhamento operacional.
  out_dir <- monitora_dir_global_obrigatorio("MONITORA_OUTPUT_DIR", criar = TRUE)
  log_dir <- monitora_dir_global_obrigatorio("MONITORA_LOG_DIR", criar = TRUE)
  arquivos_raiz_observados <- list.files(out_dir, recursive = FALSE, full.names = FALSE, all.files = FALSE)
  arquivos_raiz_observados <- arquivos_raiz_observados[file.info(file.path(out_dir, arquivos_raiz_observados))$isdir == FALSE]
  output_ja_organizado <- all(arquivos_raiz_observados %in% c("README_OUTPUT.txt", "indice_produtos.csv"))
  caminho_raiz_ou_organizado <- function(bn) {
    raiz <- file.path(out_dir, bn)
    if (file.exists(raiz)) return(raiz)
    if (exists("monitora_output_classificar_arquivo_raiz", mode = "function")) {
      return(file.path(out_dir, monitora_output_classificar_arquivo_raiz(bn), bn))
    }
    raiz
  }
  caminho_escrita_final <- function(bn) {
    if (isTRUE(output_ja_organizado) && exists("monitora_output_classificar_arquivo_raiz", mode = "function")) {
      return(file.path(out_dir, monitora_output_classificar_arquivo_raiz(bn), bn))
    }
    file.path(out_dir, bn)
  }
  corr_dir <- monitora_global_get("MONITORA_CORRECOES_DIR", file.path(out_dir, "correcoes_campos"))
  corr_dir <- normalizePath(as.character(corr_dir), winslash = "/", mustWork = FALSE)
  if (grepl("/(output|log|input|extracted)/(output|log|input|extracted)$", corr_dir)) {
    stop("MONITORA_CORRECOES_DIR inválido com diretório operacional aninhado: ", corr_dir, call. = FALSE)
  }
  dir.create(corr_dir, showWarnings = FALSE, recursive = TRUE)
  caminho_correcao_organizado <- function(rel) {
    if (exists("monitora_output_destino_correcao", mode = "function")) {
      return(file.path(out_dir, monitora_output_destino_correcao(rel)))
    }
    file.path(corr_dir, rel)
  }
  if (basename(out_dir) == "output" && basename(dirname(out_dir)) == "output") {
    stop("MONITORA_OUTPUT_DIR inválido na auditoria final: ", out_dir, call. = FALSE)
  }
  if (basename(log_dir) == "log" && basename(dirname(log_dir)) == "log") {
    stop("MONITORA_LOG_DIR inválido na auditoria final: ", log_dir, call. = FALSE)
  }
 ### alinhado ao diretório canônico de escrita dos
 ### PNGs (output/06_graficos/, ver bloco de exportação de gráficos acima).
  png_dir <- file.path(out_dir, "06_graficos")

 ### - ajuste -----------------------------------------------
 ### Auditoria final estritamente observacional para produtos centrais.
 ### A auditoria pode apontar ausência/vazio, mas nao regrava tardiamente
 ### registros_corrig.csv nem registros_corrig_stat.csv a partir de objetos
 ### em memoria. A linhagem desses produtos deve vir do fluxo legitimo de
 ### exportacao anterior, sem reparo tardio na etapa de auditoria.
  produto_ausente_ou_vazio <- function(path, min_bytes = 1L) {
    !file.exists(path) || is.na(suppressWarnings(file.info(path)$size)) ||
      suppressWarnings(file.info(path)$size) < min_bytes
  }
  caminho_relatorio_execucao <- caminho_raiz_ou_organizado("relatorio_execucao_ultima_execucao.csv")
  caminho_performance_execucao <- caminho_raiz_ou_organizado("performance_execucao_ultima_execucao.csv")
  if (produto_ausente_ou_vazio(caminho_relatorio_execucao, 1L) &&
      monitora_global_existe("MONITORA_LOG_EXECUCAO")) {
    monitora_fwrite(monitora_global_get("MONITORA_LOG_EXECUCAO"), caminho_escrita_final("relatorio_execucao_ultima_execucao.csv"), na = "")
  }
  if (produto_ausente_ou_vazio(caminho_performance_execucao, 1L) &&
      exists("monitora_perf_gravar_relatorio", mode = "function", envir = .GlobalEnv, inherits = FALSE)) {
    tryCatch(monitora_perf_gravar_relatorio(), error = function(e) NULL)
  }

  modo_png <- as.character(monitora_global_get("MONITORA_EXPORTAR_PNG_MODO", "completo"))
  espera_png <- isTRUE(monitora_global_get("MONITORA_EXPORTAR_GRAFICOS_PNG", FALSE)) &&
    !isTRUE(monitora_global_get("MONITORA_PNG_SKIP_POR_EDICAO", FALSE)) &&
    !(modo_png %in% c("desligado", "indice"))

  rcs <- monitora_global_get("registros_corrig_stat", NULL)
  espera_kml <- isTRUE(monitora_global_get("MONITORA_EXPORTAR_KML", FALSE)) &&
    is.data.frame(rcs) &&
    nrow(rcs) > 0 &&
    nrow(rcs) <= as.integer(monitora_global_get("MONITORA_MAX_UAS_KML_AUTO", Inf)) &&
    all(c("long_ini", "lat_ini", "long_fin", "lat_fin") %in% names(rcs))

  espera_rel_painel <- isTRUE(monitora_global_get("MONITORA_GERAR_RELATORIOS_SUPORTE_PAINEL", FALSE)) && isTRUE(monitora_global_get("MONITORA_GERAR_RELATORIOS_POS_CORRECOES", TRUE)) &&
    isTRUE(monitora_global_get("MONITORA_DEVE_PROCESSAR_CORRECOES_CAMPOS", FALSE))

  espera_registros_validados <- isTRUE(monitora_global_get("MONITORA_GERAR_REGISTROS_VALIDADOS", FALSE))
  espera_registros_importados <- (
    isTRUE(monitora_global_get("MONITORA_GERAR_REGISTROS_IMPORTADOS", FALSE)) ||
      isTRUE(monitora_global_get("MONITORA_GERAR_REGISTROS_IMPORTADOS_PRE_PAINEL", FALSE))
  ) &&
    !isTRUE(monitora_global_get("MONITORA_MODO_USA_REGISTROS_CORRIG_ENTRADA", FALSE)) &&
    !isTRUE(monitora_global_get("MONITORA_REGISTROS_IMPORTADOS_NAO_APLICAVEL_MODO_REGISTROS_CORRIG", FALSE))

  produtos <- list(
    produto_linha("registros_importados.csv", if (exists("monitora_produtos_path_canonico", mode = "function")) monitora_produtos_path_canonico("registros_importados.csv", out_dir) else file.path(out_dir, "01_produtos_dados", "registros_importados.csv"), "arquivo", espera_registros_importados, FALSE, 1L, "produto saneado/comparável de entrada, antes de correções e deduplicações finais"),
    produto_linha("registros_importados_operacional_pre_painel.csv", if (exists("monitora_produtos_path_canonico", mode = "function")) monitora_produtos_path_canonico("registros_importados_operacional_pre_painel.csv", out_dir) else file.path(out_dir, "01_produtos_dados", "registros_importados_operacional_pre_painel.csv"), "arquivo", espera_registros_importados, FALSE, 1L, "camada operacional pós-tokenização/pré-painel; não substitui registros_importados.csv, registros_corrig.csv nem registros_validados.csv"),
    produto_linha("registros_importados_bruto.csv", if (exists("monitora_produtos_path_canonico", mode = "function")) monitora_produtos_path_canonico("registros_importados_bruto.csv", out_dir) else file.path(out_dir, "01_produtos_dados", "registros_importados_bruto.csv"), "arquivo", espera_registros_importados, FALSE, 1L, "snapshot técnico bruto da leitura/montagem dos arquivos de entrada"),
    produto_linha("registros_corrig.csv", if (exists("monitora_produtos_path_canonico", mode = "function")) monitora_produtos_path_canonico("registros_corrig.csv", out_dir) else file.path(out_dir, "01_produtos_dados", "registros_corrig.csv"), "arquivo", TRUE, TRUE, 1L, "base corrigida final"),
    produto_linha("registros_validados.csv", if (exists("monitora_produtos_path_canonico", mode = "function")) monitora_produtos_path_canonico("registros_validados.csv", out_dir) else file.path(out_dir, "01_produtos_dados", "registros_validados.csv"), "arquivo", espera_registros_validados, espera_registros_validados, 1L, "produto opcional no schema SISMONITORA 21FEV25"),
    produto_linha("registros_corrig_stat.csv", if (exists("monitora_produtos_path_canonico", mode = "function")) monitora_produtos_path_canonico("registros_corrig_stat.csv", out_dir) else file.path(out_dir, "01_produtos_dados", "registros_corrig_stat.csv"), "arquivo", TRUE, TRUE, 1L, "base estatística final"),
    produto_linha("relatorio_execucao_ultima_execucao.csv", caminho_raiz_ou_organizado("relatorio_execucao_ultima_execucao.csv"), "arquivo", TRUE, TRUE, 1L, "log consolidado da última execução"),
    produto_linha("performance_execucao_ultima_execucao.csv", caminho_raiz_ou_organizado("performance_execucao_ultima_execucao.csv"), "arquivo", TRUE, TRUE, 1L, "performance consolidada da última execução"),
    produto_linha("RELATORIO_CADEIA_DADOS.md", file.path(out_dir, "00_manifesto_execucao", "cadeia_dados", "RELATORIO_CADEIA_DADOS.md"), "arquivo", TRUE, TRUE, 1L, "narrativa ponta a ponta input -> bruto -> importados -> corrig -> validados"),
    produto_linha("cadeia_dados_etapas_ultima_execucao.csv", file.path(out_dir, "00_manifesto_execucao", "cadeia_dados", "cadeia_dados_etapas_ultima_execucao.csv"), "arquivo", TRUE, TRUE, 1L, "estado, dimensões, hashes disponíveis e evidências por etapa"),
    produto_linha("cadeia_dados_eventos_ultima_execucao.csv", file.path(out_dir, "00_manifesto_execucao", "cadeia_dados", "cadeia_dados_eventos_ultima_execucao.csv"), "arquivo", TRUE, TRUE, 1L, "transformações, avisos, bloqueios e ações da execução em ordem"),
    produto_linha("auditoria_fechamento_hierarquico_ultima_execucao.csv", caminho_correcao_organizado("auditoria_fechamento_hierarquico_ultima_execucao.csv"), "arquivo", espera_rel_painel, espera_rel_painel, 1L, "regras ascendentes, ambiguidades recusadas e sanitizações automáticas aplicadas"),
    produto_linha("controle_recursos_ultima_execucao.csv", caminho_raiz_ou_organizado("controle_recursos_ultima_execucao.csv"), "arquivo", TRUE, FALSE, 1L, "controle de recursos/RAM"),
    produto_linha("relatorio_textual_estatistico.txt", caminho_raiz_ou_organizado("relatorio_textual_estatistico.txt"), "arquivo", TRUE, FALSE, 1L, "relatório textual estatístico"),
    produto_linha("indice_graficos.csv", caminho_raiz_ou_organizado("indice_graficos.csv"), "arquivo", TRUE, FALSE, 1L, "índice dos gráficos"),
    produto_linha("plots_png", png_dir, "diretorio", espera_png, TRUE, 1L, paste0("MONITORA_EXPORTAR_PNG_MODO=", modo_png)),
    produto_linha("UAs_registros_corrig_stat.kml", caminho_raiz_ou_organizado("UAs_registros_corrig_stat.kml"), "arquivo", espera_kml, FALSE, 1L, "KML linhas inicial-final"),
    produto_linha("UAs_verg_ini_verg_fin.kml", caminho_raiz_ou_organizado("UAs_verg_ini_verg_fin.kml"), "arquivo", espera_kml, FALSE, 1L, "KML pontos inicial/final"),
    produto_linha("relatorios_pre_painel", file.path(out_dir, "02_painel_correcoes", "relatorios_apoio_tematicos", "pre_painel"), "diretorio", espera_rel_painel, FALSE, 1L, "relatórios de apoio antes do painel"),
    produto_linha("relatorios_pos_correcoes", file.path(out_dir, "02_painel_correcoes", "relatorios_apoio_tematicos", "pos_painel"), "diretorio", espera_rel_painel, FALSE, 1L, "relatórios de apoio após correções"),
    produto_linha("comparacao_relatorios_pre_pos_correcoes.csv", caminho_correcao_organizado("comparacao_relatorios_pre_pos_correcoes.csv"), "arquivo", espera_rel_painel, FALSE, 1L, "comparação pré/pós-correções"),
    produto_linha("auditoria_colunas_protegidas_pos_correcoes", file.path(out_dir, "03_auditorias", "persistencia"), "diretorio", TRUE, FALSE, 1L, "diretório canônico de auditorias de persistência/colunas protegidas")
  )

  aud <- data.table::rbindlist(produtos, fill = TRUE, use.names = TRUE)
  idx_validados_aud <- which(aud$produto == "registros_validados.csv" & aud$esperado == TRUE)
  if (length(idx_validados_aud) && !isTRUE(monitora_global_get("MONITORA_REGISTROS_VALIDADOS_GERADO", FALSE))) {
    data.table::set(aud, i = idx_validados_aud, j = "status", value = "nao_gerado_nesta_execucao")
    data.table::set(aud, i = idx_validados_aud, j = "observacao", value = paste0(
      aud$observacao[idx_validados_aud],
      "; arquivo eventualmente preexistente não é aceito como evidência da execução atual"
    ))
  }
  arq_log <- file.path(log_dir, paste0("auditoria_produtos_finais_", MONITORA_EXEC_ID, ".csv"))
  arq_out <- caminho_escrita_final("auditoria_produtos_finais_ultima_execucao.csv")
  dir.create(dirname(arq_log), showWarnings = FALSE, recursive = TRUE)
  dir.create(dirname(arq_out), showWarnings = FALSE, recursive = TRUE)
  monitora_fwrite(aud, arq_log, na = "")
  monitora_fwrite(aud, arq_out, na = "")

  falhas <- aud[esperado == TRUE & obrigatorio == TRUE & status != "ok"]
  if (nrow(falhas)) {
    msg <- paste0(
      "Produtos finais obrigatórios ausentes/vazios: ",
      paste(falhas$produto, collapse = ", "),
      ". Ver ", arq_out
    )
    monitora_log_registrar_evento("auditoria_produtos_finais", "ERRO", arq_out, msg, "produto obrigatório não gerado")
    if (isTRUE(monitora_global_get("MONITORA_FALHAR_PRODUTOS_FINAIS_AUSENTES", TRUE))) {
      stop(msg, call. = FALSE)
    } else {
      warning(msg, call. = FALSE)
    }
  } else {
    monitora_log_registrar_evento("auditoria_produtos_finais", "INFO", arq_out, "Produtos finais obrigatórios presentes", "auditoria final OK")
  }

  invisible(aud)
}

### Garantir que a auditoria final rode a partir da raiz canônica, mas sem depender de getwd .
tryCatch(setwd(monitora_dir_global_obrigatorio("MONITORA_BASE_DIR", criar = FALSE)), error = function(e) NULL)

if (isTRUE(monitora_global_get("MONITORA_VALIDAR_PRODUTOS_FINAIS", TRUE))) {
  MONITORA_AUDITORIA_PRODUTOS_FINAIS <- monitora_auditar_produtos_finais()
  monitora_perf_registrar_checkpoint("auditoria_produtos_finais", "verificação de presença dos produtos finais esperados", MONITORA_AUDITORIA_PRODUTOS_FINAIS)
}

if (exists("monitora_gravar_manifesto_execucao", mode = "function", inherits = FALSE)) {
  monitora_gravar_manifesto_execucao("fim")
}

monitora_plot_limpar_ambiente_temporario()
monitora_recurso_gc("limpeza_final_ambiente")
monitora_progresso_finalizar()

### Último consumidor de output: executa depois de relatórios, auditoria final,
### manifesto, performance e limpeza. Assim nenhum produto tardio permanece na
### raiz por ter sido criado depois das organizações intermediárias.
tryCatch(
  monitora_output_organizar_produtos(
    MONITORA_OUTPUT_DIR,
    MONITORA_EXEC_ID,
    contexto = "fechamento_final_pos_todos_produtos"
  ),
  error = function(e) warning("Falha na organização final do output: ", conditionMessage(e), call. = FALSE)
)

tryCatch(
  monitora_cadeia_dados_relatorio_gerar("fechamento_final"),
  error = function(e) warning("Falha ao gerar relatório ponta a ponta da cadeia de dados: ", conditionMessage(e), call. = FALSE)
)

if (exists("monitora_diagnostico_posix_restaurar", mode = "function")) {
  monitora_diagnostico_posix_restaurar()
}

} ### Fim do bloco protegido por MONITORA_EXECUCAO_ENCERRADA_CONTROLADAMENTE

